/* ============================================================
   Procedure: [dbo].[Usp_insertusercartsettings]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 CREATE   PROCEDURE dbo.Usp_insertusercartsettings     
  @ParentID  BIGINT,    
                                                @AboutUs   VARCHAR(500),    
                                                @ContactUs VARCHAR(500),    
                                                @IsPayment BIT,    
                                                @CreatedBy BIGINT,    
                                                @Domain    VARCHAR(500),    
                                                @Template  VARCHAR(50),    
                                                @Other     BIT,    
                                                @FooterValue   VARCHAR(500),    
@SliderImage1   VARCHAR(500),    
@SliderImage2   VARCHAR(500),    
@SliderImage3   VARCHAR(500),    
@SliderImage4   VARCHAR(500),    
@SliderImage5   VARCHAR(500),    
@IsSlider bit  ,@LogoImage varchar(500)  
AS    
  BEGIN     
            IF EXISTS (SELECT 'x'    
                       FROM   usercartsettings AS ucs    
                       WHERE  ucs.parentid = @ParentID)    
              BEGIN    
                  IF @Other = 1    
                    BEGIN    
                        UPDATE usercartsettings    
                        SET      
SliderImage1=@SliderImage1,  
SliderImage2=@SliderImage2,  
SliderImage3=@SliderImage3,  
SliderImage4=@SliderImage4,  
SliderImage5=@SliderImage5,  
IsSlider=@IsSlider,LogoImage=@LogoImage  
                        WHERE  parentid = @ParentID 
                        SELECT 'Success'       
                    END    
                  ELSE                    
                    BEGIN  
                       if not Exists(select domain from usercartsettings where domain=@Domain and  parentid <> @ParentID ) 
                       Begin  
                        UPDATE usercartsettings    
                        SET    domain = @Domain,    
                               [template] = @Template    
                        WHERE  parentid = @ParentID 
                           SELECT 'Success'   
                        End  
                        Else
                        Begin
                        SELECT 'Already Exists'    
                        End 
                    END    
    
                
              END    
            ELSE    
              BEGIN    
                  DELETE FROM usercartsettings    
                  WHERE  parentid = @ParentID    
        if not Exists(select domain from usercartsettings where domain=@Domain)
           Begin
                  INSERT INTO usercartsettings    
                              (parentid,ispayment,createdon,createdby,domain,[template],SliderImage1,SliderImage2,SliderImage3,SliderImage4,SliderImage5,IsSlider,LogoImage)    
                  VALUES      ( @ParentID,@IsPayment,Getdate(),@CreatedBy,@Domain,@Template,@SliderImage1,@SliderImage2,@SliderImage3,@SliderImage4,@SliderImage5,@IsSlider ,@LogoImage)    
    
                  SELECT 'Success'    
                
          END 
        else
        Begin 
         SELECT 'Already Exists'    
        End  
        End 
  END   


GO

