/* ============================================================
   Procedure: [dbo].[usp_InsertUserDetail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


 ------------------------------------------------------------------------------
 CREATE   PROCEDURE [dbo].[usp_InsertUserDetail]
    @User_Id bigint=null,
	@P_UserId bigint=null,
	--@M_ID BIGINT,
    @User_Login VARCHAR(25),
    --@Pwd VARCHAR(15),
    @FName VARCHAR(50) = NULL,
    @LName VARCHAR(50) = NULL,
    @EMail VARCHAR(50) = NULL,
    @Mobile FLOAT,
    @City VARCHAR(50) = NULL,
    @State VARCHAR(50) = NULL,
    @Country VARCHAR(50) = NULL,
	@TimeZone nvarchar(200)=null,
	@Country_ID bigint=null
	
AS
BEGIN
    BEGIN TRY
	DECLARE @M_ID BIGINT;
        
        SELECT @M_ID = reseller_id 
        FROM reseller_detail with(nolock)
        WHERE user_id = @P_UserId;

       
	 IF @M_ID IS NOT NULL
		BEGIN
		-- Generate a random 4-digit password
            DECLARE @Pwd VARCHAR(4);
            SET @Pwd = RIGHT('0000' + CAST(CAST(ABS(CHECKSUM(NEWID())) % 10000 AS INT) AS VARCHAR(4)), 4);
        -- Insert into User_Detail
        INSERT INTO [dbo].[User_Detail] (
            M_ID,
            User_Login,
            Pwd,
            FName,
            LName,
            EMail,
            Mobile,
            City,
            State,
            Country,
            Type,
            Status,
            --IsInternalUser,
            IsAdmin,
            --MACAddress,
            --Presence,
            --IsBusyOnCall,
            DateCreated,
			Timezone,
			ParentSuperResellerId,
			CountryCode
        )
        VALUES (
            @M_ID,
            @User_Login,
            @Pwd,
            @FName,
            @LName,
            @EMail,
            @Mobile,
            @City,
            @State,
            @Country,
            0,
            1,
            --@IsInternalUser,
            0,
            --@MACAddress,
            --@Presence,
            --@IsBusyOnCall,
            GETDATE(),
			@TimeZone,
			@User_Id,
			@Country_ID
        );

        -- Return success message
         SELECT 
            'Success' AS [Status],
            'Record inserted successfully.' AS [Message];
			end
			ELSE
        BEGIN
            -- If no M_ID is found, return a message
            SELECT 
                'Data not saved.' AS Message;
        END
    END TRY
    BEGIN CATCH
        EXEC usp_InsertErrorInfo
    END CATCH
END





GO

