CREATE   PROCEDURE dbo.usp_InsertUserGroupDetailsTemplate @ParentID BIGINT
	,@GroupName VARCHAR(50)
	,@IsSMS BIT
	,@IsMail BIT
	,@CreatedBy BIGINT
AS
BEGIN
	INSERT INTO UserTemplateGroupDetails (
		ParentID
		,GroupName
		,IsSMS
		,IsMail
		,CreatedOn
		,CreatedBy
		)
