/* ============================================================
   Procedure: [dbo].[usp_InsertUserGroupTemplateMixfromTemplate]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_InsertUserGroupTemplateMixfromTemplate]
	@ParentID BIGINT,
	@TemplateID BIGINT,
	@GroupID VARCHAR(500)
AS
BEGIN
	DELETE 
	FROM   UserGroupTemplateMix
	WHERE  TemplateID = @TemplateID
	       AND ParentID = @ParentID  
	
	INSERT INTO UserGroupTemplateMix
	  (
	    -- ID -- this column value is auto-generated    
	    ParentID,
	    GroupID,
	    TemplateID,
	    OrderNo,
	    CreatedOn
	  )
	SELECT @ParentID,
	       fs.[value],
	       @TemplateID,
	       ISNULL(
	           (
	               SELECT MAX(ugtm.OrderNo) + 1
	               FROM   UserGroupTemplateMix ugtm
	               WHERE  ugtm.ParentID = @ParentID
	                      AND ugtm.GroupID = fs.[value]
	           ),
	           1
	       ),
	       GETDATE()
	FROM   dbo.fn_Split(@GroupID, '#') fs
END



