CREATE   PROCEDURE [dbo].[usp_InsertUserMailbox]
	@UserID BIGINT,
	@ParentID BIGINT,
	@CreatedBy BIGINT,
	@EmailID VARCHAR(100)
AS
BEGIN
	IF NOT EXISTS (
	       SELECT 'x'
	       FROM   UserMailbox AS um
	       WHERE  um.UserID = @UserID
	              AND um.ParentID = @ParentID
	   )
	BEGIN
	    INSERT INTO UserMailbox
	      (
	        -- ID -- this column value is auto-generated
	        UserID,
	        ParentID,
	        EmailID,
	        CreatedOn,
	        CreatedBy
	      )
	    VALUES
	      (
	        @UserID,
	        @ParentID,
	        @EmailID,
	        GETDATE(),
	        @CreatedBy
	      )
	    SELECT 'Success'
	END
	ELSE
	BEGIN
	    SELECT 'Already'
	END
END



