/* ============================================================
   Procedure: [dbo].[usp_InsertUserMailsFiltersPart1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_InsertUserMailsFiltersPart1 @ParentID BIGINT
	,@NAME VARCHAR(500)
	,@FromEmail VARCHAR(500)
	,@ToEmail VARCHAR(500)
	,@SubjectContains VARCHAR(500)
	,@MailContentContains VARCHAR(500)
	,@IsMapped BIT
	,@IsNotMapped BIT
	,@CreatedBy BIGINT
AS
BEGIN
	DECLARE @id BIGINT

	INSERT INTO UserMailsFilters (
		-- ID -- this column value is auto-generated  
		ParentID
		,NAME
		,FromEmail
		,ToEmail
		,SubjectContains
		,MailContentContains
		,IsMapped
		,IsNotMapped
		,CreatedOn
		,CreatedBy
		)
	VALUES (
		@ParentID
		,@NAME
		,@FromEmail
		,@ToEmail
		,@SubjectContains
		,@MailContentContains
		,@IsMapped
		,@IsNotMapped
		,GETDATE()
		,@CreatedBy
		)

	SELECT @id = SCOPE_IDENTITY()

	DECLARE @count INT = (
			SELECT COUNT(1)
			FROM UserMailsFilters(NOLOCK)
			WHERE ParentID = @parentid
			)
	DECLARE @m_id BIGINT
		,@user_login NVARCHAR(50)

	SELECT @m_id = m_id
		,@user_login = user_login
	FROM user_detail(NOLOCK)
	WHERE USER_ID = @parentid

	IF @m_id = 10043
		AND @count = 1
	BEGIN
		DECLARE @description NVARCHAR(200) = 'User ' + cast(@user_login AS NVARCHAR) + ' created a filter for the first time'

		EXEC Usp_InsertUserEventDetails 'Filter Created'
			,@parentID
			,@Description
			,'UserMailsFilters'
			,@ID
	END

	SELECT 'Success'

	DECLARE @rowJson NVARCHAR(MAX) = (
			SELECT *
			FROM UserMailsFilters(NOLOCK)
			WHERE ID = @id
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @CreatedBy
		,@Activity_type = 'Inst_UsrMail_Fltrs'
		,@ActionType = 'I'
		,@RowJson = @rowJson
		,@Table_name = 'UserMailsFilters'
END



GO

/* ============================================================
   Procedure: [dbo].[usp_InsertUserMailsSettings]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_InsertUserMailsSettings @ParentID BIGINT
	,@MailName VARCHAR(50)
	,@EmailAddress VARCHAR(250)
	,@CreatedBy BIGINT
AS
BEGIN
	IF (
			NOT EXISTS (
				SELECT 'x'
				FROM UserMailsSettings
				WHERE (
						MailName = @MailName
						OR EmailAddress = @EmailAddress
						)
					AND ParentID = @ParentID
				)
			)
	BEGIN
		INSERT INTO UserMailsSettings (
			-- ID -- this column value is auto-generated    
			ParentID
			,MailName
			,EmailAddress
			,CreatedOn
			,CreatedBy
			)
		VALUES (
			@ParentID
			,@MailName
			,@EmailAddress
			,GETDATE()
			,@CreatedBy
			)

		DECLARE @ID BIGINT = SCOPE_IDENTITY();

		SELECT 'Success'
	END
	ELSE
	BEGIN
		SELECT 'Already Exists'
	END

	DECLARE @rowJson NVARCHAR(MAX) = (
			SELECT *
			FROM UserMailsSettings(NOLOCK)
			WHERE ID = @ID
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @CreatedBy
		,@Activity_type = 'Inst_UsrMail_Sttng'
		,@ActionType = 'I'
		,@RowJson = @rowJson
		,@Table_name = 'UserMailsSettings'
END



GO

/* ============================================================
   Procedure: [dbo].[usp_InsertUserMailTemplates]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_InsertUserMailTemplates @ParentID BIGINT
	,@Name VARCHAR(250)
	,@IsSMS BIT
	,@IsMail BIT
	,@MailSubject NVARCHAR(500)
	,@MailContent NVARCHAR(MAX)
	,@IsLeads BIT
	,@IsEnquiry BIT
	,@IsConversion BIT
	,@IsGroup BIT
	,@IsList BIT
	,@ListID BIGINT
	,@CreatedBy BIGINT
	,@IsPersonalized BIT
	,@IsUnicode BIT
	,@MailContentEditable NVARCHAR(MAX) = NULL
	,@IsRTE BIT
	,@body_disp NVARCHAR(max) = NULL
AS
BEGIN
	SET @body_disp = coalesce(@body_disp, '')

	IF isnull(@mailcontent, '') = ''
		AND isnull(@MailContentEditable, '') <> ''
	BEGIN
		SET @MailContent = isnull(@MailContentEditable, '')
	END
	ELSE
	BEGIN
		SET @MailContentEditable = coalesce(@MailContentEditable, @MailContent)
	END

	IF (
			rtrim(ltrim(isnull(@body_disp, ''))) <> ''
			AND rtrim(ltrim(isnull(@MailContent, ''))) = ''
			)
	BEGIN
		SET @MailContent = rtrim(ltrim(isnull(@body_disp, '')))
	END

	IF (
			NOT EXISTS (
				SELECT 'x'
				FROM UserMailTemplate
				WHERE NAME = @Name
					AND ParentID = @ParentID
				)
			)
	BEGIN
		INSERT INTO UserMailTemplate (
			ParentID
			,IsSMS
			,IsMail
			,NAME
			,MailSubject
			,MailContent
			,IsLeads
			,IsEnquiry
			,IsConversion
			,IsGroup
			,IsList
			,ListID
			,CreatedOn
			,CreatedBy
			,IsPersonalized
			,IsUnicode
			,MailContentEditable
			,IsRTE
			,body_disp
			)
		VALUES (
			@ParentID
			,@IsSMS
			,@IsMail
			,@Name
			,@MailSubject
			,@MailContent
			,@IsLeads
			,@IsEnquiry
			,@IsConversion
			,@IsGroup
			,@IsList
			,@ListID
			,GETDATE()
			,@CreatedBy
			,@IsPersonalized
			,@IsUnicode
			,@MailContentEditable
			,@IsRTE
			,@body_disp
			)

		DECLARE @ID BIGINT = SCOPE_IDENTITY();

		SELECT @@identity
	END
	ELSE
	BEGIN
		SELECT 'Already Exists'
	END

	DECLARE @rowJson NVARCHAR(MAX) = (
			SELECT *
			FROM UserMailTemplate(NOLOCK)
			WHERE ID = @ID
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @CreatedBy
		,@Activity_type = 'Inst_MailTmplt'
		,@ActionType = 'I'
		,@RowJson = @rowJson
		,@Table_name = 'UserMailTemplate'
END



GO

