/* ============================================================
   Procedure: [dbo].[usp_insertuserstagefeedback_transfertoCRM]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROCEDURE usp_insertuserstagefeedback_transfertoCRM  
as  
begin  
select * into #t from user_stagefeedback (nolock) where isprocessed=0 or (isprocessed=2 and DATEDIFF(hh,processedtime,getdate())>1)  
update u set isprocessed=2 ,processedtime=getdate() from user_stagefeedback u join #t t on t.id=u.id  
declare @c int=(select count(1) from #t),@id bigint=0,@mappingid bigint,@enqno bigint,@stageid bigint,@feedback nvarchar(1000),@ispositive bit,  
@eventdate datetime,@status nvarchar(100)  
while @c>0  
begin  
begin try  
select @id=min(id) from #t where id>@id  
select @mappingid=mappingid,@feedback=feedback,@stageid=stageid,@ispositive=ispositive,@eventdate=createdon,@enqno=enqno from #t where id=@id  
--select @mappingid,@stageid,@enqno,@id,@eventdate,@feedback,@ispositive
exec CRM.CRMDB.dbo.usp_insertuserstagefeedback @mappingid,@stageid,@enqno,@id,@eventdate,@feedback,@ispositive,@status out  
update u set isprocessed=1,processedtime=getdate(),status=@status from user_stagefeedback u where id=@id  
end try  
begin catch  
exec usp_inserterrorinfo  
end catch  
set @c=@c-1  
end  
end


GO

