/* ============================================================
   Procedure: [dbo].[USP_INSERTVOICEMESSAGES]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[USP_INSERTVOICEMESSAGES]      
(      
@MID BIGINT=10000,    
@UID INT=3,      
@MOBILENUMBERS  VARCHAR(MAX)='911234567,12345678,123456789,1111111,7654',      
@WAVFILE VARCHAR(100)='RITU1.WAV',
@TOTALCOUNT INT =2
)      
AS      
SET NOCOUNT ON      
 DECLARE @CNT INT      
 SET  @CNT=(select count(*) from [fn_Split](@MOBILENUMBERS,','))           
 DECLARE @VALUEAT INT      
 SET @VALUEAT=1          
DECLARE @MOBILENUMBERAT VARCHAR(20)      
 DECLARE @BATCHID BIGINT      
EXEC USP_GetRandomNumbers @BATCHID OUT  
WHILE (@valueAt<=@CNT)          
 BEGIN      
		SELECT  @MOBILENUMBERAT=value from [fn_Split](@MOBILENUMBERS,',') where POSITION=@valueAt        
		SET @MOBILENUMBERAT='91'+@MOBILENUMBERAT      
		INSERT INTO TBL_VoiceSmsDetails      
		(      
		M_ID,U_ID,MobilesNumber,FileName,BatchID,Status      
		)      
		VALUES      
		(@MID,@UID,@MOBILENUMBERAT,@WAVFILE,@BATCHID,0)      
		SET @VALUEAT=@VALUEAT+1      
 END   

UPDATE  tbl_VoiceSmsUsers SET  VoiceSmsCredits=VoiceSmsCredits-@TOTALCOUNT




GO

/* ============================================================
   Procedure: [dbo].[usp_InsertWebEntryTbl]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--sp_helptext usp_InsertWebEntryTbl

--sp_helptext usp_InsertWebEntryTbl      
      
--sp_helptext usp_InsertWebEntryTbl                
                
CREATE   PROCEDURE usp_InsertWebEntryTbl                      
  @PrentId bigint=0,                    
  @FormName nvarchar(max)='',                   
   @Name  nvarchar(max)='',                   
   @Mobile  nvarchar(max)='',                  
   @Email  nvarchar(max)='',                  
   @Address nvarchar(max)='',                  
   @Remarks nvarchar(max)='',                  
  @DynimicAttr nvarchar(max)='',          
  @mail_body nvarchar(max)='',                  
  @msg_body nvarchar(max)='',    
  @CampaignName  nvarchar(max)=''                 
                   
AS                      
BEGIN                   
declare @entid bigint = 0;                     
declare @formid bigint = 0;                  
declare @MediumID bigint = 0;                    
declare @Sourceid bigint = 0;                  
declare @isenquery  bit ;                  
declare @userid  bigint = 0;                   
declare @EnquiryID  bigint = 0;                   
set @isenquery = 0;                  
select  @formid = formid, @MediumID= MediumID, @Sourceid=Sourceid, @isenquery= isEnquiry,                  
  @userid = userid from WebFormTbl where  ParentId = @PrentId and FormName = @FormName  ;                     
                  
 insert into WebEntryTbl (FormId, Mobile, formname, Name, Email, Address,Remarks, DynimicAttr,          
 mail_body, msg_body,CampaignName )                    
 values (@FormId, @Mobile, @formname, @Name, @Email, @Address, @Remarks,  @DynimicAttr,           
 @mail_body, @msg_body,@CampaignName )  ;                  
 select @entid = SCOPE_IDENTITY();                     
                
                  
                    
--if (@isenquery =1 and @entid > 0)           
if (@isenquery =1 and @entid > 0)       
begin        
      
create table #temp(mobile varchar(100),email varchar(100))                      
insert into #temp(mobile,email)                    
select (cast(isnull(NULLIF(MobileNo,''),0) as nvarchar)),isnull(NULLIF(EmailID,''),0) from UserLeads where ParentID=@PrentId                      
                    
      
                 
BEGIN                    
declare @leadn varchar(max) = ''      
                    
if exists(select 1 from UserLeads where ParentID=@PrentId and (cast(isnull(@Mobile,1) as nvarchar) in (select Mobile from #temp)))                     
BEGIN                     
select @leadn = leadno from UserLeads where ParentID=@PrentId and       
(cast(isnull(@Mobile,1) as nvarchar) in (select Mobile from #temp))                      
END       
end      
      
if (@leadn='')       
begin                     
if exists(select 1 from UserLeads where ParentID=@PrentId and (cast(isnull(NULLIF(@Email,''),1) as nvarchar) in (select email from #temp)))                      
BEGIN                    
select @leadn = leadno from UserLeads where ParentID=@PrentId        
and (cast(isnull(NULLIF(@Email,''),1) as nvarchar) in (select email from #temp))                    
END        
end      
      
                
INSERT INTO UserEnquiry                    
       ( PersonName,                    
         CountryCode,                    
         MobileNo,                    
         EmailID,                    
         ResidentialAddress,                    
         SourceName,                    
         MediumName,                    
         InitialRemarks,                    
         ParentID,                    
         CreatedDate,                    
         CreatedBy,                  
         CampaignName, LeadNo                   
       )                    
     VALUES                    
       (                    
         @Name,                    
         '+91',                    
         @Mobile,                    
         @Email,                    
         @Address,                    
         @Sourceid,                    
         @MediumID,                    
         @Remarks,                    
   @PrentId,                    
         GETDATE(),                    
         @userid ,'',@leadn                   
       )                    
 set @EnquiryID=SCOPE_IDENTITY()      
         
 update WebEntryTbl set enqueryId = @EnquiryID where EntryId= @entid                  
         
 declare @AutoLeadDistribution bit         
 sELECT @AutoLeadDistribution = AutoLeadDistribution FROM   CRMCampaignSettings            
 WHERE  UserID = @PrentId            
           
      
      
if (@AutoLeadDistribution = 1 and @leadn='')          
  begin          
  DECLARE @Leadno BIGINT = isnull((select MAX(LeadNo)                             
  FROM   UserLeads WHERE  ParentID = @PrentId),0)+1          
        
  Insert into userleads (LeadNo,PersonName,MobileNo,EmailID,City,PinCode,CountryCode,          
  OfficeAddress,AssignedTo,SourceName,MediumName,CampaignName,ParentID,          
  Remarks,CreatedOn,CreatedBy,FollowUpStatus,NextStatusDate)                
  select @leadno,@Name,@Mobile,@Email,'','','+91',@Address,          
  (select top 1 value from fn_Split((select agents from CRMCampaignSettings where userid=@PrentId),'#')           
  ORDER BY NEWID()),@Sourceid,@MediumID,'',@PrentId,@Remarks,GETDATE(),@PrentId,1,GETDATE()            
  declare @leadid bigint        
  --set @leadid=SCOPE_IDENTITY()          
        
  update UserEnquiry  set LeadNo=@LeadNo, IsOpen= 1 where EnquiryID=@EnquiryID        
        
  insert into  tbl_MergeLeadsEnquiry( EnquiryNo ,LeadNo,IsOpen) values (@EnquiryID,@Leadno,1)              
           
 end        
        
end                
if (@entid > 0)              
BEGIN              
if (@isenquery =0 and @Mobile <> '' )                
begin                
 exec [Usp_insertDeliverySMS_WebFrom] @entid, @FormId                
end               
if (@isenquery =0 and @Email <> '' )               
begin               
 exec [Usp_insertDeliveryMails_WebFrom] @entid, @FormId                
end              
end              
select @entid              
END                  
            
--select * from WebEntryTbl 


GO

/* ============================================================
   Procedure: [dbo].[usp_InsertWebEntryTbl_new_WithCountryCode]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_InsertWebEntryTbl_new_WithCountryCode] @PrentId BIGINT = 0
	,@FormName NVARCHAR(max) = ''
	,@Name NVARCHAR(max) = ''
	,@Mobile NVARCHAR(max) = ''
	,@Email NVARCHAR(max) = ''
	,@Address NVARCHAR(max) = ''
	,@Remarks NVARCHAR(max) = ''
	,@DynimicAttr NVARCHAR(max) = ''
	,@mail_body NVARCHAR(max) = ''
	,@msg_body NVARCHAR(max) = ''
	,@CampaignName NVARCHAR(max) = ''
	,@leadno BIGINT = 0
	,@CountryCode NVARCHAR(max) = ''
	,@EntityId BIGINT = 0
	,@EntityName NVARCHAR(50) = ''
	,@AgentId BIGINT = 0
	,@fieldvalues NVARCHAR(max) = NULL
	,@Country Nvarchar(max) = ''
	,@State nvarchar(max)=''
	,@City nvarchar(max)=''
	,@CompanyName nvarchar(max)=''
	,@PinCode nvarchar(max)=''
AS
BEGIN
	--declare 
	--	@PrentId BIGINT = 41643,
	--	@FormName NVARCHAR(max) = N'HoliOfferLead',
	--	@Name NVARCHAR(max) = N'Test',
	--	@Mobile NVARCHAR(max) = N'9879879879',
	--	@Email NVARCHAR(max) = N'test@gmail.com',
	--	@Address NVARCHAR(max)=N'',
	--	@Remarks NVARCHAR(max) =N'',
	--	@DynimicAttr NVARCHAR(max) =N'{"Name ":"Test";"Email":"test@gmail.com";"Mobile ":"9879879879";"CountryCode ":"+91";"Choose Offer ":"Offers on Apple Watch*";"Choose Store Location":"iFuture - Yamuna Nagar"}',
	--	@mail_body NVARCHAR(max) =N'',
	--	@msg_body NVARCHAR(max) =N'',
	--	@CampaignName NVARCHAR(max) =N'',
	--	@leadno BIGINT = 0,
	--	@CountryCode NVARCHAR(max) =N'+91',
	--	@EntityId BIGINT = 0,
	--	@EntityName NVARCHAR(max) = '',
	--	@AgentId BIGINT = 0,
	--	@fieldvalues NVARCHAR(max) = N'[{"FieldCtrl":"Name ","FieldValue":"Test"},{"FieldCtrl":"Email","FieldValue":"test@gmail.com"},{"FieldCtrl":"Mobile ","FieldValue":"9879879879"},{"FieldCtrl":"CountryCode ","FieldValue":"+91"},{"FieldCtrl":"Choose Offer ","FieldValue":"Offers on Apple Watch*"},{"FieldCtrl":"Choose Store Location","FieldValue":"iFuture - Yamuna Nagar"}]'
	
	  SELECT @fieldvalues =  REPLACE(REPLACE(@fieldvalues, CHAR(10), ''), CHAR(13), '') 
  


	if(len(@Remarks) > 1000)
	   begin
	       set @Remarks = left(@Remarks,1000);
	   end
	 
	if(isnull(@PinCode,'') = '')
	  begin
	    set @Pincode = '0'
	  end
	
	
	IF (@CountryCode = '')
	BEGIN
		SET @CountryCode = '+91'
	END

	DECLARE @mobileTemp NVARCHAR(max) = ''

	SET @mobileTemp = dbo.[fn_trimprefixes](@Mobile, '0');
	SET @Mobile = @mobileTemp

	DECLARE @entid BIGINT = 0;
	DECLARE @formid BIGINT = 0;
	DECLARE @MediumID BIGINT = 0;
	DECLARE @Sourceid BIGINT = 0;
	DECLARE @isenquery BIT;
	DECLARE @userid BIGINT = 0;
	DECLARE @EnquiryID BIGINT = 0;

	SET @isenquery = 0;

	SELECT @formid = formid
		,@MediumID = MediumID
		,@Sourceid = Sourceid
		,@isenquery = isEnquiry
		,@userid = userid
	FROM WebFormTbl(NOLOCK)
	WHERE ParentId = @PrentId
		AND FormName = @FormName;

	DECLARE @SequenceNumber BIGINT = (
			SELECT ISNULL(SequenceNumber, 1)
			FROM WebFormTbl(NOLOCK)
			WHERE FormId = @formid
			)

	IF (
			EXISTS (
				SELECT 1
				FROM WebEntryTbl(NOLOCK)
				WHERE FormId = @formid
				)
			)
	BEGIN
		SET @SequenceNumber = (
				SELECT ISNULL(max(EntryNo), @SequenceNumber) + 1
				FROM WebEntryTbl(NOLOCK)
				WHERE FormId = @formid
				)
	END

	INSERT INTO WebEntryTbl (
		FormId
		,Mobile
		,formname
		,Name
		,Email
		,Address
		,Remarks
		,Country
		,State
		,City
		,CompanyName
		,PinCode
		,DynimicAttr
		,mail_body
		,msg_body
		,CampaignName
		,CountryCode
		,EntityId
		,EntityName
		,AgentId
		,EntryNo
		)
	VALUES (
		@FormId
		,@Mobile
		,@formname
		,@Name
		,@Email
		,@Address
		,@Remarks
		,@Country
		,@State
		,@City
		,@CompanyName
		,@PinCode
		,@DynimicAttr
		,@mail_body
		,@msg_body
		,@CampaignName
		,@CountryCode
		,@EntityId
		,@EntityName
		,@AgentId
		,@SequenceNumber
		);

	SELECT @entid = SCOPE_IDENTITY();

	----------------------------------------------------------Altered By Rajneesh Mishra Dated 18/05/2022 ----------------------------------            
	DECLARE @data NVARCHAR(max) = @fieldvalues

	DROP TABLE

	IF EXISTS #tempCustom
		PRINT '#temp'

	CREATE TABLE #tempCustom (
		FieldCtrl nVARCHAR(200)
		,FieldValue nVARCHAR(200)
		)

	INSERT INTO #tempCustom (
		FieldCtrl
		,FieldValue
		)
	SELECT FieldCtrl
		,FieldValue
	FROM OPENJSON(@data) WITH (
			FieldCtrl nVARCHAR(200) '$.FieldCtrl'
			,FieldValue nVARCHAR(200) '$.FieldValue'
			)

	DROP TABLE

	IF EXISTS #temp2
		DECLARE @i INT = 1

	SELECT cf.*
		,(
			CASE 
				WHEN cf.datatype = 'f'
					THEN IIF(CAST(TP.FieldValue AS BIGINT) >= ISNULL(CAST(cf.minvalue AS BIGINT), - 2222222222222222)
							AND CAST(TP.FieldValue AS BIGINT) <= ISNULL(CAST(cf.maxvalue AS BIGINT), 2222222222222222), 1, 0)
				WHEN cf.datatype = 'd'
					THEN IIF(CAST(TP.FieldValue AS DATE) >= CAST(ISNULL(cf.minvalue, '') AS DATE)
							AND CAST(TP.FieldValue AS DATE) <= IIF(ISNULL(cf.maxvalue, '') <> '', cast(cf.maxvalue AS DATE), cast('9999-01-01' AS DATE)), 1, 0)
				WHEN cf.datatype IN (
						'r'
						,'s'
						,'l'
						)
					AND cf.choices IS NOT NULL
					THEN IIF(@i = (
								SELECT DISTINCT 1
								FROM dbo.fn_Split(cf.choices, ',')
								WHERE CAST(TP.FieldValue AS NVARCHAR(max)) = value
								), 1, 0)
				WHEN cf.datatype IN (
						'r'
						,'s'
						,'l'
						)
					AND cf.choices IS NULL
					THEN 1
				WHEN cf.datatype IN (
						'm'
						,'c'
						,'v'
						)
					THEN 1
				ELSE 0
				END
			) AS [status]
	INTO #temp2
	FROM #tempCustom tp(NOLOCK)
	JOIN tbl_CustomFieldWebFormFieldMapping cfwf(NOLOCK) 
	--ON tp.FieldCtrl = cfwf.CtrlName
	 on  REPLACE(REPLACE(tp.FieldCtrl, CHAR(10), ''), CHAR(13), '')
	   = REPLACE(REPLACE(cfwf.CtrlName, CHAR(10), ''), CHAR(13), '')
	
	JOIN customfields cf(NOLOCK) ON cf.field_ID = cfwf.FieldId
	WHERE cfwf.WebFormId = @formid
		AND cfwf.ParentId = @prentid

	IF EXISTS (
			SELECT DISTINCT 1
			FROM #temp2
			WHERE STATUS = 0
			)
	BEGIN
		INSERT INTO ErrorLogCustomField (
			FormId
			,FieldId
			,FieldType
			,ErrorMessage
			,UserId
			,EntryDate
			,fieldvaluejson
			,Entryid
			)
		SELECT @formid
			,field_ID
			,(
				CASE datatype
					WHEN 'd'
						THEN 'Date'
					WHEN 'f'
						THEN 'Numeric'
					WHEN 'v'
						THEN 'Text'
					WHEN 'r'
						THEN 'Radio'
					WHEN 'm'
						THEN 'Multiline'
					WHEN 's'
						THEN 'Select'
					WHEN 'c'
						THEN 'Checkbox'
					WHEN 'l'
						THEN 'List'
					END
				) AS FieldType
			,(
				CASE datatype
					WHEN 'd'
						THEN 'Date not in Custom Field Range'
					WHEN 'f'
						THEN 'Number not in Custom Field Range'
					WHEN 'r'
						THEN 'Value not matches with Custom Field Choices'
					WHEN 's'
						THEN 'Value not matches with Custom Field Choices'
					WHEN 'c'
						THEN 'Value not matches with  Custom Field Choices'
					WHEN 'l'
						THEN 'Value not matches with Custom Field Choices'
					ELSE 'Wrong Input Value'
					END
				) AS ErrorMessage
			,@userid
			,getdate()
			,@fieldvalues
			,@entid
		FROM #temp2
		WHERE STATUS = 0
	END
			-----------------------------------------------------------------------------------------------------------------------------------------------            
	ELSE
	BEGIN
		IF (@EntityId = 0)
		BEGIN
			IF @leadno = 0
				BEGIN
					IF EXISTS (SELECT 1 FROM UserLeads_mobile_email(NOLOCK) WHERE ParentID = @PrentId AND 
					((@mobile <> '' AND isnull(nullif(@Mobile, ''), '1') = Mobile AND @CountryCode <> ''
					  AND isnull(nullif(@CountryCode, ''), '3') = CountryCode) OR 
					  (@Email <> ''	AND isnull(nullif(@Email, ''), '2') = Email)))
					BEGIN
						SELECT TOP 1 @leadno = leadno
						FROM UserLeads_mobile_email(NOLOCK)
						WHERE ParentID = @PrentId AND 
					((@mobile <> '' AND isnull(nullif(@Mobile, ''), '1') = Mobile AND @CountryCode <> ''
					  AND isnull(nullif(@CountryCode, ''), '3') = CountryCode) OR 
					  (@Email <> ''	AND isnull(nullif(@Email, ''), '2') = Email))
                 	ORDER BY leadno desc
					END
				END
			
			IF (
					@isenquery = 1
					AND @entid > 0
					)
			BEGIN
				DECLARE @leadn VARCHAR(max) = ''

				

				INSERT INTO UserEnquiry (
					PersonName
					,CountryCode
					,MobileNo
					,EmailID
					,ResidentialAddress
					,Country
					,State
					,City
					,CompanyName
					,PinCode
					,SourceName
					,MediumName
					,InitialRemarks
					,ParentID
					,CreatedDate
					,CreatedBy
					,CampaignName
					,LeadNo
					,enquirysource
					)
				VALUES (
					@Name
					,@CountryCode
					,@Mobile
					,@Email
					,@Address
					,@Country
					,@State
					,@City
					,@CompanyName
					,@PinCode
					,@Sourceid
					,@MediumID
					,@Remarks
					,@PrentId
					,GETDATE()
					,@userid
					,0
					,@leadno
					,9
					)

				SET @EnquiryID = SCOPE_IDENTITY()

				INSERT INTO ParsedEnquiries (
					RawEnquiryId
					,EnquiryId
					,Parentid
					,Createddate
					,EnquirySource
					)
				SELECT @entid
					,@EnquiryID
					,@PrentId
					,getdate()
					,'Webform'

				UPDATE WebEntryTbl
				SET enqueryId = @EnquiryID
				WHERE EntryId = @entid

				---- ---------------------------------------------Altered By Rajneesh Mishra Dated 14/05/2022------------------------------------------             
				INSERT INTO customfieldEnquiryvalue (
					EnquiryID
					,fieldID
					,fieldvalue
					)
				SELECT @EnquiryID
					,cfwf.FieldId
					,tp.FieldValue
				FROM #tempCustom tp
					,tbl_CustomFieldWebFormFieldMapping cfwf
				WHERE tp.FieldCtrl = cfwf.CtrlName
					AND cfwf.WebFormId = @formid
					AND cfwf.ParentId = @PrentId

				---- ----------------------------------------------------------------------------------------------------------------------------------------            
				DECLARE @AutoLeadDistribution BIT

				SELECT @AutoLeadDistribution = AutoLeadDistribution
				FROM CRMCampaignSettings(NOLOCK)
				WHERE UserID = @PrentId

				IF (
						@AutoLeadDistribution = 1
						AND @leadno = 0
						)
				BEGIN
					SELECT @Leadno = isnull((
								SELECT MAX(LeadNo)
								FROM UserLeads(NOLOCK)
								WHERE ParentID = @PrentId
								), 0) + 1

                  
				  SET Context_Info 0x55555


					INSERT INTO userleads (
						LeadNo
						,PersonName
						,MobileNo
						,EmailID
						,City
						,PinCode
						,CountryCode
						,OfficeAddress
						,Country
						,State
						,CompanyName

						,AssignedTo
						,SourceName
						,MediumName
						,CampaignName
						,ParentID
						,Remarks
						,CreatedOn
						,CreatedBy
						,--FollowUpStatus,NextStatusDate,FollowupDate,              
						enquirysource
						,LastFollowupCreatedBy
						,LastFollowupCreatedOn
						)
					SELECT @leadno
						,@Name
						,@Mobile
						,@Email
						,@City
						,@PinCode
						,@CountryCode
						,@Address
						,@Country
						,@State
						,@CompanyName
						
						,(
							SELECT TOP 1 value
							FROM fn_Split((
										SELECT agents
										FROM CRMCampaignSettings
										WHERE userid = @PrentId
										), '#')
							ORDER BY NEWID()
							)
						,@Sourceid
						,@MediumID
						,0
						,@PrentId
						,@Remarks
						,GETDATE()
						,@PrentId
						,--1,GETDATE(),GETDATE(),              
						9
						,@PrentId
						,getdate()

					DECLARE @leadid BIGINT = SCOPE_IDENTITY()

					UPDATE UserEnquiry
					SET LeadNo = @LeadNo
						,IsOpen = 1
					WHERE EnquiryID = @EnquiryID

					---- -----------------------------------------------Altered By Rajneesh Mishra Dated 14/05/2022-------------------------------------------------------------            
					INSERT INTO customfieldLeadvalue (
						LeadID
						,fieldID
						,fieldvalue
						)
					SELECT @leadid
						,cfwf.FieldId
						,tp.FieldValue
					FROM #tempCustom tp
						,tbl_CustomFieldWebFormFieldMapping cfwf
					WHERE tp.FieldCtrl = cfwf.CtrlName
						AND cfwf.WebFormId = @formid
						AND cfwf.ParentId = @PrentId

					---- -----------------------------------------------------------------------------------------------------------------------------------------------------------            
				   INSERT INTO tbl_MergeLeadsEnquiry (
						EnquiryNo
						,LeadNo
						,IsOpen
						)
					VALUES (
						@EnquiryID
						,@Leadno
						,1
						)

					Exec mysms.dbo.usp_ExecLeadTriggerTasks @leadid
					SET Context_Info 0x  

				 	EXEC Usp_insertdefaultfollowup @prentid
						,@leadid
				END
			END

			IF (@entid > 0)
			BEGIN
				IF (
						@isenquery = 0
						AND @Mobile <> ''
						)
				BEGIN
					EXEC [Usp_insertDeliverySMS_WebFrom] @entid
						,@FormId
						,@msg_body
				END

				IF (
						@isenquery = 0
						AND @Email <> ''
						)
				BEGIN
					EXEC [Usp_insertDeliveryMails_WebFrom] @entid
						,@FormId
						,@mail_body
				END
			END
		END
		ELSE
		BEGIN
			SET @leadno = (
					SELECT LeadNo
					FROM UserLeads(NOLOCK)
					WHERE ID = @EntityId
					)
		END
	END

	--            
	IF (@FormId = 2456)
	BEGIN
		EXEC usp_Tbl_BM_General_Delivery @PrentId
			,@Mobile
			,CountryCode
			,@Sourceid
			,'WebEntryTbl'
			,@entid
			,'EntryId'
			,'Web Form Created'
			,0
			,NULL
			--   @SourceName, @TableName, @ColumnId, @ColumnName, @MsgContent,             
	END

	--            
	/* Start lead activity  Lead filled web form */
	BEGIN TRY
		DECLARE @UserID_LDACTV BIGINT = @userid
		DECLARE @ParentID_LDACTV BIGINT = @PrentId
		DECLARE @LeadID_LDACTV BIGINT = 0
		DECLARE @Cname NVARCHAR(500) = @FormName

		SELECT TOP 1 @LeadID_LDACTV = isnull(ID, 0)
		FROM UserLeads(NOLOCK)
		WHERE LeadNo = @leadno
			AND ParentID = @ParentID_LDACTV

		DROP TABLE

		IF EXISTS #tblEventDescrb
			CREATE TABLE #tblEventDescrb (EVNT_Description NVARCHAR(max))

		IF (isnull(@LeadID_LDACTV, 0) > 0)
		BEGIN
			INSERT INTO #tblEventDescrb
			EXEC Usp_EventTemplate_DynamicVarReplacement 'Lead filled web form'
				,@UserID_LDACTV
				,''
				,''
				,@LeadID_LDACTV
				,''
				,NULL
				,0
				,0
				,''
				,''
				,0
				,''
				,0
				,NULL
				,NULL
				,NULL
				,NULL
				,NULL
				,NULL
				,NULL
				,NULL
				,NULL
				,NULL
				,NULL
				,NULL
				,NULL
				,NULL
				,NULL
				,NULL
				,NULL
				,0
				,0
				,0
				,NULL
				,NULL
				,NULL
				,0
				,NULL
				,NULL
				,@Cname
				,0
				,NULL
				,NULL

			DECLARE @evntMessage NVARCHAR(max) = ''

			SELECT @evntMessage = isnull(EVNT_Description, '')
			FROM #tblEventDescrb

			IF (@evntMessage <> '')
			BEGIN
				EXEC UspSaveLeadActivity_withid @LeadID_LDACTV
					,@UserID_LDACTV
					,@ParentID_LDACTV
					,@evntMessage
					,'Lead filled web form'
					,'WebEntryTbl'
					,@entid
			END
		END
	END TRY

	BEGIN CATCH
		EXEC usp_insertErrorInfo
	END CATCH

	IF OBJECT_ID('tempdb..#tblEventDescrb') IS NOT NULL -- Check for table existence                              
	BEGIN
		DROP TABLE #tblEventDescrb
	END

	--Drop table #tblEventDescrb                   
	/* End Lead Activity Lead filled web form */
	SELECT @entid

	DECLARE @RowJson NVARCHAR(MAX) = (
			SELECT *
			FROM WebEntryTbl
			WHERE EntryId = @entid
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			);

	IF @rowJson IS NOT NULL
	BEGIN
