/* ============================================================
   Procedure: [dbo].[usp_InsertWebsiteInteractions]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_InsertWebsiteInteractions](
	@InteractionJson nvarchar(max),
	@ParentId bigint,
	@UserId bigint,
	@ConnectionId nvarchar(max),
	@SessionId bigint
)
as
begin
	
	declare @WebsiteIntegractionId bigint = 0;

	if(exists(
		select * from tbl_WebsiteInteractions(nolock) where ParentId = @ParentId and UserId = @UserId and SessionId = @SessionId
	))
	begin
		
		select @WebsiteIntegractionId = Id from tbl_WebsiteInteractions(nolock) where ParentId = @ParentId and UserId = @UserId and SessionId = @SessionId
	end

	if(@WebsiteIntegractionId > 0)
	begin

		update w set
			w.InteractionJson = l.InteractionJson,
			w.loadTime = l.loadTime,
			w.unloadTime = l.unloadTime,
			w.language = l.language,
			w.platform = l.platform,
			w.pageHref = l.pageHref, 
			w.pageTitle = l.pageTitle, 
			w.clientStart = l.clientStart,
			w.page = l.page,
			w.interactions = l.interactions,
			w.clientEnd = l.clientEnd,
			w.LastUpdateOn = GETDATE(),
			w.ConnectionId = l.ConnectionId
		from (
			select @InteractionJson as InteractionJson, @ParentId as ParentId, @UserId as UserId, loadTime, unloadTime, 
				language, platform, pageHref, pageTitle, clientStart, Page, interactions, clientEnd, @ConnectionId as ConnectionId, @SessionId as SessionId
			from openjson(@InteractionJson) with (
				loadTime datetime '$.loadTime',
				unloadTime datetime '$.unloadTime',
				language nvarchar(255) '$.language',
				platform nvarchar(255) '$.platform',
				pageHref nvarchar(255) '$.page.href',
				pageTitle nvarchar(255) '$.page.title',
				clientStart nvarchar(max) '$.clientStart' as json,
				page nvarchar(max) '$.page' as json,
				interactions nvarchar(max) '$.interactions' as json,
				interactions nvarchar(max) '$.interactions' as json,
				clientEnd nvarchar(max) '$.clientEnd' as json
			)) l inner join tbl_WebsiteInteractions(nolock) w 
				on l.ParentId = w.ParentId and l.UserId = w.UserId and l.SessionId = w.SessionId
			where w.Id = @WebsiteIntegractionId
	end
	else
	begin
		insert into tbl_WebsiteInteractions(InteractionJson, ParentId, UserId, loadTime, unloadTime, language, platform,
			pageHref, pageTitle, clientStart, page, interactions, clientEnd, ConnectionId, SessionId)
		select @InteractionJson, @ParentId, @UserId, loadTime, unloadTime, language, platform, pageHref, pageTitle,
				clientStart, Page, interactions, clientEnd, @ConnectionId, @SessionId
			from openjson(@InteractionJson) with (
				loadTime datetime '$.loadTime',
				unloadTime datetime '$.unloadTime',
				language nvarchar(255) '$.language',
				platform nvarchar(255) '$.platform',
				pageHref nvarchar(255) '$.page.href',
				pageTitle nvarchar(255) '$.page.title',
				clientStart nvarchar(max) '$.clientStart' as json,
				page nvarchar(max) '$.page' as json,
				interactions nvarchar(max) '$.interactions' as json,
				interactions nvarchar(max) '$.interactions' as json,
				clientEnd nvarchar(max) '$.clientEnd' as json
			)

		set @WebsiteIntegractionId = SCOPE_IDENTITY();
		
	end

	if(@WebsiteIntegractionId > 0) 
	begin
		insert into tbl_WebsiteInteractionHistory(InteractionJson, ParentId, UserId, loadTime, unloadTime, language, platform, pageHref, pageTitle, clientStart, page, interactions, clientEnd, ConnectionId, SessionId, WebsiteInteractionId, CreatedOn, LastUpdateOn)
		select @InteractionJson, @ParentId, @UserId, loadTime, unloadTime, language, platform, pageHref, pageTitle,
				clientStart, Page, interactions, clientEnd, @ConnectionId, @SessionId, @WebsiteIntegractionId, GETDATE(), GETDATE()
			from openjson(@InteractionJson) with (
				loadTime datetime '$.loadTime',
				unloadTime datetime '$.unloadTime',
				language nvarchar(255) '$.language',
				platform nvarchar(255) '$.platform',
				pageHref nvarchar(255) '$.page.href',
				pageTitle nvarchar(255) '$.page.title',
				clientStart nvarchar(max) '$.clientStart' as json,
				page nvarchar(max) '$.page' as json,
				interactions nvarchar(max) '$.interactions' as json,
				interactions nvarchar(max) '$.interactions' as json,
				clientEnd nvarchar(max) '$.clientEnd' as json
			)
	end

end



