/* ============================================================
   Procedure: [dbo].[usp_Int_DeleveryReport]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_Int_DeleveryReport]          
    @User_Id INT,                                   
    @fromDate VARCHAR(20),                        
    @todate VARCHAR(20),      
    @Mobile VARCHAR(20) = '',      
    @Msz VARCHAR(255) = '',      
    @status VARCHAR(50) = '',      
    @SenderId VARCHAR(50) = ''      
AS                   
BEGIN                               
    DECLARE @TimeZoneName NVARCHAR(255) = ISNULL(          
        (SELECT TimeZone           
         FROM User_Detail (NOLOCK)           
         WHERE User_ID = @User_Id),           
        'India Standard Time'          
    );               
      
    -- Step 1: Fetch all records from Tbl_MassOperationSummary for 'Send InternationalSMS'      
    WITH MassOperationBatches AS (      
        SELECT       
            MOS.BatchID,      
            MOS.EntityType,      
            Details.EntityID,      
            MOS.SenderID,      
            MOS.metadata AS Message,      
            MOS.Remarks,      
            MOS.CreatedDate,      
            MOS.ErrorDetails      
        FROM       
            Tbl_MassOperationSummary MOS (NOLOCK)      
        INNER JOIN       
            Tbl_MassOperationDetails Details (NOLOCK)      
            ON MOS.BatchID = Details.SummaryId      
        WHERE       
            MOS.UserID = @User_Id      
            AND MOS.MassOperationName = 'Send InternationalSMS'  
   and MOS.IsProcessed=1 and MOS.isvalid=1  
            AND CAST(MOS.CreatedDate AS DATE) BETWEEN CAST(@fromDate AS DATE) AND CAST(@todate AS DATE)      
    )      
      
    -- Step 2: Fetch records from Int_MessageDeliveryStatus for processed entity IDs      
    SELECT      
        ROW_NUMBER() OVER (ORDER BY MDS.MessageDeliveryStatusID) AS SrNo,  -- Adding row number      
        --CASE       
        --    WHEN MOB.EntityType = 'lead' THEN CONCAT(RTRIM(LTRIM(Lead.CountryCode)), ' ', Lead.MobileNo)      
        --    WHEN MOB.EntityType = 'enquiry' THEN CONCAT(RTRIM(LTRIM(Enquiry.CountryCode)), ' ', Enquiry.MobileNo)      
        --    ELSE NULL      
        --END AS Mobile,       
   CONCAT(RTRIM(LTRIM(MDS.CountryCode)), ' ', MDS.Mobile) AS Mobile,     
        MDS.Message,           
        MDS.SenderID,          
        ISNULL(      
            CASE         
                WHEN MDS.MessageStatus = '6' THEN 'Invalid'         
                WHEN MDS.MessageStatus = '200' THEN 'DELIVER'         
                WHEN MDS.MessageStatus = '-108' THEN 'Insufficient Balance'         
                WHEN MDS.MessageStatus = 'NULL' THEN 'Sent'          
                WHEN MDS.MessageStatus = '5' THEN 'Blacklisted'         
                WHEN MDS.MessageStatus = '7' THEN 'Sent'         
                WHEN MDS.MessageStatus = 'DND_check_failed' THEN 'Sent'          
                WHEN MDS.MessageStatus = '9' THEN 'UNDELIV'         
                WHEN MDS.MessageStatus = '' THEN 'Sent'         
                ELSE MDS.MessageStatus         
            END, 'Sent') AS StatusDescription,      
      
        CASE         
            -- If Mobile is null or blank, mark the status as 'Failed'      
            WHEN Mobile IS NULL OR Mobile = '' THEN 'Failed'      
            WHEN MDS.MessageStatus = '200' THEN 'Delivered'         
            WHEN MDS.MessageStatus IN ('6', '-108', '5', '9', 'NonDeliverable CountryCode', 'Invalid MobileNo','NonDeliverable CountryCode') THEN 'Failed'         
            ELSE 'Sent'         
        END AS MessageStatus,        
      
        Mysms.dbo.fn_ConvertDateTime(MDS.MessageInsertDate, @TimeZoneName, 0) AS MessageDeliveredDate,          
        MDS.LastError,          
        CAST(MDS.MessageInsertDate AS DATE) AS InsertDate,      
        'Processed' AS ProcessStatus -- Indicate these records are processed      
    FROM       
        Int_MessageDeliveryStatus MDS (NOLOCK)      
    INNER JOIN       
        MassOperationBatches MOB      
        ON MDS.MassOpBatchID = MOB.BatchID      
        AND MDS.EntityID = MOB.EntityID      
    LEFT JOIN       
        UserLeads Lead (NOLOCK)      
        ON MOB.EntityID = Lead.ID      
    LEFT JOIN       
        UserEnquiry Enquiry (NOLOCK)      
        ON MOB.EntityID = Enquiry.EnquiryID      
    WHERE             --((LTRIM(RTRIM(Lead.MobileNo)) = @Mobile OR @Mobile = '') OR (LTRIM(RTRIM(Enquiry.MobileNo)) = @Mobile OR @Mobile = ''))     
   (CONCAT(RTRIM(LTRIM(MDS.CountryCode)), ' ', MDS.Mobile) LIKE '%' + @Mobile + '%' OR @Mobile = '')    
        AND (MDS.Message LIKE '%' + @Msz + '%' OR @Msz = '')    
  --AND (MessageStatus LIKE '%' + @status + '%' OR @status = '')   
  AND (  
    CASE   
        WHEN Mobile IS NULL OR Mobile = '' THEN 'Failed'      
        WHEN MDS.MessageStatus = '200' THEN 'Delivered'         
        WHEN MDS.MessageStatus IN ('6', '-108', '5', '9', 'NonDeliverable CountryCode', 'Invalid MobileNo', 'NonDeliverable CountryCode') THEN 'Failed'         
        ELSE 'Sent'         
    END LIKE '%' + @status + '%' OR @status = ''  
)  
  AND (MDS.SenderID LIKE '%' + @SenderId + '%' OR @SenderId = '')    
        AND CAST(MDS.MessageInsertDate AS DATE) BETWEEN CAST(@fromDate AS DATE) AND CAST(@todate AS DATE)      
          
    UNION ALL      
          
    -- Step 3: Fetch records from Tbl_MassOperationSummary that are not processed (not in Int_MessageDeliveryStatus)      
    SELECT      
        ROW_NUMBER() OVER (ORDER BY MOB.BatchID) AS SrNo,  -- Adding row number for unprocessed batches      
        CASE       
            WHEN MOB.EntityType = 'lead' THEN CONCAT(RTRIM(LTRIM(Lead.CountryCode)), ' ', Lead.MobileNo)      
            WHEN MOB.EntityType = 'enquiry' THEN CONCAT(RTRIM(LTRIM(Enquiry.CountryCode)), ' ', Enquiry.MobileNo)      
            ELSE NULL      
        END AS Mobile,       
        MOB.Message,           
        MOB.SenderID,          
    --     CASE   
    --    WHEN (Lead.MobileNo IS NULL OR LTRIM(RTRIM(Lead.MobileNo)) = '' OR ISNUMERIC(Lead.MobileNo) = 0)  
    --      OR (Enquiry.MobileNo IS NULL OR LTRIM(RTRIM(Enquiry.MobileNo)) = '' OR ISNUMERIC(Enquiry.MobileNo) = 0)   
    --      THEN 'Invalid Mobile No'  
  
    --    WHEN (Lead.MobileNo IS NOT NULL AND LEN(LTRIM(RTRIM(Lead.MobileNo))) > 10)   
    --      OR (Enquiry.MobileNo IS NOT NULL AND LEN(LTRIM(RTRIM(Enquiry.MobileNo))) > 10)  
    --      THEN 'Invalid Mobile No'  
  
    --    WHEN (Lead.CountryCode = '+91' OR Enquiry.CountryCode = '+91')  
    --      THEN 'Non-Deliverable Country Code'  
  
    --    ELSE MOB.Remarks  
    --END AS StatusDescription,    
 CASE
        -- Check if the mobile number is NULL or empty
        --WHEN (Mobile IS NULL OR Mobile = '')
        --    THEN 'Invalid Mobile No'
        
        -- Check if the mobile number starts with '+91', marking it as an invalid country code
        WHEN (Mobile LIKE '+91%')
            THEN 'Invalid Country Code'
        
        -- If the mobile number starts with '+61', show `MOB.Remarks`
        WHEN (Mobile LIKE '+61%')
            THEN 'Valid Mobile No with remarks: ' + ISNULL(MOB.Remarks, 'No Remarks')
        
        -- Default case, return `MOB.Remarks` if none of the above conditions match
        ELSE ISNULL(MOB.Remarks, 'No Remarks')
    END AS StatusDescription,
        CASE         
            -- If Mobile is null or blank, mark the status as 'Failed'      
            WHEN (Lead.MobileNo IS NULL OR LTRIM(RTRIM(Lead.MobileNo)) = '')       
                 AND (Enquiry.MobileNo IS NULL OR LTRIM(RTRIM(Enquiry.MobileNo)) = '')       
                 THEN 'Failed'      
            WHEN (MOB.Remarks IS NULL OR LTRIM(RTRIM(MOB.Remarks)) = '')       
                 OR (ISNULL(StatusDescription, '') = '')  -- Explicitly check StatusDescription for blank or null      
                 THEN 'Failed'      
            WHEN MOB.Remarks = 'Record save' THEN 'Delivered'         
            WHEN MOB.Remarks IN ('You have insufficient balance', 'We do not serve SMS to this country.') THEN 'Failed'         
            ELSE 'Sent'         
        END AS MessageStatus,     
      
        Mysms.dbo.fn_ConvertDateTime(MOB.CreatedDate, @TimeZoneName, 0) AS MessageDeliveredDate,          
        MOB.ErrorDetails AS LastError,          
        CAST(MOB.CreatedDate AS DATE) AS InsertDate,      
        'Not Processed' AS ProcessStatus -- Indicate these records are not processed      
    FROM       
        MassOperationBatches MOB      
    LEFT JOIN       
        Int_MessageDeliveryStatus MDS (NOLOCK)      
        ON MDS.MassOpBatchID = MOB.BatchID      
        AND MDS.EntityID = MOB.EntityID      
    LEFT JOIN       
        UserLeads Lead (NOLOCK)      
        ON MOB.EntityID = Lead.ID      
    LEFT JOIN       
        UserEnquiry Enquiry (NOLOCK)      
        ON MOB.EntityID = Enquiry.EnquiryID      
    WHERE       
        MDS.EntityID IS NULL      
        AND (CONCAT(RTRIM(LTRIM(Lead.CountryCode)), ' ', LTRIM(RTRIM(Lead.MobileNo))) LIKE '%' + @Mobile + '%' OR @Mobile = '')       AND (CONCAT(RTRIM(LTRIM(Enquiry.CountryCode)), ' ', LTRIM(RTRIM(Enquiry.MobileNo))) LIKE '%' + @Mobile + '%' OR @Mobile =  '')      
       AND (MOB.Message LIKE '%' + @Msz + '%' OR @Msz = '')       
    --AND (MessageStatus LIKE '%' + @status + '%' OR @status = '')     
    AND (  
    CASE   
        WHEN (Lead.MobileNo IS NULL OR LTRIM(RTRIM(Lead.MobileNo)) = '')       
            AND (Enquiry.MobileNo IS NULL OR LTRIM(RTRIM(Enquiry.MobileNo)) = '')       
            THEN 'Failed'      
        WHEN (MOB.Remarks IS NULL OR LTRIM(RTRIM(MOB.Remarks)) = '')       
            OR (ISNULL(StatusDescription, '') = '')    
            THEN 'Failed'      
        WHEN MOB.Remarks = 'Record save' THEN 'Delivered'         
        WHEN MOB.Remarks IN ('You have insufficient balance', 'We do not serve SMS to this country.') THEN 'Failed'         
        ELSE 'Sent'         
    END LIKE '%' + @status + '%' OR @status = ''  
)  
    AND (MOB.SenderID LIKE '%' + @SenderId + '%' OR @SenderId = '')     
        AND CAST(MOB.CreatedDate AS DATE) BETWEEN CAST(@fromDate AS DATE) AND CAST(@todate AS DATE);      
END;   


GO

/* ============================================================
   Procedure: [dbo].[usp_Int_DeleveryReport_Pagination]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_Int_DeleveryReport_Pagination]          
    @User_Id INT,                                   
    @fromDate VARCHAR(20),                        
    @todate VARCHAR(20),      
    @Mobile VARCHAR(20) = '',      
    @Msz VARCHAR(255) = '',      
    @status VARCHAR(50) = '',      
    @SenderId VARCHAR(50) = ''      
AS                   
BEGIN                               
    DECLARE @TimeZoneName NVARCHAR(255) = ISNULL(          
        (SELECT TimeZone           
         FROM User_Detail (NOLOCK)           
         WHERE User_ID = @User_Id),           
        'India Standard Time'          
    );               
      
    -- Step 1: Fetch all records from Tbl_MassOperationSummary for 'Send InternationalSMS'      
    WITH MassOperationBatches AS (      
        SELECT       
            MOS.BatchID,      
            MOS.EntityType,      
            Details.EntityID,      
            MOS.SenderID,      
            MOS.metadata AS Message,      
            MOS.Remarks,      
            MOS.CreatedDate,      
            MOS.ErrorDetails      
        FROM       
            Tbl_MassOperationSummary MOS (NOLOCK)      
        INNER JOIN       
            Tbl_MassOperationDetails Details (NOLOCK)      
            ON MOS.BatchID = Details.SummaryId      
        WHERE       
            MOS.UserID = @User_Id      
            AND MOS.MassOperationName = 'Send InternationalSMS'  
   and MOS.IsProcessed=1 and MOS.isvalid=1  
            AND CAST(MOS.CreatedDate AS DATE) BETWEEN CAST(@fromDate AS DATE) AND CAST(@todate AS DATE)      
    )      
      
    -- Step 2: Fetch records from Int_MessageDeliveryStatus for processed entity IDs      
    SELECT      
        ROW_NUMBER() OVER (ORDER BY MDS.MessageDeliveryStatusID) AS SrNo,  -- Adding row number      
        --CASE       
        --    WHEN MOB.EntityType = 'lead' THEN CONCAT(RTRIM(LTRIM(Lead.CountryCode)), ' ', Lead.MobileNo)      
        --    WHEN MOB.EntityType = 'enquiry' THEN CONCAT(RTRIM(LTRIM(Enquiry.CountryCode)), ' ', Enquiry.MobileNo)      
        --    ELSE NULL      
        --END AS Mobile,       
   CONCAT(RTRIM(LTRIM(MDS.CountryCode)), ' ', MDS.Mobile) AS Mobile,     
        MDS.Message,           
        MDS.SenderID,          
        ISNULL(      
            CASE         
                WHEN MDS.MessageStatus = '6' THEN 'Invalid'         
                WHEN MDS.MessageStatus = '200' THEN 'DELIVER'         
                WHEN MDS.MessageStatus = '-108' THEN 'Insufficient Balance'         
                WHEN MDS.MessageStatus = 'NULL' THEN 'Sent'          
                WHEN MDS.MessageStatus = '5' THEN 'Blacklisted'         
                WHEN MDS.MessageStatus = '7' THEN 'Sent'         
                WHEN MDS.MessageStatus = 'DND_check_failed' THEN 'Sent'          
                WHEN MDS.MessageStatus = '9' THEN 'UNDELIV'         
                WHEN MDS.MessageStatus = '' THEN 'Sent'         
                ELSE MDS.MessageStatus         
            END, 'Sent') AS StatusDescription,      
      
        CASE         
            -- If Mobile is null or blank, mark the status as 'Failed'      
            WHEN Mobile IS NULL OR Mobile = '' THEN 'Failed'      
            WHEN MDS.MessageStatus = '200' THEN 'Delivered'         
            WHEN MDS.MessageStatus IN ('6', '-108', '5', '9', 'NonDeliverable CountryCode', 'Invalid MobileNo','NonDeliverable CountryCode') THEN 'Failed'         
            ELSE 'Sent'         
        END AS MessageStatus,        
      
        Mysms.dbo.fn_ConvertDateTime(MDS.MessageInsertDate, @TimeZoneName, 0) AS MessageDeliveredDate,          
        MDS.LastError,          
        CAST(MDS.MessageInsertDate AS DATE) AS InsertDate,      
        'Processed' AS ProcessStatus -- Indicate these records are processed      
    FROM       
        Int_MessageDeliveryStatus MDS (NOLOCK)      
    INNER JOIN       
        MassOperationBatches MOB      
        ON MDS.MassOpBatchID = MOB.BatchID      
        AND MDS.EntityID = MOB.EntityID      
    LEFT JOIN       
        UserLeads Lead (NOLOCK)      
        ON MOB.EntityID = Lead.ID      
    LEFT JOIN       
        UserEnquiry Enquiry (NOLOCK)      
        ON MOB.EntityID = Enquiry.EnquiryID      
    WHERE             --((LTRIM(RTRIM(Lead.MobileNo)) = @Mobile OR @Mobile = '') OR (LTRIM(RTRIM(Enquiry.MobileNo)) = @Mobile OR @Mobile = ''))     
   (CONCAT(RTRIM(LTRIM(MDS.CountryCode)), ' ', MDS.Mobile) LIKE '%' + @Mobile + '%' OR @Mobile = '')    
        AND (MDS.Message LIKE '%' + @Msz + '%' OR @Msz = '')    
  --AND (MessageStatus LIKE '%' + @status + '%' OR @status = '')   
  AND (  
    CASE   
        WHEN Mobile IS NULL OR Mobile = '' THEN 'Failed'      
        WHEN MDS.MessageStatus = '200' THEN 'Delivered'         
        WHEN MDS.MessageStatus IN ('6', '-108', '5', '9', 'NonDeliverable CountryCode', 'Invalid MobileNo', 'NonDeliverable CountryCode') THEN 'Failed'         
        ELSE 'Sent'         
    END LIKE '%' + @status + '%' OR @status = ''  
)  
  AND (MDS.SenderID LIKE '%' + @SenderId + '%' OR @SenderId = '')    
        AND CAST(MDS.MessageInsertDate AS DATE) BETWEEN CAST(@fromDate AS DATE) AND CAST(@todate AS DATE)      
          
    UNION ALL      
          
    -- Step 3: Fetch records from Tbl_MassOperationSummary that are not processed (not in Int_MessageDeliveryStatus)      
    SELECT      
        ROW_NUMBER() OVER (ORDER BY MOB.BatchID) AS SrNo,  -- Adding row number for unprocessed batches      
        CASE       
            WHEN MOB.EntityType = 'lead' THEN CONCAT(RTRIM(LTRIM(Lead.CountryCode)), ' ', Lead.MobileNo)      
            WHEN MOB.EntityType = 'enquiry' THEN CONCAT(RTRIM(LTRIM(Enquiry.CountryCode)), ' ', Enquiry.MobileNo)      
            ELSE NULL      
        END AS Mobile,       
        MOB.Message,           
        MOB.SenderID,          
    --     CASE   
    --    WHEN (Lead.MobileNo IS NULL OR LTRIM(RTRIM(Lead.MobileNo)) = '' OR ISNUMERIC(Lead.MobileNo) = 0)  
    --      OR (Enquiry.MobileNo IS NULL OR LTRIM(RTRIM(Enquiry.MobileNo)) = '' OR ISNUMERIC(Enquiry.MobileNo) = 0)   
    --      THEN 'Invalid Mobile No'  
  
    --    WHEN (Lead.MobileNo IS NOT NULL AND LEN(LTRIM(RTRIM(Lead.MobileNo))) > 10)   
    --      OR (Enquiry.MobileNo IS NOT NULL AND LEN(LTRIM(RTRIM(Enquiry.MobileNo))) > 10)  
    --      THEN 'Invalid Mobile No'  
  
    --    WHEN (Lead.CountryCode = '+91' OR Enquiry.CountryCode = '+91')  
    --      THEN 'Non-Deliverable Country Code'  
  
    --    ELSE MOB.Remarks  
    --END AS StatusDescription,    
 CASE
        -- Check if the mobile number is NULL or empty
        --WHEN (Mobile IS NULL OR Mobile = '')
        --    THEN 'Invalid Mobile No'
        
        -- Check if the mobile number starts with '+91', marking it as an invalid country code
        WHEN (Mobile LIKE '+91%')
            THEN 'Invalid Country Code'
        
        -- If the mobile number starts with '+61', show `MOB.Remarks`
        WHEN (Mobile LIKE '+61%')
            THEN 'Valid Mobile No with remarks: ' + ISNULL(MOB.Remarks, 'No Remarks')
        
        -- Default case, return `MOB.Remarks` if none of the above conditions match
        ELSE ISNULL(MOB.Remarks, 'No Remarks')
    END AS StatusDescription,
        CASE         
            -- If Mobile is null or blank, mark the status as 'Failed'      
            WHEN (Lead.MobileNo IS NULL OR LTRIM(RTRIM(Lead.MobileNo)) = '')       
                 AND (Enquiry.MobileNo IS NULL OR LTRIM(RTRIM(Enquiry.MobileNo)) = '')       
                 THEN 'Failed'      
            WHEN (MOB.Remarks IS NULL OR LTRIM(RTRIM(MOB.Remarks)) = '')       
                 OR (ISNULL(StatusDescription, '') = '')  -- Explicitly check StatusDescription for blank or null      
                 THEN 'Failed'      
            WHEN MOB.Remarks = 'Record save' THEN 'Delivered'         
            WHEN MOB.Remarks IN ('You have insufficient balance', 'We do not serve SMS to this country.') THEN 'Failed'         
            ELSE 'Sent'         
        END AS MessageStatus,     
      
        Mysms.dbo.fn_ConvertDateTime(MOB.CreatedDate, @TimeZoneName, 0) AS MessageDeliveredDate,          
        MOB.ErrorDetails AS LastError,          
        CAST(MOB.CreatedDate AS DATE) AS InsertDate,      
        'Not Processed' AS ProcessStatus -- Indicate these records are not processed      
    FROM       
        MassOperationBatches MOB      
    LEFT JOIN       
        Int_MessageDeliveryStatus MDS (NOLOCK)      
        ON MDS.MassOpBatchID = MOB.BatchID      
        AND MDS.EntityID = MOB.EntityID      
    LEFT JOIN       
        UserLeads Lead (NOLOCK)      
        ON MOB.EntityID = Lead.ID      
    LEFT JOIN       
        UserEnquiry Enquiry (NOLOCK)      
        ON MOB.EntityID = Enquiry.EnquiryID      
    WHERE       
        MDS.EntityID IS NULL      
        AND (CONCAT(RTRIM(LTRIM(Lead.CountryCode)), ' ', LTRIM(RTRIM(Lead.MobileNo))) LIKE '%' + @Mobile + '%' OR @Mobile = '')       AND (CONCAT(RTRIM(LTRIM(Enquiry.CountryCode)), ' ', LTRIM(RTRIM(Enquiry.MobileNo))) LIKE '%' + @Mobile + '%' OR @Mobile =  '')      
       AND (MOB.Message LIKE '%' + @Msz + '%' OR @Msz = '')       
    --AND (MessageStatus LIKE '%' + @status + '%' OR @status = '')     
    AND (  
    CASE   
        WHEN (Lead.MobileNo IS NULL OR LTRIM(RTRIM(Lead.MobileNo)) = '')       
            AND (Enquiry.MobileNo IS NULL OR LTRIM(RTRIM(Enquiry.MobileNo)) = '')       
            THEN 'Failed'      
        WHEN (MOB.Remarks IS NULL OR LTRIM(RTRIM(MOB.Remarks)) = '')       
            OR (ISNULL(StatusDescription, '') = '')    
            THEN 'Failed'      
        WHEN MOB.Remarks = 'Record save' THEN 'Delivered'         
        WHEN MOB.Remarks IN ('You have insufficient balance', 'We do not serve SMS to this country.') THEN 'Failed'         
        ELSE 'Sent'         
    END LIKE '%' + @status + '%' OR @status = ''  
)  
    AND (MOB.SenderID LIKE '%' + @SenderId + '%' OR @SenderId = '')     
        AND CAST(MOB.CreatedDate AS DATE) BETWEEN CAST(@fromDate AS DATE) AND CAST(@todate AS DATE);      
END;   


GO

/* ============================================================
   Procedure: [dbo].[usp_Int_DeleveryReport_Pagination1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_Int_DeleveryReport_Pagination1] --34594, '01-Jan-2026','26-Jan-2026','','','','',1,50           
    @User_Id bigINT,                                   
    @fromDate VARCHAR(20),                        
    @todate VARCHAR(20),      
    @Mobile VARCHAR(20) = '',      
    @Msz VARCHAR(255) = '',      
    @status VARCHAR(50) = '',      
    @SenderId VARCHAR(50) = '',
    @PageNumber INT = 1,
    @PageSize   INT = 50
AS                   
BEGIN                               
    DECLARE @TimeZoneName NVARCHAR(255) = ISNULL(          
        (SELECT TimeZone           
         FROM User_Detail (NOLOCK)           
         WHERE User_ID = @User_Id),           
        'India Standard Time'          
    );               
      

       drop table if exists #DeliveryTemp

    /* ================= TEMP TABLE ================= */
    CREATE TABLE #DeliveryTemp
    (
       --BatchId        BIGINT,
       SrNo           Bigint,    
       Mobile         VARCHAR(20),
       Message        VARCHAR(500),

       SenderId       VARCHAR(50),
        --Status
       StatusDescription VARCHAR(50),
         --SentDateTime
       InsertDate DATETIME,
        --DeliveredDate  DATETIME
       MessageDeliveredDate  DATETIME
    );




    -- Step 1: Fetch all records from Tbl_MassOperationSummary for 'Send InternationalSMS'      
    WITH MassOperationBatches AS (      
        SELECT       
            MOS.BatchID,      
            MOS.EntityType,      
            Details.EntityID,      
            MOS.SenderID,      
            MOS.metadata AS Message,      
            MOS.Remarks,      
            MOS.CreatedDate,      
            MOS.ErrorDetails      
        FROM       
            Tbl_MassOperationSummary MOS (NOLOCK)      
        INNER JOIN       
            Tbl_MassOperationDetails Details (NOLOCK)      
            ON MOS.BatchID = Details.SummaryId      
        WHERE       
            MOS.UserID = @User_Id      
            AND MOS.MassOperationName = 'Send InternationalSMS'  
   and MOS.IsProcessed=1 and MOS.isvalid=1  
            AND CAST(MOS.CreatedDate AS DATE) BETWEEN CAST(@fromDate AS DATE) AND CAST(@todate AS DATE)      
    )      
      
    -- Step 2: Fetch records from Int_MessageDeliveryStatus for processed entity IDs      
    
    
    /* ================= MAIN DATA INSERT ================= */
    
    
    INSERT INTO #DeliveryTemp
    select 
        --BatchId      
        SrNo
       ,Mobile       
       ,Message      
       ,SenderId     
       ,StatusDescription --Status       
       ,InsertDate --SentDateTime 
       ,MessageDeliveredDate --DeliveredDate
    
    from 
     (
      SELECT      
        ROW_NUMBER() OVER (ORDER BY MDS.MessageDeliveryStatusID) AS SrNo,  -- Adding row number      
        --CASE       
        --    WHEN MOB.EntityType = 'lead' THEN CONCAT(RTRIM(LTRIM(Lead.CountryCode)), ' ', Lead.MobileNo)      
        --    WHEN MOB.EntityType = 'enquiry' THEN CONCAT(RTRIM(LTRIM(Enquiry.CountryCode)), ' ', Enquiry.MobileNo)      
        --    ELSE NULL      
        --END AS Mobile,       
   CONCAT(RTRIM(LTRIM(MDS.CountryCode)), ' ', MDS.Mobile) AS Mobile,     
        MDS.Message,           
        MDS.SenderID,          
        ISNULL(      
            CASE         
                WHEN MDS.MessageStatus = '6' THEN 'Invalid'         
                WHEN MDS.MessageStatus = '200' THEN 'DELIVER'         
                WHEN MDS.MessageStatus = '-108' THEN 'Insufficient Balance'         
                WHEN MDS.MessageStatus = 'NULL' THEN 'Sent'          
                WHEN MDS.MessageStatus = '5' THEN 'Blacklisted'         
                WHEN MDS.MessageStatus = '7' THEN 'Sent'         
                WHEN MDS.MessageStatus = 'DND_check_failed' THEN 'Sent'          
                WHEN MDS.MessageStatus = '9' THEN 'UNDELIV'         
                WHEN MDS.MessageStatus = '' THEN 'Sent'         
                ELSE MDS.MessageStatus         
            END, 'Sent') AS StatusDescription,      
      
        CASE         
            -- If Mobile is null or blank, mark the status as 'Failed'      
            WHEN Mobile IS NULL OR Mobile = '' THEN 'Failed'      
            WHEN MDS.MessageStatus = '200' THEN 'Delivered'         
            WHEN MDS.MessageStatus IN ('6', '-108', '5', '9', 'NonDeliverable CountryCode', 'Invalid MobileNo','NonDeliverable CountryCode') THEN 'Failed'         
            ELSE 'Sent'         
        END AS MessageStatus,        
      
        --Mysms.dbo.fn_ConvertDateTime(MDS.MessageInsertDate, @TimeZoneName, 0) AS MessageDeliveredDate,
        MessageInsertDate AS MessageDeliveredDate,
        MDS.LastError,          
        CAST(MDS.MessageInsertDate AS DATE) AS InsertDate,      
        'Processed' AS ProcessStatus -- Indicate these records are processed      
    FROM       
        Int_MessageDeliveryStatus MDS (NOLOCK)      
    INNER JOIN       
        MassOperationBatches MOB      
        ON MDS.MassOpBatchID = MOB.BatchID      
        AND MDS.EntityID = MOB.EntityID      
    LEFT JOIN       
        UserLeads Lead (NOLOCK)      
        ON MOB.EntityID = Lead.ID      
    LEFT JOIN       
        UserEnquiry Enquiry (NOLOCK)      
        ON MOB.EntityID = Enquiry.EnquiryID      
    WHERE             --((LTRIM(RTRIM(Lead.MobileNo)) = @Mobile OR @Mobile = '') OR (LTRIM(RTRIM(Enquiry.MobileNo)) = @Mobile OR @Mobile = ''))     
   (CONCAT(RTRIM(LTRIM(MDS.CountryCode)), ' ', MDS.Mobile) LIKE '%' + @Mobile + '%' OR @Mobile = '')    
        AND (MDS.Message LIKE '%' + @Msz + '%' OR @Msz = '')    
  --AND (MessageStatus LIKE '%' + @status + '%' OR @status = '')   
  AND (  
    CASE   
        WHEN Mobile IS NULL OR Mobile = '' THEN 'Failed'      
        WHEN MDS.MessageStatus = '200' THEN 'Delivered'         
        WHEN MDS.MessageStatus IN ('6', '-108', '5', '9', 'NonDeliverable CountryCode', 'Invalid MobileNo', 'NonDeliverable CountryCode') THEN 'Failed'         
        ELSE 'Sent'         
    END LIKE '%' + @status + '%' OR @status = ''  
)  
  AND (MDS.SenderID LIKE '%' + @SenderId + '%' OR @SenderId = '')    
        AND CAST(MDS.MessageInsertDate AS DATE) BETWEEN CAST(@fromDate AS DATE) AND CAST(@todate AS DATE)      
          
    UNION ALL      
          
    -- Step 3: Fetch records from Tbl_MassOperationSummary that are not processed (not in Int_MessageDeliveryStatus)      
    SELECT      
        ROW_NUMBER() OVER (ORDER BY MOB.BatchID) AS SrNo,  -- Adding row number for unprocessed batches      
        CASE       
            WHEN MOB.EntityType = 'lead' THEN CONCAT(RTRIM(LTRIM(Lead.CountryCode)), ' ', Lead.MobileNo)      
            WHEN MOB.EntityType = 'enquiry' THEN CONCAT(RTRIM(LTRIM(Enquiry.CountryCode)), ' ', Enquiry.MobileNo)      
            ELSE NULL      
        END AS Mobile,       
        MOB.Message,           
        MOB.SenderID,          
   
     CASE
        -- Check if the mobile number is NULL or empty
        --WHEN (Mobile IS NULL OR Mobile = '')
        --    THEN 'Invalid Mobile No'
        
        -- Check if the mobile number starts with '+91', marking it as an invalid country code
        WHEN (Mobile LIKE '+91%')
            THEN 'Invalid Country Code'
        
        -- If the mobile number starts with '+61', show `MOB.Remarks`
        WHEN (Mobile LIKE '+61%')
            THEN 'Valid Mobile No with remarks: ' + ISNULL(MOB.Remarks, 'No Remarks')
        
        -- Default case, return `MOB.Remarks` if none of the above conditions match
        ELSE ISNULL(MOB.Remarks, 'No Remarks')
    END AS StatusDescription,
        CASE         
            -- If Mobile is null or blank, mark the status as 'Failed'      
            WHEN (Lead.MobileNo IS NULL OR LTRIM(RTRIM(Lead.MobileNo)) = '')       
                 AND (Enquiry.MobileNo IS NULL OR LTRIM(RTRIM(Enquiry.MobileNo)) = '')       
                 THEN 'Failed'      
            WHEN (MOB.Remarks IS NULL OR LTRIM(RTRIM(MOB.Remarks)) = '')       
                 OR (ISNULL(StatusDescription, '') = '')  -- Explicitly check StatusDescription for blank or null      
                 THEN 'Failed'      
            WHEN MOB.Remarks = 'Record save' THEN 'Delivered'         
            WHEN MOB.Remarks IN ('You have insufficient balance', 'We do not serve SMS to this country.') THEN 'Failed'         
            ELSE 'Sent'         
        END AS MessageStatus,     
      
        --Mysms.dbo.fn_ConvertDateTime(MOB.CreatedDate, @TimeZoneName, 0) AS MessageDeliveredDate,          
        MOB.CreatedDate AS MessageDeliveredDate,
        MOB.ErrorDetails AS LastError,          
        CAST(MOB.CreatedDate AS DATE) AS InsertDate,      
        'Not Processed' AS ProcessStatus -- Indicate these records are not processed      
    FROM       
        MassOperationBatches MOB      
    LEFT JOIN       
        Int_MessageDeliveryStatus MDS (NOLOCK)      
        ON MDS.MassOpBatchID = MOB.BatchID      
        AND MDS.EntityID = MOB.EntityID      
    LEFT JOIN       
        UserLeads Lead (NOLOCK)      
        ON MOB.EntityID = Lead.ID      
    LEFT JOIN       
        UserEnquiry Enquiry (NOLOCK)      
        ON MOB.EntityID = Enquiry.EnquiryID      
    WHERE       
        MDS.EntityID IS NULL      
        AND (CONCAT(RTRIM(LTRIM(Lead.CountryCode)), ' ', LTRIM(RTRIM(Lead.MobileNo))) LIKE '%' + @Mobile + '%' OR @Mobile = '')       AND (CONCAT(RTRIM(LTRIM(Enquiry.CountryCode)), ' ', LTRIM(RTRIM(Enquiry.MobileNo))) LIKE '%' + @Mobile + '%' OR @Mobile =  '')      
       AND (MOB.Message LIKE '%' + @Msz + '%' OR @Msz = '')       
    --AND (MessageStatus LIKE '%' + @status + '%' OR @status = '')     
    AND (  
    CASE   
        WHEN (Lead.MobileNo IS NULL OR LTRIM(RTRIM(Lead.MobileNo)) = '')       
            AND (Enquiry.MobileNo IS NULL OR LTRIM(RTRIM(Enquiry.MobileNo)) = '')       
            THEN 'Failed'      
        WHEN (MOB.Remarks IS NULL OR LTRIM(RTRIM(MOB.Remarks)) = '')       
            OR (ISNULL(StatusDescription, '') = '')    
            THEN 'Failed'      
        WHEN MOB.Remarks = 'Record save' THEN 'Delivered'         
        WHEN MOB.Remarks IN ('You have insufficient balance', 'We do not serve SMS to this country.') THEN 'Failed'         
        ELSE 'Sent'         
       END LIKE '%' + @status + '%' OR @status = ''  
     )  
    AND (MOB.SenderID LIKE '%' + @SenderId + '%' OR @SenderId = '')     
        AND CAST(MOB.CreatedDate AS DATE) BETWEEN CAST(@fromDate AS DATE) AND CAST(@todate AS DATE)      
   ) as tbl


     


      /* ================= TOTAL COUNT ================= */
    SELECT COUNT(1) AS TotalCount
    FROM #DeliveryTemp;

    /* ================= PAGED DATA ================= */
   
   
   if(@PageSize < 101)
   begin

    SELECT 
       --BatchId      BIGINT,
        SrNo         --  Bigint,    
       ,Mobile       --  VARCHAR(20),
       ,Message      --  VARCHAR(500),
       ,SenderId     --  VARCHAR(50),
        --Status
       ,StatusDescription as Status --VARCHAR(50),
         --SentDateTime
       ,InsertDate as SentDateTime --DATETIME,
        --DeliveredDate  DATETIME
       ,MessageDeliveredDate as DeliveredDate -- DATETIME 
      FROM #DeliveryTemp
    ORDER BY MessageDeliveredDate DESC
    OFFSET (@PageNumber - 1) * @PageSize ROWS
    FETCH NEXT @PageSize ROWS ONLY;
   end
   else
     begin
           SELECT 
       --BatchId      BIGINT,
        SrNo         --  Bigint,    
       ,Mobile       --  VARCHAR(20),
       ,Message      --  VARCHAR(500),
       ,SenderId     --  VARCHAR(50),
        --Status
       ,StatusDescription as Status --VARCHAR(50),
         --SentDateTime
       ,InsertDate as SentDateTime --DATETIME,
        --DeliveredDate  DATETIME
       ,MessageDeliveredDate as DeliveredDate -- DATETIME 
      FROM #DeliveryTemp
    ORDER BY MessageDeliveredDate DESC

     end

   


    drop table if exists #DeliveryTemp

END;   


GO

/* ============================================================
   Procedure: [dbo].[usp_Int_DeleveryReportAll]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_Int_DeleveryReportAll]        
    @User_Id INT,                                 
    @fromDate VARCHAR(20),                      
    @todate VARCHAR(20)        
AS                 
BEGIN                             
    DECLARE @TimeZoneName NVARCHAR(255) = ISNULL(        
        (SELECT TimeZone         
         FROM User_Detail (NOLOCK)         
         WHERE User_ID = @User_Id),         
        'India Standard Time'        
    );             
    
    -- Step 1: Fetch all records from Tbl_MassOperationSummary for 'Send InternationalSMS'    
    WITH MassOperationBatches AS (    
        SELECT     
            MOS.BatchID,    
            MOS.EntityType,    
            Details.EntityID,    
            MOS.SenderID,    
            MOS.metadata AS Message,    
            MOS.Remarks,    
            MOS.CreatedDate,    
            MOS.ErrorDetails    
        FROM     
            Tbl_MassOperationSummary MOS (NOLOCK)    
        INNER JOIN     
            Tbl_MassOperationDetails Details (NOLOCK)    
            ON MOS.BatchID = Details.SummaryId    
        WHERE     
            MOS.UserID = @User_Id    
            AND MOS.MassOperationName = 'Send InternationalSMS'
			and MOS.IsProcessed=1 and MOS.isvalid=1
            AND CAST(MOS.CreatedDate AS DATE) BETWEEN CAST(@fromDate AS DATE) AND CAST(@todate AS DATE)    
    )    
    
    -- Step 2: Fetch records from Int_MessageDeliveryStatus for processed entity IDs    
    SELECT    
        ROW_NUMBER() OVER (ORDER BY MDS.MessageDeliveryStatusID) AS SrNo,  -- Adding row number    
  --MDS.MassOpBatchId AS BatchId,  
         --CASE              WHEN MOB.EntityType = 'lead' THEN CONCAT(RTRIM(LTRIM(Lead.CountryCode)), ' ', Lead.MobileNo)             WHEN MOB.EntityType = 'enquiry' THEN CONCAT(RTRIM(LTRIM(Enquiry.CountryCode)), ' ', Enquiry.MobileNo)             ELSE NULL  
         --END AS Mobile,    
    CONCAT(RTRIM(LTRIM(MDS.CountryCode)), ' ', MDS.Mobile) AS Mobile,   
        MDS.Message,         
        MDS.SenderID,        
              
        ISNULL(    
            CASE       
                WHEN MDS.MessageStatus = '6' THEN 'Invalid'       
                WHEN MDS.MessageStatus = '200' THEN 'DELIVER'       
                WHEN MDS.MessageStatus = '-108' THEN 'Insufficient Balance'       
                WHEN MDS.MessageStatus = 'NULL' THEN 'Sent'        
                WHEN MDS.MessageStatus = '5' THEN 'Blacklisted'       
                WHEN MDS.MessageStatus = '7' THEN 'Sent'       
                WHEN MDS.MessageStatus = 'DND_check_failed' THEN 'Sent'        
                WHEN MDS.MessageStatus = '9' THEN 'UNDELIV'       
                WHEN MDS.MessageStatus = '' THEN 'Sent'       
                ELSE MDS.MessageStatus       
            END, 'Sent') AS StatusDescription,    
    
        CASE       
            -- If Mobile is null, mark the status as 'Failed'    
            WHEN MDS.Mobile IS NULL  THEN 'Failed'    
            WHEN MDS.MessageStatus = '200' THEN 'Delivered'       
            WHEN MDS.MessageStatus IN ('6', '-108', '5', '9', 'NonDeliverable CountryCode', 'Invalid MobileNo','N  onDeliverable CountryCode') THEN 'Failed'       
            ELSE 'Sent'       
        END AS MessageStatus,      
    
        Mysms.dbo.fn_ConvertDateTime(MDS.MessageInsertDate, @TimeZoneName, 0) AS MessageDeliveredDate,        
        MDS.LastError,        
        CAST(MDS.MessageInsertDate AS DATE) AS InsertDate  
        --'Processed' AS ProcessStatus -- Indicate these records are processed    
    FROM     
        Int_MessageDeliveryStatus MDS (NOLOCK)    
    INNER JOIN     
        MassOperationBatches MOB    
        ON MDS.MassOpBatchID = MOB.BatchID    
        AND MDS.EntityID = MOB.EntityID    
    --LEFT JOIN     
    --    UserLeads Lead (NOLOCK)    
    --    ON MOB.EntityID = Lead.ID    
    --LEFT JOIN     
    --    UserEnquiry Enquiry (NOLOCK)    
    --    ON MOB.EntityID = Enquiry.EnquiryID    
        
    UNION ALL    
        
    -- Step 3: Fetch records from Tbl_MassOperationSummary that are not processed (not in Int_MessageDeliveryStatus)    
    SELECT    
        ROW_NUMBER() OVER (ORDER BY MOB.BatchID) AS SrNo,  -- Adding row number for unprocessed batches   
  --MOB.BatchID,  
        CASE              WHEN MOB.EntityType = 'lead' THEN CONCAT(RTRIM(LTRIM(Lead.CountryCode)), ' ', Lead.MobileNo)             WHEN MOB.EntityType = 'enquiry' THEN CONCAT(RTRIM(LTRIM(Enquiry.CountryCode)), ' ', Enquiry.MobileNo)             ELSE NULL 
  
        END AS Mobile,     
        MOB.Message,         
        MOB.SenderID,        
        --MOB.Remarks AS StatusDescription,    
--  CASE          WHEN (Lead.MobileNo IS NULL OR LTRIM(RTRIM(Lead.MobileNo)) = '' OR ISNUMERIC(Lead.MobileNo) = 0)           OR (Enquiry.MobileNo IS NULL OR LTRIM(RTRIM(Enquiry.MobileNo)) = '' OR ISNUMERIC(Enquiry.MobileNo) = 0)            THEN 'Invalid Mobile No'          WHEN (Lead.MobileNo IS NOT NULL AND LEN(LTRIM(RTRIM(Lead.MobileNo))) > 10)            OR (Enquiry.MobileNo IS NOT NULL AND LEN(LTRIM(RTRIM(Enquiry.MobileNo))) > 10)           THEN 'Invalid Mobile No'          WHEN (Lead.CountryCode = '+91
--' OR Enquiry.CountryCode = '+91')           THEN 'Non-Deliverable Country Code'          ELSE MOB.Remarks     END AS StatusDescription,  
CASE
    WHEN (Lead.MobileNo IS NULL OR LTRIM(RTRIM(Lead.MobileNo)) = '' OR ISNUMERIC(Lead.MobileNo) = 0) 
        OR (Enquiry.MobileNo IS NULL OR LTRIM(RTRIM(Enquiry.MobileNo)) = '' OR ISNUMERIC(Enquiry.MobileNo) = 0) 
    THEN 'Invalid Mobile No'

    WHEN (Lead.MobileNo IS NOT NULL AND LEN(LTRIM(RTRIM(Lead.MobileNo))) > 10) 
        OR (Enquiry.MobileNo IS NOT NULL AND LEN(LTRIM(RTRIM(Enquiry.MobileNo))) > 10) 
    THEN 'Invalid Mobile No'

    WHEN (Lead.CountryCode = '+91' OR Enquiry.CountryCode = '+91') 
    THEN 'Non-Deliverable Country Code'

    WHEN (Lead.CountryCode = '+61' OR Enquiry.CountryCode = '+61') 
    THEN MOB.Remarks

    ELSE MOB.Remarks
END AS StatusDescription,
    
        CASE       
            -- If Mobile is null, mark the status as 'Failed'    
            WHEN (Lead.MobileNo IS NULL OR LTRIM(RTRIM(Lead.MobileNo)) = '')                   AND (Enquiry.MobileNo IS NULL OR LTRIM(RTRIM(Enquiry.MobileNo)) = '')                   THEN 'Failed'    
     WHEN (MOB.Remarks IS NULL OR LTRIM(RTRIM(MOB.Remarks)) = '')  OR (ISNULL(StatusDescription, '') = '')THEN 'Failed'  -- Explicitly check StatusDescription for blank or null          THEN 'Failed'    
            WHEN MOB.Remarks = 'Record save' THEN 'Delivered'       
            WHEN MOB.Remarks IN ('You have insufficient balance', 'We do not serve SMS to this country.') THEN 'Failed'       
            ELSE 'Sent'       
        END AS MessageStatus,      
    
        Mysms.dbo.fn_ConvertDateTime(MOB.CreatedDate, @TimeZoneName, 0) AS MessageDeliveredDate,        
        MOB.ErrorDetails AS LastError,        
        CAST(MOB.CreatedDate AS DATE) AS InsertDate    
       -- 'Not Processed' AS ProcessStatus -- Indicate these records are not processed    
    FROM     
        MassOperationBatches MOB    
    LEFT JOIN     
        Int_MessageDeliveryStatus MDS (NOLOCK)    
        ON MDS.MassOpBatchID = MOB.BatchID    
        AND MDS.EntityID = MOB.EntityID    
    LEFT JOIN     
        UserLeads Lead (NOLOCK)    
        ON MOB.EntityID = Lead.ID    
    LEFT JOIN     
        UserEnquiry Enquiry (NOLOCK)    
        ON MOB.EntityID = Enquiry.EnquiryID    
    WHERE     
        MDS.EntityID IS NULL; -- Fetch only unprocessed entries    
END; 



GO

/* ============================================================
   Procedure: [dbo].[USP_Int_GetBatchInfoForProcess]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROC  [dbo].[USP_Int_GetBatchInfoForProcess]  --4                                                                              
@PROCESSTABLE INT                                                                                        
AS                                                                                        
BEGIN                                                     
DECLARE @BATCHINFOID BIGINT -- CHANGED                                                                                       
DECLARE @BATCHID BIGINT     -- CHANGED                                                                                    
DECLARE @COUNT INT, @TOTALRECORD INT,@ISALLOWDND BIT,@MESSAGEINSERTDATE DATETIME,    
  @DIFFDATE INT , @CURRENTDTTIME DATETIME ,@USERFILTER NVARCHAR(200)                                          
DECLARE @QUERY NVARCHAR(MAX)                                  
DECLARE @TABLENAMECLONE VARCHAR(150)                                  
DECLARE @PROCESSTABLE_NAME VARCHAR(50)                                
DECLARE @PROCESS_TABLE_QUERY NVARCHAR(MAX)                                
DECLARE @PROCESS_TABLE_COUNT BIGINT                                
     
BEGIN TRY                                     
BEGIN TRANSACTION                   
SET   @CURRENTDTTIME = GETDATE()      
    
  SELECT TOP 1 @BATCHINFOID = BATCHINFOID , @BATCHID = BATCHID , @TOTALRECORD =  TOTALRECORDS,    
 @ISALLOWDND=ISALLOWDND,@MESSAGEINSERTDATE=BATCHINSERTTIME,@USERFILTER=USERFILTER       
 FROM dbo.BatchIntInfo  WITH(NOLOCK)   WHERE  ISPROCESS = 0 OR ISPROCESS IS NULL    
ORDER BY BATCHINFOID     -- CHANGED                    
--SELECT TOP 1 @BATCHINFOID = BATCHINFOID , @BATCHID = BATCHID , @TOTALRECORD =  TOTALRECORDS,    
-- @ISALLOWDND=ISALLOWDND,@MESSAGEINSERTDATE=BATCHINSERTTIME,@USERFILTER=USERFILTER                   FROM dbo.BatchIntInfo  WITH(NOLOCK)   WHERE PROCESSTABLE = @PROCESSTABLE AND     
-- SCHEDULEDDATE <= @CURRENTDTTIME AND ( ISPROCESS = 0 OR ISPROCESS IS NULL )     
--ORDER BY BATCHINFOID     -- CHANGED                                  
                               
               
                                   
UPDATE  BatchIntInfo   SET ISPROCESS = 1                                                                                WHERE BATCHINFOID = @BATCHINFOID                               
                            
AND ( ISPROCESS = 0 OR ISPROCESS IS NULL ) -- CHANGED           
SELECT BATCHINFOID,USERID,BATCHID,TOTALRECORDS,PROCESSTABLE,ISPRORITY,ISALLOWDND,USERFILTER+'-TRUE'     
AS USERFILTER,USERFILTER AS 'AC_TYPE'     
FROM BatchIntInfo WITH(NOLOCK) WHERE BATCHINFOID = @BATCHINFOID                                                       
                                                           
IF @@TRANCOUNT > 0                                    
COMMIT;                                                             
END TRY                                                  
BEGIN CATCH                                     
IF @@TRANCOUNT > 0                                     
ROLLBACK;                                                  
EXEC USP_INSERTERRORINFO                                                  
END CATCH                                                     
END 



GO

