/* ============================================================
   Procedure: [dbo].[usp_IntCredit_Details_CheckBalance]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_IntCredit_Details_CheckBalance](      
 @Mode varchar(2),      
 @UserId bigint,      
 @totalword int,      
 @FeatureTypeId int      
)      
as      
begin      
 --Declare @Mode varchar(2) = 'C',      
 --@UserId bigint = 32222,      
 --@totalword int = 200,      
 --@FeatureTypeId int = 4      
if(@Mode = 'C')      
Begin      
Declare @ParentId bigint, @MId int, @Price numeric(18,4), @Cost decimal(18,4),       
 @mCount int, @TotalBalance decimal(18, 4), @Agreed int = 0      
      
select @ParentId = ParentID, @MId = M_ID from User_Detail(nolock) where User_ID = @UserId      
      
 declare @Pulse numeric(18,4)      
       
 select @ParentId = ParentID, @MId = M_ID from User_Detail(nolock) where User_ID = @UserId      
 select top 1 @Pulse = (Price * LoadFactor), @Price = Price  from [dbo].[tbl_AI_PriceMaster](nolock) where FeatureTypeId = @FeatureTypeId       
 --and (ParentId = @ParentId or @ParentId is null)      
      
set  @TotalBalance = Isnull((select  top 1 balance FROM IntCredit_Details c with (nolock) where user_ID=@ParentId     
 order by Credit_ID desc), 0)    
      
 set @Cost = (isnull(@Pulse, 0) * @totalword)      
    
 Set @Agreed = Isnull((Select Top 1 IsAgreed from TBL_AI_AgreedMaster aa where aa.ParentId = @ParentId), 0)      
      
 if(@Cost <= @TotalBalance)      
 begin      
  select @Agreed Agreed, 1 as isBalance, @TotalBalance Balance, @Price Price, 'Balance Available' as BalanceRemarks      
 end      
 else      
 begin      
  select @Agreed Agreed, 0 as isBalance, @TotalBalance Balance, @Price Price, 'Balance is not sufficient.' as BalanceRemarks      
 end      
End      
end  


GO

