/* ============================================================
   Procedure: [dbo].[usp_IntCredit_SaveReserveFund]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_IntCredit_SaveReserveFund]  
(  
    @UserId BIGINT,  
    @CreditTypeId BIGINT,  
    @ResearveForUserId BIGINT,  
    @ServiceName NVARCHAR(25),  
    @Amount DECIMAL(18,4),  
    @IsLock BIT= 0   
)  
AS  
BEGIN  
  
  
 --DECLARE   
 -- @UserId BIGINT = 49625,  
 -- @ResearveForUserId BIGINT = 49625,  
 -- @CreditTypeId BIGINT = 11,  
 -- @ServiceName NVARCHAR(25) = 'Whatsapp',  
 -- @Amount DECIMAL(18,4) = 1,  
 -- @IsLock BIT = 0  
  
 --SELECT @UserId=335,@CreditTypeId=11,@ResearveForUserId=34594,@ServiceName=N'Whatsapp',@Amount=N'100',@IsLock=1  
  
 DECLARE @ReserveFundId BIGINT,  @ReservedFunds DECIMAL(18,4), @StartAmount DECIMAL(18,4) = 0, 
    @CurrentDate DATETIME = GETDATE(), @ParentId BIGINT, @AmountLockedBy BIGINT = 0;  
  
 DECLARE @Status int = 0, @Message nvarchar(255) = 'Failed',   
    @Details nvarchar(max) = 'Unable to process your requrest please contact administrator or contact suppport';  
  
SELECT @ParentId = ParentID  FROM User_Detail (NOLOCK)  WHERE User_ID = @ResearveForUserId;  
  
SELECT TOP 1 @CreditTypeId = CreditTypeID FROM Price_Master_TypeCredit (NOLOCK)  WHERE CreditName = @ServiceName;  
  
 PRINT concat('@CreditTypeId=> ', @CreditTypeId)   
   
 SELECT TOP 1 @ReserveFundId = Id,  @StartAmount = Amount FROM tbl_IntCreditReserveFunds (NOLOCK)   
  WHERE ParentId = @ResearveForUserId AND CreditTypeId = @CreditTypeId AND IsLock = @IsLock order by Id desc  
  
 PRINT concat('@ReserveFundId=> ', @ReserveFundId)  
  
 IF(@StartAmount > 0 and @IsLock = 1 AND @Amount > 0 )   
 BEGIN  
  select @Status = 0, @Message = 'Failed', @Details = 'Sorry, you have already reserved funds for this service.'  
        GOTO EXIT_PROC  
 END  
  
 SET @ReservedFunds = isnull(@StartAmount, 0) + (@Amount);  
 declare @intCreditBal decimal(18, 0), @totalReserveAmount decimal(18, 4) = 0, @UnreservedFunds decimal(18, 4) = 0  
 select top 1 @intCreditBal = Balance from IntCredit_Details(nolock) where User_ID = @ParentId order by Credit_ID desc  
  
 select @totalReserveAmount = sum(Amount) from tbl_IntCreditReserveFunds(nolock) where ParentId = @ParentId  
  
 set @UnreservedFunds = isnull(@intCreditBal, 0) - isnull(@totalReserveAmount, 0)
  
 PRINT  CONCAT('@intCreditBal => ', @intCreditBal)  
 PRINT  CONCAT('@ReservedFunds => ', @ReservedFunds)  
 PRINT  CONCAT('@Amount => ', @Amount)  
 PRINT  CONCAT('@totalReserveAmount => ', @totalReserveAmount)
 PRINT  CONCAT('@UnreservedFunds => ', @UnreservedFunds)  
  
 IF((@StartAmount + @Amount) < 0)  
 BEGIN  
  select @Status = 0, @Message = 'Failed', @Details = 'Sorry, your withdrawal amount exceeds the reserved amount.'  
        GOTO EXIT_PROC  
 END  
  
IF(@Amount > 0 and @ReservedFunds > @intCreditBal)  
BEGIN  
    select @Status = 0, @Message = 'Failed', @Details = 'Sorry, your balance is too low.'  
    GOTO EXIT_PROC  
END  

IF( @Amount < isnull(@StartAmount, 0))  
BEGIN  
    select @Status = 0, @Message = 'Failed', @Details = 'Sorry, your withdrawal amount exceeds the reserved amount.'  
    GOTO EXIT_PROC  
END  
  
 BEGIN TRY  
        BEGIN TRANSACTION  
        IF(ISNULL(@ReserveFundId, 0) = 0)  
        BEGIN          
            INSERT INTO tbl_IntCreditReserveFunds (ParentId, Amount, IsLock, CreditTypeId, CreatedBy, CreatedOn)  
            VALUES (@ParentId, @ReservedFunds, @IsLock, @CreditTypeId, @UserId, @CurrentDate);  
            SET @ReserveFundId = SCOPE_IDENTITY();  
        END  
        ELSE  
        BEGIN  
            UPDATE tbl_IntCreditReserveFunds   
            SET Amount = @ReservedFunds,   
                CreditTypeId = @CreditTypeId,   
                ModifiedBy = @UserId,   
                ModifiedOn = @CurrentDate   
            WHERE Id = @ReserveFundId AND ParentId = @ParentId;  
        END  
  
        IF(ISNULL(@ReserveFundId, 0) > 0)  
        BEGIN  
            INSERT INTO tbl_IntCreditAuditLog (Action, ParentId,StartingfAmount, Credit, Amount, CreditTypeId, IsLock, CreatedBy, CreatedDate)  
                VALUES (CASE WHEN @Amount > 0 THEN 'Credit' ELSE 'Debit' END,   
                            @ParentId, @StartAmount ,@Amount, @ReservedFunds , @CreditTypeId, @IsLock, @UserId, @CurrentDate);  
        END  
  
        COMMIT TRANSACTION  
  
        select @Status = 1, @Message = 'Success', @Details = 'Reserve fund saved successfully.'  
        GOTO EXIT_PROC  
  
 END TRY  
 BEGIN CATCH  
        ROLLBACK TRANSACTION  
  EXEC usp_InsertErrorInfo  
  select @Status = 0, @Message = 'Failed', @Details = 'Unable to process your requrest please contact administrator or contact suppport';  
 END CATCH  
   
  
 EXIT_PROC:  
 SELECT @Status AS [Status], @Message as [Message], @Details as [Details]  
   
  
END


GO

/* ============================================================
   Procedure: [dbo].[Usp_IntCreditUpdate]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROC [dbo].[Usp_IntCreditUpdate] -- 25211,1,'10'       
@userId bigint, -- from bigint by Abhishek         
@credit bigint,         
@DNDAcType varchar(20)           
as          
begin 
 
     Declare @ParentID bigint = ( select top 1 isnull(ParentID,0) from User_Detail with(nolock) where User_ID = @userId )     
	 Declare @MID_P bigint = ( select top 1 isnull(M_ID,0) from User_Detail with(nolock) where User_ID = @ParentID )     
         
declare @balance bigint,@default_credit bigint,@rmid bigint,@ruid bigint,@rbal bigint,@rcid bigint,@MIDUser bigint          
declare @rvalidity nvarchar(300),@rdefault_credit nvarchar(300),@temp nvarchar(800),@finalbalance2 bigint,@finalbalance bigint,@creditup bigint,@rCredit bigint,@uCredits bigint                
select top(1) @MIDUser=m_id from User_Detail with(nolock) where user_id=@userId              
select top(1) @rmid=m_id, @ruid=user_id from reseller_detail with(nolock) where reseller_id=@MIDUser          
select top(1) @rbal=balance,@rvalidity=validity,@rdefault_credit=default_credit,      
@rCredit=credits,@rcid=credit_id   from IntCredit_Details with(nolock) where m_id=@rmid and user_id=@ruid  order by credit_id  desc                              
select top(1) @balance=balance,@default_credit=default_credit,@ucredits=credits from IntCredit_Details with(nolock) where user_id=@ParentID order by credit_id desc                                    
update dbo.User_Detail set AcType=@DNDAcType  where user_id=@ParentID        
set @finalbalance=(@credit+isnull(@balance,0))          
set @finalbalance2=( isnull(@rbal,0)-@credit)          
--Debit          
insert into IntCredit_Details(FromUser_ID,M_ID,User_ID,Debits,Credits,Balance,      
Validity,Default_Credit,ICD_CreatedBy)          
values(@ParentID,@rmid,@ruid,@credit,0,@finalbalance2,@rvalidity,@rdefault_credit,@userId)          
--- Credit          
insert into IntCredit_Details (FromUser_ID,M_ID,User_ID,Debits,Credits,Balance,      
Validity,Default_Credit,ICD_CreatedBy)          
values(@ruid,@MID_P,@ParentID,0,@credit,@finalbalance,99999,@default_credit,@userId)          
select 'Record update'          
end   
  


GO

/* ============================================================
   Procedure: [dbo].[Usp_IntCreditUpdate_new1]
   ============================================================ */

SET ANSI_NULLS ON
