CREATE   PROC [dbo].[Usp_IntCreditUpdate_new1] -- 25211,1,'10'  ----- for wallet credit new      
@P_userId BIGINT,
@userId bigint,          
@credit numeric(18,4),         
@DNDAcType varchar(20)           
as          
begin          

DECLARE @InsertedLicenseId VARCHAR(MAX) = '0';
    DECLARE @LicenseMetadata VARCHAR(MAX);
	 Declare @ParentID  bigint = ( select top 1 isnull(ParentID,0) from User_Detail with(nolock) where User_ID = @userId )--456        
      Declare @MID_P  bigint = ( select top 1 isnull(M_ID,0) from User_Detail with(nolock) where User_ID = @ParentID ) --1
	declare @balance numeric(18,4),@default_credit bigint,@rmid bigint,@ruid bigint,@rbal numeric(18,4),@rcid bigint,@MIDUser bigint          
	declare @rvalidity nvarchar(300),@rdefault_credit nvarchar(300),@temp nvarchar(800),@finalbalance2 bigint,@finalbalance bigint,@creditup bigint,@rCredit bigint,@uCredits bigint                
 
    BEGIN TRY
	select top(1) @MIDUser=  m_id  from User_Detail with(nolock) where user_id=@P_userId  --null   
	--select top(1) @MIDUser= case when @P_userId=335 then 1 else m_id end from User_Detail with(nolock) where user_id=@P_userId  --null            
	--select top(1) @rmid=m_id, @ruid=user_id from reseller_detail where reseller_id=@MIDUser --null         
	select top(1) @rbal=balance,@rvalidity= validity, @rdefault_credit= default_credit from IntCredit_Details with(nolock) where USER_ID=@P_userId order by credit_id  desc -- balace of parent partner(335)                             
	select top(1) @balance=balance,@default_credit =default_credit,  @ucredits= credits  from IntCredit_Details with(nolock) where USER_ID=@userId order by credit_id desc  -- balace of chld partner(456)         
     

 UPDATE dbo.User_Detail  
 SET    AcType = @DNDAcType  
 WHERE  USER_ID = @userId 
 DECLARE @NewBalance numeric(18,4) = ISNULL(@balance, 0) + @credit;  --balace of child partner after addition

		 DECLARE @NewBalanceFromUser numeric(18,4) = ISNULL(@rbal, 0) - @credit; --balace of parent partner after addition

   begin tran

 --Debit        
 INSERT INTO IntCredit_Details  
   (  
     FromUser_ID, M_ID, USER_ID, Debits,Credits, Balance,Validity, Default_Credit  
   )  
 VALUES  
   (  
     @P_userId, @MID_P, @userId,0, @credit, @NewBalance, @rvalidity,@rdefault_credit  
   )  
   
 --- Credit        
 INSERT INTO IntCredit_Details  
   (  
     FromUser_ID,M_ID, USER_ID, Debits,Credits,Balance,Validity,Default_Credit  
   )  
 VALUES  
   (  
     @userId, @MIDUser, @P_userId, @credit, 0, @NewBalanceFromUser,99999, @default_credit  
   )

   	SET @InsertedLicenseId = SCOPE_IDENTITY();

    select 1 as status, 'Wallet credited successful!' AS Message
	   commit
	   if @@TRANCOUNT >0
	   begin
	   rollback
        select 0 as status, 'Wallet credit failed!' AS Message
		end 


	
-----  activity start   -----
		--activity vars
		Declare @PartnerType int  =0;  
		DECLARE @UserName varchar(255), @PartnerUserName varchar(255) , @ChildPartnerName varchar(255);
		Declare @Eventdata varchar(max);
		---activity vars
			
		select @UserName = User_login from User_Detail where User_ID =  @P_userId;
		select @PartnerUserName = User_login from User_Detail where User_ID = @MIDUser;
		select @ChildPartnerName = User_login from User_Detail where User_ID = @userId;
		 
		SET @Eventdata = '{"#partner#":"'+ @UserName +'","#username#":"'+@ChildPartnerName +'","#moneyadded#":"'+ CONVERT(varchar, @credit )+'"}';

		---select * from ActivityMaster  where EventName like '%partner%' 
		--#partner# added balance of #moneyadded# in wallet money to the account of #username#
		exec usp_pm_PartnerActivity  @P_userid, @P_userid, @userId, 'Partner added wallet balance',@Eventdata,'IntCredit_Details',@InsertedLicenseId;
	 
----- activity end  ---



END TRY
    BEGIN CATCH
        -- Log error details
        EXEC usp_InsertErrorInfo;
    END CATCH
END; 





GO

