CREATE   PROCEDURE [dbo].[usp_internalcrm_getexecutivemobile] --8657874148
@callermobile nvarchar(20)
as
begin
--declare @callermobile nvarchar(20)='8657874148'
declare @executive varchar(100),@mobile nvarchar(20),@enqno bigint,@cname nvarchar(100),@messagetext nvarchar(2000),@dltid nvarchar(50),@mo nvarchar(20)

