SET QUOTED_IDENTIFIER ON

  
CREATE   PROCEDURE usp_internalcrm_insertcall  
(@mobile nvarchar(20),@extension int,@executive varchar(100))  
as  
begin  
declare @callid bigint  
insert into internalcrm_calls(mobile,extension,executive,createdon)  
select dbo.fn_trim0prefix(@mobile),@extension,@executive,getdate()  
select @callid=SCOPE_IDENTITY()  
 select @callid
end  


