/* ============================================================
   Procedure: [dbo].[usp_InternationalBatchMetadataLengthAndCost]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- select * From Price_base_sms_rate where DestinationCountryCode='+27'
--update Price_base_sms_rate set PTrns=1,IsEligible=1 where DestinationCountryCode='+27' and OriginCountryCode='+1'
--update Price_base_sms_rate set IsEligible=0 where IsEligible is null

--Exec usp_InternationalBatchMetadataLengthAndCost @UserId=34594,@BatchID=40032
CREATE   PROCEDURE [dbo].[usp_InternationalBatchMetadataLengthAndCost]  
   @UserId  BIGINT,  
   @BatchID BIGINT  
AS  
BEGIN  

--   declare @UserId  BIGINT=34594, @BatchID BIGINT=40032  

    DECLARE @IsUnicode BIT;  
    DECLARE @NoOfUnit INT;  
    DECLARE @SmsMsg NVARCHAR(MAX);  
    DECLARE @EntityType NVARCHAR(10);  
    DECLARE @TotalCostForBatch DECIMAL(18, 2);  
    DECLARE @TotalEntities INT;  
    DECLARE @TotalCostMultiplied DECIMAL(18, 2);  
  
    -- Step 1: Retrieve the metadata (assuming it's the SmsMsg)  
    SELECT @SmsMsg = metadata, @EntityType = EntityType  
    FROM [dbo].[Tbl_MassOperationSummary]  
    WHERE BatchID = @BatchID;  
  
    -- Step 2: Check if the message is Unicode or not  
    SELECT @IsUnicode = dbo.fn_isunicode(@SmsMsg);  
  
    -- Step 3: Calculate the number of units based on message length  
    SELECT @NoOfUnit =   
    (  
        CASE  
            WHEN @IsUnicode = 0 AND LEN(@SmsMsg) <= 160 THEN 1  
            WHEN @IsUnicode = 0 AND LEN(@SmsMsg) > 160 THEN CEILING(LEN(@SmsMsg) / CAST(153 AS FLOAT))  
            WHEN @IsUnicode = 1 AND LEN(@SmsMsg) <= 70 THEN 1  
            ELSE CEILING(LEN(@SmsMsg) / CAST(67 AS FLOAT))  
        END  
    );  
  PRINT 'Number of units: ' + CAST(@NoOfUnit AS NVARCHAR(10)); 
    -- Step 4: Fetch details from Tbl_MassOperationDetails without validating country code and mobile number  
    CREATE TABLE #MobileNumbers  
    (  
        CountryCode NVARCHAR(10),  
        MobileNo NVARCHAR(15),  
        Cost DECIMAL(18, 4) DEFAULT 0  
    );  
  
    -- Step 4: Fetch details from Tbl_MassOperationDetails and insert all mobile numbers
INSERT INTO #MobileNumbers (CountryCode, MobileNo)
SELECT 
    CASE @EntityType
        WHEN 'Lead' THEN ul.CountryCode
        WHEN 'Enquiry' THEN ue.CountryCode
    END AS CountryCode,
    CASE @EntityType
        WHEN 'Lead' THEN ul.MobileNo
        WHEN 'Enquiry' THEN ue.MobileNo
    END AS MobileNo
FROM [dbo].[Tbl_MassOperationDetails] mod
LEFT JOIN userleads ul 
    ON @EntityType = 'Lead' AND ul.ID = mod.EntityID
LEFT JOIN userenquiry ue 
    ON @EntityType = 'Enquiry' AND ue.EnquiryID = mod.EntityID
WHERE mod.SummaryID = @BatchID;

-- Step 5: Update temp table to set cost where BR.IsEligible = 1
UPDATE MN
SET MN.Cost = CAST(ISNULL(BR.PTrns, 0.00) * @NoOfUnit AS NUMERIC(18, 4))
FROM Price_base_sms_rate BR
JOIN #MobileNumbers MN
ON BR.DestinationCountryCode = MN.CountryCode
WHERE BR.IsEligible = 1;

-- Step 6: Remove records where the cost is not updated (i.e., non-eligible country codes)
DELETE FROM #MobileNumbers
WHERE Cost IS NULL;

--select * from #MobileNumbers
-- Step 7: Calculate total cost and total entities (only eligible ones)
--SELECT 
--    @TotalCostForBatch = SUM(CASE WHEN CountryCode = '+61' THEN Cost ELSE 0 END),  
--    @TotalEntities = COUNT(CASE WHEN CountryCode = '+61' THEN 1 END)  
--    --@TotalCostForCountryCode = SUM(CASE WHEN CountryCode = '+61' THEN Cost ELSE 0 END)  -- Total cost for CountryCode '+61'
--FROM #MobileNumbers;

SELECT 
    @TotalCostForBatch = isnull(Cost,0),  
    @TotalEntities = count(*)over(order by Cost)  
    --@TotalCostForCountryCode = SUM(CASE WHEN CountryCode = '+61' THEN Cost ELSE 0 END)  -- Total cost for CountryCode '+61'
FROM #MobileNumbers;


-- Step 8: Multiply total cost by total entities and 1.5
SET @TotalCostMultiplied = @TotalCostForBatch * 1.5;

-- Step 9: Return the total cost, total entities, and the multiplied result
SELECT 
    @TotalCostForBatch AS TotalCost, 
    @TotalEntities AS TotalEntities, 
    @TotalCostMultiplied AS TotalCostMultiplied;

-- Cleanup
DROP TABLE #MobileNumbers; 

END;  



GO

/* ============================================================
   Procedure: [dbo].[usp_IntindMassSMSFromEnquiry]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
