CREATE   PROCEDURE [dbo].[usp_IntindMassSMSFromEnquiry]        
@tbl EnquiryMessageTbltype1 readonly ,        
@Userid bigint,        
@massbatchid bigint =0    ,    
@StartDateTime VARCHAR(50)=''       
AS        
BEGIN        
--begin try      
Drop Table if exists #temp        
if @massbatchid IS NOT NULL AND @massbatchid <> 0        
 BEGIN        
  --Update  Tbl_MassOperationSummary set BatchStartTime= GetDate(),ScheduleDateTime= @StartDateTime  where BatchID=@massbatchid     
  UPDATE Tbl_MassOperationSummary  
        SET BatchStartTime = GETDATE(),  
            ScheduleDateTime = CASE   
                                 WHEN ScheduleDateTime IS NULL OR ScheduleDateTime = '' OR ScheduleDateTime = '1900-01-01 00:00:00.000'  
                                 THEN @StartDateTime  
                                 ELSE ScheduleDateTime  
                               END  
        WHERE BatchID = @massbatchid;  
  
 END        
         
DROP TABLE  IF EXISTS #output         
  CREATE TABLE #output (          
    enquiryid BIGINT            
    ,Message nvarchar(max)        
 ,Mobile nvarchar(100)        
    )         
        
Declare @parentid bigint =(Select parentid from User_Detail where user_id = @Userid)        
Declare @username nvarchar(50) =(Select User_login from User_Detail where user_id = @Userid)        
        
  --select getdate() GetMessageStart      
Declare @rowJson nvarchar(max),@batchID bigint,@count int=0, @TemptableName nvarchar(50)='', @sqls nvarchar(max)=''      
 Select         
 [TemplateID]      
,[BatchID]        
,[leadid]        
,[U_ID]        
,[Mobile]        
, dbo.fn_getEnquiryMessageSMS_new(@parentid,[Message],Mobile,leadid) AS    [Message]        
,[ScheduledDate]        
,[ScheduledTime]        
,[SenderID]        
,[IsPrority]        
,[IsAllowDND]        
,[IsUniCode]        
,[SmppID]        
,[MobileSubSet]        
,[MessageStatus]        
,[isflash]        
,[sms_source]        
 into #temp from @tbl        
      
 --select getdate() GetMessageend      
      
        
  set @count= (Select COUNT(*) from #temp)      
  --select getdate() insertMessageStart      
  if @count <200      
  BEGIN      
 INSERT INTO CloneMessageDeliveryStatus (BatchID, Mobile, Message, MessageStatus, SenderID,MessageInsertDate, ScheduledDate, ScheduledTime,SmppID, U_ID, IsUniCode,       
           IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType,CMDS_CreatedBy,sms_source,[isflash])       
 select BatchID, Mobile, Message, MessageStatus, SenderID, GETDATE(), isnull(ScheduledDate,''), isnull(ScheduledTime,''), SmppID, U_ID, IsUniCode, 0, 0, 0,                                            
   1, IsPrority, IsAllowDND, 0,@UserId,[sms_source],[isflash] from #temp              
       
 END      
 ELSE       
 BEGIN      
 DROP TABLE  IF EXISTS #tableName         
 CREATE TABLE #tableName (TableName nvarchar(max)  )         
      
 INSERT INTO #tableName (TableName)      
 EXEC usp_CreateCloneTable2_FnlSendSMS      
 set @TemptableName = (Select top 1 TableName from #tableName)       
      
 set @sqls = 'INSERT INTO '+@TemptableName+' (BatchID, Mobile, Message, MessageStatus, SenderID,MessageInsertDate, ScheduledDate, ScheduledTime,SmppID, U_ID, IsUniCode,       
           IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType,DT_CreatedBy,sms_source,[isflash])       
 select BatchID, Mobile, Message, MessageStatus, SenderID, GETDATE(), isnull(ScheduledDate,''''), isnull(ScheduledTime,''''), SmppID, U_ID, IsUniCode, 0, 0, 0,                                            
   1, IsPrority, IsAllowDND, 0,'+cast (@UserId as varchar) +',[sms_source],[isflash] from #temp'              
  print @sqls      
  execute sp_executesql @sqls      
      
 END      
   DECLARE @tbl1 AS LeadActivitywithid_Tbltype          
    INSERT INTO @tbl1 (          
    leadid          
    ,userid          
    ,parentid          
    ,eventdescription          
    ,eventname          
    ,reftable          
 ,refid          
    )          
  SELECT leadid          
    ,@Userid          
    ,@ParentID          
 , @username + ' sent an sms with content "'+Message+'" on mobile '+Mobile        
    ,'SMS sent to enquiry'          
    ,null          
    ,null         
   FROM #temp l          
    EXEC UspSaveentityActivity_withMultipleValue_withid_bulk @tbl1          
  --select getdate() insertMessageend      
   Set @batchID= (select top 1 BatchID from [#temp])        
   set @rowJson  = (        
   SELECT * FROM CloneMessageDeliveryStatus (NOLOCK) cimds        
   WHERE BatchID = @batchID        
   FOR JSON AUTO        
    ,INCLUDE_NULL_VALUES        
   )         
 --  if @rowJson is not null       
 --  begin      
 -- EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId        
 -- ,@Activity_type = 'Inst_MassSms_Enq'        
 -- ,@ActionType = 'I'        
 -- ,@RowJson = @rowJson        
 -- ,@Table_name = 'CloneMessageDeliveryStatus'             
 --end      
  if @massBatchID IS NOT NULL AND @massBatchID <> 0        
   BEGIN        
    --Update  Tbl_MassOperationSummary set BatchEndTime= GetDate(),ScheduleDateTime= @StartDateTime , Remarks = 'Record Saved', IsProcessed=1 where BatchID=@massBatchID      
 UPDATE Tbl_MassOperationSummary  
        SET BatchEndTime = GETDATE(),  
            ScheduleDateTime = CASE   
                                 WHEN ScheduleDateTime IS NULL OR ScheduleDateTime = '' OR ScheduleDateTime = '1900-01-01 00:00:00.000'  
                                 THEN @StartDateTime  
                                 ELSE ScheduleDateTime  
                               END,  
            Remarks = 'Record Saved',  
            IsProcessed = 1  
        WHERE BatchID = @massBatchID;  
   END        
 Drop Table if exists #temp       
 --end try      
 --begin catch      
 --insert into ErrorReportNew(ERRORNUMBER,ERRORSEVERITY,ERRORSTATE,ERRORPROCEDURE,ERRORLINE,ERRORMESSAGE,dATE)       
 --Select  Error_Number(),ERROR_SEVERITY(),ERROR_STATE(),ERROR_PROCEDURE(),ERROR_LINE(),ERROR_MESSAGE(),getdate()               
 --end CATCH       
END   
  


GO

