        BEGIN
            -- Return message if @IDS is null or blank
            SELECT 'ID is null or blank' AS StatusMessage;
            RETURN;
        END
        DECLARE @IDsTable TABLE (ID BIGINT);    
        DECLARE @InsertedTable TABLE (EntityID BIGINT);    
        DECLARE @ParentID BIGINT;    
        DECLARE @NewBatchID BIGINT;    
    
        -- Fetch the ParentID using @UserId    
        SELECT @ParentID = ParentID    
        FROM User_Detail (NOLOCK)    
        WHERE User_ID = @UserId;    
    
        -- Insert into Tbl_MassOperationSummary and capture the BatchID    
        INSERT INTO Tbl_MassOperationSummary (    
            MassOperationName,    
            UserID,    
            Parentid,    
            CreatedDate,    
            IsProcessed,    
            Remarks,    
            BatchStartTime,    
            BatchEndTime,    
