CREATE   PROCEDURE [dbo].[usp_IntindMassSMSFromLeads]         
@tbl LeadMessageTbltype1 readonly ,        
@Userid bigint,        
 @massbatchid bigint=0  ,      
   @StartDateTime VARCHAR(50)=''       
AS        
BEGIN        
Drop Table if exists #temp        
Declare @parentid bigint =(Select parentid from User_Detail where user_id = @Userid)        
Declare @username nvarchar(50) =(Select User_login from User_Detail where user_id = @Userid)        
        
Declare @rowJson nvarchar(max),@batchID bigint         
        
 if @massbatchid IS NOT NULL AND @massbatchid <> 0        
BEGIN        
 --Update  Tbl_MassOperationSummary set BatchStartTime= GetDate(),ScheduleDateTime= @StartDateTime  where BatchID=@massbatchid    
 UPDATE Tbl_MassOperationSummary  
        SET BatchStartTime = GETDATE(),  
            ScheduleDateTime = CASE   
                                 WHEN ScheduleDateTime IS NULL OR ScheduleDateTime = '' OR ScheduleDateTime = '1900-01-01 00:00:00.000'  
                                 THEN @StartDateTime  
                                 ELSE ScheduleDateTime  
                               END  
        WHERE BatchID = @massbatchid;  
  
END        
        
DROP TABLE  IF EXISTS #output         
  CREATE TABLE #output (          
    leadid BIGINT            
    ,Message nvarchar(max)        
 ,Mobile nvarchar(100)        
    )         
        
 Select         
[BatchID]        
,[leadid]        
,[U_ID]        
,[Mobile]        
, dbo.fn_getLeadsMailMessage_new(@parentid,[Message],Mobile,leadid) AS    [Message]        
,[ScheduledDate]        
,[ScheduledTime]        
,[SenderID]        
,[IsPrority]        
,[IsAllowDND]        
,[IsUniCode]        
,[SmppID]        
,[MobileSubSet]        
,[MessageStatus]        
,[isflash]        
,[sms_source]        
 into #temp from @tbl        
        
 INSERT INTO CloneMessageDeliveryStatus                                            
   (BatchID, Mobile, Message, MessageStatus, SenderID,                                            
     MessageInsertDate, ScheduledDate, ScheduledTime,                                            
     SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,                                            
     ValidNo, IsPrority, IsAllowDND, DBType,CMDS_CreatedBy,[sms_source],[isflash])             
          
 select BatchID, Mobile, Message, MessageStatus, SenderID,                                            
     GETDATE(), isnull(ScheduledDate,''), isnull(ScheduledTime,''),                                            
     SmppID, U_ID, IsUniCode, 0, 0, 0,                                            
     1, IsPrority, IsAllowDND, 0,@UserId,[sms_source],[isflash] from #temp                   
        
 insert into #output (leadid,Message,Mobile)        
 select [leadid],[Message],Mobile from #temp         
          
   DECLARE @tbl1 AS LeadActivitywithid_Tbltype          
          
   INSERT INTO @tbl1 (          
    leadid          
    ,userid          
    ,parentid          
    ,eventdescription          
    ,eventname          
    ,reftable          
    ,refid          
    )          
  SELECT leadid          
    ,@Userid          
    ,@ParentID          
 , @username + ' sent an sms with content "'+Message+'" on mobile '+Mobile        
    ,'SMS sent to lead'          
    ,null          
    ,null         
   FROM #output l          
        
    EXEC UspSaveentityActivity_withMultipleValue_withid_bulk @tbl1          
        
  --select * from [#temp]        
  Set @batchID= (select top 1 BatchID from [#temp])        
   set @rowJson  = (        
   SELECT * FROM CloneIntMsgDeliveryStatus (NOLOCK) cimds        
        
   WHERE BatchID = @batchID        
   FOR JSON AUTO        
    ,INCLUDE_NULL_VALUES        
   )         
  EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId        
  ,@Activity_type = 'Inst_Sms_LeadMass'        
  ,@ActionType = 'I'        
  ,@RowJson = @rowJson        
  ,@Table_name = 'CloneMessageDeliveryStatus'             
 if @massBatchID IS NOT NULL AND @massBatchID <> 0        
 BEGIN        
 -- Update  Tbl_MassOperationSummary set BatchEndTime= GetDate() , Remarks = 'Record Saved ', IsProcessed=1 where BatchID=@massBatchID    
 UPDATE Tbl_MassOperationSummary  
        SET BatchEndTime = GETDATE(),  
            ScheduleDateTime = CASE   
                                 WHEN ScheduleDateTime IS NULL OR ScheduleDateTime = '' OR ScheduleDateTime = '1900-01-01 00:00:00.000'  
                                 THEN @StartDateTime  
                                 ELSE ScheduleDateTime  
                               END,  
            Remarks = 'Record Saved',  
            IsProcessed = 1  
        WHERE BatchID = @massBatchID;  
 END        
          
 Drop Table if exists #temp        
END  
  


