CREATE   PROCEDURE [dbo].[usp_IntindMassVoiceFromLeads]       
@tbl SendMassVoiceTblType readonly ,      
@Userid bigint,      
 @massbatchid bigint=0,      
@ScheduleDate datetime=null,    
@BroadcastStartDateTime VARCHAR(50)=''    
AS      
BEGIN      
Drop Table if exists #tempVoice      
Declare @parentid bigint =(Select parentid from User_Detail where user_id = @Userid)      
Declare @username nvarchar(50) =(Select User_login from User_Detail where user_id = @Userid)      
Declare @rowJson nvarchar(max),@batchID bigint ,  @ttcount int, @sno int  =1        
DECLARE @tbl1 AS LeadActivitywithid_Tbltype        
      
 if @massbatchid IS NOT NULL AND @massbatchid <> 0      
BEGIN      
 --Update  Tbl_MassOperationSummary set BatchStartTime= GetDate(),ScheduleDateTime= @BroadcastStartDateTime  where BatchID=@massbatchid       
  UPDATE Tbl_MassOperationSummary  
        SET BatchStartTime = GETDATE(),  
            ScheduleDateTime = CASE   
                                 WHEN ScheduleDateTime IS NULL OR ScheduleDateTime = '' OR ScheduleDateTime = '1900-01-01 00:00:00.000'  
                                 THEN @BroadcastStartDateTime  
                                 ELSE ScheduleDateTime  
                               END  
        WHERE BatchID = @massbatchid;  
END      
      
 Select       
 [row_no],[LeadId], [BatchID], [country_code], [didno], [Mobile], [voiceDuration], [AppId], [IsDnd], [IsPrority], [price] , [user_id], [voice_type], [route], [parentid], [voice_source]      
 into #tempVoice from @tbl      
      
 Select @ttcount = count(1) from #tempVoice       
         
   while (@ttcount>0)      
 BEGIN      
      
 INSERT INTO Clone_VoiceDeliveryStatus                                          
   ( [BatchID], [country_code], [didno], [Mobile], [voiceDuration], [AppId], [IsDnd], [IsPrority], [price] , [user_id], [voice_type], [route], [parentid], [voice_source],[ScheduledDate])           
        
 select  [BatchID], [country_code], [didno], [Mobile], [voiceDuration], [AppId], [IsDnd], [IsPrority], [price] , [user_id], [voice_type], [route], [parentid], [voice_source] ,@ScheduleDate      
  from #tempVoice where row_no between @sno and @sno+100      
      
         
   Set @batchID= (select top 1 BatchID from [#tempVoice])      
      
   INSERT INTO @tbl1 (        
    leadid        
    ,userid        
    ,parentid        
    ,eventdescription        
    ,eventname        
    ,reftable        
    ,refid        
    )        
  SELECT LeadId        
    , @Userid        
    , @ParentID        
 , dbo.fn_getentityfullname ('user',@Userid) + ' sent an automated call on mobile '+mobile+' with ivr '+ (SELECT AppName  FROM Cloud_app_master cm(NOLOCK) WHERE cm.AppId = l.Appid) +' and did no. '+[didno]      
    , 'SMS sent to lead'        
    , null        
    , null       
   FROM #tempVoice l  where row_no between @sno and @sno+100      
      
    EXEC UspSaveentityActivity_withMultipleValue_withid_bulk @tbl1        
 delete from @tbl1      
  --select * from [#tempVoice]      
 set @sno=@sno+100      
   set @ttcount =@ttcount-100      
   end         
       
   set @rowJson  = (      
   SELECT * FROM Clone_VoiceDeliveryStatus (NOLOCK) cimds      
      
   WHERE BatchID = @batchID      
   FOR JSON AUTO      
    ,INCLUDE_NULL_VALUES      
   )       
  EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId      
  ,@Activity_type = 'Inst_voice_Lead'      
  ,@ActionType = 'I'      
  ,@RowJson = @rowJson      
  ,@Table_name = 'Clone_VoiceDeliveryStatus'           
 if @massBatchID IS NOT NULL AND @massBatchID <> 0      
 BEGIN      
  --Update  Tbl_MassOperationSummary set BatchEndTime= GetDate(),ScheduleDateTime= @BroadcastStartDateTime , Remarks = 'Record Saved ', IsProcessed=1 where BatchID=@massBatchID     
  UPDATE Tbl_MassOperationSummary  
        SET BatchEndTime = GETDATE(),  
            ScheduleDateTime = CASE   
                                 WHEN ScheduleDateTime IS NULL OR ScheduleDateTime = '' OR ScheduleDateTime = '1900-01-01 00:00:00.000'  
                                 THEN @BroadcastStartDateTime  
                                 ELSE ScheduleDateTime  
                               END,  
            Remarks = 'Record Saved',  
            IsProcessed = 1  
        WHERE BatchID = @massBatchID;  
 END      
        
 Drop Table if exists #tempVoice      
END      
  


