 --@Mobile BIT=1,                                              
 --@mobile1 BIT=1,                                              
 --@Mobile2 BIT =1                                              
 CREATE TABLE #TableData2 (ID BIGINT)  
      
 INSERT INTO #TableData2 (ID)             
 select Item from fu_SplitString(@EnqID,'#')  
  
  
 DECLARE @BatchID BIGINT = (                                              
             SELECT MAX(gbr.BatchID)                                          
             FROM   GetBatchRecord AS gbr                                              
             WHERE  gbr.[User_id] = @Account                                              
         )                                     
                                               
                                               
                                               
 DELETE                                               
 FROM   GetBatchRecord                                              
 WHERE  [User_id] = @Account                                                  
                                   
                                  
                                   
                                  
 declare @Uccode varchar(20)                                   
  SELECT TOP 1 @Uccode =  CountryCode                                  
  FROM   User_Detail AS ud                                  
  WHERE  ud.[User_ID] = @ParentAccount                                               
                                   
                                   
                                   
 INSERT INTO #tmpflind                                              
   ( BatchID,Mobile,Country_Code,Message,                                              
             MessageStatus, SenderID,MessageInsertDate,ScheduledDate,                                              
             ScheduledTime,SmppID,U_ID,IsUnicode,IsDnd,IsAirtel,MobileSubSet,                                  
             ValidNo,IsPrority,IsAllowDND,DBType, EnquiryId                                                 
   )                        
     SELECT BatchID,Mobile,CountryCode,Messagetext,                                              
             MessageStatus, SenderID,MessageInsertDate, ScheduledDate,                                              
             ScheduledTime,SmppID,U_ID,IsUnicode,IsDnd,IsAirtel,MobileSubSet,                                  
             ValidNo,IsPrority,IsAllowDND,DBType, EnquiryId                                     
    FROM   (                                              
            SELECT @BatchID AS BatchID,                                              
               CASE                                               
         WHEN @Mobile = 1 THEN ISNULL(NULLIF(ue.MobileNo ,''),'0')  ELSE '0'                                             
               END  AS Mobile,                                   
               CASE                                               
                WHEN @Mobile = 1 THEN ISNULL(ue.CountryCode ,'')                                  
                ELSE '' END AS CountryCode,                                  
                dbo.fn_getEnquiryMessage_new(ue.ParentID, @Message, ue.MobileNo) AS                                               
                   Messagetext,                 
                   NULL         AS MessageStatus,                                              
                   @SenderID    AS SenderID,                                              
                   GETDATE()    AS MessageInsertDate,                                              
                   NULL         AS ScheduledDate,                     
                   NULL         AS ScheduledTime,                                              
                   (                                              
                       SELECT TOP 1 ud.SmppID                                              
                       FROM   User_Detail AS ud                                       
                       WHERE  ud.[User_ID] = @Account                                              
                   )            AS SmppID,                                              
                   @Account     AS U_ID,                                              
                   @IsUnicode   AS IsUnicode,                                       
                   0            AS IsDnd,                                              
                   0            AS IsAirtel,                                              
                   0            AS MobileSubSet,                                              
                   1            AS ValidNo,                           
                   1            AS IsPrority,                                              
                   0            AS IsAllowDND,                                              
                   0            AS DBType,        
       ue.EnquiryID as [EnquiryId]        
            FROM   UserEnquiry  AS ue                                              
         inner join #TableData2 t2 on ue.EnquiryID = t2.ID   
            WHERE    
   --ue.EnquiryID IN (SELECT [value] FROM   dbo.fn_Split(@EnqID, '#') AS fs) AND  
  
      ISNULL(NULLIF(ue.MobileNo, ''), '') <> ''                                         
                   AND ISNULL(NULLIF(ue.MobileNo, ''), '') not in                                         
                   (                                        
                   select  ISNULL(C_UDTemp.Mobile,'') as MobileNo                                         
                   from UserEnquiry UETemp inner join Client_UnSubscribeDetails C_UDTemp                                        
                   on (UeTemp.MobileNo =C_UDTemp.Mobile and UETemp.CountryCode = C_UDTemp.CountryCode)              
           inner join #TableData2 t2 on UE.EnquiryID = t2.ID   
     --where UE.EnquiryID in(Select fs.value from dbo.fn_Split(@EnqID, '#') AS fs )  
       )                                        
            UNION                                   
            SELECT @BatchID,                                              
                   CASE                                               
                        WHEN @mobile1 = 1 THEN ISNULL(NULLIF( ue.MobileNo1,''),'0') ELSE '0'                                              
                   END  AS Mobile,                                   
               CASE                                               
                WHEN @Mobile = 1 THEN ISNULL(ue.CountryCode1 ,'')                                  
                ELSE '' END AS CountryCode ,                                  
                dbo.fn_getEnquiryMessage_new(ue.ParentID, @Message, ue.MobileNo) AS                                               
                   Messagetext,                                              
                   NULL    AS MessageStatus,                                              
                   @SenderID    AS SenderID,                                              
                   GETDATE()    AS MessageInsertDate,                                              
                   NULL         AS ScheduledDate,                                        
                   NULL         AS ScheduledTime,                                              
                   (                                              
                     SELECT TOP 1 ud.SmppID                                              
                       FROM   User_Detail AS ud                                              
                       WHERE  ud.[User_ID] = @Account                                              
       )            AS SmppID,                                              
                   @Account     AS U_ID,                                              
    @IsUnicode   AS IsUnicode,                                              
                   0            AS IsDnd,                                              
                   0            AS IsAirtel,                                              
                   0            AS MobileSubSet,                                              
                   1            AS ValidNo,                                              
                   1            AS IsPrority,                                              
                   0            AS IsAllowDND,                                              
                   0            AS DBType,        
       ue.EnquiryID as [EnquiryId]                                            
            FROM   UserEnquiry  AS ue                                              
           inner join #TableData2 t2 on ue.EnquiryID = t2.ID   
            WHERE  --ue.EnquiryID IN (SELECT [value] FROM   dbo.fn_Split(@EnqID, '#') AS fs) AND  
  
                   ISNULL(NULLIF(ue.MobileNo1, ''), '') <> ''                                              
                    AND ISNULL(NULLIF(ue.MobileNo1, ''), '') not in                                         
                   (                                        
                   select  ISNULL(C_UDTemp.Mobile,'') as MobileNo1                                         
                   from UserEnquiry UETemp inner join Client_UnSubscribeDetails C_UDTemp                                        
                   on (UeTemp.MobileNo1 =C_UDTemp.Mobile and                                   
                   UETemp.CountryCode1 = C_UDTemp.CountryCode)                                        
           inner join #TableData2 t2 on ue.EnquiryID = t2.ID   
                   --where UE.EnquiryID in(Select fs.value from dbo.fn_Split(@EnqID, '#') AS fs )  
       )                                        
            UNION                                              
            SELECT @BatchID,                                              
                   CASE                                               
                        WHEN @Mobile2 = 1 THEN ISNULL(NULLIF(ue.MobileNo2,''),'0') ELSE '0'                                              
                   END  AS Mobile,                                   
               CASE                                               
                WHEN @Mobile = 1 THEN ISNULL(ue.CountryCode2 ,'')                                  
                ELSE '' END AS CountryCode ,                                  
                dbo.fn_getEnquiryMessage_new(ue.ParentID, @Message, ue.MobileNo) AS                        
                   Messagetext,                                              
                   NULL         AS MessageStatus,                                          
                   @SenderID    AS SenderID,                                              
                   GETDATE()    AS MessageInsertDate,                                              
                   NULL         AS ScheduledDate,                                              
                   NULL         AS ScheduledTime,                                              
                   (                                       
                       SELECT TOP 1 ud.SmppID                                              
                       FROM   User_Detail AS ud                                              
                       WHERE  ud.[User_ID] = @Account                                              
                   )            AS SmppID,                                              
                   @Account     AS U_ID,                                              
          @IsUnicode   AS IsUnicode,                                              
                   0            AS IsDnd,                                              
                   0            AS IsAirtel,                                              
                   0            AS MobileSubSet,                                              
                   1            AS ValidNo,                                              
                   1            AS IsPrority,                                              
                   0            AS IsAllowDND,                                              
                   0            AS DBType,        
       ue.EnquiryID as [EnquiryId]        
            FROM   UserEnquiry  AS ue                                              
           inner join #TableData2 t2 on ue.EnquiryID = t2.ID   
            WHERE  --ue.EnquiryID IN (SELECT [value]                                              
                    --                FROM   dbo.fn_Split(@EnqID, '#') AS fs) AND                                              
                   ISNULL(NULLIF(ue.MobileNo2, ''), '') <> ''                                          
                    AND ISNULL(NULLIF(ue.MobileNo2, ''), '') not in                                        
                   (                                        
                   select  ISNULL(C_UDTemp.Mobile,'') as MobileNo2                                         
                   from UserEnquiry UETemp inner join Client_UnSubscribeDetails C_UDTemp                                        
            on (UeTemp.MobileNo2 =C_UDTemp.Mobile and                                   
              UETemp.CountryCode2 = C_UDTemp.CountryCode)                                        
           inner join #TableData2 t2 on UE.EnquiryID = t2.ID   
                   --where UE.EnquiryID in(Select fs.value from dbo.fn_Split(@EnqID, '#') AS fs )  
       )                                        
        ) A                                              
 WHERE  A.Mobile <> '0'                                  
                                   
                      
 if @Uccode = '+91'                                  
 begin                                  
  insert into #tmpflint (BatchID, Country_code,Mobile, Message, MessageStatus, SenderID,                     
     MessageInsertDate, ScheduledDate, ScheduledTime,    
     SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,                                              
     ValidNo, IsPrority, IsAllowDND, DBType)                                   
   select BatchID, Country_code,replace(Country_code,'+','')+Mobile, Message, MessageStatus, SenderID,                                              
     MessageInsertDate, ScheduledDate, ScheduledTime,                                              
     SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,                                              
     ValidNo, IsPrority, IsAllowDND, DBType from  #tmpflind                                  
   where Country_Code <>'+91'                                  
  delete From #tmpflind where Country_Code <>'+91'                                  
 end                                  
 else               
 begin                                  
  insert into #tmpflint (BatchID, Country_code,Mobile, Message, MessageStatus, SenderID,                                              
     MessageInsertDate, ScheduledDate, ScheduledTime,                                              
     SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,                                              
     ValidNo, IsPrority, IsAllowDND, DBType)                                   
   select BatchID, Country_code,Mobile, Message, MessageStatus, SenderID,                                              
     MessageInsertDate, ScheduledDate, ScheduledTime,                                              
     SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,                                              
     ValidNo, IsPrority, IsAllowDND, DBType from  #tmpflind                                  
 end                                  
   
 DROP Table #TableData2  
  
 Declare @NoOfSMS  bigint = 0, @intsms bigint =0;                                   
 select @intsms = COUNT(*) from #tmpflint                                    
                               
                                 
declare @intprc int = 0 , @indprc int = 0                                  
if @intsms > 0                                  
begin                                  
 update #tmpflint set price= (case when IsUniCode=0 and len(message)<=160  then 1                                         
 when IsUniCode=0 and LEN(message)>160 then ceiling(LEN(message)/cast(153 as FLOat))                                         
  when IsUniCode=1                                         
 and len(message)<=70 then 1 else ceiling(LEN(message)/cast(67 as float)) end )*                                  
  (select price from dbo.IntSMSRateMast where country_code =#tmpflint.country_code)                                    
                                   
 declare @Cr_amt float,@balance float                                        
 select @Cr_amt = SUM(price) from #tmpflint                                        
 select top 1 @balance= Balance from dbo.IntCredit_Details where USER_ID = @ParentAccount                                
   
 if @balance < @Cr_amt                                  
set @intprc = 1                                     
end                                  
                                   
if @intprc =0                                  
begin                                 
                             
  select @NoOfSMS = COUNT(*) from #tmpflind                            
 if @NoOfSMS > 0                                  
 begin                                  
                                   
                                   
  DECLARE @CurrentBalance BIGINT = (                                                  
             SELECT TOP 1 isnull(cd.Balance,0)                                                  
             FROM   Credit_Details AS cd                                                  
             WHERE  cd.[User_ID] = @ParentAccount                                                  
             ORDER BY                                                  
 cd.Credit_ID DESC                                                  
   )                   
    declare @rlnk as int =0                                                     
 DECLARE @mBalance BIGINT = @CurrentBalance - @NoOfSMS                                                  
 IF @mBalance > 0                                      
   begin                                  
                   
 select @rlnk= COUNT(*) from @tbl                        
      if @rlnk >0                    
      begin                        
  exec Usp_Insert_SMSUrl_Link_new 0,@BatchID,'Enquiry SMS',@tbl                        
  end                                     
 INSERT INTO CloneMessageDeliveryStatus                                              
   (BatchID, Mobile, Message, MessageStatus, SenderID,                                              
     MessageInsertDate, ScheduledDate, ScheduledTime,                                              
     SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,                                              
     ValidNo, IsPrority, IsAllowDND, DBType,CMDS_CreatedBy)                                          
 select BatchID, Mobile, Message, MessageStatus, SenderID,                                              
     MessageInsertDate, isnull(ScheduledDate,''), isnull(ScheduledTime,''),                                              
     SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,                                              
     ValidNo, IsPrority, IsAllowDND, DBType,@UserId from #tmpflind                                  
                
   Begin try          
   exec Usp_Save_DLTTemplateID_with_BatchID @batchid,@DLTTemplateID       
   End try          
   begin catch          
     exec usp_InsertErrorInfo          
   End catch           
             
                                  
   end                                  
   else                           
 set @indprc = 1                                  
 end                                  
end                                  
 if @intprc  = 1 and @indprc  = 0                                  
 begin                  
  select @rlnk= COUNT(*) from @tbl                        
      if @rlnk >0                   
      begin                       
  exec Usp_Insert_SMSUrl_Link_new 0,@BatchID,'Enquiry Int SMS',@tbl                   
  end                                       
  insert into CloneIntMsgDeliveryStatus                                  
  (BatchID, Country_code, Mobile, Message, MessageStatus, SenderID,                                   
  MessageInsertDate, ScheduledDate, ScheduledTime, SmppID, U_ID, IsUniCode,                                   
  IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType,                                   
  campaignid, Processed, Hasvirtualcredits, HasSufficientvirtualcredits, price,CIMDS_CreatedBy)                                  
  select BatchID, Country_code, Mobile, Message, MessageStatus, SenderID,                                  
   MessageInsertDate, isnull(ScheduledDate,''), isnull(ScheduledTime,''), SmppID, U_ID, IsUniCode,                                   
   IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType,                                   
   campaignid, Processed, Hasvirtualcredits, HasSufficientvirtualcredits,                                   
   price ,@UserId from #tmpflint             
             
   Begin try          
   exec Usp_Save_DLTTemplateID_with_BatchID @batchid,@DLTTemplateID          
   End try          
   begin catch          
     exec usp_InsertErrorInfo          
   End catch           
                                  
 end                                  
 if @intprc  = 0 and @indprc  = 0           
 begin        
 if(@UserId  > 0 )            
 begin            
  declare @ParentId bigint ,  @Username nvarchar(255)          
  declare @leadActivityHistory AS LeadActivitywithid_Tbltype            
  select @Username = User_Login, @ParentId = ParentID from User_Detail(nolock) where User_Id = @UserId          
            
  insert into @leadActivityHistory ( LeadID, UserID, ParentID, EventDescription, EventName, RefTable, refid )            
   select             
    EnquiryId,            
    @UserId,             
    @parentid,            
    concat(@Username , ' sent an sms with content ', Message , ' on mobile ', Mobile),            
    'SMS sent to Enquiry',            
    'Batchinfo',                
    @BatchID            
   from #tmpflind            
           
  exec UspSaveentityActivity_withMultipleValue_withid @leadActivityHistory            
 end        
       SELECT 'Record Saved'                                            
    end        
     else        
  begin        
        select 'Insufficient Balance'                        
 end                                            
                                                  
END     
    


GO

