 @Message NVARCHAR(4000),                                      
 @IsUnicode BIT,                                      
 @Mobile BIT,                                      
 @mobile1 BIT,                                      
 @Mobile2 BIT,
 @CreatedBy bigint                                      
AS                                      
BEGIN                            
                          
