CREATE   PROCEDURE [dbo].[usp_IntindSMSFromEnquiry_WithDLTTemplateID_new_bulkreplace] --2211077,32222,'RJGURU','hello 4:49 pm',0,1,1,1                                                       
 @EnqID VARCHAR(MAX),                                                          
 @Account BIGINT,                                                          
 @SenderID NVARCHAR(100),                                                          
 @Message NVARCHAR(4000),                                                          
 @IsUnicode BIT,                                                          
 @Mobile BIT,                                                          
 @mobile1 BIT,                                                          
 @Mobile2 BIT,                    
 @DLTTemplateID nvarchar(200)   ,               
 @UserId bigint = 0   ,      
 @massbatchid bigint =0,    
 @StartDateTime VARCHAR(50)=''      
AS                                                          
BEGIN                                                
               
 declare @ParentAccount bigint = ( select top 1 ParentID from User_Detail with(nolock)  where User_ID = @Account)          

if @massbatchid IS NOT NULL AND @massbatchid <> 0        
BEGIN        
 select @EnqID= STRING_AGG(cast(Entityid as nvarchar(max)),'#') from Tbl_MassOperationDetails(nolock) where SummaryId=@massbatchid         
 --Update  Tbl_MassOperationSummary set BatchStartTime= GetDate(),ScheduleDateTime= @StartDateTime  where BatchID=@massbatchid  
 UPDATE Tbl_MassOperationSummary  
        SET BatchStartTime = GETDATE(),  
            ScheduleDateTime = CASE   
                                 WHEN ScheduleDateTime IS NULL OR ScheduleDateTime = '' OR ScheduleDateTime = '1900-01-01 00:00:00.000'  
                                 THEN @StartDateTime  
                                 ELSE ScheduleDateTime  
                               END  
        WHERE BatchID = @massbatchid;  
  
  
END                                          
 declare @batchid bigint                            
 begin tran                                                       
 INSERT INTO GetBatchRecord                                                          
   (                                                          
     -- BatchID -- this column value is auto-generated                                                              
                                                               
     [User_id],                                                          
     RandNum                                                          
   )                                                          
 VALUES                                                          
   (                                                          
     @Account,                                                          
     @Account                                                          
   )                                   
select @batchid=scope_identity()                            
delete from getbatchrecord where batchid=@batchid                            
commit     
print concat('Batchid: ',@batchid)
                                               
 CREATE TABLE #tmpflint(                                              
 [BatchID] [bigint]  NULL,                                              
 [Country_code] [varchar](10) NULL,                                              
 [Mobile] [varchar](20) NULL,                                              
 [Message] [nvarchar](2500) NULL,                                              
 [MessageStatus] [varchar](20) NULL,                                              
 [SenderID] [nchar](20) NULL,                                              
 [MessageInsertDate] [datetime]  NULL,                                              
 [ScheduledDate] [varchar](50) NULL,           
 [ScheduledTime] [varchar](50) NULL,                                              
 [SmppID] [tinyint]  NULL,                                              
 [U_ID] [int]  NULL,                                              
 [IsUniCode] [bit]  NULL,                                              
 [IsDnd] [bit]  NULL,                                              
 [IsAirtel] [bit]  NULL,                                              
 [MobileSubSet] [bigint] NULL,                                              
 [ValidNo] [tinyint] NULL,                                              
 [IsPrority] [tinyint] NULL,              
 [IsAllowDND] [tinyint] NULL,                                              
 [DBType] [nchar](10) NULL,                                              
 [campaignid] [bigint] NULL,                                            
 [Processed] [int] NULL,                                              
 [Hasvirtualcredits] [int] NULL,                                              
 [HasSufficientvirtualcredits] [int] NULL,                                              
 [price] [float] NULL                                              
)                        
--drop table #tmpflind                                              
CREATE TABLE #tmpflind(                 
 [BatchID] [bigint]  NULL,                                              
 [Country_code] [varchar](10) NULL,                                              
 [Mobile] [varchar](20) NULL,                                              
 [Message] [nvarchar](2500) NULL,                                       
 [MessageStatus] [varchar](20) NULL,                                              
 [SenderID] [nchar](20) NULL,                                          
 [MessageInsertDate] [datetime]  NULL,                                              
 [ScheduledDate] [varchar](50) NULL,                        
 [ScheduledTime] [varchar](50) NULL,                                              
 [SmppID] [tinyint]  NULL,                                              
 [U_ID] [int]  NULL,                                              
 [IsUniCode] [bit]  NULL,                                              
 [IsDnd] [bit]  NULL,                             [IsAirtel] [bit]  NULL,                                              
 [MobileSubSet] [bigint] NULL,                                              
 [ValidNo] [tinyint] NULL,                                              
 [IsPrority] [tinyint] NULL,                                      
 [IsAllowDND] [tinyint] NULL,                                              
 [DBType] [nchar](10) NULL,              
 [EnquiryId] [bigint] --,              
 --[campaignid] [bigint] NULL,                                           
 --[Processed] [int] NULL,                                              
 --[Hasvirtualcredits] [int] NULL,                                              
 --[HasSufficientvirtualcredits] [int] NULL                                              
)                                              
                                               
                                               
 -- declare @EnqID VARCHAR(500) ='291573#291572' ,                               --@Account BIGINT =16301,                                                          
 --@SenderID VARCHAR(50) ='KitApp',                                                          
 --@Message VARCHAR(2000)='qwwee',                                                          
 --@IsUnicode BIT=0,                                                          
 --@Mobile BIT=1,                                                          
 --@mobile1 BIT=1,                                                          
 --@Mobile2 BIT =1                                                          
 --DECLARE @BatchID BIGINT = (                                                          
 --            SELECT MAX(gbr.BatchID)                                                      
 --            FROM   GetBatchRecord AS gbr                                                   
 --            WHERE  gbr.[User_id] = @Account                                                          
 --        )                                                 
                                                           
                                                           
                                                           
 --DELETE                                                           
 --FROM   GetBatchRecord                                                          
 --WHERE  [User_id] = @Account                                                              
  
  drop table if exists #TableData2
 CREATE TABLE #TableData2 (Sno int identity(1,1), ID BIGINT)            
                
 INSERT INTO #TableData2 (ID)                       
 select Item from fu_SplitString(@EnqID,'#')            
  
 --select * from #TableData2 
  Declare @mincount int = 1 , @maxcount int = 100    
                 
 declare @Uccode varchar(20)='+91'                                               
  --SELECT TOP 1 @Uccode =  isnull(CountryCode,'+91')                                              
  --FROM   User_Detail AS ud (nolock)                                             
  --WHERE  ud.[User_ID] = @ParentAccount  
    
  
  declare @entity nvarchar(20)='Enquiry',@entityplaceholders nvarchar(2000)                                           
  drop table if exists #entitypcvalues  
  declare @entities as entities  
  create table #entitypcvalues(entityid bigint,content nvarchar(max))  
    
  select @entityplaceholders=dbo.ExtractPlaceholders(@entity,@message)  
  
   insert into @entities(entity,entityid)  
   select @entity,ID from #TableData2--Tbl_MassOperationDetails(nolock) where SummaryId=@massbatchid  
  


   if @entityplaceholders<>''  
   begin  
   insert into #entitypcvalues(entityid,content)  
   exec [usp_replaceentityplaceholders_bulk_singlecontent] @entities,@message ,@entityplaceholders 
   end  
   else  
   begin  
     insert into #entitypcvalues(entityid,content)  
     select entityid,@message from @entities  
  end  
  

  --select * from @entities
  --select * from #entitypcvalues
                                               
 WHILE EXISTS (Select 1 from #TableData2 where Sno between @mincount and @maxcount)      
  BEGIN                                              
                                               
 INSERT INTO #tmpflind                               
   ( BatchID,Mobile,Country_Code,Message,                                                          
             MessageStatus, SenderID,MessageInsertDate,ScheduledDate,                  
             ScheduledTime,SmppID,U_ID,IsUnicode,IsDnd,IsAirtel,MobileSubSet,                                              
             ValidNo,IsPrority,IsAllowDND,DBType, EnquiryId                                                            
   )                                                     
     SELECT BatchID,Mobile,CountryCode,Messagetext,                  
             MessageStatus, SenderID,MessageInsertDate, ScheduledDate,                                                          
             ScheduledTime,SmppID,U_ID,IsUnicode,IsDnd,IsAirtel,MobileSubSet,                                              
             ValidNo,IsPrority,IsAllowDND,DBType, EnquiryId                                                
    FROM   (                       
            SELECT @BatchID AS BatchID,                                                          
               CASE                                                           
                WHEN @Mobile = 1 THEN ISNULL(NULLIF(ue.MobileNo ,''),'0')  ELSE '0'                               
               END  AS Mobile,                                               
               CASE                                                           
                WHEN @Mobile = 1 THEN ISNULL(ue.CountryCode ,'')                                              
                ELSE '' END AS CountryCode,   
    content Messagetext,  
               -- dbo.fn_getEnquiryMessageSMS_new(ue.ParentID, @Message, ue.MobileNo,ue.EnquiryID) AS  Messagetext,                                                      
                 NULL         AS MessageStatus,                                                          
                   @SenderID    AS SenderID,                                                          
                   GETDATE()    AS MessageInsertDate,                                                          
                   NULL         AS ScheduledDate,                                 
                   NULL         AS ScheduledTime,                                                          
                   2  AS SmppID,                                                          
                   @ParentAccount     AS U_ID,                                                          
                   @IsUnicode   AS IsUnicode,                                                          
                   0            AS IsDnd,                                                          
                   0            AS IsAirtel,                                                          
                   0            AS MobileSubSet,                                                          
                  1            AS ValidNo,                                                          
                   1            AS IsPrority,       
                   0            AS IsAllowDND,                                                          
                   0            AS DBType  ,               
                  ue.EnquiryID as [EnquiryId]              
            FROM   UserEnquiry  AS ue  (nolock)                                                        
            inner join #TableData2 t2 on ue.EnquiryID = t2.ID    
   join #entitypcvalues e on ue.enquiryid=e.entityid  
            WHERE  --ue.EnquiryID IN (SELECT [value] FROM   dbo.fn_Split(@EnqID, '#') AS fs) AND             
              ISNULL(NULLIF(ue.MobileNo, ''), '') <> ''                                                     
    --               AND ISNULL(NULLIF(ue.MobileNo, ''), '') not in                                                     
    --          (                                                    
    --               select  ISNULL(C_UDTemp.Mobile,'') as MobileNo                                                     
    --               from UserEnquiry UETemp(nolock) inner join Client_UnSubscribeDetails C_UDTemp (nolock)                    
    --               on (UeTemp.MobileNo =C_UDTemp.Mobile and UETemp.CountryCode = C_UDTemp.CountryCode and C_UDTemp.ParentId=UETemp.ParentID)                                                
    --      inner join #TableData2 t2 on UE.EnquiryID = t2.ID   where  t2.Sno between @mincount and @maxcount           
    -- --where UE.EnquiryID in(Select fs.value from dbo.fn_Split(@EnqID, '#') AS fs )            
    --)     
 and   t2.Sno between @mincount and @maxcount                                                
            UNION                                        
            SELECT @BatchID,                                                          
                   CASE                                                           
                        WHEN @mobile1 = 1 THEN ISNULL(NULLIF( ue.MobileNo1,''),'0') ELSE '0'                                                          
                   END  AS Mobile,                                               
               CASE                        
                WHEN @mobile1 = 1 THEN ISNULL(ue.CountryCode1 ,'')                                              
                ELSE '' END AS CountryCode ,   
    content as Messagetext,  
    --            dbo.fn_getEnquiryMessageSMS_new(ue.ParentID, @Message, ue.MobileNo1,ue.EnquiryID) AS                                                           
    --Messagetext,                                                          
                   NULL         AS MessageStatus,                 
                   @SenderID    AS SenderID,                                                          
                   GETDATE()    AS MessageInsertDate,                                                          
  NULL         AS ScheduledDate,                                                    
                   NULL         AS ScheduledTime,  
       2 AS SmppID,  
                   --(                                                          
                   --  SELECT TOP 1 ud.SmppID                                                          
                   --    FROM   User_Detail AS ud                                                 
                   --    WHERE  ud.[User_ID] = @Account                                                          
                   --)            AS SmppID,                                                          
                   @ParentAccount     AS U_ID,                                                          
    @IsUnicode   AS IsUnicode,                                                          
                   0            AS IsDnd,                                                          
                   0            AS IsAirtel,                                                 
                   0            AS MobileSubSet,                                                          
                   1            AS ValidNo,                                                          
                   1            AS IsPrority,                                                          
              0            AS IsAllowDND,                                                    
                   0            AS DBType  ,               
       ue.EnquiryID as [EnquiryId]              
            FROM   UserEnquiry  AS ue (nolock)                                                         
            inner join #TableData2 t2 on ue.EnquiryID = t2.ID     
   join #entitypcvalues e on e.entityid=ue.EnquiryID  
