    --   where  t2.Sno between @mincount and @maxcount          
    --               --where UE.EnquiryID in(Select fs.value from dbo.fn_Split(@EnqID, '#') AS fs )            
    --   )           
    and  t2.Sno between @mincount and @maxcount                                               
            UNION                                                          
            SELECT @BatchID,                                                          
                   CASE                                                           
                        WHEN @Mobile2 = 1 THEN ISNULL(NULLIF(ue.MobileNo2,''),'0') ELSE '0'                                            
                   END  AS Mobile,                                               
               CASE                                                           
                WHEN @Mobile2 = 1 THEN ISNULL(ue.CountryCode2 ,'')                                              
                ELSE '' END AS CountryCode ,   
    content as messagetext,  
           --   dbo.fn_getEnquiryMessageSMS_new(ue.ParentID, @Message, ue.MobileNo2,ue.EnquiryID) AS                                    
           --Messagetext,                                                          
                   NULL         AS MessageStatus,                                                          
                   @SenderID    AS SenderID,                                                          
                   GETDATE()    AS MessageInsertDate,                                                          
                   NULL         AS ScheduledDate,                                                       
                   NULL         AS ScheduledTime,    
       2 as smppid,  
                   --(                                                          
                   --    SELECT TOP 1 ud.SmppID                                                          
                   --    FROM   User_Detail AS ud                                                          
                   --    WHERE  ud.[User_ID] = @Account                                                          
                   --)            AS SmppID,                                                          
                   @ParentAccount     AS U_ID,                                                          
           @IsUnicode   AS IsUnicode,                                            
                   0            AS IsDnd,                                                          
                   0            AS IsAirtel,                           
                   0            AS MobileSubSet,                                                          
                   1            AS ValidNo,                                                          
                   1            AS IsPrority,                                      
                   0            AS IsAllowDND,                                                          
                   0            AS DBType  ,               
       ue.EnquiryID as [EnquiryId]                                                                   
            FROM   UserEnquiry  AS ue (nolock)                                                    
  inner join #TableData2 t2 on ue.EnquiryID = t2.ID    
  join #entitypcvalues e on e.entityid=ue.enquiryid  
  WHERE              
  --ue.EnquiryID IN (SELECT [value] FROM   dbo.fn_Split(@EnqID, '#') AS fs) AND            
                 
     ISNULL(NULLIF(ue.MobileNo2, ''), '') <> ''                                                      
       --             AND ISNULL(NULLIF(ue.MobileNo2, ''), '') not in                                                    
       --            (                                 
       --            select  ISNULL(C_UDTemp.Mobile,'') as MobileNo2                                                     
       --            from UserEnquiry UETemp(nolock) inner join Client_UnSubscribeDetails C_UDTemp (nolock)                                                
       --     on (UeTemp.MobileNo2 =C_UDTemp.Mobile and                                               
       --            UETemp.CountryCode2 = C_UDTemp.CountryCode and C_UDTemp.ParentId=UETemp.ParentID)           inner join #TableData2 t2 on ue.EnquiryID = t2.ID        
       --where  t2.Sno between @mincount and @maxcount          
       --            --where UE.EnquiryID in(Select fs.value from dbo.fn_Split(@EnqID, '#') AS fs )            
       --)       
    and  t2.Sno between @mincount and @maxcount                                                   
        ) A                                                     
 WHERE  A.Mobile <> '0'                                              


 
