  declare @entity nvarchar(20)='Enquiry',@entityplaceholders nvarchar(2000)                                         
  drop table if exists #entitypcvalues
  
  declare @entities as entities
  create table #entitypcvalues(entityid bigint,content nvarchar(max))
    select @entityplaceholders=dbo.ExtractPlaceholders(@entity,@message)

   insert into @entities(entity,entityid)
   select @entity,ID from #TableData2--Tbl_MassOperationDetails(nolock) where SummaryId=@massbatchid  

   if @entityplaceholders<>''
   begin
   insert into #entitypcvalues(entityid,content)
   exec [usp_replaceentityplaceholders_bulk_singlecontent] @entities,@message,@entityplaceholders 
   end
   else
   begin
     insert into #entitypcvalues(entityid,content)
     select entityid,@message from @entities
  end   
  
  
 DECLARE @CurrentBalance decimal(18,4)
Declare @NoOfSMS  bigint = 0, @intsms bigint =0,@sms_cost numeric(18,4),@tot_price numeric(18,4);  
 DECLARE  @servicetype varchar(100),@credittypeid int,@eligible int=0 ;

 select @sms_cost=(      
    SELECT top 1  isnull(PTrns,0)      
    FROM dbo.Price_Base_SMS_RateDeduction      
      BR (nolock) where BR.OriginCountryCode = '+91'   and br.destinationcountrycode='+91'        
    ) 
SElecT @tot_price = sum(cast((      
    CASE       
     WHEN dbo.fn_isunicode(content) = 0      
      AND len(content) <= 160      
      THEN 1      
     WHEN dbo.fn_isunicode(content) = 0      
      AND LEN(content) > 160      
      THEN ceiling(LEN(content) / cast(153 AS FLOAT))      
     WHEN dbo.fn_isunicode(content) = 1      
      AND len(content) <= 70      
      THEN 1      
     ELSE ceiling(LEN(content) / cast(67 AS FLOAT))      
     END      
    ) as int) * @sms_cost) from #entitypcvalues
  
  set @servicetype='DomesticSMS';
  select @credittypeid=CreditTypeID from Price_Master_TypeCredit(nolock) where CreditName=@servicetype
    SET @CurrentBalance = dbo.GetAvailableBalanceForService(@ParentAccount,@credittypeid);

select @eligible=case when dbo.GetAvailableBalanceForService(@ParentAccount,@credittypeid)-@tot_price>=0 then 1 else 0 end

if  @eligible=1
begin
select * into #clonemessagedeliverystatus from CloneMessageDeliveryStatus(nolock) where MessageID=0

