        --WHERE  ud.[User_ID] = @Account                                            
        --           )           AS SmppID,                                            
                   @ParentAccount    AS U_ID,                                            
                   @IsUnicode  AS IsUnicode,                                            
                   0           AS IsDnd,                    
                   0           AS IsAirtel,                                            
                   0           AS MobileSubSet,                                            
                   1           AS ValidNo,                                            
                   1           AS IsPrority,                                            
                   0           AS IsAllowDND,                                            
