       --      inner join #TableData2 tb2 on UE.ID = tb2.ID   and   tb2.SNo between @sno and @sno+100      
       --            --where UE.ID in(Select fs.value from dbo.fn_Split(@ID, '#') AS fs )        
       --) 
	   and tb2.SNo between @sno and @sno+100                                        
            UNION                                              
            SELECT @BatchID,                                            
                   CASE                                             
                        WHEN @mobile1 = 1 THEN ISNULL(NULLIF(ue.MobileNo1, ''), '0') ELSE '0'                                            
                   END AS Mobile,                            
                   CASE                                         
                WHEN @Mobile = 1 THEN ISNULL(ue.CountryCode ,'')                            
                ELSE '' END AS CountryCode,                      
    -- dbo.fn_getLeadsMessage_new(ue.ParentID, @Message, ue.MobileNo1) AS Messagetext,  
	content as Messagetext,
                   NULL       AS MessageStatus,                                            
                   @SenderID,                                            
     GETDATE(),                                            
                   NULL,                                            
                   NULL,
				   2 AS SmppID,
      --             (                                            
      --                 SELECT TOP 1 ud.SmppID                                            
      --FROM   User_Detail AS ud                                            
      --        WHERE  ud.[User_ID] = @Account                                            
      --          ),                                            
                   @ParentAccount,                                            
                   @IsUnicode,               
                   0,                                            
                   0,                                            
                   0,                                            
                   1,                                            
                   1,                                            
                   0,                                            
          0,          
       ue.ID as [LeadId]                                                              
            FROM   UserLeads  AS ue (nolock)                                           
             inner join #TableData2 t2 on ue.ID = t2.ID   
			join #entitypcvalues e on e.entityid=ue.ID       
   WHERE         
   --ue.ID IN (SELECT [value] FROM   dbo.fn_Split(@ID, '#') AS fs) AND        
   ISNULL(NULLIF(ue.MobileNo1, ''), '') < > ''                                        
       --                 AND ISNULL(NULLIF(ue.MobileNo1, ''), '') not in                                       
       --            (                          
       --            select  ISNULL(C_UDTemp.Mobile,'') as MobileNo1                                       
       --            from UserLeads UETemp inner join Client_UnSubscribeDetails C_UDTemp                                      
       --            on (UeTemp.MobileNo1 =C_UDTemp.Mobile and                             
       --            UETemp.CountryCode1 = C_UDTemp.CountryCode)                                      
       --inner join #TableData2 tb2 on UETemp.ID = tb2.ID     and   tb2.SNo between @sno and @sno+100    
       --            --where UE.ID in(Select fs.value from dbo.fn_Split(@ID, '#') AS fs )        
       --)     
	   and   tb2.SNo between @sno and @sno+100                                       
            UNION                                              
            SELECT @BatchID,                                            
                   CASE             
                        WHEN @Mobile2 = 1 THEN ISNULL(NULLIF(ue.MobileNo2, ''), '0') ELSE '0'                                            
                   END AS Mobile,                            
                   CASE WHEN @Mobile = 1 THEN ISNULL(ue.CountryCode ,'')                            
       ELSE '' END AS CountryCode,
	   content as messagetext,
                   --dbo.fn_getLeadsMessage_new(ue.ParentID, @Message, ue.MobileNo2),                                            
                   NULL       AS MessageStatus,                                            
                   @SenderID,                                            
                   GETDATE(),                                            
                   NULL,                          
                   NULL,                                            
                   --(                                            
                   --    SELECT TOP 1 ud.SmppID                                            
                   --    FROM   User_Detail AS ud                                            
                   --    WHERE  ud.[User_ID] = @Account                                            
                   --),
				    2 as smppid,
                   @ParentAccount,                                            
                   @IsUnicode,                                            
                   0,                                            
                   0,                                            
                   0,                                            
                   1,                                            
                   1,                                            
                   0,                                
                   0,          
       ue.ID as [LeadId]                            
            FROM   UserLeads  AS ue                                            
      inner join #TableData2 t2 on ue.ID = t2.ID  
  join #entitypcvalues e on e.entityid=ue.ID         
            WHERE         
   --ue.ID IN (SELECT [value] FROM   dbo.fn_Split(@ID, '#') AS fs) AND         
   ISNULL(NULLIF(ue.MobileNo2, ''), '') <> ''                                       
  --               AND ISNULL(NULLIF(ue.MobileNo2, ''), '') not in                                      
  --                 (select  ISNULL(C_UDTemp.Mobile,'') as MobileNo2                                       
  --                 from UserLeads UETemp inner join Client_UnSubscribeDetails C_UDTemp                                      
  --                 on (UeTemp.MobileNo2 =C_UDTemp.Mobile                             
  --                 and UETemp.CountryCode2 = C_UDTemp.CountryCode)                                      
  --     inner join #TableData2 tb2 on UETemp.ID = tb2.ID   and   tb2.SNo between @sno and @sno+100       
  --   --where UE.ID in(Select fs.value from dbo.fn_Split(@ID, '#') AS fs )        
  --)        
  and   tb2.SNo between @sno and @sno+100                              
        ) A                                            
 WHERE  A.Mobile <> '0'                                              
                             
  if @Uccode = '+91'                            
 begin                            
  insert into #tmpflint (BatchID, Country_code,Mobile, Message, MessageStatus, SenderID,                                        
     MessageInsertDate, ScheduledDate, ScheduledTime,                                        
     SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,                                        
     ValidNo, IsPrority, IsAllowDND, DBType)                             
   select BatchID, Country_code,replace(Country_code,'+','')+Mobile, Message, MessageStatus, SenderID,                                        
     MessageInsertDate, ScheduledDate, ScheduledTime,                                        
     SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,                                        
     ValidNo, IsPrority, IsAllowDND, DBType from  #tmpflind                            
   where Country_Code <>'+91'                            
  delete From #tmpflind where Country_Code <>'+91'                            
 end                            
 else                            
 begin                            
  insert into #tmpflint (BatchID, Country_code,Mobile, Message, MessageStatus, SenderID,                                        
     MessageInsertDate, ScheduledDate, ScheduledTime,                                        
     SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,                                        
     ValidNo, IsPrority, IsAllowDND, DBType)                             
   select BatchID, Country_code,Mobile, Message, MessageStatus, SenderID,                                        
     MessageInsertDate, ScheduledDate, ScheduledTime,                 
     SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,                                        
     ValidNo, IsPrority, IsAllowDND, DBType from  #tmpflind                            
 end                            
 Declare @NoOfSMS  bigint = 0, @intsms bigint =0;                             
 select @intsms = COUNT(*) from #tmpflint                              
                            
declare @intprc int = 0 , @indprc int = 0 
DECLARE  @servicetype varchar(100) ;
if @intsms > 0                            
begin                            
 update #tmpflint set price= (case when IsUniCode=0 and len(message)<=160  then 1                                   
 when IsUniCode=0 and LEN(message)>160 then ceiling(LEN(message)/cast(153 as FLOat))                                   
  when IsUniCode=1                                   
 and len(message)<=70 then 1 else ceiling(LEN(message)/cast(67 as float)) end )*                            
  (select price from dbo.IntSMSRateMast where country_code =#tmpflint.country_code)                              
                             
 declare @Cr_amt float,@balance float                                  
 select @Cr_amt = SUM(price) from #tmpflint                                  
 --select top 1 @balance= Balance from dbo.IntCredit_Details where USER_ID = @ParentAccount 
  set @servicetype='DomesticSMS';
    SET @balance = dbo.GetAvailableBalanceForService(@ParentAccount,21);
 if @balance < @Cr_amt                            
 set @intprc = 1                               
end                            
                            
if @intprc =0                            
begin                             
  select @NoOfSMS = COUNT(*) from #tmpflind                            
 if @NoOfSMS > 0                            
 begin  
 UPDATE #tmpflind      
  SET price = (      
    CASE       
     WHEN IsUniCode = 0      
      AND len(message) <= 160      
      THEN 1      
     WHEN IsUniCode = 0      
      AND LEN(message) > 160      
      THEN ceiling(LEN(message) / cast(153 AS FLOAT))      
     WHEN IsUniCode = 1      
      AND len(message) <= 70      
      THEN 1      
     ELSE ceiling(LEN(message) / cast(67 AS FLOAT))      
     END      
    ) * (      
    SELECT top 1  isnull(price,0)      
    FROM dbo.Price_Base_SMS_RateDeduction      
     BR (nolock) where BR.OriginCountryCode = '+91'      
    )      
      
  DECLARE @Cr_amt1 decimal(18,4)      
   ,@balance1 decimal(18,4)      
      
  SELECT @Cr_amt1 = SUM(isnull(price,0))      
  FROM #tmpflind  
  DECLARE @CurrentBalance decimal(18,2)
  set @servicetype='DomesticSMS';
    SET @CurrentBalance = dbo.GetAvailableBalanceForService(@ParentAccount,21);
  --DECLARE @CurrentBalance BIGINT = (                                            
  --           SELECT TOP 1 isnull(cd.Balance,0)                                            
  --  FROM   Credit_Details AS cd                                        
  --           WHERE  cd.[User_ID] = @ParentAccount                                            
  --           ORDER BY                                            
  --                  cd.Credit_ID DESC                                            
  -- ) 
  DECLARE @mBalance decimal(18,4) = @CurrentBalance - (@NoOfSMS*@Cr_amt1) 
 --DECLARE @mBalance BIGINT = @CurrentBalance - @NoOfSMS                                            
 IF @mBalance > 0                                
   begin                            
 INSERT INTO CloneMessageDeliveryStatus                                        
   (BatchID, Mobile, Message, MessageStatus, SenderID,                                        
     MessageInsertDate, ScheduledDate, ScheduledTime,                                        
     SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,                                        
     ValidNo, IsPrority, IsAllowDND, DBType,CMDS_CreatedBy)                                    
 select BatchID, Mobile, Message, MessageStatus, SenderID,                                        
     MessageInsertDate, isnull(ScheduledDate,''), isnull(ScheduledTime,''),                                        
     SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,                                        
     ValidNo, IsPrority, IsAllowDND, DBType,@UserId from #tmpflind                            
             
    Begin try            
        exec Usp_Save_DLTTemplateID_with_BatchID @batchid,@DLTTemplateID            
    End try            
    begin catch            
      exec usp_InsertErrorInfo            
    End catch               
             
                               
   end                            
   else                        
 set @indprc = 1                            
 end                            
end                            
 if @intprc  = 1 and @indprc  = 0                            
 begin                            
  insert into CloneIntMsgDeliveryStatus                            
  (BatchID, Country_code, Mobile, Message, MessageStatus, SenderID,                     
  MessageInsertDate, ScheduledDate, ScheduledTime, SmppID, U_ID, IsUniCode,                             
  IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType,                             
  campaignid, Processed, Hasvirtualcredits, HasSufficientvirtualcredits, price,CIMDS_CreatedBy)                            
  select BatchID, Country_code, Mobile, Message, MessageStatus, SenderID,                            
   MessageInsertDate, isnull(ScheduledDate,''), isnull(ScheduledTime,''), SmppID, U_ID, IsUniCode,                             
   IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType,                             
   campaignid, Processed, Hasvirtualcredits, HasSufficientvirtualcredits,                             
   price,@UserId from #tmpflint             
               
               
   Begin try            
        exec Usp_Save_DLTTemplateID_with_BatchID @batchid,@DLTTemplateID            
    End try            
    begin catch            
      exec usp_InsertErrorInfo            
    End catch               
                              
 end                            
 if (@intprc  = 0 and @indprc  = 0)          
 begin          
    if(@UserId  > 0 )            
   begin            
   declare @leadActivityHistory AS LeadActivitywithid_Tbltype            
   declare  @Username nvarchar(255), @ParentId bigint = 0            
              
   select @Username = User_Login, @ParentId = ParentID from User_Detail(nolock) where User_Id = @UserId            
              
   insert into @leadActivityHistory ( LeadID, UserID, ParentID, EventDescription, EventName, RefTable, refid )            
   select             
   leadid,            
   @UserId,             
   @parentid,            
   concat(@Username , ' sent an sms with content ',  Message, ' on mobile ', Mobile),            
   'SMS sent to lead',            
   'Batchinfo',                
   @BatchID            
   from #tmpflind            
        exec UspSaveentityActivity_withMultipleValue_withid_bulk @leadActivityHistory         
  delete from @leadActivityHistory    
   --exec UspSaveLeadActivity_withMultipleValue_withid @leadActivityHistory            
   end     
       
  SELECT 'Record Saved'        
                     
 if @massbatchid IS NOT NULL AND @massbatchid <> 0      
BEGIN      
 --Update  Tbl_MassOperationSummary set BatchEndTime= GetDate() , ScheduleDateTime=@startDateTime, Remarks = 'Record Saved ', IsProcessed=1 where BatchID=@massbatchid 
 UPDATE Tbl_MassOperationSummary
        SET BatchEndTime = GETDATE(),
            ScheduleDateTime = CASE 
                                 WHEN ScheduleDateTime IS NULL OR ScheduleDateTime = '' OR ScheduleDateTime = '1900-01-01 00:00:00.000'
                                 THEN @startDateTime
                                 ELSE ScheduleDateTime
                               END,
            Remarks = 'Record Saved',
            IsProcessed = 1
        WHERE BatchID = @massbatchid;
END      
 end          
 else          
 begin          
  select 'Insufficient Balance'          
 end          
   set @sno=@sno+100    
   set @ttcount =@ttcount-100    
   end              
       
   Declare @rowJson nvarchar(max) = (Select * from CloneIntMsgDeliveryStatus where batchid=@BatchID for json auto, Include_null_values)    
    EXEC Mysms.dbo.Usp_AuditTableDataByParentId @User_id = @UserId    
  ,@Activity_type = 'Inst_MassSms_Lead'    
  ,@ActionType = 'I'    
  ,@RowJson = @rowJson    
  ,@Table_name = 'CloneEmailsFilter'                  
END 



GO

