 @Mobile2 BIT,            
 @DLTTemplateID nvarchar(200),        
 @UserId bigint  ,      
 @massbatchid bigint ,  
 @startDateTime nvarchar(100) = null  
AS                                            
BEGIN                                            
 -- BatchID -- this column value is auto-generated                                                  
        
   declare @ParentAccount bigint = ( select top 1 ParentID from User_Detail with(nolock) where User_ID = @Account)      
   declare    @ttcount int, @sno int  =1      
    drop table if exists #TableData2        
CREATE TABLE #TableData2 ( Sno int identity, ID BIGINT )        
      if @massbatchid IS NOT NULL AND @massbatchid <> 0      
BEGIN      
 select @ID= STRING_AGG(cast(Entityid as nvarchar(max)),'#') from Tbl_MassOperationDetails(nolock) where SummaryId=@massbatchid       
 --Update  Tbl_MassOperationSummary set BatchStartTime= GetDate(),ScheduleDateTime=@startDateTime  where BatchID=@massbatchid
 UPDATE Tbl_MassOperationSummary
        SET BatchStartTime = GETDATE(),
            ScheduleDateTime = CASE 
                                 WHEN ScheduleDateTime IS NULL OR ScheduleDateTime = '' OR ScheduleDateTime = '1900-01-01 00:00:00.000'
                                 THEN @startDateTime
                                 ELSE ScheduleDateTime
                               END
        WHERE BatchID = @massbatchid;

END      
INSERT INTO #TableData2 (ID)                   
SELECT fs.[value] FROM   dbo.fn_Split(@ID, '#') fs        
              
    Select @ttcount = count(1) from #TableData2     
    
 INSERT INTO GetBatchRecord                                            
   (                                            
     [User_id],                                            
     RandNum                                            
   )                                            
 VALUES                                            
   (                                            
     @Account,                                            
     @Account                                            
   )                                                  
                                             
  DECLARE @BatchID BIGINT = scope_identity()                         
                                                                         
  DELETE                                             
 FROM   GetBatchRecord                                            
 WHERE  [User_id] = @Account                                              
                             
   CREATE TABLE #tmpflint(                            
 [BatchID] [bigint]  NULL,                            
 [Country_code] [varchar](10) NULL,                            
 [Mobile] [varchar](20) NULL,                            
 [Message] [nvarchar](2500) NULL,                            
 [MessageStatus] [varchar](20) NULL,                            
 [SenderID] [nchar](20) NULL,                            
 [MessageInsertDate] [datetime]  NULL,                            
 [ScheduledDate] [varchar](50) NULL,                            
 [ScheduledTime] [varchar](50) NULL,                            
 [SmppID] [tinyint]  NULL,                            
 [U_ID] [int]  NULL,                            
 [IsUniCode] [bit]  NULL,                            
 [IsDnd] [bit]  NULL,                            
 [IsAirtel] [bit]  NULL,                            
 [MobileSubSet] [bigint] NULL,                            
 [ValidNo] [tinyint] NULL,                            
 [IsPrority] [tinyint] NULL,                            
 [IsAllowDND] [tinyint] NULL,                            
 [DBType] [nchar](10) NULL,                            
 [campaignid] [bigint] NULL,                            
 [Processed] [int] NULL,                            
 [Hasvirtualcredits] [int] NULL,                            
 [HasSufficientvirtualcredits] [int] NULL,                            
 [price] [float] NULL                            
)                            
--drop table #tmpflind                            
CREATE TABLE #tmpflind(                            
 [BatchID] [bigint]  NULL,      
 [Country_code] [varchar](10) NULL,                            
 [Mobile] [varchar](20) NULL,                            
 [Message] [nvarchar](2500) NULL,                            
 [MessageStatus] [varchar](20) NULL,                            
 [SenderID] [nchar](20) NULL,                            
 [MessageInsertDate] [datetime]  NULL,                            
 [ScheduledDate] [varchar](50) NULL,                            
 [ScheduledTime] [varchar](50) NULL,                            
 [SmppID] [tinyint]  NULL,                            
 [U_ID] [int]  NULL,                            
 [IsUniCode] [bit]  NULL,                            
 [IsDnd] [bit]  NULL,                            
 [IsAirtel] [bit]  NULL,                            
 [MobileSubSet] [bigint] NULL,                            
 [ValidNo] [tinyint] NULL,                            
 [IsPrority] [tinyint] NULL,                   
 [IsAllowDND] [tinyint] NULL,                            
 [DBType] [nchar](10) NULL,          
 [LeadId] bigint--,                            
 --[campaignid] [bigint] NULL,                            
 --[Processed] [int] NULL,                      
 --[Hasvirtualcredits] [int] NULL,                            
 --[HasSufficientvirtualcredits] [int] NULL                            
)                            
                          
                          
                                             
declare @Uccode varchar(20) ='+91'                            
  --SELECT TOP 1 @Uccode =  CountryCode                            
  --FROM   User_Detail AS ud                                        
  --WHERE  ud.[User_ID] = @Account                          
 
   declare @entity nvarchar(20)='Lead',@entityplaceholders nvarchar(2000)                                         
  drop table if exists #entitypcvalues
  declare @entities as entities
  create table #entitypcvalues(entityid bigint,content nvarchar(max))
  
  select @entityplaceholders=dbo.ExtractPlaceholders(@entity,@message)

   insert into @entities(entity,entityid)
   select @entity,EntityID from Tbl_MassOperationDetails(nolock) where SummaryId=@massbatchid

   if @entityplaceholders<>''
   begin
   insert into #entitypcvalues(entityid,content)
   exec [usp_replaceentityplaceholders_bulk_singlecontent] @entities,@message
   end
   else
   begin
     insert into #entitypcvalues(entityid,content)
     select entityid,@message from @entities
  end






  while (@ttcount>0)    
  begin    
 INSERT INTO #tmpflind                                        
   ( BatchID,Mobile,Country_Code,Message,                                        
             MessageStatus, SenderID,MessageInsertDate,ScheduledDate,                                        
             ScheduledTime,SmppID,U_ID,IsUnicode,IsDnd,IsAirtel,MobileSubSet,                            
             ValidNo,IsPrority,IsAllowDND,DBType, LeadId                             
   )                                   
     SELECT BatchID,Mobile,CountryCode,Messagetext,                                        
             MessageStatus, SenderID,MessageInsertDate,ScheduledDate,                                        
        ScheduledTime,SmppID,U_ID,IsUnicode,IsDnd,IsAirtel,MobileSubSet,                            
             ValidNo,IsPrority,IsAllowDND,DBType, LeadId                       
 FROM   (                                            
            SELECT @BatchID    AS BatchID,                                            
                   CASE                                             
                        WHEN @Mobile = 1 THEN ISNULL(NULLIF(ue.MobileNo, ''), '0') ELSE '0'                                            
                  END         AS Mobile,                            
                   CASE                                         
                WHEN @Mobile = 1 THEN ISNULL(ue.CountryCode ,'')                            
                ELSE '' END AS CountryCode,     
				content Messagetext,
     --dbo.fn_getLeadsMessage_new(ue.ParentID, @Message, ue.MobileNo) AS Messagetext,                                            
                   NULL        AS MessageStatus,                                            
                   @SenderID   AS SenderID,                                            
                   GETDATE()   AS MessageInsertDate,                                            
                   NULL        AS ScheduledDate,                                            
                   NULL     AS ScheduledTime, 
				   2 SMPPID,
        --           (                                            
        --               SELECT TOP 1 ud.SmppID                                            
        --               FROM   User_Detail AS ud                                            
        --WHERE  ud.[User_ID] = @Account                                            
                   --)           AS SmppID,                                            
                   @parentaccount    AS U_ID,                                            
                   @IsUnicode  AS IsUnicode,                                            
                   0           AS IsDnd,                    
                   0           AS IsAirtel,                                            
                   0           AS MobileSubSet,                                            
                   1           AS ValidNo,                                            
                   1           AS IsPrority,                                            
                   0           AS IsAllowDND,                                            
                   0           AS DBType,          
       ue.ID as [LeadId]          
            FROM   UserLeads   AS ue  (nolock)                                          
   inner join #TableData2 tb2 on ue.ID = tb2.ID  
   join #entitypcvalues e on ue.enquiryid=e.entityid
            WHERE  
        ISNULL(NULLIF(ue.MobileNo, ''), '') <> ''                                             
      and tb2.SNo between @sno and @sno+100                                        
            UNION                                              
            SELECT @BatchID,                                            
                   CASE                                             
                        WHEN @mobile1 = 1 THEN ISNULL(NULLIF(ue.MobileNo1, ''), '0') ELSE '0'                                            
                   END AS Mobile,                            
                   CASE                                         
                WHEN @Mobile = 1 THEN ISNULL(ue.CountryCode ,'')                            
                ELSE '' END AS CountryCode,
				content,
     --dbo.fn_getLeadsMessage_new(ue.ParentID, @Message, ue.MobileNo1),                                            
                   NULL       AS MessageStatus,                                            
                   @SenderID,                                            
                   GETDATE(),                                            
                   NULL,                                            
                   NULL, 
				   2 SMPPID,
      --             (                                            
      --                 SELECT TOP 1 ud.SmppID                                            
      --FROM   User_Detail AS ud                                            
      --        WHERE  ud.[User_ID] = @Account                                            
      --          ),                                            
                   @ParentAccount,                                            
                   @IsUnicode,               
                   0,                                            
                   0,                                            
                   0,                                            
                   1,                                            
                   1,                                            
                   0,                                            
          0,          
       ue.ID as [LeadId]                                                              
            FROM   UserLeads  AS ue  (nolock)                                          
            inner join #TableData2 tb2 on ue.ID = tb2.ID  
			 join #entitypcvalues e on ue.enquiryid=e.entityid
   WHERE         
   ISNULL(NULLIF(ue.MobileNo1, ''), '') < > ''                                        
                     and   tb2.SNo between @sno and @sno+100                                       
            UNION                                              
            SELECT @BatchID,                                            
                   CASE             
                        WHEN @Mobile2 = 1 THEN ISNULL(NULLIF(ue.MobileNo2, ''), '0') ELSE '0'                                            
                   END AS Mobile,                            
                   CASE WHEN @Mobile = 1 THEN ISNULL(ue.CountryCode ,'')                            
       ELSE '' END AS CountryCode,
	              content,
                   --dbo.fn_getLeadsMessage_new(ue.ParentID, @Message, ue.MobileNo2),                                            
                   NULL       AS MessageStatus,                                            
                   @SenderID,                                            
                   GETDATE(),                                            
                   NULL,                          
                   NULL,                                            
                   2 SMPPID,
				   --(                                            
       --                SELECT TOP 1 ud.SmppID                                            
       --                FROM   User_Detail AS ud                                            
       --                WHERE  ud.[User_ID] = @Account                                            
       --            ),                                            
                   @ParentAccount,                                            
                   @IsUnicode,                                            
                   0,                                            
                   0,                                            
                   0,                                            
                   1,                                            
                   1,                                            
                   0,                                
                   0,          
       ue.ID as [LeadId]                            
            FROM   UserLeads  AS ue(nolock)                                            
       inner join #TableData2 tb2 on ue.ID = tb2.ID    
	    join #entitypcvalues e on ue.enquiryid=e.entityid
            WHERE         
   ISNULL(NULLIF(ue.MobileNo2, ''), '') <> ''                                       
                     and   tb2.SNo between @sno and @sno+100                              
        ) A                                            
 WHERE  A.Mobile <> '0'                                              
                             
  if @Uccode = '+91'                            
 begin                            
  insert into #tmpflint (BatchID, Country_code,Mobile, Message, MessageStatus, SenderID,                                        
     MessageInsertDate, ScheduledDate, ScheduledTime,                                        
     SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,                                        
     ValidNo, IsPrority, IsAllowDND, DBType)                             
   select BatchID, Country_code,replace(Country_code,'+','')+Mobile, Message, MessageStatus, SenderID,                                        
     MessageInsertDate, ScheduledDate, ScheduledTime,                                        
     SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,                                        
     ValidNo, IsPrority, IsAllowDND, DBType from  #tmpflind                            
   where Country_Code <>'+91'                            
  delete From #tmpflind where Country_Code <>'+91'                            
 end                            
 else                            
 begin                            
  insert into #tmpflint (BatchID, Country_code,Mobile, Message, MessageStatus, SenderID,                                        
     MessageInsertDate, ScheduledDate, ScheduledTime,                                        
     SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,                                        
     ValidNo, IsPrority, IsAllowDND, DBType)                             
   select BatchID, Country_code,Mobile, Message, MessageStatus, SenderID,                                        
     MessageInsertDate, ScheduledDate, ScheduledTime,                 
     SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,                                        
     ValidNo, IsPrority, IsAllowDND, DBType from  #tmpflind                            
 end                            
 Declare @NoOfSMS  bigint = 0, @intsms bigint =0;                             
 select @intsms = COUNT(*) from #tmpflint                              
                            
declare @intprc int = 0 , @indprc int = 0                            
if @intsms > 0                            
begin                            
 update #tmpflint set price= (case when IsUniCode=0 and len(message)<=160  then 1                                   
 when IsUniCode=0 and LEN(message)>160 then ceiling(LEN(message)/cast(153 as FLOat))                                   
  when IsUniCode=1                                   
 and len(message)<=70 then 1 else ceiling(LEN(message)/cast(67 as float)) end )*                            
  (select price from dbo.IntSMSRateMast(nolock) where country_code =#tmpflint.country_code)                              
                             
 declare @Cr_amt float,@balance float                                  
 select @Cr_amt = SUM(price) from #tmpflint                                  
 select top 1 @balance= Balance from dbo.IntCredit_Details(nolock) where USER_ID = @ParentAccount                              
 if @balance < @Cr_amt                            
 set @intprc = 1                               
end                            
                            
if @intprc =0                            
begin                             
  select @NoOfSMS = COUNT(*) from #tmpflind                            
 if @NoOfSMS > 0                            
 begin                            
  DECLARE @CurrentBalance BIGINT = (                                            
             SELECT TOP 1 isnull(cd.Balance,0)                                            
    FROM   Credit_Details AS cd (nolock)                                       
             WHERE  cd.[User_ID] = @ParentAccount                                            
             ORDER BY                                            
                    cd.Credit_ID DESC                                            
   )                                            
 DECLARE @mBalance BIGINT = @CurrentBalance - @NoOfSMS                                            
 IF @mBalance > 0                                
   begin                            
 INSERT INTO CloneMessageDeliveryStatus                                        
   (BatchID, Mobile, Message, MessageStatus, SenderID,                                        
     MessageInsertDate, ScheduledDate, ScheduledTime,                                        
     SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,                                        
     ValidNo, IsPrority, IsAllowDND, DBType,CMDS_CreatedBy)                                    
 select BatchID, Mobile, Message, MessageStatus, SenderID,                                        
     MessageInsertDate, isnull(ScheduledDate,''), isnull(ScheduledTime,''),                                        
     SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,                                        
     ValidNo, IsPrority, IsAllowDND, DBType,@UserId from #tmpflind                            
             
    Begin try            
        exec Usp_Save_DLTTemplateID_with_BatchID @batchid,@DLTTemplateID            
    End try            
    begin catch            
      exec usp_InsertErrorInfo            
    End catch               
             
                               
   end                            
   else                        
 set @indprc = 1                            
 end                            
end                            
 if @intprc  = 1 and @indprc  = 0                            
 begin                            
  insert into CloneIntMsgDeliveryStatus                            
  (BatchID, Country_code, Mobile, Message, MessageStatus, SenderID,                     
  MessageInsertDate, ScheduledDate, ScheduledTime, SmppID, U_ID, IsUniCode,                             
  IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType,                             
  campaignid, Processed, Hasvirtualcredits, HasSufficientvirtualcredits, price,CIMDS_CreatedBy)                            
  select BatchID, Country_code, Mobile, Message, MessageStatus, SenderID,                            
   MessageInsertDate, isnull(ScheduledDate,''), isnull(ScheduledTime,''), SmppID, U_ID, IsUniCode,                             
   IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType,                             
   campaignid, Processed, Hasvirtualcredits, HasSufficientvirtualcredits,                             
   price,@UserId from #tmpflint             
               
               
   Begin try            
        exec Usp_Save_DLTTemplateID_with_BatchID @batchid,@DLTTemplateID            
    End try            
    begin catch            
      exec usp_InsertErrorInfo            
    End catch               
                              
 end                            
 if (@intprc  = 0 and @indprc  = 0)          
 begin          
    if(@UserId  > 0 )            
   begin            
   declare @leadActivityHistory AS LeadActivitywithid_Tbltype            
   declare  @Username nvarchar(255), @ParentId bigint = 0            
              
   select @Username = User_Login, @ParentId = ParentID from User_Detail(nolock) where User_Id = @UserId            
              
   insert into @leadActivityHistory ( LeadID, UserID, ParentID, EventDescription, EventName, RefTable, refid )            
   select             
   leadid,            
   @UserId,             
   @parentid,            
   concat(@Username , ' sent an sms with content ',  Message, ' on mobile ', Mobile),            
   'SMS sent to lead',            
   'Batchinfo',                
   @BatchID            
   from #tmpflind            
        exec UspSaveentityActivity_withMultipleValue_withid_bulk @leadActivityHistory         
  delete from @leadActivityHistory    
   --exec UspSaveLeadActivity_withMultipleValue_withid @leadActivityHistory            
   end     
       
  SELECT 'Record Saved'        
                     
 if @massbatchid IS NOT NULL AND @massbatchid <> 0      
BEGIN      
 --Update  Tbl_MassOperationSummary set BatchEndTime= GetDate() , ScheduleDateTime=@startDateTime, Remarks = 'Record Saved ', IsProcessed=1 where BatchID=@massbatchid 
 UPDATE Tbl_MassOperationSummary
        SET BatchEndTime = GETDATE(),
            ScheduleDateTime = CASE 
                                 WHEN ScheduleDateTime IS NULL OR ScheduleDateTime = '' OR ScheduleDateTime = '1900-01-01 00:00:00.000'
                                 THEN @startDateTime
                                 ELSE ScheduleDateTime
                               END,
            Remarks = 'Record Saved',
            IsProcessed = 1
        WHERE BatchID = @massbatchid;
END      
 end          
 else          
 begin          
  select 'Insufficient Balance'          
 end          
   set @sno=@sno+100    
   set @ttcount =@ttcount-100    
   end              
     drop table if exists #TableData2     
   Declare @rowJson nvarchar(max) = (Select * from CloneIntMsgDeliveryStatus where batchid=@BatchID for json auto, Include_null_values)    
    EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId    
  ,@Activity_type = 'Inst_MassSms_Lead'    
  ,@ActionType = 'I'    
  ,@RowJson = @rowJson    
  ,@Table_name = 'CloneEmailsFilter'                  
END 


