   declare  @Username nvarchar(255), @ParentId bigint = 0            
              
   select @Username = User_Login, @ParentId = ParentID from User_Detail(nolock) where User_Id = @UserId            
              
   insert into @leadActivityHistory ( LeadID, UserID, ParentID, EventDescription, EventName, RefTable, refid )            
   select             
   leadid,            
   @UserId,             
   @parentid,            
   concat(@Username , ' sent an sms with content ',  Message, ' on mobile ', Mobile),            
   'SMS sent to lead',            
   'Batchinfo',                
   @BatchID            
   from #tmpflind            
        exec UspSaveentityActivity_withMultipleValue_withid_bulk @leadActivityHistory         
  delete from @leadActivityHistory    
   --exec UspSaveLeadActivity_withMultipleValue_withid @leadActivityHistory            
   end     
        end            
  
  
  set @mincount =@mincount+100    
  --set @maxcount = @maxcount +100  
  set @sno=@sno+100
  delete from #tmpflind
  delete from #tmpflint

 ENd 
  SELECT 'Record Saved'        

INSERT INTO CloneMessageDeliveryStatus                                        
   (BatchID, Mobile, Message, MessageStatus, SenderID,                                        
     MessageInsertDate, ScheduledDate, ScheduledTime,                                        
     SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,                                        
     ValidNo, IsPrority, IsAllowDND, DBType,CMDS_CreatedBy)                                    
 select BatchID, Mobile, Message, MessageStatus, SenderID,                                        
     MessageInsertDate, ScheduledDate, ScheduledTime,                                        
     SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,                                        
     ValidNo, IsPrority, IsAllowDND, DBType,CMDS_CreatedBy from #CloneMessageDeliveryStatus   
 
 delete from #CloneMessageDeliveryStatus

 Declare @rowJson nvarchar(max) = (Select * from batchinfo(nolock) where batchid=@BatchID for json auto, Include_null_values)    
    EXEC mysms.dbo.Usp_AuditTableDataByParentId @User_id = @UserId    
  ,@Activity_type = 'MassSms_Lead'    
  ,@ActionType = 'I'    
  ,@RowJson = @rowJson    
  ,@Table_name = 'batchinfo'                  


 if @massbatchid IS NOT NULL AND @massbatchid <> 0      
BEGIN      
 --Update  Tbl_MassOperationSummary set BatchEndTime= GetDate() , ScheduleDateTime=@startDateTime, Remarks = 'Record Saved ', IsProcessed=1 where BatchID=@massbatchid 
 UPDATE Tbl_MassOperationSummary
        SET BatchEndTime = GETDATE(),
            ScheduleDateTime = CASE 
                                 WHEN ScheduleDateTime IS NULL OR ScheduleDateTime = '' OR ScheduleDateTime = '1900-01-01 00:00:00.000'
                                 THEN @startDateTime
                                 ELSE ScheduleDateTime
                               END,
            Remarks = 'Record Saved',
            IsProcessed = 1
        WHERE BatchID = @massbatchid;
END      
 
 
 end
  Else                                           
    begin            
  select 'Insufficient Balance'              
 if @massbatchid IS NOT NULL AND @massbatchid <> 0      
BEGIN 
 UPDATE Tbl_MassOperationSummary
        SET BatchEndTime = GETDATE(),
            ScheduleDateTime = CASE 
                                 WHEN ScheduleDateTime IS NULL OR ScheduleDateTime = '' OR ScheduleDateTime = '1900-01-01 00:00:00.000'
                                 THEN @startDateTime
                                 ELSE ScheduleDateTime
                               END,
            Remarks = 'Insufficient Balance',
            IsProcessed = 1
        WHERE BatchID = @massbatchid;
end
 end        

 drop table if exists #TableData2     
   
END 






GO

/* ============================================================
   Procedure: [dbo].[usp_IntindSMSFromLeads_New_WithDLTTemplateID_PM]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_IntindSMSFromLeads_New_WithDLTTemplateID_PM]
     @ID VARCHAR(Max)
	,@Account BIGINT
	,@SenderID VARCHAR(50)
	,@Message NVARCHAR(2000)
	,@IsUnicode BIT
	,@Mobile BIT
	,@mobile1 BIT
	,@Mobile2 BIT
	,@DLTTemplateID NVARCHAR(200)
	,@UserId BIGINT
AS
BEGIN
	-- BatchID -- this column value is auto-generated                                            
	      
	
	
	
	DECLARE @ParentAccount BIGINT = (
			SELECT TOP 1 ParentID
			FROM User_Detail WITH (NOLOCK)
			WHERE User_ID = @Account
			)

	 declare @TblRectifiedMSG table(Row_Num int,Country_Code varchar(10),Mobile varchar(20),[Message] varchar(2500),[LeadID] bigint)
     
	  insert into @TblRectifiedMSG(Row_Num,Country_Code,Mobile,[Message],[LeadID])
	  exec Usp_GetLeadMessageNew @ID,@Message,@Mobile,@mobile1,@Mobile2,@ParentAccount 
   
    --exec Usp_GetLeadMessageNew '1214327#3888241#3888184','Hello #PersonName#  #LastProducts#',1,0,0,34594 
   -- select * from @TblRectifiedMSG




	CREATE TABLE #TableData2 (ID BIGINT)

	INSERT INTO #TableData2 (ID)
	SELECT fs.[value]
	FROM dbo.fn_Split(@ID, '#') fs

	INSERT INTO GetBatchRecord (
		[User_id]
		,RandNum
		)
	VALUES (
		@Account
		,@Account
		)

	DECLARE @BatchID BIGINT = scope_identity()

	DELETE
	FROM GetBatchRecord
	WHERE [User_id] = @Account

	CREATE TABLE #tmpflint (
		[BatchID] [bigint] NULL
		,[Country_code] [varchar](10) NULL
		,[Mobile] [varchar](20) NULL
		,[Message] [nvarchar](2500) NULL
		,[MessageStatus] [varchar](20) NULL
		,[SenderID] [nchar](20) NULL
		,[MessageInsertDate] [datetime] NULL
		,[ScheduledDate] [varchar](50) NULL
		,[ScheduledTime] [varchar](50) NULL
		,[SmppID] [tinyint] NULL
		,[U_ID] [int] NULL
		,[IsUniCode] [bit] NULL
		,[IsDnd] [bit] NULL
		,[IsAirtel] [bit] NULL
		,[MobileSubSet] [bigint] NULL
		,[ValidNo] [tinyint] NULL
		,[IsPrority] [tinyint] NULL
		,[IsAllowDND] [tinyint] NULL
		,[DBType] [nchar](10) NULL
		,[campaignid] [bigint] NULL
		,[Processed] [int] NULL
		,[Hasvirtualcredits] [int] NULL
		,[HasSufficientvirtualcredits] [int] NULL
		,[price] [float] NULL
		)

	--drop table #tmpflind                      
	CREATE TABLE #tmpflind (
		[BatchID] [bigint] NULL
		,[Country_code] [varchar](10) NULL
		,[Mobile] [varchar](20) NULL
		,[Message] [nvarchar](2500) NULL
		,[MessageStatus] [varchar](20) NULL
		,[SenderID] [nchar](20) NULL
		,[MessageInsertDate] [datetime] NULL
		,[ScheduledDate] [varchar](50) NULL
		,[ScheduledTime] [varchar](50) NULL
		,[SmppID] [tinyint] NULL
		,[U_ID] [int] NULL
		,[IsUniCode] [bit] NULL
		,[IsDnd] [bit] NULL
		,[IsAirtel] [bit] NULL
		,[MobileSubSet] [bigint] NULL
		,[ValidNo] [tinyint] NULL
		,[IsPrority] [tinyint] NULL
		,[IsAllowDND] [tinyint] NULL
		,[DBType] [nchar](10) NULL
		,[LeadId] BIGINT --,                      
		--[campaignid] [bigint] NULL,                      
		--[Processed] [int] NULL,                
		--[Hasvirtualcredits] [int] NULL,                      
		--[HasSufficientvirtualcredits] [int] NULL                      
		)

	DECLARE @Uccode VARCHAR(20)

	SELECT TOP 1 @Uccode = CountryCode
	FROM User_Detail AS ud (nolock)
	WHERE ud.[User_ID] = @Account

	INSERT INTO #tmpflind (
		BatchID
		,Mobile
		,Country_Code
		,Message
		,MessageStatus
		,SenderID
		,MessageInsertDate
		,ScheduledDate
		,ScheduledTime
		,SmppID
		,U_ID
		,IsUnicode
		,IsDnd
		,IsAirtel
		,MobileSubSet
		,ValidNo
		,IsPrority
		,IsAllowDND
		,DBType
		,LeadId
		)
	SELECT BatchID
		,Mobile
		,CountryCode
		,Messagetext
		,MessageStatus
		,SenderID
		,MessageInsertDate
		,ScheduledDate
		,ScheduledTime
		,SmppID
		,U_ID
		,IsUnicode
		,IsDnd
		,IsAirtel
		,MobileSubSet
		,ValidNo
		,IsPrority
		,IsAllowDND
		,DBType
		,LeadId
	FROM (
		SELECT @BatchID AS BatchID
			,CASE 
				WHEN @Mobile = 1
					THEN ISNULL(NULLIF(ue.MobileNo, ''), '0')
				ELSE '0'
				END AS Mobile
			,CASE 
				WHEN @Mobile = 1
					THEN ISNULL(ue.CountryCode, '')
				ELSE ''
				END AS CountryCode
			--,dbo.fn_getLeadsMessage_new(ue.ParentID, @Message, ue.MobileNo) AS Messagetext
			,tblMSG.Message AS Messagetext
			,NULL AS MessageStatus
			,@SenderID AS SenderID
			,GETDATE() AS MessageInsertDate
			,NULL AS ScheduledDate
			,NULL AS ScheduledTime
			,(
				SELECT TOP 1 ud.SmppID
				FROM User_Detail AS ud (nolock)
				WHERE ud.[User_ID] = @Account
				) AS SmppID
			,@Account AS U_ID
			,@IsUnicode AS IsUnicode
			,0 AS IsDnd
			,0 AS IsAirtel
			,0 AS MobileSubSet
			,1 AS ValidNo
			,1 AS IsPrority
			,0 AS IsAllowDND
			,0 AS DBType
			,ue.ID AS [LeadId]
		FROM UserLeads AS ue (nolock)
		INNER JOIN #TableData2 tb2 ON ue.ID = tb2.ID
		inner join @TblRectifiedMSG as tblMSG on ue.ID = tblMSG.LeadID 
		                                     and ue.MobileNo = tblMSG.Mobile 
		WHERE --ue.ID IN (SELECT [value] FROM  dbo.fn_Split(@ID, '#') AS fs) AND   
			ISNULL(NULLIF(ue.MobileNo, ''), '') <> ''
			AND ISNULL(NULLIF(ue.MobileNo, ''), '') NOT IN (
				SELECT ISNULL(C_UDTemp.Mobile, '') AS MobileNo
				FROM UserLeads UETemp (nolock)
				INNER JOIN Client_UnSubscribeDetails (nolock) C_UDTemp ON (
						UeTemp.MobileNo = C_UDTemp.Mobile
						AND UETemp.CountryCode = C_UDTemp.CountryCode
						)
				INNER JOIN #TableData2 tb2 ON UE.ID = tb2.ID
				)
		--where UE.ID in(Select fs.value from dbo.fn_Split(@ID, '#') AS fs )  
		
		UNION
		
		SELECT @BatchID
			,CASE 
				WHEN @mobile1 = 1
					THEN ISNULL(NULLIF(ue.MobileNo1, ''), '0')
				ELSE '0'
				END AS Mobile
			,CASE 
				WHEN @Mobile = 1
					THEN ISNULL(ue.CountryCode, '')
				ELSE ''
				END AS CountryCode
			--,dbo.fn_getLeadsMessage_new(ue.ParentID, @Message, ue.MobileNo1)
			,tblMSG.Message
			,NULL AS MessageStatus
			,@SenderID
			,GETDATE()
			,NULL
			,NULL
			,(
				SELECT TOP 1 ud.SmppID
				FROM User_Detail AS ud
				WHERE ud.[User_ID] = @Account
				)
			,@Account
			,@IsUnicode
			,0
			,0
			,0
			,1
			,1
			,0
			,0
			,ue.ID AS [LeadId]
		FROM UserLeads AS ue (nolock)
		INNER JOIN #TableData2 tb2 ON ue.ID = tb2.ID
		inner join @TblRectifiedMSG as tblMSG on ue.ID = tblMSG.LeadID
		                           and ue.MobileNo1 = tblMSG.Mobile 
		WHERE
			--ue.ID IN (SELECT [value] FROM   dbo.fn_Split(@ID, '#') AS fs) AND  
			ISNULL(NULLIF(ue.MobileNo1, ''), '') < > ''
			AND ISNULL(NULLIF(ue.MobileNo1, ''), '') NOT IN (
				SELECT ISNULL(C_UDTemp.Mobile, '') AS MobileNo1
				FROM UserLeads UETemp (nolock)
				INNER JOIN Client_UnSubscribeDetails (nolock) C_UDTemp ON (
						UeTemp.MobileNo1 = C_UDTemp.Mobile
						AND UETemp.CountryCode1 = C_UDTemp.CountryCode
						)
				INNER JOIN #TableData2 tb2 ON UETemp.ID = tb2.ID
				)
		--where UE.ID in(Select fs.value from dbo.fn_Split(@ID, '#') AS fs )  
		
		UNION
		
		SELECT @BatchID
			,CASE 
				WHEN @Mobile2 = 1
					THEN ISNULL(NULLIF(ue.MobileNo2, ''), '0')
				ELSE '0'
				END AS Mobile
			,CASE 
				WHEN @Mobile = 1
					THEN ISNULL(ue.CountryCode, '')
				ELSE ''
				END AS CountryCode
			--,dbo.fn_getLeadsMessage_new(ue.ParentID, @Message, ue.MobileNo2)
			,tblMsg.Message
			,NULL AS MessageStatus
			,@SenderID
			,GETDATE()
			,NULL
			,NULL
			,(
				SELECT TOP 1 ud.SmppID
				FROM User_Detail AS ud
				WHERE ud.[User_ID] = @Account
				)
			,@Account
			,@IsUnicode
			,0
			,0
			,0
			,1
			,1
			,0
			,0
			,ue.ID AS [LeadId]
		FROM UserLeads AS ue (nolock)
		INNER JOIN #TableData2 tb2 ON ue.ID = tb2.ID
		inner join @TblRectifiedMSG as tblMSG on ue.ID = tblMSG.LeadID
		                                      and ue.MobileNo2 = tblMSG.Mobile     
		
		WHERE
			--ue.ID IN (SELECT [value] FROM   dbo.fn_Split(@ID, '#') AS fs) AND   
			ISNULL(NULLIF(ue.MobileNo2, ''), '') <> ''
			AND ISNULL(NULLIF(ue.MobileNo2, ''), '') NOT IN (
				SELECT ISNULL(C_UDTemp.Mobile, '') AS MobileNo2
				FROM UserLeads UETemp (nolock)
				INNER JOIN Client_UnSubscribeDetails (nolock) C_UDTemp ON (
						UeTemp.MobileNo2 = C_UDTemp.Mobile
						AND UETemp.CountryCode2 = C_UDTemp.CountryCode
						)
				INNER JOIN #TableData2 tb2 ON UETemp.ID = tb2.ID
					--where UE.ID in(Select fs.value from dbo.fn_Split(@ID, '#') AS fs )  
				)
		) A
	WHERE A.Mobile <> '0'

	IF @Uccode = '+91'
	BEGIN
		INSERT INTO #tmpflint (
			BatchID
			,Country_code
			,Mobile
			,Message
			,MessageStatus
			,SenderID
			,MessageInsertDate
			,ScheduledDate
			,ScheduledTime
			,SmppID
			,U_ID
			,IsUniCode
			,IsDnd
			,IsAirtel
			,MobileSubSet
			,ValidNo
			,IsPrority
			,IsAllowDND
			,DBType
			)
		SELECT BatchID
			,Country_code
			,replace(Country_code, '+', '') + Mobile
			,Message
			,MessageStatus
			,SenderID
			,MessageInsertDate
			,ScheduledDate
			,ScheduledTime
			,SmppID
			,U_ID
			,IsUniCode
			,IsDnd
			,IsAirtel
			,MobileSubSet
			,ValidNo
			,IsPrority
			,IsAllowDND
			,DBType
		FROM #tmpflind
		WHERE Country_Code <> '+91'

		DELETE
		FROM #tmpflind
		WHERE Country_Code <> '+91'
	END
	ELSE
	BEGIN
		INSERT INTO #tmpflint (
			BatchID
			,Country_code
			,Mobile
			,Message
			,MessageStatus
			,SenderID
			,MessageInsertDate
			,ScheduledDate
			,ScheduledTime
			,SmppID
			,U_ID
			,IsUniCode
			,IsDnd
			,IsAirtel
			,MobileSubSet
			,ValidNo
			,IsPrority
			,IsAllowDND
			,DBType
			)
		SELECT BatchID
			,Country_code
			,Mobile
			,Message
			,MessageStatus
			,SenderID
			,MessageInsertDate
			,ScheduledDate
			,ScheduledTime
			,SmppID
			,U_ID
			,IsUniCode
			,IsDnd
			,IsAirtel
			,MobileSubSet
			,ValidNo
			,IsPrority
			,IsAllowDND
			,DBType
		FROM #tmpflind
	END

	DECLARE @NoOfSMS BIGINT = 0
		,@intsms BIGINT = 0;

	SELECT @intsms = COUNT(*)
	FROM #tmpflint

	DECLARE @intprc INT = 0
		,@indprc INT = 0

	IF @intsms > 0
	BEGIN
		UPDATE #tmpflint
		SET price = (
				CASE 
					WHEN IsUniCode = 0
						AND len(message) <= 160
						THEN 1
					WHEN IsUniCode = 0
						AND LEN(message) > 160
						THEN ceiling(LEN(message) / cast(153 AS FLOAT))
					WHEN IsUniCode = 1
						AND len(message) <= 70
						THEN 1
					ELSE ceiling(LEN(message) / cast(67 AS FLOAT))
					END
				) * (
				SELECT price
				FROM dbo.IntSMSRateMast
				WHERE country_code = #tmpflint.country_code
				)

		DECLARE @Cr_amt FLOAT
			,@balance FLOAT

		SELECT @Cr_amt = SUM(price)
		FROM #tmpflint

		SELECT TOP 1 @balance = Balance
		FROM dbo.IntCredit_Details
		WHERE USER_ID = @ParentAccount

		IF @balance < @Cr_amt
			SET @intprc = 1
	END

	IF @intprc = 0
	BEGIN
		SELECT @NoOfSMS = COUNT(*)
		FROM #tmpflind

		IF @NoOfSMS > 0
		BEGIN
			DECLARE @CurrentBalance BIGINT = (
					SELECT TOP 1 isnull(cd.Balance, 0)
					FROM Credit_Details AS cd
					WHERE cd.[User_ID] = @ParentAccount
					ORDER BY cd.Credit_ID DESC
					)
			DECLARE @mBalance BIGINT = @CurrentBalance - @NoOfSMS

			IF @mBalance > 0
			BEGIN
				INSERT INTO CloneMessageDeliveryStatus (
					BatchID
					,Mobile
					,Message
					,MessageStatus
					,SenderID
					,MessageInsertDate
					,ScheduledDate
					,ScheduledTime
					,SmppID
					,U_ID
					,IsUniCode
					,IsDnd
					,IsAirtel
					,MobileSubSet
					,ValidNo
					,IsPrority
					,IsAllowDND
					,DBType
					,CMDS_CreatedBy
					)
				SELECT BatchID
					,Mobile
					,Message
					,MessageStatus
					,SenderID
					,MessageInsertDate
					,isnull(ScheduledDate, '')
					,isnull(ScheduledTime, '')
					,SmppID
					,U_ID
					,IsUniCode
					,IsDnd
					,IsAirtel
					,MobileSubSet
					,ValidNo
					,IsPrority
					,IsAllowDND
					,DBType
					,@UserId
				FROM #tmpflind

				BEGIN TRY
					EXEC Usp_Save_DLTTemplateID_with_BatchID @batchid
						,@DLTTemplateID
				END TRY

				BEGIN CATCH
					EXEC usp_InsertErrorInfo
				END CATCH
			END
			ELSE
				SET @indprc = 1
		END
	END

	IF @intprc = 1
		AND @indprc = 0
	BEGIN
		INSERT INTO CloneIntMsgDeliveryStatus (
			BatchID
			,Country_code
			,Mobile
			,Message
			,MessageStatus
			,SenderID
			,MessageInsertDate
			,ScheduledDate
			,ScheduledTime
			,SmppID
			,U_ID
			,IsUniCode
			,IsDnd
			,IsAirtel
			,MobileSubSet
			,ValidNo
			,IsPrority
			,IsAllowDND
			,DBType
			,campaignid
			,Processed
			,Hasvirtualcredits
			,HasSufficientvirtualcredits
			,price
			,CIMDS_CreatedBy
			)
		SELECT BatchID
			,Country_code
			,Mobile
			,Message
			,MessageStatus
			,SenderID
			,MessageInsertDate
			,isnull(ScheduledDate, '')
			,isnull(ScheduledTime, '')
			,SmppID
			,U_ID
			,IsUniCode
			,IsDnd
			,IsAirtel
			,MobileSubSet
			,ValidNo
			,IsPrority
			,IsAllowDND
			,DBType
			,campaignid
			,Processed
			,Hasvirtualcredits
			,HasSufficientvirtualcredits
			,price
			,@UserId
		FROM #tmpflint

		BEGIN TRY
			EXEC Usp_Save_DLTTemplateID_with_BatchID @batchid
				,@DLTTemplateID
		END TRY

		BEGIN CATCH
			EXEC usp_InsertErrorInfo
		END CATCH
	END

	IF (
			@intprc = 0
			AND @indprc = 0
			)
	BEGIN
		IF (@UserId > 0)
		BEGIN
			DECLARE @leadActivityHistory AS LeadActivitywithid_Tbltype
			DECLARE @Username NVARCHAR(255)
				,@ParentId BIGINT = 0

			SELECT @Username = User_Login
				,@ParentId = ParentID
			FROM User_Detail(NOLOCK)
			WHERE User_Id = @UserId

			INSERT INTO @leadActivityHistory (
				LeadID
				,UserID
				,ParentID
				,EventDescription
				,EventName
				,RefTable
				,refid
				)
			SELECT leadid
				,@UserId
				,@parentid
				,CONCAT (
					@Username
					,' sent an sms with content '
					,Message
					,' on mobile '
					,Mobile
					)
				,'SMS sent to lead'
				,'Batchinfo'
				,@BatchID
			FROM #tmpflind

			EXEC UspSaveLeadActivity_withMultipleValue_withid @leadActivityHistory
		END

		SELECT 'Record Saved'

		DECLARE @rowJson NVARCHAR(MAX) = (
				SELECT *
				FROM CloneMessageDeliveryStatus ul(NOLOCK)
				WHERE ul.BatchID = @BatchID
				FOR JSON AUTO
					,INCLUDE_NULL_VALUES
				)

		IF @rowJson IS NOT NULL
		BEGIN
			EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId
				,@Activity_type = 'Inst_MassSms_Lead'
				,@ActionType = 'I'
				,@RowJson = @rowJson
				,@Table_name = 'CloneMessageDeliveryStatus'
		END
	END
	ELSE
	BEGIN
		SELECT 'Insufficient Balance'
	END
END



GO

/* ============================================================
   Procedure: [dbo].[usp_IntindSMSFromLeads_New1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROCEDURE [dbo].[usp_IntindSMSFromLeads_New1]                                    
 @ID VARCHAR(500),                                      
 @Account BIGINT,                                      
 @SenderID VARCHAR(50),                                      
 @Message NVARCHAR(4000),                                      
 @IsUnicode BIT,                                      
 @Mobile BIT,                                      
 @mobile1 BIT,                                      
 @Mobile2 BIT                                      
AS                                      
BEGIN                                      
 -- BatchID -- this column value is auto-generated                                            
      
 DECLARE @BatchID BIGINT         
      
 begin tran                                      
 INSERT INTO GetBatchRecord                                      
   (                                      
     [User_id],                                      
     RandNum                                      
   )                                      
 VALUES                                      
   (                                      
     @Account,                                      
     @Account                                      
   )                                            
select @BatchID =scope_identity()      
DELETE                                       
 FROM   GetBatchRecord                                      
 WHERE  batchid=@batchid                                        
commit      
                       
   CREATE TABLE #tmpflint(                      
 [BatchID] [bigint]  NULL,                      
 [Country_code] [varchar](10) NULL,                      
 [Mobile] [varchar](20) NULL,                      
 [Message] [nvarchar](2500) NULL,                      
 [MessageStatus] [varchar](20) NULL,                      
 [SenderID] [nchar](40) NULL,                      
 [MessageInsertDate] [datetime]  NULL,                      
 [ScheduledDate] [varchar](50) NULL,                      
 [ScheduledTime] [varchar](50) NULL,                      
 [SmppID] [tinyint]  NULL,                      
 [U_ID] [int]  NULL,                      
 [IsUniCode] [bit]  NULL,                      
 [IsDnd] [bit]  NULL,                      
 [IsAirtel] [bit]  NULL,                      
 [MobileSubSet] [bigint] NULL,                      
 [ValidNo] [tinyint] NULL,                      
 [IsPrority] [tinyint] NULL,                      
 [IsAllowDND] [tinyint] NULL,                      
 [DBType] [nchar](10) NULL,                      
 [campaignid] [bigint] NULL,                      
 [Processed] [int] NULL,                      
 [Hasvirtualcredits] [int] NULL,                      
 [HasSufficientvirtualcredits] [int] NULL,                      
 [price] [float] NULL                      
)                      
--drop table #tmpflind                      
CREATE TABLE #tmpflind(                      
 [BatchID] [bigint]  NULL,                      
 [Country_code] [varchar](10) NULL,                      
 [Mobile] [varchar](20) NULL,                      
 [Message] [nvarchar](2500) NULL,                      
 [MessageStatus] [varchar](20) NULL,                      
 [SenderID] [nchar](40) NULL,                      
 [MessageInsertDate] [datetime]  NULL,                      
 [ScheduledDate] [varchar](50) NULL,                      
 [ScheduledTime] [varchar](50) NULL,                      
 [SmppID] [tinyint]  NULL,                      
 [U_ID] [int]  NULL,                      
 [IsUniCode] [bit]  NULL,                      
 [IsDnd] [bit]  NULL,                      
 [IsAirtel] [bit]  NULL,                      
 [MobileSubSet] [bigint] NULL,                      
 [ValidNo] [tinyint] NULL,                      
 [IsPrority] [tinyint] NULL,                      
 [IsAllowDND] [tinyint] NULL,                      
 [DBType] [nchar](10) NULL--,                      
 --[campaignid] [bigint] NULL,                      
 --[Processed] [int] NULL,   
 --[Hasvirtualcredits] [int] NULL,                      
 --[HasSufficientvirtualcredits] [int] NULL                      
)                      
                    
            
                                    
declare @Uccode varchar(20)                       
  SELECT TOP 1 @Uccode =  isnull(CountryCode,'+91')                      
  FROM   User_Detail AS ud with(nolock)                                  
  WHERE  ud.[User_ID] = @Account                     
                       
 INSERT INTO #tmpflind                                  
   ( BatchID,Mobile,Country_Code,Message,                                  
             MessageStatus, SenderID,MessageInsertDate,ScheduledDate,                                  
             ScheduledTime,SmppID,U_ID,IsUnicode,IsDnd,IsAirtel,MobileSubSet,                      
             ValidNo,IsPrority,IsAllowDND,DBType                         
   )                             
     SELECT BatchID,Mobile,CountryCode,Messagetext,                                  
             MessageStatus, SenderID,MessageInsertDate,ScheduledDate,                                  
        ScheduledTime,SmppID,U_ID,IsUnicode,IsDnd,IsAirtel,MobileSubSet,                      
             ValidNo,IsPrority,IsAllowDND,DBType                         
 FROM   (                                      
            SELECT @BatchID    AS BatchID,                                      
                   CASE                                       
                        WHEN @Mobile = 1 THEN ISNULL(NULLIF(ue.MobileNo, ''), '0') ELSE '0'                                      
                  END         AS Mobile,                      
                   CASE                                   
                WHEN @Mobile = 1 THEN ISNULL(ue.CountryCode ,'')                      
                ELSE '' END AS CountryCode,                                     
     dbo.fn_getLeadsMessage(ue.ParentID, @Message, ue.MobileNo) AS                                       
                   Messagetext,                                      
                   NULL        AS MessageStatus,                                      
                   @SenderID   AS SenderID,                                      
                   GETDATE()   AS MessageInsertDate,                                      
                   NULL        AS ScheduledDate,                                      
                   NULL        AS ScheduledTime,                                      
                   (                                      
                       SELECT TOP 1 ud.SmppID                                      
                       FROM   User_Detail AS ud                                      
                       WHERE  ud.[User_ID] = @Account                                      
                   )           AS SmppID,                                      
                   @Account    AS U_ID,                                      
                   @IsUnicode  AS IsUnicode,                                      
                   0           AS IsDnd,                                      
                   0           AS IsAirtel,                                      
                   0           AS MobileSubSet,                                      
                   1           AS ValidNo,                                      
                   1           AS IsPrority,                                      
                   0           AS IsAllowDND,                                      
                   0           AS DBType                                      
            FROM   UserLeads   AS ue with(nolock)                                     
            WHERE  ue.ID =@ID                                     
                   AND ISNULL(NULLIF(ue.MobileNo, ''), '') <>''                                       
                   AND ISNULL(NULLIF(ue.MobileNo , ''), '') not in                                 
                   (select  ISNULL(C_UDTemp.Mobile,'') as MobileNo                      
                   from UserLeads as UETemp with(nolock) inner join Client_UnSubscribeDetails as C_UDTemp with(nolock)                                
                   on (UeTemp.MobileNo =C_UDTemp.Mobile                       
                   and UETemp.CountryCode = C_UDTemp.CountryCode and C_UDTemp.ParentId=UETemp.ParentID)                                
                   where UE.ID =@ID )                               
            UNION                                        
            SELECT @BatchID,                                      
            CASE                                      
                   WHEN @mobile1 = 1 THEN ISNULL(NULLIF(ue.MobileNo1, ''), '0') ELSE '0'                                      
                   END AS Mobile,                      
                   CASE                                   
         WHEN @Mobile = 1 THEN ISNULL(ue.CountryCode ,'')                      
                ELSE '' END AS CountryCode,                                      
     dbo.fn_getLeadsMessage(ue.ParentID, @Message, ue.MobileNo1),                                      
                   NULL       AS MessageStatus,                       
                   @SenderID,                                      
     GETDATE(),                                      
                   NULL,                                  
                   NULL,                                      
                   (                                      
                       SELECT TOP 1 ud.SmppID                                      
      FROM   User_Detail AS ud with(nolock)                                     
              WHERE  ud.[User_ID] = @Account                                      
                ),                                      
                   @Account,                                      
                   @IsUnicode,                                      
                   0,                                      
                   0,                                      
                   0,                                      
                   1,                                      
           1,                                      
     0,                                      
                   0                                      
            FROM   UserLeads  AS ue with(nolock)                                     
            WHERE  ue.ID =@ID                      
                   AND ISNULL(NULLIF(ue.MobileNo1, ''), '') < > ''                                  
                        AND ISNULL(NULLIF(ue.MobileNo1, ''), '') not in                                 
                   (                                
                   select  ISNULL(C_UDTemp.Mobile,'') as MobileNo1                                 
                   from UserLeads as UETemp with(nolock) inner join Client_UnSubscribeDetails as C_UDTemp with(nolock)                                
                   on (UeTemp.MobileNo1 =C_UDTemp.Mobile and                       
                   UETemp.CountryCode1 = C_UDTemp.CountryCode  and C_UDTemp.ParentId=UETemp.ParentID)                                
                   where UE.ID =@ID)                                     
            UNION                                        
            SELECT @BatchID,                                      
                   CASE                                       
                   WHEN @Mobile2 = 1 THEN ISNULL(NULLIF(ue.MobileNo2, ''), '0') ELSE '0'                                      
                   END AS Mobile,                      
                   CASE WHEN @Mobile = 1 THEN ISNULL(ue.CountryCode ,'')                      
       ELSE '' END AS CountryCode,                                        
                   dbo.fn_getLeadsMessage(ue.ParentID, @Message, ue.MobileNo2),                                      
                   NULL       AS MessageStatus,                                      
                   @SenderID,                                      
                   GETDATE(),                                      
                   NULL,                                      
                   NULL,                                      
                   (                                      
                       SELECT TOP 1 ud.SmppID                                      
                       FROM   User_Detail AS ud with(nolock)         
                       WHERE  ud.[User_ID] = @Account                                      
                   ),                                      
                   @Account,                                      
                   @IsUnicode,                                      
                   0,                                      
                   0,                                      
               0,                                      
                   1,                                      
                   1,                                   
                   0,                                      
                   0                                      
            FROM   UserLeads  AS ue with(nolock)                                     
            WHERE  ue.ID =@ID                                      
                 AND ISNULL(NULLIF(ue.MobileNo2, ''), '') <> ''                                 
                 AND ISNULL(NULLIF(ue.MobileNo2, ''), '') not in                                
                   (select  ISNULL(C_UDTemp.Mobile,'') as MobileNo2                                 
                   from UserLeads as UETemp with(nolock) inner join Client_UnSubscribeDetails as C_UDTemp with(nolock)                                
                   on (UeTemp.MobileNo2 =C_UDTemp.Mobile                       
                   and UETemp.CountryCode2 = C_UDTemp.CountryCode and C_UDTemp.ParentId=UETemp.ParentID)                                
     where UE.ID =@ID)                                
        ) A                                      
 WHERE  A.Mobile <> '0'                                        
                       
 if @Uccode = '+91'                      
 begin                      
  insert into #tmpflint (BatchID, Country_code,Mobile, Message, MessageStatus, SenderID,                                  
     MessageInsertDate, ScheduledDate, ScheduledTime,                                  
     SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,                                  
     ValidNo, IsPrority, IsAllowDND, DBType)                       
   select BatchID, Country_code,Mobile, Message, MessageStatus, SenderID,                                  
     MessageInsertDate, ScheduledDate, ScheduledTime,                                  
     SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,                                  
     ValidNo, IsPrority, IsAllowDND, DBType from  #tmpflind                      
   where Country_Code <>'+91'                      
  delete From #tmpflind where Country_Code <>'+91'                      
 end                      
 else                      
 begin                      
  insert into #tmpflint (BatchID, Country_code,Mobile, Message, MessageStatus, SenderID,                                  
     MessageInsertDate, ScheduledDate, ScheduledTime,                                  
     SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,                                  
     ValidNo, IsPrority, IsAllowDND, DBType)                       
   select BatchID, Country_code,Mobile, Message, MessageStatus, SenderID,                                  
     MessageInsertDate, ScheduledDate, ScheduledTime,                                  
     SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,                                  
     ValidNo, IsPrority, IsAllowDND, DBType from  #tmpflind                      
 end                      
 Declare @NoOfSMS  bigint = 0, @intsms bigint =0;                       
 select @intsms = COUNT(*) from #tmpflint                        
                      
declare @intprc int = 0 , @indprc int = 0    
if @intsms > 0                      
begin                      
 update #tmpflint set price= (case when IsUniCode=0 and len(message)<=160  then 1                             
 when IsUniCode=0 and LEN(message)>160 then ceiling(LEN(message)/cast(153 as FLOat))                             
  when IsUniCode=1                             
 and len(message)<=70 then 1 else ceiling(LEN(message)/cast(67 as float)) end )*                      
  (select price from dbo.IntSMSRateMast where country_code =#tmpflint.country_code)                        
                       
 declare @Cr_amt float,@balance float                            
 select @Cr_amt = SUM(price) from #tmpflint                            
 select top 1 @balance= Balance from dbo.IntCredit_Details with(nolock) where USER_ID = @Account                        
 if @balance < @Cr_amt                      
 set @intprc = 1                         
end                      
                      
if @intprc =0                      
begin                       
  select @NoOfSMS = COUNT(*) from #tmpflind                      
 if @NoOfSMS > 0                      
 begin                      
  DECLARE @CurrentBalance BIGINT = (                                      
             SELECT TOP 1 isnull(cd.Balance,0)                                      
             FROM   Credit_Details AS cd with(nolock)                                     
             WHERE  cd.[User_ID] = @Account                                      
             ORDER BY                                      
                    cd.Credit_ID DESC                                      
   )                                      
 DECLARE @mBalance BIGINT = @CurrentBalance - @NoOfSMS                                      
 IF @mBalance >= 0                          
   begin                      
 INSERT INTO CloneMessageDeliveryStatus                                  
   (BatchID, Mobile, Message, MessageStatus, SenderID,                                  
     MessageInsertDate, ScheduledDate, ScheduledTime,                                  
     SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,                                  
     ValidNo, IsPrority, IsAllowDND, DBType)                              
 select BatchID, Mobile, Message, MessageStatus, SenderID,                                  
     MessageInsertDate, isnull(ScheduledDate,''), isnull(ScheduledTime,''),                                  
     SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,                                  
     ValidNo, IsPrority, IsAllowDND, DBType from #tmpflind                      
   end                      
   else                      
 set @indprc = 1                      
 end                      
end         
/*       Commented as indian messages should not be inserted here      
 if @intprc  = 0 and @indprc  = 0                      
 begin                      
  insert into CloneIntMsgDeliveryStatus                      
  (BatchID, Country_code, Mobile, Message, MessageStatus, SenderID,                       
  MessageInsertDate, ScheduledDate, ScheduledTime, SmppID, U_ID, IsUniCode,                       
  IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType,                       
  campaignid, Processed, Hasvirtualcredits, HasSufficientvirtualcredits, price)                      
  select BatchID, Country_code, Mobile, Message, MessageStatus, SenderID,                      
   MessageInsertDate, isnull(ScheduledDate,''), isnull(ScheduledTime,''), SmppID, U_ID, IsUniCode,                       
   IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType,                       
   campaignid, Processed, Hasvirtualcredits, HasSufficientvirtualcredits,                       
   price from #tmpflint                      
 end           
 */                 
 if @intprc  = 0 and @indprc  = 0                   
 BEGIN  
       SELECT 'Record Saved'         
         
 DECLARE @rowJson NVARCHAR(MAX) = (          
   SELECT *          
   FROM CloneMessageDeliveryStatus          
   WHERE BatchID = @BatchID          
   FOR JSON AUTO          
    ,INCLUDE_NULL_VALUES          
   )          
          
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @Account          
  ,@Activity_type = 'Inst_Sms_Lead'          
  ,@ActionType = 'I'           
  ,@RowJson = @rowJson          
  ,@Table_name = 'CloneMessageDeliveryStatus'       
 END  
     Else                              
        select 'Insufficient Balance'                              
                                   
                                      
END 


GO

