CREATE   PROCEDURE [dbo].[usp_IntindSMSFromLeads_New1_WithDLTTemplateID] @ID VARCHAR(500)  --- send  sms with template    
 ,@Account BIGINT      
 ,@SenderID VARCHAR(50)      
 ,@Message NVARCHAR(4000)      
 ,@IsUnicode BIT      
 ,@Mobile BIT      
 ,@mobile1 BIT      
 ,@Mobile2 BIT      
 ,@DLTTemplateID NVARCHAR(200)      
 ,@UserId BIGINT = 0      
AS      
BEGIN      
 -- BatchID -- this column value is auto-generated                                                          
 DECLARE @CreatedBy BIGINT = 0      
      
 IF (@UserId > 0)      
 BEGIN      
  SET @CreatedBy = @UserId      
 END      
 ELSE      
 BEGIN      
  SET @CreatedBy = @Account      
 END      
      
 DECLARE @ParentIDAccount BIGINT = (      
   SELECT TOP 1 ParentID      
   FROM User_Detail WITH (NOLOCK)      
   WHERE User_ID = @Account      
   )      
 DECLARE @BatchID BIGINT      
      
 BEGIN TRAN      
      
 INSERT INTO GetBatchRecord (      
  [User_id]      
  ,RandNum      
  )      
 VALUES (      
  @Account      
  ,@Account      
  )      
      
 SELECT @BatchID = scope_identity()      
      
 DELETE      
 FROM GetBatchRecord      
 WHERE batchid = @batchid      
      
 COMMIT      
      
 CREATE TABLE #tmpflint (      
  [BatchID] [bigint] NULL      
  ,[Country_code] [varchar](10) NULL      
  ,[Mobile] [varchar](20) NULL      
  ,[Message] [nvarchar](2500) NULL      
  ,[MessageStatus] [varchar](20) NULL      
  ,[SenderID] [nchar](40) NULL      
  ,[MessageInsertDate] [datetime] NULL      
  ,[ScheduledDate] [varchar](50) NULL      
  ,[ScheduledTime] [varchar](50) NULL      
  ,[SmppID] [tinyint] NULL      
  ,[U_ID] [int] NULL      
  ,[IsUniCode] [bit] NULL      
  ,[IsDnd] [bit] NULL      
  ,[IsAirtel] [bit] NULL      
  ,[MobileSubSet] [bigint] NULL      
  ,[ValidNo] [tinyint] NULL      
  ,[IsPrority] [tinyint] NULL      
  ,[IsAllowDND] [tinyint] NULL      
  ,[DBType] [nchar](10) NULL      
  ,[campaignid] [bigint] NULL      
  ,[Processed] [int] NULL      
  ,[Hasvirtualcredits] [int] NULL      
  ,[HasSufficientvirtualcredits] [int] NULL      
  ,[price] [float] NULL      
  )      
      
 --drop table #tmpflind                                    
 CREATE TABLE #tmpflind (      
  [BatchID] [bigint] NULL      
  ,[Country_code] [varchar](10) NULL      
  ,[Mobile] [varchar](20) NULL      
  ,[Message] [nvarchar](2500) NULL      
  ,[MessageStatus] [varchar](20) NULL      
  ,[SenderID] [nchar](40) NULL      
  ,[MessageInsertDate] [datetime] NULL      
  ,[ScheduledDate] [varchar](50) NULL      
  ,[ScheduledTime] [varchar](50) NULL      
  ,[SmppID] [tinyint] NULL      
  ,[U_ID] [int] NULL      
  ,[IsUniCode] [bit] NULL      
  ,[IsDnd] [bit] NULL      
  ,[IsAirtel] [bit] NULL      
  ,[MobileSubSet] [bigint] NULL      
  ,[ValidNo] [tinyint] NULL      
  ,[IsPrority] [tinyint] NULL      
  ,[IsAllowDND] [tinyint] NULL      
  ,[DBType] [nchar](10) NULL      
  ,[LeadId] [bigint]      
  ,[price] decimal(18,4) NULL                                   
  --[campaignid] [bigint] NULL,                                    
  --[Processed] [int] NULL,                                    
  --[Hasvirtualcredits] [int] NULL,                                    
  --[HasSufficientvirtualcredits] [int] NULL                                    
  )      
      
 DECLARE @Uccode VARCHAR(20) ='+91'     
      
 --SELECT TOP 1 @Uccode = isnull(CountryCode, '+91')      
 --FROM User_Detail AS ud (NOLOCK)     
 --WHERE ud.[User_ID] = @Account      
  declare @entity nvarchar(20)='Lead',@entityplaceholders nvarchar(2000)                                         
  drop table if exists #entitypcvalues
  declare @entities as entities
  create table #entitypcvalues(entityid bigint,content nvarchar(max))
  
  select @entityplaceholders=dbo.ExtractPlaceholders(@entity,@message)

  drop table if exists #TableData2
  CREATE TABLE #TableData2 (ID BIGINT)  
      
 INSERT INTO #TableData2 (ID)             
 select Item from fu_SplitString(@ID,'#') 

 INSERT INTO @entities (entity, entityid)
SELECT @entity, T2.ID FROM #TableData2 T2;


   --insert into @entities(entity,entityid)
   --select @entity,EntityID from Tbl_MassOperationDetails(nolock) where SummaryId=@massbatchid

   if @entityplaceholders<>''
   begin
   insert into #entitypcvalues(entityid,content)
   exec [usp_replaceentityplaceholders_bulk_singlecontent] @entities,@message,@entityplaceholders
   end
   else
   begin
     insert into #entitypcvalues(entityid,content)
     select entityid,@message from @entities
  end       
 INSERT INTO #tmpflind (      
  BatchID      
  ,Mobile      
  ,Country_Code      
  ,Message      
  ,MessageStatus      
  ,SenderID      
  ,MessageInsertDate      
  ,ScheduledDate      
  ,ScheduledTime      
  ,SmppID      
  ,U_ID      
  ,IsUnicode      
  ,IsDnd      
  ,IsAirtel      
  ,MobileSubSet      
  ,ValidNo      
  ,IsPrority      
  ,IsAllowDND      
  ,DBType      
  ,LeadId      
  )      
 SELECT BatchID      
  ,Mobile      
  ,CountryCode      
  ,Messagetext      
  ,MessageStatus      
  ,SenderID      
  ,MessageInsertDate      
  ,ScheduledDate      
  ,ScheduledTime      
  ,SmppID      
  ,U_ID      
  ,IsUnicode      
  ,IsDnd      
  ,IsAirtel        ,MobileSubSet      
  ,ValidNo      
  ,IsPrority      
  ,IsAllowDND      
  ,DBType      
  ,LeadId      
 FROM (      
  SELECT @BatchID AS BatchID      
   ,CASE       
    WHEN @Mobile = 1      
     THEN ISNULL(NULLIF(ue.MobileNo, ''), '0')      
    ELSE '0'      
    END AS Mobile      
   ,CASE       
    WHEN @Mobile = 1      
     THEN ISNULL(ue.CountryCode, '')      
    ELSE ''      
    END AS CountryCode 
	,content Messagetext
   --,dbo.fn_getLeadsMessage(ue.ParentID, @Message, ue.MobileNo) AS Messagetext      
   ,NULL AS MessageStatus      
   ,@SenderID AS SenderID      
   ,GETDATE() AS MessageInsertDate      
   ,NULL AS ScheduledDate      
   ,NULL AS ScheduledTime
   ,2  AS SmppID
   --,(      
   -- SELECT TOP 1 ud.SmppID      
   -- FROM User_Detail AS ud(NOLOCK)      
   -- WHERE ud.[User_ID] = @Account      
   -- ) AS SmppID      
   ,@ParentIDAccount AS U_ID      
   ,@IsUnicode AS IsUnicode      
   ,0 AS IsDnd      
   ,0 AS IsAirtel      
   ,0 AS MobileSubSet      
   ,1 AS ValidNo      
   ,1 AS IsPrority      
   ,0 AS IsAllowDND      
   ,0 AS DBType      
   ,ue.ID AS LeadId      
  FROM UserLeads AS ue(NOLOCK)
  inner join #TableData2 t2 on ue.ID = t2.ID  
			join #entitypcvalues e on ue.ID=e.entityid
  WHERE 
  --ue.ID = @ID      
    ISNULL(NULLIF(ue.MobileNo, ''), '') <> ''      
   --AND ISNULL(NULLIF(ue.MobileNo, ''), '') NOT IN (      
   -- SELECT ISNULL(C_UDTemp.Mobile, '') AS MobileNo      
   -- FROM UserLeads UETemp(NOLOCK)      
   -- INNER JOIN Client_UnSubscribeDetails C_UDTemp(NOLOCK) ON (      
   --   UeTemp.MobileNo = C_UDTemp.Mobile      
   --   AND UETemp.CountryCode = C_UDTemp.CountryCode      
   --   AND C_UDTemp.ParentId = UETemp.ParentID      
   --   )      
   -- WHERE UE.ID = @ID      
   -- )      
        
  UNION      
        
  SELECT @BatchID      
   ,CASE       
    WHEN @mobile1 = 1      
     THEN ISNULL(NULLIF(ue.MobileNo1, ''), '0')      
    ELSE '0'      
    END AS Mobile      
   ,CASE       
    WHEN @Mobile = 1      
     THEN ISNULL(ue.CountryCode, '')      
    ELSE ''      
    END AS CountryCode  
	,content as Messagetext
   --,dbo.fn_getLeadsMessage(ue.ParentID, @Message, ue.MobileNo1)      
   ,NULL AS MessageStatus      
   ,@SenderID      
   ,GETDATE()      
   ,NULL      
   ,NULL 
   ,2 AS SmppID
   --,(      
   -- SELECT TOP 1 ud.SmppID      
   -- FROM User_Detail AS ud(NOLOCK)      
   -- WHERE ud.[User_ID] = @Account      
   -- )      
   ,@ParentIDAccount      
   ,@IsUnicode      
   ,0      
   ,0      
   ,0      
   ,1      
   ,1      
   ,0      
   ,0      
   ,ue.ID AS LeadId      
  FROM UserLeads AS ue (nolock)  
    inner join #TableData2 t2 on ue.ID = t2.ID  
			join #entitypcvalues e on ue.ID=e.entityid

  WHERE 
  --ue.ID = @ID      
    ISNULL(NULLIF(ue.MobileNo1, ''), '') < > ''      
   --AND ISNULL(NULLIF(ue.MobileNo1, ''), '') NOT IN (      
   -- SELECT ISNULL(C_UDTemp.Mobile, '') AS MobileNo1      
   -- FROM UserLeads UETemp(NOLOCK)      
   -- INNER JOIN Client_UnSubscribeDetails C_UDTemp(NOLOCK) ON (      
   --   UeTemp.MobileNo1 = C_UDTemp.Mobile      
   --   AND UETemp.CountryCode1 = C_UDTemp.CountryCode      
   --   AND C_UDTemp.ParentId = UETemp.ParentID      
   --   )      
   -- WHERE UE.ID = @ID      
   -- )      
        
  UNION      
        
  SELECT @BatchID      
   ,CASE       
    WHEN @Mobile2 = 1      
     THEN ISNULL(NULLIF(ue.MobileNo2, ''), '0')      
    ELSE '0'      
    END AS Mobile      
   ,CASE       
    WHEN @Mobile = 1      
     THEN ISNULL(ue.CountryCode, '')      
    ELSE ''      
    END AS CountryCode
	,content as messagetext
   --,dbo.fn_getLeadsMessage(ue.ParentID, @Message, ue.MobileNo2)      
   ,NULL AS MessageStatus      
   ,@SenderID      
   ,GETDATE()      
   ,NULL      
   ,NULL
    ,2 as smppid
   --,(      
   -- SELECT TOP 1 ud.SmppID      
   -- FROM User_Detail AS ud(NOLOCK)      
   -- WHERE ud.[User_ID] = @Account      
   -- )      
   ,@ParentIDAccount     
   ,@IsUnicode      
   ,0      
   ,0      
   ,0      
   ,1      
   ,1      
   ,0      
   ,0      
   ,ue.ID AS LeadId      
  FROM UserLeads AS ue (nolock)
  inner join #TableData2 t2 on ue.ID = t2.ID  
			join #entitypcvalues e on ue.ID=e.entityid
  WHERE 
  --ue.ID = @ID      
    ISNULL(NULLIF(ue.MobileNo2, ''), '') <> ''      
   --AND ISNULL(NULLIF(ue.MobileNo2, ''), '') NOT IN (      
   -- SELECT ISNULL(C_UDTemp.Mobile, '') AS MobileNo2      
   -- FROM UserLeads UETemp(NOLOCK)      
   -- INNER JOIN Client_UnSubscribeDetails C_UDTemp(NOLOCK) ON (      
   --   UeTemp.MobileNo2 = C_UDTemp.Mobile      
   --   AND UETemp.CountryCode2 = C_UDTemp.CountryCode      
   --   AND C_UDTemp.ParentId = UETemp.ParentID      
   --   )      
   -- WHERE UE.ID = @ID      
   -- )      
  ) A      
 WHERE A.Mobile <> '0'      
      
 IF @Uccode = '+91'      
 BEGIN      
  INSERT INTO #tmpflint (      
   BatchID      
   ,Country_code      
   ,Mobile      
   ,Message      
   ,MessageStatus      
   ,SenderID      
   ,MessageInsertDate      
   ,ScheduledDate      
   ,ScheduledTime      
   ,SmppID      
   ,U_ID      
   ,IsUniCode      
   ,IsDnd      
   ,IsAirtel      
   ,MobileSubSet      
   ,ValidNo      
   ,IsPrority      
   ,IsAllowDND      
   ,DBType      
   )      
  SELECT BatchID      
   ,Country_code      
   ,Mobile      
   ,Message      
   ,MessageStatus      
   ,SenderID      
   ,MessageInsertDate      
   ,ScheduledDate      
   ,ScheduledTime      
   ,SmppID      
   ,U_ID      
   ,IsUniCode      
   ,IsDnd      
   ,IsAirtel      
   ,MobileSubSet      
   ,ValidNo      
   ,IsPrority      
   ,IsAllowDND      
   ,DBType      
  FROM #tmpflind      
  WHERE Country_Code <> '+91'      
      
  DELETE      
  FROM #tmpflind      
  WHERE Country_Code <> '+91'      
 END      
 ELSE      
 BEGIN      
  INSERT INTO #tmpflint (      
   BatchID      
   ,Country_code      
   ,Mobile      
   ,Message      
   ,MessageStatus      
   ,SenderID      
   ,MessageInsertDate      
   ,ScheduledDate      
   ,ScheduledTime      
   ,SmppID      
   ,U_ID      
   ,IsUniCode      
   ,IsDnd      
   ,IsAirtel      
   ,MobileSubSet      
   ,ValidNo      
   ,IsPrority      
   ,IsAllowDND      
   ,DBType      
   )      
  SELECT BatchID      
   ,Country_code      
   ,Mobile      
   ,Message      
   ,MessageStatus      
   ,SenderID      
   ,MessageInsertDate      
   ,ScheduledDate      
   ,ScheduledTime      
   ,SmppID      
   ,U_ID      
   ,IsUniCode      
   ,IsDnd      
   ,IsAirtel      
   ,MobileSubSet      
   ,ValidNo      
   ,IsPrority      
   ,IsAllowDND      
   ,DBType      
  FROM #tmpflind      
 END      
      
 DECLARE @NoOfSMS BIGINT = 0      
  ,@intsms BIGINT = 0;      
      
 SELECT @intsms = COUNT(*)      
 FROM #tmpflint      
      
 DECLARE @intprc INT = 0      
  ,@indprc INT = 0 ,  @servicetype varchar(100),@sms_cost numeric(18,4),@credittypeid int ;     
      
 IF 1=2--@intsms > 0      
 BEGIN      
  UPDATE #tmpflint      
  SET price = cast((      
    CASE       
     WHEN IsUniCode = 0      
      AND len(message) <= 160      
      THEN 1      
     WHEN IsUniCode = 0      
      AND LEN(message) > 160      
      THEN ceiling(LEN(message) / cast(153 AS FLOAT))      
     WHEN IsUniCode = 1      
      AND len(message) <= 70      
      THEN 1      
     ELSE ceiling(LEN(message) / cast(67 AS FLOAT))      
     END      
    ) as int)* (      
    SELECT top 1  isnull(price,0)      
    FROM dbo.IntSMSRateMast      
    WHERE country_code = #tmpflint.country_code      
    )      
      
  DECLARE @Cr_amt FLOAT      
   ,@balance FLOAT      
      
  SELECT @Cr_amt = SUM(isnull(price,0))      
  FROM #tmpflint      
     set @servicetype='DomesticSMS';
    SET @balance = dbo.GetAvailableBalanceForService(@ParentIDAccount,21);  
  --SELECT TOP 1 @balance = Balance      
  --FROM dbo.IntCredit_Details(NOLOCK)      
  --WHERE USER_ID = @ParentIDAccount      
      
  IF @balance < @Cr_amt      
   SET @intprc = 1      
 END      
      
 IF @intprc = 0      
 BEGIN      
  SELECT @NoOfSMS = COUNT(*)      
  FROM #tmpflind      
  
  select @sms_cost=
  (      
    SELECT top 1  isnull(PTrns,0)      
    FROM dbo.Price_Base_SMS_RateDeduction      
     BR (nolock) where BR.OriginCountryCode = '+91'  and br.destinationcountrycode='+91'    
    ) 
  IF @NoOfSMS > 0      
  BEGIN   
  UPDATE #tmpflind      
  SET price = (      
    CASE       
     WHEN IsUniCode = 0      
      AND len(message) <= 160      
      THEN 1      
     WHEN IsUniCode = 0      
      AND LEN(message) > 160      
      THEN ceiling(LEN(message) / cast(153 AS FLOAT))      
     WHEN IsUniCode = 1      
      AND len(message) <= 70      
      THEN 1      
     ELSE ceiling(LEN(message) / cast(67 AS FLOAT))      
     END      
    ) * (      
    @sms_cost
    )      
      
  DECLARE @Cr_amt1 decimal(18,4)      
   ,@balance1 decimal(18,4)      
      
  SELECT @Cr_amt1 = SUM(isnull(price,0))      
  FROM #tmpflind  
   --DECLARE @CurrentBalance BIGINT = (      
   --  SELECT TOP 1 isnull(cd.Balance, 0)      
   --  FROM Credit_Details AS cd(NOLOCK)      
   --  WHERE cd.[User_ID] = @ParentIDAccount      
   --  ORDER BY cd.Credit_ID DESC      
   --  )      
   --DECLARE @mBalance BIGINT = @CurrentBalance - @NoOfSMS      
      DECLARE @CurrentBalance decimal(18,4)
  set @servicetype='DomesticSMS';
  select @credittypeid=credittypeid from Price_Master_TypeCredit(nolock) where creditname=@servicetype
    SET @CurrentBalance = dbo.GetAvailableBalanceForService(@ParentIDAccount,@credittypeid);
	DECLARE @mBalance decimal(18,4) = @CurrentBalance -@Cr_amt1-- (@NoOfSMS*@Cr_amt1)  
   IF @mBalance >= 0      
   BEGIN      
    INSERT INTO CloneMessageDeliveryStatus (      
     BatchID      
     ,Mobile      
     ,Message      
     ,MessageStatus      
     ,SenderID      
     ,MessageInsertDate      
     ,ScheduledDate      
     ,ScheduledTime      
     ,SmppID      
     ,U_ID      
     ,IsUniCode      
     ,IsDnd      
     ,IsAirtel      
     ,MobileSubSet      
     ,ValidNo      
     ,IsPrority      
     ,IsAllowDND      
     ,DBType      
     ,sms_source      
     ,CMDS_CreatedBy      
     )      
    SELECT BatchID      
     ,Mobile      
     ,Message      
     ,MessageStatus      
     ,SenderID      
     ,MessageInsertDate      
     ,isnull(ScheduledDate, '')      
     ,isnull(ScheduledTime, '')      
     ,SmppID      
     ,U_ID      
     ,IsUniCode      
     ,IsDnd      
     ,IsAirtel      
     ,MobileSubSet      
     ,ValidNo      
     ,IsPrority      
     ,IsAllowDND      
     ,DBType      
     ,'Mass Send Lead'      
     ,@CreatedBy      
    FROM #tmpflind      
      
    BEGIN TRY      
     EXEC Usp_Save_DLTTemplateID_with_BatchID @batchid      
      ,@DLTTemplateID      
    END TRY      
      
    BEGIN CATCH      
     EXEC usp_InsertErrorInfo      
    END CATCH      
   END      
   ELSE      
    SET @indprc = 1      
  END      
 END      
      
 /*       Commented as indian messages should not be inserted here                    
 if @intprc  = 0 and @indprc  = 0                                    
 begin                                    insert into CloneIntMsgDeliveryStatus                                    
  (BatchID, Country_code, Mobile, Message, MessageStatus, SenderID,                                     
  MessageInsertDate, ScheduledDate, ScheduledTime, SmppID, U_ID, IsUniCode,                                     
  IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType,                                   
  campaignid, Processed, Hasvirtualcredits, HasSufficientvirtualcredits, price)                                    
  select BatchID, Country_code, Mobile, Message, MessageStatus, SenderID,                                    
   MessageInsertDate, isnull(ScheduledDate,''), isnull(ScheduledTime,''), SmppID, U_ID, IsUniCode,                                     
   IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType,                                     
   campaignid, Processed, Hasvirtualcredits, HasSufficientvirtualcredits,                                     
   price from #tmpflint                  
 end                         
 */      
 IF @intprc = 0 AND @indprc = 0      
 BEGIN      
  IF (@UserId > 0)      
  BEGIN      
   DECLARE @leadActivityHistory AS LeadActivitywithid_Tbltype      
   DECLARE @Username NVARCHAR(255)      
    ,@ParentId BIGINT = 0      
      
   SELECT top 1 @Username = User_Login      
    ,@ParentId = ParentID      
   FROM User_Detail(NOLOCK)      
   WHERE User_Id = @UserId      
      
   INSERT INTO @leadActivityHistory (      
    LeadID      
    ,UserID      
    ,ParentID      
    ,EventDescription      
    ,EventName      
    ,RefTable      
    ,refid      
    )      
   SELECT leadid      
    ,@UserId      
    ,@parentid      
    ,CONCAT (      
     @Username      
     ,' sent an sms with content '      
     ,Message      
     ,' on mobile '      
     ,Mobile      
     )      
    ,'SMS sent to lead'      
    ,'Batchinfo'      
    ,@BatchID      
   FROM #tmpflind      
      
   EXEC UspSaveLeadActivity_withMultipleValue_withid @leadActivityHistory      
  END      
      
  SELECT 'Record Saved'      
 END      
 ELSE      
 BEGIN      
  SELECT 'Insufficient Balance'      
 END      
      
 DECLARE @rowJson NVARCHAR(MAX) = (      
   SELECT *      
   FROM batchinfo(nolock)      
   WHERE BatchID = @BatchID      
   FOR JSON AUTO      
    ,INCLUDE_NULL_VALUES      
   )      
      
 EXEC mysms.dbo.Usp_AuditTableDataByParentId @User_id = @UserId      
  ,@Activity_type = 'Inst_Sms_Lead'      
  ,@ActionType = 'I'       
  ,@RowJson = @rowJson      
  ,@Table_name = 'batchinfo'      
END 





GO

/* ============================================================
   Procedure: [dbo].[usp_IntindSMSFromLeads_New1_WithDLTTemplateID_new]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_IntindSMSFromLeads_New1_WithDLTTemplateID_new] @ID VARCHAR(500)      
 ,@Account BIGINT      
 ,@SenderID VARCHAR(50)      
 ,@Message NVARCHAR(4000)      
 ,@IsUnicode BIT      
 ,@Mobile BIT      
 ,@mobile1 BIT      
 ,@Mobile2 BIT      
 ,@DLTTemplateID NVARCHAR(200)      
 ,@UserId BIGINT = 0      
AS      
BEGIN      
 -- BatchID -- this column value is auto-generated                                                          
 DECLARE @CreatedBy BIGINT = 0      
      
 IF (@UserId > 0)      
 BEGIN      
  SET @CreatedBy = @UserId      
 END      
 ELSE      
 BEGIN      
  SET @CreatedBy = @Account      
 END      
      
 DECLARE @ParentIDAccount BIGINT = (      
   SELECT TOP 1 ParentID      
   FROM User_Detail WITH (NOLOCK)      
   WHERE User_ID = @Account      
   )      
 DECLARE @BatchID BIGINT      
      
 BEGIN TRAN      
      
 INSERT INTO GetBatchRecord (      
  [User_id]      
  ,RandNum      
  )      
 VALUES (      
  @Account      
  ,@Account      
  )      
      
 SELECT @BatchID = scope_identity()      
      
 DELETE      
 FROM GetBatchRecord      
 WHERE batchid = @batchid      
      
 COMMIT      
      
 CREATE TABLE #tmpflint (      
  [BatchID] [bigint] NULL      
  ,[Country_code] [varchar](10) NULL      
  ,[Mobile] [varchar](20) NULL      
  ,[Message] [nvarchar](2500) NULL      
  ,[MessageStatus] [varchar](20) NULL      
  ,[SenderID] [nchar](40) NULL      
  ,[MessageInsertDate] [datetime] NULL      
  ,[ScheduledDate] [varchar](50) NULL      
  ,[ScheduledTime] [varchar](50) NULL      
  ,[SmppID] [tinyint] NULL      
  ,[U_ID] [int] NULL      
  ,[IsUniCode] [bit] NULL      
  ,[IsDnd] [bit] NULL      
  ,[IsAirtel] [bit] NULL      
  ,[MobileSubSet] [bigint] NULL      
  ,[ValidNo] [tinyint] NULL      
  ,[IsPrority] [tinyint] NULL      
  ,[IsAllowDND] [tinyint] NULL      
  ,[DBType] [nchar](10) NULL      
  ,[campaignid] [bigint] NULL      
  ,[Processed] [int] NULL      
  ,[Hasvirtualcredits] [int] NULL      
  ,[HasSufficientvirtualcredits] [int] NULL      
  ,[price] [float] NULL      
  )      
      
 --drop table #tmpflind                                    
 CREATE TABLE #tmpflind (      
  [BatchID] [bigint] NULL      
  ,[Country_code] [varchar](10) NULL      
  ,[Mobile] [varchar](20) NULL      
  ,[Message] [nvarchar](2500) NULL      
  ,[MessageStatus] [varchar](20) NULL      
  ,[SenderID] [nchar](40) NULL      
  ,[MessageInsertDate] [datetime] NULL      
  ,[ScheduledDate] [varchar](50) NULL      
  ,[ScheduledTime] [varchar](50) NULL      
  ,[SmppID] [tinyint] NULL      
  ,[U_ID] [int] NULL      
  ,[IsUniCode] [bit] NULL      
  ,[IsDnd] [bit] NULL      
  ,[IsAirtel] [bit] NULL      
  ,[MobileSubSet] [bigint] NULL      
  ,[ValidNo] [tinyint] NULL      
  ,[IsPrority] [tinyint] NULL      
  ,[IsAllowDND] [tinyint] NULL      
  ,[DBType] [nchar](10) NULL      
  ,[LeadId] [bigint]      
  ,--,                                    
  --[campaignid] [bigint] NULL,                                    
  --[Processed] [int] NULL,                                    
  --[Hasvirtualcredits] [int] NULL,                                    
  --[HasSufficientvirtualcredits] [int] NULL                                    
  )      
      
 DECLARE @Uccode VARCHAR(20)      
      
 SELECT TOP 1 @Uccode = isnull(CountryCode, '+91')      
 FROM User_Detail AS ud      
 WHERE ud.[User_ID] = @Account      
      
 INSERT INTO #tmpflind (      
  BatchID      
  ,Mobile      
  ,Country_Code      
  ,Message      
  ,MessageStatus      
  ,SenderID      
  ,MessageInsertDate      
  ,ScheduledDate      
  ,ScheduledTime      
  ,SmppID      
  ,U_ID      
  ,IsUnicode      
  ,IsDnd      
  ,IsAirtel      
  ,MobileSubSet      
  ,ValidNo      
  ,IsPrority      
  ,IsAllowDND      
  ,DBType      
  ,LeadId      
  )      
 SELECT BatchID      
  ,Mobile      
  ,CountryCode      
  ,Messagetext      
  ,MessageStatus      
  ,SenderID      
  ,MessageInsertDate      
  ,ScheduledDate      
  ,ScheduledTime      
  ,SmppID      
  ,U_ID      
  ,IsUnicode      
  ,IsDnd      
  ,IsAirtel        ,MobileSubSet      
  ,ValidNo      
  ,IsPrority      
  ,IsAllowDND      
  ,DBType      
  ,LeadId      
 FROM (      
  SELECT @BatchID AS BatchID      
   ,CASE       
    WHEN @Mobile = 1      
     THEN ISNULL(NULLIF(ue.MobileNo, ''), '0')      
    ELSE '0'      
    END AS Mobile      
   ,CASE       
    WHEN @Mobile = 1      
     THEN ISNULL(ue.CountryCode, '')      
    ELSE ''      
    END AS CountryCode      
   ,dbo.fn_getLeadsMailMessage_new(ue.ParentID, @Message, ue.MobileNo,ue.ID) AS Messagetext      
   ,NULL AS MessageStatus      
   ,@SenderID AS SenderID      
   ,GETDATE() AS MessageInsertDate      
   ,NULL AS ScheduledDate      
   ,NULL AS ScheduledTime      
   ,(      
    SELECT TOP 1 ud.SmppID      
    FROM User_Detail AS ud(NOLOCK)      
    WHERE ud.[User_ID] = @Account      
    ) AS SmppID      
   ,@Account AS U_ID      
   ,@IsUnicode AS IsUnicode      
   ,0 AS IsDnd      
   ,0 AS IsAirtel      
   ,0 AS MobileSubSet      
   ,1 AS ValidNo      
   ,1 AS IsPrority      
   ,0 AS IsAllowDND      
   ,0 AS DBType      
   ,ue.ID AS LeadId      
  FROM UserLeads AS ue(NOLOCK)      
  WHERE ue.ID = @ID      
   AND ISNULL(NULLIF(ue.MobileNo, ''), '') <> ''      
   AND ISNULL(NULLIF(ue.MobileNo, ''), '') NOT IN (      
    SELECT ISNULL(C_UDTemp.Mobile, '') AS MobileNo      
    FROM UserLeads UETemp(NOLOCK)      
    INNER JOIN Client_UnSubscribeDetails C_UDTemp(NOLOCK) ON (      
      UeTemp.MobileNo = C_UDTemp.Mobile      
      AND UETemp.CountryCode = C_UDTemp.CountryCode      
      AND C_UDTemp.ParentId = UETemp.ParentID      
      )      
    WHERE UE.ID = @ID      
    )      
        
  UNION      
        
  SELECT @BatchID      
   ,CASE       
    WHEN @mobile1 = 1      
     THEN ISNULL(NULLIF(ue.MobileNo1, ''), '0')      
    ELSE '0'      
    END AS Mobile      
   ,CASE       
    WHEN @Mobile = 1      
     THEN ISNULL(ue.CountryCode, '')      
    ELSE ''      
    END AS CountryCode      
   ,dbo.fn_getLeadsMailMessage_new(ue.ParentID, @Message, ue.MobileNo1,ue.Id)      
   ,NULL AS MessageStatus      
   ,@SenderID      
   ,GETDATE()      
   ,NULL      
   ,NULL      
   ,(      
    SELECT TOP 1 ud.SmppID      
    FROM User_Detail AS ud(NOLOCK)      
    WHERE ud.[User_ID] = @Account      
    )      
   ,@Account      
   ,@IsUnicode      
   ,0      
   ,0      
   ,0      
   ,1      
   ,1      
   ,0      
   ,0      
   ,ue.ID AS LeadId      
  FROM UserLeads AS ue      
  WHERE ue.ID = @ID      
   AND ISNULL(NULLIF(ue.MobileNo1, ''), '') < > ''      
   AND ISNULL(NULLIF(ue.MobileNo1, ''), '') NOT IN (      
    SELECT ISNULL(C_UDTemp.Mobile, '') AS MobileNo1      
    FROM UserLeads UETemp(NOLOCK)      
    INNER JOIN Client_UnSubscribeDetails C_UDTemp(NOLOCK) ON (      
      UeTemp.MobileNo1 = C_UDTemp.Mobile      
      AND UETemp.CountryCode1 = C_UDTemp.CountryCode      
      AND C_UDTemp.ParentId = UETemp.ParentID      
      )      
    WHERE UE.ID = @ID      
    )      
        
  UNION      
        
  SELECT @BatchID      
   ,CASE       
    WHEN @Mobile2 = 1      
     THEN ISNULL(NULLIF(ue.MobileNo2, ''), '0')      
    ELSE '0'      
    END AS Mobile      
   ,CASE       
    WHEN @Mobile = 1      
     THEN ISNULL(ue.CountryCode, '')      
    ELSE ''      
    END AS CountryCode      
   ,dbo.fn_getLeadsMailMessage_new(ue.ParentID, @Message, ue.MobileNo2,ue.id)      
   ,NULL AS MessageStatus      
   ,@SenderID      
   ,GETDATE()      
   ,NULL      
   ,NULL      
   ,(      
    SELECT TOP 1 ud.SmppID      
    FROM User_Detail AS ud(NOLOCK)      
    WHERE ud.[User_ID] = @Account      
    )      
   ,@Account      
   ,@IsUnicode      
   ,0      
   ,0      
   ,0      
   ,1      
   ,1      
   ,0      
   ,0      
   ,ue.ID AS LeadId      
  FROM UserLeads AS ue      
  WHERE ue.ID = @ID      
   AND ISNULL(NULLIF(ue.MobileNo2, ''), '') <> ''      
   AND ISNULL(NULLIF(ue.MobileNo2, ''), '') NOT IN (      
    SELECT ISNULL(C_UDTemp.Mobile, '') AS MobileNo2      
    FROM UserLeads UETemp(NOLOCK)      
    INNER JOIN Client_UnSubscribeDetails C_UDTemp(NOLOCK) ON (      
      UeTemp.MobileNo2 = C_UDTemp.Mobile      
      AND UETemp.CountryCode2 = C_UDTemp.CountryCode      
      AND C_UDTemp.ParentId = UETemp.ParentID      
      )      
    WHERE UE.ID = @ID      
    )      
  ) A      
 WHERE A.Mobile <> '0'      
      
 IF @Uccode = '+91'      
 BEGIN      
  INSERT INTO #tmpflint (      
   BatchID      
   ,Country_code      
   ,Mobile      
   ,Message      
   ,MessageStatus      
   ,SenderID      
   ,MessageInsertDate      
   ,ScheduledDate      
   ,ScheduledTime      
   ,SmppID      
   ,U_ID      
   ,IsUniCode      
   ,IsDnd      
   ,IsAirtel      
   ,MobileSubSet      
   ,ValidNo      
   ,IsPrority      
   ,IsAllowDND      
   ,DBType      
   )      
  SELECT BatchID      
   ,Country_code      
   ,Mobile      
   ,Message      
   ,MessageStatus      
   ,SenderID      
   ,MessageInsertDate      
   ,ScheduledDate      
   ,ScheduledTime      
   ,SmppID      
   ,U_ID      
   ,IsUniCode      
   ,IsDnd      
   ,IsAirtel      
   ,MobileSubSet      
   ,ValidNo      
   ,IsPrority      
   ,IsAllowDND      
   ,DBType      
  FROM #tmpflind      
  WHERE Country_Code <> '+91'      
      
  DELETE      
  FROM #tmpflind      
  WHERE Country_Code <> '+91'      
 END      
 ELSE      
 BEGIN      
  INSERT INTO #tmpflint (      
   BatchID      
   ,Country_code      
   ,Mobile      
   ,Message      
   ,MessageStatus      
   ,SenderID      
   ,MessageInsertDate      
   ,ScheduledDate      
   ,ScheduledTime      
   ,SmppID      
   ,U_ID      
   ,IsUniCode      
   ,IsDnd      
   ,IsAirtel      
   ,MobileSubSet      
   ,ValidNo      
   ,IsPrority      
   ,IsAllowDND      
   ,DBType      
   )      
  SELECT BatchID      
   ,Country_code      
   ,Mobile      
   ,Message      
   ,MessageStatus      
   ,SenderID      
   ,MessageInsertDate      
   ,ScheduledDate      
   ,ScheduledTime      
   ,SmppID      
   ,U_ID      
   ,IsUniCode      
   ,IsDnd      
   ,IsAirtel      
   ,MobileSubSet      
   ,ValidNo      
   ,IsPrority      
   ,IsAllowDND      
   ,DBType      
  FROM #tmpflind      
 END      
      
 DECLARE @NoOfSMS BIGINT = 0      
  ,@intsms BIGINT = 0;      
      
 SELECT @intsms = COUNT(*)      
 FROM #tmpflint      
      
 DECLARE @intprc INT = 0      
  ,@indprc INT = 0      
      
 IF @intsms > 0      
 BEGIN      
  UPDATE #tmpflint      
  SET price = (      
    CASE       
     WHEN IsUniCode = 0      
      AND len(message) <= 160      
      THEN 1      
     WHEN IsUniCode = 0      
      AND LEN(message) > 160      
      THEN ceiling(LEN(message) / cast(153 AS FLOAT))      
     WHEN IsUniCode = 1      
      AND len(message) <= 70      
      THEN 1      
     ELSE ceiling(LEN(message) / cast(67 AS FLOAT))      
     END      
    ) * (      
    SELECT top 1  isnull(price,0)      
    FROM dbo.IntSMSRateMast      
    WHERE country_code = #tmpflint.country_code      
    )      
      
  DECLARE @Cr_amt FLOAT      
   ,@balance FLOAT      
      
  SELECT @Cr_amt = SUM(isnull(price,0))      
  FROM #tmpflint      
      
  SELECT TOP 1 @balance = Balance      
  FROM dbo.IntCredit_Details(NOLOCK)      
  WHERE USER_ID = @ParentIDAccount      
      
  IF @balance < @Cr_amt      
   SET @intprc = 1      
 END      
      
 IF @intprc = 0      
 BEGIN      
  SELECT @NoOfSMS = COUNT(*)      
  FROM #tmpflind      
      
  IF @NoOfSMS > 0      
  BEGIN      
   DECLARE @CurrentBalance BIGINT = (      
     SELECT TOP 1 isnull(cd.Balance, 0)      
     FROM Credit_Details AS cd(NOLOCK)      
     WHERE cd.[User_ID] = @ParentIDAccount      
     ORDER BY cd.Credit_ID DESC      
     )      
   DECLARE @mBalance BIGINT = @CurrentBalance - @NoOfSMS      
      
   IF @mBalance >= 0      
   BEGIN      
    INSERT INTO CloneMessageDeliveryStatus (      
     BatchID      
     ,Mobile      
     ,Message      
     ,MessageStatus      
     ,SenderID      
     ,MessageInsertDate      
     ,ScheduledDate      
     ,ScheduledTime      
     ,SmppID      
     ,U_ID      
     ,IsUniCode      
     ,IsDnd      
     ,IsAirtel      
     ,MobileSubSet      
     ,ValidNo      
     ,IsPrority      
     ,IsAllowDND      
     ,DBType      
     ,sms_source      
     ,CMDS_CreatedBy      
     )      
    SELECT BatchID      
     ,Mobile      
     ,Message      
     ,MessageStatus      
     ,SenderID      
     ,MessageInsertDate      
     ,isnull(ScheduledDate, '')      
     ,isnull(ScheduledTime, '')      
     ,SmppID      
     ,U_ID      
     ,IsUniCode      
     ,IsDnd      
     ,IsAirtel      
     ,MobileSubSet      
     ,ValidNo      
     ,IsPrority      
     ,IsAllowDND      
     ,DBType      
     ,'Mass Send Lead'      
     ,@CreatedBy      
    FROM #tmpflind      
      
    BEGIN TRY      
     EXEC Usp_Save_DLTTemplateID_with_BatchID @batchid      
      ,@DLTTemplateID      
    END TRY      
      
    BEGIN CATCH      
     EXEC usp_InsertErrorInfo      
    END CATCH      
   END      
   ELSE      
    SET @indprc = 1      
  END      
 END      
      
 /*       Commented as indian messages should not be inserted here                    
 if @intprc  = 0 and @indprc  = 0                                    
 begin                                    insert into CloneIntMsgDeliveryStatus                                    
  (BatchID, Country_code, Mobile, Message, MessageStatus, SenderID,                                     
  MessageInsertDate, ScheduledDate, ScheduledTime, SmppID, U_ID, IsUniCode,                                     
  IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType,                                   
  campaignid, Processed, Hasvirtualcredits, HasSufficientvirtualcredits, price)                                    
  select BatchID, Country_code, Mobile, Message, MessageStatus, SenderID,                                    
   MessageInsertDate, isnull(ScheduledDate,''), isnull(ScheduledTime,''), SmppID, U_ID, IsUniCode,                                     
   IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType,                                     
   campaignid, Processed, Hasvirtualcredits, HasSufficientvirtualcredits,                                     
   price from #tmpflint                  
 end                         
 */      
 IF @intprc = 0      
  AND @indprc = 0      
 BEGIN      
  IF (@UserId > 0)      
  BEGIN      
   DECLARE @leadActivityHistory AS LeadActivitywithid_Tbltype      
   DECLARE @Username NVARCHAR(255)      
    ,@ParentId BIGINT = 0      
      
   SELECT top 1 @Username = User_Login      
    ,@ParentId = ParentID      
   FROM User_Detail(NOLOCK)      
   WHERE User_Id = @UserId      
      
   INSERT INTO @leadActivityHistory (      
    LeadID      
    ,UserID      
    ,ParentID      
    ,EventDescription      
    ,EventName      
    ,RefTable      
    ,refid      
    )      
   SELECT leadid      
    ,@UserId      
    ,@parentid      
    ,CONCAT (      
     @Username      
     ,' sent an sms with content '      
     ,Message      
     ,' on mobile '      
     ,Mobile      
     )      
    ,'SMS sent to lead'      
    ,'Batchinfo'      
    ,@BatchID      
   FROM #tmpflind      
      
   EXEC UspSaveLeadActivity_withMultipleValue_withid @leadActivityHistory      
  END      
      
  SELECT 'Record Saved'      
 END      
 ELSE      
 BEGIN      
  SELECT 'Insufficient Balance'      
 END      
      
 DECLARE @rowJson NVARCHAR(MAX) = (      
   SELECT *      
   FROM CloneMessageDeliveryStatus      
   WHERE BatchID = @BatchID      
   FOR JSON AUTO      
    ,INCLUDE_NULL_VALUES      
   )      
     IF(@rowJson is not null)
	 begin
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId      
  ,@Activity_type = 'Inst_Sms_Lead'      
  ,@ActionType = 'I'       
  ,@RowJson = @rowJson      
  ,@Table_name = 'CloneMessageDeliveryStatus'      
  end
END      
    
    


