   --  )      
   DECLARE @mBalance decimal(18,4) = @CurrentBalance - @Cr_amt1-- (@NoOfSMS*@Cr_amt1)      
      print @mBalance


	  DECLARE @SenderName NVARCHAR(100) = NULL;

	  SELECT TOP 1 @SenderName = Sender_Name 
		FROM SenderID_Detail WITH (NOLOCK) 
			WHERE User_ID = @ParentIDAccount and (
				(Sender_ID = TRY_CONVERT(BIGINT, @SenderID, 0 ) and ISNUMERIC(@SenderID) = 1)
				or Sender_Name =  @SenderID 
			);

   IF @mBalance >= 0      
   BEGIN      
    INSERT INTO CloneMessageDeliveryStatus (      
     BatchID      
     ,Mobile      
     ,Message      
