    SELECT BatchID      
     ,Mobile      
     ,Message      
     ,MessageStatus      
     --,SenderID  
	 ,@SenderName
     ,MessageInsertDate      
     ,isnull(ScheduledDate, '')      
     ,isnull(ScheduledTime, '')      
     ,SmppID      
     ,U_ID      
     ,IsUniCode      
     ,IsDnd      
     ,IsAirtel      
     ,MobileSubSet      
     ,ValidNo      
     ,IsPrority      
     ,IsAllowDND      
     ,DBType      
     ,'Mass Send Lead'      
     ,@CreatedBy      
    FROM #tmpflind      
      
    BEGIN TRY      
     EXEC Usp_Save_DLTTemplateID_with_BatchID @batchid      
      ,@DLTTemplateID      
    END TRY      
      
    BEGIN CATCH      
