CREATE   PROCEDURE [dbo].[usp_IntindSMSFromlLead_WithDLTTemplateID] --2211077,32222,'RJGURU','hello 4:49 pm',0,1,1,1                                             
	@ID VARCHAR(MAX)
	,@Account BIGINT
	,@SenderID NVARCHAR(100)
	,@Message NVARCHAR(4000)
	,@IsUnicode BIT
	,@Mobile BIT
	,@mobile1 BIT
	,@Mobile2 BIT
	,@DLTTemplateID NVARCHAR(200)
	,@UserId BIGINT = 0
AS
BEGIN
	DECLARE @ParentAccount BIGINT = (
			SELECT TOP 1 ParentID
			FROM User_Detail WITH (NOLOCK)
			WHERE User_ID = @Account
			)
	DECLARE @batchid BIGINT

	BEGIN TRAN

	INSERT INTO GetBatchRecord (
		-- BatchID -- this column value is auto-generated                                                    
		[User_id]
		,RandNum
		)
	VALUES (
		@Account
		,@Account
		)

	SELECT @batchid = scope_identity()

	DELETE
	FROM getbatchrecord
	WHERE batchid = @batchid

	COMMIT

	CREATE TABLE #tmpflint (
		[BatchID] [bigint] NULL
		,[Country_code] [varchar](10) NULL
		,[Mobile] [varchar](20) NULL
		,[Message] [nvarchar](2500) NULL
		,[MessageStatus] [varchar](20) NULL
		,[SenderID] [nchar](20) NULL
		,[MessageInsertDate] [datetime] NULL
		,[ScheduledDate] [varchar](50) NULL
		,[ScheduledTime] [varchar](50) NULL
		,[SmppID] [tinyint] NULL
		,[U_ID] [int] NULL
		,[IsUniCode] [bit] NULL
		,[IsDnd] [bit] NULL
		,[IsAirtel] [bit] NULL
		,[MobileSubSet] [bigint] NULL
		,[ValidNo] [tinyint] NULL
		,[IsPrority] [tinyint] NULL
		,[IsAllowDND] [tinyint] NULL
		,[DBType] [nchar](10) NULL
		,[campaignid] [bigint] NULL
		,[Processed] [int] NULL
		,[Hasvirtualcredits] [int] NULL
		,[HasSufficientvirtualcredits] [int] NULL
		,[price] [float] NULL
		)

	--drop table #tmpflind                                    
	CREATE TABLE #tmpflind (
		[BatchID] [bigint] NULL
		,[Country_code] [varchar](10) NULL
		,[Mobile] [varchar](20) NULL
		,[Message] [nvarchar](2500) NULL
		,[MessageStatus] [varchar](20) NULL
		,[SenderID] [nchar](20) NULL
		,[MessageInsertDate] [datetime] NULL
		,[ScheduledDate] [varchar](50) NULL
		,[ScheduledTime] [varchar](50) NULL
		,[SmppID] [tinyint] NULL
		,[U_ID] [int] NULL
		,[IsUniCode] [bit] NULL
		,[IsDnd] [bit] NULL
		,[IsAirtel] [bit] NULL
		,[MobileSubSet] [bigint] NULL
		,[ValidNo] [tinyint] NULL
		,[IsPrority] [tinyint] NULL
		,[IsAllowDND] [tinyint] NULL
		,[DBType] [nchar](10) NULL
		,[Id] [bigint] --,    
		--[campaignid] [bigint] NULL,                                 
		--[Processed] [int] NULL,                                    
		--[Hasvirtualcredits] [int] NULL,                                    
		--[HasSufficientvirtualcredits] [int] NULL                                    
		)

	-- declare @ID VARCHAR(500) ='291573#291572' ,                               --@Account BIGINT =16301,                                                
	--@SenderID VARCHAR(50) ='KitApp',                                                
	--@Message VARCHAR(2000)='qwwee',                                                
	--@IsUnicode BIT=0,                                                
	--@Mobile BIT=1,                                                
	--@mobile1 BIT=1,                                                
	--@Mobile2 BIT =1                                                
	--DECLARE @BatchID BIGINT = (                                                
	--            SELECT MAX(gbr.BatchID)                                            
	--            FROM   GetBatchRecord AS gbr                                                
	--            WHERE  gbr.[User_id] = @Account                                                
	--        )                                       
	--DELETE                                                 
	--FROM   GetBatchRecord                                                
	--WHERE  [User_id] = @Account                                                    
	CREATE TABLE #TableData2 (ID BIGINT)

	INSERT INTO #TableData2 (ID)
	SELECT Item
	FROM fu_SplitString(@ID, '#')

	DECLARE @Uccode VARCHAR(20)

	SELECT TOP 1 @Uccode = isnull(CountryCode, '+91')
	FROM User_Detail AS ud
	WHERE ud.[User_ID] = @ParentAccount

	INSERT INTO #tmpflind (
		BatchID
		,Mobile
		,Country_Code
		,Message
		,MessageStatus
		,SenderID
		,MessageInsertDate
		,ScheduledDate
		,ScheduledTime
		,SmppID
		,U_ID
		,IsUnicode
		,IsDnd
		,IsAirtel
		,MobileSubSet
		,ValidNo
		,IsPrority
		,IsAllowDND
		,DBType
		,Id
		)
	SELECT BatchID
		,Mobile
		,CountryCode
		,Messagetext
		,MessageStatus
		,SenderID
		,MessageInsertDate
		,ScheduledDate
		,ScheduledTime
		,SmppID
		,U_ID
		,IsUnicode
		,IsDnd
		,IsAirtel
		,MobileSubSet
		,ValidNo
		,IsPrority
		,IsAllowDND
		,DBType
		,Id
	FROM (
		SELECT @BatchID AS BatchID
			,CASE 
				WHEN @Mobile = 1
					THEN ISNULL(NULLIF(ue.MobileNo, ''), '0')
				ELSE '0'
				END AS Mobile
			,CASE 
				WHEN @Mobile = 1
					THEN ISNULL(ue.CountryCode, '')
				ELSE ''
				END AS CountryCode
			,dbo.fn_getEnquiryMessage_new(ue.ParentID, @Message, ue.MobileNo) AS Messagetext
			,NULL AS MessageStatus
			,@SenderID AS SenderID
			,GETDATE() AS MessageInsertDate
			,NULL AS ScheduledDate
			,NULL AS ScheduledTime
			,(
				SELECT TOP 1 ud.SmppID
				FROM User_Detail AS ud
				WHERE ud.[User_ID] = @Account
				) AS SmppID
			,@Account AS U_ID
			,@IsUnicode AS IsUnicode
			,0 AS IsDnd
			,0 AS IsAirtel
			,0 AS MobileSubSet
			,1 AS ValidNo
			,1 AS IsPrority
			,0 AS IsAllowDND
			,0 AS DBType
			,ue.ID AS [Id]
		FROM UserLeads AS ue
		INNER JOIN #TableData2 t2 ON ue.ID = t2.ID
		WHERE --ue.ID IN (SELECT [value] FROM   dbo.fn_Split(@ID, '#') AS fs) AND   
			ISNULL(NULLIF(ue.MobileNo, ''), '') <> ''
			AND ISNULL(NULLIF(ue.MobileNo, ''), '') NOT IN (
				SELECT ISNULL(C_UDTemp.Mobile, '') AS MobileNo
				FROM UserLeads UETemp
				INNER JOIN Client_UnSubscribeDetails C_UDTemp ON (
						UeTemp.MobileNo = C_UDTemp.Mobile
						AND UETemp.CountryCode = C_UDTemp.CountryCode
						AND C_UDTemp.ParentId = UETemp.ParentID
						)
				INNER JOIN #TableData2 t2 ON UE.ID = t2.ID
				)
		--where UE.ID in(Select fs.value from dbo.fn_Split(@ID, '#') AS fs )  
		
		UNION
		
		SELECT @BatchID
			,CASE 
				WHEN @mobile1 = 1
					THEN ISNULL(NULLIF(ue.MobileNo1, ''), '0')
				ELSE '0'
				END AS Mobile
			,CASE 
				WHEN @mobile1 = 1
					THEN ISNULL(ue.CountryCode1, '')
				ELSE ''
				END AS CountryCode
			,dbo.fn_getEnquiryMessage_new(ue.ParentID, @Message, ue.MobileNo1) AS Messagetext
			,NULL AS MessageStatus
			,@SenderID AS SenderID
			,GETDATE() AS MessageInsertDate
			,NULL AS ScheduledDate
			,NULL AS ScheduledTime
			,(
				SELECT TOP 1 ud.SmppID
				FROM User_Detail AS ud
				WHERE ud.[User_ID] = @Account
				) AS SmppID
			,@Account AS U_ID
			,@IsUnicode AS IsUnicode
			,0 AS IsDnd
			,0 AS IsAirtel
			,0 AS MobileSubSet
			,1 AS ValidNo
			,1 AS IsPrority
			,0 AS IsAllowDND
			,0 AS DBType
			,ue.ID AS [Id]
		FROM UserLeads AS ue
		INNER JOIN #TableData2 t2 ON ue.ID = t2.ID
		WHERE -- ue.ID IN (SELECT [value] FROM   dbo.fn_Split(@ID, '#') AS fs) AND    
			ISNULL(NULLIF(ue.MobileNo1, ''), '') <> ''
			AND ISNULL(NULLIF(ue.MobileNo1, ''), '') NOT IN (
				SELECT ISNULL(C_UDTemp.Mobile, '') AS MobileNo1
				FROM UserLeads UETemp
				INNER JOIN Client_UnSubscribeDetails C_UDTemp ON (
						UeTemp.MobileNo1 = C_UDTemp.Mobile
						AND UETemp.CountryCode1 = C_UDTemp.CountryCode
						AND C_UDTemp.ParentId = UETemp.ParentID
						)
				INNER JOIN #TableData2 t2 ON UE.ID = t2.ID
				)
		--where UE.ID in(Select fs.value from dbo.fn_Split(@ID, '#') AS fs )  
		
		UNION
		
		SELECT @BatchID
			,CASE 
				WHEN @Mobile2 = 1
					THEN ISNULL(NULLIF(ue.MobileNo2, ''), '0')
				ELSE '0'
				END AS Mobile
			,CASE 
				WHEN @Mobile2 = 1
					THEN ISNULL(ue.CountryCode2, '')
				ELSE ''
				END AS CountryCode
			,dbo.fn_getEnquiryMessage_new(ue.ParentID, @Message, ue.MobileNo2) AS Messagetext
			,NULL AS MessageStatus
			,@SenderID AS SenderID
			,GETDATE() AS MessageInsertDate
			,NULL AS ScheduledDate
			,NULL AS ScheduledTime
			,(
				SELECT TOP 1 ud.SmppID
				FROM User_Detail AS ud
				WHERE ud.[User_ID] = @Account
				) AS SmppID
			,@Account AS U_ID
			,@IsUnicode AS IsUnicode
			,0 AS IsDnd
			,0 AS IsAirtel
			,0 AS MobileSubSet
			,1 AS ValidNo
			,1 AS IsPrority
			,0 AS IsAllowDND
			,0 AS DBType
			,ue.ID AS [ID]
		FROM UserLeads AS ue
		INNER JOIN #TableData2 t2 ON ue.ID = t2.ID
		WHERE
			--ue.ID IN (SELECT [value] FROM   dbo.fn_Split(@ID, '#') AS fs) AND  
			ISNULL(NULLIF(ue.MobileNo2, ''), '') <> ''
			AND ISNULL(NULLIF(ue.MobileNo2, ''), '') NOT IN (
				SELECT ISNULL(C_UDTemp.Mobile, '') AS MobileNo2
				FROM UserLeads UETemp
				INNER JOIN Client_UnSubscribeDetails C_UDTemp ON (
						UeTemp.MobileNo2 = C_UDTemp.Mobile
						AND UETemp.CountryCode2 = C_UDTemp.CountryCode
						AND C_UDTemp.ParentId = UETemp.ParentID
						)
				INNER JOIN #TableData2 t2 ON ue.ID = t2.ID
					--where UE.ID in(Select fs.value from dbo.fn_Split(@ID, '#') AS fs )  
				)
		) A
	WHERE A.Mobile <> '0'

	IF @Uccode = '+91'
	BEGIN
		INSERT INTO #tmpflint (
			BatchID
			,Country_code
			,Mobile
			,Message
			,MessageStatus
			,SenderID
			,MessageInsertDate
			,ScheduledDate
			,ScheduledTime
			,SmppID
			,U_ID
			,IsUniCode
			,IsDnd
			,IsAirtel
			,MobileSubSet
			,ValidNo
			,IsPrority
			,IsAllowDND
			,DBType
			)
		SELECT BatchID
			,Country_code
			,replace(Country_code, '+', '') + Mobile
			,Message
			,MessageStatus
			,SenderID
			,MessageInsertDate
			,ScheduledDate
			,ScheduledTime
			,SmppID
			,U_ID
			,IsUniCode
			,IsDnd
			,IsAirtel
			,MobileSubSet
			,ValidNo
			,IsPrority
			,IsAllowDND
			,DBType
		FROM #tmpflind
		WHERE Country_Code <> '+91'

		DELETE
		FROM #tmpflind
		WHERE Country_Code <> '+91'
	END
	ELSE
	BEGIN
		INSERT INTO #tmpflint (
			BatchID
			,Country_code
			,Mobile
			,Message
			,MessageStatus
			,SenderID
			,MessageInsertDate
			,ScheduledDate
			,ScheduledTime
			,SmppID
			,U_ID
			,IsUniCode
			,IsDnd
			,IsAirtel
			,MobileSubSet
			,ValidNo
			,IsPrority
			,IsAllowDND
			,DBType
			)
		SELECT BatchID
			,Country_code
			,Mobile
			,Message
			,MessageStatus
			,SenderID
			,MessageInsertDate
			,ScheduledDate
			,ScheduledTime
			,SmppID
			,U_ID
			,IsUniCode
			,IsDnd
			,IsAirtel
			,MobileSubSet
			,ValidNo
			,IsPrority
			,IsAllowDND
			,DBType
		FROM #tmpflind
	END

	DECLARE @NoOfSMS BIGINT = 0
		,@intsms BIGINT = 0;

	SELECT @intsms = COUNT(*)
	FROM #tmpflint

	DECLARE @intprc INT = 0
		,@indprc INT = 0

	IF @intsms > 0
	BEGIN
		UPDATE #tmpflint
		SET price = (
				CASE 
					WHEN IsUniCode = 0
						AND len(message) <= 160
						THEN 1
					WHEN IsUniCode = 0
						AND LEN(message) > 160
						THEN ceiling(LEN(message) / cast(153 AS FLOAT))
					WHEN IsUniCode = 1
						AND len(message) <= 70
						THEN 1
					ELSE ceiling(LEN(message) / cast(67 AS FLOAT))
					END
				) * (
				SELECT price
				FROM dbo.IntSMSRateMast
				WHERE country_code = #tmpflint.country_code
				)

		DECLARE @Cr_amt FLOAT
			,@balance FLOAT

		SELECT @Cr_amt = SUM(price)
		FROM #tmpflint

		SELECT TOP 1 @balance = Balance
		FROM dbo.IntCredit_Details
		WHERE USER_ID = @ParentAccount

		IF @balance < @Cr_amt
			SET @intprc = 1
	END

	IF @intprc = 0
	BEGIN
		--select 1                                 
		SELECT @NoOfSMS = COUNT(*)
		FROM #tmpflind

		IF @NoOfSMS > 0
		BEGIN
			DECLARE @CurrentBalance BIGINT = (
					SELECT TOP 1 isnull(cd.Balance, 0)
					FROM Credit_Details AS cd
					WHERE cd.[User_ID] = @ParentAccount
					ORDER BY cd.Credit_ID DESC
					)

			PRINT @CurrentBalance
			PRINT @NoOfSMS

			DECLARE @mBalance BIGINT = @CurrentBalance - @NoOfSMS

			IF @mBalance >= 0
			BEGIN
				INSERT INTO CloneMessageDeliveryStatus (
					BatchID
					,Mobile
					,Message
					,MessageStatus
					,SenderID
					,MessageInsertDate
					,ScheduledDate
					,ScheduledTime
					,SmppID
					,U_ID
					,IsUniCode
					,IsDnd
					,IsAirtel
					,MobileSubSet
					,ValidNo
					,IsPrority
					,IsAllowDND
					,DBType
					,CMDS_CreatedBy
					)
				SELECT BatchID
					,Mobile
					,Message
					,MessageStatus
					,SenderID
					,MessageInsertDate
					,isnull(ScheduledDate, '')
					,isnull(ScheduledTime, '')
					,SmppID
					,U_ID
					,IsUniCode
					,IsDnd
					,IsAirtel
					,MobileSubSet
					,ValidNo
					,IsPrority
					,IsAllowDND
					,DBType
					,@UserId
				FROM #tmpflind

				BEGIN TRY
					EXEC Usp_Save_DLTTemplateID_with_BatchID @batchid
						,@DLTTemplateID
				END TRY

				BEGIN CATCH
					EXEC usp_InsertErrorInfo
				END CATCH
			END
			ELSE
				SET @indprc = 1
		END
	END

	DROP TABLE #TableData2

	/*       Commented as indian messages should not be inserted here                  
 if @intprc  = 1 and @indprc  = 0                                    
 begin                                    
  insert into CloneIntMsgDeliveryStatus                                    
  (BatchID, Country_code, Mobile, Message, MessageStatus, SenderID,                                     
  MessageInsertDate, ScheduledDate, ScheduledTime, SmppID, U_ID, IsUniCode,                                     
  IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType,                                     
  campaignid, Processed, Hasvirtualcredits, HasSufficientvirtualcredits, price)                        
  select BatchID, Country_code, Mobile, Message, MessageStatus, SenderID,                                    
   MessageInsertDate, isnull(ScheduledDate,''), isnull(ScheduledTime,''), SmppID, U_ID, IsUniCode,                                     
   IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType,                                     
   campaignid, Processed, Hasvirtualcredits, HasSufficientvirtualcredits,                                     
   price from #tmpflint                                    
 end                       
 */
	IF @intprc = 0
		AND @indprc = 0
	BEGIN
		IF (@UserId > 0)
		BEGIN
			DECLARE @ParentId BIGINT
				,@Username NVARCHAR(255)
			DECLARE @leadActivityHistory AS LeadActivitywithid_Tbltype

			SELECT @Username = User_Login
				,@ParentId = ParentID
			FROM User_Detail(NOLOCK)
			WHERE User_Id = @UserId

			INSERT INTO @leadActivityHistory (
				LeadID
				,UserID
				,ParentID
				,EventDescription
				,EventName
				,RefTable
				,refid
				)
			SELECT Id
				,@UserId
				,@parentid
				,CONCAT (
					@Username
					,' sent an sms with content '
					,Message
					,' on mobile '
					,Mobile
					)
				,'SMS sent to Lead'
				,'Batchinfo'
				,@BatchID
			FROM #tmpflind

			EXEC UspSaveentityActivity_withMultipleValue_withid @leadActivityHistory
		END

		SELECT 'Record Saved'
	END
	ELSE
	BEGIN
		SELECT 'Insufficient Balance'
	END

	DECLARE @rowJson NVARCHAR(MAX) = (
			SELECT *
			FROM CloneMessageDeliveryStatus WITH(NOLOCK)
			WHERE BatchID = @BatchID
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)
	IF @rowJson IS NOT NULL
	BEGIN
	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId
		,@Activity_type = 'Inst_Sms_Lead'
		,@ActionType = 'I'
		,@RowJson = @rowJson
		,@Table_name = 'CloneMessageDeliveryStatus'
	END
END



GO

/* ============================================================
   Procedure: [dbo].[usp_IntindSMSFromUser_New1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


  
CREATE   PROCEDURE [dbo].[usp_IntindSMSFromUser_New1]                                    
 @UserID VARCHAR(500),                                      
 @Account BIGINT,                                      
 @SenderID VARCHAR(50),                                      
 @Message NVARCHAR(4000),                                      
 @IsUnicode BIT,                                      
 @Mobile BIT                                     
 --@mobile1 BIT,                                      
 --@Mobile2 BIT                                      
AS                                      
BEGIN                                      
 -- BatchID -- this column value is auto-generated                                            
      
 DECLARE @BatchID BIGINT         
      
 begin tran                                      
 INSERT INTO GetBatchRecord                                      
   (                                      
     [User_id],                                      
     RandNum                                      
   )                                      
 VALUES                                      
   (                                      
     @Account,                                      
     @Account                                      
   )                                            
select @BatchID =scope_identity()      
DELETE                                       
 FROM   GetBatchRecord                                      
 WHERE  batchid=@batchid                                        
commit      
                       
   CREATE TABLE #tmpflint(                      
 [BatchID] [bigint]  NULL,                      
 [Country_code] [varchar](10) NULL,                      
 [Mobile] [varchar](20) NULL,                      
 [Message] [nvarchar](2500) NULL,                      
 [MessageStatus] [varchar](20) NULL,                      
 [SenderID] [nchar](40) NULL,                      
 [MessageInsertDate] [datetime]  NULL,                      
 [ScheduledDate] [varchar](50) NULL,                      
 [ScheduledTime] [varchar](50) NULL,                      
 [SmppID] [tinyint]  NULL,                      
 [U_ID] [int]  NULL,                      
 [IsUniCode] [bit]  NULL,                      
 [IsDnd] [bit]  NULL,                      
 [IsAirtel] [bit]  NULL,                      
 [MobileSubSet] [bigint] NULL,                      
 [ValidNo] [tinyint] NULL,                      
 [IsPrority] [tinyint] NULL,                      
 [IsAllowDND] [tinyint] NULL,                      
 [DBType] [nchar](10) NULL,                      
 [campaignid] [bigint] NULL,                      
 [Processed] [int] NULL,                      
 [Hasvirtualcredits] [int] NULL,                      
 [HasSufficientvirtualcredits] [int] NULL,                      
 [price] [float] NULL                      
)                      
--drop table #tmpflind                      
CREATE TABLE #tmpflind(                      
 [BatchID] [bigint]  NULL,                      
 [Country_code] [varchar](10) NULL,                      
 [Mobile] [varchar](20) NULL,                      
 [Message] [nvarchar](2500) NULL,                      
 [MessageStatus] [varchar](20) NULL,                      
 [SenderID] [nchar](40) NULL,                      
 [MessageInsertDate] [datetime]  NULL,                      
 [ScheduledDate] [varchar](50) NULL,                      
 [ScheduledTime] [varchar](50) NULL,                      
 [SmppID] [tinyint]  NULL,                      
 [U_ID] [int]  NULL,                      
 [IsUniCode] [bit]  NULL,                      
 [IsDnd] [bit]  NULL,                      
 [IsAirtel] [bit]  NULL,                      
 [MobileSubSet] [bigint] NULL,                      
 [ValidNo] [tinyint] NULL,                      
 [IsPrority] [tinyint] NULL,                      
 [IsAllowDND] [tinyint] NULL,                      
 [DBType] [nchar](10) NULL--,                      
 --[campaignid] [bigint] NULL,                      
 --[Processed] [int] NULL,   
 --[Hasvirtualcredits] [int] NULL,                      
 --[HasSufficientvirtualcredits] [int] NULL                      
)                      
                    
            
                                    
declare @Uccode varchar(20)                       
  SELECT TOP 1 @Uccode =  isnull(CountryCode,'+91')                      
  FROM   User_Detail (nolock) AS ud                                  
  WHERE  ud.[User_ID] = @Account                     
                       
 INSERT INTO #tmpflind                                  
   ( BatchID,Mobile,Country_Code,Message,                                  
             MessageStatus, SenderID,MessageInsertDate,ScheduledDate,                                  
             ScheduledTime,SmppID,U_ID,IsUnicode,IsDnd,IsAirtel,MobileSubSet,                      
             ValidNo,IsPrority,IsAllowDND,DBType                         
   )                             
     SELECT BatchID,Mobile,CountryCode,Messagetext,                                  
             MessageStatus, SenderID,MessageInsertDate,ScheduledDate,                                  
        ScheduledTime,SmppID,U_ID,IsUnicode,IsDnd,IsAirtel,MobileSubSet,                      
             ValidNo,IsPrority,IsAllowDND,DBType                         
 FROM   (                                      
            SELECT @BatchID    AS BatchID,                                      
                   CASE                                       
                        WHEN @Mobile = 1 THEN ISNULL(NULLIF(ude.Mobile, ''), '0') ELSE '0'                                      
                  END         AS Mobile,                      
                   CASE                                   
                WHEN @Mobile = 1 THEN ISNULL(ude.CountryCode ,'')                      
                ELSE '' END AS CountryCode,                                     
     dbo.fn_getUserMessage(ude.ParentID, @Message, ude.Mobile) AS                                       
                   Messagetext,                                      
                   NULL        AS MessageStatus,                                      
                   @SenderID   AS SenderID,                                      
                   GETDATE()   AS MessageInsertDate,                                      
                   NULL        AS ScheduledDate,                                      
                   NULL        AS ScheduledTime,                                      
                   (                                      
                       SELECT TOP 1 ud.SmppID                                      
                       FROM   User_Detail (nolock) AS ud                                      
                       WHERE  ud.[User_ID] = @Account                                      
                   )           AS SmppID,                                      
                   @Account    AS U_ID,                                      
                   @IsUnicode  AS IsUnicode,                                      
                   0           AS IsDnd,                                      
                   0           AS IsAirtel,                                      
                   0           AS MobileSubSet,                                      
                   1           AS ValidNo,                                      
                   1           AS IsPrority,                                      
                   0           AS IsAllowDND,                                      
                   0           AS DBType                                      
            FROM   User_Detail  (nolock) AS ude                                      
            WHERE  ude.User_ID =@UserID                                     
                   AND ISNULL(NULLIF(ude.Mobile, ''), '') <>''                                       
                   AND ISNULL(NULLIF(ude.Mobile , ''), '') not in                                 
                   (select  ISNULL(C_UDTemp.Mobile,'') as MobileNo                      
                   from User_Detail UETemp inner join Client_UnSubscribeDetails C_UDTemp                                
                   on (UeTemp.Mobile =C_UDTemp.Mobile                       
                   and UETemp.CountryCode = C_UDTemp.CountryCode and C_UDTemp.ParentId=UETemp.ParentID)                                
                   where ude.User_ID =@UserID )                               
                                           
        ) A                                      
 WHERE  A.Mobile <> '0'                                        
                       
 if @Uccode = '+91'                      
 begin                      
  insert into #tmpflint (BatchID, Country_code,Mobile, Message, MessageStatus, SenderID,                                  
     MessageInsertDate, ScheduledDate, ScheduledTime,                                  
     SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,                                  
     ValidNo, IsPrority, IsAllowDND, DBType)                       
   select BatchID, Country_code,Mobile, Message, MessageStatus, SenderID,                                  
     MessageInsertDate, ScheduledDate, ScheduledTime,                                  
     SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,                                  
     ValidNo, IsPrority, IsAllowDND, DBType from  #tmpflind                      
   where Country_Code <>'+91'                      
  delete From #tmpflind where Country_Code <>'+91'                      
 end                      
 else                      
 begin                      
  insert into #tmpflint (BatchID, Country_code,Mobile, Message, MessageStatus, SenderID,                                  
     MessageInsertDate, ScheduledDate, ScheduledTime,                                  
     SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,                                  
     ValidNo, IsPrority, IsAllowDND, DBType)                       
   select BatchID, Country_code,Mobile, Message, MessageStatus, SenderID,                                  
     MessageInsertDate, ScheduledDate, ScheduledTime,                                  
     SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,                                  
     ValidNo, IsPrority, IsAllowDND, DBType from  #tmpflind                      
 end                      
 Declare @NoOfSMS  bigint = 0, @intsms bigint =0;                       
 select @intsms = COUNT(*) from #tmpflint                        
                      
declare @intprc int = 0 , @indprc int = 0    
if @intsms > 0                      
begin                      
 update #tmpflint set price= (case when IsUniCode=0 and len(message)<=160  then 1                             
 when IsUniCode=0 and LEN(message)>160 then ceiling(LEN(message)/cast(153 as FLOat))                             
  when IsUniCode=1                             
 and len(message)<=70 then 1 else ceiling(LEN(message)/cast(67 as float)) end )*                      
  (select price from dbo.IntSMSRateMast where country_code =#tmpflint.country_code)                        
                       
 declare @Cr_amt float,@balance float                            
 select @Cr_amt = SUM(price) from #tmpflint                            
 select top 1 @balance= Balance from dbo.IntCredit_Details where USER_ID = @Account                        
 if @balance < @Cr_amt                      
 set @intprc = 1                         
end                      
                      
if @intprc =0                      
begin                       
  select @NoOfSMS = COUNT(*) from #tmpflind                      
 if @NoOfSMS > 0                      
 begin                      
  DECLARE @CurrentBalance BIGINT = (                                      
             SELECT TOP 1 isnull(cd.Balance,0)                                      
             FROM   Credit_Details AS cd                                      
             WHERE  cd.[User_ID] = @Account                                      
             ORDER BY                                      
                    cd.Credit_ID DESC                                      
   )                                      
 DECLARE @mBalance BIGINT = @CurrentBalance - @NoOfSMS                                      
 IF @mBalance >= 0                          
   begin                      
 INSERT INTO CloneMessageDeliveryStatus                                  
   (BatchID, Mobile, Message, MessageStatus, SenderID,                                  
     MessageInsertDate, ScheduledDate, ScheduledTime,                                  
     SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,                                  
     ValidNo, IsPrority, IsAllowDND, DBType)                              
 select BatchID, Mobile, Message, MessageStatus, SenderID,                                  
     MessageInsertDate, isnull(ScheduledDate,''), isnull(ScheduledTime,''),                                  
     SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,                                  
     ValidNo, IsPrority, IsAllowDND, DBType from #tmpflind                      
   end                      
   else                      
 set @indprc = 1                      
 end                      
end         
/*       Commented as indian messages should not be inserted here      
 if @intprc  = 0 and @indprc  = 0                      
 begin                      
  insert into CloneIntMsgDeliveryStatus                      
  (BatchID, Country_code, Mobile, Message, MessageStatus, SenderID,                       
  MessageInsertDate, ScheduledDate, ScheduledTime, SmppID, U_ID, IsUniCode,                       
  IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType,                       
  campaignid, Processed, Hasvirtualcredits, HasSufficientvirtualcredits, price)                      
  select BatchID, Country_code, Mobile, Message, MessageStatus, SenderID,                      
   MessageInsertDate, isnull(ScheduledDate,''), isnull(ScheduledTime,''), SmppID, U_ID, IsUniCode,                       
   IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType,                       
   campaignid, Processed, Hasvirtualcredits, HasSufficientvirtualcredits,                       
   price from #tmpflint                      
 end           
 */                 
 if @intprc  = 0 and @indprc  = 0                   
 BEGIN  
       SELECT 'Record Saved'         
         
 DECLARE @rowJson NVARCHAR(MAX) = (          
   SELECT *          
   FROM CloneMessageDeliveryStatus          
   WHERE BatchID = @BatchID          
   FOR JSON AUTO          
    ,INCLUDE_NULL_VALUES          
   )          
          
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @Account          
  ,@Activity_type = 'Inst_Sms_User'          
  ,@ActionType = 'I'           
  ,@RowJson = @rowJson          
  ,@Table_name = 'CloneMessageDeliveryStatus'       
 END  
     Else                              
        select 'Insufficient Balance'                              
                                   
                                      
END 




GO

/* ============================================================
   Procedure: [dbo].[usp_intlSMSDeductBalGetFinalMsg]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_intlSMSDeductBalGetFinalMsg]
(
    @userId bigint ,    
    @Batchid nvarchar(max),
    @MessageID nvarchar(max),
    @Mode varchar(10)='Single'
)          
as          
begin          
          
    -- declare @CountryCode nvarchar(200)='+27',@userId bigint=34594 ,@Batchid nvarchar(max)='156198643',@MessageID nvarchar(max)='22009',@Mode varchar(10)='bulk'    


DECLARE @ParentId bigint,@M_ID bigint,@MessageDeliveryStatusID bigint=0,@Message_ID bigint=0;          
declare @Balance as numeric(18,4), @Batch_ID bigint=0, @MobileNo varchar(50)='',@SenderID nvarchar(40);          
declare @cost_in_inr as numeric(18,4)=0, @Def_cost_in_inr numeric(18,4)=1;          
          
--select * from user_detail where User_ID=335          
          
select @ParentId=ParentId,@M_ID=M_ID from user_detail with(nolock) where User_ID=@userId
  
                
  -------------------------------------
    drop table if exists #remp
    drop table if exists #temp

    create table #remp([id] int identity(1,1),[rexp] nvarchar(20))  

     Select *,  ROW_NUMBER() OVER (ORDER BY MessageDeliveryStatusID) AS RowNum  
     into #temp from Int_MessageDeliveryStatus(nolock) 
     Where MessageDeliveryStatusID=case when @Mode='Single' then @MessageID else MessageDeliveryStatusID end 
            and BatchID=case when @Mode='Bulk' then @Batchid else BatchID end

    if exists (select 1 from Link_smsUrl_dtl(nolock) where batchid=@Batchid)  
    begin  
     print 'Entered Link tracking '  
     DECLARE @result NCHAR(4),@shorturl nvarchar(100),@longurl nvarchar(1000),@processurlid bigint ,@dlcount int  
     select top 1 @shorturl=short_url,@processurlid=ProcessUrl_Id,@longurl=longurl from Link_smsUrl_dtl(nolock) where BatchId=@Batchid  
     print concat('longurl: ',@longurl, ', @batchid: ',@Batchid)  
  
     RETRY:  
     BEGIN TRY  
     BEGIN TRAN  

  
     select @dlcount=count(1) from #temp m join Link_smsUrl_dtl(nolock) l on  
     m.BatchID=l.BatchId and m.Message like '%'+l.longurl+'%'  
     where m.batchid=@Batchid  
  
  
     --create short urls for each message  
     insert into #remp(rexp)  
     select top (@dlcount) r.[randomexp]  
     from dbo.randomexp(nolock) r where r.id>(select isnull(lastid,0) from Link_urlMaster(nolock) where shorturl=@shorturl) order by r.id  
  
  
     --update short url master so the short urls are picked after the ones that are used above  
     update Link_urlMaster set lastid=isnull(lastid,0)+@dlcount where shorturl=@shorturl ;  
  
     COMMIT  
     END TRY  
     BEGIN CATCH  
      IF @@TRANCOUNT>0  
       ROLLBACK  
        
      --EXECUTE USP_INSERTERRORINFO;  
      IF ERROR_NUMBER() = 1205 -- Deadlock Error Number  
      BEGIN  
       WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms  
       GOTO RETRY -- Go to Label RETRY  
      END  
     END CATCH  
  
     --update temp table with link tracking urls, temporarily use status description column for short url exp  
     ;WITH CTE AS (  
     SELECT rownum,ROW_NUMBER() OVER (ORDER BY rownum) AS id  
     FROM #temp  
     )  
  
     UPDATE T1  
     SET T1.message=case when t2.rexp is not null then replace(message,@longurl,@shorturl+'/'+rexp) else message end  
     , T1.IsPersonalised=1
     ,t1.StatusDescription=rexp  
     FROM #temp T1  
     JOIN CTE C1 ON T1.RowNum = C1.rownum  
     left JOIN #remp T2 ON C1.id = T2.id where t1.batchid=@batchid;  
  
     --insert in link tracking table so we recognize the mobile associated with the short url  
     insert into dbo.Link_smsMobile  
     (Mobile, batchid, shorturl, longurl, ProcessUrl_id, Final_url, Parentid, MessageID, Page_nm,p_url)  
     select Mobile, batchid, @shorturl, @longurl, @processurlid, rexp, @Parentid, lk.MessageDeliveryStatusID, 'Send IntSMS Proc', @longurl  
     from #remp ins inner join #temp lk  
     on ins.rexp=lk.StatusDescription  
     print concat('rowsinserted in link_smsmobile: ',@@rowcount, ', @batchid: ',@batchid)  
  
     --update statusdescription to its original null value  
     update t set t.StatusDescription=null from #temp t where batchid=@batchid  
    end  
    -----------------------------
   


    update p set price=Cast((dbo.ufn_GetIntlSMSUnitPrice(@parentid,CountryCode) *  
    (case when dbo.fn_isunicode(p.message)=0 and len(p.message)<=160 then 1  
    when dbo.fn_isunicode(p.message)=0 and LEN(p.message)>160 then  
    ceiling(LEN(p.message)/cast(153 as FLOat))  
    when dbo.fn_isunicode(p.message)=1 and len(p.message)<=70 then 1  
    else ceiling(LEN(p.message)/cast(67 as float)) end)) as Numeric(18,4))  
    from #temp p where batchid=@batchid  


  update I set I.Processed=1,I.MessageStatus='InProcess', I.price=T.price, I.IsPersonalised=T.IsPersonalised    
  From Int_MessageDeliveryStatus I inner join #temp T
  on I.MessageDeliveryStatusID=T.MessageDeliveryStatusID
  where I.BatchID in (select value from dbo.fn_Split(@BatchID ,',') )    

    ---------------
  --return
  ------------------


 declare @i bigint=0, @RecCnt int=0  
   
 Select @RecCnt=max(MessageDeliveryStatusID) From #temp --#tbl_MessageId  
 Select @i=min(MessageDeliveryStatusID) From #temp 
  

 While (@i<=@RecCnt)  
 Begin  
        
  Select @cost_in_inr=isnull(price,@Def_cost_in_inr),@MessageDeliveryStatusID=MessageDeliveryStatusID, @Batch_ID=BatchID,@MobileNo=CONCAT(Countrycode,Mobile),@SenderID=SenderID  
  from #temp(nolock)   
  Where  MessageDeliveryStatusID=@i  


     select @Balance=dbo.fn_GetMoneyBalance(@userId)    
     

  insert into IntCredit_Details( FromUser_ID, M_ID, User_ID, Debits, Credits, Balance, Validity, typecredit, Remarks, Batchid)                                
  select @userId, isnull(@M_ID,10043),@userId,@cost_in_inr,0,(@Balance-@cost_in_inr),99999,3,concat('Balance deducted for SMS with SenderId ',trim(@SenderID),' for Mobileno ',   
      @MobileNo,' under MessageDeliveryStatusID ',@MessageDeliveryStatusID,' dated ', format(getdate(),'dd-MMM-yyyy')), @Batch_ID    
  
    declare @intCreditId bigint = scope_identity()  
    exec usp_rf_UpdateReserveFundTransaction @CreditId = @intCreditId  

  if exists(Select min(MessageDeliveryStatusID) From #temp  where MessageDeliveryStatusID > @i)
  Begin
    Select @i=min(MessageDeliveryStatusID) From #temp  where MessageDeliveryStatusID > @i
  end
  Else
  Begin 
    break
  End
    --Set @i=@i+1  
 End  
             
      
  SELECT MessageDeliveryStatusID,CountryCode,Mobile,BatchID,Message,SenderID,U_ID,IsUniCode,EntityId,EntityName,UrlTrack,TrackedUrl,IsPersonalised
  from #temp;  
          
end   



GO

