   Procedure: [dbo].[usp_inv_AddProductInline]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_inv_AddProductInline] --'abc','imgtr1.jpg','abcd',23.45,35.23,311
(
	@ProductName nvarchar(200),
	@ProductImage nvarchar(200),
	@ProductDescription nvarchar(400),
	@ProductPrice decimal(18, 2),
	@ProductSalePrice decimal(18, 2),
	@UserId bigint
)
as
begin
    --declare @ParentID bigint = (select top 1 isnull(ParentID,0) from User_Detail with(nolock) where User_ID = @UserId)
	declare @ParentId bigint = (select top 1 isnull(parentid,0) from mysms.dbo.User_Detail(nolock) where User_Id = @UserId)
	
	declare @ProductId bigint = 0
	declare @ProductIDTemp bigint = 0    
    exec Usp_createProductMasterTable @ParentID 
		
	declare @Query nvarchar(max) =  concat( N'      
	insert into mysms.dbo.tbl_ProductMaster_',cast(@ParentID as nvarchar(max)),
	' ( Name, UserID, Image, Description, Price, sale_priceNoUSE,  CreatedOn, CreatedBy)
	values( ''',@ProductName,''',',cast(@ParentId as nvarchar(max)),', ''',@ProductImage,''', ''',@ProductDescription,''',
	', cast(@ProductPrice as nvarchar(max)),',', cast( @ProductSalePrice as nvarchar(max)),', getdate() ,', cast(@UserId as nvarchar(max)),' )
	 select @ProductIDTemp = scope_identity() ','')
	
	print @Query
	exec sp_executesql @Query, N' @ProductIDTemp bigint out ', @ProductId out


	Declare @Query_S nvarchar(max) = Concat(N' select ProductID as Id, Name, Image, Description, Price as [PurchasePrice], sale_priceNoUSE as SalePrice  
	from mysms.dbo.tbl_ProductMaster_',cast(@ParentID as nvarchar(max)),' (nolock) where ProductID = ', @ProductId ,'','')

	print @Query_S
	exec sp_executesql @Query_S

end



