 exec MySMSInvoicing.dbo.usp_ims_GetSettingBySetion @UserId, 'company'      
      
 --Table[4]      
 exec proc_displaySenderNameOfGSMType  @MId, @UserId      
      
 --Table[5]      
 exec proc_DisplayMailIDDetails @MId, @UserId, '1'      
    
 --Table[6]    
 select * from industry(nolock)    
    
 --Table[7]    
 select * from IST_TimeZone(nolock)    
--Table[8]    
 select City_ID, City_Name from m_city1(nolock) where State_ID =  ( select State_ID from m_state1(nolock) where State_Name = @StateName)    
end 



