/* ============================================================
   Procedure: [dbo].[usp_inv_GetCompanyTaxById]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_inv_GetCompanyTaxById](  
 @Id bigint  
)  
as  
begin  
 select   
  count(utn.id) over() as TotalRow,  
  utn.id as Id,  
  utn.tax_number as TaxNumber,  
  utn.address as Address,  
  cn.Country_Name as CountryName,  
  cn.Country_ID as CountryId,  
  st.State_Name as StateName,  
  st.State_ID as StateId,  
  ct.City_Name as CityName,  
  ct.City_ID as CityId,  
  utn.pincode as PinCode,  
  utn.is_default as IsDefault,  
  utn.name as name,  
     utn.mobile as mobile,    
     utn.emailid as emailid,  
     utn.latitude as latitude,    
     utn.longitude as longitude,    
     utn.MapAddress as MapAddress,    
     isnull(utn.IsActive, 0) as IsActive   
  
 from tbl_inv_UserTaxNumber(nolock) utn  
  left join m_country1(nolock)  cn on utn.country_id = cn.Country_ID  
  left join m_state1(nolock) st on utn.state_id = st.State_ID  
  left join m_city1(nolock) ct on utn.city_id = ct.City_ID  
  where utn.id =  @Id  
end


GO

/* ============================================================
   Procedure: [dbo].[usp_inv_GetCompanyTaxList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_inv_GetCompanyTaxList](    
 @UserId bigint,                  
 @FilterText nvarchar(max) = '',                
 @OperationMode nvarchar(20) = '',                
 @OffsetValue int = 0,                                                        
 @PagingSize int  = 20       
)    
as    
begin    
 declare @ParentId bigint = ( select ParentID from MySMS.dbo.User_Detail(nolock) where User_ID = @UserId )  
 select     
  count(utn.id) over() as TotalRow,    
  utn.id as Id,    
  utn.tax_number as TaxNumber,    
  utn.address as Address,    
  cn.Country_Name as CountryName,    
  cn.Country_ID as CountryId,    
  st.State_Name as StateName,    
  st.State_ID as StateId,    
  ct.City_Name as CityName,    
  ct.City_ID as CityId,    
  utn.pincode as PinCode,    
  utn.is_default as IsDefault,  
  isnull(utn.name, '') as name,  
  isnull(utn.mobile, '') as mobile,    
  isnull(utn.emailid, '') as emailid,  
  isnull(utn.latitude, '') as latitude,    
  isnull(utn.longitude, '') as longitude,    
  isnull(utn.MapAddress, '') as MapAddress,    
  isnull(utn.IsActive, 0) as IsActive  
 from tbl_inv_UserTaxNumber(nolock) utn    
  left join m_country1(nolock)  cn on utn.country_id = cn.Country_ID    
  left join m_state1(nolock) st on utn.state_id = st.State_ID    
  left join m_city1(nolock) ct on utn.city_id = ct.City_ID    
  where utn.is_deleted <> 1 and parentid = @ParentId and (   
  utn.tax_number like '%'+@FilterText+'%'  
 or cn.Country_Name like '%'+@FilterText+'%'  
 or st.State_Name like '%'+@FilterText+'%'  
 or ct.City_Name like '%'+@FilterText+'%'  
 or utn.address like '%'+@FilterText+'%'  
  )   
  order by id desc    
    
   OFFSET @OffsetValue Rows FETCH NEXT @PagingSize ROWS ONLY     

    EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId  
  ,@Activity_type = 'View_TaxDtls_Cmpny'  
  ,@ActionType = 'S'  
  ,@RowJson = ''  
  ,@Table_name = 'tbl_inv_UserTaxNumber'  

end 


GO

