/* ============================================================
   Procedure: [dbo].[usp_inv_GetLeadTaxById]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_inv_GetLeadTaxById](
	@Id bigint,
	@UserId bigint
)
as
begin
--declare @Id bigint=15,
--	@UserId bigint=34594
	declare @ParentId bigint = 0, @IsAdmin bit = 0       
select @IsAdmin = IsAdmin, @ParentId = ParentID from Mysms.dbo.User_Detail(nolock) where User_ID = @UserId        
declare @maxScore numeric(18,2)=isnull((select (max(currentscore)*100)/99 from Mysms.dbo.lead_score_history(nolock)e where parentid=@ParentId),0)        
declare @hot int,@warm int,@cold int             
                
select @hot=hot,@warm=warm,@cold=cold from Mysms.dbo.lead_cateogy_thresholds(nolock) where parentid=@ParentID                      
if @hot is null                      
begin                      
 select @hot=hot,@warm=warm,@cold=cold from Mysms.dbo.lead_cateogy_thresholds(nolock) where parentid=0        
end 

declare @queryStirng nvarchar(max) = N'select count(b.id) over() as TotalRow, * from ( select utn.id as Id, utn.tax_number as TaxNumber, utn.address as Address, cn.Country_Name as CountryName, cn.Country_ID as CountryId, st.State_Name as StateName, st.State_ID as StateId, ct.City_Name as CityName, ct.City_ID as CityId, utn.pincode as PinCode, utn.is_default as IsDefault, ul.PersonName as [PersonName], ul.ProfileImgFileName as [ProfileImgFileName], COALESCE(ul.MobileNo, ul.MobileNo1, ul.MobileNo) as [ContactPhone], COALESCE(ul.EmailId , ul.EmailID1, ul.EmailID2) as [ContactEmail], ul.LeadNo, ul.CreatedOn, concat(cb.FName, '' '', cb.LName) as [CreatedBy], case when LS.ScoreAdded > 0 then ''Green_Up'' when LS.ScoreAdded < 0 then ''Red_Down'' else '''' end as [Profit_Loss], cast(isnull((LS.currentscore/nullif( '+ cast(@maxScore as nvarchar) + ', 0.00))*99,0) as int)  as  [CurrentScore], case when cast(isnull((LS.currentscore/nullif('+ cast(@maxScore as nvarchar) + ' ,0.00))*99,0) as int)> '+ cast(@warm as nvarchar) +' then ''Hot'' when cast(isnull((LS.currentscore/nullif('+ cast(@maxScore as nvarchar) + ' ,0.00))*99,0) as int) between '+ cast(@cold as nvarchar) +'   and  '+ cast(@warm as nvarchar) + 'then ''Warm'' else ''Cold'' end as [ThresholdColor], ul.ID as [LeadId], utn.PanNumber, utn.CompanyName
	from tbl_inv_LeadTaxNumbers(nolock) utn left join m_country1(nolock)  cn on utn.country_id = cn.Country_ID left join m_state1(nolock) st on utn.state_id = st.State_ID left join m_city1(nolock) ct on utn.city_id = ct.City_ID
	inner join Mysms.dbo.UserLeads(nolock) ul on utn.leadid = ul.ID left join Mysms.dbo.lead_score_history_latest(nolock) LS on LS.leadid=ul.id left join Mysms.dbo.User_Detail(nolock) cb on utn.created_by = cb.User_ID where  utn.is_deleted <> 1 and utn.parentid = '+ cast(@ParentId as nvarchar) + ' ) b where b.id = ' + cast( @Id as nvarchar)

	print @queryStirng

	execute sp_executesql  @queryStirng     
end



