CREATE   PROCEDURE [dbo].[usp_inv_GetLeadTaxList] (
	@UserId BIGINT
	,@FilterText NVARCHAR(MAX) = ''
	,@OperationMode NVARCHAR(20) = ''
	,@OffsetValue INT = 0
	,@PagingSize INT = 20
	)
AS
BEGIN
--declare @UserId BIGINT=34594
--	,@FilterText NVARCHAR(MAX) = ''
--	,@OperationMode NVARCHAR(20) = ''
--	,@OffsetValue INT = 0
--	,@PagingSize INT = 20

	DECLARE @ParentId BIGINT = 0
		,@IsAdmin BIT = 0

	SELECT @IsAdmin = IsAdmin
		,@ParentId = ParentID
	FROM Mysms.dbo.User_Detail(NOLOCK)
	WHERE User_ID = @UserId

	DECLARE @maxScore NUMERIC(18, 2) = ISNULL((
				SELECT (MAX(currentscore) * 100) / 99
				FROM Mysms.dbo.lead_score_history(NOLOCK) e
				WHERE ParentID = @ParentId
				), 0)
	DECLARE @hot INT
		,@warm INT
		,@cold INT

	SELECT @hot = hot
		,@warm = warm
		,@cold = cold
	FROM Mysms.dbo.lead_cateogy_thresholds(NOLOCK)
	WHERE ParentID = @ParentId

	IF @hot IS NULL
	BEGIN
		SELECT @hot = hot
			,@warm = warm
			,@cold = cold
		FROM Mysms.dbo.lead_cateogy_thresholds(NOLOCK)
		WHERE ParentID = 0
	END

	DECLARE @queryStirng NVARCHAR(MAX) = N'select count(b.id) over() as TotalRow, * from ( select utn.id as Id, utn.tax_number as TaxNumber, utn.address as Address, cn.Country_Name as CountryName, cn.Country_ID as CountryId, st.State_Name as StateName, 
st.State_ID as StateId, ct.City_Name as CityName, ct.City_ID as CityId, utn.pincode as PinCode, utn.is_default as IsDefault, ul.PersonName as [PersonName], ul.ProfileImgFileName as [ProfileImgFileName], COALESCE(ul.MobileNo, ul.MobileNo1, ul.MobileNo) as [ContactPhone],
COALESCE(ul.EmailId , ul.EmailID1, ul.EmailID2) as [ContactEmail], ul.LeadNo, ul.CreatedOn, concat(cb.FName, '' '', cb.LName) as [CreatedBy], case when LS.ScoreAdded > 0 then ''Green_Up'' when LS.ScoreAdded < 0 then ''Red_Down'' else '''' end as
 [Profit_Loss], cast(isnull((LS.currentscore/nullif( ' + CAST(@maxScore AS NVARCHAR) + ', 0.00))*99,0) as int)  as  [CurrentScore],
 case when cast(isnull((LS.currentscore/nullif(' + CAST(@maxScore AS NVARCHAR) + ' ,0.00))*99,0) as int)> ' + 
		CAST(@warm AS NVARCHAR) + ' then ''Hot'' when cast(isnull((LS.currentscore/nullif(' + CAST(@maxScore AS NVARCHAR) + ' ,0.00))*99,0) as int) between ' + CAST(@cold AS NVARCHAR) + '   and  ' + CAST(@warm AS NVARCHAR) + 'then ''Warm'' else ''Cold'' end as [ThresholdColor], ul.ID as [LeadId] ,utn.PanNumber, utn.CompanyName 
 from tbl_inv_LeadTaxNumbers(nolock) utn left join m_country1(nolock)  cn on utn.country_id = cn.Country_ID left join m_state1(nolock) st on utn.state_id = st.State_ID left join m_city1(nolock) ct on utn.city_id = ct.City_ID  
 inner join Mysms.dbo.UserLeads(nolock) ul on utn.leadid = ul.ID left join Mysms.dbo.lead_score_history_latest(nolock) LS on LS.leadid=ul.id left join Mysms.dbo.User_Detail(nolock) cb on utn.created_by = cb.User_ID where  utn.is_deleted <> 1 and 
 utn.parentid = ' + CAST(@ParentId AS NVARCHAR) + ' ) b where b.TaxNumber like ''%' + @FilterText + '%'' or PersonName like ''%' + @FilterText + '%'' or CountryName like ''%' + @FilterText + '%'' or StateName like ''%' + @FilterText + '%'' or CityName like ''%' + 
		@FilterText + '%'' or 
Address like ''%' + @FilterText + '%'' order by id desc OFFSET ' + CAST(@OffsetValue AS NVARCHAR) + ' Rows FETCH NEXT ' + CAST(@PagingSize AS NVARCHAR) + ' ROWS ONLY '

	PRINT @queryStirng

	EXECUTE sp_executesql @queryStirng

	EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId
		,@Activity_type = 'View_Taxsttng_Lead'
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'tbl_inv_LeadTaxNumbers'
END



