/* ============================================================
   Procedure: [dbo].[usp_inv_GetProductForSuggetion]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_inv_GetProductForSuggetion] --'PB-102','invoice',42980  latest
(
  @FilterText NVARCHAR(255),
  @Section NVARCHAR(255) = '',
  @UserId BIGINT
)          
AS          
BEGIN        
    DECLARE @ParentId BIGINT = 0, @ItemEntity NVARCHAR(MAX) = '';  

    -- Fetch ParentID from User_Detail
    SELECT @ParentId = ParentID 
    FROM MySMS.dbo.User_Detail WITH (NOLOCK)        
    WHERE User_ID = @UserId  

    -- Fetch ItemEntity setting
    SELECT @ItemEntity = [value] 
    FROM MYSMSInvoicing.dbo.settings WITH (NOLOCK)
    WHERE parentid = @ParentId AND section = @Section AND [key] = 'ItemEntity'
  
    PRINT @ItemEntity

    DECLARE @Query NVARCHAR(MAX) =  
    CONCAT( 
        N'SELECT *, ',  
        N'dbo.udf_inv_GetTaxJsonByProductIds(HomeTaxIDs) AS [HomeTaxJson], ',  
        N'dbo.udf_inv_GetTaxJsonByProductIds(OtherTaxIDs) AS [OtherTaxJson] ',  
        --N'VariantsJson, VCombinationJson ',  -- Include VariantsJson and VCombinationJson
        N'FROM ( ',
        N'    SELECT TOP 10 ',
        N'        ProductID AS Id, Name, FullPath AS [Image], Description, ',
        N'        ''0'' AS [PurchasePrice], Price AS SalePrice, HomeTaxIDs, OtherTaxIDs, sku, ',
        N'        ', 
        IIF(ISNULL(@ItemEntity, '') <> '', 
            CONCAT(
                N'(SELECT ', @ItemEntity,  
                N' FROM tbl_ProductMaster_', CAST(@ParentId AS NVARCHAR(MAX)), N' (NOLOCK) p ',  
                N' WHERE p.ProductID = t.ProductID FOR JSON PATH, WITHOUT_ARRAY_WRAPPER )'
            ),  
            '''{}'''
        ),  
        N' AS [ItemJSON], ',  
        N'    (SELECT * FROM tbl_ProductMaster_', CAST(@ParentId AS NVARCHAR(MAX)),  
        N'    (NOLOCK) p WHERE p.ProductID = t.ProductID FOR JSON PATH, WITHOUT_ARRAY_WRAPPER) AS ProjectJSON, ',
        N'    VariantsJson, VCombinationJson ',  -- Ensure VariantsJson and VCombinationJson are selected
        N'FROM tbl_ProductMaster_', CAST(@ParentId AS NVARCHAR(MAX)), N' (NOLOCK) t ',  
        N'WHERE USERID = ', CAST(@ParentId AS NVARCHAR(MAX)),  
        N' AND IsActive = 1 AND IsSaleable = 1 ',  
        N' AND Name LIKE ''%', @FilterText, N'%'' ',  
        N'ORDER BY Name ASC ',
        N') p '
    );  

    PRINT @Query
    EXEC sp_executesql @Query
END


GO

/* ============================================================
   Procedure: [dbo].[usp_inv_GetTaxDetailByEntityId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_inv_GetTaxDetailByEntityId](  
 @EntityId bigint,  
 @Mode nvarchar(20)  
)  
as  
begin  
	
	--declare   
	--	@EntityId bigint = 18,  
	--	@Mode nvarchar(20) = 'lead'  
  
	declare @countryId int = 101, @stateId bigint = 0  
  
	drop table if exists #userTaxTable  
	drop table if exists #leadTaxTable  
  
	if(@Mode = 'user')  
	begin  
		select * into #userTaxTable from tbl_inv_UserTaxNumber(nolock) t
			where id = @EntityId  
		select @countryId = country_id, @stateId = state_id from #userTaxTable  
		select * from #userTaxTable  
	end  
  
	if(@Mode = 'lead')  
	begin  
		select t.*, l.PersonName as [name], coalesce(l.emailid, l.emailid1, l.emailid2) as emailid, coalesce(l.mobileno, l.mobileno1, l.mobileno2) as mobile
		into #leadTaxTable from tbl_inv_LeadTaxNumbers(nolock) t 
			inner join UserLeads(nolock) l on t.leadid = l.ID   where t.id = @EntityId  
		select @countryId = country_id, @stateId = state_id from #leadTaxTable  
		select * from #leadTaxTable  
	end  
  
	select Country_ID, Country_Name from m_country1(nolock)  
	select State_ID, State_Name from m_state1(nolock) where Country_ID = @countryId   
	select City_ID, City_Name from m_city1(nolock) where State_ID = @stateId   
  
end 



GO

