CREATE   PROCEDURE [dbo].[usp_inv_GetTaxesByUserId_forProduct] --34594 
( 
 @UserId bigint 
) 
as 
begin 
 select count(ID) over() as TotalRow, 
 * from [mysmsinvoicing].dbo.taxes with (nolock) 
 where parentid = ( select parentid from MySMS.dbo.User_Detail with (nolock) 
 where User_ID = @UserId ) and is_deleted = 0 and enabled = 1 and isnull(name,'') <> '' 
 order by name asc 
end 
 



