/* ============================================================
   Procedure: [dbo].[usp_inv_InsertEditLeadTax]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_inv_InsertEditLeadTax] (    
 @id BIGINT = 0    
 ,@has_tax_number BIT    
 ,@tax_number NVARCHAR(255)    
 ,@address NVARCHAR(1000)    
 ,@country_id BIGINT    
 ,@state_id BIGINT    
 ,@city_id BIGINT    
 ,@pincode NVARCHAR(255)    
 ,@is_default BIT = 0    
 ,@lead_id BIGINT    
 ,@user_id BIGINT 
 ,@PersonName nvarchar(255)
 ,@CompanyName nvarchar(500)
 ,@PanNumber nvarchar(10)
 )    
AS    
BEGIN    
 BEGIN TRY    
  BEGIN TRANSACTION    
    
  DECLARE @created_at DATETIME = getdate()    
   ,@updated_at DATETIME = getdate()    
   ,@parentid BIGINT = 0    
    
  SELECT @parentid = parentid    
  FROM User_Detail(NOLOCK)    
  WHERE User_ID = @user_id    
    
  IF (@is_default = 1)    
  BEGIN    
   UPDATE tbl_inv_LeadTaxNumbers    
   SET is_default = 0    
   WHERE parentid = @parentid    
    AND leadid = @lead_id    
  END    
    
  IF (    
    EXISTS (    
     SELECT *    
     FROM tbl_inv_LeadTaxNumbers(NOLOCK)    
     WHERE id = @id    
      AND parentid = @parentid    
      AND leadid = @lead_id    
     )    
    )    
  BEGIN    
   UPDATE tbl_inv_LeadTaxNumbers    
   SET has_tax_number = @has_tax_number    
    ,tax_number = @tax_number    
    ,address = @address    
    ,country_id = @country_id    
    ,state_id = @state_id    
    ,city_id = @city_id    
    ,pincode = @pincode    
    ,leadid = @lead_id  ,PanNumber=@PanNumber, CompanyName=@CompanyName, PersonName=@PersonName  
    ,is_default = @is_default    
   WHERE id = @id    
    
   DECLARE @rowJson NVARCHAR(MAX) = (    
     SELECT *    
     FROM tbl_inv_LeadTaxNumbers(NOLOCK)    
     WHERE id = @id    
     FOR JSON AUTO    
      ,INCLUDE_NULL_VALUES    
     )    
    
   EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @user_id    
    ,@Activity_type = 'Updt_TaxSttng_Lead'    
    ,@ActionType = 'U'    
    ,@RowJson = @rowJson    
    ,@Table_name = 'tbl_inv_LeadTaxNumbers'    
  END    
  ELSE    
  BEGIN    
   INSERT INTO tbl_inv_LeadTaxNumbers (    
    has_tax_number    
    ,tax_number    
    ,address    
    ,country_id    
    ,state_id    
    ,city_id    
    ,pincode    
    ,is_default    
    ,leadid    
    ,parentid    
    ,created_by 
	,PersonName
	,CompanyName
	,PanNumber
    )    
   VALUES (    
    @has_tax_number    
    ,@tax_number    
    ,@address    
    ,@country_id    
    ,@state_id    
    ,@city_id    
    ,@pincode    
    ,@is_default    
    ,@lead_id    
    ,@parentid    
    ,@user_id 
	,@PersonName
	,@CompanyName,
	@PanNumber
    )    
    
   SET @id = SCOPE_IDENTITY()    
   SET @rowJson = (    
     SELECT *    
     FROM tbl_inv_LeadTaxNumbers(NOLOCK)    
     WHERE id = @id    
     FOR JSON AUTO    
      ,INCLUDE_NULL_VALUES    
     )    
    
   EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId @User_id = @user_id    
    ,@Activity_type = 'Inst_TaxSttng_Lead'    
    ,@ActionType = 'I'    
    ,@RowJson = @rowJson    
    ,@Table_name = 'tbl_inv_LeadTaxNumbers'    
  END    
    
  COMMIT TRANSACTION    
    
  SELECT 'Success' AS [title]    
   ,'Lead tax detail saved successfully.' AS [message]    
   ,'success' AS [type]    
 END TRY    
    
 BEGIN CATCH    
  EXEC usp_InsertErrorInfo    
 END CATCH    
END 


GO

/* ============================================================
   Procedure: [dbo].[usp_inv_InsertEditLeadTax_MOB]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_inv_InsertEditLeadTax_MOB(    
