 @has_tax_number bit,  
 @tax_number nvarchar(255),    
 @address nvarchar(1000),    
 @country_id bigint,    
 @state_id bigint,    
 @city_id bigint,    
 @pincode nvarchar(255),    
 @is_default bit  = 0,    
 @lead_id bigint,  
 @user_id bigint    
)    
as    
begin    
    
 begin try    
    
  begin transaction    
  declare  @created_at datetime  = getdate(), @updated_at datetime  = getdate(), @parentid bigint   = 0    
  select @parentid  = parentid  from User_Detail(nolock) where User_ID = @user_id    
     
  if(@is_default = 1)    
  begin    
   update tbl_inv_LeadTaxNumbers set is_default = 0 where parentid = @parentid and leadid = @lead_id  
  end    
    
  if(exists(select * from tbl_inv_LeadTaxNumbers(nolock) where id = @id and parentid = @parentid and leadid = @lead_id))    
  begin    
 update tbl_inv_LeadTaxNumbers set  
  has_tax_number = @has_tax_number,  
  tax_number = @tax_number,  
  address = @address,  
  country_id = @country_id,  
  state_id = @state_id,  
  city_id = @city_id,  
  pincode = @pincode,  
  leadid = @lead_id,  
  is_default = @is_default  
 where id = @id    
  end    
  else  
  begin  
  insert into tbl_inv_LeadTaxNumbers( has_tax_number, tax_number, address, country_id, state_id, city_id, pincode, is_default, leadid, parentid, created_by  )    
  values( @has_tax_number, @tax_number, @address, @country_id, @state_id, @city_id, @pincode, @is_default, @lead_id, @parentid, @user_id )   
  end  
    
    
  commit transaction    
    
  select 'Success' as [title], 'Lead tax detail saved successfully.' as [message], 'success' as [type]    
    
 end try    
 begin catch    
  exec usp_InsertErrorInfo    
 end catch    
    
end    



GO

/* ============================================================
   Procedure: [dbo].[usp_inv_InsertEditTax]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_inv_InsertEditTax](    
 @id bigint = 0,    
 @tax_number nvarchar(255),    
 @address nvarchar(1000),    
 @country_id bigint,    
 @state_id bigint,    
 @city_id bigint,    
 @pincode nvarchar(255),    
 @is_default bit  = 0,    
 @user_id bigint,  
 @name nvarchar(400) = '',  
 @mobile varchar(50) = '',    
 @emailid varchar(50) = '',  
 @latitude float = '',    
 @longitude float = '',    
 @MapAddress nvarchar(1000)= '',    
 @IsActive bit = 0  
)  
as    
begin     
    
 begin try    
    
  begin transaction    
  declare  @created_at datetime  = getdate(), @updated_at datetime  = getdate(), @parentid bigint   = 0    
  select @parentid  = parentid  from User_Detail(nolock) where User_ID = @user_id    
  
  declare @isNameExists bit = 0  
  
  if(exists(select 1 from tbl_inv_UserTaxNumber(nolock) where parentid = @parentid  
 and 1 = ( case   
  when @id > 0 and id = @id and [name] = @name then 0  
  when @id > 0 and id <> @id and [name] = @name then 1  
  when @id = 0  and [name] = @name then 1  
  else 0 end   
 )  
  ))  
  begin  
 set @isNameExists = 1  
  end  
  
  declare   
 @title nvarchar(255),  
 @message nvarchar(255),  
 @type nvarchar(20)  
  
  if(@isNameExists = 0)  
  begin  
   if(@is_default = 1)   
   begin    
  update tbl_inv_UserTaxNumber set is_default = 0 where parentid = @parentid    
   end    
    
   if(exists(select * from  tbl_inv_UserTaxNumber(nolock) where id = @id and parentid = @parentid))    
   begin    
  update tbl_inv_UserTaxNumber set    
   tax_number = @tax_number,  
   address = @address,  
   country_id = @country_id,  
   state_id = @state_id,  
   city_id = @city_id,  
   pincode = @pincode,  
   is_default = @is_default,  
   name = @name,  
   mobile = @mobile,    
   emailid = @emailid,  
   latitude = @latitude,    
   longitude = @longitude,    
   MapAddress = @MapAddress,    
   IsActive = @IsActive  
  where id = @id    
   end    
   else  
   begin  
   insert into tbl_inv_UserTaxNumber( tax_number, address, country_id, state_id, city_id, pincode, is_default, parentid, created_by,   
  name, mobile, emailid, latitude, longitude, MapAddress, IsActive)    
   values( @tax_number, @address, @country_id, @state_id, @city_id, @pincode, @is_default, @parentid, @user_id, @name, @mobile, @emailid,@latitude, @longitude, @MapAddress,  @IsActive )   
   end  
  
   select @title = 'Success', @message = 'Company tax detail saved successfully.', @type =  'success'  
  end    
  else   
  begin  
 select @title ='Name Exists', @message = 'Branch name already exists.', @type = 'warning'  
  end  
  
  
  commit transaction    
    
  select @title as [title], @message as [message], @type as [type]    
    
 end try    
 begin catch    
  exec usp_InsertErrorInfo    
 end catch    
end    



GO

