CREATE   PROCEDURE [dbo].[usp_inv_LeadCustomerSuggection_1] --'test',47566
(
    @FilterText NVARCHAR(250) = '',          
    @UserId BIGINT        
)        
AS        
BEGIN       
    DECLARE @ParentId BIGINT = (SELECT ParentID FROM dbo.User_Detail WITH (NOLOCK) WHERE User_ID = @UserId);
  
    SELECT TOP 10     
        ul.Id AS LeadId,    
        ul.PersonName,    
        COALESCE(ul.MobileNo, ul.MobileNo1, ul.MobileNo2) AS [MobileNo],        
        COALESCE(ul.EmailID, ul.EmailID1, ul.EmailID2) AS [EmailId],        
        COALESCE(ul.OfficeAddress, ul.ResidentialAddress) AS [Address],  
        ul.CompanyName,  
        ul.LeadNo,  
        ul.ProfileImgFileName,  
        ul.ParentId,  
        
        -- Get Country, State, and City Names
        COALESCE(mcy.Country_Name, ul.Country) AS [Country],    
        COALESCE(ms.State_Name, ul.State) AS [State],    
        COALESCE(mc.City_Name, ul.City) AS [City],    

        mcy.Country_ID AS CountryId,  
        ms.State_ID AS StateId,  
        mc.City_ID AS CityId,
		isnull(cast(ul.PinCode as nvarchar),'') as Pincode, 
        ltn.tax_number AS [TaxNumber],  
        ltn.PanNumber  
    FROM UserLeads ul WITH (NOLOCK)   
    LEFT JOIN tbl_inv_LeadTaxNumbers ltn WITH (NOLOCK) 
        ON ul.ID = ltn.leadid AND ltn.is_default = 1  

    LEFT JOIN m_country1 mcy WITH (NOLOCK)  
        ON mcy.Country_Name = ul.Country  
    LEFT JOIN m_state1 ms WITH (NOLOCK)  
        ON ms.State_Name = ul.State  
    LEFT JOIN m_city1 mc WITH (NOLOCK)  
        ON mc.City_Name = ul.City  

    WHERE ul.ParentID = @ParentId    
      AND (   
          ul.PersonName LIKE '%' + @FilterText + '%'          
          OR ISNULL(ul.MobileNo, '') LIKE '%' + @FilterText + '%'          
          OR ISNULL(ul.EmailID, '') LIKE '%' + @FilterText + '%'          
          OR ISNULL(ul.CompanyName, '') LIKE '%' + @FilterText + '%'        
      );    
END;



