/* ============================================================
   Procedure: [dbo].[usp_inv_LeadSuggectionById]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_inv_LeadSuggectionById](  
 @LeadId bigint          
)          
as          
begin         
    
 select top 10       
  ul.Id as LeadId,      
  ul.PersonName,      
  COALESCE(ul.MobileNo, ul.MobileNo1, ul.MobileNo2 ) as [MobileNo],          
  COALESCE(ul.EmailID, ul.EmailID1, ul.EmailID2 ) as [EmailId],          
  COALESCE(ul.ResidentialAddress, ul.OfficeAddress) as [Address],    
  ul.CompanyName,    
  ul.LeadNo,    
  ul.ProfileImgFileName,    
  ul.ParentId,    
  COALESCE(mcy.Country_Name, ul.Country) as  [Country],      
  COALESCE(ms.State_Name, ul.State) as [State],      
  COALESCE(mc.City_Name, ul.City) as  [City],      
  COALESCE(mc.City_Name, cast(ul.PinCode as nvarchar)) as Pincode,    
  ltn.tax_number as  [TaxNumber],    
  COALESCE(ltn.country_id, 0 ) as CountryId,    
  COALESCE(ltn.state_id, 0 ) as StateId,    
  COALESCE(ltn.city_id, 0) as CityId,
  COALESCE(ltn.PanNumber, '') as PanNumber
  from UserLeads ul with (nolock)     
  left join tbl_inv_LeadTaxNumbers ltn with (nolock) on ul.ID = ltn.leadid and ltn.is_default = 1    
  left join m_country1 mcy with (nolock)  on ltn.country_id = cast(mcy.Country_ID as bigint)    
  left join m_state1 ms with (nolock)  on ltn.state_id = cast(ms.State_ID as bigint)    
  left join m_city1 mc with (nolock)  on ltn.city_id = cast(mc.City_ID as bigint)    
  where ul.ID = @LeadId     
       
end  


GO

