   Procedure: [dbo].[usp_inv_SavePaymentRequest]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_inv_SavePaymentRequest(         
@id bigint,        
 @parentId bigint ,          
 @amount nvarchar(1000) ,          
 @enquiry nvarchar(1000) ,          
 @entityName nvarchar(1000) ,          
 @entityId nvarchar(1000) ,          
 @status nvarchar(1000) ,          
 @modifiedOn nvarchar(1000),        
 @Remark nvarchar(400),       
 @Description nvarchar(max),      
 @Provider nvarchar(max),      
 @ProvidedBy nvarchar(max),      
 @url nvarchar(max) ,
  @invoiceid bigint          
 )              
as              
begin   
  
--declare @id bigint=0,        
-- @parentId bigint =34594 ,          
-- @amount nvarchar(1000) =10,          
-- @enquiry nvarchar(1000)='lead' ,          
-- @entityName nvarchar(1000)='Keshav' ,          
-- @entityId nvarchar(1000) ='1691772',          
-- @status nvarchar(1000)='one time' ,          
-- @modifiedOn nvarchar(1000)='',        
-- @Remark nvarchar(400)='ghfhgh',       
-- @Description nvarchar(max)='xhb chgh',      
-- @Provider nvarchar(max)='RazorPay-1709391322799',      
-- @ProvidedBy nvarchar(max)='RazorPay-1709391322799',      
-- @url nvarchar(max)='http://localhost:58275'        
      
  
declare @rid bigint=0,@eventName nvarchar(500)='',@EventDescription nvarchar(max)='',@reftables nvarchar(500)='',@refid nvarchar(500)='',@Parent bigint=0,@user nvarchar(500)='',@companyName nvarchar(1000)='', @finalUrl nvarchar(max)='',@encodedId nvarchar
(255)=''  
  
select @Parent=ParentId,@user=CONCAT(FName,' ',LName),@companyName=CompnayName from Mysms.dbo.User_Detail(nolock) where User_ID=@parentid
declare @pid bigint

select @pid=parentid,@entityName=contact_name from invoices(nolock) where id=@invoiceid

select  @provider=GatewayName,@ProvidedBy=Provide from PaymentGatewaySetting(nolock) ps
 left join tbl_inv_Paymentdata pd on pd.rId=ps.id and pd.parentId=ps.parentid
where ps.parentid=@pid and ps.IsActive=1 and IsDefault=1 and pd.status='Success'
if(exists(select id from tbl_inv_PaymentRequest(nolock) where invoiceId = @invoiceid and parentid = @pid ))      
  begin      
 update tbl_inv_PaymentRequest set Provider=@Provider,providedBy=@ProvidedBy,entityName=@entityName
 where invoiceId = @invoiceid      
  end 
  else
  begin
insert into tbl_inv_PaymentRequest(parentId,amount,enquiry,entityId,entityName,CreatedBy,status,isactive,modifiedon,Remarks,Description,Provider,providedBy,invoiceId) values(@parentId,@amount,@enquiry,@entityId,@entityName,@parentId,@status,1,@modifiedOn,@Remark,@Description,      
@Provider,@ProvidedBy,@invoiceid)

    set @rid = scope_identity()  
 set @encodedId= substring(lower(convert(nvarchar(34), HASHBYTES('MD5',CAST(@rid as nvarchar)),1)),3,32)  
 set @finalUrl=Concat(@url,'/PayNow.aspx?rid=',@encodedId,'&cname=',dbo.EncodeURL(@companyName),'&amount=',@amount)  
 --select @finalUrl  
 update tbl_inv_PaymentRequest set [url]=@finalUrl ,encodedId =@encodedId   
 where id = @rid    
  set @EventDescription=concat('Payment link ',@finalUrl,' Amounting ',@amount,' INR for lead ',@entityName,', lead no ',cast(@entityId as bigint),' was created by ',@entityName,' for ',@Remark)  
  set @entityId=cast(@entityId as bigint)  
  set @rid=cast(@rid as nvarchar)  
 exec Mysms.dbo.UspSaveEntityActivity_withid @enquiry,@entityId,@parentId,@Parent,@EventDescription, 'Payment', 'tbl_inv_PaymentRequest', @rid  
  end      
end 



GO

