 exec MySMS.dbo.usp_SendMailFromLeads @LeadId, @Account, @Email_Subject, @Message, @SenderName, 
 @ReplyTo, @EmailId, @EmailId1, @EmailId2, @UserId 
 
 
 commit transaction 
 end try 
 begin catch 
 rollback transaction 
 end catch 
end 
 



