 @dltid = null, 
 @batchid = @retBatchid output 
 
 if(@retBatchid > 0) 
 begin 
 declare @leadActivityHistory as LeadActivitywithid_Tbltype 
 
 insert into [mysmsinvoicing].dbo.quote_histories( parentid, quote_no, status, notify, description, created_at, updated_at ) 
 values ( @ParentId, @QuotationId, 'active', 0, 'Quotation share via sms', getdate(), getdate() ) 
 
 declare @quoteHistoryId bigint = SCOPE_IDENTITY() 
 
 insert into @leadActivityHistory ( LeadID, UserID, ParentID, EventDescription, EventName, RefTable, refid ) 
 select @LeadId, @UserId, @parentid, concat(@Username, ' sent an sms with content "', @quotationMessage, '" on mobile ', @MobileNos), 'SMS sent to Lead', 'Batchinfo', @retBatchid 
 
 insert into @leadActivityHistory ( LeadID, UserID, ParentID, EventDescription, EventName, RefTable, refid ) 
 select @LeadId, @UserId, @parentid, concat('Quotation with no. ', @QuotationNumber, ' for amount ', @QuotationAmount, ' was sent to ', @PersonName, ' by ', @Username), '[mysmsinvoicing].dbo.quote_histories', 'Batchinfo', @quoteHistoryId
 
 
 exec UspSaveentityActivity_withMultipleValue_withid @leadActivityHistory 
 
 
 end 
 commit transaction 
 end try 
 begin catch 
 rollback transaction 
 end catch 
end 



