 @u_id = @UserId, 
 @message = @quotationMessage, 
 @mobile = @MobileNos, 
 @sender = @retSender, 
 @isunicode =null, 
 @priority =null, 
 @shorturl ='pel.im', 
 @longurl =@LongUrl, 
 @page_nm =null, 
 @IAction =null, 
 @Cmobile =null, 
 @email =null, 
 @subject =null, 
 @body =null, 
 @wmobile =null, 
 @wtext =null, 
 @isvoice =null, 
 @appid = @retAppid, 
 @duration =null, 
 @dnid = null, 
 @frequency = null, 
 @latency = null, 
 @route = null, 
 @event = null, 
 @dltid = null, 
 @batchid = @retBatchid output 
 
 if(@retBatchid > 0) 
 begin 
 declare @leadActivityHistory as LeadActivitywithid_Tbltype 
 
 insert into [mysmsinvoicing].dbo.transaction_histories( parentid, receipt_no, status, notify, description, created_at, updated_at, transaction_id ) 
 values ( @ParentId, @RevenueNumber, 'active', 0, 'Revenue share via sms', getdate(), getdate(), @RevenueId ) 
 
 declare @quoteHistoryId bigint = SCOPE_IDENTITY() 
 
 insert into @leadActivityHistory ( LeadID, UserID, ParentID, EventDescription, EventName, RefTable, refid ) 
 select @LeadId, @UserId, @parentid, concat(@Username, ' sent an sms with content "', @quotationMessage, '" on mobile ', @MobileNos), 'SMS sent to Lead', 'Batchinfo', @retBatchid 
 
 insert into @leadActivityHistory ( LeadID, UserID, ParentID, EventDescription, EventName, RefTable, refid ) 
 select @LeadId, @UserId, @parentid, concat('Revenue sent to customer for amount ', @QuotationAmount, ' was sent to ', @PersonName, ' by ', @Username), '[mysmsinvoicing].dbo.quote_histories', 'Batchinfo', @quoteHistoryId 
 
 exec UspSaveentityActivity_withMultipleValue_withid @leadActivityHistory 
 
 
 end 
 commit transaction 
 end try 
 begin catch 
 rollback transaction 
 end catch 
end 



GO

/* ============================================================
   Procedure: [dbo].[usp_inv_UpdateCompanyTaxStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_inv_UpdateCompanyTaxStatus (
	@Ids NVARCHAR(max)
	,@Status BIT = 0
	,@UserId BIGINT
	,@Mode NVARCHAR(50) = ''
	)
AS
BEGIN
	BEGIN TRY
		BEGIN TRANSACTION

		DECLARE @ParentId BIGINT = 0
			,@Username NVARCHAR(255)
			,@activity VARCHAR(MAX) = ''

		SELECT @ParentId = parentid
			,@Username = User_Login
		FROM User_Detail(NOLOCK)
		WHERE User_Id = @UserId

		SELECT [value] AS ctId
		INTO #tempCtIds
		FROM dbo.fn_split(@Ids, ',')

		IF (@Mode = 'default')
		BEGIN
			UPDATE tbl_inv_UserTaxNumber
			SET is_default = 0
			WHERE parentid = @ParentId

			UPDATE utn
			SET utn.is_default = 1
				,updated_at = getdate()
			FROM #tempCtIds tc
			INNER JOIN tbl_inv_UserTaxNumber utn ON tc.ctId = utn.id
			SET @activity = 'Updt_CpnyTaxStatus_Deflt'
		END

		IF (@Mode = 'delete')
		BEGIN
			UPDATE utn
			SET utn.is_deleted = 1
				,utn.deleted_at = GETDATE()
			FROM #tempCtIds tc
			INNER JOIN tbl_inv_UserTaxNumber utn ON tc.ctId = utn.id
			SET @activity = 'Delt_CpnyTax_sttng'
		END

		COMMIT TRANSACTION

		SELECT 'success'
	END TRY

	BEGIN CATCH
		EXEC usp_InsertErrorInfo

		ROLLBACK TRANSACTION

		SELECT 'fail'
	END CATCH

	DECLARE @rowJson NVARCHAR(MAX) = (
			SELECT *
			FROM tbl_inv_UserTaxNumber
			WHERE ID = @Ids
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

	

	IF @RowJson IS NOT NULL
	BEGIN
		EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId
			,@Activity_type = @activity
			,@ActionType = 'U'
			,@RowJson = @rowJson
			,@Table_name = 'tbl_inv_UserTaxNumber'
	END
END



GO

/* ============================================================
   Procedure: [dbo].[usp_inv_UpdateLeadTaxStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_inv_UpdateLeadTaxStatus (    
 @Ids NVARCHAR(max)    
 ,@Status BIT = 0    
 ,@UserId BIGINT    
 ,@Mode NVARCHAR(50) = ''    
 )    
AS    
BEGIN    
 BEGIN TRY    
  BEGIN TRANSACTION    
    
  DECLARE @ParentId BIGINT = 0    
   ,@Username NVARCHAR(255)    
    
  SELECT @ParentId = parentid    
   ,@Username = User_Login    
  FROM User_Detail(NOLOCK)    
  WHERE User_Id = @UserId    
    
  SELECT [value] AS ctId    
  INTO #tempCtIds    
  FROM dbo.fn_split(@Ids, ',')    
    
  IF (@Mode = 'default')    
  BEGIN    
   UPDATE tbl_inv_LeadTaxNumbers    
   SET is_default = 0    
   WHERE parentid = @ParentId    
    AND leadid IN (    
     SELECT utn.leadid    
     FROM #tempCtIds tc    
     INNER JOIN tbl_inv_LeadTaxNumbers(NOLOCK) utn ON tc.ctId = utn.id    
     )    
    
   UPDATE utn    
   SET utn.is_default = @Status    
    ,updated_at = getdate()    
   FROM #tempCtIds tc    
   INNER JOIN tbl_inv_LeadTaxNumbers utn ON tc.ctId = utn.id    
  END    
    
  IF (@Mode = 'delete')    
  BEGIN    
   UPDATE utn    
   SET utn.is_deleted = @Status    
    ,utn.deleted_at = GETDATE()    
   FROM #tempCtIds tc    
   INNER JOIN tbl_inv_LeadTaxNumbers utn ON tc.ctId = utn.id    
  END    
    
  COMMIT TRANSACTION    
    
  SELECT 'success'    
 END TRY    
    
 BEGIN CATCH    
  EXEC usp_InsertErrorInfo    
    
  ROLLBACK TRANSACTION    
    
  SELECT 'fail'    
 END CATCH    
    
 DECLARE @rowJson NVARCHAR(MAX) = (    
   SELECT *    
   FROM tbl_inv_LeadTaxNumbers(NOLOCK)    
   WHERE parentid = @ParentId    
   AND leadid IN (    
     SELECT utn.leadid    
     FROM #tempCtIds tc    
     INNER JOIN tbl_inv_LeadTaxNumbers(NOLOCK) utn ON tc.ctId = utn.id    
     )    
   FOR JSON AUTO    
    ,INCLUDE_NULL_VALUES    
   )    
    
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId    
  ,@Activity_type = 'Updt_TaxSts_Lead'    
  ,@ActionType = 'U'    
  ,@RowJson = @rowJson    
  ,@Table_name = 'tbl_inv_LeadTaxNumbers'    
END 


GO

/* ============================================================
   Procedure: [dbo].[usp_inv_UpdateLeadTaxStatus_MOB]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_inv_UpdateLeadTaxStatus_MOB(
 @Ids nvarchar(max),  
 @Status bit = 0,  
 @UserId bigint,    
 @Mode nvarchar(50) = ''  
)    
as    
begin    
 begin try     
  begin transaction    
  declare @ParentId bigint = 0, @Username nvarchar(255)    
  select @ParentId = parentid, @Username = User_Login from User_Detail(nolock) where User_Id = @UserId             
    
  select [value] as ctId into #tempCtIds from dbo.fn_split(@Ids,',')      
  
     
  if(@Mode = 'default')    
  begin    
   update tbl_inv_LeadTaxNumbers set is_default = 0  
 where parentid = @ParentId and leadid in (   
   select utn.leadid from #tempCtIds tc   
   inner join tbl_inv_LeadTaxNumbers(nolock) utn on tc.ctId= utn.id  
  )  
  
  
   update utn set utn.is_default = @Status, updated_at = getdate()  from #tempCtIds tc     
    inner join tbl_inv_LeadTaxNumbers utn on tc.ctId= utn.id    
  end    
    
  if(@Mode = 'delete')    
  begin    
   update utn set utn.is_deleted = @Status, utn.deleted_at = GETDATE() from #tempCtIds tc     
    inner join tbl_inv_LeadTaxNumbers utn on tc.ctId= utn.id    
  end    
  commit transaction    
  select 'success'    
 end try    
 begin catch    
  exec usp_InsertErrorInfo    
  rollback transaction    
  select 'fail'    
 end catch    
end    



GO

/* ============================================================
   Procedure: [dbo].[USP_INVALIDNUMBER_DELETE_IN_PROCESSTABLE]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/********
 This SP is used for Delete Invalidnumber record( messagestatus is 6) in ProcessTable 
*********/
CREATE   PROC USP_INVALIDNUMBER_DELETE_IN_PROCESSTABLE
 @BatchID      BIGINT,       
           @ProcessTable INT       
AS       
  BEGIN  
 SET NOCOUNT ON    
      IF (@ProcessTable = 1) 
        BEGIN
         DELETE  FROM processtablefirst WHERE  batchid = @BatchID and isnull(messagestatus,'0')='6'  
       END 
      IF (@ProcessTable = 2) 
        BEGIN
         DELETE  FROM processtabletwo WHERE  batchid = @BatchID and isnull(messagestatus,'0')='6'  
       END 
      IF (@ProcessTable = 3) 
        BEGIN
         DELETE  FROM processtablethree WHERE  batchid = @BatchID and isnull(messagestatus,'0')='6'  
       END 
      IF (@ProcessTable = 4) 
       BEGIN
        DELETE  FROM processtablefour WHERE  batchid = @BatchID and isnull(messagestatus,'0')='6'  
       END 
    END 






GO

