/* ============================================================
   Procedure: [dbo].[usp_IsAllowedClickToCal]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_IsAllowedClickToCal](  
	@User_Id BIGINT  
)  
AS  
BEGIN  
  
	--declare @User_Id bigint= 40856
	--declare @User_Id bigint= 34594
   
    DECLARE @Cloudrole INT= 0, @Parent_Id BIGINT= 0, @PhoneNo VARCHAR(50)= '';  
    SELECT @Cloudrole = Cloudrole, @Parent_Id = ParentID FROM User_Detail(NOLOCK) WHERE User_ID = @User_Id;  
    SELECT @PhoneNo = phoneno FROM Cloud_User_Phone(NOLOCK) WHERE active = 1  
            AND Isdefault != 0 AND parentid = @Parent_Id;  
  
    -------- Voip  Setup   
  
    DECLARE @IsVoipAllowed BIT= 0, @voipUserData NVARCHAR(MAX)= '', @defaultProvider nvarchar(255);  
  
	select @defaultProvider = provider_name from tbl_voip_ServiceProvider(nolock) sp 
		inner join tbl_voip_DefaultCallingService(nolock) dcs on  sp.id = dcs.ServiceProviderId  
			where dcs.ParentId = @Parent_Id and dcs.IsActive = 1   
  
  
	declare @DefaultIncoming nvarchar(255), @DefaultOutgoing nvarchar(255), @prefixValue nvarchar(255), @suffixValue nvarchar(255)  
  
	select top 1 @prefixValue = PrefixValue, @suffixValue = SuffixValue 
		from tbl_c2c_PasswordSetting(nolock) 
	where IsAcive = 1 and UserLastDigit = CAST(RIGHT(@User_Id, 1) as int)  
			order by Id desc  
  
	select   
		@DefaultIncoming = incoming_provider,  
		@DefaultOutgoing= outgoing_provider  
	from tbl_ClickToCallSetting(nolock)  
		where parentId = @Parent_Id  
  
	if(isnull(@DefaultOutgoing, '') = '')  
	begin  
		set @DefaultOutgoing = (select provider_name from tbl_voip_ServiceProvider(nolock) where id = (   
			select ServiceProviderId from tbl_voip_DefaultCallingService(NOLOCK) WHERE ParentId = @Parent_Id AND IsActive = 1  
		))
	end  
  
	if(isnull(@DefaultOutgoing, '') = '')
	begin
		set @DefaultOutgoing = 'Mobile Like Number'  
	end

	if(isnull(@DefaultIncoming, '') = '')  
	begin 
		--set @DefaultIncoming = 'kit19'
		set @DefaultIncoming = 'Mobile Like Number'  
	end  

  
    IF(EXISTS ( SELECT 1 FROM tbl_voip_ParentServiceMapping(NOLOCK) WHERE parent_id = @Parent_Id AND is_active = 1 ))  
    BEGIN  
        IF(EXISTS( SELECT 1 FROM tbl_voip_userAgentSetting(NOLOCK) WHERE user_id = @User_Id AND is_active = 1 ))  
        BEGIN  
            SET @IsVoipAllowed = 1;  
            SET @voipUserData = (  
                SELECT id AS [Id],   
                        user_id AS [UserId],   
                        ext_number AS [ExtNumber],   
                        mobile_no AS [MobileNo],   
                        default_caller_no AS [CallerId],  
      default_machine as [DefaultMachine],  
                        is_active AS [IsActive]  
                FROM tbl_voip_userAgentSetting(NOLOCK)  
                WHERE user_id = @User_Id  
                        AND is_active = 1 FOR JSON PATH  
            );  
        END;  
    END;  
  
	 if(isnull(@defaultProvider, '') = '')  
	 set @defaultProvider = @DefaultOutgoing  
  
	if(isnull(@voipUserData, '') = '') 
	begin
		set @voipUserData = ( select 0 as [Id], @User_Id as [UserId], @User_Id as [ExtNumber], Mobile as [MobileNo], 'Any' as [CallerId], 'm' as [DefaultMachine], 1 as [IsActive] from User_Detail(nolock) where User_Id = @User_Id for json auto )
	end

	select 
		IsAllowed = isnull(case 
			when not exists ( select 1 from telephonykyc(nolock) where parentid=@Parent_Id and kycstatus=1) then 0
			when @DefaultOutgoing = 'kit19' or @IsVoipAllowed = 0 then (
			case when @Cloudrole = 0 THEN 0 
				else (
					case when RTRIM(LTRIM(ISNULL(@PhoneNo, ''))) != '' and  @DefaultOutgoing = 'kit19' then 1 else 0 end)  
				end
			) else 0 end, 0),
		PhoneNo = RTRIM(LTRIM(ISNULL(@PhoneNo, ''))),   
		IsVoipAllowed = cast((case when @DefaultOutgoing <> 'kit19' then 1 else 0 end) as bit), --; @IsVoipAllowed,   
		VoipSetupData = @voipUserData,  
		@defaultProvider as ServiceProvider,  
		@DefaultIncoming as DefaultIncoming,  
		@DefaultOutgoing as DefaultOutgoing,  
		@prefixValue as PrefixValue,  
		@suffixValue as SuffixValue  

end



GO

