/* ============================================================
   Procedure: [dbo].[usp_ISMS_GetCountryDocumentRequirements]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ISMS_GetCountryDocumentRequirements]
    @CountryCode NVARCHAR(10) = NULL,
    @CountryName NVARCHAR(100) = NULL,
    @IsActiveOnly BIT = 1
AS
BEGIN
    SET NOCOUNT ON;
    
    BEGIN TRY
        SELECT 
            Id,
            CountryCode,
            CountryName,
            DocumentType,
            DocumentDescription,
            IsRequired,
            DisplayOrder,
            IsActive,
            CreatedOn,
            CreatedBy,
            ModifiedOn,
            ModifiedBy
        FROM CountryDocumentRequirements nolock
        WHERE 
            (@CountryCode IS NULL OR CountryCode = @CountryCode)
            AND (@CountryName IS NULL OR CountryName = @CountryName)
            AND (@IsActiveOnly = 0 OR IsActive = 1)
        ORDER BY 
            CountryName, 
            DisplayOrder, 
            DocumentType;
            
    END TRY
    BEGIN CATCH
        -- Log error details
        EXEC dbo.usp_insertErrorInfo;

    END CATCH
END



GO

/* ============================================================
   Procedure: [dbo].[usp_ISMS_ManageCountryDocumentRequirements]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ISMS_ManageCountryDocumentRequirements]
    @Action NVARCHAR(10), -- INSERT, UPDATE, DELETE
    @Id INT = NULL,
    @CountryCode NVARCHAR(10) = NULL,
    @CountryName NVARCHAR(100) = NULL,
    @DocumentType NVARCHAR(200) = NULL,
    @DocumentDescription NVARCHAR(500) = NULL,
    @IsRequired BIT = 1,
    @DisplayOrder INT = 1,
    @IsActive BIT = 1,
    @ModifiedBy NVARCHAR(50) = NULL
AS
BEGIN
    SET NOCOUNT ON;
    
    BEGIN TRY
        IF @Action = 'INSERT'
        BEGIN
            INSERT INTO CountryDocumentRequirements 
            (CountryCode, CountryName, DocumentType, DocumentDescription, IsRequired, DisplayOrder, IsActive, CreatedBy)
            VALUES 
            (@CountryCode, @CountryName, @DocumentType, @DocumentDescription, @IsRequired, @DisplayOrder, @IsActive, @ModifiedBy);
            
            SELECT SCOPE_IDENTITY() as NewId, 'Document requirement added successfully.' as Message;
        END
        ELSE IF @Action = 'UPDATE'
        BEGIN
            UPDATE CountryDocumentRequirements
            SET 
                CountryCode = ISNULL(@CountryCode, CountryCode),
                CountryName = ISNULL(@CountryName, CountryName),
                DocumentType = ISNULL(@DocumentType, DocumentType),
                DocumentDescription = ISNULL(@DocumentDescription, DocumentDescription),
                IsRequired = ISNULL(@IsRequired, IsRequired),
                DisplayOrder = ISNULL(@DisplayOrder, DisplayOrder),
                IsActive = ISNULL(@IsActive, IsActive),
                ModifiedOn = GETDATE(),
                ModifiedBy = @ModifiedBy
            WHERE Id = @Id;
            
            SELECT @Id as Id, 'Document requirement updated successfully.' as Message;
        END
        ELSE IF @Action = 'DELETE'
        BEGIN
            -- Soft delete by setting IsActive = 0
            UPDATE CountryDocumentRequirements
            SET 
                IsActive = 0,
                ModifiedOn = GETDATE(),
                ModifiedBy = @ModifiedBy
            WHERE Id = @Id;
            
            SELECT @Id as Id, 'Document requirement deleted successfully.' as Message;
        END
        ELSE
        BEGIN
            SELECT 0 as Id, 'Invalid action specified.' as Message;
        END
            
    END TRY
    BEGIN CATCH
      EXEC dbo.usp_insertErrorInfo;

    END CATCH
END



GO

/* ============================================================
   Procedure: [dbo].[usp_ISMS_SubmitCountryDocumentReferences]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ISMS_SubmitCountryDocumentReferences]
    @Country NVARCHAR(100),
    @CountryCode NVARCHAR(10),
    @UserId BIGINT,
    @DocumentType NVARCHAR(200),
    @FileName NVARCHAR(255),
    @FilePath NVARCHAR(500),
    @FileSize BIGINT = 0,
    @UploadDate DATETIME = NULL
AS
BEGIN
    SET NOCOUNT ON;
    
    BEGIN TRY
        -- Set default upload date if not provided
        IF @UploadDate IS NULL
            SET @UploadDate = GETDATE();
        
        -- Check if a record already exists for this user, country, and document type
        IF EXISTS (
            SELECT 1 FROM CountryDocuments WITH(NOLOCK) 
            WHERE UserId = @UserId 
            AND Country = @Country 
            AND DocumentType = @DocumentType
        )
        BEGIN
            -- Update existing record
            UPDATE CountryDocuments
            SET 
                FileName = @FileName,
                FilePath = @FilePath,
                FileSize = @FileSize,
                ModifiedOn = GETDATE(),
                ReviewStatus = 'Pending', -- Reset review status when document is updated
                ReviewedBy = NULL,
                ReviewedOn = NULL,
                Remarks = NULL
            WHERE 
                UserId = @UserId 
                AND Country = @Country 
                AND DocumentType = @DocumentType;
                
            SELECT @@ROWCOUNT as RowsAffected, 'Document reference updated successfully.' as Message;
        END
        ELSE
        BEGIN
            -- Insert new record
            INSERT INTO CountryDocuments (
                Country,
                CountryCode,
                UserId,
                DocumentType,
                FileName,
                FilePath,
                FileSize,
                CreatedOn,
                ReviewStatus
            )
            VALUES (
                @Country,
                @CountryCode,
                @UserId,
                @DocumentType,
                @FileName,
                @FilePath,
                @FileSize,
                @UploadDate,
                'Pending'
            );
            
            SELECT @@ROWCOUNT as RowsAffected, 'Document reference saved successfully.' as Message;
        END
        
    END TRY
    BEGIN CATCH
        EXEC dbo.usp_insertErrorInfo;

    END CATCH
END



GO

/* ============================================================
   Procedure: [dbo].[usp_ISMS_SubmitCountryDocuments]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ISMS_SubmitCountryDocuments]
    @Country NVARCHAR(100),
    @CountryCode NVARCHAR(100),
    @UserId INT,
    @DocumentType NVARCHAR(200),
    @FileName NVARCHAR(255),
    @FilePath NVARCHAR(500)
AS
BEGIN
    BEGIN TRY
        DECLARE @ParentId BIGINT;
        DECLARE @MobileCountryCode NVARCHAR(100);
        
        SELECT @ParentId = ParentID
        FROM User_Detail (NOLOCK)
        WHERE User_ID = @UserId;

        -- Set mobile country code based on country code
        SET @MobileCountryCode = CASE 
            WHEN @CountryCode = '229' THEN '+971'  -- UAE
            WHEN @CountryCode = '202' THEN '+27'   -- South Africa
            WHEN @CountryCode = '13' THEN '+61'    -- Australia
            ELSE NULL  -- Default case for other country codes
        END;

        INSERT INTO tbl_ISMS_CountryDocuments
        (
            Country,
            CountryCode,
            UserId,
            Parentid,
            DocumentType,
            FileName,
            FilePath,
            MobileCountryCode,
            Documents_Status,
            CreatedOn
        )
        VALUES
        (
            @Country,
            @CountryCode,
            @UserId,
            @ParentId,
            @DocumentType,
            @FileName,
            @FilePath,
            @MobileCountryCode,
            'InProcess',
            GETDATE()
        );

        -- Return success
        SELECT SCOPE_IDENTITY() AS DocumentId;
    END TRY
    BEGIN CATCH
        EXEC usp_InsertErrorInfo;
    END CATCH
END



GO

