/* ============================================================
   Procedure: [dbo].[usp_ivr_GetUnproccessedReport]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE usp_ivr_GetUnproccessedReport  
as  
begin  
 drop table if exists #tempCR  
 select d.Id, d.CampaignId, d.CampaignName, d.ScheduleOn,
	(datediff(HOUR,  getdate() , dateadd(hour, (case isnull(d.ReportSyncCount, 0) 
			when 0 then 2 when 2 then 3 when 3 then 5 when 4 then 7 when 5 then 12 else 0 end 
		), d.ScheduleOn))) as [diff] into #tempCR    
 from tbl_obd_IvrScheduleData(nolock) d where   
  d.IsProccess = 1 and 
	1 = (case   
		when isnull(d.IsReportProcess, 0) = 0 then   1
	   when  d.IsReportProcess = 1 and isnull(d.ReportSyncCount, 0) < 5  
	   and
		datediff(HOUR, getdate(), dateadd(hour, (case isnull(d.ReportSyncCount, 0) 
			when 0 then 1 
			when 1 then 2 
			when 2 then 3 
			when 3 then 5
			when 4 then 7 
			when 5 then 12 end 
		), d.ScheduleOn )) < 0
	   and  exists (select 1 from tbl_obd_IvrDesignDataContact(nolock) c where c.IvrDesignId = d.Id) 
	   then 1  
   else 0 end ) 
  
 update d set  d.IsReportProcess = 2  
 from #tempCR t inner join  tbl_obd_IvrScheduleData(nolock) d on t.Id = d.Id  
  
 select * from #tempCR  

end  



