   tbl_obd_IvrDesignDataContact(nolock) o on t.ObdId = o.Id    
    
  update tbl_obd_IvrScheduleData set  
   IsReportProcess = 1,   
   ReportSyncCount = isnull(ReportSyncCount, 0) + 1  
  where CampaignId = @CampaignId  
  
 end    
end   



