/* ============================================================
   Procedure: [dbo].[usp_job_UserUntrackable]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROC usp_job_UserUntrackable
AS
Begin

	declare	@UserID bigint=0, @RowId bigint=0;

	declare @tblUnTrackable table 
	(
		Id int identity(1,1),
		User_Id bigint
	)

	Insert into @tblUnTrackable
	Select  User_ID
	From
	(
		select	LS.User_ID, LS.FrequencyUnit, LS.Untrackable, LS.Untrackableunit, UD.ParentID, 
				IsAppLoggedIn=Case when ISNULL(UD.DeviceID,'') != '' then 1 else 0 end, RTL.CreatedDate 
		From	tbl_location_setting(nolock) LS inner join User_Detail(nolock) UD
		On		LS.User_ID = UD.User_ID
		Left join
		(
			select UserID, CreatedDate
			From
			(
				select ROW_NUMBER()over(partition by UserId order by CreatedDate desc) as SNo, UserID, CreatedDate
				From Realtimelocation(nolock)
			) B
			Where B.SNo=1
		) RTL
		ON	LS.User_ID = RTL.UserID
		Where LS.Untrackable=1 and LS.Untrackableunit>0
	) UT
	Where UT.IsAppLoggedIn=1 and DATEADD(s,UT.Untrackableunit,UT.CreatedDate) < getdate()

	Select @RowId=min(Id) from @tblUnTrackable;
	While exists(Select * from @tblUnTrackable where id=@RowId)
	Begin
		select @UserID=user_id	from @tblUnTrackable where id=@RowId

		exec usp_mk_send_autonotification @UserID,'trackable'

		set @RowId += 1
	End

End



GO

/* ============================================================
   Procedure: [dbo].[usp_karix_updateCurrentmaildeliveryreport]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_karix_updateCurrentmaildeliveryreport]             
as            
begin            
declare @MailDeliveryReportId bigint=isnull((select max(MailDeliveryReportId) from MailupdatedTill where updatetable='Current_karix'),0)            
declare @CurrentMailDeliveryReportId bigint=(select MAX(id) from [EmailDeliveryStatus](nolock)) ,@c bigint ,@minid bigint,@maxid bigint         
if @MailDeliveryReportId<@CurrentMailDeliveryReportId          
begin           
select @c= count(1) from [EmailDeliveryStatus] MDR (nolock) where mdr.ID>@MailDeliveryReportId   
--and mdr.id=(select max(id) from [EmailDeliveryStatus] MD (nolock) where cust_ref_id=mdr.cust_ref_id)  
create table #temp(ID bigint,Datecreated datetime,event nvarchar(max),Response nvarchar(max) ,APIHEADER nvarchar(200))    
while @c>0  
begin  
insert into #temp(ID,Datecreated,event,Response,APIHEADER)  
select top 1000 ID,try_cast(nullif(event_time,'null') as datetime),event_desc,Reason,cust_ref_id from [EmailDeliveryStatus] MDR (nolock)   
where mdr.ID between @MailDeliveryReportId and @MailDeliveryReportId +1000 order by mdr.ID   
--and mdr.id=(select max(id) from [PelConnectDB].[dbo].[MailDeliveryReport] MD (nolock) where APIHEADER=mdr.APIHEADER)  
set @c=@c-1000  
set @MailDeliveryReportId=@MailDeliveryReportId+1000  
end  
select @minid=min(ID),@maxid=max(id) from #temp  
while @minid<@maxid  
begin  
begin try            
begin transaction            
update m set SentFinalDatetime=case   
when SentFinalDatetime is null and mdr.datecreated is not null then mdr.DateCreated   
when SentFinalDatetime is null and mdr.datecreated is null then m.SentDateTime   
else SentFinalDatetime end,  
status=mdr.event ,status_desc=mdr.RESPONSE   
from   
   ClientEmails m  join #temp MDR on MDR.APIHEADER=cast(m.GUID as nvarchar(50))            
        --and MDR.ID=(select MAX(id) from #temp mm (nolock) where mm.APIHEADER=mdr.APIHEADER)   
  and mdr.id<@minid+1000  
delete from #temp where id<@minid+1000  
select @minid=isnull((select min(ID) from #temp),@maxid)   
COMMIT TRANSACTION              
END TRY              
BEGIN CATCH              
ROLLBACK TRANSACTION    
exec usp_InsertErrorInfo  
--SELECT ERROR_NUMBER()     AS ErrorNumber,              
--         ERROR_SEVERITY()   AS ErrorSeverity,              
--         ERROR_STATE()      AS ErrorState,              
--         ERROR_PROCEDURE()  AS ErrorProcedure,              
--         ERROR_LINE()       AS ErrorLine,              
--         ERROR_MESSAGE()    AS ErrorMessage;            
 END CATCH       
 end   
insert into mailupdatedtill(dateupdated,MailDeliveryReportId,Updatetable)            
select GETDATE(),@CurrentMailDeliveryReportId,'Current_karix'            
drop table #temp            
end         
end   
  
  


GO

