/* ============================================================
   Procedure: [dbo].[usp_Kit19EngagementStatsMail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_Kit19EngagementStatsMail]  
as  
begin  
DECLARE @xml NVARCHAR(MAX)DECLARE @body NVARCHAR(MAX)  
--Total users added and logged in  
declare @reportstarttime datetime=(select dateadd(day, datediff(day, 1, getdate()), 0) + '20:00')  
declare @startofmonth datetime =(SELECT DATEADD(month, DATEDIFF(month, 0, datediff(day, 0, getdate())), 0))  
declare @userssignedup int =(select COUNT(u.user_id) from user_detail u where u.DateCreated>@reportstarttime)  
declare @usersloggedin int =(select COUNT(u.user_id)from user_detail u where LastLogin1>@reportstarttime)  
declare @usersloggedinthismonth int =(select COUNT(u.user_id)from user_detail u where LastLogin1>@startofmonth)  
select @userssignedup as userssignedup,@usersloggedin as usersloggedin,@usersloggedinthismonth as usersloggedinthismonth into #temp  
SET @xml =CAST(( SELECT [UsersSignedUp] AS 'td','',[UsersLoggedIn] AS 'td','',UsersLoggedInThisMonth from #temp FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX))  
set @body='<html><H1>Kit19 Users Addition & Engagement as on '+cast (getdate() as nvarchar)+ '</H1><body><p><table border = 2><tr><th>UsersSignedUp</th><th>UsersLoggedIn</th><th>UsersLoggedInThisMonth</th></tr>'   
SET @body = @body + @xml +'</table></p>'  
  
select count(distinct UserID) as TotalUsersForwardingMails ,COUNT(1) as TotalMailsForwarded into #temp1 from UserMails where UserID<>0  
SET @xml =CAST(( SELECT [TotalUsersForwardingMails] AS 'td','',[TotalMailsForwarded]from #temp1 FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX))  
set @body=@body + '<p><table border = 2><tr><th>TotalUsersForwardingMails</th><th>TotalMailsForwarded</th></tr>'  
SET @body = @body + @xml +'</table></p>'   
  
select count(distinct UserID) as UsersForwardingMailsThisMonth ,COUNT(1) as MailsForwardedThisMonth into #temp2 from UserMails where UserID<>0 and CreatedOn>@startofmonth  
SET @xml =CAST(( SELECT [UsersForwardingMailsThisMonth] AS 'td','',[MailsForwardedThisMonth]from #temp2 FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX))  
set @body=@body + '<p><table border = 2><tr><th>UsersForwardingMailsThisMonth</th><th>MailsForwardedThisMonth</th></tr>'   
SET @body = @body + @xml +'</table></p>'  
  
--Users adding enquiries, Followups  
select count(distinct ParentID) as TotalUsersAddingEnquiries ,COUNT(1) as TotalEnquiriesAdded into #temp3 from UserEnquiry where ParentID<>0  
SET @xml =CAST(( SELECT [TotalUsersAddingEnquiries] AS 'td','',[TotalEnquiriesAdded]from #temp3 FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX))  
set @body=@body + '<p><table border = 2><tr><th>TotalUsersAddingEnquiries</th><th>TotalEnquiriesAdded</th></tr>'   
SET @body = @body + @xml +'</table></p>'  
  
select count(distinct ParentID) as UsersAddingEnquiriesThisMonth ,COUNT(1) as EnquiriesAddedThisMonth into #temp4 from UserEnquiry where ParentID<>0 and CreatedDate>@startofmonth  
SET @xml =CAST(( SELECT [UsersAddingEnquiriesThisMonth] AS 'td','',[EnquiriesAddedThisMonth]from #temp4 FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX))  
set @body=@body + '<p><table border = 2><tr><th>UsersAddingEnquiriesThisMonth</th><th>EnquiriesAddedThisMonth</th></tr>'   
SET @body = @body + @xml +'</table></p>'  
  
select count(distinct ParentID) as TotalUsersAddingFollowup ,COUNT(1) as TotalFollowupsAdded into #temp5 from LeadInteractionHistory where ParentID<>0  
SET @xml =CAST(( SELECT [TotalUsersAddingFollowup] AS 'td','',TotalFollowupsAdded from #temp5 FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX))  
set @body=@body + '<p><table border = 2><tr><th>TotalUsersAddingFollowup</th><th>TotalFollowupsAdded</th></tr>'   
SET @body = @body + @xml +'</table></p>'  
  
select count(distinct ParentID) as UsersAddingFollowupThisMonth ,COUNT(1) as FollowupsAddedThisMonth into #temp6 from LeadInteractionHistory where ParentID<>0 and CreatedOn>@startofmonth  
SET @xml =CAST(( SELECT [UsersAddingFollowupThisMonth] AS 'td','',FollowupsAddedThisMonth from #temp6 FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX))  
set @body=@body + '<p><table border = 2><tr><th>UsersAddingFollowupThisMonth</th><th>FollowupsAddedThisMonth</th></tr>'   
SET @body = @body + @xml +'</table></p>'  
  
--Users adding campaigns  
select count(distinct ParentID) as TotalUsersAddingCampaign ,COUNT(1) as TotalCampaignsAdded into #temp7 from UserCampaignMaster where ParentID<>0  
SET @xml =CAST(( SELECT TotalUsersAddingCampaign AS 'td','',TotalCampaignsAdded from #temp7 FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX))  
set @body=@body + '<p><table border = 2><tr><th>TotalUsersAddingCampaign</th><th>TotalCampaignsAdded</th></tr>'   
SET @body = @body + @xml +'</table></p>'  
  
select count(distinct ParentID) as UsersAddingCampaignThisMonth ,COUNT(1) as CampaignsAddedThisMonth into #temp8 from LeadInteractionHistory where ParentID<>0 and CreatedOn>@startofmonth  
SET @xml =CAST(( SELECT UsersAddingCampaignThisMonth AS 'td','',CampaignsAddedThisMonth from #temp8 FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX))  
set @body=@body + '<p><table border = 2><tr><th>UsersAddingCampaignThisMonth</th><th>CampaignsAddedThisMonth</th></tr>'   
SET @body = @body + @xml +'</table></p>'  
  
--Users campaign execution  
select count(distinct ParentID) as TotalUsersExecutingSMSCampaign,count(distinct CampaignID) as TotalCampaignsExecuted,sum(Step3Recipients) as TotalSMSSent into #temp9 from UserCampaignhistory (nolock) where ParentID<>0  and issms=1-- and IsScheduled=1   
and Step3=1 and Step3Recipients>0  
SET @xml =CAST(( SELECT TotalUsersExecutingSMSCampaign AS 'td','',TotalCampaignsExecuted as 'td','',TotalSMSSent from #temp9 FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX))  
set @body=@body + '<p><table border = 2><tr><th>TotalUsersExecutingSMSCampaign</th><th>TotalCampaignsExecuted</th><th>TotalSMSSent</th></tr>'   
SET @body = @body + @xml +'</table></p>'  
  
select count(distinct ParentID) as TotalUsersExecutingMailCampaign,count(distinct CampaignID) as TotalCampaignsExecuted,sum(Step3Recipients) as TotalMailSent into #temp10 from UserCampaignhistory (nolock) where ParentID<>0  and ismail=1 --and IsScheduled=1   
and Step3=1 and Step3Recipients>0  
SET @xml =CAST(( SELECT TotalUsersExecutingMailCampaign AS 'td','',TotalCampaignsExecuted as 'td','',TotalMailSent from #temp10 FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX))  
set @body=@body + '<p><table border = 2><tr><th>TotalUsersExecutingMailCampaign</th><th>TotalCampaignsExecuted</th><th>TotalMailSent</th></tr>'   
SET @body = @body + @xml +'</table></p>'  
  
select count(distinct ParentID) as UsersExecutingSMSCampaignThismonth,count(distinct CampaignID) as CampaignsExecutedThismonth,sum(Step3Recipients) as TotalSMSSent into #temp11 from UserCampaignhistory (nolock) where ParentID<>0  and issms=1 --and IsScheduled=1   
and Step3=1 and Step3Recipients>0 and CreatedOn>@startofmonth  
SET @xml =CAST(( SELECT UsersExecutingSMSCampaignThismonth AS 'td','',CampaignsExecutedThismonth as 'td','',TotalSMSSent from #temp11 FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX))  
set @body=@body + '<p><table border = 2><tr><th>UsersExecutingSMSCampaignThismonth</th><th>CampaignsExecutedThismonth</th><th>TotalSMSSent</th></tr>'   
SET @body = @body + @xml +'</table></p>'  
  
  
select count(distinct ParentID) as UsersExecutingMailCampaignThismonth,count(distinct CampaignID) as CampaignsExecutedThismonth,sum(Step3Recipients) as TotalMailSent into #temp12 from UserCampaignhistory (nolock) where ParentID<>0  and ismail=1 --and IsScheduled=1   
and Step3=1 and Step3Recipients>0 and CreatedOn>@startofmonth  
SET @xml =CAST(( SELECT UsersExecutingMailCampaignThismonth AS 'td','',CampaignsExecutedThismonth as 'td','',TotalMailSent from #temp12 FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX))  
set @body=@body + '<p><table border = 2><tr><th>UsersExecutingMailCampaignThismonth</th><th>CampaignsExecutedThismonth</th><th>TotalMailSent</th></tr>'   
SET @body = @body + @xml +'</table></p>'  
  
--Userscreatingtemplates  
select count(distinct ParentID) as TotalUsersAddingSMSTemplate,count(distinct ID) as TotalSMSTemplatesCreated into #temp13 from Usermailtemplate (nolock) where ParentID<>0  and issms=1  
SET @xml =CAST(( SELECT TotalUsersAddingSMSTemplate AS 'td','',TotalSMSTemplatesCreated from #temp13 FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX))  
set @body=@body + '<p><table border = 2><tr><th>TotalUsersAddingSMSTemplate</th><th>TotalSMSTemplatesCreated</th></tr>'   
SET @body = @body + @xml +'</table></p>'  
  
  
select count(distinct ParentID) as TotalUsersAddingMailTemplate,count(distinct ID) as TotalMailTemplatesCreated into #temp14 from Usermailtemplate (nolock) where ParentID<>0  and ismail=1  
SET @xml =CAST(( SELECT TotalUsersAddingMailTemplate AS 'td','',TotalMailTemplatesCreated from #temp14 FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX))  
set @body=@body + '<p><table border = 2><tr><th>TotalUsersAddingMailTemplate</th><th>TotalMailTemplatesCreated</th></tr>'   
SET @body = @body + @xml +'</table></p>'  
  
select count(distinct ParentID) as UsersAddingSMSTemplateThisMonth,count(distinct ID) as SMSTemplatesCreatedThisMonth into #temp15 from Usermailtemplate (nolock) where ParentID<>0  and issms=1 and CreatedOn>@startofmonth  
SET @xml =CAST(( SELECT UsersAddingSMSTemplateThisMonth AS 'td','',SMSTemplatesCreatedThisMonth from #temp15 FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX))  
set @body=@body + '<p><table border = 2><tr><th>UsersAddingSMSTemplateThisMonth</th><th>SMSTemplatesCreatedThisMonth</th></tr>'   
SET @body = @body + @xml +'</table></p>'  
  
  
  
select count(distinct ParentID) as UsersAddingMailTemplateThisMonth,count(distinct ID) as MAilTemplatesCreatedThisMonth into #temp16  from Usermailtemplate (nolock) where ParentID<>0  and ismail=1 and CreatedOn>@startofmonth  
SET @xml =CAST(( SELECT UsersAddingMailTemplateThisMonth AS 'td','',MailTemplatesCreatedThisMonth from #temp16 FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX))  
set @body=@body + '<p><table border = 2><tr><th>UsersAddingMailTemplateThisMonth</th><th>MAilTemplatesCreatedThisMonth</th></tr>'   
--SET @body = @body + @xml +'</table></p>'  
  
  
SET @body = @body + @xml +'</table></p>'+'</body></html>'  
EXEC usp_enqueueemail  
@profile_name='Alerts',   
@recipients='csshukla@pelsoftlabs.in',  
@blind_copy_recipients='karuna@pelsoftlabs.in',  
@subject='Kit19 Users Addition & Engagaement',  
