/* ============================================================
   Procedure: [dbo].[usp_kt_GetSetTemplateCols]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC usp_kt_GetSetTemplateCols    
(    
 @UserId bigint,    
 @TemplateType varchar(3)='EN', --'EN' Enquiry,'LD' Lead    
 @TemplateCols Nvarchar(max)='',    
 @Mode varchar(3)='Get'    
)    
AS    
BEGIN    
 If(@Mode = 'Get')    
 Begin    
  declare @ColList nvarchar(max)='';    
    
  Select @ColList=ColumnList From tbl_kt_ViewTemplate(nolock) Where User_Id = @UserId and TemplateType=@TemplateType    
    
  select @ColList as ColList    
 End    
    
 If(@Mode = 'Set')    
 Begin    
  IF EXISTS(Select * From tbl_kt_ViewTemplate(nolock) Where User_Id = @Userid and TemplateType=@TemplateType)    
  BEGIN    
   Update tbl_kt_ViewTemplate set ColumnList=@TemplateCols,ModifiedDate=GETDATE()  Where User_Id = @UserId and TemplateType=@TemplateType    
  END    
  ELSE    
  BEGIN    
   insert into [tbl_kt_ViewTemplate] values(@TemplateCols,@UserId,@TemplateType,GETDATE(),null)    
  END    
    
  select @@ROWCOUNT as ColList    
 End    
    
END 


GO

/* ============================================================
   Procedure: [dbo].[usp_las_ActiveInvtiveSetting]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_las_ActiveInvtiveSetting (
	@RuleId BIGINT
	,@Status BIGINT
	,@UserId BIGINT
	)
AS
BEGIN
	IF (@Status = 1)
	BEGIN
		UPDATE tbl_LeadAssignmentRules
		SET rule_priority = 1
			,is_active = 1
		WHERE id = @RuleId
	END
	ELSE
	BEGIN
		DECLARE @currentPriority INT = (
				SELECT rule_priority
				FROM tbl_LeadAssignmentRules(NOLOCK)
				WHERE id = @RuleId
				)
		DECLARE @maxPriorityId INT = (
				SELECT max(r.rule_priority)
				FROM tbl_LeadAssignmentRules(NOLOCK) r
				INNER JOIN tbl_LeadAssignmentMaster(NOLOCK) m ON r.lam_id = m.id
				WHERE m.ParentId = (
						SELECT ParentId
						FROM User_Detail(NOLOCK)
						WHERE User_ID = @UserId
						)
				)

		UPDATE r
		SET r.rule_priority = r.rule_priority - 1
		FROM tbl_LeadAssignmentRules r
		INNER JOIN tbl_LeadAssignmentMaster m ON r.lam_id = m.id
			AND m.ParentId = (
				SELECT ParentId
				FROM User_Detail(NOLOCK)
				WHERE User_ID = @UserId
				)
		WHERE r.rule_priority > @currentPriority

		UPDATE tbl_LeadAssignmentRules
		SET rule_priority = @maxPriorityId
			,is_active = 0
		WHERE id = @RuleId
	END

	DECLARE @rowJson NVARCHAR(MAX) = (
			SELECT *
			FROM tbl_LeadAssignmentRules WITH(NOLOCK)
			WHERE ID = @RuleId
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

	IF @RowJson IS NOT NULL
	BEGIN
		EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID
			,@Activity_type = 'Updt_ldasnmtstng_stst'
			,@ActionType = 'U'
			,@RowJson = @rowJson
			,@Table_name = 'tbl_LeadAssignmentRules'
	END
END



GO

/* ============================================================
   Procedure: [dbo].[usp_las_EnquiryActiveInvtiveSetting]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


---------------------------

CREATE   PROCEDURE usp_las_EnquiryActiveInvtiveSetting(      
 @RuleId bigint,      
 @Status bigint,      
 @UserId bigint      
)      
as      
begin      
       
      
 if(@Status = 1)      
 begin      
  update tbl_EnquiryAssignmentRules set rule_priority = 1,is_active = 1  where id = @RuleId      
 end      
 else      
 begin      
  declare @currentPriority int = ( select rule_priority from tbl_EnquiryAssignmentRules(nolock) where id = @RuleId)       
  declare @maxPriorityId int = ( select  max(r.rule_priority) from tbl_EnquiryAssignmentRules(nolock) r       
          inner join tbl_EnquiryAssignmentMaster(nolock) m  on r.lam_id = m.id       
          where m.ParentId = (      
           select ParentId from User_Detail(nolock)      
            where User_ID = @UserId)      
          )      
      
        
      
  update r set r.rule_priority = r.rule_priority - 1 from tbl_EnquiryAssignmentRules r       
   inner join tbl_EnquiryAssignmentMaster m  on r.lam_id = m.id       
    and m.ParentId = (select ParentId from User_Detail(nolock) where User_ID = @UserId)      
   where r.rule_priority > @currentPriority      
      
    update tbl_EnquiryAssignmentRules       
   set rule_priority = @maxPriorityId, is_active = 0      
   where id =  @RuleId      
      
 end      
DECLARE @rowJson NVARCHAR(MAX) = (    
   SELECT *    
   FROM tbl_EnquiryAssignmentRules WITH(NOLOCK)    
   WHERE ID = @RuleId    
   FOR JSON AUTO    
    ,INCLUDE_NULL_VALUES    
   )    
    
 IF @RowJson IS NOT NULL    
 BEGIN    
  EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID    
   ,@Activity_type = 'Updt_enqasnmtstng_stst'    
   ,@ActionType = 'U'    
   ,@RowJson = @rowJson    
   ,@Table_name = 'tbl_EnqAssignmentRules'    
 END    
 END



GO

/* ============================================================
   Procedure: [dbo].[usp_las_EnquiryInsertUpdateEnquiryAssignment]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


----------------------
CREATE   PROCEDURE usp_las_EnquiryInsertUpdateEnquiryAssignment(        
 @RuleId bigint = 0,        
 @RuleName nvarchar(255),        
 @SelectedUsers nvarchar(1000),        
 @RulePriority int  = 0,        
 @LogicalOperator nvarchar(255),        
 @AssignmentExpression nvarchar(max),        
 @IsActive bit = 1,        
 @UserId bigint,        
 @LeadAssignmentId bigint = 0,     
 @Segmentations FbFieldMappingData readonly,    
 @larcCondition larcCondition readonly,    
 @SettingJSON nvarchar(max) = null    
    
)        
as        
begin        
 declare @ParentId bigint=0,@activity VARCHAR(MAX), @action VARCHAR(1), @RuleType nvarchar(255) = 'CustomCondition'    
 select @ParentId = ParentID from User_Detail(nolock) where User_ID = @UserId and Status = 1    
        
         
  if(exists(select 1 from @Segmentations))    
 begin    
  set @RuleType  = 'SegmentCondition'    
 end    
    
 --Getting LeadAssignmentMaster Id        
 if(exists(select 1 from tbl_EnquiryAssignmentMaster(nolock) where ParentId = @ParentId))        
 begin        
  set @LeadAssignmentId = (select id from tbl_EnquiryAssignmentMaster(nolock) where ParentId = @ParentId )        
 end        
 else        
 begin        
  insert into tbl_EnquiryAssignmentMaster( overwrite_agent, default_agent, is_active, ParentId, created_by, created_on )        
   values ( 0, @ParentId, 1, @ParentId, @UserId, GETDATE())        
  set @LeadAssignmentId = SCOPE_IDENTITY();        
 end        
        
 if(@RulePriority = 0 and @RuleId = 0)        
 begin        
  set @RulePriority = (select cast(isnull(max(rule_priority), 0) as int) + 1 from tbl_EnquiryAssignmentRules)        
 end        
       
   if(exists(select 1 from tbl_EnquiryAssignmentRules(nolock) where lam_id = @LeadAssignmentId and rule_name = @RuleName))    
 begin    
  select top 1 @RuleId = id from tbl_EnquiryAssignmentRules(nolock)     
   where lam_id = @LeadAssignmentId and rule_name = @RuleName order by id desc    
 end    
    
 if(@RuleId > 0)        
 begin        
  update tbl_EnquiryAssignmentRules set        
   rule_name = @RuleName,        
   selected_users = @SelectedUsers,        
   rule_priority = @RulePriority,        
   logical_operator= @LogicalOperator,        
   is_active = @IsActive,        
   assignment_expression = @AssignmentExpression ,    
   SettingJSON = @SettingJSON,    
   RuleType = @RuleType    
    where id = @RuleId SET @activity = 'Updt_ldasnmt_stng'    
  SET @action = 'U'    
       
 end        
 else        
 begin        
  insert into tbl_EnquiryAssignmentRules( rule_name, selected_users, rule_priority, logical_operator, is_active, assignment_expression, lam_id, SettingJSON, RuleType)         
   values(@RuleName, @SelectedUsers, @RulePriority, @LogicalOperator, @IsActive, @AssignmentExpression, @LeadAssignmentId, @SettingJSON, @RuleType)    
  SET @RuleId = SCOPE_IDENTITY();    
  SET @activity = 'Inst_ldasnmt_stng'    
  SET @action = 'I'    
 END    
  --select @SettingJSON = JSON_MODIFY(@SettingJSON, '$.enquiryAssignmentRule.Id', @RuleId)    
    
 --update tbl_EnquiryAssignmentRules set SettingJSON = @SettingJSON where id = @RuleId  
   
 SET @SettingJSON = JSON_MODIFY(@SettingJSON, '$.Id', @RuleId);  -- Update tbl_EnquiryAssignmentRules with the modified SettingJSON UPDATE tbl_EnquiryAssignmentRules SET SettingJSON = @SettingJSON WHERE id = @RuleId;  
     
 if(@RuleType = 'CustomCondition')    
 begin    
     
        
 drop table if exists #tempCondtions        
 select *, 0 as isprocess into #tempCondtions from @larcCondition;        
        
 IF (EXISTS (SELECT * FROM tbl_EnquiryAssignmentRuleConditions (NOLOCK) WHERE lam_rule_id = @RuleId ))    
  BEGIN    
   DELETE FROM tbl_EnquiryAssignmentRuleConditions WHERE lam_rule_id = @RuleId    
  END    
  WHILE (EXISTS (SELECT 1 FROM #tempCondtions WHERE isprocess = 0 ) )    
  BEGIN    
          
  declare @sr int, @rowId int, @cId bigint, @FieldName nvarchar(255), @FieldOpText nvarchar(255), @FieldValue nvarchar(max), @FieldOpId  nvarchar(255), @FieldPlaceholder nvarchar(255), @FieldOpSign nvarchar(255)        
        
  select top 1 @sr = sr, @rowId = Id, @cId = Id, @FieldName = FieldName, @FieldOpText = FieldOpText,         
   @FieldValue = FieldValue, @FieldOpId = FieldOpId, @FieldPlaceholder = FieldPlaceholder, @FieldOpSign = FieldOpSign        
    from #tempCondtions where isprocess = 0         
        
  if(exists(select 1 from tbl_EnquiryAssignmentRuleConditions(nolock) where id = @cId))        
  begin        
   update tbl_EnquiryAssignmentRuleConditions set        
    FieldName =  @FieldName,        
    FieldOpText =  @FieldOpText,        
    FieldValue =  @FieldValue,        
    FieldOpId =  @FieldOpId,        
    FieldPlaceholder =  @FieldPlaceholder,        
    FieldOpSign =  @FieldOpSign,        
    lam_rule_id =  @RuleId        
     where id = @cId        
  end        
  else        
  begin        
    insert into tbl_EnquiryAssignmentRuleConditions( FieldName, FieldOpText, FieldValue,         
     FieldOpId, FieldPlaceholder, FieldOpSign, lam_rule_id)        
    values( @FieldName, @FieldOpText, @FieldValue, @FieldOpId, @FieldPlaceholder, @FieldOpSign, @RuleId)        
  end        
        
        
  update #tempCondtions set isprocess = 1 where sr = @sr;        
 end      
 end    
 select 'inserted'     
 DECLARE @rowJson NVARCHAR(MAX) = ( SELECT * FROM tbl_EnquiryAssignmentRules WHERE ID = @RuleId FOR JSON AUTO, INCLUDE_NULL_VALUES)    
 IF @RowJson IS NOT NULL    
 BEGIN    
  EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID    
   ,@Activity_type = @activity    
   ,@ActionType = @action    
   ,@RowJson = @rowJson    
   ,@Table_name = 'tbl_EnquiryAssignmentRules'    
 END    
    
    
    
 print 'Procedure completed'    
    
end 




GO

