CREATE   PROCEDURE usp_las_EnquiryUpdateRulePriority(  
    @RulePriorityType RulePriorityType READONLY  
)  
AS  
BEGIN  
    -- Perform the update  
    UPDATE lar  
    SET lar.rule_priority = rpt.PriorityNo  
    FROM tbl_EnquiryAssignmentRules lar  
    INNER JOIN @RulePriorityType rpt ON lar.id = rpt.RuleId;  
      
    -- Return the count of rows updated  
    DECLARE @UpdatedRowCount INT;  
    SET @UpdatedRowCount = @@ROWCOUNT;  
  
    SELECT @UpdatedRowCount AS UpdatedCount;  
END




