CREATE   PROCEDURE usp_las_GetEnquiryAssignmentByUserId(      
 @UserId bigint      
)      
as      
begin      
 declare @ParentId bigint  = ( select ParentID from User_Detail(nolock) where User_ID = @UserId )      
      
      
 select * into #tempLeadAssignmentMaster       
  from tbl_EnquiryAssignmentMaster(nolock) where ParentId = @ParentId      
      
 select * from #tempLeadAssignmentMaster      
      
 select lar.*,       
 (      
  select STRING_AGG(u.User_Login, ', ') from fn_split(lar.selected_users, ',') as a      
   inner join User_Detail(nolock) u on  u.User_ID = [a].[value]      
 ) as [AssigneeUserName]       
 from tbl_EnquiryAssignmentRules(nolock) lar       
  inner join #tempLeadAssignmentMaster tlam on  lar.lam_id = tlam.id      
  where tlam.ParentId = @ParentId --and lar.is_active = 1      
   order by lar.rule_priority asc      
       
 select larc.* from tbl_EnquiryAssignmentRuleConditions(nolock) larc       
  left join tbl_EnquiryAssignmentRules(nolock) lar on larc.lam_rule_id = lar.id --and lar.is_active = 1      
  left join #tempLeadAssignmentMaster tlam on lar.lam_id = tlam.id      
   where tlam.ParentId = @ParentId -- and lar.is_active = 1      
      
end 




