/* ============================================================
   Procedure: [dbo].[usp_las_GetLeadAssignmentByUserId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-----------------------------------------------


CREATE   PROCEDURE [dbo].[usp_las_GetLeadAssignmentByUserId]
(
    @UserId BIGINT
)
AS
BEGIN
    DECLARE @ParentId BIGINT = (
        SELECT ParentID
        FROM User_Detail (NOLOCK)
        WHERE User_ID = @UserId
    );

    -- Temp Master
    SELECT *
    INTO #tempLeadAssignmentMaster
    FROM tbl_LeadAssignmentMaster (NOLOCK)
    WHERE ParentId = @ParentId;

    SELECT *
    FROM #tempLeadAssignmentMaster;

    -- Lead Assignment Rules
    SELECT 
        lar.*,
        (
            SELECT STRING_AGG(u.User_Login + ' (' + u.FName + ' ' + u.LName + ')', ', ')
            FROM fn_split(lar.selected_users, ',') a
            INNER JOIN User_Detail (NOLOCK) u ON u.User_ID = a.[value]
        ) AS [AssigneeUserName],

        -- ✅ Get type names from LeadAssignmentCollaborators
        (
            SELECT STRING_AGG(ctm.type_name, ', ')
            FROM LeadAssignmentCollaborators lac
            INNER JOIN Tbl_coll_CollaboratorTypeMaster ctm ON ctm.id = lac.TypeId
            WHERE lac.RuleId = lar.id
              AND ctm.isactive = 1
        ) AS CollaboratorTypeNames,

        -- ✅ Get team names from LeadAssignmentCollaborators where AssignType = 'Team'
        (
            SELECT STRING_AGG(ct.team_name, ', ')
            FROM LeadAssignmentCollaborators lac WITH(NOLOCK)
            INNER JOIN tbl_coll_CollaboratorTeams ct WITH(NOLOCK) ON ct.id = lac.CollaboratorId
            WHERE lac.RuleId = lar.id
              AND lac.AssignType = 'Team'
              AND ct.isactive = 1
        ) AS CollaboratorTeamNames
    FROM tbl_LeadAssignmentRules (NOLOCK) lar
    INNER JOIN #tempLeadAssignmentMaster tlam  ON lar.lam_id = tlam.id
    WHERE tlam.ParentId = @ParentId
    ORDER BY lar.rule_priority ASC;

    -- Rule Conditions
    SELECT larc.*
    FROM tbl_LeadAssignmentRuleConditions (NOLOCK) larc
    LEFT JOIN tbl_LeadAssignmentRules (NOLOCK) lar ON larc.lam_rule_id = lar.id
    LEFT JOIN #tempLeadAssignmentMaster tlam ON lar.lam_id = tlam.id
    WHERE tlam.ParentId = @ParentId;

    -- Collaborators (raw data)
    SELECT 
        lac.RuleId,
        lac.TypeId,
        lac.AssignType,
        lac.CollaboratorId
    FROM LeadAssignmentCollaborators (NOLOCK) lac
    INNER JOIN tbl_LeadAssignmentRules (NOLOCK) lar ON lar.id = lac.RuleId
    INNER JOIN #tempLeadAssignmentMaster tlam ON lar.lam_id = tlam.id
    WHERE tlam.ParentId = @ParentId;
END;



GO

/* ============================================================
   Procedure: [dbo].[usp_las_InsertUpdateLAGlobalSetting]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_las_InsertUpdateLAGlobalSetting (
	@IsOverwrite BIT = 1
	,@DefaultUser BIGINT
	,@UserId BIGINT
	)
AS
BEGIN
	DECLARE @ParentId BIGINT = (
			SELECT ParentID
			FROM User_Detail(NOLOCK)
			WHERE User_ID = @UserId
			)
		,@activity VARCHAR(MAX)
		,@action VARCHAR(1)

	IF (
			EXISTS (
				SELECT 1
				FROM tbl_LeadAssignmentMaster(NOLOCK)
				WHERE ParentId = @ParentId
				)
			)
	BEGIN
		UPDATE tbl_LeadAssignmentMaster
		SET overwrite_agent = @IsOverwrite
			,default_agent = @DefaultUser
		WHERE ParentId = @ParentId

		SET @action = 'U'
		SET @activity = 'Updt_ldasnmt_asgusr'
	END
	ELSE
	BEGIN
		INSERT INTO tbl_LeadAssignmentMaster (
			overwrite_agent
			,default_agent
			,is_active
			,ParentId
			,created_by
			,created_on
			)
		VALUES (
			@IsOverwrite
			,@DefaultUser
			,1
			,@ParentId
			,@UserId
			,GETDATE()
			)

		SET @action = 'I'
		SET @activity = 'Inst_ldasnmt_asgusr'
	END

	DECLARE @rowJson NVARCHAR(MAX) = (
			SELECT *
			FROM tbl_LeadAssignmentMaster WITH(NOLOCK)
			WHERE ParentId = @ParentId
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

	IF @RowJson IS NOT NULL
	BEGIN
		EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId
			,@Activity_type = @activity
			,@ActionType = @action
			,@RowJson = @rowJson
			,@Table_name = 'tbl_LeadAssignmentMaster'
	END
END



GO

/* ============================================================
   Procedure: [dbo].[usp_las_InsertUpdateLAGlobalSettingEnquiry]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


------------------------
CREATE   PROCEDURE usp_las_InsertUpdateLAGlobalSettingEnquiry    
    @IsOverwrite bit = 1,    
    @DefaultUser bigint,    
    @UserId bigint,  
    @AssignToEnquiry bit  
AS    
BEGIN    
    DECLARE @ParentId bigint = (SELECT ParentID FROM User_Detail(NOLOCK) WHERE User_ID = @UserId);  
    DECLARE @RowCount int;  
  
    IF EXISTS (SELECT 1 FROM tbl_EnquiryAssignmentMaster(NOLOCK) WHERE ParentId = @ParentId)    
    BEGIN    
        UPDATE tbl_EnquiryAssignmentMaster   
        SET     
            overwrite_agent = @IsOverwrite,    
            default_agent = @DefaultUser,  
            AssignToEnquiry = @AssignToEnquiry  
        WHERE ParentId = @ParentId;  
  
        -- Get the number of affected rows by the update  
        SET @RowCount = @@ROWCOUNT;  
    END    
    ELSE    
    BEGIN    
        INSERT INTO tbl_EnquiryAssignmentMaster (overwrite_agent, default_agent, is_active, ParentId, created_by, created_on, AssignToEnquiry)    
        VALUES (@IsOverwrite, @DefaultUser, 1, @ParentId, @UserId, GETDATE(), @AssignToEnquiry);  
  
        -- Since an insert affects one row, set @RowCount to 1  
        SET @RowCount = 1;  
    END  
  
    -- Return the count of affected rows  
    SELECT @RowCount AS AffectedRows;  
END  




GO

/* ============================================================
   Procedure: [dbo].[usp_las_InsertUpdateLeadAssignment]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_las_InsertUpdateLeadAssignment]    --------------------------------------existing sp
(

    @RuleId BIGINT = 0,

    @RuleName NVARCHAR(255),

    @SelectedUsers NVARCHAR(1000) = null,

    @RulePriority INT = 0,

    @LogicalOperator NVARCHAR(255),

    @AssignmentExpression NVARCHAR(MAX),

    @IsActive BIT = 1,

    @UserId BIGINT,

    @LeadAssignmentId BIGINT = 0,

    @Segmentations FbFieldMappingData READONLY,

    @larcCondition larcCondition READONLY,

    @Collaborators CollaboratorTableType READONLY,  -- ✅ New parameter

    @SettingJSON NVARCHAR(MAX) = NULL

)

AS
 
BEGIN

    SET NOCOUNT ON;
 
    DECLARE @ParentId BIGINT = 0, 

            @activity VARCHAR(MAX), 

            @action VARCHAR(1), 

            @RuleType NVARCHAR(255) = 'CustomCondition';

            DECLARE @ColloborationType NVARCHAR(MAX) = NULL;

            DECLARE @CollaborationTeam NVARCHAR(MAX) = NULL;

            SELECT 

                @ColloborationType = STRING_AGG(CAST(TypeId AS NVARCHAR(50)), ','),

                @CollaborationTeam = STRING_AGG(CAST(CollaboratorId AS NVARCHAR(50)), ',')

            FROM @Collaborators;

    -- Get ParentId

    SELECT @ParentId = ParentID 

    FROM User_Detail(NOLOCK) 

    WHERE User_ID = @UserId AND Status = 1;
 
    -- Decide RuleType

    IF EXISTS (SELECT 1 FROM @Segmentations)

    BEGIN

        SET @RuleType = 'SegmentCondition';

    END
 
    -- Ensure LeadAssignmentMaster exists

    IF EXISTS (SELECT 1 FROM tbl_LeadAssignmentMaster(NOLOCK) WHERE ParentId = @ParentId)

    BEGIN

        SET @LeadAssignmentId = (SELECT id FROM tbl_LeadAssignmentMaster(NOLOCK) WHERE ParentId = @ParentId);

    END

    ELSE

    BEGIN

        INSERT INTO tbl_LeadAssignmentMaster (overwrite_agent, default_agent, is_active, ParentId, created_by, created_on)

        VALUES (0, @ParentId, 1, @ParentId, @UserId, GETDATE()); 

        SET @LeadAssignmentId = SCOPE_IDENTITY();

    END
 
    -- Set default priority

    IF (@RulePriority = 0 AND @RuleId = 0)

    BEGIN

        SET @RulePriority = (

            SELECT CAST(ISNULL(MAX(rule_priority), 0) AS INT) + 1 

            FROM tbl_LeadAssignmentRules WITH(NOLOCK)

        );

    END
 
    -- Check if rule already exists by name

    IF EXISTS (SELECT 1 FROM tbl_LeadAssignmentRules(NOLOCK) WHERE lam_id = @LeadAssignmentId AND rule_name = @RuleName)

    BEGIN

        SELECT TOP 1 @RuleId = id 

        FROM tbl_LeadAssignmentRules(NOLOCK) 

        WHERE lam_id = @LeadAssignmentId AND rule_name = @RuleName 

        ORDER BY id DESC;

    END
 
    -- Insert or update the main rule

    IF @RuleId > 0

    BEGIN

       UPDATE tbl_LeadAssignmentRules

       SET rule_name = @RuleName,

           selected_users = @SelectedUsers,

           rule_priority = @RulePriority,

           logical_operator = @LogicalOperator,

           is_active = @IsActive,

           assignment_expression = @AssignmentExpression,

           SettingJSON = @SettingJSON,

           RuleType = @RuleType,

           ColloborationType = @ColloborationType,

           CollaborationTeam = @CollaborationTeam

       WHERE id = @RuleId;

 
        SET @activity = 'Updt_ldasnmt_stng';

        SET @action = 'U';

    END

    ELSE

    BEGIN

INSERT INTO tbl_LeadAssignmentRules (rule_name,selected_users,rule_priority, logical_operator, is_active,

    assignment_expression,lam_id,SettingJSON,RuleType,ColloborationType,CollaborationTeam

)

VALUES (

    @RuleName,  @SelectedUsers, @RulePriority, @LogicalOperator, @IsActive, @AssignmentExpression, @LeadAssignmentId,  @SettingJSON,

    @RuleType,  @ColloborationType, @CollaborationTeam

);
 
        SELECT @RuleId = SCOPE_IDENTITY();

        SET @activity = 'Inst_ldasnmt_stng';

        SET @action = 'I';

    END
 
    -- ✅ Handle Collaborators

    DELETE FROM LeadAssignmentCollaborators WHERE RuleId = @RuleId;
 
    INSERT INTO LeadAssignmentCollaborators (RuleId, TypeId, AssignType, CollaboratorId)

    SELECT @RuleId, TypeId, AssignType, CollaboratorId

    FROM @Collaborators;
 
    -- Update JSON with new RuleId

    SELECT @SettingJSON = JSON_MODIFY(@SettingJSON, '$.leadAssignmentRule.Id', @RuleId);

    UPDATE tbl_LeadAssignmentRules 

    SET SettingJSON = @SettingJSON 

    WHERE id = @RuleId;
 
    -- Handle conditions for CustomCondition type

    IF @RuleType = 'CustomCondition'

    BEGIN

        DROP TABLE IF EXISTS #tempCondtions;

        SELECT *, 0 AS isprocess INTO #tempCondtions FROM @larcCondition;
 
        IF EXISTS (SELECT * FROM tbl_LeadAssignmentRuleConditions(NOLOCK) WHERE lam_rule_id = @RuleId)

        BEGIN

            DELETE FROM tbl_LeadAssignmentRuleConditions WHERE lam_rule_id = @RuleId;

        END
 
        WHILE EXISTS (SELECT 1 FROM #tempCondtions WHERE isprocess = 0)

        BEGIN

            DECLARE @sr INT, @rowId INT, @cId BIGINT,

                    @FieldName NVARCHAR(255), @FieldOpText NVARCHAR(255), 

                    @FieldValue NVARCHAR(MAX), @FieldOpId NVARCHAR(255),

                    @FieldPlaceholder NVARCHAR(255), @FieldOpSign NVARCHAR(255);
 
            SELECT TOP 1 

                @sr = sr, @rowId = Id, @cId = Id, 

                @FieldName = FieldName, @FieldOpText = FieldOpText, @FieldValue = FieldValue, 

                @FieldOpId = FieldOpId, @FieldPlaceholder = FieldPlaceholder, @FieldOpSign = FieldOpSign

            FROM #tempCondtions 

            WHERE isprocess = 0;
 
            INSERT INTO tbl_LeadAssignmentRuleConditions (

                FieldName, FieldOpText, FieldValue, FieldOpId, 

                FieldPlaceholder, FieldOpSign, lam_rule_id

            )

            VALUES (

                @FieldName, @FieldOpText, @FieldValue, @FieldOpId,

                @FieldPlaceholder, @FieldOpSign, @RuleId

            );
 
            UPDATE #tempCondtions SET isprocess = 1 WHERE sr = @sr;

        END

    END
 
    -- Audit log

    DECLARE @rowJson NVARCHAR(MAX) = (

        SELECT * FROM tbl_LeadAssignmentRules WHERE ID = @RuleId FOR JSON AUTO, INCLUDE_NULL_VALUES

    );
 
    IF @rowJson IS NOT NULL

    BEGIN

        EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId 

            @User_id = @UserID,

            @Activity_type = @activity,

            @ActionType = @action,

            @RowJson = @rowJson,

            @Table_name = 'tbl_LeadAssignmentRules';

    END

-- Final output

    IF @action = 'I'

        SELECT 'inserted' AS Result;

    ELSE IF @action = 'U'

        SELECT 'updated' AS Result;

END

 


GO

/* ============================================================
   Procedure: [dbo].[usp_las_processEnquiryRequest]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


------------------------------

CREATE   PROCEDURE [dbo].[usp_las_processEnquiryRequest]      
as      
begin      
 drop table if exists #tempLR      
      
 select top 10 * into  #tempLR from tbl_las_EnquiryRequest where is_processed = 0  and retryCount < 5    
  order by id desc      
       
 update t set  t.is_processed = 2, t.processed_on = GETDATE() from tbl_las_EnquiryRequest t       
  inner join #tempLR r on t.id = r.id      
      
 declare @Id bigint = 0, @EnqiryId bigint = 0, @errordesc nvarchar(max)       
      
 while(exists(select 1 from #tempLR where is_processed = 0))      
 begin      
  begin try      
   select @errordesc  = ''      
   select top 1 @Id = min(id) from #tempLR where is_processed = 0 and id > @Id       
   select @EnqiryId  = enquiryid from #tempLR where id = @Id       
   exec ups_las_UpdateEnquiryAssignmentUser @EntityId = @EnqiryId      
   update #tempLR set is_processed = 1, processed_on = GETDATE() where id = @Id       
  end try      
  begin catch      
   set @errordesc = error_message()      
   exec Mysms.dbo.usp_InsertErrorInfo       
   update #tempLR set is_processed = 3, processed_on = GETDATE(), error_description = @errordesc where id = @Id       
  end catch      
 end      
      
 update t set is_processed = (case when ISNULL(l.enquiryId, 0) = 0 then 0 else 1 end)       
  from #tempLR t left join tbl_lam_EnquiryAssignmentHistory(nolock) l on t.enquiryid = l.enquiryId      
      
 update t set  t.is_processed = r.is_processed, t.processed_on = r.processed_on, t.error_description = r.error_description,    
  t.retryCount = (t.retryCount + 1)    
 from tbl_las_EnquiryRequest t       
  inner join #tempLR r on t.id = r.id      
      
end 




GO

/* ============================================================
   Procedure: [dbo].[usp_las_processLeadRequest]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_las_processLeadRequest]      
as      
begin

	/*
	DBA
	Revised : 2025-05-28
	*/
	DECLARE @to_dt AS DATETIME = GETDATE() --'2025-05-24 16:35:30.640'
	DECLARE @from_dt AS DATETIME

	SET @from_dt = dateadd(hh,-6,@to_dt);

	DROP TABLE IF EXISTS #id_list;
	DROP TABLE IF EXISTS #tempLR;

	SELECT TOP (1000) id INTO #id_list from tbl_las_LeadRequest(nolock) 
	where is_processed = 0  AND retryCount < 5 and created_on> @from_dt AND created_on <= @to_dt 
		--id = 10951861
			ORDER BY id ASC

	OPTION (RECOMPILE);
	
	select lr.* into  #tempLR from tbl_las_LeadRequest lr 
	where lr.id IN
	(
		SELECT TOP (1000) t.id FROM #id_list t -- ORDER BY t.id DESC
	);
       
	update t set  t.is_processed = 2, t.processed_on = GETDATE() from tbl_las_LeadRequest t       
	inner join #tempLR r on t.id = r.id      
      
	declare @Id bigint = 0, @LeadId bigint = 0, @errordesc nvarchar(max) ,@createdon datetime       
      
	while(exists(select 1 from #tempLR where is_processed = 0))      
	begin      
		begin try      
			select @errordesc  = ''   
			select top 1 @Id = min(id) from #tempLR where is_processed = 0 and id > @Id       
			select @LeadId  = leadid,@createdon=created_on from #tempLR where id = @Id 
			if exists(select 1 from LeadInteractionHistory(nolock) where Id_Lead=@LeadId and CreatedOn>dateadd(minute,2,@createdon))
			begin
			update #tempLR set is_processed = 4, processed_on = GETDATE(),error_description='Lead already assignment pre processing. Dropped as may create conflict' where id = @Id
			end
			else
			begin
			exec ups_las_UpdateLeadAssignmentUser @EntityId = @LeadId      
			update #tempLR set is_processed = 1, processed_on = GETDATE() where id = @Id  
			end
		end try      
		begin catch      
			set @errordesc = error_message()      
			exec mysms.dbo.usp_InsertErrorInfo       
			update #tempLR set is_processed = 3, processed_on = GETDATE(), error_description = @errordesc where id = @Id       
		end catch      
	end      
      
	update t set is_processed = (case when t.is_processed=4 then t.is_processed when ISNULL(l.leadid, 0) = 0 then 0 else 1 end)       
	from #tempLR t left join tbl_lam_UserAssignmentHistory(nolock) l on t.leadid = l.leadid      
      
	update t set  
		t.is_processed = case when r.is_processed=4 then r.is_processed when r.is_processed =1 then r.is_processed else t.is_processed end,
		t.processed_on = r.processed_on,
		t.error_description = case when r.error_description is not null then r.error_description else t.error_description end,    
		t.retryCount = (t.retryCount + 1)    
	from tbl_las_LeadRequest t       
		inner join #tempLR r on t.id = r.id      
      
end 



GO

