/* ============================================================
   Procedure: [dbo].[usp_LE_MassOperations]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_LE_MassOperations]
(
	@jsonData		nvarchar(max)
)
