ELSE
BEGIN
    


	If(@Mode = 'Send SMS')
	Begin
	IF @IDS IS NULL OR LTRIM(RTRIM(@IDS)) = ''
        BEGIN
            -- Return message if @IDS is null or blank
            SELECT 'ID is null or blank' AS StatusMessage;
            RETURN;
        END
		SELECT 
    @MassOperationName = Mode,
    @UserID = UserId,
    @EntityType = EntityType,
    @MetaData = JSON_QUERY(MetaData),  -- Use JSON_QUERY to parse JSON from string
    @ScheduleDateTime = ScheduleDateTime
FROM 
    openjson(@jsonData)
WITH 
(
    Mode               nvarchar(100)  '$.Mode',
    UserId             bigint         '$.UserId',
    EntityType         nvarchar(100)  '$.EntityType',
    MetaData           nvarchar(max)  '$.MetaData',  
    ScheduleDateTime   nvarchar(100)  '$.ScheduleDateTime'
);

-- Extract message from MetaData JSON
    DECLARE @message NVARCHAR(MAX), @IsUnicode BIT;

    SELECT 
        @message = JSON_VALUE(@MetaData, '$.Message'),  -- Extract message
        @IsUnicode = JSON_VALUE(@MetaData, '$.IsUnicode') -- Extract Unicode flag
print concat('@@@@message =>',@message)
    -- Calculate message length and determine units
    DECLARE @messageLength INT, @noOfUnit INT;
    SET @messageLength = LEN(@message);

    SET @noOfUnit = CASE 
        WHEN @IsUnicode = 0 AND @messageLength <= 160 THEN 1
        WHEN @IsUnicode = 0 AND @messageLength > 160 THEN CEILING(@messageLength / 153.0)
        WHEN @IsUnicode = 1 AND @messageLength <= 70 THEN 1
        ELSE CEILING(@messageLength / 67.0)
    END;
	print concat('@@@@@NoOfUnit =>',@noOfUnit)

    -- Get SMS price per unit from pricing table
    DECLARE @price DECIMAL(18,4);
    SELECT TOP 1 @price = ISNULL(PTrns, 0)
    FROM dbo.Price_Base_SMS_RateDeduction BR (NOLOCK)
    WHERE BR.OriginCountryCode = '+91';
	print concat('@@@price =>',@price)
    -- Get the current balance
    DECLARE @CurrentBalance DECIMAL(18,4), @ParentIDAccount BIGINT, @deductedCost DECIMAL(18,4),@servicetype varchar(50);
    SET @servicetype = 'DomesticSMS';
    SET @ParentIDAccount = @UserID;  -- Assuming ParentIDAccount is same as UserID, modify if different.
	print concat('@@ParentIDAccount =>',@ParentIDAccount)
    SET @CurrentBalance = dbo.GetAvailableBalanceForService(@ParentIDAccount, 21);
	print concat('@CurrentBalance =>',@CurrentBalance)
    -- Split @IDS and count IDs (i.e., recipients)
    SET @IDS = REPLACE(REPLACE(@IDS, '{', ''), '}', '');
    
    DECLARE @recipientCount INT;
    SELECT @recipientCount = COUNT(*) FROM STRING_SPLIT(@IDS, ',');
	print concat('@@@recipientCount =>',@recipientCount)
    -- Calculate total cost
    SET @deductedCost = (@recipientCount * @noOfUnit * @price);
	print concat('@@@@deductedCost =>',@deductedCost)
    -- Check if there is sufficient balance
    IF @deductedCost > @CurrentBalance
    BEGIN
        SELECT 'Insufficient balance' AS StatusMessage;
        RETURN;
    END


			 INSERT INTO Tbl_MassOperationSummary (    
            MassOperationName, UserID,Parentid, CreatedDate,IsProcessed,Remarks, BatchStartTime, BatchEndTime, EntityType, isvalid,metadata,    
            ErrorDetails, SenderId,UrlTrack,TrackedUrl,SmsPlaceHolder, ScheduleDateTime    
        )    
        VALUES (    
            @MassOperationName,@UserID,@ParentID, GETDATE(), 0,NULL,null,NULL,@EntityType,1,@MetaData,NULL,NULL,NULL,NULL,NULL,@ScheduleDateTime    
        );    
			SELECT @NewBatchID = SCOPE_IDENTITY();  
			SET @IDS = REPLACE(REPLACE(@IDS, '{', ''), '}', '');  
  
        -- Split the @IDS string and insert into the @IDsTable table using STRING_SPLIT
        INSERT INTO @IDsTable (ID)
        SELECT CAST(value AS BIGINT)
        FROM STRING_SPLIT(@IDS, ',');
		INSERT INTO Tbl_MassOperationDetails (SummaryId, EntityID)  
        SELECT @NewBatchID, ID FROM @IDsTable; 
		 EXEC [dbo].[Usp_MassOperationLeadEnquiryProcess] @summary_batchid = @NewBatchID;  
		 SELECT 'Message saved' AS StatusMessage, @NewBatchID AS BatchId   

		 SET @rowJson = (SELECT * FROM Tbl_MassOperationSummary(nolock) WHERE batchid=@NewBatchID FOR JSON AUTO,INCLUDE_NULL_VALUES)
			SET @activity = 'Insert SendSms'
			SET @action = 'I'  
			SET @TableName = 'Tbl_MassOperationSummary'
	End

	If(@Mode = 'Send Mail')
	Begin
	IF @IDS IS NULL OR LTRIM(RTRIM(@IDS)) = ''
        BEGIN
            -- Return message if @IDS is null or blank
            SELECT 'ID is null or blank' AS StatusMessage;
            RETURN;
        END
		SELECT 
    @MassOperationName = Mode,
    @UserID = UserId,
    @EntityType = EntityType,
    @MetaData = JSON_QUERY(MetaData),  -- Use JSON_QUERY to parse JSON from string
    @ScheduleDateTime = ScheduleDateTime
FROM 
    openjson(@jsonData)
WITH 
(
    Mode               nvarchar(100)  '$.Mode',
    UserId             bigint         '$.UserId',
    EntityType         nvarchar(100)  '$.EntityType',
    MetaData           nvarchar(max)  '$.MetaData',  
    ScheduleDateTime   nvarchar(100)  '$.ScheduleDateTime'
);
-- Extract message from MetaData JSON
    DECLARE @message1 NVARCHAR(MAX), @IsUnicode1 BIT;

    SELECT 
        @message1 = JSON_VALUE(@MetaData, '$.Message'),  -- Extract message
        @IsUnicode1 = JSON_VALUE(@MetaData, '$.IsUnicode') -- Extract Unicode flag
print concat('@@@@message =>',@message1)
    -- Calculate message length and determine units
    DECLARE @messageLength1 INT, @noOfUnit1 INT;
    SET @messageLength1 = LEN(@message1);

    SET @noOfUnit1 = CASE 
        WHEN @IsUnicode1 = 0 AND @messageLength1 <= 160 THEN 1
        WHEN @IsUnicode1 = 0 AND @messageLength1 > 160 THEN CEILING(@messageLength1 / 153.0)
        WHEN @IsUnicode1 = 1 AND @messageLength1 <= 70 THEN 1
        ELSE CEILING(@messageLength1 / 67.0)
    END;
	print concat('@@@@@NoOfUnit =>',@noOfUnit1)

    -- Get SMS price per unit from pricing table
    DECLARE @price1 DECIMAL(18,4);
    SELECT TOP 1 @price1 = ISNULL(PTrns, 0)
    FROM dbo.Price_Base_SMS_RateDeduction BR (NOLOCK)
    WHERE BR.OriginCountryCode = '+91';
	print concat('@@@price =>',@price1)
    -- Get the current balance
    DECLARE @CurrentBalance1 DECIMAL(18,4), @ParentIDAccount1 BIGINT, @deductedCost1 DECIMAL(18,4),@servicetype1 varchar(50);
    SET @servicetype1 = 'DomesticSMS';
    SET @ParentIDAccount1 = @UserID;  -- Assuming ParentIDAccount is same as UserID, modify if different.
	print concat('@@ParentIDAccount =>',@ParentIDAccount1)
    SET @CurrentBalance1 = dbo.GetAvailableBalanceForService(@ParentIDAccount, 21);
	print concat('@CurrentBalance =>',@CurrentBalance1)
    -- Split @IDS and count IDs (i.e., recipients)
    SET @IDS = REPLACE(REPLACE(@IDS, '{', ''), '}', '');
    
    DECLARE @recipientCount1 INT;
    SELECT @recipientCount1 = COUNT(*) FROM STRING_SPLIT(@IDS, ',');
	print concat('@@@recipientCount =>',@recipientCount1)
    -- Calculate total cost
    SET @deductedCost1 = (@recipientCount1 * @price1);
	print concat('@@@@deductedCost =>',@deductedCost1)
    -- Check if there is sufficient balance
    IF @deductedCost1 > @CurrentBalance1
    BEGIN
        SELECT 'Insufficient balance' AS StatusMessage;
        RETURN;
    END
		
			 INSERT INTO Tbl_MassOperationSummary (    
            MassOperationName, UserID,Parentid, CreatedDate,IsProcessed,Remarks, BatchStartTime, BatchEndTime, EntityType, isvalid,metadata,    
            ErrorDetails, SenderId,UrlTrack,TrackedUrl,SmsPlaceHolder, ScheduleDateTime    
        )    
        VALUES (    
            @MassOperationName,@UserID,@ParentID, GETDATE(), 0,NULL,null,NULL,@EntityType,1,@MetaData,NULL,NULL,NULL,NULL,NULL,@ScheduleDateTime    
        );    
			SELECT @NewBatchID = SCOPE_IDENTITY();  
			SET @IDS = REPLACE(REPLACE(@IDS, '{', ''), '}', '');  
  
        -- Split the @IDS string and insert into the @IDsTable table using STRING_SPLIT
        INSERT INTO @IDsTable (ID)
        SELECT CAST(value AS BIGINT)
        FROM STRING_SPLIT(@IDS, ',');
		INSERT INTO Tbl_MassOperationDetails (SummaryId, EntityID)  
        SELECT @NewBatchID, ID FROM @IDsTable; 
		 EXEC [dbo].[Usp_MassOperationLeadEnquiryProcess] @summary_batchid = @NewBatchID;  
		 SELECT 'Mail Sent Successfully' AS StatusMessage, @NewBatchID AS BatchId   

		  SET @rowJson = (SELECT * FROM Tbl_MassOperationSummary(nolock) WHERE batchid=@NewBatchID FOR JSON AUTO,INCLUDE_NULL_VALUES)
			SET @activity = 'Insert SendMail'
			SET @action = 'I'  
