			SELECT @NewBatchID = SCOPE_IDENTITY();  
			SET @IDS = REPLACE(REPLACE(@IDS, '{', ''), '}', '');  
  
        -- Split the @IDS string and insert into the @IDsTable table using STRING_SPLIT
        INSERT INTO @IDsTable (ID)
        SELECT CAST(value AS BIGINT)
        FROM STRING_SPLIT(@IDS, ',');
		INSERT INTO Tbl_MassOperationDetails (SummaryId, EntityID)  
        SELECT @NewBatchID, ID FROM @IDsTable; 
		 EXEC [dbo].[Usp_MassOperationLeadEnquiryProcess] @summary_batchid = @NewBatchID;  
		 SELECT 'Call list added Successfully' AS StatusMessage, @NewBatchID AS BatchId   

		 SET @rowJson = (SELECT * FROM Tbl_MassOperationSummary(nolock) WHERE batchid=@NewBatchID FOR JSON AUTO,INCLUDE_NULL_VALUES)
			SET @activity = 'Call added'
			SET @action = 'I'  
			SET @TableName = 'Tbl_MassOperationSummary'
	End
	
	If(@Mode = 'Delete')

	Begin
		IF @IDS IS NULL OR LTRIM(RTRIM(@IDS)) = ''
        BEGIN
            -- Return message if @IDS is null or blank
            SELECT 'ID is null or blank' AS StatusMessage;
            RETURN;
        END
		SELECT 
    @MassOperationName = Mode,
    @UserID = UserId,
    @EntityType = EntityType,
    @MetaData = JSON_QUERY(MetaData),  -- Use JSON_QUERY to parse JSON from string
    @ScheduleDateTime = ScheduleDateTime
FROM 
    openjson(@jsonData)
WITH 
(
    Mode               nvarchar(100)  '$.Mode',
    UserId             bigint         '$.UserId',
    EntityType         nvarchar(100)  '$.EntityType',
    MetaData           nvarchar(max)  '$.MetaData',  
    ScheduleDateTime   nvarchar(100)  '$.ScheduleDateTime'
);

		
			 INSERT INTO Tbl_MassOperationSummary (    
            MassOperationName, UserID,Parentid, CreatedDate,IsProcessed,Remarks, BatchStartTime, BatchEndTime, EntityType, isvalid,metadata,    
            ErrorDetails, SenderId,UrlTrack,TrackedUrl,SmsPlaceHolder, ScheduleDateTime    
        )    
        VALUES (    
            @MassOperationName,@UserID,@ParentID, GETDATE(), 0,NULL,null,NULL,@EntityType,1,@MetaData,NULL,NULL,NULL,NULL,NULL,@ScheduleDateTime    
        );    
		print '@MetaData: ' + isnull(@MetaData,'') 
			SELECT @NewBatchID = SCOPE_IDENTITY();  
			SET @IDS = REPLACE(REPLACE(@IDS, '{', ''), '}', '');  
  
        -- Split the @IDS string and insert into the @IDsTable table using STRING_SPLIT
        INSERT INTO @IDsTable (ID)
        SELECT CAST(value AS BIGINT)
        FROM STRING_SPLIT(@IDS, ',');
		INSERT INTO Tbl_MassOperationDetails (SummaryId, EntityID)  
        SELECT @NewBatchID, ID FROM @IDsTable; 
		 EXEC [dbo].[Usp_MassOperationLeadEnquiryProcess] @summary_batchid = @NewBatchID;  
		 SELECT 'Deleted Successfully' AS StatusMessage, @NewBatchID AS BatchId   

		   SET @rowJson = (SELECT * FROM Tbl_MassOperationSummary(nolock) WHERE batchid=@NewBatchID FOR JSON AUTO,INCLUDE_NULL_VALUES)
			SET @activity = 'Delete'
			SET @action = 'I'  
			SET @TableName = 'Tbl_MassOperationSummary'
	End
	END

	If(isnull(@UserId,0) > 0)
	Begin
		EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId  
		,@Activity_type = @activity  
