/* ============================================================
   Procedure: [dbo].[usp_LE_UpdateApk]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

------------------------------------------------------

CREATE   PROC [dbo].[usp_LE_UpdateApk]  --- latest
(  
    @jsonData nvarchar(max)  
)  
AS  
BEGIN  
    DECLARE @ApkName nvarchar(1000) = '',   
            @ApkVersion int = '',   
            @IsActive int = '',   
            @Apktype nvarchar(30) = '',   
			@Projectname nvarchar(30) = '',   
            @ApkId int;  
  
    DECLARE @Status nvarchar(50),   
            @StatusMessage nvarchar(200);  
  
    BEGIN TRY  
        -- Parse JSON data  
        SELECT   
            @ApkName = ApkName,   
            @ApkVersion = ApkVersion,   
            @IsActive = IsActive,   
            @Apktype = Apktype  ,
			@ProjectName =Projectname
        FROM OPENJSON(@jsonData)  
        WITH   
        (  
            ApkName    nvarchar(1000) '$.ApkName',  
            ApkVersion int           '$.ApkVersion',  
            IsActive   int           '$.IsActive',  
            Apktype    nvarchar(30)  '$.Apktype',
			Projectname nvarchar(30)  '$.Projectname'
        );  
  
        -- Retrieve ApkId  
        SELECT @ApkId = id   
        FROM tbl_App_UrlVersion WITH (NOLOCK)   
        WHERE name = @ApkName AND apktype = @Apktype;  
  
        -- Insert or Update logic  
        IF ISNULL(@ApkId, 0) > 0  
        BEGIN  
            -- Update existing record  
            UPDATE tbl_App_UrlVersion  
            SET   
       name = @ApkName,  
                Version = @ApkVersion,  
                IsActive = @IsActive,  
                Apktype = @Apktype,
				 projectname = @ProjectName  
            WHERE id = @ApkId;  
  
            SET @Status = 'Success';  
            SET @StatusMessage = 'Record updated successfully.';  
        END  
        ELSE  
        BEGIN  
            -- Insert new record  
            INSERT INTO tbl_App_UrlVersion (name, Version, IsActive, Apktype,projectname,createddate)  
            VALUES (@ApkName, @ApkVersion, @IsActive, @Apktype,@ProjectName,getdate());  
  
            SET @Status = 'Success';  
            SET @StatusMessage = 'Record inserted successfully.';  
        END  
    END TRY  
    BEGIN CATCH  
         EXEC usp_InsertErrorInfo       
    END CATCH  
  
    -- Return status and status message  
    SELECT   
        @Status AS Status,   
        @StatusMessage AS StatusMessage;  
END;


GO

/* ============================================================
   Procedure: [dbo].[usp_lead_detail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- exec usp_lead_detail 559132            
-- exec usp_lead_detail 321217            
CREATE   PROCEDURE [dbo].[usp_lead_detail]            
(            
    @leadid bigint            
)            
as                                          
begin            
set nocount on                                      
declare @uid bigint                                      
declare @cnt_start int                                        
declare @cnt_max int                                        
declare @grp_id int                                        
declare @out varchar(max)=''                                         
select @uid=parentid from UserLeads where ID=@leadid;                                       
set @cnt_start=0;                                        
select distinct Group_Name, Group_ID into #group from Group_Detail where USER_ID=@uid                                        
select @cnt_max=COUNT(Group_Name) from #group                                        
while (@cnt_start < @cnt_max)                                        
begin                                        
select @grp_id=MAX(group_id) from #group;                                        
if(@cnt_start>0)                                        
begin                                        
select @out=@out+', '+group_name from #group where Group_ID=@grp_id;                                        
end                                        
else                                        
begin                                        
select @out=group_name from #group where Group_ID=@grp_id;                                        
end                                        
delete From #group where Group_ID=@grp_id;                                        
set @cnt_start=@cnt_start+1;                                        
end                                        
drop table #group;                                      
SELECT [ul].[leadno],             
       [ul].[personname],             
       [ul].[companyname],             
       trim(ISNULL([ul].[mobileno], '')) AS [mobileno],             
       [ul].[emailid],             
       [ul].[city],             
       [ul].[state],             
       [ul].[country],             
       [ul].[pincode],             
       [ul].[residentialaddress],             
         
    --[ud].[user_login] AS [assigned_to],   
    [ud].[user_login] + ' ('+[ud].[FName] + ' ' +[ud].[LName] + ')' AS [assigned_to],                
         
    [src].[name] AS [source],             
       ISNULL([md].[name], '') AS [medium],             
       ISNULL([cmp].[Name], '') AS [campaignname],             
       [ul].[remarks] AS [remark],             
       [fs].[followupstatus],             
       CONVERT(VARCHAR(20), [ul].[createdon], 113) AS [createdon],            
       CASE            
           WHEN [ul].[modifiedon] = ''            
           THEN CONVERT(VARCHAR(20), [ul].[createdon], 113)            
           WHEN [ul].[modifiedon] IS NULL            
           THEN CONVERT(VARCHAR(20), [ul].[createdon], 113)            
           ELSE CONVERT(VARCHAR(20), [ul].[modifiedon], 113)            
       END AS [modifiedon],             
       --CONVERT(VARCHAR(20), [ul].[followupdate], 20) AS [followupdate],             
       dbo.fn_getusertimefromindiantime(@uid, [ul].[followupdate]) AS [followupdate],             
       [ud1].[user_login] AS [createdby],             
       [ud2].[user_login] AS [modifiedby],             
       @out AS [groups],             
       trim(ISNULL([ul].[mobileno1], '')) AS [mobileno1],             
       trim(ISNULL([ul].[mobileno2], '')) AS [mobileno2],             
       ISNULL([ul].[emailid1], '') AS [emailid1],             
       ISNULL([ul].[emailid2], '') AS [emailid2],             
       [ul].[officeaddress],             
       [ul].[countrycode],             
       [ul].[AssignedTo] AS [assign_id],             
       [ul].[SourceName] AS [source_id],             
       [ul].[MediumName] AS [medium_id],             
       [ul].[CampaignName] AS [camp_id],             
       [ul].[FollowUpStatus] AS [follow_status_id],             
       [ul].[Products],             
       [ul].[AmountPaid],             
       ltrim(ISNULL([ul].[countrycode], '') + ' ' + trim(ISNULL([ul].[MobileNo], ''))) +          
   CASE WHEN trim(ISNULL([ul].[MobileNo1], '')) <> ''            
    THEN ', ' + ltrim(ISNULL([ul].[countrycode1], '') + ' ' + trim(ISNULL([ul].[MobileNo1], '')))            
    ELSE '' END +             
   CASE WHEN trim(ISNULL([ul].[MobileNo2], '')) <> ''            
    THEN ', ' + ltrim(ISNULL([ul].[countrycode2], '') + ' ' + trim(ISNULL([ul].[MobileNo2], '')))            
    ELSE '' END AS [phones],             
       ISNULL([ul].[CountryCode1], '') AS [CountryCode1],             
       ISNULL([ul].[CountryCode2], '') AS [CountryCode2],             
       ISNULL([ul].[EmailID], '') + CASE WHEN ISNULL([ul].[EmailID1], '') <> ''            
                                        THEN ', ' + ISNULL([ul].[EmailID1], '')            
                                        ELSE '' END         
          + CASE WHEN ISNULL([ul].[EmailID2], '') <> ''            
                                        THEN ', ' + ISNULL([ul].[EmailID2], '')            
                                        ELSE '' END AS [emails],             
       ISNULL([ul].[img_ext], '.abc') as [img_ext],          
 CASE WHEN ISNULL([UL].[CountryCode], '') <> '' THEN ISNULL([UL].[Countrycode], '') + ' ' + trim(ISNULL([UL].[MobileNo], ''))        
 ELSE '' END             
    +             
    CASE WHEN trim(ISNULL([UL].[Mobileno1], '')) <> ''   THEN ', ...'  ELSE '' END as Mobile,          
 CASE WHEN ISNULL([UL].[Emailid], '') <> ''     THEN ISNULL([UL].[Emailid], '')  ELSE '' END             
    +             
    CASE WHEN ISNULL([UL].[EmailID1], '') <> ''    THEN ', ...'     ELSE '' END  AS Email,        
 InitialRemarks=isnull([UL].InitialRemarks,''),      
 ul.whereAddress,       
 ul.latitude,       
 ul.longitude,      
 ( select STRING_AGG(tm.Tag, ',') from EntityTagMapping(nolock) etm inner join       
  TagMaster(nolock) tm on etm.TagID = tm.Id where Entity = 'lead' and EntityID = ul.ID       
 ) as TagNames      
FROM userleads ul(nolock) LEFT JOIN user_detail ud(nolock)         
ON  ul.assignedto = ud.user_id LEFT JOIN usersourcesettings src         
ON  ul.sourcename = src.sourceid LEFT JOIN usermediumsettings md         
ON  ul.mediumname = md.mediumid LEFT JOIN UserCampaignSettings cmp         
ON  ul.campaignname = cmp.CampaignID LEFT JOIN followup_status fs         
ON  ul.followupstatus = fs.id LEFT JOIN user_detail ud1         
ON  ul.createdby = ud1.user_id LEFT JOIN user_detail ud2         
ON  ul.modifiedby = ud2.user_id            
WHERE [ul].[id] = @leadid;                                       
end 


GO

