   Procedure: [dbo].[usp_lead_detail_with_leadno]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
-- exec usp_lead_detail_with_leadno 82, 335  
CREATE   PROCEDURE usp_lead_detail_with_leadno  
(  
@leadno bigint,        
@parentid bigint                  
)  
as                  
begin                  
set nocount on              
declare @uid bigint              
declare @cnt_start int                
declare @cnt_max int                
declare @grp_id int                
declare @out varchar(max)=''         
set @cnt_start=0;                
select distinct Group_Name, Group_ID into #group from Group_Detail where USER_ID=@parentid;                
select @cnt_max=COUNT(Group_Name) from #group                
while (@cnt_start < @cnt_max)                
begin                
select @grp_id=MAX(group_id) from #group;                
if(@cnt_start>0)                
begin                
select @out=@out+', '+group_name from #group where Group_ID=@grp_id;                
end                
else                
begin                
select @out=group_name from #group where Group_ID=@grp_id;                
end                
delete From #group where Group_ID=@grp_id;                
set @cnt_start=@cnt_start+1;                
end                
drop table #group;              
SELECT ul.leadno,   
       ul.personname,   
       ul.companyname,   
       ISNULL(ul.mobileno, '') AS mobileno,   
       ul.emailid,   
       ul.city,   
       ul.[state],   
       ul.country,   
       ul.pincode,   
       ul.residentialaddress,   
       ud.user_login AS assigned_to,   
       src.[name] AS [source],   
       ISNULL(md.[name], '') AS medium,   
       ISNULL(cmp.campaignname, '') AS campaignname,   
       ul.remarks AS remark,   
       fs.followupstatus,   
       CONVERT(VARCHAR(20), ul.createdon, 113) AS createdon,   
       CONVERT(VARCHAR(20), ul.modifiedon, 113) AS modifiedon,   
       CONVERT(VARCHAR(20), ul.followupdate, 113) AS followupdate,   
       ud1.user_login AS createdby,   
       ud2.user_login AS modifiedby,   
       @out AS groups,   
       ISNULL(ul.mobileno1, '') AS mobileno1,   
       ISNULL(ul.mobileno2, '') AS mobileno2,   
       ISNULL(ul.emailid1, '') AS emailid1,   
       ISNULL(ul.emailid2, '') AS emailid2,   
       ul.officeaddress,   
       ul.id,  
   isnull(ul.img_ext,'.abc') as img_ext,
   isnull	(ul.ProfileImgFileName, '')  as ProfileImgFileName
FROM userleads ul  
     LEFT JOIN user_detail ud ON ul.assignedto = ud.user_id  
     LEFT JOIN usersourcesettings src ON ul.sourcename = src.sourceid  
     LEFT JOIN usermediumsettings md ON ul.mediumname = md.mediumid  
     LEFT JOIN campaignmaster cmp ON ul.campaignname = cmp.id  
     LEFT JOIN followup_status fs ON ul.followupstatus = fs.id  
     LEFT JOIN user_detail ud1 ON ul.createdby = ud1.user_id  
     LEFT JOIN user_detail ud2 ON ul.modifiedby = ud2.user_id  
WHERE ul.LeadNo = @leadno  
      AND ul.ParentID = @parentid;            
end  


