/* ============================================================
   Procedure: [dbo].[Usp_LeadAttributes]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_LeadAttributes --335    
(    
  @ParentID bigint    
)     
as    
Begin    
     
   SELECT  distinct    
       
  (   
    case   
            when COLUMN_NAME = 'MobileNo' Then 'Mobile'  
      when COLUMN_NAME = 'MobileNo1' Then 'Mobile'  
      when COLUMN_NAME = 'MobileNo2' Then 'Mobile'  
      when COLUMN_NAME = 'EmailID' Then 'Email'  
      when COLUMN_NAME = 'EmailID1' Then 'Email'  
      when COLUMN_NAME = 'EmailID2' Then 'Email'  
            else COLUMN_NAME  
      end  
    
  ) COLUMN_NAME,    
     
     
   (     
     case when ((DATA_TYPE = 'varchar' or DATA_TYPE = 'nvarchar') and COLUMN_NAME <> 'NextStatusDate' ) then 'varchar'    
       when (COLUMN_NAME = 'PinCode' ) then 'varchar'    
    when (COLUMN_NAME = 'NextStatusDate') then 'datetime'     
          when ((COLUMN_NAME = 'SourceName') or (COLUMN_NAME = 'MediumName') or (COLUMN_NAME = 'CampaignName')) then 'varchar'    
    when ((COLUMN_NAME = 'CreatedBy') or (COLUMN_NAME = 'ModifiedBy') or  (COLUMN_NAME = 'AssignedTo') ) then 'varchar'     
          when (COLUMN_NAME = 'FollowUpStatus') then 'varchar'    
    when (DATA_TYPE = 'bigint') then  'numeric'    
    else DATA_TYPE    
    end     
    ) DATA_TYPE    
         
     
   FROM INFORMATION_SCHEMA.COLUMNS     
      WHERE TABLE_NAME = 'userleads'     
   and COLUMN_NAME    
   not in (    
          'ID','ProfileImgFileName','temp_id','img_ext','ResidentialAddress','OfficeAddress','InitialRemarks',    
          'ParentID','Remarks','Products','LeadImage','CountryCode','CountryCode1','CountryCode2','ModifiedOn',
	     'ModifiedBy','NextStatusDate','FollowupDate'

          )    
   union     
    select fieldname as COLUMN_NAME,    
         (      
         case when datatype = 'f' then 'numeric'     
            when datatype = 'v' then 'varchar'    
      when datatype = 'd' then 'datetime'    
      else 'varchar'    
         end         
         )  DATA_TYPE    
       
      from customfields(nolock)  where isnull(isActive,0) = 1 and  ParentID = @ParentID    
       
  End       
       
       
          


GO

