CREATE   PROCEDURE [dbo].[Usp_LeadConflictionDetails]  --8484994 , 42185      
(@EnquiryID BIGINT, @ParentID BIGINT)        
AS         
BEGIN      
 DECLARE @MobileNo      NVARCHAR(100),      
         @MobileNo1     NVARCHAR(100),      
         @MobileNo2     NVARCHAR(100),      
         @EmailID       NVARCHAR(100),      
         @EmailID1      NVARCHAR(100),      
         @EmailID2      NVARCHAR(100);         
 SELECT @MobileNo = MobileNo,      
        @MobileNo1     = MobileNo1,      
        @MobileNo2     = MobileNo2,      
        @EmailID       = EmailID,      
        @EmailID1      = EmailID1,      
        @EmailID2      = EmailID2      
 FROM   UserEnquiry with(nolock)     
 WHERE  EnquiryID      = @EnquiryID      
       
 SELECT [ID],      
        [LeadNo],      
        [PersonName],      
        [CompanyName],      
        [MobileNo],      
        [MobileNo1],      
        [MobileNo2],      
        [EmailID],      
        [EmailID1],      
        [EmailID2],      
        UL.City,      
        UL.[State],      
        UL.Country,      
        UL.CountryCode,     
        UL.CountryCode1,    
        UL.CountryCode2,     
        UL.PinCode,      
        UL.ResidentialAddress,      
        UL.OfficeAddress      
 FROM   UserLeads UL (nolock)      
 WHERE  UL.ParentID = @ParentID      
        AND (      
                ISNULL(NULLIF(ul.MobileNo, ''), '1') = ISNULL(NULLIF(@MobileNo, ''), '@')      
                OR ISNULL(NULLIF(ul.MobileNo, ''), '1') = ISNULL(NULLIF(@MobileNo1, ''), '@')      
                OR ISNULL(NULLIF(ul.MobileNo, ''), '1') = ISNULL(NULLIF(@MobileNo2, ''), '@')      
                OR ISNULL(NULLIF(ul.MobileNo1, ''), '1') = ISNULL(NULLIF(@MobileNo, ''), '@')      
                OR ISNULL(NULLIF(ul.MobileNo1, ''), '1') = ISNULL(NULLIF(@MobileNo1, ''), '@')      
                OR ISNULL(NULLIF(ul.MobileNo1, ''), '1') = ISNULL(NULLIF(@MobileNo2, ''), '@')      
                OR ISNULL(NULLIF(ul.MobileNo2, ''), '1') = ISNULL(NULLIF(@MobileNo, ''), '@')      
                OR ISNULL(NULLIF(ul.MobileNo2, ''), '1') = ISNULL(NULLIF(@MobileNo1, ''), '@')      
                OR ISNULL(NULLIF(ul.MobileNo2, ''), '1') = ISNULL(NULLIF(@MobileNo2, ''), '@')      
                OR ISNULL(NULLIF(ul.EmailID, ''), '1') = ISNULL(NULLIF(@EmailID, ''), '2')      
                OR ISNULL(NULLIF(ul.EmailID, ''), '1') = ISNULL(NULLIF(@EmailID1, ''), '2')      
                OR ISNULL(NULLIF(ul.EmailID, ''), '1') = ISNULL(NULLIF(@EmailID2, ''), '2')      
                OR ISNULL(NULLIF(ul.EmailID1, ''), '1') = ISNULL(NULLIF(@EmailID, ''), '2')      
                OR ISNULL(NULLIF(ul.EmailID1, ''), '1') = ISNULL(NULLIF(@EmailID1, ''), '2')      
                OR ISNULL(NULLIF(ul.EmailID1, ''), '1') = ISNULL(NULLIF(@EmailID2, ''), '2')      
                OR ISNULL(NULLIF(ul.EmailID2, ''), '1') = ISNULL(NULLIF(@EmailID, ''), '2')      
                OR ISNULL(NULLIF(ul.EmailID2, ''), '1') = ISNULL(NULLIF(@EmailID1, ''), '2')      
                OR ISNULL(NULLIF(ul.EmailID2, ''), '1') = ISNULL(NULLIF(@EmailID2, ''), '2')      
            )      
END    


