/* ============================================================
   Procedure: [dbo].[Usp_LeadConflictionForImportedFile_New]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


        
--------Modified By Abhishek Makkar ----------- Time: 8/18/2017 10:14:17 PM        
CREATE   PROCEDURE [dbo].[Usp_LeadConflictionForImportedFile_New]         
(        
    @ParentID               BIGINT,        
    @CountryCode            VARCHAR(50),        
    @CountryCode1           VARCHAR(50),        
    @CountryCode2           VARCHAR(50),        
    @MobileNo               VARCHAR(100),        
    @MobileNo1              VARCHAR(100),        
    @MobileNo2              VARCHAR(100),        
    @EmailID                VARCHAR(100),        
    @EmailID1               VARCHAR(100),        
    @EmailID2               VARCHAR(100)        
          
)        
AS        
BEGIN        
create table #temp(mobile varchar(100),email varchar(100))      
insert into #temp(mobile,email)    
select (cast(isnull(CountryCode,0) as nvarchar)+ cast(isnull(NULLIF(MobileNo,''),0) as nvarchar)),isnull(NULLIF(EmailID,''),0) from UserLeads where ParentID=@PARENTID      
union       
select (cast(isnull(CountryCode1,0) as nvarchar)+ cast(isnull(NULLIF(MobileNo1,''),0) as nvarchar)),isnull(NULLIF(EmailID1,''),0) from UserLeads where ParentID=@PARENTID     
union       
select (cast(isnull(CountryCode2,0) as nvarchar)+ cast(isnull(NULLIF(MobileNo2,''),0) as nvarchar)),isnull(NULLIF(EmailID2,''),0) from UserLeads where ParentID=@PARENTID      
    
if exists(select 1 from UserLeads where ParentID=@ParentID and (cast(isnull(@CountryCode,1) as nvarchar)+ cast(isnull(@MobileNo,1) as nvarchar) in (select Mobile from #temp)))      
BEGIN    
select 'Lead with Mobile ' + @mobileno + ' already exists'      
goto LeadNotInserted      
END    
if exists(select 1 from UserLeads where ParentID=@ParentID and (cast(isnull(@CountryCode1,1) as nvarchar)+ cast(isnull(@MobileNo1,1) as nvarchar) in (select Mobile from #temp)))     
BEGIN     
select 'Lead with Mobile ' + @mobileno1 + ' already exists'      
goto LeadNotInserted       
END    
if exists(select 1 from UserLeads where ParentID=@ParentID and (cast(isnull(@CountryCode2,1) as nvarchar)+ cast(isnull(@MobileNo2,1) as nvarchar) in (select Mobile from #temp)))      
BEGIN    
select 'Lead with Mobile ' + @mobileno2 + ' already exists'      
goto LeadNotInserted      
END    
if exists(select 1 from UserLeads where ParentID=@ParentID and (cast(isnull(NULLIF(@EmailID,''),1) as nvarchar) in (select email from #temp)))      
BEGIN    
select 'Lead with Email ' + @EmailID + ' already exists'      
goto LeadNotInserted      
END    
if exists(select 1 from UserLeads where ParentID=@ParentID and (cast(isnull(NULLIF(@EmailID1,''),1) as nvarchar) in (select email from #temp)))      
BEGIN    
select 'Lead with Email ' + @EmailID1 + ' already exists'      
goto LeadNotInserted       
END    
if exists(select 1 from UserLeads where ParentID=@ParentID and (cast(isnull(NULLIF(@EmailID2,''),1) as nvarchar) in (select email from #temp)))      
BEGIN    
select 'Lead with Email ' + @EmailID2 + ' already exists'      
goto LeadNotInserted      
END     
                 
 LeadNotInserted:       
END 



GO

