/* ============================================================
   Procedure: [dbo].[Usp_LeadDeleteById]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_LeadDeleteById]            
(                
@CSVID varchar(max),  
@Mode varchar(20)  
)                
AS                
BEGIN         
-- declare @CSVID varchar(max)='$$15660541',@Mode varchar(20)='criteria'  
  
--ID, IDList, Parent, User, Import, Criteria                 
 Declare @IDCollections VARCHAR(Max), @query nvarchar(max)                
 Declare @ParentID BIGINT                
 Declare @UserID BIGINT                
 Declare @AssignTo BIGINT                
--Declare @ImportRowId BIGINT = 0                
                
 Declare @BatchId bigint = 0                
 --Select @BatchId = (Isnull(Max(BatchId), 0) + 1) from Tbl_DataArchive(nolock)                
                
 Declare @RowField varchar(50) = ''                 
 Declare @RowId bigint = 0                 
                
 Drop TABLE if exists #TableData2   
 Drop TABLE if exists #TableData3   
 Drop TABLE if exists #TableData4   
  
 CREATE TABLE #TableData2 (ROWNUM int, IDS Varchar(Max))                
 CREATE TABLE #TableData3 (ID BIGINT)     
 CREATE TABLE #TableData4 (ID BIGINT)                
    
                
 if(LOWER(@Mode) = 'criteria')            
 Begin  
  set @BatchId = null   
  INSERT INTO #TableData2 (ROWNUM, IDS)            
  select ROW_NUMBER() OVER(ORDER BY (SELECT 1)) AS MyIndex, Item from fu_SplitString(@CSVID,'$')            
             
  select @ParentID = Cast(IDS as Bigint) from #TableData2 where ROWNUM = 1            
  select @UserID = Cast(IDS as Bigint) from #TableData2 where ROWNUM = 2            
             
  set @RowField = 'IDS'            
  set @RowId = @ParentID            
             
  INSERT INTO #TableData4 (ID)            
  Select Item from fu_SplitString((select IDS from #TableData2 where ROWNUM = 3), '#')            
 End            
          
 if(LOWER(@Mode) = 'parentid')                
 Begin                
 set @ParentID = CAST(@CSVID as bigint);            
 set @UserID = 0            
 set @RowField = 'ParentID'            
 set @RowId = @ParentID  
 set @BatchId = null   
            
 INSERT INTO #TableData4 (ID)            
 select ID from UserLeads (Nolock) where ParentID = @ParentID            
 End                
            
 if(LOWER(@Mode) = 'userid')                
 Begin                
 set @UserID = CAST(@CSVID as bigint);            
 select @ParentID = ParentId from User_Detail(nolock) where User_Id = @UserID            
 set @RowField = 'UserID'            
 set @RowId = @UserID 
 set @BatchId = null   
            
 INSERT INTO #TableData4 (ID)            
 select  ID from UserLeads(Nolock) where CreatedBy = @UserID            
 End                
                
 if(LOWER(@Mode) = 'assignto')                
 Begin                
 set @AssignTo = CAST(@CSVID as bigint);            
 select @ParentID = ParentId from User_Detail(nolock) where User_Id = @AssignTo            
 set @RowField = 'assignTo'            
 set @RowId = @AssignTo
 set @BatchId = null   
            
 INSERT INTO #TableData4 (ID)            
 select  ID from UserLeads(Nolock) where AssignedTo = @AssignTo                
 End            
           
 if(LOWER(@Mode) = 'batchid')                
 Begin 
 
  select @ParentID = Parentid from Tbl_MassOperationSummary(nolock) where BatchID=@CSVID            
  set @RowId = @ParentID        
  set @RowField = 'BatchID' 
   set @BatchId = @CSVID   
      
      
if @CSVID IS NOT NULL AND @CSVID <> 0          
  BEGIN          
   INSERT into #TableData4 (ID)            
   Select  EntityID as ID  from Tbl_MassOperationDetails where SummaryId=@CSVID          
             
   Update  Tbl_MassOperationSummary set BatchStartTime= GetDate()  where BatchID=@CSVID           
  
 --  insert into [10.0.0.135].MySMSConversations.dbo.tbl_MassBatchAction(BatchId,ActionType)    
 --values(@CSVID,'Delete')    
    
  
  END          
 End           
    
    
    
declare @td3 int=(select count(1) from #TableData4),@l_id bigint=0    
    
while @td3 >0    
begin    
    
print concat('Total records left to delete: ',@td3)    
insert into #TableData3(id)    
select top 500 id from #TableData4(nolock) where id>@l_id order by id    
    
    
If exists(Select * from UserEnquiry (nolock) UE INNER JOIN UserLeads(nolock) ul ON  ue.LeadNo = ul.LeadNo and ue.ParentID=ul.ParentID INNER JOIN #TableData3 tb3 ON  ul.ID = tb3.ID)            
Begin            
  Insert into Tbl_DataArchive (DatabaseName, TableName, BatchId, RowId, RowField, RowData, ActionType, CreatedDate)                
  Select 'Mysms', 'UserEnquiry', @BatchId,  @RowId, @RowField,     
 (Select UE.* from UserEnquiry (nolock) UE                
    INNER JOIN UserLeads(nolock) ul ON  ue.LeadNo = ul.LeadNo and ue.ParentID=ul.ParentID               
    INNER JOIN #TableData3 tb3 ON  ul.ID = tb3.ID                
  FOR JSON AUTO, INCLUDE_NULL_VALUES), 'U', GETDATE()                
                
  update UserEnquiry                 
  set IsOpen = 1, LeadNo = NULL                  
  where LeadNo in (select LeadNo from UserLeads (nolock) ul                 
  INNER JOIN #TableData3 tb3 ON  ul.ID = tb3.ID)               
  and ParentID = @ParentID               
 End            
            
If exists(SELECT * FROM  LeadInteractionHistory(nolock) kd INNER JOIN UserLeads(nolock) ul ON  ul.LeadNo = kd.LeadNo and ul.ParentID = kd.ParentID INNER JOIN #TableData3 tb3 ON  ul.ID = tb3.ID)            
Begin            
 Insert into Tbl_DataArchive (DatabaseName, TableName, BatchId, RowId, RowField, RowData, ActionType, CreatedDate)            
 Select 'Mysms', 'LeadInteractionHistory', @BatchId,  @RowId, @RowField,                
 (SELECT kd.* FROM LeadInteractionHistory(nolock) kd                 
