--exec Usp_LeadDeleteById @CSVID='36950$0$987942',@Mode='criteria'  
CREATE   PROCEDURE [dbo].[Usp_LeadDeleteById_while_loop]  
(      
@CSVID varchar(max),  
@Mode varchar(20)      
)      
AS      
BEGIN      
--ID, IDList, Parent, User, Import, Criteria       
 Declare @IDCollections VARCHAR(Max), @query nvarchar(max)
 Declare @ParentID BIGINT      
 Declare @UserID BIGINT      
 Declare @AssignTo BIGINT      
--Declare @ImportRowId BIGINT = 0      
      
 Declare @BatchId bigint = 0  
  DECLARE @existsFlag BIGINT;

DECLARE @sqlquery NVARCHAR(MAX);
 Select @BatchId = (Isnull(Max(BatchId), 0) + 1) from Tbl_DataArchive(nolock)      
      
 Declare @RowField varchar(50) = ''       
 Declare @RowId bigint = 0       
      
 CREATE TABLE #TableData2 (ROWNUM int, IDS Varchar(Max))      
 CREATE TABLE #TableData3 (ID BIGINT)      
      
 if(LOWER(@Mode) = 'criteria')      
 Begin      
          
 INSERT INTO #TableData2 (ROWNUM, IDS)                 
 select  ROW_NUMBER() OVER(ORDER BY (SELECT 1)) AS MyIndex,       
       Item from fu_SplitString(@CSVID,'$')      
      
select @ParentID = Cast(IDS as Bigint) from #TableData2 where ROWNUM = 1      
select @UserID = Cast(IDS as Bigint) from #TableData2 where ROWNUM = 2      
      
 set @RowField = 'IDS'      
 set @RowId = @ParentID      
          
 INSERT INTO #TableData3 (ID)                 
 Select Item from fu_SplitString((select IDS from #TableData2 where ROWNUM = 3), '#')      
       
 End      

declare @cd bigint
drop table if exists #insertedids
create table #insertedids(primaryid bigint,secondaryid bigint)

 if(LOWER(@Mode) = 'parentid')      
 Begin      
 set @ParentID = CAST(@CSVID as bigint);      
 set @UserID = 0      
 set @RowField = 'ParentID'      
 set @RowId = @ParentID      
      
 INSERT INTO #TableData3 (ID)                 
 select ID from UserLeads (Nolock) where ParentID = @ParentID      
 End      
  
 if(LOWER(@Mode) = 'userid')      
 Begin      

 set @UserID = CAST(@CSVID as bigint);      
 select @ParentID = ParentId from User_Detail(nolock) where User_Id = @UserID      
 set @RowField = 'UserID'      
 set @RowId = @UserID      
      
 INSERT INTO #TableData3 (ID)                 
 select ID from UserLeads(Nolock) where CreatedBy = @UserID      
      
 End      
      
 if(LOWER(@Mode) = 'assignto')      
 Begin      
 set @AssignTo = CAST(@CSVID as bigint);      
 select @ParentID = ParentId from User_Detail(nolock) where User_Id = @AssignTo      
 set @RowField = 'assignTo'      
 set @RowId = @AssignTo      
      
 INSERT INTO #TableData3 (ID)                 
 select ID from UserLeads(Nolock) where AssignedTo = @AssignTo      
      
 End      
  
If exists(Select 1 from UserEnquiry (nolock) UE INNER JOIN UserLeads(nolock) ul ON  ue.LeadNo = ul.LeadNo and ue.ParentID=ul.ParentID     
   INNER JOIN #TableData3 tb3 ON  ul.ID = tb3.ID)  
Begin  

select @cd=(Select count(1) from UserEnquiry (nolock) UE INNER JOIN UserLeads(nolock) ul ON  ue.LeadNo = ul.LeadNo and ue.ParentID=ul.ParentID     
   INNER JOIN #TableData3 tb3 ON  ul.ID = tb3.ID)
   while @cd>0
   begin
   insert into #insertedids(primaryid)
   select top 500 enquiryid  from UserEnquiry (nolock) UE INNER JOIN UserLeads(nolock) ul ON  ue.LeadNo = ul.LeadNo and ue.ParentID=ul.ParentID     
   INNER JOIN #TableData3 tb3 ON  ul.ID = tb3.ID order by EnquiryID

  Insert into Tbl_DataArchive (DatabaseName, TableName, BatchId, RowId, RowField, RowData, ActionType, CreatedDate)      
  Select 'MySMS', 'UserEnquiry', @BatchId,  @RowId, @RowField,      
 (Select UE.* from UserEnquiry (nolock) UE      
    INNER JOIN UserLeads(nolock) ul ON  ue.LeadNo = ul.LeadNo and ue.ParentID=ul.ParentID     
    INNER JOIN #TableData3 tb3 ON  ul.ID = tb3.ID
	inner join #insertedids i on i.primaryid=ue.enquiryid
  FOR JSON AUTO, INCLUDE_NULL_VALUES), 'U', GETDATE()      
      
  update u        
  set IsOpen = 1, LeadNo = NULL    from userenquiry u join #insertedids i on i.primaryid=u.enquiryid    
  
  truncate table #insertedids

  set @cd=@cd-500
  end
 End  
  
If exists(SELECT * FROM  LeadInteractionHistory(nolock) kd INNER JOIN UserLeads(nolock) ul ON  ul.LeadNo = kd.LeadNo and ul.ParentID = kd.ParentID INNER JOIN #TableData3 tb3 ON  ul.ID = tb3.ID)  
Begin  
select @cd=count(1) FROM  LeadInteractionHistory(nolock) kd INNER JOIN UserLeads(nolock) ul ON  ul.LeadNo = kd.LeadNo and ul.ParentID = kd.ParentID INNER JOIN #TableData3 tb3 ON  ul.ID = tb3.ID

while @cd>0
begin

insert into #insertedids(primaryid)
select top 500 kd.id FROM  LeadInteractionHistory(nolock) kd INNER JOIN UserLeads(nolock) ul ON  ul.LeadNo = kd.LeadNo and ul.ParentID = kd.ParentID INNER JOIN #TableData3 tb3 ON  ul.ID = tb3.ID
order by ID

 Insert into Tbl_DataArchive (DatabaseName, TableName, BatchId, RowId, RowField, RowData, ActionType, CreatedDate)      
 Select 'MySMS', 'LeadInteractionHistory', @BatchId,  @RowId, @RowField,      
 (SELECT kd.* FROM  LeadInteractionHistory(nolock) kd       
        INNER JOIN UserLeads(nolock) ul ON  ul.LeadNo = kd.LeadNo and ul.ParentID = kd.ParentID      
  INNER JOIN #TableData3 tb3 ON  ul.ID = tb3.ID   
  inner join #insertedids i on i.primaryid=kd.id
  FOR JSON AUTO, INCLUDE_NULL_VALUES), 'D', GETDATE()      
      
 DELETE kd     
 FROM  (select * from LeadInteractionHistory kd where exists (select 1 from #insertedids where primaryid=kd.id)) kd
  
  truncate table #insertedids

  set @cd=@cd-500
end
End  
           
If exists(SELECT * FROM  customfieldLeadvalue(nolock) cfv INNER JOIN UserLeads(nolock) ul ON  cfv.LeadID = ul.ID INNER JOIN #TableData3 tb3 ON  ul.ID = tb3.ID)  
Begin  
select @cd=count(1) from customfieldLeadvalue(nolock) cfv INNER JOIN UserLeads(nolock) ul ON  cfv.LeadID = ul.ID INNER JOIN #TableData3 tb3 ON  ul.ID = tb3.ID
while @cd>0
begin
insert into #insertedids(primaryid)
select top 500 cfv.recordid from customfieldLeadvalue(nolock) cfv INNER JOIN UserLeads(nolock) ul ON  cfv.LeadID = ul.ID INNER JOIN #TableData3 tb3 ON  ul.ID = tb3.ID
order by recordid

 Insert into Tbl_DataArchive (DatabaseName, TableName, BatchId, RowId, RowField, RowData, ActionType, CreatedDate)      
 select 'MySMS', 'customfieldLeadvalue', @BatchId,  @RowId, @RowField,      
 (SELECT cfv.* FROM  customfieldLeadvalue(nolock) cfv       
  INNER JOIN UserLeads(nolock) ul ON  cfv.LeadID = ul.ID            
  INNER JOIN #TableData3 tb3 ON  ul.ID = tb3.ID
  inner join #insertedids i on i.primaryid=cfv.recordID
     FOR JSON AUTO, INCLUDE_NULL_VALUES), 'D', GETDATE()      
      
 DELETE cfv  from
 (select * From customfieldLeadvalue c where exists (select 1 from #insertedids where primaryid=c.recordid)) cfv       

 truncate table #insertedids
 set @cd=@cd-500
 end
End  
       
