/* ============================================================
   Procedure: [dbo].[Usp_LeadEnquiryMassActivity]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_LeadEnquiryMassActivity]
@FieldId BIGINT = 0
	,@FieldName NVARCHAR(500) = ''
	,@FieldValue NVARCHAR(max)
	,@TableName NVARCHAR(500)
	,@UserId BIGINT = 0
	,@FilterExp NVARCHAR(MAX)
	as 
	BEGIN
	DECLARE @upid BIGINT;

	INSERT INTO fieldupdated (
		Tablename
		,FieldName
		,Oldvalue
		,NewValue
		,CreatedBy
		,fieldid
		)
	SELECT @TableName
		,@FieldName
		,''
		,@FieldValue
		,@UserId
		,@fieldid;

	SELECT @upid = SCOPE_IDENTITY();

	IF NOT (
			@FieldId = 0
			AND @FieldName = ''
			)
	BEGIN
		DECLARE @SQL NVARCHAR(MAX);
		DECLARE @ParentId BIGINT;

		/*Getting ParentID By User_ID*/
		SELECT @ParentId = ParentID
		FROM User_Detail
		WHERE User_ID = @UserId;

		BEGIN TRY
			DECLARE @TableName_LDACTV NVARCHAR(200) = @TableName;
			DECLARE @UserID_LDACTV BIGINT = @UserId
					,@ParentID_LDACTV BIGINT = @ParentId
					,@FieldName_LDACTV NVARCHAR(200) = @FieldName
					,@FieldValue_LDACTV NVARCHAR(500) = @FieldValue
					,@FilterExp_LDACTV NVARCHAR(MAX) = @FilterExp
					,@OldValue_LDACTV NVARCHAR(500) = ''
					,@NewValue_LDACTV NVARCHAR(500) = @FieldValue
					,@Query_LDACTV NVARCHAR(MAX) = ''
					,@ID NVARCHAR(50) = '0'
					,@customfieldName NVARCHAR(max)
					,@eventname nvarchar(max)
			SELECT @ParentId = ParentID FROM User_Detail WHERE User_ID = @UserId;
			SET @customfieldName = (
						SELECT STRING_AGG(CONCAT (
									'['
									,fieldname
									,']'
									), ',')
						FROM (
							SELECT DISTINCT fieldname
							FROM customfields(NOLOCK)
							WHERE ParentID = @ParentId
							) f
						)
				IF (@TableName_LDACTV = 'UserEnquiry' OR @TableName_LDACTV = 'customfieldEnquiryvalue')
			BEGIN
				
				set @eventname = 'Enquiry details edited'
				SET @Query_LDACTV = CONCAT (
						' select cast('
						,@fieldName
						,' as nvarchar), EnquiryID from ( SELECT ul.* '
						,iif(isnull(@customfieldName, '') <> '', ', c.*', '')
						,'  FROM UserEnquiry(NOLOCK) ul '
						,iif(isnull(@customfieldName, '') <> '', CONCAT (
								N' LEFT JOIN ( SELECT * FROM ( SELECT cfv.EnquiryID CFEnquiryid, cf.fieldname, cfv.fieldvalue FROM customfields(NOLOCK) '
								,N' cf INNER JOIN customfieldEnquiryvalue(NOLOCK) cfv ON cf.field_ID = cfv.fieldID  WHERE cf.ParentID = '
								,cast(@ParentId AS NVARCHAR)
								,' ) ipc PIVOT(MAX(fieldvalue) '
								,N' FOR fieldname IN( '
								,@customfieldName
								,N' )) p ) c ON ul.EnquiryID = c.CFEnquiryid '
								,''
								), '') + N' 
								left join UserSourceSettings(nolock) us on ul.SourceName = us.SourceID 
								left join UserMediumSettings(nolock) md on ul.MediumName = md.MediumID 
								left join UserCampaignSettings(nolock) cm on ul.CampaignName = cm.CampaignID 
								WHERE ul.ParentID = '
						,cast(@ParentId AS NVARCHAR)
						,' and '
						,replace(@FilterExp, 'LeadId', 'ul.ID ')
						,' ) myTab '
						)

				PRINT @Query_LDACTV
				END
				IF (@TableName_LDACTV = 'Userleads' OR @TableName_LDACTV = 'customfieldLeadvalue')
				BEGIN
				set @eventname = 'Lead details edited'
				SET @Query_LDACTV = CONCAT (
						' select cast('
						,@fieldName
						,' as nvarchar), ID from ( SELECT ul.* '
						,iif(isnull(@customfieldName, '') <> '', ', c.*', '')
						,'  FROM UserLeads(NOLOCK) ul '
						,iif(isnull(@customfieldName, '') <> '', CONCAT (
								N' LEFT JOIN ( SELECT * FROM ( SELECT cfv.LeadID, cf.fieldname, cfv.fieldvalue FROM customfields(NOLOCK) '
								,N' cf INNER JOIN customfieldLeadvalue(NOLOCK) cfv ON cf.field_ID = cfv.fieldID  WHERE cf.ParentID = '
								,cast(@ParentId AS NVARCHAR)
								,' ) ipc PIVOT(MAX(fieldvalue) '
								,N' FOR fieldname IN( '
								,@customfieldName
								,N' )) p ) c ON ul.ID = c.LeadID '
								,''
								), '') + N' LEFT JOIN lead_score_history_latest(NOLOCK) LS ON UL.ID = LS.LeadId left join UserSourceSettings(nolock) us on ul.SourceName = us.SourceID left join UserMediumSettings(nolock) md on ul.MediumName = md.MediumID left join UserCampaignSettings(nolock) cm on ul.CampaignName = cm.CampaignID left join User_Detail(nolock) ag on ul.AssignedTo = ag.User_ID LEFT JOIN FollowUp_Status(NOLOCK) fs on ul.FollowUpStatus = fs.ID  WHERE ul.ParentID = '
						,cast(@ParentId AS NVARCHAR)
						,' and '
						,replace(@FilterExp, 'LeadId', 'ul.ID ')
						,' ) myTab '
						)

				PRINT @Query_LDACTV
				END
				DROP TABLE

				IF EXISTS #temptbl
					DROP TABLE

				IF EXISTS #tblEventDescrb
					CREATE TABLE #temptbl (
						OldValue NVARCHAR(max)
						,ID BIGINT
						);

				INSERT INTO #temptbl
				EXECUTE sp_executesql @Query_LDACTV;
				
				--select * from #temptbl

				--SELECT @OldValue_LDACTV = OldValue
				--	,@ID = ID
				--FROM #temptbl;
			SELECT @OldValue_LDACTV = Case @FieldName 
										when 'MediumName' 
										Then (Select Name FROM UserMediumSettings where UserID=34594 and Cast(MediumID as nvarchar)=OldValue  ) 
										when 'SourceName' 
										Then (Select Name FROM UserSourceSettings where UserID=34594 and Cast(SourceID as nvarchar)=OldValue  ) 
										when 'CampaignName' 
										Then (Select Name FROM UserCampaignSettings where UserID=34594 and Cast(CampaignID as nvarchar)=OldValue  ) 
										Else OldValue
										END 
			 ,@ID = ID FROM #temptbl;  

  SELECT @NewValue_LDACTV = Case @FieldName 
			when 'MediumName' 
			Then (Select Name FROM UserMediumSettings where UserID=34594 and Cast(MediumID as nvarchar)=@NewValue_LDACTV  ) 
			when 'SourceName' 
			Then (Select Name FROM UserSourceSettings where UserID=34594 and Cast(SourceID as nvarchar)=@NewValue_LDACTV  ) 
			when 'CampaignName' 
			Then (Select Name FROM UserCampaignSettings where UserID=34594 and Cast(CampaignID as nvarchar)=@NewValue_LDACTV  ) 
			Else @NewValue_LDACTV
			END 
				--select  @OldValue_LDACTV,@ID    
				CREATE TABLE #tblEventDescrb (EVNT_Description NVARCHAR(MAX));

				IF (ISNULL(@ID, 0) > 0)
				BEGIN
					INSERT INTO #tblEventDescrb
					EXEC Usp_EventTemplate_DynamicVarReplacement @eventname
						,@UserID_LDACTV
						,''
						,''
						,@ID
						,''
						,NULL
						,0
						,0
						,''
						,''
						,0
						,''
						,0
						,NULL
						,@FieldName_LDACTV
						,@OldValue_LDACTV
