/* ============================================================
   Procedure: [dbo].[Usp_LeadExist_WithAgentParent]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_LeadExist_WithAgentParent --'7266895785',40856
(
  @ToMobileNo nvarchar(50),
  @AgentUserID bigint 
)
as
begin
      Declare @ParentID bigint = 0;
	  
	  select top 1 @ParentID = isnull(ParentID,0) from User_Detail as ud with(nolock) where ud.User_ID = @AgentUserID 
      
	  if(exists (select 1 from UserLeads as ul with(nolock) where ul.ParentID = @ParentID 
	                 and (  ul.MobileNo = @ToMobileNo or  ul.MobileNo1 = @ToMobileNo or  ul.MobileNo2 = @ToMobileNo ) 
				))
       begin
	      select 'true' as IsLeadExist
	   end
      else
	    begin   
		   select 'false' as IsLeadExist
		end

end




