/* ============================================================
   Procedure: [dbo].[Usp_LeadListTransferToCRM_New]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_LeadListTransferToCRM_New]                              
as                              
Begin                              
                           
 CREATE TABLE #TempLinked                                                              
   (                                                              
     Result VARCHAR(200)                                                              
    )                                
                             
  begin try                          
     INSERT INTO #TempLinked                                                              
     EXEC GetStatusofLinkedServer 'CRM'                                                              
    IF NOT EXISTS(                                                              
       SELECT 'x'                                                              
       FROM   #TempLinked                                                              
    )                                                   
 begin                              
 declare @max bigint= isnull((select MAX(ID) from LeadList where IsProcessed = 1),0)                           
 create table #output(smsleadlistid bigint)        
        
 insert into #output(smsleadlistid)        
 SELECT id FROM  LeadList (nolock) where IsProcessed = 0              
        
               
  insert into CRM.CRMDB.dbo.LeadList              
 --insert into CRMDB.dbo.LeadList              
   (              
    [Source]              
      ,[LeadDetails]              
      ,[Name]              
      ,[Mobile]              
      ,[EmailID]              
      ,[Company]              
      ,[Address]              
      ,[Remarks]              
      ,[ParentID]       
   ,Leadsettingid  
   ,CountryCode 
   ,welcome_wa_date
   )              
   SELECT               
       l.Source,      
   [LeadDetails]              
      ,[Name]              
      ,[Mobile]              
      ,[EmailID]              
      ,[Company]              
      ,[Address]              
      ,[Remarks]              
      ,[ParentID]      
   ,coalesce(l.leadsettingid,s.id,0)  
   ,l.CountryCode
   ,l.welcome_wa_date
  FROM  LeadList (nolock) l join #output o on l.id=o.smsleadlistid            
  left join CRM.CRMDB.dbo.leadsettings s on s.mode=l.source and s.status=1      
  where IsProcessed = 0  and (s.id is null or s.id=(select max(id) from CRM.CRMDB.dbo.leadsettings where mode=s.mode and status=1 and s.status=1))            
              
  update l set IsProcessed = 1 from LeadList l join #output o on l.id=o.smsleadlistid            
                       
  end                            
               
  end try                          
  begin catch                          
       exec Usp_inserterrorinfo                            
  end catch                          
               
               
    drop table #output           
    drop table #TempLinked                            
                            
 end


GO

/* ============================================================
   Procedure: [dbo].[Usp_LeadScoreDatatableFromJSON]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_LeadScoreDatatableFromJSON 
(
  @JSON nvarchar(max)
)
as
Begin

     SELECT Attribute,Operator,Value
FROM
    OPENJSON(@JSON)
    WITH
        (
		EventName nvarchar(50),
        Conditions NVARCHAR(MAX) AS JSON,
		Operation nvarchar(50),
		Points int
        ) AS a
		cross apply
		openjson(Conditions)
		with
		(
		Attribute nvarchar(50),Operator nvarchar(50),Value nvarchar(max)
		)

End


GO

/* ============================================================
   Procedure: [dbo].[usp_LeadTypeofActivityCountByLeadId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_LeadTypeofActivityCountByLeadId] (
	@LeadId	bigint
	,@UserId bigint
 )
AS
SET NOCOUNT ON

BEGIN TRY
	BEGIN
  --
  Declare @ParentId bigint = (Select top 1 ParentId from User_Detail(nolock) where User_ID = @UserId)

  --Followup Status
  Declare @val Varchar(MAX); 
  SELECT @val = COALESCE(@val + ', ' + FollowupStatus + ' ' + cast(Tcount as varchar(20)), FollowupStatus + ' ' + cast(Tcount as varchar(20)))  
  FROM    
        ( SELECT DISTINCT isnull(fus.FollowupStatus, 'Lead Created') FollowupStatus, count(ul.ParentID) Tcount
            FROM LeadInteractionHistory AS lih(NOLOCK)    
                 INNER JOIN UserLeads UL ON lih.ParentID = UL.ParentID    
                                            AND lih.LeadNo = UL.LeadNo    
                 LEFT JOIN FollowUp_Status AS fus(NOLOCK) ON fus.ID = lih.FollowUpStatus    
            WHERE UL.ID = @LeadId    
			group by fus.FollowupStatus
    ) AS tbl 

	--Note
	Declare @Taskval Varchar(MAX); 
  
	Declare @Mode varchar(10) = 'T'
	select @Taskval = cast(count(tsk.id) as varchar(50))
--, tsk.Title, (case 
--				when LOWER(tsk.Status) = 'completed' then 'Completed' else ( case 
--					when CAST(iif(tsk.IsTask = 1, tsk.EndDate, tsk.StartDate) as date) > CAST(GETDATE() as date) then 'Scheduled' 
--					when CAST(iif(tsk.IsTask = 1, tsk.EndDate, tsk.StartDate) as date) < CAST(GETDATE() as date) then 'Over Due' 
--					else 'Due Today' end
--				) end
--			) as TaskStatus

		from ( 
			select th.id, th.Title, th.Status, th.LeadId from tbl_tsk_TaskHistory(nolock) th where th.IsActive = 1 
				and 1 = ( case when @Mode = 'T' and th.IsTask = 1 then 1 when @Mode = 'A' and th.IsAppointment = 1 then 1 when @Mode = 'C' and th.TaskId = 4 then 1 else 0 end ) 
				and th.CreatedBy = @UserId and th.LeadId  = @LeadId
		union 
			select th.id, Title, th.Status, th.LeadId from tbl_tsk_TaskHistory(nolock) th where th.IsActive = 1 
				and 1 = ( case when @Mode = 'T' and th.IsTask = 1 then 1 when @Mode = 'A' and th.IsAppointment = 1 then 1 when @Mode = 'C' and th.TaskId = 4 then 1 else 0 end ) 
				and th.AssignedTo = @UserId  and th.LeadId  = @LeadId
		union 
			select th.id, Title, th.Status, th.LeadId from tbl_tsk_TaskHistory(nolock) th inner join tbl_tsk_CollaborationUserMapping(NOLOCK)
				tcm on th.Id = tcm.TaskHistoryId where th.IsActive = 1 
				and 1 = ( case when @Mode = 'T' and th.IsTask = 1 then 1 when @Mode = 'A' and th.IsAppointment = 1 then 1 when @Mode = 'C' and th.TaskId = 4 then 1 else 0 end ) 
				and tcm.User_Id = @UserId and th.CreatedBy = @UserId  
				and th.LeadId  = @LeadId
	) tsk inner join UserLeads(nolock) ul on tsk.LeadId = ul.ID 

	-- Appointment
	Declare @Appointval Varchar(MAX); 
  
	Declare @ModeA varchar(10) = 'A'
	select @Appointval = cast(count(tsk.id) as varchar(50))
--, tsk.Title, (case 
--				when LOWER(tsk.Status) = 'completed' then 'Completed' else ( case 
--					when CAST(iif(tsk.IsTask = 1, tsk.EndDate, tsk.StartDate) as date) > CAST(GETDATE() as date) then 'Scheduled' 
--					when CAST(iif(tsk.IsTask = 1, tsk.EndDate, tsk.StartDate) as date) < CAST(GETDATE() as date) then 'Over Due' 
--					else 'Due Today' end
--				) end
--			) as TaskStatus

		from ( 
			select th.id, th.Title, th.Status, th.LeadId from tbl_tsk_TaskHistory(nolock) th where th.IsActive = 1 
				and 1 = ( case when @ModeA = 'T' and th.IsTask = 1 then 1 when @ModeA = 'A' and th.IsAppointment = 1 then 1 when @ModeA = 'C' and th.TaskId = 4 then 1 else 0 end ) 
				and th.CreatedBy = @UserId and th.LeadId  = @LeadId
		union 
			select th.id, Title, th.Status, th.LeadId from tbl_tsk_TaskHistory(nolock) th where th.IsActive = 1 
				and 1 = ( case when @ModeA = 'T' and th.IsTask = 1 then 1 when @ModeA = 'A' and th.IsAppointment = 1 then 1 when @ModeA = 'C' and th.TaskId = 4 then 1 else 0 end ) 
				and th.AssignedTo = @UserId  and th.LeadId  = @LeadId
		union 
			select th.id, Title, th.Status, th.LeadId from tbl_tsk_TaskHistory(nolock) th inner join tbl_tsk_CollaborationUserMapping(NOLOCK)
				tcm on th.Id = tcm.TaskHistoryId where th.IsActive = 1 
				and 1 = ( case when @ModeA = 'T' and th.IsTask = 1 then 1 when @ModeA = 'A' and th.IsAppointment = 1 then 1 when @ModeA = 'C' and th.TaskId = 4 then 1 else 0 end ) 
				and tcm.User_Id = @UserId and th.CreatedBy = @UserId  
				and th.LeadId  = @LeadId
	) tsk inner join UserLeads(nolock) ul on tsk.LeadId = ul.ID 

	--Ticket
	Declare @StatDescval Varchar(MAX); 
select @StatDescval = COALESCE(@StatDescval + ', ' + Stat_Desc + ' ' + cast(Tcount as varchar(20)), Stat_Desc + ' ' + cast(Tcount as varchar(50)))
from(
	select Stat_Desc, count(Stat_Desc) Tcount from (
select ISNULL([stm].[Stat_Desc], 'New') AS [Stat_Desc] FROM Serv_TicketMaster(nolock) AS tm     
   LEFT OUTER JOIN Serv_Ticket_Stat_Mast(nolock) AS stm ON stm.Stat_ID = tm.STATUS 
   LEFT JOIN Serv_Group_Mast(nolock) AS GM ON GM.Groupid = tm.Assign_Group 
   LEFT OUTER JOIN dbo.Serv_User_Detail(nolock) AS ud ON ud.ser_user_id = tm.User_id 
   LEFT OUTER JOIN dbo.Serv_User_Detail(nolock) AS ag ON ag.ser_user_id = tm.AssignTo 
   left join V_sm_Serv_TicketHistory(nolock) VST ON tm.TicketId=VST.TicketId       
   WHERE [tm].deleted = 0 and tm.LeadId = @LeadId 
   and [tm].ParentId = @ParentId 
   )t
   group by Stat_Desc
   )q

--Invoice
Declare @StatInvval Varchar(MAX); 
select @StatInvval = COALESCE(@StatInvval + ', ' + Status + ' ' + cast(Tcount as varchar(20)), Status + ' ' + cast(Tcount as varchar(50)))
from(
	select Status, count(Status) Tcount from (
Select [Status] from MySMSInvoicing.dbo.invoices(nolock) invo where invo.status != 'deleted' and invo.leadid = @LeadId
)t
group by [Status]
)q

--Quotes
Declare @StatQuoval Varchar(MAX); 
select @StatQuoval = COALESCE(@StatQuoval + ', ' + Status + ' ' + cast(Tcount as varchar(20)), Status + ' ' + cast(Tcount as varchar(50)))
from(
	select Status, count(Status) Tcount from (
select status from MySMSInvoicing.dbo.quotes(nolock) quot where quot.status != 'deleted' and quot.leadid = @LeadId
)t
group by [Status]
)q

	Select * from (
	Select 'Lead Activities' Section, 
 cast(isnull((select count(leh.HistoryID) from tbl_LeadEventHistory(nolock) leh where leh.LeadID = @LeadId and UserId != 0), 0) as varchar(100)) + ' Record(s) ' TotalCountStatus
	union
	Select 'Web Forms' Section, cast(isnull((select count(w.EntryId) from WebEntryTbl(nolock) w where w.EntityName = 'lead' and w.EntityId = @LeadId ), 0) as varchar(100)) + ' Record(s) ' TotalCountStatus
	union
	Select 'Followup History' Section, (case when @val is null then cast(isnull((@val),0) as varchar(100)) + ' Record(s) '
	else cast(isnull((@val),0) as varchar(100)) end) TotalCountStatus
	union
	Select 'Notes' Section, cast(isnull((select count(n.noteID) from tbl_LeadNotes n(nolock) where n.ParentID = @ParentID and n.LeadID = @LeadID  and n.ISDeleted = 0), 0) as varchar(100)) + ' Record(s) ' TotalCountStatus
	union
	Select 'Documents' Section, cast(isnull((select count(d.DocUpID) from tbl_LeadDocumentUpload d(nolock) where d.ParentID = @ParentID and d.LeadID = @LeadID and d.ISDeleted = 0), 0) as varchar(100)) + ' Record(s) ' TotalCountStatus
	union
	Select 'Task' Section, @Taskval + ' Record(s) ' TotalCountStatus
	union
	Select 'Appointment' Section, @Appointval + ' Record(s) ' TotalCountStatus
	union
	Select 'Ticket' Section, (case when @StatDescval is null then cast(isnull((@StatDescval),0) as varchar(100)) + ' Record(s) '
	else cast(isnull((@StatDescval),0) as varchar(100)) end) TotalCountStatus
	union
	Select 'Invoice' Section, (case when @StatInvval is null then cast(isnull((@StatInvval),0) as varchar(100)) + ' Record(s) '
	else cast(isnull((@StatInvval),0) as varchar(100)) end) TotalCountStatus
	union
	Select 'Quotation' Section, (case when @StatQuoval is null then cast(isnull((@StatQuoval),0) as varchar(100)) + ' Record(s) '
	else cast(isnull((@StatQuoval),0) as varchar(100)) end) TotalCountStatus
	)t

	End
END TRY

BEGIN CATCH
	DECLARE @ErrorMessage NVARCHAR(4000);

	SELECT @ErrorMessage = ERROR_MESSAGE();

	RAISERROR (
			@ErrorMessage
			,16
			,1
			);
END CATCH

--DECLARE @rowJson NVARCHAR(MAX) = (
--		SELECT *
--		FROM tbl_WA_ProductOrderHistory WITH(NOLOCK)
--		WHERE OrderId = @OrderId
--		FOR JSON AUTO
--			,INCLUDE_NULL_VALUES
--		)

--IF @rowJson IS NOT NULL
--BEGIN
--	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @LeadId
--		,@Activity_type = 'tbl_WA_InsertProductOrderHistory'
--		,@ActionType = 'I'
--		,@RowJson = @rowJson
--		,@Table_name = 'tbl_WA_InsertProductOrderHistory'
--END



