/* ============================================================
   Procedure: [dbo].[usp_link_getorg]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_link_getorg] --17626,''--335,''      
(      
@usrid bigint,      
@srch varchar(250)      
)      
as      
begin      
if @srch=''      
select mobile_url_id,ProcessUrl_id,shorturl +'/'+final_url shorturl,Final_url,longurl,batchid,status,Mobile,CreatedDate,Parentid,DeleveryStatus,MessageID,Page_nm,location,shortkey,p_url,Convert(date,sm.CreatedDate) dte,     
case when DeleveryStatus= 0 then 'Not Delevered' else     
case when DeleveryStatus= 1     
then 'Delevered' else case when DeleveryStatus= 2 then 'Invalid No'  else  case    
when DeleveryStatus=3 then 'DND No' else '' end end end end as DelStatus    
 from dbo.Link_smsMobile sm     
where Parentid = @usrid and sm.status = 1 --and batchid=batchid      
order by dte desc, shorturl,longurl, sm.Mobile       
else      
select mobile_url_id,ProcessUrl_id,shorturl +'/'+final_url shorturl,Final_url,longurl,batchid,status,Mobile,CreatedDate,Parentid,DeleveryStatus,MessageID,Page_nm,location,shortkey,p_url, Convert(date,sm.CreatedDate) dte,    
case when DeleveryStatus= 0 then 'Not Delevered' else     
case when DeleveryStatus= 1     
then 'Delevered' else case when DeleveryStatus= 2 then 'Invalid No'  else  case    
when DeleveryStatus=3 then 'DND No' else '' end end end end as DelStatus    
from dbo.Link_smsMobile sm     
where Parentid = @usrid and sm.status = 1 and (sm.shorturl like @srch+'%' or sm.batchid like @srch+'%'      
or sm.Mobile like @srch+'%' or sm.longurl like  @srch+'%')      
order by dte desc, shorturl,longurl, sm.Mobile     
      
end    


GO

/* ============================================================
   Procedure: [dbo].[usp_link_updateOrgUrl]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_link_updateOrgUrl]
(
@BatchId  bigint,
@mobile_url_id  bigint,
@usrid bigint,
@url varchar(max),
@status int,
@opt int
)
as
begin
if @BatchId = 0
	begin
		if @opt =0 and @mobile_url_id = 0 --All record update
		begin
			if not exists(select 1 from dbo.link_orgUrl where org_url=@url)
				begin
					insert into	dbo.link_orgUrl(org_url,user_id) select @url, @usrid
				end
			
			update lm set longurl = @url 
			from dbo.Link_smsMobile lm 
				where lm.longurl = @url and lm.Parentid = @usrid
		end
		if @opt =1 and @mobile_url_id = 0  --All record Cancel
		begin
			
			update lm set  status = 0 
			from dbo.Link_smsMobile lm  
				where lm.longurl = @url and lm.Parentid = @usrid
		end
		if @opt =0 and @mobile_url_id > 0 
		begin
			update lm set  longurl = @url 
				from dbo.Link_smsMobile lm
					where mobile_url_id = @mobile_url_id
		end
		if @opt =1 and @mobile_url_id > 0 
		begin
			update lm set  status = 0 
				from dbo.Link_smsMobile lm
					where mobile_url_id = @mobile_url_id
		end
	end
	else
	begin
		if @opt =0 
		begin
			update lm set  longurl = @url 
				from dbo.Link_smsMobile lm
					where batchid = @BatchId
		end
		if @opt =1 
		begin
			update lm set  status = 0 
				from dbo.Link_smsMobile lm
					where batchid = @BatchId
		end	
	end
end



GO

