/* ============================================================
   Procedure: [dbo].[usp_LoadDashboard]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC dbo.usp_LoadDashboard (
	@ParentId BIGINT
	,@DashboardId BIGINT
	)
AS
BEGIN
	IF (@ParentId > 0)
	BEGIN
		SELECT *
		FROM tbl_Dashboard(NOLOCK)
		WHERE ParentId = @ParentId
	END
	ELSE IF (@DashboardId > 0)
	BEGIN
		SELECT *
		FROM tbl_Dashboard(NOLOCK)
		WHERE DashboardId = @DashboardId
	END

	IF @ParentId > 0
	BEGIN
		EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @parentId
			,@Activity_type = 'View_Dsbrd'
			,@ActionType = 'S'
			,@RowJson = ''
			,@Table_name = 'tbl_Dashboard'
	END
END



