/* ============================================================
   Procedure: [dbo].[usp_LoadDateRange]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROC [dbo].[usp_LoadDateRange]
(
	@RangeType varchar(10)='All' -- 'Forward','Backward'
)
As
Begin

	If(@RangeType='All')
	Begin
		Select * 
		From tbl_DateRange(nolock)
		Where IsActive=1 
	End

	If(@RangeType='Forward')
	Begin
		Select * 
		From tbl_DateRange(nolock)
		Where IsActive=1 and RangeCode like 'FORW%'
	End

	If(@RangeType='Backward')
	Begin
		Select * 
		From tbl_DateRange(nolock)
		Where IsActive=1 and RangeCode like 'BACK%' 
	End

End





GO

/* ============================================================
   Procedure: [dbo].[usp_LoadSixDaysMsgHistory]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_LoadSixDaysMsgHistory AS
SET NOCOUNT ON

DECLARE @minDate DATETIME
DECLARE @maxDate DATETIME
DECLARE @dayCount SMALLINT
BEGIN
	
	
	SELECT @minDate = MIN(MessageInsertDate)
	FROM SixDaysHistory

	SELECT @dayCount = COUNT(DISTINCT CONVERT(VARCHAR(10),MessageInsertDate,120))
	FROM SixDaysHistory
	

	IF @minDate IS NULL AND ISNULL(@dayCount,0)=0
	BEGIN
		SET @minDate = '01-JAN-1900' +' 23:59:59.997'  	
		ALTER PARTITION FUNCTION MessageDeliveryStatusPartitionRange () MERGE RANGE (@minDate)
	END
	ELSE IF @minDate IS NOT NULL AND ISNULL(@dayCount,0)=6
	BEGIN
		TRUNCATE TABLE SixDaysHistory_Bak

		ALTER TABLE SixDaysHistory
		SWITCH PARTITION 1
		TO SixDaysHistory_Bak
		SET @minDate = CONVERT(VARCHAR(10),@minDate,120)+' 23:59:59.997'

		ALTER PARTITION FUNCTION MessageDeliveryStatusPartitionRange () MERGE RANGE (@minDate)
	END
	
	SELECT @maxDate = MAX(MessageInsertDate)
	FROM SixDaysHistory

	SET @maxDate = ISNULL(@maxDate,'01-JAN-1900')
	
	SET @maxDate = CONVERT(VARCHAR(10),@maxDate,120)+' 23:59:59.997'
	
	INSERT INTO [dbo].[SixDaysHistory](MessageID,MessageRefID,Mobile,Message,SenderID,MessageStatus,
	MessageInsertDate,U_ID,BatchID,LastError,IsDND,Operator,Isallowdnd)
	SELECT MessageID,MessageRefID,Mobile,Message,SenderID,MessageStatus,MessageInsertDate,U_ID,BatchID,LastError,
	IsDND,Operator,Isallowdnd 
	FROM [dbo].[MessageDeliveryStatus](NOLOCK)
	WHERE messageinsertdate > @maxDate
	
	SELECT @maxDate = CONVERT(VARCHAR(10),MAX(MessageInsertDate),120)+' 23:59:59.997'
	FROM SixDaysHistory
	ALTER PARTITION SCHEME MessageDeliveryStatusPartitionScheme NEXT USED [PRIMARY]
	ALTER PARTITION FUNCTION MessageDeliveryStatusPartitionRange () split RANGE (@maxDate)	

END



