-- =============================================  
CREATE   PROCEDURE [dbo].[USP_LogoutStatus_MobileApp] --'9015396496'  
 @User_ID varchar(20),  
 @Mobile varchar(14)  
AS  
BEGIN  
   IF EXISTS(SELECT 'E' FROM DBO.User_Detail(NOLOCK) WHERE User_ID=@User_ID and Mobile=@Mobile)    
   begin  
     update User_Detail set Status=0 where User_ID=@User_ID and  Mobile=@Mobile  
    select 'Logout Successfully.' as Msg  
 end  
 else  
 begin  
    select 'User does not Exist.' as Error  
 end  
END  


