   Procedure: [dbo].[Usp_MailToLeadEvent]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_MailToLeadEvent    
(    
  @LeadID bigint,      
  @UserID bigint,      
  @Subject nvarchar(200),
  @Message nvarchar(max)        
  
)    
as    
Begin    
     
   Declare @EventID bigint = 0     
   Declare @EventName nvarchar(500) = 'Mail sent to lead'      
   Declare @EventTemplate nvarchar(max) = ''    
   Declare @UserName nvarchar(200) = ''  
   Declare @EmailID nvarchar(500) = ''  
   Declare @ParentID bigint = 0    
	
  select @ParentID = isnull(ParentID,0) from user_detail(nolock) where user_Id = @UserID  
	   
  select @UserName = isnull(user_login,'') from user_detail  where USER_ID = @UserID         
  select @EmailID = isnull(@EmailID,'') from UserLeads where ID = @LeadID  
    
 select @EventID = isnull(ID,0) ,@EventTemplate = isnull(EventTemplate,'')  from ActivityMaster where EventName = @EventName     
   if(@EventID > 0)    
    Begin  
     
	 if( rtrim(ltrim(@EmailID)) <> '' )
       Begin
          
		  select @EventTemplate = replace(replace(replace(replace(@EventTemplate,'#username#',@UserName),'#mailtemplate#',@Message),'#MailSubject#',@Subject),'#emailid#',@EmailID)
          
		    exec UspSaveLeadActivity @LeadID,@UserID,@ParentID,@EventTemplate,@EventID  
       End


    End    
    
End


