/* ============================================================
   Procedure: [dbo].[Usp_MaintainLoginStatus_API]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_MaintainLoginStatus_API
(      
   @UserID bigint,      
   @DeviceID nvarchar(500)       
)      
as      
Begin      
      
    if exists(select 1 from user_detail where USER_ID=@UserID and ISNULL(LastLogin1,'')= '')      
    Begin      
       update user_detail set LastLogin1 = GETDATE() , isverify = 1, DeviceID = @DeviceID where USER_ID = @UserID and ISNULL(LastLogin1,'')= ''             
       exec usp_insertloginhistory @UserID,null,null,@DeviceID,'Login',null        
    End       
    else if(exists(select 1 from user_detail where USER_ID=@UserID and ISNULL(LastLogin1,'') <> ''))      
    begin      
		UPDATE a                
		SET    a.LastLogin2 = a.LastLogin1,  a.DeviceID = @DeviceID,  a.LastLogin1 = GETDATE()              
        from User_Detail a              
		WHERE  a.USER_ID = @UserID        
		
		exec usp_insertloginhistory @UserID,null,null,@DeviceID,'Login',null
	 end      
      
End



