/* ============================================================
   Procedure: [dbo].[usp_ManageExpressionField]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



 /*          
 Formula for custom formula field          
 select * from UserLeads(nolock) where Id = 1049610          
 select * from UserEnquiry(nolock) where EnquiryID = 4156388          
 */          
          
CREATE   PROCEDURE usp_ManageExpressionField(          
 @EntityId bigint,          
 @ParentId bigint,           
 @entityName nvarchar(255)          
 )          
as          
begin          
          
-- declare @EntityId bigint =1049610 , @ParentId bigint = 34594, @entityName nvarchar(255) = 'lead'          
 SET NOCOUNT ON;           
    
    
 drop table if exists #tempExpression             
 select cf.field_ID, cf.ParentID, cf.fieldname, cf.defaultValue, tf.name as [formula_name], tf.NoOfParam, tf.return_type,           
  0 as [isProcess] into #tempExpression           
  from customfields(nolock) cf           
   inner join tbl_Formulas(nolock) tf on cf.formulaId = tf.id          
   where cf.ParentID = @ParentId and cf.isActive = 1 and cf.datatype = 'e'   
     
 while(exists(select * from #tempExpression where isProcess = 0))          
 begin   
   
   
  declare @field_ID bigint, @fieldname nvarchar(255), @defaultValue sql_variant, @formula_name nvarchar(255), @NoOfParam int,          
  @isProcess int, @ReturnType nvarchar(255)          
          
  select top 1 @field_ID = field_ID, @fieldname = fieldname, @defaultValue = defaultValue,          
   @formula_name = LTRIM(RTRIM(LOWER(formula_name))), @NoOfParam = NoOfParam, @ReturnType = return_type          
  from #tempExpression   where isProcess = 0          
          
  --select * from #tempExpression  
  --begin try          
   declare @tempParamValue as funcParamValueType          
   --add by anit  
   delete from @tempParamValue  
  
   insert into @tempParamValue (           
     id, fParamId, ParamName, ParamType, ParamValue, fieldId, ParentId, created_on, isProcess           
    )          
    select           
     pv.id, pv.fieldId, pv.ParamName, pv.ParamType, pv.ParamValue, pv.fieldId, pv.ParentId, pv.created_on, 0 as isProcess           
    from tbl_customFieldFormulaParamMapping(nolock) pv where fieldId = @field_ID          
  
  --select * from @tempParamValue  
            
 --select * from @tempParamValue        
        
        
   while(exists(select 1 from @tempParamValue where isProcess = 0))          
   begin          
    declare @tpvId bigint, @fParamId bigint, @ParamName nvarchar(255), @ParamType nvarchar(255), @ParamValue nvarchar(max)          
    select top 1 @tpvId = id, @fParamId = fParamId, @ParamName = ParamName, @ParamType = ParamType, @ParamValue = ParamValue          
     from @tempParamValue where isProcess = 0           
          
    drop table  if exists #tempColName          
          
    --print @tpvId          
          
    select *, @entityName as [EntityName] into #tempColName from           
     ( select LOWER(COLUMN_NAME) as colName, 'predefined' as [columnType] from INFORMATION_SCHEMA.COLUMNS(nolock) colName          
       where TABLE_NAME = case when @entityName = 'lead'          
        then  'UserLeads' else 'UserEnquiry'  end          
      union           
      select fieldname as colName, 'custom' as [columnType] from customfields(nolock) where ParentID = 34594          
     ) as col           
          
    if(exists( select * from #tempColName c where c.colName = (           
      select REPLACE(ParamValue, '#', '') from tbl_customFieldFormulaParamMapping(nolock) where id = @tpvId          
     )))          
    begin          
     declare @colName nvarchar(255), @columType nvarchar(255), @paramQuery nvarchar(max)          
     select @colName = colName, @columType = columnType from #tempColName c where c.colName = (           
      select REPLACE(ParamValue, '#', '') from tbl_customFieldFormulaParamMapping(nolock) where id = @tpvId )          
          
     declare @retParamValue sql_variant, @ParmDefinition nvarchar(500)          
     set @ParmDefinition = N'@retValInnerOut sql_variant OUTPUT';            
          
     set @paramQuery = case when @entityName  = 'lead'          
          then case           
           when @columType = 'predefined'          
            then concat( 'select @retValInnerOut = ',  @colName, ' from UserLeads(nolock) where ID = ', @EntityId)          
           when @columType = 'custom'          
            then concat('select @retValInnerOut = fieldvalue from customfieldLeadvalue(nolock) where LeadID = ', @EntityId, ' and fieldID = ', @field_ID)          
           end           
          when @entityName  = 'enquiry'          
          then case           
           when @columType = 'predefined'          
            then concat( 'select @retValInnerOut = ',  @colName, ' from UserEnquiry(nolock) where EnquiryID = ', @EntityId)          
           when @columType = 'custom'          
            then concat('select @retValInnerOut = fieldvalue from customfieldEnquiryvalue(nolock) where EnquiryID = ', @EntityId, ' and fieldID = ', @field_ID)          
          end          
         end           
             
     --print @paramQuery          
 execute sp_executesql @paramQuery, @ParmDefinition, @retValInnerOut=@retParamValue OUTPUT;            
     update @tempParamValue set ParamValue = isnull(cast(@retParamValue as nvarchar(max)), '') where id = @tpvId          
        
    end          
          
    update @tempParamValue set isProcess = 1 where id = @tpvId          
   end          
          
  -- select * from @tempParamValue          
        
  --print 'h1';      
      
   declare @retFormulaValue sql_variant = ( case           
    when @formula_name = 'max'           
     then ( select max(ParamValue) from @tempParamValue)          
    when @formula_name = 'min'           
     then ( select min(ParamValue) from @tempParamValue)          
    when @formula_name = 'avg'           
     then ( select avg(cast(ParamValue as float)) from @tempParamValue)          
    when @formula_name = 'log'           
     then ( select top 1 log(ParamValue) from @tempParamValue)          
    when @formula_name = 'floor'           
     then ( select top 1 floor(ParamValue) from @tempParamValue)          
    when @formula_name = 'ceil'           
     then ( select top 1 CEILING(ParamValue) from @tempParamValue)             
    when @formula_name = 'square root'           
     then ( select top 1 dbo.funcGetSquareRoot( @tempParamValue, @ReturnType) )          
    when @formula_name = 'exponential function'           
     then ( select dbo.funcGetExponentialFunction( @tempParamValue, @ReturnType) )          
    when @formula_name = 'power function'           
     then ( select dbo.funcPower( @tempParamValue, @ReturnType) )          
    when @formula_name = 'random'           
     then ( select dbo.funcRandom( @tempParamValue, @ReturnType) )          
    when @formula_name = 'charat'           
     then ( select dbo.funcCharAt( @tempParamValue, @ReturnType) )          
    when @formula_name = 'concat'           
     then ( select dbo.funcConcat( @tempParamValue, @ReturnType) )          
    when @formula_name = 'endswith'           
     then ( select dbo.funcEndWiths( @tempParamValue, @ReturnType) )          
    when @formula_name = 'equals'           
     then ( select dbo.funcEqualsTo( @tempParamValue, @ReturnType) )          
    when @formula_name = 'equalsignorecase'           
     then ( select dbo.funcEqualsTo( @tempParamValue, @ReturnType) )          
    when @formula_name = 'indexof'           
     then ( select dbo.funcEqualsTo( @tempParamValue, @ReturnType) )          
    when @formula_name = 'lastindexof'           
     then ( select dbo.funcLastIndexOf( @tempParamValue, @ReturnType) )          
    when @formula_name = 'length'           
     then ( select dbo.funcLength( @tempParamValue, @ReturnType) )          
    when @formula_name = 'replace'           
     then ( select dbo.funcReplace( @tempParamValue, @ReturnType) )          
    when @formula_name = 'annualpercentageyield'           
     then ( select dbo.funcAnnualPercentageYield( @tempParamValue, @ReturnType) )          
    when @formula_name = 'compoundinterest'           
     then ( select dbo.funcCompoundInterest( @tempParamValue, @ReturnType) )          
    when @formula_name = 'simpleinterest'           
     then ( select dbo.funcSimpleInterest( @tempParamValue, @ReturnType) )          
    when @formula_name = 'realrateofreturn'           
     then ( select dbo.funcRealRateOfReturn( @tempParamValue, @ReturnType) )          
    when @formula_name = 'netassetvalue'           
     then ( select dbo.funcNetAssetValue( @tempParamValue, @ReturnType) )          
    when @formula_name = 'averagecollectionperiod'           
     then ( select dbo.funcAverageCollectionPeriod( @tempParamValue, @ReturnType) )          
    when @formula_name = 'contributionmargin'           
     then ( select dbo.funcDaysInInventory( @tempParamValue, @ReturnType) )          
    when @formula_name = 'daysininventory'           
     then ( select dbo.funcDaysInInventory( @tempParamValue, @ReturnType) )          
 when @formula_name = 'futurevalue'           
     then ( select dbo.funcFutureValue( @tempParamValue, @ReturnType) )          
    when @formula_name = 'presentvalue'           
     then ( select dbo.funcPresentValue( @tempParamValue, @ReturnType) )          
    when @formula_name = 'ruleof72'           
     then ( select dbo.funcRuleOf72( @tempParamValue, @ReturnType) )           
   end)  
     
  --print cast(@retFormulaValue  as nvarchar(500))       
  --print 'h2';      
        
  --end try          
  --begin catch          
  -- exec dbo.usp_InsertErrorInfo          
  -- set @retFormulaValue = ''          
  --end catch          
           
  --select @formula_name, @retFormulaValue          
          
  if(len(cast(@retFormulaValue as nvarchar(max)))  =  0)          
  begin          
   set @retFormulaValue = @defaultValue          
  end          
          
  if(@entityName = 'lead')          
  begin          
   if(exists(select 1 from customfieldLeadvalue(nolock) where LeadID = @EntityId and fieldID = @field_ID))          
   begin          
    update customfieldLeadvalue set fieldvalue = cast(@retFormulaValue as decimal(20,6)) where LeadID = @EntityId and fieldID = @field_ID          
   end          
   else          
   begin          
           
    insert into customfieldLeadvalue( LeadID, fieldID, fieldvalue)          
     values( @EntityId, @field_ID, cast(@retFormulaValue as decimal(20,6)) )          
   end          
  end          
          
  if(@entityName = 'enquiry')          
  begin          
   if(exists(select 1 from customfieldEnquiryValue  (nolock) where EnquiryID = @EntityId and fieldID = @field_ID))          
   begin          
    update customfieldEnquiryValue set fieldvalue = @retFormulaValue where EnquiryID = @EntityId and fieldID = @field_ID          
   end          
   else          
   begin          
    insert into customfieldEnquiryValue( EnquiryID, fieldID, fieldvalue)          
     values( @EntityId, @field_ID, @retFormulaValue )          
   end          
  end          
          
  update #tempExpression set isProcess = 1 where field_ID = @field_ID          
 end          
end 




GO

