    when @formula_name = 'indexof'   
     then ( select dbo.funcEqualsTo( @tempParamValue, @ReturnType) )  
    when @formula_name = 'lastindexof'   
     then ( select dbo.funcLastIndexOf( @tempParamValue, @ReturnType) )  
    when @formula_name = 'length'   
     then ( select dbo.funcLength( @tempParamValue, @ReturnType) )  
    when @formula_name = 'replace'   
     then ( select dbo.funcReplace( @tempParamValue, @ReturnType) )  
    when @formula_name = 'annualpercentageyield'   
     then ( select dbo.funcAnnualPercentageYield( @tempParamValue, @ReturnType) )  
    when @formula_name = 'compoundinterest'   
     then ( select dbo.funcCompoundInterest( @tempParamValue, @ReturnType) )  
    when @formula_name = 'simpleinterest'   
     then ( select dbo.funcSimpleInterest( @tempParamValue, @ReturnType) )  
    when @formula_name = 'realrateofreturn'   
     then ( select dbo.funcRealRateOfReturn( @tempParamValue, @ReturnType) )  
    when @formula_name = 'netassetvalue'   
     then ( select dbo.funcNetAssetValue( @tempParamValue, @ReturnType) )  
    when @formula_name = 'averagecollectionperiod'   
     then ( select dbo.funcAverageCollectionPeriod( @tempParamValue, @ReturnType) )  
    when @formula_name = 'contributionmargin'   
     then ( select dbo.funcDaysInInventory( @tempParamValue, @ReturnType) )  
    when @formula_name = 'daysininventory'   
     then ( select dbo.funcDaysInInventory( @tempParamValue, @ReturnType) )  
    when @formula_name = 'futurevalue'   
     then ( select dbo.funcFutureValue( @tempParamValue, @ReturnType) )  
    when @formula_name = 'presentvalue'   
     then ( select dbo.funcPresentValue( @tempParamValue, @ReturnType) )  
    when @formula_name = 'ruleof72'   
     then ( select dbo.funcRuleOf72( @tempParamValue, @ReturnType) )   
   end)  
   
  --end try  
  --begin catch  
  -- exec dbo.usp_InsertErrorInfo  
  -- set @retFormulaValue = ''  
  --end catch  
   
  -- select @formula_name, @retFormulaValue  
  
  if(len(cast(@retFormulaValue as nvarchar(max)))  =  0)  
  begin  
   set @retFormulaValue = @defaultValue  
  end  
  
  if(@entityName = 'lead')  
  begin  
   if(exists(select 1 from customfieldLeadvalue(nolock) where LeadID = @EntityId and fieldID = @field_ID))  
   begin  
    update customfieldLeadvalue set fieldvalue = @retFormulaValue where LeadID = @EntityId and fieldID = @field_ID  
   end  
   else  
   begin  
    insert into customfieldLeadvalue( LeadID, fieldID, fieldvalue)  
     values( @EntityId, @field_ID, @retFormulaValue )  
   end  
  end  
  
  if(@entityName = 'enquiry')  
  begin  
   if(exists(select 1 from customfieldEnquiryValue  (nolock) where EnquiryID = @EntityId and fieldID = @field_ID))  
   begin  
    update customfieldEnquiryValue set fieldvalue = @retFormulaValue where EnquiryID = @EntityId and fieldID = @field_ID  
   end  
   else  
   begin  
    insert into customfieldEnquiryValue( EnquiryID, fieldID, fieldvalue)  
     values( @EntityId, @field_ID, @retFormulaValue )  
   end  
  end  
  
  update #tempExpression set isProcess = 1 where field_ID = @field_ID  
 end  
end  


