/* ============================================================
   Procedure: [dbo].[usp_ManageNTFCNSettingDuplicacy]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_ManageNTFCNSettingDuplicacy
(
  @EventID int,
  @ParentID bigint
)
as
begin
     
	  Declare @Count int = 0;
	  Declare @admnNTNSetting bigint = 0;

	          select  top 1 @Count = count(admns.id) from adminnotificationsettings as admns with(nolock) 
	                                where admns.notificationid
									   in  (
	                                          select id 
									           from notificationsmaster as ntfm with(nolock)
										        where ntfm.activityid = @EventID and parentid = @ParentID  
										   )
							  group by admns.id
						      having count(admns.id) > 1


       if(@Count > 1)
	      begin
		       select  top 1  @admnNTNSetting = admns.id from adminnotificationsettings as admns with(nolock) 
	                                where admns.notificationid
									   in  (
	                                          select id 
									           from notificationsmaster as ntfm with(nolock)
										        where ntfm.activityid = @EventID and parentid = @ParentID  
										   )
							   
							      order by admns.id desc       
		  
		      delete from adminnotificationsettings where id = @admnNTNSetting
		  
		  end     

	select 'Data updated' 	   

end








