/* ============================================================
   Procedure: [dbo].[usp_ManageSaleActivityQueue]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ManageSaleActivityQueue]
    @Mode NVARCHAR(20),                             -- 'Insert', 'Update', 'Delete', 'Get', 'BulkInsert', 'Process'
    @Id BIGINT = NULL,
    @EntityName NVARCHAR(255) = NULL,
    @EntityId BIGINT = NULL,
    @ActivityId BIGINT = NULL,
    @ProcessStatus INT = 0,
    @ErrorDescription NVARCHAR(MAX) = NULL,
    @whoWillExecute nvarchar(255) = NULL,
    @BulkData SaleActivityQueueType READONLY -- Only used when Mode = 'BulkInsert'
AS
BEGIN
    --SET NOCOUNT ON;


    SET @whoWillExecute = isnull(@whoWillExecute, 'usp_st_SaleActivityMasterManage');

    BEGIN TRY
        IF @Mode = 'Insert'
        BEGIN
            PRINT 'Inserting a new sale activity record...';

            INSERT INTO tbl_SaleActivity_Queue (EntityName, EntityId, ActivityId, ErrorDescription, whoWillExecute)
            VALUES (@EntityName, @EntityId, @ActivityId, @ErrorDescription, @whoWillExecute);

            DECLARE @NewId BIGINT = SCOPE_IDENTITY();

            PRINT 'Insert successful. New Id: ' + CAST(@NewId AS NVARCHAR(20));
        END
        ELSE IF @Mode = 'BulkInsert'
        BEGIN
            PRINT 'Performing bulk insert...';

            INSERT INTO tbl_SaleActivity_Queue (EntityName, EntityId, ActivityId, IsProcessed, ErrorDescription, whoWillExecute)
            SELECT EntityName, EntityId, ActivityId, IsProcessed, ErrorDescription, @whoWillExecute
            FROM @BulkData;

            DECLARE @InsertedCount INT = (SELECT COUNT(*) FROM @BulkData);

            PRINT 'Bulk insert completed. Rows inserted: ' + CAST(@InsertedCount AS NVARCHAR(20));
        END
        ELSE IF @Mode = 'Update'
        BEGIN
            PRINT 'Updating sale activity record with Id = ' + CAST(@Id AS NVARCHAR(20)) + '...';

            UPDATE tbl_SaleActivity_Queue
            SET 
                EntityName = ISNULL(@EntityName, EntityName),
                EntityId = ISNULL(@EntityId, EntityId),
                ActivityId = ISNULL(@ActivityId, ActivityId),
                IsProcessed = ISNULL(@ProcessStatus, IsProcessed),
                ErrorDescription = ISNULL(@ErrorDescription, ErrorDescription),
				ProcessedOn = GETDATE()
            WHERE Id = @Id;

            PRINT 'Update successful.';
        END
        ELSE IF @Mode = 'Delete'
        BEGIN
            PRINT 'Deleting sale activity record with Id = ' + CAST(@Id AS NVARCHAR(20)) + '...';

            DELETE FROM tbl_SaleActivity_Queue
            WHERE Id = @Id;

            PRINT 'Delete successful.';
        END
        ELSE IF @Mode = 'Get'
        BEGIN
            PRINT 'Retrieving top 10 sale activity records...';

            DECLARE @Count INT;
            SELECT @Count = COUNT(*) FROM tbl_SaleActivity_Queue WITH (NOLOCK);

            PRINT 'Total records available: ' + CAST(@Count AS NVARCHAR(20)) + '.';

            PRINT 'Note: Data retrieval suppressed as per requirement.';
        END
        ELSE IF @Mode = 'Process'
        BEGIN
            PRINT 'Processing top 10 unprocessed sale activity records...';

            DECLARE @Ids TABLE (Id BIGINT PRIMARY KEY);

            INSERT INTO @Ids (Id)
            SELECT TOP 1000 Id
            FROM tbl_SaleActivity_Queue WITH (NOLOCK)
            WHERE IsProcessed = 0 --AND whoWillExecute <> 'usp_SaveActivityJson' 
            ORDER BY Id ASC;

            UPDATE q
            SET IsProcessed = 2
            FROM tbl_SaleActivity_Queue q
            INNER JOIN @Ids i ON q.Id = i.Id;

			SELECT q.Id, q.EntityName, q.EntityId, q.ActivityId, q.IsProcessed, q.ErrorDescription, 
                q.CreatedOn, q.ProcessedOn, q.whoWillExecute, q.ActivityJson
            
            FROM tbl_SaleActivity_Queue q INNER JOIN @Ids i ON q.Id = i.Id
            ORDER BY q.Id ASC;

            DECLARE @ProcessedCount INT = (SELECT COUNT(*) FROM @Ids);

            PRINT 'Updated IsProcessed status to 2 (Processing) for ' + CAST(@ProcessedCount AS NVARCHAR(20)) + ' records.';

        END
        ELSE
        BEGIN
            PRINT 'Invalid Mode specified.';
        END
    END TRY
    BEGIN CATCH
		EXEC usp_InsertErrorInfo
    END CATCH
END



GO

/* ============================================================
   Procedure: [dbo].[usp_ManageSMSMailCredits]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ManageSMSMailCredits]          
(          
          
@SMSCredits bigint,          
@MailCredits bigint,          
@FromUserID bigint,          
@UserID   bigint          
          
)          
as          
Begin      
     
      Declare @ParentID bigint = 0    
      Declare @MIDP bigint = 0
	  Declare @MID_FromUserID bigint = 0 

	  Select top 1  @ParentID = isnull(ParentID,0) from User_detail with(nolock)  where User_ID =  @UserID           
      Select top 1  @MIDP = isnull(M_ID,0) from User_detail with(nolock) where User_ID =  @ParentID           
      Select top 1  @MID_FromUserID = isnull(M_ID,0) from User_detail with(nolock) where User_ID =  @FromUserID             

      ---- SMS Credits  ----          
   if(@SMSCredits>0)          
   Begin          
          
    if(exists(select 'x' from Credit_Details with(nolock) where USER_ID=@ParentID))          
        Begin          
          Declare @VarCredits bigint = 0,@VarBalance bigint = 0             
              select top 1 @VarCredits = ISNULL(Credits,0), @VarBalance =  Isnull(Balance,0)   from      
                          Credit_Details with(nolock) where USER_ID= @ParentID order by DateCreated desc          
       set @VarBalance = @SMSCredits + @VarBalance                  
     insert into Credit_Details          
       (          
       M_ID,FromUser_ID,User_ID,Credits,Balance,DateCreated,DateUpdated,LastModified, CD_CreatedBy --, CreatedBy          
       )          
       values          
       (          
          @MIDP,@FromUserID,@ParentID,@SMSCredits,@VarBalance,GETDATE(),GETDATE(),GETDATE(), @UserID  -- ,@UserID         
       )                 
              
           End           
       else          
           Begin          
            insert into Credit_Details          
        (          
          M_ID,FromUser_ID,User_ID,Credits,Balance,DateCreated,DateUpdated,LastModified,CD_CreatedBy--,CreatedBy          
        )          
       values          
       (          
         @MIDP,@FromUserID,@ParentID,@SMSCredits,@SMSCredits,GETDATE(),GETDATE(),GETDATE(),@UserID --,@UserID         
                    )          
           End           
                  
                  
      End          
                  
        ---- Mail Credits  -----          
     if(@MailCredits>0)          
        Begin          
                  
       if(exists(select 'x' from MailCreditDetails with(nolock) where USER_ID=@ParentID))          
        Begin          
          Declare @VarMailCredits bigint = 0,@VarMailBalance bigint = 0             
              select top 1 @VarMailCredits = ISNULL(Credits,0), @VarMailBalance =  Isnull(Balance,0)   from MailCreditDetails with(nolock) where USER_ID= @ParentID order by DateCreated desc          
       set @VarMailBalance = @MailCredits + @VarMailBalance                  
     insert into MailCreditDetails          
       (          
       M_ID,FromUser_ID,User_ID,Credits,Balance,DateCreated,DateUpdated,LastModified --,CreatedBy         
       )          
       values          
       (          
          @MIDP,@FromUserID,@ParentID,@MailCredits,@VarMailBalance,GETDATE(),GETDATE(),GETDATE()-- ,@UserID         
       )                 
              
       End           
    else          
        Begin          
            insert into MailCreditDetails          
        (          
          M_ID,FromUser_ID,User_ID,Credits,Balance,DateCreated,DateUpdated,LastModified --,CreatedBy          
        )          
       values          
          (          
           @MIDP,@FromUserID,@ParentID,@MailCredits,@MailCredits,GETDATE(),GETDATE(),GETDATE() -- ,@UserID         
          )          
        End           
                       
                  
        End          
                  
       select 'Success'           
                  
               
End      


