/* ============================================================
   Procedure: [dbo].[usp_ManageTranscriptDeduction]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_ManageTranscriptDeduction(
	@RequestId bigint
)
as
begin

	begin try
		begin transaction	
		--declare @RequestId bigint = 4

		declare 
			@ParentId bigint, @DurationInSec int = 0, @Type nvarchar(50), @UnitsPerCredit int,
			@PricePerUnit decimal(18, 4), @mId bigint = 0, @typeCredit nvarchar(50) = 8, 
			@remarks nvarchar(255) = '', @intCreditId int, @requestDatetime datetime = getdate()

		select @ParentId = ParentId, @DurationInSec = DurationInSec, @requestDatetime = CreatedOn from tbl_stt_Requests where id = @RequestId

		select @mId = M_ID  from User_Detail where User_Id = @ParentId

		select @UnitsPerCredit = Units_Per_Credit, @PricePerUnit = PricePerUnit 
			from Price_Base_AICredits_Rate where id = 8 and Type = 'Transcript'

		declare @totalPlus int = ceiling(cast(@DurationInSec as float) / @UnitsPerCredit)
		declare @totalPrice decimal(18, 4) = @totalPlus * @PricePerUnit


		if(@totalPrice > 0)
		begin

			set @remarks = concat( 'Amount deducted for Transcript for RequestId: ', @RequestId,
			' at ', format(@requestDatetime, 'dd-MMM-yyyy HH:mm:ss'), ' with audio duration of ', @DurationInSec, ' seconds',
			' (TotalPrice: ', @totalPrice, ')' );

			PRINT CONCAT('Remarks: ', @remarks)
			print 'Calling usp_DeductRefundBalanceWithOutput stored procedure to deduct balance...'
			print concat('Parameters - ParentId: ', @ParentId, ', RequestId: ', @RequestId, ', mId: ', @mId, 
				', cost_in_inr_credit: 0, cost_in_inr_debit: ', @totalPrice, 
				', credit_type: ', @typeCredit, ', remarks: ', @remarks)

			exec usp_DeductRefundBalanceWithOutput  
				@parentid = @ParentId,    
				@batchId = @RequestId,    
				@m_id = @mId,    
				@cost_in_inr_credit = 0,    
				@cost_in_inr_debit = @totalPrice,    
				@credit_type = @typeCredit,    
				@remarks = @remarks,    
				@intCredId = @intCreditId output  

			if(@intCreditId > 0)
			begin
				update tbl_stt_Requests set IntCreditId = @intCreditId where id = @RequestId
			end

			select @intCreditId as CreditId, @totalPrice as TotalPrice, @remarks as Remarks

		end
		commit transaction
	end try
	begin catch
		rollback transaction
		exec usp_InsertErrorInfo
	end catch	
end



GO

/* ============================================================
   Procedure: [dbo].[usp_ManageTranslation]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ManageTranslation](
	@RequestId bigint = 0,
	@UserId bigint = 0,
	@RefTableName nvarchar(255) = '',
	@RefTableId bigint = 0,
	@CharCount int = 0,
	@ApiStatus nvarchar(25) = '',
	@tLnCode nvarchar(25)  = '',
	@tLnName nvarchar(100) = '' ,
	@DetailJson nvarchar(max)  = '{}',
	@Mode nvarchar(25) = 'insert'
)
as
begin


	--declare
	--	@RequestId bigint = 0,
	--	@UserId bigint = 0,
	--	@RefTableName nvarchar(255) = '',
	--	@RefTableId bigint = 0,
	--	@CharCount int = 0,
	--	@ApiStatus nvarchar(25) = '',
	--	@tLnCode nvarchar(25)  = '',
	--	@tLnName nvarchar(100) = '' ,
	--	@DetailJson nvarchar(max)  = '{}',
	--	@Mode nvarchar(25) = 'insert'


	--select @RefTableName=N'conversations',@RefTableId=18865223,@tLnCode=N'hi',@Mode=N'check',@UserId=34594


	declare @ParentId bigint
	select @ParentId = dbo.ufn_GetUserParentId(@UserId)

	declare @resStatus nvarchar(25), @resCode int = 0, @resMessage nvarchar(255), @metaData nvarchar(max) = '{}'

	set @RefTableName = ( case isnull(@RefTableName, '')
		when 'conversations' then concat('tbl_conversations_', @ParentId)
		when 'calllog' then 'calllog'
		else '' end )


	if(isnull(@Mode, '') = 'insert')
	begin
		print 'INSERT SECTION'

		declare @pulseChar int = 1000, @pulseRate decimal(18, 4) = 0.12, @totalPulse int = 0, @totalPrice decimal(18, 4) = 0, 
			@intCredtiId bigint = 0, @remarks nvarchar(max) = '', @intCreditId bigint = 0, @typeCredit bigint = 24, @mId bigint

		select @mId	 = M_ID from User_Detail with (nolock) where User_Id = @ParentId

		select top 1 @pulseChar = Units_Per_Credit, @pulseRate = PricePerUnit from Price_Base_AICredits_Rate with (nolock) 
			where [Type] = 'Translate' and ParentId in (0, @ParentId) order by ParentId desc


		set @remarks = concat(N'Balance is used to translate the ',
			(case when @refTableName like 'tbl_conversations_%' then 'Whatsapp Conversation' else 'text' end ),
			' with ID ', @RefTableId, '. The translation covers ', @CharCount, ' characters and is provided in ', concat(@tLnName, ' (', @tLnCode, ')'),
			'. ')

		set @totalPulse = ceiling(cast(@CharCount as float) / @pulseChar)
		set @totalPrice = isnull(@totalPulse * isnull(@pulseRate,  0.12), 0)


		insert into tbl_translation_deduction(parentid, refTableName, refTableId, char_count, cost_applied, createon, detail_json, languageCode)
			values (@ParentId, @RefTableName, @RefTableId, @CharCount, @totalPrice, getdate(), @DetailJson, @tLnCode)

		set @RequestId = scope_identity()

		select @resStatus = 'success', @resCode  = 1, @resMessage = 'Recored Inserted'
		set @metaData =  json_modify(@metaData, '$.RequestId', @requestId)

		if(@RequestId > 0 and @totalPrice > 0)
		begin
			exec usp_DeductRefundBalanceWithOutput
				@parentid = @ParentId,  
				@batchId = @RequestId,  
				@m_id = @mId,  
				@cost_in_inr_credit = 0,  
				@cost_in_inr_debit = @totalPrice,  
				@credit_type = @typeCredit,  
				@remarks = @remarks,  
				@intCredId = @intCreditId output

			set @metaData =  json_modify(@metaData, '$.IntCreditId', @intCreditId)
			set @resMessage = 'Balance deducted for translation'
		end

		update tbl_translation_deduction set int_credit_id = @intCreditId where id = @RequestId

	end if(isnull(@Mode, '') = 'update')
	begin
		update tbl_translation_deduction set  detail_json = @DetailJson where id = @RequestId
		select @resStatus = 'success', @resCode  = 1, @resMessage = 'Recored Updated'
	end 
	else if(isnull(@Mode, '') = 'check')
	begin
		select @resStatus = 'success', @resCode  = 1, @resMessage = 'Recored Checked'
		select @metaData = detail_json from tbl_translation_deduction where refTableName = @refTableName 
			and refTableId = @RefTableId and languageCode = @tLnCode
	end


	select @resStatus as [resStatus], @resCode as [resCode], @resMessage as [resMessage], @metaData as [resMetaData]
end



GO

