/* ============================================================
   Procedure: [dbo].[usp_Map_SulekhaParentID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_Map_SulekhaParentID @userid BIGINT
	,@SulekhaParentid NVARCHAR(200)
AS
BEGIN
	DECLARE @parentid BIGINT = (
			SELECT parentid
			FROM user_detail(NOLOCK)
			WHERE user_id = @userid
			)
		,@flg BIT = 0

	IF NOT EXISTS (
			SELECT 1
			FROM SulekhaMapping(NOLOCK)
			WHERE SulekhaId = @SulekhaParentid
			)
	BEGIN
		INSERT INTO SulekhaMapping (
			SulekhaId
			,Kit19ParentId
			,Createdby
			,CreatedOn
			)
		SELECT @SulekhaParentid
			,@parentid
			,@userid
			,getdate()

		SELECT 'This Id got mapped with your account'

		SET @flg = 1
	END
	ELSE
	BEGIN
		IF EXISTS (
				SELECT 1
				FROM SulekhaMapping(NOLOCK)
				WHERE SulekhaId = @SulekhaParentid
					AND Kit19ParentId = @parentid
				)
		BEGIN
			SELECT 'This Id is already mapped with your account'
		END
		ELSE IF EXISTS (
				SELECT 1
				FROM SulekhaMapping(NOLOCK)
				WHERE SulekhaId = @SulekhaParentid
					AND Kit19ParentId <> @parentid
				)
		BEGIN
			SELECT 'Sorry ! This Id is mapped with some other account. If this Sulekha id belongs to you, Please contact us'
		END
	END

	IF @flg = 1
	BEGIN
		DECLARE @rowJson VARCHAR(MAX) = (
				SELECT *
				FROM SulekhaMapping(NOLOCK)
				WHERE SulekhaId = @SulekhaParentid
					AND Kit19ParentId = @parentid
				FOR JSON AUTO
					,INCLUDE_NULL_VALUES
				)

		IF @rowJson IS NOT NULL
		BEGIN
			EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @userid
				,@Activity_type = 'Inst_SlkhaMppng'
				,@ActionType = 'I'
				,@RowJson = @rowJson
				,@Table_name = 'SulekhaMapping'
		END
	END
END



GO

/* ============================================================
   Procedure: [dbo].[usp_MapExporterKey]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_MapExporterKey    
(    
  @ExporterKey nvarchar(500),    
  @ExporterEmailID nvarchar(500),    
  @UserID bigint    
)    
as    
Begin    
   DECLARE @parentid BIGINT = ( SELECT isnull(parentid,0) FROM User_Detail(NOLOCK)      
                                 WHERE User_id = @userid      
                               )    
   declare @id BIT = 0      
   IF NOT EXISTS (      
   SELECT 1      
   FROM [tbl_ExporterMapping](NOLOCK)      
   WHERE ExporterKey = @ExporterKey      
   )      
 BEGIN     
    insert into tbl_ExporterMapping    
  (    
    [ParentID]    
      ,[ExporterKey]    
      ,[ExporterEmailID]    
      ,[CreatedOn]    
      ,[CreatedBy]    
  )    
  select @parentid, @ExporterKey,@ExporterEmailID,GETDATE(),@UserID     
      
     SELECT 'This Id got mapped with your account'      
     SET @id = 1           
  End    
  ELSE      
 BEGIN      
  IF EXISTS (      
    SELECT 1      
    FROM tbl_ExporterMapping(NOLOCK)      
    WHERE [ExporterKey] = @ExporterKey     
     AND [ParentID] = @parentid      
    )      
  BEGIN      
   SELECT 'This Id is already mapped with your account'      
  END      
  ELSE IF EXISTS (      
    SELECT 1      
    FROM tbl_ExporterMapping(NOLOCK)      
    WHERE [ExporterKey] = @ExporterKey      
     AND [ParentID] <> @parentid      
    )      
  BEGIN      
   SELECT 'Sorry ! This Id is mapped with some other account. If this Exporter Key belongs to you, Please contact us'      
  END      
 END       
     IF @id = 1      
   BEGIN      
    DECLARE @rowJson VARCHAR(MAX) = (      
   SELECT top 1 *      
   FROM tbl_ExporterMapping(NOLOCK)      
   WHERE ExporterKey = ExporterKey      
   FOR JSON AUTO      
    ,INCLUDE_NULL_VALUES      
   )      
      
    IF @rowJson IS NOT NULL      
    BEGIN      
     EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @userid      
   ,@Activity_type = 'Insert Exporter Key'      
   ,@ActionType = 'I'      
   ,@RowJson = @rowJson      
   ,@Table_name = 'tbl_ExporterMapping'      
    END      
   END     
 End


GO

/* ============================================================
   Procedure: [dbo].[usp_MapIndiaMartKey]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_MapIndiaMartKey @userid BIGINT
	,@IndiaMartKey NVARCHAR(200)
	,@CountryCode NVARCHAR(10)
	,@Mob_No NVARCHAR(20)
AS
BEGIN
	DECLARE @parentid BIGINT = (
			SELECT parentid
			FROM user_detail(NOLOCK)
			WHERE user_id = @userid
			)
		,@id BIT = 0

	IF NOT EXISTS (
			SELECT 1
			FROM IndiamartMapping(NOLOCK)
			WHERE IndiamartId = @IndiaMartKey
			)
	BEGIN
		INSERT INTO IndiamartMapping (
			IndiamartId
			,Kit19ParentId
			,Createdby
			,CreatedOn
			,CountryCode
			,MobileNo
			)
		SELECT @IndiaMartKey
			,@parentid
			,@userid
			,getdate()
			,@CountryCode
			,@Mob_No

		SELECT 'This Id got mapped with your account'

		SET @id = 1
	END
	ELSE
	BEGIN
		IF EXISTS (
				SELECT 1
				FROM IndiamartMapping(NOLOCK)
				WHERE IndiamartId = @IndiaMartKey
					AND Kit19ParentId = @parentid
				)
		BEGIN
			SELECT 'This Id is already mapped with your account'
		END
		ELSE IF EXISTS (
				SELECT 1
				FROM IndiamartMapping(NOLOCK)
				WHERE IndiamartId = @IndiaMartKey
					AND Kit19ParentId <> @parentid
				)
		BEGIN
			SELECT 'Sorry ! This Id is mapped with some other account. If this Indian Mart id belongs to you, Please contact us'
		END
	END

	IF @id = 1
	BEGIN
		DECLARE @rowJson VARCHAR(MAX) = (
				SELECT *
				FROM IndiamartMapping(NOLOCK)
				WHERE IndiamartId = @IndiaMartKey
				FOR JSON AUTO
					,INCLUDE_NULL_VALUES
				)

		IF @rowJson IS NOT NULL
		BEGIN
			EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @userid
				,@Activity_type = 'Inst_IndMrt_Mppng'
				,@ActionType = 'I'
				,@RowJson = @rowJson
				,@Table_name = 'IndiamartMapping'
		END
	END
END



