/* ============================================================
   Procedure: [dbo].[usp_mapreplysupportmail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_mapreplysupportmail] --18907,'info@tttextiles.com',1  
(@parentid bigint,@usermail nvarchar(200),@virtualmail nvarchar(200),@isactive int)  
as  
begin  
if exists (SELECT ParentId FROM serv_user_domain(nolock) where virtual_mail = @virtualmail and parentid=@parentid )  
begin  
if exists(select 1 from supportreplymail(nolock) where parentid=@parentid and @usermail=usermail and virtualmail=@virtualmail)  
--and not exists (select 1 from supportreplymail(nolock) where parentid=@parentid and @usermail=usermail and virtualmail<>@virtualmail and isactive=1)  
begin  
update supportreplymail set isactive=@isactive,lastmodified=getdate() where parentid=@parentid and @usermail=usermail and virtualmail=@virtualmail  
print 'record updated'  
end  
else if exists(select 1 from supportreplymail(nolock) where parentid=@parentid and @usermail<>usermail and virtualmail=@virtualmail and isactive=1)  
begin  
declare @existing nvarchar(200)=(select usermail from supportreplymail(nolock) where parentid=@parentid and virtualmail=@virtualmail and isactive=1)  
select 'Reply mail for this user is already mapped as , '+@existing + '. Please deactivate the existing mail to map another reply mail '  
end  
else  
begin  
insert into supportreplymail(parentid,isactive,createdon,lastmodified,usermail,virtualmail)  
select @parentid,@isactive,getdate(),getdate(),@usermail,@virtualmail  
print 'record created'  
end  
end  
else  
begin  
Select 'This virtual mail is linked to a different user '  
end  
end


GO

/* ============================================================
   Procedure: [dbo].[usp_mapsupportmail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_mapsupportmail] --18907,'info@tttextiles.com',1
(@parentid bigint,@usermail nvarchar(200),@virtualmail nvarchar(200),@isactive int)
as
begin
if exists (SELECT ParentId FROM serv_user_domain where virtual_mail = @virtualmail and parentid=@parentid )
begin
if exists(select 1 from supportmailforwarding(nolock) where parentid=@parentid and @usermail=usermail and virtualmail=@virtualmail)
and not exists (select 1 from supportmailforwarding(nolock) where parentid=@parentid and @usermail=usermail and virtualmail<>@virtualmail and isactive=1)
begin
update supportmailforwarding set isactive=@isactive,lastmodified=getdate() where parentid=@parentid and @usermail=usermail and virtualmail=@virtualmail
print 'record updated'
end
else if exists(select 1 from supportmailforwarding(nolock) where parentid=@parentid and @usermail=usermail and virtualmail<>@virtualmail and isactive=1)
begin
declare @existing nvarchar(200)=(select virtualmail from supportmailforwarding(nolock) where parentid=@parentid and @usermail=usermail and isactive=1)
select 'The usermail is already mapped with a virtual mail, '+@existing + '. Please deactivate the existing mail to map another virtual mail '
end
else
begin
insert into supportmailforwarding(parentid,isactive,createdon,lastmodified,usermail,virtualmail)
select @parentid,@isactive,getdate(),getdate(),@usermail,@virtualmail
print 'record created'
end
end
else
begin
Select 'This virtual mail is already linked to a different user '
end
end


GO

