/* ============================================================
   Procedure: [dbo].[usp_mass_marketingsequence_insert]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_mass_marketingsequence_insert]
@ids nvarchar(max),@batchid bigint,@entity nvarchar(20),@sequenceid bigint
as
begin
DECLARE @existsFlag INT;

DECLARE @sqlquery NVARCHAR(MAX)
if @BatchID IS NOT NULL AND @BatchID <> 0      
BEGIN      
 Update  Tbl_MassOperationSummary set BatchStartTime= GetDate()  where BatchID=@BatchID       
END      

set @sqlquery  = 
    'SELECT TOP 1 1 
     FROM tbl_WA_SequenceMaster (NOLOCK) 
     WHERE sequenceid = ' + CAST(@sequenceid AS NVARCHAR) + ' 
       AND isactive = 1 
       AND isdeleted = 0';

EXEC usp_clr_GetRemoteIntValue  @sqlquery, @retval = @existsFlag OUTPUT;

IF @existsFlag > 0
--if exists(select 1 from MySMSConversations.dbo.tbl_WA_SequenceMaster (nolock) where sequenceid=@sequenceid and isactive=1 and isdeleted=0)
begin
drop table if exists #entityids
create table #entityids(id bigint)
if @ids<>''
begin
insert into #entityids(id)
select item  from SplitString(@ids,'#')
end
insert into #entityids(id)
select EntityID from  Tbl_MassOperationDetails(nolock) t where SummaryId=@batchid


/*insert into [tbl_mass_mktgsequence]
(batchid,sequenceid,SequenceActionId,actiontype,actiondetails,parentid,createdon,scheduledfor,entity,entityid)
select @batchid,@sequenceid,SequenceActionId,actiontype,actiondetails,parentid,getdate(),isnull(mysmsconversations.dbo.fn_getnextschedule(sequenceactionid),getdate()),@entity,e.id
from MySMSConversations.dbo.tbl_wa_sequenceactionmaster(nolock) s 
join #entityids e on 1=1
where s.sequenceid=@sequenceid and s.IsActive = 1 and s.IsDeleted = 0         */

DECLARE @query NVARCHAR(MAX);

DROP TABLE IF EXISTS #temp1;
   
   CREATE TABLE #temp1 (SequenceId bigint, TimeInterval int, TimeUnit varchar(50), TimeValue varchar(100),Days varchar(100) ,FromTime time(7), ToTime time(7), ActionType varchar(500), ActionDetails nvarchar(max),ActionDetailsView nvarchar(max) ,IsActive bit,IsDeleted bit,
	CreatedOn datetime  ,CreatedBy bigint );

SET @query = '
        SELECT SequenceId , TimeInterval , TimeUnit , TimeValue ,Days ,FromTime , ToTime , ActionType , ActionDetails ,ActionDetailsView  ,IsActive ,IsDeleted ,
	CreatedOn   ,CreatedBy 
        FROM tbl_wa_sequenceactionmaster (NOLOCK) ';

    -- Execute the query using your CLR procedure
    INSERT INTO #temp1(SequenceId , TimeInterval , TimeUnit , TimeValue ,Days ,FromTime , ToTime , ActionType , ActionDetails ,ActionDetailsView  ,IsActive ,IsDeleted ,
	CreatedOn   ,CreatedBy  )
	EXEC usp_clr_FillRemoteData @query;

insert into [tbl_mass_mktgsequence]
(batchid,sequenceid,SequenceActionId,actiontype,actiondetails,parentid,createdon,scheduledfor,entity,entityid)
select @batchid,@sequenceid,SequenceActionId,actiontype,actiondetails,parentid,getdate(),isnull(mysmsconversations.dbo.fn_getnextschedule(sequenceactionid),getdate()),@entity,e.id
from #temp1 s 
join #entityids e on 1=1
where s.sequenceid=@sequenceid and s.IsActive = 1 and s.IsDeleted = 0  

end
else
begin
update t set isprocessed=1,batchendtime=getdate(),errordetails='Sequence is not active or deleted' from  tbl_massoperationsummary t  where BatchID=@BatchID  
end

end



GO

/* ============================================================
   Procedure: [dbo].[Usp_Mass_TaskAppointment_CrtUpdt]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

----------------------------------------------------------------------------  
  
CREATE   PROCEDURE [dbo].[Usp_Mass_TaskAppointment_CrtUpdt]      
@HashedIDs    Nvarchar(max)='',      
@Title               VARCHAR(255) ,                             
@Description         VARCHAR(1000) ,                             
@Remarks             VARCHAR(500)  = '' ,                             
@Address             VARCHAR(500) ='',                             
@StartDate           DATETIME      = '' ,                             
@EndDate             DATETIME ,                             
@LeadIds             Varchar(max) ,                             
@AssignedTo          BIGINT ,                             
@IsActive            BIT           = 1 ,                             
@TaskId              BIGINT ,                             
@Status              VARCHAR(255)  = 'open' ,                             
@UserID     BIGINT ,                             
@OutcomesId          BIGINT =0 ,                             
@CollabratoerUserIds VARCHAR(1000) ='',                             
@IsSMS               BIT           = 0 ,                             
@IsEmail             BIT           = 0 ,                             
@IsTask              BIT           = 0 ,                             
@IsAppointment       BIT           = 0 ,                             
@TaskType            VARCHAR(100)  = '' ,                             
@CompleteAddress     VARCHAR(500)  = NULL ,                             
@Latitude            VARCHAR(50)   = NULL ,                             
@Longitude           VARCHAR(50)   = NULL ,                             
@SmsSchedule         VARCHAR(50)   = NULL ,                             
@EmailSchedule       VARCHAR(50)   = NULL ,                             
@NotifyMe            BIT           = 0  ,      
@outcomeid BIGINT =0 ,       
@massbatchid BIGINT=0,      
@StartDateTime VARCHAR(50)='',    
@mode     Nvarchar(50)       
 AS      
 BEGIN      
  drop table if exists #TEMCollabatoerUser      
      
  DECLARE @min int , @max int , @leadId bigint, @EventDescription nvarchar(max), @EventName nvarchar(100), @reftables nvarchar(20),@ParentID bigint      
  ,@TaskHistoryId bigint,@Leadno bigint      
   DECLARE @Counter INT  , @Collaboratorid bigint       
   DECLARE @CollabratoerMappingId BIGINT= 0,@event nvarchar(100)              
   Declare @username varchar(50) =(select User_login from user_detail where user_id= @UserID)      
   declare @Activitytype nvarchar(50),@rowJson nvarchar(max), @actiontype varchar(1)      
      
  if @mode = 'Insert'      
  BEGIN      
  Drop Table If Exists #Leadtemp       
  CREATE TABLE #Leadtemp(      
   RowID int,      
   LeadID bigint      
  )      
  Drop Table If Exists #tasktempOutput      
  CREATE TABLE #tasktempOutput(      
   TaskID bigint,      
   LeadId bigint      
  )      
  Drop Table If Exists #CollabtempOutput      
  CREATE TABLE #CollabtempOutput(      
   CollabID bigint      
  )      
      
  BEGIN try       
  BEGIN TRANSACTION      
  if @massbatchid IS NOT NULL AND @massbatchid <> 0      
  BEGIN      
   INSERT into #Leadtemp (RowID, LeadID)      
   Select Row_number() over(order by ID) RowID , EntityID as LeadID  from Tbl_MassOperationDetails where SummaryId=@massbatchid      
   --Update  Tbl_MassOperationSummary set BatchStartTime= GetDate(),ScheduleDateTime= @StartDateTime  where BatchID=@massbatchid  
   UPDATE Tbl_MassOperationSummary  
        SET BatchStartTime = GETDATE(),  
            ScheduleDateTime = CASE   
                                 WHEN ScheduleDateTime IS NULL OR ScheduleDateTime = '' OR ScheduleDateTime = '1900-01-01 00:00:00.000'  
                                 THEN @StartDateTime  
                                 ELSE ScheduleDateTime  
                               END  
        WHERE BatchID = @massbatchid;  
  
  END      
  ELSE       
  BEGIN      
   INSERT into #Leadtemp (RowID, LeadID)      
   Select RowID,LeadID  from OpenJson(@leadIds) with (RowID int , LeadID bigint)        END      
  Select @ParentID = parentid from  user_detail  where User_id=@UserID      
      
  Select @min = min(Rowid) , @max= max(Rowid)  from #Leadtemp       
  --Select * ,@min min, @max max from #Leadtemp      
      
   INSERT INTO tbl_tsk_TaskHistory ( Title , Description , Address , StartDate , EndDate , LeadId , AssignedTo , IsActive , CreatedOn , TaskId , CreatedBy ,         
   OutcomesId , STATUS , IsTask , IsAppointment , TaskType , CompleteAddress , Latitude , Longitude , Remarks )         
   OutPut inserted.id as TaskID, inserted.LeadId as LeadId into #tasktempOutput      
   Select  @Title , @Description , @Address , @StartDate , @EndDate , LeadId , @AssignedTo , 1 , GETDATE() , @TaskId , @UserID ,         
   @OutcomesId , @Status , @IsTask , @IsAppointment , @TaskType , @CompleteAddress , @Latitude , @Longitude , @Remarks from #Leadtemp ;         
         
   if @IsAppointment=1      
   begin       
    set @EventName='Appointment Added'      
      
   end      
   else      
   begin      
    set @EventName='Task Added'      
   end      
        
    IF @CollabratoerUserIds <> ''                          
            BEGIN         
   drop table if exists #TEMCollabatoerUser      
    CREATE TABLE #TEMCollabatoerUser (                     
                             Id     INT PRIMARY KEY IDENTITY(1 , 1),                     
                             UserId BIGINT );         
                INSERT INTO #TEMCollabatoerUser ( UserId                          
                                                )                           
                       SELECT value AS UserId                          
                       FROM STRING_SPLIT(@CollabratoerUserIds , '#')                          
                       WHERE LTRIM(RTRIM(value)) <> '';                          
                     
                SELECT @Counter = COUNT(*) FROM #TEMCollabatoerUser;                          
                WHILE @Counter > 0                          
                    BEGIN                          
                        SELECT @Collaboratorid = UserId                          
                        FROM #TEMCollabatoerUser                          
                        WHERE Id = @Counter;                          
                        set @CollabratoerMappingId = 0;                          
                        INSERT INTO tbl_tsk_CollaborationUserMapping ( User_Id , CreatedOn , CreatedBy , TaskHistoryId)      
      OUTPUT INSERTED.ID as CollabID into #CollabtempOutput      
                        select @Collaboratorid , GETDATE() , @userid , TaskID  from #tasktempOutput                     
                                                         
                        --SET @CollabratoerMappingId = SCOPE_IDENTITY();                          
                        IF EXISTS (SELECT 1 from #CollabtempOutput)                       
                         BEGIN                          
                                IF @IsSMS = 1                          
                                    BEGIN                          
                      INSERT INTO tbl_tsk_Reminder ( Description , STATUS , Schedule , CreatedOn , CreatedBy , IsSMS , IsEmail , CollaborationUserMappingId )                           
                                        Select   'You are now a Collaborater of a task with title '+@Title+' for Leadno ' + CAST(@Leadno AS VARCHAR) + ' scheduled for '+ cast(@EndDate as nvarchar(50)), 'open' , @SmsSchedule , GETDATE() , @userid , 1 ,    
  
   
    0 , CollabID   from     #CollabtempOutput                  
                                END;                          
                                IF @IsEmail = 1                          
                                    BEGIN                          
                                        INSERT INTO tbl_tsk_Reminder ( Description , STATUS , Schedule , CreatedOn , CreatedBy , IsSMS , IsEmail , CollaborationUserMappingId )   
                                        Select  'You are now a Collaborater of a task with title '+@Title+' for Leadno ' + CAST(@Leadno AS VARCHAR) + ' scheduled for '+ cast(@EndDate as nvarchar(50)) , 'open' , @EmailSchedule , GETDATE() , @userid , 0   
   
     , 1 ,  CollabID   from     #CollabtempOutput                      
                                END;                          
                        END;                          
                   SET @Counter = @Counter - 1;          
             
   END;       
   END      
          
 SELECT @TaskType = TaskName FROM tbl_tsk_UserTaskMaster(nolock) WHERE ID =@TaskId      
      
   DECLARE @tbl1 AS LeadActivitywithid_Tbltype        
   INSERT INTO @tbl1 (        
    leadid        
    ,userid        
    ,parentid        
    ,eventdescription        
    ,eventname        
    ,reftable        
    ,refid        
    )        
  SELECT leadid        
    ,@Userid        
    ,@ParentID        
 , Case when @IsAppointment=1 then  @username + ' added an appointment with title '+@Title+' for '+ convert (varchar,@StartDate,0) else  @username + ' added task of type '+@TaskType+' with title '+@Title end eventdescription      
    ,@EventName      
    ,'tbl_tsk_TaskHistory'         
    ,TaskID       
   FROM #tasktempOutput       
      
    EXEC UspSaveentityActivity_withMultipleValue_withid_bulk @tbl1       
       
  Commit Transaction      
  SET Context_Info 0x      
  END TRY      
  BEGIN CATCH      
   While @@TRANCOUNT > 0      
   ROLLBACK TRANSACTION      
            Select 'Error'          
  SET Context_Info 0x      
  insert into tmp_error_report(ErrorNumber,ErrorSeverity,ErrorState,ErrorProcedure,ErrorLine,ErrorMessage,Date)              
  SELECT ERROR_NUMBER(),ERROR_SEVERITY(),ERROR_STATE(),ERROR_PROCEDURE(),ERROR_LINE(),ERROR_MESSAGE(),GETDATE()        
  END CATCH      
  if @IsTask =1      
  BEGIN      
   Select 'Task Created Successfully'      
   if @massBatchID IS NOT NULL AND @massBatchID <> 0      
   BEGIN      
    --Update  Tbl_MassOperationSummary set BatchEndTime= GetDate(),ScheduleDateTime= @StartDateTime , Remarks = 'Task Created Successfully', IsProcessed=1 where BatchID=@massBatchID    
 UPDATE Tbl_MassOperationSummary  
        SET BatchEndTime = GETDATE(),  
            ScheduleDateTime = CASE   
                                 WHEN ScheduleDateTime IS NULL OR ScheduleDateTime = '' OR ScheduleDateTime = '1900-01-01 00:00:00.000'  
                                 THEN @StartDateTime  
                                 ELSE ScheduleDateTime  
                               END,  
            Remarks = 'Task Created Successfully',  
            IsProcessed = 1  
        WHERE BatchID = @massBatchID;  
   END      
   set @rowJson = (Select * from tbl_tsk_TaskHistory (nolock)  th      
       join #tasktempOutput tem on tem.TaskID=th.Id for json auto, include_null_values)      
   set @Activitytype = 'Inst_MassTask'      
   set @actiontype = 'I'      
  END      
  if @IsAppointment=1      
  begin      
    Select 'Appointment Created Successfully'      
    if @massBatchID IS NOT NULL AND @massBatchID <> 0      
    BEGIN      
     --Update  Tbl_MassOperationSummary set BatchEndTime= GetDate(),ScheduleDateTime= @StartDateTime , Remarks = 'Appointment Created Successfully', IsProcessed=1 where BatchID=@massBatchID    
  UPDATE Tbl_MassOperationSummary  
        SET BatchEndTime = GETDATE(),  
            ScheduleDateTime = CASE   
                                 WHEN ScheduleDateTime IS NULL OR ScheduleDateTime = '' OR ScheduleDateTime = '1900-01-01 00:00:00.000'  
                                 THEN @StartDateTime  
                                 ELSE ScheduleDateTime  
                               END,  
            Remarks = 'Appointment Created Successfully',  
            IsProcessed = 1  
        WHERE BatchID = @massBatchID;  
    END      
    set @rowJson = (Select * from tbl_tsk_TaskHistory (nolock) th      
       join #tasktempOutput tem on tem.TaskID=th.Id for json auto, include_null_values)      
    set @Activitytype = 'Inst_MassAppoint'      
    set @actiontype = 'I'      
  End      
      
  END      
      
  else if @mode ='Update'      
  BEGIN      
   BEGIN try       
  BEGIN TRANSACTION      
   drop table if exists #TaskAppntIDs      
   drop table if exists #Updatedetails      
   Create table #TaskAppntIDs (Rowid int identity , TaskId int)      
   Insert into #TaskAppntIDs (TaskID)      
   select [Value] from fn_split(@HashedIDs,'#')      
         
   Select TaskId Id, @Title Title, @Description Description, @Address Address, @StartDate StartDate, @EndDate EndDate, @AssignedTo AssignedTo, @IsActive IsActive,      
     @TaskId TaskId, @Status STATUS, @IsTask IsTask, @IsAppointment IsAppointment,  @TaskType TaskType, CASE @Status when 'completed' then GETDATE() else NUll END CompletedOn,      
     @CompleteAddress CompleteAddress, @Latitude Latitude, @Longitude Longitude, @Remarks Remarks, @outcomeid outcomeid into #Updatedetails from #TaskAppntIDs      
   --select * from #UpdateDetails      
   Update tsk      
   set  tsk.Description =ud.Description, tsk.Address = ud.Address , tsk.StartDate=ud.StartDate, tsk.EndDate=ud.EndDate, tsk.AssignedTo=ud.AssignedTo,      
    tsk.TaskId=ud.TaskId, tsk.Status=ud.Status, tsk.TaskType=ud.TaskType, tsk.CompleteAddress=ud.CompleteAddress,tsk.Latitude=ud.Latitude,tsk.Longitude=ud.Longitude ,      
    tsk.Remarks=ud.Remarks, UpdatedOn = GETDATE(), tsk.OutcomesId=  ud.outcomeid, tsk.CompletedOn=ud.CompletedOn      
   from tbl_tsk_TaskHistory tsk       
   join #Updatedetails ud  on tsk.id=ud.id      
      
     UPDATE tbl_tsk_CollaborationUserMapping                    
               SET DeletedOn = GETDATE()                    
        WHERE TaskHistoryId in (Select TaskID from #TaskAppntIDs);      
        
  Select 'Data Updated Successfully'      
              
  IF ( @CollabratoerUserIds <> '' )                     
            BEGIN                    
      
                drop table if exists #TEMUPCollabatoerUser      
    CREATE TABLE #TEMUPCollabatoerUser (                     
                             Id     INT PRIMARY KEY IDENTITY(1 , 1),                     
                             UserId BIGINT );           
                INSERT INTO #TEMUPCollabatoerUser ( UserId                    
                                                )                     
                       SELECT value AS [UserId]                    
                       FROM STRING_SPLIT(@CollabratoerUserIds , '#')                    
                       WHERE LTRIM(RTRIM(value)) <> '';                    
    --select * from #TEMUPCollabatoerUser      
                SELECT @Counter = COUNT(*)                    
                FROM #TEMUPCollabatoerUser;                    
                WHILE ( @Counter > 0 )                     
                    BEGIN                    
           
                        SELECT @Collaboratorid = UserId                    
                        FROM #TEMUPCollabatoerUser                    
       WHERE Id = @Counter;                    
                        IF ( EXISTS ( SELECT *                    
                                      FROM tbl_tsk_CollaborationUserMapping                    
                                      WHERE User_Id = @Collaboratorid                    
                                            AND                     
                                            TaskHistoryId in (Select TaskID from #TaskAppntIDs)                  
                                    ) )                     
                            BEGIN                    
                                UPDATE tbl_tsk_CollaborationUserMapping                    
                                       SET DeletedOn = NULL                    
                                WHERE User_Id = @Collaboratorid                    
                                      AND                     
                                      TaskHistoryId in (Select TaskID from #TaskAppntIDs);      
                                SELECT @CollabratoerMappingId = Id                    
                                FROM tbl_tsk_CollaborationUserMapping                    
                                WHERE User_Id = @UserId                    
                                      AND                     
                                      TaskHistoryId in (Select TaskID from #TaskAppntIDs);              
                        END                    
                            ELSE                    
                            BEGIN                    
                                INSERT INTO tbl_tsk_CollaborationUserMapping ( User_Id , CreatedOn , CreatedBy , TaskHistoryId                    
                                                  )                     
        Select  @Collaboratorid,GETDATE(),@UserID , TaskId from #TaskAppntIDs      
                                      
                                SET @CollabratoerMappingId = SCOPE_IDENTITY();             
                        END;                    
                        IF ( @CollabratoerMappingId > 0 )                     
                            BEGIN                    
                                IF ( @IsSMS = 1 )                     
                                    BEGIN                    
                                        INSERT INTO tbl_tsk_Reminder ( Description , STATUS , Schedule , CreatedOn , CreatedBy , IsSMS , IsEmail , CollaborationUserMappingId                    
                                                                     )                     
                                       VALUES ( 'You are now a Collaborator of task of type '+ @TaskType+' with title '+ @Title +' for Lead no. ' + CAST(@LeadId AS VARCHAR)+ ' scheduled at '+cast(@EndDate as nvarchar(50))  , ' open ' , @SmsSchedule , GETDATE() , @UserID , 1 , 0 ,           
            @CollabratoerMappingId                    
                                               );                    
                                END;                    
 IF ( @IsEmail = 1 )                     
                                    BEGIN                    
                                        INSERT INTO tbl_tsk_Reminder ( Description , STATUS , Schedule , CreatedOn , CreatedBy , IsSMS , IsEmail , CollaborationUserMappingId                    
                                                                     )                     
                                        VALUES ( 'You are now a Collaborator of task of type '+ @TaskType+' with title '+ @Title +' for Lead no. ' + CAST(@LeadId AS VARCHAR)+ ' scheduled at '+cast(@EndDate as nvarchar(50)) , ' open ' , @EmailSchedule , GETDATE() , @UserID , 0 , 1 ,          
           @CollabratoerMappingId                   
                                               );                    
                                END;                    
                                IF ( @NotifyMe <> 0 )                     
                                    BEGIN                    
                                        DECLARE @FullName NVARCHAR(255)= ( SELECT ( FName + ' ' + LName ) AS [UserFullName]                    
                                                                           FROM User_Detail                    
                            WHERE User_ID = @UserId                    
                                                                         );                    
                                        DECLARE @CreatorName NVARCHAR(255)= ( SELECT ( FName + ' ' + LName ) AS [UserFullName]                    
                                                                              FROM User_Detail                    
                                                                              WHERE User_ID = @UserID                    
                                                                            );                    
      set @event=case when @IsAppointment=1 then 'Appointment ' else 'Task ' end +'edited'          
                                        DECLARE @colMsg NVARCHAR(MAX)=  case when @IsAppointment=1 then 'Appointment ' else 'Task ' end +'Edited notification: Dear '              
           + @FullName + ', '+case when @IsAppointment=1 then 'Appointment ' else 'Task ' end+'with title ' + @Title + '  with your role as Collaborator has been edited on '              
            + CAST(GETDATE() AS NVARCHAR) + ' by ' + @CreatorName;              
                                
                                        DECLARE @ScheduleData DATETIME= DATEADD(MINUTE , 10 , GETDATE());                    
                                        DECLARE @cutOffTime DATETIME= DATEADD(HH , 6 , GETDATE());                    
                                        EXEC usp_SaveNotification @CollabratoerUserIds , @Title , @colMsg , 'https://kit19.com/IndexNew1/images/logo.png' , '' , @ScheduleData , @cutOffTime , @UserID;              
                        
         declare @ParentID1 bigint = 0              
                       
         select @ParentID1 = isnull(ParentID,User_ID) from User_Detail(nolock) where User_ID = @UserID              
              
                        
             declare @Sender_Name1 as nvarchar(200) = ''            
         SELECT @Sender_Name1 = 'KitApp'          
   --ISNULL(Sender_Name , '')                          
   --       FROM Default_SenderID                          
   --       WHERE User_ID = @CreatedBy                          
   --          AND                           
   --        Sender_ID > 0;                          
          --SELECT @Sender_Name1;                          
          DECLARE @mobilenos1 VARCHAR(MAX);                          
             IF(@Sender_Name1 <> '' )                           
          BEGIN                          
            SET @mobilenos1 = dbo.udf_tsk_GetCollabortorMobiles ( STR(@UserID));                          
        --EXEC usp_sendmessage @ParentId , @colMsgAss , @mobilenos , @Sender_Name , 0 , 2;                       
                      
   exec [usp_sendmessage_WithdltOrEvent]     335 , @colMsg , @mobilenos1 , @Sender_Name1 , 0 ,    2,null,@event ;                           
   --EXEC usp_sendmessage_WithDLTTemplateID @ParentID1 , @colMsg , @mobilenos1 , @Sender_Name1 , 0 ,    2,@DLTTemplateIDForNotification ;                           
                        
          END;                
    END;                    
          END;                    
     SET @Counter = @Counter - 1;                    
        END;         
        
          
  END      
        
  if(@IsTask=1)      
  begin      
  set @Activitytype = 'Updt_MassTask'      
  END      
  else if (@IsAppointment=1)      
  begin      
  set @Activitytype = 'Updt_MassAppoint'      
  end      
  set @rowJson = (Select * from tbl_tsk_TaskHistory (nolock) th      
       join #Updatedetails tem on tem.Id=th.Id for json auto, include_null_values)      
  set @actiontype = 'U'      
      
  Commit Transaction      
  SET Context_Info 0x      
  END TRY      
  BEGIN CATCH      
   While @@TRANCOUNT > 0      
   ROLLBACK TRANSACTION      
                      
  SET Context_Info 0x      
  insert into tmp_error_report(ErrorNumber,ErrorSeverity,ErrorState,ErrorProcedure,ErrorLine,ErrorMessage,Date)              
  SELECT ERROR_NUMBER(),ERROR_SEVERITY(),ERROR_STATE(),ERROR_PROCEDURE(),ERROR_LINE(),ERROR_MESSAGE(),GETDATE()        
  END CATCH      
          
 END      
      
 if(@rowJson is not null)      
  Begin      
  EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId      
   ,@Activity_type = @Activitytype      
   ,@ActionType = @actiontype      
   ,@RowJson = @rowJson      
   ,@Table_name = 'tbl_tsk_TaskHistory'       
  END      
      
 END   
  


GO

