   Procedure: [dbo].[Usp_Mass_TaskAppointment_CrtUpdt_mktg_schedule]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE  PROCEDURE [dbo].[Usp_Mass_TaskAppointment_CrtUpdt_mktg_schedule]          
@Title               VARCHAR(255) ,                                 
@Description         VARCHAR(1000) ,                                 
@Remarks             VARCHAR(500)  = '' ,                                 
@Address             VARCHAR(500) ='',                                 
@StartDate           DATETIME      = '' ,                                 
@EndDate             DATETIME ,                                 
@LeadIds             Varchar(max) ,                                 
@AssignedTo          BIGINT ,                                 
@IsActive            BIT           = 1 ,                                 
@TaskId              BIGINT ,                                 
@Status              VARCHAR(255)  = 'open' ,                                 
@UserID     BIGINT ,                                 
@OutcomesId          BIGINT =0 ,                                 
@CollabratoerUserIds VARCHAR(1000) ='',                                 
@IsSMS               BIT           = 0 ,                                 
@IsEmail             BIT           = 0 ,                                 
@IsTask              BIT           = 0 ,                                 
@IsAppointment       BIT           = 0 ,                                 
@TaskType            VARCHAR(100)  = '' ,                                 
@CompleteAddress     VARCHAR(500)  = NULL ,                                 
@Latitude            VARCHAR(50)   = NULL ,                                 
@Longitude           VARCHAR(50)   = NULL ,                                 
@SmsSchedule         VARCHAR(50)   = NULL ,                                 
@EmailSchedule       VARCHAR(50)   = NULL ,                                 
@NotifyMe            BIT           = 0  ,          
@outcomeid BIGINT =0 ,           
@massbatchid BIGINT=0,          
@mode     Nvarchar(50),@error nvarchar(max) output           
 AS          
 BEGIN          
  drop table if exists #TEMCollabatoerUser          
          
  DECLARE @min int , @max int , @leadId bigint, @EventDescription nvarchar(max), @EventName nvarchar(100),        
  @reftables nvarchar(20),@ParentID bigint          
  ,@TaskHistoryId bigint,@Leadno bigint          
   DECLARE @Counter INT  , @Collaboratorid bigint           
   DECLARE @CollabratoerMappingId BIGINT= 0,@event nvarchar(100)                  
   Declare @username varchar(50)        
   select @username=User_login,@ParentID = parentid from user_detail(nolock) where user_id= @UserID        
             
  if @mode = 'Insert'          
  BEGIN      
  print 'creating task'      
  Drop Table If Exists #Leadtemp           
  CREATE TABLE #Leadtemp(          
   RowID int,          
   LeadID bigint          
  )          
  Drop Table If Exists #tasktempOutput          
  CREATE TABLE #tasktempOutput(          
   TaskID bigint,          
   LeadId bigint,        
   isprocessed bit default 0        
  )          
  Drop Table If Exists #CollabtempOutput          
  CREATE TABLE #CollabtempOutput(          
   CollabID bigint          
  )          
          
  BEGIN try        
  if isnull(@massbatchid,0)<>0    
  begin    
INSERT into #Leadtemp (RowID, LeadID)          
Select Row_number() over(order by ID) RowID , EntityID as LeadID  from Tbl_MassOperationDetails(nolock) where         
SummaryId=@massbatchid    
end    
else    
begin    
INSERT into #Leadtemp (RowID, LeadID)          
select position,value from dbo.fn_split(@LeadIds,',')    
end    
    
    
declare @lc int=(select count(1) from #Leadtemp)      
print concat('total tasks to be created for lead nos: ',@lc)      
      
drop table if exists #TEMCollabatoerUser          
CREATE TABLE #TEMCollabatoerUser (Id INT PRIMARY KEY IDENTITY(1 , 1),UserId BIGINT );             
      
IF @CollabratoerUserIds <> ''                              
BEGIN             
INSERT INTO #TEMCollabatoerUser ( UserId)                               
SELECT value AS UserId FROM STRING_SPLIT(@CollabratoerUserIds , ',') WHERE LTRIM(RTRIM(value)) <> '';                            
END          
          
Select @min = min(Rowid) , @max= max(Rowid)  from #Leadtemp           
        
while @min<=@max        
begin        
      
--Select top 100 case when @Title='' then 'Newtask_'+cast(leadid as nvarchar)+'_'+cast(format(getdate(),'yyyyMMddHHmm') as nvarchar) else @title +cast(leadid as nvarchar)+ '_'+  
--cast(format(getdate(),'yyyyMMddHHmm') as nvarchar) end, @Description , @Address,    
-- @StartDate , @EndDate , LeadId , dbo.fn_getleadowner(leadid) , 1 , GETDATE() , @TaskId , @UserID ,             
--   @OutcomesId , @Status , @IsTask , @IsAppointment , @TaskType , @CompleteAddress , @Latitude , @Longitude , @Remarks        
--   from #Leadtemp where rowid between @min and @min+100;             
   --zauver      
      
INSERT INTO tbl_tsk_TaskHistory ( Title , Description , Address , StartDate , EndDate , LeadId , AssignedTo , IsActive , CreatedOn , TaskId , CreatedBy ,             
   OutcomesId , STATUS , IsTask , IsAppointment , TaskType , CompleteAddress , Latitude , Longitude , Remarks )             
   OutPut inserted.id as TaskID, inserted.LeadId as LeadId,0 into #tasktempOutput          
Select top 100 (case when @Title='' then 'Newtask_'+cast(leadid as nvarchar)+'_'+cast(format(getdate(),'yyyyMMddHHmm') as nvarchar) else @title +cast(leadid as nvarchar)+ '_'+cast(format(getdate(),'yyyyMMddHHmm') as nvarchar) end), @Description , @Address
  
    
 , @StartDate , @EndDate , LeadId , case when @assignedto=0 then dbo.fn_getleadowner(leadid) else @assignedto end , 1 , GETDATE() , @TaskId , @UserID ,             
   isnull(@OutcomesId,0) , isnull(@Status,'open') , @IsTask , @IsAppointment , @TaskType , @CompleteAddress , @Latitude , @Longitude , @Remarks        
   from #Leadtemp where rowid between @min and @min+100;             
 select @Counter=@@ROWCOUNT            
       
 print concat('task created: ',@Counter)      
INSERT INTO tbl_tsk_CollaborationUserMapping ( User_Id , CreatedOn , CreatedBy , TaskHistoryId)          
select userid , GETDATE() , @userid , TaskID  from #tasktempOutput t join #TEMCollabatoerUser c on 1=1           
 where t.isprocessed=0        
        
 SELECT @TaskType = TaskName FROM tbl_tsk_UserTaskMaster(nolock) WHERE ID =@TaskId          
          
set @EventName=case when @IsAppointment=1 then 'Appointment Added'  else 'Task Added' end        
        
   DECLARE @tbl1 AS LeadActivitywithid_Tbltype            
   INSERT INTO @tbl1 (            
    leadid            
    ,userid            
    ,parentid            
    ,eventdescription            
    ,eventname            
    ,reftable            
    ,refid            
    )            
  SELECT leadid            
    ,@Userid            
    ,@ParentID            
 , Case when @IsAppointment=1 then  @username + ' added an appointment with title '+@Title+' for '+ convert (varchar,@StartDate,0) else  @username + ' added task of type '+@TaskType+' with title '+@Title end eventdescription          
    ,@EventName          
    ,'tbl_tsk_TaskHistory'             
    ,TaskID           
   FROM #tasktempOutput  t --on t.LeadId=l.LeadID  
     
   --where rowid between @min and @min+100;                  
          
    EXEC UspSaveentityActivity_withMultipleValue_withid_bulk @tbl1           
       
  delete from @tbl1    
  delete from #tasktempOutput  
  set @min=@min+@counter        
        
end        
              
  END TRY          
  BEGIN CATCH      
  print 'entered catch block'      
  exec usp_inserterrorinfo        
  set @error=ERROR_MESSAGE()        
  END CATCH          
          
  END          
  set @error=isnull(@error,'')        
 END 


GO

