      BEGIN TRY  
	   -- Check if @IDS is NULL or blank
        IF @IDS IS NULL OR LTRIM(RTRIM(@IDS)) = ''
        BEGIN
            -- Return message if @IDS is null or blank
            SELECT 'ID is null or blank' AS StatusMessage;
            RETURN;
        END
       DECLARE @IDsTable TABLE (ID BIGINT);  
        DECLARE @InsertedTable TABLE (EntityID BIGINT);  
        DECLARE @ParentID BIGINT;  
        DECLARE @NewBatchID BIGINT;  
   DECLARE @MassOperationName VARCHAR(50);  
  
     IF @IsTask = 1  
            SET @MassOperationName = 'Add Task';  
        ELSE IF @IsAppointment = 1  
            SET @MassOperationName = 'Add Appointment';  
  
        -- Fetch the ParentID using @UserId  
        SELECT @ParentID = ParentID  
        FROM User_Detail (NOLOCK)  
        WHERE User_ID = @UserId;  
   
      
       INSERT INTO Tbl_MassOperationSummary (  
            MassOperationName,  
            UserID,  
            Parentid,  
            CreatedDate,  
            IsProcessed,  
            Remarks,  
            BatchStartTime,  
            BatchEndTime,  
            EntityType,  
            isvalid,  
            metadata,  
            ErrorDetails,  
            SenderId,  
            UrlTrack,  
   TrackedUrl,  
            SmsPlaceHolder,  
   ScheduleDateTime  
        )  
        VALUES (  
            @MassOperationName,  
            @UserId,  
            @ParentID,  
            GETDATE(),  
            0,  
            NULL,  
            null,  
            NULL,  
            'Lead',  
            1,  
            @metatdata, -- metadata  
            NULL,  
            NULL,  
            NULL,  
   NULL,  
            NULL,  
   @StartDateTime  
        );  
  
        -- Get the BatchID of the last inserted row  
        SELECT @NewBatchID = SCOPE_IDENTITY();  
  
       /* -- Remove braces from @IDS if they exist  
        SET @IDS = REPLACE(REPLACE(@IDS, '{', ''), '}', '');  
  
        -- Split the IDs and insert into the temporary table  
        DECLARE @Pos INT, @Str VARCHAR(MAX);  
        SET @Pos = 1;  
        WHILE CHARINDEX(',', @IDS, @Pos) > 0  
        BEGIN  
            SET @Str = SUBSTRING(@IDS, @Pos, CHARINDEX(',', @IDS, @Pos) - @Pos);  
            INSERT INTO @IDsTable (ID) VALUES (CAST(@Str AS BIGINT));  
            SET @Pos = CHARINDEX(',', @IDS, @Pos) + 1;  
        END  
        INSERT INTO @IDsTable (ID) VALUES (CAST(SUBSTRING(@IDS, @Pos, LEN(@IDS) - @Pos + 1) AS BIGINT));  
  
        -- Insert records into Tbl_MassOperationDetails using the new BatchID  
        INSERT INTO Tbl_MassOperationDetails (SummaryId, EntityID)  
        SELECT @NewBatchID, ID FROM @IDsTable; */
		 -- Remove braces from @IDS if they exist  
        SET @IDS = REPLACE(REPLACE(@IDS, '{', ''), '}', '');  
  
        -- Split the @IDS string and insert into the @IDsTable table using STRING_SPLIT
        INSERT INTO @IDsTable (ID)
        SELECT CAST(value AS BIGINT)
        FROM STRING_SPLIT(@IDS, ',');
  
        -- Insert records into Tbl_MassOperationDetails using the new BatchID  
        INSERT INTO Tbl_MassOperationDetails (SummaryId, EntityID)  
        SELECT @NewBatchID, ID FROM @IDsTable;  
  
  -- Call Usp_MassOperationLeadEnquiryProcess with the new BatchID  
        EXEC [dbo].[Usp_MassOperationLeadEnquiryProcess] @summary_batchid = @NewBatchID;  
  
        -- Return a status message and count of rows inserted for the given IDs  
        SELECT 'Success' AS StatusMessage, COUNT(*) AS TotalRecords FROM @IDsTable;  
  
    END TRY  
    BEGIN CATCH  
        EXEC usp_InsertErrorInfo;   
    END CATCH;  
  
 END 




GO

/* ============================================================
   Procedure: [dbo].[Usp_Mass_TaskAppointment_CrtUpdt_while]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

----------------------------------------------------------------------------  
  
CREATE   PROCEDURE [dbo].[Usp_Mass_TaskAppointment_CrtUpdt_while]      
@HashedIDs    Nvarchar(max)='',      
@Title               VARCHAR(255) ,                             
@Description         VARCHAR(1000) ,                             
@Remarks             VARCHAR(500)  = '' ,                             
@Address             VARCHAR(500) ='',                             
@StartDate           DATETIME      = '' ,                             
@EndDate             DATETIME ,                             
@LeadIds             Varchar(max) ,                             
@AssignedTo          BIGINT ,                             
@IsActive            BIT           = 1 ,                             
@TaskId              BIGINT ,                             
@Status              VARCHAR(255)  = 'open' ,                             
@UserID     BIGINT ,                             
@OutcomesId          BIGINT =0 ,                             
@CollabratoerUserIds VARCHAR(1000) ='',                             
@IsSMS               BIT           = 0 ,                             
@IsEmail             BIT           = 0 ,                             
@IsTask              BIT           = 0 ,                             
@IsAppointment       BIT           = 0 ,                             
@TaskType            VARCHAR(100)  = '' ,                             
@CompleteAddress     VARCHAR(500)  = NULL ,                             
@Latitude            VARCHAR(50)   = NULL ,                             
@Longitude           VARCHAR(50)   = NULL ,                             
@SmsSchedule         VARCHAR(50)   = NULL ,                             
@EmailSchedule       VARCHAR(50)   = NULL ,                             
@NotifyMe            BIT           = 0  ,      
@outcomeid BIGINT =0 ,       
@massbatchid BIGINT=0,      
@StartDateTime VARCHAR(50)='',    
@mode     Nvarchar(50)       
 AS      
 BEGIN      
  drop table if exists #TEMCollabatoerUser      
      
  DECLARE @min int , @max int , @leadId bigint, @EventDescription nvarchar(max), @EventName nvarchar(100), @reftables nvarchar(20),@ParentID bigint      
  ,@TaskHistoryId bigint,@Leadno bigint      
   DECLARE @Counter INT  , @Collaboratorid bigint       
   DECLARE @CollabratoerMappingId BIGINT= 0,@event nvarchar(100)              
   Declare @username varchar(50) =(select User_login from user_detail where user_id= @UserID)      
   declare @Activitytype nvarchar(50),@rowJson nvarchar(max), @actiontype varchar(1)      
      
  if @mode = 'Insert'      
  BEGIN      
  Drop Table If Exists #Leadtemp       
  CREATE TABLE #Leadtemp(      
   RowID int,      
   LeadID bigint      
  ) 
    Drop Table If Exists #Leadtemp2       
  CREATE TABLE #Leadtemp2(      
   RowID int,      
   LeadID bigint      
  ) 

  Drop Table If Exists #tasktempOutput      
  CREATE TABLE #tasktempOutput(      
   TaskID bigint,      
   LeadId bigint      
  )      
  Drop Table If Exists #CollabtempOutput      
  CREATE TABLE #CollabtempOutput(      
   CollabID bigint      
  )  
  
  drop table if exists #TEMCollabatoerUser      
  CREATE TABLE #TEMCollabatoerUser (Id     INT PRIMARY KEY IDENTITY(1 , 1),UserId BIGINT );         

      
  
  --BEGIN TRANSACTION      
  if @massbatchid IS NOT NULL AND @massbatchid <> 0      
  BEGIN      
   INSERT into #Leadtemp2 (RowID, LeadID)      
   Select Row_number() over(order by ID) RowID , EntityID as LeadID  from Tbl_MassOperationDetails where SummaryId=@massbatchid      
   --Update  Tbl_MassOperationSummary set BatchStartTime= GetDate(),ScheduleDateTime= @StartDateTime  where BatchID=@massbatchid  
   UPDATE Tbl_MassOperationSummary  
        SET BatchStartTime = GETDATE(),  
            ScheduleDateTime = CASE   
                                 WHEN ScheduleDateTime IS NULL OR ScheduleDateTime = '' OR ScheduleDateTime = '1900-01-01 00:00:00.000'  
                                 THEN @StartDateTime  
                                 ELSE ScheduleDateTime  
                               END  
        WHERE BatchID = @massbatchid;  
  
  END      
  ELSE       
  BEGIN      
   INSERT into #Leadtemp2 (RowID, LeadID)      
   Select RowID,LeadID  from OpenJson(@leadIds) with (RowID int , LeadID bigint)        
 END      
  
  Select @ParentID = parentid from  user_detail(nolock)  where User_id=@UserID      
   
   declare @ta int,@tid bigint=0
  Select @min = min(Rowid) , @max= max(Rowid) ,@ta=count(1) from #Leadtemp2       
  --Select * ,@min min, @max max from #Leadtemp      
      
while @ta>0
begin

BEGIN try       
insert into #Leadtemp(RowID,LeadID)
select top 500 RowID,LeadID from #Leadtemp2 where leadid>@tid order by leadid



   INSERT INTO tbl_tsk_TaskHistory ( Title , Description , Address , StartDate , EndDate , LeadId , AssignedTo , IsActive , CreatedOn , TaskId , CreatedBy ,         
   OutcomesId , STATUS , IsTask , IsAppointment , TaskType , CompleteAddress , Latitude , Longitude , Remarks )         
   OutPut inserted.id as TaskID, inserted.LeadId as LeadId into #tasktempOutput      
   Select  @Title , @Description , @Address , @StartDate , @EndDate , LeadId , @AssignedTo , 1 , GETDATE() , @TaskId , @UserID ,         
   @OutcomesId , @Status , @IsTask , @IsAppointment , @TaskType , @CompleteAddress , @Latitude , @Longitude , @Remarks from #Leadtemp ;         
         
        
    IF @CollabratoerUserIds <> ''                          
            BEGIN         
                     INSERT INTO tbl_tsk_CollaborationUserMapping ( User_Id , CreatedOn , CreatedBy , TaskHistoryId) 
					   select distinct f.value, GETDATE() , @userid , TaskID  from #tasktempOutput  t cross apply 
					   dbo.fn_split(@CollabratoerUserIds , '#') f WHERE LTRIM(RTRIM(value)) <> '';
    END      
          
   SELECT @TaskType = TaskName FROM tbl_tsk_UserTaskMaster(nolock) WHERE ID =@TaskId      
    select @EventName=case when @IsAppointment=1 then 'Appointment Added'  else 'Task Added' end    
      
   DECLARE @tbl1 AS LeadActivitywithid_Tbltype        
   INSERT INTO @tbl1 (        
    leadid        
    ,userid        
    ,parentid        
    ,eventdescription        
    ,eventname        
    ,reftable        
    ,refid        
    )        
  SELECT leadid        
    ,@Userid        
    ,@ParentID        
 , Case when @IsAppointment=1 then  @username + ' added an appointment with title '+@Title+' for '+ convert (varchar,@StartDate,0) else  @username + ' added task of type '+@TaskType+' with title '+@Title end eventdescription      
    ,@EventName      
    ,'tbl_tsk_TaskHistory'         
    ,TaskID       
   FROM #tasktempOutput       
      
    EXEC UspSaveentityActivity_withMultipleValue_withid_bulk @tbl1       
    delete from @tbl1  
  END TRY      
  BEGIN CATCH
  exec usp_inserterrorinfo
 END CATCH      

select @tid=max(leadid) from #leadtemp
select @ta=@ta-500
truncate table #leadtemp
end

  END      

  if @IsTask =1      
  BEGIN      
   Select 'Task Created Successfully'      
   if @massBatchID IS NOT NULL AND @massBatchID <> 0      
   BEGIN      
   UPDATE Tbl_MassOperationSummary SET BatchEndTime = GETDATE(),
   ScheduleDateTime = CASE WHEN ScheduleDateTime IS NULL OR ScheduleDateTime = ''
   OR ScheduleDateTime = '1900-01-01 00:00:00.000'  THEN @StartDateTime ELSE ScheduleDateTime  END,  
   Remarks = 'Task Created Successfully', IsProcessed = 1  WHERE BatchID = @massBatchID;  
   END      
   --set @rowJson = (Select * from tbl_tsk_TaskHistory (nolock)  th      
   --    join #tasktempOutput tem on tem.TaskID=th.Id for json auto, include_null_values)      
   --set @Activitytype = 'Inst_MassTask'      
   --set @actiontype = 'I'      
  END      
  if @IsAppointment=1      
  begin      
    Select 'Appointment Created Successfully'      
    if @massBatchID IS NOT NULL AND @massBatchID <> 0      
    BEGIN      
     --Update  Tbl_MassOperationSummary set BatchEndTime= GetDate(),ScheduleDateTime= @StartDateTime , Remarks = 'Appointment Created Successfully', IsProcessed=1 where BatchID=@massBatchID    
  UPDATE Tbl_MassOperationSummary  
        SET BatchEndTime = GETDATE(),  
            ScheduleDateTime = CASE   
                                 WHEN ScheduleDateTime IS NULL OR ScheduleDateTime = '' OR ScheduleDateTime = '1900-01-01 00:00:00.000'  
                                 THEN @StartDateTime  
                                 ELSE ScheduleDateTime  
                               END,  
            Remarks = 'Appointment Created Successfully',  
            IsProcessed = 1  
        WHERE BatchID = @massBatchID;  
    END      
    --set @rowJson = (Select * from tbl_tsk_TaskHistory (nolock) th      
    --   join #tasktempOutput tem on tem.TaskID=th.Id for json auto, include_null_values)      
    --set @Activitytype = 'Inst_MassAppoint'      
    --set @actiontype = 'I'      
  End      
      
/*      
 --if(@rowJson is not null)      
 -- Begin      
 -- EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId      
 --  ,@Activity_type = @Activitytype      
 --  ,@ActionType = @actiontype      
 --  ,@RowJson = @rowJson      
 --  ,@Table_name = 'tbl_tsk_TaskHistory'       
 -- END      
 */     


 
 END   
  


GO

