CREATE   PROCEDURE [dbo].[Usp_Mass_TaskAppointment_Seq]      
@Title               VARCHAR(255) ,                             
@Description         VARCHAR(1000) ,                             
@Remarks             VARCHAR(500)  = '' ,                             
@Address             VARCHAR(500) ='',                             
@StartDate           DATETIME      = '' ,                             
@EndDate             DATETIME ,                             
@LeadId              bigint,                             
@AssignedTo          BIGINT ,                             
@IsActive            BIT           = 1 ,                             
@TaskId              BIGINT ,                             
@Status              VARCHAR(255)  = 'open' ,                             
@UserID     BIGINT ,                             
@CollabratoerUserIds VARCHAR(1000) ='',                             
@IsTask              BIT           = 0 ,                             
@IsAppointment       BIT           = 0 ,                             
@TaskType            VARCHAR(100)  = '' ,                             
@CompleteAddress     VARCHAR(500)  = NULL ,                             
@Latitude            VARCHAR(50)   = NULL ,                             
@Longitude           VARCHAR(50)   = NULL                              

AS      
 BEGIN      
      
  DECLARE @EventDescription nvarchar(max), @EventName nvarchar(100), @reftables nvarchar(20),@ParentID bigint      
  ,@TaskHistoryId bigint,@Leadno bigint      
   DECLARE @Counter INT  , @Collaboratorid bigint       
   DECLARE @CollabratoerMappingId BIGINT= 0,@event nvarchar(100)              
   Declare @username varchar(50) =(select User_login from user_detail where user_id= @UserID)      
   declare @Activitytype nvarchar(50),@rowJson nvarchar(max), @actiontype varchar(1) ,@newtaskid bigint     
      
       
  BEGIN try       
 
   Select @ParentID = parentid from  user_detail(nolock)  where User_id=@UserID      
      
   INSERT INTO tbl_tsk_TaskHistory ( Title , Description , Address , StartDate , EndDate , LeadId , AssignedTo ,
   IsActive , CreatedOn , TaskId , CreatedBy ,IsTask , IsAppointment , TaskType , CompleteAddress , Latitude , Longitude ,
 Remarks )         
   Select  @Title , @Description , @Address , @StartDate , @EndDate , @LeadId , @AssignedTo , 1 , GETDATE() , @TaskId , 
@UserID ,  @IsTask , @IsAppointment , @TaskType , @CompleteAddress , @Latitude , @Longitude , @Remarks;         
   select @newtaskid=SCOPE_IDENTITY()      
   
   if @IsAppointment=1      
   begin       
    set @EventName='Appointment Added'     
   end      
   else      
   begin      
    set @EventName='Task Added'      
   end      
        
   IF @CollabratoerUserIds <> ''                          
            BEGIN         
   INSERT INTO tbl_tsk_CollaborationUserMapping ( User_Id , CreatedOn , CreatedBy , TaskHistoryId )
   select value as userid , GETDATE() , @userid , @newtaskid from  STRING_SPLIT(@CollabratoerUserIds , ',')              WHERE LTRIM(RTRIM(value)) <> '';
                
   ENd      
          
 SELECT @TaskType = TaskName FROM tbl_tsk_UserTaskMaster(nolock) WHERE ID =@TaskId      
    
exec UspSaveEntityActivity_withid 'lead',@leadid,@userid,@parentid,@eventdescription,@eventname, 'tbl_tsk_TaskHistory', 
@newtaskid
  
  END TRY      
  BEGIN CATCH      
  exec usp_InsertErrorInfo
  END CATCH      
       
  ENd  
  


GO

/* ============================================================
   Procedure: [dbo].[usp_MassAddFollowupfromEnq]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_MassAddFollowupfromEnq]      
 @EnqID VARCHAR(500) ,      
 @FollowupStatus BIGINT,      
 @AssignTo BIGINT ,      
 @NextStatusDate VARCHAR(50) ,      
 @Remarks VARCHAR(500),      
 @Products VARCHAR(500) ,      
 @AmountPaid VARCHAR(50),      
 @CreatedBy BIGINT ,      
 @ParentID BIGINT      
AS      
BEGIN      
 DECLARE @maxID INT
 declare @leadid bigint
 declare @conversion varchar(50)=null   
 declare @FollowupDate   Datetime = null        
   
     
   if(@NextStatusDate <> '' and @NextStatusDate is not null)        
   Begin        
    begin try
    set @FollowupDate=convert(datetime,@NextStatusDate)
    select @FollowupDate = dbo.[fn_getISTtimefromusertime](@ParentID,@FollowupDate)
    select @NextStatusDate = convert(nvarchar(100),@FollowupDate,121)   
    end try
    begin catch
    set @conversion= 'Invalid Date'
    end catch 
   End   
       
 SET @maxID = (      
         SELECT isnull(MAX(ul.LeadNo),0) + 1      
         FROM   UserLeads AS ul      
         WHERE  ul.ParentID = @ParentID      
     );           
       
 SELECT (@maxID + ROW_NUMBER() OVER(ORDER BY ue.EnquiryID)) AS LeadNo,     
  EnquiryID,     
        PersonName,      
        CompanyName,      
        MobileNo,      
        MobileNo1,      
        MobileNo2,      
        EmailID,      
        EmailID1,      
        EmailID2,      
        City,      
        [State],      
        Country,      
        CountryCode,      
        CountryCode1,      
        CountryCode2,      
        PinCode,      
        ResidentialAddress,      
        OfficeAddress,      
        @AssignTo        AS AssignedTo,      
        SourceName,      
        MediumName,      
        CampaignName,      
        InitialRemarks,      
        ParentID,      
        @FollowupStatus  AS FollowUpStatus,      
        @NextStatusDate  AS NextStatusDate,      
        @Remarks         AS Remarks,      
        @Products        AS Products,      
        @AmountPaid      AS AmountPaid,      
        GETDATE()        AS CreatedOn,
        @FollowupDate    AS FollowupDate,      
        @CreatedBy       AS CreatedBy INTO #TempTable      
 FROM   UserEnquiry      AS ue      
 WHERE  ue.EnquiryID IN (SELECT fs.[value]      
                         FROM   dbo.fn_Split(@EnqID, '#') AS fs)      
        AND ue.ParentID = @ParentID          
       
 INSERT INTO UserLeads      
   (      
     -- ID -- this column value is auto-generated          
     LeadNo,      
     PersonName,      
     CompanyName,      
     MobileNo,      
     MobileNo1,      
     MobileNo2,      
     EmailID,      
     EmailID1,      
     EmailID2,      
     City,      
     [State],      
     Country,      
     CountryCode,      
     CountryCode1,      
     CountryCode2,      
     PinCode,      
     ResidentialAddress,      
     OfficeAddress,      
     AssignedTo,      
     SourceName,      
     MediumName,      
     CampaignName,      
     InitialRemarks,      
     ParentID,      
     FollowUpStatus,      
     NextStatusDate,      
     Remarks,      
     Products,      
     AmountPaid,      
     CreatedOn,      
     CreatedBy,
     FollowupDate      
   )      
 SELECT LeadNo,      
        PersonName,      
        CompanyName,      
        MobileNo,      
        MobileNo1,      
        MobileNo2,      
        EmailID,      
        EmailID1,      
        EmailID2,      
        City,      
        [State],      
        Country,      
        CountryCode,      
        CountryCode1,      
        CountryCode2,      
        PinCode,      
        ResidentialAddress,      
        OfficeAddress,      
        AssignedTo,      
        SourceName,      
        MediumName,      
        CampaignName,      
        InitialRemarks,      
        ParentID,      
        FollowUpStatus,      
        NextStatusDate,      
        Remarks,      
        Products,      
        AmountPaid,      
        CreatedOn,      
        CreatedBy,
        FollowupDate      
 FROM   #TempTable          
       
       select @leadid=SCOPE_IDENTITY();
	   if(@conversion= 'Invalid Date')
	   begin
	   insert into followupDateError (leadid, nextstatusdate, parentid) values (@leadid, @NextStatusDate, @ParentID)
	   end

 INSERT INTO LeadInteractionHistory      
   (      
     -- ID -- this column value is auto-generated          
     LeadNo,      
     FollowUpStatus,      
     NextStatusDate,      
     Remarks,      
     Products,      
     AmountPaid,      
     AssignedTo,      
     ParentID,      
     CreatedOn,      
     CreatedBy,
     FollowupDate      
   )      
 SELECT LeadNo,      
        FollowUpStatus,      
        NextStatusDate,      
        Remarks,      
        Products,      
        AmountPaid,      
        AssignedTo,      
        @ParentID,      
        CreatedOn,      
        CreatedBy,
        FollowupDate      
 FROM   #TempTable      
      
       
     
  UPDATE  ue     
 SET    ue.IsOpen = 0,ue.LeadNo = tp.LeadNo    
 from  UserEnquiry ue inner join #TempTable tp     
 on tp.EnquiryID = ue.EnquiryID    
      
              
 SELECT 'Record Saved'       
       
 DROP TABLE #TempTable      
END


GO

/* ============================================================
   Procedure: [dbo].[usp_MassAddFollowupfromEnq_ChangeWithFollowupDate]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROCEDURE [dbo].[usp_MassAddFollowupfromEnq_ChangeWithFollowupDate]   
(  
    @EnqID          VARCHAR(500),   
    @FollowupStatus BIGINT,   
    @AssignTo       BIGINT,   
    @NextStatusDate VARCHAR(50),   
    @Remarks        VARCHAR(500),   
    @Products       VARCHAR(500),   
    @AmountPaid     VARCHAR(50),   
    @CreatedBy      BIGINT,   
    @ParentID       BIGINT  
)  
AS  
BEGIN  
    DECLARE @maxID INT;  
    DECLARE @FollowupDate DATETIME= NULL;  
  
    IF(@NextStatusDate <> '')  
    BEGIN  
            SET @FollowupDate = @NextStatusDate;  
            SELECT @FollowupDate = dbo.[fn_getISTtimefromusertime](@ParentID, @FollowupDate);  
            SELECT @NextStatusDate = CONVERT(NVARCHAR(100), @FollowupDate, 121);  
    END;  
      
    SET @maxID = ISNULL(  
    (  
        SELECT MAX(ul.LeadNo)  
        FROM UserLeads AS ul  
        WHERE ul.ParentID = @ParentID  
    ), 0);  
      
    SELECT ( @maxID + ROW_NUMBER() OVER( ORDER BY ue.EnquiryID) ) AS LeadNo , EnquiryID , PersonName , CompanyName , MobileNo , MobileNo1 , MobileNo2 , EmailID , EmailID1 , EmailID2 , City , [State] , Country , CountryCode , CountryCode1 , 
	CountryCode2 ,PinCode , ResidentialAddress , OfficeAddress , @AssignTo AS AssignedTo , SourceName , MediumName , CampaignName , InitialRemarks , ParentID , @FollowupStatus AS FollowUpStatus , @NextStatusDate AS NextStatusDate , 
	@Remarks AS Remarks , @Products AS Products , @AmountPaid AS AmountPaid , GETDATE() AS CreatedOn , @CreatedBy AS CreatedBy , @FollowupDate AS FollowupDate  
    INTO #TempTable  
    FROM UserEnquiry AS ue  
    WHERE ue.EnquiryID IN ( SELECT fs.[value] FROM dbo.fn_Split ( @EnqID , '#') AS fs ) AND ue.ParentID = @ParentID;  
  
    INSERT INTO UserLeads (                  
    -- ID -- this column value is auto-generated                      
    LeadNo , PersonName , CompanyName , MobileNo , MobileNo1 , MobileNo2 , EmailID , EmailID1 , EmailID2 , City , [State] , Country , CountryCode , CountryCode1 , CountryCode2 , PinCode , ResidentialAddress , OfficeAddress , AssignedTo , 
	SourceName , MediumName , CampaignName , InitialRemarks , ParentID , FollowUpStatus , NextStatusDate , Remarks , Products , AmountPaid , CreatedOn , CreatedBy , FollowupDate)   
    SELECT LeadNo , PersonName , CompanyName , MobileNo , MobileNo1 , MobileNo2 , EmailID , EmailID1 , EmailID2 , City , [State] , Country , CountryCode , CountryCode1 , CountryCode2 , PinCode , ResidentialAddress , OfficeAddress , AssignedTo , SourceName
 , MediumName , CampaignName , InitialRemarks , ParentID , FollowUpStatus , NextStatusDate , Remarks , Products , AmountPaid , CreatedOn , CreatedBy , FollowupDate  
    FROM #TempTable;  
  
    INSERT INTO LeadInteractionHistory (                  
    -- ID -- this column value is auto-generated                      
    LeadNo , FollowUpStatus , NextStatusDate , Remarks , Products , AmountPaid , AssignedTo , ParentID , CreatedOn , CreatedBy , FollowupDate)   
    SELECT LeadNo , FollowUpStatus , NextStatusDate , Remarks , Products , AmountPaid , AssignedTo , @ParentID , CreatedOn , CreatedBy , @FollowupDate  
    FROM #TempTable;  
  
    --UPDATE UserEnquiry                  
    --SET    IsOpen = 0                  
    --WHERE  EnquiryID   IN (SELECT fs.[value]                  
    --                       FROM   dbo.fn_Split(@EnqID, '#') AS fs)                  
    --       AND ParentID = @ParentID                  
  
    UPDATE ue SET  ue.IsOpen = 0, ue.LeadNo = tp.LeadNo  
    FROM UserEnquiry ue INNER JOIN #TempTable tp   
    ON tp.EnquiryID = ue.EnquiryID;  
  
    --WHERE  EnquiryID   IN (SELECT fs.[value]                  
    --                       FROM   dbo.fn_Split(@EnqID, '#') AS fs)                  
    --       AND ParentID = @ParentID                  
  
    SELECT 'Record Saved' as Msg, TT.EnquiryID, UL.ID as LeadID  
    From #TempTable TT inner join UserLeads UL   
    ON TT.LeadNo = UL.LeadNo and UL.ParentID = @ParentID  
  
    DROP TABLE #TempTable;  
END;  


GO

