/* ============================================================
   Procedure: [dbo].[usp_MassAddFollowupfromEnq_ChangeWithFollowupDate1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE  PROCEDURE [dbo].[usp_MassAddFollowupfromEnq_ChangeWithFollowupDate1]
(                                    
    @EnqID          NVARCHAR(max), --='2558419#2558420#2554188#2554125#2577089',                                     
    @FollowupStatus BIGINT,                                     
    @AssignTo       BIGINT,                                     
    @NextStatusDate VARCHAR(50),                                     
    @Remarks        VARCHAR(500),                                     
    @Products       VARCHAR(500),                                     
    @AmountPaid     VARCHAR(50),                                     
    @CreatedBy      BIGINT,                                     
    @ParentID       BIGINT,          
 @IsReAssign bit = 0,          
 @BatchID BIGINT = 0           
)                                    
AS                                    
BEGIN                 
 drop table if exists #enqt          
 drop table if exists #tempUE                                
 DROP TABLE  if exists #TempTable;           
 DROP TABLE  if exists #enq;          
Create Table #enqt (          
 enquiryid bigint ,          
 CountryCode varchar(55),          
 Mobile varchar(100),          
 email varchar(100),          
 Parentid bigint ,          
 position bigint ,          
 value bigint           
)          
          
if @BatchID IS NOT NULL AND @BatchID <> 0          
BEGIN          
 select @EnqID= STRING_AGG(cast(Entityid as NVARCHAR(max)),'#') from Tbl_MassOperationDetails(nolock) where SummaryId=@BatchID           
 Update  Tbl_MassOperationSummary set BatchStartTime= GetDate()  where BatchID=@BatchID           
END          
          
if @EnqID IS NOT NULL AND @EnqID <> ''          
BEGIN          
INSERT INTO #enqt (enquiryid, CountryCode, Mobile, email, Parentid, position, value)          
select enquiryid, CountryCode, Mobile, email, Parentid, position, value from Userenquiry_Mobile_Email u (nolock) cross apply dbo.fn_split(@EnqID,'#') f where f.value=u.enquiryid              
END          
          
declare @total int=(select count(distinct enquiryid) from #enqt),@eid bigint=0 ,@leadid bigint ,@leadno bigint,@eligibleenquiries int=0              
,@newtotal int               
delete e from #enqt e where              
(e.email<>'1' and e.email in               
(select email from userleads_mobile_email(nolock) ue               
where Parentid=e.ParentID))              
or (e.mobile<>'0'              
and e.mobile in              
(select mobile from userleads_mobile_email(nolock) ue               
where Parentid=e.ParentID)              
)              
select distinct position,[value] into #enq from #enqt              
drop table if exists #enqt              
select @newtotal=count(1) from #enq              
DECLARE @maxID INT,@ftotal int=@total                                    
DECLARE @FollowupDate DATETIME= NULL;                                    
create table #tempUE(enquiryid bigint,leadid bigint)                                   
IF(@NextStatusDate <> '')                                    
BEGIN                                    
SET @FollowupDate = @NextStatusDate;                                    
SELECT @FollowupDate = dbo.[fn_getISTtimefromusertime](@ParentID, @FollowupDate);                                    
SELECT @NextStatusDate = CONVERT(NVARCHAR(100), @FollowupDate, 121);                                    
END;                                    

begin transaction

while @newtotal>0                        
begin                        
select @eid=min(value) from #enq where value>@eid                        
SET @maxID = ISNULL((SELECT MAX(ul.LeadNo) FROM UserLeads AS ul  with (UPDLOCK,HOLDLOCK) WHERE ul.ParentID = @ParentID ), 0);                       
--if exists(select 1 from userenquiry(nolock) ue where enquiryid=@eid and                         
--not exists(select 1 from userleads_mobile_email(nolock) where Parentid=ue.ParentID               
--and cast(countrycode as nvarchar)+cast(mobile as nvarchar)                  
-- in (cast(ue.countrycode as nvarchar)+cast(ue.MobileNo as nvarchar),                            
-- cast(ue.CountryCode1 as nvarchar)+cast(ue.MobileNo1 as nvarchar),                            
-- cast(ue.countrycode2 as nvarchar)+cast(ue.MobileNo2 as nvarchar))                         
-- or email in (ue.emailid,ue.EmailID1,ue.EmailID2) )                    
--)                    
--begin                   
 SET Context_Info 0x55555            
INSERT INTO UserLeads (LeadNo , PersonName , CompanyName , MobileNo , MobileNo1 , MobileNo2 , EmailID , EmailID1 , EmailID2 , City , [State] , Country , CountryCode , CountryCode1 ,                         
CountryCode2 , PinCode , ResidentialAddress , OfficeAddress , AssignedTo ,                                   
 SourceName , MediumName , CampaignName , InitialRemarks , ParentID , FollowUpStatus , NextStatusDate , Remarks , Products , AmountPaid , CreatedOn , CreatedBy , FollowupDate,enquirysource)            
SELECT (@maxID + 1) AS LeadNo , PersonName , CompanyName , MobileNo , MobileNo1 , MobileNo2 , EmailID , EmailID1 , EmailID2 , City , [State] , Country , CountryCode , CountryCode1 ,                                   
 CountryCode2 ,PinCode , ResidentialAddress , OfficeAddress , @AssignTo AS AssignedTo ,                         
 SourceName , MediumName , CampaignName , InitialRemarks , ParentID , @FollowupStatus AS FollowUpStatus , @NextStatusDate AS NextStatusDate ,                                   
 @Remarks AS Remarks , @Products AS Products , @AmountPaid AS AmountPaid , GETDATE() AS CreatedOn , @CreatedBy AS CreatedBy , @FollowupDate AS FollowupDate,24                                    
FROM UserEnquiry AS ue    (nolock)                   
WHERE ue.EnquiryID =@eid           
and not exists           
(select 1 from userleads_mobile_email(nolock) where Parentid=ue.ParentID and           
((email<>'1' and email in (isnull(ue.EmailID,''),isnull(ue.EmailID1,''),isnull(ue.EmailID2,'')))
or           
(mobile<>'0' and mobile in (isnull(ue.MobileNo,''),isnull(ue.MobileNo1,''),isnull(ue.MobileNo2,'')))
))          
                        
                         
 select @leadid=SCOPE_IDENTITY()                        
  SET Context_Info 0x;            
          
if isnull(@leadid,0)>0                        
 begin                        
 insert into #tempUE(enquiryid,leadid)                        
 select @eid as enquiryid,@leadid as leadid                        
select @leadno=leadno,@eligibleenquiries=@eligibleenquiries+1  from userleads(nolock) where id=@leadid                        
INSERT INTO LeadInteractionHistory (LeadNo , FollowUpStatus , NextStatusDate , Remarks , Products , AmountPaid , AssignedTo , ParentID , CreatedOn , CreatedBy , FollowupDate, IsReAssign,id_lead)                                     
SELECT LeadNo , FollowUpStatus , NextStatusDate , Remarks , Products , AmountPaid , AssignedTo , @ParentID , CreatedOn , CreatedBy , @FollowupDate, @IsReAssign,id                                    
FROM userleads(nolock) where id=@leadid;                                    
                        
begin try                          
insert into customfieldLeadvalue(LeadID,EnquiryID,fieldID,fieldvalue)                           
select id,@eid,cfe.fieldID,cfe.fieldvalue from userleads(nolock) as ttl join customfieldEnquiryvalue(nolock) as cfe                           
on @eid = cfe.EnquiryID  and ttl.id=@leadid                        
end try                          
Begin catch                          
exec usp_InsertErrorInfo                               
end catch                           
                        
UPDATE ue SET  ue.IsOpen = 0, ue.LeadNo = @LeadNo FROM UserEnquiry ue where ue.EnquiryID = @eid;                                    
end                                    
--end                
delete from #enq where value=@eid
select @newtotal=@newtotal-1,@leadno=0,@leadid=0                        
end             

commit

drop table if exists #enq                        
if @eligibleenquiries>0               
 begin                                
SELECT 'Record Saved' as status,cast(@eligibleenquiries as nvarchar)+ ' Records Saved as lead, '                            
 + cast((@ftotal-@eligibleenquiries) as nvarchar) + ' duplicate entries' as Msg, EnquiryID, LeadID            from #tempUE            
           
 if @BatchID IS NOT NULL AND @BatchID <> 0          
BEGIN          
 Update  Tbl_MassOperationSummary set BatchEndTime= GetDate() , Remarks = 'Record Saved ', IsProcessed=1 where BatchID=@BatchID           
END          
end                              
 else                                
 begin                                
 Select 'Record not saved' as status,cast((@ftotal-@eligibleenquiries) as nvarchar) + ' duplicate entries, No records saved as lead.' as Msg, 0 as EnquiryID, 0 as LeadID           
            
 if @BatchID IS NOT NULL AND @BatchID <> 0          
BEGIN          
 Update  Tbl_MassOperationSummary set BatchEndTime= GetDate() , Remarks = 'Record not Saved ', IsProcessed=1  where BatchID=@BatchID           
END          
 end                                
                                    
drop table if exists #tempUE                                
DROP TABLE  if exists #TempTable;                 
DROP TABLE  if exists #enq;          
END 



GO

/* ============================================================
   Procedure: [dbo].[usp_MassAddFollowupfromEnq_ChangeWithFollowupDate1_CustomFields]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

          
CREATE   PROCEDURE [dbo].usp_MassAddFollowupfromEnq_ChangeWithFollowupDate1_CustomFields          
(          
    @EnqID          VARCHAR(max), --='2558419#2558420#2554188#2554125#2577089',           
    @FollowupStatus BIGINT,           
    @AssignTo       BIGINT,           
    @NextStatusDate VARCHAR(50),           
    @Remarks        VARCHAR(500),           
    @Products       VARCHAR(500),           
    @AmountPaid     VARCHAR(50),           
    @CreatedBy      BIGINT,           
    @ParentID       BIGINT          
)          
AS          
BEGIN          
declare @total int=(select count(1) from dbo.fn_split(@EnqID,'#'))      
    DECLARE @maxID INT;          
    DECLARE @FollowupDate DATETIME= NULL;          
          
    IF(@NextStatusDate <> '')          
    BEGIN          
            SET @FollowupDate = @NextStatusDate;          
            SELECT @FollowupDate = dbo.[fn_getISTtimefromusertime](@ParentID, @FollowupDate);          
            SELECT @NextStatusDate = CONVERT(NVARCHAR(100), @FollowupDate, 121);          
    END;          
              
    SET @maxID = ISNULL(          
    (          
        SELECT MAX(ul.LeadNo)          
        FROM UserLeads AS ul    (nolock)      
        WHERE ul.ParentID = @ParentID          
    ), 0);          
      
create table #temp(leadno bigint,countrycode varchar(50),mobile varchar(100),email varchar(100))                                
insert into #temp(leadno,countrycode,mobile,email)                                
select leadno,isnull(CountryCode,'0'),isnull(nullif(mobileno,''),'0'),'1' from UserLeads(nolock) where ParentID=@ParentID and ISNULL(MobileNo,'')<>''                                
union                                
select leadno,isnull(CountryCode1,'0'),isnull(nullif(mobileno1,''),'0'),'1' from UserLeads(nolock) where ParentID=@ParentID and isnull(MobileNo1,'')<>''                                
union                                
select leadno,isnull(CountryCode2,'0'),isnull(nullif(mobileno2,''),'0'),'1' from UserLeads(nolock) where ParentID=@ParentID and isnull(MobileNo2,'')<>''                                
union                                
      
select leadno,'0','0',isnull(nullif(emailid,''),'1') from UserLeads(nolock) where ParentID=@ParentID   and isnull(emailid,'')<>''                              
union                                
select leadno,'0','0',isnull(nullif(emailid1,''),'1') from UserLeads(nolock) where ParentID=@ParentID  and isnull(emailid1,'')<>''                                               
union                                
select leadno,'0','0',isnull(nullif(emailid2,''),'1') from UserLeads(nolock) where ParentID=@ParentID  and isnull(emailid2,'')<>''                
      
SELECT ( @maxID + ROW_NUMBER() OVER( ORDER BY ue.EnquiryID) ) AS LeadNo , EnquiryID , PersonName , CompanyName , MobileNo , MobileNo1 , MobileNo2 , EmailID , EmailID1 , EmailID2 , City , [State] , Country , CountryCode , CountryCode1 ,         
 CountryCode2 ,PinCode , ResidentialAddress , OfficeAddress , @AssignTo AS AssignedTo , SourceName , MediumName , CampaignName , InitialRemarks , ParentID , @FollowupStatus AS FollowUpStatus , @NextStatusDate AS NextStatusDate ,         
 @Remarks AS Remarks , @Products AS Products , @AmountPaid AS AmountPaid , GETDATE() AS CreatedOn , @CreatedBy AS CreatedBy , @FollowupDate AS FollowupDate          
    INTO #TempTable          
    FROM UserEnquiry AS ue    (nolock)      
    WHERE ue.EnquiryID IN ( SELECT fs.[value] FROM dbo.fn_Split ( @EnqID , '#') AS fs ) AND ue.ParentID = @ParentID      
 and not exists(select 1 from #temp where cast(countrycode as nvarchar)+cast(mobile as nvarchar)   
 in (cast(ue.countrycode as nvarchar)+cast(ue.MobileNo as nvarchar),  
 cast(ue.CountryCode1 as nvarchar)+cast(ue.MobileNo1 as nvarchar),  
 cast(ue.countrycode2 as nvarchar)+cast(ue.MobileNo2 as nvarchar))   
 or email in (emailid,EmailID1,EmailID2) );      
 declare @eligibleenquries int=@@ROWCOUNT;          
      
          
    INSERT INTO UserLeads (                          
    -- ID -- this column value is auto-generated                              
    LeadNo , PersonName , CompanyName , MobileNo , MobileNo1 , MobileNo2 , EmailID , EmailID1 , EmailID2 , City , [State] , Country , CountryCode , CountryCode1 , CountryCode2 , PinCode , ResidentialAddress , OfficeAddress , AssignedTo ,         
 SourceName , MediumName , CampaignName , InitialRemarks , ParentID , FollowUpStatus , NextStatusDate , Remarks , Products , AmountPaid , CreatedOn , CreatedBy , FollowupDate)           
    SELECT LeadNo , PersonName , CompanyName , MobileNo , MobileNo1 , MobileNo2 , EmailID , EmailID1 , EmailID2 , City , [State] , Country , CountryCode , CountryCode1 , CountryCode2 , PinCode , ResidentialAddress , OfficeAddress , AssignedTo , SourceName
  
    
      
        
 , MediumName , CampaignName , InitialRemarks , ParentID , FollowUpStatus , NextStatusDate , Remarks , Products , AmountPaid , CreatedOn , CreatedBy , FollowupDate          
    FROM #TempTable;          
          
    INSERT INTO LeadInteractionHistory (                          
    -- ID -- this column value is auto-generated                              
    LeadNo , FollowUpStatus , NextStatusDate , Remarks , Products , AmountPaid , AssignedTo , ParentID , CreatedOn , CreatedBy , FollowupDate)           
    SELECT LeadNo , FollowUpStatus , NextStatusDate , Remarks , Products , AmountPaid , AssignedTo , @ParentID , CreatedOn , CreatedBy , @FollowupDate          
    FROM #TempTable;          
          
    --UPDATE UserEnquiry                          
    --SET    IsOpen = 0                          
    --WHERE  EnquiryID   IN (SELECT fs.[value]                          
    --                       FROM   dbo.fn_Split(@EnqID, '#') AS fs)                          
    --       AND ParentID = @ParentID                          
          
    UPDATE ue SET  ue.IsOpen = 0, ue.LeadNo = tp.LeadNo          
    FROM UserEnquiry ue INNER JOIN #TempTable tp           
    ON tp.EnquiryID = ue.EnquiryID;          
          
    --WHERE  EnquiryID   IN (SELECT fs.[value]                          
    --                       FROM   dbo.fn_Split(@EnqID, '#') AS fs)                          
    --       AND ParentID = @ParentID                          
      


	  --Start custom fields
	  begin try
	 	insert into customfieldLeadvalue(LeadID,EnquiryID,fieldID,fieldvalue) 
		select
		  (select top 1 isnull(ulinner.ID,0) from UserLeads(nolock) as ulinner where ulinner.LeadNo = ttl.LeadNo and ulinner.ParentID = ttl.ParentID)
		  ,ttl.EnquiryID
		  ,cfe.fieldID
		  ,cfe.fieldvalue
		  from #TempTable(nolock) as ttl join customfieldEnquiryvalue(nolock) as cfe 
		  on ttl.EnquiryID = cfe.EnquiryID
	  end try
	  Begin catch
	   exec usp_InsertErrorInfo     
	  end catch 

	  --End custom fields
	  
	  
	      
 if @eligibleenquries>0       
 begin      
    SELECT 'Record saved' as status,cast(@eligibleenquries as nvarchar)+ ' Records Saved as lead, '  
 + cast((@total-@eligibleenquries) as nvarchar) + ' duplicate entries' as Msg, TT.EnquiryID, UL.ID as LeadID          
    From #TempTable TT  join UserLeads UL (nolock)          
    ON TT.LeadNo = UL.LeadNo and UL.ParentID = @ParentID          
 end      
 else      
 begin      
 Select 'Record not saved' as status,cast((@total-@eligibleenquries) as nvarchar) + ' duplicate entries, No records saved as lead.' as Msg, 0 as EnquiryID, 0 as LeadID          
 end      
          
 drop table #temp      
    DROP TABLE #TempTable;          
END 


GO

/* ============================================================
   Procedure: [dbo].[usp_MassAddFollowupfromEnq_ChangeWithFollowupDate1_CustomFields1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

            
CREATE   PROCEDURE [dbo].usp_MassAddFollowupfromEnq_ChangeWithFollowupDate1_CustomFields1            
(            
    @EnqID          VARCHAR(max), --='2558419#2558420#2554188#2554125#2577089',             
    @FollowupStatus BIGINT,             
    @AssignTo       BIGINT,             
    @NextStatusDate VARCHAR(50),             
    @Remarks        VARCHAR(500),             
    @Products       VARCHAR(500),             
    @AmountPaid     VARCHAR(50),             
    @CreatedBy      BIGINT,             
    @ParentID       BIGINT            
)            
AS            
BEGIN     
select * into #enq from  dbo.fn_split(@EnqID,'#')     
declare @total int=(select max(position) from #enq),@eid bigint=0 ,@leadid bigint ,@leadno bigint,@eligibleenquiries int=0     
DECLARE @maxID INT,@ftotal int=@total            
DECLARE @FollowupDate DATETIME= NULL;            
 create table #temp(enquiryid bigint,leadid bigint)           
IF(@NextStatusDate <> '')            
BEGIN            
SET @FollowupDate = @NextStatusDate;            
SELECT @FollowupDate = dbo.[fn_getISTtimefromusertime](@ParentID, @FollowupDate);            
SELECT @NextStatusDate = CONVERT(NVARCHAR(100), @FollowupDate, 121);            
END;            
                
while @total>0
begin
select @eid=min(value) from #enq where value>@eid
SET @maxID = ISNULL((SELECT MAX(ul.LeadNo) FROM UserLeads AS ul    (nolock) WHERE ul.ParentID = @ParentID ), 0);            
INSERT INTO UserLeads (LeadNo , PersonName , CompanyName , MobileNo , MobileNo1 , MobileNo2 , EmailID , EmailID1 , EmailID2 , City , [State] , Country , CountryCode , CountryCode1 , 
CountryCode2 , PinCode , ResidentialAddress , OfficeAddress , AssignedTo ,           
 SourceName , MediumName , CampaignName , InitialRemarks , ParentID , FollowUpStatus , NextStatusDate , Remarks , Products , AmountPaid , CreatedOn , CreatedBy , FollowupDate)             
SELECT (@maxID + 1) AS LeadNo , PersonName , CompanyName , MobileNo , MobileNo1 , MobileNo2 , EmailID , EmailID1 , EmailID2 , City , [State] , Country , CountryCode , CountryCode1 ,           
 CountryCode2 ,PinCode , ResidentialAddress , OfficeAddress , @AssignTo AS AssignedTo , 
 SourceName , MediumName , CampaignName , InitialRemarks , ParentID , @FollowupStatus AS FollowUpStatus , @NextStatusDate AS NextStatusDate ,           
 @Remarks AS Remarks , @Products AS Products , @AmountPaid AS AmountPaid , GETDATE() AS CreatedOn , @CreatedBy AS CreatedBy , @FollowupDate AS FollowupDate            
FROM UserEnquiry AS ue    (nolock)        
WHERE ue.EnquiryID =@eid 
 and 
not exists(select 1 from userleads_mobile_email where cast(countrycode as nvarchar)+cast(mobile as nvarchar)     
 in (cast(ue.countrycode as nvarchar)+cast(ue.MobileNo as nvarchar),    
 cast(ue.CountryCode1 as nvarchar)+cast(ue.MobileNo1 as nvarchar),    
 cast(ue.countrycode2 as nvarchar)+cast(ue.MobileNo2 as nvarchar))     
 or email in (emailid,EmailID1,EmailID2) );        
 select @leadid=SCOPE_IDENTITY()

if @leadid>0
 begin
 insert into #temp(enquiryid,leadid)
 select @eid,@leadid
select @leadno=leadno,@eligibleenquiries=@eligibleenquiries+1  from userleads(nolock) where id=@leadid
INSERT INTO LeadInteractionHistory (LeadNo , FollowUpStatus , NextStatusDate , Remarks , Products , AmountPaid , AssignedTo , ParentID , CreatedOn , CreatedBy , FollowupDate)             
SELECT LeadNo , FollowUpStatus , NextStatusDate , Remarks , Products , AmountPaid , AssignedTo , @ParentID , CreatedOn , CreatedBy , @FollowupDate            
FROM userleads(nolock) where id=@leadid;            

begin try  
insert into customfieldLeadvalue(LeadID,EnquiryID,fieldID,fieldvalue)   
select id,@eid,cfe.fieldID,cfe.fieldvalue from userleads(nolock) as ttl join customfieldEnquiryvalue(nolock) as cfe   
on @eid = cfe.EnquiryID  and ttl.id=@leadid
end try  
Begin catch  
exec usp_InsertErrorInfo       
end catch   

UPDATE ue SET  ue.IsOpen = 0, ue.LeadNo = @LeadNo FROM UserEnquiry ue where ue.EnquiryID = @eid;            
end            
 
select @total=@total-1,@leadno=0,@leadid=0
end
drop table if exists #enq
if @eligibleenquiries>0         
 begin        
SELECT 'Record saved' as status,cast(@eligibleenquiries as nvarchar)+ ' Records Saved as lead, '    
 + cast((@ftotal-@eligibleenquiries) as nvarchar) + ' duplicate entries' as Msg, EnquiryID, LeadID            from #temp
end        
 else        
 begin        
 Select 'Record not saved' as status,cast((@total-@eligibleenquiries) as nvarchar) + ' duplicate entries, No records saved as lead.' as Msg, 0 as EnquiryID, 0 as LeadID            
 end        
            
drop table if exists #temp        
DROP TABLE  if exists #TempTable;            
END 


GO

