CREATE   PROCEDURE [dbo].[usp_MassAddFollowupfromEnq_ChangeWithFollowupDate1_Replication]    
(                                              
 @EnqID NVARCHAR(max),  
 @FollowupStatus BIGINT,  
 @AssignTo BIGINT,  
 @NextStatusDate VARCHAR(50),  
 @Remarks VARCHAR(500),  
 @Products VARCHAR(500),  
 @AmountPaid VARCHAR(50),  
 @CreatedBy BIGINT,  
 @ParentID BIGINT,  
 @IsReAssign bit = 0,  
 @BatchID BIGINT = 0 ,  
 @StartDateTime VARCHAR(50)='',  
  @metatdata NVARCHAR(max)='',  
 @userid BIGINT  
)                                              
AS                                              
BEGIN      
  
 --  declare @EnqID NVARCHAR(max)=N'369511345,369511344,369511343,369511342,369511340,369511338,369511337,369511336,369511335,369511334,369511333,369511332,369511331,369511330,369511329,369511328,369511327,369511326,369511325,369511324',  
 --@FollowupStatus BIGINT=1368,  
