 --@AmountPaid VARCHAR(50)=0,  
 --@CreatedBy BIGINT=41960,  
 --@ParentID BIGINT=41960,  
 --@IsReAssign bit = 0,  
 --@BatchID BIGINT = 0 ,  
 --@StartDateTime VARCHAR(50)=N'31-Jul-2025 14:47',  
 -- @metatdata NVARCHAR(max)=N'[{"IDS":"369511345,369511344,369511343,369511342,369511340,369511338,369511337,369511336,369511335,369511334,369511333,369511332,369511331,369511330,369511329,369511328,369511327,369511326,369511325,369511324","AssignTo":42369,"FollowupStatus":1368,"NextStatusDate":"2025-08-01 02:42:00.000","Products":"","AmountPaid":0.0,"Remarks":"test","IsReassign":0,"Fallowupdatetime":"31-Jul-2025 14:47"}]',  
 --@userid BIGINT=N'41960'

  
 insert into tbl_trace_DbObjectExecution(DbOjectName,DbObjectType,MetaData,ActionDescription,ActionTimeStamp)  
