BEGIN      
print concat('@EnqID',@EnqID)  
INSERT INTO #enqt (enquiryid, CountryCode, Mobile, email, Parentid, position, value)                    
select enquiryid, CountryCode, Mobile, email, Parentid, position, value from Userenquiry_Mobile_Email u (nolock) cross apply dbo.fn_split(@EnqID,',') f where f.value=u.enquiryid                        
END                    
  print '1'                  
declare @total int=(select count(distinct enquiryid) from #enqt),@eid bigint=0 ,@leadid bigint ,@leadno bigint,@eligibleenquiries int=0,@newtotal int   
  
/*   
  
Added By DBA   
Date : 2024-12-17  
  
*/  
  
/*  
delete e from #enqt e where                        
(e.email<>'1' and e.email in                         
(select email from userleads_mobile_email(nolock) ue                         
where Parentid=e.ParentID))                        
or (e.mobile<>'0' and e.CountryCode <> '0'                        
and e.mobile in                        
(select mobile from userleads_mobile_email(nolock) ue                         
where Parentid=e.ParentID)                        
)  
*/  
  
 print '12'    
DELETE e FROM #enqt e  
INNER JOIN (  
   SELECT ParentID, EmailID AS email FROM UserLeads WHERE EmailID IS NOT NULL AND EmailID != ''  
   UNION ALL  
   SELECT ParentID, EmailID1 AS email FROM UserLeads WHERE EmailID1 IS NOT NULL AND EmailID1 != ''  
   UNION ALL  
   SELECT ParentID, EmailID2 AS email FROM UserLeads WHERE EmailID2 IS NOT NULL AND EmailID2 != ''  
   ) ue  
 ON e.Parentid = ue.Parentid AND e.email = ue.email  
WHERE e.email <> '1';  
  
DELETE e FROM #enqt e  
INNER JOIN (  
   SELECT ParentID, MobileNo AS mobile FROM UserLeads WHERE MobileNo IS NOT NULL AND MobileNo != ''  
   UNION ALL  
   SELECT ParentID, MobileNo1 AS mobile FROM UserLeads WHERE MobileNo1 IS NOT NULL AND MobileNo1 != ''  
   UNION ALL  
   SELECT ParentID, MobileNo2 AS mobile FROM UserLeads WHERE MobileNo2 IS NOT NULL AND MobileNo2 != ''  
   ) ue  
 ON e.Parentid = ue.Parentid AND e.Mobile = ue.mobile  
WHERE e.mobile <> '0' and e.CountryCode <> '0';  
  
 WITH MobileDuplicates AS (
    SELECT *,rn = ROW_NUMBER() OVER (PARTITION BY Mobile ORDER BY enquiryid)
    FROM #enqt
	where mobile not in ('0','NA','N/A') 

)
DELETE FROM MobileDuplicates WHERE rn > 1;

WITH EmailDuplicates AS (
    SELECT *,rn = ROW_NUMBER() OVER (PARTITION BY email ORDER BY enquiryid)
    FROM #enqt
	where email not in ('1','NA','N/A') 
)
DELETE FROM EmailDuplicates WHERE rn > 1;

DROP TABLE IF EXISTS #enqt_email;  
DROP TABLE IF EXISTS #enqt_mobile;  
  
SELECT ue.* INTO #enqt_email  
FROM   
 (  
 SELECT ParentID, EmailID AS email FROM UserLeads WHERE EmailID IS NOT NULL AND EmailID != ''  
 UNION ALL  
 SELECT ParentID, EmailID1 AS email FROM UserLeads WHERE EmailID1 IS NOT NULL AND EmailID1 != ''  
 UNION ALL  
 SELECT ParentID, EmailID2 AS email FROM UserLeads WHERE EmailID2 IS NOT NULL AND EmailID2 != ''  
 ) ue  
INNER JOIN (SELECT DISTINCT ParentID FROM #enqt) e  
 ON e.Parentid = ue.Parentid  
  
SELECT ue.* INTO #enqt_mobile  
FROM   
 (  
 SELECT ParentID, MobileNo AS mobile FROM UserLeads WHERE MobileNo IS NOT NULL AND MobileNo != ''  
 UNION ALL  
 SELECT ParentID, MobileNo1 AS mobile FROM UserLeads WHERE MobileNo1 IS NOT NULL AND MobileNo1 != ''  
 UNION ALL  
 SELECT ParentID, MobileNo2 AS mobile FROM UserLeads WHERE MobileNo2 IS NOT NULL AND MobileNo2 != ''  
 ) ue  
INNER JOIN (SELECT DISTINCT ParentID FROM #enqt) e  
 ON e.Parentid = ue.Parentid  
     
/* End of DBA Modification */  
  
select distinct position,[value] into #enq from #enqt                        
  
--drop table if exists #enqt         
  
select @newtotal=count(1) from #enq                        
DECLARE @maxID INT,@ftotal int=@total                                              
DECLARE @FollowupDate DATETIME= NULL;                                              
create table #tempUE(enquiryid bigint,leadid bigint)                                             
IF(@NextStatusDate <> '')                                              
BEGIN                                              
SET @FollowupDate = @NextStatusDate;                                              
SELECT @FollowupDate = dbo.[fn_getISTtimefromusertime](@ParentID, @FollowupDate);                                              
