/* ============================================================
   Procedure: [dbo].[usp_massDelete]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_massDelete]  
    @IDS VARCHAR(MAX) = '',    
    @MassOperationName NVARCHAR(100),      
    @EntityType NVARCHAR(10),              
    @UserId BIGINT,                        
    @StartDateTime VARCHAR(50) = ''        
  
AS  
BEGIN  
    SET NOCOUNT ON;  
    
	--declare  @IDS VARCHAR(MAX) = '17493007/17486643/17486000/17480218/17403090',    
 --   @MassOperationName NVARCHAR(100)='Delete',      
 --   @EntityType NVARCHAR(10)='Lead',              
 --   @UserId BIGINT=32222,                        
 --   @StartDateTime VARCHAR(50) = ''  

	
	BEGIN TRY  

        declare @jsonids nvarchar(max)='';  
  SELECT @jsonids = (     SELECT id      FROM (         SELECT value AS id          FROM fn_Split(@IDS, ',')     ) AS tbl     FOR JSON AUTO );  
  
        DECLARE @IDsTable TABLE (ID BIGINT);    
        DECLARE @ParentID BIGINT;  
        DECLARE @NewBatchID BIGINT;  
  
        -- Fetch the ParentID using @UserId  
        SELECT @ParentID = ParentID  
        FROM User_Detail (NOLOCK)  
        WHERE User_ID = @UserId;  
  
        -- Insert into Tbl_MassOperationSummary and capture the BatchID  
        INSERT INTO Tbl_MassOperationSummary (  
            MassOperationName,  
            UserID,  
            Parentid,  
            CreatedDate,  
            IsProcessed,  
            Remarks,  
            BatchStartTime,  
            BatchEndTime,  
            EntityType,  
            isvalid,  
            metadata,  
            ErrorDetails,  
            SenderId,  
            ScheduleDateTime  
        )  
        VALUES (  
            @MassOperationName,  
            @UserId,  
            @ParentID,  
            GETDATE(),  
            0,                 
            NULL,              
            NULL,              
            NULL,              
            @EntityType,  
            1,                 
            @jsonids,               
            NULL,              
            Null,  
            @StartDateTime     
        );  
  
        -- Get the BatchID of the last inserted row  
        SELECT @NewBatchID = SCOPE_IDENTITY();  
  
    --    -- Remove braces from @IDS if they exist  
    --    SET @IDS = REPLACE(REPLACE(@IDS, '{', ''), '}', '');  
  	--
    --    -- Split the IDs and insert into the temporary table  
    --    DECLARE @Pos INT, @Str VARCHAR(MAX);  
    --    SET @Pos = 1;  
    --    WHILE CHARINDEX(',', @IDS, @Pos) > 0  
    --    BEGIN  
    --        SET @Str = SUBSTRING(@IDS, @Pos, CHARINDEX(',', @IDS, @Pos) - @Pos);  
    --        INSERT INTO @IDsTable (ID) VALUES (CAST(@Str AS BIGINT));  
    --        SET @Pos = CHARINDEX(',', @IDS, @Pos) + 1;  
    --    END  
    --    INSERT INTO @IDsTable (ID) VALUES (CAST(SUBSTRING(@IDS, @Pos, LEN(@IDS) - @Pos + 1) AS BIGINT));  
  	--
    --    -- Insert records into Tbl_MassOperationDetails using the new BatchID  
    --    INSERT INTO Tbl_MassOperationDetails (SummaryId, EntityID)  
    --    SELECT @NewBatchID, ID FROM @IDsTable;  
  
       -- Normalize input format: accept "17493007/17486643/17486000" OR "17493007,17486643"
          SET @IDS = REPLACE(@IDS, '/', ',');
          SET @IDS = REPLACE(REPLACE(@IDS, '{', ''), '}', '');
          
          -- Split IDs and populate temporary table
          INSERT INTO @IDsTable (ID)
          SELECT CAST(value AS BIGINT)
          FROM STRING_SPLIT(@IDS, ',')
          WHERE ISNUMERIC(value) = 1;
          
          -- Insert into detail table
          INSERT INTO Tbl_MassOperationDetails (SummaryId, EntityID)  
          SELECT @NewBatchID, ID 
          FROM @IDsTable;


  EXEC [dbo].[Usp_MassOperationLeadEnquiryProcess] @summary_batchid = @NewBatchID;  
        -- Return a status message and count of rows deleted for the given IDs  
        SELECT 'Success' AS StatusMessage, COUNT(*) AS TotalDeletedRecords FROM @IDsTable;  
  
    END TRY  
    BEGIN CATCH  
        DECLARE @ErrorMessage NVARCHAR(4000);  
        DECLARE @ErrorSeverity INT;  
        DECLARE @ErrorState INT;  
  
        SELECT  
            @ErrorMessage = ERROR_MESSAGE(),  
            @ErrorSeverity = ERROR_SEVERITY(),  
            @ErrorState = ERROR_STATE();  
  
       RAISERROR (@ErrorMessage, @ErrorSeverity, @ErrorState);  
    END CATCH;  
END;  


GO

