	lastactivityby  ,astactivitydate ,lastactivitydirection ,unreadconversations  ,
	isdeactivatedon ,SnoozedDateTime ,is_blocked ,country_iso ,wa_chatexpiry ,wa_chargesexpiry )
    EXEC usp_clr_FillRemoteData @query;


 if(exists(select 1 from #temp1 
	where trim(lower(Entity)) = 'enquiry' and Entityid IN (SELECT fs.[value]      
               FROM   dbo.fn_Split(@IDCollections, '#') fs)))
/* SET @sqlquery = '
SELECT TOP 1 1 
FROM convusers (NOLOCK) 
WHERE LTRIM(RTRIM(LOWER(Entity))) = ''enquiry'' 
  AND Entityid IN (
      SELECT [value] 
      FROM dbo.fn_Split(''' + @IDCollections + ''', ''#'')
  )';

-- Execute the SQL using the CLR method to check if the record exists
EXEC usp_clr_GetRemoteLongValue     @sqlquery, @retval = @existsFlag OUTPUT;*/

-- Use the @existsFlag in your logic
IF @existsFlag > 0
 begin
	update #temp1 set isactive = 0 
		where  trim(lower(Entity)) = 'enquiry' and Entityid IN (SELECT fs.[value]      
               FROM   dbo.fn_Split(@IDCollections, '#') fs)
 /*SET @sqlquery = '
UPDATE convusers
SET isactive = 0
WHERE LTRIM(RTRIM(LOWER(Entity))) = ''enquiry'' 
  AND Entityid IN (
      SELECT [value]
      FROM dbo.fn_Split(''' + @IDCollections + ''', ''#'')
  )';

-- Execute the SQL using the CLR method
EXEC usp_clr_ExecuteRemoteQuery @sqlquery;*/
 end
   
