CREATE   PROCEDURE usp_MassEnquiryAddTag  
    @IDS VARCHAR(MAX) = '',    
 @Tags nvarchar (max)=null,  
    @MassOperationName NVARCHAR(100),   
    @EntityType NVARCHAR(10),  
    @UserId BIGINT  
AS  
BEGIN  
    SET NOCOUNT ON;  
  
    BEGIN TRY  
        -- Temporary table to hold the split IDs  
        DECLARE @IDsTable TABLE (ID BIGINT)  
          
        -- Temporary table to capture inserted rows  
        DECLARE @InsertedTable TABLE (EntityID BIGINT)  
  DECLARE @ParentID BIGINT;         SELECT @ParentID = ParentID         FROM User_Detail (NOLOCK)         WHERE User_ID = @UserId;  
        -- Split the IDs and insert into the temporary table  
        DECLARE @Pos INT, @Str VARCHAR(MAX)  
        SET @Pos = 1  
        WHILE CHARINDEX(',', @IDS, @Pos) > 0  
        BEGIN  
            SET @Str = SUBSTRING(@IDS, @Pos, CHARINDEX(',', @IDS, @Pos) - @Pos)  
            INSERT INTO @IDsTable (ID) VALUES (CAST(@Str AS BIGINT))  
            SET @Pos = CHARINDEX(',', @IDS, @Pos) + 1  
        END  
        INSERT INTO @IDsTable (ID) VALUES (CAST(SUBSTRING(@IDS, @Pos, LEN(@IDS) - @Pos + 1) AS BIGINT))  
  
        -- Insert into Tbl_MassInternationalSMS and capture the inserted rows  
        INSERT INTO Tbl_MassEnquiryAddTag (  
            EntityID,  
   Tags,  
            MassOperationName,  
            UserID,  
            Parentid,  
            CreatedDate,  
            IsProcessed,  
            Remarks,  
            BatchStartTime,  
            BatchEndTime,  
            EntityType,  
            isvalid,  
            metadata,  
            ErrorDetails  
        )  
        OUTPUT   
            INSERTED.EntityID INTO @InsertedTable -- Capture the inserted rows  
        SELECT  
            ID,  
   @Tags,  
            @MassOperationName,  
            @UserId,  
            @ParentID,   
            GETDATE(),  
            0,   
            NULL,   
            GETDATE(),  
            NULL,   
            @EntityType,  
            1,   
            NULL,   
            NULL   
     
        FROM @IDsTable  
  
        -- Return a status message and count of rows inserted for the given IDs  
        SELECT   
            'Success' AS StatusMessage,   
            COUNT(*) AS TotalRecords   
        FROM @InsertedTable  
    END TRY  
    BEGIN CATCH  
        DECLARE @ErrorMessage NVARCHAR(4000)  
        DECLARE @ErrorSeverity INT  
        DECLARE @ErrorState INT  
  
        SELECT   
            @ErrorMessage = ERROR_MESSAGE(),  
            @ErrorSeverity = ERROR_SEVERITY(),  
            @ErrorState = ERROR_STATE()  
  
        -- Rethrow the error to be handled by the calling procedure or application  
        RAISERROR (@ErrorMessage, @ErrorSeverity, @ErrorState)  
    END CATCH  
END




GO

/* ============================================================
   Procedure: [dbo].[usp_massinternationalsms]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_massinternationalsms]    
    @IDS VARCHAR(MAX) = '',    
    @Msg NVARCHAR(MAX) = NULL,    
    @MassOperationName NVARCHAR(100),    
    @EntityType NVARCHAR(10),    
    @UserId BIGINT,    
    @SenderId NVARCHAR(100),    
    @urltrack BIT = NULL,    
    @TrackedUrl NVARCHAR(MAX) = '',    
    @SmsPlaceHolder NVARCHAR(MAX) = '',    
    @StartDateTime VARCHAR(50)=''         
    
AS    
BEGIN    
    SET NOCOUNT ON;    
    
    BEGIN TRY    
        DECLARE @IDsTable TABLE (ID BIGINT);    
        DECLARE @InsertedTable TABLE (EntityID BIGINT);    
        DECLARE @ParentID BIGINT;    
        DECLARE @NewBatchID BIGINT;    
    
        -- Fetch the ParentID using @UserId    
        SELECT @ParentID = ParentID    
        FROM User_Detail (NOLOCK)    
        WHERE User_ID = @UserId;    
    
        -- Insert into Tbl_MassOperationSummary and capture the BatchID    
        INSERT INTO Tbl_MassOperationSummary (    
            MassOperationName,    
            UserID,    
            Parentid,    
            CreatedDate,    
            IsProcessed,    
            Remarks,    
            BatchStartTime,    
            BatchEndTime,    
            EntityType,    
            isvalid,    
            metadata,    
            ErrorDetails,    
            SenderId,    
            UrlTrack,    
            TrackedUrl,    
            SmsPlaceHolder,    
            ScheduleDateTime    
        )    
        VALUES (    
            @MassOperationName,    
            @UserId,    
            @ParentID,    
            GETDATE(),    
            0,    
            NULL,    
            NULL,    
            NULL,    
            @EntityType,    
            1,    
            @Msg, -- metadata    
            NULL,    
            @SenderId,    
            @urltrack,    
            @TrackedUrl,    
            @SmsPlaceHolder,    
            @StartDateTime    
        );    
    
        -- Get the BatchID of the last inserted row    
        SELECT @NewBatchID = SCOPE_IDENTITY();    
    
        -- Remove braces from @IDS if they exist    
        SET @IDS = REPLACE(REPLACE(@IDS, '{', ''), '}', '');    
    
        -- Split the IDs and insert into the temporary table    
        DECLARE @Pos INT, @Str VARCHAR(MAX);    
        SET @Pos = 1;    
        WHILE CHARINDEX(',', @IDS, @Pos) > 0    
        BEGIN    
            SET @Str = SUBSTRING(@IDS, @Pos, CHARINDEX(',', @IDS, @Pos) - @Pos);    
            INSERT INTO @IDsTable (ID) VALUES (CAST(@Str AS BIGINT));    
            SET @Pos = CHARINDEX(',', @IDS, @Pos) + 1;    
        END    
        INSERT INTO @IDsTable (ID) VALUES (CAST(SUBSTRING(@IDS, @Pos, LEN(@IDS) - @Pos + 1) AS BIGINT));    
    
        -- Insert records into Tbl_MassOperationDetails using the new BatchID    
        INSERT INTO Tbl_MassOperationDetails (SummaryId, EntityID)    
        SELECT @NewBatchID, ID FROM @IDsTable;    
    
        -- Execute the mass operation processing    
        EXEC [dbo].[Usp_MassOperationLeadEnquiryProcess] @summary_batchid = @NewBatchID;    
    
        -- Return a status message, count of inserted rows, and the new BatchID    
        SELECT   
            'Success' AS StatusMessage,   
            COUNT(*) AS TotalRecords,   
            @NewBatchID AS BatchID   
        FROM @IDsTable;    
    
    END TRY    
    BEGIN CATCH    
        DECLARE @ErrorMessage NVARCHAR(4000);    
        DECLARE @ErrorSeverity INT;    
        DECLARE @ErrorState INT;    
    
        SELECT    
            @ErrorMessage = ERROR_MESSAGE(),    
            @ErrorSeverity = ERROR_SEVERITY(),    
            @ErrorState = ERROR_STATE();    
    
        -- Rethrow the error to be handled by the calling procedure or application    
        RAISERROR (@ErrorMessage, @ErrorSeverity, @ErrorState);    
    END CATCH;    
END;  




GO

