CREATE   PROCEDURE [dbo].[Usp_MassOperationEnquiryID]   
(    
  @Txtsearch NVARCHAR(max) = ''    
 ,@Userid INT = 0    
 ,@FilterText NVARCHAR(max) = ''    
 ,@ordstr NVARCHAR(Max) = ''    
 ,@srno NVARCHAR(100)    
 ,@enno NVARCHAR(100)    
 ,@ue_query NVARCHAR(max) = ''    
 ,@MassOperationName Nvarchar(100)   
 )    
AS    
BEGIN    

 --Declare @Txtsearch NVARCHAR(max) = N''    
 --,@Userid INT = 46312   --0    
 --,@FilterText NVARCHAR(max) = N''    
 --,@ordstr NVARCHAR(Max) = N''    
 --,@srno NVARCHAR(100) = '1'   
 --,@enno NVARCHAR(100) = '10'   
 --,@ue_query NVARCHAR(max) = ''    
 --,@MassOperationName Nvarchar(100) = ''   
  


DROP TABLE IF EXISTS #temp2;   
Create Table #Enqtemp (EnquiryID BIGINT)  
DECLARE @Parentid BIGINT  =(Select ParentId from User_Detail (NOLOCK) where User_ID=@Userid)  
DECLARE @User_id Bigint = @Userid   
 DECLARE @TimeZoneName NVARCHAR(255) = isnull((    
    SELECT TimeZone    
    FROM User_Detail(NOLOCK)    
    WHERE User_ID = @Userid    
    ), 'india standard time')    
 DECLARE @IsAdmin BIT = 0    
 DECLARE @Str NVARCHAR(200) = @ordstr;--' personname desc '    
 DECLARE @ColumnName NVARCHAR(200) = ''    
 DECLARE @StrPredefinedOrderBy NVARCHAR(500) = ''    
 DECLARE @StrCustomOrderBy NVARCHAR(500) = ''    
 DECLARE @actUserId BIGINT = @Userid    
    
 IF (rtrim(ltrim(@Str)) <> '')    
 BEGIN    
  SET @Str = ltrim(RTRIM(@Str))    
    
  --select @Str    
  SELECT TOP 1 @ColumnName = value    
  FROM string_split(@Str, ' ')    
    
  --select @ColumnName     
  IF (EXISTS(SELECT 1 FROM INFORMATION_SCHEMA.COLUMNS WHERE table_name = 'UserEnquiry' AND column_name = rtrim(ltrim(@ColumnName))))    
  BEGIN    
   --set @StrPredefinedOrderBy = N' order by ' +  @Str;    
   SET @StrPredefinedOrderBy = N' ' + @Str + ' , ';    
   SET @StrCustomOrderBy = '';    
  END    
  ELSE    
  BEGIN    
   DECLARE @FullDataType NVARCHAR(200) = 'nvarchar(max)'    
    
   SELECT TOP 1 @FullDataType = CASE     
     WHEN ISNULL(datatype, 'v') = 'd'    
      THEN 'date'    
     WHEN ISNULL(datatype, 'v') = 'f'    
      THEN 'bigint'    
     WHEN ISNULL(datatype, 'v') = 'v'    
      THEN 'nvarchar(max)'    
     ELSE 'nvarchar(max)'    
     END    
   FROM customfields WITH (NOLOCK)    
   WHERE ParentID = @Parentid    
    AND fieldname = rtrim(ltrim(@ColumnName))    
    
   DECLARE @CustomStrExp NVARCHAR(200) = '';    
    
   IF(EXISTS(SELECT value FROM string_split(@Str, ' ')WHERE rtrim(ltrim(value)) = 'asc'))    
   BEGIN    
    SET @CustomStrExp = N' ' + 'CAST(' + @ColumnName + ' as  ' + @FullDataType + ')' + '  asc '    
   END    
   ELSE    
   BEGIN    
    SET @CustomStrExp = N' ' + 'CAST(' + @ColumnName + ' as  ' + @FullDataType + ')' + '  desc '    
   END    
    
   SET @StrPredefinedOrderBy = ''    
   --set @StrCustomOrderBy = N' order by ' +  @Str;      
   SET @StrCustomOrderBy = N' ' + @CustomStrExp + ' , ';    
  END    
    --select @StrPredefinedOrderBy    
    --select @StrCustomOrderBy    
 END    
    
  DROP TABLE IF EXISTS #temp1;  
  DROP TABLE IF EXISTS #temp2;  
  
  IF @srno = ''    
  BEGIN    
   SET @srno = '1';    
  END    
    
  IF @enno = ''    
  BEGIN    
   SET @enno = '20';    
  END    
    
  IF (@Txtsearch = '')    
  BEGIN    
   SET @Txtsearch = N' (1=1) ';    
  END;    
    
  IF (@FilterText = '')    
  BEGIN    
   SET @FilterText = N' (1=1) ';    
  END;    
    
  IF (@FilterText LIKE '%MobileNo3%')    
  BEGIN    
   SET @FilterText = replace(@FilterText, 'MobileNo3', 'MobileNo')    
  END    
    
  DECLARE @Query1 NVARCHAR(max) = ''    
  DECLARE @Pivot_Column [nvarchar] (max);    
    
 /*Select Pivot Column*/    
  SELECT @Pivot_Column = COALESCE(@Pivot_Column + ',', '') + QUOTENAME(fieldname)    
  FROM   
  (    
 SELECT DISTINCT [fieldname]    
 FROM customfields(NOLOCK)    
 WHERE ParentID = @ParentID AND isActive = 1    
  ) Tab    
    
 DECLARE @NoCustomFields BIGINT, @filterCnt INT = 0    
    
 SET @NoCustomFields = (    
   SELECT count(DISTINCT [fieldname])    
   FROM customfields    
   WHERE [ParentID] = @ParentID AND [isActive] = 1    
   )    
    
 DECLARE @Query NVARCHAR(max) = ''    
 DECLARE @TeamCode VARCHAR(10) = ''    
 DECLARE @ScopeCode VARCHAR(10) = ''    
 DECLARE @UserIdTeamLst VARCHAR(Max) = ''    
 DECLARE @UserLoginTeamLst VARCHAR(Max) = ''    
 --select @TeamCode = TeamCode, @ScopeCode = ScopeCode, @UserIdTeamLst = UserIdTeamLst, @UserLoginTeamLst = UserLoginTeamLst from dbo.ufn_GetUserRoleScope(@UserId)    
 DECLARE @tbluser TABLE (    
  User_ID BIGINT    
  ,Name VARCHAR(100)    
  ,IMAGE VARCHAR(100)    
  )    
    
 SELECT @IsAdmin = isnull(IsAdmin, 0)    
 FROM User_Detail(NOLOCK)    
 WHERE User_ID = @UserID    
    
 IF (@IsAdmin = 1)    
 BEGIN    
  SET @UserID = 0    
    
  INSERT INTO @tbluser    
  EXEC Use_GetUserDetails @ParentId    
 END    
 ELSE    
 BEGIN    
  INSERT INTO @tbluser    
  EXEC Use_GetUserDetails @UserID    
 END    
    
 SELECT @UserIdTeamLst = isnull(STRING_AGG(User_ID, ','), '')    
 FROM @tbluser    
    
 PRINT '@UserIdTeamLst: ' + @UserIdTeamLst    
    
 IF (@FilterText = ' (1=1) ' AND @Txtsearch = ' (1=1) ')    
 BEGIN    
  PRINT 'Branch A'    
    
  SET @Query =     
   N'SELECT distinct A.Enquiryid,A.Personname,A.Companyname,rtrim(ltrim(A.MobileNo3)) as MobileNo3 , rtrim(ltrim(A.MobileNo1)) as MobileNo1 , rtrim(ltrim(A.MobileNo2)) as MobileNo2, A.EmailID3, A.EmailID1, A.EmailID2, A.Residentialaddress, A.Officeaddress
,A.User_login,rtrim(ltrim(A.MobileNo)) as MobileNo,A.EmailID,A.City,A.[State],A.Country,A.Countrycode,A.Pincode,A.[ADDRESS], A.Initialremarks, A.SourceName, A.MediumName, A.CampaignName, A.Parentid, A.CreatedDate, A.CreatedDate1,A.Createdby,A.Leads,A.Isopen,      
   isnull(A.img_ext,'''') as img_ext, A.WhereAddress, A.Tags, RowNumber1, rc1, A.IsduplicateEmail, A.IsduplicateMobile         
   into #Temp2      
   FROM       
   (       
  SELECT distinct Ue.Enquiryid,Ue.Personname,Ue.Companyname,Ue.Mobileno, ltrim(trim(isnull(Ue.Countrycode, ''''))+'' ''+trim(isnull(Ue.Mobileno, '''')))+ case when trim(isnull(Ue.Mobileno1,''''))<>'''' then '', ...'' else '''' end AS MobileNo3, trim(Ue.Mobileno1) as Mobileno1, trim( Ue.Mobileno2) as Mobileno2,Ue.Emailid,  Ue.Emailid AS EmailID3, Ue.Emailid1, Ue.Emailid2, Ue.Residentialaddress, Ue.Officeaddress, Ud.User_login, Ue.CreatedDate , Ue.City, Ue.[State], Ue.Country, Ue.Countrycode, Ue.Pincode, CASE WHEN Ue.Companyname <> '''' THEN Case WHEN Ue.Officeaddress <> '''' THEN Ue.Officeaddress ELSE Ue.Residentialaddress END ELSE Ue.Residentialaddress END AS [ADDRESS], Ue.Initialremarks, Uss.Name AS SourceName, Ums.Name AS MediumName, Ucs.Name AS CampaignName,  Ue.Parentid, CONVERT(VARCHAR(10), Ue.Createddate, 101) + STUFF( RIGHT(CONVERT(VARCHAR(26), Ue.Createddate, 109), 15),7,7, '' '') AS CreatedDate1, Ue.Createdby, CASE WHEN isnull(ue.isopen,1)=1 then null else ue.LeadNo end AS Leads, (CASE WHEN isnull(ue.isopen,1)=1 and isnull(ue.LeadNo,0) = 0 then ''open'' when isnull(ue.LeadNo,0) > 0 THEN ''lead'' ELSE ''open'' END) as Isopen, Ue.img_ext, Ue.WhereAddress, isnull(tg.Tags, '''') Tags , ROW_NUMBER() OVER(ORDER BY '     
   + @StrPredefinedOrderBy + '   Ue.Enquiryid DESC) AS RowNumber1, count(*) OVER(ORDER BY Ue.Parentid) AS rc1, Ue.IsduplicateEmail, Ue.IsduplicateMobile        
  FROM Userenquiry (NOLOCK) Ue left JOIN Usersourcesettings (NOLOCK) Uss       
  ON Ue.Sourcename = Uss.Sourceid LEFT JOIN Usermediumsettings (NOLOCK) Ums       
  ON Ue.Mediumname = Ums.Mediumid LEFT JOIN Usercampaignsettings (NOLOCK) Ucs       
  ON Ue.Campaignname = Ucs.Campaignid LEFT JOIN User_detail (NOLOCK) Ud       
  ON Ue.Createdby = Ud.User_id and Ue.Parentid = Ud.ParentID LEFT JOIN ( select STRING_AGG(Tag, '','') as Tags, etm.EntityID from TagMaster(nolock) tm inner join EntityTagMapping(nolock) etm on tm.id = etm.TagID and etm.entity = ''enquiry'' and tm.ParentID = ' + Convert(VARCHAR(100), @ParentID) + ' where ISNULL(etm.EntityID, 0) > 0 group by etm.EntityID ) tg on tg.EntityID = Ue.EnquiryId      
  WHERE Ue.Parentid = ' + Convert(VARCHAR(100), @Parentid)    
    
  --CASE WHEN @Userid = 0 THEN N' = UL.AssignedTo '     
  --WHEN @Userid > 0 and isnull(@TeamCode,'') != '' THEN ' in (' + isnull(@UserIdTeamLst, '') + ')'     
  --ELSE ' = ' + CAST(@Userid AS NVARCHAR(MAX)) End + '    
  IF @Userid > 0    
  BEGIN    
   SET @Query += N' AND ' + CASE --When isnull(@Userid,0) > 0 and isnull(@TeamCode,'') != '' then  ' ue.CreatedBy in ('+ isnull(@UserIdTeamLst, '') + ') '    
     WHEN isnull(@UserIdTeamLst, '') != ''    
      THEN ' ue.CreatedBy in (' + isnull(@UserIdTeamLst, '') + ') '    
     WHEN isnull(@Userid, 0) = 0    
      THEN ' ue.CreatedBy = ue.CreatedBy '    
     ELSE ' ue.CreatedBy = ' + Convert(VARCHAR(100), @Userid)    
     END    
  END    
    
  SET @Query += N' ) A Where A.RowNumber1 BETWEEN ' + CONVERT(NVARCHAR(max), @srno) + N' AND ' + CONVERT(NVARCHAR(max), @enno)    
 END    
 ELSE    
 BEGIN    
  PRINT 'Branch B'    
    
  SET @Query += N'SELECT distinct A.Enquiryid,A.Personname,A.Companyname, rtrim(ltrim(A.MobileNo3)) as MobileNo3 , rtrim(ltrim(A.MobileNo1)) as MobileNo1 ,rtrim(ltrim(A.MobileNo2)) as MobileNo2, A.EmailID3, A.EmailID1, A.EmailID2, A.Residentialaddress, A.Officeaddress,A.User_login,A.MobileNo,A.EmailID,A.City,A.[State],A.Country,A.Countrycode,A.Pincode,A.[ADDRESS], A.Initialremarks, A.SourceName, A.MediumName, A.CampaignName, A.Parentid,A.CreatedDate, A.CreatedDate1,A.Createdby,A.Leads,A.Isopen,      
   isnull(A.img_ext,'''') as img_ext, A.WhereAddress, A.Tags, RowNumber1, rc1, A.IsduplicateEmail, A.IsduplicateMobile         
   into #Temp2      
   FROM       
   (       
  Select *, ROW_NUMBER() OVER(ORDER BY ' + @StrPredefinedOrderBy +     
   ' T.Enquiryid DESC) AS RowNumber1, count(*) OVER(ORDER BY T.Parentid) AS rc1        
  From       
  (      
   SELECT distinct Ue.Enquiryid,Ue.Personname,Ue.Companyname,trim(Ue.Mobileno) as Mobileno,ltrim(trim(isnull(Ue.Countrycode, ''''))+'' ''+trim(isnull(Ue.Mobileno, '''')))+ case when trim(isnull(Ue.Mobileno1,''''))<>'''' then '', ...'' else '''' end AS MobileNo3, trim(Ue.Mobileno1) as Mobileno1, trim(Ue.Mobileno2) as Mobileno2,Ue.Emailid, Ue.Emailid AS EmailID3,Ue.Emailid1,Ue.Emailid2,Ue.Residentialaddress,Ue.Officeaddress, Ud.User_login,Ue.CreatedDate , Ue.City, Ue.[State], Ue.Country, Ue.Countrycode, Ue.Pincode, CASE WHEN Ue.Companyname <> '''' THEN Case WHEN Ue.Officeaddress <> '''' THEN Ue.Officeaddress ELSE Ue.Residentialaddress END ELSE Ue.Residentialaddress END AS [ADDRESS], Ue.Initialremarks, Uss.Name AS SourceName, Ums.Name AS MediumName, Ucs.Name AS CampaignName,  Ue.Parentid, CONVERT(VARCHAR(10), Ue.Createddate, 101) + STUFF( RIGHT(CONVERT(VARCHAR(26), Ue.Createddate, 109), 15),7,7, '' '') AS CreatedDate1, Ue.Createdby, CASE WHEN isnull(ue.isopen,1)=1 then null else ue.LeadNo end AS Leads, (CASE
  
 WHEN isnull(ue.isopen,1)=1 and isnull(ue.LeadNo,0) = 0 then ''open'' when isnull(ue.LeadNo,0) > 0 THEN ''lead'' ELSE ''open'' END) as Isopen, Ue.img_ext, Ue.WhereAddress, isnull(tg.Tags, '''') Tags ,Ue.IsduplicateEmail,ue.IsduplicateMobile     
   FROM Userenquiry (NOLOCK) Ue left JOIN Usersourcesettings (NOLOCK) Uss       
   ON Ue.Sourcename = Uss.Sourceid LEFT JOIN Usermediumsettings (NOLOCK) Ums       
   ON Ue.Mediumname = Ums.Mediumid LEFT JOIN Usercampaignsettings (NOLOCK) Ucs       
   ON Ue.Campaignname = Ucs.Campaignid LEFT JOIN User_detail (NOLOCK) Ud       
   ON Ue.Createdby = Ud.User_id and Ue.Parentid = Ud.ParentID LEFT JOIN ( select STRING_AGG(Tag, '','') as Tags, etm.EntityID from TagMaster(nolock) tm inner join EntityTagMapping(nolock) etm on tm.id = etm.TagID and etm.entity = ''enquiry'' and tm.ParentID = '     
   + Convert(VARCHAR(100), @ParentID) + ' where ISNULL(etm.EntityID, 0) > 0 group by etm.EntityID ) tg on tg.EntityID = Ue.EnquiryId    
   WHERE Ue.Parentid = ' + Convert(VARCHAR(100), @ParentID)    
    
  IF @Userid > 0    
  BEGIN    
   --When isnull(@Userid,0) > 0 and isnull(@TeamCode,'') != '' then  ' ue.CreatedBy in ('+ isnull(@UserIdTeamLst, '') + ') '    
   SET @Query += N' AND ' + CASE     
     WHEN isnull(@UserIdTeamLst, '') != ''    
      THEN ' ue.CreatedBy in (' + isnull(@UserIdTeamLst, '') + ') '    
     WHEN isnull(@Userid, 0) = 0    
      THEN ' ue.CreatedBy = ue.CreatedBy '    
     ELSE ' ue.CreatedBy = ' + Convert(VARCHAR(100), @Userid)    
     END    
  END    
    
  SET @Query += N' ) T Where ' + @FilterText + N' ) A Where ' + CASE   
    WHEN @Txtsearch = ' (1=1) '    
     THEN ' A.RowNumber1 BETWEEN ' + CONVERT(NVARCHAR(max), @srno) + N' AND ' + CONVERT(NVARCHAR(max), @enno)    
    ELSE ' (1=1) '    
    END    
 END    
    
 IF (@ue_query = '')    
 BEGIN    
  SET @ue_query = ' (1=1) '    
 END    
    
 IF (@FilterText != '' AND @ue_query != '')    
 BEGIN    
  SET @FilterText += ' AND ' + @ue_query    
 END    
    
 IF (@ordstr = '')    
 BEGIN    
  SET @ordstr = ' Enquiryid desc '    
 END    
    
 IF (@Pivot_Column IS NOT NULL)    
 BEGIN    
  PRINT 'Branch C'    
    
  IF (@Txtsearch = ' (1=1) ') -- From Branch A      
  BEGIN    
   PRINT 'Branch CA'    
    
   SET @Query += CAST(N'; INSERT INTO #EnqTemp (EnquiryID) Select EnquiryId From (SELECT  rc1 AS [rcnt], EnquiryId, PersonName, CompanyName, MobileNo3, MobileNo1, MobileNo2, EmailID3, EmailID1, EmailID2, Residentialaddress, Officeaddress, User_login, MobileNo, EmailID, City, [State], Country, Countrycode, Pincode, [ADDRESS], Initialremarks, SourceName, MediumName, CampaignName, Parentid, dbo.fn_ConvertDateTime(cast(CreatedDate as datetime), ''' + cast(@TimeZoneName AS NVARCHAR(255)) + ''', 0) as CreatedDate,    dbo.fn_ConvertDateTime(cast(CreatedDate1 as datetime), ''' + cast(@TimeZoneName AS NVARCHAR(255)) + ''', 0) as  CreatedDate1, Createdby, Leads, Isopen, Img_ext, ROW_NUMBER() OVER(ORDER BY ' + @StrPredefinedOrderBy + N' ' + @StrCustomOrderBy + '  EnquiryId Desc) + cast( ' + cast(@srno - 1 AS NVARCHAR) + ' as int) ' + '  AS [RowNumber1], WhereAddress, rc1, IsduplicateEmail, IsduplicateMobile,   ' + @Pivot_Column +  
     N' FROM (SELECT EnquiryId, PersonName, CompanyName, MobileNo3, MobileNo1, MobileNo2, EmailID3, EmailID1, EmailID2, Residentialaddress, Officeaddress, User_login, MobileNo, EmailID, City, [State], Country, Countrycode, Pincode, [ADDRESS], Initialremarks, SourceName, MediumName, CampaignName, Parentid, CreatedDate, CreatedDate1, Createdby, Leads, Isopen, Img_ext, WhereAddress, [fieldname], fieldvalue, RowNumber1, rc1, IsduplicateEmail, IsduplicateMobile        
  FROM (select E.Enquiryid, E.PersonName, E.CompanyName, E.MobileNo3, E.MobileNo1, E.MobileNo2, E.EmailID3, E.EmailID1, E.EmailID2, E.Residentialaddress, E.Officeaddress, E.User_login, E.MobileNo, E.EmailID, E.City, E.[State], E.Country, E.Countrycode, E.Pincode, E.[ADDRESS], E.Initialremarks, E.SourceName, E.MediumName, E.CampaignName, E.Parentid, E.CreatedDate, E.CreatedDate1, E.Createdby, E.Leads, E.Isopen, E.Img_ext, E.WhereAddress, y.fieldname, x.fieldvalue ,E.RowNumber1, E.rc1, E.IsduplicateEmail, E.IsduplicateMobile         
  From #temp2 E left join customfieldEnquiryvalue(nolock) x       
  ON E.Enquiryid = x.Enquiryid left join customfields(nolock) y       
  ON x.fieldID=y.field_ID AND y.[ParentID] = '     
     + CAST(@Parentid AS NVARCHAR(MAX)) + ' AND y.[isActive] = 1      
  )q )Tab1      
  PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + ') ) AS Tab2      
  WHERE ' + @Txtsearch + '  ) T1 Where RowNumber1 BETWEEN ' + CONVERT(VARCHAR(100), @srno) + ' AND ' + CONVERT(VARCHAR(100), @enno) + N' ORDER BY ' + @ordstr AS NVARCHAR(MAX));    
  END    
  ELSE    
  BEGIN    
   PRINT 'Branch CB'    
    
   SELECT @filterCnt = count(*)    
   FROM dbo.fn_Split(@Txtsearch, ' ) ')    
    
  SELECT @Query += CAST(N'; select * into #Temp1 From (select [x].EnquiryId, [y].[fieldname],   
 [x].[fieldvalue] from customfieldEnquiryvalue(nolock) x inner join customfields(nolock) y  
 ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + N' AND y.[isActive] = 1 ) T1 PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + N')) AS Tab2 Where ' + @Txtsearch AS NVARCHAR(MAX));  
  
   SET @Query += CAST(N';  INSERT INTO #EnqTemp (EnquiryID) Select EnquiryId From (SELECT ROW_NUMBER() OVER(ORDER BY ' + @StrPredefinedOrderBy + N' ' + @StrCustomOrderBy + '  A.EnquiryId Desc) AS [RowNumber1], count(*) OVER(ORDER BY [ParentID]) AS [rc1], 
count(*) OVER(ORDER BY [ParentID]) AS [rcnt], A.EnquiryId, PersonName, CompanyName, MobileNo3, MobileNo1, MobileNo2, EmailID3, EmailID1, EmailID2, Residentialaddress, Officeaddress, User_login, MobileNo, EmailID, City, [State], Country, Countrycode, Pincode, [ADDRESS], Initialremarks, SourceName, MediumName, CampaignName, Parentid, dbo.fn_ConvertDateTime(cast(CreatedDate as datetime), ''' + cast(@TimeZoneName AS NVARCHAR(255)) + ''', 0) as CreatedDate,      dbo.fn_ConvertDateTime(cast(CreatedDate1 as datetime), ''' + cast(@TimeZoneName AS NVARCHAR(255)) + ''', 0) as  CreatedDate1, Createdby, Leads, Isopen, Img_ext, WhereAddress, ' + @Pivot_Column +     
     N' From #Temp1 A inner join #temp2 E       
  ON A.EnquiryId = E.Enquiryid  
  ) T1 Where RowNumber1 BETWEEN ' + CONVERT(VARCHAR(100), @srno) + ' AND ' + CONVERT(VARCHAR(100), @enno) AS NVARCHAR(MAX)) + N' ORDER BY ' + @ordstr;    
  END    
 END    
 ELSE    
 BEGIN    
  PRINT 'Branch D'    
    
  SET @Query += CAST(N';  INSERT INTO #EnqTemp (EnquiryID) Select EnquiryId From( select distinct Enquiryid, Personname, Companyname, MobileNo3, MobileNo1, MobileNo2, EmailID3,EmailID1,EmailID2,Residentialaddress,Officeaddress,User_login,MobileNo,EmailID,
City,[State], Country,Countrycode,Pincode,[ADDRESS], Initialremarks,  SourceName, MediumName, CampaignName, Parentid,dbo.fn_ConvertDateTime(cast(CreatedDate as datetime), ''' + cast(@TimeZoneName AS NVARCHAR(255)) + ''', 0) as CreatedDate, dbo.fn_ConvertDateTime(cast(CreatedDate1 as datetime), ''' + cast(@TimeZoneName AS NVARCHAR(255)) + ''', 0) as  CreatedDate1,Createdby,Leads,Isopen, isnull(img_ext,'''') as img_ext, WhereAddress, Tags, RowNumber1, rc1, IsduplicateEmail, IsduplicateMobile from #temp2 Where RowNumber1 BETWEEN ' + CONVERT(VARCHAR(100), @srno) + ' AND ' + CONVERT(VARCHAR(100), @enno)
+ N' ) as tbl ORDER BY ' + @ordstr AS NVARCHAR(MAX)) -- +')';    
 END    
    
 PRINT '@FinalQuery:- ' + cast(@Query AS VARCHAR(max))    
    
 EXEC sp_executesql @Query;    
 --select  * from #EnqTemp

  --INSERT INTO Tbl_MassOperationSummary (MassOperationName, UserID, Parentid, CreatedDate, IsProcessed, ProcedureName, FilterCriteria, EntityType)  
   --Values (@MassOperationName, @User_id, @parentid, getdate(), 0, 'Usp_MassOperationEnquiryID', @FilterText, 'Enquiry')  
   
   
 
IF @MassOperationName = 'delete'
BEGIN
    INSERT INTO Tbl_MassOperationSummary (MassOperationName, UserID, Parentid, CreatedDate, IsProcessed, ProcedureName, FilterCriteria, EntityType,isvalid)
			Values (@MassOperationName, @User_id, @parentid, getdate(), 0, 'Usp_MassOperationEnquiryID', @FilterText, 'Enquiry',1)
			END
ELSE
BEGIN
 
	INSERT INTO Tbl_MassOperationSummary (MassOperationName, UserID, Parentid, CreatedDate, IsProcessed, ProcedureName, FilterCriteria, EntityType)
			Values (@MassOperationName, @User_id, @parentid, getdate(), 0, 'Usp_MassOperationEnquiryID', @FilterText, 'Enquiry')
			END
 
 
   
   Declare @BatchID Bigint  = Scope_Identity()  
  
  INSERT INTO Tbl_MassOperationDetails (SummaryId,EntityID)  
  Select @BatchID, EnquiryID from #EnqTemp   
  Select @BatchID BatchID  

  DROP TABLE IF EXISTS #EnqTemp   
  DROP TABLE IF EXISTS #temp1;    
  DROP TABLE IF EXISTS #temp2;   
     
END    




GO

/* ============================================================
   Procedure: [dbo].[Usp_MassOperationEnquiryID_withoutput]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_MassOperationEnquiryID_withoutput] 
(  
  @Txtsearch NVARCHAR(max) = ''  
 ,@Userid INT = 0  
 ,@FilterText NVARCHAR(max) = ''  
 ,@ordstr NVARCHAR(Max) = ''  
 ,@srno NVARCHAR(100)  
 ,@enno NVARCHAR(100)  
 ,@ue_query NVARCHAR(max) = ''  
 ,@MassOperationName Nvarchar(100)
 ,@BatchId bigint output
 )  
AS  
BEGIN 
--set nocount on
DROP TABLE IF EXISTS #temp2; 
Create Table #Enqtemp (EnquiryID BIGINT)
DECLARE @Parentid BIGINT  =(Select ParentId from User_Detail (NOLOCK) where User_ID=@Userid)
DECLARE @User_id Bigint = @Userid 
 DECLARE @TimeZoneName NVARCHAR(255) = isnull((  
    SELECT TimeZone  
    FROM User_Detail(NOLOCK)  
    WHERE User_ID = @Userid  
    ), 'india standard time')  
 DECLARE @IsAdmin BIT = 0  
 DECLARE @Str NVARCHAR(200) = @ordstr;--' personname desc '  
 DECLARE @ColumnName NVARCHAR(200) = ''  
 DECLARE @StrPredefinedOrderBy NVARCHAR(500) = ''  
 DECLARE @StrCustomOrderBy NVARCHAR(500) = ''  
 DECLARE @actUserId BIGINT = @Userid  
  
 IF (rtrim(ltrim(@Str)) <> '')  
 BEGIN  
  SET @Str = ltrim(RTRIM(@Str))  
  
  --select @Str  
  SELECT TOP 1 @ColumnName = value  
  FROM string_split(@Str, ' ')  
  
  --select @ColumnName   
  IF (EXISTS(SELECT 1 FROM INFORMATION_SCHEMA.COLUMNS WHERE table_name = 'UserEnquiry' AND column_name = rtrim(ltrim(@ColumnName))))  
  BEGIN  
   --set @StrPredefinedOrderBy = N' order by ' +  @Str;  
   SET @StrPredefinedOrderBy = N' ' + @Str + ' , ';  
   SET @StrCustomOrderBy = '';  
  END  
  ELSE  
  BEGIN  
   DECLARE @FullDataType NVARCHAR(200) = 'nvarchar(max)'  
  
   SELECT TOP 1 @FullDataType = CASE   
     WHEN ISNULL(datatype, 'v') = 'd'  
      THEN 'date'  
     WHEN ISNULL(datatype, 'v') = 'f'  
      THEN 'bigint'  
     WHEN ISNULL(datatype, 'v') = 'v'  
      THEN 'nvarchar(max)'  
     ELSE 'nvarchar(max)'  
     END  
   FROM customfields WITH (NOLOCK)  
   WHERE ParentID = @Parentid  
    AND fieldname = rtrim(ltrim(@ColumnName))  
  
   DECLARE @CustomStrExp NVARCHAR(200) = '';  
  
   IF(EXISTS(SELECT value FROM string_split(@Str, ' ')WHERE rtrim(ltrim(value)) = 'asc'))  
   BEGIN  
    SET @CustomStrExp = N' ' + 'CAST(' + @ColumnName + ' as  ' + @FullDataType + ')' + '  asc '  
   END  
   ELSE  
   BEGIN  
    SET @CustomStrExp = N' ' + 'CAST(' + @ColumnName + ' as  ' + @FullDataType + ')' + '  desc '  
   END  
  
   SET @StrPredefinedOrderBy = ''  
   --set @StrCustomOrderBy = N' order by ' +  @Str;    
   SET @StrCustomOrderBy = N' ' + @CustomStrExp + ' , ';  
  END  
    --select @StrPredefinedOrderBy  
    --select @StrCustomOrderBy  
 END  
  
  DROP TABLE IF EXISTS #temp1;
  DROP TABLE IF EXISTS #temp2;

  IF @srno = ''  
  BEGIN  
   SET @srno = '1';  
  END  
  
  IF @enno = ''  
  BEGIN  
   SET @enno = '20';  
  END  
  
  IF (@Txtsearch = '')  
  BEGIN  
   SET @Txtsearch = N' (1=1) ';  
  END;  
  
  IF (@FilterText = '')  
  BEGIN  
   SET @FilterText = N' (1=1) ';  
  END;  
  
  IF (@FilterText LIKE '%MobileNo3%')  
  BEGIN  
   SET @FilterText = replace(@FilterText, 'MobileNo3', 'MobileNo')  
  END  
  
  DECLARE @Query1 NVARCHAR(max) = ''  
  DECLARE @Pivot_Column [nvarchar] (max);  
  
 /*Select Pivot Column*/  
  SELECT @Pivot_Column = COALESCE(@Pivot_Column + ',', '') + QUOTENAME(fieldname)  
  FROM 
  (  
	SELECT DISTINCT [fieldname]  
	FROM customfields(NOLOCK)  
	WHERE ParentID = @ParentID AND isActive = 1  
  ) Tab  
  
 DECLARE @NoCustomFields BIGINT, @filterCnt INT = 0  
  
 SET @NoCustomFields = (  
   SELECT count(DISTINCT [fieldname])  
   FROM customfields  
   WHERE [ParentID] = @ParentID AND [isActive] = 1  
   )  
  
 DECLARE @Query NVARCHAR(max) = ''  
 DECLARE @TeamCode VARCHAR(10) = ''  
 DECLARE @ScopeCode VARCHAR(10) = ''  
 DECLARE @UserIdTeamLst VARCHAR(Max) = ''  
 DECLARE @UserLoginTeamLst VARCHAR(Max) = ''  
 --select @TeamCode = TeamCode, @ScopeCode = ScopeCode, @UserIdTeamLst = UserIdTeamLst, @UserLoginTeamLst = UserLoginTeamLst from dbo.ufn_GetUserRoleScope(@UserId)  
 DECLARE @tbluser TABLE (  
  User_ID BIGINT  
  ,Name VARCHAR(100)  
  ,IMAGE VARCHAR(100)  
  )  
  
 SELECT @IsAdmin = isnull(IsAdmin, 0)  
 FROM User_Detail(NOLOCK)  
 WHERE User_ID = @UserID  
  
 IF (@IsAdmin = 1)  
 BEGIN  
  SET @UserID = 0  
  
  INSERT INTO @tbluser  
  EXEC Use_GetUserDetails @ParentId  
 END  
 ELSE  
 BEGIN  
  INSERT INTO @tbluser  
  EXEC Use_GetUserDetails @UserID  
 END  
  
 SELECT @UserIdTeamLst = isnull(STRING_AGG(User_ID, ','), '')  
 FROM @tbluser  
  
 PRINT '@UserIdTeamLst: ' + @UserIdTeamLst  
  
 IF (@FilterText = ' (1=1) ' AND @Txtsearch = ' (1=1) ')  
 BEGIN  
  PRINT 'Branch A'  
  
  SET @Query =   
   N'SELECT distinct A.Enquiryid,A.Personname,A.Companyname,rtrim(ltrim(A.MobileNo3)) as MobileNo3 , rtrim(ltrim(A.MobileNo1)) as MobileNo1 , rtrim(ltrim(A.MobileNo2)) as MobileNo2, A.EmailID3, A.EmailID1, A.EmailID2, A.Residentialaddress, A.Officeaddress,A.User_login,rtrim(ltrim(A.MobileNo)) as MobileNo,A.EmailID,A.City,A.[State],A.Country,A.Countrycode,A.Pincode,A.[ADDRESS], A.Initialremarks, A.SourceName, A.MediumName, A.CampaignName, A.Parentid, A.CreatedDate, A.CreatedDate1,A.Createdby,A.Leads,A.Isopen,    
   isnull(A.img_ext,'''') as img_ext, A.WhereAddress, A.Tags, RowNumber1, rc1, A.IsduplicateEmail, A.IsduplicateMobile       
   into #Temp2    
   FROM     
   (     
  SELECT distinct Ue.Enquiryid,Ue.Personname,Ue.Companyname,Ue.Mobileno, ltrim(trim(isnull(Ue.Countrycode, ''''))+'' ''+trim(isnull(Ue.Mobileno, '''')))+ case when trim(isnull(Ue.Mobileno1,''''))<>'''' then '', ...'' else '''' end AS MobileNo3, trim(Ue.Mobileno1) as Mobileno1, trim( Ue.Mobileno2) as Mobileno2,Ue.Emailid,  Ue.Emailid AS EmailID3, Ue.Emailid1, Ue.Emailid2, Ue.Residentialaddress, Ue.Officeaddress, Ud.User_login, Ue.CreatedDate , Ue.City, Ue.[State], Ue.Country, Ue.Countrycode, Ue.Pincode, CASE WHEN Ue.Companyname <> '''' THEN Case WHEN Ue.Officeaddress <> '''' THEN Ue.Officeaddress ELSE Ue.Residentialaddress END ELSE Ue.Residentialaddress END AS [ADDRESS], Ue.Initialremarks, Uss.Name AS SourceName, Ums.Name AS MediumName, Ucs.Name AS CampaignName,  Ue.Parentid, CONVERT(VARCHAR(10), Ue.Createddate, 101) + STUFF( RIGHT(CONVERT(VARCHAR(26), Ue.Createddate, 109), 15),7,7, '' '') AS CreatedDate1, Ue.Createdby, CASE WHEN isnull(ue.isopen,1)=1 then null else ue.LeadNo end AS Leads, (CASE WHEN isnull(ue.isopen,1)=1 and isnull(ue.LeadNo,0) = 0 then ''open'' when isnull(ue.LeadNo,0) > 0 THEN ''lead'' ELSE ''open'' END) as Isopen, Ue.img_ext, Ue.WhereAddress, isnull(tg.Tags, '''') Tags , ROW_NUMBER() OVER(ORDER BY '   
   + @StrPredefinedOrderBy + '   Ue.Enquiryid DESC) AS RowNumber1, count(*) OVER(ORDER BY Ue.Parentid) AS rc1, Ue.IsduplicateEmail, Ue.IsduplicateMobile      
  FROM Userenquiry (NOLOCK) Ue left JOIN Usersourcesettings (NOLOCK) Uss     
  ON Ue.Sourcename = Uss.Sourceid LEFT JOIN Usermediumsettings (NOLOCK) Ums     
  ON Ue.Mediumname = Ums.Mediumid LEFT JOIN Usercampaignsettings (NOLOCK) Ucs     
  ON Ue.Campaignname = Ucs.Campaignid LEFT JOIN User_detail (NOLOCK) Ud     
  ON Ue.Createdby = Ud.User_id and Ue.Parentid = Ud.ParentID LEFT JOIN ( select STRING_AGG(Tag, '','') as Tags, etm.EntityID from TagMaster(nolock) tm inner join EntityTagMapping(nolock) etm on tm.id = etm.TagID and etm.entity = ''enquiry'' and tm.ParentID = ' + Convert(VARCHAR(100), @ParentID) + ' where ISNULL(etm.EntityID, 0) > 0 group by etm.EntityID ) tg on tg.EntityID = Ue.EnquiryId    
  WHERE Ue.Parentid = ' + Convert(VARCHAR(100), @Parentid)  
  
  --CASE WHEN @Userid = 0 THEN N' = UL.AssignedTo '   
  --WHEN @Userid > 0 and isnull(@TeamCode,'') != '' THEN ' in (' + isnull(@UserIdTeamLst, '') + ')'   
  --ELSE ' = ' + CAST(@Userid AS NVARCHAR(MAX)) End + '  
  IF @Userid > 0  
  BEGIN  
   SET @Query += N' AND ' + CASE --When isnull(@Userid,0) > 0 and isnull(@TeamCode,'') != '' then  ' ue.CreatedBy in ('+ isnull(@UserIdTeamLst, '') + ') '  
     WHEN isnull(@UserIdTeamLst, '') != ''  
      THEN ' ue.CreatedBy in (' + isnull(@UserIdTeamLst, '') + ') '  
     WHEN isnull(@Userid, 0) = 0  
      THEN ' ue.CreatedBy = ue.CreatedBy '  
     ELSE ' ue.CreatedBy = ' + Convert(VARCHAR(100), @Userid)  
     END  
  END  
  
  SET @Query += N' ) A Where A.RowNumber1 BETWEEN ' + CONVERT(NVARCHAR(max), @srno) + N' AND ' + CONVERT(NVARCHAR(max), @enno)  
 END  
 ELSE  
 BEGIN  
  PRINT 'Branch B'  
  
  SET @Query += N'SELECT distinct A.Enquiryid,A.Personname,A.Companyname, rtrim(ltrim(A.MobileNo3)) as MobileNo3 , rtrim(ltrim(A.MobileNo1)) as MobileNo1 ,rtrim(ltrim(A.MobileNo2)) as MobileNo2, A.EmailID3, A.EmailID1, A.EmailID2, A.Residentialaddress, A.Officeaddress,A.User_login,A.MobileNo,A.EmailID,A.City,A.[State],A.Country,A.Countrycode,A.Pincode,A.[ADDRESS], A.Initialremarks, A.SourceName, A.MediumName, A.CampaignName, A.Parentid,A.CreatedDate, A.CreatedDate1,A.Createdby,A.Leads,A.Isopen,    
   isnull(A.img_ext,'''') as img_ext, A.WhereAddress, A.Tags, RowNumber1, rc1, A.IsduplicateEmail, A.IsduplicateMobile       
   into #Temp2    
   FROM     
   (     
  Select *, ROW_NUMBER() OVER(ORDER BY ' + @StrPredefinedOrderBy +   
   ' T.Enquiryid DESC) AS RowNumber1, count(*) OVER(ORDER BY T.Parentid) AS rc1      
  From     
  (    
   SELECT distinct Ue.Enquiryid,Ue.Personname,Ue.Companyname,trim(Ue.Mobileno) as Mobileno,ltrim(trim(isnull(Ue.Countrycode, ''''))+'' ''+trim(isnull(Ue.Mobileno, '''')))+ case when trim(isnull(Ue.Mobileno1,''''))<>'''' then '', ...'' else '''' end AS MobileNo3, trim(Ue.Mobileno1) as Mobileno1, trim(Ue.Mobileno2) as Mobileno2,Ue.Emailid, Ue.Emailid AS EmailID3,Ue.Emailid1,Ue.Emailid2,Ue.Residentialaddress,Ue.Officeaddress, Ud.User_login,Ue.CreatedDate , Ue.City, Ue.[State], Ue.Country, Ue.Countrycode, Ue.Pincode, CASE WHEN Ue.Companyname <> '''' THEN Case WHEN Ue.Officeaddress <> '''' THEN Ue.Officeaddress ELSE Ue.Residentialaddress END ELSE Ue.Residentialaddress END AS [ADDRESS], Ue.Initialremarks, Uss.Name AS SourceName, Ums.Name AS MediumName, Ucs.Name AS CampaignName,  Ue.Parentid, CONVERT(VARCHAR(10), Ue.Createddate, 101) + STUFF( RIGHT(CONVERT(VARCHAR(26), Ue.Createddate, 109), 15),7,7, '' '') AS CreatedDate1, Ue.Createdby, CASE WHEN isnull(ue.isopen,1)=1 then null else ue.LeadNo end AS Leads, (CASE
 WHEN isnull(ue.isopen,1)=1 and isnull(ue.LeadNo,0) = 0 then ''open'' when isnull(ue.LeadNo,0) > 0 THEN ''lead'' ELSE ''open'' END) as Isopen, Ue.img_ext, Ue.WhereAddress, isnull(tg.Tags, '''') Tags ,Ue.IsduplicateEmail,ue.IsduplicateMobile   
   FROM Userenquiry (NOLOCK) Ue left JOIN Usersourcesettings (NOLOCK) Uss     
   ON Ue.Sourcename = Uss.Sourceid LEFT JOIN Usermediumsettings (NOLOCK) Ums     
   ON Ue.Mediumname = Ums.Mediumid LEFT JOIN Usercampaignsettings (NOLOCK) Ucs     
   ON Ue.Campaignname = Ucs.Campaignid LEFT JOIN User_detail (NOLOCK) Ud     
   ON Ue.Createdby = Ud.User_id and Ue.Parentid = Ud.ParentID LEFT JOIN ( select STRING_AGG(Tag, '','') as Tags, etm.EntityID from TagMaster(nolock) tm inner join EntityTagMapping(nolock) etm on tm.id = etm.TagID and etm.entity = ''enquiry'' and tm.ParentID = '   
   + Convert(VARCHAR(100), @ParentID) + ' where ISNULL(etm.EntityID, 0) > 0 group by etm.EntityID ) tg on tg.EntityID = Ue.EnquiryId  
   WHERE Ue.Parentid = ' + Convert(VARCHAR(100), @ParentID)  
  
  IF @Userid > 0  
  BEGIN  
   --When isnull(@Userid,0) > 0 and isnull(@TeamCode,'') != '' then  ' ue.CreatedBy in ('+ isnull(@UserIdTeamLst, '') + ') '  
   SET @Query += N' AND ' + CASE   
     WHEN isnull(@UserIdTeamLst, '') != ''  
      THEN ' ue.CreatedBy in (' + isnull(@UserIdTeamLst, '') + ') '  
     WHEN isnull(@Userid, 0) = 0  
      THEN ' ue.CreatedBy = ue.CreatedBy '  
     ELSE ' ue.CreatedBy = ' + Convert(VARCHAR(100), @Userid)  
     END  
  END  
  
  SET @Query += N' ) T Where ' + @FilterText + N' ) A Where ' + CASE   
    WHEN @Txtsearch = ' (1=1) '  
     THEN ' A.RowNumber1 BETWEEN ' + CONVERT(NVARCHAR(max), @srno) + N' AND ' + CONVERT(NVARCHAR(max), @enno)  
    ELSE ' (1=1) '  
    END  
 END  
  
 IF (@ue_query = '')  
 BEGIN  
  SET @ue_query = ' (1=1) '  
 END  
  
 IF (@FilterText != '' AND @ue_query != '')  
 BEGIN  
  SET @FilterText += ' AND ' + @ue_query  
 END  
  
 IF (@ordstr = '')  
 BEGIN  
  SET @ordstr = ' Enquiryid desc '  
 END  
  
 IF (@Pivot_Column IS NOT NULL)  
 BEGIN  
  PRINT 'Branch C'  
  
  IF (@Txtsearch = ' (1=1) ') -- From Branch A    
  BEGIN  
  PRINT 'Branch CA'  
  
   /*SET @Query += CAST(N'; INSERT INTO #EnqTemp (EnquiryID) Select EnquiryId From (SELECT  rc1 AS [rcnt], EnquiryId, PersonName, CompanyName, MobileNo3, MobileNo1, MobileNo2, EmailID3, EmailID1, EmailID2, Residentialaddress, Officeaddress, User_login, MobileNo, EmailID, City, [State], Country, Countrycode, Pincode, [ADDRESS], Initialremarks, SourceName, MediumName, CampaignName, Parentid, dbo.fn_ConvertDateTime(cast(CreatedDate as datetime), ''' + cast(@TimeZoneName AS NVARCHAR(255)) + ''', 0) as CreatedDate,    dbo.fn_ConvertDateTime(cast(CreatedDate1 as datetime), ''' + cast(@TimeZoneName AS NVARCHAR(255)) + ''', 0) as  CreatedDate1, Createdby, Leads, Isopen, Img_ext, ROW_NUMBER() OVER(ORDER BY ' + @StrPredefinedOrderBy + N' ' + @StrCustomOrderBy + '  EnquiryId Desc) + cast( ' + cast((@srno - 1) AS NVARCHAR) + ' as int) ' + '  AS [RowNumber1], WhereAddress, rc1, IsduplicateEmail, IsduplicateMobile,   ' + @Pivot_Column +
     N' FROM (SELECT EnquiryId, PersonName, CompanyName, MobileNo3, MobileNo1, MobileNo2, EmailID3, EmailID1, EmailID2, Residentialaddress, Officeaddress, User_login, MobileNo, EmailID, City, [State], Country, Countrycode, Pincode, [ADDRESS], Initialremarks, SourceName, MediumName, CampaignName, Parentid, CreatedDate, CreatedDate1, Createdby, Leads, Isopen, Img_ext, WhereAddress, [fieldname], fieldvalue, RowNumber1, rc1, IsduplicateEmail, IsduplicateMobile      
  FROM (select E.Enquiryid, E.PersonName, E.CompanyName, E.MobileNo3, E.MobileNo1, E.MobileNo2, E.EmailID3, E.EmailID1, E.EmailID2, E.Residentialaddress, E.Officeaddress, E.User_login, E.MobileNo, E.EmailID, E.City, E.[State], E.Country, E.Countrycode, E.Pincode, E.[ADDRESS], E.Initialremarks, E.SourceName, E.MediumName, E.CampaignName, E.Parentid, E.CreatedDate, E.CreatedDate1, E.Createdby, E.Leads, E.Isopen, E.Img_ext, E.WhereAddress, y.fieldname, x.fieldvalue ,E.RowNumber1, E.rc1, E.IsduplicateEmail, E.IsduplicateMobile       
  From #temp2 E left join customfieldEnquiryvalue(nolock) x     
  ON E.Enquiryid = x.Enquiryid left join customfields(nolock) y     
  ON x.fieldID=y.field_ID AND y.[ParentID] = '   
     + CAST(@Parentid AS NVARCHAR(MAX)) + ' AND y.[isActive] = 1    
  )q )Tab1    
  PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + ') ) AS Tab2    
  WHERE ' + @Txtsearch + '  ) T1 Where RowNumber1 BETWEEN ' + CONVERT(VARCHAR(100), @srno) + ' AND ' + CONVERT(VARCHAR(100), @enno));--+ N' ORDER BY ' + @ordstr AS NVARCHAR(MAX));  
  */
  SET @Query += N'
    INSERT INTO #EnqTemp (EnquiryID)
    SELECT EnquiryId
    FROM (
        SELECT 
            rc1 AS [rcnt], 
            EnquiryId, 
            PersonName, 
            CompanyName, 
            MobileNo3, 
            MobileNo1, 
            MobileNo2, 
            EmailID3, 
            EmailID1, 
            EmailID2, 
            Residentialaddress, 
            Officeaddress, 
            User_login, 
            MobileNo, 
            EmailID, 
            City, 
            [State], 
            Country, 
            Countrycode, 
            Pincode, 
            [ADDRESS], 
            Initialremarks, 
            SourceName, 
            MediumName, 
            CampaignName, 
            Parentid, 
            dbo.fn_ConvertDateTime(CAST(CreatedDate AS datetime), ''' + CAST(@TimeZoneName AS NVARCHAR(255)) + N''', 0) AS CreatedDate,
            dbo.fn_ConvertDateTime(CAST(CreatedDate1 AS datetime), ''' + CAST(@TimeZoneName AS NVARCHAR(255)) + N''', 0) AS CreatedDate1,
            Createdby, 
            Leads, 
            Isopen, 
            Img_ext, 
            ROW_NUMBER() OVER(ORDER BY ' + @StrPredefinedOrderBy + N' ' + @StrCustomOrderBy + N' EnquiryId DESC) + CAST(' + CAST((@srno - 1) AS NVARCHAR) + N' AS INT) AS [RowNumber1],
            WhereAddress, 
            rc1, 
            IsduplicateEmail, 
            IsduplicateMobile, 
            ' + @Pivot_Column + N'
        FROM (
            SELECT 
                EnquiryId, 
                PersonName, 
                CompanyName, 
                MobileNo3, 
                MobileNo1, 
                MobileNo2, 
                EmailID3, 
                EmailID1, 
                EmailID2, 
                Residentialaddress, 
                Officeaddress, 
                User_login, 
                MobileNo, 
                EmailID, 
                City, 
                [State], 
                Country, 
                Countrycode, 
                Pincode, 
                [ADDRESS], 
                Initialremarks, 
                SourceName, 
                MediumName, 
                CampaignName, 
                Parentid, 
                CreatedDate, 
                CreatedDate1, 
                Createdby, 
                Leads, 
                Isopen, 
                Img_ext, 
                WhereAddress, 
                [fieldname], 
                fieldvalue, 
                RowNumber1, 
                rc1, 
                IsduplicateEmail, 
                IsduplicateMobile
            FROM (
                SELECT 
                    E.Enquiryid, 
                    E.PersonName, 
                    E.CompanyName, 
                    E.MobileNo3, 
                    E.MobileNo1, 
                    E.MobileNo2, 
                    E.EmailID3, 
                    E.EmailID1, 
                    E.EmailID2, 
                    E.Residentialaddress, 
                    E.Officeaddress, 
                    E.User_login, 
                    E.MobileNo, 
                    E.EmailID, 
                    E.City, 
                    E.[State], 
                    E.Country, 
                    E.Countrycode, 
                    E.Pincode, 
                    E.[ADDRESS], 
                    E.Initialremarks, 
                    E.SourceName, 
                    E.MediumName, 
                    E.CampaignName, 
                    E.Parentid, 
                    E.CreatedDate, 
                    E.CreatedDate1, 
                    E.Createdby, 
                    E.Leads, 
                    E.Isopen, 
                    E.Img_ext, 
                    E.WhereAddress, 
                    y.fieldname, 
                    x.fieldvalue, 
                    E.RowNumber1, 
                    E.rc1, 
                    E.IsduplicateEmail, 
                    E.IsduplicateMobile
                FROM 
                    #temp2 E
                LEFT JOIN 
                    customfieldEnquiryvalue(nolock) x ON E.Enquiryid = x.Enquiryid
                LEFT JOIN 
                    customfields(nolock) y ON x.fieldID = y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + N' AND y.[isActive] = 1
            ) q
        ) Tab1
        PIVOT (
            MAX(fieldvalue)
            FOR [fieldname] IN (' + @Pivot_Column + N')
        ) AS Tab2
        WHERE ' + @Txtsearch + N'
    ) T1
    WHERE RowNumber1 BETWEEN ' + CONVERT(VARCHAR(100), @srno) + N' AND ' + CONVERT(VARCHAR(100), @enno) + N';';

  END  
  ELSE  
  BEGIN  
   PRINT 'Branch CB'  
  
   SELECT @filterCnt = count(*)  
   FROM dbo.fn_Split(@Txtsearch, ' ) ')  
  
 	SELECT @Query += CAST(N'; select * into #Temp1 From (select [x].EnquiryId, [y].[fieldname], 
	[x].[fieldvalue] from customfieldEnquiryvalue(nolock) x inner join customfields(nolock) y
	ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + N' AND y.[isActive] = 1 ) T1 PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + N')) AS Tab2 Where ' + @Txtsearch AS NVARCHAR(MAX));

   SET @Query += CAST(N';  INSERT INTO #EnqTemp (EnquiryID) Select EnquiryId From (SELECT ROW_NUMBER() OVER(ORDER BY ' + @StrPredefinedOrderBy + N' ' + @StrCustomOrderBy + '  A.EnquiryId Desc) AS [RowNumber1], count(*) OVER(ORDER BY [ParentID]) AS [rc1], count(*) OVER(ORDER BY [ParentID]) AS [rcnt], A.EnquiryId, PersonName, CompanyName, MobileNo3, MobileNo1, MobileNo2, EmailID3, EmailID1, EmailID2, Residentialaddress, Officeaddress, User_login, MobileNo, EmailID, City, [State], Country, Countrycode, Pincode, [ADDRESS], Initialremarks, SourceName, MediumName, CampaignName, Parentid, dbo.fn_ConvertDateTime(cast(CreatedDate as datetime), ''' + cast(@TimeZoneName AS NVARCHAR(255)) + ''', 0) as CreatedDate,      dbo.fn_ConvertDateTime(cast(CreatedDate1 as datetime), ''' + cast(@TimeZoneName AS NVARCHAR(255)) + ''', 0) as  CreatedDate1, Createdby, Leads, Isopen, Img_ext, WhereAddress, ' + @Pivot_Column +   
     N' From #Temp1 A inner join #temp2 E     
  ON A.EnquiryId = E.Enquiryid
  ) T1 Where RowNumber1 BETWEEN ' + CONVERT(VARCHAR(100), @srno) + ' AND ' + CONVERT(VARCHAR(100), @enno) AS NVARCHAR(MAX)) + N' ORDER BY ' + @ordstr;  
  END  
 END  
 ELSE  
 BEGIN  
 PRINT 'Branch D'  
  
  SET @Query += CAST(N';  INSERT INTO #EnqTemp (EnquiryID) Select EnquiryId From( select distinct Enquiryid, Personname, Companyname, MobileNo3, MobileNo1, MobileNo2, EmailID3,EmailID1,EmailID2,Residentialaddress,Officeaddress,User_login,MobileNo,EmailID,City,[State], Country,Countrycode,Pincode,[ADDRESS], Initialremarks,  SourceName, MediumName, CampaignName, Parentid,dbo.fn_ConvertDateTime(cast(CreatedDate as datetime), ''' + cast(@TimeZoneName AS NVARCHAR(255)) + ''', 0) as CreatedDate, dbo.fn_ConvertDateTime(cast(CreatedDate1 as datetime), ''' + cast(@TimeZoneName AS NVARCHAR(255)) + ''', 0) as  CreatedDate1,Createdby,Leads,Isopen, isnull(img_ext,'''') as img_ext, WhereAddress, Tags, RowNumber1, rc1, IsduplicateEmail, IsduplicateMobile from #temp2 Where RowNumber1 BETWEEN ' + CONVERT(VARCHAR(100), @srno) + ' AND ' + CONVERT(VARCHAR(100), @enno) + N' ORDER BY ' + @ordstr AS NVARCHAR(MAX)) +')';  
 END  
  
 PRINT '@FinalQuery:- ' + cast(@Query AS VARCHAR(max))  
  
 EXEC sp_executesql @Query;  
  
  INSERT INTO Tbl_MassOperationSummary (MassOperationName, UserID, Parentid, CreatedDate, IsProcessed, ProcedureName, FilterCriteria, EntityType)
			Values (@MassOperationName, @User_id, @parentid, getdate(), 0, 'Usp_MassOperationEnquiryID', @FilterText, 'Enquiry')
	--Declare @BatchID Bigint  = Scope_Identity()
	set @BatchID=Scope_Identity()

	INSERT INTO Tbl_MassOperationDetails (SummaryId,EntityID)
	Select @BatchID, EnquiryID from #EnqTemp 
  --return @BatchID
  --Select @BatchID BatchID
  DROP TABLE IF EXISTS #EnqTemp 
  DROP TABLE IF EXISTS #temp1;  
  DROP TABLE IF EXISTS #temp2; 
   
END  



GO

