/* ============================================================
   Procedure: [dbo].[Usp_MassOperationLeadEnquiryData]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE Usp_MassOperationLeadEnquiryData                 
@metatdata nvarchar(max),                
@batchid bigint,                
@userid bigint  ,              
@StartDateTime VARCHAR(50)='',      
@SenderId VARCHAR(50)='',    
@urltrack bit= null  ,  
@TrackedUrl nvarchar(max)='',      
@SmsPlaceHolder nvarchar(max)=''  
AS                
BEGIN                
 --Update Tbl_MassOperationSummary set metadata=@metatdata, isvalid=1, ScheduleDateTime=@StartDateTime where BatchID = @batchid          
 UPDATE Tbl_MassOperationSummary        
        SET metadata=@metatdata,        
      isvalid=1,        
            ScheduleDateTime = CASE         
                                 WHEN ScheduleDateTime IS NULL OR ScheduleDateTime = '' OR ScheduleDateTime = '1900-01-01 00:00:00.000'        
                                 THEN @StartDateTime        
                                 ELSE ScheduleDateTime        
                               END  ,      
          SenderId=@SenderId,    
    UrlTrack = @urltrack,  
 TrackedUrl = @TrackedUrl,  
 SmsPlaceHolder = @SmsPlaceHolder  
        WHERE BatchID = @batchid;        
        
 select @batchid Batchid , count(EntityID) TotalEntity from Tbl_MassOperationDetails where SummaryId=@batchid                
END 


GO

