CREATE  PROCEDURE [dbo].[Usp_MassOperationLeadEnquiryProcess]       
   @summary_batchid bigint=null    
AS    
BEGIN    
    --declare @summary_batchid bigint=31668    
    
 Drop TABLE IF EXISTS #tempMassOperation    
 Create Table #tempMassOperation (ROwNo int, BatchID bigint )    
    
 DECLARE @BatchID bigint,@sequenceid bigint, @UserID bigint, @EntityType nvarchar(10), @MassOperation varchar(50), @metaData nvarchar(max)='' ,    
 @IDS VARCHAR(Max), @AssignedTo BIGINT,@FollowUpStatus INT, @NextStatusDate VARCHAR(50), @Products VARCHAR(1000), @AmountPaid NUMERIC(18, 2), @Remarks VARCHAR(1000), @ParentID BIGINT,     
 @ModifiedBy BIGINT,  @IsReAssign bit = 0,@AccountID BIGINT,@Subjects VARCHAR(1000), @TemplateID Bigint, @ComposeMsg VARCHAR(MAX), @SenderName VARCHAR(100), @ReplyTo VARCHAR(1000),     
 @EmailId BIT, @EmailId1 BIT, @EmailId2 BIT, @FromMailID varchar(500), @Title VARCHAR(255) ,@Description VARCHAR(1000), @Address VARCHAR(500), @StartDate DATETIME, @EndDate DATETIME, @LeadIds Varchar(max),                         
 @IsActive BIT, @TaskId BIGINT, @Status VARCHAR(255), @OutcomesId BIGINT, @CollabratoerUserIds VARCHAR(1000), @IsSMS BIT, @IsEmail BIT, @IsTask BIT, @IsAppointment BIT,@TaskType VARCHAR(100),    
 @CompleteAddress VARCHAR(500) ,@Latitude VARCHAR(50), @Longitude VARCHAR(50), @SmsSchedule VARCHAR(50), @EmailSchedule VARCHAR(50), @NotifyMe BIT,@SenderID VARCHAR(100),   @Message nvarchar(max),    
 @IsUniCode bit, @IsMobile bit, @IsMobile1 bit, @IsMobile2 bit, @SMSTemplateID nvarchar(max), @sms_source nvarchar(20),@count int =0, @minrow int=1,@actiondetails nvarchar(max),@ScheduleDatetime DATETIME,   
 @ScheduleFollowupDatetime DATETIME,@ScheduleForUpdateDateTime DATETIME,@ScheduleForTaskDateTime DATETIME, @ScheduleDateTimeTagsremve DATETIME ,@tags nvarchar(max),@smsLeadDateTime DATETIME,  
 @SchedulemailComposedatetime DATETIME,@SchedulemailTempdatetime DATETIME, @SchedulemailEnqTempdatetime DATETIME, @SchedulLeadEmailComposedatetime DATETIME,  
 @SchedulEnqEmailComposedatetime DATETIME, @LaedBroadcastStartDateTime DATETIME, @LeadAppointmentDatetime DATETIME  
    
 declare @entitydata as entities            
                
 if(@summary_batchid is not null)--force run a batchid                
  begin    
  Insert into #tempMassOperation(ROwNo,  BatchID)    
  Select ROW_NUMBER () Over (Order by Batchid) ROwNo,  BatchID  from tbl_massoperationsummary (NOLOCK) where     
  batchid=case when @summary_batchid is not null then @summary_batchid else batchid end    
  and MassOperationName <> 'Send InternationalSMS'        
  --and isnull(scheduledatetime,getdate())<=getdate()            
  end    
 else    
  begin    
  Insert into #tempMassOperation(ROwNo,  BatchID)    
  Select ROW_NUMBER () Over (Order by Batchid) ROwNo,  BatchID from tbl_massoperationsummary (NOLOCK) where     
  IsProcessed=0 and isvalid=1    
  and batchid=case when @summary_batchid is not null then @summary_batchid else batchid end    
  and isnull(scheduledatetime,getdate())<=getdate()          
  and MassOperationName <> 'Send InternationalSMS'        
            
  end    
 select @count= count (ROwNo) from #tempMassOperation     
 WHILE ( @minrow <=@count)    
  BEGIN     
        
   BEGIN TRY    
      
   Select @BatchID = BatchID from #tempMassOperation where ROwNo=@minrow     
    
   select @BatchID = BatchID, @UserID=userid, @EntityType=Entitytype,@MassOperation=MassOperationName, @metaData=metadata,    
   @actiondetails=metadata  from tbl_massoperationsummary (NOLOCK)     
   where BatchID=@BatchID    
        
   print '@Massoperation name'+@MassOperation;  
    --print '@ScheduleDateTimeTag  '+ @ScheduleDateTimeTag;  
  
   UPDATE  Tbl_MassOperationSummary set IsProcessed =2 where BatchID=@BatchID    
   print @BatchID    
   select @ParentID=ParentID from user_detail (NOLOCK) where User_ID=@userid    
   if @metaData<>'' AND  @metaData is not null and @MassOperation <> 'Delete'  
   BEGIN    
     print 'MetaGO

as :  '+ @metaData;

   SELECT @IDS=IDS,@sequenceid=SequenceId,@AssignedTo=AssignTo, @FollowUpStatus=FollowUpStatus, @NextStatusDate=NextStatusDate,@Products =Products,@AmountPaid =AmountPaid, @Remarks=Remarks,                 
   @IsReAssign=IsReassign,@AccountID=AccountID,@Subjects=Subjects, @TemplateID=TemplateID, @ComposeMsg=ComposeMsg,@SenderName=SenderName,@ReplyTo=ReplyTo,@EmailId=EmailId,    
   @EmailId1=EmailId1, @EmailId2=EmailId2, @FromMailID=FromMailID, @Title=Title,@Description=Description,@Address=Address,@StartDate=StartDate, @EndDate=EndDate,@LeadIds=LeadIds,    
   @IsActive =IsActive, @TaskId=TaskId,@Status=Status, @OutcomesId=OutcomesId, @CollabratoerUserIds=CollabratoerUserIds, @IsSMS=IsSMS,@IsEmail=IsEmail, @IsTask=IsTask,    
   @IsAppointment=IsAppointment,@TaskType=TaskType,@CompleteAddress=CompleteAddress,@Latitude=Latitude,@Longitude=Longitude,@SmsSchedule=SmsSchedule,@EmailSchedule=EmailSchedule,    
   @NotifyMe=NotifyMe,@SenderID=SenderID,@Message=Message, @IsUniCode=IsUniCode,@IsMobile=IsMobile, @IsMobile1=IsMobile1, @IsMobile2=IsMobile2,@SMSTemplateID=TemplateID, @sms_source=sms_source,  
   @ScheduleDatetime=Scheduledatetime,@ScheduleFollowupDatetime=ScheduleFollowup,@ScheduleForUpdateDateTime=ScheduleForUpdate,@ScheduleForTaskDateTime=scheduledatetime,@ScheduleDateTimeTagsremve=SceduledDateTime,@tags=Tags,  
   @smsLeadDateTime=smsDateTime, @SchedulemailTempdatetime =Schedulemaildatetime,@SchedulemailEnqTempdatetime=EnquiryScheduleDateTime, @SchedulLeadEmailComposedatetime=Schedulemaildatetime,  
   @SchedulEnqEmailComposedatetime=EnquiryScheduleDateTime, @LaedBroadcastStartDateTime=BroadcastStartDateTime,@LeadAppointmentDatetime=scheduledatetime  
  
   from OPENJSON(@metaData)     
   WITH(     
   IDS VARCHAR(Max),SequenceId bigint, AssignTo BIGINT, FollowupStatus INT, NextStatusDate VARCHAR(50), Products VARCHAR(1000), AmountPaid NUMERIC(18, 2), Remarks VARCHAR(1000), IsReassign int                
   , AccountID BIGINT, Subjects VARCHAR(1000), TemplateID Bigint, ComposeMsg VARCHAR(MAX), SenderName VARCHAR(100), ReplyTo VARCHAR(1000), EmailId BIT, EmailId1 BIT, EmailId2 BIT,     
   FromMailID varchar(500), Title VARCHAR(255) ,Description VARCHAR(1000), Address VARCHAR(500), StartDate DATETIME, EndDate DATETIME, LeadIds Varchar(max),                           
   IsActive BIT, TaskId BIGINT, Status VARCHAR(255), OutcomesId BIGINT, CollabratoerUserIds VARCHAR(1000), IsSMS BIT, IsEmail BIT, IsTask BIT, IsAppointment BIT,TaskType VARCHAR(100),    
   CompleteAddress VARCHAR(500) ,Latitude VARCHAR(50), Longitude VARCHAR(50), SmsSchedule VARCHAR(50), EmailSchedule VARCHAR(50), NotifyMe BIT,SenderID VARCHAR(100), Message nvarchar(max),    
   IsUniCode bit,IsMobile bit, IsMobile1 bit, IsMobile2 bit,TemplateID nvarchar(max),sms_source nvarchar(20),Scheduledatetime DATETIME,ScheduleFollowup DATETIME, ScheduleForUpdate DATETIME,  
   scheduledatetime DATETIME, SceduledDateTime DATETIME,SceduledDateTime DATETIME,Tags nvarchar(max),smsDateTime DATETIME, Schedulemaildatetime DATETIME,  
   ScheduleDateTime DATETIME , Schedulemaildatetime DATETIME , BroadcastStartDateTime DATETIME, EnquiryScheduleDateTime DATETIME, scheduledatetime DATETIME  
   )    
   END   
   DECLARE @StartDateTime1 VARCHAR(50)  
   SET @StartDateTime1 = CONVERT(VARCHAR(50), @ScheduleFollowupDatetime, 120)  
  
   DECLARE @StartDateTime2 VARCHAR(50)  
   SET @StartDateTime2 = CONVERT(VARCHAR(50), @ScheduleForUpdateDateTime, 120)  
  
   DECLARE @StartDateTime3 VARCHAR(50)  
   SET @StartDateTime3 = CONVERT(VARCHAR(50), @ScheduleForTaskDateTime, 120)  
  
   DECLARE @StartDateTime4 VARCHAR(50)  
   SET @StartDateTime4 = CONVERT(VARCHAR(50), @ScheduleDateTimeTagsremve, 120)  
  
   DECLARE @LeadSmsDateTime VARCHAR(50)  
   SET @LeadSmsDateTime = CONVERT(VARCHAR(50), @smsLeadDateTime, 120)  
  
   DECLARE @LeadTemMailDateTime VARCHAR(50)  
   SET @LeadTemMailDateTime = CONVERT(VARCHAR(50), @SchedulemailTempdatetime, 120)   
  
   DECLARE @EnqTemMailDateTime VARCHAR(50)  
   SET @EnqTemMailDateTime = CONVERT(VARCHAR(50), @SchedulemailEnqTempdatetime, 120)  
  
   DECLARE @LeadComMailDateTime VARCHAR(50)  
   SET @LeadComMailDateTime = CONVERT(VARCHAR(50), @SchedulLeadEmailComposedatetime, 120)  
  
   DECLARE @EnqComMailDateTime VARCHAR(50)  
   SET @EnqComMailDateTime = CONVERT(VARCHAR(50), @SchedulEnqEmailComposedatetime, 120)  
  
   DECLARE @LeadsBroadcastStartDateTime VARCHAR(50)  
   SET @LeadsBroadcastStartDateTime = CONVERT(VARCHAR(50), @LaedBroadcastStartDateTime, 120)  
  
    DECLARE @LeadsAppointmentStartDateTime VARCHAR(50)  
   SET @LeadsAppointmentStartDateTime = CONVERT(VARCHAR(50), @LeadAppointmentDatetime, 120)  
  
   print '@StartDateTime4'+@StartDateTime4;  
   IF @EntityType='Lead'    
   BEGIN    
   delete from @entitydata            
   insert into @entitydata(entity,entityid)            
   select 'lead',t.EntityID from Tbl_MassOperationDetails(nolock) t where SummaryId=@BatchID   
   --IF @MassOperation='AssignTo' 
   IF @MassOperation IN ('AssignTo', 'AddAssignTo') 
   BEGIN    
   print 'Lead AssignTo'    
   EXEC Usp_InsertLeadAssignTo_Followup_MassOperation_Replication @IDS='',@AssignedTo=@AssignedTo,@FollowUpStatus=@FollowUpStatus,@NextStatusDate=@NextStatusDate,@Products=@Products,                 
           @AmountPaid=@AmountPaid, @Remarks=@Remarks,@ParentID=@ParentID, @ModifiedBy=@UserID, @BatchID=@Batchid,@Assigndatetime=Scheduledatetime    
      
   END    
   else if @massoperation='Marketing Sequence'        
   begin        
   print 'Entered Marketing Sequence'      
   exec usp_insertmassmktgsequence @batchid        
   update tbl_massoperationsummary set batchstarttime=getdate() where batchid=@batchid      
   end        
   ELSE IF @MassOperation='Add FollowUp'    
   BEGIN    
   print 'Lead Add FollowUp'    
     
   EXEC Usp_AddMassFollowup_Replication @IDS='', @AssignedTo=@AssignedTo,@FollowUpStatus=@FollowUpStatus,@NextStatusDate=@NextStatusDate,@Products=@Products,                 
    @AmountPaid=@AmountPaid, @Remarks=@Remarks, @ModifiedBy=@UserID, @BatchID=@Batchid,@IsReAssign=@IsReAssign,@StartDateTime=@StartDateTime1  
   END    
   else if @massoperation in ('Add Tag','Remove Tag','addcommontag','removecommontag')            
   begin            
   print 'Lead add/remove tag'            
   exec usp_add_remove_tag_bulk @entitydata,@massoperation,@tags,@BatchID,@StartDateTime4            
            
   end            
            
            
   ELSE IF @MassOperation='Send Mail'    
   begin    
   print 'Lead Send Mail templateid: ' + cast (@TemplateID as varchar)    
   if @TemplateID>0    
   BEGIN   
     
   EXEC usp_SendMailFromLeads_WithTemplateID_FromMailID_new @IDS=@IDS, @Account=@AccountID, @Email_Subject=@Subjects, @Message_TemplateID=@TemplateID, @SenderName=@SenderName,    
   @ReplyTo=@ReplyTo, @EmailId=@EmailId, @EmailId1=@EmailId1, @EmailId2= @EmailId2, @UserId=@UserId, @FromMailID=@FromMailID, @massbatchid=@Batchid,@Mail_ScheduleDate=@LeadTemMailDateTime    
    
   /*             
   EXEC usp_SendMailFromLeads_WithTemplateID_FromMailID_new_ViaOtherDB @IDS=@IDS, @Account=@AccountID, @Email_Subject=@Subjects, @Message_TemplateID=@TemplateID, @SenderName=@SenderName,                
   @ReplyTo=@ReplyTo, @EmailId=@EmailId, @EmailId1=@EmailId1, @EmailId2= @EmailId2, @UserId=@UserId, @FromMailID=@FromMailID, @massbatchid=@Batchid                
   */          
   END    
   ELSE     
   BEGIN     
   EXEC usp_SendMassMailFromLeads_FromMailID  @IDS=@IDS,@Account=@AccountID, @Email_Subject=@Subjects, @Message=@ComposeMsg, @SenderName=@SenderName, @ReplyTo=@ReplyTo,    
   @EmailId=@EmailId, @EmailId1=@EmailId1, @EmailId2=@EmailId2, @UserId=@UserId, @FromMailID=@FromMailID,@massbatchid=@BatchID,@Mail_ScheduleDate=@LeadComMailDateTime    
    
   /*          
   EXEC usp_SendMassMailFromLeads_FromMailID_ViaOtherDB  @IDS=@IDS,@Account=@AccountID, @Email_Subject=@Subjects, @Message=@ComposeMsg, @SenderName=@SenderName, @ReplyTo=@ReplyTo,                
   @EmailId=@EmailId, @EmailId1=@EmailId1, @EmailId2=@EmailId2, @UserId=@UserId, @FromMailID=@FromMailID,@massbatchid=@BatchID           
   */          
   END    
   end    
   ELSE IF @MassOperation='Voice Broadcast'    
  
   BEGIN    
   declare @tbl AS SendMassVoiceTblType    
   Insert Into @tbl([row_no],[LeadId], [BatchID], [country_code], [didno], [Mobile], [voiceDuration], [AppId], [IsDnd], [IsPrority], [price] ,     
   [user_id], [voice_type], [route], [parentid], [voice_source]  )    
   SELECT * From OpenJson (@metaData) with (    
   row_no int, LeadId bigint, BatchID bigint, country_code nvarchar(5), didno nvarchar(100), Mobile varchar(20), voiceDuration bigint,    
   AppId bigint, IsDnd bit, IsPrority bit, price decimal(8, 2), user_id bigint, voice_type int, route nvarchar(max), parentid bigint,    
   voice_source nvarchar(100) )    
   exec usp_IntindMassVoiceFromLeads @tbl=@tbl, @Userid=@Userid,  @massbatchid = @batchid,@BroadcastStartDateTime= @LeadsBroadcastStartDateTime     
   END    
   ELSE IF @MassOperation='Send SMS'    
   BEGIN    
   print 'Lead Send SMS'    
  
   --exec usp_IntindSMSFromLeads_New_WithDLTTemplateID @ID=IDS, @Account=@AccountID, @SenderID=@SenderID, @Message=@Message, @IsUnicode=@IsUnicode, @Mobile=@IsMobile,    
   --@mobile1=@IsMobile1, @Mobile2=@IsMobile2, @DLTTemplateID=@SMSTemplateID, @UserId= @UserId, @massbatchid=@BatchID,@startDateTime=@LeadSmsDateTime      
  exec usp_IntindSMSFromLeads_New_WithDLTTemplateID_new1 @ID=IDS, @Account=@AccountID, @SenderID=@SenderID, @Message=@Message, @IsUnicode=@IsUnicode, @Mobile=@IsMobile,    
   @mobile1=@IsMobile1, @Mobile2=@IsMobile2, @DLTTemplateID=@SMSTemplateID, @UserId= @UserId, @massbatchid=@BatchID,@startDateTime=@LeadSmsDateTime      
    
  
   END    
   ELSE IF @MassOperation='Update'    
   BEGIN    
   print 'Lead Update'    
   exec Usp_Update_MassLeadEnquiry @userid=@userid, @tablename='UserLeads', @updatevalues=@metaData, @HashSeparatedIDs='', @batchid=@batchid, @mode='Update' ,@scheduleleaddatetime=@StartDateTime2   
   END    
   ELSE IF @MassOperation='Add Task'    
   BEGIN    
   print 'Lead Add Task'    
   EXEC Usp_Mass_TaskAppointment_CrtUpdt @HashedIDs=@IDS,@Title=@Title, @Description=@Description, @Remarks=@Remarks, @Address=@Address, @StartDate=@StartDate, @EndDate=@EndDate,    
   @LeadIds=@LeadIds,@AssignedTo=@AssignedTo, @IsActive=@IsActive, @TaskId=@TaskId, @Status=@Status,@UserID=@UserID,@OutcomesId=@OutcomesId,@CollabratoerUserIds=@CollabratoerUserIds,    
   @IsSMS=@IsSMS,@IsEmail=@IsEmail,@IsTask=@IsTask, @IsAppointment=@IsAppointment, @TaskType=@TaskType, @CompleteAddress=@CompleteAddress, @Latitude=@Latitude,     
   @Longitude=@Longitude, @SmsSchedule=@SmsSchedule,@EmailSchedule=@EmailSchedule, @NotifyMe=@NotifyMe, @outcomeid=0,@massbatchid=@BatchID,@mode='Insert',@StartDateTime=@StartDateTime3    
    
   END    
   ELSE IF @MassOperation='Add Appointment'    
   BEGIN    
   print 'Lead Add Task'    
   EXEC Usp_Mass_TaskAppointment_CrtUpdt @HashedIDs=@IDS,@Title=@Title, @Description=@Description, @Remarks=@Remarks, @Address=@Address, @StartDate=@StartDate, @EndDate=@EndDate,    
   @LeadIds=@LeadIds,@AssignedTo=@AssignedTo, @IsActive=@IsActive, @TaskId=@TaskId, @Status=@Status,@UserID=@UserID,@OutcomesId=@OutcomesId,@CollabratoerUserIds=@CollabratoerUserIds,    
   @IsSMS=@IsSMS,@IsEmail=@IsEmail,@IsTask=@IsTask, @IsAppointment=@IsAppointment, @TaskType=@TaskType, @CompleteAddress=@CompleteAddress, @Latitude=@Latitude,     
   @Longitude=@Longitude, @SmsSchedule=@SmsSchedule,@EmailSchedule=@EmailSchedule, @NotifyMe=@NotifyMe, @outcomeid=0,@massbatchid=@BatchID,@mode='Insert'   
    
   END    
   ELSE IF @MassOperation='Delete'    
   BEGIN    
   print 'Lead Delete'    
   EXEC Usp_LeadDeleteById @CSVID=@BatchID, @Mode='batchid'    
    
   END    
   ELSE IF @MassOperation='Add Call List'    
   BEGIN    
   print 'lead Add Call List'  
     
   SELECT @IDS=STRING_AGG(t.EntityId, ',')   
FROM Tbl_MassOperationDetails(NOLOCK) t  
WHERE t.SummaryId = @BatchID;  
  
   print @IDS  
   print @metaData  
      exec usp_dc_MassAddCallList @summary_batchid, @IDS,'Lead',@UserID,@metaData  
   --exec usp_Add_MassCallList @massbatchid=@BatchID , @HashedIDs=@IDS,@UserID=@UserID,@massbatchid=@BatchID,@mode='Lead', @StartDate=@StartDate    
   END    
   END    
        
   ELSE IF @EntityType='Enquiry'    
   BEGIN     
   delete from @entitydata            
   insert into @entitydata(entity,entityid)            
   select 'enquiry',t.EntityID from Tbl_MassOperationDetails(nolock) t where SummaryId=@BatchID            
            
   IF @MassOperation ='Add Lead'    
   begin    
   print 'Enquiry Add Lead'    
   EXEC usp_MassAddFollowupfromEnq_ChangeWithFollowupDate1 @EnqID=@IDS, @FollowupStatus=@FollowUpStatus, @AssignTo=@AssignedTo, @NextStatusDate=@NextStatusDate, @Remarks=@Remarks,     
   @Products=@Products, @AmountPaid=@AmountPaid, @CreatedBy=@UserID, @ParentID=@ParentID, @IsReAssign=@IsReAssign,@BatchID=@BatchID    
    
   end    
   else if @massoperation in ('Add Tag','Remove Tag')            
   begin            
   print 'Enquiry add/remove tag'    
     
   exec usp_add_remove_tag_bulk @entitydata,@massoperation,@tags,@BatchID,@StartDateTime4            
            
   end            
   else if @massoperation='Marketing Sequence'        
   begin        
   print 'Entered Marketing Sequence'      
   exec usp_insertmassmktgsequence @batchid        
   update tbl_massoperationsummary set batchstarttime=getdate() where batchid=@batchid      
   end        
      
            
   ELSE IF @MassOperation='Send SMS'    
   BEGIN    
   print 'Enquiry Send SMS'    
   --exec usp_IntindSMSFromEnquiry_WithDLTTemplateID_new @EnqID=IDS, @Account=@AccountID, @SenderID=@SenderID, @Message=@Message, @IsUnicode=@IsUnicode, @Mobile=@IsMobile,    
   --@mobile1=@IsMobile1, @Mobile2=@IsMobile2, @DLTTemplateID=@SMSTemplateID, @UserId= @UserId, @massbatchid=@BatchID,@StartDateTime=@StartDateTime2    
   exec usp_IntindSMSFromEnquiry_WithDLTTemplateID_new1 @EnqID=IDS, @Account=@AccountID, @SenderID=@SenderID, @Message=@Message, @IsUnicode=@IsUnicode, @Mobile=@IsMobile,    
   @mobile1=@IsMobile1, @Mobile2=@IsMobile2, @DLTTemplateID=@SMSTemplateID, @UserId= @UserId, @massbatchid=@BatchID,@StartDateTime=@StartDateTime2    
     
   END    
   ELSE IF @MassOperation='Send Mail'    
   BEGIN    
   print 'Enquiry Send Mail, TemplateID: ' + cast(@TemplateID as varchar)    
   if @TemplateID>0    
   BEGIN    
   EXEC usp_SendMassMailFromEnquiry_WithTemplateID_WithFromMailID_new @IDS=@IDS, @Account=@AccountID, @Email_Subject=@Subjects, @Message_TemplateID=@TemplateID, @SenderName=@SenderName,    
   @ReplyTo=@ReplyTo, @EmailId=@EmailId, @EmailId1=@EmailId1, @EmailId2= @EmailId2, @UserId=@UserId, @FromMailID=@FromMailID, @massbatchid=@Batchid,  @Mail_ScheduleDate=@EnqTemMailDateTime    
    
   /*            
   EXEC usp_SendMassMailFromEnquiry_WithTemplateID_WithFromMailID_new__ViaOtherDB @IDS=@IDS, @Account=@AccountID, @Email_Subject=@Subjects, @Message_TemplateID=@TemplateID, @SenderName=@SenderName,                
   @ReplyTo=@ReplyTo, @EmailId=@EmailId, @EmailId1=@EmailId1, @EmailId2= @EmailId2, @UserId=@UserId, @FromMailID=@FromMailID, @massbatchid=@Batchid                
   */              
   END    
   ELSE     
   BEGIN     
   EXEC usp_SendMassMailFromEnquiry_WithFromMailID  @IDS=@IDS,@Account=@AccountID, @Email_Subject=@Subjects, @Message=@ComposeMsg, @SenderName=@SenderName, @ReplyTo=@ReplyTo,    
   @EmailId=@EmailId, @EmailId1=@EmailId1, @EmailId2=@EmailId2, @UserId=@UserId, @FromMailID=@FromMailID,@massbatchid=@BatchID,@startDateTime=@EnqComMailDateTime    
    
   /*            
   EXEC usp_SendMassMailFromEnquiry_WithFromMailID_ViaOtherDB  @IDS=@IDS,@Account=@AccountID, @Email_Subject=@Subjects, @Message=@ComposeMsg, @SenderName=@SenderName, @ReplyTo=@ReplyTo,                
   @EmailId=@EmailId, @EmailId1=@EmailId1, @EmailId2=@EmailId2, @UserId=@UserId, @FromMailID=@FromMailID,@massbatchid=@BatchID                
   */          
   END    
   END    
   ELSE IF @MassOperation='Delete'    
   BEGIN    
   print 'Enquiry Delete'    
   exec Usp_EnquiryDeleteById @CSVID=@BatchID, @Mode='batchid'    
   END    
   ELSE IF @MassOperation='Update'    
   BEGIN    
   print 'Enquiry Update'    
   exec Usp_Update_MassLeadEnquiry @userid=@userid, @tablename='UserEnquiry', @updatevalues=@metaData, @HashSeparatedIDs='', @batchid=@batchid, @mode='Update',@scheduleleaddatetime=@StartDateTime2    
   END    
   ELSE IF @MassOperation='Add Call List'    
   BEGIN    
   print 'Enquiry AddCallList'  
    
    SELECT @IDS=STRING_AGG(t.EntityId, ',')   
FROM Tbl_MassOperationDetails(NOLOCK) t  
WHERE t.SummaryId = @BatchID;  
  
   print @IDS  
      exec usp_dc_MassAddCallList @summary_batchid, @IDS,'enquiry',@UserID,@metaData  
  
  -- exec usp_Add_MassCallList @massbatchid=@BatchID , @HashedIDs=@IDS,@UserID=@UserID,@massbatchid=@BatchID,@mode='Enquiry', @StartDate=@StartDate    
   END    
   END    
        
   UPDATE  Tbl_MassOperationSummary set IsProcessed =1 where BatchID=@BatchID    
       
   END TRY    
    BEGIN CATCH    
      Update Tbl_massoperationsummary set errorDetails=Error_message(),IsProcessed =1 where BatchID=@Batchid     
      exec usp_inserterrorinfo    
	END CATCH    
    set @minrow = @minrow +1     
    END    
END  
  
  

