/* ============================================================
   Procedure: [dbo].[Usp_MassOperationLeadEnquiryProcess_Replication]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_MassOperationLeadEnquiryProcess_Replication]   
@summary_batchid bigint=null  
AS  
BEGIN  
   
 Drop TABLE IF EXISTS #tempMassOperation  
 Create Table #tempMassOperation (ROwNo int, BatchID bigint )  
  
 DECLARE @BatchID bigint, @UserID bigint, @EntityType nvarchar(10), @MassOperation varchar(50), @metaData nvarchar(max)='' ,  
 @IDS VARCHAR(Max), @AssignedTo BIGINT,@FollowUpStatus INT, @NextStatusDate VARCHAR(50), @Products VARCHAR(1000), @AmountPaid NUMERIC(18, 2), @Remarks VARCHAR(1000), @ParentID BIGINT,   
 @ModifiedBy BIGINT,  @IsReAssign bit = 0,@AccountID BIGINT,@Subjects VARCHAR(1000), @TemplateID Bigint, @ComposeMsg VARCHAR(MAX), @SenderName VARCHAR(100), @ReplyTo VARCHAR(1000),   
 @EmailId BIT, @EmailId1 BIT, @EmailId2 BIT, @FromMailID varchar(500), @Title VARCHAR(255) ,@Description VARCHAR(1000), @Address VARCHAR(500), @StartDate DATETIME, @EndDate DATETIME, @LeadIds Varchar(max),                       
     @IsActive BIT, @TaskId BIGINT, @Status VARCHAR(255), @OutcomesId BIGINT, @CollabratoerUserIds VARCHAR(1000), @IsSMS BIT, @IsEmail BIT, @IsTask BIT, @IsAppointment BIT,@TaskType VARCHAR(100),  
     @CompleteAddress VARCHAR(500) ,@Latitude VARCHAR(50), @Longitude VARCHAR(50), @SmsSchedule VARCHAR(50), @EmailSchedule VARCHAR(50), @NotifyMe BIT,@SenderID VARCHAR(100),   @Message nvarchar(max),  
     @IsUniCode bit, @IsMobile bit, @IsMobile1 bit, @IsMobile2 bit, @SMSTemplateID nvarchar(max), @sms_source nvarchar(20),@count int =0, @minrow int=1  
  
  if(@summary_batchid is not null)  
  begin  
   Insert into #tempMassOperation(ROwNo,  BatchID)  
   Select ROW_NUMBER () Over (Order by Batchid) ROwNo,  BatchID  from tbl_massoperationsummary (NOLOCK) where batchid=case when @summary_batchid is not null then @summary_batchid else batchid end  
  end  
  else  
  begin  
   Insert into #tempMassOperation(ROwNo,  BatchID)  
   Select ROW_NUMBER () Over (Order by Batchid) ROwNo,  BatchID from tbl_massoperationsummary (NOLOCK) where IsProcessed=0 and isvalid=1  
   and batchid=case when @summary_batchid is not null then @summary_batchid else batchid end  
  end  
  select @count= count (ROwNo) from #tempMassOperation   
  WHILE ( @minrow <=@count)  
  BEGIN   
      
   BEGIN TRY  
    
    Select @BatchID = BatchID from #tempMassOperation where ROwNo=@minrow   
  
    select @BatchID =BatchID, @UserID=userid, @EntityType=Entitytype,@MassOperation=MassOperationName, @metaData=metadata from tbl_massoperationsummary (NOLOCK)   
    where BatchID=@BatchID  
      
     UPDATE  Tbl_MassOperationSummary set IsProcessed =2 where BatchID=@BatchID  
  
    select @ParentID=ParentID from user_detail (NOLOCK) where User_ID=@userid  
    if @metaData<>'' AND  @metaData is not null  
    BEGIN  
     SELECT @IDS=IDS,@AssignedTo=AssignTo, @FollowUpStatus=FollowUpStatus, @NextStatusDate=NextStatusDate,@Products =Products,@AmountPaid =AmountPaid, @Remarks=Remarks,   
      @IsReAssign=IsReassign,@AccountID=AccountID,@Subjects=Subjects, @TemplateID=TemplateID, @ComposeMsg=ComposeMsg,@SenderName=SenderName,@ReplyTo=ReplyTo,@EmailId=EmailId,  
      @EmailId1=EmailId1, @EmailId2=EmailId2, @FromMailID=FromMailID, @Title=Title,@Description=Description,@Address=Address,@StartDate=StartDate, @EndDate=EndDate,@LeadIds=LeadIds,  
      @IsActive =IsActive, @TaskId=TaskId,@Status=Status, @OutcomesId=OutcomesId, @CollabratoerUserIds=CollabratoerUserIds, @IsSMS=IsSMS,@IsEmail=IsEmail, @IsTask=IsTask,  
      @IsAppointment=IsAppointment,@TaskType=TaskType,@CompleteAddress=CompleteAddress,@Latitude=Latitude,@Longitude=Longitude,@SmsSchedule=SmsSchedule,@EmailSchedule=EmailSchedule,  
      @NotifyMe=NotifyMe,@SenderID=SenderID,@Message=Message, @IsUniCode=IsUniCode,@IsMobile=IsMobile, @IsMobile1=IsMobile1, @IsMobile2=IsMobile2,@SMSTemplateID=TemplateID, @sms_source=sms_source  
      from OPENJSON(@metaData)   
      WITH(   
       IDS VARCHAR(Max), AssignTo BIGINT, FollowupStatus INT, NextStatusDate VARCHAR(50), Products VARCHAR(1000), AmountPaid NUMERIC(18, 2), Remarks VARCHAR(1000), IsReassign int  
       , AccountID BIGINT, Subjects VARCHAR(1000), TemplateID Bigint, ComposeMsg VARCHAR(MAX), SenderName VARCHAR(100), ReplyTo VARCHAR(1000), EmailId BIT, EmailId1 BIT, EmailId2 BIT,   
       FromMailID varchar(500), Title VARCHAR(255) ,Description VARCHAR(1000), Address VARCHAR(500), StartDate DATETIME, EndDate DATETIME, LeadIds Varchar(max),                         
       IsActive BIT, TaskId BIGINT, Status VARCHAR(255), OutcomesId BIGINT, CollabratoerUserIds VARCHAR(1000), IsSMS BIT, IsEmail BIT, IsTask BIT, IsAppointment BIT,TaskType VARCHAR(100),  
       CompleteAddress VARCHAR(500) ,Latitude VARCHAR(50), Longitude VARCHAR(50), SmsSchedule VARCHAR(50), EmailSchedule VARCHAR(50), NotifyMe BIT,SenderID VARCHAR(100), Message nvarchar(max),  
       IsUniCode bit,IsMobile bit, IsMobile1 bit, IsMobile2 bit,TemplateID nvarchar(max),sms_source nvarchar(20)  
      )  
    END  
      
    IF @EntityType='Lead'  
    BEGIN  
     IF @MassOperation='AssignTo'  
     BEGIN  
     print 'Lead AssignTo'  
      EXEC Usp_InsertLeadAssignTo_Followup_MassOperation_Replication @IDS='',@AssignedTo=@AssignedTo,@FollowUpStatus=@FollowUpStatus,@NextStatusDate=@NextStatusDate,@Products=@Products,   
                   @AmountPaid=@AmountPaid, @Remarks=@Remarks,@ParentID=@ParentID, @ModifiedBy=@UserID, @BatchID=@Batchid  
    
     END  
     ELSE IF @MassOperation='Add FollowUp'  
     BEGIN  
     print 'Lead Add FollowUp'  
      EXEC Usp_AddMassFollowup_Replication @IDS='', @AssignedTo=@AssignedTo,@FollowUpStatus=@FollowUpStatus,@NextStatusDate=@NextStatusDate,@Products=@Products,   
            @AmountPaid=@AmountPaid, @Remarks=@Remarks, @ModifiedBy=@UserID, @BatchID=@Batchid,@IsReAssign=@IsReAssign  
     END  
     ELSE IF @MassOperation='Send Mail'  
     begin  
     print 'Lead Send Mail templateid: ' + cast (@TemplateID as varchar)  
      if @TemplateID>0  
      BEGIN  
       EXEC usp_SendMailFromLeads_WithTemplateID_FromMailID_new @IDS=@IDS, @Account=@AccountID, @Email_Subject=@Subjects, @Message_TemplateID=@TemplateID, @SenderName=@SenderName,  
       @ReplyTo=@ReplyTo, @EmailId=@EmailId, @EmailId1=@EmailId1, @EmailId2= @EmailId2, @UserId=@UserId, @FromMailID=@FromMailID, @massbatchid=@Batchid  
  
      END  
      ELSE   
      BEGIN   
       EXEC usp_SendMassMailFromLeads_FromMailID  @IDS=@IDS,@Account=@AccountID, @Email_Subject=@Subjects, @Message=@ComposeMsg, @SenderName=@SenderName, @ReplyTo=@ReplyTo,  
       @EmailId=@EmailId, @EmailId1=@EmailId1, @EmailId2=@EmailId2, @UserId=@UserId, @FromMailID=@FromMailID,@massbatchid=@BatchID  
  
      END  
     end  
     ELSE IF @MassOperation='Voice Broadcast'  
     BEGIN  
     declare @tbl AS SendMassVoiceTblType  
       Insert Into @tbl([row_no],[LeadId], [BatchID], [country_code], [didno], [Mobile], [voiceDuration], [AppId], [IsDnd], [IsPrority], [price] ,   
           [user_id], [voice_type], [route], [parentid], [voice_source]  )  
       SELECT * From OpenJson (@metaData) with (  
         row_no int, LeadId bigint, BatchID bigint, country_code nvarchar(5), didno nvarchar(100), Mobile varchar(20), voiceDuration bigint,  
          AppId bigint, IsDnd bit, IsPrority bit, price decimal(8, 2), user_id bigint, voice_type int, route nvarchar(max), parentid bigint,  
           voice_source nvarchar(100) )  
      exec usp_IntindMassVoiceFromLeads @tbl=@tbl, @Userid=@Userid,  @massbatchid = @batchid   
     END  
     ELSE IF @MassOperation='Send SMS'  
     BEGIN  
      print 'Lead Send SMS'  
      exec usp_IntindSMSFromLeads_New_WithDLTTemplateID @ID=IDS, @Account=@AccountID, @SenderID=@SenderID, @Message=@Message, @IsUnicode=@IsUnicode, @Mobile=@IsMobile,  
      @mobile1=@IsMobile1, @Mobile2=@IsMobile2, @DLTTemplateID=@SMSTemplateID, @UserId= @UserId, @massbatchid=@BatchID  
  
     END  
     ELSE IF @MassOperation='Update'  
     BEGIN  
      print 'Lead Update'  
      exec Usp_Update_MassLeadEnquiry @userid=@userid, @tablename='', @updatevalues=@metaData, @HashSeparatedIDs='', @batchid=@batchid, @mode='Update'  
     END  
     ELSE IF @MassOperation='Add Task'  
     BEGIN  
     print 'Lead Add Task'  
      EXEC Usp_Mass_TaskAppointment_CrtUpdt @HashedIDs=@IDS,@Title=@Title, @Description=@Description, @Remarks=@Remarks, @Address=@Address, @StartDate=@StartDate, @EndDate=@EndDate,  
        @LeadIds=@LeadIds,@AssignedTo=@AssignedTo, @IsActive=@IsActive, @TaskId=@TaskId, @Status=@Status,@UserID=@UserID,@OutcomesId=@OutcomesId,@CollabratoerUserIds=@CollabratoerUserIds,  
        @IsSMS=@IsSMS,@IsEmail=@IsEmail,@IsTask=@IsTask, @IsAppointment=@IsAppointment, @TaskType=@TaskType, @CompleteAddress=@CompleteAddress, @Latitude=@Latitude,   
        @Longitude=@Longitude, @SmsSchedule=@SmsSchedule,@EmailSchedule=@EmailSchedule, @NotifyMe=@NotifyMe, @outcomeid=0,@massbatchid=@BatchID,@mode='Insert'  
  
     END  
     ELSE IF @MassOperation='Add Appointment'  
     BEGIN  
      print 'Lead Add Task'  
      EXEC Usp_Mass_TaskAppointment_CrtUpdt @HashedIDs=@IDS,@Title=@Title, @Description=@Description, @Remarks=@Remarks, @Address=@Address, @StartDate=@StartDate, @EndDate=@EndDate,  
        @LeadIds=@LeadIds,@AssignedTo=@AssignedTo, @IsActive=@IsActive, @TaskId=@TaskId, @Status=@Status,@UserID=@UserID,@OutcomesId=@OutcomesId,@CollabratoerUserIds=@CollabratoerUserIds,  
        @IsSMS=@IsSMS,@IsEmail=@IsEmail,@IsTask=@IsTask, @IsAppointment=@IsAppointment, @TaskType=@TaskType, @CompleteAddress=@CompleteAddress, @Latitude=@Latitude,   
        @Longitude=@Longitude, @SmsSchedule=@SmsSchedule,@EmailSchedule=@EmailSchedule, @NotifyMe=@NotifyMe, @outcomeid=0,@massbatchid=@BatchID,@mode='Insert'  
  
     END  
     ELSE IF @MassOperation='Delete'  
     BEGIN  
     print 'Lead Delete'  
      EXEC Usp_LeadDeleteById @CSVID=@BatchID, @Mode='batchid'  
  
     END  
    END  
      
    ELSE IF @EntityType='Enquiry'  
    BEGIN   
     IF @MassOperation ='Add Lead'  
     begin  
     print 'Enquiry Add Lead'  
      EXEC usp_MassAddFollowupfromEnq_ChangeWithFollowupDate1 @EnqID=@IDS, @FollowupStatus=@FollowUpStatus, @AssignTo=@AssignedTo, @NextStatusDate=@NextStatusDate, @Remarks=@Remarks,   
       @Products=@Products, @AmountPaid=@AmountPaid, @CreatedBy=@UserID, @ParentID=@ParentID, @IsReAssign=@IsReAssign,@BatchID=@BatchID  
  
     end  
     ELSE IF @MassOperation='Send SMS'  
     BEGIN  
     print 'Enquiry Send SMS'  
      exec usp_IntindSMSFromEnquiry_WithDLTTemplateID_new @EnqID=IDS, @Account=@AccountID, @SenderID=@SenderID, @Message=@Message, @IsUnicode=@IsUnicode, @Mobile=@IsMobile,  
       @mobile1=@IsMobile1, @Mobile2=@IsMobile2, @DLTTemplateID=@SMSTemplateID, @UserId= @UserId, @massbatchid=@BatchID  
     END  
     ELSE IF @MassOperation='Send Mail'  
     BEGIN  
     print 'Enquiry Send Mail, TemplateID: ' + cast(@TemplateID as varchar)  
      if @TemplateID>0  
       BEGIN  
        EXEC usp_SendMassMailFromEnquiry_WithTemplateID_WithFromMailID_new @IDS=@IDS, @Account=@AccountID, @Email_Subject=@Subjects, @Message_TemplateID=@TemplateID, @SenderName=@SenderName,  
        @ReplyTo=@ReplyTo, @EmailId=@EmailId, @EmailId1=@EmailId1, @EmailId2= @EmailId2, @UserId=@UserId, @FromMailID=@FromMailID, @massbatchid=@Batchid  
  
       END  
       ELSE   
       BEGIN   
        EXEC usp_SendMassMailFromEnquiry_WithFromMailID  @IDS=@IDS,@Account=@AccountID, @Email_Subject=@Subjects, @Message=@ComposeMsg, @SenderName=@SenderName, @ReplyTo=@ReplyTo,  
        @EmailId=@EmailId, @EmailId1=@EmailId1, @EmailId2=@EmailId2, @UserId=@UserId, @FromMailID=@FromMailID,@massbatchid=@BatchID  
  
       END  
     END  
     ELSE IF @MassOperation='Delete'  
     BEGIN  
     print 'Enquiry Delete'  
      exec Usp_EnquiryDeleteById @CSVID=@BatchID, @Mode='batchid'  
     END  
     ELSE IF @MassOperation='Update'  
     BEGIN  
     print 'Enquiry Update'  
       exec Usp_Update_MassLeadEnquiry @userid=@userid, @tablename='', @updatevalues=@metaData, @HashSeparatedIDs='', @batchid=@batchid, @mode='Update'  
     END  
    END  
      
    UPDATE  Tbl_MassOperationSummary set IsProcessed =1 where BatchID=@BatchID  
     
   END TRY  
   BEGIN CATCH  
   exec usp_inserterrorinfo  
    Update Tbl_massoperationsummary set errorDetails=Error_message(),IsProcessed =1 where BatchID=@Batchid   
   END CATCH  
   set @minrow = @minrow +1   
  END  
END


GO

/* ============================================================
   Procedure: [dbo].[Usp_MassOperationLeadEnquiryProcess_withtag]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_MassOperationLeadEnquiryProcess_withtag]       
@summary_batchid bigint=null      
AS      
BEGIN      
       
 Drop TABLE IF EXISTS #tempMassOperation      
 Create Table #tempMassOperation (ROwNo int, BatchID bigint )      
      
 DECLARE @BatchID bigint, @UserID bigint, @EntityType nvarchar(10), @MassOperation varchar(50), @metaData nvarchar(max)='' ,      
 @IDS VARCHAR(Max), @AssignedTo BIGINT,@FollowUpStatus INT, @NextStatusDate VARCHAR(50), @Products VARCHAR(1000), @AmountPaid NUMERIC(18, 2), @Remarks VARCHAR(1000), @ParentID BIGINT,       
 @ModifiedBy BIGINT,  @IsReAssign bit = 0,@AccountID BIGINT,@Subjects VARCHAR(1000), @TemplateID Bigint, @ComposeMsg VARCHAR(MAX), @SenderName VARCHAR(100), @ReplyTo VARCHAR(1000),       
 @EmailId BIT, @EmailId1 BIT, @EmailId2 BIT, @FromMailID varchar(500), @Title VARCHAR(255) ,@Description VARCHAR(1000), @Address VARCHAR(500), @StartDate DATETIME, @EndDate DATETIME, @LeadIds Varchar(max),                           
     @IsActive BIT, @TaskId BIGINT, @Status VARCHAR(255), @OutcomesId BIGINT, @CollabratoerUserIds VARCHAR(1000), @IsSMS BIT, @IsEmail BIT, @IsTask BIT, @IsAppointment BIT,@TaskType VARCHAR(100),      
     @CompleteAddress VARCHAR(500) ,@Latitude VARCHAR(50), @Longitude VARCHAR(50), @SmsSchedule VARCHAR(50), @EmailSchedule VARCHAR(50), @NotifyMe BIT,@SenderID VARCHAR(100),   @Message nvarchar(max),      
     @IsUniCode bit, @IsMobile bit, @IsMobile1 bit, @IsMobile2 bit, @SMSTemplateID nvarchar(max), @sms_source nvarchar(20),@count int =0, @minrow int=1,@actiondetails nvarchar(max)      
  
  declare @entitydata as entities  
      
  if(@summary_batchid is not null)--force run a batchid      
  begin      
   Insert into #tempMassOperation(ROwNo,  BatchID)      
   Select ROW_NUMBER () Over (Order by Batchid) ROwNo,  BatchID  from tbl_massoperationsummary (NOLOCK) where   
   batchid=case when @summary_batchid is not null then @summary_batchid else batchid end   
   --and isnull(scheduledatetime,getdate())<=getdate()  
  end      
  else      
  begin      
   Insert into #tempMassOperation(ROwNo,  BatchID)      
   Select ROW_NUMBER () Over (Order by Batchid) ROwNo,  BatchID from tbl_massoperationsummary (NOLOCK) where   
   IsProcessed=0 and isvalid=1      
   and batchid=case when @summary_batchid is not null then @summary_batchid else batchid end     
   and isnull(scheduledatetime,getdate())<=getdate()  
  
  end      
  select @count= count (ROwNo) from #tempMassOperation       
  WHILE ( @minrow <=@count)      
  BEGIN       
          
   BEGIN TRY      
        
    Select @BatchID = BatchID from #tempMassOperation where ROwNo=@minrow       
      
    select @BatchID =BatchID, @UserID=userid, @EntityType=Entitytype,@MassOperation=MassOperationName, @metaData=metadata,  
@actiondetails=metadata from tbl_massoperationsummary (NOLOCK)       
    where BatchID=@BatchID      
          
     UPDATE  Tbl_MassOperationSummary set IsProcessed =2 where BatchID=@BatchID      
      
    select @ParentID=ParentID from user_detail (NOLOCK) where User_ID=@userid      
    if @metaData<>'' AND  @metaData is not null      
    BEGIN      
     SELECT @IDS=IDS,@AssignedTo=AssignTo, @FollowUpStatus=FollowUpStatus, @NextStatusDate=NextStatusDate,@Products =Products,@AmountPaid =AmountPaid, @Remarks=Remarks,       
      @IsReAssign=IsReassign,@AccountID=AccountID,@Subjects=Subjects, @TemplateID=TemplateID, @ComposeMsg=ComposeMsg,@SenderName=SenderName,@ReplyTo=ReplyTo,@EmailId=EmailId,      
      @EmailId1=EmailId1, @EmailId2=EmailId2, @FromMailID=FromMailID, @Title=Title,@Description=Description,@Address=Address,@StartDate=StartDate, @EndDate=EndDate,@LeadIds=LeadIds,      
      @IsActive =IsActive, @TaskId=TaskId,@Status=Status, @OutcomesId=OutcomesId, @CollabratoerUserIds=CollabratoerUserIds, @IsSMS=IsSMS,@IsEmail=IsEmail, @IsTask=IsTask,      
      @IsAppointment=IsAppointment,@TaskType=TaskType,@CompleteAddress=CompleteAddress,@Latitude=Latitude,@Longitude=Longitude,@SmsSchedule=SmsSchedule,@EmailSchedule=EmailSchedule,      
      @NotifyMe=NotifyMe,@SenderID=SenderID,@Message=Message, @IsUniCode=IsUniCode,@IsMobile=IsMobile, @IsMobile1=IsMobile1, @IsMobile2=IsMobile2,@SMSTemplateID=TemplateID, @sms_source=sms_source      
      from OPENJSON(@metaData)       
      WITH(       
       IDS VARCHAR(Max), AssignTo BIGINT, FollowupStatus INT, NextStatusDate VARCHAR(50), Products VARCHAR(1000), AmountPaid NUMERIC(18, 2), Remarks VARCHAR(1000), IsReassign int      
       , AccountID BIGINT, Subjects VARCHAR(1000), TemplateID Bigint, ComposeMsg VARCHAR(MAX), SenderName VARCHAR(100), ReplyTo VARCHAR(1000), EmailId BIT, EmailId1 BIT, EmailId2 BIT,       
       FromMailID varchar(500), Title VARCHAR(255) ,Description VARCHAR(1000), Address VARCHAR(500), StartDate DATETIME, EndDate DATETIME, LeadIds Varchar(max),                             
       IsActive BIT, TaskId BIGINT, Status VARCHAR(255), OutcomesId BIGINT, CollabratoerUserIds VARCHAR(1000), IsSMS BIT, IsEmail BIT, IsTask BIT, IsAppointment BIT,TaskType VARCHAR(100),      
       CompleteAddress VARCHAR(500) ,Latitude VARCHAR(50), Longitude VARCHAR(50), SmsSchedule VARCHAR(50), EmailSchedule VARCHAR(50), NotifyMe BIT,SenderID VARCHAR(100), Message nvarchar(max),      
       IsUniCode bit,IsMobile bit, IsMobile1 bit, IsMobile2 bit,TemplateID nvarchar(max),sms_source nvarchar(20)      
      )      
    END      
  
   
          
    IF @EntityType='Lead'      
    BEGIN      
 delete from @entitydata  
 insert into @entitydata(entity,entityid)  
 select 'lead',t.EntityID from Tbl_MassOperationDetails(nolock) t where SummaryId=@BatchID  
     IF @MassOperation='AssignTo'      
     BEGIN      
     print 'Lead AssignTo'      
      EXEC Usp_InsertLeadAssignTo_Followup_MassOperation_Replication @IDS='',@AssignedTo=@AssignedTo,@FollowUpStatus=@FollowUpStatus,@NextStatusDate=@NextStatusDate,@Products=@Products,       
                   @AmountPaid=@AmountPaid, @Remarks=@Remarks,@ParentID=@ParentID, @ModifiedBy=@UserID, @BatchID=@Batchid      
        
     END      
     ELSE IF @MassOperation='Add FollowUp'      
     BEGIN      
     print 'Lead Add FollowUp'      
      EXEC Usp_AddMassFollowup_Replication @IDS='', @AssignedTo=@AssignedTo,@FollowUpStatus=@FollowUpStatus,@NextStatusDate=@NextStatusDate,@Products=@Products,       
            @AmountPaid=@AmountPaid, @Remarks=@Remarks, @ModifiedBy=@UserID, @BatchID=@Batchid,@IsReAssign=@IsReAssign      
     END      
  else if @massoperation in ('addtag','removetag','addcommontag','removecommontag')  
  begin  
  print 'Lead add/remove tag'  
  exec usp_add_remove_tag_bulk @entitydata,@massoperation,@actiondetails  
  
  end  
  
  
     ELSE IF @MassOperation='Send Mail'      
     begin      
     print 'Lead Send Mail templateid: ' + cast (@TemplateID as varchar)      
      if @TemplateID>0      
      BEGIN  
       
       EXEC usp_SendMailFromLeads_WithTemplateID_FromMailID_new @IDS=@IDS, @Account=@AccountID, @Email_Subject=@Subjects, @Message_TemplateID=@TemplateID, @SenderName=@SenderName,      
       @ReplyTo=@ReplyTo, @EmailId=@EmailId, @EmailId1=@EmailId1, @EmailId2= @EmailId2, @UserId=@UserId, @FromMailID=@FromMailID, @massbatchid=@Batchid      
        /*  
      EXEC usp_SendMailFromLeads_WithTemplateID_FromMailID_new_ViaOtherDB @IDS=@IDS, @Account=@AccountID, @Email_Subject=@Subjects, @Message_TemplateID=@TemplateID, @SenderName=@SenderName,      
       @ReplyTo=@ReplyTo, @EmailId=@EmailId, @EmailId1=@EmailId1, @EmailId2= @EmailId2, @UserId=@UserId, @FromMailID=@FromMailID, @massbatchid=@Batchid      
    */  
      END      
      ELSE       
      BEGIN    
     
       EXEC usp_SendMassMailFromLeads_FromMailID  @IDS=@IDS,@Account=@AccountID, @Email_Subject=@Subjects, @Message=@ComposeMsg, @SenderName=@SenderName, @ReplyTo=@ReplyTo,      
       @EmailId=@EmailId, @EmailId1=@EmailId1, @EmailId2=@EmailId2, @UserId=@UserId, @FromMailID=@FromMailID,@massbatchid=@BatchID      
      
   /*  
    EXEC usp_SendMassMailFromLeads_FromMailID_ViaOtherDB  @IDS=@IDS,@Account=@AccountID, @Email_Subject=@Subjects, @Message=@ComposeMsg, @SenderName=@SenderName, @ReplyTo=@ReplyTo,      
       @EmailId=@EmailId, @EmailId1=@EmailId1, @EmailId2=@EmailId2, @UserId=@UserId, @FromMailID=@FromMailID,@massbatchid=@BatchID      
   */  
      END      
     end      
     ELSE IF @MassOperation='Voice Broadcast'      
     BEGIN      
     declare @tbl AS SendMassVoiceTblType      
       Insert Into @tbl([row_no],[LeadId], [BatchID], [country_code], [didno], [Mobile], [voiceDuration], [AppId], [IsDnd], [IsPrority], [price] ,       
           [user_id], [voice_type], [route], [parentid], [voice_source]  )      
       SELECT * From OpenJson (@metaData) with (      
         row_no int, LeadId bigint, BatchID bigint, country_code nvarchar(5), didno nvarchar(100), Mobile varchar(20), voiceDuration bigint,      
          AppId bigint, IsDnd bit, IsPrority bit, price decimal(8, 2), user_id bigint, voice_type int, route nvarchar(max), parentid bigint,      
           voice_source nvarchar(100) )      
      exec usp_IntindMassVoiceFromLeads @tbl=@tbl, @Userid=@Userid,  @massbatchid = @batchid       
     END      
     ELSE IF @MassOperation='Send SMS'      
     BEGIN      
      print 'Lead Send SMS'      
      exec usp_IntindSMSFromLeads_New_WithDLTTemplateID @ID=IDS, @Account=@AccountID, @SenderID=@SenderID, @Message=@Message, @IsUnicode=@IsUnicode, @Mobile=@IsMobile,      
      @mobile1=@IsMobile1, @Mobile2=@IsMobile2, @DLTTemplateID=@SMSTemplateID, @UserId= @UserId, @massbatchid=@BatchID      
         END      
     ELSE IF @MassOperation='Update'      
     BEGIN      
      print 'Lead Update'      
      exec Usp_Update_MassLeadEnquiry @userid=@userid, @tablename='', @updatevalues=@metaData, @HashSeparatedIDs='', @batchid=@batchid, @mode='Update'      
     END      
     ELSE IF @MassOperation='Add Task'      
     BEGIN      
     print 'Lead Add Task'      
      EXEC Usp_Mass_TaskAppointment_CrtUpdt @HashedIDs=@IDS,@Title=@Title, @Description=@Description, @Remarks=@Remarks, @Address=@Address, @StartDate=@StartDate, @EndDate=@EndDate,      
        @LeadIds=@LeadIds,@AssignedTo=@AssignedTo, @IsActive=@IsActive, @TaskId=@TaskId, @Status=@Status,@UserID=@UserID,@OutcomesId=@OutcomesId,@CollabratoerUserIds=@CollabratoerUserIds,      
        @IsSMS=@IsSMS,@IsEmail=@IsEmail,@IsTask=@IsTask, @IsAppointment=@IsAppointment, @TaskType=@TaskType, @CompleteAddress=@CompleteAddress, @Latitude=@Latitude,       
        @Longitude=@Longitude, @SmsSchedule=@SmsSchedule,@EmailSchedule=@EmailSchedule, @NotifyMe=@NotifyMe, @outcomeid=0,@massbatchid=@BatchID,@mode='Insert'      
      
     END      
     ELSE IF @MassOperation='Add Appointment'      
     BEGIN      
      print 'Lead Add Task'      
      EXEC Usp_Mass_TaskAppointment_CrtUpdt @HashedIDs=@IDS,@Title=@Title, @Description=@Description, @Remarks=@Remarks, @Address=@Address, @StartDate=@StartDate, @EndDate=@EndDate,      
        @LeadIds=@LeadIds,@AssignedTo=@AssignedTo, @IsActive=@IsActive, @TaskId=@TaskId, @Status=@Status,@UserID=@UserID,@OutcomesId=@OutcomesId,@CollabratoerUserIds=@CollabratoerUserIds,      
        @IsSMS=@IsSMS,@IsEmail=@IsEmail,@IsTask=@IsTask, @IsAppointment=@IsAppointment, @TaskType=@TaskType, @CompleteAddress=@CompleteAddress, @Latitude=@Latitude,       
        @Longitude=@Longitude, @SmsSchedule=@SmsSchedule,@EmailSchedule=@EmailSchedule, @NotifyMe=@NotifyMe, @outcomeid=0,@massbatchid=@BatchID,@mode='Insert'      
      
     END      
     ELSE IF @MassOperation='Delete'      
     BEGIN      
     print 'Lead Delete'      
      EXEC Usp_LeadDeleteById @CSVID=@BatchID, @Mode='batchid'      
      
     END      
    END      
          
    ELSE IF @EntityType='Enquiry'      
    BEGIN       
 delete from @entitydata  
 insert into @entitydata(entity,entityid)  
 select 'enquiry',t.EntityID from Tbl_MassOperationDetails(nolock) t where SummaryId=@BatchID  
  
     IF @MassOperation ='Add Lead'      
     begin      
     print 'Enquiry Add Lead'      
      EXEC usp_MassAddFollowupfromEnq_ChangeWithFollowupDate1 @EnqID=@IDS, @FollowupStatus=@FollowUpStatus, @AssignTo=@AssignedTo, @NextStatusDate=@NextStatusDate, @Remarks=@Remarks,       
       @Products=@Products, @AmountPaid=@AmountPaid, @CreatedBy=@UserID, @ParentID=@ParentID, @IsReAssign=@IsReAssign,@BatchID=@BatchID      
      
     end      
   else if @massoperation in ('addtag','removetag')  
  begin  
  print 'Enquiry add/remove tag'  
  exec usp_add_remove_tag_bulk @entitydata,@massoperation,@actiondetails  
  
  end  
  
     ELSE IF @MassOperation='Send SMS'      
     BEGIN      
     print 'Enquiry Send SMS'      
      exec usp_IntindSMSFromEnquiry_WithDLTTemplateID_new @EnqID=IDS, @Account=@AccountID, @SenderID=@SenderID, @Message=@Message, @IsUnicode=@IsUnicode, @Mobile=@IsMobile,      
       @mobile1=@IsMobile1, @Mobile2=@IsMobile2, @DLTTemplateID=@SMSTemplateID, @UserId= @UserId, @massbatchid=@BatchID      
     END      
     ELSE IF @MassOperation='Send Mail'      
     BEGIN      
     print 'Enquiry Send Mail, TemplateID: ' + cast(@TemplateID as varchar)      
      if @TemplateID>0      
       BEGIN  
   
         
        EXEC usp_SendMassMailFromEnquiry_WithTemplateID_WithFromMailID_new @IDS=@IDS, @Account=@AccountID, @Email_Subject=@Subjects, @Message_TemplateID=@TemplateID, @SenderName=@SenderName,      
        @ReplyTo=@ReplyTo, @EmailId=@EmailId, @EmailId1=@EmailId1, @EmailId2= @EmailId2, @UserId=@UserId, @FromMailID=@FromMailID, @massbatchid=@Batchid      
        /*  
     EXEC usp_SendMassMailFromEnquiry_WithTemplateID_WithFromMailID_new__ViaOtherDB @IDS=@IDS, @Account=@AccountID, @Email_Subject=@Subjects, @Message_TemplateID=@TemplateID, @SenderName=@SenderName,      
        @ReplyTo=@ReplyTo, @EmailId=@EmailId, @EmailId1=@EmailId1, @EmailId2= @EmailId2, @UserId=@UserId, @FromMailID=@FromMailID, @massbatchid=@Batchid      
  */  
       END      
       ELSE       
       BEGIN     
          
        EXEC usp_SendMassMailFromEnquiry_WithFromMailID  @IDS=@IDS,@Account=@AccountID, @Email_Subject=@Subjects, @Message=@ComposeMsg, @SenderName=@SenderName, @ReplyTo=@ReplyTo,      
        @EmailId=@EmailId, @EmailId1=@EmailId1, @EmailId2=@EmailId2, @UserId=@UserId, @FromMailID=@FromMailID,@massbatchid=@BatchID      
         
     /*   
     EXEC usp_SendMassMailFromEnquiry_WithFromMailID_ViaOtherDB  @IDS=@IDS,@Account=@AccountID, @Email_Subject=@Subjects, @Message=@ComposeMsg, @SenderName=@SenderName, @ReplyTo=@ReplyTo,      
        @EmailId=@EmailId, @EmailId1=@EmailId1, @EmailId2=@EmailId2, @UserId=@UserId, @FromMailID=@FromMailID,@massbatchid=@BatchID      
  */  
       END      
     END      
     ELSE IF @MassOperation='Delete'      
     BEGIN      
     print 'Enquiry Delete'      
      exec Usp_EnquiryDeleteById @CSVID=@BatchID, @Mode='batchid'      
     END      
     ELSE IF @MassOperation='Update'      
     BEGIN      
     print 'Enquiry Update'      
       exec Usp_Update_MassLeadEnquiry @userid=@userid, @tablename='', @updatevalues=@metaData, @HashSeparatedIDs='', @batchid=@batchid, @mode='Update'      
     END      
    END      
          
    UPDATE  Tbl_MassOperationSummary set IsProcessed =1 where BatchID=@BatchID      
         
   END TRY      
   BEGIN CATCH      
   exec usp_inserterrorinfo      
    Update Tbl_massoperationsummary set errorDetails=Error_message(),IsProcessed =1 where BatchID=@Batchid       
   END CATCH      
   set @minrow = @minrow +1       
  END      
END


GO

/* ============================================================
   Procedure: [dbo].[Usp_MassOperationLeadID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

---------------------------------------

  
/*   
--exec [Usp_MassOperationLeadID_Temp] @txtSearch=N'',@ParentID=34594,@Userid=34594,@FilterText=N'',@srno=N'1',@enno=N'20',@notfollowedup='0',@MassOperationName =''  
  
  --exec [Usp_MassOperationLeadID_Temp] @txtSearch=N'',@Userid=34594,@FilterText=N'',@srno=N'1',@enno=N'20',@notfollowedup='0',@MassOperationName =''  
*/  
 CREATE   PROCEDURE [dbo].[Usp_MassOperationLeadID] (  
 @txtSearch NVARCHAR(max)  
 ,@Userid INT = 0  
 ,@FilterText NVARCHAR(MAX) = ''  
 ,@srno NVARCHAR(100)  
 ,@enno NVARCHAR(100)  
 ,@ordstr NVARCHAR(Max) = ''  
 ,@notfollowedup INT = 0  
 ,@MassOperationName nvarchar(100)=''  
 )  
AS  
BEGIN  
  
 --  declare  @txtSearch NVARCHAR(max) = N''  
 --,@ParentID BIGINT = 40834  
 --,@Userid INT = 40834  
 --,@FilterText NVARCHAR(MAX) = N' (personname like ''%a%'' ) '  
 --,@srno NVARCHAR(100) = N'1'  
 --,@enno NVARCHAR(100) = N'20'  
 --,@ordstr NVARCHAR(Max) = N''  
 --,@notfollowedup INT = 0  
  
   
 IF OBJECT_ID('tempdb.dbo.#temp1', 'U') IS NOT NULL  
 BEGIN  
  DROP TABLE #temp1;  
 END;  
  
 IF OBJECT_ID('tempdb.dbo.#temp2', 'U') IS NOT NULL  
 BEGIN  
  DROP TABLE #temp2;  
 END;  
 drop table if exists #Leadtemp   
 Create Table #Leadtemp (LeadID BIGINT)  
 --IF OBJECT_ID('tempdb.dbo.#TableData2', 'U') IS NOT NULL BEGIN DROP TABLE #TableData2; END;                         
 DECLARE @Str NVARCHAR(200) = @ordstr;--' personname desc '  
 DECLARE @ColumnName NVARCHAR(200) = ''  
 DECLARE @StrPredefinedOrderBy NVARCHAR(500) = ''  
 DECLARE @StrCustomOrderBy NVARCHAR(500) = ''  
 DECLARE @actUserID BIGINT = @Userid  
 DECLARE @Parentid BIGINT  =(Select ParentId from User_Detail (NOLOCK) where User_ID=@Userid)  
  
    --select @enno=count(1) from userleads(nolock) where parentid=@parentid  
  
 IF (rtrim(ltrim(@Str)) <> '')  
 BEGIN  
  SET @Str = ltrim(RTRIM(@Str))  
  
  --select @Str  
  SELECT TOP 1 @ColumnName = value  
  FROM string_split(@Str, ' ')  
  
  --select @ColumnName   
  IF (  
    EXISTS (  
     SELECT 1  
     FROM INFORMATION_SCHEMA.COLUMNS  
     WHERE table_name = 'UserLeads'  
      AND column_name = rtrim(ltrim(@ColumnName))  
     )  
    )  
  BEGIN  
   --set @StrPredefinedOrderBy = N' order by ' +  @Str;  
   SET @StrPredefinedOrderBy = N' ' + @Str + ' , ';  
   SET @StrCustomOrderBy = '';  
  END  
  ELSE  
  BEGIN  
   DECLARE @FullDataType NVARCHAR(200) = 'nvarchar(max)'  
  
   SELECT TOP 1 @FullDataType = CASE   
     WHEN ISNULL(datatype, 'v') = 'd'  
      THEN 'date'  
     WHEN ISNULL(datatype, 'v') = 'f'  
      THEN 'bigint'  
     WHEN ISNULL(datatype, 'v') = 'v'  
      THEN 'nvarchar(max)'  
     ELSE 'nvarchar(max)'  
     END  
   FROM customfields WITH (NOLOCK)  
   WHERE ParentID = @Parentid  
    AND fieldname = rtrim(ltrim(@ColumnName))  
  
   DECLARE @CustomStrExp NVARCHAR(200) = '';  
  
   IF (  
     EXISTS (  
      SELECT value  
      FROM string_split(@Str, ' ')  
      WHERE rtrim(ltrim(value)) = 'asc'  
      )  
     )  
   BEGIN  
    SET @CustomStrExp = N' ' + 'CAST(' + @ColumnName + ' as  ' + @FullDataType + ')' + '  asc '  
   END  
   ELSE  
   BEGIN  
    SET @CustomStrExp = N' ' + 'CAST(' + @ColumnName + ' as  ' + @FullDataType + ')' + '  desc '  
   END  
  
   SET @StrPredefinedOrderBy = ''  
   --set @StrCustomOrderBy = N' order by ' +  @Str;    
   SET @StrCustomOrderBy = N' ' + @CustomStrExp + ' , ';  
  END  
    --select @StrPredefinedOrderBy  
    --select @StrCustomOrderBy  
 END  
  
 DECLARE @IsAdmin BIT = 0  
 DECLARE @TimeZoneName NVARCHAR(255) = isnull((  
    SELECT TimeZone  
    FROM User_Detail(NOLOCK)  
    WHERE User_ID = @Userid  
    ), 'India Standard Time')  
 DECLARE @UserIDTeam BIGINT = @Userid;  
 DECLARE @tbluser TABLE (  
  User_ID BIGINT  
  ,Name VARCHAR(100)  
  ,IMAGE VARCHAR(100)  
  )  
  
 SELECT @IsAdmin = IsAdmin  
 FROM User_Detail(NOLOCK)  
 WHERE User_ID = @Userid  
  
 IF (@IsAdmin = 1)  
 BEGIN  
  SET @Userid = 0;  
  
  INSERT INTO @tbluser  
  EXEC Use_GetUserDetails @ParentId  
 END  
 ELSE  
 BEGIN  
  INSERT INTO @tbluser  
  EXEC Use_GetUserDetails @UserId  
 END  
  
 DECLARE @TeamCode VARCHAR(10) = ''  
 DECLARE @ScopeCode VARCHAR(10) = ''  
 DECLARE @UserIdTeamLst VARCHAR(4000) = ''  
 DECLARE @HierarchyJSON VARCHAR(Max) = ''  
  
 SELECT @UserIdTeamLst = isnull(STRING_AGG(User_ID, ','), '')  
 FROM @tbluser  
  
 PRINT '@UserIdTeamLst: ' + @UserIdTeamLst  
               
 BEGIN  
                                  
  DECLARE @NoCustomFields BIGINT  
   ,@offset INT = 20  
   ,@filterCnt INT = 0  
  DECLARE @Pivot_Column NVARCHAR(MAX);  
  DECLARE @Query NVARCHAR(MAX) = ''  
   ,@Query1 NVARCHAR(MAX) = ''  
   ,@Query2 NVARCHAR(max) = ''  
  DECLARE @maxScore NUMERIC(18, 2) = isnull((  
     SELECT (max(currentscore) * 100) / 99  
     FROM lead_score_history(NOLOCK) e  
     WHERE parentid = @ParentID  
     ), 0)  
  DECLARE @hot INT  
   ,@warm INT  
   ,@cold INT  
  
  SELECT @hot = hot  
   ,@warm = warm  
   ,@cold = cold  
  FROM lead_cateogy_thresholds(NOLOCK)  
  WHERE parentid = @ParentID  
  
  IF @hot IS NULL  
  BEGIN  
   SELECT @hot = hot  
    ,@warm = warm  
    ,@cold = cold  
   FROM lead_cateogy_thresholds(NOLOCK)  
   WHERE parentid = 0  
  END  
  
  /*Select Pivot Column*/  
  SELECT @Pivot_Column = COALESCE(@Pivot_Column + ',', '') + QUOTENAME([fieldname])  
  FROM (  
   SELECT DISTINCT [fieldname]  
   FROM customfields  
   WHERE [ParentID] = @ParentID  
    AND [isActive] = 1  
   ) AS Tab;  
  
  SET @NoCustomFields = (  
    SELECT count(DISTINCT [fieldname])  
    FROM customfields  
    WHERE [ParentID] = @ParentID  
     AND [isActive] = 1  
    )  
  
  DECLARE @Rcnt VARCHAR(100);  
  
  IF (@ordstr = '')  
  BEGIN  
   SET @ordstr = ' CurrentScore desc, case when cast(followupdate as date) = cast(getdate() as date) then 0        
     when followupdate < getdate()  then 1        
     when followupdate > getdate() then 2        
     when followupdate is null then 3        
      end,followupdate '  
  END  
  
  IF (@txtSearch = '')  
  BEGIN  
   SET @txtSearch = N' (1=1) ';  
   SET @offset = 0  
  END;  
  
  IF (@FilterText = '')  
  BEGIN  
   SET @FilterText = N' (1=1) ';  
  END;  
  
  IF (  
    @FilterText = ' (1=1) '  
    AND @txtSearch = ' (1=1) '  
    )  
  BEGIN  
   PRINT 'Branch A'  
  
   SET @Query += CAST(N'SELECT A.ID  
   ,A.LeadNo,A.PersonName,A.CompanyName,A.MobileNo,A.EmailID,A.City,A.State,A.Country,A.CountryCode,A.PinCode, A.ResidentialAddress, A.OfficeAddress, isnull(A.SourceName,''Unknown'') SourceName, A.MediumName,A.CampaignName,A.InitialRemarks, A.ParentID, A.FollowupBy,format(A.FollowupDate,''dd-MMM-yyyy HH:mm:ss'') as FollowupDate, format(A.FollowupCreatedDate,''dd-MMM-yyyy HH:mm:ss'') as FollowupCreatedDate, format(A.CreatedOn1,''dd-MMM-yyyy HH:mm:ss'') as CreatedOn1New, format(A.CreatedOn1,''dd-MMM-yyyy HH:mm:ss'') as CreatedOn1 , A.AssignedTo, A.Remarks, CASE WHEN ISNULL(A.FollowupStatus, '''') <> '''' THEN '' <p><b>Follow Up Status:&nbsp;&nbsp;</b>'' + CAST(ISNULL(A.FollowupStatus, '''') AS VARCHAR(50))  + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.FollowupDate, '''') <> '''' THEN '' <p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST(A.FollowupDate AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.Products, '''') <> '''' THEN ''<p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST(A.Products AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.AmountPaid,0) <> 0 THEN ''<p><b>Amount Paid:&nbsp;&nbsp;</b>'' + CAST(CAST(ISNULL(A.AmountPaid, 0) AS DECIMAL(18, 0)) AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.Remarks, '''') <> '''' THEN ''<p><b>Remarks:&nbsp;&nbsp;</b>'' + ISNULL(A.Remarks, '''') + ''</p>'' ELSE '''' END AS FollowUp,A.MobileNo1, A.MobileNo2, A.MobileNo3, A.EmailID3, A.EmailID1, A.EmailID2, A.FollowupStatus, A.assigneduser,A.assignedUserloginOnly ,A.img_ext, A.WhereAddress, A.Tags, isnull(A.Products, '''') as Products, A.CurrentScore, A.Profit_Loss, A.ThresholdColor, RowNumber1, rc1, A.User_Login, A.LastFollowupCreatedByName, format(A.LastFollowupedOn,''dd-MMM-yyyy HH:mm:ss'') as LastFollowupedOn, A.WhatsAppNoColName,A.CreatedBy, cast(A.ModifiedOn as datetime) as ModifiedOn, A.ModifiedBy,CAST(CAST(ISNULL(A.AmountPaid, 0) AS DECIMAL(18, 0)) AS VARCHAR(50)) as AmountPaid  INTO #temp1 FROM ( select ROW_NUMBER() OVER(ORDER BY ' + @StrPredefinedOrderBy +   
     N'   S.ID DESC) AS RowNumber1, count(*) OVER(ORDER BY S.ParentID) AS rc1, * From ( select * From   
     ( SELECT UL.ID  
     , UL.LeadNo, UL.PersonName, UL.img_ext, UL.WhereAddress, isnull(tg.Tags, '''') Tags, UL.CompanyName, UL.CreatedOn AS CreatedOn1,  CASE WHEN ISNULL(UL.CountryCode, '''') <> '''' and trim(ISNULL(UL.MobileNo, '''')) <> ''''  THEN TRIM(ISNULL(UL.Countrycode, '''')) + '' '' + TRIM(ISNULL(UL.MobileNo, ''''))  ELSE '''' END +  CASE WHEN trim(ISNULL(UL.Mobileno1, '''')) <> '''' THEN '', ...'' ELSE '''' END AS MobileNo, CASE WHEN ISNULL(UL.Emailid, '''') <> '''' THEN UL.Emailid ELSE '''' END +  CASE WHEN ISNULL(UL.EmailID1, '''') <> '''' THEN '', '' ELSE '''' END +  CASE WHEN ISNULL(UL.EmailID2, '''') <> '''' THEN '', '' ELSE '''' END AS EmailID, UL.City, UL.State, UL.Country, UL.CountryCode, UL.PinCode, UL.ResidentialAddress, UL.OfficeAddress, UL.AssignedTo, USS.Name AS SourceName, UMS.Name AS MediumName, UCS.Name AS CampaignName, UL.InitialRemarks, UL.ParentID,FUS.FollowupStatus, UL.FollowupDate, UL.Remarks, ISNULL(UL.AmountPaid, 0) AS AmountPaid, UL.CreatedOn AS FollowupCreatedDate, UL.CreatedBy, UL.ModifiedOn, UL.ModifiedBy,ISNULL(UD2.User_Login,'''') as FollowupBy, trim(UL.MobileNo) AS MobileNo3, trim(UL.MobileNo1) as MobileNo1, trim(UL.MobileNo2) as MobileNo2, UL.EmailID AS EmailID3, UL.EmailID1, UL.EmailID2, (  select isnull((select STRING_AGG(isnull(ProductName,''''),'', '') from openjson(ul.productsJson) with(ProductName nvarchar(max) ''$.ProductName'' )  
          where isnull(ul.productsJson,'''') != '''') , '''') ) AS Products, UD.User_Login + '' ('' + Ud.FName +  '' '' + Ud.LName + '')'' AS assigneduser, UD.User_Login as assignedUserloginOnly , Profit_Loss=case when LS.ScoreAdded > 0 then ''Green_Up'' when LS.ScoreAdded < 0 then ''Red_Down'' else '''' end, CurrentScore=cast(isnull((LS.currentscore/nullif(' + cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int) , ThresholdColor=case when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int)>' + cast(@warm AS NVARCHAR(max)) + N' then ''Hot'' when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int) between ' + cast(@cold AS NVARCHAR(max)) + N' and ' + cast(@warm AS NVARCHAR(max)) + N' then ''Warm'' else ''Cold'' end , UD1.User_Login , ISNULL(UD2.User_Login, '''') as LastFollowupCreatedByName, ul.LastFollowupCreatedOn as LastFollowupedOn, UL.WhatsAppNoColName  ' AS NVARCHAR(max))  
    
   SELECT @Query += cast(N' FROM UserLeads AS UL(NOLOCK) left JOIN UserSourceSettings AS USS(NOLOCK)  
  ON UL.SourceName = USS.SourceID --outer apply dbo.funcToGetScoredetails(ul.id) f  
  left join lead_score_history_latest(nolock) LS   
 ON UL.ID=LS.LeadId LEFT JOIN UserMediumSettings AS UMS(NOLOCK)  
 ON UL.MediumName = UMS.MediumID LEFT JOIN UserCampaignSettings AS UCS(NOLOCK)  
 ON UL.CampaignName = UCS.CampaignID LEFT JOIN User_Detail AS UD(NOLOCK)  
 ON UL.AssignedTo = UD.User_ID LEFT JOIN User_Detail AS UD1(NOLOCK)  
 ON UL.CreatedBy = UD1.User_ID LEFT JOIN User_Detail AS UD2(NOLOCK)  
 ON UL.LastFollowupCreatedBy = UD2.User_ID left join FollowUp_Status AS FUS(NOLOCK)  
 ON UL.FollowUpStatus = FUS.id   
 --left join LeadPipelineMapping_latest(nolock) as lpm  
 --on UL.ID = lpm.LeadID   
  LEFT JOIN ( select STRING_AGG(Tag, '','') as Tags, etm.EntityID from TagMaster(nolock) tm inner join EntityTagMapping(nolock) etm on tm.id = etm.TagID and etm.entity = ''lead'' and tm.ParentID = ' +   
     Convert(VARCHAR(100), @ParentID) + N' where ISNULL(etm.EntityID, 0) > 0 group by etm.EntityID ) tg on tg.EntityID = UL.ID   
 WHERE UL.ParentID = ' + CAST(@ParentID AS NVARCHAR(MAX)) + N' AND UL.AssignedTo ' + CASE   
      WHEN @Userid = 0  
       THEN N' = UL.AssignedTo '  
      WHEN @Userid > 0 /*and isnull(@TeamCode,'') != ''*/  
       THEN N' in (' + isnull(@UserIdTeamLst, '') + ')'  
      ELSE N' = ' + CAST(@Userid AS NVARCHAR(MAX))  
      END + N'     
 and 1= case when isnull(' + cast(@notfollowedup AS NVARCHAR) + N',''0'')=''0'' then 1 when isnull(' + cast(@notfollowedup AS NVARCHAR) + N',''0'')=''1''       
 and abs(datediff(mi,ul.createdon,ul.followupdate))<=2      
 --and ul.enquirysource not between 12 and 15 and ul.enquirysource<>22        
 and ul.ModifiedOn is null  then 1 else 0 end' + '      
 ) T         
 ) S         
 ) AS A ' --as nvarchar(max))  
 + ' Where A.RowNumber1 BETWEEN ' + CONVERT(NVARCHAR(max), @srno) + N' AND ' + CONVERT(NVARCHAR(max), @enno + @offset) AS NVARCHAR(MAX));;  
     
  END  
  ELSE  
  BEGIN  
   PRINT 'Branch B'  
  
   SET @Query += CAST(N'SELECT A.ID, A.LeadNo, A.PersonName, A.CompanyName, A.MobileNo, A.EmailID, A.City, A.State, A.Country, A.CountryCode, A.PinCode, A.ResidentialAddress, A.OfficeAddress,isnull(A.SourceName,''Unknown'') SourceName, A.MediumName, A.CampaignName, A.InitialRemarks, A.ParentID, A.FollowupBy, format(A.FollowupDate,''dd-MMM-yyyy HH:mm:ss'') as FollowupDate,format(A.FollowupCreatedDate,''dd-MMM-yyyy HH:mm:ss'') as FollowupCreatedDate,format(A.CreatedOn1,''dd-MMM-yyyy HH:mm:ss'') as CreatedOn1New,format(A.CreatedOn1,''dd-MMM-yyyy HH:mm:ss'') as CreatedOn1, A.AssignedTo,A.Remarks,CASE WHEN ISNULL(A.FollowupStatus,'''') <> '''' THEN '' <p><b>Follow Up Status:&nbsp;&nbsp;</b>'' + CAST(ISNULL(A.FollowupStatus,'''') AS VARCHAR(50))  + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.FollowupDate,'''') <> '''' THEN '' <p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST(A.FollowupDate AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.Products,'''') <> '''' THEN ''<p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST(A.Products AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.AmountPaid,0) <> 0 THEN ''<p><b>Amount Paid:&nbsp;&nbsp;</b>'' + CAST(CAST(ISNULL(A.AmountPaid, 0) AS DECIMAL(18, 0)) AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL (A.Remarks, '''') <> '''' THEN ''<p><b>Remarks:&nbsp;&nbsp;</b>'' + ISNULL(A.Remarks,'''') + ''</p>'' ELSE '''' END AS FollowUp, A.MobileNo1,A.MobileNo2,A.MobileNo3,A.EmailID3,A.EmailID1,A.EmailID2,A.FollowupStatus,A.assigneduser,A.assignedUserloginOnly,A.img_ext, A.WhereAddress, A.Tags, isnull(A.Products, '''') as Products, A.CurrentScore, A.Profit_Loss, A.ThresholdColor,RowNumber1,rc1 ,A.User_Login, A.LastFollowupCreatedByName, format(A.LastFollowupedOn,''dd-MMM-yyyy HH:mm:ss'') as LastFollowupedOn,A.WhatsAppNoColName, A.CreatedBy, cast(A.ModifiedOn as datetime) as ModifiedOn, A.ModifiedBy,CAST(CAST(ISNULL(A.AmountPaid, 0) AS DECIMAL(18, 0)) AS VARCHAR(50)) as AmountPaid INTO #temp1 FROM ( select ROW_NUMBER() OVER(ORDER BY ' + @StrPredefinedOrderBy + N'   S.ID DESC) AS RowNumber1, count(*) OVER(ORDER BY S.ParentID) AS rc1,* From ( select * From ( SELECT UL.ID,UL.LeadNo,UL.PersonName,UL.img_ext,UL.CompanyName,UL.CreatedOn AS CreatedOn1, CASE WHEN ISNULL(UL.CountryCode,'''') <> '''' and trim(ISNULL(UL.MobileNo,'''')) <> ''''  THEN TRIM(ISNULL(UL.Countrycode,'''')) + '' '' + TRIM(ISNULL(UL.MobileNo,''''))  ELSE '''' END +  CASE WHEN trim(ISNULL(UL.Mobileno1,'''')) <> '''' THEN '', ...'' ELSE '''' END AS MobileNo, CASE WHEN ISNULL(UL.Emailid,'''') <> '''' THEN UL.Emailid ELSE '''' END + CASE WHEN ISNULL(UL.EmailID1,'''') <> '''' THEN '', '' ELSE '''' END + CASE WHEN ISNULL(UL.EmailID2,'''') <> '''' THEN '', '' ELSE '''' END AS EmailID, UL.City, UL.State, UL.Country, UL.CountryCode, UL.PinCode,UL.ResidentialAddress, UL.OfficeAddress, UL.AssignedTo, USS.Name AS SourceName, UMS.Name AS MediumName, UCS.Name AS CampaignName, UL.InitialRemarks, UL.ParentID,FUS.FollowupStatus, UL.FollowupDate, UL.Remarks, ISNULL(UL.AmountPaid, 0) AS AmountPaid
   , UL.CreatedOn AS FollowupCreatedDate, UL.CreatedBy, UL.ModifiedOn, UL.ModifiedBy, ISNULL(UD2.User_Login,'''') as FollowupBy, trim(UL.MobileNo) AS MobileNo3, trim(UL.MobileNo1) as MobileNo1, trim(UL.MobileNo2) as MobileNo2, UL.EmailID AS EmailID3, UL.EmailID1, UL.EmailID2, UL.WhereAddress, isnull(tg.Tags, '''') Tags, ( select isnull((select STRING_AGG(isnull(ProductName,''''),'', '') from openjson(ul.productsjson) with(ProductName nvarchar(max) ''$.ProductName'' ) where isnull(ul.productsjson,'''') != '''') , '''')) AS Products,UD.User_Login + '' ('' + Ud.FName +  '' '' + Ud.LName + '')'' AS assigneduser, UD.User_Login as assignedUserloginOnly, Profit_Loss=case when LS.ScoreAdded > 0 then ''Green_Up'' when LS.ScoreAdded < 0 then ''Red_Down'' else '''' end,CurrentScore=cast(isnull((LS.currentscore/nullif('+ cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int), ThresholdColor=case when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int)>' + cast(@warm AS NVARCHAR(max)) + N' then ''Hot'' when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int) between ' + cast(@cold AS NVARCHAR(max)) + N'  and ' + cast(@warm AS NVARCHAR(max)) + N' then ''Warm'' else ''Cold'' end, UD1.User_Login ' AS NVARCHAR(max)) + N', isnull(UD2.User_Login, '''') as LastFollowupCreatedByName, ul.LastFollowupCreatedOn as LastFollowupedOn, UL.WhatsAppNoColName  '  
  
   SELECT @Query += cast(N' FROM UserLeads AS UL(NOLOCK) left JOIN UserSourceSettings AS USS(NOLOCK)  
  ON UL.SourceName = USS.SourceID --outer apply dbo.funcToGetScoredetails(ul.id) f  
  left join lead_score_history_latest(nolock) LS ON UL.ID=LS.LeadId LEFT JOIN UserMediumSettings AS UMS(NOLOCK) ON UL.MediumName = UMS.MediumID LEFT JOIN UserCampaignSettings AS UCS(NOLOCK) ON UL.CampaignName = UCS.CampaignID LEFT JOIN User_Detail AS UD(NOLOCK) ON UL.AssignedTo = UD.User_ID LEFT JOIN User_Detail AS UD1(NOLOCK) ON UL.CreatedBy = UD1.User_ID LEFT JOIN User_Detail AS UD2(NOLOCK) ON UL.LastFollowupCreatedBy = UD2.User_ID left join FollowUp_Status AS FUS(NOLOCK) ON UL.FollowUpStatus = FUS.id  
 --left join LeadPipelineMapping_latest(nolock) as lpm  
 --on UL.ID = lpm.LeadID  
  LEFT JOIN ( select STRING_AGG(Tag, '','') as Tags, etm.EntityID from TagMaster(nolock) tm inner join EntityTagMapping(nolock) etm on tm.id = etm.TagID and etm.entity = ''lead'' and tm.ParentID = ' + Convert(VARCHAR(100), @ParentID) + ' where ISNULL(etm.EntityID, 0) > 0 group by etm.EntityID ) tg on tg.EntityID = UL.ID     
 WHERE UL.ParentID = ' + CAST(@ParentID AS NVARCHAR(MAX)) + N' AND UL.AssignedTo ' + CASE   
      WHEN @Userid = 0  
       THEN N' = UL.AssignedTo '  
      WHEN @Userid > 0 /*and isnull(@TeamCode,'') != ''*/  
       THEN ' in (' + isnull(@UserIdTeamLst, '') + ')'  
      ELSE ' = ' + CAST(@Userid AS NVARCHAR(MAX))  
      END + ' and 1= case when isnull(' + cast(@notfollowedup AS NVARCHAR) + ',''0'')=''0'' then 1 when isnull(' + cast(@notfollowedup AS NVARCHAR) + ',''0'')=''1'' and abs(datediff(mi,ul.createdon,ul.followupdate))<=2  
 --and ul.enquirysource not between 12 and 15 and ul.enquirysource<>22  
 and ul.ModifiedOn is null  then 1 else 0 end' + ' ) T Where ' + @FilterText + ' ) S ) AS A   
                    Where '   
                 + CASE   
      WHEN @txtSearch = ' (1=1) '  
       THEN ' A.RowNumber1 BETWEEN ' + CONVERT(NVARCHAR(max), @srno) + N' AND ' + CONVERT(NVARCHAR(max), @enno)  
      ELSE ' (1=1) '  
      END   
      AS NVARCHAR(MAX));  
  END  
  
  PRINT cast(@Query AS VARCHAR(max))  
  
  IF (@Pivot_Column IS NOT NULL)  
  BEGIN  
   PRINT 'Branch C'  
  
   --IF(@FilterText = ' (1=1) ' and @txtSearch = ' (1=1) ')-- From Branch A   
   IF (@txtSearch = ' (1=1) ') -- From Branch A   
   BEGIN  
    PRINT 'Branch CA'  
    DECLARE @caQuery NVARCHAR(max) = CAST(N'; Insert into #Leadtemp (LeadId) Select id from ( Select *         
   From ( SELECT ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, User_Login, FollowupDate, FollowupCreatedDate as CreatedOn, CreatedOn1New, CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus, assigneduser,assignedUserloginOnly, Img_Ext, WhereAddress, Products, FollowupCreatedDate, FollowupBy, ' + @Pivot_Column + N', CurrentScore, Profit_Loss, ThresholdColor, ROW_NUMBER() OVER(ORDER BY ' + @StrPredefinedOrderBy + N' ' + @StrCustomOrderBy + '  [ID] DESC)  ' + ' AS [RowNumber1], rc1, LastFollowupCreatedByName, LastFollowupedOn,
   WhatsAppNoColName,CreatedBy, ModifiedOn, ModifiedBy, AmountPaid FROM  
   (SELECT ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, FollowupBy, FollowupDate, FollowupCreatedDate
, CreatedOn1New, CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus, assigneduser,assignedUserloginOnly, img_ext, WhereAddress, Products, [fieldname] , fieldvalue, CurrentScore, Profit_Loss,ThresholdColor, RowNumber1, rc1 ,User_Login,LastFollowupCreatedByName, LastFollowupedOn, WhatsAppNoColName,CreatedBy, ModifiedOn, ModifiedBy, AmountPaid FROM (select L.ID,  L.LeadNo, L.PersonName, L.CompanyName,L.MobileNo,L.EmailID, L.City, L.State,L.Country, L.CountryCode, L.PinCode, L.ResidentialAddress, L.OfficeAddress, L.SourceName, L.MediumName, L.CampaignName, L.InitialRemarks, L.ParentID, L.FollowupBy, L.FollowupDate, L.FollowupCreatedDate, L.CreatedOn1New, L.CreatedOn1, L.AssignedTo, L.Remarks, L.FollowUp, L.MobileNo1, L.MobileNo2, L.MobileNo3, L.EmailID3, L.EmailID1, L.EmailID2, L.FollowupStatus,  L.assigneduser,L.assignedUserloginOnly, L.Img_Ext, L.WhereAddress, L.Products, y.fieldname, x.fieldvalue, L.CurrentScore, L.Profit_Loss, L.ThresholdColor, L.RowNumber1, L.rc1, L.User_Login,L.LastFollowupCreatedByName, L.LastFollowupedOn, L.WhatsAppNoColName, L.CreatedBy, L.ModifiedOn, L.ModifiedBy, L.AmountPaid  From #temp1 L left join customfieldLeadvalue(nolock) x ON L.ID = x.LeadID left join customfields(nolock) y ON x.fieldID=y.field_ID AND y.[ParentID] = '   
      + CAST(@Parentid AS NVARCHAR(MAX)) + N' AND y.[isActive] = 1 )q )Tab1  
  PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + N')) AS Tab2 Where ' + @txtSearch + ' ) T1  
   ) T2 '   
        --'Where T2.RowNumber1 BETWEEN ' + CONVERT(NVARCHAR(max), @srno) + N' AND ' + CONVERT(NVARCHAR(max), @enno)   
      + N' ORDER BY ' + @ordstr AS NVARCHAR(MAX));  
  
    --PRINT cast(@caQuery as varchar(max))  
  
    SELECT @Query = @Query + @caQuery  
   END  
   ELSE -- From Branch B        
   BEGIN  
    PRINT 'Branch CB'  
 SELECT @filterCnt = count(*)  
    FROM dbo.fn_Split(@txtSearch, ' ) ')  
    select @filterCnt = 1  
  
    SELECT @Query1 += CAST(N'; select * into #Temp2 From (select [x].LeadID, [y].[fieldname], [x].[fieldvalue] from customfieldLeadvalue(nolock) x inner join customfields(nolock) y ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + N' AND y.[isActive] = 1 ) T1 PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + N')) AS Tab2 Where ' + @txtSearch AS NVARCHAR(MAX));  
  
    SELECT @Query1 += CAST(N'; Insert into #Leadtemp (LeadId) Select id from ( Select ROW_NUMBER() OVER(ORDER BY ' + @StrPredefinedOrderBy + N' ' + @StrCustomOrderBy + '  [ID] DESC)  ' + ' AS [RowNumber1], count(*) OVER(ORDER BY [ParentID]) AS [rc1], * From ( SELECT ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, User_Login, FollowupDate, FollowupCreatedDate as CreatedOn, CreatedOn1New, CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus, assigneduser,assignedUserloginOnly, Img_Ext, WhereAddress, Products, FollowupCreatedDate, FollowupBy, 
' + @Pivot_Column +   
      N', CurrentScore, Profit_Loss, ThresholdColor, LastFollowupCreatedByName, LastFollowupedOn, WhatsAppNoColName, CreatedBy, ModifiedOn, ModifiedBy, AmountPaid   
       From #Temp2 A inner join #temp1 L         
     ON A.LeadId = L.ID  ) T1         
      ) T2    
        Where  T2.RowNumber1 BETWEEN ' + CONVERT(NVARCHAR(max), @srno) + N' AND ' + CONVERT(NVARCHAR(max), @enno)   
       + N' ORDER BY ' + @ordstr AS NVARCHAR(MAX)) ;  
  
  
    --PRINT cast(@Query1 as varchar(max))  
  
    SELECT @Query = @Query + @Query1  
   END  
  END  
  ELSE  
  BEGIN  
   PRINT 'Branch D'  
  
   SET @Query2 += CAST(N';Insert into #Leadtemp (LeadId) Select ID    
  From #temp1        
  Where RowNumber1 BETWEEN ' + CONVERT(NVARCHAR(max), @srno) + N' AND ' + CONVERT(NVARCHAR(max), @enno) + N' ORDER BY ' + @ordstr  AS NVARCHAR(MAX));  
  
   PRINT cast(@Query2 as varchar(max))  
  
   SELECT @Query = @Query + @Query2  
  END  
  
  --print '@FinalQuery:- ' + cast(@Query as varchar(max))        
  EXEC sp_executesql @Query;  
      
-- INSERT INTO Tbl_MassOperationSummary (MassOperationName, UserID, Parentid, CreatedDate, IsProcessed, ProcedureName, FilterCriteria, EntityType)  
  -- Values (@MassOperationName, @actUserID, @parentid, getdate(), 0, 'Usp_MassOperationLeadID', @FilterText, 'Lead')  
 
   IF @MassOperationName = 'delete'
BEGIN
    INSERT INTO Tbl_MassOperationSummary (MassOperationName, UserID, Parentid, CreatedDate, IsProcessed, ProcedureName, FilterCriteria, EntityType,isvalid)
			Values (@MassOperationName, @actUserID, @parentid, getdate(), 0, 'Usp_MassOperationLeadID', @FilterText, 'Lead',1)
			END
ELSE
BEGIN
 
	INSERT INTO Tbl_MassOperationSummary (MassOperationName, UserID, Parentid, CreatedDate, IsProcessed, ProcedureName, FilterCriteria, EntityType)
			Values (@MassOperationName, @actUserID, @parentid, getdate(), 0, 'Usp_MassOperationLeadID', @FilterText, 'Lead')
			END
 
 Declare @BatchID Bigint  = Scope_Identity()  
  
 INSERT INTO Tbl_MassOperationDetails (SummaryId,EntityID)  
 Select @BatchID, LeadID from #Leadtemp   
   
 Select @BatchID BatchId  
  IF OBJECT_ID('tempdb.dbo.#temp1', 'U') IS NOT NULL  
  BEGIN  
   DROP TABLE #temp1;  
  END;  
  
  IF OBJECT_ID('tempdb.dbo.#temp2', 'U') IS NOT NULL  
  BEGIN  
   DROP TABLE #temp2;  
  END;  
     
  -- for temp display  
   --Select  LeadID from #Leadtemp   
   drop table if exists #Leadtemp  
  
  
 END  
END  





GO

/* ============================================================
   Procedure: [dbo].[Usp_MassOperationLeadID_Temp]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


/* 
--exec [Usp_MassOperationLeadID_Temp] @txtSearch=N'',@ParentID=34594,@Userid=34594,@FilterText=N'',@srno=N'1',@enno=N'20',@notfollowedup='0',@MassOperationName =''

  --exec [Usp_MassOperationLeadID_Temp] @txtSearch=N'',@Userid=32222,@FilterText=N'',@srno=N'1',@enno=N'20',@notfollowedup='0',@MassOperationName =''
*/
CREATE   PROCEDURE [dbo].[Usp_MassOperationLeadID_Temp] (
	@txtSearch NVARCHAR(max)
	,@Userid INT = 0
	,@FilterText NVARCHAR(MAX) = ''
	,@srno NVARCHAR(100)
	,@enno NVARCHAR(100)
	,@ordstr NVARCHAR(Max) = ''
	,@notfollowedup INT = 0
	,@MassOperationName nvarchar(100)=''
	)
AS
BEGIN

 --  declare  @txtSearch NVARCHAR(max) = N''
	--,@ParentID BIGINT = 40834
	--,@Userid INT = 40834
	--,@FilterText NVARCHAR(MAX) = N' (personname like ''%a%'' ) '
	--,@srno NVARCHAR(100) = N'1'
	--,@enno NVARCHAR(100) = N'20'
	--,@ordstr NVARCHAR(Max) = N''
	--,@notfollowedup INT = 0

	
	IF OBJECT_ID('tempdb.dbo.#temp1', 'U') IS NOT NULL
	BEGIN
		DROP TABLE #temp1;
	END;

	IF OBJECT_ID('tempdb.dbo.#temp2', 'U') IS NOT NULL
	BEGIN
		DROP TABLE #temp2;
	END;
	drop table if exists #Leadtemp 
	Create Table #Leadtemp (LeadID BIGINT)
	--IF OBJECT_ID('tempdb.dbo.#TableData2', 'U') IS NOT NULL BEGIN DROP TABLE #TableData2; END;                       
	DECLARE @Str NVARCHAR(200) = @ordstr;--' personname desc '
	DECLARE @ColumnName NVARCHAR(200) = ''
	DECLARE @StrPredefinedOrderBy NVARCHAR(500) = ''
	DECLARE @StrCustomOrderBy NVARCHAR(500) = ''
	DECLARE @actUserID BIGINT = @Userid
	DECLARE @Parentid BIGINT  =(Select ParentId from User_Detail (NOLOCK) where User_ID=@Userid)

    --select @enno=count(1) from userleads(nolock) where parentid=@parentid

	IF (rtrim(ltrim(@Str)) <> '')
	BEGIN
		SET @Str = ltrim(RTRIM(@Str))

		--select @Str
		SELECT TOP 1 @ColumnName = value
		FROM string_split(@Str, ' ')

		--select @ColumnName 
		IF (
				EXISTS (
					SELECT 1
					FROM INFORMATION_SCHEMA.COLUMNS
					WHERE table_name = 'UserLeads'
						AND column_name = rtrim(ltrim(@ColumnName))
					)
				)
		BEGIN
			--set @StrPredefinedOrderBy = N' order by ' +  @Str;
			SET @StrPredefinedOrderBy = N' ' + @Str + ' , ';
			SET @StrCustomOrderBy = '';
		END
		ELSE
		BEGIN
			DECLARE @FullDataType NVARCHAR(200) = 'nvarchar(max)'

			SELECT TOP 1 @FullDataType = CASE 
					WHEN ISNULL(datatype, 'v') = 'd'
						THEN 'date'
					WHEN ISNULL(datatype, 'v') = 'f'
						THEN 'bigint'
					WHEN ISNULL(datatype, 'v') = 'v'
						THEN 'nvarchar(max)'
					ELSE 'nvarchar(max)'
					END
			FROM customfields WITH (NOLOCK)
			WHERE ParentID = @Parentid
				AND fieldname = rtrim(ltrim(@ColumnName))

			DECLARE @CustomStrExp NVARCHAR(200) = '';

			IF (
					EXISTS (
						SELECT value
						FROM string_split(@Str, ' ')
						WHERE rtrim(ltrim(value)) = 'asc'
						)
					)
			BEGIN
				SET @CustomStrExp = N' ' + 'CAST(' + @ColumnName + ' as  ' + @FullDataType + ')' + '  asc '
			END
			ELSE
			BEGIN
				SET @CustomStrExp = N' ' + 'CAST(' + @ColumnName + ' as  ' + @FullDataType + ')' + '  desc '
			END

			SET @StrPredefinedOrderBy = ''
			--set @StrCustomOrderBy = N' order by ' +  @Str;  
			SET @StrCustomOrderBy = N' ' + @CustomStrExp + ' , ';
		END
				--select @StrPredefinedOrderBy
				--select @StrCustomOrderBy
	END

	DECLARE @IsAdmin BIT = 0
	DECLARE @TimeZoneName NVARCHAR(255) = isnull((
				SELECT TimeZone
				FROM User_Detail(NOLOCK)
				WHERE User_ID = @Userid
				), 'India Standard Time')
	DECLARE @UserIDTeam BIGINT = @Userid;
	DECLARE @tbluser TABLE (
		User_ID BIGINT
		,Name VARCHAR(100)
		,IMAGE VARCHAR(100)
		)

	SELECT @IsAdmin = IsAdmin
	FROM User_Detail(NOLOCK)
	WHERE User_ID = @Userid

	IF (@IsAdmin = 1)
	BEGIN
		SET @Userid = 0;

		INSERT INTO @tbluser
		EXEC Use_GetUserDetails @ParentId
	END
	ELSE
	BEGIN
		INSERT INTO @tbluser
		EXEC Use_GetUserDetails @UserId
	END

	DECLARE @TeamCode VARCHAR(10) = ''
	DECLARE @ScopeCode VARCHAR(10) = ''
	DECLARE @UserIdTeamLst VARCHAR(4000) = ''
	DECLARE @HierarchyJSON VARCHAR(Max) = ''

	SELECT @UserIdTeamLst = isnull(STRING_AGG(User_ID, ','), '')
	FROM @tbluser

	PRINT '@UserIdTeamLst: ' + @UserIdTeamLst
             
	BEGIN
		                              
		DECLARE @NoCustomFields BIGINT
			,@offset INT = 20
			,@filterCnt INT = 0
		DECLARE @Pivot_Column NVARCHAR(MAX);
		DECLARE @Query NVARCHAR(MAX) = ''
			,@Query1 NVARCHAR(MAX) = ''
			,@Query2 NVARCHAR(max) = ''
		DECLARE @maxScore NUMERIC(18, 2) = isnull((
					SELECT (max(currentscore) * 100) / 99
					FROM lead_score_history(NOLOCK) e
					WHERE parentid = @ParentID
					), 0)
		DECLARE @hot INT
			,@warm INT
			,@cold INT

		SELECT @hot = hot
			,@warm = warm
			,@cold = cold
		FROM lead_cateogy_thresholds(NOLOCK)
		WHERE parentid = @ParentID

		IF @hot IS NULL
		BEGIN
			SELECT @hot = hot
				,@warm = warm
				,@cold = cold
			FROM lead_cateogy_thresholds(NOLOCK)
			WHERE parentid = 0
		END

		/*Select Pivot Column*/
		SELECT @Pivot_Column = COALESCE(@Pivot_Column + ',', '') + QUOTENAME([fieldname])
		FROM (
			SELECT DISTINCT [fieldname]
			FROM customfields
			WHERE [ParentID] = @ParentID
				AND [isActive] = 1
			) AS Tab;

		SET @NoCustomFields = (
				SELECT count(DISTINCT [fieldname])
				FROM customfields
				WHERE [ParentID] = @ParentID
					AND [isActive] = 1
				)

		DECLARE @Rcnt VARCHAR(100);

		IF (@ordstr = '')
		BEGIN
			SET @ordstr = ' CurrentScore desc, case when cast(followupdate as date) = cast(getdate() as date) then 0      
     when followupdate < getdate()  then 1      
     when followupdate > getdate() then 2      
     when followupdate is null then 3      
      end,followupdate '
		END

		IF (@txtSearch = '')
		BEGIN
			SET @txtSearch = N' (1=1) ';
			SET @offset = 0
		END;

		IF (@FilterText = '')
		BEGIN
			SET @FilterText = N' (1=1) ';
		END;

		IF (
				@FilterText = ' (1=1) '
				AND @txtSearch = ' (1=1) '
				)
		BEGIN
			PRINT 'Branch A'

			SET @Query += CAST(N'SELECT A.ID
			,A.LeadNo,A.PersonName,A.CompanyName,A.MobileNo,A.EmailID,A.City,A.State,A.Country,A.CountryCode,A.PinCode, A.ResidentialAddress, A.OfficeAddress, isnull(A.SourceName,''Unknown'') SourceName, A.MediumName,A.CampaignName,A.InitialRemarks, A.ParentID, A.FollowupBy,format(A.FollowupDate,''dd-MMM-yyyy HH:mm:ss'') as FollowupDate, format(A.FollowupCreatedDate,''dd-MMM-yyyy HH:mm:ss'') as FollowupCreatedDate, format(A.CreatedOn1,''dd-MMM-yyyy HH:mm:ss'') as CreatedOn1New, format(A.CreatedOn1,''dd-MMM-yyyy HH:mm:ss'') as CreatedOn1 , A.AssignedTo, A.Remarks, CASE WHEN ISNULL(A.FollowupStatus, '''') <> '''' THEN '' <p><b>Follow Up Status:&nbsp;&nbsp;</b>'' + CAST(ISNULL(A.FollowupStatus, '''') AS VARCHAR(50))  + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.FollowupDate, '''') <> '''' THEN '' <p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST(A.FollowupDate AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.Products, '''') <> '''' THEN ''<p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST(A.Products AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.AmountPaid,0) <> 0 THEN ''<p><b>Amount Paid:&nbsp;&nbsp;</b>'' + CAST(CAST(ISNULL(A.AmountPaid, 0) AS DECIMAL(18, 0)) AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.Remarks, '''') <> '''' THEN ''<p><b>Remarks:&nbsp;&nbsp;</b>'' + ISNULL(A.Remarks, '''') + ''</p>'' ELSE '''' END AS FollowUp,A.MobileNo1, A.MobileNo2, A.MobileNo3, A.EmailID3, A.EmailID1, A.EmailID2, A.FollowupStatus, A.assigneduser,A.assignedUserloginOnly ,A.img_ext, A.WhereAddress, A.Tags, isnull(A.Products, '''') as Products, A.CurrentScore, A.Profit_Loss, A.ThresholdColor, RowNumber1, rc1, A.User_Login, A.LastFollowupCreatedByName, format(A.LastFollowupedOn,''dd-MMM-yyyy HH:mm:ss'') as LastFollowupedOn, A.WhatsAppNoColName,A.CreatedBy, cast(A.ModifiedOn as datetime) as ModifiedOn, A.ModifiedBy,CAST(CAST(ISNULL(A.AmountPaid, 0) AS DECIMAL(18, 0)) AS VARCHAR(50)) as AmountPaid  INTO #temp1 FROM ( select ROW_NUMBER() OVER(ORDER BY ' + @StrPredefinedOrderBy + 
					N'   S.ID DESC) AS RowNumber1, count(*) OVER(ORDER BY S.ParentID) AS rc1, * From ( select * From 
					( SELECT UL.ID
					, UL.LeadNo, UL.PersonName, UL.img_ext, UL.WhereAddress, isnull(tg.Tags, '''') Tags, UL.CompanyName, UL.CreatedOn AS CreatedOn1,  CASE WHEN ISNULL(UL.CountryCode, '''') <> '''' and trim(ISNULL(UL.MobileNo, '''')) <> ''''  THEN TRIM(ISNULL(UL.Countrycode, '''')) + '' '' + TRIM(ISNULL(UL.MobileNo, ''''))  ELSE '''' END +  CASE WHEN trim(ISNULL(UL.Mobileno1, '''')) <> '''' THEN '', ...'' ELSE '''' END AS MobileNo, CASE WHEN ISNULL(UL.Emailid, '''') <> '''' THEN UL.Emailid ELSE '''' END +  CASE WHEN ISNULL(UL.EmailID1, '''') <> '''' THEN '', '' ELSE '''' END +  CASE WHEN ISNULL(UL.EmailID2, '''') <> '''' THEN '', '' ELSE '''' END AS EmailID, UL.City, UL.State, UL.Country, UL.CountryCode, UL.PinCode, UL.ResidentialAddress, UL.OfficeAddress, UL.AssignedTo, USS.Name AS SourceName, UMS.Name AS MediumName, UCS.Name AS CampaignName, UL.InitialRemarks, UL.ParentID,FUS.FollowupStatus, UL.FollowupDate, UL.Remarks, ISNULL(UL.AmountPaid, 0) AS AmountPaid, UL.CreatedOn AS FollowupCreatedDate, UL.CreatedBy, UL.ModifiedOn, UL.ModifiedBy,ISNULL(UD2.User_Login,'''') as FollowupBy, trim(UL.MobileNo) AS MobileNo3, trim(UL.MobileNo1) as MobileNo1, trim(UL.MobileNo2) as MobileNo2, UL.EmailID AS EmailID3, UL.EmailID1, UL.EmailID2, (  select isnull((select STRING_AGG(isnull(ProductName,''''),'', '') from openjson(ul.productsJson)
	               with(ProductName nvarchar(max) ''$.ProductName'' )
			       where isnull(ul.productsJson,'''') != '''') , '''') ) AS Products, UD.User_Login + '' ('' + Ud.FName +  '' '' + Ud.LName + '')'' AS assigneduser, UD.User_Login as assignedUserloginOnly , Profit_Loss=case when LS.ScoreAdded > 0 then ''Green_Up'' when LS.ScoreAdded < 0 then ''Red_Down'' else '''' end, CurrentScore=cast(isnull((LS.currentscore/nullif(' + cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int) , ThresholdColor=case when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int)>' + cast(@warm AS NVARCHAR(max)) + N' then ''Hot'' when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int) between ' + cast(@cold AS NVARCHAR(max)) + N' and ' + cast(@warm AS NVARCHAR(max)) + N' then ''Warm'' else ''Cold'' end , UD1.User_Login , ISNULL(UD2.User_Login, '''') as LastFollowupCreatedByName, ul.LastFollowupCreatedOn as LastFollowupedOn, UL.WhatsAppNoColName  ' AS NVARCHAR(max))
		
			SELECT @Query += cast(N' FROM UserLeads AS UL(NOLOCK) left JOIN UserSourceSettings AS USS(NOLOCK)
	 ON UL.SourceName = USS.SourceID --outer apply dbo.funcToGetScoredetails(ul.id) f
	 left join lead_score_history_latest(nolock) LS 
	ON UL.ID=LS.LeadId LEFT JOIN UserMediumSettings AS UMS(NOLOCK)
	ON UL.MediumName = UMS.MediumID LEFT JOIN UserCampaignSettings AS UCS(NOLOCK)
	ON UL.CampaignName = UCS.CampaignID LEFT JOIN User_Detail AS UD(NOLOCK)
	ON UL.AssignedTo = UD.User_ID LEFT JOIN User_Detail AS UD1(NOLOCK)
	ON UL.CreatedBy = UD1.User_ID LEFT JOIN User_Detail AS UD2(NOLOCK)
	ON UL.LastFollowupCreatedBy = UD2.User_ID left join FollowUp_Status AS FUS(NOLOCK)
	ON UL.FollowUpStatus = FUS.id 
	--left join LeadPipelineMapping_latest(nolock) as lpm
	--on UL.ID = lpm.LeadID 
	 LEFT JOIN ( select STRING_AGG(Tag, '','') as Tags, etm.EntityID from TagMaster(nolock) tm inner join EntityTagMapping(nolock) etm on tm.id = etm.TagID and etm.entity = ''lead'' and tm.ParentID = ' + 
					Convert(VARCHAR(100), @ParentID) + N' where ISNULL(etm.EntityID, 0) > 0 group by etm.EntityID ) tg on tg.EntityID = UL.ID 
	WHERE UL.ParentID = ' + CAST(@ParentID AS NVARCHAR(MAX)) + N' AND UL.AssignedTo ' + CASE 
						WHEN @Userid = 0
							THEN N' = UL.AssignedTo '
						WHEN @Userid > 0 /*and isnull(@TeamCode,'') != ''*/
							THEN N' in (' + isnull(@UserIdTeamLst, '') + ')'
						ELSE N' = ' + CAST(@Userid AS NVARCHAR(MAX))
						END + N'   
	and 1= case when isnull(' + cast(@notfollowedup AS NVARCHAR) + N',''0'')=''0'' then 1 when isnull(' + cast(@notfollowedup AS NVARCHAR) + N',''0'')=''1''     
	and abs(datediff(mi,ul.createdon,ul.followupdate))<=2    
	--and ul.enquirysource not between 12 and 15 and ul.enquirysource<>22      
	and ul.ModifiedOn is null  then 1 else 0 end' + '    
	) T       
	) S       
	) AS A ' --as nvarchar(max))
	+ ' Where A.RowNumber1 BETWEEN ' + CONVERT(NVARCHAR(max), @srno) + N' AND ' + CONVERT(NVARCHAR(max), @enno + @offset) AS NVARCHAR(MAX));;
			
		END
		ELSE
		BEGIN
			PRINT 'Branch B'

			SET @Query += CAST(N'SELECT A.ID, A.LeadNo, A.PersonName, A.CompanyName, A.MobileNo, A.EmailID, A.City, A.State, A.Country, A.CountryCode, A.PinCode, A.ResidentialAddress, A.OfficeAddress,isnull(A.SourceName,''Unknown'') SourceName, A.MediumName, A.CampaignName, A.InitialRemarks, A.ParentID, A.FollowupBy, format(A.FollowupDate,''dd-MMM-yyyy HH:mm:ss'') as FollowupDate,format(A.FollowupCreatedDate,''dd-MMM-yyyy HH:mm:ss'') as FollowupCreatedDate,format(A.CreatedOn1,''dd-MMM-yyyy HH:mm:ss'') as CreatedOn1New,format(A.CreatedOn1,''dd-MMM-yyyy HH:mm:ss'') as CreatedOn1, A.AssignedTo,A.Remarks,CASE WHEN ISNULL(A.FollowupStatus,'''') <> '''' THEN '' <p><b>Follow Up Status:&nbsp;&nbsp;</b>'' + CAST(ISNULL(A.FollowupStatus,'''') AS VARCHAR(50))  + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.FollowupDate,'''') <> '''' THEN '' <p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST(A.FollowupDate AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.Products,'''') <> '''' THEN ''<p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST(A.Products AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.AmountPaid,0) <> 0 THEN ''<p><b>Amount Paid:&nbsp;&nbsp;</b>'' + CAST(CAST(ISNULL(A.AmountPaid, 0) AS DECIMAL(18, 0)) AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL (A.Remarks, '''') <> '''' THEN ''<p><b>Remarks:&nbsp;&nbsp;</b>'' + ISNULL(A.Remarks,'''') + ''</p>'' ELSE '''' END AS FollowUp, A.MobileNo1,A.MobileNo2,A.MobileNo3,A.EmailID3,A.EmailID1,A.EmailID2,A.FollowupStatus,A.assigneduser,A.assignedUserloginOnly,A.img_ext, A.WhereAddress, A.Tags, isnull(A.Products, '''') as Products, A.CurrentScore, A.Profit_Loss, A.ThresholdColor,RowNumber1,rc1 ,A.User_Login, A.LastFollowupCreatedByName, format(A.LastFollowupedOn,''dd-MMM-yyyy HH:mm:ss'') as LastFollowupedOn,A.WhatsAppNoColName, A.CreatedBy, cast(A.ModifiedOn as datetime) as ModifiedOn, A.ModifiedBy,CAST(CAST(ISNULL(A.AmountPaid, 0) AS DECIMAL(18, 0)) AS VARCHAR(50)) as AmountPaid INTO #temp1 FROM ( select ROW_NUMBER() OVER(ORDER BY ' + @StrPredefinedOrderBy + N'   S.ID DESC) AS RowNumber1, count(*) OVER(ORDER BY S.ParentID) AS rc1,* From ( select * From ( SELECT UL.ID,UL.LeadNo,UL.PersonName,UL.img_ext,UL.CompanyName,UL.CreatedOn AS CreatedOn1, CASE WHEN ISNULL(UL.CountryCode,'''') <> '''' and trim(ISNULL(UL.MobileNo,'''')) <> ''''  THEN TRIM(ISNULL(UL.Countrycode,'''')) + '' '' + TRIM(ISNULL(UL.MobileNo,''''))  ELSE '''' END +  CASE WHEN trim(ISNULL(UL.Mobileno1,'''')) <> '''' THEN '', ...'' ELSE '''' END AS MobileNo, CASE WHEN ISNULL(UL.Emailid,'''') <> '''' THEN UL.Emailid ELSE '''' END + CASE WHEN ISNULL(UL.EmailID1,'''') <> '''' THEN '', '' ELSE '''' END + CASE WHEN ISNULL(UL.EmailID2,'''') <> '''' THEN '', '' ELSE '''' END AS EmailID, UL.City, UL.State, UL.Country, UL.CountryCode, UL.PinCode, UL.ResidentialAddress, UL.OfficeAddress, UL.AssignedTo, USS.Name AS SourceName, UMS.Name AS MediumName, UCS.Name AS CampaignName, UL.InitialRemarks, UL.ParentID,FUS.FollowupStatus, UL.FollowupDate, UL.Remarks, ISNULL(UL.AmountPaid, 0) AS AmountPaid, UL.CreatedOn AS FollowupCreatedDate, UL.CreatedBy, UL.ModifiedOn, UL.ModifiedBy, ISNULL(UD2.User_Login,'''') as FollowupBy, trim(UL.MobileNo) AS MobileNo3, trim(UL.MobileNo1) as MobileNo1, trim(UL.MobileNo2) as MobileNo2, UL.EmailID AS EmailID3, UL.EmailID1, UL.EmailID2, UL.WhereAddress, isnull(tg.Tags, '''') Tags, ( select isnull((select STRING_AGG(isnull(ProductName,''''),'', '') from openjson(ul.productsjson) with(ProductName nvarchar(max) ''$.ProductName'' ) where isnull(ul.productsjson,'''') != '''') , '''')) AS Products,UD.User_Login + '' ('' + Ud.FName +  '' '' + Ud.LName + '')'' AS assigneduser, UD.User_Login as assignedUserloginOnly, Profit_Loss=case when LS.ScoreAdded > 0 then ''Green_Up'' when LS.ScoreAdded < 0 then ''Red_Down'' else '''' end,CurrentScore=cast(isnull((LS.currentscore/nullif('+ cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int), ThresholdColor=case when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int)>' + cast(@warm AS NVARCHAR(max)) + N' then ''Hot'' when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int) between ' + cast(@cold AS NVARCHAR(max)) + N'  and ' + cast(@warm AS NVARCHAR(max)) + N' then ''Warm'' else ''Cold'' end, UD1.User_Login ' AS NVARCHAR(max)) + N', isnull(UD2.User_Login, '''') as LastFollowupCreatedByName, ul.LastFollowupCreatedOn as LastFollowupedOn, UL.WhatsAppNoColName  '

			SELECT @Query += cast(N' FROM UserLeads AS UL(NOLOCK) left JOIN UserSourceSettings AS USS(NOLOCK)
	 ON UL.SourceName = USS.SourceID --outer apply dbo.funcToGetScoredetails(ul.id) f
	 left join lead_score_history_latest(nolock) LS ON UL.ID=LS.LeadId LEFT JOIN UserMediumSettings AS UMS(NOLOCK) ON UL.MediumName = UMS.MediumID LEFT JOIN UserCampaignSettings AS UCS(NOLOCK) ON UL.CampaignName = UCS.CampaignID LEFT JOIN User_Detail AS UD(NOLOCK) ON UL.AssignedTo = UD.User_ID LEFT JOIN User_Detail AS UD1(NOLOCK) ON UL.CreatedBy = UD1.User_ID LEFT JOIN User_Detail AS UD2(NOLOCK) ON UL.LastFollowupCreatedBy = UD2.User_ID left join FollowUp_Status AS FUS(NOLOCK) ON UL.FollowUpStatus = FUS.id
	--left join LeadPipelineMapping_latest(nolock) as lpm
	--on UL.ID = lpm.LeadID
	 LEFT JOIN ( select STRING_AGG(Tag, '','') as Tags, etm.EntityID from TagMaster(nolock) tm inner join EntityTagMapping(nolock) etm on tm.id = etm.TagID and etm.entity = ''lead'' and tm.ParentID = ' + Convert(VARCHAR(100), @ParentID) + ' where ISNULL(etm.EntityID, 0) > 0 group by etm.EntityID ) tg on tg.EntityID = UL.ID   
	WHERE UL.ParentID = ' + CAST(@ParentID AS NVARCHAR(MAX)) + N' AND UL.AssignedTo ' + CASE 
						WHEN @Userid = 0
							THEN N' = UL.AssignedTo '
						WHEN @Userid > 0 /*and isnull(@TeamCode,'') != ''*/
							THEN ' in (' + isnull(@UserIdTeamLst, '') + ')'
						ELSE ' = ' + CAST(@Userid AS NVARCHAR(MAX))
						END + ' and 1= case when isnull(' + cast(@notfollowedup AS NVARCHAR) + ',''0'')=''0'' then 1 when isnull(' + cast(@notfollowedup AS NVARCHAR) + ',''0'')=''1'' and abs(datediff(mi,ul.createdon,ul.followupdate))<=2
	--and ul.enquirysource not between 12 and 15 and ul.enquirysource<>22
	and ul.ModifiedOn is null  then 1 else 0 end' + ' ) T Where ' + @FilterText + ' ) S ) AS A 
                    Where ' 
                 + CASE 
						WHEN @txtSearch = ' (1=1) '
							THEN ' A.RowNumber1 BETWEEN ' + CONVERT(NVARCHAR(max), @srno) + N' AND ' + CONVERT(NVARCHAR(max), @enno)
						ELSE ' (1=1) '
						END 
						AS NVARCHAR(MAX));
		END

		PRINT cast(@Query AS VARCHAR(max))

		IF (@Pivot_Column IS NOT NULL)
		BEGIN
			PRINT 'Branch C'

			--IF(@FilterText = ' (1=1) ' and @txtSearch = ' (1=1) ')-- From Branch A 
			IF (@txtSearch = ' (1=1) ') -- From Branch A 
			BEGIN
				PRINT 'Branch CA'
				DECLARE @caQuery NVARCHAR(max) = CAST(N'; Insert into #Leadtemp (LeadId) Select id from ( Select *       
   From ( SELECT ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, User_Login, FollowupDate, FollowupCreatedDate as CreatedOn, CreatedOn1New, CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus, assigneduser,assignedUserloginOnly, Img_Ext, WhereAddress, Products, FollowupCreatedDate, FollowupBy, ' + @Pivot_Column + N', CurrentScore, Profit_Loss, ThresholdColor, ROW_NUMBER() OVER(ORDER BY ' + @StrPredefinedOrderBy + N' ' + @StrCustomOrderBy + '  [ID] DESC)  ' + ' AS [RowNumber1], rc1, LastFollowupCreatedByName, LastFollowupedOn, WhatsAppNoColName,CreatedBy, ModifiedOn, ModifiedBy, AmountPaid FROM
   (SELECT ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, FollowupBy, FollowupDate, FollowupCreatedDate, CreatedOn1New, CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus, assigneduser,assignedUserloginOnly, img_ext, WhereAddress, Products, [fieldname] , fieldvalue, CurrentScore, Profit_Loss,ThresholdColor, RowNumber1, rc1 ,User_Login,LastFollowupCreatedByName, LastFollowupedOn, WhatsAppNoColName,CreatedBy, ModifiedOn, ModifiedBy, AmountPaid FROM (select L.ID,  L.LeadNo, L.PersonName, L.CompanyName,L.MobileNo,L.EmailID, L.City, L.State, L.Country, L.CountryCode, L.PinCode, L.ResidentialAddress, L.OfficeAddress, L.SourceName, L.MediumName, L.CampaignName, L.InitialRemarks, L.ParentID, L.FollowupBy, L.FollowupDate, L.FollowupCreatedDate, L.CreatedOn1New, L.CreatedOn1, L.AssignedTo, L.Remarks, L.FollowUp, L.MobileNo1, L.MobileNo2, L.MobileNo3, L.EmailID3, L.EmailID1, L.EmailID2, L.FollowupStatus,  L.assigneduser,L.assignedUserloginOnly, L.Img_Ext, L.WhereAddress, L.Products, y.fieldname, x.fieldvalue, L.CurrentScore, L.Profit_Loss, L.ThresholdColor, L.RowNumber1, L.rc1, L.User_Login,L.LastFollowupCreatedByName, L.LastFollowupedOn, L.WhatsAppNoColName, L.CreatedBy, L.ModifiedOn, L.ModifiedBy, L.AmountPaid  From #temp1 L left join customfieldLeadvalue(nolock) x ON L.ID = x.LeadID left join customfields(nolock) y ON x.fieldID=y.field_ID AND y.[ParentID] = ' 
						+ CAST(@Parentid AS NVARCHAR(MAX)) + N' AND y.[isActive] = 1 )q )Tab1
  PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + N')) AS Tab2 Where ' + @txtSearch + ' ) T1
   ) T2 ' 
        --'Where T2.RowNumber1 BETWEEN ' + CONVERT(NVARCHAR(max), @srno) + N' AND ' + CONVERT(NVARCHAR(max), @enno) 
      + N' ORDER BY ' + @ordstr AS NVARCHAR(MAX));

				--PRINT cast(@caQuery as varchar(max))

				SELECT @Query = @Query + @caQuery
			END
			ELSE -- From Branch B      
			BEGIN
				PRINT 'Branch CB'
	SELECT @filterCnt = count(*)
				FROM dbo.fn_Split(@txtSearch, ' ) ')
				select @filterCnt = 1

				SELECT @Query1 += CAST(N'; select * into #Temp2 From (select [x].LeadID, [y].[fieldname], [x].[fieldvalue] from customfieldLeadvalue(nolock) x inner join customfields(nolock) y ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + N' AND y.[isActive] = 1 ) T1 PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + N')) AS Tab2 Where ' + @txtSearch AS NVARCHAR(MAX));

				SELECT @Query1 += CAST(N'; Insert into #Leadtemp (LeadId) Select id from ( Select ROW_NUMBER() OVER(ORDER BY ' + @StrPredefinedOrderBy + N' ' + @StrCustomOrderBy + '  [ID] DESC)  ' + ' AS [RowNumber1], count(*) OVER(ORDER BY [ParentID]) AS [rc1], * From ( SELECT ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, User_Login, FollowupDate, FollowupCreatedDate as CreatedOn, CreatedOn1New, CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus, assigneduser,assignedUserloginOnly, Img_Ext, WhereAddress, Products, FollowupCreatedDate, FollowupBy, ' + @Pivot_Column + 
						N', CurrentScore, Profit_Loss, ThresholdColor, LastFollowupCreatedByName, LastFollowupedOn, WhatsAppNoColName, CreatedBy, ModifiedOn, ModifiedBy, AmountPaid 
				   From #Temp2 A inner join #temp1 L       
					ON A.LeadId = L.ID  ) T1       
				  ) T2  
				    Where  T2.RowNumber1 BETWEEN ' + CONVERT(NVARCHAR(max), @srno) + N' AND ' + CONVERT(NVARCHAR(max), @enno) 
				   + N' ORDER BY ' + @ordstr AS NVARCHAR(MAX)) ;


				--PRINT cast(@Query1 as varchar(max))

				SELECT @Query = @Query + @Query1
			END
		END
		ELSE
		BEGIN
			PRINT 'Branch D'

			SET @Query2 += CAST(N';Insert into #Leadtemp (LeadId) Select ID  
  From #temp1      
  Where RowNumber1 BETWEEN ' + CONVERT(NVARCHAR(max), @srno) + N' AND ' + CONVERT(NVARCHAR(max), @enno) + N' ORDER BY ' + @ordstr  AS NVARCHAR(MAX));

			PRINT cast(@Query2 as varchar(max))

			SELECT @Query = @Query + @Query2
		END

		--print '@FinalQuery:- ' + cast(@Query as varchar(max))      
		EXEC sp_executesql @Query;
    
	INSERT INTO Tbl_MassOperationSummary (MassOperationName, UserID, Parentid, CreatedDate, IsProcessed, ProcedureName, FilterCriteria, EntityType)
			Values (@MassOperationName, @actUserID, @parentid, getdate(), 0, 'Usp_MassOperationLeadID', @FilterText, 'Lead')
	Declare @BatchID Bigint  = Scope_Identity()

	INSERT INTO Tbl_MassOperationDetails (SummaryId,EntityID)
	Select @BatchID, LeadID from #Leadtemp 
	
	Select @BatchID BatchId
		IF OBJECT_ID('tempdb.dbo.#temp1', 'U') IS NOT NULL
		BEGIN
			DROP TABLE #temp1;
		END;

		IF OBJECT_ID('tempdb.dbo.#temp2', 'U') IS NOT NULL
		BEGIN
			DROP TABLE #temp2;
		END;
	 

	 -- for temp display
	  --Select  LeadID from #Leadtemp 
	  drop table if exists #Leadtemp


	END
END



GO

/* ============================================================
   Procedure: [dbo].[Usp_MassOperationLeadID_withoutput]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_MassOperationLeadID_withoutput] (
	@txtSearch NVARCHAR(max)
	,@Userid INT = 0
	,@FilterText NVARCHAR(MAX) = ''
	,@srno NVARCHAR(100)
	,@enno NVARCHAR(100)
	,@ordstr NVARCHAR(Max) = ''
	,@notfollowedup INT = 0
	,@MassOperationName nvarchar(100)=''
	,@BatchId bigint output
	)
AS
BEGIN

 --  declare  @txtSearch NVARCHAR(max) = N''
	--,@ParentID BIGINT = 40834
	--,@Userid INT = 40834
	--,@FilterText NVARCHAR(MAX) = N' (personname like ''%a%'' ) '
	--,@srno NVARCHAR(100) = N'1'
	--,@enno NVARCHAR(100) = N'20'
	--,@ordstr NVARCHAR(Max) = N''
	--,@notfollowedup INT = 0

	
	IF OBJECT_ID('tempdb.dbo.#temp1', 'U') IS NOT NULL
	BEGIN
		DROP TABLE #temp1;
	END;

	IF OBJECT_ID('tempdb.dbo.#temp2', 'U') IS NOT NULL
	BEGIN
		DROP TABLE #temp2;
	END;
	drop table if exists #Leadtemp 
	Create Table #Leadtemp (LeadID BIGINT)
	--IF OBJECT_ID('tempdb.dbo.#TableData2', 'U') IS NOT NULL BEGIN DROP TABLE #TableData2; END;                       
	DECLARE @Str NVARCHAR(200) = @ordstr;--' personname desc '
	DECLARE @ColumnName NVARCHAR(200) = ''
	DECLARE @StrPredefinedOrderBy NVARCHAR(500) = ''
	DECLARE @StrCustomOrderBy NVARCHAR(500) = ''
	DECLARE @actUserID BIGINT = @Userid
	DECLARE @Parentid BIGINT  =(Select ParentId from User_Detail (NOLOCK) where User_ID=@Userid)

    --select @enno=count(1) from userleads(nolock) where parentid=@parentid

	IF (rtrim(ltrim(@Str)) <> '')
	BEGIN
		SET @Str = ltrim(RTRIM(@Str))

		--select @Str
		SELECT TOP 1 @ColumnName = value
		FROM string_split(@Str, ' ')

		--select @ColumnName 
		IF (
				EXISTS (
					SELECT 1
					FROM INFORMATION_SCHEMA.COLUMNS
					WHERE table_name = 'UserLeads'
						AND column_name = rtrim(ltrim(@ColumnName))
					)
				)
		BEGIN
			--set @StrPredefinedOrderBy = N' order by ' +  @Str;
			SET @StrPredefinedOrderBy = N' ' + @Str + ' , ';
			SET @StrCustomOrderBy = '';
		END
		ELSE
		BEGIN
			DECLARE @FullDataType NVARCHAR(200) = 'nvarchar(max)'

			SELECT TOP 1 @FullDataType = CASE 
					WHEN ISNULL(datatype, 'v') = 'd'
						THEN 'date'
					WHEN ISNULL(datatype, 'v') = 'f'
						THEN 'bigint'
					WHEN ISNULL(datatype, 'v') = 'v'
						THEN 'nvarchar(max)'
					ELSE 'nvarchar(max)'
					END
			FROM customfields WITH (NOLOCK)
			WHERE ParentID = @Parentid
				AND fieldname = rtrim(ltrim(@ColumnName))

			DECLARE @CustomStrExp NVARCHAR(200) = '';

			IF (
					EXISTS (
						SELECT value
						FROM string_split(@Str, ' ')
						WHERE rtrim(ltrim(value)) = 'asc'
						)
					)
			BEGIN
				SET @CustomStrExp = N' ' + 'CAST(' + @ColumnName + ' as  ' + @FullDataType + ')' + '  asc '
			END
			ELSE
			BEGIN
				SET @CustomStrExp = N' ' + 'CAST(' + @ColumnName + ' as  ' + @FullDataType + ')' + '  desc '
			END

			SET @StrPredefinedOrderBy = ''
			--set @StrCustomOrderBy = N' order by ' +  @Str;  
			SET @StrCustomOrderBy = N' ' + @CustomStrExp + ' , ';
		END
				--select @StrPredefinedOrderBy
				--select @StrCustomOrderBy
	END

	DECLARE @IsAdmin BIT = 0
	DECLARE @TimeZoneName NVARCHAR(255) = isnull((
				SELECT TimeZone
				FROM User_Detail(NOLOCK)
				WHERE User_ID = @Userid
				), 'India Standard Time')
	DECLARE @UserIDTeam BIGINT = @Userid;
	DECLARE @tbluser TABLE (
		User_ID BIGINT
		,Name VARCHAR(100)
		,IMAGE VARCHAR(100)
		)

	SELECT @IsAdmin = IsAdmin
	FROM User_Detail(NOLOCK)
	WHERE User_ID = @Userid

	IF (@IsAdmin = 1)
	BEGIN
		SET @Userid = 0;

		INSERT INTO @tbluser
		EXEC Use_GetUserDetails @ParentId
	END
	ELSE
	BEGIN
		INSERT INTO @tbluser
		EXEC Use_GetUserDetails @UserId
	END

	DECLARE @TeamCode VARCHAR(10) = ''
	DECLARE @ScopeCode VARCHAR(10) = ''
	DECLARE @UserIdTeamLst VARCHAR(4000) = ''
	DECLARE @HierarchyJSON VARCHAR(Max) = ''

	SELECT @UserIdTeamLst = isnull(STRING_AGG(User_ID, ','), '')
	FROM @tbluser

	PRINT '@UserIdTeamLst: ' + @UserIdTeamLst
             
	BEGIN
		                              
		DECLARE @NoCustomFields BIGINT
			,@offset INT = 20
			,@filterCnt INT = 0
		DECLARE @Pivot_Column NVARCHAR(MAX);
		DECLARE @Query NVARCHAR(MAX) = ''
			,@Query1 NVARCHAR(MAX) = ''
			,@Query2 NVARCHAR(max) = ''
		DECLARE @maxScore NUMERIC(18, 2) = isnull((
					SELECT (max(currentscore) * 100) / 99
					FROM lead_score_history(NOLOCK) e
					WHERE parentid = @ParentID
					), 0)
		DECLARE @hot INT
			,@warm INT
			,@cold INT

		SELECT @hot = hot
			,@warm = warm
			,@cold = cold
		FROM lead_cateogy_thresholds(NOLOCK)
		WHERE parentid = @ParentID

		IF @hot IS NULL
		BEGIN
			SELECT @hot = hot
				,@warm = warm
				,@cold = cold
			FROM lead_cateogy_thresholds(NOLOCK)
			WHERE parentid = 0
		END

		/*Select Pivot Column*/
		SELECT @Pivot_Column = COALESCE(@Pivot_Column + ',', '') + QUOTENAME([fieldname])
		FROM (
			SELECT DISTINCT [fieldname]
			FROM customfields
			WHERE [ParentID] = @ParentID
				AND [isActive] = 1
			) AS Tab;

		SET @NoCustomFields = (
				SELECT count(DISTINCT [fieldname])
				FROM customfields
				WHERE [ParentID] = @ParentID
					AND [isActive] = 1
				)

		DECLARE @Rcnt VARCHAR(100);

		IF (@ordstr = '')
		BEGIN
			SET @ordstr = ' CurrentScore desc, case when cast(followupdate as date) = cast(getdate() as date) then 0      
     when followupdate < getdate()  then 1      
     when followupdate > getdate() then 2      
     when followupdate is null then 3      
      end,followupdate '
		END

		IF (@txtSearch = '')
		BEGIN
			SET @txtSearch = N' (1=1) ';
			SET @offset = 0
		END;

		IF (@FilterText = '')
		BEGIN
			SET @FilterText = N' (1=1) ';
		END;

		IF (
				@FilterText = ' (1=1) '
				AND @txtSearch = ' (1=1) '
				)
		BEGIN
			PRINT 'Branch A'

			SET @Query += CAST(N'SELECT A.ID
			,A.LeadNo,A.PersonName,A.CompanyName,A.MobileNo,A.EmailID,A.City,A.State,A.Country,A.CountryCode,A.PinCode, A.ResidentialAddress, A.OfficeAddress, isnull(A.SourceName,''Unknown'') SourceName, A.MediumName,A.CampaignName,A.InitialRemarks, A.ParentID, A.FollowupBy,format(A.FollowupDate,''dd-MMM-yyyy HH:mm:ss'') as FollowupDate, format(A.FollowupCreatedDate,''dd-MMM-yyyy HH:mm:ss'') as FollowupCreatedDate, format(A.CreatedOn1,''dd-MMM-yyyy HH:mm:ss'') as CreatedOn1New, format(A.CreatedOn1,''dd-MMM-yyyy HH:mm:ss'') as CreatedOn1 , A.AssignedTo, A.Remarks, CASE WHEN ISNULL(A.FollowupStatus, '''') <> '''' THEN '' <p><b>Follow Up Status:&nbsp;&nbsp;</b>'' + CAST(ISNULL(A.FollowupStatus, '''') AS VARCHAR(50))  + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.FollowupDate, '''') <> '''' THEN '' <p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST(A.FollowupDate AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.Products, '''') <> '''' THEN ''<p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST(A.Products AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.AmountPaid,0) <> 0 THEN ''<p><b>Amount Paid:&nbsp;&nbsp;</b>'' + CAST(CAST(ISNULL(A.AmountPaid, 0) AS DECIMAL(18, 0)) AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.Remarks, '''') <> '''' THEN ''<p><b>Remarks:&nbsp;&nbsp;</b>'' + ISNULL(A.Remarks, '''') + ''</p>'' ELSE '''' END AS FollowUp,A.MobileNo1, A.MobileNo2, A.MobileNo3, A.EmailID3, A.EmailID1, A.EmailID2, A.FollowupStatus, A.assigneduser,A.assignedUserloginOnly ,A.img_ext, A.WhereAddress, A.Tags, isnull(A.Products, '''') as Products, A.CurrentScore, A.Profit_Loss, A.ThresholdColor, RowNumber1, rc1, A.User_Login, A.LastFollowupCreatedByName, format(A.LastFollowupedOn,''dd-MMM-yyyy HH:mm:ss'') as LastFollowupedOn, A.WhatsAppNoColName,A.CreatedBy, cast(A.ModifiedOn as datetime) as ModifiedOn, A.ModifiedBy,CAST(CAST(ISNULL(A.AmountPaid, 0) AS DECIMAL(18, 0)) AS VARCHAR(50)) as AmountPaid  INTO #temp1 FROM ( select ROW_NUMBER() OVER(ORDER BY ' + @StrPredefinedOrderBy + 
					N'   S.ID DESC) AS RowNumber1, count(*) OVER(ORDER BY S.ParentID) AS rc1, * From ( select * From 
					( SELECT UL.ID
					, UL.LeadNo, UL.PersonName, UL.img_ext, UL.WhereAddress, isnull(tg.Tags, '''') Tags, UL.CompanyName, UL.CreatedOn AS CreatedOn1,  CASE WHEN ISNULL(UL.CountryCode, '''') <> '''' and trim(ISNULL(UL.MobileNo, '''')) <> ''''  THEN TRIM(ISNULL(UL.Countrycode, '''')) + '' '' + TRIM(ISNULL(UL.MobileNo, ''''))  ELSE '''' END +  CASE WHEN trim(ISNULL(UL.Mobileno1, '''')) <> '''' THEN '', ...'' ELSE '''' END AS MobileNo, CASE WHEN ISNULL(UL.Emailid, '''') <> '''' THEN UL.Emailid ELSE '''' END +  CASE WHEN ISNULL(UL.EmailID1, '''') <> '''' THEN '', '' ELSE '''' END +  CASE WHEN ISNULL(UL.EmailID2, '''') <> '''' THEN '', '' ELSE '''' END AS EmailID, UL.City, UL.State, UL.Country, UL.CountryCode, UL.PinCode, UL.ResidentialAddress, UL.OfficeAddress, UL.AssignedTo, USS.Name AS SourceName, UMS.Name AS MediumName, UCS.Name AS CampaignName, UL.InitialRemarks, UL.ParentID,FUS.FollowupStatus, UL.FollowupDate, UL.Remarks, ISNULL(UL.AmountPaid, 0) AS AmountPaid, UL.CreatedOn AS FollowupCreatedDate, UL.CreatedBy, UL.ModifiedOn, UL.ModifiedBy,ISNULL(UD2.User_Login,'''') as FollowupBy, trim(UL.MobileNo) AS MobileNo3, trim(UL.MobileNo1) as MobileNo1, trim(UL.MobileNo2) as MobileNo2, UL.EmailID AS EmailID3, UL.EmailID1, UL.EmailID2, (  select isnull((select STRING_AGG(isnull(ProductName,''''),'', '') from openjson(ul.productsJson)
	               with(ProductName nvarchar(max) ''$.ProductName'' )
			       where isnull(ul.productsJson,'''') != '''') , '''') ) AS Products, UD.User_Login + '' ('' + Ud.FName +  '' '' + Ud.LName + '')'' AS assigneduser, UD.User_Login as assignedUserloginOnly , Profit_Loss=case when LS.ScoreAdded > 0 then ''Green_Up'' when LS.ScoreAdded < 0 then ''Red_Down'' else '''' end, CurrentScore=cast(isnull((LS.currentscore/nullif(' + cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int) , ThresholdColor=case when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int)>' + cast(@warm AS NVARCHAR(max)) + N' then ''Hot'' when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int) between ' + cast(@cold AS NVARCHAR(max)) + N' and ' + cast(@warm AS NVARCHAR(max)) + N' then ''Warm'' else ''Cold'' end , UD1.User_Login , ISNULL(UD2.User_Login, '''') as LastFollowupCreatedByName, ul.LastFollowupCreatedOn as LastFollowupedOn, UL.WhatsAppNoColName  ' AS NVARCHAR(max))
		
			SELECT @Query += cast(N' FROM UserLeads AS UL(NOLOCK) left JOIN UserSourceSettings AS USS(NOLOCK)
	 ON UL.SourceName = USS.SourceID --outer apply dbo.funcToGetScoredetails(ul.id) f
	 left join lead_score_history_latest(nolock) LS 
	ON UL.ID=LS.LeadId LEFT JOIN UserMediumSettings AS UMS(NOLOCK)
	ON UL.MediumName = UMS.MediumID LEFT JOIN UserCampaignSettings AS UCS(NOLOCK)
	ON UL.CampaignName = UCS.CampaignID LEFT JOIN User_Detail AS UD(NOLOCK)
	ON UL.AssignedTo = UD.User_ID LEFT JOIN User_Detail AS UD1(NOLOCK)
	ON UL.CreatedBy = UD1.User_ID LEFT JOIN User_Detail AS UD2(NOLOCK)
	ON UL.LastFollowupCreatedBy = UD2.User_ID left join FollowUp_Status AS FUS(NOLOCK)
	ON UL.FollowUpStatus = FUS.id 
	--left join LeadPipelineMapping_latest(nolock) as lpm
	--on UL.ID = lpm.LeadID 
	 LEFT JOIN ( select STRING_AGG(Tag, '','') as Tags, etm.EntityID from TagMaster(nolock) tm inner join EntityTagMapping(nolock) etm on tm.id = etm.TagID and etm.entity = ''lead'' and tm.ParentID = ' + 
					Convert(VARCHAR(100), @ParentID) + N' where ISNULL(etm.EntityID, 0) > 0 group by etm.EntityID ) tg on tg.EntityID = UL.ID 
	WHERE UL.ParentID = ' + CAST(@ParentID AS NVARCHAR(MAX)) + N' AND UL.AssignedTo ' + CASE 
						WHEN @Userid = 0
							THEN N' = UL.AssignedTo '
						WHEN @Userid > 0 /*and isnull(@TeamCode,'') != ''*/
							THEN N' in (' + isnull(@UserIdTeamLst, '') + ')'
						ELSE N' = ' + CAST(@Userid AS NVARCHAR(MAX))
						END + N'   
	and 1= case when isnull(' + cast(@notfollowedup AS NVARCHAR) + N',''0'')=''0'' then 1 when isnull(' + cast(@notfollowedup AS NVARCHAR) + N',''0'')=''1''     
	and abs(datediff(mi,ul.createdon,ul.followupdate))<=2    
	--and ul.enquirysource not between 12 and 15 and ul.enquirysource<>22      
	and ul.ModifiedOn is null  then 1 else 0 end' + '    
	) T       
	) S       
	) AS A ' --as nvarchar(max))
	+ ' Where A.RowNumber1 BETWEEN ' + CONVERT(NVARCHAR(max), @srno) + N' AND ' + CONVERT(NVARCHAR(max), @enno + @offset) AS NVARCHAR(MAX));;
			
		END
		ELSE
		BEGIN
			PRINT 'Branch B'

			SET @Query += CAST(N'SELECT A.ID, A.LeadNo, A.PersonName, A.CompanyName, A.MobileNo, A.EmailID, A.City, A.State, A.Country, A.CountryCode, A.PinCode, A.ResidentialAddress, A.OfficeAddress,isnull(A.SourceName,''Unknown'') SourceName, A.MediumName, A.CampaignName, A.InitialRemarks, A.ParentID, A.FollowupBy, format(A.FollowupDate,''dd-MMM-yyyy HH:mm:ss'') as FollowupDate,format(A.FollowupCreatedDate,''dd-MMM-yyyy HH:mm:ss'') as FollowupCreatedDate,format(A.CreatedOn1,''dd-MMM-yyyy HH:mm:ss'') as CreatedOn1New,format(A.CreatedOn1,''dd-MMM-yyyy HH:mm:ss'') as CreatedOn1, A.AssignedTo,A.Remarks,CASE WHEN ISNULL(A.FollowupStatus,'''') <> '''' THEN '' <p><b>Follow Up Status:&nbsp;&nbsp;</b>'' + CAST(ISNULL(A.FollowupStatus,'''') AS VARCHAR(50))  + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.FollowupDate,'''') <> '''' THEN '' <p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST(A.FollowupDate AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.Products,'''') <> '''' THEN ''<p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST(A.Products AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.AmountPaid,0) <> 0 THEN ''<p><b>Amount Paid:&nbsp;&nbsp;</b>'' + CAST(CAST(ISNULL(A.AmountPaid, 0) AS DECIMAL(18, 0)) AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL (A.Remarks, '''') <> '''' THEN ''<p><b>Remarks:&nbsp;&nbsp;</b>'' + ISNULL(A.Remarks,'''') + ''</p>'' ELSE '''' END AS FollowUp, A.MobileNo1,A.MobileNo2,A.MobileNo3,A.EmailID3,A.EmailID1,A.EmailID2,A.FollowupStatus,A.assigneduser,A.assignedUserloginOnly,A.img_ext, A.WhereAddress, A.Tags, isnull(A.Products, '''') as Products, A.CurrentScore, A.Profit_Loss, A.ThresholdColor,RowNumber1,rc1 ,A.User_Login, A.LastFollowupCreatedByName, format(A.LastFollowupedOn,''dd-MMM-yyyy HH:mm:ss'') as LastFollowupedOn,A.WhatsAppNoColName, A.CreatedBy, cast(A.ModifiedOn as datetime) as ModifiedOn, A.ModifiedBy,CAST(CAST(ISNULL(A.AmountPaid, 0) AS DECIMAL(18, 0)) AS VARCHAR(50)) as AmountPaid INTO #temp1 FROM ( select ROW_NUMBER() OVER(ORDER BY ' + @StrPredefinedOrderBy + N'   S.ID DESC) AS RowNumber1, count(*) OVER(ORDER BY S.ParentID) AS rc1,* From ( select * From ( SELECT UL.ID,UL.LeadNo,UL.PersonName,UL.img_ext,UL.CompanyName,UL.CreatedOn AS CreatedOn1, CASE WHEN ISNULL(UL.CountryCode,'''') <> '''' and trim(ISNULL(UL.MobileNo,'''')) <> ''''  THEN TRIM(ISNULL(UL.Countrycode,'''')) + '' '' + TRIM(ISNULL(UL.MobileNo,''''))  ELSE '''' END +  CASE WHEN trim(ISNULL(UL.Mobileno1,'''')) <> '''' THEN '', ...'' ELSE '''' END AS MobileNo, CASE WHEN ISNULL(UL.Emailid,'''') <> '''' THEN UL.Emailid ELSE '''' END + CASE WHEN ISNULL(UL.EmailID1,'''') <> '''' THEN '', '' ELSE '''' END + CASE WHEN ISNULL(UL.EmailID2,'''') <> '''' THEN '', '' ELSE '''' END AS EmailID, UL.City, UL.State, UL.Country, UL.CountryCode, UL.PinCode, UL.ResidentialAddress, UL.OfficeAddress, UL.AssignedTo, USS.Name AS SourceName, UMS.Name AS MediumName, UCS.Name AS CampaignName, UL.InitialRemarks, UL.ParentID,FUS.FollowupStatus, UL.FollowupDate, UL.Remarks, ISNULL(UL.AmountPaid, 0) AS AmountPaid, UL.CreatedOn AS FollowupCreatedDate, UL.CreatedBy, UL.ModifiedOn, UL.ModifiedBy, ISNULL(UD2.User_Login,'''') as FollowupBy, trim(UL.MobileNo) AS MobileNo3, trim(UL.MobileNo1) as MobileNo1, trim(UL.MobileNo2) as MobileNo2, UL.EmailID AS EmailID3, UL.EmailID1, UL.EmailID2, UL.WhereAddress, isnull(tg.Tags, '''') Tags, ( select isnull((select STRING_AGG(isnull(ProductName,''''),'', '') from openjson(ul.productsjson) with(ProductName nvarchar(max) ''$.ProductName'' ) where isnull(ul.productsjson,'''') != '''') , '''')) AS Products,UD.User_Login + '' ('' + Ud.FName +  '' '' + Ud.LName + '')'' AS assigneduser, UD.User_Login as assignedUserloginOnly, Profit_Loss=case when LS.ScoreAdded > 0 then ''Green_Up'' when LS.ScoreAdded < 0 then ''Red_Down'' else '''' end,CurrentScore=cast(isnull((LS.currentscore/nullif('+ cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int), ThresholdColor=case when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int)>' + cast(@warm AS NVARCHAR(max)) + N' then ''Hot'' when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int) between ' + cast(@cold AS NVARCHAR(max)) + N'  and ' + cast(@warm AS NVARCHAR(max)) + N' then ''Warm'' else ''Cold'' end, UD1.User_Login ' AS NVARCHAR(max)) + N', isnull(UD2.User_Login, '''') as LastFollowupCreatedByName, ul.LastFollowupCreatedOn as LastFollowupedOn, UL.WhatsAppNoColName  '

			SELECT @Query += cast(N' FROM UserLeads AS UL(NOLOCK) left JOIN UserSourceSettings AS USS(NOLOCK)
	 ON UL.SourceName = USS.SourceID --outer apply dbo.funcToGetScoredetails(ul.id) f
	 left join lead_score_history_latest(nolock) LS ON UL.ID=LS.LeadId LEFT JOIN UserMediumSettings AS UMS(NOLOCK) ON UL.MediumName = UMS.MediumID LEFT JOIN UserCampaignSettings AS UCS(NOLOCK) ON UL.CampaignName = UCS.CampaignID LEFT JOIN User_Detail AS UD(NOLOCK) ON UL.AssignedTo = UD.User_ID LEFT JOIN User_Detail AS UD1(NOLOCK) ON UL.CreatedBy = UD1.User_ID LEFT JOIN User_Detail AS UD2(NOLOCK) ON UL.LastFollowupCreatedBy = UD2.User_ID left join FollowUp_Status AS FUS(NOLOCK) ON UL.FollowUpStatus = FUS.id
	--left join LeadPipelineMapping_latest(nolock) as lpm
	--on UL.ID = lpm.LeadID
	 LEFT JOIN ( select STRING_AGG(Tag, '','') as Tags, etm.EntityID from TagMaster(nolock) tm inner join EntityTagMapping(nolock) etm on tm.id = etm.TagID and etm.entity = ''lead'' and tm.ParentID = ' + Convert(VARCHAR(100), @ParentID) + ' where ISNULL(etm.EntityID, 0) > 0 group by etm.EntityID ) tg on tg.EntityID = UL.ID   
	WHERE UL.ParentID = ' + CAST(@ParentID AS NVARCHAR(MAX)) + N' AND UL.AssignedTo ' + CASE 
						WHEN @Userid = 0
							THEN N' = UL.AssignedTo '
						WHEN @Userid > 0 /*and isnull(@TeamCode,'') != ''*/
							THEN ' in (' + isnull(@UserIdTeamLst, '') + ')'
						ELSE ' = ' + CAST(@Userid AS NVARCHAR(MAX))
						END + ' and 1= case when isnull(' + cast(@notfollowedup AS NVARCHAR) + ',''0'')=''0'' then 1 when isnull(' + cast(@notfollowedup AS NVARCHAR) + ',''0'')=''1'' and abs(datediff(mi,ul.createdon,ul.followupdate))<=2
	--and ul.enquirysource not between 12 and 15 and ul.enquirysource<>22
	and ul.ModifiedOn is null  then 1 else 0 end' + ' ) T Where ' + @FilterText + ' ) S ) AS A 
                    Where ' 
                 + CASE 
						WHEN @txtSearch = ' (1=1) '
							THEN ' A.RowNumber1 BETWEEN ' + CONVERT(NVARCHAR(max), @srno) + N' AND ' + CONVERT(NVARCHAR(max), @enno)
						ELSE ' (1=1) '
						END 
						AS NVARCHAR(MAX));
		END

		PRINT cast(@Query AS VARCHAR(max))

		IF (@Pivot_Column IS NOT NULL)
		BEGIN
			PRINT 'Branch C'

			--IF(@FilterText = ' (1=1) ' and @txtSearch = ' (1=1) ')-- From Branch A 
			IF (@txtSearch = ' (1=1) ') -- From Branch A 
			BEGIN
				PRINT 'Branch CA'
				DECLARE @caQuery NVARCHAR(max) = CAST(N'; Insert into #Leadtemp (LeadId) Select id from ( Select *       
   From ( SELECT ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, User_Login, FollowupDate, FollowupCreatedDate as CreatedOn, CreatedOn1New, CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus, assigneduser,assignedUserloginOnly, Img_Ext, WhereAddress, Products, FollowupCreatedDate, FollowupBy, ' + @Pivot_Column + N', CurrentScore, Profit_Loss, ThresholdColor, ROW_NUMBER() OVER(ORDER BY ' + @StrPredefinedOrderBy + N' ' + @StrCustomOrderBy + '  [ID] DESC)  ' + ' AS [RowNumber1], rc1, LastFollowupCreatedByName, LastFollowupedOn, WhatsAppNoColName,CreatedBy, ModifiedOn, ModifiedBy, AmountPaid FROM
   (SELECT ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, FollowupBy, FollowupDate, FollowupCreatedDate, CreatedOn1New, CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus, assigneduser,assignedUserloginOnly, img_ext, WhereAddress, Products, [fieldname] , fieldvalue, CurrentScore, Profit_Loss,ThresholdColor, RowNumber1, rc1 ,User_Login,LastFollowupCreatedByName, LastFollowupedOn, WhatsAppNoColName,CreatedBy, ModifiedOn, ModifiedBy, AmountPaid FROM (select L.ID,  L.LeadNo, L.PersonName, L.CompanyName,L.MobileNo,L.EmailID, L.City, L.State, L.Country, L.CountryCode, L.PinCode, L.ResidentialAddress, L.OfficeAddress, L.SourceName, L.MediumName, L.CampaignName, L.InitialRemarks, L.ParentID, L.FollowupBy, L.FollowupDate, L.FollowupCreatedDate, L.CreatedOn1New, L.CreatedOn1, L.AssignedTo, L.Remarks, L.FollowUp, L.MobileNo1, L.MobileNo2, L.MobileNo3, L.EmailID3, L.EmailID1, L.EmailID2, L.FollowupStatus,  L.assigneduser,L.assignedUserloginOnly, L.Img_Ext, L.WhereAddress, L.Products, y.fieldname, x.fieldvalue, L.CurrentScore, L.Profit_Loss, L.ThresholdColor, L.RowNumber1, L.rc1, L.User_Login,L.LastFollowupCreatedByName, L.LastFollowupedOn, L.WhatsAppNoColName, L.CreatedBy, L.ModifiedOn, L.ModifiedBy, L.AmountPaid  From #temp1 L left join customfieldLeadvalue(nolock) x ON L.ID = x.LeadID left join customfields(nolock) y ON x.fieldID=y.field_ID AND y.[ParentID] = ' 
						+ CAST(@Parentid AS NVARCHAR(MAX)) + N' AND y.[isActive] = 1 )q )Tab1
  PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + N')) AS Tab2 Where ' + @txtSearch + ' ) T1
   ) T2 ' 
        --'Where T2.RowNumber1 BETWEEN ' + CONVERT(NVARCHAR(max), @srno) + N' AND ' + CONVERT(NVARCHAR(max), @enno) 
      + N' ORDER BY ' + @ordstr AS NVARCHAR(MAX));

				--PRINT cast(@caQuery as varchar(max))

				SELECT @Query = @Query + @caQuery
			END
			ELSE -- From Branch B      
			BEGIN
				PRINT 'Branch CB'
	SELECT @filterCnt = count(*)
				FROM dbo.fn_Split(@txtSearch, ' ) ')
				select @filterCnt = 1

				SELECT @Query1 += CAST(N'; select * into #Temp2 From (select [x].LeadID, [y].[fieldname], [x].[fieldvalue] from customfieldLeadvalue(nolock) x inner join customfields(nolock) y ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + N' AND y.[isActive] = 1 ) T1 PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + N')) AS Tab2 Where ' + @txtSearch AS NVARCHAR(MAX));

				SELECT @Query1 += CAST(N'; Insert into #Leadtemp (LeadId) Select id from ( Select ROW_NUMBER() OVER(ORDER BY ' + @StrPredefinedOrderBy + N' ' + @StrCustomOrderBy + '  [ID] DESC)  ' + ' AS [RowNumber1], count(*) OVER(ORDER BY [ParentID]) AS [rc1], * From ( SELECT ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, User_Login, FollowupDate, FollowupCreatedDate as CreatedOn, CreatedOn1New, CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus, assigneduser,assignedUserloginOnly, Img_Ext, WhereAddress, Products, FollowupCreatedDate, FollowupBy, ' + @Pivot_Column + 
						N', CurrentScore, Profit_Loss, ThresholdColor, LastFollowupCreatedByName, LastFollowupedOn, WhatsAppNoColName, CreatedBy, ModifiedOn, ModifiedBy, AmountPaid 
				   From #Temp2 A inner join #temp1 L       
					ON A.LeadId = L.ID  ) T1       
				  ) T2  
				    Where  T2.RowNumber1 BETWEEN ' + CONVERT(NVARCHAR(max), @srno) + N' AND ' + CONVERT(NVARCHAR(max), @enno) 
				   + N' ORDER BY ' + @ordstr AS NVARCHAR(MAX)) ;


				--PRINT cast(@Query1 as varchar(max))

				SELECT @Query = @Query + @Query1
			END
		END
		ELSE
		BEGIN
			PRINT 'Branch D'

			SET @Query2 += CAST(N';Insert into #Leadtemp (LeadId) Select ID  
  From #temp1      
  Where RowNumber1 BETWEEN ' + CONVERT(NVARCHAR(max), @srno) + N' AND ' + CONVERT(NVARCHAR(max), @enno) + N' ORDER BY ' + @ordstr  AS NVARCHAR(MAX));

			PRINT cast(@Query2 as varchar(max))

			SELECT @Query = @Query + @Query2
		END

		--print '@FinalQuery:- ' + cast(@Query as varchar(max))      
		EXEC sp_executesql @Query;
    
	INSERT INTO Tbl_MassOperationSummary (MassOperationName, UserID, Parentid, CreatedDate, IsProcessed, ProcedureName, FilterCriteria, EntityType)
			Values (@MassOperationName, @actUserID, @parentid, getdate(), 0, 'Usp_MassOperationLeadID', @FilterText, 'Lead')
	--Declare @BatchID Bigint  = Scope_Identity()
	set @BatchID=Scope_Identity()

	INSERT INTO Tbl_MassOperationDetails (SummaryId,EntityID)
	Select @BatchID, LeadID from #Leadtemp 
	
	Select @BatchID BatchId
		IF OBJECT_ID('tempdb.dbo.#temp1', 'U') IS NOT NULL
		BEGIN
			DROP TABLE #temp1;
		END;

		IF OBJECT_ID('tempdb.dbo.#temp2', 'U') IS NOT NULL
		BEGIN
			DROP TABLE #temp2;
		END;
	  
	 -- for temp display
	  --Select  LeadID from #Leadtemp 
	  drop table if exists #Leadtemp


	END
END


GO

/* ============================================================
   Procedure: [dbo].[Usp_MassOperationLeadIDBySearchCriteria]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- exec Usp_MassOperationLeadIDBySearchCriteria @srno=N'1',@enno=N'all',@CriteriaName=N'All Leads',@UserID=34594,@CriteriaID=0,@SearchByMode=N'Name',@MassOperationName=''
CREATE   PROCEDURE [dbo].[Usp_MassOperationLeadIDBySearchCriteria] --'1','20','',34594,231745,'id'    
(    
	--@txtSearch NVARCHAR(max),
	--@FilterText NVARCHAR(MAX) = '',
	@srno NVARCHAR(100),
	@enno NVARCHAR(100),
	--@ordstr nvarchar(Max)='' ,
	--@notfollowedup int=null,
	@CriteriaName nvarchar(500),
	@UserID bigint,
	@CriteriaID bigint=0,
	@SearchByMode nvarchar(50),
	@MassOperationName Nvarchar(100) 
)    
as    
Begin
	-- declare @srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@CriteriaName nvarchar(500)=N'All Leads',@UserID bigint=39042,@CriteriaID bigint=0,@SearchByMode nvarchar(50)=N'Name'

	declare @ParentID bigint = 0    
	declare @IsAdmin bit = 0     
    
	select @ParentID = ISNULL(ParentID,User_ID) , @IsAdmin = isnull(IsAdmin,0) from User_Detail(nolock) where User_ID = @UserID
    
	if(@SearchByMode = 'Name')    
	Begin    
		select top 1 @CriteriaID = isnull(ID,0) from tbl_SearchCriteria(nolock) where CriteriaName = @CriteriaName and ParentID = @ParentID      
	end

    Declare @ApplyTo nvarchar(50) = 'applyall'                       
	Declare @AndorOR nvarchar(10) = 'and'                      
	Declare @SearchType nvarchar(200) = 'Enquiry'                      
                      
   --select top 1 @ParentID = isnull(ParentID,USER_ID),@IsAdmin = isnull(IsAdmin,0) from User_Detail(nolock) where User_ID = @UserID                      
	select @ApplyTo = isnull(ApplyTo,'') , @SearchType = CriteriaType from tbl_SearchCriteria(nolock) where ID = @CriteriaID  
                         
	if(@ApplyTo = 'applyall')
	Begin
		set @AndorOR = 'and';
	End
	else
	Begin
		set @AndorOR = 'or'
	End
                      
	declare @tempConditions table(RowNum int,FieldName nvarchar(200),[FieldType] nvarchar(200),[Operator] nvarchar(200),Value nvarchar(max))      
      
  --SELECT ROW_NUMBER() over(order by id asc) as RowNum,                      
  --    [FieldName]                      
  --    ,[FieldType]                      
  --    ,[Operator]                      
  --    ,[Value] into #tempConditions                            
  --FROM [tbl_SearchCriteriaConditions] where CriteriaID = @CriteriaID  and [FieldType] <> 'Custom'                       
	insert into @tempConditions(RowNum,[FieldName],[FieldType],[Operator],[Value])    
	SELECT ROW_NUMBER() over(order by id asc) as RowNum,[FieldName],[FieldType],[Operator],[Value]                            
	FROM [tbl_SearchCriteriaConditions] where CriteriaID = @CriteriaID  and [FieldType] <> 'Custom'                       

	Declare @InvertedComma nvarchar(10) = '''';                      
  --select @InvertedComma+'a'                      
	declare @Count int = 0                      
	declare @RowIndex int = 0                      
	Declare @FieldName nvarchar(200) = ''                      
	Declare @FieldOperator nvarchar(200) = ''                      
	Declare @Value nvarchar(max) = ''                      
	Declare @FieldType nvarchar(200) = ''                      
	Declare @DataType nvarchar(200)= ''                            
	--select @Count = count(1) from #tempConditions     
	select @Count = count(1) from @tempConditions      
                        
	Declare @FilterQuery nvarchar(max) = ' ('                      
                          
	if(@Count = 0)                      
    Begin                      
		set @FilterQuery = @FilterQuery + '1=1'                        
	end                      
                      
	while(@Count > 0)                      
    Begin                      
		set @RowIndex = @RowIndex + 1                       
		select @FieldName = FieldName,@FieldOperator = Operator,@Value = Value ,@FieldType = FieldType 
		from  @tempConditions where RowNum = @RowIndex                      
                      
		select @DataType = dbo.ufn_FetchDataType(@FieldName,@FieldType,@ParentID);                        
		-- select @DataType                      
                 
		if(@FieldName = 'LastFollowupCreatedBy')          
		 Begin          
		 set @FieldName =  'LastFollowupCreatedByName'          
	  end          
                   
		if(@FieldName = 'CreatedOn' and @FieldType = 'Lead')                      
		 Begin                      
			set @FieldName = 'CreatedOn1'                      
		 End                       
                      
		if(@FieldName = 'CreatedBy')           
		 Begin                      
			set @FieldName = 'User_Login'                      
		 End               
                
		if(@FieldName = 'AssignedTo' and @FieldType = 'Lead')                      
		 Begin                      
			--set @FieldName = 'assigneduser'
			set @FieldName = 'assignedUserloginOnly'                      
		 End                  
              
		if(@FieldName = 'GoogleLocation')                      
		 Begin                      
			set @FieldName = 'whereAddress'                      
		 End              
              
		if(@FieldOperator = '%[A]%')                      
		 Begin                      
			set @FieldOperator = ' like '                      
		 set @Value = SUBSTRING(@Value,2,LEN(@Value)-2);                      
		 set @Value = @InvertedComma + REPLACE('%[A]%','[A]',@Value) + @InvertedComma;                        
		End                             
		else if(@FieldOperator = '[A]%')                      
		 Begin                      
			set @FieldOperator = ' like '                      
