	set @FilterQuery = @FilterQuery + ') ';                      
    -- select @FilterQuery                      
                        
   --select * from #tempConditions                      
	drop table if exists #tempConditions                       
      
	declare @tempConditionsCustom table(RowNum int,FieldName nvarchar(200),[FieldType] nvarchar(200),[Operator] nvarchar(200),Value nvarchar(max))                      
                      
  --SELECT ROW_NUMBER() over(order by id asc) as RowNum,                      
  --    [FieldName]                      
  --    ,[FieldType]                      
  --    ,[Operator]                      
  --    ,[Value] into #tempConditionsCustom                            
  --FROM [tbl_SearchCriteriaConditions] where CriteriaID = @CriteriaID and [FieldType] = 'Custom'                       
	insert into @tempConditionsCustom(RowNum,[FieldName],[FieldType],[Operator],[Value])
	SELECT ROW_NUMBER() over(order by id asc) as RowNum,[FieldName],[FieldType],[Operator],[Value]                            
	FROM [tbl_SearchCriteriaConditions] where CriteriaID = @CriteriaID and [FieldType] = 'Custom'                       
    
                        
	set @RowIndex  = 0                      
  --select @Count = count(1) from #tempConditionsCustom     
	select @Count = count(1) from @tempConditionsCustom     
                        
	Declare @FilterQueryCustom nvarchar(max) = ' ('                      
                          
	if(@Count = 0)                      
    Begin                      
		set @FilterQueryCustom = @FilterQueryCustom + '1=1'                        
	end                      
                      
	while(@Count > 0)                      
    Begin                      
		set @RowIndex = @RowIndex + 1                       
		select @FieldName = FieldName,@FieldOperator = Operator,@Value = Value,@FieldType = FieldType  from  @tempConditionsCustom where RowNum = @RowIndex                      
		select @DataType = dbo.ufn_FetchDataType(@FieldName,@FieldType,@ParentID);                       
                      
        if(@FieldOperator = '%[A]%')                      
		Begin                      
			set @FieldOperator = ' like '                      
			set @Value = SUBSTRING(@Value,2,LEN(@Value)-2);                      
			set @Value = @InvertedComma + REPLACE('%[A]%','[A]',@Value) + @InvertedComma;                        
		End
		else if(@FieldOperator = '[A]%')                      
		Begin                      
			set @FieldOperator = ' like '                      
			set @Value = SUBSTRING(@Value,2,LEN(@Value)-2);                      
			set @Value = @InvertedComma + REPLACE('[A]%','[A]',@Value) + @InvertedComma;                        
		End                           
        else if(@FieldOperator = '%[A]')                      
		Begin                      
			set @FieldOperator = ' like '                      
			set @Value = SUBSTRING(@Value,2,LEN(@Value)-2);                      
			set @Value = @InvertedComma + REPLACE('%[A]','[A]',@Value) + @InvertedComma;                        
		End                          
        else if(@FieldOperator = '[A]')                      
		Begin                      
			set @FieldOperator = ' like '                      
			set @Value = SUBSTRING(@Value,2,LEN(@Value)-2);                      
			set @Value = @InvertedComma + REPLACE('[A]','[A]',@Value) + @InvertedComma;                        
		End                         
        else if(@FieldOperator = 'not %[A]%')                      
		Begin                      
			set @FieldOperator = ' not like '                      
			set @Value = SUBSTRING(@Value,2,LEN(@Value)-2);                      
			set @Value = @InvertedComma + REPLACE('%[A]%','[A]',@Value) + @InvertedComma;                        
		End                      
		else if(@FieldOperator = 'not [A]%')                      
		Begin
			set @FieldOperator = ' not like '                      
			set @Value = SUBSTRING(@Value,2,LEN(@Value)-2);                      
			set @Value = @InvertedComma + REPLACE('[A]%','[A]',@Value) + @InvertedComma ;                        
		End                      
		else if(@FieldOperator = 'not %[A]')                      
		Begin                      
			set @FieldOperator = ' not like '                      
			set @Value = SUBSTRING(@Value,2,LEN(@Value)-2);                      
			set @Value = @InvertedComma + REPLACE('%[A]','[A]',@Value) + @InvertedComma;                        
		End                         
		else if(@FieldOperator = 'not [A]')                      
		Begin                      
			set @FieldOperator = ' not like '                      
			set @Value = SUBSTRING(@Value,2,LEN(@Value)-2);                      
			set @Value = @InvertedComma + REPLACE('[A]','[A]',@Value) + @InvertedComma ;                        
		End                         
		else if(@FieldOperator = 'in [A]')                      
		Begin                      
			set @FieldOperator = ' in '                      
			--set @Value = SUBSTRING(@Value,2,LEN(@Value)-2);                      
			set @Value = REPLACE('in [A]','in [A]',@Value) ;                        
		End                
                      
     --if(@DataType = 'datetime' and @FieldOperator = 'between')                      
     -- Begin                      
        --   set @FieldName = ' DATEDIFF(DAY,'+@FieldName+',getdate()) '                      
     -- end                      
                           
		declare @FieldColumnText nvarchar(500) = ' cast( '+ @FieldName +'  as varchar(100)) '                       
		if(@DataType = 'varchar' or @DataType = 'nvarchar')                      
        begin                      
			set @FieldColumnText = ' cast('+ @FieldName +' as varchar(100)) ';                      
		end                       
        else if(@DataType = 'numeric' or @DataType = 'float' or @DataType = 'int' )                      
        begin                      
			set @FieldColumnText = ' cast(cast('+ @FieldName +' as nvarchar(100)) as numeric(18,4)) ';                      
		end                            
		else if(@DataType = 'datetime' and @FieldOperator <> 'between')                      
		begin                      
			set @FieldColumnText = ' cast('+ @FieldName +' as date) ';                      
		end                         
           else if(@DataType = 'datetime' and @FieldOperator = 'between')                      
		begin                      
			--set @FieldColumnText = ' DATEDIFF(DAY,cast(fieldvalue as date),getdate()) ';                      
			set @FieldColumnText = ' DATEDIFF(DAY,getdate(),cast('+ @FieldName +' as date)) ';                       
		end                      
                             
                      
		if(@RowIndex = 1)                      
		Begin                      
			--set @FilterQueryCustom = @FilterQueryCustom + ' ( fieldname =' +''''+@FieldName+'''' +' and '+ ' '+@FieldColumnText+' ' +@FieldOperator+' '+ @Value + ' ) '; 
		  set @FilterQueryCustom = @FilterQueryCustom + ' ( '+@FieldColumnText+' ' +@FieldOperator+' '+ @Value + ' ) ';	
			                     
		end                      
		else                       
		Begin                      
			--set @FilterQueryCustom = @FilterQueryCustom + @AndorOR + ' ( fieldname =' +'''' + @FieldName+'''' +' and '+ ' '+@FieldColumnText+' ' + @FieldOperator+' '+ @Value + ' ) ';
			set @FilterQueryCustom = @FilterQueryCustom + @AndorOR + ' ( '+@FieldColumnText+' ' + @FieldOperator+' '+ @Value + ' ) ';                       

		End                      
                      
		set @Count = @Count - 1                         
	End                      
                     
                         
	set @FilterQueryCustom = @FilterQueryCustom + ') ';                      
                   
  --select @FilterQuery as TableFilter                      
  --select @FilterQueryCustom as CustomFilter                      
   --  select * from #tempConditionsCustom                      
	drop table if exists  #tempConditionsCustom                      
       
	if(@SearchType = 'Conversion')
	Begin
		set  @FilterQuery = '( ( FollowupStatus = ''Converted'' ) and  ' + '('+@FilterQuery +')'+ ')'  
	End

	print @FilterQueryCustom + ',' + cast(@ParentID as varchar) + ',' + cast(@UserID as varchar) + ',' + @FilterQuery 
	       
    if(@IsAdmin = 0)    
    Begin    
		exec Usp_MassOperationLeadID_withoutput --@FilterQueryCustom,@ParentID,@UserID,@FilterQuery,@srno,@enno,'',0     
			@txtSearch = @FilterQueryCustom, 
			@Userid = @UserID,  
			@FilterText  = @FilterQuery,  
			@srno = @srno,  
			@enno = @enno,  
			@ordstr = '',  
			@notfollowedup  = 0 ,
			@MassOperationName=@MassOperationName,
			@BatchId = @BatchId OUTPUT;
  End		
      else     
     Begin    
    exec Usp_MassOperationLeadID_withoutput -- @FilterQueryCustom,@ParentID,@UserID,@FilterQuery,@srno,@enno,'',0     
			@Txtsearch = @FilterQueryCustom,   
			@Userid = @UserID,  
			@FilterText  = @FilterQuery,  
			@srno = @srno,  
			@enno = @enno,  
			@ordstr = '',  
			@notfollowedup=0,
			@MassOperationName=@MassOperationName,
			@BatchId = @BatchId OUTPUT; 
  End       
   PRINT 'Captured BatchId: ' + CAST(@BatchId AS NVARCHAR); 
    
End



