/* ============================================================
   Procedure: [dbo].[Usp_MassProductDeletion]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE dbo.Usp_MassProductDeletion  
(  
  @ProductIDs  nvarchar(max)  
)  
as   
Begin  
  
        select  cast(isnull(value,0) as bigint)  as ProductID into #TBL_ProductIDs  from fn_split(@ProductIDs,',')  
  
        delete  from  ProductImageMapping where ProductID in (select ProductID from #TBL_ProductIDs)  
  delete from EntityTagMapping where Entity = 'Product' and  EntityID in (select ProductID from #TBL_ProductIDs)   
  update ProductMaster set DeletedAt = GETDATE() where ProductID in (select ProductID from #TBL_ProductIDs)   
    
    
  select 'Data Deleted' as msg  
   
  drop table #TBL_ProductIDs   
End  





GO

/* ============================================================
   Procedure: [dbo].[Usp_MassProductDeletion_WithParentID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
  
CREATE   PROCEDURE dbo.Usp_MassProductDeletion_WithParentID    
(    
  @ProductIDs  nvarchar(max),
  @ParentID bigint    
)    
as     
Begin    
    
	  exec Usp_createProductMasterTable @ParentID

     select  cast(isnull(value,0) as bigint)  as ProductID into #TBL_ProductIDs  from fn_split(@ProductIDs,',')    
    
    delete  from  ProductImageMapping where ProductID in (select ProductID from #TBL_ProductIDs)    
    delete from EntityTagMapping where Entity = 'Product' and  EntityID in (select ProductID from #TBL_ProductIDs)     
 
    Declare @Query nvarchar(max) = N'
	  update tbl_ProductMaster_' + cast(@ParentID as nvarchar(20)) + '  set DeletedAt = GETDATE() 
	  where ProductID in (select ProductID from #TBL_ProductIDs) '     
     
	exec sp_executesql @Query
        
  select 'Data Deleted' as msg    
     
  drop table #TBL_ProductIDs     
End    
  
  


GO

/* ============================================================
   Procedure: [dbo].[usp_MassSendMailCountValidationForLeads]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_MassSendMailCountValidationForLeads] --'65941#65942#65944',1,1,1                
 @IDS VARCHAR(MAX),                
 @EmailId BIT ,                
 @EmailId1 BIT ,                
 @EmailId2 BIT ,
  @massbatchid bigint=0
AS                
BEGIN       
   DROP TABLE if exists #tempTable                     
 DROP TABLE if exists #TableData2                     
  
CREATE TABLE #TableData2     
          (                        
              ID BIGINT    
          )    
	if @massbatchid IS NOT NULL AND @massbatchid <> 0
	BEGIN
		select @IDS= STRING_AGG(cast(Entityid as nvarchar(max)),'#') from Tbl_MassOperationDetails where SummaryId=@massbatchid 
	END
INSERT INTO #TableData2 (ID)               
SELECT fs.[value]                        
                FROM   dbo.fn_Split(@IDS, '#') fs    
      
    
 SELECT A.EmailID                
         INTO #tempTable                
 FROM   (                
            SELECT ISNULL(A.EmailID, '') AS EmailID                
                        
            FROM   (                
                       SELECT CASE                 
                                   WHEN @EmailId = 1 THEN ul.EmailID                
                                   ELSE ''                
                              END AS EmailID                
                                          
                       FROM   UserLeads  AS ul with(nolock)     
        inner join #TableData2 tb2 on ul.ID = tb2.ID     
    
                       WHERE -- ul.ID IN (SELECT [value]                
                       --                 FROM   dbo.fn_Split(@IDS, '#') AS fs) AND         
                                          ISNULL(NULLIF(CAST(ul.EmailID as varchar), ''), '') <> ''           
                      AND ISNULL(NULLIF(CAST(ul.EmailID as varchar), ''), '') not in           
                   ( select ISNULL(C_UDTemp.Email,'') as EmailID           
                      from UserLeads as UETemp with(nolock) inner join Client_UnSubscribeDetails as C_UDTemp with(nolock)          
                      on (UETemp.EmailID =C_UDTemp.Email)          
        inner join #TableData2 tb2 on UETemp.ID = tb2.ID     
                              
                      --where ul.ID in(Select fs.value from dbo.fn_Split(@IDS, '#') AS fs)    
       )         
                                                       
                       UNION ALL                 
                                       
                       SELECT CASE                 
                                   WHEN @EmailId1 = 1 THEN ul.EmailID1                
                                   ELSE ''                
                              END AS EmailID                
                       FROM   UserLeads AS ul with(nolock)               
                       inner join #TableData2 tb2 on ul.ID = tb2.ID     
                          
       WHERE      
       --ul.ID IN (SELECT [value]                
       --                                 FROM   dbo.fn_Split(@IDS, '#') AS fs) AND     
          ISNULL(NULLIF(CAST(ul.EmailID1 as varchar), ''), '') <> ''           
                      AND ISNULL(NULLIF(CAST(ul.EmailID1 as varchar), ''), '') not in           
                   ( select ISNULL(C_UDTemp.Email,'') as EmailID           
                      from UserLeads as UETemp with(nolock) inner join Client_UnSubscribeDetails as C_UDTemp with(nolock)          
                      on (UETemp.EmailID1 =C_UDTemp.Email)          
                      inner join #TableData2 tb2 on UETemp.ID = tb2.ID     
        
                      --where ul.ID in(Select fs.value from dbo.fn_Split(@IDS, '#') AS fs )    
       )        
                                                
                                                       
                       UNION ALL                
                                       
                       SELECT CASE                 
                                   WHEN @EmailId2 = 1 THEN ul.EmailID2                
                                   ELSE ''                
                              END AS EmailID                
                                             
                       FROM   UserLeads AS ul with(nolock)    
        inner join #TableData2 tb2 on ul.ID = tb2.ID     
    
                       WHERE     
        --ul.ID IN (SELECT [value]                
        --                                FROM   dbo.fn_Split(@IDS, '#') AS fs) AND     
          ISNULL(NULLIF(CAST(ul.EmailID2 as varchar), ''), '') <> ''           
     AND ISNULL(NULLIF(CAST(ul.EmailID2 as varchar), ''), '') not in           
                   ( select ISNULL(C_UDTemp.Email,'') as EmailID           
                      from UserLeads as UETemp with(nolock) inner join Client_UnSubscribeDetails as C_UDTemp with(nolock)          
                      on (UETemp.EmailID2 =C_UDTemp.Email)          
                      inner join #TableData2 tb2 on UETemp.ID = tb2.ID     
                              
                      --where ul.LeadNo in(Select fs.value from dbo.fn_Split(@IDS, '#') AS fs )    
       )        
                                                
                                                
                                                        
                   )                  A                
          WHERE  ISNULL(A.EmailID, '') <> ''                
       ) A                
                 
   DECLARE @MailCount BIGINT                
   SELECT @MailCount = COUNT(*)                
   FROM   #tempTable                
  -- select @MailCount
    
  /* commnted as ProcessMailLimit has nothing to do with mail sending limit
   Declare @Status Bigint=0,@CountLimit bigint = 0          
   select @Status = status,@CountLimit = Plimit from ProcessMailLimit                 
   if(@Status=1)          
      Begin          
           if(@MailCount < = @CountLimit )          
              Begin          
                 select 'Success'          
              End          
           else          
              Begin          
                select 'Fail'           
              End             
       End          
   else          
      Begin          
      select 'Success'          
    End             
    */
	
	 select 'Success' 
               
                 
 DROP TABLE if exists #tempTable                     
END     


GO

/* ============================================================
   Procedure: [dbo].[usp_massSendSMSBatchEntityDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_massSendSMSBatchEntityDetails  
    @JsonEntityData NVARCHAR(MAX)  
AS  
BEGIN  
    SET NOCOUNT ON;  
  
    DECLARE @EntityID BIGINT,  
            @BatchID BIGINT,  
            @Metadata NVARCHAR(MAX),  
            @MassOperationName NVARCHAR(50),  
            @UserID BIGINT,  
            @Remarks NVARCHAR(MAX),  
            @EntityType NVARCHAR(50),  
            @IsValid BIT,  
            @ErrorDetails NVARCHAR(MAX),  
            @ParentID BIGINT;  
  
    -- Parse JSON data once  
    SELECT   
        @EntityID = JSON_VALUE(@JsonEntityData, '$.EntityID'),  
        @BatchID = JSON_VALUE(@JsonEntityData, '$.BatchID'),  
        @Metadata = JSON_VALUE(@JsonEntityData, '$.Metadata'),  
        @MassOperationName = JSON_VALUE(@JsonEntityData, '$.MassOperationName'),  
        @UserID = JSON_VALUE(@JsonEntityData, '$.UserID'),  
        @Remarks = JSON_VALUE(@JsonEntityData, '$.Remarks'),  
        @EntityType = JSON_VALUE(@JsonEntityData, '$.EntityType'),  
        @IsValid = JSON_VALUE(@JsonEntityData, '$.IsValid'),  
        @ErrorDetails = JSON_VALUE(@JsonEntityData, '$.ErrorDetails');  
  
    -- Retrieve ParentID  
    SELECT @ParentID = ParentID  
    FROM User_Detail  
    WHERE User_ID = @UserID;  
  
    -- Check if record exists and insert if it does not  
    IF NOT EXISTS (  
        SELECT 1  
        FROM Tbl_MassSendSMSBatchEntityDetails  
        WHERE EntityID = @EntityID AND BatchID = @BatchID AND Msg = @Metadata  
    )  
    BEGIN  
        -- Insert the new record  
        INSERT INTO Tbl_MassSendSMSBatchEntityDetails (EntityID, BatchID, Msg, MassOperationName, UserID, ParentID, CreatedDate, IsProcessed, Remarks, EntityType, IsValid, ErrorDetails)  
        VALUES (@EntityID, @BatchID, @Metadata, @MassOperationName, @UserID, @ParentID, GETDATE(), 1, @Remarks, @EntityType, @IsValid, @ErrorDetails);  
    END  
END


GO

/* ============================================================
   Procedure: [dbo].[Usp_MassSMSToLeadEvent]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_MassSMSToLeadEvent --'260',335,1,1,1,'This is testing for Mss sms'
(
 @LeadIDs nvarchar(max),
 @UserID bigint,
 @CHK_Mobile bit,
 @CHk_Mobile1 bit,
 @CHk_Mobile2 bit,
 @Message nvarchar(max)
)
as
Begin

   Declare @EventID bigint = 0     
   Declare @EventName nvarchar(500) = 'SMS sent to lead'      
   Declare @EventTemplate nvarchar(max) = ''    
   Declare @UserName nvarchar(200) = ''  
   Declare @MobileNo nvarchar(50) = '' 
   Declare @MobileNo1 nvarchar(50) = '' 
   Declare @MobileNo2 nvarchar(50) = '' 
   
   Declare @ParentID bigint = 0
   
   Select  @ParentID = ISNULL(Parentid,0) from User_Detail where User_ID = @UserID   
   Select  @UserName = isnull(User_login,'') from User_Detail where User_ID = @UserID
   Select  @EventID = isnull(ID,0) ,@EventTemplate = isnull(EventTemplate,'')  from ActivityMaster where EventName = @EventName    
	
    select tbl.LeadID,row_number() over( order by LeadID) as RowNum  into #tbl_LeadIDs     From
	(Select fs.value as LeadID  from dbo.fn_Split(@LeadIDs, '#') AS fs ) as tbl

	 
	 Declare @RowNum int = 1
	 Declare @RowCount int = 0
	 Declare @LeadID bigint = 0

	 select @RowCount =  isnull(count(1),0) From #tbl_LeadIDs



	if(@EventID > 0)
	 Begin 
		 if(@CHK_Mobile = 1)
			   Begin
	              set @RowNum = 1
				 while( @RowNum <= @RowCount )			 	    	
				   Begin
                        select @LeadID = isnull(LeadID,0) from #tbl_LeadIDs where RowNum =@RowNum     
						select @MobileNo = rtrim(ltrim(isnull(MobileNo,'')))  from UserLeads where ID = @LeadID

						if(@MobileNo <> '')
						   Begin
						      select @EventTemplate = replace(replace(replace(@EventTemplate,'#username#',@UserName),'#Messagecontent#',@Message),'#mobileno#',@MobileNo)
  	                           exec UspSaveLeadActivity @LeadID,@UserID,@ParentID,@EventTemplate,@EventID
						   End
						
						set @MobileNo = ''
						
						set @RowNum = @RowNum +1
				   end
			   End

		  if(@CHk_Mobile1 = 1)
				Begin
				
              set @RowNum = 1
				 while( @RowNum <= @RowCount )			 	    	
				   Begin
                        select @LeadID = isnull(LeadID,0) from #tbl_LeadIDs where RowNum =@RowNum     
						select @MobileNo1 = rtrim(ltrim(isnull(MobileNo1,'')))  from UserLeads where ID = @LeadID

						if(@MobileNo1 <> '')
						   Begin
						      select @EventTemplate = replace(replace(replace(@EventTemplate,'#username#',@UserName),'#Messagecontent#',@Message),'#mobileno#',@MobileNo1)
  	                           exec UspSaveLeadActivity @LeadID,@UserID,@ParentID,@EventTemplate,@EventID
						   End
						set @MobileNo1 = ''

						set @RowNum = @RowNum +1
				   end

				End

		   if(@CHk_Mobile2 = 1)
				Begin
				  set @RowNum = 1
				 while( @RowNum <= @RowCount )			 	    	
				   Begin
                        select @LeadID = isnull(LeadID,0) from #tbl_LeadIDs where RowNum =@RowNum     
						select @MobileNo2 = rtrim(ltrim(isnull(MobileNo2,'')))  from UserLeads where ID = @LeadID

						if(@MobileNo2 <> '')
						   Begin
						      select @EventTemplate = replace(replace(replace(@EventTemplate,'#username#',@UserName),'#Messagecontent#',@Message),'#mobileno#',@MobileNo2)
  	                           exec UspSaveLeadActivity @LeadID,@UserID,@ParentID,@EventTemplate,@EventID
						   End
						
						set @MobileNo2 = ''
						set @RowNum = @RowNum +1
				   end
				End  
      End 

	  drop table #tbl_LeadIDs
end


GO

