SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_MatchUserTokenGuid    --'C021E2A1-6B3B-42F1-81E7-4D58D604B6F4'
(    
  @TokenGuid nvarchar(500)    
)    
as    
begin    
  
    --declare @TokenGuid nvarchar(500)  = 'C021E2A1-6B3B-42F1-81E7-4D58D604B6F4'  
  
  
    declare @isValid int = 0, @parentId bigint;  
  
    select @parentId = ParentID from tbl_UserTokenGuid with(nolock)   
            where TokenGuid = @TokenGuid and isactive = 1   
  
    if(isnull(@parentId, 0) > 0)     
    begin    
        select @isValid = dbo.fn_parent_hasactivesubscription(@parentId)  
    end     
    
    select @isValid as [status]  
  
end


