SET QUOTED_IDENTIFIER ON

CREATE   PROC dbo.Usp_MediumDeletion (
	@MediumID BIGINT
	,@IsActive BIT
	)
AS
BEGIN
	--if(@IsActive=1)
	--Begin
	--update  UserMediumSettings set IsActive=0 where MediumID = @MediumID
	--select 'Record Deactivated'
	--End
	--else
	--Begin
	--update  UserMediumSettings set IsActive=1 where MediumID = @MediumID
	--select 'Record Activated'
	--End  
	DECLARE @rowJson NVARCHAR(MAX) = (
			SELECT *
			FROM UserMediumSettings
			WHERE MediumID = @MediumID
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)
	DECLARE @userid BIGINT = (
			SELECT UserID
			FROM UserMediumSettings(NOLOCK)
			WHERE MediumID = @MediumID
			)

	UPDATE UserMediumSettings
	SET IsActive = @IsActive
	WHERE MediumID = @MediumID

	SELECT 'Record Deactivated'

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @userid
		,@Activity_type = 'Delt_Med_Sttng'
		,@ActionType = 'D'
		,@RowJson = @rowJson
		,@Table_name = 'UserMediumSettings'
END



