CREATE   PROCEDURE [dbo].[Usp_meet_CreateReccuringMeetings]   
--declare  
@ID BIGINT= 0      
,@ReccuringMeetingData nvarchar(max)=null  
,@Meeting_Name nvarchar(max) =NULL      
,@MeetingId nvarchar(max) =NULL      
,@RecurringEndByDate datetime =null  
,@RepeatType nvarchar(20) =null      
,@RepeatDays nvarchar(max)    =null    
,@RecurringEndAfterTimes int    =null     
,@MeetStartTime Datetime   =null      
,@MeetEndTime Datetime=null      
,@CreateMeetLink nvarchar(max)=null      
,@JoinModeratorLink nvarchar(max) =null      
,@JoinAttendeeLink nvarchar(max)=null      
,@Isrecurring bit = 0      
,@recuringDates nvarchar(max) =null      
,@meetUsers nvarchar(max)=null     
,@StartTime datetime =NULL   
,@Docid bigint =null    
,@MeetingType Nvarchar(MAX) =NULL  
  
,@isMeeting bit =null      
,@isWebinar bit =null      
,@UserId bigint =34594      
,@welcomeMessage nvarchar(max) =NULL      
,@record bit =NULL      
,@duration int =NULL      
,@Isactive bit =NULL      
,@Meeting_Status nvarchar(max) =NULL      
,@EndTime datetime =NULL      
,@LogoutURL nvarchaR(MAX) =NULL      
,@autoStartRecording BIT =NULL      
,@maxparticipants INT     =null    
,@allowStartStoprecording BIT     =null    
,@MeetingExpireIfNoUserJoinedInMinutes INT   =null      
,@MeetingAgenda NVARCHAR(MAX)   =null      
,@ScheduledDate DATETIME =NULL      
,@WebCamOnlyforhost BIT =NULL      
,@AllowhosttoUnmuteUsers BIT =NULL      
,@AllowHosttoCloseUsersCamera BIT   =null      
,@MuteOnStart BIT =Null      
,@DisbleCameraForUsers bit =null      
,@DisblePrivateChatForUsers bit =null      
,@DisablePublicChatForUsers bit =null      
,@AudioJoin bit =null      
,@SendChatTexttoUsers bit  =null       
,@sendrecordingtousers bit =null      
,@InviteParticipantsByMail bit =null      
,@InviteMailFrom Nvarchar(max) =null      
,@InviteMailSubject Nvarchar(max) =null        
,@InvitetempType nvarchar(max)   =null      
,@InvitetemplateId bigint     =null    
,@InviteParticipantsByMailText nvarchar(max) =null      
,@RemindParticipantsByMail bit =null      
,@RemindMailFrom nvarchar(max)     =null    
,@RemindMailSubject nvarchar(max)    =null     
,@Remindtemplatetype nvarchar(max)    =null     
,@RemindtemplateId Bigint     =null    
,@RemindParticipantsByMailText Nvarchar(max) =null      
,@RemindBeforeTime nvarchar(max) =null      
,@InviteNonEnquiryLead bit =null      
,@AddNewParticipantAsEnquiryLead bit =null      
,@SourceName bigint =null      
,@AddPartType nvarchar(10)=null   
,@searchtext nvarchar(max) =null        
,@createFromDate datetime    =null     
,@createtoDate datetime   =null      
,@WebinarType nvarchar =null  ,      
@DisablemicForUsers bit     =null    
,@AuthForm bigint =null      
,@Isregistration bit     =null    
,@regisFormname bigint     =null    
,@ApprovalType nvarchar(max)=null      
,@ApproverName nvarchar(max)=null      
,@AapproverId bigint     =null    
,@RegisStartDate datetime     =null    
,@RegisEndDate datetime     =null    
,@TotalRegisLimit int     =null    
,@AllowBusinessEmail  bit     =null    
,@BlockedEmailDomain nvarchar(max)   =null      
,@AllowAuthDomain bit     =null    
,@AuthDomain nvarchar(max) =null      
,@AllowJoinByMail bit     =null    
,@AllowDenyRegisbyCountry bit    =null     
,@allowCountry nvarchar(max)     =null     
,@denyCountry nvarchar(max)    =null     
,@userrole nvarchar(max)=null      
,@startMeeting nvarchar(max)=null      
,@returncode nvarchar(max)      =null     
,@RecordResponse nvarchar(max)   =null     
,@entityid bigint   =null     
,@RegistrationFormLink nvarchar(max)=null    
,@Banner nvarchar(max)  =null     
,@CompanyLogo nvarchar(max)  =null     
,@filtertext nvarchar(max)=''    
,@mode varchar(100)   =null     
As  
BEGIN  
  
  
 drop table if exists #temprecurring   
 drop table if exists #tempUsers  
 drop table if exists #tempRandExp
 DECLARE @min int =0 ,@max int = 0, @recurID bigint, @parentid bigint  
   Create TAble #tempOutUsers ( ID Bigint Identity, MeetUserid bigint, MeetingID bigint, Mobile nvarchar(20) , Email nvarchar(100)  )
   Create Table #tempRandExp (RowNo int , ID bigint , randomexp nvarchar(50)
)
 Declare @lastRndExpID bigint , @usercount int ,@joinurl nvarchar(1000),@urlid bigint
 select @parentid = parentid from User_Detail (nolock) where User_ID=@UserId  
  
   
 Select ROW_NUMBER() OVER (order by meetingid ) rowno, * INTO #temprecurring from OpenJSON(@ReccuringMeetingData)     
	WITH (meetname nvarchar(max), meetingid nvarchar(max)     , RecurringEndByDate datetime , recuringtype nvarchar(20)     , 
	RepeatDays nvarchar(max)    , RecurringEndAfterTimes int       
   , meetstarttime Datetime ,     meetendtime Datetime    , CreateMeetLink nvarchar(max)    , JoinModeratorLink nvarchar(max)     , JoinAttendeeLink nvarchar(max)    , Isrecurring bit      
   , recuringDates nvarchar(max)     , meetUsers nvarchar(max)   , StartTime datetime  , Docid bigint   , MeetingType Nvarchar(MAX) ,Parentmeetid bigint, AttachmentId bigint)  
  
   Select top 1 @joinurl= [Url],@urlid=ID from tbl_MeetingJoinUrl where IsActive=1

 Select @min = min(rowno) , @max= max(rowno) from #temprecurring    
  --select * from #temprecurring    
  
   while @min<=@max     
   BEGIN    
 Select @meetUsers = meetUsers from #temprecurring where rowno=@min   
  
    Insert INTO Tbl_Meeting (Meeting_Name, MeetingId, ParentId, UserId, welcome, duration, Isactive, Meeting_Status, Createddate, StartTime,LogoutURL, AutoStartRecording, MaxParticipants,      
       AllowStartStopRecording, MeetingExpireIfNoUserJoinedInMinutes,MeetingAgenda, MeetingType, ScheduledDate, WebCamOnlyforhost, AllowhosttoUnmuteUsers, AllowHosttoCloseUsersCamera,      
       MuteOnStart, DisbleCameraForUsers, DisblePrivateChatForUsers, DisablePublicChatForUsers, AudioJoin, SendChatTexttoUsers, SendRecordingToUsers, InviteParticipantsByMail,       
       InviteMailFrom, InviteMailSubject, InvitetempType, InvitetemplateId, InviteParticipantsByMailText, RemindParticipantsByMail, RemindMailFrom, RemindMailSubject, Remindtemplatetype,       
       RemindtemplateId, RemindParticipantsByMailText, RemindBeforeTime, InviteNonEnquiryLead, AddNewParticipantAsEnquiryLead, SourceName, AddPartType,RecurringEndByDate, RepeatType,       
       RepeatDays, RecurringEndAfterTimes, MeetStartTime, MeetEndTime, ismeeting, iswebinar, WebinarType,DisablemicForUsers,AuthForm, CreateMeetLink, JoinModeratorLink, JoinAttendeeLink,      
       Isregistration, regisFormname, ApprovalType, ApproverName, AapproverId, RegisStartDate, RegisEndDate, TotalRegisLimit, AllowBusinessEmail, BlockedEmailDomain, AllowAuthDomain,       
       AuthDomain, AllowJoinByMail, AllowDenyRegisbyCountry, allowCountry, denyCountry,FileAttachmentId, RecurringParentID,Isrecurring,RegistrationFormLink,Banner,CompanyLogo)    
     SELECT meetname, meetingid, @parentid, @UserId, @welcomeMessage, @duration, 1, @Meeting_Status, GETDATE(), @StartTime,@LogoutURL, @AutoStartRecording, @MaxParticipants,      
       @AllowStartStopRecording, @MeetingExpireIfNoUserJoinedInMinutes, @MeetingAgenda, MeetingType, @ScheduledDate, @WebCamOnlyforhost, @AllowhosttoUnmuteUsers,      
       @AllowHosttoCloseUsersCamera, @MuteOnStart, @DisbleCameraForUsers, @DisblePrivateChatForUsers, @DisablePublicChatForUsers, @AudioJoin, @SendChatTexttoUsers,      
       @SendRecordingToUsers, @InviteParticipantsByMail, @InviteMailFrom, @InviteMailSubject, @InvitetempType, @InvitetemplateId, @InviteParticipantsByMailText,      
       @RemindParticipantsByMail, @RemindMailFrom, @RemindMailSubject, @Remindtemplatetype, @RemindtemplateId, @RemindParticipantsByMailText, @RemindBeforeTime, @InviteNonEnquiryLead,      
       @AddNewParticipantAsEnquiryLead, @SourceName, @AddPartType,RecurringEndByDate, recuringtype, RepeatDays, RecurringEndAfterTimes,meetstarttime, meetendtime,@isMeeting,      
       @isWebinar, @WebinarType, @DisablemicForUsers,@AuthForm,CreateMeetLink, JoinModeratorLink, JoinAttendeeLink, @Isregistration, @regisFormname, @ApprovalType, @ApproverName,      
       @AapproverId, @RegisStartDate, @RegisEndDate, @TotalRegisLimit, @AllowBusinessEmail, @BlockedEmailDomain, @AllowAuthDomain, @AuthDomain, @AllowJoinByMail,       
       @AllowDenyRegisbyCountry, @allowCountry, @denyCountry,AttachmentId, Parentmeetid, Isrecurring, @RegistrationFormLink,@Banner,@CompanyLogo From #temprecurring where rowno=@min    
        
    
    Set @recurID = SCOPE_IDENTITY();    
 --select @recurID   
 --select  @id, @Isrecurring, @InviteParticipantsByMail    
   Select * Into #tempUsers from OpenJson(@meetUsers)       
      with (      
       Entitytype nvarchar(max) '$.Entitytype',       
       EntityId  nvarchar(max) '$.EntityId',      
       EntityName  nvarchar(max) '$.EntityName',      
       EntityEmail  nvarchar(max) '$.EntityEmail',      
       EntityMobile nvarchar(max) '$.EntityMobile',      
       EntityRole  nvarchar(max) '$.EntityRole',      
       joinlink  nvarchar(max) '$.joinlink'      
      )      
    Insert Into Tbl_MeetingUser( Meeting_ID, EntityID, Entity_Type, User_Role, Mobile, Email, UserName,  JoinLink, EntityName)   
	Output  inserted.ID As MeetUserid, inserted.Meeting_ID as Meeting_ID into #tempOutUsers
    Select @recurID, EntityId, Entitytype, EntityRole, EntityMobile, EntityEmail, EntityName, joinlink, EntityName from #tempUsers     

	   Select top 1 @lastRndExpID= ISNULL(LastUsedRandomExp,0)  from tbl_MeetingJoinUrl (nolock) where IsActive=1 order by ID
	  select @usercount = count (1) from Tbl_MeetingUser (nolock) where Meeting_ID=@recurID 

	  insert into #tempRandExp (RowNo,ID,randomexp)
	  Select ROW_NUMBER() Over(Order by ID desc) RowNo, ID,randomexp  from randomexp (nolock) where Id >@lastRndExpID and Id <= @lastRndExpID + @usercount 

	  Insert Into Tbl_MeetingUserJoinExpression(MeetingId, MeetUserId,Expression,Mode,ModeValue,Expiry,IsExpired)
	  Select MeetingID, MeetUserid,@joinurl+''+re.randomexp ,@AuthForm, Case WHEN tou.Email <> '' THEN  'Email' WHEN tou.Mobile <> '' THEN  'Mobile' END AS MODE, DATEADD(DAY,@MeetStartTime,30) ,0 from #tempOutUsers tou
		Join #tempRandExp re on tou.ID=re.RowNo

	  Insert Into Tbl_MeetingUsedRandonExpression (RandonExpressionID,MeetingUserid)
		Select Re.id, MeetUserid from #tempOutUsers tou
		Join #tempRandExp re on tou.ID=re.RowNo

       Update tbl_MeetingJoinUrl set LastUsedRandomExp = @lastRndExpID+@usercount where id=@urlid

 drop table if exists #tempUsers   
    Set @min=@min+1    
   END  
   Select 'Data Saved'  
   EnD  
  

  



GO

/* ============================================================
   Procedure: [dbo].[Usp_Meet_GetMeetingDetailsByMeetid]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROCEDURE [dbo].[Usp_Meet_GetMeetingDetailsByMeetid]    
@meetid bigint = null,    
@meeting_ID nvarchar(500) = null,    
@Entitytype nvarchar(20) =null,    
@EntityId bigint = null,    
@mode varchar(20)    
AS     
BEGIN    
  
 Declare @totalregislimit bigint =0, @Sequence bigint=0    
 IF @mode='regis'    
 BEGIN    
  IF EXISTS (SELECT 1 From Tbl_Meet_RegistrationFormData(nolock) where MeetingId=@meeting_ID and Entitytype=@Entitytype and EntityId=@EntityId)    
  BEGIN     
 Select @meetid=ID from Tbl_Meeting (nolock)  where MeetingId = @meeting_ID  
   Select 'Already Registered'  Status, Url,@meetid ID from tbl_meetingjoinurl where Isactive=1  
  END    
  ELSE     
  BEGIN    
    
  If @meeting_ID is not null    
  BEGIN    
    print 1  
   Select @totalregislimit= TotalRegisLimit,@meetid=ID from tbl_meeting  (nolock) where MeetingId=@meeting_ID     
   Select @Sequence = ISNULL (MAx ([Sequence]),0) from Tbl_Meet_RegistrationFormData (nolock) where MeetingId=@meeting_ID     
   if @totalregisLimit = 0    
   BEGIN    
   print 2  
    Select mt.ID, MeetingId, RegisStartDate, RegisEndDate, mju.Url, StartTime,EndTime from tbl_meeting mt (nolock)    
    cross join tbl_meetingjoinurl mju    
    where mt.MeetingId= @meeting_ID and mju.Isactive=1    
   END    
   ELSE if @totalregisLimit > 0 and @Sequence < @totalregisLimit    
   begin    
   print 3  
    Select mt.ID, MeetingId, RegisStartDate, RegisEndDate, mju.Url, StartTime,EndTime from tbl_meeting mt (nolock)    
    cross join tbl_meetingjoinurl mju    
    where mt.MeetingId= @meeting_ID and mju.Isactive=1    
   END    
   else     
   begin    
   print 4  
  Select @meetid=ID from Tbl_Meeting (nolock) where MeetingId = @meeting_ID  
    Select 'Limit Completed' Status, Url,@meetid ID from tbl_meetingjoinurl where Isactive=1   
   END    
  END    
  END    
 END    
 IF @mode='getdate'    
 BEGIN    
  If @meetid is not null    
  BEGIN    
   Select mt.ID, MeetingId, RegisStartDate, RegisEndDate, mju.Url,convert(varchar(max), MeetStartTime,13) StartTime, convert(varchar(max), MeetEndTime,13)  EndTime from tbl_meeting mt (nolock)    
   cross join tbl_meetingjoinurl mju    
   where mt.ID= @meetid and mju.Isactive=1    
  END    
  ELSE If @meeting_ID is not null    
  BEGIN    
   Select mt.ID, MeetingId, RegisStartDate, RegisEndDate, mju.Url, convert(varchar(max), MeetStartTime,13)  StartTime,convert(varchar(max),  MeetEndTime,13)  EndTime from tbl_meeting mt (nolock)    
   cross join tbl_meetingjoinurl mju    
   where mt.MeetingId= @meeting_ID and mju.Isactive=1    
  END    
 END    
END  
  


GO

/* ============================================================
   Procedure: [dbo].[Usp_Meet_GetMeetingjoinDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


  
CREATE   PROCEDURE [dbo].[Usp_Meet_GetMeetingjoinDetails]       
@randomexp nvarchar(1000)=null ,      
@meetuserid bigint= null,       
@type nvarchar(5)='',      
@message nvarchar(max)='',      
@mode nvarchar(20)      
AS      
BEGIN      
 Declare @entitype nvarchar(20), @entityid bigint , @eventDescription nvarchar(max),@UserID bigint , @ParentID bigint ,@reftables nvarchar(20)='Tbl_Meeting',@EventName  NVARCHAR(500),       
 @refid NVARCHAR(100),@EntityName nvarchar(100)  , @meetingName nvarchar(200)    
      
 if @mode='visit'      
 begin      
  Update Tbl_MeetingUserJoinExpression set UserVisitLink=1  Where Expression like '%'+@randomexp+'%'      
        
  Select  @entitype= mu.Entity_Type, @entityid=mu.EntityID, @UserID=mt.UserId, @ParentID=mt.ParentId, @refid=mt.ID,@EntityName =mu.EntityName, @meetingName=mt.Meeting_Name      
  from Tbl_MeetingUserJoinExpression (NOLOCK) muje      
  JOIN Tbl_MeetingUser mu on mu.ID=muje.MeetUserId      
  Join Tbl_Meeting mt on mu.Meeting_ID=mt.ID     
  Where Expression like '%'+@randomexp+'%'       
      
  Select muje.ID, muje.Expression, muje.MeetingId, muje.MeetUserId, muje.Mode, muje.ModeValue,mu.JoinLink,mu.Entity_Type,mu.Email,mu.Mobile,mu.EntityName,mt.Meeting_Status      
   from Tbl_MeetingUserJoinExpression (NOLOCK) muje      
  JOIN Tbl_MeetingUser mu on mu.ID=muje.MeetUserId      
  Join Tbl_Meeting mt on mu.Meeting_ID=mt.ID      
  Where Expression like '%'+@randomexp+'%'       
      
  if(@entitype='Enquiry')      
  BEGIN      
   set @EventName='Enquiry Visited Meeting Join Page'      
   set @eventDescription= @EntityName+' visited meeting join page for meeting titled ' + @meetingName     
  END      
  else if(@entitype='Lead')      
  BEGIN      
   set @EventName='Lead Visited Meeting Join Page'      
   set @eventDescription= @EntityName+' visited meeting join page for meeting titled ' + @meetingName      
  END      
  Exec UspSaveEntityActivity_withid @entityname= @entitype ,@EntityID=@entityid,@UserID=@userid,@ParentID=@parentid,@EventDescription=@eventDescription,@EventName=@EventName      
    ,@reftables=@reftables,@refid=@refid      
      
 end      
 Else IF @mode ='joined'      
 BEGIN      
  Select  @entitype= mu.Entity_Type, @entityid=mu.EntityID, @UserID=mt.UserId, @ParentID=mt.ParentId, @refid=mt.ID,@EntityName =mu.EntityName, @meetingName=mt.Meeting_Name       
  from Tbl_MeetingUserJoinExpression (NOLOCK) muje      
  JOIN Tbl_MeetingUser mu on mu.ID=muje.MeetUserId      
  Join Tbl_Meeting mt on mu.Meeting_ID=mt.ID      
  Where mu.ID=@meetuserid      
      
  Update Tbl_MeetingUser set UserJoined = 1 where ID=@meetuserid      
      
  if(@entitype='Enquiry')      
  BEGIN      
   set @EventName='Enquiry  Joined Meeting'      
   set @eventDescription= @EntityName+' Joined Meeting titled '+ @meetingName      
  END      
  else if(@entitype='Lead')      
  BEGIN      
   set @EventName='Lead Joined Meeting '      
   set @eventDescription= @EntityName+' Joined Meeting titled '+ @meetingName   
     
   END      
  Exec UspSaveEntityActivity_withid @entityname= @entitype ,@EntityID=@entityid,@UserID=@userid,@ParentID=@parentid,@EventDescription=@eventDescription,@EventName=@EventName      
    ,@reftables=@reftables,@refid=@refid      
 END      
 ELse IF @mode='OTP'      
 BEGIN      
  IF Lower(@type) ='email'      
  BEGIN      
    Declare @fromMailId nvarchar(max), @Subject nvarchar(max),  @Ismonitor bit=1, @mailcount int  =1          
      
   Select   @UserID=mt.UserId, @ParentID=mt.ParentId      
   from Tbl_MeetingUserJoinExpression (NOLOCK) muje      
   JOIN Tbl_MeetingUser mu on mu.ID=muje.MeetUserId      
   Join Tbl_Meeting mt on mu.Meeting_ID=mt.ID      
   Where mu.ID=@meetuserid   
   
     select top 1 @fromMailId=Mail_ID from (
	select TRIM(Mail_ID) Mail_ID from DefaultMailID(nolock) where user_id in (@userid)
	) MAIL

   DECLARE @CurrentBalance BIGINT = (                                          
        SELECT TOP 1 mcd.Balance                                          
        FROM   MailCreditDetails AS mcd   (nolock)                                       
        WHERE  mcd.[User_ID] = @parentid                    
        ORDER BY mcd.Credit_ID DESC                                          
    )         
     DECLARE @Balance BIGINT = @CurrentBalance - @MailCount             
    IF @Balance>0            
    begin       
    Declare @Status Bigint=0,@CountLimit bigint = 0                                
    select @Status = status,@CountLimit = Plimit from ProcessMailLimit                                       
    if(@Status = 1)        
    Begin                                                         
       if(@MailCount >  @CountLimit )                                
       Begin                                
        set @IsMonitor = 0                                 
       End                                   
    End         
    DECLARE @BatchID BIGINT                    
    begin tran                                              
    INSERT INTO GetBatchRecord ([User_id], RandNum) VALUES(@userid, @userid )                                                
    select @BatchID=SCOPE_IDENTITY()                                               
    DELETE FROM GetBatchRecord WHERE batchid=@BatchID                    
    commit      
      
     Select ISNULL(mt.InviteMailFrom,@fromMailId) FrommailID, mu.Email Email, 'Otp for Join Meeting' MailSubject, '' MailTempleteName,@message MailBody, getDate() mailDate,      
       @userid  MailUserid,@parentid MailParentID ,ISNULL(mt.InviteMailFrom, @fromMailId) MailReplyto, @BatchID BatchID,1 MailPriorty,'' MailScheduledDate, '' MailScheduledtime, '' MailAttachment,      
       @message Messages,@Ismonitor Ismonitor ,0 TemplateID,@mailCount MailCount,'OtpForJoinMeeting' MailSource   into #temp       
     from tbl_meeting mt       
     Join Tbl_MeetingUser mu on mu.Meeting_ID=mt.ID       
     where mu.id=@meetuserid      
      
     insert into CloneEmailsFilter( Mail_FromEmail, Mail_ToEmail, Mail_Subject, Mail_TempleteName, Messages, Mail_InsertedDate, Mail_UserID, Mail_ParentID, ReplyTo, Mail_BatchID,                    
      Mail_Priority,Mail_ScheduleDate,Mail_ScheduledTime,Mail_Attechement, Mail_TempleteBody, IsMonitor,TemplateID,Count,Source)                 
     Select  FrommailID , Email, MailSubject, MailTempleteName, MailBody, mailDate, MailUserid, MailParentID, MailReplyto, BatchID,         
      MailPriorty, MailScheduledDate, MailScheduledtime, MailAttachment, MailBody, Ismonitor ,  TemplateID, MailCount, MailSource         
     From #temp         
           
     Select 'Mail Sent'      
   END      
  END      
  Else IF Lower(@type) ='mobile'      
  BEGIN      
   Select * from tbl_meeting mt       
   Join Tbl_MeetingUser mu on mu.Meeting_ID=mt.ID       
   where mu.id=@meetuserid      
  END      
 END      
END      
      


GO

