/* ============================================================
   Procedure: [dbo].[Usp_Meet_InsertBigBlueButtonSetup]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_Meet_InsertBigBlueButtonSetup] 
@ID bigint =NULL,
@ServerURL nvarchar(max),
@SharedSecret nvarchar(max),
@Active bit =0,
@mode nvarchar(50)
As 
BEGIN
	if(@mode='active')
	begin
		if(@Active =1)
			BEGIN
			 UPdate Tbl_BigBlueButtonSetup set IsActive=0 
			 UPdate Tbl_BigBlueButtonSetup set IsActive=1 where ID=@ID 
			 Select 'BigBlueButton ServerURL Changed' 
			END
	end
	else if(@mode = 'insert')
	BEGIN
		INSERT Tbl_BigBlueButtonSetup (ServerURL,SharedSecret , IsActive)
		Select @ServerURL, @SharedSecret, 0

		Select SCOPE_IDENTITY(), 'BigBlueButton ServerURL,SharedSecret Saved ' 
	END
END



