CREATE   PROCEDURE [dbo].[Usp_meet_MeetingOutcomedetails]

@MeetOutcomeJson nvarchar(max)='',
@mode varchar(max),
@userid bigint 
As
BEGIN
	Declare @parentid bigint = (Select Parentid From User_Detail where User_ID=@userid )
	IF @mode='insert'
	BEGIN
		Insert INTO Tbl_MeetingOutcome (OutcomeName,OutcomeResult,ParentId,CreatedBy,CreatedOn,Sequence) 
		select Outcomename,Outcomeresult, @parentid, @userid,getdate() ,Sequence  from openjson (@MeetOutcomeJson) with(
		Outcomename nvarchar(max) '$.Outcomename',
		Outcomeresult nvarchar(max) '$.Outcomeresult',
		Sequence bigint '$.Sequence')
		
		Select 'Outcome Saved'
	END
	If @mode = 'select'
	BEGIN
		select ID, OutcomeName,OutcomeResult,ParentId,CreatedBy,CreatedOn,Sequence from tbl_meetingOutcome (NOLOCK)
		where ParentId=@parentid
		Order by Sequence 
	END
END



