CREATE   PROCEDURE [dbo].[Usp_Meet_SaveMeetingDetails]           
@ID BIGINT= 0          
,@Meeting_Name nvarchar(max) =NULL          
,@MeetingId nvarchar(max) =NULL          
,@isMeeting bit =null          
,@isWebinar bit =null          
,@UserId bigint =NULL          
,@welcomeMessage nvarchar(max) =NULL          
,@record bit =NULL          
,@duration int =NULL          
,@Isactive bit =NULL          
,@Meeting_Status nvarchar(max) =NULL          
,@StartTime datetime =NULL          
,@EndTime datetime =NULL          
,@LogoutURL nvarchaR(MAX) =NULL          
,@autoStartRecording BIT =NULL          
,@maxparticipants INT = NULL          
,@allowStartStoprecording BIT = NULL          
,@MeetingExpireIfNoUserJoinedInMinutes INT = NULL          
,@MeetingAgenda NVARCHAR(MAX) = NULL          
,@MeetingType Nvarchar(MAX) =NULL          
,@ScheduledDate DATETIME =NULL          
,@WebCamOnlyforhost BIT =NULL          
,@AllowhosttoUnmuteUsers BIT =NULL          
,@AllowHosttoCloseUsersCamera BIT = NULL          
,@MuteOnStart BIT =Null          
,@DisbleCameraForUsers bit =null          
,@DisblePrivateChatForUsers bit =null          
,@DisablePublicChatForUsers bit =null          
,@AudioJoin bit =null          
,@SendChatTexttoUsers bit = null          
,@sendrecordingtousers bit =null          
,@InviteParticipantsByMail bit =null          
,@InviteMailFrom Nvarchar(max) =null          
,@InviteMailSubject Nvarchar(max) = null          
,@InvitetempType nvarchar(max) = null          
,@InvitetemplateId bigint = null          
,@InviteParticipantsByMailText nvarchar(max) =null          
,@RemindParticipantsByMail bit =null          
,@RemindMailFrom nvarchar(max) = null          
,@RemindMailSubject nvarchar(max) = null          
,@Remindtemplatetype nvarchar(max) = null          
,@RemindtemplateId Bigint = null          
,@RemindParticipantsByMailText Nvarchar(max) =null          
,@RemindBeforeTime nvarchar(max) =null          
,@InviteNonEnquiryLead bit =null          
,@AddNewParticipantAsEnquiryLead bit =null          
,@SourceName bigint =null          
,@AddPartType nvarchar(10)=null          
,@RecurringEndByDate datetime =null          
,@RepeatType nvarchar(20) =null          
,@RepeatDays nvarchar(max)= null          
,@RecurringEndAfterTimes int = null          
,@MeetStartTime Datetime = null          
,@MeetEndTime Datetime=null          
,@searchtext nvarchar(max) = null          
,@createFromDate datetime = null          
,@createtoDate datetime = null          
,@WebinarType nvarchar = null,          
@DisablemicForUsers bit = null          
,@AuthForm bigint =null          
,@CreateMeetLink nvarchar(max)=null          
,@JoinModeratorLink nvarchar(max) =null          
,@JoinAttendeeLink nvarchar(max)=null          
,@Isregistration bit = null          
,@regisFormname bigint = null          
,@ApprovalType nvarchar(max)=null          
,@ApproverName nvarchar(max)=null          
,@AapproverId bigint = null          
,@RegisStartDate datetime = null          
,@RegisEndDate datetime = null          
,@TotalRegisLimit int = null          
,@AllowBusinessEmail  bit = null          
,@BlockedEmailDomain nvarchar(max) = null          
,@AllowAuthDomain bit = null          
,@AuthDomain nvarchar(max) =null          
,@AllowJoinByMail bit = null          
,@AllowDenyRegisbyCountry bit = null          
,@allowCountry nvarchar(max) = null          
,@denyCountry nvarchar(max)= null          
,@Isrecurring bit = 0          
,@recuringDates nvarchar(max) =null          
,@meetUsers nvarchar(max)=null          
,@userrole nvarchar(max)=null          
,@startMeeting nvarchar(max)=null          
,@returncode nvarchar(max) = null          
,@Docid bigint =null          
,@RecordResponse nvarchar(max)= null         
,@entityid bigint = null        
,@RegistrationFormLink nvarchar(max)=null        
,@Banner nvarchar(max)= null        
,@CompanyLogo nvarchar(max)= null        
,@filtertext nvarchar(max)=''      
,@registrationid bigint=null  
,@Isapproved bit =0  
,@mode varchar(100)          
AS          
BEGIN     
 Declare @parentid Bigint = (Select Parentid from User_Detail (NOLOCK) WHERE User_ID= @UserId)           
 declare @min int , @max int , @recurID int ,@joinurl nvarchar(1000) ,@urlid bigint        
 drop table if exists #tempTime           
 drop table if exists #tempUsers          
 drop table if exists #tempUsers2        
 drop table if exists #tempUsersHierarchy         
 drop table if exists #tempOutUsers  
 drop table if exists #tempRandExp  
 CREATE table #tempUsersHierarchy (USER_ID bigint, NAme nvarchar(100), Image nvarchar(max))        
 Create TAble #tempOutUsers ( ID Bigint Identity, MeetUserid bigint, MeetingID bigint, Mobile nvarchar(20) , Email nvarchar(100) )  
 Declare @lastRndExpID bigint , @usercount int   
 Insert into  #tempUsersHierarchy (USER_ID,Name,Image)        
 EXEC use_getuserdetails @UserID        
         
    Select top 1 @joinurl= [Url],@urlid=ID from tbl_MeetingJoinUrl where IsActive=1  
  
 IF @mode ='save'          
 BEGIN           
  IF @ID =0          
  Begin          
  Begin try  
   Insert INTO Tbl_Meeting (Meeting_Name, MeetingId, ParentId, UserId, welcome, duration, Isactive, Meeting_Status, Createddate, StartTime,LogoutURL, AutoStartRecording, MaxParticipants,          
          AllowStartStopRecording, MeetingExpireIfNoUserJoinedInMinutes,MeetingAgenda, MeetingType, ScheduledDate, WebCamOnlyforhost, AllowhosttoUnmuteUsers, AllowHosttoCloseUsersCamera          
         , MuteOnStart, DisbleCameraForUsers, DisblePrivateChatForUsers, DisablePublicChatForUsers, AudioJoin, SendChatTexttoUsers, SendRecordingToUsers, InviteParticipantsByMail,           
         InviteMailFrom, InviteMailSubject, InvitetempType, InvitetemplateId, InviteParticipantsByMailText, RemindParticipantsByMail, RemindMailFrom, RemindMailSubject, Remindtemplatetype,           
         RemindtemplateId, RemindParticipantsByMailText, RemindBeforeTime, InviteNonEnquiryLead, AddNewParticipantAsEnquiryLead, SourceName, AddPartType,RecurringEndByDate, RepeatType,           
         RepeatDays, RecurringEndAfterTimes, MeetStartTime, MeetEndTime, ismeeting, iswebinar, WebinarType,DisablemicForUsers,AuthForm, CreateMeetLink, JoinModeratorLink, JoinAttendeeLink,          
         Isregistration, regisFormname, ApprovalType, ApproverName, AapproverId, RegisStartDate, RegisEndDate, TotalRegisLimit, AllowBusinessEmail, BlockedEmailDomain, AllowAuthDomain,           
         AuthDomain, AllowJoinByMail, AllowDenyRegisbyCountry, allowCountry, denyCountry,FileAttachmentId,RegistrationFormLink,Banner,CompanyLogo,IsRecurring)           
          
   VALUES (@Meeting_Name, @MeetingId, @parentid, @UserId, @welcomeMessage, @duration, 1, @Meeting_Status, GETDATE(), @StartTime,@LogoutURL, @AutoStartRecording, @MaxParticipants,          
          @AllowStartStopRecording, @MeetingExpireIfNoUserJoinedInMinutes, @MeetingAgenda, @MeetingType, @ScheduledDate, @WebCamOnlyforhost, @AllowhosttoUnmuteUsers          
          , @AllowHosttoCloseUsersCamera, @MuteOnStart, @DisbleCameraForUsers, @DisblePrivateChatForUsers, @DisablePublicChatForUsers, @AudioJoin, @SendChatTexttoUsers          
          , @SendRecordingToUsers, @InviteParticipantsByMail, @InviteMailFrom, @InviteMailSubject, @InvitetempType, @InvitetemplateId, @InviteParticipantsByMailText          
          , @RemindParticipantsByMail, @RemindMailFrom, @RemindMailSubject, @Remindtemplatetype, @RemindtemplateId, @RemindParticipantsByMailText, @RemindBeforeTime, @InviteNonEnquiryLead          
          , @AddNewParticipantAsEnquiryLead, @SourceName, @AddPartType,@RecurringEndByDate, @RepeatType, @RepeatDays, @RecurringEndAfterTimes, @MeetStartTime, @MeetEndTime,@isMeeting          
          , @isWebinar, @WebinarType, @DisablemicForUsers,@AuthForm,@CreateMeetLink, @JoinModeratorLink, @JoinAttendeeLink, @Isregistration, @regisFormname, @ApprovalType, @ApproverName          
          ,@AapproverId, @RegisStartDate, @RegisEndDate, @TotalRegisLimit, @AllowBusinessEmail, @BlockedEmailDomain, @AllowAuthDomain, @AuthDomain, @AllowJoinByMail,           
          @AllowDenyRegisbyCountry, @allowCountry, @denyCountry,@Docid,@RegistrationFormLink,@Banner,@CompanyLogo,@IsRecurring)          
             
   SELECT @ID= SCOPE_IDENTITY()           
   --select  @id, @Isrecurring, @InviteParticipantsByMail        
   Select distinct * Into #tempUsers from OpenJson(@meetUsers)           
      with (          
       Entitytype nvarchar(max) '$.Entitytype',           
       EntityId  nvarchar(max) '$.EntityId',          
       EntityName  nvarchar(max) '$.EntityName',          
       EntityEmail  nvarchar(max) '$.EntityEmail',          
       EntityMobile nvarchar(max) '$.EntityMobile',          
       EntityRole  nvarchar(max) '$.EntityRole',          
       joinlink  nvarchar(max) '$.joinlink',  
    regisFormUrl nvarchar(max) '$.regisFormUrl'  
      )          
   --Select * from #tempUsers        
      Insert Into Tbl_MeetingUser( Meeting_ID, EntityID, Entity_Type, User_Role, Mobile, Email, UserName,  JoinLink, EntityName, RegistrationLink)   
   Output  inserted.ID As MeetUserid, inserted.Meeting_ID as MeetingID, inserted.Mobile AS Mobile, inserted.Email AS Email into #tempOutUsers  
      Select @ID, EntityId, Entitytype, EntityRole, EntityMobile, EntityEmail, EntityName, joinlink, EntityName, regisFormUrl from #tempUsers        
     
       Select top 1 @lastRndExpID= ISNULL(LastUsedRandomExp,0)  from tbl_MeetingJoinUrl (nolock) where IsActive=1 order by ID  
   select @usercount = count (1) from Tbl_MeetingUser (nolock) where Meeting_ID=@ID   
  
   Select ROW_NUMBER() Over(Order by ID desc) RowNo, ID,randomexp into #tempRandExp from randomexp (nolock) where Id >@lastRndExpID and Id <= @lastRndExpID + @usercount   
  
   Insert Into Tbl_MeetingUserJoinExpression(MeetingId, MeetUserId,Expression,Mode,ModeValue,Expiry,IsExpired)  
   Select MeetingID, MeetUserid,@joinurl+''+re.randomexp ,@AuthForm, Case WHEN tou.Email <> '' THEN  'Email' WHEN tou.Mobile <> '' THEN  'Mobile' Else '' END AS MODE, DATEADD(DAY,30,@MeetStartTime ) Expiry ,0 IsExpired from #tempOutUsers tou  
  Join #tempRandExp re on tou.ID=re.RowNo  
  
   Insert Into Tbl_MeetingUsedRandonExpression (RandonExpressionID,MeetingUserid)  
  Select Re.id, MeetUserid from #tempOutUsers tou  
  Join #tempRandExp re on tou.ID=re.RowNo  
         Update tbl_MeetingJoinUrl set LastUsedRandomExp = @lastRndExpID+@usercount where id=@urlid  
   IF @InviteParticipantsByMail =1          
   BEGIN          
 EXEC Usp_Meet_SendEmailToMeetingParticipants @MeetingId=@ID, @userid=@userid          
   END          
          
   Select @ID           
        end try  
 begin catch   
   EXEC usp_InsertErrorInfo        
        
 end catch  
  END          
  Else           
  BEGIN           
   Update Tbl_Meeting Set Meeting_Name =@Meeting_Name, MeetingId=@MeetingId, ParentId=@parentid, UserId =@UserId, welcome=@welcomeMessage, duration=@duration, Meeting_Status=@Meeting_Status,  StartTime=@StartTime,          
         LogoutURL=@LogoutURL, AutoStartRecording=@AutoStartRecording, MaxParticipants=@MaxParticipants,AllowStartStopRecording=@AllowStartStopRecording,           
         MeetingExpireIfNoUserJoinedInMinutes=@MeetingExpireIfNoUserJoinedInMinutes,MeetingAgenda=@MeetingAgenda, MeetingType=@MeetingType, ScheduledDate=@ScheduledDate, WebCamOnlyforhost=@WebCamOnlyforhost,          
         AllowhosttoUnmuteUsers=@AllowhosttoUnmuteUsers, AllowHosttoCloseUsersCamera=@AllowHosttoCloseUsersCamera          
         , MuteOnStart=@MuteOnStart, DisbleCameraForUsers=@DisbleCameraForUsers, DisblePrivateChatForUsers=@DisblePrivateChatForUsers, DisablePublicChatForUsers=@DisablePublicChatForUsers,          
         AudioJoin=@AudioJoin, SendChatTexttoUsers=@SendChatTexttoUsers, SendRecordingToUsers=@SendRecordingToUsers, InviteParticipantsByMail=@InviteParticipantsByMail, InviteMailFrom=@InviteMailFrom          
         , InviteMailSubject=@InviteMailSubject, InvitetempType=@InvitetempType, InvitetemplateId=@InvitetemplateId, InviteParticipantsByMailText=@InviteParticipantsByMailText,           
         RemindParticipantsByMail=@RemindParticipantsByMail, RemindMailFrom=@RemindMailFrom, RemindMailSubject=@RemindMailSubject, Remindtemplatetype=@Remindtemplatetype, RemindtemplateId=@RemindtemplateId          
         , RemindParticipantsByMailText=@RemindParticipantsByMailText, RemindBeforeTime=@RemindBeforeTime, InviteNonEnquiryLead=@InviteNonEnquiryLead, AddNewParticipantAsEnquiryLead=@AddNewParticipantAsEnquiryLead,          
         SourceName=@SourceName,AapproverId=@AapproverId, AddPartType =@AddPartType ,UpdatedBy = @UserId,Banner=@Banner,CompanyLogo=@CompanyLogo, UpdateedOn=GETDATE()          
         Where ID=@ID          
  END          
 END          
 ELSE IF @mode ='updatestatus'          
 BEGIN          
  UPDATE Tbl_Meeting SET Isactive =@Isactive where ID=@ID           
  Select CASE @Isactive WHEN 1 Then 'Meeting Activated' When 0 Then 'Meeting Deactivated' END           
 END          
          
 ELSE IF @mode ='Upcoming'          
 BEGIN          
 select [Sequence], B.ID, B.Meeting_Name, B.MeetingId, B.MeetStartDate, B.MeetStartTime, B.MeetEndTime, B.Duration, B.StartInMinutes, B.CohostCount, B.ParticipantCount,B.Host, B.CreateMeetLink        
  , B.Isactive, B.StartTime, B.EndTime, B.JoinLink, B.User_Role,B.meetingtype,B.Meeting_Status,B.Isregistration from (        
 Select  A.[Sequence], A.ID, A.Meeting_Name, A.MeetingId, A.MeetStartDate, A.MeetStartTime, A.MeetEndTime, A.Duration, A.StartInMinutes, A.CohostCount, A.ParticipantCount,A.Host, A.CreateMeetLink        
  , A.Isactive, A.StartTime, A.EndTime, A.JoinLink, A.User_Role,A.meetingtype,A.Meeting_Status,A.Isregistration        
  From (        
  select 0  [Sequence],mt.ID, mt.Meeting_Name, mt.MeetStartTime MeetDateTime, mt.MeetingId,         
  convert(varchar , dbo.fn_getusertimefromindiantime(@UserId, mt.MeetStartTime ), 106) MeetStartDate,           
    format(dbo.fn_getusertimefromindiantime(@UserId, mt.MeetStartTime ),'hh:mm tt') MeetStartTime , mt.MeetEndTime,          
    Convert(varchar,DATEDIFF(MINUTE,mt.MeetStartTime,mt.MeetEndTime )/60)  Duration,           
 Convert(Varchar(max),DATEDIFF(MINUTE,GETDATE(),mt.MeetStartTime ))  StartInMinutes,          
    (select Count(mtu.ID) from Tbl_MeetingUser (nolock)  mtu where mtu.Meeting_ID = mt.ID and (mtu.User_Role='cohost' or mtu.User_Role='host') ) CohostCount ,           
    (select Count(mtu.ID) from Tbl_MeetingUser (nolock) mtu where mtu.Meeting_ID = mt.ID and mtu.User_Role='participant' ) ParticipantCount,          
    --(select mtu.Email from Tbl_MeetingUser (nolock) mtu where mtu.Meeting_ID = mt.ID and mtu.User_Role='host' )   
 mtu.Email  Host, mt.CreateMeetLink,          
    mt.Isactive, mt.StartTime, mt.EndTime, mtu.JoinLink, mtu.User_Role,mt.meetingtype,mt.Meeting_Status,mt.Isregistration          
  from Tbl_Meeting (nolock)  mt          
  left join Tbl_MeetingUser (nolock) mtu on mt.ID=mtu.Meeting_ID         
  join #tempUsersHierarchy Uh on mt.UserId = Uh.USER_ID        
  where mt.Meeting_Status='Started'         
 and DateDIff(hour, mt.Starttime,GETDATE())< 12        
 and mtu.entityid=@UserId        
          
  UNION ALL         
        
  select  ROW_NUMBER() Over( Partition by Isactive Order by mt.MeetStartTime)  [Sequence], mt.ID, mt.Meeting_Name, mt.MeetStartTime MeetDateTime, mt.MeetingId,         
  convert(varchar , dbo.fn_getusertimefromindiantime(@UserId, mt.MeetStartTime ), 106) MeetStartDate,           
    format(dbo.fn_getusertimefromindiantime(@UserId, mt.MeetStartTime ),'hh:mm tt') MeetStartTime , mt.MeetEndTime,          
    Convert(varchar,DATEDIFF(MINUTE,mt.MeetStartTime,mt.MeetEndTime )/60)  Duration,           
    Convert(Varchar(max),DATEDIFF(MINUTE,GETDATE(),mt.MeetStartTime ))  StartInMinutes,          
    (select Count(mtu.ID) from Tbl_MeetingUser (nolock)  mtu where mtu.Meeting_ID = mt.ID and (mtu.User_Role='cohost' or mtu.User_Role='host') ) CohostCount ,           
    (select Count(mtu.ID) from Tbl_MeetingUser (nolock) mtu where mtu.Meeting_ID = mt.ID and mtu.User_Role='participant' ) ParticipantCount,          
    --(select mtu.Email from Tbl_MeetingUser (nolock)  mtu where mtu.Meeting_ID = mt.ID and mtu.User_Role='host' )  
 mtu.Email  Host, mt.CreateMeetLink,          
    mt.Isactive, mt.StartTime, mt.EndTime, mtu.JoinLink, mtu.User_Role,mt.meetingtype ,mt.Meeting_Status,mt.Isregistration         
  from Tbl_Meeting (nolock)  mt          
  left join Tbl_MeetingUser (nolock) mtu on mt.ID=mtu.Meeting_ID           
  join #tempUsersHierarchy Uh on mt.UserId = Uh.USER_ID        
  where mt.Starttime IS NULL and mt.MeetStartTime IS Not NULL        
  AND (@createFromDate IS NULL OR Createddate > @createFromDate)          
  AND (@createtodate IS NULL OR Createddate < @createtodate)           
  and mtu.entityid=@UserId and DATEDIFF(MINUTE,GETDATE(),mt.MeetStartTime )>=-15        
  )A        
  Where         
  (@Meeting_Name IS NULL OR Meeting_Name Like '%'+@Meeting_Name+'%')          
  AND (@Isactive IS NULL OR Isactive = @Isactive)           
  )B        
  Order by B.Sequence  Asc         
        
 END           
 ELSE IF @mode ='past'          
 BEGIN          
            
        
 Select distinct *  from (        
        
  select mt.ID, mt.Meeting_Name, mt.MeetingId,  convert(varchar , dbo.fn_getusertimefromindiantime(@UserId, mt.MeetStartTime ), 106) MeetStartDate,           
    format(dbo.fn_getusertimefromindiantime(@UserId, mt.MeetStartTime ),'hh:mm tt') MeetStartTime,          
    format(dbo.fn_getusertimefromindiantime(@UserId, mt.MeetStartTime ),'ddd') MeetStartday, mt.MeetEndTime,          
    Convert(varchar,DATEDIFF(MINUTE,mt.StartTime,mt.EndTime))  Duration,           
    (select Count(mtu.ID) from Tbl_MeetingUser (nolock) mtu where mtu.Meeting_ID = mt.ID and mtu.User_Role='participant' ) ParticipantCount,          
    (select Count(mtu.ID) from Tbl_MeetingUser (nolock) mtu where mtu.Meeting_ID = mt.ID and( mtu.User_Role='cohost' OR mtu.User_Role='host')) CohostCount,          
    (select Count(mtu.ID) from Tbl_MeetingUser (nolock) mtu where mtu.Meeting_ID = mt.ID and  mtu.User_Role='host') HostCount,          
    (select Count(mtu.UserJoined) from Tbl_MeetingUser (nolock) mtu where mtu.Meeting_ID = mt.ID and mtu.UserJoined=1 ) ParticipantJoined,          
    (select mtu.Email from Tbl_MeetingUser (nolock) mtu where mtu.Meeting_ID = mt.ID and mtu.User_Role='host' and mtu.EntityID=@userid  ) Host,          
    mt.Isactive, mt.StartTime, mt.EndTime,mt.MeetOutcome, mto.OutcomeName,mt.OutComeRemarks          
  from Tbl_Meeting (nolock)  mt          
  join Tbl_MeetingUser (nolock) mtu on mt.ID=mtu.Meeting_ID           
  left join tbl_meetingOutcome (nolock) mto on mto.id = mt.MeetOutcome            
  join #tempUsersHierarchy uh ON mt.Userid=uh.user_id         
  WHERE mt.Meeting_status='Ended'        
  UNION         
  select mt.ID, mt.Meeting_Name, mt.MeetingId,  convert(varchar , dbo.fn_getusertimefromindiantime(@UserId, mt.MeetStartTime ), 106) MeetStartDate,           
    format(dbo.fn_getusertimefromindiantime(@UserId, mt.MeetStartTime ),'hh:mm tt') MeetStartTime,          
    format(dbo.fn_getusertimefromindiantime(@UserId, mt.MeetStartTime ),'ddd') MeetStartday, mt.MeetEndTime,          
    Convert(varchar,DATEDIFF(MINUTE,mt.StartTime,mt.EndTime))  Duration,           
    (select Count(mtu.ID) from Tbl_MeetingUser (nolock) mtu where mtu.Meeting_ID = mt.ID and mtu.User_Role='participant' ) ParticipantCount,          
    (select Count(mtu.ID) from Tbl_MeetingUser (nolock) mtu where mtu.Meeting_ID = mt.ID and( mtu.User_Role='cohost' OR mtu.User_Role='host')) CohostCount,          
    (select Count(mtu.ID) from Tbl_MeetingUser (nolock) mtu where mtu.Meeting_ID = mt.ID and  mtu.User_Role='host') HostCount,          
    (select Count(mtu.UserJoined) from Tbl_MeetingUser (nolock) mtu where mtu.Meeting_ID = mt.ID and mtu.UserJoined=1 ) ParticipantJoined,          
    (select mtu.Email from Tbl_MeetingUser (nolock) mtu where mtu.Meeting_ID = mt.ID and mtu.User_Role='host' and mtu.EntityID=@userid  ) Host,          
    mt.Isactive, mt.StartTime, mt.EndTime,mt.MeetOutcome, mto.OutcomeName,mt.OutComeRemarks          
  from Tbl_Meeting (nolock)  mt          
  join Tbl_MeetingUser (nolock) mtu on mt.ID=mtu.Meeting_ID           
  left join tbl_meetingOutcome (nolock) mto on mto.id = mt.MeetOutcome            
  join #tempUsersHierarchy uh ON mt.Userid=uh.user_id        
  where mt.Isactive=1 and mt.StartTime IS NULL and mtu.EntityID=@UserId and DATEDIFF(hour,mt.MeetStartTime,getdate())>12        
  )A where         
  (@Meeting_Name IS NULL OR a.Meeting_Name Like '%'+@Meeting_Name+'%')          
  order by A.ID desc        
          
 END          
 Else IF @mode ='host'          
 BEGIN          
  Select User_ID as EntityID, User_Login as EntityName, EMail as Email , Mobile  as Mobile, 'User' as EntityType from User_Detail (NOLOCK) where ParentID= @parentid          
 END          
 Else IF @mode ='users'          
 BEGIN          
  Select Top 10 EntityID,EntityName,Email ,Mobile,EntityType  From(          
  Select User_ID as EntityID, User_Login as EntityName, EMail as Email , Mobile  as Mobile,'User' as EntityType           
  from User_Detail (NOLOCK)          
  where ParentID= @parentid           
  and( User_Login like '%'+@searchtext+'%'  OR FName like '%'+@searchtext+'%')          
  UNION ALL          
  Select EnquiryID as EntityID, PersonName as EntityName, EmailID as Email , MobileNo as Mobile,'Enquiry' as EntityType            
  from UserEnquiry (NOLOCK)          
  where ParentID= @parentid           
  and( PersonName like '%'+@searchtext+'%' OR EmailID like '%'+@searchtext+'%')           
  UNION ALL          
  Select ID as EntityID, PersonName as EntityName, EmailID as Email, MobileNo as Mobile,'Lead' as EntityType           
  from UserLeads (NOLOCK)          
  where ParentID= @parentid           
  and (PersonName like '%'+@searchtext+'%' OR EmailID like '%'+@searchtext+'%')          
  ) A          
 END          
 Else IF @mode ='participant'          
 BEGIN          
  Select ID, Meeting_ID, EntityName,  EntityID, Entity_Type, User_Role,  Mobile, Email, UserName,  JoinLink,UserJoined           
  from Tbl_MeetingUser (nolock)        
  where Meeting_ID = @ID           
 END          
 Else IF @mode='Start'          
 BEGIN          
  IF @returncode = 'SUCCESS'          
  BEGIN          
   Select [Name],[Value]          
   INTO #tempMeetResponce          
   from OpenJson (@startMeeting)           
    WITH(          
       Name nvarchar(max),          
      Value nvarchar(max)          
    )          
             
   Update Tbl_meeting set Meeting_Status='Started' , StartTime = getDate() where ID=@ID          
          
   Insert into Tbl_MeetingResponce(ReturnCode, ResponseJson, CreateDate, MeetingID)           
   Values(@returncode, @startMeeting, GETDATE(), @ID)          
   Select @returncode          
  END          
  Else           
  BEGIN          
  Update Tbl_meeting set Meeting_Status=@returncode where ID=@ID          
   Insert into Tbl_MeetingResponce(ReturnCode, ResponseJson, CreateDate, MeetingID)           
   Values(@returncode, @startMeeting, GETDATE(), @ID)          
   Select @returncode          
  END          
          
 END          
 Else IF @mode='End'          
 BEGIN          
  Update Tbl_meeting set Meeting_Status='Ended' , EndTime = getDate() where MeetingId=@MeetingId           
  select EndTime from Tbl_Meeting (nolock)  where MeetingId=@MeetingId          
 END          
  Else IF @mode='recordStatus'          
 BEGIN          
  Insert Into  Tbl_MeetingRecording (RecordResponse) values (@RecordResponse)           
 END          
 ELSE IF @mode ='UpLeadEnq'          
 BEGIN          
     
select [Sequence], B.ID, B.Meeting_Name, B.MeetingId, B.MeetStartDate, B.MeetStartTime, B.MeetEndTime, B.Duration, B.StartInMinutes, B.CohostCount, B.ParticipantCount,B.Host, B.CreateMeetLink        
  , B.Isactive, B.StartTime, B.EndTime, B.JoinLink, B.User_Role,B.meetingtype,B.Meeting_Status,B.Isregistration,B.participantJoinLink   from (        
 Select  A.[Sequence], A.ID, A.Meeting_Name, A.MeetingId, A.MeetStartDate, A.MeetStartTime, A.MeetEndTime, A.Duration, A.StartInMinutes, A.CohostCount, A.ParticipantCount,A.Host, A.CreateMeetLink        
  , A.Isactive, A.StartTime, A.EndTime, A.JoinLink, A.User_Role,A.meetingtype,A.Meeting_Status,A.Isregistration, A.participantJoinLink       
  From (        
  select 0  [Sequence],mt.ID, mt.Meeting_Name, mt.MeetStartTime MeetDateTime, mt.MeetingId,         
  convert(varchar , dbo.fn_getusertimefromindiantime(@UserId, mt.MeetStartTime ), 106) MeetStartDate,           
    format(dbo.fn_getusertimefromindiantime(@UserId, mt.MeetStartTime ),'hh:mm tt') MeetStartTime , mt.MeetEndTime,          
    Convert(varchar,DATEDIFF(MINUTE,mt.MeetStartTime,mt.MeetEndTime )/60)  Duration,           
    Convert(Varchar(max),DATEDIFF(MINUTE,GETDATE(),mt.MeetStartTime ))  StartInMinutes,          
    (select Count(mtu.ID) from Tbl_MeetingUser (nolock)  mtu where mtu.Meeting_ID = mt.ID and (mtu.User_Role='cohost' or mtu.User_Role='host') ) CohostCount ,           
    (select Count(mtu.ID) from Tbl_MeetingUser (nolock) mtu where mtu.Meeting_ID = mt.ID and mtu.User_Role='participant' ) ParticipantCount,          
    (select mtu.Email from Tbl_MeetingUser (nolock) mtu where mtu.Meeting_ID = mt.ID and mtu.User_Role='host' ) Host, mt.CreateMeetLink,     
 (select mtu.User_Role from Tbl_MeetingUser (nolock) mtu where mtu.Meeting_ID =mt.ID and mtu.EntityID= @UserId  ) User_Role,  
 (select mtu.JoinLink from Tbl_MeetingUser (nolock) mtu where mtu.Meeting_ID = mt.ID  and mtu.EntityID= @UserId   ) JoinLink,  
    mt.Isactive, mt.StartTime, mt.EndTime, mju.Expression as participantJoinLink , mt.meetingtype,mt.Meeting_Status,mt.Isregistration          
  from Tbl_Meeting (nolock)  mt          
  left join Tbl_MeetingUser (nolock) mtu on mt.ID=mtu.Meeting_ID       
  join Tbl_MeetingUserJoinExpression mju on mju.MeetUserId= mtu.ID  
  where mt.Meeting_Status='Started'         
 and DateDIff(hour, mt.Starttime,GETDATE())< 12        
 and mtu.entityid=@entityid        
          
  UNION ALL         
        
  select  ROW_NUMBER() Over( Partition by Isactive Order by mt.MeetStartTime)  [Sequence], mt.ID, mt.Meeting_Name, mt.MeetStartTime MeetDateTime, mt.MeetingId,         
  convert(varchar , dbo.fn_getusertimefromindiantime(@UserId, mt.MeetStartTime ), 106) MeetStartDate,           
    format(dbo.fn_getusertimefromindiantime(@UserId, mt.MeetStartTime ),'hh:mm tt') MeetStartTime , mt.MeetEndTime,          
    Convert(varchar,DATEDIFF(MINUTE,mt.MeetStartTime,mt.MeetEndTime )/60)  Duration,           
    Convert(Varchar(max),DATEDIFF(MINUTE,GETDATE(),mt.MeetStartTime ))  StartInMinutes,          
    (select Count(mtu.ID) from Tbl_MeetingUser (nolock)  mtu where mtu.Meeting_ID = mt.ID and (mtu.User_Role='cohost' or mtu.User_Role='host') ) CohostCount ,           
    (select Count(mtu.ID) from Tbl_MeetingUser (nolock) mtu where mtu.Meeting_ID = mt.ID and mtu.User_Role='participant' ) ParticipantCount,          
    (select mtu.Email from Tbl_MeetingUser (nolock)  mtu where mtu.Meeting_ID = mt.ID and mtu.User_Role='host' ) Host, mt.CreateMeetLink,      
 (select mtu.User_Role from Tbl_MeetingUser (nolock) mtu where mtu.Meeting_ID = mt.ID  and mtu.EntityID= @UserId   ) User_Role,  
 (select mtu.JoinLink from Tbl_MeetingUser (nolock) mtu where mtu.Meeting_ID = mt.ID  and mtu.EntityID= @UserId   ) JoinLink,  
    mt.Isactive, mt.StartTime, mt.EndTime, mju.Expression as participantJoinLink ,mt.meetingtype ,mt.Meeting_Status,mt.Isregistration         
  from Tbl_Meeting (nolock)  mt          
  left join Tbl_MeetingUser (nolock) mtu on mt.ID=mtu.Meeting_ID     
  join Tbl_MeetingUserJoinExpression mju on mju.MeetUserId= mtu.ID  
  where mt.Starttime IS NULL and mt.MeetStartTime IS Not NULL       
  and mt.Meeting_Status is null
  and mtu.entityid=@entityid and DATEDIFF(MINUTE,GETDATE(),mt.MeetStartTime )>=-15        
  )A       
  )B        
  Order by B.Sequence  Asc     
    
  --select ROW_NUMBER() Over( Partition by Isactive Order by mt.id) [Sequence] , mt.ID , mt.Meeting_Name, mt.MeetingId,  convert(varchar , dbo.fn_getusertimefromindiantime(@UserId, mt.MeetStartTime ), 106) MeetStartDate,         
  --  format(dbo.fn_getusertimefromindiantime(@UserId, mt.MeetStartTime ),'hh:mm tt') MeetStartTime ,         
  --  format(dbo.fn_getusertimefromindiantime(@UserId, mt.MeetEndTime),'hh:mm tt') MeetEndTime,        
  --  Convert(varchar,DATEDIFF(MINUTE,mt.MeetStartTime,mt.MeetEndTime )/60)  Duration,         
  --  Convert(Varchar(max),DATEDIFF(MINUTE,GETDATE(),mt.MeetStartTime ))  StartInMinutes,        
  --  (select mtu.Email from Tbl_MeetingUser (nolock) mtu where mtu.Meeting_ID = mt.ID and mtu.User_Role='host' ) Host, mt.CreateMeetLink,        
  --  mt.Isactive, mt.StartTime, mt.EndTime, mtu.JoinLink, mtu.User_Role        
  --from Tbl_MeetingUser  (nolock)  mtu        
  -- join Tbl_Meeting (nolock) mt on mt.ID=mtu.Meeting_ID         
  --where  mtu.EntityID=@entityid        
         
  --Order by mt.ID          
 END           
  ELSE IF @mode ='PastLeadEnq'          
 BEGIN          
    select ROW_NUMBER() Over( Partition by Isactive Order by mt.id) [Sequence] , mt.ID , mt.Meeting_Name, mt.MeetingId,         
    convert(varchar , dbo.fn_getusertimefromindiantime(@UserId, mt.MeetStartTime ), 106) MeetStartDate,         
    format(dbo.fn_getusertimefromindiantime(@UserId, mt.MeetStartTime ),'ddd') MeetStartday,        
    format(dbo.fn_getusertimefromindiantime(@UserId, mt.MeetStartTime ),'hh:mm tt') MeetStartTime ,         
    format(dbo.fn_getusertimefromindiantime(@UserId, mt.MeetEndTime),'hh:mm tt') MeetEndTime,        
    Convert(Varchar(max),DATEDIFF(MINUTE,mt.StartTime,mt.EndTime)) Duration,        
    (select mtu.Email from Tbl_MeetingUser (nolock) mtu where mtu.Meeting_ID = mt.ID and mtu.User_Role='host' ) Host,        
    mt.CreateMeetLink, mt.Isactive, mt.StartTime, mt.EndTime, mju.Expression as JoinLink, mtu.User_Role, mt.MeetOutcome, mto.OutcomeName,mt.OutComeRemarks        
  from Tbl_MeetingUser  (nolock)  mtu        
   join Tbl_Meeting (nolock) mt on mt.ID=mtu.Meeting_ID         
   left join Tbl_MeetingOutcome (nolock) mto on mt.Meetoutcome= mto.id      
   join Tbl_MeetingUserJoinExpression mju on mju.MeetUserId= mtu.ID  
  where  mtu.EntityID=@entityid        
          
  Order by mt.ID          
 END         
  ELSE IF @mode ='Edit'          
 BEGIN          
   SET @meetUsers = (Select Entity_Type, EntityId, EntityName, Email, Mobile, User_Role, JoinLink from Tbl_MeetingUser (nolock) where Meeting_ID=@ID for JSON AUTO);        
        
        
   select Meeting_Name, MeetingId, ParentId, UserId, welcome, duration, Isactive, Meeting_Status, Createddate, StartTime,LogoutURL, AutoStartRecording, MaxParticipants,          
          AllowStartStopRecording, MeetingExpireIfNoUserJoinedInMinutes,MeetingAgenda, MeetingType, ScheduledDate, WebCamOnlyforhost, AllowhosttoUnmuteUsers, AllowHosttoCloseUsersCamera          
         , MuteOnStart, DisbleCameraForUsers, DisblePrivateChatForUsers, DisablePublicChatForUsers, AudioJoin, SendChatTexttoUsers, SendRecordingToUsers, InviteParticipantsByMail,           
         InviteMailFrom, InviteMailSubject, InvitetempType, InvitetemplateId, InviteParticipantsByMailText, RemindParticipantsByMail, RemindMailFrom, RemindMailSubject, Remindtemplatetype,                  RemindtemplateId, RemindParticipantsByMailText, 
  
RemindBeforeTime, InviteNonEnquiryLead, AddNewParticipantAsEnquiryLead, SourceName, AddPartType,RecurringEndByDate, RepeatType,           
         RepeatDays, RecurringEndAfterTimes, MeetStartTime, MeetEndTime, ismeeting, iswebinar, WebinarType,DisablemicForUsers,AuthForm, CreateMeetLink, JoinModeratorLink, JoinAttendeeLink,          
         Isregistration, regisFormname, ApprovalType, ApproverName, AapproverId, RegisStartDate, RegisEndDate, TotalRegisLimit, AllowBusinessEmail, BlockedEmailDomain, AllowAuthDomain,           
         AuthDomain, AllowJoinByMail, AllowDenyRegisbyCountry, allowCountry, denyCountry,FileAttachmentId, @meetUsers MeetUsers        
   from Tbl_Meeting (nolock)        
  where  ID = @ID        
 END         
 Else IF @mode ='Cancel'        
 BEGIN         
 Update Tbl_Meeting set Meeting_Status='Cancelled' where ID= @ID        
 Select 'Meeting cancelled';        
 END        
 Else IF @mode ='Meetdetails'        
 BEGIN         
 Declare @details nvarchar(max)        
 select mt.ID,mt.Meeting_Name, mt.MeetingId,         
   convert(varchar , dbo.fn_getusertimefromindiantime(@userid,MeetStartTime),107) StartDate,        
   format(dbo.fn_getusertimefromindiantime(@userid, MeetStartTime ),'hh:mm tt') StartTime,        
   Convert(varchar,DATEDIFF(MINUTE,MeetStartTime,MeetEndTime )/60)  Duration,        
    (select mtu.EntityName from Tbl_MeetingUser(nolock) mtu where mtu.Meeting_ID = mt.ID and mtu.User_Role='host' ) Host,        
    convert(varchar , dbo.fn_getusertimefromindiantime(@userid,RegisStartDate),107) RegisStartDate,        
    format(dbo.fn_getusertimefromindiantime(@userid, RegisStartDate),'hh:mm tt') RegisStartTime,        
    convert(varchar , dbo.fn_getusertimefromindiantime(@userid,RegisEndDate),107) RegisEndDate,        
    format(dbo.fn_getusertimefromindiantime(@userid, RegisEndDate),'hh:mm tt') RegisEndTime,        
    mt.RegistrationFormLink, mju.Expression JoinLink, mu.user_role, mt.MeetingType, mt.Isregistration,mt.Meeting_Status        
 from Tbl_Meeting (nolock) mt         
 join Tbl_MeetingUser (nolock) mu on mt.id=mu.meeting_id     
 join Tbl_MeetingUserJoinExpression mju on mju.MeetUserId= mu.ID  
 where mt.id=@ID and mu.entityid=@userid        
 --Select @details MeetDetails        
        
 END        
 ElSE IF @mode='participants'        
 BEGIN        
         
 Declare @participants Nvarchar(max)  
    select @Isregistration =Isregistration from Tbl_Meeting (NOLOCK) where id=@ID   
 if @Isregistration = 0  
 BEGIN  
  Set @participants=( Select * from (  Select mu.EntityID,mu.Entity_Type,mu.User_Role,mu.EntityName,mu.Email,mu.Mobile ,'' CreatedOn,1 Isapproved, mje.Expression  JoinLink ,  
       'NO' Isregistration  
  from tbl_MeetingUser (nolock) mu    
  join Tbl_Meeting mt on mt.id=mu.meeting_id  
  join Tbl_MeetingUserJoinExpression (nolock) mje on mje.MeetUserId=mu.ID  
  where mu.Meeting_ID=@ID AND User_Role='participant') T For JSON AUTO)        
 END  
 if @Isregistration = 1  
 BEGIN  
  Set @participants=( Select * from (  Select mu.EntityID,mu.Entity_Type,mu.User_Role,mu.EntityName,mu.Email,mu.Mobile,ISNULL(Cast(mrf.CreatedOn as varchar),'') CreatedOn,ISNULL( mrf.Isapproved ,0) Isapproved  
  ,Case    
   when mt.Isregistration=1   
    then Case when 1=(Select 1 from Tbl_Meet_RegistrationFormData mrf where mu.EntityID=mrf.EntityID and mrf.Isapproved=1) then mje.Expression  
      ELSE mu.RegistrationLink END   
   else mje.Expression END JoinLink ,  
   iif(mrf.CreatedOn is  NULL , 'NO','YES' ) Isregistration  
     
  from tbl_MeetingUser (nolock) mu    
  join Tbl_Meeting mt on mt.id=mu.meeting_id  
  join Tbl_MeetingUserJoinExpression (nolock) mje on mje.MeetUserId=mu.ID  
  left join Tbl_Meet_RegistrationFormData mrf on mrf.EntityID=mu.EntityID  
  where mu.Meeting_ID=@ID AND User_Role='participant') T For JSON AUTO)        
 END  
  Select @participants Participants        
         
 END   
 ElSE IF @mode='registrants'        
 BEGIN        
 select @MeetingId = Meetingid from Tbl_Meeting (nolock) where id=@ID  
 Declare @registrants nvarchar(max)=''  
     set @registrants = (Select * from (select ID, MeetingId, Name, Mobile, Email, CreatedOn, Isapproved, Approvedtype  from  
  Tbl_Meet_RegistrationFormData (NOLOCK)  where @MeetingId=@MeetingId) T for json auto , Include_null_values )  
  
 Select @participants Registrants          
 END   
 ELSE IF @mode='saveapproved'  
 BEGIN  
 Update Tbl_Meet_RegistrationFormData set Isapproved=@Isapproved , AprroveUserid=@UserId where ID=@registrationid  
 Select 'Status Updated'  
 END  
  
  ElSE IF @mode='docdetails'        
 BEGIN        
 Declare @Docdetails nvarchar(max)        
 set @Docdetails=(select mtd.DocName,DocUrl,UploadUserid,type from Tbl_Meeting (nolock) mt         
  join Tbl_MeetingDocuments mtd on mt.FileAttachmentId =mtd.ID        
  Where mt.id=@ID FOR JSON AUTO)        
 SELECT @Docdetails        
 END        
 ELSE IF @mode='updatedoc'        
 BEGIN        
 Update Tbl_Meeting set FileAttachmentId=@Docid where id=@ID         
 Select 'File Updated'        
 END        
        
           
 ELSE IF @mode ='filterUpcom'          
 BEGIN          
 if(@filtertext<>'')        
 begin         
  set @filtertext = 'where '+@filtertext        
 END        
 Declare @sqls nvarchar(max)='        
 Select [Sequence], A.ID, A.Meeting_Name, A.MeetingId, A.MeetStartDate, A.MeetStartTime, A.MeetEndTime, A.Duration, A.StartInMinutes, A.CohostCount, A.ParticipantCount,A.Host, A.CreateMeetLink        
  , A.Isactive, A.StartTime, A.EndTime, A.JoinLink, A.User_Role, A.MeetingStartTime, A.MeetingEndTime, A.CreatedBy, A.CreatedDate,A.MeetingAgenda, A.Meeting_Status, A.OutcomeName         
  From (        
  select ROW_NUMBER() Over( Partition by Isactive Order by mt.id) [Sequence],mt.ID, mt.Meeting_Name, mt.MeetingId,         
  convert(varchar , dbo.fn_getusertimefromindiantime('+Cast(@UserId as varchar)+', mt.MeetStartTime ), 106) MeetStartDate,           
    format(dbo.fn_getusertimefromindiantime('+Cast(@UserId as varchar)+', mt.MeetStartTime ),''hh:mm tt'') MeetStartTime , mt.MeetEndTime,          
    Convert(varchar,DATEDIFF(MINUTE,mt.MeetStartTime,mt.MeetEndTime )/60)  Duration,           
    Convert(Varchar(max),DATEDIFF(MINUTE,GETDATE(),mt.MeetStartTime ))  StartInMinutes,          
    (select Count(mtu.ID) from Tbl_MeetingUser (nolock)  mtu where mtu.Meeting_ID = mt.ID and (mtu.User_Role=''cohost'' or mtu.User_Role=''host'') ) CohostCount ,           
    (select Count(mtu.ID) from Tbl_MeetingUser (nolock)  mtu where mtu.Meeting_ID = mt.ID and mtu.User_Role=''participant'' ) ParticipantCount,          
    (select mtu.Email from Tbl_MeetingUser (nolock)  mtu where mtu.Meeting_ID = mt.ID and mtu.User_Role=''host'' ) Host, mt.CreateMeetLink,          
    mt.Isactive, mt.StartTime, mt.EndTime, mtu.JoinLink, mtu.User_Role, mt.MeetStartTime MeetingStartTime, mt.MeetEndTime MeetingEndTime, ud.User_login CreatedBy, mt.CreatedDate,mt.MeetingAgenda,mt.Meeting_Status,        
 mto.OutcomeName        
        
  from Tbl_Meeting (nolock)  mt          
  left join Tbl_MeetingUser (nolock) mtu on mt.ID=mtu.Meeting_ID         
  join User_detail ud on ud.User_id=mt.UserId        
  left join tbl_meetingOutcome mto on mto.id=mt.MeetOutcome         
  where mt.EndTime IS NULL and mtu.EntityID='+Cast(@UserId as varchar)+'          
  )A '+@filtertext        
        
  print @sqls        
  Execute sp_executesql @sqls        
 END           
 ELSE IF  @mode= 'webforms'        
 BEGIN        
 Select FormId, FormName, url_script FROM WebFormTbl (nolock)  where parentid=@parentid        
 END       
 Else IF @mode='fltrfield'      
 BEGIN      
  Select      
  case COLUMN_NAME       
   when 'TempName'      
   then 'Template Name'      
   when 'UserId'      
   then 'Created By'      
   when 'regisFormname'      
   then 'Refistration Form Name'      
   when 'welcome'      
   then 'Welcome'      
  else COLUMN_NAME END COLUMN_NAME,      
  COLUMN_NAME fieldname,       
  case       
   when COLUMN_NAME = 'AuthFormId'       
    then 'NVARCHAR'      
   when COLUMN_NAME = 'CreatedBy'      
    then 'NVARCHAR'      
   when COLUMN_NAME ='InvitetemplateId'      
    then 'NVARCHAR'      
   when COLUMN_NAME ='SourceName'      
    then 'NVARCHAR'      
   when COLUMN_NAME = 'UpdatedBy'      
    then 'NVARCHAR'      
   when  UPPER(DATA_TYPE) = 'INT'      
   then 'NVARCHAR'      
   when  UPPER(DATA_TYPE) = 'BIGINT'      
   then 'NVARCHAR'      
   else UPPER(DATA_TYPE) end  DATA_TYPE      
  from INFORMATION_SCHEMA.COLUMNS      
  where TABLE_NAME='Tbl_Meeting'       
   and TABLE_CATALOG=DB_NAME()      
 and COLUMN_NAME NOT IN('ID','LogoutURL','Parentid','IsDefault', 'AddPartType','RemindBeforeTime','RemindtemplateId','Remindtemplatetype','InviteNonEnquiryLead','InviteParticipantsByMail'       
    ,'InvitetemplateId','InvitetempType','AuthFormId','AuthType','Webinartype','AapproverId','FileAttachmentId','MeetingId','record','RegistrationFormLink','CreateMeetLink','JoinAttendeeLink',      
    'JoinModeratorLink','CompanyLogo','RecurringParentID','AuthForm')      
  Order By COLUMN_NAME asc       
 END      
ELSE IF @mode=''        
BEGIN        
 Select User_ID as EntityID, User_Login as EntityName, EMail as Email , Mobile  as Mobile, 'Host' as EntityType from User_Detail (NOLOCK) where User_ID= @UserId        
END        
        
 drop table if exists #tempTime          
 drop table if exists #tempUsers           
 drop table if exists #tempUsers2           
 drop table if exists #tempMeetResponce          
END  
  


GO

/* ============================================================
   Procedure: [dbo].[Usp_meet_saveMeetingSetting]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_meet_saveMeetingSetting]   
@ID bigint = 0 ,  
@tempname nvarchar(max)=null ,  
@isMeeting bit=null ,  
@isWebinar bit=null ,  
@WebinarType nvarchar(10)=null ,  
@Agenda nvarchar(max)=null ,  
@welcomeMessage nvarchar(max)=null ,  
@autoStartRecording bit=null ,  
@allowStartStoprecording bit=null ,  
@sendrecordingtousers bit=null ,  
@maxparticipants int=null ,  
@meetingexpireifnousers int=null ,  
@webCamOnlyForHost bit=null ,  
@muteOnStart bit=null ,  
@AudioJoin bit=null ,  
@AlowHostToUnmuteUsers bit=null ,  
@DisablemicForUsers bit=null ,  
@AllowHosttoCloseUsersCam bit=null ,  
@DisablePrivateChat bit=null ,  
@DisablePublicChat bit=null ,  
@SendChatToUsers bit=null ,  
@AuthForm bigint=null ,  
@InviteByMail bit=null ,  
@InviteMailFrom nvarchar(max)=null ,  
@InviteMailSubject nvarchar(max)=null ,  
@InvitetempType nvarchar(15) = null,  
@InvitetemplateId bigint = null,  
@InviteMailMessage nvarchar(max)=null ,  
@InviteNonEnquiry bit=null ,  
@AddNewparticipant varchar(10)=null ,  
@AddPartType varchar(10)=null ,  
@SourceName bigint =null ,  
@RemindByMail bit=null ,  
@RemindMailFrom nvarchar(max)=null ,  
@RemindMailSubject nvarchar(max)=null ,  
@Remindtemplatetype nvarchar(15)=null,  
@RemindtemplateId bigint = null,  
@RemingMailMessage nvarchar(max)=null ,  
@remindMailBeforeTime nvarchar(max)=null   
,@Isregistration bit = null  
,@regisFormname bigint = null  
,@ApprovalType nvarchar(max)=null  
,@ApproverName nvarchar(max)=null  
,@AapproverId bigint = null  
,@RegisStartDate datetime = null  
,@RegisEndDate datetime = null  
,@TotalRegisLimit int = null  
,@AllowBusinessEmail  bit = null  
,@BlockedEmailDomain nvarchar(max) = null  
,@AllowAuthDomain bit = null  
,@AuthDomain nvarchar(max) =null  
,@AllowJoinByMail bit = null  
,@AllowDenyRegisbyCountry bit = null  
,@allowCountry nvarchar(max) = null  
,@denyCountry nvarchar(max)= null  
,@Banner nvarchar(max)= null  
,@CompanyLogo nvarchar(max)= null  
,@userid bigint =null   
,@isactive bit=null   
,@createdFromdate datetime =null  
,@createtodate datetime= null  
,@filtertext nvarchar(max)=''  
,@LogoutUrl nvarchar(max)=null  
,@mode nvarchar(20)  
  
  
AS   
BEGIN  
drop table if exists #tempUsersHierarchy     
 CREATE table #tempUsersHierarchy (USER_ID bigint, NAme nvarchar(100), Image nvarchar(max))    
     
 Insert into  #tempUsersHierarchy (USER_ID,Name,Image)    
 EXEC use_getuserdetails @UserID    
     
 DECLARE @parentid bigint = (SELECT parentid from User_Detail where user_id=@userid )  
 if @filtertext <> '' AND @filtertext IS NOT  NULL    
 begin     
  set @filtertext ='where '+@filtertext    
 end    
  
 IF @mode= 'save'  
 BEGIN  
  IF @id=0  
  BEGIN  
   INSERT INTO Tbl_MeetingSetting (TempName, Ismeeting, IsWebinar, Webinartype, MeetingAgenda, Welcome_Message, AutoStartRecording, AllowStartStopRecording, SendRecordingToUsers, MaxParticipants,  
   MeetingExpireIfNoUserJoinedInMinutes, WebCamOnlyForHost, MuteOnStart, AllowUsersToListenOnly, AllowHosttoUnmuteUsers, DisableUsersCamera, AllowHostToCloseUsersCam, DisablePrivateChat, DisablePublicChat,  
   SendChatTexttoUsers, AuthFormId, InviteParticipantsByMail, InviteFromMailID, InviteMailSubject, InviteParticipantsByMailText,InviteNonEnquiryLead, AddNewParticipantAsEnquiryLead, AddPartType, SourceName,   
   RemindParticipantsByMail, RemindFromMailID, RemindMailSubject, RemindParticipantsByMailText, RemindBeforeTime, InvitetempType, InvitetemplateId, Remindtemplatetype, RemindtemplateId,Isregistration,  
   regisFormname, ApprovalType, ApproverName, AapproverId, RegisStartDate, RegisEndDate, TotalRegisLimit, AllowBusinessEmail, BlockedEmailDomain, AllowAuthDomain, AuthDomain, AllowJoinByMail,  
   AllowDenyRegisbyCountry, allowCountry, denyCountry, Banner, CompanyLogo, CreatedBy, Parentid, CreatedOn, Isactive,LogoutURL)   
  
   VALUES (@tempname, @ismeeting, @iswebinar, @WebinarType, @Agenda, @welcomeMessage, @autoStartRecording, @allowStartStoprecording, @sendrecordingtousers, @maxparticipants, @meetingexpireifnousers,  
   @webCamOnlyForHost, @muteOnStart,@DisablemicForUsers, @AlowHostToUnmuteUsers, @AudioJoin , @AllowHosttoCloseUsersCam,  @DisablePrivateChat, @DisablePublicChat,  
   @SendChatToUsers, @AuthForm, @InviteByMail, @InviteMailFrom, @InviteMailSubject, @InviteMailMessage, @InviteNonEnquiry, @AddNewparticipant,@AddPartType, @SourceName, @RemindByMail, @RemindMailFrom,  
   @RemindMailFrom, @RemingMailMessage, @remindMailBeforeTime, @InvitetempType, @InvitetemplateId, @Remindtemplatetype, @RemindtemplateId,@Isregistration, @regisFormname, @ApprovalType, @ApproverName,  
   @AapproverId, @RegisStartDate, @RegisEndDate, @TotalRegisLimit, @AllowBusinessEmail, @BlockedEmailDomain, @AllowAuthDomain, @AuthDomain, @AllowJoinByMail, @AllowDenyRegisbyCountry, @allowCountry,  
   @denyCountry,@Banner, @CompanyLogo, @userid, @parentid, GetDate(), 1,@LogoutUrl )  
  
   Select @id=SCOPE_IDENTITY();  
  select 'Meeting Template Saved'  
  END  
  IF @id<>0  
  Begin  
   UPDATE Tbl_MeetingSetting Set TempName= @tempname, Ismeeting=@isMeeting, IsWebinar=@isWebinar, Webinartype=@WebinarType, MeetingAgenda=@Agenda, Welcome_Message=@welcomeMessage,  
   AutoStartRecording=@autoStartRecording, AllowStartStopRecording= @allowStartStoprecording, SendRecordingToUsers=@sendrecordingtousers, MaxParticipants=@maxparticipants,   
   MeetingExpireIfNoUserJoinedInMinutes=@meetingexpireifnousers, WebCamOnlyForHost= @webCamOnlyForHost, MuteOnStart=@muteOnStart, AllowUsersToListenOnly= @DisablemicForUsers,   
   AllowHosttoUnmuteUsers=@AlowHostToUnmuteUsers, DisableUsersCamera=@AudioJoin, AllowHostToCloseUsersCam= @AllowHosttoCloseUsersCam, DisablePrivateChat=@DisablePrivateChat,   
   DisablePublicChat=@DisablePublicChat, SendChatTexttoUsers = @SendChatToUsers, AuthFormId= @AuthForm, InviteParticipantsByMail=@InviteByMail, InviteFromMailID=@InviteMailFrom,   
   InviteMailSubject=@InviteMailSubject, InviteParticipantsByMailText=@InviteMailMessage, InviteNonEnquiryLead=@InviteNonEnquiry, AddNewParticipantAsEnquiryLead= @AddNewparticipant,  
   SourceName=@SourceName, RemindParticipantsByMail=@RemindByMail, RemindFromMailID=@RemindMailFrom, RemindMailSubject=@RemindMailSubject, RemindParticipantsByMailText=@RemingMailMessage,  
   RemindBeforeTime=@remindMailBeforeTime, Isregistration=@Isregistration, regisFormname=@regisFormname, ApprovalType=@ApprovalType, ApproverName=@ApproverName, AapproverId=@AapproverId,   
   RegisStartDate=@RegisStartDate, RegisEndDate=@RegisEndDate, TotalRegisLimit=@TotalRegisLimit, AllowBusinessEmail=@AllowBusinessEmail, BlockedEmailDomain=@BlockedEmailDomain, AllowAuthDomain=@AllowAuthDomain,  
   AuthDomain=@AuthDomain, AllowJoinByMail=@AllowJoinByMail, AllowDenyRegisbyCountry=@AllowDenyRegisbyCountry, allowCountry=@allowCountry, denyCountry =@denyCountry, Banner=@Banner,  
   CompanyLogo=@CompanyLogo, UpdateOn=GETDATE() ,UpdatedBy=@userid,LogoutURL=@LogoutUrl  
   WHERE ID =@ID  
   select 'Meeting Template Updated'  
  END  
    
 END  
 ELSE IF @mode='select'  
 BEGIN  
  Select ms.ID,TempName, Ismeeting, IsWebinar, Webinartype, MeetingAgenda, WebCamOnlyForHost, AllowUsersToListenOnly , DisablePrivateChat, DisableUsersCamera , AutoStartRecording,  
  convert(varchar,dbo.fn_getusertimefromindiantime(@userid,ms.CreatedOn),13) CreatedOn,  
   ud.User_Login ,InviteNonEnquiryLead, Isactive  
  from Tbl_MeetingSetting ms   
  Join User_Detail ud ON ms.CreatedBy= ud.User_ID  
  where ms.Parentid = @parentid   
  AND (@tempname IS NULL OR ms.TempName like '%'+@tempname+'%')  
  AND (@createdFromdate IS NULL OR ms.CreatedOn > @createdFromdate)  
  AND (@createtodate IS NULL OR ms.CreatedOn< @createtodate)  
  AND (@isactive IS NULL OR ms.Isactive = @isactive)  
  Order BY ms.ID Desc  
    
    
 END  
 ELSE IF @mode='delete'  
 BEGIN  
  Delete from Tbl_MeetingSetting where ID=@ID   
  Select 'Meeting Template deleted'  
 END   
 ELSE IF @mode='edit'  
 BEGIN  
  Select TempName, Ismeeting, IsWebinar, Webinartype, MeetingAgenda, Welcome_Message, AutoStartRecording, AllowStartStopRecording, SendRecordingToUsers, MaxParticipants,  
   MeetingExpireIfNoUserJoinedInMinutes, WebCamOnlyForHost, MuteOnStart, AllowUsersToListenOnly, AllowHosttoUnmuteUsers, DisableUsersCamera, AllowHostToCloseUsersCam, DisablePrivateChat, DisablePublicChat,  
   SendChatTexttoUsers, AuthFormId, InviteParticipantsByMail, InviteFromMailID, InviteMailSubject, InviteParticipantsByMailText,InviteNonEnquiryLead, AddNewParticipantAsEnquiryLead, AddPartType, SourceName,   
   RemindParticipantsByMail, RemindFromMailID, RemindMailSubject, RemindParticipantsByMailText, RemindBeforeTime, InvitetempType, InvitetemplateId, Remindtemplatetype, RemindtemplateId, Isregistration,  
   regisFormname, ApprovalType, ApproverName, AapproverId, RegisStartDate, RegisEndDate, TotalRegisLimit, AllowBusinessEmail, BlockedEmailDomain, AllowAuthDomain, AuthDomain, AllowJoinByMail,  
   AllowDenyRegisbyCountry, allowCountry, denyCountry, Banner, CompanyLogo, CreatedBy, Parentid,CreatedOn, Isactive,LogoutURL  
   from Tbl_MeetingSetting where ID = @ID  
 END  
  
 ELSE IF @mode='togglestatus'  
 BEGIN  
  update Tbl_MeetingSetting set Isactive=@isactive where id=@ID  
  
  select 'Meeting Template Status Changed to ' + Case @isactive when 1 then 'Active' when 0 then 'Inactive' end   
 END  
 Else IF @mode='fltrfield'  
 BEGIN  
  Select  
  case COLUMN_NAME   
   when 'TempName'  
   then 'Template Name'  
   when 'denyCountry'  
   Then 'DenyCountry'  
   when 'regisFormname'  
   Then 'Regisration Form Name'  
  
  else COLUMN_NAME END COLUMN_NAME,  
  COLUMN_NAME fieldname,   
  case    
   when COLUMN_NAME='AuthFormId'   
    then 'NVARCHAR'  
   when COLUMN_NAME='CreatedBy'  
    then 'NVARCHAR'  
   when COLUMN_NAME='InvitetemplateId'  
    then 'NVARCHAR'  
   when COLUMN_NAME='SourceName'  
    then 'NVARCHAR'  
   when COLUMN_NAME='UpdatedBy'  
    then 'NVARCHAR'  
   when UPPER(DATA_TYPE) = 'INT'  
   then 'NVARCHAR'  
   when UPPER(DATA_TYPE) = 'BIGINT'  
   then 'NVARCHAR'  
   when UPPER(DATA_TYPE) = 'VARCHAR'  
   then 'NVARCHAR'  
   else UPPER(DATA_TYPE) end  DATA_TYPE  
  from INFORMATION_SCHEMA.COLUMNS  
  where TABLE_NAME='Tbl_MeetingSetting'   
   and TABLE_CATALOG=DB_NAME()  
   and COLUMN_NAME NOT IN('ID','LogoutURL','Parentid','IsDefault', 'AddPartType','RemindBeforeTime','RemindtemplateId','Remindtemplatetype','InviteNonEnquiryLead','InviteParticipantsByMail'   
    ,'InvitetemplateId','InvitetempType','AuthFormId','AuthType','Webinartype','AapproverId','CompanyLogo')  
  Order By COLUMN_NAME asc  
 END  
  
 ELSE IF @mode='filter'  
 BEGIN  
 declare @sqls Nvarchar(max)= N'select A.ID,A.TempName, A.Ismeeting, A.IsWebinar, A.Webinartype, A.MeetingAgenda, A.WebCamOnlyForHost, A.AllowUsersToListenOnly , A.DisablePrivateChat, A.DisableUsersCamera , A.AutoStartRecording,  
   dbo.fn_getusertimefromindiantime('+CAST( @userid AS NVARCHAR)+',A.CreatedOn) CreatedOn,  
   A.CreatedBy User_Login ,A.InviteNonEnquiryLead, A.Isactive from (  
  Select ms.ID,ms.TempName, AddNewParticipantAsEnquiryLead, ms.AllowHostToCloseUsersCam ,ms.AllowHosttoUnmuteUsers, ms.AllowStartStopRecording, ms.AllowUsersToListenOnly, ms.AutoStartRecording, ms.CreatedOn  
  , ms.DisablePrivateChat, ms.DisablePublicChat, ms.DisableUsersCamera, ms.InviteFromMailID, ms.InviteMailSubject, ms.InviteParticipantsByMailText, ms.Isactive, ms.Ismeeting, ms.IsWebinar, ms.MaxParticipants  
  , ms.MeetingAgenda, ms.MeetingExpireIfNoUserJoinedInMinutes, ms.MuteOnStart, ms.RemindFromMailID, ms.RemindMailSubject, ms.RemindParticipantsByMail, ms.RemindParticipantsByMailText, ms.SendChatTexttoUsers  
  , ms.SendRecordingToUsers, uss.Name as SourceName, ud1.User_Login as UpdatedBy, ms.UpdateOn, ms.WebCamOnlyForHost, ms.Welcome_Message,   
  ud.User_Login as CreatedBy,ms.Webinartype,ms.InviteNonEnquiryLead  
  from Tbl_MeetingSetting ms   
   left JOIN UserSourceSettings uss ON ms.SourceName= uss.SourceID   
  Join User_Detail ud ON ms.CreatedBy= ud.User_ID   
   left Join User_Detail ud1 ON ms.UpdatedBy= ud1.User_ID   
    
  where ms.CreatedBy in (Select Userid from #tempUsersHierarchy))A   
  '+@filtertext+'  
  Order BY A.ID Desc'  
  
  print @sqls  
  execute sp_executesql @sqls  
    
 END  
 Else IF @mode ='settingslist'  
 BEGIN  
  Select ID, TempName,  CASE WHEN ismeeting=1 then 'Meeting' when iswebinar=1 then 'Webinar' end as MeetType From Tbl_MeetingSetting   
  where Parentid=@parentid   
  AND (@isMeeting IS NULL OR Ismeeting=@isMeeting)  
  and isactive=1
 END  
 END   
    
 --Usp_meet_saveMeetingSetting @mode='filter', @filtertext='A.Template Name LIKE ''%NewTest1%'' ', @userid=34594   
    




GO

/* ============================================================
   Procedure: [dbo].[Usp_Meet_SaveMeetingsUsersdetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROCEDURE [dbo].[Usp_Meet_SaveMeetingsUsersdetails]     
@userid BIGINT = NULL,    
@meetingid BIGINT = NULL,    
@meetUserJson Nvarchar(max) =NULL    
AS     
    
BEGIN    
Drop table if exists #tempOutUsers
Create TAble #tempOutUsers ( ID Bigint Identity, MeetUserid bigint, MeetingID bigint, Mobile nvarchar(20) , Email nvarchar(100) )
 Declare @lastRndExpID bigint , @usercount int ,@joinurl nvarchar(1000) , @AuthForm int, @MeetStartTime datetime, @urlid bigint
 Declare @registrationform nvarchar(max) = (select RegistrationFormLink  from Tbl_Meeting where id=@meetingid) 
 set @AuthForm = (Select AuthForm from Tbl_Meeting (nolock) where id=@meetingid )
 set @MeetStartTime = (Select MeetStartTime from Tbl_Meeting (nolock) where id=@meetingid )
  Select top 1 @joinurl= [Url],@urlid=ID from tbl_MeetingJoinUrl (nolock)  where IsActive=1

 Delete from Tbl_MeetingUser where Meeting_ID=@meetingid   

 Insert into Tbl_MeetingUser ( Meeting_ID, EntityID, Entity_Type, User_Role, Mobile, Email, UserName, EntityName,JoinLink,RegistrationLink) 
 Output  inserted.ID As MeetUserid, inserted.Meeting_ID as MeetingID, inserted.Mobile AS Mobile, inserted.Email AS Email into #tempOutUsers
 SELECT meetingID, EntityID, EntityType, UserRole, Mobile, Email, UserName,UserName, joinlink , @registrationform+ '&Entitytype=' + EntityType + '&EntityId='+ cast( EntityID as varchar)
 From OPENJSON (@meetUserJson)     
  with (     
   meetingID Bigint '$.meetingID',    
   EntityID Bigint '$.EntityID',    
   EntityType nvarchar(max) '$.EntityType',    
   UserRole nvarchar(max) '$.UserRole',       
   Mobile NVARCHAR(MAX) '$.Mobile',    
   Email NVARCHAR(MAX) '$.Email',    
   UserName NVARCHAR(MAX) '$.UserName',    
   joinlink NVARCHAR(MAX) '$.joinlink'  
   )    
  Select SCOPE_IDENTITY();    

    Select top 1 @lastRndExpID= ISNULL(LastUsedRandomExp,0)  from tbl_MeetingJoinUrl (nolock) where IsActive=1 order by ID
	  select @usercount = count (1) from Tbl_MeetingUser (nolock) where Meeting_ID=@meetingid 

	  Select ROW_NUMBER() Over(Order by ID desc) RowNo, ID,randomexp into #tempRandExp from randomexp (nolock) where Id >@lastRndExpID and Id <= @lastRndExpID + @usercount 

	  Insert Into Tbl_MeetingUserJoinExpression(MeetingId, MeetUserId,Expression,Mode,ModeValue,Expiry,IsExpired)
	  Select MeetingID, MeetUserid,@joinurl+''+re.randomexp ,@AuthForm,
	  Case WHEN tou.Email <> '' THEN  'Email' WHEN tou.Mobile <> '' THEN  'Mobile' Else '' END AS MODE, DATEADD(DAY,30,@MeetStartTime ) Expiry ,0 IsExpired from #tempOutUsers tou
		Join #tempRandExp re on tou.ID=re.RowNo

	  Insert Into Tbl_MeetingUsedRandonExpression (RandonExpressionID,MeetingUserid)
		Select Re.id, MeetUserid from #tempOutUsers tou
		Join #tempRandExp re on tou.ID=re.RowNo

	Update tbl_MeetingJoinUrl set LastUsedRandomExp = @lastRndExpID+@usercount where id=@urlid
END   
  
  



GO

/* ============================================================
   Procedure: [dbo].[Usp_meet_SaveMeetingWebFormRegistrationData]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_meet_SaveMeetingWebFormRegistrationData] 
@MeetingId varchar(max),
@WebformName varchar(max),
@Name varchar(max),
@Mobile varchar(max),
@CountryCode NVARCHAR(max) = '',
@Email varchar(max),
@Address varchar(max),
@Remarks varchar(max),
@Country varchar(max),
@State varchar(max),
@City varchar(max),
@CompanyName varchar(max),
@PinCode varchar(max),
@Parentid bigint, 
@joinlink nvarchar(max),
@EntityId bigint,
@Entitytype nvarchar(20)
As
BEGIN

	Declare @regisStartdate datetime, @regisEndDate datetime, @totalregisLimit bigint,@Sequence bigint, @ApprovalType nvarchar(20), @approverid bigint, @isapproved bit=0,
		@isinvitemail bit ,@InviteNonEnquiryLead bit, @addparttype varchar(20),@Source bigint, @inviteMessage nvarchar(max),@InviteMailSubject nvarchar(max),
		@InviteMailFrom nvarchar(max), @meetingrefID bigint

	Drop table if exists #tempOutUsers
	Create TAble #tempOutUsers ( ID Bigint Identity, MeetUserid bigint, MeetingID bigint, Mobile nvarchar(20) , Email nvarchar(100) )
	Declare @lastRndExpID bigint , @usercount int ,@joinurl nvarchar(1000) , @AuthForm int, @MeetStartTime datetime,@urlid bigint

	 Select top 1 @joinurl= [Url],@urlid=ID from tbl_MeetingJoinUrl where IsActive=1

	DECLARE @entid BIGINT = 0;
	DECLARE @formid BIGINT = 0;
	DECLARE @MediumID BIGINT = 0;
	DECLARE @Sourceid BIGINT = 0;
	DECLARE @isenquery BIT;
	DECLARE @userid BIGINT = 0;
	DECLARE @EnquiryID BIGINT = 0;

	SELECT @formid = formid
		,@MediumID = MediumID
		,@Sourceid = Sourceid
		,@isenquery = isEnquiry
		,@userid = userid
	FROM WebFormTbl(NOLOCK)
	WHERE ParentId = @Parentid
		AND FormName = @WebformName;

	select @meetingrefID=ID, @regisStartdate=RegisStartDate,@regisEndDate=RegisEndDate,@totalregisLimit=TotalRegisLimit, @ApprovalType=ApprovalType, @approverid=AapproverId,
			@isinvitemail=InviteParticipantsByMail,@InviteNonEnquiryLead=InviteNonEnquiryLead,@addparttype=AddPartType,@Source=SourceNAme,
			@inviteMessage=InviteParticipantsByMailText,@InviteMailSubject =InviteMailSubject
	from Tbl_Meeting where MeetingId=@MeetingId
	
		if(ISNULL(@ApprovalType,'auto')='auto')
		begin
			set @isapproved =1
			set @ApprovalType='auto'
		END
		Select @Sequence = ISNULL (MAx ([Sequence]),0) + 1 from 	Tbl_Meet_RegistrationFormData	where MeetingId=@MeetingId 

		select @ApprovalType , @Sequence, @regisStartdate,@regisEndDate ,@totalregisLimit

		if @regisStartdate is null and @regisEndDate is null
		begin
			INSERT INTO Tbl_Meet_RegistrationFormData (MeetingId, WebformName, Name, Mobile, Email, Address, Remarks, Country, State, City, CompanyName, PinCode, Parentid, Source,
			Sequence, AprroveUserid, Isapproved, Approvedtype,joinlink,EntityID,Entitytype)
			Select @MeetingId, @WebformName, @Name, @Mobile, @Email, @Address, @Remarks, @Country, @State, @City, @CompanyName, @PinCode, @Parentid, @Source, @Sequence,
				@approverid, @isapproved, @ApprovalType,@joinlink,@EntityId,@Entitytype
			SELECT @entid = SCOPE_IDENTITY();
		end
		else if @regisStartdate is not null and @regisStartdate > GetDate()
		begin
			Select 'Registration not started yet'
		end
		Else if @regisEndDate is not null and @regisEndDate < getdate()
		begin
			Select 'Registration for meeting ended '
		end
		else if @regisStartdate < GetDate() and  @regisEndDate > getdate()
		begin
			if isnull(@totalregisLimit,0) =0
			begin
				INSERT INTO Tbl_Meet_RegistrationFormData (MeetingId, WebformName, Name, Mobile, Email, Address, Remarks, Country, State, City, CompanyName, PinCode, Parentid, Source,
					Sequence, AprroveUserid, Isapproved, Approvedtype,EntityID,Entitytype)
				Select @MeetingId, @WebformName, @Name, @Mobile, @Email, @Address, @Remarks, @Country, @State, @City, @CompanyName, @PinCode, @Parentid, @Source, @Sequence,
					@approverid, @isapproved, @ApprovalType,@EntityId,@Entitytype
				SELECT @entid = SCOPE_IDENTITY();
			end
			else if @totalregisLimit > 0 and @Sequence < @totalregisLimit
			BEGIN
				INSERT INTO Tbl_Meet_RegistrationFormData (MeetingId, WebformName, Name, Mobile, Email, Address, Remarks, Country, State, City, CompanyName, PinCode, Parentid, Source,
					Sequence, AprroveUserid, Isapproved, Approvedtype,EntityID,Entitytype)
				Select @MeetingId, @WebformName, @Name, @Mobile, @Email, @Address, @Remarks, @Country, @State, @City, @CompanyName, @PinCode, @Parentid, @Source, @Sequence,
					@approverid, @isapproved, @ApprovalType,@EntityId,@Entitytype
				SELECT @entid = SCOPE_IDENTITY();
			END
			else 
			begin
				Select 'Registration for meeting closed'
			end
		ENd
		if(@InviteNonEnquiryLead=1)
		BEGIN
			if(@addparttype='enquiry')
			BEGIN
				EXEC USp_AddLeadEnquiryFromMeetingRegistration @Entitytype='enquiry',@MeetingId=@MeetingId, @Name=@Name, @CountryCode=@CountryCode, @Mobile=@Mobile, @Email=@Email
				, @Address=@Address, @Remarks=@Remarks, @Country=@Country, @State=@State, @City=@City, @CompanyName=@CompanyName, @PinCode=@PinCode, @Parentid=@Parentid, @Sourceid=@Source
				,@MediumID=@MediumID, @userid= @Parentid,@entid=@entid
			END
			if(@addparttype='lead')
			BEGIN
				EXEC USp_AddLeadEnquiryFromMeetingRegistration @Entitytype='lead',@MeetingId=@MeetingId, @Name=@Name, @CountryCode=@CountryCode, @Mobile=@Mobile, @Email=@Email
				, @Address=@Address, @Remarks=@Remarks, @Country=@Country, @State=@State, @City=@City, @CompanyName=@CompanyName, @PinCode=@PinCode, @Parentid=@Parentid, @Sourceid=@Source
				,@MediumID=@MediumID, @userid= @Parentid, @entid=@entid
			END
		END
		if @ApprovalType='auto'
		BEGIN
			
			if NOT EXISTS (select 1 from Tbl_MeetingUser (Nolock) where EntityID=@EntityId and Entity_Type=@Entitytype and Meeting_ID= @meetingrefID)
			BEGIN
			Insert Into Tbl_MeetingUser( Meeting_ID, EntityID, Entity_Type, User_Role, Mobile, Email, UserName,  JoinLink, EntityName)  
			SELECT @meetingrefID, @entid, 'Registration', 'participant', @Mobile, @Email,@Name,@joinlink,@Name 
			EXEC Usp_Meet_SendEmailToMeetingParticipants   @MeetingId=@meetingrefID, @userid=@userid 
			
			--set @AuthForm = (Select AuthForm from Tbl_Meeting (nolock) where id=@meetingrefID )
			--set @MeetStartTime = (Select MeetStartTime from Tbl_Meeting (nolock) where id=@meetingrefID )

			-- Select top 1 @lastRndExpID= ISNULL(LastUsedRandomExp,0)  from tbl_MeetingJoinUrl (nolock) where IsActive=1 order by ID
			--select @usercount = count (1) from Tbl_MeetingUser (nolock) where Meeting_ID=@meetingrefID 

			--Select ROW_NUMBER() Over(Order by ID desc) RowNo, ID,randomexp into #tempRandExp from randomexp (nolock) where Id >@lastRndExpID and Id <= @lastRndExpID + @usercount 

			--Insert Into Tbl_MeetingUserJoinExpression(MeetingId, MeetUserId,Expression,Mode,ModeValue,Expiry,IsExpired)
			--Select MeetingID, MeetUserid,@joinurl+''+re.randomexp ,@AuthForm,
			--Case WHEN tou.Email <> '' THEN  'Email' WHEN tou.Mobile <> '' THEN  'Mobile' Else '' END AS MODE, DATEADD(DAY,30,@MeetStartTime ) Expiry ,0 IsExpired from #tempOutUsers tou
			--	Join #tempRandExp re on tou.ID=re.RowNo

			--Insert Into Tbl_MeetingUsedRandonExpression (RandonExpressionID,MeetingUserid)
			--	Select Re.id, MeetUserid from #tempOutUsers tou
			--	Join #tempRandExp re on tou.ID=re.RowNo
				END
		END
END





GO

/* ============================================================
   Procedure: [dbo].[Usp_Meet_SendEmailToMeetingParticipants]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_Meet_SendEmailToMeetingParticipants]           
@MeetingId bigint,      
@userid bigint  
As       
BEGIN      
      
 Drop Table IF Exists #temp       
 Declare @fromMailId nvarchar(max), @Subject nvarchar(max), @Message nvarchar(max), @parentid bigint,@Ismonitor bit=1, @mailcount int      
 Select @mailcount = Count (EntityId) from Tbl_MeetingUser where Meeting_ID=@MeetingId       
 Select @parentid=parentid from User_Detail where User_id=@userid      
 DECLARE @CurrentBalance BIGINT = (                                    
             SELECT TOP 1 mcd.Balance                                    
             FROM   MailCreditDetails AS mcd   (nolock)                                 
             WHERE  mcd.[User_ID] = @parentid                                    
             ORDER BY mcd.Credit_ID DESC                                    
         )                                                
                                
 DECLARE @Balance BIGINT = @CurrentBalance - @MailCount       
 IF @Balance>0      
 begin      
 SELECT @fromMailId=InviteMailFrom, @Subject=InviteMailSubject, @Message=InviteParticipantsByMailText from tbl_Meeting  where ID=@MeetingId       
       
 Declare @Status Bigint=0,@CountLimit bigint = 0                          
   select @Status = status,@CountLimit = Plimit from ProcessMailLimit                                 
      if(@Status = 1)                          
      Begin                          
    Begin                          
      if(@MailCount >  @CountLimit )                          
      Begin                          
       set @IsMonitor = 0                           
      End                          
     End                          
       End         
      
 DECLARE @BatchID BIGINT              
 begin tran                                        
 INSERT INTO GetBatchRecord                                    
       (                                    
         [User_id],                                    
         RandNum                                    
       )                       
     VALUES                                    
       (                                    
         @userid,                                    
         @userid                                    
       )                                          
 select @BatchID=SCOPE_IDENTITY()                                         
 DELETE FROM GetBatchRecord WHERE batchid=@BatchID              
 commit         
       
   select Meeting_ID, @fromMailId FrommailID , Email,  dbo.Fun_GetMeetingMailMessage ( @Subject, @userid, @MeetingId, EntityID)  MailSubject, '' MailTempleteName, getDate() mailDate, @userid MailUserid, @parentid MailParentID,   
   @fromMailId MailReplyto, @BatchID BatchID, 1 MailPriorty, '' MailScheduledDate, '' MailScheduledtime, '' MailAttachment,   
   dbo.Fun_GetMeetingMailMessage ( @Message, @userid, @MeetingId, EntityID) MailBody, @Ismonitor Ismonitor ,0 TemplateID,@mailCount MailCount,'InviteMeetingMail' MailSource      
    into #temp  from Tbl_MeetingUser where Meeting_ID =@MeetingID and ISNULL(IsInviteMailSend,'0') =0        
               
  insert into CloneEmailsFilter( Mail_FromEmail, Mail_ToEmail, Mail_Subject, Mail_TempleteName, Messages, Mail_InsertedDate, Mail_UserID, Mail_ParentID, ReplyTo, Mail_BatchID,              
        Mail_Priority,Mail_ScheduleDate,Mail_ScheduledTime,Mail_Attechement, Mail_TempleteBody, IsMonitor,TemplateID,Count,Source)           
  Select  FrommailID , Email, MailSubject, MailTempleteName, MailBody, mailDate, MailUserid, MailParentID, MailReplyto, BatchID,   
   MailPriorty, MailScheduledDate, MailScheduledtime, MailAttachment, MailBody, Ismonitor ,  TemplateID, MailCount, MailSource   
 From #temp      
      
 update mu set  mu.IsInviteMailSend =1  
 from tbl_meetingUser mu  
 join #temp tp on mu.Meeting_ID = tp.Meeting_ID  
 END      
 Drop Table IF Exists #temp       
END 




GO

/* ============================================================
   Procedure: [dbo].[Usp_Meet_SendReminderEmailToMeetingParticipants]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_Meet_SendReminderEmailToMeetingParticipants] 
@SettingId bigint ,
@MeetingId bigint,
@userid bigint
As 
BEGIN

	Drop Table IF Exists #temp 
	Declare @fromMailId nvarchar(max), @Subject nvarchar(max), @Message nvarchar(max), @parentid bigint,@Ismonitor bit=1, @mailcount int
	Select @mailcount = Count (EntityId) from Tbl_MeetingUser where Meeting_ID=@MeetingId 
	Select @parentid=parentid from User_Detail where User_id=@userid
	DECLARE @CurrentBalance BIGINT = (                              
             SELECT TOP 1 mcd.Balance                              
             FROM   MailCreditDetails AS mcd   (nolock)                           
             WHERE  mcd.[User_ID] = @parentid                              
             ORDER BY mcd.Credit_ID DESC                              
         )                                          
                          
	DECLARE @Balance BIGINT = @CurrentBalance - @MailCount 
	IF @Balance>0
	begin
	SELECT @fromMailId=RemindMailFrom, @Subject=RemindMailSubject, @Message=RemindParticipantsByMailText from tbl_Meeting where ID=@MeetingId 

	SET @message = (Select * From dbo.Fun_GetMeetingMailMessage(@Message,@userid,@meetingid)) 

	Declare @Status Bigint=0,@CountLimit bigint = 0                    
   select @Status = status,@CountLimit = Plimit from ProcessMailLimit                           
      if(@Status = 1)                    
      Begin                    
    Begin                    
      if(@MailCount >  @CountLimit )                    
      Begin                    
       set @IsMonitor = 0                     
      End                    
     End                    
       End   

	DECLARE @BatchID BIGINT        
	begin tran                                  
	INSERT INTO GetBatchRecord                              
	      (                              
	        [User_id],                              
	        RandNum                              
	      )                 
	    VALUES                              
       (                              
         @userid,                              
         @userid                              
       )                                    
	select @BatchID=SCOPE_IDENTITY()                                   
	DELETE FROM GetBatchRecord WHERE batchid=@BatchID        
	commit   
	
			select @fromMailId FrommailID , Email, @Subject MailSubject, '' MailTempleteName, @Message MailMessage, getDate() mailDate, @userid MailUserid, @parentid MailParentID, @fromMailId MailReplyto, @BatchID BatchID, 1 MailPriorty 
					, '' MailScheduledDate, '' MailScheduledtime, '' MailAttachment, @Message MailBody, @Ismonitor Ismonitor ,0 TemplateID,@mailCount MailCount,'InviteMeetingMail' MailSource
				into #temp  from Tbl_MeetingUser where Meeting_ID =@MeetingID  
			      
		insert into CloneEmailsFilter(Mail_FromEmail,Mail_ToEmail,Mail_Subject,Mail_TempleteName,Messages,Mail_InsertedDate,Mail_UserID,Mail_ParentID,ReplyTo,Mail_BatchID,        
		Mail_Priority,Mail_ScheduleDate,Mail_ScheduledTime,Mail_Attechement,Mail_TempleteBody,IsMonitor,TemplateID,Count,Source)     
		Select  FrommailID , Email, MailSubject, MailTempleteName, MailMessage, mailDate, MailUserid, MailParentID, MailReplyto, BatchID, MailPriorty, MailScheduledDate, MailScheduledtime, MailAttachment, MailBody, Ismonitor ,
		TemplateID, MailCount, MailSource From #temp

	END
	Drop Table IF Exists #temp 
END



