/* ============================================================
   Procedure: [dbo].[USp_MeetShareMeetingurl]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[USp_MeetShareMeetingurl] 
@participants nvarchar(max)=null,
@maildata nvarchar(max),
@userid bigint,
@mode nvarchar(50)='mail'
AS 
BEGIN
		drop table if exists #tmpflind
		drop table if exists #tmpflint
	Declare @meetingID varchar(100), @Account varchar(100),@SenderName nvarchar(max), @EmailType nvarchar(10),@Subject nvarchar(max),@Message nvarchar(max),@Template varchar(100), 
			@ReplyTo nvarchar(max),@FromMailID nvarchar(max), @joinlink nvarchar(max), @parentid bigint, @BatchID bigint, @Ismonitor bit=1, @mailcount int, @Balance BIGINT,
			 @CurrentBalance BIGINT

			Select @parentid= Parentid from User_Detail (nolock) where User_id=@userid
	if @mode='mail'
	BEGIN
			Drop TAble if exists #tempParticipants
			Drop TAble if exists #tempMessage
			CREate Table #tempParticipants (Meetingid varchar(100), Entitytype nvarchar(max),EntityId nvarchar(max),EntityName nvarchar(max),EntityEmail nvarchar(max),EntityMobile nvarchar(max), EntityRole nvarchar(max), joinlink nvarchar(max))
			
			Select @meetingID = meetingID, @Account=Account, @SenderName=SenderName, @EmailType=EmailType, @Subject=Subject, @Message=Message,@Template= Template, 
				@ReplyTo=ReplyTo, @FromMailID =FromMailID 
				from OPENJSON(@maildata) 
				with ( meetingID varchar(100),  Account varchar(100), SenderName nvarchar(max),  EmailType nvarchar(10), Subject nvarchar(max), Message nvarchar(max), Template varchar(100), 
			 ReplyTo nvarchar(max), FromMailID nvarchar(max))

			 select @joinlink=JoinAttendeeLink from Tbl_Meeting where ID=@meetingID 

			 insert into #tempParticipants (Meetingid, Entitytype  ,EntityId  ,EntityName  ,EntityEmail  ,EntityMobile  , EntityRole, joinlink)
			 Select @meetingID, Entitytype  ,EntityId  ,EntityName  ,EntityEmail  ,EntityMobile  , EntityRole,  REPLACE(@joinlink,'#username#',trim(Entityname)) joinlink  from openJSON(@participants) with (
			 Entitytype nvarchar(max),EntityId nvarchar(max),EntityName nvarchar(max),EntityEmail nvarchar(max),EntityMobile nvarchar(max), EntityRole nvarchar(max)) 

			 Insert Into Tbl_MeetingUser( Meeting_ID, EntityID, Entity_Type, User_Role, Mobile, Email, UserName,  JoinLink, EntityName) 
			 Select Meetingid, tp.EntityId  ,Entitytype  ,EntityRole   ,EntityMobile, EntityEmail   ,tp.EntityName , tp.joinlink,tp.EntityName from #tempParticipants tp
					where EntityId not in (Select EntityId from Tbl_MeetingUser mu (nolock) where mu.meeting_id=@meetingID) 
			
			

			 set @CurrentBalance = (                                  
             SELECT TOP 1 mcd.Balance                                  
             FROM   MailCreditDetails AS mcd   (nolock)                               
             WHERE  mcd.[User_ID] = @parentid                                  
             ORDER BY mcd.Credit_ID DESC                                  
         )                                              
             Select @mailcount = Count (EntityId) from #tempParticipants where MeetingID=@MeetingId    
			 
			set @Balance = @CurrentBalance - @MailCount     
		IF @Balance>0    
		 begin       
			 
			 Declare @Status Bigint=0,@CountLimit bigint = 0                        
			   select @Status = status,@CountLimit = Plimit from ProcessMailLimit                               
				  if(@Status = 1)                        
				  Begin                        
				Begin                        
				  if(@MailCount >  @CountLimit )                        
				  Begin                        
				   set @IsMonitor = 0                         
				  End                        
				 End                        
       End       
			begin tran                                      
				INSERT INTO GetBatchRecord([User_id], RandNum) VALUES (@userid,@userid)                                        
				select @BatchID=SCOPE_IDENTITY()                                       
				DELETE FROM GetBatchRecord WHERE batchid=@BatchID            
			commit       
			
			select  @fromMailId FrommailID , EntityEmail as Email, dbo.Fun_GetMeetingMailMessage ( @Subject, @userid, @MeetingId, EntityID)  MailSubject, '' MailTempleteName, getDate() mailDate, @userid MailUserid, @parentid MailParentID, 
			@fromMailId MailReplyto, @BatchID BatchID, 1 MailPriorty, '' MailScheduledDate, '' MailScheduledtime, '' MailAttachment, 
			dbo.Fun_GetMeetingMailMessage ( @Message, @userid, @MeetingId, EntityID) MailBody, @Ismonitor Ismonitor ,@Template TemplateID ,@mailCount MailCount,'InviteMeetingMail' MailSource    
			into #tempMessage  from #tempParticipants where MeetingID =@MeetingID 
             
			insert into CloneEmailsFilter(	Mail_FromEmail, Mail_ToEmail, Mail_Subject, Mail_TempleteName, Messages, Mail_InsertedDate, Mail_UserID, Mail_ParentID, ReplyTo, Mail_BatchID,            
								Mail_Priority,Mail_ScheduleDate,Mail_ScheduledTime,Mail_Attechement, Mail_TempleteBody, IsMonitor,TemplateID,Count,Source)         
		 Select  FrommailID , Email, MailSubject, MailTempleteName, MailBody, mailDate, MailUserid, MailParentID, MailReplyto, BatchID, 
			MailPriorty, MailScheduledDate, MailScheduledtime, MailAttachment, MailBody, Ismonitor ,  TemplateID, MailCount, MailSource 
			From #tempMessage    
			 
			 Update tu set tu.IsInviteMailSend=1
			 from Tbl_MeetingUser tu join
			 #tempParticipants tp on tu.Entity_Type=tp.EntityId and tu.Meeting_ID=@meetingID
			 Select 'Mail Send'
	END
		
	END 

	if @mode='sms'
	BEGIN
	declare  @SenderID NVARCHAR(100), @IsUnicode BIT,  @DLTTemplateID nvarchar(200)
		 
			Select @meetingID = meetingID, @Account=Account, @SenderID =SenderID,@SenderName=SenderName, @Message=Message,@DLTTemplateID= Template, @IsUnicode=IsUnicode
				from OPENJSON(@maildata) 
				with ( meetingID varchar(100),  Account varchar(100),SenderID nvarchar(100), SenderName nvarchar(max),  Message nvarchar(max), Template varchar(100),IsUnicode bit 
				,LongURL nvarchar(max),InvModuleEntity nvarchar(max),InvModuleEntityId nvarchar(max) )

		begin tran                        
		 -- BatchID -- this column value is auto-generated
			INSERT INTO GetBatchRecord   ([User_id],RandNum   )  VALUES   (@Account, @Account)                          
			select @batchid=scope_identity()                    
			delete from getbatchrecord where batchid=@batchid                    
			commit                
			                                    
 CREATE TABLE #tmpflint(                                      
 [BatchID] [bigint]  NULL,                                      
 [Country_code] [varchar](10) NULL,                                      
 [Mobile] [varchar](20) NULL,                                      
 [Message] [nvarchar](2500) NULL,                                      
 [MessageStatus] [varchar](20) NULL,                                      
 [SenderID] [nchar](20) NULL,                                      
 [MessageInsertDate] [datetime]  NULL,                                      
 [ScheduledDate] [varchar](50) NULL,                                      
 [ScheduledTime] [varchar](50) NULL,                                      
 [SmppID] [tinyint]  NULL,                                      
 [U_ID] [int]  NULL,                                      
 [IsUniCode] [bit]  NULL,                                      
 [IsDnd] [bit]  NULL,                                      
 [IsAirtel] [bit]  NULL,                                      
 [MobileSubSet] [bigint] NULL,                                      
 [ValidNo] [tinyint] NULL,                                      
 [IsPrority] [tinyint] NULL,                                      
 [IsAllowDND] [tinyint] NULL,                                      
 [DBType] [nchar](10) NULL,                                      
 [campaignid] [bigint] NULL,                                      
 [Processed] [int] NULL,                                      
 [Hasvirtualcredits] [int] NULL,                                      
 [HasSufficientvirtualcredits] [int] NULL,                                      
 [price] [float] NULL                                      
)                                      
--drop table #tmpflind                                      
CREATE TABLE #tmpflind(         
 [BatchID] [bigint]  NULL,                                      
 [Country_code] [varchar](10) NULL,                                      
 [Mobile] [varchar](20) NULL,                                      
 [Message] [nvarchar](2500) NULL,                               
 [MessageStatus] [varchar](20) NULL,                                      
 [SenderID] [nchar](20) NULL,                                  
 [MessageInsertDate] [datetime]  NULL,                                      
 [ScheduledDate] [varchar](50) NULL,                
 [ScheduledTime] [varchar](50) NULL,                                      
 [SmppID] [tinyint]  NULL,                                      
 [U_ID] [int]  NULL,                                      
 [IsUniCode] [bit]  NULL,                                      
 [IsDnd] [bit]  NULL,                             [IsAirtel] [bit]  NULL,                                      
 [MobileSubSet] [bigint] NULL,                                      
 [ValidNo] [tinyint] NULL,                                      
 [IsPrority] [tinyint] NULL,                              
 [IsAllowDND] [tinyint] NULL,                                      
 [DBType] [nchar](10) NULL,      
 [EnquiryId] [bigint]
 )
                 
                                      
			declare @Uccode varchar(20)   
			 SELECT TOP 1 @Uccode =  isnull(CountryCode,'+91')  FROM   User_Detail AS ud  WHERE  ud.[User_ID] = @parentid    

			 INSERT INTO #tmpflind                                                  
   ( BatchID,Mobile,Country_Code,Message,                                                  
             MessageStatus, SenderID,MessageInsertDate,ScheduledDate,          
             ScheduledTime,SmppID,U_ID,IsUnicode,IsDnd,IsAirtel,MobileSubSet,                                      
             ValidNo,IsPrority,IsAllowDND,DBType
   )          
			SELECT BatchID,Mobile,CountryCode,Messagetext,          
             MessageStatus, SenderID,MessageInsertDate, ScheduledDate,                                                  
             ScheduledTime,SmppID,U_ID,IsUnicode,IsDnd,IsAirtel,MobileSubSet,                                      
             ValidNo,IsPrority,IsAllowDND,DBType
			 from(
			 Select @batchid Batchid, Mobile ,
						Case WHEN Entity_type ='User' THEN (Select CountryCode from user_detail where User_id=EntityID) 
								WHEN Entity_type ='Enquiry' THEN (Select CountryCode from userenquiry where Enquiryid=EntityID) 
								WHEN Entity_type ='Lead' THEN (Select CountryCode from UserLeads where ID=EntityID) 
						end CountryCode ,dbo.Fun_GetMeetingMailMessage ( @Message, @userid, @MeetingId, EntityID) Messagetext ,NULL AS MessageStatus, @SenderID AS SenderID, GetDate() MessageInsertDate,
						 NULL AS ScheduledDate, NULL AS ScheduledTime,   ( SELECT TOP 1 ud.SmppID FROM   User_Detail AS ud WHERE  ud.[User_ID] = @Account) AS SmppID, @Account AS U_ID,@IsUnicode   AS IsUnicode, 
						  0 AS IsDnd,0 AS IsAirtel,0 AS MobileSubSet,1 AS ValidNo,1 AS IsPrority,0 AS IsAllowDND,0 AS DBType 
		from tbl_meetinguser where meeting_id=@meetingID and User_role <>'host'
			) a
			
		if @Uccode = '+91'                                      
		begin                                      
		insert into #tmpflint (BatchID, Country_code,Mobile, Message, MessageStatus, SenderID,                                                  
     MessageInsertDate, ScheduledDate, ScheduledTime,                                                  
     SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,                                       
     ValidNo, IsPrority, IsAllowDND, DBType)                                       
   select BatchID, Country_code,replace(Country_code,'+','')+Mobile, Message, MessageStatus, SenderID,                                                  
     MessageInsertDate, ScheduledDate, ScheduledTime,                                                  
     SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,                                                  
     ValidNo, IsPrority, IsAllowDND, DBType from  #tmpflind                                      
   where Country_Code <>'+91'                                      
  delete From #tmpflind where Country_Code <>'+91'                                      
 end                                      
 else                                      
 begin                                      
  insert into #tmpflint (BatchID, Country_code,Mobile, Message, MessageStatus, SenderID,                                                  
     MessageInsertDate, ScheduledDate, ScheduledTime,                                    
     SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,                                                  
     ValidNo, IsPrority, IsAllowDND, DBType)                                       
   select BatchID, Country_code,Mobile, Message, MessageStatus, SenderID,                                                  
     MessageInsertDate, ScheduledDate, ScheduledTime,                                                  
     SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,            
     ValidNo, IsPrority, IsAllowDND, DBType from  #tmpflind                                      
 end                                      
 Declare @NoOfSMS  bigint = 0, @intsms bigint =0;                                       
 select @intsms = COUNT(*) from #tmpflint                                        
                                   
                                     
declare @intprc int = 0 , @indprc int = 0  
 
	select @intsms = COUNT(*) from #tmpflint                                        
                                   
                                                      
if @intsms > 0                                      
begin                                      
 update #tmpflint set price= (case when IsUniCode=0 and len(message)<=160  then 1                                             
 when IsUniCode=0 and LEN(message)>160 then ceiling(LEN(message)/cast(153 as FLOat))                                             
  when IsUniCode=1                                             
 and len(message)<=70 then 1 else ceiling(LEN(message)/cast(67 as float)) end )*                                      
  (select price from dbo.IntSMSRateMast where country_code =#tmpflint.country_code)                                        
                                       
 declare @Cr_amt float                                        
 select @Cr_amt = SUM(price) from #tmpflint                                            
 select top 1 @balance= Balance from dbo.IntCredit_Details where USER_ID = @Parentid
 if @balance < @Cr_amt                                      
set @intprc = 1                                         
end                                      
                                       
if @intprc =0                                      
begin                                     
   --select 1                                   
  select @NoOfSMS = COUNT(*) from #tmpflind                          
 if @NoOfSMS > 0                                      
 begin                                      
                                       
                                       
  set @CurrentBalance  = (                                                      
             SELECT TOP 1 isnull(cd.Balance,0)                                                      
             FROM   Credit_Details AS cd                                                      
             WHERE  cd.[User_ID] = @parentid                                                      
             ORDER BY                                                      
 cd.Credit_ID DESC                                             
   )                 
                   
   print @CurrentBalance                
   print @NoOfSMS                                                     
 DECLARE @mBalance BIGINT = @CurrentBalance - @NoOfSMS                                           
 IF @mBalance >= 0                                          
   begin                                      
                                        
 INSERT INTO CloneMessageDeliveryStatus                                                  
   (BatchID, Mobile, Message, MessageStatus, SenderID,                                                  
     MessageInsertDate, ScheduledDate, ScheduledTime,                                                  
     SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,                                                  
     ValidNo, IsPrority, IsAllowDND, DBType,CMDS_CreatedBy)                                              
 select BatchID, Mobile, Message, MessageStatus, SenderID,                                                  
   MessageInsertDate, isnull(ScheduledDate,''), isnull(ScheduledTime,''),                                                  
     SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,                                                  
     ValidNo, IsPrority, IsAllowDND, DBType,@UserId from #tmpflind                                      
                      
   Begin try            
   exec Usp_Save_DLTTemplateID_with_BatchID @batchid,@DLTTemplateID            
   End try            
   begin catch            
     exec usp_InsertErrorInfo            
   End catch               
                 
                  Select 'Sms Send'                 
   end                                      
   else                    
    
 set @indprc = 1                                      
 end                                      
end                                      
    
                                               
 drop table if exists #TableData2    

	END

END  
 


GO

