 --  OR ISNULL(NULLIF(ul.MobileNo2, ''), '1') = ISNULL(NULLIF(@MobileNo1, ''), '2')        
 --  OR ISNULL(NULLIF(ul.MobileNo2, ''), '1') = ISNULL(NULLIF(@MobileNo2 , ''), '2')        
 --  OR ISNULL(NULLIF(ul.EmailID, ''), '1') = ISNULL(NULLIF(@EmailID , ''), '2')        
 --  OR ISNULL(NULLIF(ul.EmailID, ''), '1') = ISNULL(NULLIF(@EmailID1 , ''), '2')        
 --  OR ISNULL(NULLIF(ul.EmailID, ''), '1') = ISNULL(NULLIF(@EmailID2 , ''), '2')        
 --  OR ISNULL(NULLIF(ul.EmailID1, ''), '1') = ISNULL(NULLIF(@EmailID, ''), '2')        
 --  OR ISNULL(NULLIF(ul.EmailID1, ''), '1') = ISNULL(NULLIF(@EmailID1, ''), '2')        
 --  OR ISNULL(NULLIF(ul.EmailID1, ''), '1') = ISNULL(NULLIF(@EmailID2 , ''), '2')        
 --  OR ISNULL(NULLIF(ul.EmailID2, ''), '1') = ISNULL(NULLIF(@EmailID, ''), '2')        
 --  OR ISNULL(NULLIF(ul.EmailID2, ''), '1') = ISNULL(NULLIF(@EmailID1, ''), '2')        
 --  OR ISNULL(NULLIF(ul.EmailID2, ''), '1') = ISNULL(NULLIF(@EmailID2 , ''), '2')                          
 -- )            
 -- )        
 Begin        
  Select -1 as Id,'Conflict found while merging Enquiry to Lead' as Msg        
 End        
 Else        
 Begin        
   declare @latitude float = null;      
if(ISNULL(@WhereLatitude, '') <> '')      
begin      
 set @latitude = cast(@WhereLatitude as float)      
end      
declare @longitude float = null;      
if(ISNULL(@WhereLongitude, '') <> '')      
begin      
 set @longitude = cast(@WhereLongitude as float)       
end      
      
   
  UPDATE UserLeads                  
  SET    PersonName = @PersonName,                  
   CompanyName = @CompanyName,                  
   City = @City,                  
   Country = @Country,                  
   [State] = @State,                  
   ResidentialAddress = @ResidentialAddress,                  
   OfficeAddress = @OfficeAddress,                  
   PinCode = @PinCode,                  
   @LeadNo = LeadNo,        
        
   CountryCode = @CountryCode,                
   CountryCode1 = @CountryCode1,                
   CountryCode2 = @CountryCode2,                
                                
   MobileNo = @MobileNo,                  
   MobileNo1 = @MobileNo1,                  
   MobileNo2 = @MobileNo2,                  
                        
   EmailID = @EmailID,                  
   EmailID1 = @EmailID1,                  
   EmailID2 = @EmailID2,                  

   SourceName = @SourceName,        
   MediumName = @MediumName,        
   CampaignName = @CampaignName,
   latitude = (case when @latitude > 0 then @latitude else null end),
   longitude = (case when @longitude > 0 then @longitude else null end),
   ModifiedBy = @ModifiedBy,                  
   ModifiedOn = GETDATE()        
  WHERE  ID = @LeadID                  
                   
  DECLARE @FollowUpID BIGINT = (SELECT TOP 1 ID FROM FollowUp_Status(nolock) AS fus WHERE fus.FollowupStatus = 'Merge lead')        
    
  insert into LeadInteractionHistory( LeadNo, FollowUpStatus, FollowupDate, NextStatusDate, ParentID, AssignedTo, IsReassign, CreatedBy, CreatedOn,Products,AmountPaid)  
  select LeadNo, FollowUpStatus, FollowupDate, NextStatusDate, ParentID, AssignedTo, 0, @ModifiedBy, GETDATE(), Products, AmountPaid  from UserLeads(nolock) where ID = @LeadID  
  
  --INSERT INTO LeadInteractionHistory                  
  --(        
  -- LeadNo, FollowUpStatus, ParentID, CreatedOn, CreatedBy        
  --)                  
  --VALUES                  
  --(                  
  -- @LeadNo, @FollowUpID, @ParentID, GETDATE(), @ModifiedBy        
  --)                  
                   
  UPDATE UserEnquiry SET LeadNo=@LeadNo, IsOpen = 0        
  WHERE EnquiryID = @EnquiryID        
                   
  insert into tbl_MergeLeadsEnquiry( EnquiryNo ,LeadNo,IsOpen) values (@EnquiryID,@LeadNo,1)          
            
  select * into #tbl_CustomFields from @custom        
  alter table #tbl_CustomFields add Sno int not null identity(1,1)        
        
  Declare @recordID bigint=0, @EnqID bigint=0, @LdID bigint=0, @FieldID bigint=0, @FieldVal varchar(100), @i int=1, @recCnt int=0        
        
  Select @recCnt=count(*) From #tbl_CustomFields        
        
  While (@i <= @recCnt)        
  Begin        
   Select @EnqID=[EnquiryID], @LdID=[LeadID], @FieldID=[fieldID], @FieldVal=[fieldvalue]          
   From #tbl_CustomFields aa         
   Where Sno=@i  
        
   If exists(select recordID from customfieldLeadvalue where LeadID = @LdID and fieldID = @FieldID)          
   Begin          
    update customfieldLeadvalue set fieldvalue=@FieldVal where LeadID = @LdID and fieldID = @FieldID          
   End          
   Else          
   Begin          
    insert into customfieldLeadvalue(LeadID,EnquiryID,fieldID,fieldvalue,CreatedDate)        
     values(@LeadID, @EnqID, @FieldID, @FieldVal,getdate())        
   End          
        
   Set @i = @i + 1        
  End       
  
          
    SELECT @LeadNo as Id, 'Merged Successfully' as Msg        
        
    declare @mergid bigint=0        
    if exists(select 1 from tbl_MergeLeadsEnquiry(nolock) where EnquiryNo=@EnquiryID and leadno=@leadno)        
    begin        
    select @mergid=id from tbl_MergeLeadsEnquiry(nolock) where EnquiryNo=@EnquiryID and leadno=@leadno        
  end         
    else        
    begin        
    insert into tbl_MergeLeadsEnquiry(EnquiryNo,LeadNo,IsOpen,CreatedDate)        
    select @EnquiryID,@LeadNo,0,getdate()         
    select @mergid=scope_identity()        
    end        

  	/*Start Enquiry Id Associate to Lead Id Associate with Wtatsapp */
			
	EXEC usp_ims_UpgradeEnquiryToLead @leadid

        
    /* Start lead activity Merge Lead (Enquiry)*/          
          
  Begin try          
          
   Declare @UserID_LDACTV bigint = @ModifiedBy          
   Declare @ParentID_LDACTV bigint = @ParentID          
           
   Declare @LeadID_LDACTV bigint = @LeadID          
   Declare @EnquiryID_LDACTV bigint = @EnquiryID          
            
          
   create table #tblEventDescrb          
   (          
    EVNT_Description nvarchar(max)           
   )          
          
   if( isnull(@LeadID_LDACTV,0) > 0)          
   Begin          
              
   insert into #tblEventDescrb          
exec  Usp_EventTemplate_DynamicVarReplacement 'Lead merged',@UserID_LDACTV,'','',@LeadID_LDACTV,'',null          
   ,0,0,'','',0,'',0,null,null,null,null,null,null,null,null,null          
   ,null,null,null,null,null,null,@EnquiryID_LDACTV,null,          
   0,0,0,null,null,null,0,null,null,null,0,null,null          
               
   declare @evntMessage nvarchar(max) = ''           
   select @evntMessage = isnull( EVNT_Description,'') from #tblEventDescrb          
           
   if(@evntMessage <> '')          
   Begin          
   exec UspSaveLeadActivity_withid @LeadID_LDACTV,@UserID_LDACTV,@ParentID_LDACTV,@evntMessage,'Lead merged from enquiry',         
    'tbl_MergeLeadsEnquiry',@mergid        
   end          
          
        
   End            
          
   End try          
          
   Begin catch          
    exec usp_insertErrorInfo          
   End catch          
          
  IF OBJECT_ID('tempdb..#tblEventDescrb') IS NOT NULL -- Check for table existence            
  Begin            
   DROP TABLE #tblEventDescrb            
  End            
          
    /* End lead activity Merge Lead (Enquiry)*/          
          
   End        
        
 if object_id('tempdb..#tbl_CustomFields') is not null begin drop table #tbl_CustomFields end            
        
END 


GO

/* ============================================================
   Procedure: [dbo].[usp_message_detailGrpWise]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_message_detailGrpWise]                     
@m_id nvarchar(50),                                    
@user_id nvarchar(50),                                  
@fdate nvarchar(50),                                  
@tdate nvarchar(50),                          
@status nvarchar(10),                  
@Mobile nvarchar(50),                  
@Sender_Id nvarchar(50),        
@msgGroup varchar(200)        
as                                                                                                                            
Declare @ErrNo Int,@Query varchar(2000),@whereClause varchar(500),@operator varchar(10)                                                                                                        
Set Nocount on                                                                                                        
Begin Transaction                                                                                                        
set @whereClause=''                                    
                                     
If (@fdate !='' and @tdate !='')                                      
 Begin                                       
 Set @whereClause = @whereClause+ '(convert(nvarchar,convert(datetime,md.datecreated,104),112) between convert(nvarchar,convert(datetime,'''+@fdate+''',104),112) and convert(nvarchar,convert(datetime ,'''+@tdate +''',104),112))and '                 
 Set @ErrNo = @@error                                       
 End                                      
Else                                      
 Begin                                      
  Set @whereClause =@whereClause +  ' 1=1 and '                                      
  Set @ErrNo = @@error                                      
 End                   
If (@Mobile='')                                                                                      
 Begin                            
 Set @whereClause =@whereClause +  '1=1 and '                                                                                    
  Set @ErrNo = @@error                                                                                  
 End                                                                                      
Else                                              
Begin                                                                                      
 Set @whereClause = @whereClause+ 'md.[To] like ''%'+@Mobile+'%'' and '                                                                                      
  Set @ErrNo = @@error                                                                        
 End                   
If (@Sender_Id='')                                                                                      
 Begin                            
 Set @whereClause =@whereClause +  '1=1 and '                                                                                      
  Set @ErrNo = @@error                                                                                  
 End                                                                                      
Else                                              
Begin                                                                                      
 Set @whereClause = @whereClause+ 'sd.Sender_ID ='''+@Sender_Id+''' and '                                                                                      
  Set @ErrNo = @@error                                                                        
 End                            
If (@status='All')                                                                                      
 Begin                            
 Set @whereClause =@whereClause +  '1=1'                                                                                      
  Set @ErrNo = @@error                                                                                  
 End       
Else                                              
Begin                                              
 Set @whereClause = @whereClause+ 'md.Delivery_Status ='''+@status+''' '                                                                                      
  Set @ErrNo = @@error                                                                        
 End                
set @Query='select md.Message_ID,md.Message,md.M_ID,md.User_ID,count(md.msggroup) as msggroup,                   
md.[From],md.[To],md.MsgCount,md.NoOfPeople,md.Delivery_Status,md.Schedule_Date,                
md.Schedule_Time,md.Mode,md.DateCreated as Time_of_Sending,sd.Sender_ID,sd.Sender_Name from message_detail md inner join                  
SenderID_Detail sd on md.Sender_ID=sd.Sender_ID                                    
where md.m_id='''+@m_id +''' and md.User_id='''+@user_id+''' and (md.Schedule_Date='''' or md.Schedule_Date is null) and (md.Schedule_Time='''' or md.Schedule_Time is null) and  '+@whereClause+' and md.msggroup='''+@msgGroup+'''     
group by md.msggroup,md.Message_ID,md.Message,md.M_ID,md.User_ID,md.[From],md.[To],md.MsgCount,md.NoOfPeople,md.Delivery_Status,md.Schedule_Date,                
md.Schedule_Time,md.Mode,md.DateCreated,sd.Sender_ID,sd.Sender_Name order by md.DateCreated desc '     
    
    
print @Query                                      
exec (@Query)                                      
If @ErrNo = 0                                      
 Begin                                      
  Commit Transaction                                      
  Set Nocount off                                     
  Return 0                                      
 End                                      
Else                                      
 Begin                                      
  Rollback Transaction                                      
  Set Nocount off                                       
  Return @ErrNo                                      
 End




GO

/* ============================================================
   Procedure: [dbo].[usp_messagelinkreplace]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_messagelinkreplace  
(@batchid bigint,@TableNAMECLONE varchar(150))  
as  
begin  
DECLARE  @fromid    BIGINT,              
@maxid     BIGINT,              
@toid      BIGINT,              
@batchsize BIGINT ,@queryFORID nvarchar(max) ,@id int            
SELECT TOP(1) @TableNAMECLONE=TABLENAME FROM BATCHINFO WHERE BATCHID=@BatchID                            
      
--Get Min and max ID table name (CloneMessageDeliveryStatus)                            
SET @queryFORID=' SELECT @fromid = Min(messageid) , @maxid = Max(messageid)                              
FROM   '+@TableNAMECLONE+'              
WHERE  batchid = '+convert(nvarchar,@BatchID,100 )+''                            
-- select @queryFORID                        
exec sp_executesql @queryFORID,N'@fromid bigint OUTPUT,@maxid bigint OUTPUT', @fromid OUTPUT,@maxid OUTPUT;   
  
declare @count int=isnull(@maxid,0)-isnull(@fromid,0)    
if exists(select 1 from Link_smsUrl_dtl (nolock) where BatchID =@BATCHID)    
begin    
    
select @id=@fromid      
    
DECLARE @result NCHAR(4),@shorturl nvarchar(100)    
select top 1 @shorturl=short_url from Link_smsUrl_dtl(nolock) where BatchId=@BATCHID    
 --select @Parentid = Parent_id from Link_urlMaster where shorturl=@shorturl    
declare @dlcount int    
 select @dlcount= COUNT(1) from dbo.Link_smsMobile l where status = 0 and  shorturl=@shorturl and l.mobile_url_id=(select max(mobile_url_id) from dbo.Link_smsMobile l2 where l2.final_url=l.final_url and l.shorturl=l2.shorturl)    
 --and Parentid = @Parentid    
if @dlcount > 0    
 begin    
 if @dlcount >= @count    
 begin    
  set @dlcount = @count    
  set @count=0    
 end    
 else    
 begin    
  set @count = @count-@dlcount    
 end    
 end     
    
RETRY:                                               
BEGIN TRY                                            
BEGIN TRAN    
    
 select row_number() over (order by randomexp) as id, randomexp into #temp from     
 (select top(@dlcount) Final_url randomexp from dbo.Link_smsMobile(nolock) l where status = 0 and shorturl=@shorturl    
 and l.mobile_url_id=(select max(mobile_url_id) from dbo.Link_smsMobile l2(nolock) where l2.final_url=l.final_url and l.       shorturl=l2.shorturl)    
 order by mobile_url_id    
 union all    
 select top (@count) randomexp      
 from randomexp(nolock) where id>(select isnull(lastid,0) from Link_urlMaster(nolock) where shorturl=@shorturl)     
 order by id) as aa    
 update Link_urlMaster set lastid=isnull(lastid,0)+@count where shorturl=@shorturl     
 --update l set status=1 from Link_smsMobile l join #temp t on l.final_url=t.randomexp where shorturl=@shorturl    
 --and l.mobile_url_id=(select max(mobile_url_id) from dbo.Link_smsMobile l2 where l2.final_url=l.final_url and l.       shorturl=l2.shorturl)    
     
 --select top (@count) row_number() over (order by id) as id, randomexp      
 --into #temp from randomexp where id>(select isnull(lastid,0) from Link_urlMaster where shorturl=@shorturl)     
 --order by id    
 --update Link_urlMaster set lastid=isnull(lastid,0)+@count where shorturl=@shorturl     
    
COMMIT                                            
END TRY                                            
                  
BEGIN CATCH                                                                                                
IF @@TRANCOUNT>0                                            
ROLLBACK                                            
--EXECUTE USP_INSERTERRORINFO;       
IF ERROR_NUMBER() = 1205 -- Deadlock Error Number      
BEGIN      
WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms      
GOTO RETRY -- Go to Label RETRY      
END                                                 
END CATCH    
 --trans    
    
 --4444    
 --XXXX    
 --RRRR    
 --WWWW    
   
 declare @tquery nvarchar(500),@tempq nvarchar(500),@temp2q nvarchar(500)  
 --set @tquery='select * into ##inserted from '+@TableNAMECLONE+' where batchid='+@batchid+''  
   
 set @tempq=' select row_number() over (order by ProcessUrl_Id) as id,Mobile,ins.batchid, short_url,     
 longurl, ProcessUrl_Id,Parentid ,MessageID,Page_nm, p_url    
  into ##temp2    
  from '+@TableNAMECLONE+' ins inner join  Link_smsUrl_dtl lk (nolock)   
  on lk.BatchId = ins.BatchID'  
 exec (@tempq)  
   
    
declare @cc int,@tid int    
select @cc=count(1),@tid=min(id) from ##temp2    
    
while @cc >0    
begin    
 insert into dbo.Link_smsMobile     
 (Mobile, batchid,shorturl, longurl,  ProcessUrl_id,Final_url,Parentid,MessageID,Page_nm,p_url)    
 select top 1000 Mobile,batchid, short_url, longurl, ProcessUrl_Id,     
 randomexp,Parentid ,MessageID,Page_nm,p_url    
  from #temp ins inner join  ##temp2 lk    
  on lk.id = ins.ID where lk.id between @tid and @tid+1000 order by lk.id    
set @cc=@cc-1000      
set @tid=@tid+1000    
end    
    
set @count=@dlcount+@count   
declare @updateq nvarchar(1000)= 'update cl    
 set Message = REPLACE(message,longurl, shorturl+''/''+Final_url)     
 from '+@TableNAMECLONE + ' cl inner join     
 Link_smsMobile lm  (nolock)  
 on lm.Mobile= cl.Mobile and lm.batchid = cl.BatchID    
 where lm.batchid = @BATCHID and messageid between '+cast(@fromid as nvarchar)+' and '+ cast(@fromid+1000 as nvarchar)+''    
RETRY1:                                               
BEGIN TRY                                            
BEGIN TRAN     
while @count>0    
begin      
set @updateq='update cl    
 set Message = REPLACE(message,longurl, shorturl+''/''+Final_url)     
 from '+@TableNAMECLONE + ' cl inner join     
 Link_smsMobile lm (nolock)   
 on lm.Mobile= cl.Mobile and lm.batchid = cl.BatchID    
 where lm.batchid = @BATCHID and messageid between '+cast(@fromid as nvarchar)+' and '+ cast(@fromid+1000 as nvarchar)+''    
 exec (@updateq)  
 set @count=@count-1000    
 set @fromid=@fromid+1000    
end    
COMMIT                                            
END TRY                                            
                  
BEGIN CATCH                                                                                                
IF @@TRANCOUNT>0                                            
ROLLBACK                                            
--EXECUTE USP_INSERTERRORINFO;       
IF ERROR_NUMBER() = 1205 -- Deadlock Error Number      
BEGIN      
WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms      
GOTO RETRY1 -- Go to Label RETRY      
END                                                 
END CATCH    
end      
end


GO

/* ============================================================
   Procedure: [dbo].[USP_MessageSourceToqueueValueFirstAirtel]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[USP_MessageSourceToqueueValueFirstAirtel]
@TABLENAME NVARCHAR(100),                   
@TABLENAMEAIRTEL NVARCHAR(100)                     
AS                      
BEGIN                      
	BEGIN TRY                
		DECLARE @TABLEROWCOUNT1 BIGINT                      
		DECLARE @MESSAGECOUNT BIGINT                      
		DECLARE @BATCHID BIGINT                      
		DECLARE @QUERY NVARCHAR(MAX)                      
		DECLARE @TEMPADCOUNT BIGINT                      
		DECLARE @COUNTPERCENTAGE BIGINT                  
		DECLARE @COUNTAIRTELSENDER INT                  
		DECLARE @INSERQUERYAIRTEL NVARCHAR(MAX)                  
		DECLARE @INSERQUERYVF NVARCHAR(MAX)            
		DECLARE @USERFILTER CHAR(10)                
		SET @MESSAGECOUNT=7000
		SET @TABLEROWCOUNT1=(SELECT ROWS MESSAGEQUEUE FROM SYSINDEXES WHERE ID = OBJECT_ID(''+@TABLENAME+'')  AND			INDID < 2)                                
			IF(@TABLEROWCOUNT1<@MESSAGECOUNT)                      
			BEGIN                      
				DECLARE @TEMP1 VARCHAR(100)                      
				SET @TEMP1=(SELECT TOP(1) MESSAGEBATCHID FROM MESSAGESOURCE INNER JOIN PROCESSBATCHAIRTEL ON						MESSAGEBATCHID>PROCESSNO GROUP BY MESSAGEBATCHID ORDER BY MESSAGEBATCHID)                            				IF(@TEMP1 IS NULL)                                  
					BEGIN                                  
						SET @TEMP1=(SELECT TOP(1) MESSAGEBATCHID FROM MESSAGESOURCE	GROUP BY MESSAGEBATCHID ORDER BY						MESSAGEBATCHID)                                  
						UPDATE PROCESSBATCHAIRTEL SET PROCESSNO=@TEMP1                                  
						SET @BATCHID=@TEMP1                                  
					END                                  
				ELSE                                  
					BEGIN                                  
						UPDATE PROCESSBATCHAIRTEL SET PROCESSNO=@TEMP1                                  
						SET @BATCHID=@TEMP1                       
					END                       
						EXEC USP_INSERTMESSAGEDETAIL @BATCHID 
				IF (EXISTS (SELECT 'X' FROM BATCHINFO WHERE BATCHID=@BATCHID AND DBTYPE!=1))
					BEGIN
						EXEC USP_GETPREMIUMCOUNT @BATCHID                 
					END 
						SELECT TOP(@MESSAGECOUNT) MESSAGESOURCEID,MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,								PRIORITY,U_ID,ISUNICODE,ISDND,OPERATOR,MESSAGEBATCHID,ISALLOWDND INTO #TEMPTABLE FROM								MESSAGESOURCE WHERE MESSAGEBATCHID=@BATCHID
						DELETE MESSAGESOURCE FROM MESSAGESOURCE JOIN #TEMPTABLE TMP ON MESSAGESOURCE.MESSAGEID=								TMP.MESSAGEID  
						SELECT @USERFILTER=USERFILTER FROM BATCHINFO WITH(NOLOCK) WHERE BATCHID=@BATCHID
				IF (@USERFILTER='ON')          
					BEGIN          
						INSERT INTO MESSAGEQUEUE(MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID,									ISUNICODE,ISDND, OPERATOR, BATCHID,ISALLOWDND) 
						SELECT MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID,ISUNICODE,ISDND,OPERATOR,							MESSAGEBATCHID,ISALLOWDND FROM #TEMPTABLE 
					END          
				ELSE IF (@USERFILTER='OPEN')          
					BEGIN          
						INSERT INTO MESSAGEQUEUEAIRTELTHREE(MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,							U_ID,ISUNICODE,ISDND,OPERATOR,BATCHID,ISALLOWDND) 
						SELECT MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID,ISUNICODE,ISDND,OPERATOR,							MESSAGEBATCHID,ISALLOWDND FROM #TEMPTABLE           
					END          
				ELSE        
					BEGIN                
						SET @INSERQUERYVF='INSERT INTO '+@TABLENAME+' (MESSAGEID,MOBILE,[MESSAGE],SENDERID,
						SMPPID,PRIORITY,U_ID,ISUNICODE,ISDND, OPERATOR, BATCHID,ISALLOWDND)                
						SELECT  MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID,ISUNICODE,											ISDND, OPERATOR, MESSAGEBATCHID,ISALLOWDND FROM  #TEMPTABLE'                 
						EXEC (@INSERQUERYVF)                
					END                                                          
						DROP TABLE #TEMPTABLE                
			END                
	END TRY                
	BEGIN CATCH                
		EXEC USP_INSERTERRORINFO                
	END CATCH                
END 


GO

/* ============================================================
   Procedure: [dbo].[USP_MessageSourceToqueueValueFirstAirtel_Getbatchid]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[USP_MessageSourceToqueueValueFirstAirtel_Getbatchid] --'messagesource' --'MessageQueueProMTIX1'--'[MESSAGEQUEUEAIRTELDIRECT]','MESSAGEQUEUEFOUR'               
@TABLENAME NVARCHAR(100)               
--,@TABLENAMEAIRTEL NVARCHAR(100)               
AS               
BEGIN       
declare @t1 int   ,@u_id bigint 
 select @t1=case when @TABLENAME ='messagesource' then 0       
 when @TABLENAME ='messagesource1' then 1       
 when @TABLENAME ='messagesource2' then 2       
 when @TABLENAME ='messagesource3' then 3 end      
DECLARE @TEMP1 VARCHAR(100)        
SET @TEMP1=(SELECT TOP(1) m.MESSAGEBATCHID FROM MESSAGESOURCE m with (nolock) where MESSAGEBATCHID%4=@t1     
--and not exists (select * from [10.0.0.132].mysms.dbo.message_detail with (nolock) where batchid=m.MessageBatchID)    
GROUP BY m.MESSAGEBATCHID ORDER BY MESSAGEBATCHID)  
exec Usp_InsertMessageDetail_and_premium @temp1  
  
  Declare @UserFilter nvarchar(50) = ''    
  select @UserFilter = isnull(userfilter,''),@u_id=dbo.ufn_getuserparentid(userid) from BatchInfo with(nolock)  where batchID = @temp1   
     -- select @UserFilter as userfilter
	 
	 if 1=1-- @u_id<>33819
	 begin
    select @temp1 as batchid  , @UserFilter as userfilter  
	end
	else
	begin
	    select null as batchid  , null as userfilter  

	end

  
end


GO

/* ============================================================
   Procedure: [dbo].[USP_MessageSourceToqueueValueFirstAirtel_New]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

   
CREATE   PROCEDURE [dbo].[USP_MessageSourceToqueueValueFirstAirtel_New] --'messagesource'--'[MESSAGEQUEUEAIRTELDIRECT]','MESSAGEQUEUEFOUR'   
@TABLENAME NVARCHAR(100)   
--,@TABLENAMEAIRTEL NVARCHAR(100)   
AS   
BEGIN   
   
 DECLARE @TABLEROWCOUNT1 BIGINT   
 DECLARE @TABLEROWCOUNT2 BIGINT   
 DECLARE @MESSAGECOUNT BIGINT   
 DECLARE @BATCHID BIGINT   
 DECLARE @QUERY NVARCHAR(MAX)   
 DECLARE @TEMPADCOUNT BIGINT   
 DECLARE @COUNTPERCENTAGE BIGINT   
 DECLARE @COUNTAIRTELSENDER INT   
 DECLARE @INSERQUERYAIRTEL NVARCHAR(MAX)   
 DECLARE @INSERQUERYVF NVARCHAR(MAX)   
 DECLARE @USERFILTER CHAR(10)   
 DECLARE @INSERQUERYAIR NVARCHAR(MAX)   
 SET @MESSAGECOUNT=1000   
SET @TABLEROWCOUNT1=(SELECT ROWS MESSAGEQUEUE FROM SYSINDEXES WHERE ID = OBJECT_ID(''+@TABLENAME+'') AND INDID < 2)   
IF(@TABLEROWCOUNT1<@MESSAGECOUNT)   
BEGIN   
DECLARE @TEMP1 VARCHAR(100)   
SET @TEMP1=(SELECT TOP(1) m.MESSAGEBATCHID FROM MESSAGESOURCE m with (nolock) INNER JOIN PROCESSBATCHAIRTEL p with (nolock) ON   
m.MESSAGEBATCHID> p.PROCESSNO GROUP BY m.MESSAGEBATCHID ORDER BY m.MESSAGEBATCHID)   
IF(@TEMP1 IS NULL)   
BEGIN   
SET @TEMP1=(SELECT TOP(1) m.MESSAGEBATCHID FROM MESSAGESOURCE m with (nolock) GROUP BY m.MESSAGEBATCHID ORDER BY MESSAGEBATCHID)   
UPDATE PROCESSBATCHAIRTEL SET PROCESSNO=@TEMP1 SET @BATCHID=@TEMP1   
END   
ELSE   
BEGIN   
UPDATE PROCESSBATCHAIRTEL SET PROCESSNO=@TEMP1 SET @BATCHID=@TEMP1   
END   
   
EXEC USP_INSERTMESSAGEDETAIL @BATCHID   
IF (EXISTS (SELECT 'X' FROM BATCHINFO with (nolock) WHERE BATCHID=@BATCHID AND DBTYPE!=1))   
BEGIN   
EXEC USP_GETPREMIUMCOUNT @BATCHID   
END   
RETRY:   
BEGIN TRY   
--BEGIN TRAN   
SELECT TOP(@MESSAGECOUNT) MESSAGESOURCEID,MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID,ISUNICODE,ISDND,OPERATOR,MESSAGEBATCHID,ISALLOWDND   
INTO #TEMPTABLE FROM MESSAGESOURCE with (nolock) WHERE MESSAGEBATCHID=@BATCHID   
DELETE MESSAGESOURCE FROM MESSAGESOURCE JOIN #TEMPTABLE TMP ON MESSAGESOURCE.MESSAGEID= TMP.MESSAGEID   
SELECT @USERFILTER=USERFILTER FROM BATCHINFO with (nolock) WHERE BATCHID=@BATCHID   
IF (@USERFILTER='ON')   
BEGIN   
INSERT INTO MESSAGEQUEUE(MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID, ISUNICODE,ISDND, OPERATOR, BATCHID,ISALLOWDND)   
SELECT MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID,ISUNICODE,ISDND,OPERATOR, MESSAGEBATCHID, ISALLOWDND FROM #TEMPTABLE   
END   
ELSE IF (@USERFILTER='TRANS')   
BEGIN   
INSERT INTO MESSAGEQUEUEAIRTELPRI(MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID, ISUNICODE,ISDND, OPERATOR, BATCHID,ISALLOWDND)   
SELECT MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID,ISUNICODE,ISDND,OPERATOR, MESSAGEBATCHID, ISALLOWDND FROM #TEMPTABLE   
END   
ELSE IF (@USERFILTER='MT_TRANS')   
BEGIN   
INSERT INTO MESSAGEQUEUEAIRTEL(MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID, ISUNICODE,ISDND, OPERATOR, BATCHID,ISALLOWDND)   
SELECT MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID,ISUNICODE,ISDND,OPERATOR, MESSAGEBATCHID, ISALLOWDND FROM #TEMPTABLE   
END   
ELSE IF (@USERFILTER='MT')   
BEGIN   
INSERT INTO MESSAGEQUEUEMO(MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID, ISUNICODE,ISDND, OPERATOR, BATCHID,ISALLOWDND)   
SELECT MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID,ISUNICODE,ISDND,OPERATOR, MESSAGEBATCHID,ISALLOWDND FROM #TEMPTABLE   
END   
ELSE IF (@USERFILTER='OPEN')   
BEGIN   
INSERT INTO MESSAGEQUEUEAIRTELTHREE(MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY, U_ID,ISUNICODE,ISDND,OPERATOR,BATCHID,ISALLOWDND)   
SELECT MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID,ISUNICODE,ISDND,OPERATOR, MESSAGEBATCHID,ISALLOWDND FROM #TEMPTABLE   
EXEC USP_MOVE_AIRTELTHREE_AIRTELDIRECT   
END   
   
 -- ELSE IF (@USERFILTER='FRC')   
 -- BEGIN   
 -- SET @INSERQUERYVF='INSERT INTO '+@TABLENAME+' (MESSAGEID,MOBILE,[MESSAGE],SENDERID,   
 -- SMPPID,PRIORITY,U_ID,ISUNICODE,ISDND, OPERATOR, BATCHID,ISALLOWDND)   
 -- SELECT MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID,ISUNICODE,ISDND, OPERATOR, MESSAGEBATCHID,ISALLOWDND FROM #TEMPTABLE '   
 -- EXEC (@INSERQUERYVF)   
