 --ELSE IF (@USERFILTER='OFF')   
 -- BEGIN   
 -- SET @INSERQUERYAIR='INSERT INTO '+@TABLENAMEAIRTEL+' (MESSAGEID,MOBILE,[MESSAGE],SENDERID,   
 -- SMPPID,PRIORITY,U_ID,ISUNICODE,ISDND, OPERATOR, BATCHID,ISALLOWDND)   
 -- SELECT MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID,ISUNICODE,ISDND, OPERATOR, MESSAGEBATCHID,ISALLOWDND FROM #TEMPTABLE '   
 -- EXEC (@INSERQUERYAIR)   
 -- END   
ELSE IF (@USERFILTER='MTIX_PRO')   
BEGIN   
 --SET @INSERQUERYVF='INSERT INTO '+@TABLENAME+' (MESSAGEID,MOBILE,[MESSAGE],SENDERID,   
 --SMPPID,PRIORITY,U_ID,ISUNICODE,ISDND, OPERATOR, BATCHID,ISALLOWDND)   
 --SELECT MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID,ISUNICODE,ISDND, OPERATOR, MESSAGEBATCHID,ISALLOWDND FROM #TEMPTABLE '   
 --EXEC (@INSERQUERYVF)   
INSERT INTO mysmstrans.dbo.MessageQueueProROUTE(MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID,ISUNICODE,ISDND,OPERATOR,BATCHID,ISALLOWDND)   
SELECT MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID,ISUNICODE,ISDND,OPERATOR, MESSAGEBATCHID,ISALLOWDND FROM #TEMPTABLE   
 --code just to test 200418--   
