 select @BATCHID,(select COUNT(1) from MessageSource where MessageBatchID=@BATCHID),(select TotalRecords from batchinfo where BatchID=@BATCHID),(select COUNT(1) from #TEMPTABLE),GETDATE()*/   
END   
ELSE IF (@USERFILTER='TR_CURVE')   
BEGIN   
