SET @TEMP1=(SELECT TOP(1) m.MESSAGEBATCHID FROM MESSAGESOURCE m with (nolock) GROUP BY m.MESSAGEBATCHID ORDER BY MESSAGEBATCHID) 
UPDATE PROCESSBATCHAIRTEL SET PROCESSNO=@TEMP1 SET @BATCHID=@TEMP1 
END 
ELSE 
