 -- INSERT INTO [MessageQueueTrcRoute2](MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID,ISUNICODE,ISDND,OPERATOR,BATCHID,ISALLOWDND) 
 --SELECT MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID,ISUNICODE,ISDND,OPERATOR,MESSAGEBATCHID,ISALLOWDND FROM #TEMPTABLE 
 
 
 --Commented below code as transcrub now goes from promo which is pre DND scrubbed 
