 SELECT distinct MESSAGEID,'91'+MOBILE,[MESSAGE],SENDERID,'Sent',SMPPID,PRIORITY,U_ID,ISUNICODE,OPERATOR,MESSAGEBATCHID FROM #TEMPTABLE t join MyGroupAppComb.dbo.dnddirectory d with (nolock) on t.mobile=d.DNDMobileNo -- isnull(dbo.fn_finddnd(mobile)
,0)=1 
