INSERT INTO mysmstrans.dbo.MessageQueueTrcRoute(MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID,ISUNICODE,ISDND,OPERATOR,BATCHID,ISALLOWDND) 
SELECT MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID,ISUNICODE,ISDND,OPERATOR,MESSAGEBATCHID,ISALLOWDND FROM #TEMPTABLE --where isnull(dbo.fn_finddnd(mobile),0)=0 
