SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROC [dbo].[USP_MessageSourceToqueueValueFirstAirtel_New2] --'MessageQueueTrcRoute2'--'messagesource'--'[MESSAGEQUEUEAIRTELDIRECT]','MESSAGEQUEUEFOUR'
@TABLENAME NVARCHAR(100)
--,@TABLENAMEAIRTEL NVARCHAR(100)                       
AS                        
BEGIN                        
 BEGIN TRY 
 --declare @TABLENAME  NVARCHAR(100)=  'MessageQueueTrcRoute2'             
  DECLARE @TABLEROWCOUNT1 BIGINT  
  DECLARE @TABLEROWCOUNT2 BIGINT  
  DECLARE @MESSAGECOUNT BIGINT                        
  DECLARE @BATCHID BIGINT                        
  DECLARE @QUERY NVARCHAR(MAX)                        
  DECLARE @TEMPADCOUNT BIGINT                        
  DECLARE @COUNTPERCENTAGE BIGINT                    
  DECLARE @COUNTAIRTELSENDER INT                    
  DECLARE @INSERQUERYAIRTEL NVARCHAR(MAX)                    
  DECLARE @INSERQUERYVF NVARCHAR(MAX)              
  DECLARE @USERFILTER CHAR(10)                  
  DECLARE @INSERQUERYAIR NVARCHAR(MAX)
  SET @MESSAGECOUNT=50000
  SET @TABLEROWCOUNT1=(SELECT ROWS MESSAGEQUEUE FROM SYSINDEXES WHERE ID = OBJECT_ID(''+@TABLENAME+'')  AND   INDID < 2) 
   --SET @TABLEROWCOUNT2=(SELECT ROWS MESSAGEQUEUE FROM SYSINDEXES WHERE ID = OBJECT_ID(''+@TABLENAMEAIRTEL+'')  AND   INDID < 2)                                 
   IF(@TABLEROWCOUNT1<@MESSAGECOUNT)                        
   BEGIN                        
    DECLARE @TEMP1 VARCHAR(100)                        
    SET @TEMP1=(SELECT TOP(1) BATCHID FROM MessageQueueTrcRoute2 GROUP BY BATCHID ORDER BY BATCHID)
    IF(@TEMP1 IS NULL)                              
      BEGIN                                    
      SET @TEMP1=(SELECT TOP(1) BATCHID FROM MessageQueueTrcRoute2 GROUP BY BATCHID ORDER BY BATCHID)         
      --UPDATE PROCESSBATCHAIRTEL SET PROCESSNO=@TEMP1                                    
      SET @BATCHID=@TEMP1                                    
     END                                    
    ELSE                                    
     BEGIN                                    
      --UPDATE PROCESSBATCHAIRTEL SET PROCESSNO=@TEMP1                                    
      SET @BATCHID=@TEMP1                         
     END                         
      EXEC USP_INSERTMESSAGEDETAIL @BATCHID   
    IF (EXISTS (SELECT 'X' FROM BATCHINFO WHERE BATCHID=@BATCHID AND DBTYPE!=1))  
     BEGIN  
      EXEC USP_GETPREMIUMCOUNT @BATCHID                   
     END   
      SELECT TOP(@MESSAGECOUNT) MessageQueueID,MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,        PRIORITY,U_ID,ISUNICODE,ISDND,OPERATOR,BATCHID,ISALLOWDND INTO #TEMPTABLE FROM        MessageQueueTrcRoute2 WHERE BATCHID=@BATCHID  
      DELETE MessageQueueTrcRoute2 FROM MessageQueueTrcRoute2 JOIN #TEMPTABLE TMP ON MessageQueueTrcRoute2.MESSAGEID=        TMP.MESSAGEID    
      SELECT @USERFILTER=USERFILTER FROM BATCHINFO WITH(NOLOCK) WHERE BATCHID=@BATCHID  
    IF (@USERFILTER='ON')            
     BEGIN            
      INSERT INTO MESSAGEQUEUE(MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID,         ISUNICODE,ISDND, OPERATOR, BATCHID,ISALLOWDND)   
      SELECT MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID,ISUNICODE,ISDND,OPERATOR, batchid,	ISALLOWDND FROM #TEMPTABLE   
     END 
    ELSE IF (@USERFILTER='TRANS')            
     BEGIN            
      INSERT INTO MESSAGEQUEUEAIRTELPRI(MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID,         ISUNICODE,ISDND, OPERATOR, BATCHID,ISALLOWDND)   
      SELECT MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID,ISUNICODE,ISDND,OPERATOR,       batchid,	ISALLOWDND FROM #TEMPTABLE   
     END 
     ELSE IF (@USERFILTER='MT_TRANS')            
     BEGIN            
      INSERT INTO MESSAGEQUEUEAIRTEL(MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID,         ISUNICODE,ISDND, OPERATOR, BATCHID,ISALLOWDND)   
      SELECT MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID,ISUNICODE,ISDND,OPERATOR,       batchid,	ISALLOWDND FROM #TEMPTABLE   
     END 
      ELSE IF (@USERFILTER='MT')            
     BEGIN            
      INSERT INTO MESSAGEQUEUEMO(MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID,         ISUNICODE,ISDND, OPERATOR, BATCHID,ISALLOWDND)   
      SELECT MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID,ISUNICODE,ISDND,OPERATOR,       batchid,ISALLOWDND FROM #TEMPTABLE   
     END            
    ELSE IF (@USERFILTER='OPEN')            
     BEGIN            
      INSERT INTO MESSAGEQUEUEAIRTELTHREE(MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,       U_ID,ISUNICODE,ISDND,OPERATOR,BATCHID,ISALLOWDND)   
      SELECT MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID,ISUNICODE,ISDND,OPERATOR,       batchid,ISALLOWDND FROM #TEMPTABLE  
      EXEC USP_MOVE_AIRTELTHREE_AIRTELDIRECT           
     END   
              
  --   ELSE IF (@USERFILTER='FRC')            
		--	BEGIN    
		--		SET @INSERQUERYVF='INSERT INTO '+@TABLENAME+' (MESSAGEID,MOBILE,[MESSAGE],SENDERID,  
		--		SMPPID,PRIORITY,U_ID,ISUNICODE,ISDND, OPERATOR, BATCHID,ISALLOWDND)                  
		--		SELECT  MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID,ISUNICODE,ISDND, OPERATOR,							batchid,ISALLOWDND FROM  #TEMPTABLE '   
		--		EXEC (@INSERQUERYVF) 
		--	END
		--ELSE IF (@USERFILTER='OFF')
		--	BEGIN
		--		SET @INSERQUERYAIR='INSERT INTO '+@TABLENAMEAIRTEL+' (MESSAGEID,MOBILE,[MESSAGE],SENDERID,  
		--		SMPPID,PRIORITY,U_ID,ISUNICODE,ISDND, OPERATOR, BATCHID,ISALLOWDND)                  
		--		SELECT  MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID,ISUNICODE,ISDND, OPERATOR,							batchid,ISALLOWDND FROM  #TEMPTABLE '         
		--		EXEC (@INSERQUERYAIR)                    
		--	END  
		ELSE IF (@USERFILTER='MTIX_PRO')            
			BEGIN    
				--SET @INSERQUERYVF='INSERT INTO '+@TABLENAME+' (MESSAGEID,MOBILE,[MESSAGE],SENDERID,  
				--SMPPID,PRIORITY,U_ID,ISUNICODE,ISDND, OPERATOR, BATCHID,ISALLOWDND)                  
				--SELECT  MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID,ISUNICODE,ISDND, OPERATOR,							batchid,ISALLOWDND FROM  #TEMPTABLE '   
				--EXEC (@INSERQUERYVF) 
				BEGIN            
      INSERT INTO MessageQueueProROUTE(MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID,ISUNICODE,ISDND,OPERATOR,BATCHID,ISALLOWDND)   
      SELECT MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID,ISUNICODE,ISDND,OPERATOR,       batchid,ISALLOWDND FROM #TEMPTABLE             
     END 
			END
    ELSE IF (@USERFILTER='TR_CURVE')            
     BEGIN            
      INSERT INTO MESSAGEQUEUEAIRTELTWO(MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,       U_ID,ISUNICODE,ISDND,OPERATOR,BATCHID,ISALLOWDND)   
      SELECT MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID,ISUNICODE,ISDND,OPERATOR,       batchid,ISALLOWDND FROM #TEMPTABLE             
     END
     ELSE IF(@USERFILTER='P_TRANS')
        BEGIN            
      INSERT INTO MESSAGEQUEUEPTRANS(MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID,ISUNICODE,ISDND,OPERATOR,BATCHID,ISALLOWDND)   
      SELECT MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID,ISUNICODE,ISDND,OPERATOR,       batchid,ISALLOWDND FROM #TEMPTABLE             
     END  
            ELSE IF(@USERFILTER='MTIX_TRC')
        BEGIN      
      --  INSERT INTO [MessageQueueTrcRoute2](MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,PRIORITY,U_ID,ISUNICODE,ISDND,OPERATOR,BATCHID,ISALLOWDND)   
