@batchid1 bigint        
--,@TABLENAMEAIRTEL NVARCHAR(100)                   
AS                   
BEGIN                   
                   
 DECLARE @TABLEROWCOUNT1 BIGINT                   
 DECLARE @TABLEROWCOUNT2 BIGINT                   
 DECLARE @MESSAGECOUNT BIGINT                   
 DECLARE @BATCHID BIGINT                   
 DECLARE @QUERY NVARCHAR(MAX)                   
 DECLARE @TEMPADCOUNT BIGINT                   
 DECLARE @COUNTPERCENTAGE BIGINT                   
 DECLARE @COUNTAIRTELSENDER INT                   
 DECLARE @INSERQUERYAIRTEL NVARCHAR(MAX)                   
 DECLARE @INSERQUERYVF NVARCHAR(MAX)                   
 DECLARE @USERFILTER CHAR(10)                   
 DECLARE @INSERQUERYAIR NVARCHAR(MAX)              
 declare @whilebatch int=1000,@rowsaffected int=0,@batchcount int,@t1 int,@total_sent int          
           
          
IF(1=1)                   
BEGIN                   
DECLARE @TEMP1 VARCHAR(100)  =@batchid1        
UPDATE mysms.dbo.PROCESSBATCHAIRTEL SET PROCESSNO=@TEMP1 SET @BATCHID=@TEMP1              
print concat('temp1 from processtable when null: ',@TEMP1, ', batchid: ',@batchid)            
        
--EXEC USP_INSERTMESSAGEDETAIL @BATCHID                   
--print 'USP_INSERTMESSAGEDETAIL completed'          
--IF (EXISTS (SELECT 'X' FROM BATCHINFO with (nolock) WHERE BATCHID=@BATCHID AND DBTYPE!=1))                   
--BEGIN                   
--EXEC USP_GETPREMIUMCOUNT @BATCHID                   
--print 'USP_GETPREMIUMCOUNT completed'          
--END                   
RETRY:                   
BEGIN TRY                   
--BEGIN TRAN            
          
drop table if exists #temptable          
drop table if exists #output          
          
CREATE TABLE [dbo].#Temptable(          
 [MessageSourceID] [int] ,          
 [MessageID] [bigint] NULL,          
 [MessageBatchID] [bigint] NULL,          
 [Mobile] [char](20) NULL,          
 [Message] [nvarchar](2500) NULL,          
 [M_ID] [bigint] NULL,          
 [U_ID] [int] NULL,          
 [SenderID] [nchar](20) NULL,          
