IsDnd,Operator,Priority,Isallowdnd,userFilter)   
  
output inserted.messagesourceid into #output          
  
SELECT TOP(@whilebatch) 
MessageSourceID,MessageID,MessageBatchID,Mobile,Message,M_ID,U_ID,SenderID,SmppID,ScheduleDate,ScheduleTime,MessageInsertDate,ScheduleTag,IsUniCode,          
IsDnd,Operator,Priority,Isallowdnd,userFilter FROM  mysms.dbo.MESSAGESOURCE with (nolock)     
