end          
  
 select MESSAGEID,[MessageBatchID] as 
BATCHID,MOBILE,MESSAGE,SENDERID,SMPPID,U_ID,PRIORITY,ISUNICODE,IsDND,OPERATOR,ISALLOWDND from #TEMPTABLE     

