/* ============================================================
   Procedure: [dbo].[Usp_MessageStatusDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


/*
Author : Madan lal Sharma
Purpose: Used to Check the Message Status in SMS19.info
Date   : 20-Sep-2013
User : Class MessageStatus.cs in Sms19.info

*/

CREATE   PROC Usp_MessageStatusDetails --'08/27/2013' ,'09/05/2013','X_MTIX_PROMO_','','Search'
	@FromDate Varchar (20),
	@ToDate Varchar (20),
	@Account Varchar (50),
	@Status Varchar (50),
	@Type varchar (10)
	
	as
		begin 
			--	select (CONVERT(nvarchar,CONVERT(datetime,'2013-08-28 00:01:01.557'),112))
			--select	convert(nvarchar,convert(datetime,'08/29/2013',111),112) 
			declare @Query varchar (max)
			declare @Wheres varchar (max)		
			set	 @Query=''
			set	 @Wheres=''
			if	@Type='Account'
				begin
					set	 @Query='SELECT Account  FROM [MySMS].[dbo].[MessageStatus](nolock)  group by Account'
				end
			else if	@Type='Status'
				begin
					set	 @Query='SELECT Delivered  FROM [MySMS].[dbo].[MessageStatus](nolock) group by Delivered'
				end	
			else if	@Type='Search'
				begin
					if @FromDate!='' and @ToDate!=''
						begin
							Set @Wheres = @Wheres+' (CONVERT(nvarchar,CONVERT(datetime,CreatedDate),112) 
							between convert(nvarchar,convert(datetime,'''+@FromDate+''',111),112) 
							and convert(nvarchar,convert(datetime,'''+@ToDate +''',111),112)) and '                                                                              
							
						end
					else
						begin
							set @Wheres= @Wheres + ' 1 = 1  and '
						end	
					if @Account!=''
						begin
							set @Wheres= @Wheres + ' Account = '''+ @Account + ''' and '
						end
					else
						begin
							set @Wheres= @Wheres + ' 1 = 1  and '
						end	
					if @Status!='' 
						begin
							 set @Wheres= @Wheres + ' Delivered = '''+ @Status + '''  '
						end
					else
						begin
							set @Wheres= @Wheres + ' 1 = 1   '
						end	
								
					   set @Query='	SELECT ID, Date, Account, ResultCode, Submitted, Delivered   FROM [MySMS].[dbo].[MessageStatus](nolock) where '+ @Wheres + ' order by resultcode '
				end	
				
			exec (@Query)		
			print(@Query)
		end
		return;
		
		
		



GO

