CREATE   PROCEDURE [dbo].[usp_MicrositeName]
	@UserID INT
AS
BEGIN
	SELECT DISTINCT cpd.Id,
	       cpd.PageName      AS PageName
	FROM   ClientPageDetail  AS cpd
	WHERE  cpd.[User_ID] = @UserID
END



