/* ============================================================
   Procedure: [dbo].[usp_MicrositeNameCampaign]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


--------Modified By Abhishek Makkar ----------- Time: 8/21/2017 2:43:51 PM------/  
CREATE   PROCEDURE [dbo].[usp_MicrositeNameCampaign]  
 @ParentID BIGINT  
AS  
BEGIN  
 SELECT DISTINCT cpd.Id,  
      'http://www.kit19.com/' + REPLACE(cpd.PageName, 'www.kit19.com/', '') AS PageName  
 FROM   ClientPageDetail             AS cpd  
        INNER JOIN CampaignAccounts  AS ca  
             ON  cpd.[User_ID] = ca.UserID  
 WHERE  ca.UserID IN (SELECT ud.[User_ID]  
                      FROM   User_Detail AS ud  
                      WHERE  ud.ParentID = @ParentID)  
END



