*/  
-- [dbo].[usp_mk_Cloud_get_UserDIDNo] 32222,0,2    
-- [dbo].[usp_mk_Cloud_get_UserDIDNo] 32222,0,0      
CREATE   PROC [dbo].[usp_mk_Cloud_get_UserDIDNo] --32222,0,0               
(                  
	@User_id bigint,        
	@appid int,        
	@opt int                 
)                  
as                   
begin                  
	if @opt=0                 
		select PhoneNo, 0 as AppId, 'NoName' as AppName from Cloud_User_Phone(nolock)
			where Parentid=@User_id and  Active = 1 -- and Appid = 0 
			and PhoneNo not in (select didno from dbo.Cloud_DIDDuty)
	if @opt=1        
		select *,FName+' '+Lname usr_name,dbo.Cloud_Get_User_Group(User_id)
		as Groupname ,Create_Date, role1 role
		from dbo.Cloud_User_Detail(nolock) where Parentid =@User_id  and Active=1
		and isnull(Mobile,'')!='' 
                      
                   
	if @opt=2        
	begin  
		select cm.PhoneNo, cm.AppId, cm.AppName  from Cloud_app_master(nolock) cm                        
			where cm.User_id = @User_id          
			and cm.appid in (select appid from dbo.Cloud_flow_api where Parentid =@User_id )                 
			and Active = 1           
	end        
end   
  
