/* ============================================================
   Procedure: [dbo].[usp_mk_DependentDetail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE  [dbo].[usp_mk_DependentDetail]  
(  
@ParentID bigint=0,      
@mode nvarchar(500)='',      
@FieldValue nvarchar(500)='',      
@DeleteID bigint=0      
)  
as      
begin 
--declare 
--	@parentID bigint = 46286,      
--	@mode nvarchar(500) = 'EditChildMapValue',      
--	@FieldValue nvarchar(500) = '5630',
--	@DeleteID bigint = 0

declare @seq smallint;                          
 select @seq=isnull(MAX(sequence), 0)+1 from customfields (NOLOCK) where ParentID=@parentID       
      
if(@mode='Parent')  --child of      
begin      
	SELECT field_ID, fieldname,DependencyJson   FROM  customfields (NOLOCK)         
	WHERE datatype = 's' AND isActive = 1 AND ParentID = @ParentID and field_ID != @FieldValue   
end      
if(@mode='Child')  --Parent of      
begin      
	SELECT field_ID, fieldname ,DependencyJson  FROM  customfields (NOLOCK)        
	WHERE datatype = 's' AND isActive = 1 AND ParentID = @ParentID AND   isnull(ParentFieldId,0)=0;             
end      
      
if(@mode='EditParentof')   -- child of      
begin 
	DECLARE @HasChild BIT = 0--,@ParentFieldId bigint     
	SELECT @HasChild = CASE WHEN EXISTS (SELECT 1 FROM customfields (NOLOCK) WHERE ParentFieldId = @FieldValue) THEN 1 ELSE 0 END;     
	DECLARE @HasParent BIT = 0; 
	SELECT @HasParent = CASE WHEN isnull(ParentFieldId,0) !=0 THEN 1 ELSE 0 END FROM customfields (NOLOCK) WHERE field_ID = @FieldValue;      
	--set @ParentFieldId=(select ParentFieldId from  [customfields] where field_ID=@FieldValue)      
	-- Main query to select the appropriate records      
      
	if( @HasChild = 0 AND @HasParent = 0 )      
	begin      
		SELECT field_ID,fieldname,DependencyJson
		FROM customfields (NOLOCK)
		WHERE datatype = 's' AND isActive = 1 and field_ID != @FieldValue and ParentID=@ParentID

		UNION

		SELECT field_ID, fieldname ,DependencyJson
		FROM customfields (NOLOCK)
		WHERE ParentFieldId = @FieldValue AND isActive = 1 and field_ID != @FieldValue
	end      
	else if ( @HasChild = 1 AND @HasParent = 0)      
	begin      
	 -- CTE to get all descendants of the current DDL      
		;WITH Descendants AS (      
		SELECT field_ID, ParentID      
		FROM customfields (NOLOCK)      
		WHERE parentfieldid = @FieldValue      
          
		UNION ALL      
          
		SELECT c.field_ID, c.ParentID      
		FROM customfields (NOLOCK) c      
		INNER JOIN Descendants d ON c.ParentfieldID = d.field_ID      
	 )      
	 SELECT field_ID,fieldname,DependencyJson FROM customfields (NOLOCK) WHERE datatype = 's' AND isActive = 1 and field_ID != @FieldValue AND field_ID NOT IN (SELECT field_ID FROM Descendants)  and ParentID=@ParentID      
 
	 UNION            
	SELECT field_ID, fieldname,DependencyJson AS choices      
	FROM customfields (NOLOCK)      
	WHERE ParentFieldId = @FieldValue AND isActive = 1      
      
	 end      
	 else if  (@HasParent = 1)      
	 begin      
		SELECT field_ID,fieldname,DependencyJson FROM customfields (NOLOCK) WHERE datatype = 's' AND isActive = 1 and 1=0 and ParentID=@ParentID      
	  UNION      
      
	SELECT field_ID, fieldname,DependencyJson AS choices      
	FROM customfields (NOLOCK)      
	WHERE ParentFieldId = @FieldValue AND isActive = 1      
	 end      
	end      
	if(@mode='EditChildof')  -- Parent of      
	begin      
	declare @ParentFieldId bigint      
	set @ParentFieldId=(select ParentFieldId from  [customfields] (NOLOCK) where field_ID=@FieldValue)      
	SELECT field_ID, fieldname,DependencyJson   FROM  customfields (NOLOCK)        
	WHERE datatype = 's' AND isActive = 1 AND ParentID = @ParentID AND (ParentFieldId IS NULL OR ParentFieldId = 0) 
	and field_ID != @FieldValue      
	UNION  
	SELECT field_ID, fieldname ,DependencyJson FROM customfields (NOLOCK) WHERE field_ID = @ParentFieldId AND isActive = 1 and field_ID != @FieldValue     
	end      
	if(@mode='ParentMapValue')        
	begin      
      
	SELECT field_ID, value AS choices into #temp2 FROM  customfields (NOLOCK)  CROSS APPLY STRING_SPLIT(choices, ',')       
	WHERE datatype = 's' AND isActive = 1 AND ParentID = @ParentID and field_ID in (@FieldValue)      
	select * from #temp2 where choices!=''      
      
	end      
      
	if(@mode='ChildMapValue')      
	begin      
		SELECT field_ID, value AS choices into #temp3 FROM  customfields (NOLOCK)  CROSS APPLY STRING_SPLIT(choices, ',')       
		WHERE datatype = 's' AND isActive = 1 AND ParentID = @ParentID and field_ID in (@FieldValue)--and ParentFieldId in (@FieldValue)      
		select * from #temp3 where choices!=''      
	end      
      
	if(@mode='EditParentMapValue')      
	begin      
	SELECT field_ID, DependencyJson, choices   FROM  customfields (NOLOCK)  where ParentFieldId=@FieldValue AND ParentID = @ParentID AND isActive = 1      
	end      
	if(@mode='EditChildMapValue')      
	begin    
		declare @fieldId bigint, @fieldName nvarchar(255),  @dependencyJson nvarchar(max), @choices nvarchar(max), @prentFieldId bigint
		SELECT @fieldId = field_ID, @fieldName = fieldname, @dependencyJson = DependencyJson, @choices = choices, @prentFieldId = ParentFieldId 
			FROM  customfields (NOLOCK)  where field_ID=@FieldValue AND ParentID = @ParentID AND isActive = 1

		declare @parentChoices nvarchar(max) 
		
		select @parentChoices = choices from customfields(nolock) where field_ID = @prentFieldId
		print concat('@ParentFieldId => ', @prentFieldId)

		drop table if exists #parenChildMap
		create table #parenChildMap(ParentValue nvarchar(255), ChildValue nvarchar(max))

		insert into #parenChildMap(ParentValue, ChildValue)
		select ParentValue, ChildValue from openjson(@dependencyJson) with (
			ParentValue nvarchar(255) '$.ParentValue',
			ChildValue nvarchar(max) '$.ChildValue' as json )

		insert into #parenChildMap(ParentValue, ChildValue)
		select [value], '[]' from string_split(@parentChoices, ',')
			where [value] not in ( select ParentValue from #parenChildMap)
		
		select @dependencyJson  = ( SELECT ParentValue, json_query(ChildValue) as ChildValue FROM #parenChildMap FOR JSON PATH )
		select @fieldId as field_ID, @fieldName as fieldname, @dependencyJson as DependencyJson, @choices as choices, @prentFieldId as ParentFieldId 

	end      
	if(@mode='DeletechildofParent')      
	begin      
		update customfields set parentfieldid=0 ,DependencyJson='' where field_ID=@FieldValue and ParentFieldId=@DeleteID      
      
	end      
	if(@mode='DeleteParentofChild')      
	begin      
		update customfields set parentfieldid=0 ,DependencyJson='' where field_ID=@DeleteID and ParentFieldId=@FieldValue
	end      
end



GO

