/* ============================================================
   Procedure: [dbo].[usp_mk_ExcutiveLocationAutoSuggestion]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- usp_mk_ExcutiveLocationAutoSuggestion 32222, 'vik'      
CREATE   PROCEDURE usp_mk_ExcutiveLocationAutoSuggestion      
(      
 @UserId BIGINT,      
 @SearchText VARCHAR(100)      
)      
AS        
BEGIN        
 DECLARE @Role VARCHAR(10) = ''        
       
 SELECT @Role = (CASE WHEN IsAdmin = 1 THEN 'SuperAdmin' ELSE isnull(TR.Role,'') END)       
 FROM User_Detail(nolock) UD LEFT JOIN tbl_location_territory_mapping(nolock) TR       
 ON UD.User_ID = TR.User_ID       
 WHERE UD.User_ID=@UserId      
      
 IF(@Role = '')      
 BEGIN      
  print 1.0      
  SELECT 0 as ID, 'UnAuthorized User' as Name, '' as Type      
 END      
 ELSE      
 BEGIN      
  print 1.1      
  IF(@Role = 'SuperAdmin')        
  BEGIN        
   print 1.2      
   Select *      
   From      
   (      
    select ID, Name, 'T' as [TYPE] from tbl_location_territory(nolock) where CreatedBy = @UserId    
    UNION        
    select distinct LTM.User_ID as ID, UD.User_Login as [Name] , 'U' as [TYPE]       
    from tbl_location_territory_mapping(nolock) LTM inner join User_Detail(nolock) UD      
    On  LTM.User_Id = UD.User_Id inner join tbl_location_territory LT  
 on LTM.Territory_Id=LT.ID  
 Where LT.CreatedBy = @UserId    
   ) A WHERE A.Name LIKE @SearchText+'%'        
  END        
        
  print 1.3      
  IF(@Role = 'Manager')        
  BEGIN      
   print 1.4      
   SELECT *       
   FROM       
   (      
    select LT.ID, LT.Name, 'T' as [TYPE]       
    from tbl_location_territory(nolock) LT inner join tbl_location_territory_mapping(nolock) LTM      
    on  LT.ID = LTM.Territory_Id      
    where LTM.User_Id  = @UserId        
    UNION        
    select distinct UD.User_ID as ID, UD.User_Login as [Name], 'U' as [TYPE]       
    from User_Detail(nolock) UD INNER JOIN tbl_location_territory_mapping(nolock) LTM       
    ON  UD.User_ID = LTM.User_ID       
    WHERE LTM.Territory_Id in (SELECT Territory_Id FROM tbl_location_territory_mapping(nolock) where User_ID = @UserId)      
   ) A WHERE A.Name LIKE @SearchText+ '%'        
  END      
       
  print 1.5      
  IF(@Role = 'User')        
  BEGIN      
   print 1.6      
   SELECT *       
   FROM       
   (      
    select LT.ID, LT.Name, 'T' as [TYPE]       
    from tbl_location_territory(nolock) LT inner join tbl_location_territory_mapping(nolock) LTM      
    on  LT.ID = LTM.Territory_Id      
    where LTM.User_Id  = @UserId        
    UNION        
    select distinct UD.User_ID as ID, UD.User_Login as [Name], 'U' as [TYPE]       
    from User_Detail(nolock) UD INNER JOIN tbl_location_territory_mapping(nolock) LTM       
    ON  UD.User_ID = LTM.User_ID       
    WHERE LTM.User_ID = @UserId      
   ) A WHERE A.Name LIKE @SearchText+ '%'        
  END      
  print 1.7      
       
 END      
      
 print 1.8      
      
END   


GO

/* ============================================================
   Procedure: [dbo].[Usp_MK_ExecutiveLatLngByUserID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE dbo.Usp_MK_ExecutiveLatLngByUserID -- Usp_MK_ExecutiveLatLngByUserID 32222              
(               
@UserID Bigint      
)              
as              
Begin   
           
select rt1.ID, rt1.UserID,(select top 1  isnull(ud.FName+' '+ISNULL(ud.LName,''),User_Login)           
from User_Detail where User_ID = rt1.UserID) as ExecutiveName ,rt1.Latitude,rt1.Longitude,  
rt1.MeaningfulAddress,rt1.CreatedDate, CONVERT(varchar(10), Cast(ud.Mobile as decimal(10, 0))) Mobile, ud.Image,  
ud.FName+' '+ISNULL(ud.LName,'') AS Territory  
INTO #TEMP      
           From RealTimeLocation(nolock) as rt1 left outer join User_Detail ud (nolock)     
     on rt1.UserID= ud.User_ID      
     where  isnull(rt1.MeaningfulAddress,'') !=''           
           and rt1.MeaningfulAddress != 'Object reference not set to an instance of an object.'           
           and rt1.ID in (select MAX(ID) from RealTimeLocation(nolock) as rt2              
             group by rt2.UserID)   
  and rt1.UserID = @UserID      
 order by rt1.CreatedDate desc          
   
 update a  
 set a.Territory = isnull(c.Name,'')  
 from #TEMP a left outer join tbl_location_territory_mapping b on a.UserID = b.User_ID  
 left outer join tbl_location_territory c(nolock) on b.Territory_ID = c.ID  
  
 select * from #TEMP  
 drop table #TEMP  
                
End



GO

/* ============================================================
   Procedure: [dbo].[usp_mk_FollowupDataForDashboard]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_mk_FollowupDataForDashboard] (    
 @UserId bigint,    
 @ActivityDate date    
)    
as    
begin    

 --declare @UserId bigint = 38439, @ActivityDate date = '20250418' --, @Mode char(1) = 'C'    
 declare @StartDate datetime = cast(@ActivityDate as date),     
 @EndDate datetime = dateadd(hh, 24, cast(@ActivityDate as datetime)),    
 @ParentId bigint = (select ParentID from User_Detail(nolock) where User_ID = @UserId)    
  
 select @StartDate = StartDateTime, @EndDate = EndDateTime from fn_getIndiaStartEndTimefromUserTime(@UserId, @ActivityDate)  
   
 --declare @UserIdTeamLst varchar(500) = ''       
 --Declare @IsAdmin bit = 0        
 --declare @tbluser table (User_ID bigint,Name varchar(100), Image varchar(100))  
 --select @IsAdmin = IsAdmin from User_Detail(nolock) where User_ID = @UserId  
 --if(@IsAdmin = 1)  
 --begin  
 -- set @UserId = 0;  
 -- insert into @tbluser  
 -- exec Use_GetUserDetails @ParentId  
 --end  
 --else  
 --Begin  
 -- insert into @tbluser  
 -- exec Use_GetUserDetails @UserId  
 --End  
  
 --select @UserIdTeamLst=isnull(STRING_AGG(User_ID,','),'') From @tbluser  
  
 drop table if exists #tempUsers    
 create table #tempUsers(User_ID bigint, Name nvarchar(255), Image nvarchar(255))    
 insert into #tempUsers(User_ID, Name, Image)    
 exec Use_GetUserDetails @UserID = @UserId    
  
 select     
  lih.ID as id,    
  fs.FollowupStatus as Title,  lih.FollowupDate,  
  dbo.fn_getusertimefromindiantime(@UserId,lih.CreatedOn) as StartDate,    
  dbo.fn_getusertimefromindiantime(@UserId, ( case   
  when fs.IsCallback = 1 and lih.TaskStatus <> 'Due' then lih.FollowupDate   
  when lih.TaskStatus = 'Due' then lih.CreatedOn   
  else lih.FollowupDate  end) ) as EndDate,    
  dbo.fn_getusertimefromindiantime(@UserID,lih.CreatedOn) CreatedOn,   
  ul.ID as LeadId,   
  ul.PersonName,   
  ul.ProfileImgFileName as PersonImage,     
  ud.User_ID as AgentId,    
  trim(concat(trim(cast(ud.FName as nvarchar)), ' ', trim(cast(ud.LName as nvarchar)))) as AgentName,    
  ud.Image as AgentImage,    
  (case when fs.IsCallback = 1 and lih.TaskStatus <> 'Due' then 'Completed'   
  else lih.TaskStatus end ) as [TaskStatus],  
  ud.ParentID as ParentId,    
  fs.Intent,    
  0 as IsEditable,    
  0 as IsRemoval,    
  lih.lihCount    
  from (    
   select *, (case   
  when cast(ab.CreatedOn as date) < cast(ab.FollowupDate as date)   
   and  cast(ab.FollowupDate as date) = cast(@ActivityDate as date)  and ab.lihCount = 1 then 'Due'  
  when cast(ab.FollowupDate as date) > cast(@ActivityDate as date) and ab.lihCount = 1 then 'Schedule'  
  when cast(ab.FollowupDate as date) < cast(@ActivityDate as date) and ab.lihCount = 1 then 'Due'  
  when cast(ab.FollowupDate as date) = cast(@ActivityDate as date) and ab.lihCount = 1 then 'Completed'   
  else 'Completed' end) as [TaskStatus] from (    
    select     
     li.ID,    
     li.FollowupDate,    
     li.CreatedOn,   
     li.NextStatusDate,   
     li.FollowUpStatus,   
     li.LeadNo,   
     li.CreatedBy,   
     li.ParentID,   
     li.Assignedto,   
     row_number() over(partition by li.ParentID, li.LeadNo order by li.ID desc) as lihCount  
    from LeadInteractionHistory(nolock) li 
     where li.ParentId = @ParentId
		--and Cast(FollowupDate as date) = cast(@ActivityDate as date) and   
		--and @UserId in (isnull(li.CreatedBy, 0), isnull(li.AssignedTo, 0))      
		--((isnull(li.CreatedBy, 0) in (select [value] from dbo.fn_Split(@UserIdTeamLst, ','))) or   
		--(isnull(li.AssignedTo, 0) in (select [value] from dbo.fn_Split(@UserIdTeamLst, ','))))
		--and cast(@ActivityDate as date) in (cast(li.FollowupDate as date), cast(li.CreatedOn as date))
	) ab 
	--where 1 = (case when cast(ab.FollowupDate as date) = cast(@ActivityDate as date) and ab.lihCount = 1 and @userid=isnull(ab.AssignedTo, 0) then 1   
	--when cast(ab.CreatedOn as date) = cast(@ActivityDate as date) and   
	--ab.lihCount >= 1 and @userid=isnull(ab.createdby, 0) then 1   
	--else 0 end)   
) lih   
  inner join FollowUp_Status(nolock) fs  on lih.FollowUpStatus = fs.ID   
  inner join UserLeads(nolock) ul on lih.LeadNo = ul.LeadNo and ul.ParentID = lih.ParentID   
  inner join #tempUsers tu on isnull(ul.AssignedTo, ul.CreatedBy) = tu.User_Id 
  inner join User_Detail(nolock) ud on lih.CreatedBy = ud.User_ID   
  where  --lihCount = 1 and  
 cast(@ActivityDate as date) in (isnull(cast(lih.FollowupDate as date),  cast(lih.CreatedOn as date)))   
  
 order by lih.ID desc   
  
end



GO

/* ============================================================
   Procedure: [dbo].[usp_mk_FollowupDataForDashboardNew]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_mk_FollowupDataForDashboardNew] (  
 @UserId bigint,  
 @ActivityDate date,
 @FilterText varchar(20),
 @Start int,
 @Limit int  
)
as  
begin  
 --declare @UserId bigint = 34594, @ActivityDate date = '2022-04-13 23:59:59.999', @Mode char(1) = 'C'  
 declare   

  @StartDate datetime = cast(@ActivityDate as datetime),   
  @EndDate datetime = dateadd(hh, 24, cast(@ActivityDate as datetime)),  
  @ParentId bigint = (select ParentID from User_Detail(nolock) where User_ID = @UserId)  

  --declare @TeamCode varchar(10) = ''    
  --declare @ScopeCode varchar(10) = ''     
  declare @UserIdTeamLst varchar(500) = ''     
  select @UserIdTeamLst = UserIdTeamLst from MySMS.dbo.ufn_GetUserRoleScope(@UserId)     

 select   
  lih.ID as id,  
  fs.FollowupStatus as Title,  
  lih.FollowupDate as StartDate,  
  lih.FollowupDate as EndDate,  
  lih.CreatedOn,  
  ul.ID as LeadId,  
  ul.PersonName,   
  ul.ProfileImgFileName as PersonImage,   
  ud.User_ID as AgentId,  
  trim(concat(trim(cast(ud.FName as nvarchar)), ' ', trim(cast(ud.LName as nvarchar)))) as AgentName,  
  ud.Image as AgentImage,  
  ( case   
   when lih.lihCount = 1 then 'Due'  
   else 'Completed'end   
  ) as TaskStatus,  
  ud.ParentID as ParentId,  
  fs.Intent,  
  0 as IsEditable,  
  0 as IsRemoval,  
  lih.lihCount  
  from (  
   select * from (  
    select   
     li.ID,  
     li.FollowupDate,  
     li.CreatedOn,  
     li.NextStatusDate,  
     li.FollowUpStatus,  
     li.LeadNo,  
     li.CreatedBy,  
     li.ParentID,  
     li.Assignedto,  
     row_number() over(partition by li.ParentID, li.LeadNo order by li.ID desc) as lihCount  
    from LeadInteractionHistory(nolock) li    
     where li.ParentId = @ParentId and 
	-- and @UserId in (isnull(li.CreatedBy, 0), isnull(li.AssignedTo, 0))  
	 ((isnull(li.CreatedBy, 0) in (select [value] from dbo.fn_Split(@UserIdTeamLst, ','))) or 
	 (isnull(li.AssignedTo, 0) in (select [value] from dbo.fn_Split(@UserIdTeamLst, ','))))
     --and  @ActivityDate in (cast(li.FollowupDate as date), cast(li.CreatedOn as date))  
   ) ab  where 1 =  case when cast(ab.FollowupDate as date) = cast(@ActivityDate as date) and ab.lihCount = 1 and @userid=isnull(ab.AssignedTo, 0) then 1  
   when ab.lihCount > 1 and @userid=isnull(ab.createdby, 0) then 1  
    else 0 end   
  ) lih  
  inner join FollowUp_Status(nolock) fs  on lih.FollowUpStatus = fs.ID   
  inner join UserLeads(nolock) ul on lih.LeadNo = ul.LeadNo and ul.ParentID = lih.ParentID  
  inner join User_Detail(nolock) ud on lih.CreatedBy = ud.User_ID  
   
 order by lih.ID desc  
 offset @Start rows fetch next @Limit rows only

end  



GO

