/* ============================================================
   Procedure: [dbo].[usp_mk_get_notification]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC usp_mk_get_notification  --32222,'',''
(  
@User_ID bigint,  
@FromDate datetime,  
@ToDate datetime  
)  
as  
begin  
  
DECLARE @Datefrom DATETIME, @Dateto DATETIME;    
    
 IF(@Fromdate = '')    
 BEGIN    
  SET @Datefrom = DATEADD(mm,-1,getdate());    
 END;    
 ELSE    
 BEGIN    
  SET @Datefrom = @Fromdate;    
 END;
 
    
 IF(@Todate = '')    
 BEGIN    
  SET @Dateto = getdate();    
 END;    
 ELSE    
 BEGIN    
  SET @Dateto = @Todate;    
 END;    
 
  SELECT Title, MessageText, ScheduleOn    
 FROM     
 (    
select n.Title, n.MessageText, FORMAT(n.ScheduledDate, 'dd-MMM-yyyy hh:mm:ss tt') AS ScheduleOn  
from MK_BatchNotification n (nolock)  
inner join MK_BatchNotificationDetail d(nolock)  
on n.BatchNotification_Id = d.BatchNotification_Id  
where d.User_ID = @User_ID   
)AS tblDetail    
where CONVERT(DATETIME, CONVERT(VARCHAR(11), ScheduleOn, 106)) BETWEEN @Datefrom AND @Dateto    
  
end


GO

