/* ============================================================
   Procedure: [dbo].[usp_mk_get_territory_details]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

    
--usp_get_territory_details 27701,27701      
CREATE   PROC usp_mk_get_territory_details        
(          
@ParentID varchar(10),          
@User_ID  varchar(10)          
)          
as          
begin          
Declare @Role varchar(50)          
set @Role = (select distinct Role from tbl_location_territory_mapping (nolock) where User_ID = @User_ID)          
          
if (@Role = 'Manager')          
begin          
select distinct t.ID,t.Name, t.Description,t.ParentID,          
(Select SUBSTRING(( SELECT ',' + PersonName AS 'data()' FROM tbl_location_territory_mapping(NOLOCK) where Territory_Id = t.ID            
        and Role = 'Manager' FOR XML PATH('')), 2 , 9999) As Manager) As Manager,           
(Select SUBSTRING(( SELECT ',' + PersonName AS 'data()' FROM tbl_location_territory_mapping(NOLOCK) where Territory_Id = t.ID            
        and Role = 'User' FOR XML PATH('')), 2 , 9999) As Executive) As Executive           
from tbl_location_territory(NOLOCK) t
inner join tbl_location_territory_mapping(NOLOCK) m
on t.ID = m.Territory_Id          
where convert(varchar(10),t.ParentID) = @ParentID          
end          
else          
begin          
select distinct t.ID,t.Name, t.Description,t.ParentID,          
(Select SUBSTRING(( SELECT ',' + PersonName AS 'data()' FROM tbl_location_territory_mapping(NOLOCK) where Territory_Id = t.ID            
        and Role = 'Manager' FOR XML PATH('')), 2 , 9999) As Manager)As Manager,           
(Select SUBSTRING(( SELECT ',' + PersonName AS 'data()' FROM tbl_location_territory_mapping(NOLOCK) where Territory_Id = t.ID and User_ID = @User_ID           
        and Role = 'User' FOR XML PATH('')), 2 , 9999) As Executive)  As Executive        
from tbl_location_territory(NOLOCK) t
inner join tbl_location_territory_mapping(NOLOCK) m
on t.ID = m.Territory_Id          
where convert(varchar(10),m.User_ID) = @User_ID  and convert(varchar(10),t.ParentID) = @ParentID         
end          
end 


GO

