/* ============================================================
   Procedure: [dbo].[usp_mk_GetActivityDetailsById]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_mk_GetActivityDetailsById]
(
	@Parentid BIGINT,
	@Userid INT = 0,
	@Columns NVARCHAR(MAX) = '',
	@FilterExp NVARCHAR(MAX) = '',
	@OutputAllCols bit=0,
	@Mode varchar(10)=''
)
AS
BEGIN
         
   -- Value swaping because ColumnView not working while passing {O in UserId}      
   declare @vmUserId bigint = @UserId, @IsAdmin bit = 0; 
   select @IsAdmin = IsAdmin from User_Detail(nolock) where User_ID = @Userid 

	if(@Parentid = @Userid or @IsAdmin = 1)
	begin
		set @Userid = 0
	end

    DECLARE @Query NVARCHAR(MAX)= '';                          
                          
    SET @Query= CAST(N'select e.ID LeadPipe, P.ID as PipelineID, P.Name PipeLineName, s.Name  PipeLineStageName, e.Probability, e.Amount, 
	ud.FName + '' '' + ud.LName FullName, ud.User_Login, e.EstimatedClosureDate, e.Remarks, e.CreatedDate from Pipeline_Master P       
    join PipelineStages S on P.id=S.PipelineID 
    join LeadPipelineMapping e on e.PipeLineStage=S.ID 
    join User_Detail ud on e.CreatedBy=ud.User_ID 
    where e.isdeleted=0 and e.'+ @FilterExp +' and 
   e.id in (select isnull(id,0) from LeadPipelineMapping where LeadID=e.LeadID and PipeLineStage=e.PipeLineStage) order by e.ID Asc ' AS NVARCHAR(MAX));   
    
	print '@FinalQuery:- ' + cast(@Query as varchar(max))                          

  EXEC sp_executesql @Query;                          
END 



GO

/* ============================================================
   Procedure: [dbo].[usp_mk_GetActivityListByLeadId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_mk_GetActivityListByLeadId]      
(      
 @Parentid BIGINT,      
 @Userid INT = 0,      
 @Columns NVARCHAR(MAX) = '',      
 @FilterExp NVARCHAR(MAX) = '',      
 @Ordstr NVARCHAR(MAX) = '', --order by column name ex Enquiryid      
 @Sdate VARCHAR(50) = '', --start date      
 @Edate VARCHAR(50) = '', --end date      
 @OutputAllCols bit=0,      
 @Mode varchar(10)=''      
)      
AS      
BEGIN      
               
   -- Value swaping because ColumnView not working while passing {O in UserId}            
   declare @vmUserId bigint = @UserId, @IsAdmin bit = 0;       
   select @IsAdmin = IsAdmin from User_Detail(nolock) where User_ID = @Userid       
      
 if(@Parentid = @Userid or @IsAdmin = 1)      
 begin      
  set @Userid = 0      
 end      
      
      
    DECLARE @Query NVARCHAR(MAX)= '';                                
                                
    SET @Query= CAST(N'select e.ID LeadPipeLineMappingId, e.LeadId, P.ID as PipelineID, P.Name PipeLineName, s.Name  PipeLineStageName, e.Probability, e.Amount,       
 ud.FName + '' '' + ud.LName FullName, ud.User_Login, e.EstimatedClosureDate, e.Amount,UL.ProfileImgFileName, e.CreatedDate from Pipeline_Master P             
    join PipelineStages S on P.id=S.PipelineID       
    join LeadPipelineMapping e on e.PipeLineStage=S.ID       
    join User_Detail ud on e.CreatedBy=ud.User_ID       
 join UserLeads UL on e.LeadID = UL.ID  
    where e.isdeleted=0 and e.'+ @FilterExp +' and       
   e.id in (select isnull(id,0) from LeadPipelineMapping where LeadID=e.LeadID and PipeLineStage=e.PipeLineStage) order by e.ID Asc ' AS NVARCHAR(MAX));         
          
 print '@FinalQuery:- ' + cast(@Query as varchar(max))                                
      
  EXEC sp_executesql @Query;                                
END       
  



