/* ============================================================
   Procedure: [dbo].[usp_mk_GetBalance]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_mk_GetBalance
(    
   @UserID Bigint,
   @M_ID Bigint     
)    
as    
Begin

declare @IntCredit_Balance decimal
declare @Mail_Balance bigint
declare @SMS_Balance Bigint


if exists(select 1 from user_detail where HasVirtualCredits=1 and IsSuperReseller=1 and USER_ID=@UserID)        
begin        
declare @actualbalance bigint= isnull((select top 1 balance from  SuperResellerMailCreditDetails   
where m_id=@m_id and user_id=@UserID order by credit_id desc),0)
SELECT TOP 1 @Mail_Balance =  cast(balance as nvarchar)+'('+cast(@actualbalance as nvarchar)+')' FROM   MailCreditDetails 
WHERE  m_id = @M_ID  AND USER_ID = @UserID 
ORDER BY credit_id       DESC        
end        
else        
begin  
SELECT TOP 1 @Mail_Balance = ISNULL(balance,0) FROM   MailCreditDetails WHERE  m_id = @M_ID  AND USER_ID = @UserID ORDER BY credit_id DESC         
end               
 
if exists(select 1 from user_detail where HasVirtualCredits=1 and IsSuperReseller=1 and USER_ID=@UserID)      
begin      
declare @actualbalance1 bigint= isnull((select top 1 balance from  superresellercredit_details where m_id=@M_ID and user_id=@UserID order by credit_id desc),0)
select top 1 @SMS_Balance = cast(balance as nvarchar) + ' ( ' +cast(@actualbalance1 as nvarchar) + ' ) '     
from credit_details --with(index(idx_Credit_id_user_id_m_id))           
where m_id=@M_ID and user_id=@UserID order by credit_id desc                
end      
else      
begin  
select top 1 @SMS_Balance = ISNULL(balance,0)  from credit_details --with(index(idx_Credit_id_user_id_m_id))           
where m_id=@M_ID and user_id=@UserID order by credit_id desc                
end    
select top 1 @IntCredit_Balance = isnull(Balance,0)  From IntCredit_Details  where USER_ID = @UserID order by Credit_ID desc

select @IntCredit_Balance as IntCredit_Balance,Convert(Varchar(8),@Mail_Balance) as Mail_Balance,Convert(Varchar(8),@SMS_Balance) as SMS_Balance
end 


GO

