/* ============================================================
   Procedure: [dbo].[usp_mk_GetCustomFields]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- exec usp_mk_GetCustomFields @ParentID=32222, @FieldId=0, @IsMandatory=default, @IsQuickAdd=default
-- exec usp_mk_GetCustomFields @ParentID=32222, @FieldId=0, @IsMandatory=1, @IsQuickAdd=default
-- exec usp_mk_GetCustomFields @ParentID=32222, @FieldId=368, @IsMandatory=-1, @IsQuickAdd=default
CREATE   PROC usp_mk_GetCustomFields
(
	@ParentID bigint,
	@FieldId bigint=0,
	@IsMandatory int=-1,
	@IsQuickAdd int=-1
)
AS
Begin

select		field_ID,ParentID,fieldname,datatype,sequence,minvalue,maxvalue,isActive,isMandatory,defaultValue,quickAdd,currentDate
From		customfields
Where		ParentID=@ParentID and isActive=1 
			and Field_Id=Case when @FieldId=0 then Field_Id else @FieldId end 
			and isMandatory=Case when @IsMandatory=-1 then isMandatory else @IsMandatory end 
			and quickAdd=Case when @IsQuickAdd=-1 then quickAdd else @IsQuickAdd end
Order By	sequence

End



GO

