CREATE   PROCEDURE [dbo].[usp_mk_GetEnquiryLeadByMobileNo] --'8035714556',43889     
(                
 @MobileNo nVARCHAR(20),                
 @UserId bigint                
)                
AS                  
BEGIN         
      
--declare @MobileNo VARCHAR(20) = '+91730309678',--'+919911076042',                
--@UserId bigint  = 34594  

declare @cid_id bigint,@cid_json nvarchar(max)
insert into callerid_detected(CallerMobile,user_id)
select @MobileNo,@userid
select @cid_id=scope_identity()
      
set @MobileNo=REPLACE(@mobileno,'+91','')       

set @MobileNo = dbo.fn_trim0prefix(@mobileno)--IIF(LEFT(@MobileNo,1) = 0, RIGHT(@MobileNo, len(@MobileNo)-1), @MobileNo)      
      
PRINT @MobileNo      
      
----set @MobileNo=REPLACE(@mobileno,'+91','')       
drop table if exists #caller
 
create table #caller(MobileNo nvarchar(20))                
insert into #caller              
exec usp_getcallersmobile @userid,@Mobileno              


              
if exists(select 1 from #caller where Mobileno is not null)              
select top 1 @mobileno=Mobileno from #caller              
 print concat('Mobile: ',@mobileno)             
drop table #caller              
-- -- declare @MobileNo VARCHAR(15)='9313943059'                

declare @LastContacted varchar(30)='', @CallDirection varchar(15)='', @ParentId bigint=0 ,@entity nvarchar(20),@entityid bigint, @entityidNew bigint,@leadno bigint,    
  @company nvarchar(100),@ProfileImgFileName nvarchar(200),@lastactivity nvarchar(100),@lastactivitydate datetime = null,@lastactivitydetails nvarchar(1000),    
  @fullname nvarchar(100),@leadscore int    
                
Select @ParentId=ParentID From User_Detail(nolock) Where User_ID=@UserId                
 
--------------------------------------------------------------------------------------------------------------------------------------

--select top 1 @LastContacted=callcreatedon, @CallDirection=(CASE Direction WHEN 'incoming' THEN 'In' WHEN 'outgoing' THEN 'Out' ELSE 'In' END) ,    
-- @entity=isnull(customerentity,'New'),@entityid=isnull(nullif(customerentityid,''),0)    
--from calllog(nolock) where customernumber=@MobileNo and parentid=@ParentId    
-- order by id desc    
--select @MobileNo     
if exists (Select top 1 '1' from UserLeads_mobile_email(nolock) where ParentID = @ParentId and mobile<>'0' and 
dbo.fn_trim0prefix(mobile)=dbo.fn_trim0prefix(@MobileNo))--@entity='lead'    
begin    
set @entity='lead'
Select top 1 @entityid = ulme_id from UserLeads_mobile_email(nolock) where ParentID = @ParentId and mobile<>'0' and 
dbo.fn_trim0prefix(mobile)=dbo.fn_trim0prefix(@MobileNo) order by ulme_id desc
select @entityidNew = ID, @fullname=dbo.fn_getentityfullname('lead',@entityid)--+'-'+@MobileNo  
,@company=CompanyName,@leadno=leadno,@ProfileImgFileName=ProfileImgFileName from userleads(nolock) where id=@entityid    
select top 1 @lastactivity=a.EventName,@lastactivitydate=EventDate,@lastactivitydetails=EventDescription from tbl_LeadEventHistory(nolock) t     
join activitymaster(nolock) a on a.id=t.eventid where leadid=@entityid order by Historyid desc    
select top 1 @leadscore=CurrentScore from lead_score_history_latest(nolock) where leadid=@entityid order by id desc    
end 
else if exists (Select top 1 '1' from UserEnquiry_mobile_email(nolock) where ParentID = @ParentId and mobile<>'0' and 
dbo.fn_trim0prefix(mobile)=dbo.fn_trim0prefix(@MobileNo))--@entity='enquiry' 
begin
set @entity='enquiry'

 Select top 1 @entityid = EnquiryID from UserEnquiry_mobile_email(nolock) where ParentID = @ParentId and mobile<>'0' and 
dbo.fn_trim0prefix(mobile)=dbo.fn_trim0prefix(@MobileNo) order by enquiryid desc
select @entityidNew = EnquiryId, @fullname=dbo.fn_getentityfullname('enquiry',@entityid)--+'-'+@MobileNo 
,@company=CompanyName,@leadno=0,@ProfileImgFileName=ProfileImgFileName, @leadscore=''    
from userenquiry(nolock) where EnquiryID=@entityid 
select top 1 @lastactivity=a.EventName,@lastactivitydate=EventDate,@lastactivitydetails=EventDescription from tbl_enquiryEventHistory(nolock) t     
join activitymaster(nolock) a on a.id=t.eventid where EnquiryID=@entityid order by Historyid desc    
end    
else     
begin   
set @entity='New'

if exists (select 1 from Userleads_Mobile_Email(nolock) where mobile=@mobileno and parentid=@ParentId)  
begin  
select top 1 @entityid=ulme_id,@entity='Lead' from Userleads_Mobile_Email(nolock) where mobile=@mobileno and parentid=@ParentId order by ulme_id desc  
select @entityidNew = ID, @fullname=dbo.fn_getentityfullname('lead',@entityid)--+'-'+@MobileNo  
,@company=CompanyName,@leadno=leadno,@ProfileImgFileName=ProfileImgFileName from userleads(nolock) where id=@entityid    


select top 1 @lastactivity=a.EventName,@lastactivitydate=EventDate,@lastactivitydetails=EventDescription from tbl_LeadEventHistory(nolock) t     
join activitymaster(nolock) a on a.id=t.eventid where leadid=@entityid order by Historyid desc  



select top 1 @leadscore=CurrentScore from lead_score_history_latest(nolock) where leadid = @entityid order by id desc    
  
end  
else if exists (select 1 from Userenquiry_Mobile_Email(nolock) where mobile=@MobileNo and parentid=@parentid)  
begin  
select top 1 @entityid=enquiryid,@entity='Enquiry' from Userenquiry_Mobile_Email(nolock) where mobile=@mobileno and parentid=@ParentId order by enquiryid desc  
  
select @entityidNew = EnquiryId, @fullname=dbo.fn_getentityfullname('enquiry',@entityid)--+'-'+@MobileNo  
,@company=CompanyName,@leadno=0,@ProfileImgFileName=ProfileImgFileName    
,@leadscore=''    
from userenquiry(nolock) where EnquiryID=@entityid    
select top 1 @lastactivity=a.EventName,@lastactivitydate=EventDate,@lastactivitydetails=EventDescription from tbl_enquiryEventHistory(nolock) t     
join activitymaster(nolock) a on a.id=t.eventid where EnquiryID=@entityid order by Historyid desc    
  
end  
else  
begin

select @entityidNew = 0, @fullname=@MobileNo,@company='',@leadno=0,@ProfileImgFileName='',@lastactivity='',@lastactivitydate=null,@lastactivitydetails='',@leadscore=''

end 
end 
    
	

select top 1 @LastContacted=callcreatedon, @CallDirection=(CASE Direction WHEN 'incoming' THEN 'In' WHEN 'outgoing' THEN 'Out' ELSE 'In' END)     
 from calllog(nolock) where customerentity=@entity and customerentityid=@entityid   and parentid=@ParentId    
 order by id desc    
     
  
if( @entityidNew is null)    
 set @entityidNew = 0    
    


Declare @AppointmentTitle nvarchar(100) = '', @AppointmentAddedDays int = 0
set @AppointmentTitle = isnull((select top 1 Title FROM tbl_tsk_TaskHistory(NOLOCK) where IsActive = 1 and IsAppointment = '1' and LeadId = @entityidNew), 'blank')

select top 1 @AppointmentTitle = isnull(Title, 'Blank'), @AppointmentAddedDays = (case when ttth.CreatedOn is null then 0 else DATEDIFF(DAY, cast(ttth.CreatedOn as date), cast(GETDATE() as date)) end) FROM tbl_tsk_TaskHistory(NOLOCK) ttth where IsActive = 1 and IsAppointment = '1' and 1 = (case when isnull(@entityidNew, 0) > 0 and LeadId = @entityidNew
			then 1 else 0 end )

select @entityidNew as ID, @fullname as PersonName, @MobileNo as [CallFromMobileNo], isnull(@company,'') as CompanyName,isnull(@ProfileImgFileName,'') as ProfileImgFileName,@LastContacted as Lastcontacted, @CallDirection as CallDirection, @entity as Type, @lastactivitydate as Lastactivitydate,@lastactivity as LastActivity, @lastactivitydetails as LastActivityDetails,
isnull(DATEDIFF(DAY, cast(@lastactivitydate as date), cast(GETDATE() as date)), 0) LastCallDays,
isnull(@leadscore,0) as LeadScore, isnull(@AppointmentTitle, '') AppointmentAdded, @AppointmentAddedDays AppointmentAddedDays

select @cid_json=
(SELECT * FROM               
(select @entityidNew as ID, @fullname as PersonName, @MobileNo as [CallFromMobileNo], isnull(@company,'') as CompanyName,isnull(@ProfileImgFileName,'') as ProfileImgFileName,@LastContacted as Lastcontacted, @CallDirection as CallDirection, @entity as Type, @lastactivitydate as Lastactivitydate,@lastactivity as LastActivity, @lastactivitydetails as LastActivityDetails,
isnull(DATEDIFF(DAY, cast(@lastactivitydate as date), cast(GETDATE() as date)), 0) LastCallDays,
isnull(@leadscore,0) as LeadScore, isnull(@AppointmentTitle, '') AppointmentAdded, @AppointmentAddedDays AppointmentAddedDays ) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);              

update callerid_detected set CallerDetected=@MobileNo,CallerMetaData=@cid_json where id=@cid_id
print @lastactivitydate

end 






