CREATE   PROCEDURE [dbo].[usp_mk_GetEnquiryList]          
(          
 @Parentid BIGINT,          
 @Userid BIGINT = 0,          
 @FilterExp NVARCHAR(MAX) = '', --condition query ex Enquiryid=987803          
 @Ordstr NVARCHAR(MAX) = '', --order by column name ex Enquiryid          
 @Sdate VARCHAR(50) = '', --start date          
 @Edate VARCHAR(50) = '', --end date       
 @OutputAllCols bit=0
)          
AS          
BEGIN          
          
 -- declare @Txtsearch NVARCHAR(100)='',@Parentid BIGINT=32222,@Userid INT=0,@FilterExp nvarchar(max) = '',@ordstr nvarchar(Max)='', @Sdate VARCHAR(50) = '4-Jan-2020', @Edate VARCHAR(50) = '29-Feb-2020'          
          
 DROP TABLE IF EXISTS #temp2;          
          
    IF @Ordstr = ''          
    BEGIN          
        SET @Ordstr = 'Enquiryid desc';          
    END;          
          
    DECLARE @Base_Column [NVARCHAR](MAX)='', @Pivot_Column [NVARCHAR](MAX);          
    DECLARE @Query1 NVARCHAR(MAX)= '';          
          
    IF @Sdate = '' AND @Edate = '' AND @FilterExp = ''          
    BEGIN          
        SELECT @Sdate = replace(convert(varchar,dateadd(day,-2,getdate()),106),' ','-');          
        SELECT @Edate = replace(convert(varchar,dateadd(day,1,getdate()),106),' ','-');          
    END;          
          
    /*Select Pivot Column*/          
    SELECT @Pivot_Column = COALESCE(@Pivot_Column + ',', '') + QUOTENAME(fieldname)          
    FROM           
 (     
  SELECT DISTINCT [fieldname]          
  FROM customfields(nolock)          
  WHERE ParentID = @Parentid AND isActive = 1          
 ) AS Tab;          
          
    IF @FilterExp <> ''    
    BEGIN          
        --SET @Query1 = @Query1 + 'Select ROW_NUMBER() OVER(Order By ' + @Ordstr + ') AS RowNumber, * into #TMPquery FROM Userenquiry(nolock) Ue ';          
        --SET @Query1 = @Query1 + ' where ParentID = ' + CONVERT(VARCHAR(100), @Parentid);          
          
        IF @Sdate <> '' AND @Edate <> ''          
        BEGIN          
            SET @Query1 = @Query1 + ' AND CreatedDate >''' + @Sdate + '''  AND CreatedDate <''' + @Edate + '''';          
        END;          
          
        SET @Query1 = @Query1 + ' AND ' + @FilterExp;          
        SET @Query1 = @Query1 + ' ;';          
    END;          
    ELSE          
    BEGIN          
        --SET @Query1 = @Query1 + 'Select ROW_NUMBER() OVER(Order By ' + @Ordstr + ') AS RowNumber,* into #TMPquery FROM Userenquiry(nolock) Ue ';          
        --SET @Query1 = @Query1 + ' where ParentID = ' + CONVERT(VARCHAR(100), @Parentid);          
        SET @Query1 = @Query1 + ' AND CreatedDate >''' + @Sdate + ''' AND CreatedDate <''' + @Edate + ''';';          
    END;          
    --print '@Query1:- ' + @Query1                      
          
    DECLARE @Query NVARCHAR(MAX)= '';          
    SET @Query = ' SELECT distinct A.Enquiryid,A.Personname,A.Companyname,A.MobileNo1,A.MobileNo2,A.MobileNo3, ';          
    SET @Query = @Query + 'A.EmailID1,A.EmailID2,A.EmailID3,A.Residentialaddress,A.Officeaddress,A.User_login, ';          
    SET @Query = @Query + 'A.City,A.[State],A.Country,A.CountryCode1,A.CountryCode2,A.CountryCode3,A.Pincode,A.[Address], ';          
    SET @Query = @Query + 'A.Initialremarks,A.SourceName,A.MediumName,A.CampaignName,A.Parentid,A.CreatedDate, ';          
    SET @Query = @Query + 'A.Createdby,A.LeadNo,A.IsOpen,isnull(A.Img_Ext,'''') as Img_Ext, isnull(A.ProfileImgFileName, '''') as ProfileImgFileName into #Temp2 FROM ( ';          
    SET @Query = @Query + 'SELECT Ue.Enquiryid,Ue.Personname,Ue.Companyname,Mobileno1=Ue.Mobileno,MobileNo2=Ue.Mobileno1, ';          
    SET @Query = @Query +  'MobileNo3=Ue.Mobileno2,EmailId1=Ue.Emailid,EmailId2=Ue.Emailid1,EmailId3=Ue.Emailid2,Ue.Residentialaddress,Ue.Officeaddress, ';          
    SET @Query = @Query + 'Ud.User_login,Ue.CreatedDate, Ue.City, Ue.[State], Ue.Country, ';          
    SET @Query = @Query + ' CountryCode1=Ue.Countrycode,CountryCode2=Ue.Countrycode1,CountryCode3=Ue.Countrycode2, Ue.Pincode, ';          
    SET @Query = @Query + ' CASE WHEN Ue.Companyname <> '''' THEN Ue.Officeaddress ELSE Ue.Residentialaddress END + '' '' + cast(Ue.Pincode as varchar(10)) + '' '' + Ue.City + '' '' + Ue.State + '' '' + Ue.Country AS [ADDRESS],';          
    SET @Query = @Query + ' Ue.Initialremarks, isnull(Uss.Name,'''') AS SourceName, isnull(Ums.Name,'''') AS MediumName, isnull(Ucs.Name,'''') AS CampaignName, ';          
    SET @Query = @Query + ' Ue.Parentid, Ue.Createdby, LeadNo=isnull(ue.LeadNo,0), Ue.img_ext,';          
    SET @Query = @Query + ' (CASE WHEN Ue.Isopen = ''1'' THEN ''open'' ELSE (CASE WHEN Ue.Isopen = ''0'' THEN ''close'' ELSE ''lead'' END) END) as Isopen, Ue.ProfileImgFileName';          
    SET @Query = @Query + ' FROM Userenquiry(nolock) Ue ';          
    SET @Query = @Query + ' INNER JOIN Usersourcesettings(nolock) Uss ON Ue.Sourcename = Uss.Sourceid ';          
    SET @Query = @Query + ' LEFT JOIN Usermediumsettings(nolock) Ums ON Ue.Mediumname = Ums.Mediumid ';          
    SET @Query = @Query + ' LEFT JOIN Usercampaignsettings(nolock) Ucs ON Ue.Campaignname = Ucs.Campaignid ';          
    SET @Query = @Query + ' LEFT JOIN User_detail(nolock) Ud ON Ue.Createdby = Ud.User_id ';          
    SET @Query = @Query + ' WHERE Ue.Parentid = ' + CONVERT(VARCHAR(100), @Parentid);          
          
    -- print '@Query:- ' + @Query                      
    IF @Userid > 0          
    BEGIN          
        SET @Query = @Query + ' AND ue.CreatedBy = CASE WHEN (' + CONVERT(VARCHAR(100), @Userid) + ' = 0) THEN ue.CreatedBy ELSE ' + CONVERT(VARCHAR(100), @Userid) + ' END'          
    END;          
          
    SET @Query = @Query + ' ) A WHERE 1=1 ' + @Query1;          
          
	If(@OutputAllCols = 0)
	Begin
		IF EXISTS(Select * From tbl_mk_ViewTemplate Where User_Id in (@Userid,@Parentid) and TemplateType='EN')    
		BEGIN    
			IF EXISTS(Select * From tbl_mk_ViewTemplate Where User_Id = @Userid and TemplateType='EN')    
			BEGIN    
			Select @Base_Column=ColumnList From tbl_mk_ViewTemplate Where User_Id = @Userid and TemplateType='EN'    
			END    
			ELSE    
			BEGIN    
			Select @Base_Column=ColumnList From tbl_mk_ViewTemplate Where User_Id = @Parentid and TemplateType='EN'    
			END    
		END    
	END
	ELSE    
	BEGIN
		Set @Base_Column='EnquiryID, PersonName, CompanyName, MobileNo1, MobileNo2, MobileNo3, EmailID1, EmailID2, EmailID3, ResidentialAddress, OfficeAddress, User_Login, City, State, Country, CountryCode1, CountryCode2, CountryCode3, Pincode, [Address], InitialRemarks, SourceName, MediumName, CampaignName, ParentId, CreatedDate, CreatedBy, LeadNo, IsOpen, Img_Ext, ProfileImgFileName';
		If(isnull(@Pivot_Column,'') != '')
		Begin
			Set @Base_Column += ', ' + @Pivot_Column
		End
	END
 --print 'BaseColumn:- ' + @Base_Column    
    
 IF(@Pivot_Column IS NOT NULL)          
 BEGIN    
   /*Create Dynamic Query*/          
   SET @Query += CAST(N'; SELECT ' + @Base_Column +      
   ' FROM          
   (SELECT EnquiryID, Personname, Companyname, MobileNo1, MobileNo2, MobileNo3, EmailID1, EmailID2, EmailID3, Residentialaddress, Officeaddress, User_login, City, [State], Country, CountryCode1, CountryCode2, CountryCode3, Pincode, [ADDRESS], Initialremarks, SourceName, MediumName, CampaignName, Parentid, CreatedDate, Createdby, LeadNo, Isopen, img_ext, ProfileImgFileName, [fieldname] , fieldvalue FROM (select A.EnquiryID, A.Personname, A.Companyname, A.MobileNo1, A.MobileNo2, A.MobileNo3, A.EmailID1, A.EmailID2, A.EmailID3, A.Residentialaddress, A.Officeaddress, A.User_login, A.City, A.[State], A.Country, A.Countrycode1, A.Countrycode2, A.Countrycode3, A.Pincode, A.[ADDRESS], A.Initialremarks, A.SourceName, A.MediumName, A.CampaignName, A.Parentid, 
	A.CreatedDate, A.Createdby, A.LeadNo, A.Isopen, A.img_ext, A.ProfileImgFileName, y.fieldname, x.fieldvalue     
   From #Temp2 as A left join customfieldEnquiryvalue x ON A.EnquiryID=x.EnquiryID left join customfields y on x.fieldID=y.field_ID)q     
   )Tab1 PIVOT          
   (          
   max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + ')) AS Tab2 Order by ' + @Ordstr AS NVARCHAR(MAX));          
   --print @Query1                    
   --EXEC sp_executesql @Query1                      
 END    
 ELSE    
 BEGIN    
  SET @Query += CAST(N'select ' + @Base_Column + ' from #Temp2 Order by ' + @Ordstr AS NVARCHAR(MAX));    
 END    
          
    print '@FinalQuery:- ' + cast(@Query as varchar(max))          
    EXEC sp_executesql @Query;          
          
    DROP TABLE IF EXISTS #temp2;          
          
END; 



GO

/* ============================================================
   Procedure: [dbo].[usp_mk_GetEnquiryList_modified]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- exec usp_mk_GetEnquiryList_modified @Parentid=32222,@Userid=32222,@Columns=N'',@FilterExp=N'',@ordstr=N'CreatedDate desc',@sdate=N'08 Feb 2020',@edate=N'10 Apr 2021',@OutputAllCols=0,@Mode=N'Export'    
-- exec usp_mk_GetEnquiryList_modified @Parentid=29453,@Userid=29453,@Columns=N'',@FilterExp=N'',@ordstr=N'CreatedDate desc',@sdate=N'08 Feb 2020',@edate=N'10 Apr 2021',@OutputAllCols=0,@Mode=N'Export'    
CREATE   PROCEDURE [dbo].[usp_mk_GetEnquiryList_modified]    
(    
 @Parentid BIGINT,    
 @Userid BIGINT = 0,    
 @Columns NVARCHAR(MAX) ='',    
 @FilterExp NVARCHAR(MAX) = '', --condition query ex Enquiryid=987803    
 @Ordstr NVARCHAR(MAX) = '', --order by column name ex Enquiryid    
 @Sdate VARCHAR(50) = '', --start date    
 @Edate VARCHAR(50) = '', --end date    
 @OutputAllCols bit=0,    
 @Mode varchar(10)=''    
)    
AS    
BEGIN    
    
 -- declare @Parentid bigint = 32222, @Userid bigint = 32222, @Columns nvarchar(max) = N'', @FilterExp nvarchar(max) = N'', @ordstr nvarchar(max) = N'CreatedDate desc', @sdate varchar(50) =N'08 Dec 2020', @edate  varchar(50) = N'07 Feb 2021', @OutputAllCols bit = 0,@Mode varchar(10)='Export'    
   
 -- declare @Parentid bigint = 35778, @Userid bigint = 0, @Columns nvarchar(max) = N'', @FilterExp nvarchar(max) = N'', @ordstr nvarchar(max) = N' PersonName', @sdate varchar(50) =N'12 Mar 2021', @edate  varchar(50) = N'12 May 2021', @OutputAllCols bit = 0, @Mode varchar(10)=''    
                                  
 DROP TABLE IF EXISTS #temp2;    
                  
 -- Swaping value fo @Userid to @vtUserId to ender custom column view        
        
 declare @vtUserId bigint  = @UserId, @RecCnt nvarchar(max)='500';        
        
 Select @RecCnt= CASE WHEN @Mode = 'Export' THEN '' ELSE 'Top 500' END    
    
 if(@Parentid = @Userid)        
  begin        
   set @Userid = 0        
  end        
           
    IF @Ordstr = ''                                  
    BEGIN                                  
        SET @Ordstr = ' EnquiryID desc ';                                  
    END;                                  
                                  
    DECLARE @Base_Column [NVARCHAR](MAX)='', @Pivot_Column [NVARCHAR](MAX);                                  
    DECLARE @Query1 NVARCHAR(MAX)= '';                                  
                                  
    IF @Sdate = '' AND @Edate = '' AND @FilterExp = ''                                  
    BEGIN                                  
        SELECT @Sdate = replace(convert(varchar,dateadd(day,-4,getdate()),106),' ','-');                                  
        SELECT @Edate = replace(convert(varchar,dateadd(day,1,getdate()),106),' ','-');                                  
    END;                                  
                                  
    /*Select Pivot Column*/                                  
    SELECT @Pivot_Column = COALESCE(@Pivot_Column + ',', '') + QUOTENAME(fieldname)                                  
    FROM                                   
 (    
  SELECT DISTINCT [fieldname]    
  FROM customfields(nolock)    
  WHERE ParentID = @Parentid AND isActive = 1    
 ) AS Tab;    
                                  
    IF @FilterExp <> ''                            
    BEGIN                                  
        --SET @Query1 = @Query1 + 'Select ROW_NUMBER() OVER(Order By ' + @Ordstr + ') AS RowNumber, * into #TMPquery FROM Userenquiry(nolock) Ue ';                                  
        --SET @Query1 = @Query1 + ' where ParentID = ' + CONVERT(VARCHAR(100), @Parentid);                                  
                                  
        IF @Sdate <> '' AND @Edate <> ''                                  
        BEGIN                                  
            SET @Query1 = @Query1 + ' AND CreatedDate >''' + @Sdate + '''  AND CreatedDate <''' + @Edate + '''';                                  
        END;                                  
                                  
        --SET @Query1 = @Query1 + ' AND ' + @FilterExp + ' ' + cast(@Ordstr AS NVARCHAR(MAX));                              
		
		SET @Query1 = @Query1 + ' AND ' + @FilterExp   
        SET @Query1 = @Query1 + ' ' ;                               
    END;         
    ELSE                                  
    BEGIN                                  
        --SET @Query1 = @Query1 + 'Select ROW_NUMBER() OVER(Order By ' + @Ordstr + ') AS RowNumber,* into #TMPquery FROM Userenquiry(nolock) Ue ';                                  
        --SET @Query1 = @Query1 + ' where ParentID = ' + CONVERT(VARCHAR(100), @Parentid);                                  
        SET @Query1 = @Query1 + ' AND CreatedDate >''' + @Sdate + ''' AND CreatedDate <''' + @Edate + '''' ;                                  
    END;                    
    --print '@Query1:- ' + @Query1                                              
                                  
    DECLARE @Query NVARCHAR(MAX)= '';                                  
    SET @Query = ' SELECT ' + @RecCnt + ' A.Enquiryid,A.Personname,A.Companyname,A.MobileNo1,A.MobileNo2,A.MobileNo3, ';                       
    SET @Query = @Query + 'A.EmailID1,A.EmailID2,A.EmailID3,A.Residentialaddress,A.Officeaddress,A.User_login, ';                                  
    SET @Query = @Query + 'A.City,A.[State],A.Country,A.CountryCode1,A.CountryCode2,A.CountryCode3,A.Pincode,A.[Address], ';                       
    SET @Query = @Query + 'A.Initialremarks,A.SourceName,A.MediumName,A.CampaignName,A.Parentid,A.CreatedDate, ';                                  
    SET @Query = @Query + 'A.Createdby,A.LeadNo,A.IsOpen,isnull(A.Img_Ext,'''') as Img_Ext, isnull(A.ProfileImgFileName, '''') as ProfileImgFileName into #Temp2 FROM ( ';                                  
    SET @Query = @Query + ' SELECT Ue.Enquiryid,Ue.Personname,Ue.Companyname,Mobileno1=Ue.Mobileno,MobileNo2=Ue.Mobileno1, ';                       
    SET @Query = @Query +  'MobileNo3=Ue.Mobileno2,EmailId1=Ue.Emailid,EmailId2=Ue.Emailid1,EmailId3=Ue.Emailid2,Ue.Residentialaddress,Ue.Officeaddress, ';             
    SET @Query = @Query + 'Ud.User_login,Ue.CreatedDate, Ue.City, Ue.[State], Ue.Country, ';                                  
    SET @Query = @Query + ' CountryCode1=Ue.Countrycode,CountryCode2=Ue.Countrycode1,CountryCode3=Ue.Countrycode2,  IIF(Ue.Pincode = 0, '''', STR(Ue.Pincode)) as [Pincode], ';                                  
    SET @Query = @Query + ' CASE WHEN Ue.Companyname <> '''' THEN ISNULL(Ue.Officeaddress, '''') ELSE  ISNULL(Ue.Residentialaddress, '''') END + '' '' + IIF(Ue.Pincode = 0, '''', STR(Ue.Pincode)) + '' '' + ISNULL(Ue.City, '''') + '' '' + ISNULL(Ue.State,'''') + '' '' + ISNULL(Ue.Country, '''') AS [ADDRESS],';                               
         
    SET @Query = @Query + ' Ue.Initialremarks, isnull(Uss.Name,'''') AS SourceName, isnull(Ums.Name,'''') AS MediumName, isnull(Ucs.Name,'''') AS CampaignName, ';                                  
    SET @Query = @Query + ' Ue.Parentid, Ue.Createdby, LeadNo=isnull(ue.LeadNo,0), Ue.img_ext,';                                  
    SET @Query = @Query + ' (CASE WHEN Ue.LeadNo > ''0'' THEN ''lead'' ELSE (CASE WHEN Ue.Isopen = ''0'' THEN ''close'' ELSE ''lead'' END) END) as Isopen, Ue.ProfileImgFileName';                                  
    SET @Query = @Query + ' FROM Userenquiry(nolock) Ue ';                                  
    SET @Query = @Query + ' LEFT JOIN Usersourcesettings(nolock) Uss ON Ue.Sourcename = Uss.Sourceid ';                                  
    SET @Query = @Query + ' LEFT JOIN Usermediumsettings(nolock) Ums ON Ue.Mediumname = Ums.Mediumid ';                                  
    SET @Query = @Query + ' LEFT JOIN Usercampaignsettings(nolock) Ucs ON Ue.Campaignname = Ucs.Campaignid ';                                  
    SET @Query = @Query + ' LEFT JOIN User_detail(nolock) Ud ON Ue.Createdby = Ud.User_id ';                                  
    SET @Query = @Query + ' WHERE Ue.Parentid = ' + CONVERT(VARCHAR(100), @Parentid);                                  
        
    -- print '@Query:- ' + @Query                                              
    IF @Userid > 0                                  
    BEGIN                                  
        SET @Query = @Query + ' AND ue.CreatedBy = CASE WHEN (' + CONVERT(VARCHAR(100), @Userid) + ' = 0) THEN ue.CreatedBy ELSE ' + CONVERT(VARCHAR(100), @Userid) + ' END'                                  
    END;                                  
                                  
    SET @Query = @Query + ' ) A WHERE 1=1 ' + @Query1 + ' order by A.' + trim(@Ordstr)  
                      
 IF(@Columns = '')    
 BEGIN    
  IF(@OutputAllCols = 0)    
  BEGIN    
   IF EXISTS (SELECT * FROM tbl_mk_ViewTemplate WHERE User_Id IN( @vtUserId, @Parentid ) AND TemplateType = 'EN')    
   BEGIN    
    IF EXISTS (SELECT * FROM tbl_mk_ViewTemplate WHERE User_Id = @vtUserId AND TemplateType = 'EN')    
    BEGIN    
     SELECT @Base_Column = ColumnList FROM tbl_mk_ViewTemplate WHERE User_Id = @vtUserId AND TemplateType = 'EN';    
    END;    
    ELSE    
    BEGIN    
     SELECT @Base_Column = ColumnList FROM tbl_mk_ViewTemplate WHERE User_Id = @Parentid AND TemplateType = 'EN';    
    END;    
   END    
   ELSE    
   BEGIN    
    SET @Base_Column = 'EnquiryID, PersonName, CompanyName, MobileNo1, MobileNo2, MobileNo3, EmailID1, EmailID2, EmailID3, ResidentialAddress, OfficeAddress, User_Login, City, State, Country, CountryCode1, CountryCode2, CountryCode3, Pincode, [Address], InitialRemarks, SourceName, MediumName, CampaignName, ParentId, CreatedDate, CreatedBy, LeadNo, IsOpen, Img_Ext, ProfileImgFileName';    
    
    IF(ISNULL(@Pivot_Column, '') != '')    
    BEGIN    
     SET @Base_Column+=', ' + @Pivot_Column;    
    END;    
   END    
  END    
  ELSE    
  BEGIN    
   SET @Base_Column = 'EnquiryID, PersonName, CompanyName, MobileNo1, MobileNo2, MobileNo3, EmailID1, EmailID2, EmailID3, ResidentialAddress, OfficeAddress, User_Login, City, State, Country, CountryCode1, CountryCode2, CountryCode3, Pincode, [Address], InitialRemarks, SourceName, MediumName, CampaignName, ParentId, CreatedDate, CreatedBy, LeadNo, IsOpen, Img_Ext, ProfileImgFileName';    
   IF(ISNULL(@Pivot_Column, '') != '')    
   BEGIN    
    SET @Base_Column+=', ' + @Pivot_Column;    
   END    
  END    
 END    
 ELSE    
 BEGIN    
  SET @Base_Column = @Columns;    
 END;  
 
 --if(@Base_Column not like '%AssignedTo%')
 --begin
	--set @Base_Column += ',' + 'AssignedTo'
 --end

                        
 If(@Mode = 'Export')    
 Begin    
  Set @Base_Column  = 'EnquiryID, PersonName, CompanyName, MobileNo1, MobileNo2, MobileNo3, EmailID1, EmailID2, EmailID3, ResidentialAddress, OfficeAddress, City, State, Country, CountryCode1, CountryCode2, CountryCode3, Pincode, [Address], InitialRemarks, SourceName, MediumName, CampaignName, CreatedDate, User_Login as CreatedBy, LeadNo, IsOpen';    
 End    
                       
 --print 'BaseColumn:- ' + @Base_Column                            
                            
 IF(@Pivot_Column IS NOT NULL)    
  BEGIN                            
    /*Create Dynamic Query*/                                  
    SET @Query += CAST(N'; SELECT ' + @Base_Column + ' FROM                                  
    (SELECT EnquiryID, Personname, Companyname, MobileNo1, MobileNo2, MobileNo3, EmailID1, EmailID2, EmailID3, Residentialaddress, Officeaddress, User_login, City, [State], Country, CountryCode1, CountryCode2, CountryCode3, Pincode, [ADDRESS], Initialremarks, SourceName, MediumName, CampaignName, Parentid, CreatedDate, Createdby, LeadNo, Isopen, img_ext, ProfileImgFileName, [fieldname] , fieldvalue,  convert(varchar(10),CreatedDate,103) as Created_Date FROM (select A.EnquiryID, A.Personname, A.Companyname, A.MobileNo1, A.MobileNo2, A.MobileNo3, A.EmailID1, A.EmailID2, A.EmailID3, A.Residentialaddress, A.Officeaddress, A.User_login, A.City, A.[State], A.Country, A.Countrycode1, A.Countrycode2, A.Countrycode3, A.Pincode, A.[ADDRESS], A.Initialremarks, A.SourceName, A.MediumName, A.CampaignName, A.Parentid, A.CreatedDate, A.Createdby, A.LeadNo, A.Isopen, A.img_ext, A.ProfileImgFileName, y.fieldname, x.fieldvalue   From #Temp2 as A left join customfieldEnquiryvalue x ON A.EnquiryID=x.EnquiryID left join customfields y on x.fieldID=y.field_ID)q            
    )Tab1 PIVOT                                  
    (                                  
    max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + ')) AS Tab2 Order by ' + @Ordstr AS NVARCHAR(MAX));                                  
    --print @Query1                                            
    --EXEC sp_executesql @Query1                                              
  END           
  ELSE                            
  BEGIN                            
  SET @Query += CAST(N' select ' + @Base_Column + ' from #Temp2 Order by ' + @Ordstr AS NVARCHAR(MAX));                            
  END    
                                  
 print '@FinalQuery:- ' + cast(@Query as varchar(max))    
 EXEC sp_executesql @Query;    
    
 DROP TABLE IF EXISTS #temp2;    
                                  
END; 



GO

/* ============================================================
   Procedure: [dbo].[usp_mk_GetEnquiryList1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_mk_GetEnquiryList1]    
(    
 @Parentid BIGINT,    
 @Userid BIGINT = 0,    
 @FilterExp NVARCHAR(MAX) = '', --condition query ex Enquiryid=987803    
 @Ordstr NVARCHAR(MAX) = '', --order by column name ex Enquiryid    
 @Sdate VARCHAR(50) = '', --start date    
 @Edate VARCHAR(50) = '' --end date    
)    
AS    
BEGIN    
    
 -- declare @Txtsearch NVARCHAR(100)='',@Parentid BIGINT=32222,@Userid INT=0,@FilterExp nvarchar(max) = '',@ordstr nvarchar(Max)='', @Sdate VARCHAR(50) = '24-Oct-2019', @Edate VARCHAR(50) = '30-Jan-2020'    
    
 DROP TABLE IF EXISTS #temp2;    
    
    IF @Ordstr = ''    
    BEGIN    
        SET @Ordstr = 'Enquiryid desc';    
    END;    
    
    DECLARE @Pivot_Column [NVARCHAR](MAX);    
    DECLARE @Query1 NVARCHAR(MAX)= '';    
    
    IF @Sdate = '' AND @Edate = '' AND @FilterExp = ''    
    BEGIN    
        SELECT @Sdate = replace(convert(varchar,dateadd(day,-2,getdate()),106),' ','-');    
        SELECT @Edate = replace(convert(varchar,dateadd(day,1,getdate()),106),' ','-');    
    END;    
    
    /*Select Pivot Column*/    
    
    SELECT @Pivot_Column = COALESCE(@Pivot_Column + ',', '') + QUOTENAME(fieldname)    
    FROM     
 ( SELECT DISTINCT [fieldname]    
  FROM customfields(nolock)    
  WHERE ParentID = @Parentid AND isActive = 1    
 ) AS Tab;    
    
    IF @FilterExp <> ''    
    BEGIN    
        --SET @Query1 = @Query1 + 'Select ROW_NUMBER() OVER(Order By ' + @Ordstr + ') AS RowNumber, * into #TMPquery FROM Userenquiry(nolock) Ue ';    
        --SET @Query1 = @Query1 + ' where ParentID = ' + CONVERT(VARCHAR(100), @Parentid);    
    
        IF @Sdate <> '' AND @Edate <> ''    
        BEGIN    
            SET @Query1 = @Query1 + ' AND CreatedDate >''' + @Sdate + '''  AND CreatedDate <''' + @Edate + '''';    
        END;    
    
        SET @Query1 = @Query1 + ' AND ' + @FilterExp;    
        SET @Query1 = @Query1 + ' ;';    
    END;    
    ELSE    
    BEGIN    
        --SET @Query1 = @Query1 + 'Select ROW_NUMBER() OVER(Order By ' + @Ordstr + ') AS RowNumber,* into #TMPquery FROM Userenquiry(nolock) Ue ';    
        --SET @Query1 = @Query1 + ' where ParentID = ' + CONVERT(VARCHAR(100), @Parentid);    
        SET @Query1 = @Query1 + ' AND CreatedDate >''' + @Sdate + ''' AND CreatedDate <''' + @Edate + ''';';    
    END;    
    --print '@Query1:- ' + @Query1                
    
    DECLARE @Query NVARCHAR(MAX)= '';    
    SET @Query = ' SELECT distinct A.Enquiryid,A.Personname,A.Companyname,A.MobileNo1,A.MobileNo2,A.MobileNo3, ';    
    SET @Query = @Query + 'A.EmailID1,A.EmailID2,A.EmailID3,A.Residentialaddress,A.Officeaddress,A.User_login, ';    
    SET @Query = @Query + 'A.City,A.[State],A.Country,A.CountryCode1,A.CountryCode2,A.CountryCode3,A.Pincode,A.[Address], ';    
    SET @Query = @Query + 'A.Initialremarks,A.SourceName,A.MediumName,A.CampaignName,A.Parentid,A.CreatedDate, ';    
    SET @Query = @Query + 'A.Createdby,A.LeadNo,A.IsOpen,isnull(A.Img_Ext,'''') as Img_Ext, isnull(A.ProfileImgFileName, '''') as ProfileImgFileName into #Temp2 FROM ( ';    
    SET @Query = @Query + 'SELECT Ue.Enquiryid,Ue.Personname,Ue.Companyname,Mobileno1=Ue.Mobileno,MobileNo2=Ue.Mobileno1, ';    
    SET @Query = @Query + 'MobileNo3=Ue.Mobileno2,EmailId1=Ue.Emailid,EmailId2=Ue.Emailid1,EmailId3=Ue.Emailid2,Ue.Residentialaddress, Ue.Officeaddress, ';    
    SET @Query = @Query + 'Ud.User_login,Ue.CreatedDate, Ue.City, Ue.[State], Ue.Country, ';    
    SET @Query = @Query + ' CountryCode1=Ue.Countrycode,CountryCode2=Ue.Countrycode1,CountryCode3=Ue.Countrycode2, Ue.Pincode, ';    
    SET @Query = @Query + ' CASE WHEN Ue.Companyname <> '''' THEN Ue.Officeaddress ELSE Ue.Residentialaddress END + '' '' + cast(Ue.Pincode as varchar(10)) + '' '' + Ue.City + '' '' + Ue.State + '' '' + Ue.Country AS [ADDRESS],';    
    SET @Query = @Query + ' Ue.Initialremarks, isnull(Uss.Name,'''') AS SourceName, isnull(Ums.Name,'''') AS MediumName, isnull(Ucs.Name,'''') AS CampaignName, ';    
    SET @Query = @Query + ' Ue.Parentid, Ue.Createdby, LeadNo=isnull(ue.LeadNo,0), Ue.img_ext,';    
    SET @Query = @Query + ' (CASE WHEN Ue.Isopen = ''1'' THEN ''open'' ELSE (CASE WHEN Ue.Isopen = ''0'' THEN ''close'' ELSE ''lead'' END) END) as Isopen, Ue.ProfileImgFileName';    
    SET @Query = @Query + ' FROM Userenquiry(nolock) Ue ';    
    SET @Query = @Query + ' INNER JOIN Usersourcesettings(nolock) Uss ON Ue.Sourcename = Uss.Sourceid ';    
    SET @Query = @Query + ' LEFT JOIN Usermediumsettings(nolock) Ums ON Ue.Mediumname = Ums.Mediumid ';    
    SET @Query = @Query + ' LEFT JOIN Usercampaignsettings(nolock) Ucs ON Ue.Campaignname = Ucs.Campaignid ';    
    SET @Query = @Query + ' LEFT JOIN User_detail(nolock) Ud ON Ue.Createdby = Ud.User_id ';    
    SET @Query = @Query + ' WHERE Ue.Parentid = ' + CONVERT(VARCHAR(100), @Parentid);    
    
    -- print '@Query:- ' + @Query                
    IF @Userid > 0    
    BEGIN    
        SET @Query = @Query + ' AND ue.CreatedBy = CASE WHEN (' + CONVERT(VARCHAR(100), @Userid) + ' = 0) THEN ue.CreatedBy ELSE ' + CONVERT(VARCHAR(100), @Userid) + ' END'    
    END;    
    
    SET @Query = @Query + ' ) A WHERE 1=1 ' + @Query1;    
    
 IF(@Pivot_Column IS NOT NULL)    
    BEGIN    
        /*Create Dynamic Query*/    
  SET @Query += CAST(N'; SELECT EnquiryID, PersonName, CompanyName, MobileNo1, MobileNo2, MobileNo3, EmailID1, EmailID2, EmailID3, ResidentialAddress, OfficeAddress, User_Login, City, [State], Country, CountryCode1, CountryCode2, CountryCode3, Pincode, [Address], InitialRemarks, SourceName, MediumName, CampaignName, ParentId, CreatedDate, CreatedBy, LeadNo, IsOpen, Img_Ext, ProfileImgFileName, ' + @Pivot_Column + ' FROM    
  (SELECT EnquiryID, Personname, Companyname, MobileNo1, MobileNo2, MobileNo3, EmailID1, EmailID2, EmailID3, Residentialaddress, Officeaddress, User_login, City, [State], Country, CountryCode1, CountryCode2, CountryCode3, Pincode, [ADDRESS], Initialremarks, SourceName, MediumName, CampaignName, Parentid, CreatedDate, Createdby, LeadNo, Isopen, img_ext, ProfileImgFileName, [fieldname] , fieldvalue FROM (select A.EnquiryID, A.Personname, A.Companyname, A.MobileNo1, A.MobileNo2, A.MobileNo3, A.EmailID1, A.EmailID2, A.EmailID3,   
A.Residentialaddress, A.Officeaddress, A.User_login, A.City, A.[State], A.Country, A.Countrycode1, A.Countrycode2, A.Countrycode3, A.Pincode, A.[ADDRESS], A.Initialremarks, A.SourceName, A.MediumName, A.CampaignName, A.Parentid, A.CreatedDate, A.Createdby, A.LeadNo, A.Isopen, A.img_ext, A.ProfileImgFileName, y.fieldname, x.fieldvalue From #Temp2 as A left join customfieldEnquiryvalue x    
  ON A.EnquiryID=x.EnquiryID left join customfields y on x.fieldID=y.field_ID)q )Tab1 PIVOT    
  (    
  max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + ')) AS Tab2 Order by ' + @Ordstr AS NVARCHAR(MAX));    
        --print @Query1              
        --EXEC sp_executesql @Query1                
    END    
 ELSE    
 BEGIN    
  SET @Query += CAST(N'select * from #Temp2 Order by ' + @Ordstr AS NVARCHAR(MAX));    
 END    
    
    
    print cast(@Query as varchar(max))    
   -- EXEC sp_executesql @Query;    
    
    DROP TABLE IF EXISTS #temp2;    
    
END; 


GO

