/* ============================================================
   Procedure: [dbo].[usp_mk_GetLeadByLeadId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_mk_GetLeadByLeadId    --662577  
@LeadId bigint      
as      
begin      
 set nocount on                                  
declare @uid bigint                                  
declare @cnt_start int                                    
declare @cnt_max int                                    
declare @grp_id int                                    
declare @out varchar(max)=''                                     
select @uid=parentid from UserLeads where ID=@leadid;                                   
set @cnt_start=0;                                    
select distinct Group_Name, Group_ID into #group from Group_Detail where USER_ID=@uid                                    
select @cnt_max=COUNT(Group_Name) from #group                                    
while (@cnt_start < @cnt_max)                                    
begin                                    
select @grp_id=MAX(group_id) from #group;                                    
if(@cnt_start>0)                                    
begin                                    
select @out=@out+', '+group_name from #group where Group_ID=@grp_id;                                    
end                                    
else                                    
begin                                    
select @out=group_name from #group where Group_ID=@grp_id;                                    
end                                    
delete From #group where Group_ID=@grp_id;                                    
set @cnt_start=@cnt_start+1;                                    
end                                    
drop table #group;                                  
SELECT [ul].[leadno],         
       [ul].[personname],         
       [ul].[companyname],         
       ISNULL([ul].[mobileno], '') AS [mobileno],         
       [ul].[emailid],         
       [ul].[city],         
       [ul].[state],         
       [ul].[country],         
       [ul].[pincode],         
       [ul].[residentialaddress],
	   (select case when isnull([ul].[residentialaddress],'') <> '' then [ul].[residentialaddress]
	    else  isnull([ul].[residentialaddress],'')
		end
		)  as Address,          
       [ud].[user_login] AS [assigned_to],         
       [src].[name] AS [source],         
       ISNULL([md].[name], '') AS [medium],         
       ISNULL([cmp].[Name], '') AS [campaignname],         
       [ul].[remarks] AS [remark],         
       [fs].[followupstatus],         
       CONVERT(VARCHAR(20), [ul].[createdon], 113) AS [createdon],        
       CASE        
           WHEN [ul].[modifiedon] = ''        
           THEN CONVERT(VARCHAR(20), [ul].[createdon], 113)        
           WHEN [ul].[modifiedon] IS NULL        
           THEN CONVERT(VARCHAR(20), [ul].[createdon], 113)        
           ELSE CONVERT(VARCHAR(20), [ul].[modifiedon], 113)        
       END AS [modifiedon],         
       --CONVERT(VARCHAR(20), [ul].[followupdate], 20) AS [followupdate],         
       dbo.fn_getusertimefromindiantime(@uid, [ul].[followupdate]) AS [followupdate],         
       [ud1].[user_login] AS [createdby],         
       [ud2].[user_login] AS [modifiedby],         
       @out AS [groups],         
       ISNULL([ul].[mobileno1], '') AS [mobileno1],         
       ISNULL([ul].[mobileno2], '') AS [mobileno2],         
       ISNULL([ul].[emailid1], '') AS [emailid1],         
       ISNULL([ul].[emailid2], '') AS [emailid2],         
       [ul].[officeaddress],         
       [ul].[countrycode],         
       [ul].[AssignedTo] AS [assign_id],         
       [ul].[SourceName] AS [source_id],         
       [ul].[MediumName] AS [medium_id],         
       [ul].[CampaignName] AS [camp_id],         
       [ul].[FollowUpStatus] AS [follow_status_id],         
       [ul].[Products],         
       [ul].[AmountPaid],         
       ltrim(ISNULL([ul].[countrycode], '') + ' ' + ISNULL([ul].[MobileNo], '')) +         
   CASE WHEN ISNULL([ul].[MobileNo1], '') <> ''        
    THEN ', ' + ltrim(ISNULL([ul].[countrycode1], '') + ' ' + ISNULL([ul].[MobileNo1], ''))        
    ELSE '' END +         
   CASE WHEN ISNULL([ul].[MobileNo2], '') <> ''        
    THEN ', ' + ltrim(ISNULL([ul].[countrycode2], '') + ' ' + ISNULL([ul].[MobileNo2], ''))        
    ELSE '' END AS [phones],         
       ISNULL([ul].[CountryCode1], '') AS [CountryCode1],         
     ISNULL([ul].[CountryCode2], '') AS [CountryCode2],         
       ISNULL([ul].[EmailID], '') + CASE        
                                        WHEN ISNULL([ul].[EmailID1], '') <> ''        
                                        THEN ', ' + ISNULL([ul].[EmailID1], '')        
                                        ELSE ''        
                                    END + CASE        
                                              WHEN ISNULL([ul].[EmailID2], '') <> ''        
                                              THEN ', ' + ISNULL([ul].[EmailID2], '')        
                                              ELSE ''        
                                          END AS [emails],         
       ISNULL([ul].[img_ext], '.abc') as [img_ext],      
 CASE WHEN ISNULL([UL].[CountryCode], '') <> '' THEN ISNULL([UL].[Countrycode], '') + ' ' + ISNULL([UL].[MobileNo], '') ELSE '' END         
    +         
    CASE WHEN ISNULL([UL].[Mobileno1], '') <> ''   THEN ', ...'  ELSE '' END as Mobile,      
 CASE WHEN ISNULL([UL].[Emailid], '') <> ''     THEN ISNULL([UL].[Emailid], '')  ELSE '' END         
    +         
    CASE WHEN ISNULL([UL].[EmailID1], '') <> ''    THEN ', ...'     ELSE '' END  AS Email,    
 ul.ProfileImgFileName,  
 ul.ParentID,  
 ul.ID as LeadId  
FROM userleads ul        
     LEFT JOIN user_detail ud ON ul.assignedto = ud.user_id        
     LEFT JOIN usersourcesettings src ON ul.sourcename = src.sourceid        
     LEFT JOIN usermediumsettings md ON ul.mediumname = md.mediumid        
     LEFT JOIN UserCampaignSettings cmp ON ul.campaignname = cmp.CampaignID        
     LEFT JOIN followup_status fs ON ul.followupstatus = fs.id        
     LEFT JOIN user_detail ud1 ON ul.createdby = ud1.user_id        
     LEFT JOIN user_detail ud2 ON ul.modifiedby = ud2.user_id        
WHERE [ul].[id] =  @LeadId      
end 


GO

/* ============================================================
   Procedure: [dbo].[usp_mk_GetLeadColumnListByParentId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_mk_GetLeadColumnListByParentId](  
 @ParentId BIGINT      
)AS      
BEGIN      
        select * from (      
            SELECT
                0 as [fieldId],
                column_name AS 'fieldname',       
                UPPER(CASE column_name      
                WHEN 'CampaignName' THEN 'VARCHAR'      
                WHEN 'MediumName' THEN 'VARCHAR'      
                WHEN 'SourceName' THEN 'VARCHAR'      
                WHEN 'FollowupStatus' THEN 'VARCHAR'      
                WHEN 'FollowupDate' THEN 'DateTime'    
                WHEN 'LastFollowupCreatedBy' THEN 'VARCHAR'    
                WHEN 'AssignedTo' THEN 'VARCHAR'    
                WHEN 'CreatedBy' THEN 'VARCHAR'    
                ELSE case when data_type = 'NVARCHAR' then 'VARCHAR' else data_type end end) AS 'data_type',  
                'Predefined' as FieldType,
                '' as [ElementType]
            FROM information_schema.columns      
            WHERE table_name = 'UserLeads'     
        UNION    
            SELECT 
                field_ID as [fieldId],
                fieldname,       
                UPPER((CASE datatype      
                    WHEN 'd'      
                    THEN 'DateTime'      
                    WHEN 'f'      
                    THEN 'Numeric'      
                    WHEN 'v'      
                    THEN 'VARCHAR'      
                    WHEN 'm'      
                    THEN 'VARCHAR'      
                    WHEN 'e'      
                    THEN 'VARCHAR'      
                    WHEN 'r'      
                    THEN 'VARCHAR'      
                    WHEN 'c'      
                    THEN 'VARCHAR'      
                    WHEN 's'      
                    THEN 'VARCHAR'      
                            
                END)) AS data_type ,'Custom' as FieldType,
                lower((CASE datatype  
                    WHEN 'd'  
                    THEN 'Date'  
                    WHEN 'f'  
                    THEN 'Numeric'  
                    WHEN 'v'  
                    THEN 'Text'  
                    WHEN 'r'  
                    THEN 'Radio'  
                    WHEN 'm'  
                    THEN 'Multiline'  
                    WHEN 's'  
                    THEN 'Select'  
                    WHEN 'c'  
                    THEN 'Checkbox'  
                    WHEN 'e'  
                    THEN 'Expression'  
                    WHEN 'l'  
                    THEN 'List'  
                END)) AS [ElementType] 
            FROM customfields NOCOUNT      
            WHERE isActive = 1 and [ParentID] = @ParentId      
            ) as col 
            where col.fieldname not in ('id', 'ModifiedOn', 'ModifiedBy', 'LeadImage', 'temp_id', 'img_ext', 'ProfileImgFileName','enquirysource', 'WhatsAppNoColName', 'parentid', 'NextStatusDate')          
END



GO

/* ============================================================
   Procedure: [dbo].[usp_mk_GetLeadColumnListWithDataType]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_mk_GetLeadColumnListWithDataType](
	@ParentId BIGINT    
)AS    
BEGIN    
        select * from (    
   SELECT column_name AS 'fieldname',     
	UPPER(CASE column_name    
		WHEN 'CampaignName' THEN 'VARCHAR'    
		WHEN 'MediumName' THEN 'VARCHAR'    
		WHEN 'SourceName' THEN 'VARCHAR'    
		WHEN 'FollowupStatus' THEN 'VARCHAR'    
		WHEN 'FollowupDate' THEN 'DateTime'  
		WHEN 'LastFollowupCreatedBy' THEN 'VARCHAR'  
		WHEN 'AssignedTo' THEN 'VARCHAR'  
		WHEN 'CreatedBy' THEN 'VARCHAR'  
		ELSE case when data_type = 'NVARCHAR' then 'VARCHAR' else data_type end end) AS 'data_type',
		'Predefined' as FieldType  
   FROM information_schema.columns    
   WHERE table_name = 'UserLeads'   
   UNION  
   SELECT fieldname,     
       UPPER((CASE datatype    
         WHEN 'd'    
         THEN 'DateTime'    
         WHEN 'f'    
         THEN 'Numeric'    
         WHEN 'v'    
         THEN 'VARCHAR'    
         WHEN 'm'    
         THEN 'VARCHAR'    
         WHEN 'e'    
         THEN 'VARCHAR'    
         WHEN 'r'    
         THEN 'VARCHAR'    
         WHEN 'c'    
         THEN 'VARCHAR'    
         WHEN 's'    
         THEN 'VARCHAR'    
                          
        END)) AS data_type ,'Custom' as FieldType   
   FROM customfields NOCOUNT    
   WHERE isActive = 1 and [ParentID] = @ParentId    
  ) as col where col.fieldname not in ('id', 'ModifiedOn', 'ModifiedBy', 'LeadImage', 'temp_id', 'img_ext', 'ProfileImgFileName','enquirysource', 'WhatsAppNoColName', 'parentid', 'NextStatusDate')        
    END;    
   


GO

