CREATE   PROCEDURE usp_mk_GetLeadDocumentDetail @LeadId BIGINT
AS
    BEGIN
        SELECT 
		l.DocUpID as [NoteID],
				l.DocUpID, 
               l.UserID, 
               l.LeadID, 
               u.User_Login, 
               l.DocumentName, 
               l.FileType, 
               l.FileLocation, 
               l.FileLocation as Notes, 
               l.UploadedDate, 
               l.UpdatedDate, 
               l.DeletedDate
        FROM tbl_LeadDocumentUpload AS l
