/* ============================================================
   Procedure: [dbo].[usp_mk_GetLeadInteractionHistory]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

    
--select * from UserLeads where LeadNo = 25 and  ParentID = 32222    
--exec usp_mk_GetLeadInteractionHistory 269756    
    
CREATE   PROCEDURE [dbo].[usp_mk_GetLeadInteractionHistory]  --616992     
 @LeadId bigint    
AS                    
BEGIN      
 declare @LeadNo BIGINT = 359, @ParentID BIGINT = 32821                   
     
 select @LeadNo =  LeadNo, @ParentID = ParentID from UserLeads where ID = @LeadId    
    
    exec Usp_createProductMasterTable @ParentID    
  
Declare @Query nvarchar(max) = concat( N'  SELECT distinct fus.FollowupStatus,        
        convert(varchar(25),dbo.[fn_getusertimefromindiantime](',cast( @ParentID as nvarchar(max)) , ',lih.FollowupDate)) as NextStatusDate,                  
        Case when lih.IsReassign = 1 Then ''Reassign'' else '''' End ReAssign, lih.Remarks,                    
        (                    
            SELECT STUFF(                    
                       (                    
                           SELECT N'', '' + ss.Name                    
                           FROM   tbl_ProductMaster_',cast( @ParentID as nvarchar(max)) , ' AS ss  (NOLOCK)                    
                                  INNER JOIN dbo.fn_Split(lih.Products, ''#'') AS                     
                                       fs                    
                                       ON  ss.ProductID = fs.[value]                     
                                           FOR XML                     
                                           PATH(''''),                    
                                  TYPE                    
                       )                     
                       .value(''text()[1]'', ''nvarchar(max)''),                    
                       1,                    
                       2,                    
                       N''''                    
                   )                    
        ) AS Products,                    
        lih.AmountPaid,                    
        ud.FName + '' '' + ISNULL(ud.LName, '''') AS AssignedTo
		,convert(varchar(25),dbo.[fn_getusertimefromindiantime](',cast( @ParentID as nvarchar(max)) , ',lih.createdon)) as FollowupCreatedDate
		,(select top 1 User_Login + '' ('' + isnull(FName,'''') +'' ''+ isnull(LName,'''') + '')''  from user_detail (nolock) as udby   where udby.user_id = lih.CreatedBy ) as FollowupCreatedBy                   
 FROM   LeadInteractionHistory      AS lih (NOLOCK)      
        INNER JOIN FollowUp_Status  AS fus (NOLOCK)                    
             ON  fus.ID = lih.FollowUpStatus                    
        LEFT JOIN User_Detail       AS ud  (NOLOCK)                    
             ON  ud.[User_ID] = lih.AssignedTo                    
     WHERE  lih.LeadNo = ', cast( @LeadNo as nvarchar(max)) ,'                    
        AND lih.ParentID = ', cast( @ParentID as nvarchar(max)) ,'             
      ORDER BY NextStatusDate DESC ' )     
     
   print(@Query)  
   exec sp_executesql @query              
END    
  


GO

/* ============================================================
   Procedure: [dbo].[usp_mk_GetLeadInteractionHistoryByLeadId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_mk_GetLeadInteractionHistoryByLeadId] --616992
 @LeadId BIGINT    
AS    
BEGIN    
            
  --declare @LeadId bigint = 16512137    
      
	DECLARE @ParentID BIGINT= 0;    
	SELECT @ParentID = ParentID FROM UserLeads(NOLOCK) WHERE Id = @LeadId;    
            
	exec Usp_createProductMasterTable @ParentID 
      
	Declare @Query nvarchar(max) = concat( N'  SELECT *    
					FROM    
					(    
						SELECT DISTINCT     
							   fus.FollowupStatus,     
							   TRY_CONVERT(DATETIME, CONVERT(VARCHAR(25), dbo.[fn_getusertimefromindiantime](',cast(@ParentID as nvarchar(max)),', lih.FollowupDate))) AS NextStatusDate,     
							   lih.Remarks,     
						(    
							SELECT STUFF(    
							(    
								SELECT N'', '' + ss.Name    
								FROM tbl_ProductMaster_', cast(@ParentID as nvarchar(max)) ,' AS ss(NOLOCK)    
									 INNER JOIN dbo.fn_Split(lih.Products, ''#'') AS fs ON ss.ProductID = fs.[value] FOR XML PATH(''''), TYPE    
							).value(''text()[1]'', ''nvarchar(max)''), 1, 2, N'''')    
						) AS Products,     
							   lih.AmountPaid,     
							   concat(ast.FName, '' '', ISNULL(ast.LName, '''')) AS AssignedTo, --, lih.createdon   
				   ast.FName,  
				   ast.LName,  
				   ast.User_Login,  
				   ast.User_ID as UserId,   
				   ast.Image,   
							   ul.PersonName,     
							   ul.ProfileImgFileName,     
							  dbo.[fn_getusertimefromindiantime](',cast(@ParentID as nvarchar(max)),', lih.CreatedOn) AS CreatedOn,     
							   concat(cst.FName, '' '', ISNULL(cst.LName, '''')) AS CreatedBy,     
							   ul.Id AS [LeadId],     
							   ul.ParentID,  
				   ul.LeadNo,  
				   iif(ISNULL(MobileNo, '''') = '''',  '''', concat(ul.CountryCode, ''-'', ul.MobileNo)) as MobileNo,  
				   iif(ISNULL(MobileNo1, '''') = '''',  '''', concat(ul.CountryCode1, ''-'', ul.MobileNo1)) as MobileNo1,  
				   iif(ISNULL(MobileNo2, '''') = '''',  '''', concat(ul.CountryCode2, ''-'', ul.MobileNo2)) as MobileNo2,  
				   ul.EmailID,  
				   ul.EmailID1,  
				   ul.EmailID2, lih.ID
						FROM LeadInteractionHistory AS lih(NOLOCK)    
							 INNER JOIN UserLeads UL ON lih.ParentID = UL.ParentID    
														AND lih.LeadNo = UL.LeadNo    
							 LEFT JOIN FollowUp_Status AS fus(NOLOCK) ON fus.ID = lih.FollowUpStatus    
							 LEFT JOIN User_Detail(NOLOCK) ast ON ast.[User_ID] = lih.AssignedTo    
							 LEFT JOIN User_Detail(NOLOCK) cst ON cst.[User_ID] = lih.CreatedBy    
						WHERE UL.ID = ', cast(@LeadId as nvarchar(max)) , '   
					) AS tbl    
					ORDER BY CONVERT(DATETIME, NextStatusDate) DESC ')    

	print @query
	
	exec sp_executesql @query
				
END  






GO

/* ============================================================
   Procedure: [dbo].[usp_mk_GetLeadList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- exec usp_mk_GetLeadList @Parentid =32222,@Userid =0,@FilterExp ='',@Ordstr ='',@Sdate ='',@Edate ='' ,@OutputAllCols=1
CREATE   PROCEDURE [dbo].[usp_mk_GetLeadList]  
(  
 @Parentid BIGINT,  
 @Userid INT = 0,  
 @FilterExp NVARCHAR(MAX) = '',  
 @Ordstr NVARCHAR(MAX) = '', --order by column name ex Enquiryid  
 @Sdate VARCHAR(50) = '', --start date  
 @Edate VARCHAR(50) = '', --end date  
 @OutputAllCols bit=0
)  
AS  
BEGIN  
  
 -- declare @Parentid BIGINT=32222,@Userid INT=0,@FilterExp nvarchar(max) = '',@Ordstr nvarchar(Max)='', @Sdate VARCHAR(50)= '15-Aug-2019', @Edate VARCHAR(50)='02-Feb-2020'  
  
    IF @Ordstr = ''  
    BEGIN  
        SET @Ordstr = 'FollowupDate desc, CreatedOn desc';  
    END;  
  
    DROP TABLE IF EXISTS #temp1;  
  
    IF @Sdate = '' AND @Edate = '' AND @FilterExp = ''  
    BEGIN  
        SELECT @Sdate = replace(convert(varchar,dateadd(day,-2,getdate()),106),' ','-');  
        SELECT @Edate = replace(convert(varchar,dateadd(day,1,getdate()),106),' ','-');  
    END;  
  
    DECLARE @Base_Column NVARCHAR(MAX)='', @Pivot_Column NVARCHAR(MAX);  
    DECLARE @Query NVARCHAR(MAX)= '', @Query1 NVARCHAR(MAX)= '';  
  
    IF @FilterExp = ''  
    BEGIN  
        SET @Query1 = ' AND ((CreatedOn >''' + @Sdate + ''' AND CreatedOn <''' + @Edate + ''') OR (FollowupDate >''' + @Sdate + ''' AND FollowupDate <''' + @Edate + '''));';  
    END;  
 ELSE  
 BEGIN  
     IF @Sdate <> '' AND @Edate <> ''  
        BEGIN  
        SET @Query1 = ' AND ((CreatedOn >''' + @Sdate + ''' AND CreatedOn <''' + @Edate + ''') OR (FollowupDate >''' + @Sdate + ''' AND FollowupDate <''' + @Edate + '''))';  
        END;  
  
        SET @Query1 = @Query1 + ' AND ' + @FilterExp + ' ;';  
 END  
  
    /*Select Pivot Column*/  
  
    SELECT @Pivot_Column = COALESCE(@Pivot_Column + ',', '') + QUOTENAME([fieldname])  
    FROM   
 (  
  SELECT DISTINCT [fieldname]  
  FROM customfields  
  WHERE [ParentID] = @Parentid AND [isActive] = 1  
 ) AS Tab;  
  
  
    SET @Query=CAST(N'SELECT DISTINCT            
   [A].[LeadId], [A].[LeadNo], [A].[PersonName], [A].[CompanyName],[A].[CountryCode1], [A].[MobileNo1],[A].[CountryCode2], [A].[MobileNo2],[A].[CountryCode3], [A].[MobileNo3], [A].[EmailID1], [A].[EmailID2], [A].[EmailID3], [A].[City], [A].[State], [A].[Country], [A].[Pincode], [A].[ResidentialAddress], [A].[OfficeAddress], [A].[Address], [A].[SourceName], [A].[MediumName], [A].[CampaignName], [A].[InitialRemarks], [A].[ParentId], [A].[User_Login], [dbo].[fn_getusertimefromindiantime](' + CAST(@Parentid AS NVARCHAR(MAX)) + ', [A].[FollowupDate]) AS [FollowupDate], [dbo].[fn_getusertimefromindiantime](' + CAST(@Parentid AS NVARCHAR(MAX)) + ', [A].[CreatedOn]) AS [CreatedOn], [A].[AssignedTo], [A].[Remarks],CASE WHEN ISNULL([A].[FollowupStatus], '''') <> ''
''    THEN ''<p><b>Follow Up Status:&nbsp;&nbsp;</b>'' + CAST(ISNULL([A].[FollowupStatus], '''') AS VARCHAR(50)) + ''</p>''           
    ELSE '''' END + CASE WHEN ISNULL([A].[FollowupDate], '''') <> ''''             
    THEN ''<p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST([A].[FollowupDate] AS VARCHAR(50)) + ''</p>'' ELSE '''' END             
    + CASE WHEN ISNULL([A].[Products], '''') <> '''' THEN ''<p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST([A].[Products] AS VARCHAR(50)) + ''</p>''     
 ELSE '''' END +             
    CASE WHEN ISNULL([A].[AmountPaid], 0) <> 0            
    THEN ''<p><b>Amount Paid:&nbsp;&nbsp;</b>'' + CAST(CAST(ISNULL([A].[AmountPaid], 0) AS DECIMAL(18, 0)) AS VARCHAR(50)) + ''</p>'' ELSE '''' END  +             
    CASE WHEN ISNULL([A].[Remarks], '''') <> ''''  
    THEN ''<p><b>Remarks:&nbsp;&nbsp;</b>'' + ISNULL([A].[Remarks], '''') + ''</p>''  
    ELSE '''' END AS [FollowUp], [A].[FollowupStatus], [A].[assigneduser], [A].[img_ext]  INTO #temp1  
    FROM            
    (  
    SELECT LeadId=[UL].[ID], [UL].[LeadNo], [UL].[PersonName], img_ext=isnull([UL].[img_ext],''''), CompanyName=isnull([UL].[CompanyName],''''),    
 CountryCode1=ISNULL([UL].[CountryCode], ''''), CountryCode2=ISNULL([UL].[Countrycode1], '''') , CountryCode3=ISNULL([UL].[Countrycode2], ''''),  
 MobileNo1=ISNULL([UL].[MobileNo], ''''), MobileNo2=ISNULL([UL].[Mobileno1], ''''), MobileNo3=ISNULL([UL].[Mobileno2], ''''),  
    EmailId1=ISNULL([UL].[Emailid], ''''),EmailId2=ISNULL([UL].[EmailID1], ''''),EmailId3= ISNULL([UL].[EmailID2], ''''),             
    [City]=isnull([UL].City,''''), [State]=isnull([UL].State,''''), [Country]=isnull([UL].Country,''''), PinCode=isnull([UL].[PinCode],0),   
 [ResidentialAddress]=isnull([UL].Residentialaddress,''''), [OfficeAddress]=isnull([UL].OfficeAddress,''''),  
 [ADDRESS]=CASE WHEN isnull([UL].Companyname,'''') <> '''' THEN isnull(UL.Officeaddress,'''') ELSE isnull(UL.Residentialaddress,'''') END + '' '' + (case when [UL].Pincode=0 then '''' else cast(isnull([UL].Pincode,'''') as varchar(10)) end) + '' '' + isnull([UL].City,'''') + '' '' + isnull([UL].State,'''') + '' '' + isnull([UL].Country,''''),   
 [UL].[AssignedTo], isnull([USS].[Name],'''') AS [SourceName], isnull([UMS].[Name],'''') AS [MediumName], isnull([UCS].[Name],'''') AS [CampaignName],   
 InitialRemarks=isnull([UL].[InitialRemarks],''''), [UL].[ParentID], FUS.[FollowupStatus], [UL].[FollowupDate], [UL].[Remarks],   
 ISNULL([UL].[AmountPaid], 0) AS [AmountPaid], [CreatedOn], [UL].[CreatedBy], [UL].[ModifiedOn], [UL].[ModifiedBy], [UD].[User_Login],   
 ( SELECT STUFF( (SELECT N'', '' + [ss].[Name] FROM [ProductMaster](nolock) AS [ss] INNER JOIN [dbo].[fn_Split]([ul].[Products], ''#'') AS [fs]            
    ON [ss].[ProductID] = [fs].[value] FOR XML PATH(''''), TYPE).value(''text()[1]'', ''nvarchar(max)''), 1, 2, N'''')            
    ) AS [Products], [UD].[User_Login] AS [assigneduser]       
    FROM UserLeads AS UL(NOLOCK) INNER JOIN UserSourceSettings AS USS(NOLOCK)            
    ON UL.SourceName = USS.SourceID LEFT JOIN UserMediumSettings AS UMS(NOLOCK)            
    ON UL.MediumName = UMS.MediumID LEFT JOIN UserCampaignSettings AS UCS(NOLOCK)            
    ON UL.CampaignName = UCS.CampaignID LEFT JOIN User_Detail AS UD(NOLOCK)            
    ON UL.AssignedTo = UD.User_ID LEFT JOIN User_Detail AS UD1(NOLOCK)            
    ON UL.CreatedBy = UD1.User_ID left join [FollowUp_Status](NOLOCK) AS FUS          
 ON UL.[FollowUpStatus] = FUS.[id]  WHERE [UL].[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + ' AND [UL].[AssignedTo] = CASE WHEN ' + CAST(@Userid AS NVARCHAR(MAX)) + ' = 0 THEN [UL].[AssignedTo] ELSE ' + CAST(@Userid AS NVARCHAR(MAX)) + ' END   
    ) AS A WHERE 1=1 ' + @Query1 + ' ' AS NVARCHAR(MAX));  
  
	If(@OutputAllCols = 0)
	Begin
		IF EXISTS(Select * From tbl_mk_ViewTemplate Where User_Id in (@Userid,@Parentid) and TemplateType='LD')
		BEGIN
			IF EXISTS(Select * From tbl_mk_ViewTemplate Where User_Id = @Userid and TemplateType='LD')
			BEGIN
			Select @Base_Column=ColumnList From tbl_mk_ViewTemplate Where User_Id = @Userid and TemplateType='LD'
			END
			ELSE
			BEGIN
			Select @Base_Column=ColumnList From tbl_mk_ViewTemplate Where User_Id = @Parentid and TemplateType='LD'
			END
		END
	End
	ELSE
	BEGIN
		Set @Base_Column='LeadId, LeadNo, PersonName, CompanyName, CountryCode1, MobileNo1, CountryCode2, MobileNo2, CountryCode3, MobileNo3, EmailID1, EmailID2, EmailID3, City, State, Country, Pincode, ResidentialAddress, OfficeAddress, Address, SourceName, MediumName, CampaignName, InitialRemarks, ParentId, User_Login, FollowupDate, CreatedOn, AssignedTo, Remarks, FollowUp, FollowupStatus, AssignedUser, Img_Ext';
		If(isnull(@Pivot_Column,'') != '')
		Begin
			Set @Base_Column += ', ' + @Pivot_Column
		End
	END  
     
 IF(@Pivot_Column IS NOT NULL)  
    BEGIN  
        /*Create Dynamic Query*/  
  SELECT @Query+=CAST(N';SELECT ' + @Base_Column + ' FROM  
  (SELECT LeadId, LeadNo, PersonName, CompanyName, CountryCode1, MobileNo1, CountryCode2, MobileNo2, CountryCode3, MobileNo3, EmailID1, EmailID2, EmailID3, City, State, Country, PinCode, ResidentialAddress, OfficeAddress, Address, SourceName, MediumName, CampaignName, InitialRemarks, ParentId, User_Login, FollowupDate, CreatedOn, AssignedTo, Remarks, FollowUp, FollowupStatus, AssignedUser, Img_Ext, [fieldname] , fieldvalue FROM (select L.LeadId, L.LeadNo, L.PersonName, L.CompanyName, L.CountryCode1, L.MobileNo1, L.CountryCode2, L.MobileNo2, L.CountryCode3, L.MobileNo3, L.EmailID1, L.EmailID2, L.EmailID3, L.City, L.State, L.Country, L.PinCode, L.ResidentialAddress, L.OfficeAddress, L.Address, L.SourceName, L.MediumName, L.CampaignName, L.InitialRemarks, L.ParentId, L.User_Login, L.FollowupDate, L.CreatedOn, L.AssignedTo, L.Remarks, L.FollowUp, L.FollowupStatus, L.AssignedUser, L.Img_Ext, y.fieldname, x.fieldvalue  
  From #temp1 L left join customfieldLeadvalue(nolock) x ON L.LeadId = x.LeadID left join customfields(nolock) y on x.fieldID=y.field_ID  
  AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + ' AND y.[isActive] = 1)q )Tab1  
  PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + ')) AS Tab2  
  ORDER BY ' + @Ordstr AS NVARCHAR(MAX));  
        --EXEC sp_executesql @Query;            
    END;  
 ELSE  
 BEGIN  
  SET @Query += CAST(N';select ' + @Base_Column + ' from #temp1 Order by ' + @Ordstr AS NVARCHAR(MAX));  
 END  
  
    print '@FinalQuery:- ' + cast(@Query as varchar(max))  
    EXEC sp_executesql @Query;  
  
    DROP TABLE IF EXISTS #temp1;  
  
END  



GO

/* ============================================================
   Procedure: [dbo].[usp_mk_GetLeadList_modified]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- exec usp_mk_GetLeadList_modified @Parentid=38004,@Userid=38012,@FilterExp=N'',@Ordstr=N'',@Sdate=N'12 Feb 2021',@Edate=N'14 Apr 2021',@Columns=N'',@OutputAllCols=0  
-- exec usp_mk_GetLeadList_modified @Parentid=38004,@Userid=38012,@FilterExp=N'',@Ordstr=N'',@Sdate=N'01-Jan-1900',@Edate=N'14-Apr-2021',@Columns=default,@OutputAllCols=0,@Mode=N'Export'  
-- exec usp_mk_GetLeadList_modified @Parentid=29453,@Userid=29453,@FilterExp=N'',@Ordstr=N'',@Sdate=N'08 Feb 2021',@Edate=N'10 Apr 2021',@Columns=N'',@OutputAllCols=0  
-- exec usp_mk_GetLeadList_modified @Parentid=32222,@Userid=32222,@FilterExp=N'',@Ordstr=N'',@Sdate=N'08 Feb 2021',@Edate=N'10 Apr 2021',@Columns=N'',@OutputAllCols=0  
-- exec usp_mk_GetLeadList_modified @Parentid=32222,@Userid=32222,@FilterExp=N'',@Ordstr=N'',@Sdate=N'1 Jan 1990',@Edate=N'10 Apr 2021',@Columns=N'',@OutputAllCols=0,@Mode='Export'  
--exec usp_mk_GetLeadList_modified @Parentid=38004,@Userid=38009,@FilterExp=N'',@Ordstr=N'',@Sdate=N'1 Jan 1990',@Edate=N'12 Apr 2021',@Columns=N'',@OutputAllCols=0  
-- exec usp_mk_GetLeadList_modified @Parentid=32222,@Userid=32222,@FilterExp=N'',@Ordstr=N'',@Sdate=N'01-Jan-1900',@Edate=N'13-Apr-2021',@Columns=default,@OutputAllCols=0,@Mode=N'Export'  
-- exec usp_mk_GetLeadList_modified @Parentid=38004,@Userid=38012,@FilterExp=N'CreatedOn = ''12-Apr-2021''',@Ordstr=N'',@Sdate=N'01-Jan-1900',@Edate=N'14-Apr-2021',@Columns=default,@OutputAllCols=0,@Mode=N'Export'  
  
CREATE   PROCEDURE [dbo].[usp_mk_GetLeadList_modified]  
(
	@Parentid BIGINT,  
	@Userid INT = 0,  
	@Columns NVARCHAR(MAX) = '',  
	@FilterExp NVARCHAR(MAX) = '',  
	@Ordstr NVARCHAR(MAX) = '', --order by column name ex Enquiryid  
	@Sdate VARCHAR(50) = '', --start date  
	@Edate VARCHAR(50) = '', --end date  
	@OutputAllCols bit=0,  
	@Mode varchar(10)=''  
)  
AS  
BEGIN  
  
 -- declare @Parentid BIGINT=32222,@Userid INT=32222,@FilterExp nvarchar(max) = '',@Ordstr nvarchar(Max)='', @Sdate VARCHAR(50)= '22 Dec 2020', @Edate VARCHAR(50)='21 Feb 2021' , @Columns NVARCHAR(MAX) = '', @OutputAllCols bit=0,@Mode varchar(10)='Export'
  
  --declare @Parentid BIGINT=39680,@Userid INT=40420,@FilterExp nvarchar(max) = '',@Ordstr nvarchar(Max)='', @Sdate VARCHAR(50)= '08 Sep 2022', @Edate VARCHAR(50)='08 Nov 2022' , @Columns NVARCHAR(MAX) = '', @OutputAllCols bit=0,@Mode varchar(10)=''
  
           
   -- Value swaping because ColumnView not working while passing {O in UserId}        
   declare @vmUserId bigint = @UserId, @IsAdmin bit = 0, @RecCnt nvarchar(max)='Top 500';      
   select @IsAdmin = IsAdmin from User_Detail(nolock) where User_ID = @Userid      
      
   Select @RecCnt= CASE WHEN @Mode = 'Export' THEN '' ELSE 'Top 500' END  
      
 if(@Parentid = @Userid or @IsAdmin = 1)  
 begin  
  set @Userid = 0  
 end  
                            
    IF @Ordstr = ''  
    BEGIN                            
        SET @Ordstr = N' case when cast(followupdate as date) = cast(getdate() as date) then 0         
      when followupdate < getdate()  then 1        
      when followupdate > getdate() then 2        
      when followupdate is null then 3        
       end,followupdate  '                            
    END;                            
                            
    DROP TABLE IF EXISTS #temp1;                            
                            
    IF @Sdate = '' AND @Edate = '' AND @FilterExp = ''                            
    BEGIN                            
        SELECT @Sdate = replace(convert(varchar,dateadd(day,-2,getdate()),106),' ','-');                            
        SELECT @Edate = replace(convert(varchar,dateadd(day,1,getdate()),106),' ','-');                            
    END;                            
                            
    DECLARE @Base_Column NVARCHAR(MAX)='', @Pivot_Column NVARCHAR(MAX);                            
    DECLARE @Query NVARCHAR(MAX)= '', @Query1 NVARCHAR(MAX)= '', @Query2 NVARCHAR(MAX)= '';                            
                            
    IF @FilterExp = ''                   
    BEGIN                            
        SET @Query1 = N' AND ((CreatedOn >=''' + @Sdate + ''' AND CreatedOn <=''' + @Edate + ''') OR (FollowupDate >=''' + @Sdate + ''' AND FollowupDate <=''' + @Edate + ''')) Order By ' + @Ordstr + ';'  
    END;                            
 ELSE  
 BEGIN  
  IF @Sdate <> '' AND @Edate <> ''                            
        BEGIN                            
        SET @Query1 = N' AND ((CreatedOn >=''' + @Sdate + ''' AND CreatedOn <=''' + @Edate + ''') OR (FollowupDate >=''' + @Sdate + ''' AND FollowupDate <=''' + @Edate + ''')) '  
        END;                            
                            
        SET @Query1 = @Query1 + ' AND ' + @FilterExp + ' Order By ' + @Ordstr + ';'  
 END                            
                            
    /*Select Pivot Column*/                            
                            
    SELECT @Pivot_Column = COALESCE(@Pivot_Column + ',', '') + QUOTENAME([fieldname])                            
    FROM                             
 (                            
  SELECT DISTINCT [fieldname]  
  FROM customfields(nolock)  
  WHERE [ParentID] = @Parentid AND [isActive] = 1  
 ) AS Tab;                            
     
	exec Usp_createProductMasterTable @ParentID
	                        
    SET @Query=    
 CAST(N'SELECT ' + @RecCnt + '   
   [A].[LeadId], [A].[LeadNo], [A].[PersonName], [A].[CompanyName],[A].[CountryCode1], [A].[MobileNo1],[A].[CountryCode2], [A].[MobileNo2],[A].[CountryCode3], [A].[MobileNo3], [A].[EmailID1], [A].[EmailID2], [A].[EmailID3],     
   [A].[City], [A].[State], [A].[Country], [A].[Pincode], [A].[ResidentialAddress], [A].[OfficeAddress], [A].[Address], [A].[SourceName], [A].[MediumName], [A].[CampaignName], [A].[InitialRemarks], [A].[ParentId],     
   [A].[User_Login], [dbo].[fn_getusertimefromindiantime](' + CAST(@Parentid AS NVARCHAR(MAX)) + ', [A].[FollowupDate]) AS [FollowupDate], [dbo].[fn_getusertimefromindiantime](' + CAST(@Parentid AS NVARCHAR(MAX)) + ',     
   [A].[CreatedOn]) AS [CreatedOn], [A].[AssignedTo], [A].[Remarks],CASE WHEN ISNULL([A].[FollowupStatus], '''') <> '''' THEN ''<p><b>FollowUpStatus:&nbsp;&nbsp;</b>'' +     
   CAST(ISNULL([A].[FollowupStatus], '''') AS VARCHAR(50)) + ''</p>'' ELSE '''' END +     
   CASE WHEN ISNULL([A].[FollowupDate], '''') <> '''' THEN ''<p><b>Next Status Date:&nbsp;&nbsp;</b>'' +     
   CAST([A].[FollowupDate] AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL([A].[Products], '''') <> '''' THEN ''<p><b>Next Status Date:&nbsp;&nbsp;</b>'' +     
   CAST([A].[Products] AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL([A].[AmountPaid], 0) <> 0 THEN ''<p><b>Amount Paid:&nbsp;&nbsp;</b>'' +     
   CAST(CAST(ISNULL([A].[AmountPaid], 0) AS DECIMAL(18, 0)) AS VARCHAR(50)) + ''</p>'' ELSE '''' END  +    
   CASE WHEN ISNULL([A].[Remarks], '''') <> ''''THEN ''<p><b>Remarks:&nbsp;&nbsp;</b>'' + ISNULL([A].[Remarks], '''') + ''</p>'' ELSE '''' END AS [FollowUp], [A].[FollowupStatus], [A].[assigneduser], [A].[img_ext], [A].[ProfileImgFileName], CASE WHEN [A].[IsConvert] = 0 and CAST([A].[FollowupDate] AS DATE) = CAST(GETDATE() AS DATE) THEN ''Due today'' WHEN [A].[IsConvert] = 0 and [A].[FollowupDate] > GETDATE() THEN ''Scheduled'' WHEN [A].[IsConvert] = 0 and [A].[FollowupDate] < GETDATE() THEN ''Overdue'' 
ELSE '''' END AS StatusHtml,  
   [A].[LastFollowupCreatedBy], [A].[LastFollowupCreatedOn]  
   INTO #temp1 FROM ( SELECT LeadId=[UL].[ID], [UL].[LeadNo], [UL].[PersonName], img_ext=isnull([UL].[img_ext],''''), CompanyName=isnull([UL].[CompanyName],''''), CountryCode1=ISNULL([UL].[CountryCode], ''''), CountryCode2=ISNULL([UL].[Countrycode1], ''''
) , CountryCode3=ISNULL([UL].[Countrycode2], ''''), MobileNo1=ISNULL([UL].[MobileNo], ''''), MobileNo2=ISNULL([UL].[Mobileno1], ''''), MobileNo3=ISNULL([UL].[Mobileno2], ''''),  EmailId1=ISNULL([UL].[Emailid], ''''),EmailId2=ISNULL([UL].[EmailID1], ''''),
EmailId3= ISNULL([UL].[EmailID2], ''''), [City]=isnull([UL].City,''''), [State]=isnull([UL].State,''''), [Country]=isnull([UL].Country,''''), PinCode=isnull([UL].[PinCode],0), [ResidentialAddress]=isnull([UL].Residentialaddress,''''), [OfficeAddress]=isnull([UL].OfficeAddress,''''), [ADDRESS]=CASE WHEN isnull([UL].Companyname,'''') <> '''' THEN isnull(UL.Officeaddress,'''') ELSE isnull(UL.Residentialaddress,'''') END  + '' '' + (case when [UL].Pincode=0 then '''' else cast(isnull([UL].Pincode,'''') as varchar(10)) end) + '' '' + isnull([UL].City,'''') + '' '' + isnull([UL].State,'''') +  '' '' + isnull([UL].Country,''''), [UD].[User_Login] as [AssignedTo], isnull([USS].[Name],'''') AS [SourceName], isnull([UMS].[Name],'''') AS [MediumName], isnull([UCS].[Name],'''') AS [CampaignName], InitialRemarks=isnull([UL].[InitialRemarks],''''), [UL].[ParentID], FUS.[FollowupStatus], FUS.IsCallback, FUS.IsConvert, [UL].[FollowupDate], [UL].[Remarks], ISNULL([UL].[AmountPaid], 0) AS [AmountPaid], [CreatedOn], [UD1].[User_Login] as [CreatedBy], [UL].[ModifiedOn], [UL].[ModifiedBy], [UD].[User_Login], ProfileImgFileName = ISNULL([UL].[ProfileImgFileName], ''''), ( SELECT STUFF( (SELECT N'', '' + [ss].[Name]
   FROM tbl_ProductMaster_' + CAST(@Parentid as nvarchar(max)) + ' (nolock) AS [ss] INNER JOIN [dbo].[fn_Split]([ul].[Products], ''#'') AS [fs] ON [ss].[ProductID] = [fs].[value] FOR XML PATH(''''), TYPE).value(''text()[1]'', ''nvarchar(max)''), 1, 2, N'''')) AS [Products], [UD].[User_Login] AS [assigneduser], ISNULL(UD2.User_Login, '''') as LastFollowupCreatedBy, UL.LastFollowupCreatedOn FROM UserLeads AS UL(NOLOCK) left join UserSourceSettings AS USS(NOLOCK) ON UL.SourceName = USS.SourceID LEFT JOIN UserMediumSettings AS UMS(NOLOCK) ON UL.MediumName = UMS.MediumID LEFT JOIN UserCampaignSettings AS UCS(NOLOCK) 
ON UL.CampaignName = UCS.CampaignID LEFT JOIN User_Detail AS UD(NOLOCK) ON UL.AssignedTo = UD.User_ID LEFT JOIN User_Detail AS UD1(NOLOCK) ON UL.CreatedBy = UD1.User_ID LEFT JOIN User_Detail AS UD2(NOLOCK) ON UL.LastFollowupCreatedBy = UD2.User_ID left join FollowUp_Status AS FUS(NOLOCK) ON UL.FollowUpStatus = FUS.id WHERE [UL].[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + ' AND [UL].[AssignedTo] = CASE WHEN ''' + CAST(@Userid AS NVARCHAR(MAX)) + ''' = 0 THEN [UL].[AssignedTo] ELSE ' + CAST(@Userid 
AS NVARCHAR(MAX)) + ' END ) AS A WHERE 1=1 ' + @Query1 + ' ' AS NVARCHAR(MAX));                            
 
declare  @Base_ColumnCSV nvarchar(2000)  = 'LeadId, LeadNo, PersonName, CompanyName, CountryCode1, MobileNo1, CountryCode2, MobileNo2, CountryCode3, MobileNo3, EmailID1, EmailID2, EmailID3, City, State, Country, Pincode, ResidentialAddress, OfficeAddress
, Address, SourceName, MediumName, CampaignName, InitialRemarks, ParentId, User_Login, FollowupDate, CreatedOn, AssignedTo, Remarks, FollowUp, FollowupStatus, AssignedUser, Img_Ext, ProfileImgFileName,StatusHtml';              
  
 IF(@Columns = '')                        
 BEGIN                            
  If(@OutputAllCols = 0)                          
  Begin                          
   IF EXISTS(Select * From tbl_mk_ViewTemplate(nolock) Where User_Id in (@vmUserId, @Parentid) and TemplateType='LD')  
   BEGIN                          
    IF EXISTS(Select * From tbl_mk_ViewTemplate(nolock) Where User_Id = @vmUserId and TemplateType='LD')  
    BEGIN                          
     Select @Base_Column=ColumnList From tbl_mk_ViewTemplate(nolock) Where User_Id = @vmUserId and TemplateType='LD'  
    END  
    ELSE  
    BEGIN  
     Select @Base_Column=ColumnList From tbl_mk_ViewTemplate(nolock) Where User_Id = @Parentid and TemplateType='LD'  
    END  
   END  
   ELSE  
   BEGIN  
    Set @Base_Column= @Base_ColumnCSV;  
  
    If(isnull(@Pivot_Column,'') != '')  
    Begin  
    Set @Base_Column += ', ' + @Pivot_Column  
    End  
   END  
  End  
  ELSE  
  BEGIN  
   Set @Base_Column= @Base_ColumnCSV;  
  
   If(isnull(@Pivot_Column,'') != '')  
