/* ============================================================
   Procedure: [dbo].[usp_mk_GetLeadList_modified_cor]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- usp_mk_GetLeadList_modified 34261,34261,'','','','01Apr2020','26Apr2020',''              
CREATE   PROCEDURE [dbo].[usp_mk_GetLeadList_modified_cor]                        
(                        
 @Parentid BIGINT,                        
 @Userid INT = 0,                    
 @Columns NVARCHAR(MAX) = '',                       
 @FilterExp NVARCHAR(MAX) = '',                        
 @Ordstr NVARCHAR(MAX) = '', --order by column name ex Enquiryid                        
 @Sdate VARCHAR(50) = '', --start date                        
 @Edate VARCHAR(50) = '', --end date                        
 @OutputAllCols bit=0                      
)                        
AS                        
BEGIN                        
                        
 -- declare @Parentid BIGINT=34594,@Userid INT=34594,@FilterExp nvarchar(max) = '',@Ordstr nvarchar(Max)='', @Sdate VARCHAR(50)= '22 Dec 2020', @Edate VARCHAR(50)='21 Feb 2021' , @Columns NVARCHAR(MAX) = '',   @OutputAllCols bit=0      
       
   -- Value swaping because ColumnView not working while passing {O in UserId}    
   declare @vmUserId bigint = @UserId, @IsAdmin bit = 0;  
  
   select @IsAdmin = IsAdmin from User_Detail(nolock) where User_ID = @Userid  
  
  
  if(@Parentid = @Userid or @IsAdmin = 1)      
  begin      
   set @Userid = 0      
  end    
    
      
                        
    IF @Ordstr = ''                        
    BEGIN                        
        SET @Ordstr = '   case when cast(followupdate as date) = cast(getdate() as date) then 0     
      when followupdate < getdate()  then 1    
      when followupdate > getdate() then 2    
      when followupdate is null then 3    
       end,followupdate  '                        
    END;                        
                        
    DROP TABLE IF EXISTS #temp1;                        
                        
    IF @Sdate = '' AND @Edate = '' AND @FilterExp = ''                        
    BEGIN                        
        SELECT @Sdate = replace(convert(varchar,dateadd(day,-2,getdate()),106),' ','-');                        
        SELECT @Edate = replace(convert(varchar,dateadd(day,1,getdate()),106),' ','-');                        
    END;                        
                        
    DECLARE @Base_Column NVARCHAR(MAX)='', @Pivot_Column NVARCHAR(MAX);                        
    DECLARE @Query NVARCHAR(MAX)= '', @Query1 NVARCHAR(MAX)= '';                        
                        
    IF @FilterExp = ''                        
    BEGIN                        
        SET @Query1 = ' AND ((CreatedOn >=''' + @Sdate + ''' AND CreatedOn <=''' + @Edate + ''') OR (FollowupDate >=''' + @Sdate + ''' AND FollowupDate <=''' + @Edate + '''));';                        
    END;                        
 ELSE                        
 BEGIN                        
     IF @Sdate <> '' AND @Edate <> ''                        
        BEGIN                        
        SET @Query1 = ' AND ((CreatedOn >=''' + @Sdate + ''' AND CreatedOn <=''' + @Edate + ''') OR (FollowupDate >=''' + @Sdate + ''' AND FollowupDate <=''' + @Edate + '''))';                        
        END;                        
                        
        SET @Query1 = @Query1 + ' AND ' + @FilterExp + ' ;';                        
 END                        
                        
    /*Select Pivot Column*/                        
                        
    SELECT @Pivot_Column = COALESCE(@Pivot_Column + ',', '') + QUOTENAME([fieldname])                        
    FROM                         
 (                        
  SELECT DISTINCT [fieldname]                        
  FROM customfields(nolock)                        
  WHERE [ParentID] = @Parentid AND [isActive] = 1                        
 ) AS Tab;                        
                        
                        
    SET @Query=
	CAST(N'SELECT DISTINCT                                  
   [A].[LeadId], [A].[LeadNo], [A].[PersonName], [A].[CompanyName],[A].[CountryCode1], [A].[MobileNo1],[A].[CountryCode2], [A].[MobileNo2],[A].[CountryCode3], [A].[MobileNo3], [A].[EmailID1], [A].[EmailID2], [A].[EmailID3], 
   [A].[City], [A].[State], [A].[Country], [A].[Pincode], [A].[ResidentialAddress], [A].[OfficeAddress], [A].[Address], [A].[SourceName], [A].[MediumName], [A].[CampaignName], [A].[InitialRemarks], [A].[ParentId], 
   [A].[User_Login], [dbo].[fn_getusertimefromindiantime](' + CAST(@Parentid AS NVARCHAR(MAX)) + ', [A].[FollowupDate]) AS [FollowupDate], [dbo].[fn_getusertimefromindiantime](' + CAST(@Parentid AS NVARCHAR(MAX)) + ', 
   [A].[CreatedOn]) AS [CreatedOn], [A].[AssignedTo], [A].[Remarks],CASE WHEN ISNULL([A].[FollowupStatus], '''') <> '''' THEN ''<p><b>FollowUpStatus:&nbsp;&nbsp;</b>'' + 
   CAST(ISNULL([A].[FollowupStatus], '''') AS VARCHAR(50)) + ''</p>'' ELSE '''' END + 
   CASE WHEN ISNULL([A].[FollowupDate], '''') <> '''' THEN ''<p><b>Next Status Date:&nbsp;&nbsp;</b>'' + 
   CAST([A].[FollowupDate] AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL([A].[Products], '''') <> '''' THEN ''<p><b>Next Status Date:&nbsp;&nbsp;</b>'' + 
   CAST([A].[Products] AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL([A].[AmountPaid], 0) <> 0 THEN ''<p><b>Amount Paid:&nbsp;&nbsp;</b>'' + 
   CAST(CAST(ISNULL([A].[AmountPaid], 0) AS DECIMAL(18, 0)) AS VARCHAR(50)) + ''</p>'' ELSE '''' END  +
   CASE WHEN ISNULL([A].[Remarks], '''') <> ''''THEN ''<p><b>Remarks:&nbsp;&nbsp;</b>'' + ISNULL([A].[Remarks], '''') + ''</p>'' ELSE '''' END AS [FollowUp], 
   [A].[FollowupStatus], [A].[assigneduser], [A].[img_ext], [A].[ProfileImgFileName], 
   CASE WHEN cast([A].[FollowupDate] as date) = cast(getdate() as date)  then  ''Due today '' 
   WHEN [A].[FollowupDate] > getdate()  then  ''Scheduled'' 
   WHEN [A].[FollowupDate] < getdate()  then  ''Overdue'' ELSE ''''  end as StatusHtml             
   INTO #temp1             
    FROM             
    (             
    SELECT LeadId=[UL].[ID], [UL].[LeadNo], [UL].[PersonName], img_ext=isnull([UL].[img_ext],''''), CompanyName=isnull([UL].[CompanyName],''''), CountryCode1=ISNULL([UL].[CountryCode], ''''), 
	CountryCode2=ISNULL([UL].[Countrycode1], '''') , CountryCode3=ISNULL([UL].[Countrycode2], ''''), MobileNo1=ISNULL([UL].[MobileNo], ''''), MobileNo2=ISNULL([UL].[Mobileno1], ''''), 
	MobileNo3=ISNULL([UL].[Mobileno2], ''''),  EmailId1=ISNULL([UL].[Emailid], ''''),EmailId2=ISNULL([UL].[EmailID1], ''''),EmailId3= ISNULL([UL].[EmailID2], ''''), [City]=isnull([UL].City,''''),  
	[State]=isnull([UL].State,''''), [Country]=isnull([UL].Country,''''), PinCode=isnull([UL].[PinCode],0), [ResidentialAddress]=isnull([UL].Residentialaddress,''''), [OfficeAddress]=isnull([UL].OfficeAddress,''''),
	[ADDRESS]=CASE WHEN isnull([UL].Companyname,'''') <> '''' THEN isnull(UL.Officeaddress,'''') ELSE isnull(UL.Residentialaddress,'''') END  + '' '' + (case when [UL].Pincode=0 then '''' else 
	cast(isnull([UL].Pincode,'''') as varchar(10)) end) + '' '' + isnull([UL].City,'''') + '' '' + isnull([UL].State,'''') +  '' '' + isnull([UL].Country,''''), [UL].[AssignedTo], isnull([USS].[Name],'''') AS [SourceName], 
	isnull([UMS].[Name],'''') AS [MediumName], isnull([UCS].[Name],'''') AS [CampaignName], InitialRemarks=isnull([UL].[InitialRemarks],''''), [UL].[ParentID], FUS.[FollowupStatus], [UL].[FollowupDate], 
	[UL].[Remarks], ISNULL([UL].[AmountPaid], 0) AS [AmountPaid], [CreatedOn], [UL].[CreatedBy], [UL].[ModifiedOn], [UL].[ModifiedBy], [UD].[User_Login], ProfileImgFileName = ISNULL([UL].[ProfileImgFileName], ''''), 
	( SELECT STUFF( (SELECT N'', '' + [ss].[Name] FROM [ProductMaster](nolock) AS [ss] INNER JOIN [dbo].[fn_Split]([ul].[Products], ''#'') AS [fs] ON [ss].[ProductID] = [fs].[value] FOR XML PATH(''''), 
	TYPE).value(''text()[1]'', ''nvarchar(max)''), 1, 2, N'''')) AS [Products], [UD].[User_Login] AS [assigneduser]             
    FROM UserLeads AS UL(NOLOCK) INNER JOIN UserSourceSettings AS USS(NOLOCK)                                  
    ON UL.SourceName = USS.SourceID LEFT JOIN UserMediumSettings AS UMS(NOLOCK)                                  
    ON UL.MediumName = UMS.MediumID LEFT JOIN UserCampaignSettings AS UCS(NOLOCK)                                  
    ON UL.CampaignName = UCS.CampaignID LEFT JOIN User_Detail AS UD(NOLOCK)                                  
    ON UL.AssignedTo = UD.User_ID LEFT JOIN User_Detail AS UD1(NOLOCK)                                  
    ON UL.CreatedBy = UD1.User_ID left join [FollowUp_Status] AS FUS(NOLOCK)             
    ON UL.[FollowUpStatus] = FUS.[id]  WHERE [UL].[ParentID] = ' + 
	CAST(@Parentid AS NVARCHAR(MAX)) + ' AND [UL].[AssignedTo] = CASE WHEN ''' + CAST(@Userid AS NVARCHAR(MAX)) + ''' = 0 THEN [UL].[AssignedTo] ELSE ' + CAST(@Userid AS NVARCHAR(MAX)) + ' END ) AS A WHERE 1=1 ' 
	+ @Query1 + ' ' AS NVARCHAR(MAX));                        

declare  @Base_ColumnCSV nvarchar(2000)  = 'LeadId, LeadNo, PersonName, CompanyName, CountryCode1, MobileNo1, CountryCode2, MobileNo2, CountryCode3, MobileNo3, EmailID1, EmailID2, EmailID3, City, State, Country, Pincode, ResidentialAddress, OfficeAddress,
 Address, SourceName, MediumName, CampaignName, InitialRemarks, ParentId, User_Login, FollowupDate, CreatedOn, AssignedTo, Remarks, FollowUp, FollowupStatus, AssignedUser, Img_Ext, ProfileImgFileName,StatusHtml';          
IF(@Columns = '')                    
BEGIN                        
 If(@OutputAllCols = 0)                      
 Begin                      
  IF EXISTS(Select * From tbl_mk_ViewTemplate(nolock) Where User_Id in (@vmUserId, @Parentid) and TemplateType='LD')                      
   BEGIN                      
    IF EXISTS(Select * From tbl_mk_ViewTemplate(nolock) Where User_Id = @vmUserId and TemplateType='LD')                      
    BEGIN                      
     Select @Base_Column=ColumnList From tbl_mk_ViewTemplate(nolock) Where User_Id = @vmUserId and TemplateType='LD'                      
    END                      
    ELSE                      
    BEGIN                      
     Select @Base_Column=ColumnList From tbl_mk_ViewTemplate(nolock) Where User_Id = @Parentid and TemplateType='LD'                      
    END                      
   END                   
  ELSE                      
   BEGIN                      
    Set @Base_Column= @Base_ColumnCSV;                      
    If(isnull(@Pivot_Column,'') != '')                      
    Begin                      
     Set @Base_Column += ', ' + @Pivot_Column                      
    End                      
   END                     
 End                      
 ELSE                      
 BEGIN                      
  Set @Base_Column= @Base_ColumnCSV;                  
                     
  If(isnull(@Pivot_Column,'') != '')                      
  Begin                      
   Set @Base_Column += ', ' + @Pivot_Column                      
  End                      
 END                    
 END                    
 ELSE                    
 BEGIN                    
 SET @Base_Column = @Columns                    
 END                    
                           
 IF(@Pivot_Column IS NOT NULL)                        
    BEGIN                        
        /*Create Dynamic Query*/                        
  SELECT @Query+=CAST(N';SELECT ' + @Base_Column + ' FROM                        
  (SELECT LeadId, LeadNo, PersonName, CompanyName, CountryCode1, MobileNo1, CountryCode2, MobileNo2, CountryCode3, MobileNo3, EmailID1, EmailID2, EmailID3, City, State, Country, PinCode, ResidentialAddress, OfficeAddress, Address, 
SourceName, MediumName,CampaignName, InitialRemarks, ParentId, User_Login, FollowupDate, CreatedOn, AssignedTo, Remarks, FollowUp, FollowupStatus, AssignedUser, Img_Ext,ProfileImgFileName, StatusHtml, [fieldname] , 
fieldvalue FROM (select L.LeadId, L.LeadNo, L.PersonName, L.CompanyName, L.CountryCode1, L.MobileNo1, L.CountryCode2, L.MobileNo2, L.CountryCode3, L.MobileNo3, L.EmailID1, L.EmailID2, L.EmailID3, L.City, L.State, 
L.Country, L.PinCode, L.ResidentialAddress, L.OfficeAddress, L.Address, L.SourceName, L.MediumName, L.CampaignName, L.InitialRemarks, L.ParentId, L.User_Login, L.FollowupDate, L.CreatedOn, L.AssignedTo, L.Remarks, 
L.FollowUp, L.FollowupStatus, L.AssignedUser, L.Img_Ext, L.ProfileImgFileName, L.StatusHtml, y.fieldname, x.fieldvalue              
  From #temp1 L left join customfieldLeadvalue(nolock) x ON L.LeadId = x.LeadID left join customfields(nolock) y on x.fieldID=y.field_ID                        
  AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + ' AND y.[isActive] = 1)q )Tab1                        
  PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + ')) AS Tab2                        
  ORDER BY ' + @Ordstr AS NVARCHAR(MAX));       
      
    
    
        --EXEC sp_executesql @Query;                                  
    END;                        
 ELSE                 
 BEGIN                        
  SET @Query += CAST(N';select ' + @Base_Column + ' from #temp1 Order by ' + @Ordstr AS NVARCHAR(MAX));                        
 END                        
                        
    print '@FinalQuery:- ' + cast(@Query as varchar(max))                        
    EXEC sp_executesql @Query;                        
          
    DROP TABLE IF EXISTS #temp1;                        
                        
END     


