   [A].[MediumName], [A].[CampaignName], [A].[InitialRemarks], [A].[ParentId], [A].[User_Login], [dbo].[fn_getusertimefromindiantime](' + CAST(@Parentid AS NVARCHAR(MAX)) + ',   
   [A].[FollowupDate]) AS [FollowupDate], [dbo].[fn_getusertimefromindiantime](' + CAST(@Parentid AS NVARCHAR(MAX)) + ', [A].[CreatedOn]) AS [CreatedOn], [A].[AssignedTo],   
   [A].[Remarks],CASE WHEN ISNULL([A].[FollowupStatus], '''') <> '''' THEN ''<p><b>Follow Up Status:&nbsp;&nbsp;</b>'' + CAST(ISNULL([A].[FollowupStatus], '''') AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL([A].[FollowupDate], '''') <> ''''  THEN ''<p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST([A].[FollowupDate] AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL([A].[Products], '''') <> '''' THEN ''<p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST([A].[Products] AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL([A].[AmountPaid], 0) <> 0 THEN ''<p><b>Amount Paid:&nbsp;&nbsp;</b>'' + CAST(CAST(ISNULL([A].[AmountPaid], 0) AS DECIMAL(18, 0)) AS VARCHAR(50)) + ''</p>'' ELSE '''' END  +CASE WHEN ISNULL([A].[Remarks], '''') <> ''''THEN ''<p><b>Remarks:&nbsp;&nbsp;</b>'' + ISNULL([A].[Remarks], '''') + ''</p>'' ELSE '''' END AS [FollowUp], 
   [A].[FollowupStatus], [A].[assigneduser], [A].[img_ext], [A].[ProfileImgFileName],
   CASE WHEN convert(varchar(10),[A].[FollowupDate],103) = convert(varchar(10),getdate(),103)  then  ''Due today '' ELSE '''' END + CASE WHEN convert(varchar(10),[A].[FollowupDate],103) > convert(varchar(10),getdate(),103)  then  ''Scheduled'' ELSE '''' END +
  CASE WHEN (convert(varchar(10),[A].[FollowupDate],103) < convert(varchar(10),getdate(),103)  then  ''Overdue'' ELSE ''  end as StatusHtml
   INTO #temp1          
    FROM                    
    (          
    SELECT LeadId=[UL].[ID], [UL].[LeadNo], [UL].[PersonName], img_ext=isnull([UL].[img_ext],''''), CompanyName=isnull([UL].[CompanyName],''''),            
 CountryCode1=ISNULL([UL].[CountryCode], ''''), CountryCode2=ISNULL([UL].[Countrycode1], '''') , CountryCode3=ISNULL([UL].[Countrycode2], ''''),          
 MobileNo1=ISNULL([UL].[MobileNo], ''''), MobileNo2=ISNULL([UL].[Mobileno1], ''''), MobileNo3=ISNULL([UL].[Mobileno2], ''''),          
    EmailId1=ISNULL([UL].[Emailid], ''''),EmailId2=ISNULL([UL].[EmailID1], ''''),EmailId3= ISNULL([UL].[EmailID2], ''''),                     
    [City]=isnull([UL].City,''''), [State]=isnull([UL].State,''''), [Country]=isnull([UL].Country,''''), PinCode=isnull([UL].[PinCode],0),           
 [ResidentialAddress]=isnull([UL].Residentialaddress,''''), [OfficeAddress]=isnull([UL].OfficeAddress,''''),          
 [ADDRESS]=CASE WHEN isnull([UL].Companyname,'''') <> '''' THEN isnull(UL.Officeaddress,'''') ELSE isnull(UL.Residentialaddress,'''') END  + '' '' + 
 (case when [UL].Pincode=0 then '''' else cast(isnull([UL].Pincode,'''') as varchar(10)) end) + '' '' + isnull([UL].City,'''') + '' '' + isnull([UL].State,'''') +  '' '' + isnull([UL].Country,''''),           
 [UL].[AssignedTo], isnull([USS].[Name],'''') AS [SourceName], isnull([UMS].[Name],'''') AS [MediumName], isnull([UCS].[Name],'''') AS [CampaignName],           
 InitialRemarks=isnull([UL].[InitialRemarks],''''), [UL].[ParentID], FUS.[FollowupStatus], [UL].[FollowupDate], [UL].[Remarks],           
 ISNULL([UL].[AmountPaid], 0) AS [AmountPaid], [CreatedOn], [UL].[CreatedBy], [UL].[ModifiedOn], [UL].[ModifiedBy], [UD].[User_Login], ProfileImgFileName = ISNULL([UL].[ProfileImgFileName], ''''),          
 ( SELECT STUFF( (SELECT N'', '' + [ss].[Name] FROM [ProductMaster](nolock) AS [ss] INNER JOIN [dbo].[fn_Split]([ul].[Products], ''#'') AS [fs]                    
    ON [ss].[ProductID] = [fs].[value] FOR XML PATH(''''), TYPE).value(''text()[1]'', ''nvarchar(max)''), 1, 2, N'''')                    
    ) AS [Products], [UD].[User_Login] AS [assigneduser]            
    FROM UserLeads AS UL(NOLOCK) INNER JOIN UserSourceSettings AS USS(NOLOCK)                    
    ON UL.SourceName = USS.SourceID LEFT JOIN UserMediumSettings AS UMS(NOLOCK)                    
    ON UL.MediumName = UMS.MediumID LEFT JOIN UserCampaignSettings AS UCS(NOLOCK)                    
    ON UL.CampaignName = UCS.CampaignID LEFT JOIN User_Detail AS UD(NOLOCK)                    
    ON UL.AssignedTo = UD.User_ID LEFT JOIN User_Detail AS UD1(NOLOCK)                    
    ON UL.CreatedBy = UD1.User_ID left join [FollowUp_Status](NOLOCK) AS FUS                  
 ON UL.[FollowUpStatus] = FUS.[id]  WHERE [UL].[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + ' AND [UL].[AssignedTo] = CASE WHEN ' + CAST(@Userid AS NVARCHAR(MAX)) + ' = 0 THEN [UL].[AssignedTo] ELSE ' + CAST(@Userid AS NVARCHAR(MAX)) + ' END       
  
    
    ) AS A WHERE 1=1 ' + @Query1 + ' ' AS NVARCHAR(MAX));          
declare  @Base_ColumnCSV nvarchar(1000)  = 'LeadId, LeadNo, PersonName, CompanyName, CountryCode1, MobileNo1, CountryCode2, MobileNo2, CountryCode3, MobileNo3, EmailID1, EmailID2, EmailID3, City, State, Country, Pincode, ResidentialAddress, OfficeAddress,  
 Address, SourceName, MediumName, CampaignName, InitialRemarks, ParentId, User_Login, FollowupDate, CreatedOn, AssignedTo, Remarks, FollowUp, FollowupStatus, AssignedUser, Img_Ext, ProfileImgFileName,StatusHtml';        
IF(@Columns = '')      
BEGIN          
 If(@OutputAllCols = 0)        
 Begin        
  IF EXISTS(Select * From tbl_mk_ViewTemplate Where User_Id in (@Userid,@Parentid) and TemplateType='LD')        
   BEGIN        
    IF EXISTS(Select * From tbl_mk_ViewTemplate Where User_Id = @Userid and TemplateType='LD')        
    BEGIN        
     Select @Base_Column=ColumnList From tbl_mk_ViewTemplate Where User_Id = @Userid and TemplateType='LD'        
    END        
    ELSE        
    BEGIN        
     Select @Base_Column=ColumnList From tbl_mk_ViewTemplate Where User_Id = @Parentid and TemplateType='LD'        
    END        
   END     
  ELSE        
   BEGIN        
    Set @Base_Column= @Base_ColumnCSV;        
    If(isnull(@Pivot_Column,'') != '')        
    Begin        
     Set @Base_Column += ', ' + @Pivot_Column        
    End        
   END       
 End        
 ELSE        
 BEGIN        
  Set @Base_Column= @Base_ColumnCSV;    
       
  If(isnull(@Pivot_Column,'') != '')        
  Begin        
   Set @Base_Column += ', ' + @Pivot_Column        
  End        
 END      
 END      
 ELSE      
 BEGIN      
 SET @Base_Column = @Columns      
 END      
             
 IF(@Pivot_Column IS NOT NULL)          
    BEGIN          
        /*Create Dynamic Query*/          
  SELECT @Query+=CAST(N';SELECT ' + @Base_Column + ' FROM          
  (SELECT LeadId, LeadNo, PersonName, CompanyName, CountryCode1, MobileNo1, CountryCode2, MobileNo2, CountryCode3, MobileNo3, EmailID1, EmailID2, EmailID3, City, State,   
  Country, PinCode, ResidentialAddress, OfficeAddress, Address, SourceName, MediumName,CampaignName, InitialRemarks, ParentId, User_Login, FollowupDate, CreatedOn, AssignedTo,   
  Remarks, FollowUp, FollowupStatus, AssignedUser, Img_Ext,ProfileImgFileName, [fieldname] , fieldvalue FROM (select L.LeadId, L.LeadNo, L.PersonName, L.CompanyName,
  L.CountryCode1, L.MobileNo1, L.CountryCode2, L.MobileNo2, L.CountryCode3, L.MobileNo3, L.EmailID1, L.EmailID2, L.EmailID3, L.City, L.State, L.Country, L.PinCode,   
  L.ResidentialAddress, L.OfficeAddress, L.Address, L.SourceName, L.MediumName, L.CampaignName, L.InitialRemarks, L.ParentId, L.User_Login, L.FollowupDate, L.CreatedOn,   
  L.AssignedTo, L.Remarks, L.FollowUp, L.FollowupStatus, L.AssignedUser, L.Img_Ext, L.ProfileImgFileName, y.fieldname, x.fieldvalue          
  From #temp1 L left join customfieldLeadvalue(nolock) x ON L.LeadId = x.LeadID left join customfields(nolock) y on x.fieldID=y.field_ID          
  AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + ' AND y.[isActive] = 1)q )Tab1          
  PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + ')) AS Tab2          
  ORDER BY ' + @Ordstr AS NVARCHAR(MAX));          
        --EXEC sp_executesql @Query;                    
    END;          
 ELSE          
 BEGIN          
  SET @Query += CAST(N';select ' + @Base_Column + ' from #temp1 Order by ' + @Ordstr AS NVARCHAR(MAX));          
 END          
          
    print '@FinalQuery:- ' + cast(@Query as varchar(max))          
    EXEC sp_executesql @Query;          
          
    DROP TABLE IF EXISTS #temp1;          
          
END 


GO

/* ============================================================
   Procedure: [dbo].[usp_mk_GetLeadNotesDetail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
-- exec usp_mk_GetLeadNotesDetail 299431  
  
CREATE   PROCEDURE [dbo].[usp_mk_GetLeadNotesDetail] @LeadID INT  
AS  
    BEGIN  
        SELECT l.NoteID,   
               l.UserID,   
               l.LeadID,   
               u.User_Login,
			   u.User_Login as UserLogin  , 
               l.Notes,   
               l.CreatedDate,   
               l.DeletedDate,   
               l.UpdatedDate  
        FROM tbl_LeadNotes l  
             INNER JOIN User_Detail u ON u.User_ID = l.UserID  
        WHERE LeadID = @LeadID  
        ORDER BY NoteID DESC;  
  
        --END               
    END;  


GO

