   Procedure: [dbo].[Usp_MK_GetLocationSetting]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_MK_GetLocationSetting          
(          
  @Parent_ID bigint        
)          
as          
Begin          
   select id, @Parent_ID as Parent_ID, (select top 1  isnull(User_Login,'') from User_Detail where User_ID = rt1.User_ID) as InchargeName,  
   User_ID,(select top 1  isnull(User_Login,'') from User_Detail where User_ID = rt1.User_ID) as ExecutiveName,      
   '' as TrackStartDate,'' as TrackEndDate From tbl_location_setting(nolock) as rt1            
   where rt1.User_ID  = @Parent_ID      
    order by id desc          
          
end 



