/* ============================================================
   Procedure: [dbo].[usp_mk_GetMatchLeadOrEnquiry]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_mk_GetMatchLeadOrEnquiry](
	@UserId bigint,
	@Mode nvarchar(255),
	@Value nvarchar(255),
	@Offsets int  = 0,
	@PageSize int  = 20
)
as
begin
	--declare 
	--	@UserId bigint = 34594,
	--	@Mode nvarchar(255) = 'mobile',
	--	@Value nvarchar(255) = '9821592374'

	declare @ParentId bigint = 0;

	select @ParentId = ParentID from User_Detail(nolock) where User_ID = @UserId

	select count(*) over() as [TotalRow], * from (
		select ID as EntityId, 'Lead' as [EntityName], LeadNo, PersonName, CountryCode, CountryCode1, CountryCode2, MobileNo, MobileNo1, MobileNo2, EmailID, EmailID1, EmailID2
			from UserLeads(nolock) where ParentID = @ParentId and 1 = ( case
				when @Mode = 'mobile' and @Value in (MobileNo, MobileNo1, MobileNo2) then 1
				when @Mode = 'email' and @Value in (EmailID, EmailID1, EmailID2) then 1
				else 0 end )
		union all
		select EnquiryID as EntityId, 'Enquiry' as [EntityName], LeadNo, PersonName, CountryCode, CountryCode1, CountryCode2, MobileNo, MobileNo1, MobileNo2, EmailID, EmailID1, EmailID2
			from UserEnquiry (nolock) where ParentID = @ParentId and 1 = ( case
				when @Mode = 'mobile' and @Value in (MobileNo, MobileNo1, MobileNo2) then 1
				when @Mode = 'email' and @Value in (EmailID, EmailID1, EmailID2) then 1
				else 0 end )
	) t order  by t.EntityName desc, t.EntityId asc
	offset @Offsets rows fetch next @PageSize rows only
end



GO

/* ============================================================
   Procedure: [dbo].[usp_mk_GetMobileNoListForConference]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--exec usp_mk_GetMobileNoListForConference 32222, 32222, 'mukesh'

CREATE   PROCEDURE usp_mk_GetMobileNoListForConference 
                @ParentId BIGINT , 
                @UserId   BIGINT , 
                @Filter   VARCHAR(20)
AS
    BEGIN
        SELECT *
        FROM ( SELECT User_Id AS Id , ( FName + ' ' + LName ) AS Name , CONVERT(VARCHAR(20) , CAST(Mobile AS BIGINT)) AS MobileNo , '' AS MobileNo1 , '' AS MobileNo2, 'U' AS TYPE
               FROM User_Detail
               WHERE ParentID = @ParentId
               UNION
               SELECT EnquiryId , PersonName , MobileNo , MobileNo1 , MobileNo2, 'E' AS TYPE
               FROM UserEnquiry
               WHERE ParentID = @ParentId
               UNION
               SELECT ID , PersonName , MobileNo , MobileNo1 , MobileNo2, 'L' AS TYPE
               FROM UserLeads
               WHERE ParentID = @ParentId
             ) AS M

			 WHERE M.Name <> '' AND M.Name LIKE @Filter+'%' 


    END;


GO

/* ============================================================
   Procedure: [dbo].[Usp_MK_GetParticularUserLocation]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_MK_GetParticularUserLocation --32222      
(@UserID BIGINT
)
AS
    BEGIN            
        --declare @UserID bigint = 36950            

        SELECT TOP 25 rt1.ID, 
                      rt1.UserID, 
        (
            SELECT TOP 1 IIF(LTRIM(RTRIM(CONCAT(FName, ' ', LName))) = '', User_Login, LTRIM(RTRIM(CONCAT(FName, ' ', LName))))
            FROM User_Detail(nolock)
            WHERE User_ID = rt1.UserID
        ) AS ExecutiveName, 
                      rt1.Latitude, 
                      rt1.Longitude, 
                      rt1.MeaningfulAddress, 
                      rt1.CreatedDate, 
                      CONVERT(VARCHAR(10), CAST(ud.Mobile AS DECIMAL(10, 0))) Mobile, 
                      ud.Image, 
                      ud.FName + ' ' + ISNULL(ud.LName, '') AS Territory
        INTO #TEMP
        FROM RealTimeLocation(NOLOCK) AS rt1
             LEFT OUTER JOIN User_Detail ud(NOLOCK) ON rt1.UserID = ud.User_ID
        WHERE rt1.UserID = @UserID
              AND ISNULL(rt1.MeaningfulAddress, '') != ''
              AND rt1.MeaningfulAddress != 'Object reference not set to an instance of an object.'
        ORDER BY rt1.CreatedDate DESC;
        UPDATE a
          SET 
              a.Territory = ISNULL(c.Name, '')
        FROM #TEMP a
             LEFT OUTER JOIN tbl_location_territory_mapping b ON a.UserID = b.User_ID
             LEFT OUTER JOIN tbl_location_territory c(NOLOCK) ON b.Territory_ID = c.ID;
        SELECT *
        FROM #TEMP;
        DROP TABLE #TEMP;
    END;


GO

/* ============================================================
   Procedure: [dbo].[Usp_MK_GetParticularUserLocation11]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE dbo.Usp_MK_GetParticularUserLocation11            
(            
  @UserID bigint,      
  @fromdate varchar(30)='',      
  @todate varchar(30)=''           
)            
as            
Begin            
   --declare @UserID bigint = 3149            
            
      select top 25 rt1.ID, rt1.UserID,(select top 1  isnull(ud.FName+' '+ISNULL(ud.LName,''),User_Login)  from User_Detail where User_ID = rt1.UserID) as ExecutiveName, rt1.Latitude,rt1.Longitude,rt1.MeaningfulAddress,rt1.CreatedDate, CONVERT(varchar(10), Cast(ud.Mobile as decimal(10, 0))) Mobile, ud.Image,  
ud.FName+' '+ISNULL(ud.LName,'') AS Territory INTO #TEMP     
   From RealTimeLocation(nolock) as rt1  left outer join User_Detail ud (nolock)     
     on rt1.UserID= ud.User_ID                
   where rt1.UserID  = @UserID  and CONVERT(DATETIME, CONVERT(VARCHAR(30), CreatedDate, 106)) between isnull(@fromdate,CreatedDate) and isnull(@todate,getdate())         
   and isnull(rt1.MeaningfulAddress,'') !='' and rt1.MeaningfulAddress != 'Object reference not set to an instance of an object.'          
    order by rt1.CreatedDate desc       
   
  update a  
 set a.Territory = isnull(c.Name,'')  
 from #TEMP a left outer join tbl_location_territory_mapping b on a.UserID = b.User_ID  
 left outer join tbl_location_territory c(nolock) on b.Territory_ID = c.ID  
  
 select * from #TEMP  
 drop table #TEMP     
            
end 



GO

/* ============================================================
   Procedure: [dbo].[usp_mk_GetPhyAppointCommment]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_mk_GetPhyAppointCommment](
	@Id bigint
)
as
begin
	select comment.PhyAppointCommentId, comment.remarks, comment.CreatedDate , comment.PhysicalAppointmentId,
	( select FileName, ParentId from TBL_ET_PhyAppointCommentAttachment(nolock ) 
			where PhyAppointCommentId = comment.PhyAppointCommentId for json path ) as attachments, 
	agent.User_ID as agentId, agent.FName, agent.LName, agent.User_Login as Username, agent.Image
		from TBL_ET_PhyAppointComment(nolock) comment
	left join User_Detail(nolock) agent on comment.CreatedBy = agent.User_ID
	where comment.PhysicalAppointmentId = @Id order by comment.PhysicalAppointmentId desc
end



GO

/* ============================================================
   Procedure: [dbo].[usp_mk_GetPhysicalAppointmentFormDetail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_mk_GetPhysicalAppointmentFormDetail]
(
    @PhysicalAppointmentId BIGINT,
    @FormType              VARCHAR(20)  -- 'CheckIn' or 'CheckOut'
)
AS
BEGIN
    SET NOCOUNT ON;

    BEGIN TRY
        -- 1?? Validate ID
        IF NOT EXISTS (
            SELECT 1 
            FROM TBL_ET_PhysicalAppointment WITH (NOLOCK)
            WHERE PhysicalAppointmentId = @PhysicalAppointmentId
        )
        BEGIN
            SELECT Success = 0, Message = 'Invalid PhysicalAppointmentId';
            RETURN;
        END

        -- 2?? Validate form type
        IF (@FormType NOT IN ('CheckIn', 'CheckOut'))
        BEGIN
            SELECT Success = 0, Message = 'Invalid FormType. Must be CheckIn or CheckOut.';
            RETURN;
        END

        -- 3?? CheckIn form details
        IF (@FormType = 'CheckIn')
        BEGIN
            SELECT 
                Success = 1,
                Message = 'CheckIn form detail fetched successfully',
                PhysicalAppointmentId,
                FormType = 'CheckIn',
                JsonDetail = CheckIn_Form_Detail,
                IsFormFilled = IsCheckInFormFilled,
                FormId = TRY_CAST(JSON_VALUE(CheckIn_Form_Detail, '$.formid') AS BIGINT),
                IsDynamicWebForm = TRY_CAST(JSON_VALUE(CheckIn_Form_Detail, '$.is_dynamicwebform') AS BIT),
                EntryId = TRY_CAST(JSON_VALUE(CheckIn_Form_Detail, '$.entryid') AS BIGINT)
            FROM TBL_ET_PhysicalAppointment WITH (NOLOCK)
            WHERE PhysicalAppointmentId = @PhysicalAppointmentId;
        END

        -- 4?? CheckOut form details
        ELSE IF (@FormType = 'CheckOut')
        BEGIN
            SELECT 
                Success = 1,
                Message = 'CheckOut form detail fetched successfully',
                PhysicalAppointmentId,
                FormType = 'CheckOut',
                JsonDetail = CheckOut_Form_Detail,
                IsFormFilled = IsCheckOutFormFilled,
                FormId = TRY_CAST(JSON_VALUE(CheckOut_Form_Detail, '$.formid') AS BIGINT),
                IsDynamicWebForm = TRY_CAST(JSON_VALUE(CheckOut_Form_Detail, '$.is_dynamicwebform') AS BIT),
                EntryId = TRY_CAST(JSON_VALUE(CheckOut_Form_Detail, '$.entryid') AS BIGINT)
            FROM TBL_ET_PhysicalAppointment WITH (NOLOCK)
            WHERE PhysicalAppointmentId = @PhysicalAppointmentId;
        END

    END TRY
    BEGIN CATCH
        SELECT 
            Success = 0,
            Message = CONCAT('Error in usp_mk_GetPhysicalAppointmentFormDetail: ', ERROR_MESSAGE()),
            ErrorLine = ERROR_LINE(),
            ErrorSeverity = ERROR_SEVERITY(),
            ErrorState = ERROR_STATE();
    END CATCH
END




