CREATE   PROCEDURE [dbo].[usp_mk_getProfileDetail] 
    @UserId BIGINT
AS
    BEGIN
      SELECT User_Login, FName, LName, Email, CountryCode, Mobile, [Address], City, [State], Country, PinCode, [Image], 
		case 
 		when [Image] != '' then 
		('https://docs.kit19.com/' + REPLACE(REPLACE([Image], '~', ''), '/User', 'User'))
 		else 
		'https://docs.kit19.com/default/person.png' end ProfilePicturePath, CompnayName, 
