/* ============================================================
   Procedure: [dbo].[usp_mk_GetRecordCount]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- exec usp_mk_GetRecordCount @ParentId=30529,@UserId=0,@Code='Enquiry'
-- exec usp_mk_GetRecordCount @ParentId=30529,@UserId=30653,@Code='Enquiry'
-- exec usp_mk_GetRecordCount @ParentId=335,@UserId=0,@Code='Lead'
-- exec usp_mk_GetRecordCount @ParentId=335,@UserId=29289,@Code='Lead'
CREATE   PROCEDURE [dbo].[usp_mk_GetRecordCount]
(
	@ParentId BIGINT,
	@UserId BIGINT = 0,
	@Code NVARCHAR(50) = ''
)
AS
BEGIN

	IF(@Code = 'Enquiry')
	BEGIN
		Select count(*) as RecCnt From Userenquiry(nolock) Where ParentId=@ParentId and CreatedBy=Case when @UserId=0 then CreatedBy else @UserId end
	END

	IF(@Code = 'Lead')
	BEGIN
		Select count(*) as RecCnt From UserLeads(nolock) Where ParentId=@ParentId and AssignedTo=Case when @UserId=0 then AssignedTo else @UserId end
	END

END



