/* ============================================================
   Procedure: [dbo].[usp_mk_GetRowsCount]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


  
-- exec usp_mk_GetRowsCount @UserId=32222, @RowsTagName='Enquiry', @Filter=default  
-- exec usp_mk_GetRowsCount @UserId=32821, @RowsTagName='Enquiry', @Filter=default  
-- exec usp_mk_GetRowsCount @UserId=33196, @RowsTagName='Enquiry', @Filter=default  
-- exec usp_mk_GetRowsCount @UserId=32222, @RowsTagName='Lead', @Filter=default  
-- exec usp_mk_GetRowsCount @UserId=32821, @RowsTagName='Lead', @Filter=default  
-- exec usp_mk_GetRowsCount @UserId=33196, @RowsTagName='Lead', @Filter=default  
CREATE   PROC usp_mk_GetRowsCount  
(  
 @UserId bigint,  
 @RowsTagName nvarchar(50),  
 @Filter nvarchar(max)=''  
)  
AS  
Begin  
  
 declare @ParentID bigint=0  
 Select @ParentID=ParentID From User_Detail Where User_ID=@UserId  
  
 If(@RowsTagName = 'Enquiry')  
 Begin  
  select  count(*) as RowsCount  
  From  UserEnquiry  
  Where  ParentID=@ParentID and CreatedBy=case when @UserId = @ParentID then CreatedBy else @UserId end    
 End  
  
 If(@RowsTagName = 'Lead')  
 Begin  
  select  count(*) as RowsCount  
  From  UserLeads  
  Where  ParentID=@ParentID and AssignedTo=case when @UserId = @ParentID then AssignedTo else @UserId end    
 End  
  
End  


