/* ============================================================
   Procedure: [dbo].[usp_mk_GetSetTemplateCols]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
-- Exec usp_mk_GetSetTemplateCols 32222,'EN','','get'  
CREATE   PROC usp_mk_GetSetTemplateCols  
(  
 @UserId bigint,  
 @TemplateType varchar(3)='EN', --'EN' Enquiry,'LD' Lead  
 @TemplateCols Nvarchar(max)='',  
 @Mode varchar(3)='Get'  
)  
AS  
BEGIN  
 If(@Mode = 'Get')  
 Begin  
  declare @ColList nvarchar(max)='';  
  
  Select @ColList=ColumnList From tbl_mk_ViewTemplate(nolock) Where User_Id = @UserId and TemplateType=@TemplateType  
  
  select @ColList as ColList  
 End  
  
 If(@Mode = 'Set')  
 Begin  
  IF EXISTS(Select * From tbl_mk_ViewTemplate(nolock) Where User_Id = @Userid and TemplateType=@TemplateType)  
  BEGIN  
   Update tbl_mk_ViewTemplate set ColumnList=@TemplateCols,ModifiedDate=GETDATE()  Where User_Id = @UserId and TemplateType=@TemplateType  
  END  
  ELSE  
  BEGIN  
   insert into [tbl_mk_ViewTemplate] values(@TemplateCols,@UserId,@TemplateType,GETDATE(),null)  
  END  
  
  select @@ROWCOUNT as ColList  
 End  
  
END  


GO

/* ============================================================
   Procedure: [dbo].[usp_mk_GetSetUserDuty]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

    
    
-- exec usp_mk_GetSetUserDuty 32222,'get'        
-- exec usp_mk_GetSetUserDuty 32222,'set',0        
CREATE   PROC usp_mk_GetSetUserDuty        
(        
    @User_Id bigint,        
    @Mode varchar(3)='set',        
    @Duty int=0        
)        
As        
Begin        
        
-- declare @User_Id bigint=335, @Mode varchar(3)='set', @Duty int=0        
        
    If(@Mode = 'get')        
    Begin        
    select onduty as Duty from User_Detail(nolock) where User_ID=@User_Id           
    End        
            
    If(@Mode = 'set')        
    Begin        
  update User_Detail     
  set onduty=@Duty, Presence=case when @Duty=1 then Presence else 0 end, OnField=case when @Duty=1 then OnField else 0 end    
  where User_ID=@User_Id        
      
  Select @@ROWCOUNT as Duty        
      
  exec usp_mk_send_autonotification @User_Id,'Duty'    
  exec usp_mk_setOnDutyHistory @User_Id, @Duty    
    End        
      DECLARE @rowJson NVARCHAR(MAX) = (        
   SELECT *        
   FROM User_Detail WITH(NOLOCK)        
   WHERE User_ID = @User_Id        
   FOR JSON AUTO        
    ,INCLUDE_NULL_VALUES        
   )        
 IF @rowJson IS NOT NULL        
 BEGIN        
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @User_Id        
  ,@Activity_type = 'API_Updt_User_duty'        
  ,@ActionType = 'U'        
  ,@RowJson = @rowJson        
  ,@Table_name = 'User_Detail'        
 END        
End 


GO

