SET QUOTED_IDENTIFIER ON


-- exec usp_mk_GetSetUserField 32222,'get'      
-- exec usp_mk_GetSetUserField 32222,'set',0      

CREATE   PROC usp_mk_GetSetUserField
(
	@User_Id BIGINT, 
	@Mode    VARCHAR(3) = 'set', 
	@Field   INT        = 0
)
AS
BEGIN
    -- declare @User_Id bigint=335, @Mode varchar(3)='set', @Duty int=0   
    IF @Mode = 'get'
        BEGIN
            SELECT OnField AS Field FROM User_Detail(NOLOCK) WHERE User_ID = @User_Id;
		END;
    IF @Mode = 'set'
        BEGIN
            UPDATE User_Detail SET  OnField = @Field WHERE User_ID = @User_Id;
            SELECT OnField AS Field FROM User_Detail(NOLOCK) WHERE User_ID = @User_Id;
            EXEC usp_mk_send_autonotification  @User_Id,  'Field';
			exec usp_mk_setOnFeildHistory @User_Id, @Field;
		END;
END;


