/* ============================================================
   Procedure: [dbo].[usp_mk_GetTaskAppointmentForDashboard]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_mk_GetTaskAppointmentForDashboard](
	@UserId bigint,
	@ActivityDate date,
	@Mode char(1)
)
as
begin
	
	-- declare @UserId bigint = 32222, @ActivityDate date = '10 June 2023', @Mode char(1) = 'A'	
	-- declare @UserId bigint = 32222, @ActivityDate date = '16 October 2024', @Mode char(1) = 'A'
	
	declare 
		@StartDate date = cast(@ActivityDate as date), 
		@EndDate date = cast(@ActivityDate as date)

	----select * from fn_getStartfromUserTime(40457, '2022-12-03')
		
	select @StartDate = StartDateTime, @EndDate = EndDateTime from fn_getIndiaStartEndTimefromUserTime(@UserId, @ActivityDate)

	select * from (
		select rectype, tsk.id, tsk.Title, tsk.StartDate, tsk.EndDate, 
			tsk.LeadId, ul.PersonName, 
			isnull(ul.ProfileImgFileName, '') as PersonImage, 
			isnull(o.OutcomeName, '') as Outcome,
			isnull(o.Indent, '') as Intent,
			tsk.AgentId, ud.Image as AgentImage,
			trim(concat(trim(cast(ud.FName as nvarchar)), ' ', trim(cast(ud.LName as nvarchar)))) as AgentName, 
			(case 
				when LOWER(tsk.Status) = 'completed' then 'Completed' else ( case 
					when CAST(iif(tsk.IsTask = 1, tsk.EndDate, tsk.StartDate) as date) > CAST(GETDATE() as date) then 'Scheduled' 
					when CAST(iif(tsk.IsTask = 1, tsk.EndDate, tsk.StartDate) as date) < CAST(GETDATE() as date) then 'Over Due' 
					else 'Due Today' end
				) end
			) as TaskStatus,
			ud.ParentID as ParentId,
			IsEditable,
			IsRemoval, IsTask, TaskTypeId
		from ( 

			select 'virtualapt' rectype, th.id, th.Title, th.StartDate, th.EndDate, th.Status, th.CreatedBy as AgentId, th.LeadId, th.OutcomesId, th.IsTask, 
					iif(@UserId in (th.CreatedBy, th.AssignedTo), 1, 0) as IsEditable, 0 as IsRemoval, th.TaskId as [TaskTypeId]
				from tbl_tsk_TaskHistory(nolock) th where th.IsActive = 1 
				and 1 = ( case when @Mode = 'T' and th.IsTask = 1 then 1 when @Mode = 'A' and th.IsAppointment = 1 then 1 when @Mode = 'C' and th.TaskId = 4 then 1 else 0 end ) 
				and th.CreatedBy = @UserId and cast(th.EndDate as date) between @StartDate and @EndDate
		union 
			select 'virtualapt' rectype, th.id, Title, StartDate, EndDate, th.Status, th.AssignedTo as AgentId, th.LeadId, th.OutcomesId, th.IsTask,
					iif(@UserId in (th.CreatedBy, th.AssignedTo), 1, 0) as IsEditable, 0 as IsRemoval, th.TaskId as [TaskTypeId]
				from tbl_tsk_TaskHistory(nolock) th where th.IsActive = 1 
				and 1 = ( case when @Mode = 'T' and th.IsTask = 1 then 1 when @Mode = 'A' and th.IsAppointment = 1 then 1 when @Mode = 'C' and th.TaskId = 4 then 1 else 0 end ) 
				and th.AssignedTo = @UserId and cast(th.EndDate as date) between @StartDate and @EndDate
		union 
			select 'virtualapt' rectype, th.id, Title, StartDate, EndDate, th.Status, tcm.User_ID as AgentId, th.LeadId , th.OutcomesId, th.IsTask,
					iif(@UserId in (th.CreatedBy, th.AssignedTo), 1, 0) as IsEditable, 0 as IsRemoval, th.TaskId as [TaskTypeId]
				from tbl_tsk_TaskHistory(nolock) th inner join tbl_tsk_CollaborationUserMapping(NOLOCK)
				tcm on th.Id = tcm.TaskHistoryId where th.IsActive = 1 
				and 1 = ( case when @Mode = 'T' and th.IsTask = 1 then 1 when @Mode = 'A' and th.IsAppointment = 1 then 1 when @Mode = 'C' and th.TaskId = 4 then 1 else 0 end ) 
				and tcm.User_Id = @UserId and th.CreatedBy = @UserId and cast(th.EndDate as date) between @StartDate and @EndDate		
				
	) tsk inner join UserLeads(nolock) ul on tsk.LeadId = ul.ID 
		inner join User_Detail(nolock) ud on tsk.AgentId = ud.User_ID
		left join tbl_tsk_UserOutcomeMaster(nolock) o on tsk.OutcomesId  = o.Id
	Union
	select 'physicalapt' rectype, p.PhysicalAppointmentId Id, p.Title, p.StartDate, p.EndDate, gemr.EntityId LeadId, '' PersonName, '' PersonImage, isnull(o.OutcomeName, '') as Outcome, isnull(o.Indent, '') as Intent, p.AgentId, ud.Image as AgentImage, trim(concat(trim(cast(ud.FName as nvarchar)), ' ', trim(cast(ud.LName as nvarchar)))) as AgentName, p.Status TaskStatus,  ud.ParentID as ParentId, iif(@UserId in (p.CreatedBy, p.AssignedTo), 1, 0) as IsEditable, 0 as IsRemoval, 0 IsTask, p.TaskTypeId
	from vw_PhysicalAppoitment(nolock) p
		left join TBL_ET_GeoEntitySiteMaster gesm (nolock) on p.GeoEntitySiteId = gesm.GeoEntitySiteId
		left join TBL_ET_GeoEntityMaster gemr (nolock) on gesm.GeoEntityId = gemr.GeoEntityId 
		inner join User_Detail(nolock) ud on p.AgentId = ud.User_ID
		left join tbl_tsk_UserOutcomeMaster(nolock) o on p.OutcomesId  = o.Id
		where 1 = (case when @Mode = 'A' then 1 else 0 end)
		and p.AgentId = @UserId and cast(p.EndDate as date) between @StartDate and @EndDate		
	) t 
	where t.IsTask in (case when @Mode = 'A' then 0 else 1 end)
	order by StartDate asc
	
	--TBL_ET_PhyAppointCollaboratorUserMapping -- collaborator
	--TBL_ET_PhyAppointUserMapping -- feildExecutive

	/*
	select tsk.id, tsk.Title, tsk.StartDate, tsk.EndDate, 
			tsk.LeadId, ul.PersonName, 
			ul.ProfileImgFileName as PersonImage, 
			o.OutcomeName as Outcome,
			o.Indent as Intent,
			tsk.AgentId, ud.Image as AgentImage,
			trim(concat(trim(cast(ud.FName as nvarchar)), ' ', trim(cast(ud.LName as nvarchar)))) as AgentName, 
			(case 
				when LOWER(tsk.Status) = 'completed' then 'Completed' else ( case 
					when CAST(iif(tsk.IsTask = 1, tsk.EndDate, tsk.StartDate) as date) > CAST(GETDATE() as date) then 'Scheduled' 
					when CAST(iif(tsk.IsTask = 1, tsk.EndDate, tsk.StartDate) as date) < CAST(GETDATE() as date) then 'Over Due' 
					else 'Due Today' end
				) end
			) as TaskStatus,
			ud.ParentID as ParentId,
			IsEditable,
			IsRemoval

		from ( 
			select th.id, th.Title, th.StartDate, th.EndDate, th.Status, th.CreatedBy as AgentId, th.LeadId, th.OutcomesId, th.IsTask, 
					iif(@UserId in (th.CreatedBy, th.AssignedTo), 1, 0) as IsEditable, 0 as IsRemoval
				from tbl_tsk_TaskHistory(nolock) th where th.IsActive = 1 
				and 1 = ( case when @Mode = 'T' and th.IsTask = 1 then 1 when @Mode = 'A' and th.IsAppointment = 1 then 1 when @Mode = 'C' and th.TaskId = 4 then 1 else 0 end ) 
				and th.CreatedBy = @UserId 
				and th.StartDate between @StartDate and @EndDate
				--and @ActivityDate between th.StartDate and th.EndDate
		union 
			select th.id, Title, StartDate, EndDate, th.Status, th.AssignedTo as AgentId, th.LeadId, th.OutcomesId, th.IsTask,
					iif(@UserId in (th.CreatedBy, th.AssignedTo), 1, 0) as IsEditable, 0 as IsRemoval
				from tbl_tsk_TaskHistory(nolock) th where th.IsActive = 1 
				and 1 = ( case when @Mode = 'T' and th.IsTask = 1 then 1 when @Mode = 'A' and th.IsAppointment = 1 then 1 when @Mode = 'C' and th.TaskId = 4 then 1 else 0 end ) 
				and th.AssignedTo = @UserId 
				and th.StartDate between @StartDate and @EndDate
				--and @ActivityDate between th.StartDate and th.EndDate
		union 
			select th.id, Title, StartDate, EndDate, th.Status, tcm.User_ID as AgentId, th.LeadId , th.OutcomesId, th.IsTask,
					iif(@UserId in (th.CreatedBy, th.AssignedTo), 1, 0) as IsEditable, 0 as IsRemoval
				from tbl_tsk_TaskHistory(nolock) th inner join tbl_tsk_CollaborationUserMapping(NOLOCK)
				tcm on th.Id = tcm.TaskHistoryId where th.IsActive = 1 
				and 1 = ( case when @Mode = 'T' and th.IsTask = 1 then 1 when @Mode = 'A' and th.IsAppointment = 1 then 1 when @Mode = 'C' and th.TaskId = 4 then 1 else 0 end ) 
				and tcm.User_Id = @UserId and th.CreatedBy = @UserId 
				and th.StartDate between @StartDate and @EndDate
				--and @ActivityDate between th.StartDate and th.EndDate		
	) tsk inner join UserLeads(nolock) ul on tsk.LeadId = ul.ID 
		inner join User_Detail(nolock) ud on tsk.AgentId = ud.User_ID
		left join tbl_tsk_UserOutcomeMaster(nolock) o on tsk.OutcomesId  = o.Id

		order by id asc

		*/

end



GO

