/* ============================================================
   Procedure: [dbo].[usp_mk_GetTaskAppointmentForDashboardNew]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_mk_GetTaskAppointmentForDashboardNew](
	@UserId bigint,
	@ActivityDate date,
	@FilterText varchar(20),
	@Start int,
	@Limit int,
	@Mode char(1)
)
as
begin

	 -- declare @UserId bigint = 32222, @ActivityDate date = '2022-03-13 23:59:59.999', @Mode char(1) = 'A'
	declare 
		@StartDate datetime = cast(@ActivityDate as datetime), 
		@EndDate datetime = dateadd(hh, 24, cast(@ActivityDate as datetime))

		select * from (
	select  rectype, tsk.id, tsk.Title, tsk.StartDate, tsk.EndDate, 
			tsk.LeadId, ul.PersonName, 
			isnull(ul.ProfileImgFileName, '') as PersonImage, 
			isnull(o.OutcomeName, '') as Outcome,
			isnull(o.Indent, '') as Intent,
			tsk.AgentId, ud.Image as AgentImage,
			trim(concat(trim(cast(ud.FName as nvarchar)), ' ', trim(cast(ud.LName as nvarchar)))) as AgentName, 
			(case 
				when LOWER(tsk.Status) = 'completed' then 'Completed' else ( case 
					when CAST(iif(tsk.IsTask = 1, tsk.EndDate, tsk.StartDate) as date) > CAST(GETDATE() as date) then 'Scheduled' 
					when CAST(iif(tsk.IsTask = 1, tsk.EndDate, tsk.StartDate) as date) < CAST(GETDATE() as date) then 'Over Due' 
					else 'Due Today' end
				) end
			) as TaskStatus,
			ud.ParentID as ParentId,
			IsEditable,
			IsRemoval, IsTask
		from ( 

			select 'virtualapt' rectype, th.id, th.Title, th.StartDate, th.EndDate, th.Status, th.CreatedBy as AgentId, th.LeadId, th.OutcomesId, th.IsTask, 
					iif(@UserId in (th.CreatedBy, th.AssignedTo), 1, 0) as IsEditable, 0 as IsRemoval
				from tbl_tsk_TaskHistory(nolock) th where th.IsActive = 1 
				and 1 = ( case when @Mode = 'T' and th.IsTask = 1 then 1 when @Mode = 'A' and th.IsAppointment = 1 then 1 when @Mode = 'C' and th.TaskId = 4 then 1 else 0 end ) 
				and th.CreatedBy = @UserId and th.EndDate between @StartDate and @EndDate
		union 
			select 'virtualapt' rectype, th.id, Title, StartDate, EndDate, th.Status, th.AssignedTo as AgentId, th.LeadId, th.OutcomesId, th.IsTask,
					iif(@UserId in (th.CreatedBy, th.AssignedTo), 1, 0) as IsEditable, 0 as IsRemoval
				from tbl_tsk_TaskHistory(nolock) th where th.IsActive = 1 
				and 1 = ( case when @Mode = 'T' and th.IsTask = 1 then 1 when @Mode = 'A' and th.IsAppointment = 1 then 1 when @Mode = 'C' and th.TaskId = 4 then 1 else 0 end ) 
				and th.AssignedTo = @UserId and th.EndDate between @StartDate and @EndDate
		union 
			select 'virtualapt' rectype, th.id, Title, StartDate, EndDate, th.Status, tcm.User_ID as AgentId, th.LeadId , th.OutcomesId, th.IsTask,
					iif(@UserId in (th.CreatedBy, th.AssignedTo), 1, 0) as IsEditable, 0 as IsRemoval
				from tbl_tsk_TaskHistory(nolock) th inner join tbl_tsk_CollaborationUserMapping(NOLOCK)
				tcm on th.Id = tcm.TaskHistoryId where th.IsActive = 1 
				and 1 = ( case when @Mode = 'T' and th.IsTask = 1 then 1 when @Mode = 'A' and th.IsAppointment = 1 then 1 when @Mode = 'C' and th.TaskId = 4 then 1 else 0 end ) 
				and tcm.User_Id = @UserId and th.CreatedBy = @UserId and th.EndDate between @StartDate and @EndDate		
				
	) tsk inner join UserLeads(nolock) ul on tsk.LeadId = ul.ID 
		inner join User_Detail(nolock) ud on tsk.AgentId = ud.User_ID
		left join tbl_tsk_UserOutcomeMaster(nolock) o on tsk.OutcomesId  = o.Id
	Union
	select 'physicalapt' rectype, PhysicalAppointmentId Id, Title, StartDate, EndDate, 
	EntityId LeadId,'' PersonName, 
			--, GeoEntityType, '' ProfileImgFileName as
			'' PersonImage, 
			isnull(o.OutcomeName, '') as Outcome,
			isnull(o.Indent, '') as Intent,
			phap.CreatedBy AgentId,
			ud.Image as AgentImage,
			trim(concat(trim(cast(ud.FName as nvarchar)), ' ', trim(cast(ud.LName as nvarchar)))) as AgentName, 
			--(case 
			--	when LOWER(phap.Status) = 'completed' then 'Completed' else ( case 
			--		when CAST(iif(tsk.IsTask = 1, tsk.EndDate, tsk.StartDate) as date) > CAST(GETDATE() as date) then 'Scheduled' 
			--		when CAST(iif(tsk.IsTask = 1, tsk.EndDate, tsk.StartDate) as date) < CAST(GETDATE() as date) then 'Over Due' 
			--		else 'Due Today' end
			--	) end
			--) as TaskStatus,
			 phap.Status TaskStatus,  ud.ParentID as ParentId,
	iif(@UserId in (phap.CreatedBy, phap.AssignedTo), 1, 0) as IsEditable, 0 as IsRemoval, 0 IsTask
	from TBL_ET_PhysicalAppointment phap (nolock)
	left join TBL_ET_GeoEntitySiteMaster gesm (nolock) on phap.GeoEntitySiteId = gesm.GeoEntitySiteId
	left join TBL_ET_GeoEntityMaster gemr (nolock) on gesm.GeoEntityId = gemr.GeoEntityId 
	inner join User_Detail(nolock) ud on phap.CreatedBy = ud.User_ID
	left join tbl_tsk_UserOutcomeMaster(nolock) o on phap.OutcomesId  = o.Id
	where phap.CreatedBy = @UserId and phap.EndDate between @StartDate and @EndDate			
	) t 
	where t.IsTask in (case when @Mode = 'A' then 0 else 1 end)
	order by StartDate asc
	offset @Start rows fetch next @Limit rows only

	--select tsk.id, tsk.Title, tsk.StartDate, tsk.EndDate, 
	--		tsk.LeadId, ul.PersonName, 
	--		ul.ProfileImgFileName as PersonImage, 
	--		o.OutcomeName as Outcome,
	--		o.Indent as Intent,
	--		tsk.AgentId, ud.Image as AgentImage,
	--		trim(concat(trim(cast(ud.FName as nvarchar)), ' ', trim(cast(ud.LName as nvarchar)))) as AgentName, 
	--		(case 
	--			when LOWER(tsk.Status) = 'completed' then 'Completed' else ( case 
	--				when CAST(iif(tsk.IsTask = 1, tsk.EndDate, tsk.StartDate) as date) > CAST(GETDATE() as date) then 'Scheduled' 
	--				when CAST(iif(tsk.IsTask = 1, tsk.EndDate, tsk.StartDate) as date) < CAST(GETDATE() as date) then 'Over Due' 
	--				else 'Due Today' end
	--			) end
	--		) as TaskStatus,
	--		ud.ParentID as ParentId,
	--		IsEditable,
	--		IsRemoval

	--	from ( 
	--		select th.id, th.Title, th.StartDate, th.EndDate, th.Status, th.CreatedBy as AgentId, th.LeadId, th.OutcomesId, th.IsTask, 
	--				iif(@UserId in (th.CreatedBy, th.AssignedTo), 1, 0) as IsEditable, 0 as IsRemoval
	--			from tbl_tsk_TaskHistory(nolock) th where th.IsActive = 1 
	--			and 1 = ( case when @Mode = 'T' and th.IsTask = 1 then 1 when @Mode = 'A' and th.IsAppointment = 1 then 1 when @Mode = 'C' and th.TaskId = 4 then 1 else 0 end ) 
	--			and th.CreatedBy = @UserId and th.EndDate between @StartDate and @EndDate
	--	union 
	--		select th.id, Title, StartDate, EndDate, th.Status, th.AssignedTo as AgentId, th.LeadId, th.OutcomesId, th.IsTask,
	--				iif(@UserId in (th.CreatedBy, th.AssignedTo), 1, 0) as IsEditable, 0 as IsRemoval
	--			from tbl_tsk_TaskHistory(nolock) th where th.IsActive = 1 
	--			and 1 = ( case when @Mode = 'T' and th.IsTask = 1 then 1 when @Mode = 'A' and th.IsAppointment = 1 then 1 when @Mode = 'C' and th.TaskId = 4 then 1 else 0 end ) 
	--			and th.AssignedTo = @UserId and th.EndDate between @StartDate and @EndDate
	--	union 
	--		select th.id, Title, StartDate, EndDate, th.Status, tcm.User_ID as AgentId, th.LeadId , th.OutcomesId, th.IsTask,
	--				iif(@UserId in (th.CreatedBy, th.AssignedTo), 1, 0) as IsEditable, 0 as IsRemoval
	--			from tbl_tsk_TaskHistory(nolock) th inner join tbl_tsk_CollaborationUserMapping(NOLOCK)
	--			tcm on th.Id = tcm.TaskHistoryId where th.IsActive = 1 
	--			and 1 = ( case when @Mode = 'T' and th.IsTask = 1 then 1 when @Mode = 'A' and th.IsAppointment = 1 then 1 when @Mode = 'C' and th.TaskId = 4 then 1 else 0 end ) 
	--			and tcm.User_Id = @UserId and th.CreatedBy = @UserId and th.EndDate between @StartDate and @EndDate			
	--) tsk inner join UserLeads(nolock) ul on tsk.LeadId = ul.ID 
	--	inner join User_Detail(nolock) ud on tsk.AgentId = ud.User_ID
	--	left join tbl_tsk_UserOutcomeMaster(nolock) o on tsk.OutcomesId  = o.Id
	--	order by id asc
	--offset @Start rows fetch next @Limit rows only

end



GO

/* ============================================================
   Procedure: [dbo].[usp_mk_GetTaskCommment]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE usp_mk_GetTaskCommment(
	@Id bigint
)
as
begin
	select comment.id, comment.remarks, comment.created_on, comment.task_history_id,
	( select FileName, ParentId from tbl_tsk_CommentAttachments(nolock ) 
			where CommentId = comment.id for json path ) as attachments, 
	agent.User_ID as agentId, agent.FName, agent.LName, agent.User_Login as Username, agent.Image
		from tbl_tsk_TaskComments(nolock) comment
	left join User_Detail(nolock) agent on comment.created_by = agent.User_ID
	where comment.task_history_id = @Id order by comment.id desc
end



GO

/* ============================================================
   Procedure: [dbo].[usp_mk_GetTaskPermissionSetting]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_mk_GetTaskPermissionSetting](
	@TaskId bigint,
	@UserId bigint
)
as
begin
	-- declare@TaskId bigint @TaskId bigint = 152

	declare @PareintId bigint = (select ParentID from User_Detail(nolock) where User_ID = @UserId)

	declare @taskType varchar(20) = '', @hasView bit = 1, @hasEdit bit = 0, @hasRemove bit = 0, @hasCompletion bit = 0, @hasComment bit = 1, @hasFieldView bit = 1, @hasFieldEdit bit = 0, @hasFieldRemove bit = 0, @hasFieldCompletion bit = 0, @hasFieldComment bit = 1,
	@HasviewLead bit =0, @HaseditLead bit =0, @HasfieldviewLead bit=0, @HasfieldeditLead bit =0,
	@GeoRestrictionCheckIn varchar(20) = '', @GeoRestrictionCheckOut varchar(20) = '', @AuthTypeCheckIn varchar(20) = '',
@AuthTypeCheckOut varchar(20) = '', @CheckInRange int = 0, @CheckOutRange int =0, @CheckInFormId bigint = 0, @CheckOutFormId bigint = 0, 
@DisallowCheckInForm bit = 0, @DisallowCheckOutForm bit = 0, @CheckInDisallowMsg nvarchar(1000) = '', @CheckOutDisallowMsg nvarchar(1000) = '', @AssignmentType varchar(10) = '', @AutoAssignTerritoryType varchar(20) = '', @AssignAllocationType varchar(10) = '', @AssignMeetingDays int = 0, @AssignMeetingType varchar(10) = '', @DefineSuccessMeeting varchar(10) = '', @IsCheckInTime bit = 0, @SuccessMeetingCheckInMin int = 0, @IsSuccessMeetingOutcome bit = 0, @IsSuccessMeetingCondForm bit = 0, @CheckInBeforeDistance int = 0, @IsAllowCallBeforeCheckIn bit = 0, @CheckInClientName varchar(150) = '', @CheckInMeetingDetails varchar(150) = '', @CheckInFieldMasked varchar(20) = '', @CheckOutAfterDistance int = 0, @IsAllowCallAfterCheckOut bit = 0, @CheckOutClientName varchar(150) = '', @CheckOutMeetingDetails varchar(150) = '', @CheckOutFieldMasked varchar(20) = '', @AllowedCheckInOutOverride bit = 0, @AttendanceApproverType varchar(20) = '', @CheckInOutApproverId bigint = 0, @MarkOutcomeCheckOut bit = 0, @AddReimbursementOf int = 0, @DeductReimbursementOf int = 0, @CheckInOutApproverIds varchar(1000) = '', @ExpenseHeadIds varchar(1000) = '', @CheckInOutApproverNames varchar(1000) = '', @ExpenseHeadNames varchar(1000) = '', 
@CheckInEmailIdSetting nvarchar(max) = '{}', @CheckInSMSSetting nvarchar(max) = '{}', @CheckInWhatsappSetting nvarchar(max) = '{}', @CheckOutEmailIdSetting nvarchar(max) = '{}', @CheckOutSMSSetting nvarchar(max) = '{}', @CheckOutWhatsappSetting nvarchar(max) = '{}'


	select 
		@taskType = isnull(ttu.TaskType, ''),
		@hasView = tap.has_view,
		@hasEdit = tap.has_edit,
		@hasRemove = tap.has_remove,
		@hasCompletion = tap.has_completion,
		@hasComment = tap.has_comment,
		@hasFieldView = tap.has_fieldview,
		@hasFieldEdit = tap.has_fieldedit,
		@hasFieldRemove = tap.has_fieldremove,
		@hasFieldCompletion = tap.has_fieldcompletion,
		@hasFieldComment = tap.has_fieldcomment,
		@HasviewLead = tap.Has_viewLead,
		@HaseditLead=tap.Has_editLead,
		@HasfieldviewLead=tap.Has_fieldviewLead,
		@HasfieldeditLead=tap.Has_fieldeditLead,
		@GeoRestrictionCheckIn = tap.GeoRestrictionCheckIn,
		@GeoRestrictionCheckOut = tap.GeoRestrictionCheckOut,
		@AuthTypeCheckIn = tap.AuthTypeCheckIn,
		@AuthTypeCheckOut = tap.AuthTypeCheckOut,
		@CheckInRange = tap.CheckInRange,
		@CheckOutRange = tap.CheckOutRange,
		@CheckInFormId = tap.CheckInFormId,
		@CheckOutFormId = tap.CheckOutFormId,
		@DisallowCheckInForm = tap.DisallowCheckInForm,
		@DisallowCheckOutForm = tap.DisallowCheckOutForm,
		@CheckInDisallowMsg = tap.CheckInDisallowMsg,
		@CheckOutDisallowMsg = tap.CheckOutDisallowMsg,
		@AssignmentType = tap.AssignmentType,
		@AutoAssignTerritoryType = tap.AutoAssignTerritoryType,
		@AssignAllocationType = tap.AssignAllocationType,
		@AssignMeetingDays = tap.AssignMeetingDays,
		@AssignMeetingType = tap.AssignMeetingType,
		@DefineSuccessMeeting = tap.DefineSuccessMeeting,
		@IsCheckInTime = tap.IsCheckInTime, 
		@SuccessMeetingCheckInMin = tap.SuccessMeetingCheckInMin,
		@IsSuccessMeetingOutcome = tap.IsSuccessMeetingOutcome,
		@IsSuccessMeetingCondForm = tap.IsSuccessMeetingCondForm, 
		@CheckInBeforeDistance = tap.CheckInBeforeDistance,
		@IsAllowCallBeforeCheckIn = tap.IsAllowCallBeforeCheckIn, 
		@CheckInClientName = tap.CheckInClientName,
		@CheckInMeetingDetails = tap.CheckInMeetingDetails,
		@CheckInFieldMasked = tap.CheckInFieldMasked,
		@CheckOutAfterDistance = tap.CheckOutAfterDistance,
		@IsAllowCallAfterCheckOut = tap.IsAllowCallAfterCheckOut,
		@CheckOutClientName = tap.CheckOutClientName,
		@CheckOutMeetingDetails = tap.CheckOutMeetingDetails,
		@CheckOutFieldMasked = tap.CheckOutFieldMasked,
		@AllowedCheckInOutOverride = tap.AllowedCheckInOutOverride,
		@AttendanceApproverType = tap.AttendanceApproverType,
		@CheckInOutApproverId = tap.CheckInOutApproverId,
		@MarkOutcomeCheckOut = tap.MarkOutcomeCheckOut,
		@AddReimbursementOf = tap.AddReimbursementOf,
		@DeductReimbursementOf = tap.DeductReimbursementOf,
		@CheckInOutApproverIds = tap.CheckInOutApproverIds,
		@ExpenseHeadIds = tap.ExpenseHeadIds,
		@MarkOutcomeCheckOut = tap.MarkOutcomeCheckOut,
		@AllowedCheckInOutOverride = tap.AllowedCheckInOutOverride,
		@CheckInOutApproverId = tap.CheckInOutApproverId,
		@CheckInEmailIdSetting = tap.CheckIn_SendMail,
		@CheckInSMSSetting = tap.CheckIn_SendSMS,
		@CheckInWhatsappSetting = tap.CheckIn_SendWhatsApp,
		@CheckOutEmailIdSetting = tap.CheckOut_SendMail,
		@CheckOutSMSSetting = tap.CheckOut_SendSMS,
		@CheckOutWhatsappSetting = tap.CheckOut_SendWhatsApp
	from tbl_tsk_TaskActionPermission(nolock) tap 
	inner join tbl_tsk_UserTaskMaster (nolock) ttu on tap.task_type_id = ttu.Id
	where tap.parent_id =  @PareintId  and tap.task_type_id = @TaskId 

select @CheckInOutApproverNames = COALESCE(@CheckInOutApproverNames+', ' ,'') + Concat(User_Login, ' ('+FName + ' ' + LName +')') from User_Detail(nolock) where User_id in (select item from dbo.fu_SplitString(@CheckInOutApproverIds, '#')) 

select @ExpenseHeadNames = COALESCE(@ExpenseHeadNames+', ','') + ExpenseHeadName from TBL_ET_ExpenseHead(nolock) where ExpenseHeadId in (select item from dbo.fu_SplitString(@ExpenseHeadIds, '#')) 

	select 
		@taskType as taskType,
		isnull(@hasView, 1) as hasView,
		isnull(@hasEdit, 0) as hasEdit,
		isnull(@hasRemove, 0) as hasRemove,
		isnull(@hasCompletion, 0) as hasCompletion,
		isnull(@hasComment, 1) as hasComment,
		isnull(@hasFieldView, 1) as hasFieldView,
		isnull(@hasFieldEdit, 0) as hasFieldEdit,
		isnull(@hasFieldRemove, 0) as hasFieldRemove,
		isnull(@hasFieldCompletion, 0) as hasFieldCompletion,
		isnull(@hasFieldComment, 1) as hasFieldComment,
		ISNULL(@HasviewLead,0) as HasviewLead,
		isnull(@HaseditLead,0) as HaseditLead,
		isnull(@HasfieldviewLead,0) as HasfieldviewLead,
		isnull(@HasfieldeditLead,0) as HasfieldeditLead,
		isnull(@GeoRestrictionCheckIn,0),

		isnull(@GeoRestrictionCheckIn, '') as GeoRestrictionCheckIn,
		isnull(@GeoRestrictionCheckOut, '') as GeoRestrictionCheckOut,
		isnull(@AuthTypeCheckIn, '') as AuthTypeCheckIn,
		isnull(@AuthTypeCheckOut, '') as AuthTypeCheckOut,
		isnull(@CheckInRange, 0) as CheckInRange,
		isnull(@CheckOutRange, 0) as CheckOutRange,
		isnull(@CheckInFormId, 0) as CheckInFormId,
		isnull(@CheckOutFormId, 0) as CheckOutFormId,
		isnull(@DisallowCheckInForm, 0) as DisallowCheckInForm,
		isnull(@DisallowCheckOutForm, 0) as DisallowCheckOutForm,
		isnull(@CheckInDisallowMsg, '') as CheckInDisallowMsg,
		isnull(@CheckOutDisallowMsg, '') as CheckOutDisallowMsg,
		isnull(@AssignmentType, '') as AssignmentType,
		isnull(@AutoAssignTerritoryType, '') as AutoAssignTerritoryType,
		isnull(@AssignAllocationType, '') as AssignAllocationType,
		isnull(@AssignMeetingDays, 0) as AssignMeetingDays,
		isnull(@AssignMeetingType, '') as AssignMeetingType,
		isnull(@DefineSuccessMeeting, '') as DefineSuccessMeeting,
		isnull(@IsCheckInTime, 0) as IsCheckInTime,
		isnull(@SuccessMeetingCheckInMin, 0) as SuccessMeetingCheckInMin,
		isnull(@IsSuccessMeetingOutcome, 0) as IsSuccessMeetingOutcome,
		isnull(@IsSuccessMeetingCondForm, 0) as IsSuccessMeetingCondForm,
		isnull(@CheckInBeforeDistance, 0) as CheckInBeforeDistance,
		isnull(@IsAllowCallBeforeCheckIn, 0) as IsAllowCallBeforeCheckIn,
		isnull(@CheckInClientName, '') as CheckInClientName,
		isnull(@CheckInMeetingDetails, '') as CheckInMeetingDetails,
		isnull(@CheckInFieldMasked, '') as CheckInFieldMasked,
		isnull(@CheckOutAfterDistance, 0) as CheckOutAfterDistance,
		isnull(@IsAllowCallAfterCheckOut, 0) as IsAllowCallAfterCheckOut,
		isnull(@CheckOutClientName, '') as CheckOutClientName,
		isnull(@CheckOutMeetingDetails, '') as CheckOutMeetingDetails,
		isnull(@CheckOutFieldMasked, 0) as CheckOutFieldMasked,
		isnull(@AttendanceApproverType, '') as AttendanceApproverType,
		isnull(@AddReimbursementOf, 0) as AddReimbursementOf,
		isnull(@DeductReimbursementOf, 0) as DeductReimbursementOf,
		isnull(@CheckInOutApproverIds, '') as CheckInOutApproverIds,
		isnull(@ExpenseHeadIds, '') as ExpenseHeadIds,
		isnull(@MarkOutcomeCheckOut, 0) MarkOutcomeCheckOut,
		isnull(@AllowedCheckInOutOverride, 0) AllowedCheckInOutOverride,
		isnull(@CheckInOutApproverId, 0) CheckInOutApproverId,
		isnull(@CheckInOutApproverNames, '') CheckInOutApproverNames,
		isnull(@ExpenseHeadNames, '') ExpenseHeadNames,
		isnull(@CheckInEmailIdSetting, '') as [CheckInEmailIdSetting],
		isnull(@CheckInSMSSetting, '') as [CheckInSMSSetting],
		isnull(@CheckInWhatsappSetting, '')  as [CheckInWhatsappSetting],
		isnull(@CheckOutEmailIdSetting, '') as [CheckOutEmailIdSetting],
		isnull(@CheckOutSMSSetting, '')  as [CheckOutSMSSetting],
		isnull(@CheckOutWhatsappSetting, '')  as [CheckOutWhatsappSetting]
end



