/* ============================================================
   Procedure: [dbo].[usp_mk_GetUserCreditBalance]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE dbo.usp_mk_GetUserCreditBalance (    
	@UserId bigint
)    
AS    
BEGIN  

	--declare @UserId bigint = 34594

	declare @M_Id bigint, @ParentId bigint, @User_Id bigint

	select @M_Id = M_ID, @ParentId = ParentID, @User_Id = User_Id from User_Detail(nolock) where User_ID = @UserId

	DECLARE @Intcredit DECIMAL(18, 2)= 0, @Mailcredit DECIMAL(18, 2)= 0, @Smscredit DECIMAL(18, 2)= 0;

	select top 1 @Intcredit = ISNULL(Balance, 0) FROM IntCredit_Details(nolock) WHERE USER_ID = @ParentId ORDER BY Credit_ID DESC;    
	select top 1 @Smscredit= balance  FROM credit_details(nolock) WHERE m_id = @M_Id AND user_id = @User_Id ORDER BY credit_id DESC;
	select top 1 @Mailcredit = balance FROM MailCreditDetails(nolock) WHERE m_id = @M_Id AND USER_ID = @ParentId ORDER BY credit_id DESC;

	Select @Intcredit as Intcredit, @Mailcredit as Mailcredit, @Smscredit as Smscredit
	
END                



