/* ============================================================
   Procedure: [dbo].[usp_mk_GetUserHierarchyParentId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Exec usp_mk_GetUserHierarchyParentId @ParentId=32222
CREATE   PROCEDURE [dbo].[usp_mk_GetUserHierarchyParentId]
(                  
  @ParentId bigint
)                  
as                  
Begin             
 -- declare @ParentId bigint=32222
	If exists(Select * from tbl_UA_RoleHierarchy(nolock) where ParentId = @ParentId and IsActive=1)
	Begin
		Select 'Role' as Mode,RoleHierarchyId  as UserHierarchyId,ParentId,HierarchyJSON,CreatedBy,CreatedDate,ModifiedBy,ModifiedDate 
		from tbl_UA_RoleHierarchy(nolock) where ParentId = @ParentId and IsActive=1
	End
	Else
	Begin
		
		-- declare @ParentId bigint=32222
		declare @HierarchyJSON nvarchar(max)
		Set @HierarchyJSON=(
		select UH.user_id,UH.team_name,UD.user_login,username=concat(UD.FName,' ',UD.LName),UH.parentid,UH.rolename
		From openjson((Select top 1 HierarchyJSON from tbl_UA_UserHierarchy(nolock) where ParentId=@ParentId and IsActive=1))
		with
		(
			user_id		bigint			'$.user_id',
			team_name	varchar(100)	'$.team_name',
			user_login	varchar(100)	'$.user_login',
			username	varchar(100)	'$.username',
			parentid	bigint			'$.parentid',
			rolename	varchar(100)	'$.rolename'
		) UH inner join User_detail(nolock) UD
		on UH.user_id=UD.user_ID
		for json auto
		)

		Select 'User' as Mode,UserHierarchyId,ParentId,@HierarchyJSON as HierarchyJSON, CreatedBy,CreatedDate,ModifiedBy,ModifiedDate 
		from tbl_UA_UserHierarchy(nolock) 
		where ParentId = @ParentId and IsActive=1

    End
End     



GO

/* ============================================================
   Procedure: [dbo].[usp_mk_GetUserListForUserLocation]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- usp_mk_GetUserListForUserLocation 32222  
  
CREATE   PROCEDURE usp_mk_GetUserListForUserLocation (   
                 @UserId   BIGINT ,   
                 @ParentId BIGINT  
                                                   )   
AS  
    BEGIN  
        DECLARE @Role VARCHAR(10)= '';  
        SELECT @Role = ( CASE  
                             WHEN IsAdmin = 1  
                             THEN 'SuperAdmin'  
                             ELSE ISNULL(TR.Role , '')  
                         END )  
        FROM User_Detail AS UD LEFT JOIN tbl_location_territory_mapping(nolock) AS TR ON UD.User_ID = TR.User_ID  
        WHERE UD.User_ID = @UserId;  
        IF ( @Role = '' )   
            BEGIN  
                PRINT 1.0;  
                SELECT 0 AS ID , 'UnAuthorized User' AS Name , '' AS Type;  
        END;  
            ELSE  
            BEGIN  
                PRINT 1.1;  
                IF ( @Role = 'SuperAdmin' )   
                    BEGIN  
                        PRINT 1.2;  
                        SELECT *  
                        FROM ( SELECT DISTINCT   
                                      LTM.User_ID AS ID , UD.User_Login AS [Name] , 'U' AS [TYPE]  
                               FROM tbl_location_territory(nolock) LT LEFT JOIN tbl_location_territory_mapping(nolock) AS LTM ON LT.ID = LTM.Territory_Id  INNER JOIN User_Detail(nolock) AS UD ON LTM.User_Id = UD.User_Id  
         WHERE LT.ParentID = @ParentId  
                             ) AS A;  
                END;  
                PRINT 1.3;  
                IF ( @Role = 'Manager' )   
                    BEGIN  
                        PRINT 1.4;  
                        SELECT *  
                        FROM ( SELECT DISTINCT   
                                      UD.User_ID AS ID , UD.User_Login AS [Name] , 'U' AS [TYPE]  
                               FROM User_Detail(nolock) AS UD INNER JOIN tbl_location_territory_mapping(nolock) AS LTM ON UD.User_ID = LTM.User_ID  
                               WHERE LTM.Territory_Id IN ( SELECT Territory_Id  
                                                           FROM tbl_location_territory_mapping(nolock)  
                                                           WHERE User_ID = @UserId  
                                                         )  
                             ) AS A;  
                END;  
                PRINT 1.5;  
                IF ( @Role = 'User' )   
                    BEGIN  
                        PRINT 1.6;  
                        SELECT *  
                        FROM ( SELECT DISTINCT   
                                      UD.User_ID AS ID , UD.User_Login AS [Name] , 'U' AS [TYPE]  
                               FROM User_Detail(nolock) AS UD INNER JOIN tbl_location_territory_mapping(nolock) AS LTM ON UD.User_ID = LTM.User_ID  
                               WHERE LTM.User_ID = @UserId  
                             ) AS A;  
                END;  
                PRINT 1.7;  
        END;  
        PRINT 1.8;  
    END;


GO

