--go      
CREATE   PROCEDURE dbo.usp_mk_InsertCommentDetail (    
 @Remarks NVARCHAR(max)    
 ,@TaskId BIGINT    
 ,@CreatedBy BIGINT    
 ,@tblStringList tblStringList readonly    
 )    
AS    
BEGIN    
 DECLARE @CommentId BIGINT = - 0;    
    
 BEGIN TRANSACTION    
    
 BEGIN TRY    
  DECLARE @ParentId BIGINT    
   ,@Username NVARCHAR(255)    
   ,@TaskTitle NVARCHAR(255)    
   ,@LeadId BIGINT    
   ,@TaskTypeId BIGINT    
    
  SELECT @ParentId = ParentId    
   ,@Username = User_Login    
  FROM User_Detail(NOLOCK)    
  WHERE User_Id = @CreatedBy    
    
  SELECT @TaskTitle = Title    
   ,@LeadId = LeadId    
   ,@TaskTypeId = TaskId    
  FROM tbl_tsk_TaskHistory(NOLOCK)    
  WHERE id = @TaskId    
    
  INSERT INTO tbl_tsk_TaskComments (    
   remarks    
   ,created_on    
   ,created_by    
   ,task_history_id    
   )    
  VALUES (    
   @Remarks    
   ,getdate()    
   ,@CreatedBy    
   ,@TaskId    
   )    
    
  SET @CommentId = scope_identity()    
    
  IF (    
    EXISTS (    
     SELECT 1    
     FROM @tblStringList    
     )    
    )    
  BEGIN    
   INSERT INTO tbl_tsk_CommentAttachments (    
    FileName    
    ,CreatedBy    
    ,CreatedOn    
    ,ParentId    
    ,CommentId    
    )    
   SELECT strValue    
    ,@CreatedBy    
    ,getdate()    
    ,@ParentId    
    ,@CommentId    
   FROM @tblStringList    
  END    
    
  DECLARE @event_title NVARCHAR(255) = ''    
   ,@event_description NVARCHAR(max) = ''    
    
  SET @event_title = CONCAT (    
    'Comment added to '    
    ,iif(@TaskTypeId = 8, 'appointment', 'task')    
    )    
  SET @event_description = CONCAT (   
    'A comment like "' + left(@remarks, 20) + '"' + CASE     
     WHEN EXISTS (    
       SELECT 1    
       FROM @tblStringList    
       )    
      THEN ' and attachment(s) were '    
     ELSE ' was '    
     END + 'added by '    
    ,@Username    
    ,' to '    
    ,iif(@TaskTypeId = 8, 'appointment', 'task')    
    ,' titled "'    
    ,@TaskTitle    
    ,'" on '    
    ,cast(getdate() AS NVARCHAR)    
    )    
    
  EXEC UspSaveLeadActivity_withid @LeadId    
   ,@CreatedBy    
   ,@ParentId    
   ,@event_description    
   ,@event_title    
   ,'tbl_tsk_TaskComments'    
   ,@CommentId    
    
  COMMIT TRANSACTION    
 END TRY    
    
 BEGIN CATCH    
  ROLLBACK TRANSACTION    
    
  SET @CommentId = 0    
    
  EXEC usp_InsertErrorInfo    
 END CATCH    
    
 SELECT @CommentId AS CommentId    
    
 DECLARE @rowJson NVARCHAR(MAX) = (    
   SELECT *  
   FROM tbl_tsk_TaskComments WITH(NOLOCK)    
   WHERE id = @CommentId    
   FOR JSON AUTO    
    ,INCLUDE_NULL_VALUES    
   )    
  ,@Activity_type VARCHAR(max)    
    
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @CreatedBy    
  ,@Activity_type = 'Inst_Task_cmmnt'    
  ,@ActionType = 'I'    
  ,@RowJson = @rowJson    
  ,@Table_name = 'tbl_tsk_TaskComments'    
END 


GO

/* ============================================================
   Procedure: [dbo].[usp_mk_InsertCommentDetailWithFileRemarks]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_mk_InsertCommentDetailWithFileRemarks]
(
 @Remarks NVARCHAR(max),
 @TaskId BIGINT,
 @CreatedBy BIGINT,
 @tblFileRemarks dbo.tblFileRemarks READONLY
)
AS
BEGIN
 DECLARE @CommentId BIGINT = 0;

 BEGIN TRANSACTION;
 BEGIN TRY

  DECLARE @ParentId BIGINT,
          @Username NVARCHAR(255),
          @TaskTitle NVARCHAR(255),
          @LeadId BIGINT,
          @TaskTypeId BIGINT;

  SELECT @ParentId = ParentId,
         @Username = User_Login
  FROM User_Detail (NOLOCK)
  WHERE User_Id = @CreatedBy;

  SELECT @TaskTitle = Title,
         @LeadId = LeadId,
         @TaskTypeId = TaskId
  FROM tbl_tsk_TaskHistory (NOLOCK)
  WHERE id = @TaskId;

  INSERT INTO tbl_tsk_TaskComments (
    remarks,
    created_on,
    created_by,
    task_history_id
  )
  VALUES (
    @Remarks,
    GETDATE(),
    @CreatedBy,
    @TaskId
  );

  SET @CommentId = SCOPE_IDENTITY();

  -- Insert file attachments with per-file remarks (if any rows supplied)
  IF EXISTS (SELECT 1 FROM @tblFileRemarks)
  BEGIN
    INSERT INTO tbl_tsk_CommentAttachments (
      FileName,
      Remarks,
      CreatedBy,
      CreatedOn,
      ParentId,
      CommentId
    )
    SELECT
      FileName,
      Remarks,
      @CreatedBy,
      GETDATE(),
      @ParentId,
      @CommentId
    FROM @tblFileRemarks;
  END

  DECLARE @event_title NVARCHAR(255) = '',
          @event_description NVARCHAR(max) = '';

  SET @event_title = CONCAT('Comment added to ', IIF(@TaskTypeId = 8, 'appointment', 'task'));

  SET @event_description = CONCAT(
    'A comment like "' + LEFT(@Remarks, 20) + '"' +
    CASE WHEN EXISTS (SELECT 1 FROM @tblFileRemarks) THEN ' and attachment(s) were ' ELSE ' was ' END +
    'added by ', @Username, ' to ', IIF(@TaskTypeId = 8, 'appointment', 'task'), ' titled "', @TaskTitle, '" on ', CAST(GETDATE() AS NVARCHAR)
  );

  EXEC UspSaveLeadActivity_withid @LeadId,
       @CreatedBy,
       @ParentId,
       @event_description,
       @event_title,
       'tbl_tsk_TaskComments',
       @CommentId;

  COMMIT TRANSACTION;
 END TRY

 BEGIN CATCH
  ROLLBACK TRANSACTION;
  SET @CommentId = 0;
  EXEC usp_InsertErrorInfo;
 END CATCH

 -- Return the new CommentId
 SELECT @CommentId AS CommentId;

 -- Audit row JSON
 DECLARE @rowJson NVARCHAR(MAX) = (
   SELECT *
   FROM tbl_tsk_TaskComments WITH (NOLOCK)
   WHERE id = @CommentId
   FOR JSON AUTO, INCLUDE_NULL_VALUES
 );

 EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId @User_id = @CreatedBy,
   @Activity_type = 'Inst_Task_cmmnt',
   @ActionType = 'I',
   @RowJson = @rowJson,
   @Table_name = 'tbl_tsk_TaskComments';
END



GO

/* ============================================================
   Procedure: [dbo].[usp_mk_InsertDailPaidDetail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- EXEC usp_mk_InsertDailPaidDetail 9821592374, 'Lead', 35494  

CREATE   PROCEDURE usp_mk_InsertDailPaidDetail 
				 @MobileNo bigint, @PageName varchar(200), @UserId bigint
AS
BEGIN
	DECLARE @dailPaidId bigint;
	DECLARE @currentdate DATETIME  = GETDATE();


	INSERT INTO tbl_DailPaidCallDetails( MobileNo, PageName, UserId )
	VALUES( @MobileNo, @PageName, @UserId );
	SET @dailPaidId = (SELECT SCOPE_IDENTITY());

	-- Create Task for recently entered record
	declare @tskTitle nvarchar(250) = 'Call_Outgoing_'+REPLACE(REPLACE(REPLACE(CONVERT(VARCHAR, @currentdate, 120), '-', ''), ' ', ''), ':', '')
	


	exec usp_tsk_GenerateCallTask 0, @tskTitle, @MobileNo, @currentdate, @UserId, 'open', 1, 0, null 


	select @dailPaidId
END;  

--select * from tbl_tsk_TaskHistory order by CreatedOn desc
  


GO

/* ============================================================
   Procedure: [dbo].[usp_mk_insertnewcallForBroadcast]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
-- exec usp_mk_insertnewcallForBroadcast 32222,'promo','9313943059',983,'1204862692',60,null  
CREATE   PROCEDURE [dbo].[usp_mk_insertnewcallForBroadcast]  
(  
 @user_id      BIGINT,   
    @route        NVARCHAR(20),   
    @mobile       NVARCHAR(MAX),   
    @appid        INT,   
    @callerid     NVARCHAR(20),   
    @duration     INT,   
    @scheduledfor DATETIME= NULL  
)  
AS  
BEGIN  
        SET @scheduledfor = COALESCE(@scheduledfor, GETDATE());  
        DECLARE @batchid BIGINT;  
        BEGIN TRAN;  
   INSERT INTO Getbatchrecord  
   ([User_id], RandNum)  
   SELECT @user_id, @user_id;  
   SELECT @batchid = SCOPE_IDENTITY();  
   DELETE FROM GetBatchRecord  
   WHERE BatchID = @batchid;  
        COMMIT;  
  
        SELECT value INTO #mobile FROM fn_split(@mobile, ',');  
  
        DECLARE @mcount INT=(SELECT COUNT(1) FROM #mobile);  
  
        SELECT * INTO #temp  FROM dbo.fn_GetVoiceCreditCalculation(@route, @user_ID, @duration, @mcount);  
  
        DECLARE @credits NUMERIC(18, 4)=(SELECT balance  FROM #temp );  
          
  IF EXISTS(SELECT 1 FROM #temp WHERE msg = 'ok')  
        BEGIN  
   INSERT INTO Clone_VoiceDeliveryStatus --clonemessagedeliverystatus                                              
   (BatchID, didno, Mobile, voiceDuration, AppId, IsDnd, IsPrority, IsAllowDND, price, user_id, VoiceInsertDate, ScheduledDate, voice_type, route)  
   SELECT   
   @batchid, @callerid, m.value, @duration, @appid, 0, 2, 0, @credits, @user_id, GETDATE(), @scheduledfor, 1, @route  
   FROM #mobile m;  
  
   Select 1 as Res  
        END;  
        ELSE  
        BEGIN      
            --send notification proc to be placed here      
            DECLARE @mail NVARCHAR(200)=(SELECT email FROM user_detail(NOLOCK) WHERE user_id = @user_id);  
   Select 0 as Res  
        END;  

		    
 DECLARE @rowJson NVARCHAR(MAX) = (      
   SELECT *      
   FROM Clone_VoiceDeliveryStatus WITH(NOLOCK)      
   WHERE BatchID = @batchid      
   FOR JSON AUTO      
    ,INCLUDE_NULL_VALUES      
   )         
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @user_id = @user_id      
  ,@Activity_type = 'Inst_NewCall'      
  ,@ActionType = 'I'      
  ,@RowJson = @rowJson      
  ,@Table_name = 'Clone_VoiceDeliveryStatus'      
END;  


