   Procedure: [dbo].[usp_mk_InsertNewLeadDetailsWithFollowUp]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_mk_InsertNewLeadDetailsWithFollowUp]  
(@ParentID           BIGINT,   
 @PersonName         VARCHAR(100),
 @PersonImage         VARCHAR(100)='',
 @CompanyName        VARCHAR(100),   
 @MobileNo           VARCHAR(100),   
 @MobileNo1          VARCHAR(100),   
 @MobileNo2          VARCHAR(100),   
 @EmailID            VARCHAR(100),   
 @EmailID1           VARCHAR(100),   
 @EmailID2           VARCHAR(100),   
 @City               VARCHAR(100),   
 @State              VARCHAR(100),   
 @Country            VARCHAR(100),   
 @CountryCode        VARCHAR(50),   
 @CountryCode1       VARCHAR(50),   
 @CountryCode2       VARCHAR(50),   
 @PinCode            BIGINT,   
 @ResidentialAddress VARCHAR(500),   
 @OfficialAddress    VARCHAR(500),   
 @SourceName         BIGINT,   
 @MediumName         BIGINT,   
 @CampaignName       BIGINT,   
 @Remarks            VARCHAR(1000),   
 @CreatedBy          BIGINT,   
 @AssignedTo         BIGINT,   
 @FollowUpStatus     INT,   
 @NextStatusDate     VARCHAR(50),   
 @Products           VARCHAR(1000),   
 @AmountPaid         NUMERIC(18, 2),   
 @FollowUpRemarks    VARCHAR(1000),   
 @custom             CUSTOMLEADS1 READONLY  
)  
AS  
    BEGIN  
        DECLARE @newlead BIGINT;  
        DECLARE @FollowupDate DATETIME= NULL;  
        IF(@NextStatusDate <> '')  
            BEGIN  
                SET @FollowupDate = @NextStatusDate;  
        END;  
        CREATE TABLE #temp  
        (mobile VARCHAR(100),   
         email  VARCHAR(100)  
        );  
        INSERT INTO #temp  
        (mobile,   
         email  
        )  
               SELECT(CAST(ISNULL(CountryCode, 0) AS NVARCHAR) + CAST(ISNULL(NULLIF(MobileNo, ''), 0) AS NVARCHAR)),   
                     ISNULL(NULLIF(EmailID, ''), 0)  
               FROM UserLeads  
               WHERE ParentID = @PARENTID  
               UNION  
               SELECT(CAST(ISNULL(CountryCode1, 0) AS NVARCHAR) + CAST(ISNULL(NULLIF(MobileNo1, ''), 0) AS NVARCHAR)),   
                     ISNULL(NULLIF(EmailID1, ''), 0)  
               FROM UserLeads  
               WHERE ParentID = @PARENTID  
               UNION  
               SELECT(CAST(ISNULL(CountryCode2, 0) AS NVARCHAR) + CAST(ISNULL(NULLIF(MobileNo2, ''), 0) AS NVARCHAR)),   
                     ISNULL(NULLIF(EmailID2, ''), 0)  
               FROM UserLeads  
               WHERE ParentID = @PARENTID;  
        IF EXISTS  
        (  
            SELECT 1  
            FROM UserLeads  
            WHERE ParentID = @ParentID  
                  AND (CAST(ISNULL(@CountryCode, 1) AS NVARCHAR) + CAST(ISNULL(@MobileNo, 1) AS NVARCHAR) IN  
            (  
                SELECT Mobile  
                FROM #temp  
            ))  
        )  
            BEGIN  
    SELECT 0 AS [leadid],   
                       'Lead with Mobile ' + @mobileno + ' already exists' AS [msg],   
                       0 AS [mylead];  
                GOTO LeadNotInserted;  
        END;  
        IF EXISTS  
        (  
            SELECT 1  
            FROM UserLeads  
            WHERE ParentID = @ParentID  
                  AND (CAST(ISNULL(@CountryCode1, 1) AS NVARCHAR) + CAST(ISNULL(@MobileNo1, 1) AS NVARCHAR) IN  
            (  
                SELECT Mobile  
                FROM #temp  
            ))  
        )  
            BEGIN  
    SELECT 0 AS [leadid],   
                       'Lead with Mobile ' + @mobileno1 + ' already exists' AS [msg],   
                       0 AS [mylead];  
                GOTO LeadNotInserted;  
        END;  
        IF EXISTS  
        (  
            SELECT 1  
            FROM UserLeads  
            WHERE ParentID = @ParentID  
                  AND (CAST(ISNULL(@CountryCode2, 1) AS NVARCHAR) + CAST(ISNULL(@MobileNo2, 1) AS NVARCHAR) IN  
            (  
                SELECT Mobile  
                FROM #temp  
            ))  
        )  
            BEGIN  
    SELECT 0 AS [leadid],   
                       'Lead with Mobile ' + @mobileno2 + ' already exists' AS [msg],   
                       0 AS [mylead];  
                GOTO LeadNotInserted;  
        END;  
     IF EXISTS  
        (  
            SELECT 1  
            FROM UserLeads  
            WHERE ParentID = @ParentID  
                  AND (CAST(ISNULL(NULLIF(@EmailID, ''), 1) AS NVARCHAR) IN  
            (  
                SELECT email  
                FROM #temp  
            ))  
        )  
            BEGIN  
     SELECT 0 AS [leadid],   
                       'Lead with Email ' + @EmailID + ' already exists' AS [msg],   
                       0 AS [mylead];  
                GOTO LeadNotInserted;  
        END;  
        IF EXISTS  
        (  
            SELECT 1  
            FROM UserLeads  
            WHERE ParentID = @ParentID  
                  AND (CAST(ISNULL(NULLIF(@EmailID1, ''), 1) AS NVARCHAR) IN  
            (  
                SELECT email  
                FROM #temp  
            ))  
        )  
            BEGIN  
                SELECT 0 AS [leadid],   
                       'Lead with Email ' + @EmailID1 + ' already exists' AS [msg],   
                       0 AS [mylead];  
                GOTO LeadNotInserted;  
        END;  
        IF EXISTS  
        (  
            SELECT 1  
            FROM UserLeads  
            WHERE ParentID = @ParentID  
                  AND (CAST(ISNULL(NULLIF(@EmailID2, ''), 1) AS NVARCHAR) IN  
            (  
                SELECT email  
                FROM #temp  
            ))  
        )  
            BEGIN  
                SELECT 0 AS [leadid],   
                       'Lead with Email ' + @EmailID2 + ' already exists' AS [msg],   
                       0 AS [mylead];  
                GOTO LeadNotInserted;  
        END;  
        DECLARE @Leadno BIGINT= ISNULL(  
        (  
            SELECT MAX(LeadNo)  
            FROM UserLeads  
            WHERE ParentID = @ParentID  
        ), 0) + 1;  

		SET Context_Info 0x55555

        INSERT INTO UserLeads( ParentID, LeadNo, PersonName, ProfileImgFileName, CompanyName, MobileNo, MobileNo1, MobileNo2, EmailID, EmailID1, EmailID2, City, STATE, Country, CountryCode, CountryCode1, CountryCode2, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, CreatedOn, CreatedBy, AssignedTo, FollowUpStatus, NextStatusDate, Products, AmountPaid, Remarks, FollowupDate, enquirysource )  
        VALUES (@ParentID, @LeadNo, @PersonName, @PersonImage, @CompanyName, @MobileNo, @MobileNo1, @MobileNo2, @EmailID, @EmailID1, @EmailID2, @City, @State, @Country, @CountryCode, @CountryCode1, @CountryCode2, @PinCode, @ResidentialAddress, @OfficialAddress, @SourceName, @MediumName, @CampaignName, @Remarks, GETDATE(), @CreatedBy, @AssignedTo, @FollowUpStatus, @NextStatusDate, @Products, @AmountPaid, @FollowUpRemarks, @FollowupDate, 29
        --@CreatedBy,                                  
        -- 1,                                  
        -- cast(DATEPART(yyyy,getdate()) as nvarchar) +'-'+ RIGHT('00' + cast(DATEPART(dd,getdate()) as nvarchar(2)),2) +'-'+ RIGHT('00' + cast(DATEPART(MM,getdate()) as nvarchar(2)),2),                                  
        -- 'Lead Created'                                   
        );  
        SET @newlead = SCOPE_IDENTITY();  


		DECLARE @insertcount SMALLINT;  
		SELECT @insertcount = ISNULL(COUNT(fieldID), 0) FROM @custom;  
		IF(@insertcount > 0)  
		BEGIN  
			SELECT * INTO #temp29 FROM @custom;  
			UPDATE #temp29 SET LeadID = @newlead;  
			INSERT INTO customfieldLeadvalue (LeadID, EnquiryID, fieldID, fieldvalue )  
			SELECT * FROM #temp29;  
			DROP TABLE #temp29;  
		END;  

		EXEC MySMS.dbo.usp_ExecLeadTriggerTasks @newlead

		IF(@newlead > 0)
		begin
			EXEC MySMS.dbo.usp_inserleadinteractionhistory @newlead
		end

		SET Context_Info 0x

		declare @clMobileNo  nvarchar(20) = COALESCE(@MobileNo, @MobileNo1, @MobileNo2);
		execute usp_cl_UpdateEntityDetailToCallLog
			@EntityName = 'lead',
			@EntityId = @newlead,
			@ParentId = @ParentID,
			@CustomerMobileNo = @clMobileNo
  
        --  AssignedTo,                                  
        --FollowUpStatus,                                  
        --NextStatusDate,                              
        --Products ,                              
        --AmountPaid  ,                         
        --Remarks                               
  
        --INSERT INTO LeadInteractionHistory  
        --([LeadNo],   
        -- [FollowUpStatus],   
        -- [NextStatusDate],   
        -- [Remarks],   
        -- [Products],   
        -- AmountPaid,   
        -- [AssignedTo],   
        -- [ParentID],   
        -- [CreatedOn],   
        -- [CreatedBy],   
        -- FollowupDate  
        --)  
        --       SELECT @LeadNo,   
        --              @FollowUpStatus,   
        --              @NextStatusDate,   
        --              @FollowUpRemarks,   
        --              @Products,   
        --              @AmountPaid,   
        --              @AssignedTo  
        --              ,  
  
        --              --,cast(DATEPART(yyyy,getdate()) as nvarchar) +'-'+ RIGHT('00' + cast(DATEPART(dd,getdate()) as nvarchar(2)),2) +'-'+ RIGHT('00' + cast(DATEPART(MM,getdate()) as nvarchar(2)),2)                                  
        --              --,'Lead Created'                                  
        --              --,0                                  
        --              --,@createdby                                   
        --              @ParentID,   
        --              GETDATE(),   
        --              @CreatedBy,   
        --              @FollowupDate;  
    
	

        
	SELECT @LeadNo as [leadid], 'Record Inserted' msg, @newlead as [mylead];  
          
  LeadNotInserted:                           
        --SELECT SCOPE_IDENTITY() AS [leadid];                                     
END



GO

