CREATE   PROCEDURE [dbo].[usp_mk_InsertNewLeadDetailsWithFollowUp_Replication_AppModKit19]    
(@ParentID           BIGINT,     
 @PersonName         VARCHAR(100),  
 @PersonImage         VARCHAR(100)='',  
 @CompanyName        VARCHAR(100),     
 @MobileNo           VARCHAR(100),     
 @MobileNo1          VARCHAR(100),     
 @MobileNo2          VARCHAR(100),     
 @EmailID            VARCHAR(100),     
 @EmailID1           VARCHAR(100),     
 @EmailID2           VARCHAR(100),     
 @City               VARCHAR(100),     
 @State              VARCHAR(100),     
 @Country            VARCHAR(100),     
 @CountryCode        VARCHAR(50),     
 @CountryCode1       VARCHAR(50),     
 @CountryCode2       VARCHAR(50),     
 @PinCode            BIGINT,     
 @ResidentialAddress VARCHAR(500),     
 @OfficialAddress    VARCHAR(500),     
 @SourceName         BIGINT,     
 @MediumName         BIGINT,     
 @CampaignName       BIGINT,     
 @Remarks            nVARCHAR(2000),     
 @CreatedBy          BIGINT,     
 @AssignedTo         BIGINT,     
 @FollowUpStatus     INT,     
 @NextStatusDate     VARCHAR(50),     
 @Products           VARCHAR(1000),     
 @AmountPaid         NUMERIC(18, 2),     
 @FollowUpRemarks    VARCHAR(1000),     
 @custom             CUSTOMLEADS1 READONLY    
)    
AS    
    BEGIN   
   
           
  Declare @QueryProducts nvarchar(max) = ''  
  DECLARE @ProductsJson NVARCHAR(4000) = ''  
  
   if(isnull(@Products,'') != '')  
   begin  
         set @QueryProducts =  CONCAT('select @ProductsJsonTemp = (    
         select t.Name as ProductName from (select [value] from fn_split('''+ isnull(@Products,'''') +''',''#'')) as tbl  
        join   
      tbl_ProductMaster_', cast(@ParentID as nvarchar(50)) ,' as t with(nolock)  
        on tbl.[value] = t.ProductID  
          
        FOR JSON AUTO            
          ,INCLUDE_NULL_VALUES    
     )','')  
    
    exec sp_executesql @QueryProducts, N'@ProductsJsonTemp nvarchar(4000) out ', @ProductsJson out    
         end   
  
  
  
  
        DECLARE @newlead BIGINT;    
        DECLARE @FollowupDate DATETIME= NULL;    
        IF(@NextStatusDate <> '')    
            BEGIN    
                SET @FollowupDate = @NextStatusDate;    
        END;    
