CREATE   PROCEDURE [dbo].[usp_mk_InsertNewLeadDetailsWithFollowUpLocation]          
(@ParentID           BIGINT,           
 @PersonName         NVARCHAR(200),        
 @PersonImage        NVARCHAR(100)='',        
 @CompanyName        NVARCHAR(500),           
 @MobileNo           NVARCHAR(100),           
 @MobileNo1          NVARCHAR(100),           
 @MobileNo2          NVARCHAR(100),           
 @EmailID            NVARCHAR(100),           
 @EmailID1           NVARCHAR(100),           
 @EmailID2           NVARCHAR(100),           
 @City               NVARCHAR(100),           
 @State              NVARCHAR(100),           
 @Country            NVARCHAR(100),           
 @CountryCode        NVARCHAR(50),           
 @CountryCode1       NVARCHAR(50),           
 @CountryCode2       NVARCHAR(50),           
 @PinCode            BIGINT,           
 @ResidentialAddress NVARCHAR(500),           
 @OfficialAddress    NVARCHAR(500),           
 @SourceName         BIGINT,           
 @MediumName         BIGINT,           
 @CampaignName       BIGINT,           
 @Remarks            NVARCHAR(1000),           
 @CreatedBy          BIGINT,           
 @AssignedTo         BIGINT,           
 @FollowUpStatus     INT,           
 @NextStatusDate     VARCHAR(50),           
 @Products           VARCHAR(1000),           
 @AmountPaid         NUMERIC(18, 2),           
 @FollowUpRemarks    NVARCHAR(1000),           
 @WhereLatitude      NVARCHAR(255) = '',                
 @WhereLongitude     NVARCHAR(255) = '',                
 @custom             CUSTOMLEADS1 READONLY          
)          
AS          
    BEGIN          
        DECLARE @newlead BIGINT;          
        DECLARE @FollowupDate DATETIME= NULL;          
        IF(@NextStatusDate <> '')          
            BEGIN          
                SET @FollowupDate = @NextStatusDate;          
        END;          
        CREATE TABLE #temp          
        (mobile VARCHAR(100),           
         email  VARCHAR(100)          
        );          
        INSERT INTO #temp          
        (mobile,           
         email          
        )          
               SELECT(CAST(ISNULL(CountryCode, 0) AS NVARCHAR) + CAST(ISNULL(NULLIF(MobileNo, ''), 0) AS NVARCHAR)),           
                     ISNULL(NULLIF(EmailID, ''), 0)          
               FROM UserLeads          
               WHERE ParentID = @PARENTID          
               UNION          
               SELECT(CAST(ISNULL(CountryCode1, 0) AS NVARCHAR) + CAST(ISNULL(NULLIF(MobileNo1, ''), 0) AS NVARCHAR)),           
                     ISNULL(NULLIF(EmailID1, ''), 0)          
               FROM UserLeads          
               WHERE ParentID = @PARENTID          
               UNION          
               SELECT(CAST(ISNULL(CountryCode2, 0) AS NVARCHAR) + CAST(ISNULL(NULLIF(MobileNo2, ''), 0) AS NVARCHAR)),           
                     ISNULL(NULLIF(EmailID2, ''), 0)          
               FROM UserLeads          
               WHERE ParentID = @PARENTID;          
        IF EXISTS          
        (          
            SELECT 1          
            FROM UserLeads          
            WHERE ParentID = @ParentID          
                  AND (CAST(ISNULL(@CountryCode, 1) AS NVARCHAR) + CAST(ISNULL(@MobileNo, 1) AS NVARCHAR) IN          
            (          
                SELECT Mobile          
                FROM #temp          
            ))          
        )          
            BEGIN          
    SELECT 0 AS [leadid],           
                       'Lead with Mobile ' + @mobileno + ' already exists' AS [msg],           
                       0 AS [mylead];          
                GOTO LeadNotInserted;          
        END;          
        IF EXISTS          
        (          
            SELECT 1          
            FROM UserLeads          
            WHERE ParentID = @ParentID          
                  AND (CAST(ISNULL(@CountryCode1, 1) AS NVARCHAR) + CAST(ISNULL(@MobileNo1, 1) AS NVARCHAR) IN          
            (          
         SELECT Mobile          
                FROM #temp          
            ))          
        )          
            BEGIN          
    SELECT 0 AS [leadid],           
        'Lead with Mobile ' + @mobileno1 + ' already exists' AS [msg],           
                       0 AS [mylead];          
                GOTO LeadNotInserted;          
        END;          
        IF EXISTS          
        (          
            SELECT 1          
            FROM UserLeads          
            WHERE ParentID = @ParentID          
                  AND (CAST(ISNULL(@CountryCode2, 1) AS NVARCHAR) + CAST(ISNULL(@MobileNo2, 1) AS NVARCHAR) IN          
            (          
                SELECT Mobile          
                FROM #temp          
            ))          
        )          
            BEGIN          
    SELECT 0 AS [leadid],           
                       'Lead with Mobile ' + @mobileno2 + ' already exists' AS [msg],           
                       0 AS [mylead];          
                GOTO LeadNotInserted;          
        END;          
     IF EXISTS          
        (          
            SELECT 1          
            FROM UserLeads          
            WHERE ParentID = @ParentID          
                  AND (CAST(ISNULL(NULLIF(@EmailID, ''), 1) AS NVARCHAR) IN          
            (          
                SELECT email          
                FROM #temp          
            ))          
        )          
            BEGIN          
     SELECT 0 AS [leadid],           
                       'Lead with Email ' + @EmailID + ' already exists' AS [msg],           
                       0 AS [mylead];          
                GOTO LeadNotInserted;          
        END;          
        IF EXISTS          
        (          
            SELECT 1          
            FROM UserLeads          
            WHERE ParentID = @ParentID          
                  AND (CAST(ISNULL(NULLIF(@EmailID1, ''), 1) AS NVARCHAR) IN          
            (          
                SELECT email          
                FROM #temp          
            ))          
        )          
            BEGIN          
                SELECT 0 AS [leadid],           
                       'Lead with Email ' + @EmailID1 + ' already exists' AS [msg],           
                       0 AS [mylead];          
                GOTO LeadNotInserted;          
        END;          
        IF EXISTS          
        (          
            SELECT 1          
            FROM UserLeads          
            WHERE ParentID = @ParentID          
                  AND (CAST(ISNULL(NULLIF(@EmailID2, ''), 1) AS NVARCHAR) IN          
            (          
                SELECT email          
                FROM #temp          
            ))          
        )          
            BEGIN          
                SELECT 0 AS [leadid],           
                       'Lead with Email ' + @EmailID2 + ' already exists' AS [msg],           
                       0 AS [mylead];          
                GOTO LeadNotInserted;          
        END;          
        
declare @latitude float = null;              
if(ISNULL(@WhereLatitude, '') <> '')              
begin              
 set @latitude = cast(@WhereLatitude as float)              
end              
declare @longitude float = null;              
if(ISNULL(@WhereLatitude, '') <> '')              
begin              
 set @longitude = cast(@WhereLongitude as float)               
end              
        
  DECLARE @Leadno BIGINT= ISNULL(          
        (          
            SELECT MAX(LeadNo)          
            FROM UserLeads          
            WHERE ParentID = @ParentID          
        ), 0) + 1;          
        
        INSERT INTO UserLeads          
        (ParentID,           
         LeadNo,           
         PersonName,           
   ProfileImgFileName,        
   CompanyName,           
         MobileNo,           
         MobileNo1,           
         MobileNo2,           
         EmailID,           
         EmailID1,           
         EmailID2,           
         City,           
         STATE,           
         Country,           
         CountryCode,           
         CountryCode1,           
         CountryCode2,           
         PinCode,           
         ResidentialAddress,           
         OfficeAddress,           
         SourceName,           
         MediumName,           
         CampaignName,           
         InitialRemarks,           
         CreatedOn,           
         CreatedBy,           
         AssignedTo,           
         FollowUpStatus,           
         NextStatusDate,           
         Products,           
         AmountPaid,           
         Remarks,           
         FollowupDate,        
   latitude,        
   longitude,      
   enquirysource      
        )          
        VALUES          
        (@ParentID,           
         @LeadNo,                @PersonName,           
         @PersonImage,        
   @CompanyName,           
         @MobileNo,           
         @MobileNo1,           
         @MobileNo2,           
         @EmailID,           
         @EmailID1,           
         @EmailID2,           
         @City,           
         @State,           
         @Country,           
         @CountryCode,           
         @CountryCode1,           
         @CountryCode2,           
         @PinCode,           
         @ResidentialAddress,           
         @OfficialAddress,           
         @SourceName,           
      @MediumName,           
         @CampaignName,           
         @Remarks,           
         GETDATE(),           
         @CreatedBy,           
         @AssignedTo,           
         @FollowUpStatus,           
         @NextStatusDate,           
         @Products,           
         @AmountPaid,           
         @FollowUpRemarks,           
         @FollowupDate,        
   (case when @latitude > 0 then @latitude else null end),        
   (case when @longitude > 0 then @longitude else null end),      
  13 --Manual App kit19      
        --@CreatedBy,                                          
        -- 1,                                          
        -- cast(DATEPART(yyyy,getdate()) as nvarchar) +'-'+ RIGHT('00' + cast(DATEPART(dd,getdate()) as nvarchar(2)),2) +'-'+ RIGHT('00' + cast(DATEPART(MM,getdate()) as nvarchar(2)),2),                                          
        -- 'Lead Created'                                           
        );          
        SET @newlead = SCOPE_IDENTITY();          
          
        --  AssignedTo,                                          
        --FollowUpStatus,                                          
        --NextStatusDate,                                      
        --Products ,                                      
        --AmountPaid  ,                                 
        --Remarks    
    
        
  
        DECLARE @insertcount SMALLINT;          
        SELECT @insertcount = ISNULL(COUNT(fieldID), 0)          
        FROM @custom;          
        IF(@insertcount > 0)          
            BEGIN          
                SELECT *          
  INTO #temp29          
                FROM @custom;          
                UPDATE #temp29          
                  SET           
                      LeadID = @newlead;          
                INSERT INTO customfieldLeadvalue          
                (LeadID,           
                 EnquiryID,           
                 fieldID,           
                 fieldvalue          
                )          
                       SELECT *          
                       FROM #temp29;          
                DROP TABLE #temp29;          
        END;          
        SELECT @newlead as [leadid],           
               'Record Inserted' msg,           
               @newlead as [mylead];          
        
if isnull(@newlead,0)<>0        
begin        
  
      SET Context_Info 0x55555        
  
  declare @lehid bigint=0 ;  		
		  
        INSERT INTO LeadInteractionHistory ([LeadNo],           
         [FollowUpStatus],           
         [NextStatusDate],           
         [Remarks],           
         [Products],           
         AmountPaid,           
         [AssignedTo],           
         [ParentID],           
         [CreatedOn],           
         [CreatedBy],           
         FollowupDate,id_lead          
        )          
               SELECT @LeadNo,           
                      @FollowUpStatus,           
                      @NextStatusDate,           
                      @FollowUpRemarks,           
                      @Products,           
                      @AmountPaid,           
                      @AssignedTo          
                      ,          
          
                      --,cast(DATEPART(yyyy,getdate()) as nvarchar) +'-'+ RIGHT('00' + cast(DATEPART(dd,getdate()) as nvarchar(2)),2) +'-'+ RIGHT('00' + cast(DATEPART(MM,getdate()) as nvarchar(2)),2)                                          
                      --,'Lead Created'                                          
                      --,0                                       
                      --,@createdby                                           
                      @ParentID,           
                      GETDATE(),           
                      @CreatedBy,           
                      @FollowupDate,@newlead;    
   select @lehid=SCOPE_IDENTITY()
exec [usp_ExecLeadInteractionTriggerTasks] @lehid
SET Context_Info 0x   
end  



  LeadNotInserted:                                   
        --SELECT SCOPE_IDENTITY() AS [leadid];           
      
 END  


GO

