SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_MK_InsertUpdateLeadDocuments]      
(      
@ParentID bigint,      
@UserID bigint,      
@LeadID bigint,      
@DocumentName varchar(500),      
@FileType varchar(11),      
@FileLocation varchar(500)    
)      
AS      
BEGIN      
      
  Declare @EventDesc int      
  Declare @EventDescrip varchar(50)     
      
   INSERT INTO tbl_LeadDocumentUpload (ParentID,UserID,LeadID,DocumentName,FileType,FileLocation,UploadedDate,ISDeleted)      
        
       values(@ParentID,@UserID,@LeadID,@DocumentName,@FileType,@FileLocation,GETDATE(),0)      
   set @EventDesc=0      
    
    
  declare @docid bigint = scope_identity()  
  
  select @docid
  
  set @EventDescrip='Document Inserted'      
        
      
  INSERT INTO tbl_LeadEventHistory(ParentID,UserID,LeadID,EventDescription,EventDate,IPAddress) Values(@ParentID,@UserID,@LeadID,@EventDescrip,GETDATE(),'1.1.1.1')      
  
  
  
      
END


