/* ============================================================
   Procedure: [dbo].[usp_mk_InsertUpdateLeadNotes]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_mk_InsertUpdateLeadNotes]        
(        
@HistoryID BIGINT,        
@ParentID BIGINT,        
@UserID BIGINT,        
@LeadID BIGINT,        
@Notes  text,        
@IPAddress varchar(50)        
)        
AS        
BEGIN        
        
  Declare @EventDesc int        
  Declare @EventDescrip varchar(50)        
        
IF @HistoryID=0        
  BEGIN        
  
   INSERT INTO tbl_LeadNotes(ParentID,UserID,LeadID,Notes,CreatedDate,UpdatedDate,ISDeleted)        
   values(@ParentID,@UserID,@LeadID,@Notes,GETDATE(),GETDATE(),0)        
   select @HistoryID=SCOPE_IDENTITY()
   set @EventDesc=0        
        
  END        
else       
  BEGIN        
  UPDATE tbl_LeadNotes SET Notes=@Notes,UpdatedDate=GETDATE()        
            
    WHERE ParentID=@ParentID and UserID=@UserID and LeadID=@LeadID      and NoteID=@HistoryID  
        
   set @EventDesc=1        
  END        
        
  if @EventDesc=0        
  set @EventDescrip='Notes Inserted'        
          
  if @EventDesc=1        
  set @EventDescrip='Notes Updated'        
        
  --INSERT INTO tbl_LeadEventHistory(ParentID,UserID,LeadID,EventDescription,EventDate,IPAddress) Values(@ParentID,@UserID,@LeadID,@EventDescrip,GETDATE(),@IPAddress)        
        
  select @EventDescrip      
  
  if(@EventDescrip = 'Notes Inserted')    
   Begin     
    
        /* Start lead activity Add Notes  */    
 Begin try    
    
   Declare @UserID_LDACTV bigint =  @UserID    
   declare @evntMessage nvarchar(max) = ''     
   Declare @ParentID_LDACTV bigint = @ParentID    
   Declare @LeadID_LDACTV bigint = @LeadID    
    
   create table #tblEventDescrb    
   (    
     EVNT_Description nvarchar(max)     
   )    
    
  if( isnull(@LeadID_LDACTV,0) > 0 )    
   Begin    
        
   insert into #tblEventDescrb    
      exec  Usp_EventTemplate_DynamicVarReplacement 'Notes added',@UserID_LDACTV,'','',0,'',null    
   ,0,0,'','',0,'',0,null,null,null,null,null,null,null,null,null    
   ,null,null,null,null,null,null,null,null,    
   0,0,0,null,null,null,0,null,null,null,0,null,null    
         
       
   select @evntMessage = isnull( EVNT_Description,'') from #tblEventDescrb    
       
   select @evntMessage    
    
   if(@evntMessage <> '')    
   Begin    
   exec UspSaveLeadActivity_withid @LeadID_LDACTV,@UserID_LDACTV,@ParentID_LDACTV,@evntMessage,    'Notes added','tbl_LeadNotes',@HistoryID    
   end    
    
    
   End      
    
   end try    
   Begin catch    
     exec usp_InsertErrorInfo    
   End catch    
    
    IF OBJECT_ID('tempdb..#tblEventDescrb') IS NOT NULL -- Check for table existence      
   Begin      
        DROP TABLE #tblEventDescrb      
   End      
       
          
   /* End lead activity Add Notes  */    
    
    
    
   end    
    
    
   if(@EventDescrip = 'Notes Updated')    
         Begin    
            
      /* Start lead activity  Edit Notes */    
    
  Begin try    
    
   Declare @UserID_LDACTV_1 bigint =  @UserID    
   Declare @evntMessage_1 nvarchar(max) = ''     
   Declare @NotesID_LDACTV_1 int = 99     
   Declare @CreatedOn_LDACTV_1 nvarchar(50) = ''    
   Declare @ParentID_LDACTV_1 bigint = @ParentID    
   Declare @LeadID_LDACTV_1 bigint = @LeadID    
    
   select top 1 @CreatedOn_LDACTV_1 = isnull(CreatedDate,GETDATE()) from tbl_LeadNotes --where  NoteID = @NotesID_LDACTV_1    
    
   WHERE ParentID=@ParentID_LDACTV_1 and UserID=@UserID_LDACTV_1 and LeadID=@LeadID_LDACTV_1 order by NoteID desc    
    
    
   create table #tblEventDescrb_1    
   (    
     EVNT_Description nvarchar(max)     
   )    
    
  if( isnull(@LeadID_LDACTV_1,0) > 0 )    
   Begin    
        
   insert into #tblEventDescrb_1    
      exec  Usp_EventTemplate_DynamicVarReplacement 'Notes edited',@UserID_LDACTV_1,'','',0,'',null    
   ,0,0,'','',0,'',0,null,null,null,null,null,null,null,null,null    
   ,null,null,null,null,null,null,null,null,    
   0,0,0,null,null,null,0,null,null,null,0,null,@CreatedOn_LDACTV_1    
         
       
   select @evntMessage_1 = isnull( EVNT_Description,'') from #tblEventDescrb_1    
       
   select @evntMessage_1    
    
   if(@evntMessage_1 <> '')    
   Begin    
   exec UspSaveLeadActivity_withid @LeadID_LDACTV_1,@UserID_LDACTV_1,@ParentID_LDACTV_1,@evntMessage_1,    'Notes edited','tbl_LeadNotes',@HistoryID    
   end    
    
    
   End      
    
   end try    
   Begin catch    
    
      exec usp_insertErrorInfo    
    
   End catch    
    
    IF OBJECT_ID('tempdb..#tblEventDescrb_1') IS NOT NULL -- Check for table existence      
   Begin      
        DROP TABLE #tblEventDescrb_1      
   End      
       
       
   /* End lead activity  Edit Notes */    
    
    
   End    
  
      
END 


GO

