 @OfficeAddress      NVARCHAR(500),     
 @PinCode            BIGINT,     
 @SourceName         BIGINT,     
 @MediumName         BIGINT,     
 @CampaignName       BIGINT,     
 @InitialRemarks     NVARCHAR(1000),     
 @ParentID           BIGINT,     
 @CreatedBy          NVARCHAR(50),     
 @custom             CUSTOMENQUIRY READONLY    
)    
AS    
    BEGIN    
        DECLARE @newenq BIGINT;    
        CREATE TABLE #temp    
        (mobile VARCHAR(100),     
         email  VARCHAR(100)    
        );    
        INSERT INTO #temp    
        (mobile,     
         email    
        )    
               SELECT CAST(ISNULL(CountryCode, 0) AS NVARCHAR) + CAST(ISNULL(NULLIF(MobileNo, ''), 0) AS NVARCHAR),     
                      ISNULL(NULLIF(EmailID, ''), 0)    
               FROM UserLeads    
               WHERE ParentID = @PARENTID    
               UNION    
               SELECT CAST(ISNULL(CountryCode1, 0) AS NVARCHAR) + CAST(ISNULL(NULLIF(MobileNo1, ''), 0) AS NVARCHAR),     
                      ISNULL(NULLIF(EmailID1, ''), 0)    
               FROM UserLeads    
               WHERE ParentID = @PARENTID    
               UNION    
               SELECT CAST(ISNULL(CountryCode2, 0) AS NVARCHAR) + CAST(ISNULL(NULLIF(MobileNo2, ''), 0) AS NVARCHAR),     
                      ISNULL(NULLIF(EmailID2, ''), 0)    
               FROM UserLeads    
               WHERE ParentID = @PARENTID;    
        DECLARE @leadn AS BIGINT;    
        IF EXISTS    
        (    
            SELECT 1    
            FROM UserLeads    
            WHERE ParentID = @ParentID    
                  AND CAST(ISNULL(@CountryCode, 1) AS NVARCHAR) + CAST(ISNULL(@MobileNo, 1) AS NVARCHAR) IN    
            (    
                SELECT Mobile    
                FROM #temp    
            )    
        )    
            BEGIN    
                SELECT @leadn = leadno    
                FROM UserLeads    
                WHERE ParentID = @ParentID    
                      AND CAST(ISNULL(@CountryCode, 1) AS NVARCHAR) + CAST(ISNULL(@MobileNo, 1) AS NVARCHAR) IN    
                (    
                    SELECT Mobile    
                    FROM #temp    
                );    
        END;    
        IF @leadn = ''    
            BEGIN    
                IF EXISTS    
                (    
                    SELECT 1    
                    FROM UserLeads    
                    WHERE ParentID = @ParentID    
                          AND CAST(ISNULL(@CountryCode1, 1) AS NVARCHAR) + CAST(ISNULL(@MobileNo1, 1) AS NVARCHAR) IN    
                    (    
                        SELECT Mobile    
                        FROM #temp    
                    )    
                )    
                    BEGIN    
                        SELECT @leadn = leadno    
                    FROM UserLeads    
                        WHERE ParentID = @ParentID    
                              AND CAST(ISNULL(@CountryCode1, 1) AS NVARCHAR) + CAST(ISNULL(@MobileNo1, 1) AS NVARCHAR) IN    
                        (    
                        SELECT Mobile    
                            FROM #temp    
                        );    
                END;    
                IF EXISTS    
                (    
                    SELECT 1    
                    FROM UserLeads    
                    WHERE ParentID = @ParentID    
                          AND CAST(ISNULL(@CountryCode2, 1) AS NVARCHAR) + CAST(ISNULL(@MobileNo2, 1) AS NVARCHAR) IN    
                    (    
                        SELECT Mobile    
                        FROM #temp    
                    )    
                )    
                    BEGIN    
                        SELECT @leadn = leadno    
                        FROM UserLeads    
                        WHERE ParentID = @ParentID    
                              AND CAST(ISNULL(@CountryCode2, 1) AS NVARCHAR) + CAST(ISNULL(@MobileNo2, 1) AS NVARCHAR) IN    
                        (    
                            SELECT Mobile    
                            FROM #temp    
                        );    
                END;    
                IF EXISTS    
                (    
                    SELECT 1    
                    FROM UserLeads    
                    WHERE ParentID = @ParentID    
                          AND CAST(ISNULL(NULLIF(@EmailID, ''), 1) AS NVARCHAR) IN    
                    (    
                        SELECT email    
                        FROM #temp    
                    )    
                )    
                    BEGIN    
                        SELECT @leadn = leadno    
                        FROM UserLeads    
                        WHERE ParentID = @ParentID    
                              AND CAST(ISNULL(NULLIF(@EmailID, ''), 1) AS NVARCHAR) IN    
                        (    
                            SELECT email    
                            FROM #temp    
                        );    
                END;    
                IF EXISTS    
                (    
                    SELECT 1    
                    FROM UserLeads    
                    WHERE ParentID = @ParentID    
                          AND CAST(ISNULL(NULLIF(@EmailID1, ''), 1) AS NVARCHAR) IN    
                    (    
                        SELECT email    
                        FROM #temp    
                    )    
                )    
                    BEGIN    
                        SELECT @leadn = leadno    
                        FROM UserLeads    
                        WHERE ParentID = @ParentID    
                              AND CAST(ISNULL(NULLIF(@EmailID1, ''), 1) AS NVARCHAR) IN    
                        (    
                            SELECT email    
                            FROM #temp    
                        );    
                END;    
                IF EXISTS    
                (    
                    SELECT 1    
                    FROM UserLeads    
                    WHERE ParentID = @ParentID    
                          AND CAST(ISNULL(NULLIF(@EmailID2, ''), 1) AS NVARCHAR) IN    
                    (    
                        SELECT email    
                        FROM #temp    
                    )    
                )    
                    BEGIN    
                        SELECT @leadn = leadno    
                        FROM UserLeads    
                        WHERE ParentID = @ParentID    
                              AND CAST(ISNULL(NULLIF(@EmailID2, ''), 1) AS NVARCHAR) IN    
                        (    
                            SELECT email    
                            FROM #temp    
                        );    
                END;    
        END;    
        IF NOT EXISTS    
        (    
            SELECT 1    
            FROM UserEnquiry    
            WHERE PersonName = @PersonName    
                  AND MobileNo = @MobileNo    
                  AND MobileNo1 = @MobileNo1    
                  AND MobileNo2 = @MobileNo2    
                  AND EmailID = @EmailID    
                  AND EmailID1 = @EmailID1    
                  AND EmailID2 = @EmailID2    
                  AND CountryCode = @CountryCode    
                  AND CountryCode1 = @CountryCode1    
                  AND CountryCode2 = @CountryCode2    
                  AND SourceName = @SourceName    
                  AND ParentID = @ParentID    
                  AND CreatedBy = @CreatedBy    
        )    
            BEGIN    
                INSERT INTO UserEnquiry    
                (PersonName,     
      ProfileImgFileName,  
                 CompanyName,     
                 MobileNo,     
                 MobileNo1,     
                 MobileNo2,     
                 EmailID,     
                 EmailID1,     
                 EmailID2,     
                 City,     
                 STATE,     
                 Country,     
                 CountryCode,     
                 CountryCode1,     
                 CountryCode2,     
                 ResidentialAddress,     
                 OfficeAddress,     
                 PinCode,     
                 SourceName,     
                 MediumName,     
                 CampaignName,     
                 InitialRemarks,     
                 ParentID,     
                 CreatedDate,     
                 CreatedBy,     
                 LeadNo    
                )    
                VALUES    
                (@PersonName,     
                 @PersonImage,  
     @CompanyName,     
                 @MobileNo,     
                 @MobileNo1,     
                 @MobileNo2,     
                 @EmailID,     
                 @EmailID1,     
                 @EmailID2,     
                 @City,     
                 @State,     
                 @Country,     
                 @CountryCode,     
                 @CountryCode1,     
                 @CountryCode2,     
                 @ResidentialAddress,     
                 @OfficeAddress,     
                 @PinCode,     
                 @SourceName,     
                 @MediumName,     
                 @CampaignName,     
                 @InitialRemarks,     
                 @ParentID,     
                 GETDATE(),     
                 @CreatedBy,     
                 @leadn    
                );    
    
                --SELECT 'Record Saved Successfully'                    
                --SELECT SCOPE_IDENTITY() AS [Enquiryid];              
                SET @newenq = SCOPE_IDENTITY();    
                DECLARE @insertcount SMALLINT;    
                SELECT @insertcount = ISNULL(COUNT(fieldID), 0)    
                FROM @custom;    
                IF @insertcount > 0    
                    BEGIN    
                        SELECT *    
                        INTO #temp19    
                        FROM @custom;    
                        UPDATE #temp19    
                          SET     
                              EnquiryID = @newenq;    
                        INSERT INTO customfieldEnquiryvalue    
                        (EnquiryID,     
                         fieldID,     
                         fieldvalue    
                        )    
                               SELECT EnquiryID,     
                         fieldID,     
                         fieldvalue   
                               FROM #temp19;    
                        DROP TABLE #temp19;    
                END;    
                SELECT @newenq AS Enquiryid;    
        END;    
            ELSE    
            BEGIN    
                SELECT '' AS Enquiryid;    
        END;    
	 DECLARE @rowJson NVARCHAR(MAX) = (      
   SELECT *      
   FROM UserEnquiry WITH(NOLOCK)      
   WHERE EnquiryID = @newenq      
   FOR JSON AUTO      
    ,INCLUDE_NULL_VALUES      
   )      
 IF @rowJson IS NOT NULL      
 BEGIN      
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @CreatedBy      
  ,@Activity_type = 'Inst_User_EnqryDetails'      
  ,@ActionType = 'I'      
  ,@RowJson = @rowJson      
  ,@Table_name = 'UserEnquiry'      
 END 
    END;  


GO

