                )      
                    BEGIN      
                        SELECT @leadn = leadno      
                        FROM UserLeads      
                        WHERE ParentID = @ParentID      
                              AND CAST(ISNULL(NULLIF(@EmailID2, ''), 1) AS NVARCHAR) IN      
                        (      
                            SELECT email      
                            FROM #temp      
                        );      
                END;      
        END;      
        IF NOT EXISTS      
        (      
            SELECT 1      
            FROM UserEnquiry      
            WHERE PersonName = @PersonName      
                  AND MobileNo = @MobileNo      
                  AND MobileNo1 = @MobileNo1      
                  AND MobileNo2 = @MobileNo2      
                  AND EmailID = @EmailID      
                  AND EmailID1 = @EmailID1      
                  AND EmailID2 = @EmailID2      
                  AND CountryCode = @CountryCode      
                  AND CountryCode1 = @CountryCode1      
                  AND CountryCode2 = @CountryCode2      
                  AND SourceName = @SourceName      
                  AND ParentID = @ParentID      
                  AND CreatedBy = @CreatedBy      
        )      
            BEGIN      
                INSERT INTO UserEnquiry      
                (PersonName,       
				 ProfileImgFileName,    
                 CompanyName,       
                 MobileNo,       
                 MobileNo1,       
                 MobileNo2,       
                 EmailID,       
                 EmailID1,       
                 EmailID2,       
                 City,       
                 STATE,       
                 Country,       
                 CountryCode,       
                 CountryCode1,       
                 CountryCode2,       
                 ResidentialAddress,       
                 OfficeAddress,       
                 PinCode,       
                 SourceName,       
                 MediumName,       
                 CampaignName,       
                 InitialRemarks,       
                 ParentID,       
                 CreatedDate,       
                 CreatedBy,  
				 latitude,  
				 longitude,  
                 LeadNo,
				 enquirysource
                )      
                VALUES      
                (@PersonName,       
                 @PersonImage,    
     @CompanyName,       
                 @MobileNo,       
                 @MobileNo1,       
                 @MobileNo2,       
                 @EmailID,       
                 @EmailID1,       
                 @EmailID2,       
                 @City,       
                 @State,       
                 @Country,       
                 @CountryCode,       
                 @CountryCode1,       
                 @CountryCode2,       
                 @ResidentialAddress,       
                 @OfficeAddress,       
                 @PinCode,       
                 @SourceName,       
                 @MediumName,       
                 @CampaignName,       
                 @InitialRemarks,       
                 @ParentID,       
                 GETDATE(),       
                 @CreatedBy,       
     (case when @latitude > 0 then @latitude else null end),  
     (case when @longitude > 0 then @longitude else null end),  
     @leadn,
				13 --Manual App kit19
                );      
      
                --SELECT 'Record Saved Successfully'                      
               SET @newenq = SCOPE_IDENTITY();      
                DECLARE @insertcount SMALLINT;      
                SELECT @insertcount = ISNULL(COUNT(fieldID), 0)      
                FROM @custom;      
                IF @insertcount > 0      
                    BEGIN      
                        SELECT * INTO #temp19 FROM @custom;  
        
                        UPDATE #temp19 SET EnquiryID = @newenq;      
                        INSERT INTO customfieldEnquiryvalue (EnquiryID, fieldID, fieldvalue)      
                        SELECT * FROM #temp19;      
                       -- DROP TABLE #temp19;      
                   END;   
           SELECT @newenq AS Enquiryid;      
           END  
         ELSE  
          BEGIN      
           SELECT '-10' AS Enquiryid;      
          END      
    END;    



GO

