--    FROM dbo.fn_Split(@EnquiryTags, ',')

--) tn

-- JOIN TagMaster tm WITH(NOLOCK)

--    ON tm.ParentID = @ParentID

--    AND LOWER(tm.Tag) = LOWER(tn.tagName);

--   select @EnquiryTags , * from #tempTagName 
      
   WHILE (      
