   BEGIN      
    DECLARE @tId INT      
     ,@tTagName NVARCHAR(255)      
     ,@tagId BIGINT      
      
    SELECT TOP 1 @tId = id      
     ,@tTagName = tagName      
     ,@tagId = tagId      
    FROM #tempTagName      
    WHERE isProcess = 0      
      
    PRINT @tTagName      
      
    IF (@tagId IS NULL 

    AND NOT EXISTS (

        SELECT 1 

        FROM TagMaster 

        WHERE ParentID = @ParentID 

        AND LOWER(Tag) = LOWER(@tTagName)

    ))
     
    BEGIN      
     INSERT INTO TagMaster (      
      Tag      
      ,ParentID      
      ,CreatedDate      
      ,CreatedBy      
      )      
     VALUES (      
      @tTagName      
      ,@ParentID      
      ,getdate()      
      ,@CreatedBy      
      )      
      
     DECLARE @sId BIGINT = scope_identity()      
      
     UPDATE #tempTagName      
     SET tagId = @sId      
     WHERE id = @tId      
    END      
      
    UPDATE #tempTagName      
    SET isProcess = 1      
    WHERE id = @tId      
   END      
      
   DELETE EntityTagMapping      
   WHERE EntityID = @newenq      
    AND lower(Entity) = 'enquiry'      
      
   --INSERT INTO EntityTagMapping (      
   -- EntityID      
   -- ,Entity      
   -- ,TagID      
   -- ,CreatedDate      
   -- )      
   --SELECT @newenq      
   -- ,'Enquiry'      
   -- ,tagId      
   -- ,getdate()      
   --FROM #tempTagName    
    INSERT INTO EntityTagMapping (      
    EntityID      
    ,Entity      
    ,TagID      
    ,CreatedDate      
    )      
   SELECT @newenq      
    ,'Enquiry'      
    ,tagId      
    ,getdate()      
   FROM #tempTagName      
  END      
		  SELECT @newenq AS Enquiryid;      
           END  
         ELSE  
          BEGIN      
