   Procedure: [dbo].[usp_mk_IsEmailAlreadyExists]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_mk_IsEmailAlreadyExists
	@EmailId nvarchar(255),
	@UserId bigint
as
begin
	declare @ParentId bigint = (select ParentID from User_Detail(nolock) where User_ID = @UserId)
	if(exists(select * from (
		select EmailID as [EmailId], ParentId from UserLeads(nolock) where ParentID = @ParentId
			union
		select EmailID1 as [EmailId], ParentId from UserLeads(nolock) where ParentID = @ParentId
			union
		select EmailID2 as [EmailId], ParentId from UserLeads(nolock) where ParentID = @ParentId
	) emails where EmailId  = @EmailId))
		begin
			select 1
		end
	else
		begin
			select 0
		end
end



