/* ============================================================
   Procedure: [dbo].[usp_mk_IsTrackingEnableForUser]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- EXEC usp_mk_IsTrackingEnableForUser 34594    
    
CREATE   PROCEDURE usp_mk_IsTrackingEnableForUser (     
                @UserId BIGINT    
                                               )     
AS    
    BEGIN    
  CREATE TABLE #TEMPUSER (    
   UserId BIGINT,    
   FrequencyUnit numeric    
  )    
    
        DECLARE @Role VARCHAR(10)= '';    
        SELECT @Role = CASE    
                           WHEN IsAdmin = 1    
                           THEN 'SuperAdmin'    
                           ELSE ISNULL(TR.Role , '')    
                       END    
        FROM User_Detail AS UD LEFT JOIN tbl_location_territory_mapping AS TR ON UD.User_ID = TR.User_ID    
        WHERE UD.User_ID = @UserId;    
        IF @Role = ''    
            BEGIN    
                PRINT 1.0;    
                SELECT 0 AS ID , 'UnAuthorized User' AS Name , '' AS Type;    
        END;    
            ELSE    
            BEGIN    
                PRINT 1.1;    
                IF @Role = 'SuperAdmin'    
                    BEGIN    
                        PRINT 1.2;    
      INSERT INTO  #TEMPUSER    
                        SELECT LS.User_ID , LS.FrequencyUnit    
                        FROM tbl_location_territory_mapping AS LTM INNER JOIN User_Detail AS UD ON LTM.User_Id = UD.User_Id    
                                                                   JOIN tbl_location_setting AS LS ON UD.User_ID = LS.User_ID    
                   WHERE UD.User_ID = @UserId or UD.ParentID = @UserId  
                END;    
                IF @Role = 'Manager'    
                    BEGIN    
                        PRINT 1.4;    
      INSERT INTO  #TEMPUSER    
                        SELECT LS.User_ID , LS.FrequencyUnit    
                        FROM User_Detail AS UD INNER JOIN tbl_location_territory_mapping AS LTM ON UD.User_ID = LTM.User_ID    
                                               INNER JOIN tbl_location_setting AS LS ON UD.User_ID = LS.User_ID    
                        WHERE LTM.Territory_Id IN ( SELECT Territory_Id    
                                                    FROM tbl_location_territory_mapping    
                                                    WHERE User_ID = @UserId    
                                                  );    
                END;    
        END;    
    
        IF ( SELECT AVG(FrequencyUnit) FROM #TEMPUSER ) > 0    
            BEGIN    
                SELECT 1;    
        END;    
            ELSE    
            BEGIN    
                SELECT 0;    
        END;    
        DROP TABLE #TEMPUSER;    
    END;


GO

