/* ============================================================
   Procedure: [dbo].[usp_mk_Logout]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_mk_Logout] (    
	 @UserName nvarchar(255),
	 @DeviceId nvarchar(max) = ''
)    
AS    
Begin    
 
 Declare @oldDeviceId nvarchar(1000) = '',@UserId bigint=0,@AppVersion varchar(100),@OSVersion varchar(100),@OSName varchar(100),@ModelName varchar(100)  
   
 select @UserId=User_Id, @oldDeviceId = DeviceID, @AppVersion = AppVersion, @OSVersion = OSVersion, @OSName = OSName, @ModelName= ModelName  
 from User_Detail Where User_Login=@UserName   
  
 Update User_Detail Set
	DeviceID = case when @DeviceId = @oldDeviceId then '' else DeviceID end,
	OTP = case when @DeviceId = @oldDeviceId then '' else OTP end,
	AppVersion = case when @DeviceId = @oldDeviceId then '' else AppVersion end,
	OSVersion = case when @DeviceId = @oldDeviceId then '' else OSVersion end,
	OSName = case when @DeviceId = @oldDeviceId then '' else OSName end,
	ModelName = case when @DeviceId = @oldDeviceId then '' else ModelName end,
	IsForceOffFeild = case when @DeviceId = @oldDeviceId then 1 else 0 end,
   /*, OnField=0*/ 
   Presence = case when isnull(MACAddress,'') != '' then Presence else 0 end  
 Where User_Login=@UserName    
  
 exec usp_insertloginhistory @UserId, null, null, @oldDeviceId, 'Logout', null, @AppVersion,@OSVersion,@OSName,@ModelName  
   
End    



GO

