   Procedure: [dbo].[usp_mk_ManageDefaultSearchName]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE usp_mk_ManageDefaultSearchName(
	@UserId bigint,
	@SearchType nvarchar(20),
	@SearchName nvarchar(255)
)
as
begin
	if(exists(select * from tbl_mk_DefaultCustomSearch(nolock) where User_Id = @UserId and SearchType = @SearchType))
	begin
		update tbl_mk_DefaultCustomSearch set
			SearchName = @SearchName,
			ModifiedDate = GETDATE()
		where User_Id = @UserId and SearchType = @SearchType
	end
	else
	begin
		insert into tbl_mk_DefaultCustomSearch( SearchName, User_Id, SearchType, CreatedOn )
			values( @SearchName, @UserId, @SearchType, getdate())
	end
end



GO

/* ============================================================
   Procedure: [dbo].[usp_mk_OutcomeListByTaskId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_mk_OutcomeListByTaskId] (  
	 @TaskId bigint,  
	 @UserId bigint  
)  
as  
begin  
 
	--declare @TaskId bigint = 505, @UserId bigint = 49532  
   
	declare @TaskTypeId bigint    
	declare @ParentId bigint = 0    
	select @ParentId = dbo.ufn_getuserparentid(@UserId)

	/*     
		select @TaskTypeId = TaskId from tbl_tsk_TaskHistory(nolock) where id = @TaskId and dbo.ufn_getuserparentid(createdby)=@parentid  

		if ISNULL(@TaskTypeId,0)=0  
		begin  
		select top 1 @TaskTypeId = TaskTypeId from TBL_ET_PhysicalAppointment(nolock)   
			where PhysicalAppointmentId = @TaskId and ParentId = @ParentId
		end
 
		-- Checking @TaskId is TaskTypeId Start
		if(isnull(@TaskTypeId, 0) = 0)
		begin
		if(exists(select *  from tbl_tsk_TaskOutcomeMapping(nolock)  where TaskId = @TaskId and ParentId = @ParentId))
		begin
			set @TaskTypeId = @TaskId
		end
		end
		-- Checking @TaskId is TaskTypeId End
		print concat('@TaskTypeId => ', @TaskTypeId)
 
	*/

	declare @isUserTaskMaster bit = 0 
 
	SET @isUserTaskMaster =  CASE WHEN EXISTS ( SELECT 1 
		FROM tbl_tsk_UserTaskMaster WITH (NOLOCK) WHERE id = @TaskId
	) THEN 1 ELSE 0 END;

	--if((@TaskId > 0) and (exists(select *  from tbl_tsk_TaskOutcomeMapping(nolock) 
	--	where TaskId = @TaskId and ParentId = @ParentId)))

	if(@isUserTaskMaster = 1 and @TaskId > 0)
	begin  
		if(exists(select *  from tbl_tsk_TaskOutcomeMapping(nolock) where TaskId = @TaskId and ParentId = @ParentId))
		begin
			SELECT OutcomesId, OutcomeName, Indent, Sequence from tbl_tsk_UserOutcomeMaster(nolock) uom   
			left join tbl_tsk_TaskOutcomeMapping(nolock) TOM  ON TOM.OutcomesId = UOM.Id    
			where TOM.TaskId = @TaskId and TOM.ParentId = @ParentId      
			ORDER BY TOM.Sequence ASC  
		end
		else
		begin
			select id as [OutcomesId], OutcomeName, Indent, id as [Sequence] from tbl_tsk_UserOutcomeMaster 
			with (nolock) where ParentId = 0  order by id asc
		end
	end  
	else  
	begin  
		if(exists(select 1 from tbl_CallLogOutcomeMaster(nolock) where ParentId = @ParentId  ))  
		begin 
			print 'exists'
			select  Id OutcomesId, OutcomeName, Indent, Sequence  from tbl_CallLogOutcomeMaster(nolock)   
			where ParentId = @ParentId and IsDeleted = 0 order by Sequence asc  
		end  
		else  
		begin  
			print 'not exists'
			select  Id OutcomesId, OutcomeName, Indent, Sequence from tbl_CallLogOutcomeMaster(nolock)   
			where ParentId = 0 and IsDeleted = 0 order by Sequence asc  
		end  

		--select Id OutcomesId, OutcomeName, Indent, Sequence from tbl_CallLogOutcomeMaster(nolock)  
		-- where IsDeleted = 0    
		-- and 1 = (case   
		--  when isnull(@ParentId, 0) = 0 and ParentId = 0 and IsPredefined = 1 then 1  
		--  when isnull(@ParentId, 0) > 0 and ParentId = @ParentId then 1  
		-- else 0  end ) order by Sequence asc  
	end  
end 



