/* ============================================================
   Procedure: [dbo].[usp_mk_OutcomeListByTaskIdMode]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_mk_OutcomeListByTaskIdMode] (  
	 @TaskId bigint,  
	 @UserId bigint,
	 @Mode nvarchar(25) = 'task'
)  
as  
begin  
 
	--declare 
	--	@TaskId bigint = 505, 
	--	@UserId bigint = 49532,
	--	@Mode nvarchar(25) = 'task'
   
	declare @ParentId bigint = 0    
	select @ParentId = dbo.ufn_getuserparentid(@UserId)

	declare @tblOutcom as table (
		OutcomesId bigint,
		OutcomeName nvarchar(255),
		Indent nvarchar(25),
		[Sequence] int
	)

	if(@Mode in ('virtualapt','physicalmeeting','task'))
	begin
		if(exists(select *  from tbl_tsk_TaskOutcomeMapping(nolock) where TaskId = @TaskId and ParentId = @ParentId))
		begin
			insert into @tblOutcom (OutcomesId, OutcomeName, Indent, [Sequence])
			SELECT OutcomesId, OutcomeName, Indent, Sequence from tbl_tsk_UserOutcomeMaster(nolock) uom   
			left join tbl_tsk_TaskOutcomeMapping(nolock) TOM  ON TOM.OutcomesId = UOM.Id    
			where TOM.TaskId = @TaskId and TOM.ParentId = @ParentId 
		end
		else
		begin
			insert into @tblOutcom (OutcomesId, OutcomeName, Indent, [Sequence])
			select id, OutcomeName, Indent, id from tbl_tsk_UserOutcomeMaster 
			with (nolock) where ParentId = 0 
		end
	end

	if(@Mode in ('call'))
	begin
		if(exists(select 1 from tbl_CallLogOutcomeMaster(nolock) where ParentId = @ParentId  ))  
		begin 
			insert into @tblOutcom (OutcomesId, OutcomeName, Indent, [Sequence])
			select  Id OutcomesId, OutcomeName, Indent, Sequence  from tbl_CallLogOutcomeMaster(nolock)   
			where ParentId = @ParentId and IsDeleted = 0 
		end  
		else  
		begin  
			insert into @tblOutcom (OutcomesId, OutcomeName, Indent, [Sequence])
			select  Id OutcomesId, OutcomeName, Indent, Sequence from tbl_CallLogOutcomeMaster(nolock)   
			where ParentId = 0 and IsDeleted = 0
		end  
	end


	select OutcomesId, OutcomeName, Indent, [Sequence] from @tblOutcom order by [Sequence] asc
	
end 



GO

/* ============================================================
   Procedure: [dbo].[usp_mk_PublicApiSaveAppointment]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_mk_PublicApiSaveAppointment
(
	@IdentityMode nvarchar(50),
	@IdentityValue nvarchar(255),
	@AssignedTo nvarchar(255),
	@dtUserLogins dtUserLogins readonly,
	@UserId bigint
)
as
begin
	
	declare @LeadId bigint, @AssignedToId bigint, @CollaboratorUserIds nvarchar(max) 

	declare @ParentId bigint = ( select ParentID from User_Detail(nolock) where User_ID = @UserId )

	declare @mobileNo nvarchar(100) = ( select [value] from fn_Split(@IdentityValue, ' ') where [position] = 2  )

	select top 1 @LeadId = ID from UserLeads(nolock) where ParentID = @ParentId
		and 1 = ( case 
			when @IdentityMode = 'leadid' and ID = cast(@IdentityValue as bigint) then 1
			when @IdentityMode = 'leadno' and LeadNo = cast(@IdentityValue as bigint) then 1
			when @IdentityMode = 'mobile' and @mobileNo in (MobileNo, MobileNo1, MobileNo2) then 1
			when @IdentityMode = 'email' and @IdentityValue in (EmailID, EmailID1, EmailID2) then 1
			else 0 end )

	if(@AssignedTo = cast(@UserId as nvarchar))
	begin
		set @AssignedToId =  @UserId
	end
	else
	begin
		set @AssignedToId = ( select User_ID from User_Detail(nolock) where User_Login = @AssignedTo and ParentID = @ParentId )
	end


	if(exists(select 1 from @dtUserLogins))
	begin
		set @CollaboratorUserIds = (select STRING_AGG(User_ID, '#' )from User_Detail(nolock) 
				where User_Login in ( select UserLogin from @dtUserLogins ) and ParentID = @ParentId)
	end


	select 
		@LeadId as LeadId,
		@AssignedToId as AssignedToId,
		@CollaboratorUserIds as CollaboratorUserIds

end



GO

/* ============================================================
   Procedure: [dbo].[usp_mk_Rep_GetCallhistory]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- exec usp_mk_Rep_GetCallhistory 26023, '01-Jan-2020', '10-Feb-2020','',''    
-- exec usp_mk_Rep_GetCallhistory 34092, '01-Jan-2020', '10-Feb-2020','',''    
-- exec usp_mk_Rep_GetCallhistory 34093, '01-Jan-2020', '10-Feb-2020','',''    
-- exec usp_mk_Rep_GetCallhistory 34094, '01-Jan-2020', '10-Feb-2020','',''    
-- exec usp_mk_Rep_GetCallhistory 34096, '01-Jan-2020', '10-Feb-2020','',''    
-- exec usp_mk_Rep_GetCallhistory 32222, '01-Dec-2019', '10-Jan-2020','',''    
-- Exec usp_mk_Rep_GetCallhistory 32222, '01-Jan-2020', '02-Jan-2020'    
-- Exec usp_mk_Rep_GetCallhistory 32222, '01-Dec-2019', '10-Jan-2020','8447070969',''  
-- Exec usp_mk_Rep_GetCallhistory 32222, '01-Dec-2019', '10-Dec-2019','','1204862606'    
-- Exec usp_mk_Rep_GetCallhistory 32222, '01-Dec-2019', '10-Dec-2019','9313943059','1204862606'    
-- exec usp_mk_Rep_GetCallhistory @UserId=26023,@FromDate=N'06-Feb-2020',@ToDate=N'07-Feb-2020',@CallerId=N'',@DndId=N''
CREATE   PROC usp_mk_Rep_GetCallhistory   
(    
	@UserId bigint,
	@FromDate varchar(12)='',
	@ToDate varchar(12)='',
	@CallerId varchar(50)='',
	@Dndid varchar(50)=''
)    
As    
Begin    
    
-- declare @UserId bigint=26023,@FromDate varchar(12)='01-Nov-2019',@ToDate varchar(12)='30-Dec-2020',@CallerId varchar(50)='', @Dndid varchar(50)=''    
    
	DECLARE @Datefrom DATETIME, @Dateto DATETIME;

	IF(@Fromdate = '')
	BEGIN
		SET @Datefrom = '01-Jan-1900';
	END;
	ELSE
	BEGIN
		SET @Datefrom = @Fromdate;
	END;

	IF(@Todate = '')
	BEGIN
		SET @Dateto = '31-Jan-2100';
	END;
	ELSE
	BEGIN
		SET @Dateto = @Todate;
	END;

	SELECT *
	FROM ( SELECT FORMAT(KC.call_start_time, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate], KC.callerid, KC.dnid, recordurl = ISNULL(KC.recordurl, ''), UD.User_ID, UD.FName + ISNULL(' ' + UD.LName, '') AS [User], ISNULL(DC.Disposition, '') AS Disposition, 
	(CASE WHEN DC.Disposition = 'ANSWER' THEN 'CONNECTED' ELSE 'MISSED' END) AS CallStatus, 
	(CASE WHEN KC.context = 'DialerCalls' THEN 'Out' ELSE 'In' END) AS CallDirection, 
	CallPeriod = CONVERT(VARCHAR(8), DATEADD(SECOND, ISNULL(DATEDIFF(second, DC.call_start_time, DC.call_end_time), 0), '19000101'), 8)--,*
	FROM Kit19Calls(NOLOCK) AS KC INNER JOIN User_Detail(NOLOCK) AS UD
	ON KC.accountcode = UD.User_ID INNER JOIN DiallerCalls(NOLOCK) AS DC
	ON KC.Id = DC.kit19callsid
	WHERE KC.context = 'DialerCalls'

	UNION

	SELECT	A.CallDate, A.callerid, A.dnid, A.recordurl, UD.User_ID, UD.FName + ISNULL(' ' + UD.LName, '') AS [User], A.Disposition, A.CallStatus, 
			A.CallDirection, A.CallPeriod
	FROM 
	( 
		SELECT FORMAT(KC.call_start_time, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate], KC.CallerId, KC.dnid, recordurl = ISNULL(KC.recordurl, ''), 
		Disposition = (CASE WHEN KCD.call_answer_time IS NOT NULL THEN 'ANSWER' ELSE ISNULL(KCD.dialstatus, '') END), 
		CallStatus = CASE WHEN KCD.call_answer_time IS NOT NULL THEN 'CONNECTED' ELSE 'MISSED' END, 
		(CASE KC.context WHEN 'inbound' THEN 'In' WHEN 'outbound' THEN 'Out' ELSE 'In' END) AS CallDirection, 
		CONVERT(VARCHAR(8), DATEADD(SECOND, ISNULL(DATEDIFF(second, KCD.call_answer_time, KCD.call_end_time), 0), '19000101'), 8) AS CallPeriod, 
		AgentNo = replace(KCD.callerid, 'Sip/4862600/', ''), KC.clientid--,*     
		-- Select distinct KC.context     
		FROM Kit19Calls(NOLOCK) AS KC INNER JOIN Kit19CallsDialled(NOLOCK) AS KCD
		ON KC.uniqueid = KCD.puniqueid
		WHERE KC.context != 'DialerCalls' and KCD.callerid like '%Sip/4862600/%'
	) AS A INNER JOIN User_Detail(NOLOCK) AS UD
	ON TRIM(A.AgentNo) = TRIM(STR(UD.mobile)) AND A.clientid = UD.ParentID 
	
	UNION

	SELECT	A.CallDate, A.callerid, A.dnid, A.recordurl, UD.User_ID, UD.FName + ISNULL(' ' + UD.LName, '') AS [User], A.Disposition, A.CallStatus, 
			A.CallDirection, A.CallPeriod
	FROM 
	( 
		SELECT FORMAT(KC.call_start_time, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate], KC.CallerId, KC.dnid, recordurl = ISNULL(KC.recordurl, ''), 
		Disposition = (CASE WHEN KCD.call_answer_time IS NOT NULL THEN 'ANSWER' ELSE ISNULL(KCD.dialstatus, '') END), 
		CallStatus = CASE WHEN KCD.call_answer_time IS NOT NULL THEN 'CONNECTED' ELSE 'MISSED' END, 
		(CASE KC.context WHEN 'inbound' THEN 'In' WHEN 'outbound' THEN 'Out' ELSE 'In' END) AS CallDirection, 
		CONVERT(VARCHAR(8), DATEADD(SECOND, ISNULL(DATEDIFF(second, KCD.call_answer_time, KCD.call_end_time), 0), '19000101'), 8) AS CallPeriod, 
		AgentNo = replace(KCD.callerid, 'Sip/', ''), KC.clientid--,*     
		-- Select distinct KC.context     
		FROM Kit19Calls(NOLOCK) AS KC INNER JOIN Kit19CallsDialled(NOLOCK) AS KCD
		ON KC.uniqueid = KCD.puniqueid
		WHERE KC.context != 'DialerCalls' and KCD.callerid not like '%Sip/4862600/%' and KCD.dialstatus != 'INVALIDARGS'
	) AS A INNER JOIN User_Detail(NOLOCK) AS UD
	ON TRIM(A.AgentNo) = TRIM(STR(UD.User_ID)) AND A.clientid = UD.ParentID 		
	
	) AS tblDetail
	WHERE --User_ID = CASE WHEN @Userid = 0 THEN User_ID ELSE @Userid END
		User_ID in (Select User_Id from User_Detail where User_id = @Userid or ParentID = @Userid)
		AND CONVERT(DATETIME, CONVERT(VARCHAR(11), CallDate, 106)) BETWEEN @Datefrom AND @Dateto
		AND callerid LIKE '%' + CASE WHEN @Callerid = '' THEN callerid ELSE @Callerid END + '%'
		AND dnid = CASE WHEN @Dndid = '' THEN dnid ELSE @Dndid END
	ORDER BY CAST(CallDate AS DATETIME);
    
End 



GO

/* ============================================================
   Procedure: [dbo].[usp_mk_Rep_GetCallhistory_FilterExp]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- exec usp_mk_Rep_GetCallhistory_FilterExp  'a', 32222      
  
CREATE   PROC usp_mk_Rep_GetCallhistory_FilterExp  
(@filterValue VARCHAR(50),   
 @UserId      VARCHAR(50)  
)  
AS  
    BEGIN  
  
        -- declare @UserId bigint=32222, @filterValue VARCHAR(50) = 'a' 
  
  declare @parentid bigint  =  (select ParentID from User_Detail(nolock) ud where ud.User_ID = @UserId)

        SELECT CallDate,   
               callerid,   
               dnid,   
               recordurl,   
               User_ID,   
               [User],   
               ProfilePicturePath,   
               Disposition,   
               CallStatus,   
               CallDirection,   
               CONVERT(VARCHAR(10), CallPeriod, 108) AS CallPeriod,   
               tblDetail.ParentID,   
               PersonName,   
               ProfileImgFileName,   
               LD.ID AS LeadId  
        FROM  
        (  
            SELECT FORMAT(KC.call_start_time, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate],   
                   KC.callerid,   
                   KC.dnid,   
                   recordurl = ISNULL(KC.recordurl, ''),   
                   UD.User_ID,   
                   UD.FName + ISNULL(' ' + UD.LName, '') AS [User],   
                   UD.ProfilePicturePath AS [ProfilePicturePath],   
                   ISNULL(DC.Disposition, '') AS Disposition,   
                   (CASE  
                        WHEN DC.Disposition = 'ANSWER'  
                        THEN 'CONNECTED'  
                        ELSE 'MISSED'  
                    END) AS CallStatus,   
                   (CASE  
                        WHEN KC.context = 'DialerCalls'  
                        THEN 'Out'  
                        ELSE 'In'  
                    END) AS CallDirection,   
                   CallPeriod = CONVERT(VARCHAR(8), DATEADD(SECOND, ISNULL(DATEDIFF(second, DC.call_start_time, DC.call_end_time), 0), '19000101'), 8),   
                   UD.ParentID  
            FROM Kit19Calls(NOLOCK) AS KC  
                 INNER JOIN User_Detail(NOLOCK) AS UD ON KC.accountcode = UD.User_ID  
                 INNER JOIN DiallerCalls(NOLOCK) AS DC ON KC.Id = DC.kit19callsid  
            WHERE KC.context = 'DialerCalls'  
            UNION  
            SELECT A.CallDate,   
                   A.callerid,   
                   A.dnid,   
                   A.recordurl,   
                   UD.User_ID,   
                   UD.FName + ISNULL(' ' + UD.LName, '') AS [User],   
                   UD.ProfilePicturePath AS [ProfilePicturePath],   
                   A.Disposition,   
                   A.CallStatus,   
                   A.CallDirection,   
                   A.CallPeriod,   
                   UD.ParentID  
            FROM  
            (  
                SELECT FORMAT(KC.call_start_time, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate],   
                       KC.CallerId,   
                       KC.dnid,   
                       recordurl = ISNULL(KC.recordurl, ''),   
                       Disposition = (CASE  
                                          WHEN KCD.call_answer_time IS NOT NULL  
                                          THEN 'ANSWER'  
                                          ELSE ISNULL(KCD.dialstatus, '')  
                                      END),   
                       CallStatus = CASE  
                                        WHEN KCD.call_answer_time IS NOT NULL  
                                        THEN 'CONNECTED'  
                                        ELSE 'MISSED'  
                                    END,   
                       (CASE KC.context  
                            WHEN 'inbound'  
                            THEN 'In'  
                            WHEN 'outbound'  
                            THEN 'Out'  
                            ELSE 'In'  
                        END) AS CallDirection,   
                       CONVERT(VARCHAR(8), DATEADD(SECOND, ISNULL(DATEDIFF(second, KCD.call_answer_time, KCD.call_end_time), 0), '19000101'), 8) AS CallPeriod,   
                       --AgentNo = replace(KCD.callerid, 'Sip/4862600/', ''),   
  
        case when isnull(agenttype,'Mobile')='Mobile' then isnull(dbo.fn_trim0prefix(KCD.agentnumber),replace(KCD.callerid, 'Sip/4862600/', '')) else str(u.mobile) end   
                AgentNo ,  
                       KC.clientid--,*                 
                -- Select distinct KC.context               
                FROM Kit19Calls(NOLOCK) AS KC      
                     INNER JOIN Kit19CallsDialled(NOLOCK) AS KCD ON KC.uniqueid = KCD.puniqueid   
      left join user_detail u on u.parentid=KC.clientid and KCD.agentnumber=cast(User_ID as nvarchar)  
                WHERE KC.context != 'DialerCalls' and  kc.clientid=@parentid     
                     -- AND KCD.callerid LIKE '%Sip/4862600/%'     
            ) AS A  
            INNER JOIN User_Detail(NOLOCK) AS UD ON TRIM(A.AgentNo) = TRIM(STR(UD.mobile))  
                                                    AND A.clientid = UD.ParentID  
            UNION  
            SELECT A.CallDate,   
                   A.callerid,   
                   A.dnid,   
                   A.recordurl,   
                   UD.User_ID,   
                   UD.FName + ISNULL(' ' + UD.LName, '') AS [User],   
                   UD.ProfilePicturePath AS [ProfilePicturePath],   
                   A.Disposition,   
                   A.CallStatus,   
                   A.CallDirection,   
                   A.CallPeriod,   
                   UD.ParentID  
            FROM  
            (  
                SELECT FORMAT(KC.call_start_time, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate],   
                       KC.CallerId,   
                       KC.dnid,   
                       recordurl = ISNULL(KC.recordurl, ''),   
                       Disposition = (CASE  
                                          WHEN KCD.call_answer_time IS NOT NULL  
                                          THEN 'ANSWER'  
                                          ELSE ISNULL(KCD.dialstatus, '')  
                                      END),   
                       CallStatus = CASE  
                                        WHEN KCD.call_answer_time IS NOT NULL  
                                        THEN 'CONNECTED'  
                                        ELSE 'MISSED'  
                                    END,   
                       (CASE KC.context  
                            WHEN 'inbound'  
                            THEN 'In'  
                            WHEN 'outbound'  
                            THEN 'Out'  
                            ELSE 'In'  
                        END) AS CallDirection,   
                       CONVERT(VARCHAR(8), DATEADD(SECOND, ISNULL(DATEDIFF(second, KCD.call_answer_time, KCD.call_end_time), 0), '19000101'), 8) AS CallPeriod,   
                       AgentNo = replace(KCD.callerid, 'Sip/', ''),   
                       KC.clientid--,*               
                -- Select distinct KC.context               
                FROM Kit19Calls(NOLOCK) AS KC  
                     INNER JOIN Kit19CallsDialled(NOLOCK) AS KCD ON KC.uniqueid = KCD.puniqueid  
                WHERE KC.context != 'DialerCalls'  
                      AND KCD.callerid NOT LIKE '%Sip/4862600/%'  
                      AND KCD.dialstatus != 'INVALIDARGS'  
            ) AS A  
            INNER JOIN User_Detail(NOLOCK) AS UD ON TRIM(A.AgentNo) = TRIM(STR(UD.User_ID))  
                                                    AND A.clientid = UD.ParentID  
  UNION  
            SELECT FORMAT(DP.CreateOn, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate],   
                  CAST(DP.MobileNo AS NVARCHAR) AS [callerid],   
                   'Sim Call' AS [dnid],   
                   DP.CallRecordPath AS [recordurl],   
                   UD.User_ID AS [User_ID],   
                   UD.FName + ISNULL(' ' + UD.LName, '') AS [User],   
                   UD.ProfilePicturePath,   
                   (CASE  
                        WHEN ISNULL(DP.CallStartDateTime, '') = ''  
                        THEN 'MISSED'  
                        ELSE 'CONNECTED'  
                    END) AS [Disposition],   
                   (CASE  
                        WHEN ISNULL(DP.CallStartDateTime, '') = ''  
                        THEN 'MISSED'  
                        ELSE 'CONNECTED'  
                    END) AS [CallStatus],   
                   'Out' AS CallDirection,   
                   CAST(DP.CallEndDateTime - DP.CallStartDateTime AS TIME) AS [CallPeriod],   
                   UD.ParentID  
            FROM tbl_DailPaidCallDetails DP  
                 INNER JOIN User_Detail UD ON DP.UserId = UD.User_ID  
  
        ) AS tblDetail  
        LEFT JOIN UserLeads LD ON((tblDetail.dnid = LD.MobileNo2  
                                   OR tblDetail.dnid = LD.MobileNo1  
                                   OR tblDetail.dnid = LD.MobileNo)  
                                  AND tblDetail.ParentID = LD.ParentID)  
                                 OR ((tblDetail.callerid = LD.MobileNo2  
                                      OR tblDetail.callerid = LD.MobileNo1  
                                      OR tblDetail.callerid = LD.MobileNo)  
                                     AND tblDetail.ParentID = LD.ParentID)  
        WHERE [User_ID] = @UserId  
              AND ([tblDetail].[callerid] LIKE '%' + @filterValue + '%'  
                   OR [tblDetail].[dnid] LIKE '%' + @filterValue + '%'  
                   OR [tblDetail].[User] LIKE '%' + @filterValue + '%')  
        ORDER BY CAST(CallDate AS DATETIME) DESC;  
    END;


GO

/* ============================================================
   Procedure: [dbo].[usp_mk_Rep_GetCallhistory_modified]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- exec usp_mk_Rep_GetCallhistory_modified 32222, '17-Jul-2020', '30-Jul-2020','',''                    
-- exec usp_mk_Rep_GetCallhistory 34092, '01-Jan-2020', '10-Feb-2020','',''                    
-- exec usp_mk_Rep_GetCallhistory 34093, '01-Jan-2020', '10-Feb-2020','',''                    
-- exec usp_mk_Rep_GetCallhistory 34094, '01-Jan-2020', '10-Feb-2020','',''                    
-- exec usp_mk_Rep_GetCallhistory 34096, '01-Jan-2020', '10-Feb-2020','',''                    
-- exec usp_mk_Rep_GetCallhistory 32222, '01-Dec-2019', '10-Jan-2020','',''                    
-- Exec usp_mk_Rep_GetCallhistory 32222, '01-Jan-2020', '02-Jan-2020'                    
-- Exec usp_mk_Rep_GetCallhistory 32222, '01-Dec-2019', '10-Jan-2020','8447070969',''                  
-- Exec usp_mk_Rep_GetCallhistory 32222, '01-Dec-2019', '10-Dec-2019','','1204862606'                    
-- Exec usp_mk_Rep_GetCallhistory 32222, '01-Dec-2019', '10-Dec-2019','9313943059','1204862606'                    
-- exec usp_mk_Rep_GetCallhistory_modified @UserId=26023,@FromDate=N'06-Feb-2020',@ToDate=N'07-Feb-2020',@CallerId=N'',@DndId=N''                
CREATE   PROC usp_mk_Rep_GetCallhistory_modified        
(@UserId   BIGINT,         
 @FromDate VARCHAR(12) = '',         
 @ToDate   VARCHAR(12) = '',         
 @CallerId VARCHAR(50) = '',         
 @Dndid    VARCHAR(50) = ''        
)        
AS        
    BEGIN        
        
        -- declare @UserId bigint=32226,@FromDate varchar(12)='18-Feb-2021',@ToDate varchar(12)='25-Feb-2021',@CallerId varchar(50)='', @Dndid varchar(50)=''                    
        
  declare @parentid bigint  =  (select ParentID from User_Detail(nolock) ud where ud.User_ID = @UserId)    
    
        DECLARE @Datefrom DATETIME, @Dateto DATETIME;        
        IF(@Fromdate = '')        
            BEGIN        
                SET @Datefrom = '01-Jan-1900';        
        END;        
            ELSE        
            BEGIN        
                SET @Datefrom = @Fromdate;        
        END;        
        IF(@Todate = '')        
            BEGIN        
                SET @Dateto = '31-Jan-2100';        
        END;        
            ELSE        
            BEGIN        
                SET @Dateto = @Todate;        
        END;        
                
  SELECT CallDate,         
        callerid,         
        dnid,         
        recordurl,         
        User_ID,         
        [User],         
        ProfilePicturePath,         
        Disposition,         
        CallStatus,         
        CallDirection,         
        --CAST(ISNULL(CallPeriod, '') AS nvarchar) AS CallPeriod,        
      CONVERT(VARCHAR(10), CallPeriod, 108) AS CallPeriod,        
               tblDetail.ParentID,         
               PersonName,         
               ProfileImgFileName,        
      LD.ID AS LeadId        
        FROM        
        (        
            SELECT FORMAT(KC.call_start_time, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate],         
                   KC.callerid,         
                   KC.dnid,         
                   recordurl = ISNULL(KC.recordurl, ''),         
                   UD.User_ID,         
                   UD.FName + ISNULL(' ' + UD.LName, '') AS [User],         
                   UD.ProfilePicturePath AS [ProfilePicturePath],         
                   ISNULL(DC.Disposition, '') AS Disposition,         
                   (CASE        
                        WHEN DC.Disposition = 'ANSWER'        
                        THEN 'CONNECTED'        
                        ELSE 'MISSED'        
                    END) AS CallStatus,         
                   (CASE        
                        WHEN KC.context = 'DialerCalls'        
                        THEN 'Out'        
                        ELSE 'In'        
                    END) AS CallDirection,         
                   CallPeriod = CONVERT(VARCHAR(8), DATEADD(SECOND, ISNULL(DATEDIFF(second, DC.call_start_time, DC.call_end_time), 0), '19000101'), 8),         
               UD.ParentID        
            FROM Kit19Calls(NOLOCK) AS KC        
                 INNER JOIN User_Detail(NOLOCK) AS UD ON KC.accountcode = UD.User_ID        
                 INNER JOIN DiallerCalls(NOLOCK) AS DC ON KC.Id = DC.kit19callsid        
            WHERE KC.context = 'DialerCalls' and kc.call_start_time between @FromDate and @ToDate and kc.clientid=@parentid        
            UNION        
            SELECT A.CallDate,        
                   A.callerid,         
                   A.dnid,         
                   A.recordurl,         
                   UD.User_ID,         
                   UD.FName + ISNULL(' ' + UD.LName, '') AS [User],         
                   UD.ProfilePicturePath AS [ProfilePicturePath],         
                   A.Disposition,         
                   A.CallStatus,         
                   A.CallDirection,         
                   A.CallPeriod,         
                   UD.ParentID        
            FROM        
            (        
                SELECT FORMAT(KC.call_start_time, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate],         
                       KC.CallerId,         
                       KC.dnid,         
                       recordurl = ISNULL(KC.recordurl, ''),         
                       Disposition = (CASE        
                                          WHEN KCD.call_answer_time IS NOT NULL        
                                          THEN 'ANSWER'        
                                          ELSE ISNULL(KCD.dialstatus, '')        
                                      END),         
                       CallStatus = CASE        
                                        WHEN KCD.call_answer_time IS NOT NULL        
                                        THEN 'CONNECTED'        
                                        ELSE 'MISSED'        
                                    END,         
                       (CASE KC.context        
                            WHEN 'inbound'        
                            THEN 'In'        
                            WHEN 'outbound'        
                            THEN 'Out'        
                            ELSE 'In'        
                        END) AS CallDirection,         
                       CONVERT(VARCHAR(8), DATEADD(SECOND, ISNULL(DATEDIFF(second, KCD.call_answer_time, KCD.call_end_time), 0), '19000101'), 8) AS CallPeriod,         
                       --AgentNo = replace(KCD.callerid, 'Sip/4862600/', ''),     
    
        case when isnull(agenttype,'Mobile')='Mobile' then isnull(dbo.fn_trim0prefix(KCD.agentnumber),replace(KCD.callerid, 'Sip/4862600/', '')) else str(u.mobile) end     
                AgentNo ,    
                       KC.clientid--,*                       
                -- Select distinct KC.context                       
                FROM Kit19Calls(NOLOCK) AS KC        
                     INNER JOIN Kit19CallsDialled(NOLOCK) AS KCD ON KC.uniqueid = KCD.puniqueid     
      left join user_detail u on u.parentid=KC.clientid and KCD.agentnumber=cast(User_ID as nvarchar)    
                WHERE KC.context != 'DialerCalls' and 
				
				--kc.call_start_time between @FromDate and @ToDate and kc.clientid=@parentid       
				kc.call_start_time between cast(@FromDate as datetime) and dateadd(dd,1, cast(@ToDate as datetime)) 
				and kc.clientid=@parentid
                     -- AND KCD.callerid LIKE '%Sip/4862600/%'        
            ) AS A        
            INNER JOIN User_Detail(NOLOCK) AS UD ON TRIM(A.AgentNo) = TRIM(STR(UD.mobile))        
                                                    AND A.clientid = UD.ParentID        
            UNION        
            SELECT A.CallDate,         
                   A.callerid,         
                   A.dnid,         
                   A.recordurl,         
                   UD.User_ID,         
                   UD.FName + ISNULL(' ' + UD.LName, '') AS [User],         
                   UD.ProfilePicturePath AS [ProfilePicturePath],         
                   A.Disposition,         
                   A.CallStatus,         
                   A.CallDirection,         
                A.CallPeriod,         
                   UD.ParentID        
            FROM        
            (        
                SELECT FORMAT(KC.call_start_time, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate],         
                       KC.CallerId,         
                       KC.dnid,      
                       recordurl = ISNULL(KC.recordurl, ''),         
                       Disposition = (CASE        
                                          WHEN KCD.call_answer_time IS NOT NULL        
                                          THEN 'ANSWER'        
                                          ELSE ISNULL(KCD.dialstatus, '')        
                                      END),         
                       CallStatus = CASE        
                                        WHEN KCD.call_answer_time IS NOT NULL        
                                        THEN 'CONNECTED'        
                                        ELSE 'MISSED'        
                                    END,         
                       (CASE KC.context        
                            WHEN 'inbound'        
                            THEN 'In'        
                            WHEN 'outbound'        
                            THEN 'Out'        
                            ELSE 'In'        
                        END) AS CallDirection,         
                       CONVERT(VARCHAR(8), DATEADD(SECOND, ISNULL(DATEDIFF(second, KCD.call_answer_time, KCD.call_end_time), 0), '19000101'), 8) AS CallPeriod,         
                       AgentNo = replace(KCD.callerid, 'Sip/', ''),         
                       KC.clientid--,*             
                -- Select distinct KC.context                       
                FROM Kit19Calls(NOLOCK) AS KC        
                     INNER JOIN Kit19CallsDialled(NOLOCK) AS KCD ON KC.uniqueid = KCD.puniqueid        
                WHERE KC.context != 'DialerCalls'        
                      AND KCD.callerid NOT LIKE '%Sip/4862600/%'        
                      AND KCD.dialstatus != 'INVALIDARGS'       
       and  --kc.call_start_time between @FromDate and @ToDate 
				kc.call_start_time between cast(@FromDate as datetime) and dateadd(dd,1, cast(@ToDate as datetime)) 
	   and kc.clientid=@parentid    
            ) AS A        
            INNER JOIN User_Detail(NOLOCK) AS UD ON TRIM(A.AgentNo) = TRIM(STR(UD.User_ID))        
                                                    AND A.clientid = UD.ParentID        
            UNION        
            SELECT FORMAT(DP.CreateOn, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate],         
                  CAST(DP.MobileNo AS NVARCHAR) AS [callerid],         
                   'Sim Call' AS [dnid],         
                   DP.CallRecordPath AS [recordurl],         
                   UD.User_ID AS [User_ID],         
                   UD.FName + ISNULL(' ' + UD.LName, '') AS [User],         
                   UD.ProfilePicturePath,         
                   (CASE        
                        WHEN ISNULL(DP.CallStartDateTime, '') = ''        
                        THEN 'MISSED'        
                        ELSE 'CONNECTED'        
                    END) AS [Disposition],         
                   (CASE        
                        WHEN ISNULL(DP.CallStartDateTime, '') = ''        
                        THEN 'MISSED'        
                        ELSE 'CONNECTED'        
                    END) AS [CallStatus],         
                   'Out' AS CallDirection,         
                   CAST(DP.CallEndDateTime - DP.CallStartDateTime AS TIME) AS [CallPeriod],         
                   UD.ParentID        
            FROM tbl_DailPaidCallDetails(nolock) DP        
                 INNER JOIN User_Detail(nolock) UD ON DP.UserId = UD.User_ID      
     where -- DP.CreateOn between @FromDate and @ToDate
				DP.CreateOn between cast(@FromDate as datetime) and dateadd(dd,1, cast(@ToDate as datetime)) 
			and Ud.ParentID = @parentid    
        
        ) AS tblDetail        
        LEFT JOIN UserLeads(nolock) LD ON((tblDetail.dnid = LD.MobileNo2 OR tblDetail.dnid = LD.MobileNo1 OR tblDetail.dnid = LD.MobileNo)        
                                  AND tblDetail.ParentID = LD.ParentID)        
                                 OR ((tblDetail.callerid = LD.MobileNo2        
                                      OR tblDetail.callerid = LD.MobileNo1        
                                      OR tblDetail.callerid = LD.MobileNo)        
                                     AND tblDetail.ParentID = LD.ParentID)        
        WHERE --User_ID = CASE WHEN @Userid = 0 THEN User_ID ELSE @Userid END       
        User_ID IN        
        (        
            SELECT User_Id        
            FROM User_Detail(nolock)        
            WHERE User_id = @Userid        
                  OR ParentID = @Userid        
        )        
       AND --CONVERT(DATETIME, CONVERT(VARCHAR(11), CallDate, 106)) BETWEEN @Datefrom AND @Dateto

			CONVERT(DATETIME, CONVERT(VARCHAR(11), CallDate, 106)) between cast(@FromDate as datetime) and dateadd(dd,1, cast(@ToDate as datetime)) 
	   --AND CONVERT(DATETIME, CONVERT(VARCHAR(11), CallDate, 106)) BETWEEN CONVERT(DATETIME, CONVERT(VARCHAR(11),  @Datefrom, 106))
				--AND DATEADD(DD, 1, CONVERT(DATETIME, CONVERT(VARCHAR(11),  @Dateto, 106)))

		--AND CONVERT(VARCHAR(11), CallDate, 106)) between cast(@FromDate as datetime) and dateadd(dd,1, cast(@ToDate as datetime)) 
	   
        AND callerid LIKE '%' + CASE        
                                    WHEN @Callerid = ''        
                                    THEN callerid        
                                    ELSE @Callerid        
                                END + '%'        
        AND dnid LIKE '%' + CASE        
                                WHEN @Dndid = ''        
                                THEN dnid        
                                ELSE @Dndid        
                            END + '%'        
        ORDER BY CAST(CallDate AS DATETIME) DESC;        
    END;  



GO

/* ============================================================
   Procedure: [dbo].[usp_mk_Rep_GetCallhistory_withMode]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--exec usp_mk_Rep_GetCallhistory_withMode 335, '01-Jan-2020', '21-Feb-2020','','','AllCalls'       
--exec usp_mk_Rep_GetCallhistory_withMode 32222, '01-Jan-2020', '21-Feb-2020','','','AllCalls'       
CREATE   PROC usp_mk_Rep_GetCallhistory_withMode  
(          
 @UserId bigint,      
 @FromDate varchar(12)='',      
 @ToDate varchar(12)='',      
 @CallerId varchar(50)='',      
 @Dndid varchar(50)='',     
 @Mode varchar(10)='OtherCalls' -- 'AllCalls'     
)          
as    
Begin    
-- declare @UserId bigint=32198,@FromDate varchar(12)='01-Feb-2020',@ToDate varchar(12)='21-Feb-2020',@CallerId varchar(50)='', @Dndid varchar(50)='', @Mode varchar(10)='AllCalls'  
  
DECLARE @Datefrom DATETIME, @Dateto DATETIME;      
      
 IF(@Fromdate = '')      
 BEGIN      
  SET @Datefrom = '01-Jan-1900';      
 END;      
 ELSE      
 BEGIN      
  SET @Datefrom = @Fromdate;      
 END;      
      
 IF(@Todate = '')      
 BEGIN      
  SET @Dateto = '31-Jan-2100';      
 END;      
 ELSE      
 BEGIN      
  SET @Dateto = @Todate;      
 END;      
      
 if(@Mode = 'OtherCalls')    
 Begin    
    
 SELECT *      
 FROM ( SELECT FORMAT(KC.call_start_time, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate], KC.callerid, KC.dnid, recordurl = ISNULL(KC.recordurl, ''), UD.User_ID, UD.FName + ISNULL(' ' + UD.LName, '') AS [User], ISNULL(DC.Disposition, '') AS Disposition,       
 (CASE WHEN DC.Disposition = 'ANSWER' THEN 'CONNECTED' ELSE 'MISSED' END) AS CallStatus,       
 (CASE WHEN KC.context = 'DialerCalls' THEN 'Out' ELSE 'In' END) AS CallDirection,       
 CallPeriod = CONVERT(VARCHAR(8), DATEADD(SECOND, ISNULL(DATEDIFF(second, DC.call_start_time, DC.call_end_time), 0), '19000101'), 8)--,*      
 FROM Kit19Calls(NOLOCK) AS KC INNER JOIN User_Detail(NOLOCK) AS UD      
 ON KC.accountcode = UD.User_ID INNER JOIN DiallerCalls(NOLOCK) AS DC      
 ON KC.Id = DC.kit19callsid      
 WHERE KC.context = 'DialerCalls' and KC.dnid!='1204759870'  
      
 UNION      
      
 SELECT A.CallDate, A.callerid, A.dnid, A.recordurl, UD.User_ID, UD.FName + ISNULL(' ' + UD.LName, '') AS [User], A.Disposition, A.CallStatus,       
   A.CallDirection, A.CallPeriod      
 FROM       
 (       
  SELECT FORMAT(KC.call_start_time, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate], KC.CallerId, KC.dnid, recordurl = ISNULL(KC.recordurl, ''),       
  Disposition = (CASE WHEN KCD.call_answer_time IS NOT NULL THEN 'ANSWER' ELSE ISNULL(KCD.dialstatus, '') END),       
  CallStatus = CASE WHEN KCD.call_answer_time IS NOT NULL THEN 'CONNECTED' ELSE 'MISSED' END,       
  (CASE KC.context WHEN 'inbound' THEN 'In' WHEN 'outbound' THEN 'Out' ELSE 'In' END) AS CallDirection,       
  CONVERT(VARCHAR(8), DATEADD(SECOND, ISNULL(DATEDIFF(second, KCD.call_answer_time, KCD.call_end_time), 0), '19000101'), 8) AS CallPeriod,       
  AgentNo = replace(KCD.callerid, 'Sip/4862600/', ''), KC.clientid--,*           
  -- Select distinct KC.context           
  FROM Kit19Calls(NOLOCK) AS KC INNER JOIN Kit19CallsDialled(NOLOCK) AS KCD      
  ON KC.uniqueid = KCD.puniqueid      
  WHERE KC.context != 'DialerCalls' and KCD.callerid like '%Sip/4862600/%' and KC.dnid!='1204759870'  
 ) AS A INNER JOIN User_Detail(NOLOCK) AS UD      
 ON TRIM(A.AgentNo) = TRIM(STR(UD.mobile)) AND A.clientid = UD.ParentID       
       
 UNION      
      
 SELECT A.CallDate, A.callerid, A.dnid, A.recordurl, UD.User_ID, UD.FName + ISNULL(' ' + UD.LName, '') AS [User], A.Disposition, A.CallStatus,A.CallDirection, A.CallPeriod FROM       
 (       
  SELECT FORMAT(KC.call_start_time, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate], KC.CallerId, KC.dnid, recordurl = ISNULL(KC.recordurl, ''),       
  Disposition = (CASE WHEN KCD.call_answer_time IS NOT NULL THEN 'ANSWER' ELSE ISNULL(KCD.dialstatus, '') END),       
  CallStatus = CASE WHEN KCD.call_answer_time IS NOT NULL THEN 'CONNECTED' ELSE 'MISSED' END,       
  (CASE KC.context WHEN 'inbound' THEN 'In' WHEN 'outbound' THEN 'Out' ELSE 'In' END) AS CallDirection,       
  CONVERT(VARCHAR(8), DATEADD(SECOND, ISNULL(DATEDIFF(second, KCD.call_answer_time, KCD.call_end_time), 0), '19000101'), 8) AS CallPeriod,       
  AgentNo = case when patindex('%@%',KCD.callerid) > 0 then SUBSTRING(KCD.callerid,patindex('%/%',KCD.callerid)+1,patindex('%@%',KCD.callerid)-patindex('%/%',KCD.callerid)-1) else '0' end, KC.clientid
  FROM Kit19Calls(NOLOCK) AS KC INNER JOIN Kit19CallsDialled(NOLOCK) AS KCD      
  ON KC.uniqueid = KCD.puniqueid      
  WHERE KC.context != 'DialerCalls' and KCD.callerid like '%local/%' and KC.dnid!='1204759870'  
 ) AS A INNER JOIN User_Detail(NOLOCK) AS UD  
 ON A.clientid = UD.ParentID AND TRIM(A.AgentNo) = CASE WHEN LEN(TRIM(A.AgentNo)) = 10 THEN   TRIM(STR(UD.Mobile)) ELSE  TRIM(STR(UD.User_ID)) END
       
  
 UNION      
      
 SELECT A.CallDate, A.callerid, A.dnid, A.recordurl, UD.User_ID, UD.FName + ISNULL(' ' + UD.LName, '') AS [User], A.Disposition, A.CallStatus,       
   A.CallDirection, A.CallPeriod      
 FROM       
 (       
  SELECT FORMAT(KC.call_start_time, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate], KC.CallerId, KC.dnid, recordurl = ISNULL(KC.recordurl, ''),       
  Disposition = (CASE WHEN KCD.call_answer_time IS NOT NULL THEN 'ANSWER' ELSE ISNULL(KCD.dialstatus, '') END),       
  CallStatus = CASE WHEN KCD.call_answer_time IS NOT NULL THEN 'CONNECTED' ELSE 'MISSED' END,       
  (CASE KC.context WHEN 'inbound' THEN 'In' WHEN 'outbound' THEN 'Out' ELSE 'In' END) AS CallDirection,       
  CONVERT(VARCHAR(8), DATEADD(SECOND, ISNULL(DATEDIFF(second, KCD.call_answer_time, KCD.call_end_time), 0), '19000101'), 8) AS CallPeriod,AgentNo = replace(KCD.callerid, 'Sip/', ''), KC.clientid
  FROM Kit19Calls(NOLOCK) AS KC INNER JOIN Kit19CallsDialled(NOLOCK) AS KCD      
  ON KC.uniqueid = KCD.puniqueid      
  WHERE KC.context != 'DialerCalls' and KCD.callerid not like '%Sip/4862600/%' and KCD.callerid not like '%local/%' and KCD.dialstatus != 'INVALIDARGS' and KC.dnid!='1204759870'      
 ) AS A INNER JOIN User_Detail(NOLOCK) AS UD  
 ON TRIM(A.AgentNo) = TRIM(STR(UD.User_ID)) AND A.clientid = UD.ParentID         
       
 ) AS tblDetail      
 WHERE --User_ID = CASE WHEN @Userid = 0 THEN User_ID ELSE @Userid END      
  isnull(User_ID,0) in (Select User_Id from User_Detail where User_id = @Userid or ParentID = @Userid)      
  AND CONVERT(DATETIME, CONVERT(VARCHAR(11), CallDate, 106)) BETWEEN @Datefrom AND @Dateto      
  AND callerid LIKE '%' + CASE WHEN @Callerid = '' THEN callerid ELSE @Callerid END + '%'      
  AND dnid = CASE WHEN @Dndid = '' THEN dnid ELSE @Dndid END      
 ORDER BY CAST(CallDate AS DATETIME) desc;    
    
 end    
     
 else    
 Begin    
-- declare @UserId bigint=26023,@Datefrom varchar(12)='17-Feb-2020',@Dateto varchar(12)='17-Feb-2020',@CallerId varchar(50)='', @Dndid varchar(50)='', @Mode varchar(10)='AllCalls'    
select *  
from   
(  
 select FORMAT(a.call_start_time, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate], a.callerid, a.dnid, a.recordurl, b.user_id,   
  b.FName + ISNULL(' ' + b.LName, '') AS [User], (CASE a.context WHEN 'inbound' THEN 'In' WHEN 'outbound' THEN 'Out' ELSE 'In' END) AS CallDirection,  
  '' as Disposition, '' as CallStatus,'' as CallPeriod--, a.id, a.call_start_time, a.uniqueid, a.channel, a.context, a.clientid, c.AppName as appid,  a.call_end_time , b.user_login            
 --isnull(ul.PersonName,'+''''+''''+') name,            
 --dbo.billduration1 (a.uniqueid) as billduration,             
 --dbo.callstatus1 (a.uniqueid) as callstatus,             
 --dbo.callduration (a.uniqueid) as callduration      
 --isnull(dbo.lastagentattended(a.uniqueid),'+''''+''''+') as AgentUser       
-- select *  
from kit19calls a (nolock) left outer join cloud_app_master (nolock) c   
on  c.AppId=a.appid left join cloud_user_phone(nolock) cu   
on  cu.PhoneNo = isnull(a.clientid,(select case when a.context='outbound' then a.callerid else a.dnid end)) left outer join UserLeads ul (nolock)   
on  isnull(a.clientid,cu.parentid)=ul.ParentID and case when a.context='outbound' and a.dnid in (ul.MobileNo,ul.MobileNo1,ul.MobileNo2) then 1  
               when a.context<>'outbound' and a.callerid in (ul.MobileNo,ul.MobileNo1,ul.MobileNo2) then 1  
               else 0 end=1  
               left join user_detail (NOLOCK) b    
on b.user_id=isnull(a.clientid,cu.parentid)              
--where b.user_id='+cast(@parentid as nvarchar)+' '+case when @ft IS not null and @ft<>'' then @ft else '' end+' order by a.id desc'  
where  a.context = 'DialerCalls'   
   --and b.User_ID = @Userid or b.ParentID = @Userid      
   --AND CONVERT(DATETIME, CONVERT(VARCHAR(11), FORMAT(a.call_start_time, 'dd-MMM-yyyy hh:mm:ss tt'), 106)) BETWEEN @Datefrom AND @Dateto      
   --AND callerid LIKE '%' + CASE WHEN @Callerid = '' THEN callerid ELSE @Callerid END + '%'      
   --AND dnid = CASE WHEN @Dndid = '' THEN dnid ELSE @Dndid END      
  
 UNION  
  
 SELECT A.CallDate, A.callerid, A.dnid, A.recordurl, UD.User_ID, UD.FName + ISNULL(' ' + UD.LName, '') AS [User], A.CallDirection, A.Disposition, A.CallStatus, A.CallPeriod  
 FROM   
 (   
  SELECT FORMAT(KC.call_start_time, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate], KC.CallerId, KC.dnid, recordurl = ISNULL(KC.recordurl, ''),   
  Disposition = (CASE WHEN KCD.call_answer_time IS NOT NULL THEN 'ANSWER' ELSE ISNULL(KCD.dialstatus, '') END),   
  CallStatus = CASE WHEN KCD.call_answer_time IS NOT NULL THEN 'CONNECTED' ELSE 'MISSED' END,   
  (CASE KC.context WHEN 'inbound' THEN 'In' WHEN 'outbound' THEN 'Out' ELSE 'In' END) AS CallDirection,   
  CONVERT(VARCHAR(8), DATEADD(SECOND, ISNULL(DATEDIFF(second, KCD.call_answer_time, KCD.call_end_time), 0), '19000101'), 8) AS CallPeriod,   
  AgentNo = replace(KCD.callerid, 'Sip/4862600/', ''), KC.clientid--,*       
  -- Select distinct KC.context       
  FROM Kit19Calls(NOLOCK) AS KC INNER JOIN Kit19CallsDialled(NOLOCK) AS KCD  
  ON KC.uniqueid = KCD.puniqueid  
  WHERE KC.context != 'DialerCalls' and KCD.callerid like '%Sip/4862600/%' and KC.dnid!='1204759870'  
 ) AS A INNER JOIN User_Detail(NOLOCK) AS UD  
 ON TRIM(A.AgentNo) = TRIM(STR(UD.mobile)) AND A.clientid = UD.ParentID   
   
 UNION  
  
 SELECT A.CallDate, A.callerid, A.dnid, A.recordurl, UD.User_ID, UD.FName + ISNULL(' ' + UD.LName, '') AS [User], A.CallDirection, A.Disposition, A.CallStatus, A.CallPeriod  
 FROM   
 (   
  SELECT FORMAT(KC.call_start_time, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate], KC.CallerId, KC.dnid, recordurl = ISNULL(KC.recordurl, ''),   
  Disposition = (CASE WHEN KCD.call_answer_time IS NOT NULL THEN 'ANSWER' ELSE ISNULL(KCD.dialstatus, '') END),   
  CallStatus = CASE WHEN KCD.call_answer_time IS NOT NULL THEN 'CONNECTED' ELSE 'MISSED' END,   
  (CASE KC.context WHEN 'inbound' THEN 'In' WHEN 'outbound' THEN 'Out' ELSE 'In' END) AS CallDirection,   
  CONVERT(VARCHAR(8), DATEADD(SECOND, ISNULL(DATEDIFF(second, KCD.call_answer_time, KCD.call_end_time), 0), '19000101'), 8) AS CallPeriod,   
  AgentNo = case when patindex('%@%',KCD.callerid)>0 then SUBSTRING(KCD.callerid,patindex('%/%',KCD.callerid)+1,patindex('%@%',KCD.callerid)-patindex('%/%',KCD.callerid)-1) else '0' end, KC.clientid--,*       
  -- Select distinct KC.context       
  FROM Kit19Calls(NOLOCK) AS KC INNER JOIN Kit19CallsDialled(NOLOCK) AS KCD  
  ON KC.uniqueid = KCD.puniqueid  
  WHERE KC.context != 'DialerCalls' and KCD.callerid like '%local/%' and KC.dnid!='1204759870'  
 ) AS A INNER JOIN User_Detail(NOLOCK) AS UD  
 ON  A.clientid = UD.ParentID AND TRIM(A.AgentNo) = CASE WHEN LEN(TRIM(A.AgentNo)) = 10 THEN   TRIM(STR(UD.Mobile)) ELSE  TRIM(STR(UD.User_ID)) END 
 UNION  
  
 SELECT A.CallDate, A.callerid, A.dnid, A.recordurl, UD.User_ID, UD.FName + ISNULL(' ' + UD.LName, '') AS [User],A.CallDirection, A.Disposition,  
 A.CallStatus, A.CallPeriod  
 -- select *  
 FROM   
 (   
  SELECT FORMAT(KC.call_start_time, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate], KC.CallerId, KC.dnid, recordurl = ISNULL(KC.recordurl, ''),   
  Disposition = (CASE WHEN KCD.call_answer_time IS NOT NULL THEN 'ANSWER' ELSE ISNULL(KCD.dialstatus, '') END),   
  CallStatus = CASE WHEN KCD.call_answer_time IS NOT NULL THEN 'CONNECTED' ELSE 'MISSED' END,   
  (CASE KC.context WHEN 'inbound' THEN 'In' WHEN 'outbound' THEN 'Out' ELSE 'In' END) AS CallDirection,   
  CONVERT(VARCHAR(8), DATEADD(SECOND, ISNULL(DATEDIFF(second, KCD.call_answer_time, KCD.call_end_time), 0), '19000101'), 8) AS CallPeriod,   
  AgentNo = replace(KCD.callerid, 'Sip/', ''), KC.clientid--,*       
  -- Select *       
  FROM Kit19Calls(NOLOCK) AS KC INNER JOIN Kit19CallsDialled(NOLOCK) AS KCD  
  ON KC.uniqueid = KCD.puniqueid  
  WHERE KC.context != 'DialerCalls' and KCD.callerid not like '%Sip/4862600/%' and KCD.callerid not like '%local/%' and KCD.dialstatus != 'INVALIDARGS' and KC.dnid!='1204759870'   
 ) AS A left JOIN User_Detail(NOLOCK) AS UD  
 ON TRIM(A.AgentNo) = trim(STR(UD.User_ID)) AND A.clientid = UD.ParentID    
  
) tblAllCalls  
Where  isnull(User_ID,0) in (Select User_Id from User_Detail where User_id = @Userid or ParentID = @Userid)  
  AND CONVERT(DATETIME, CONVERT(VARCHAR(11), CallDate, 106)) BETWEEN @Datefrom AND @Dateto  
  AND callerid LIKE '%' + CASE WHEN @Callerid = '' THEN callerid ELSE @Callerid END + '%'  
  AND dnid = CASE WHEN @Dndid = '' THEN dnid ELSE @Dndid END  
 ORDER BY CAST(CallDate AS DATETIME) desc;  
  
  --ORDER BY CAST(FORMAT(a.call_start_time, 'dd-MMM-yyyy hh:mm:ss tt') AS DATETIME);     
    
 end    
     
End    


