-- select *  
from kit19calls a (nolock) left outer join cloud_app_master (nolock) c   
on  c.AppId=a.appid left join cloud_user_phone(nolock) cu   
on  cu.PhoneNo = isnull(a.clientid,(select case when a.context='outbound' then a.callerid else a.dnid end)) left outer join UserLeads ul (nolock)   
on  isnull(a.clientid,cu.parentid)=ul.ParentID and case when a.context='outbound' and a.dnid in (ul.MobileNo,ul.MobileNo1,ul.MobileNo2) then 1  
               when a.context<>'outbound' and a.callerid in (ul.MobileNo,ul.MobileNo1,ul.MobileNo2) then 1  
               else 0 end=1  
               left join user_detail (NOLOCK) b    
on b.user_id=isnull(a.clientid,cu.parentid)              
--where b.user_id='+cast(@parentid as nvarchar)+' '+case when @ft IS not null and @ft<>'' then @ft else '' end+' order by a.id desc'  
where  a.context = 'DialerCalls'   
   --and b.User_ID = @Userid or b.ParentID = @Userid      
   --AND CONVERT(DATETIME, CONVERT(VARCHAR(11), FORMAT(a.call_start_time, 'dd-MMM-yyyy hh:mm:ss tt'), 106)) BETWEEN @Datefrom AND @Dateto      
   --AND callerid LIKE '%' + CASE WHEN @Callerid = '' THEN callerid ELSE @Callerid END + '%'      
   --AND dnid = CASE WHEN @Dndid = '' THEN dnid ELSE @Dndid END      
  
 UNION  
  
 SELECT A.CallDate, A.callerid, A.dnid, A.recordurl, UD.User_ID, UD.FName + ISNULL(' ' + UD.LName, '') AS [User], A.CallDirection, A.Disposition, A.CallStatus, A.CallPeriod  
 FROM   
 (   
  SELECT FORMAT(KC.call_start_time, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate], KC.CallerId, KC.dnid, recordurl = ISNULL(KC.recordurl, ''),   
  Disposition = (CASE WHEN KCD.call_answer_time IS NOT NULL THEN 'ANSWER' ELSE ISNULL(KCD.dialstatus, '') END),   
  CallStatus = CASE WHEN KCD.call_answer_time IS NOT NULL THEN 'CONNECTED' ELSE 'MISSED' END,   
  (CASE KC.context WHEN 'inbound' THEN 'In' WHEN 'outbound' THEN 'Out' ELSE 'In' END) AS CallDirection,   
  CONVERT(VARCHAR(8), DATEADD(SECOND, ISNULL(DATEDIFF(second, KCD.call_answer_time, KCD.call_end_time), 0), '19000101'), 8) AS CallPeriod,   
  AgentNo = replace(KCD.callerid, 'Sip/4862600/', ''), KC.clientid--,*       
  -- Select distinct KC.context       
  FROM Kit19Calls(NOLOCK) AS KC INNER JOIN Kit19CallsDialled(NOLOCK) AS KCD  
  ON KC.uniqueid = KCD.puniqueid  
  WHERE KC.context != 'DialerCalls' and KCD.callerid like '%Sip/4862600/%' and KC.dnid!='1204759870'  
 ) AS A INNER JOIN User_Detail(NOLOCK) AS UD  
 ON TRIM(A.AgentNo) = TRIM(STR(UD.mobile)) AND A.clientid = UD.ParentID   
   
 UNION  
  
 SELECT A.CallDate, A.callerid, A.dnid, A.recordurl, UD.User_ID, UD.FName + ISNULL(' ' + UD.LName, '') AS [User], A.CallDirection, A.Disposition, A.CallStatus, A.CallPeriod  
 FROM   
 (   
  SELECT FORMAT(KC.call_start_time, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate], KC.CallerId, KC.dnid, recordurl = ISNULL(KC.recordurl, ''),   
  Disposition = (CASE WHEN KCD.call_answer_time IS NOT NULL THEN 'ANSWER' ELSE ISNULL(KCD.dialstatus, '') END),   
  CallStatus = CASE WHEN KCD.call_answer_time IS NOT NULL THEN 'CONNECTED' ELSE 'MISSED' END,   
  (CASE KC.context WHEN 'inbound' THEN 'In' WHEN 'outbound' THEN 'Out' ELSE 'In' END) AS CallDirection,   
  CONVERT(VARCHAR(8), DATEADD(SECOND, ISNULL(DATEDIFF(second, KCD.call_answer_time, KCD.call_end_time), 0), '19000101'), 8) AS CallPeriod,   
  AgentNo = case when patindex('%@%',KCD.callerid)>0 then SUBSTRING(KCD.callerid,patindex('%/%',KCD.callerid)+1,patindex('%@%',KCD.callerid)-patindex('%/%',KCD.callerid)-1) else '0' end, KC.clientid--,*       
  -- Select distinct KC.context       
  FROM Kit19Calls(NOLOCK) AS KC INNER JOIN Kit19CallsDialled(NOLOCK) AS KCD  
  ON KC.uniqueid = KCD.puniqueid  
  WHERE KC.context != 'DialerCalls' and KCD.callerid like '%local/%' and KC.dnid!='1204759870'  
 ) AS A INNER JOIN User_Detail(NOLOCK) AS UD  
 ON  A.clientid = UD.ParentID AND TRIM(A.AgentNo) = CASE WHEN LEN(TRIM(A.AgentNo)) = 10 THEN   TRIM(STR(UD.Mobile)) ELSE  TRIM(STR(UD.User_ID)) END 
 UNION  
  
 SELECT A.CallDate, A.callerid, A.dnid, A.recordurl, UD.User_ID, UD.FName + ISNULL(' ' + UD.LName, '') AS [User],A.CallDirection, A.Disposition,  
 A.CallStatus, A.CallPeriod  
 -- select *  
 FROM   
 (   
  SELECT FORMAT(KC.call_start_time, 'dd-MMM-yyyy hh:mm:ss tt') AS [CallDate], KC.CallerId, KC.dnid, recordurl = ISNULL(KC.recordurl, ''),   
  Disposition = (CASE WHEN KCD.call_answer_time IS NOT NULL THEN 'ANSWER' ELSE ISNULL(KCD.dialstatus, '') END),   
