/* ============================================================
   Procedure: [dbo].[usp_mk_SaveDeviceLocationDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_mk_SaveDeviceLocationDetails    
(    
	@UserName          NVARCHAR(128),       
    @MacAddress        NVARCHAR(500),       
    @Longitude         NVARCHAR(50),       
    @Latitude          NVARCHAR(50),       
    @MeaningfulAddress NVARCHAR(MAX),       
    @Reason            NVARCHAR(MAX) = '', 
	@CreatedOn          NVARCHAR(MAX) = ''  
)    
AS      
BEGIN    
 DECLARE @UserId BIGINT= 0, @BatchNotification_Id bigint, @DeviceId varchar(1000)='', @MessageText nvarchar(max)='';    
              
 SELECT @UserId = USER_ID, @DeviceId=isnull(DeviceId,'')  FROM User_Detail  WHERE User_Login = @UserName;    
       
 if(ISNULL(@CreatedOn, '') = '')  
 begin  
 set @CreatedOn = getdate()  
 end  
    
  
 INSERT INTO RealTimeLocation    
 (UserID,DeviceID,Longitude,Latitude,MeaningfulAddress,Reason,CreatedDate)      
 VALUES (@UserID,@MacAddress,@Longitude,@Latitude,@MeaningfulAddress,@Reason, @CreatedOn);      
    
 If(@DeviceId='' or @DeviceId!=@MacAddress)    
 Begin    
      INSERT INTO [dbo].[MK_BatchNotification]          
     ([Title],[MessageText],[ImageUrl],[ClickActionUrl],[BatchSentTime],[TotalRecords],[ScheduledDate],[TotalProcessed]          
     ,[BatchCompleteTime],[LastBatchProcessed],[IsProcessed],[CutOffTime],[CreatedOn],[CreatedBy])          
    VALUES          
     ('Session Invalid', 'Session Invalid. Please logout from all devices & try again', 'https://www.kit19.com/Kit19New/img/logo.jpg', 'https://modctc.kit19.com/Login', null, 1, GETDATE(), 0, null, null, 0, dateadd(hh,6,getdate()), GETDATE(), @UserID)    
  
      
          
   Select @BatchNotification_Id=SCOPE_IDENTITY()    
          
   INSERT INTO [dbo].[MK_BatchNotificationDetail]          
     ([BatchNotification_Id],[User_ID],[LastAttemptedTime],[Retries],[LastStatus],[IsProcessed],[DeviceId])          
    values (@BatchNotification_Id, @UserID, null, 0, '', 0, @MacAddress)    
 End    
 Else    
 Begin    
  If(@Longitude='0.0' and @Latitude='0.0')    
  Begin    
   INSERT INTO [dbo].[MK_BatchNotification]          
     ([Title],[MessageText],[ImageUrl],[ClickActionUrl],[BatchSentTime],[TotalRecords],[ScheduledDate],[TotalProcessed]          
     ,[BatchCompleteTime],[LastBatchProcessed],[IsProcessed],[CutOffTime],[CreatedOn],[CreatedBy])          
    VALUES          
     ('User not trackable', 'You are not trackable' + case when isnull(@Reason,'') != '' then ' because ' + @Reason else '' end, 'https://www.kit19.com/Kit19New/img/logo.jpg', '', null, 1, GETDATE(), 0, null, null, 0, dateadd(hh,6,getdate()), GETDATE(), @UserID)          
          
   Select @BatchNotification_Id=SCOPE_IDENTITY()    
          
   INSERT INTO [dbo].[MK_BatchNotificationDetail]          
     ([BatchNotification_Id],[User_ID],[LastAttemptedTime],[Retries],[LastStatus],[IsProcessed],[DeviceId])          
    values (@BatchNotification_Id, @UserID, null, 0, '', 0, @DeviceId)    
  End    
 End    
END; 


GO

/* ============================================================
   Procedure: [dbo].[Usp_MK_SaveLocationSetting]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_MK_SaveLocationSetting -- 30928,900,1800,1,1,1,27701          
 (  
 @UserID BIGINT  
 ,@FrequencyUnit NUMERIC(18, 2)  
 ,@Untrackableunit NUMERIC(18, 2)  
 ,@Uninstalled BIT  
 ,@logout BIT  
 ,@Untrackable BIT  
 ,@Createdby BIGINT  
 )  
AS  
BEGIN  
 DECLARE @ID BIGINT  
  
 IF EXISTS (  
   SELECT *  
   FROM tbl_location_setting(NOLOCK)  
   WHERE User_ID = @UserID  
   )  
 BEGIN  
  DELETE  
  FROM tbl_location_setting  
  WHERE User_ID = @UserID  
 END  
  
 INSERT INTO tbl_location_setting (  
  User_ID  
  ,FrequencyUnit  
  ,Uninstalled  
  ,logout  
  ,Untrackable  
  ,Untrackableunit  
  ,Createdby  
  ,CreatedOn  
  )  
 VALUES (  
  @UserID  
  ,@FrequencyUnit  
  ,@Uninstalled  
  ,@logout  
  ,@Untrackable  
  ,@Untrackableunit  
  ,@Createdby  
  ,getdate()  
  )  
  
 SET @ID = SCOPE_IDENTITY()  
  
 INSERT INTO tbl_location_setting_history (  
  User_ID  
  ,STATUS  
  ,Type  
  ,Uninstalled  
  ,logout  
  ,Untrackable  
  ,Untrackableunit  
  ,Createdby  
  ,CreatedOn  
  ,FrequencyUnit  
  )  
 VALUES (  
  @UserID  
  ,1  
  ,'Manual'  
  ,@Uninstalled  
  ,@logout  
  ,@Untrackable  
  ,@Untrackableunit  
  ,@Createdby  
  ,getdate()  
  ,@FrequencyUnit  
  )  
  
 SELECT @ID  
  
 DECLARE @rowJson NVARCHAR(MAX) = (  
   SELECT *  
   FROM tbl_location_setting(NOLOCK)  
   WHERE id = @ID  
   FOR JSON AUTO  
    ,INCLUDE_NULL_VALUES  
   )  
  
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID  
  ,@Activity_type = 'API_Inst_usrlocatn_sttng'  
  ,@ActionType = 'I'  
  ,@RowJson = @rowJson  
  ,@Table_name = 'tbl_location_setting'  
