/* ============================================================
   Procedure: [dbo].[usp_mk_SaveNotificationStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
-- usp_mk_SaveNotificationStatus '1','Read','16-NOV-2019 12:45:00 AM'  
CREATE   PROC usp_mk_SaveNotificationStatus  
(  
    @MsgId bigint,  
    @StatusType nvarchar(10), -- Read,Recvd  
    @ActionDateTime datetime  
)  
AS  
BEGIN  
  
    If exists(select * from MK_BatchNotificationStatus Where BatchNotificationDetail_Id=@MsgId and IsProcessed=1)  
    Begin  
		Update MK_BatchNotificationStatus   
		Set  IsDelivered = case when @StatusType = 'Recvd' then 1 else IsDelivered end,  
		 DeliveredOn = case when @StatusType = 'Recvd' then GETDATE() else DeliveredOn end,  
		 IsRead = case when @StatusType = 'Read' then 1 else IsRead end,  
		 ReadOn = case when @StatusType = 'Read' then GETDATE() else ReadOn end  
		Where BatchNotificationDetail_Id=@MsgId and IsProcessed=1  
    End  

    select @@ROWCOUNT    
END  


GO

