/* ============================================================
   Procedure: [dbo].[usp_mk_send_autonotification]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- exec usp_mk_send_autonotification 32222,'Presence'  
-- exec usp_mk_send_autonotification 32198,'Duty'  
CREATE proc [dbo].[usp_mk_send_autonotification]      
(      
 @User_ID bigint,  
 @event varchar(50),  
 @MiscMsg varchar(1000)=''  
)      
as       
begin      
  
-- declare @User_ID bigint=335, @event varchar(50)='Presence'  
  
 Declare @MgrId bigint = 0, @AdminId bigint= 0, @AgentId bigint= 0, @TerritoryId bigint = 0, @ParentId bigint = 0, @Title varchar(100), @Content varchar(1000),@ImageUrl varchar(1000), @UserName varchar(1000), @status varchar(30), @csvUserId  varchar(max),
 @Role varchar(10)='', @DeviceID nvarchar(1000)='', @AgentDeviceID nvarchar(1000)='', @MgrDeviceID nvarchar(1000)='', @AdminDeviceID nvarchar(1000)=''  
  
 select @ParentId = ParentID,@UserName = FName+' '+LName, @Role = case when IsAdmin=1 then 'Admin' else '' end, @DeviceID=DeviceID  
 from User_Detail (nolock) where User_Id = @User_Id  
  
 If (@Role = '')  
 Begin  
  Select @Role = Role From tbl_location_territory_mapping(nolock) Where User_Id = @User_ID  
 End  
  
 If (@Role = '')  
 Begin  
  print 'user not given any role'  
  return  
 End  
 Else  
 Begin  
  If(@Role = 'Admin')  
  Begin  
   set @AgentId=0  
   set @MgrId=0  
   set @AdminId=@User_ID  
   set @AdminDeviceID=@DeviceID  
  End  
  
  If(@Role = 'Manager')  
  Begin  
   set @AgentId=0  
   set @MgrId=@User_ID  
   set @MgrDeviceID=@DeviceID  
  
   select @AdminId=User_Id, @AdminDeviceID=DeviceID from User_detail(nolock) Where IsAdmin=1 and ParentID=@ParentId  
  End  
  
  If(@Role = 'User')  
  Begin  
   set @AgentId=@User_ID  
   set @AgentDeviceID=@DeviceID  
  
   Select @MgrId=ltm.User_ID, @MgrDeviceID=UD.DeviceID  
   from tbl_location_territory_mapping(nolock) ltm inner join User_Detail(nolock) UD  
   on  ltm.User_ID = UD.User_ID  
   where ltm.Territory_Id in (select ltm1.Territory_Id from tbl_location_territory_mapping(nolock) ltm1 where ltm1.User_ID = @User_ID) and Role = 'Manager'  
  
   select @AdminId=User_Id, @AdminDeviceID=DeviceID from User_detail(nolock) Where IsAdmin=1 and ParentID=@ParentId  
  End  
 End  
  
  
 --if exists (select * from tbl_location_territory_mapping (nolock) where User_Id = @User_ID and Role = 'User')      
 --begin      
 -- set @TerritoryId = (select top 1 Territory_Id from  tbl_location_territory_mapping (nolock) where User_Id = @User_ID and Role = 'User')      
 -- set @MgrId  = (Select top 1 User_ID  from tbl_location_territory_mapping (nolock) where Territory_Id = @TerritoryId and Role = 'Manager')      
 --end      
      
 if exists(select * from tbl_auto_notification(nolock) where  ParentId = @ParentId)  
 Begin  
  Select @Title = MessageTitle, @Content = MessageContent, @ImageUrl = ImageURL      
  from tbl_auto_notification (nolock) where  ParentId = @ParentId and Event like '%' + @event + '%'      
    End  
 Else  
 Begin  
  Select @Title = MessageTitle, @Content = MessageContent, @ImageUrl = ImageURL      
  from tbl_auto_notification (nolock) where IsPredefined=1 and Event like '%' + @event + '%'      
    End  
      
 If(isnull(@Content,'') = '')  
 Begin  
  print 'No Matching Notification Template Found'  
  return  
 End  
  
 set @Content = REPLACE(@Content,'#Agent.Name#',@UserName)      
      
 if (@event = 'Field')      
 begin      
  if (select count(*) from User_Detail (nolock) where User_Id = @User_Id and OnField = 1) > 0      
  begin      
   set @status = 'On'      
  end      
  else      
  begin      
   set @status = 'Off'      
  end      
  
  set @Content = REPLACE(@Content,'#field.Status#',@status)      
 end      
      
 if (@event = 'Duty')      
 begin      
  if (select count(*) from User_Detail (nolock) where User_Id = @User_Id and onduty = 1) > 0      
  begin      
   set @status = 'On'      
  end      
  else      
  begin      
   set @status = 'Off'      
  end      
  
  set @Content = REPLACE(@Content,'#duty.Status#',@status)      
 end      
      
 if (@event = 'trackable')      
 begin      
  set @status = ''      
  
  select @status=Cast(isnull(Untrackableunit,0) as varchar(50)) from tbl_location_setting (nolock) where User_Id = @User_Id    
  set @status=case when @status != '' then @status + ' seconds' else '' end  
  set @Content = REPLACE(@Content,'#User.Nontrackabletime#',@status)      
 end      
  
 if (@event = 'Call')      
 begin      
  set @status = ''      
  
  If(patindex('%,%',@MiscMsg) > 0)  
  Begin  
   set @Content = REPLACE(REPLACE(@Content,'#Call.Number#', left(@MiscMsg,patindex('%,%',@MiscMsg))), ',', '')      
   set @Content = REPLACE(REPLACE(@Content,'#Call.Time#', substring(@MiscMsg,patindex('%,%',@MiscMsg),len(@MiscMsg))), ',', '')  
  End  
  
 end      
      
 --if (@event = 'Presence')      
 --begin      
 -- if (select count(*) from User_Detail (nolock) where User_Id = @User_Id and Presence = 1) > 0      
 -- begin      
 --  set @status = 'On'      
 -- end      
 -- else      
 -- begin      
 --  set @status = 'Off'      
 -- end      
  
 -- set @Content = REPLACE(@Content,'#presence.Status#',@status)      
 --end      
    print @Content  
  
 if (@AdminId > 0 and len(isnull(@AdminDeviceID,'')) > 20)      
 begin      
  set @csvUserId =  cast(@AdminId as varchar)-- +','      
 end      
      
 if (@MgrId > 0 and len(isnull(@MgrDeviceID,'')) > 20)      
 begin      
  set @csvUserId =  isnull(@csvUserId+',','')+cast(@MgrId as varchar)     
 end      
      
 if (@AgentId > 0 and len(isnull(@AgentDeviceID,'')) > 20)  
 begin  
  set @csvUserId = isnull(@csvUserId+',','')+cast(@AgentId as varchar)  
 end  
      
 Declare @TotalRecords int=0, @BatchNotification_Id bigint=0            
            
    select @TotalRecords=Count(*) from dbo.fn_Split(@csvUserId,',')            
            
 If (@TotalRecords > 0)  
 Begin  
  INSERT INTO [dbo].[MK_BatchNotification]            
    ([Title],[MessageText],[ImageUrl],[ClickActionUrl],[BatchSentTime],[TotalRecords],[ScheduledDate],[TotalProcessed]            
    ,[BatchCompleteTime],[LastBatchProcessed],[IsProcessed],[CutOffTime],[CreatedOn],[CreatedBy])            
   VALUES            
    (@Title, @Content, @ImageUrl, ''/*@ImageUrl*/, null, @TotalRecords, GETDATE(), 0            
    , null, null, 0, dateadd(hh,6,GETDATE()), GETDATE(), @ParentId)            
            
  Select @BatchNotification_Id=SCOPE_IDENTITY()            
            
  INSERT INTO [dbo].[MK_BatchNotificationDetail]            
    ([BatchNotification_Id],[User_ID],[LastAttemptedTime],[Retries],[LastStatus],[IsProcessed])            
   Select @BatchNotification_Id, [value], null, 0, '', 0            
   From  dbo.fn_Split(@csvUserId,',')        
    End  
  
end    


GO

