/* ============================================================
   Procedure: [dbo].[usp_MK_SetBatchNotificationEndTime]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROC usp_MK_SetBatchNotificationEndTime  
(  
    @BatchNotification_Id bigint,  
    @BatchCompleteTime datetime,  
    @TotalProcessed int,  
    @IsProcessed bit  
)  
AS  
BEGIN  
    Update  [MK_BatchNotification] 
	Set BatchCompleteTime=@BatchCompleteTime, LastBatchProcessed=@BatchCompleteTime, 
		TotalProcessed+=@TotalProcessed, IsProcessed=@IsProcessed  
    Where   BatchNotification_Id=@BatchNotification_Id  
END  


