/* ============================================================
   Procedure: [dbo].[usp_mk_tsk_GetTaskDetailById]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
  
-- exec usp_mk_tsk_GetTaskDetailById  5          
CREATE   PROCEDURE [dbo].[usp_mk_tsk_GetTaskDetailById]  
 @Id bigint,  
 @UserId bigint = 0  
AS        
BEGIN        
        
  --declare @Id BIGINT = 25947    
  --exec MySMS.dbo.usp_mk_tsk_GetTaskDetailById 27388  
  
  declare @ParentId bigint, @CreatedBy bigint, @TaskId bigint  
  
  select @TaskId = TaskId, @CreatedBy = CreatedBy from tbl_tsk_TaskHistory(nolock) where Id = @Id  
  select @ParentId = ParentID from User_Detail(nolock) where User_ID = @CreatedBy  
    
  SELECT O.OutcomeName, T.Id,  
		T.Title,  
		isnull(T.Description, '') as Description,  
		T.Address,  
		T.StartDate,  
		T.EndDate,  
		T.LeadId,  
		T.AssignedTo, 
		concat(trim(ow.FName), ' ', TRIM(ow.LName), ' (', ow.User_Login, ')') as [OwnerName],
		T.IsActive,  
		T.CreatedOn,  
		T.TaskId,  
		T.CreatedBy,  
		T.OutcomesId,  
		T.Status,  
		T.IsTask,  
		T.IsAppointment,  
		T.TaskType,  
		T.CompletedOn,  
		T.CompleteAddress,  
		T.Latitude,  
		T.Longitude,  
		T.SmsBatchId,  
		T.EmailBatchId,  
		T.UpdatedOn,  
		T.Remarks,  
		T.gCalendarId,  
		T.task_deletedOn,   
		 IIF(@UserId = T.AssignedTo, 1, ISNULL(utm.has_edit, 0)) AS hasEdit,   
		 IIF(@UserId = T.AssignedTo, 1, ISNULL(utm.has_view, 1)) AS hasView,   
		 IIF(@UserId = T.AssignedTo, 1, ISNULL(utm.has_remove, 0)) AS hasRemove,   
		 IIF(@UserId = T.AssignedTo, 1, ISNULL(utm.has_completion, 0)) AS hasCompletion,   
		 IIF(@UserId = T.AssignedTo, 1, ISNULL(utm.has_comment, 1)) AS hasComment
 FROM tbl_tsk_TaskHistory(nolock) AS T
	left join User_Detail(nolock) ow on T.AssignedTo = ow.User_ID
  left join tbl_tsk_UserOutcomeMaster (nolock) AS O on T.OutcomesId = O.Id    
  left join tbl_tsk_TaskActionPermission(nolock) utm on t.TaskId = utm.task_type_id and parent_id = @ParentId  
   WHERE T.Id = @Id;      
    
                
  SELECT CUM.Id, CUM.User_Id, CUM.CreatedOn, CUM.CreatedBy, CUM.TaskHistoryId, CUM.DeletedOn, (UD.FName+' '+UD.LName) AS PersonName        
        FROM tbl_tsk_CollaborationUserMapping  CUM INNER JOIN user_detail UD ON CUM.User_Id = UD.User_ID        
        WHERE TaskHistoryId = @Id;        
                
  SELECT Id AS LeadId, PersonName, ProfileImgFileName, ParentID FROM UserLeads        
        WHERE ID IN        
        (        
            SELECT LeadId        
            FROM tbl_tsk_TaskHistory(nolock)     
            WHERE Id = @Id        
        );        
                
  IF EXISTS        
        (        
            SELECT *        
            FROM tbl_tsk_TaskOutcomeMapping(nolock)      
            WHERE TaskId = @TaskId        
        )        
            BEGIN        
                SELECT UOM.Id,         
                       UOM.OutcomeName        
                FROM tbl_tsk_TaskOutcomeMapping(nolock) AS TOM        
                     INNER JOIN tbl_tsk_UserOutcomeMaster(nolock) AS UOM ON TOM.OutcomesId = UOM.Id        
                WHERE TaskId = @TaskId;        
        END;        
            ELSE        
            BEGIN        
                BEGIN        
                    SELECT Id,         
                           OutcomeName        
                    FROM tbl_tsk_UserOutcomeMaster(nolock)    
                    WHERE IsPredefined = 1;        
        END;        
    END;        
END;  



