/* ============================================================
   Procedure: [dbo].[usp_mk_tsk_GetTaskTypeByMode]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_mk_tsk_GetTaskTypeByMode    
 @UserId bigint,    
 @Mode nvarchar(50) = 'task'    
AS          
begin         
         
 --declare     
 -- @UserId bigint = 34594,    
 -- @Mode nvarchar(50) = 'task'  
    
 declare @ParentId bigint = 0          
 select @ParentId = ParentID FROM User_Detail(NOLOCK) UD where UD.User_ID = @UserId          
          
 select * from  tbl_tsk_UserTaskMaster(nolock)     
  where IsDeleted <> 1  and  1 = (case     
   when IsPredefined = 1   
 and TaskType in (select [value] from string_split(@Mode, ',')) then 1    
   when ParentId = @ParentId and IsPredefined = 0   
 and TaskType in (select [value] from string_split(@Mode, ',')) then 1    
   else 0 end     
  )    
  
end   


