/* ============================================================
   Procedure: [dbo].[usp_mk_tsk_GetUserTaskListByUserId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--dbo.usp_mk_tsk_GetUserTaskListByUserId 32222  
CREATE   PROCEDURE dbo.usp_mk_tsk_GetUserTaskListByUserId @UserId BIGINT
AS
BEGIN
	DECLARE @ParentId BIGINT = 0

	SELECT @ParentId = ParentID
	FROM User_Detail UD
	WHERE UD.User_ID = @UserId

	--SELECT * FROM tbl_tsk_UserTaskMaster(nolock) WHERE IsPredefined = 1    
	--UNION    
	--SELECT * FROM tbl_tsk_UserTaskMaster(nolock) WHERE ParentId = @ParentId and IsPredefined = 0    
	SELECT *
	FROM tbl_tsk_UserTaskMaster(NOLOCK)
	WHERE IsDeleted <> 1
		AND (
			(
				ParentId = @ParentId
				AND IsPredefined = 0
				)
			OR (IsPredefined = 1)
			)

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_Id = @UserId
		,@Activity_type = 'View_UsrTskActvty_Sttng'
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'tbl_tsk_UserTaskMaster'
END



