/* ============================================================
   Procedure: [dbo].[usp_mk_tsk_InsertNewActivity]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_mk_tsk_InsertNewActivity] @ActivityId BIGINT  
 ,@ActivityName VARCHAR(255)  
 ,@IconClass VARCHAR(255)  
 ,@ParentId BIGINT  
 ,@CreatedBy BIGINT  
 ,@hasView BIT = 1  
 ,@hasEdit BIT = 0  
 ,@hasRemove BIT = 0  
 ,@hasCompletion BIT = 0  
 ,@hasComment BIT = 1  
 ,@HasviewLead bit =0
 ,@HaseditLead bit =0
 ,@OutcomeList TSK_OUTCOME_LIST READONLY  
AS  
BEGIN  
 DECLARE @message NVARCHAR(max) = 'exists'  
  ,@activity VARCHAR(MAX) = ''  
  ,@action VARCHAR(1)  
  
 IF (@ActivityId > 0)  
 BEGIN  
  UPDATE tbl_tsk_UserTaskMaster  
  SET TasKName = @ActivityName  
   ,IconClass = @IconClass  
  WHERE Id = @ActivityId  
  
  SET @message = 'updated'  
  SET @action = 'U'  
  SET @activity = 'Updt_TskActvty_Settng'  
 END  
  
 DECLARE @TaskId BIGINT = 0;  
  
 IF (  
   NOT EXISTS (  
    SELECT *  
    FROM tbl_tsk_UserTaskMaster  
    WHERE (  
      IsPredefined = 1  
      OR ParentId = @ParentId  
      )  
     AND TasKName = @ActivityName  
    )  
   )  
 BEGIN  
  INSERT INTO tbl_tsk_UserTaskMaster (  
   TasKName  
   ,IconClass  
   ,ParentId  
   ,IsDeleted  
   ,IsPredefined  
   ,CreatedOn  
   ,CreatedBy
   ,tasktype
   )  
  VALUES (  
   @ActivityName  
   ,@IconClass  
   ,@ParentId  
   ,0  
   ,0  
   ,GETDATE()  
   ,@CreatedBy  
   ,'task'
   );  
  
  SET @TaskId = SCOPE_IDENTITY();  
  SET @message = 'inserted'  
  SET @action = 'I'  
  SET @activity = 'Inst_TskActvty_Settng'  
 END;  
 ELSE  
 BEGIN  
  --SELECT @TaskId = Id FROM tbl_tsk_UserTaskMaster  WHERE ( IsPredefined = 1 OR ParentId = @ParentId ) AND  TasKName = @ActivityName;        
  SET @TaskId = @ActivityId  
 END;  
  
 IF (@TaskId > 0)  
 BEGIN  
  DECLARE @OutcomeCount INT = 0;  
  
  SELECT @OutcomeCount = COUNT(*)  
  FROM @OutcomeList;  
  
  IF (@OutcomeCount > 0)  
  BEGIN  
   DECLARE @OutcomeName VARCHAR(50)  
    ,@Sequence INT  
    ,@Indent VARCHAR(50);  
  
   --delete old mapping  
   DELETE  
   FROM tbl_tsk_TaskOutcomeMapping  
   WHERE TaskId = @TaskId  
    AND CreatedBy = @CreatedBy  
  
   WHILE (@OutcomeCount > 0)  
   BEGIN  
    SELECT @OutcomeName = LTRIM(RTRIM(Name))  
     ,@Sequence = Sequence  
     ,@Indent = Indent  
    FROM @OutcomeList  
    WHERE Id = @OutcomeCount;  
  
    DECLARE @UserOutcomeMasterId BIGINT = 0;  
  
    IF (  
      EXISTS (  
       SELECT *  
       FROM tbl_tsk_UserOutcomeMaster  
       WHERE IsPredefined = 1  
        AND LTRIM(RTRIM(OutcomeName)) = @OutcomeName  
        AND indent = @Indent  
       )  
      )  
    BEGIN  
     SELECT @UserOutcomeMasterId = Id  
     FROM tbl_tsk_UserOutcomeMaster  
     WHERE IsPredefined = 1  
      AND LTRIM(RTRIM(OutcomeName)) = @OutcomeName  
      AND Indent = @Indent;  
    END;  
    ELSE IF (  
      EXISTS (  
       SELECT *  
       FROM tbl_tsk_UserOutcomeMaster  
       WHERE ParentId = @ParentId  
        AND LTRIM(RTRIM(OutcomeName)) = @OutcomeName  
       )  
      )  
    BEGIN  
     SELECT @UserOutcomeMasterId = Id  
     FROM tbl_tsk_UserOutcomeMaster  
     WHERE ParentId = @ParentId  
      AND LTRIM(RTRIM(OutcomeName)) = @OutcomeName;  
    END;  
    ELSE  
    BEGIN  
     INSERT INTO tbl_tsk_UserOutcomeMaster (  
      OutcomeName  
      ,ParentId  
      ,IsDeleted  
      ,IsPredefined  
      ,CreatedOn  
      ,CreatedBy  
      ,Indent  
      )  
     VALUES (  
      @OutcomeName  
      ,@ParentId  
      ,0  
      ,0  
      ,GETDATE()  
      ,@CreatedBy  
      ,@Indent  
      );  
  
     SET @UserOutcomeMasterId = SCOPE_IDENTITY();  
    END;  
  
    PRINT str(@UserOutcomeMasterId) + ' : sq : ' + str(@Sequence)  
  
    IF (@UserOutcomeMasterId > 0)  
    BEGIN  
     IF (  
       NOT EXISTS (  
        SELECT 1  
        FROM tbl_tsk_TaskOutcomeMapping  
        WHERE TaskId = @TaskId  
         AND OutcomesId = @UserOutcomeMasterId  
        )  
       )  
     BEGIN  
      INSERT INTO tbl_tsk_TaskOutcomeMapping (  
       TaskId  
       ,OutcomesId  
       ,[Sequence]  
       ,CreatedOn  
       ,CreatedBy  
       ,ParentId  
       )  
      VALUES (  
       @TaskId  
       ,@UserOutcomeMasterId  
       ,@Sequence  
       ,GETDATE()  
       ,@CreatedBy  
       ,@ParentId  
       );  
     END;  
     ELSE  
     BEGIN  
      UPDATE tbl_tsk_TaskOutcomeMapping  
      SET [Sequence] = @Sequence  
      WHERE TaskId = @TaskId  
       AND OutcomesId = @UserOutcomeMasterId  
       --select * from tbl_tsk_TaskOutcomeMapping where TaskId = @TaskId and OutcomesId = @UserOutcomeMasterId      
     END  
  
     SET @OutcomeCount = @OutcomeCount - 1;  
    END  
   END;  
  
   IF (  
     EXISTS (  
      SELECT *  
      FROM tbl_tsk_TaskActionPermission(NOLOCK)  
      WHERE task_type_id = @TaskId  
       AND parent_id = @ParentId  
      )  
     )  
   BEGIN  
    UPDATE tbl_tsk_TaskActionPermission  
    SET has_view = @hasView  
     ,has_edit = @hasEdit  
     ,has_remove = @hasRemove  
     ,has_completion = @hasCompletion  
     ,has_comment = @hasComment,   
	Has_viewLead=@HasviewLead,
	Has_editLead=@HaseditLead
    WHERE task_type_id = @TaskId  
     AND parent_id = @ParentId  
   END  
   ELSE  
   BEGIN  
    INSERT INTO tbl_tsk_TaskActionPermission (  
     has_view  
     ,has_edit  
     ,has_remove  
     ,has_completion  
     ,has_comment
	 ,Has_viewLead
	 ,Has_editLead
     ,task_type_id  
     ,parent_id  
     )  
    VALUES (  
     @hasView  
     ,@hasEdit  
     ,@hasRemove  
     ,@hasCompletion  
     ,@hasComment  
	 ,@HasviewLead
	 ,@HaseditLead
     ,@TaskId  
     ,@ParentId  
     )  
   END  
  END  
 END  
  
 SELECT @message  
  
 DECLARE @rowJson VARCHAR(MAX) = (  
   SELECT *  
   FROM tbl_tsk_UserTaskMaster(NOLOCK)  
   WHERE id = @TaskId  
   FOR JSON AUTO  
    ,INCLUDE_NULL_VALUES  
   )  
  
 IF @rowJson IS NOT NULL  
 BEGIN  
  EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @CreatedBy  
   ,@Activity_type = @activity  
   ,@ActionType = @action  
   ,@RowJson = @rowJson  
   ,@Table_name = 'tbl_tsk_UserTaskMaster'  
 END  
END;  


GO

/* ============================================================
   Procedure: [dbo].[usp_mk_tsk_InsertNewActivityCF]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_mk_tsk_InsertNewActivityCF] 
	 @ActivityId BIGINT
	,@ActivityName VARCHAR(255)
	,@IconClass VARCHAR(255)
	,@ParentId BIGINT
	,@CreatedBy BIGINT
	,@OutcomeList TSK_OUTCOME_LIST READONLY
	,@UserActionList TSK_UserAction_List READONLY
AS
BEGIN
	DECLARE @message NVARCHAR(max) = 'exists'
		,@activity VARCHAR(MAX) = ''
		,@action VARCHAR(1)

	IF (@ActivityId > 0)
	BEGIN
		UPDATE tbl_tsk_UserTaskMaster
		SET TasKName = @ActivityName
			,IconClass = @IconClass
		WHERE Id = @ActivityId

		SET @message = 'updated'
		SET @action = 'U'
		SET @activity = 'Updt_TskActvty_Settng'
	END

	DECLARE @TaskId BIGINT = 0;

	IF (NOT EXISTS (SELECT *
				FROM tbl_tsk_UserTaskMaster(nolock)
				WHERE (IsPredefined = 1
						OR ParentId = @ParentId)
					AND TasKName = @ActivityName and TaskType = 'PhysicalMeeting'
				))
	BEGIN
		INSERT INTO tbl_tsk_UserTaskMaster (
			TasKName
			,IconClass
			,ParentId
			,IsDeleted
			,IsPredefined
			,CreatedOn
			,CreatedBy
			,TaskType
			)
		VALUES (
			@ActivityName
			,@IconClass
			,@ParentId
			,0
			,0
			,GETDATE()
			,@CreatedBy
			,'PhysicalMeeting'
			);

		SET @TaskId = SCOPE_IDENTITY();
		SET @message = 'inserted'
		SET @action = 'I'
		SET @activity = 'Inst_TskActvty_Settng'
	END;
	ELSE
	BEGIN
		--SELECT @TaskId = Id FROM tbl_tsk_UserTaskMaster  WHERE ( IsPredefined = 1 OR ParentId = @ParentId ) AND  TasKName = @ActivityName;      
		SET @TaskId = @ActivityId
	END;

	IF (@TaskId > 0)
	BEGIN
		DECLARE @OutcomeCount INT = 0;

		SELECT @OutcomeCount = COUNT(*)
		FROM @OutcomeList;

		IF (@OutcomeCount > 0)
		BEGIN
			DECLARE @OutcomeName VARCHAR(50)
				,@Sequence INT
				,@Indent VARCHAR(50);

			--delete old mapping
			DELETE
			FROM tbl_tsk_TaskOutcomeMapping
			WHERE TaskId = @TaskId
				AND CreatedBy = @CreatedBy

			WHILE (@OutcomeCount > 0)
			BEGIN
				SELECT @OutcomeName = LTRIM(RTRIM(Name))
					,@Sequence = Sequence
					,@Indent = Indent
				FROM @OutcomeList
				WHERE Id = @OutcomeCount;

				DECLARE @UserOutcomeMasterId BIGINT = 0;

				IF (
						EXISTS (
							SELECT *
							FROM tbl_tsk_UserOutcomeMaster(nolock)
							WHERE IsPredefined = 1
								AND LTRIM(RTRIM(OutcomeName)) = @OutcomeName
								AND indent = @Indent
							)
						)
				BEGIN
					SELECT @UserOutcomeMasterId = Id
					FROM tbl_tsk_UserOutcomeMaster(nolock)
					WHERE IsPredefined = 1
						AND LTRIM(RTRIM(OutcomeName)) = @OutcomeName
						AND Indent = @Indent;
				END;
				ELSE IF (
						EXISTS (
							SELECT *
							FROM tbl_tsk_UserOutcomeMaster(nolock)
							WHERE ParentId = @ParentId
								AND LTRIM(RTRIM(OutcomeName)) = @OutcomeName
							)
						)
				BEGIN
					SELECT @UserOutcomeMasterId = Id
					FROM tbl_tsk_UserOutcomeMaster(nolock)
					WHERE ParentId = @ParentId
						AND LTRIM(RTRIM(OutcomeName)) = @OutcomeName;
				END;
				ELSE
				BEGIN
					INSERT INTO tbl_tsk_UserOutcomeMaster (
						OutcomeName
						,ParentId
						,IsDeleted
						,IsPredefined
						,CreatedOn
						,CreatedBy
						,Indent
						)
					VALUES (
						@OutcomeName
						,@ParentId
						,0
						,0
						,GETDATE()
						,@CreatedBy
						,@Indent
						);

					SET @UserOutcomeMasterId = SCOPE_IDENTITY();
				END;

				PRINT str(@UserOutcomeMasterId) + ' : sq : ' + str(@Sequence)

				IF (@UserOutcomeMasterId > 0)
				BEGIN
					IF (NOT EXISTS (
								SELECT 1
								FROM tbl_tsk_TaskOutcomeMapping(nolock)
								WHERE TaskId = @TaskId
									AND OutcomesId = @UserOutcomeMasterId
								)
							)
					BEGIN
						INSERT INTO tbl_tsk_TaskOutcomeMapping (
							TaskId
							,OutcomesId
							,[Sequence]
							,CreatedOn
							,CreatedBy
							,ParentId
							)
						VALUES (
							@TaskId
							,@UserOutcomeMasterId
							,@Sequence
							,GETDATE()
							,@CreatedBy
							,@ParentId
							);
					END;
					ELSE
					BEGIN
						UPDATE tbl_tsk_TaskOutcomeMapping
						SET [Sequence] = @Sequence
						WHERE TaskId = @TaskId
							AND OutcomesId = @UserOutcomeMasterId
							--select * from tbl_tsk_TaskOutcomeMapping where TaskId = @TaskId and OutcomesId = @UserOutcomeMasterId    
					END

					SET @OutcomeCount = @OutcomeCount - 1;
				END
			END;

		DECLARE @ActionCount INT = 0;

		SELECT @ActionCount = COUNT(*) FROM @UserActionList;

		IF (@ActionCount > 0)
		Begin

		IF (EXISTS ( SELECT userType FROM @UserActionList where userType = 'Collaborator'))
		Begin
		IF (EXISTS (SELECT * FROM tbl_tsk_TaskActionPermission(NOLOCK) WHERE task_type_id = @TaskId AND parent_id = @ParentId))
			BEGIN
		Declare @hasView bit = 1,@hasEdit bit = 0 ,@hasRemove bit = 0, @hasCompletion bit = 0, @hasComment bit = 0 
		
		SELECT @hasView = hasView, @hasEdit = hasEdit, @hasRemove = hasRemove, @hasCompletion = hasCompletion, @hasComment = hasComment FROM @UserActionList where userType = 'Collaborator'

				UPDATE tbl_tsk_TaskActionPermission
				SET has_view = @hasView
					,has_edit = @hasEdit
					,has_remove = @hasRemove
					,has_completion = @hasCompletion
					,has_comment = @hasComment
				WHERE task_type_id = @TaskId
					AND parent_id = @ParentId
			END
			ELSE
			BEGIN
				INSERT INTO tbl_tsk_TaskActionPermission (has_view
					,has_edit
					,has_remove
					,has_completion
					,has_comment
					,task_type_id
					,parent_id
					)
		SELECT hasView
					,hasEdit
					,hasRemove
					,hasCompletion
					,hasComment
					,@TaskId
					,@ParentId FROM @UserActionList where userType = 'Collaborator'

			END
		END
		
		IF (EXISTS ( SELECT userType FROM @UserActionList where userType = 'FieldExecutive'))
		Begin
		IF (EXISTS (SELECT * FROM TBL_ET_PhyApptTypeFieldExecutivePermission(NOLOCK) WHERE task_type_id = @TaskId AND parent_id = @ParentId))
			BEGIN
			Declare @hasView2 bit = 1,@hasEdit2 bit = 0 ,@hasRemove2 bit = 0, @hasCompletion2 bit = 0, @hasComment2 bit = 0 
		SELECT @hasView2 = hasView, @hasEdit2 = hasEdit, @hasRemove2 = hasRemove, @hasCompletion2 = hasCompletion, @hasComment2 = hasComment FROM @UserActionList where userType = 'FieldExecutive'

				UPDATE TBL_ET_PhyApptTypeFieldExecutivePermission
				SET has_view = @hasView2
					,has_edit = @hasEdit2
					,has_remove = @hasRemove2
					,has_completion = @hasCompletion2
					,has_comment = @hasComment2
				WHERE task_type_id = @TaskId
					AND parent_id = @ParentId
			END
			ELSE
			BEGIN
				INSERT INTO TBL_ET_PhyApptTypeFieldExecutivePermission (has_view
					,has_edit
					,has_remove
					,has_completion
					,has_comment
					,task_type_id
					,parent_id
					)
		SELECT hasView
					,hasEdit
					,hasRemove
					,hasCompletion
					,hasComment
					,@TaskId
					,@ParentId FROM @UserActionList where userType = 'FieldExecutive'

			END
		END

		END
		End

	END

	SELECT 'Record ' + @message Msg, @TaskId TaskId

	DECLARE @rowJson VARCHAR(MAX) = (
			SELECT *
			FROM tbl_tsk_UserTaskMaster(NOLOCK)
			WHERE id = @TaskId
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

	IF @rowJson IS NOT NULL
	BEGIN
		EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @CreatedBy
			,@Activity_type = @activity
			,@ActionType = @action
			,@RowJson = @rowJson
			,@Table_name = 'TBL_ET_PhyApptTypeFieldExecutivePermission'
	END
END;



GO

