     ,has_fieldcompletion = @hasFieldCompletion      
     ,has_fieldcomment = @hasFieldComment  
	 ,Has_fieldviewLead=@HasfieldviewLead
	 ,Has_fieldeditLead=@HasfieldeditLead
     ,GeoRestrictionCheckIn = @GeoRestrictionCheckIn      
     ,GeoRestrictionCheckOut= @GeoRestrictionCheckOut      
     ,AuthTypeCheckIn = @AuthTypeCheckIn      
     ,AuthTypeCheckOut = @AuthTypeCheckOut      
     ,CheckInRange = @CheckInRange      
     ,CheckOutRange = @CheckOutRange      
     ,CheckInFormId = @CheckInFormId   
     ,CheckOutFormId = @CheckOutFormId
  ,DisallowCheckInForm = @DisallowCheckInForm    
  ,DisallowCheckOutForm = @DisallowCheckOutForm    
  ,CheckInDisallowMsg = @CheckInDisallowMsg    
  ,CheckOutDisallowMsg = @CheckOutDisallowMsg    
  ,AssignmentType = @AssignmentType    
  ,AutoAssignTerritoryType = @AutoAssignTerritoryType    
  ,AssignAllocationType = @AssignAllocationType    
  ,AssignMeetingDays = @AssignMeetingDays    
  ,AssignMeetingType = @AssignMeetingType    
