  ,CheckInBeforeDistance = @CheckInBeforeDistance    
  ,IsAllowCallBeforeCheckIn = @IsAllowCallBeforeCheckIn    
  ,CheckInClientName = @CheckInClientName    
  ,CheckInMeetingDetails = @CheckInMeetingDetails    
  ,CheckInFieldMasked = @CheckInFieldMasked    
  ,CheckOutAfterDistance = @CheckOutAfterDistance    
  ,IsAllowCallAfterCheckOut = @IsAllowCallAfterCheckOut    
  ,CheckOutClientName = @CheckOutClientName    
  ,CheckOutMeetingDetails = @CheckOutMeetingDetails    
  ,CheckOutFieldMasked = @CheckOutFieldMasked    
  ,AllowedCheckInOutOverride = @AllowedCheckInOutOverride    
  ,AttendanceApproverType = @AttendanceApproverType    
  ,CheckInOutApproverId = @CheckInOutApproverId    
  
  ,MarkOutcomeCheckOut = @MarkOutcomeCheckOut    
  ,AddReimbursementOf = @AddReimbursementOf    
  ,DeductReimbursementOf = @DeductReimbursementOf    
  ,CheckInOutApproverIds = @CheckInOutApproverIds  
  ,ExpenseHeadIds = @ExpenseHeadIds
  ,CheckIn_SendMail = @CheckInEmailIdSetting
  ,CheckIn_SendSMS = @CheckInSMSSetting
  ,CheckIn_SendWhatsApp = @CheckInWhatsappSetting
  ,CheckOut_SendMail = @CheckOutEmailIdSetting
  ,CheckOut_SendSMS = @CheckOutSMSSetting
  ,CheckOut_SendWhatsApp = @CheckOutWhatsappSetting
 WHERE task_type_id = @TaskId      
     AND parent_id = @ParentId      
   END      
   ELSE      
   BEGIN      
    INSERT INTO tbl_tsk_TaskActionPermission (      
     has_view      
     ,has_edit      
     ,has_remove      
     ,has_completion      
     ,has_comment      
     ,has_fieldview      
     ,has_fieldedit      
     ,has_fieldremove      
     ,has_fieldcompletion      
     ,has_fieldcomment      
	 ,Has_fieldviewLead
	 ,Has_fieldeditLead
     ,task_type_id      
