     ,CheckOutRange      
     ,CheckInFormId      
     ,CheckOutFormId      
     --,MarkOutcomeCheckOut      
     --,AllowedCheckInOutOverride      
     --,CheckInOutApproverId      
     ,parent_id      
    
  ,DisallowCheckInForm    
  ,DisallowCheckOutForm    
  ,CheckInDisallowMsg    
  ,CheckOutDisallowMsg    
  ,AssignmentType    
  ,AutoAssignTerritoryType    
  ,AssignAllocationType    
