  ,IsCheckInTime    
  ,SuccessMeetingCheckInMin    
  ,IsSuccessMeetingOutcome    
  ,IsSuccessMeetingCondForm    
  ,CheckInBeforeDistance    
  ,IsAllowCallBeforeCheckIn    
  ,CheckInClientName    
  ,CheckInMeetingDetails    
  ,CheckInFieldMasked    
  ,CheckOutAfterDistance    
  ,IsAllowCallAfterCheckOut    
  ,CheckOutClientName    
  ,CheckOutMeetingDetails    
  ,CheckOutFieldMasked    
  ,AllowedCheckInOutOverride    
  ,AttendanceApproverType    
  ,CheckInOutApproverId    
  ,MarkOutcomeCheckOut    
  ,AddReimbursementOf    
  ,DeductReimbursementOf    
  ,CheckInOutApproverIds  
  ,ExpenseHeadIds
  ,CheckIn_SendMail
  ,CheckIn_SendSMS
  ,CheckIn_SendWhatsApp
  ,CheckOut_SendMail
  ,CheckOut_SendSMS
  ,CheckOut_SendWhatsApp
     )      
    VALUES (      
     @hasView      
     ,@hasEdit      
     ,@hasRemove      
     ,@hasCompletion      
     ,@hasComment      
     ,@hasFieldView      
     ,@hasFieldEdit      
     ,@hasFieldRemove      
     ,@hasFieldCompletion      
     ,@hasFieldComment    
	 ,@HasfieldviewLead
	 ,@HasfieldeditLead
     ,@TaskId      
     ,@GeoRestrictionCheckIn      
     ,@GeoRestrictionCheckOut      
     ,@AuthTypeCheckIn      
     ,@AuthTypeCheckOut      
     ,@CheckInRange      
     ,@CheckOutRange      
     ,@CheckInFormId      
     ,@CheckOutFormId      
     --,@MarkOutcomeCheckOut      
     --,@AllowedCheckInOutOverride      
     --,@CheckInOutApproverId      
     ,@ParentId      
    
  ,@DisallowCheckInForm    
  ,@DisallowCheckOutForm    
  ,@CheckInDisallowMsg    
  ,@CheckOutDisallowMsg    
  ,@AssignmentType    
  ,@AutoAssignTerritoryType    
  ,@AssignAllocationType    
  ,@AssignMeetingDays    
  ,@AssignMeetingType    
  ,@DefineSuccessMeeting    
  ,@IsCheckInTime    
  ,@SuccessMeetingCheckInMin    
  ,@IsSuccessMeetingOutcome    
  ,@IsSuccessMeetingCondForm    
  ,@CheckInBeforeDistance    
  ,@IsAllowCallBeforeCheckIn    
  ,@CheckInClientName    
  ,@CheckInMeetingDetails    
  ,@CheckInFieldMasked    
  ,@CheckOutAfterDistance    
  ,@IsAllowCallAfterCheckOut    
  ,@CheckOutClientName    
  ,@CheckOutMeetingDetails    
  ,@CheckOutFieldMasked    
  ,@AllowedCheckInOutOverride    
  ,@AttendanceApproverType    
  ,@CheckInOutApproverId    
  ,@MarkOutcomeCheckOut    
  ,@AddReimbursementOf    
  ,@DeductReimbursementOf    
  ,@CheckInOutApproverIds  
  ,@ExpenseHeadIds    
,@CheckInEmailIdSetting
,@CheckInSMSSetting
,@CheckInWhatsappSetting
,@CheckOutEmailIdSetting
,@CheckOutSMSSetting
,@CheckOutWhatsappSetting
     )      
   END      
  END      
 END      
      
