 insert into TBL_ET_TaskConditionSetting (AttendanceGroupid, PhysicalAppointmentTypeId, TypeofForm, PromptMessage, CreatedDate, CreatedBy, IsActive)    
 select @TaskId, @CheckInFormId, 'CheckIn', '', GETDATE(), @CreatedBy, 1    
    
 Declare @LCId2 bigint = SCOPE_IDENTITY()    
 delete TBL_ET_TaskConditionDetail where TCId = @LCId2

 insert into TBL_ET_TaskConditionDetail (TCId, SequenceNo, Operand1, Operator, Operand2, Conjunction, CreatedDate, CreatedBy, IsActive)    
 select distinct @LCId2, SequenceNo, Operand1, Operator, Operand2, Conjunction, GETDATE(), @CreatedBy, 1 from openjson(@CheckInConditionList)    
 with     
 (    
  SequenceNo int '$.SequenceNo',                      
  Operand1 nvarchar(100) '$.Operand1',                      
  Operator nvarchar(50) '$.Operator',    
  Operand2 nvarchar(50) '$.Operand2',    
  Conjunction nvarchar(50) '$.Conjunction'    
 ) tS    
 End    
    
 if(@CheckOutConditionList != '')    
 Begin    
 DELETE TBL_ET_TaskConditionSetting where AttendanceGroupid = @TaskId and TypeofForm ='CheckOut'
 insert into TBL_ET_TaskConditionSetting (AttendanceGroupid, PhysicalAppointmentTypeId, TypeofForm, PromptMessage, CreatedDate, CreatedBy, IsActive)

 select @TaskId, @CheckOutFormId, 'CheckOut', '', GETDATE(), @CreatedBy, 1

 Declare @LCId3 bigint = SCOPE_IDENTITY()
 delete TBL_ET_TaskConditionDetail where TCId = @LCId3


    
insert into TBL_ET_TaskConditionDetail (TCId, SequenceNo, Operand1, Operator, Operand2, Conjunction, CreatedDate, CreatedBy, IsActive)    
select @LCId3, tso2.SequenceNo, tso2.Operand1, tso2.Operator, tso2.Operand2, tso2.Conjunction, GETDATE(), @CreatedBy, 1 from (
select distinct SequenceNo, Operand1, Operator, Operand2, Conjunction from openjson(@CheckOutConditionList)    
 with     
 (    
  SequenceNo int '$.SequenceNo',                      
  Operand1 nvarchar(100) '$.Operand1',                      
  Operator nvarchar(50) '$.Operator',    
  Operand2 nvarchar(50) '$.Operand2',    
  Conjunction nvarchar(50) '$.Conjunction'    
 ) tSo    
)tso2    
 End    
    
      
 SELECT @message      
      
 DECLARE @rowJson VARCHAR(MAX) = (      
   SELECT *      
   FROM tbl_tsk_UserTaskMaster(NOLOCK)      
   WHERE id = @TaskId      
   FOR JSON AUTO      
    ,INCLUDE_NULL_VALUES      
   )      
      
 IF @rowJson IS NOT NULL      
 BEGIN      
  EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @CreatedBy      
   ,@Activity_type = @activity      
   ,@ActionType = @action      
   ,@RowJson = @rowJson      
   ,@Table_name = 'tbl_tsk_UserTaskMaster'      
 END      
END;   



