/* ============================================================
   Procedure: [dbo].[usp_mk_tsk_InsertNewActivityPhysicalNew]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_mk_tsk_InsertNewActivityPhysicalNew] 
 @ActivityId BIGINT 
 ,@ActivityName VARCHAR(255) 
 ,@IconClass VARCHAR(255) 
 ,@ParentId BIGINT      
 ,@CreatedBy BIGINT      
 ,@hasView BIT = 1      
 ,@hasEdit BIT = 0      
 ,@hasRemove BIT = 0      
 ,@hasCompletion BIT = 0      
 ,@hasComment BIT = 1      
 ,@TaskType varchar(20)    
 ,@hasFieldView BIT = 1      
 ,@hasFieldEdit BIT = 0      
 ,@hasFieldRemove BIT = 0      
 ,@hasFieldCompletion BIT = 0      
 ,@hasFieldComment BIT = 1    
 ,@HasfieldviewLead bit=0
 ,@HasfieldeditLead bit =0
 ,@GeoRestrictionCheckIn VARCHAR(20)      
 ,@GeoRestrictionCheckOut VARCHAR(20)      
 ,@AuthTypeCheckIn VARCHAR(20)      
 ,@AuthTypeCheckOut VARCHAR(20)      
 ,@CheckInRange int      
 ,@CheckOutRange int      
 ,@CheckInFormId bigint      
 ,@CheckOutFormId bigint       
 ,@DisallowCheckInForm bit = 0  
 ,@DisallowCheckOutForm bit = 0    
 ,@CheckInDisallowMsg nvarchar(1000) = ''    
 ,@CheckOutDisallowMsg nvarchar(1000) = ''    
 ,@AssignmentType varchar(10) = ''  
 ,@AutoAssignTerritoryType varchar(20) = ''    
 ,@AssignAllocationType varchar(10) = ''  
 ,@AssignMeetingDays int = 0  
 ,@AssignMeetingType varchar(10) = ''    
 ,@DefineSuccessMeeting varchar(10) = ''  
 ,@IsCheckInTime bit = 0  
 ,@SuccessMeetingCheckInMin int = 0  
 ,@IsSuccessMeetingOutcome bit = 0  
 ,@IsSuccessMeetingCondForm bit = 0   
 ,@CheckInBeforeDistance int = 0  
 ,@IsAllowCallBeforeCheckIn bit = 0   
 ,@CheckInClientName varchar(150) = ''  
 ,@CheckInMeetingDetails varchar(150) = ''   
 ,@CheckInFieldMasked varchar(20) = ''  
 ,@CheckOutAfterDistance int = 0  
 ,@IsAllowCallAfterCheckOut bit = 0  
 ,@CheckOutClientName varchar(150) = ''  
 ,@CheckOutMeetingDetails varchar(150) = ''   
 ,@CheckOutFieldMasked varchar(20) = ''  
 ,@AllowedCheckInOutOverride bit = 0  
 ,@AttendanceApproverType varchar(20) = ''  
 ,@CheckInOutApproverId bigint = 0    
 ,@MarkOutcomeCheckOut bit = 0  
 ,@AddReimbursementOf int = 0  
 ,@DeductReimbursementOf int = 0  
 ,@CheckInOutApproverIds varchar(1000) = ''    
 ,@ExpenseHeadIds varchar(1000) = ''  
 ,@OutcomeList TSK_OUTCOME_LIST READONLY      
 ,@CheckInConditionList nvarchar(max)      
 ,@CheckOutConditionList nvarchar(max)
 ,@CheckInSMSSetting nvarchar(max) = ''
 ,@CheckInEmailIdSetting nvarchar(max) = ''
 ,@CheckInWhatsappSetting nvarchar(max) = ''
 ,@CheckOutSMSSetting nvarchar(max) = ''
 ,@CheckOutEmailIdSetting nvarchar(max) = ''
 ,@CheckOutWhatsappSetting nvarchar(max) = ''
  ,@SurveyJsCheckInFormId bigint      
 ,@SurveyJsCheckOutFormId bigint  

AS      
 BEGIN      
 DECLARE @message NVARCHAR(max) = 'exists'      
  ,@activity VARCHAR(MAX) = ''      
  ,@action VARCHAR(1)      
      
 IF (@ActivityId > 0)      
 BEGIN      
  UPDATE tbl_tsk_UserTaskMaster      
  SET TasKName = @ActivityName      
   ,IconClass = @IconClass      
   ,TaskType = @TaskType    
  WHERE Id = @ActivityId      
      
  SET @message = 'updated'      
  SET @action = 'U'      
  SET @activity = 'Updt_TskActvty_Settng'      
 END      
      
 DECLARE @TaskId BIGINT = 0;      
      
 IF (      
   NOT EXISTS (      
    SELECT *      
    FROM tbl_tsk_UserTaskMaster      
    WHERE (      
      IsPredefined = 1      
      OR ParentId = @ParentId      
      )      
     AND TasKName = @ActivityName      
    )      
   )      
 BEGIN      
  INSERT INTO tbl_tsk_UserTaskMaster (      
   TaskType    
   ,TasKName      
   ,IconClass      
   ,ParentId      
   ,IsDeleted      
   ,IsPredefined      
   ,CreatedOn      
   ,CreatedBy      
   )      
  VALUES (      
  @TaskType    
   ,@ActivityName      
   ,@IconClass      
   ,@ParentId      
   ,0      
   ,0      
   ,GETDATE()      
   ,@CreatedBy      
   );      
      
  SET @TaskId = SCOPE_IDENTITY();      
  SET @message = 'inserted'      
  SET @action = 'I'      
  SET @activity = 'Inst_TskActvty_Settng'      
 END;      
 ELSE      
 BEGIN      
  --SELECT @TaskId = Id FROM tbl_tsk_UserTaskMaster  WHERE ( IsPredefined = 1 OR ParentId = @ParentId ) AND  TasKName = @ActivityName;            
  SET @TaskId = @ActivityId      
 END;      
      
 IF (@TaskId > 0)      
 BEGIN      
  DECLARE @OutcomeCount INT = 0;      
      
  SELECT @OutcomeCount = COUNT(*)      
  FROM @OutcomeList;      
      
  IF (@OutcomeCount > 0)      
  BEGIN      
   DECLARE @OutcomeName VARCHAR(50)      
    ,@Sequence INT      
    ,@Indent VARCHAR(50);      
      
   --delete old mapping      
   DELETE      
 FROM tbl_tsk_TaskOutcomeMapping      
   WHERE TaskId = @TaskId      
    AND CreatedBy = @CreatedBy      
      
   WHILE (@OutcomeCount > 0)      
   BEGIN      
    SELECT @OutcomeName = LTRIM(RTRIM(Name))      
     ,@Sequence = Sequence      
     ,@Indent = Indent      
    FROM @OutcomeList      
    WHERE Id = @OutcomeCount;      
      
    DECLARE @UserOutcomeMasterId BIGINT = 0;      
      
    IF (      
      EXISTS (      
       SELECT *      
FROM tbl_tsk_UserOutcomeMaster      
       WHERE IsPredefined = 1      
        AND LTRIM(RTRIM(OutcomeName)) = @OutcomeName      
        AND indent = @Indent      
       )      
      )      
    BEGIN      
     SELECT @UserOutcomeMasterId = Id      
     FROM tbl_tsk_UserOutcomeMaster      
     WHERE IsPredefined = 1      
      AND LTRIM(RTRIM(OutcomeName)) = @OutcomeName      
      AND Indent = @Indent;      
    END;      
    ELSE IF (      
      EXISTS (      
       SELECT *      
       FROM tbl_tsk_UserOutcomeMaster      
       WHERE ParentId = @ParentId      
        AND LTRIM(RTRIM(OutcomeName)) = @OutcomeName      
       )      
      )      
    BEGIN      
     SELECT @UserOutcomeMasterId = Id      
     FROM tbl_tsk_UserOutcomeMaster      
     WHERE ParentId = @ParentId      
      AND LTRIM(RTRIM(OutcomeName)) = @OutcomeName;      
    END;      
    ELSE      
    BEGIN      
     INSERT INTO tbl_tsk_UserOutcomeMaster ( OutcomeName, ParentId, IsDeleted, IsPredefined      
      ,CreatedOn      
      ,CreatedBy      
      ,Indent      
      )      
     VALUES (      
      @OutcomeName      
      ,@ParentId      
      ,0      
      ,0      
      ,GETDATE()      
      ,@CreatedBy      
      ,@Indent      
      );      
      
     SET @UserOutcomeMasterId = SCOPE_IDENTITY();      
    END;      
      
    PRINT str(@UserOutcomeMasterId) + ' : sq : ' + str(@Sequence)      
      
    IF (@UserOutcomeMasterId > 0)      
    BEGIN      
     IF (      
       NOT EXISTS (      
        SELECT 1      
        FROM tbl_tsk_TaskOutcomeMapping      
        WHERE TaskId = @TaskId      
         AND OutcomesId = @UserOutcomeMasterId      
        )      
       )      
     BEGIN      
      INSERT INTO tbl_tsk_TaskOutcomeMapping (      
       TaskId      
       ,OutcomesId      
       ,[Sequence]      
       ,CreatedOn      
       ,CreatedBy      
       ,ParentId      
       )      
      VALUES (      
       @TaskId      
       ,@UserOutcomeMasterId      
       ,@Sequence      
       ,GETDATE()      
       ,@CreatedBy      
       ,@ParentId      
       );      
     END;      
     ELSE      
     BEGIN      
      UPDATE tbl_tsk_TaskOutcomeMapping      
      SET [Sequence] = @Sequence      
      WHERE TaskId = @TaskId      
       AND OutcomesId = @UserOutcomeMasterId      
       --select * from tbl_tsk_TaskOutcomeMapping where TaskId = @TaskId and OutcomesId = @UserOutcomeMasterId          
     END      
      
     SET @OutcomeCount = @OutcomeCount - 1;      
    END      
   END;      
      
