/* ============================================================
   Procedure: [dbo].[usp_mk_tsk_InsertNewFollowUp]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_mk_tsk_InsertNewFollowUp]      
                @ParentId     BIGINT ,               
                @CreatedBy    BIGINT ,               
                @OutcomeList  tsk_FollowUpType_List READONLY              
AS    
BEGIN    
 declare @message nvarchar(max) = ''    
    
 Update fs Set fs.FollowupStatus = flt.FollowupStatus, fs.OrderNumber = flt.OrderNumber, fs.Intent = flt.Intent, fs.IsCallback = flt.IsCallback,     
  fs.IsConvert = flt.IsConvert, fs.IsDisabled = flt.IsDisabled from @OutcomeList flt    
  inner join FollowUp_Status fs on flt.ID = fs.ID    
  and fs.ID not in (1,2,3,4,5,6)  
  
  INSERT into FollowUp_Status (FollowupStatus, OrderNumber, Intent, IsCallback, IsConvert,    
   IsDisabled, ParentId, CreatedBy, CreatedDate, IsActive)     
   select FollowupStatus, OrderNumber, Intent, IsCallback, IsConvert,    
   IsDisabled, @ParentId, @CreatedBy, GETDATE(), 1 from @OutcomeList flt 
   where 
   flt.ID = 0    
   and flt.FollowupStatus not in (select FollowupStatus from FollowUp_Status where ParentId = @ParentId ) 
    
    
select 'Updated'    
      
END; 


GO

