CREATE   PROCEDURE [dbo].[usp_mk_tsk_InsertNewTaskOrAppointment]  (
	@Title               VARCHAR(255) ,     
	@Description         VARCHAR(1000) ,
	@Remarks             VARCHAR(1000) = '',   
	@Address             VARCHAR(500)  = NULL,     
	@StartDate           DATETIME      = '' ,     
	@EndDate             DATETIME ,     
	@LeadId              BIGINT ,     
	@AssignedTo          BIGINT ,     
	@IsActive            BIT           = 1 ,     
	@TaskId              BIGINT ,     
	@Status              VARCHAR(255)  = 'open' ,     
	@CreatedBy           BIGINT ,     
	@OutcomesId          BIGINT ,     
	@CollabratoerUserIds VARCHAR(1000) ,     
	@IsSMS               BIT           = 0 ,     
	@IsEmail             BIT           = 0 ,     
	@IsTask              BIT           = 0 ,     
	@IsAppointment       BIT           = 0 ,     
	@TaskType            VARCHAR(100)  = '' ,     
	@CompleteAddress     VARCHAR(500)  = NULL ,     
	@Latitude            VARCHAR(50)   = NULL ,     
	@Longitude           VARCHAR(50)   = NULL ,     
	@SmsSchedule         VARCHAR(50)   = NULL ,     
	@EmailSchedule       VARCHAR(50)   = NULL ,  
	@NotifyMe            BIT           = 0  
)
AS    
BEGIN    
        
	DECLARE @TaskHistoryId BIGINT= 0;    
  
  
	INSERT INTO tbl_tsk_TaskHistory ( Title , Description , Address , StartDate , EndDate , LeadId , AssignedTo , IsActive , CreatedOn , TaskId , CreatedBy , OutcomesId , STATUS , IsTask , IsAppointment , TaskType , CompleteAddress , Latitude , Longitude, Remarks)     
	   VALUES ( @Title , @Description , @Address , @StartDate , @EndDate , @LeadId , @AssignedTo , @IsActive , GETDATE() ,  @TaskId , @CreatedBy , @OutcomesId , @Status , @IsTask , @IsAppointment , @TaskType , @CompleteAddress , @Latitude , @Longitude, @Remarks );    
	
	SET @TaskHistoryId = SCOPE_IDENTITY();  
			
	if(ISNULL(@CollabratoerUserIds, '') <> '')
