		INSERT INTO #TEMCollabatoerUser ( UserId  )     
		SELECT [value] AS [UserId] FROM fn_Split(@CollabratoerUserIds , '#') WHERE LTRIM(RTRIM(value)) <> ''; 
	
		--update cm set cm.DeletedOn = null FROM tbl_tsk_CollaborationUserMapping(nolock) cm 
