		insert into tbl_tsk_CollaborationUserMapping( User_Id, CreatedOn, CreatedBy, TaskHistoryId )
		SELECT tc.UserId, GETDATE(), @CreatedBy, @TaskHistoryId FROM #TEMCollabatoerUser tc 
			left join tbl_tsk_CollaborationUserMapping(nolock) cm on cm.User_Id = tc.UserId and cm.TaskHistoryId = @TaskHistoryId
				where cm.User_Id is null
	end

