/* ============================================================
   Procedure: [dbo].[usp_mk_tsk_InsertNewTaskOrAppointment_WithDLTTemplateID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

                    
CREATE   PROCEDURE [dbo].[usp_mk_tsk_InsertNewTaskOrAppointment_WithDLTTemplateID]                     
                @Title               VARCHAR(255) ,                     
                @Description         VARCHAR(1000) ,                     
                @Remarks             VARCHAR(500)  = '' ,                     
                @Address             VARCHAR(500) ,                     
                @StartDate           DATETIME      = '' ,                     
                @EndDate             DATETIME ,                     
                @LeadId              BIGINT ,                     
                @AssignedTo          BIGINT ,                     
                @IsActive            BIT           = 1 ,                     
                @TaskId              BIGINT ,                     
                @Status              VARCHAR(255)  = 'open' ,                     
                @CreatedBy           BIGINT ,                     
                @OutcomesId          BIGINT ,                     
                @CollabratoerUserIds VARCHAR(1000) ,                     
                @IsSMS               BIT           = 0 ,                     
                @IsEmail             BIT           = 0 ,                     
                @IsTask              BIT           = 0 ,                     
                @IsAppointment       BIT           = 0 ,                     
                @TaskType            VARCHAR(100)  = '' ,                     
                @CompleteAddress     VARCHAR(500)  = NULL ,                     
                @Latitude            VARCHAR(50)   = NULL ,                     
                @Longitude           VARCHAR(50)   = NULL ,                     
                @SmsSchedule         VARCHAR(50)   = NULL ,                     
                @EmailSchedule       VARCHAR(50)   = NULL ,                     
                @NotifyMe            BIT           = 0,                  
    @DLTTemplateIDForSMSReminder nvarchar(200),                  
    @DLTTemplateIDForNotification nvarchar(200)                    
AS                    
    BEGIN                    
  DECLARE @TaskHistoryId BIGINT= 0,@Leadno bigint=(select leadno from userleads(nolock) where id=@leadid)              
  DECLARE @Sender_Name VARCHAR(50)= '',@event nvarchar(100)            
  SELECT @Sender_Name = ISNULL(Sender_Name , '')                    
                FROM Default_SenderID                    
                WHERE User_ID = @CreatedBy                    
                      AND                     
                 Sender_ID > 0;                
                    
          
    DECLARE @ParentId BIGINT= 0;                    
                SELECT @ParentId = isnull(ParentID,User_ID)                    
                FROM User_Detail(NOLOCK)                    
                WHERE User_ID = @CreatedBy;          
          
          
        INSERT INTO tbl_tsk_TaskHistory ( Title , Description , Address , StartDate , EndDate , LeadId , AssignedTo , IsActive , CreatedOn , TaskId , CreatedBy ,   
  OutcomesId , STATUS , IsTask , IsAppointment , TaskType , CompleteAddress , Latitude , Longitude , Remarks                   
                                        )                     
        VALUES ( @Title , @Description , @Address , @StartDate , @EndDate , @LeadId , @AssignedTo , @IsActive , GETDATE() , @TaskId , @CreatedBy ,   
  @OutcomesId , @Status , @IsTask , @IsAppointment , @TaskType , @CompleteAddress , @Latitude , @Longitude , @Remarks                    
               );       
         
   SET @TaskHistoryId = SCOPE_IDENTITY();       
      
	     if(@Status = 'completed')
	       Begin
		     update tbl_tsk_TaskHistory set CompletedOn = getdate()  where id = @TaskHistoryId     
		  End 


        IF ( @NotifyMe <> 0 )                     
            BEGIN                    
                DECLARE @FullNameAss NVARCHAR(255)= ( SELECT ( FName + ' ' + LName ) AS [UserFullName]                    
                                                      FROM User_Detail                    
 WHERE User_ID = @AssignedTo                    
                                                    );                    
                DECLARE @CreatorNameAss NVARCHAR(255)= ( SELECT ( FName + ' ' + LName ) AS [UserFullName]                    
                                                         FROM User_Detail         
                                                         WHERE User_ID = @CreatedBy                    
  );              
  --Task Creation notification: Dear {#var#}, Task with title {#var#}  with your role as Owner has been {#var#} on {#var#} by {#var#} powered by kit19  
  
          
                DECLARE @colMsgAss NVARCHAR(MAX)=         
              case when @IsAppointment=1 then 'Appointment ' else 'Task ' end +        
                      'Creation notification: Dear ' + @FullNameAss + ', Task with title ' + @Title +        
                      '  with your role as Owner has been created on ' + CAST(GETDATE() AS NVARCHAR) + ' by  ' + @CreatorNameAss   
       +': Powered by Kit19';                    
                DECLARE @ScheduleDataAss DATETIME= DATEADD(MINUTE , 10 , GETDATE());    
    DECLARE @cutOffTimeAss DATETIME= DATEADD(HH , 6 , GETDATE());                  
                --DECLARE @ParentId BIGINT= 0;                    
                --SELECT @ParentId = ParentID                    
                --FROM User_Detail(NOLOCK)                    
                --WHERE User_ID = @CreatedBy;                    
                --DECLARE @Sender_Name VARCHAR(50)= '';          
    select @event=case when @IsAppointment=1 then 'Appointment ' else 'Task ' end + 'added'                 
                SELECT @Sender_Name ='KitApp'  
     --ISNULL(Sender_Name , '')                    
     --           FROM Default_SenderID                    
     --           WHERE User_ID = @CreatedBy                    
     --                 AND                     
     --            Sender_ID > 0;                    
               -- SELECT @Sender_Name;                    
                DECLARE @mobilenos VARCHAR(MAX);                    
                IF ( @Sender_Name <> '' )                     
                    BEGIN                    
                     SET @mobilenos = dbo.udf_tsk_GetCollabortorMobiles ( STR(@CreatedBy));                    
                        --EXEC usp_sendmessage @ParentId , @colMsgAss , @mobilenos , @Sender_Name , 0 , 2;                 
           exec [usp_sendmessage_WithdltOrEvent] 335 , @colMsgAss , @mobilenos , @Sender_Name , 0 , 2,null,@event ;                         
           --EXEC usp_sendmessage_WithDLTTemplateID @ParentId , @colMsgAss , @mobilenos , @Sender_Name , 0 , 2,@DLTTemplateIDForNotification ;                     
                END;                    
                    
                --exec usp_SaveNotification @CollabratoerUserIds, @Title, @colMsgAss, 'https://kit19.com/IndexNew1/images/logo.png', '', @ScheduleDataAss , @cutOffTimeAss , @CreatedBy                     
                    
        END;                    
                           
        IF @CollabratoerUserIds <> ''                    
            BEGIN                    
                CREATE TABLE #TEMCollabatoerUser (                     
                             Id     INT PRIMARY KEY IDENTITY(1 , 1) ,                     
                             UserId BIGINT                    
                                                 );                    
                INSERT INTO #TEMCollabatoerUser ( UserId                    
                                                )                     
                       SELECT value AS UserId                    
                       FROM STRING_SPLIT(@CollabratoerUserIds , '#')                    
                       WHERE LTRIM(RTRIM(value)) <> '';                    
                DECLARE @Counter INT , @UserId BIGINT;                    
                SELECT @Counter = COUNT(*)                    
     FROM #TEMCollabatoerUser;                    
                WHILE @Counter > 0                    
                    BEGIN                    
                        SELECT @UserId = UserId                    
                        FROM #TEMCollabatoerUser                    
                        WHERE Id = @Counter;                    
                        DECLARE @CollabratoerMappingId BIGINT= 0;                    
                        INSERT INTO tbl_tsk_CollaborationUserMapping ( User_Id , CreatedOn , CreatedBy , TaskHistoryId                    
                                                                     )                     
                        VALUES ( @UserId , GETDATE() , @CreatedBy , @TaskHistoryId                 
                               );                    
                        SET @CollabratoerMappingId = SCOPE_IDENTITY();                    
                        IF @CollabratoerMappingId > 0                    
                         BEGIN                    
                                IF @IsSMS = 1                    
                                    BEGIN                    
                      INSERT INTO tbl_tsk_Reminder ( Description , STATUS , Schedule , CreatedOn , CreatedBy , IsSMS , IsEmail , CollaborationUserMappingId                    
                                                                     )                     
                                        VALUES ( 'You are now a Collaborater of a task with title '+@Title+' for Leadno ' + CAST(@Leadno AS VARCHAR) + ' scheduled for '+ cast(@EndDate as nvarchar(50)), 'open' , @SmsSchedule , GETDATE() , @CreatedBy , 1 , 
0 , @CollabratoerMappingId                    
                                               );                    
                                END;                    
                                IF @IsEmail = 1                    
                                    BEGIN                    
                                        INSERT INTO tbl_tsk_Reminder ( Description , STATUS , Schedule , CreatedOn , CreatedBy , IsSMS , IsEmail , CollaborationUserMappingId                    
                                                                     )                     
                                        VALUES ( 'You are now a Collaborater of a task with title '+@Title+' for Leadno ' + CAST(@Leadno AS VARCHAR) + ' scheduled for '+ cast(@EndDate as nvarchar(50)) , 'open' , @EmailSchedule , GETDATE() , @CreatedBy , 0
 , 1 , @CollabratoerMappingId                    
                                               );                    
                                END;                    
                        END;                    
                   SET @Counter = @Counter - 1;                    
   END;                    
   IF ( @Sender_Name <> '' )                     
                BEGIN                    
                    SET @mobilenos = dbo.udf_tsk_GetCollabortorMobiles ( REPLACE(@CollabratoerUserIds , '#' , ','));                    
           --  EXEC usp_sendmessage @ParentId , @colMsgAss , @mobilenos , @Sender_Name , 0 , 2;                 
        EXEC usp_sendmessage_WithDLTTemplateID 335 , @colMsgAss , @mobilenos , @Sender_Name , 0 , 2,@DLTTemplateIDForSMSReminder;                 
                END;                    
            DROP TABLE #TEMCollabatoerUser;                    
        END;                    
       -- EXEC usp_tsk_InsertReminder @TaskHistoryId;                  
      EXEC usp_tsk_InsertReminder_WithDLTTemplateID @TaskHistoryId, @DLTTemplateIDForSMSReminder;        
         
   select @TaskHistoryId      
      
      
    END;


