/* ============================================================
   Procedure: [dbo].[usp_mk_tsk_MarkTaskDetailAsComplitedById]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE usp_mk_tsk_MarkTaskDetailAsComplitedById
                          @Id      BIGINT , 
                          @Outcome BIGINT        = 0 , 
                          @Remarks NVARCHAR(MAX) = ''
AS
    BEGIN
        DECLARE @CompletedOn DATETIME= NULL;
        IF ( @Outcome > 0 ) 
            BEGIN
                SET @CompletedOn = GETDATE();

                UPDATE tbl_tsk_TaskHistory
                       SET [Status] = 'completed' , CompletedOn = @CompletedOn , OutcomesId = @Outcome , Remarks = @Remarks
                WHERE Id = @Id;
                DECLARE @LeadId BIGINT , @UserId BIGINT , @ParentId BIGINT , @UserName NVARCHAR(255) , @AppointmentTitle NVARCHAR(255) , @AppointmentDateTime NVARCHAR(255) , @OutcomeName NVARCHAR(255) , @IsTask BIT= 0 , @TaskType NVARCHAR(255) , @TaskId BIGINT;
                SELECT @LeadId = LeadId , @UserId = CreatedBy , @AppointmentTitle = Title , @AppointmentDateTime = EndDate , @IsTask = IsTask , @TaskId = TaskId
                FROM tbl_tsk_TaskHistory(NOLOCK)
                WHERE Id = @Id;
                SELECT @UserName = User_Login , @ParentId = ParentID
                FROM User_Detail(NOLOCK)
                WHERE User_ID = @UserId;
                SELECT @TaskType = TasKName
                FROM tbl_tsk_UserTaskMaster(NOLOCK)
                WHERE Id = @TaskId;
                SELECT @OutcomeName = OutcomeName
                FROM tbl_tsk_UserOutcomeMaster(NOLOCK)
                WHERE id = @Outcome;
                DECLARE @leadtbl AS LEADACTIVITYWITHID_TBLTYPE;
                INSERT INTO @leadtbl ( leadid , userid , parentid , eventname , eventdescription , reftable , refid
                                     ) 
                       SELECT @LeadId , @UserId , @Parentid , IIF(@IsTask = 1 , 'Task Completed' , 'Appointment Completed') , IIF(@IsTask = 1 , Concat(@UserName , ' completed task of type ' , @TaskType , ' with title ' , @AppointmentTitle , ' . Task Outcome is ' , @OutcomeName) , CONCAT(@UserName , ' completed an appointment with title ' , @AppointmentTitle , ' for ' , @AppointmentDateTime , '. Appointment outcome is ' , @OutcomeName)) , 'tbl_tsk_TaskHistory' , @Id;
                EXEC UspSaveentityActivity_withMultipleValue_withid @leadtbl;
        END;
    END;


GO

