    @Status              VARCHAR(255)  = 'open' ,     
    @CreatedBy           BIGINT ,     
    @OutcomesId          BIGINT ,     
    @CollabratoerUserIds VARCHAR(1000) ,     
    @IsSMS               BIT           = 0 ,     
    @IsEmail             BIT           = 0 ,     
    @IsTask              BIT           = 0 ,     
    @IsAppointment       BIT           = 0 ,     
    @TaskType            VARCHAR(100)  = '' ,     
    @CompleteAddress     VARCHAR(500)  = NULL ,     
    @Latitude            VARCHAR(50)   = NULL ,     
    @Longitude           VARCHAR(50)   = NULL ,     
    @SmsSchedule         VARCHAR(50)   = NULL ,     
    @EmailSchedule       VARCHAR(50)   = NULL ,     
    @NotifyMe            BIT           = 0,
	@Remarks       NVARCHAR(max)   = '' 
AS    
BEGIN    
	UPDATE tbl_tsk_TaskHistory   SET 
		Title = @Title ,
		Description = @Description , 
		Address = (Case when @Address != '' then @Address else Address end) , 
		StartDate = @StartDate , 
		EndDate = @EndDate , 
		LeadId = @LeadId ,
		AssignedTo = @AssignedTo , 
		IsActive = @IsActive , 
		TaskId = @TaskId , 
		OutcomesId = @OutcomesId , 
		STATUS = @Status, 
		IsTask = @IsTask , 
		IsAppointment = @IsAppointment , 
		TaskType = @TaskType , 
		CompleteAddress = @CompleteAddress , 
		Latitude = @Latitude , 
		Longitude = @Longitude , 
		CompletedOn = IIF(@Status = 'completed' , GETDATE() , NULL), 
		UpdatedOn = GETDATE(),
		Remarks =  iif( isnull(@Remarks, '') = '', 
		Remarks, concat(Remarks, ' ', @Remarks))  
			WHERE Id = @Id;    
    
	update tbl_tsk_CollaborationUserMapping set 
			DeletedOn = GETDATE() where TaskHistoryId = @Id
    
	if(ISNULL(@CollabratoerUserIds, '') <> '')
	begin
		drop table if exists #TEMCollabatoerUser

		CREATE TABLE #TEMCollabatoerUser ( Id INT PRIMARY KEY IDENTITY(1 , 1) , UserId BIGINT )
		INSERT INTO #TEMCollabatoerUser ( UserId  )     
		SELECT [value] AS [UserId] FROM fn_Split(@CollabratoerUserIds , '#') WHERE LTRIM(RTRIM(value)) <> ''; 
	
		update cm set cm.DeletedOn = null FROM tbl_tsk_CollaborationUserMapping(nolock) cm 
			inner join #TEMCollabatoerUser tc on cm.User_Id = tc.UserId where cm.TaskHistoryId = @Id

		insert into tbl_tsk_CollaborationUserMapping( User_Id, CreatedOn, CreatedBy, TaskHistoryId )
		SELECT tc.UserId, GETDATE(), @CreatedBy, @Id FROM #TEMCollabatoerUser tc 
			left join tbl_tsk_CollaborationUserMapping(nolock) cm on cm.User_Id = tc.UserId and cm.TaskHistoryId = @Id
				where cm.User_Id is null
	end


