CREATE   PROCEDURE usp_mk_tsk_UpdateTaskOrAppointment_WithDLTTemplateID             
                @Id                  BIGINT ,             
             @Title               VARCHAR(255) ,             
                @Description         VARCHAR(1000) ,             
                @Address             VARCHAR(500) ,             
                @StartDate           DATETIME      = '' ,             
                @EndDate             DATETIME ,             
                @LeadId              BIGINT ,             
                @AssignedTo          BIGINT ,             
                @IsActive            BIT           = 1 ,             
                @TaskId              BIGINT ,             
                @Status              VARCHAR(255)  = 'open' ,             
                @CreatedBy           BIGINT ,             
                @OutcomesId          BIGINT ,             
                @CollabratoerUserIds VARCHAR(1000) ,             
                @IsSMS               BIT           = 0 ,             
                @IsEmail             BIT           = 0 ,             
                @IsTask              BIT           = 0 ,             
                @IsAppointment       BIT           = 0 ,             
                @TaskType            VARCHAR(100)  = '' ,             
                @CompleteAddress     VARCHAR(500)  = NULL ,             
                @Latitude            VARCHAR(50)   = NULL ,             
                @Longitude           VARCHAR(50)   = NULL ,             
                @SmsSchedule         VARCHAR(50)   = NULL ,             
                @EmailSchedule       VARCHAR(50)   = NULL ,             
                @NotifyMe            BIT           = 0 ,        
       @DLTTemplateIDForSMSReminder nvarchar(200),          
                @DLTTemplateIDForNotification nvarchar(200)           
               
AS            
    BEGIN            
 declare @event nvarchar(100),  @leadno bigint  
        UPDATE tbl_tsk_TaskHistory            
SET Title = @Title , Description = @Description , Address = @Address , StartDate = @StartDate , EndDate = @EndDate , LeadId = @LeadId , AssignedTo = @AssignedTo , IsActive = @IsActive , TaskId = @TaskId , OutcomesId = @OutcomesId , STATUS =  
 @Status , IsTask = @IsTask , IsAppointment = @IsAppointment , TaskType = @TaskType , CompleteAddress = @CompleteAddress , Latitude = @Latitude , Longitude = @Longitude , CompletedOn = IIF(@Status = 'completed' , GETDATE() , NULL), UpdatedOn = GETDATE()  
  
WHERE Id = @Id;            
            
  IF(@NotifyMe <> 0)            
  BEGIN            
   declare @FullNameAss nvarchar(255) = (select  (FName + ' ' + LName) as [UserFullName] from User_Detail where User_ID = @AssignedTo)                     
   declare @CreatorNameAss nvarchar(255) =  (select  (FName + ' ' + LName) as [UserFullName] from User_Detail where User_ID = @CreatedBy)                     
   declare @colMsgAss nvarchar(Max) = case when @IsAppointment=1 then 'Appointment ' else 'Task ' end+ 'Edited notification: Dear '+ @FullNameAss      
   +', '+case when @IsAppointment=1 then 'Appointment ' else 'Task ' end+'with title '+@Title+'  with your role as '+  
   --+'Owner/'+  
   'Collaborator has been edited on '+ CAST( GETDATE() AS NVARCHAR) +' by  '+@CreatorNameAss    
   +'  powered by kit19'          
     
           
   declare @ScheduleDataAss datetime = DATEADD(MINUTE, 10, GETDATE())            
   declare @cutOffTimeAss datetime = DATEADD(HH, 6, GETDATE())               
               
   exec usp_SaveNotification @CollabratoerUserIds, @Title, @colMsgAss, 'https://kit19.com/IndexNew1/images/logo.png', '', @ScheduleDataAss , @cutOffTimeAss , @CreatedBy        
         
         
         --                     declare @ParentID2 bigint = 0      
               
         --select @ParentID2 = isnull(ParentID,User_ID) from User_Detail(nolock) where User_ID = @CreatedBy      
      
                
         --    declare @Sender_Name2 as nvarchar(200) = ''      
         --SELECT @Sender_Name2 = ISNULL(Sender_Name , '')                  
         -- FROM Default_SenderID                  
     -- WHERE User_ID = @CreatedBy                  
         --    AND                   
         --  Sender_ID > 0;                  
         -- --SELECT @Sender_Name2;                  
