         --    IF(@Sender_Name2 <> '' )                   
         -- BEGIN                  
         --   SET @mobilenos = dbo.udf_tsk_GetCollabortorMobiles ( STR(@CreatedBy));                  
         --   --EXEC usp_sendmessage @ParentId , @colMsgAss , @mobilenos , @Sender_Name , 0 , 2;               
         --        EXEC usp_sendmessage_WithDLTTemplateID @ParentID2 , @colMsgAss , @mobilenos , @Sender_Name2 , 0 ,    2,@DLTTemplateIDForNotification ;                   
                
         -- END;        
         
             
  END            
            
        UPDATE tbl_tsk_CollaborationUserMapping            
               SET DeletedOn = GETDATE()            
        WHERE TaskHistoryId = @Id;            
        IF ( @CollabratoerUserIds <> '' )             
            BEGIN            
                CREATE TABLE #TEMCollabatoerUser (             
                             Id     INT PRIMARY KEY IDENTITY(1 , 1) ,             
                             UserId BIGINT            
                                                 );            
                INSERT INTO #TEMCollabatoerUser ( UserId            
                                                )             
                       SELECT value AS [UserId]            
                       FROM STRING_SPLIT(@CollabratoerUserIds , '#')            
                       WHERE LTRIM(RTRIM(value)) <> '';            
                DECLARE @Counter INT , @UserId BIGINT;            
                SELECT @Counter = COUNT(*)            
                FROM #TEMCollabatoerUser;            
                WHILE ( @Counter > 0 )             
                    BEGIN            
     DECLARE @CollabratoerMappingId BIGINT= 0;            
                        SELECT @UserId = UserId            
                        FROM #TEMCollabatoerUser            
              WHERE Id = @Counter;            
                        IF ( EXISTS ( SELECT *            
                                      FROM tbl_tsk_CollaborationUserMapping            
                                      WHERE User_Id = @UserId            
                                            AND             
                                            TaskHistoryId = @Id            
                                    ) )             
                            BEGIN            
                                UPDATE tbl_tsk_CollaborationUserMapping            
                                       SET DeletedOn = NULL            
                                WHERE User_Id = @UserId            
                                      AND             
                                      TaskHistoryId = @Id;            
                                SELECT @CollabratoerMappingId = Id            
                                FROM tbl_tsk_CollaborationUserMapping            
                                WHERE User_Id = @UserId            
                                      AND             
                                      TaskHistoryId = @Id;            
                        END;            
                            ELSE            
                            BEGIN            
                                INSERT INTO tbl_tsk_CollaborationUserMapping ( User_Id , CreatedOn , CreatedBy , TaskHistoryId            
                                                                             )             
                                VALUES ( @UserId , GETDATE() , @CreatedBy , @Id            
                                       );            
                                SET @CollabratoerMappingId = SCOPE_IDENTITY();     
                        END;            
                        IF ( @CollabratoerMappingId > 0 )             
                            BEGIN            
                                IF ( @IsSMS = 1 )             
                                    BEGIN            
                                        INSERT INTO tbl_tsk_Reminder ( Description , STATUS , Schedule , CreatedOn , CreatedBy , IsSMS , IsEmail , CollaborationUserMappingId            
                                                                     )             
                                       VALUES ( 'You are now a Collaborator of task of type '+ @TaskType+' with title '+ @Title +' for Lead no. ' + CAST(@LeadId AS VARCHAR)+ ' scheduled at '+cast(@EndDate as nvarchar(50))  , ' open ' , @SmsSchedule , GETDATE() , @CreatedBy , 1 , 0 ,   
            @CollabratoerMappingId            
                                               );            
                                END;            
                                IF ( @IsEmail = 1 )             
                                    BEGIN            
                                        INSERT INTO tbl_tsk_Reminder ( Description , STATUS , Schedule , CreatedOn , CreatedBy , IsSMS , IsEmail , CollaborationUserMappingId            
                                                                     )             
                                        VALUES ( 'You are now a Collaborator of task of type '+ @TaskType+' with title '+ @Title +' for Lead no. ' + CAST(@LeadId AS VARCHAR)+ ' scheduled at '+cast(@EndDate as nvarchar(50)) , ' open ' , @EmailSchedule , GETDATE() , @CreatedBy , 0 , 1 ,  
           @CollabratoerMappingId            
                                               );            
                                END;            
                                IF ( @NotifyMe <> 0 )             
                                    BEGIN            
                                        DECLARE @FullName NVARCHAR(255)= ( SELECT ( FName + ' ' + LName ) AS [UserFullName]            
                                                                           FROM User_Detail            
                            WHERE User_ID = @UserId            
                                                                         );            
                                        DECLARE @CreatorName NVARCHAR(255)= ( SELECT ( FName + ' ' + LName ) AS [UserFullName]            
                                                                              FROM User_Detail            
                                                                              WHERE User_ID = @CreatedBy            
                                                                            );            
set @event=case when @IsAppointment=1 then 'Appointment ' else 'Task ' end +'edited'  
                                        DECLARE @colMsg NVARCHAR(MAX)=  case when @IsAppointment=1 then 'Appointment ' else 'Task ' end +'Edited notification: Dear '      
           + @FullName + ', '+case when @IsAppointment=1 then 'Appointment ' else 'Task ' end+'with title ' + @Title + '  with your role as Collaborator has been edited on '      
            + CAST(GETDATE() AS NVARCHAR) + ' by ' + @CreatorName;      
                        
                                        DECLARE @ScheduleData DATETIME= DATEADD(MINUTE , 10 , GETDATE());            
                                        DECLARE @cutOffTime DATETIME= DATEADD(HH , 6 , GETDATE());            
                                        EXEC usp_SaveNotification @CollabratoerUserIds , @Title , @colMsg , 'https://kit19.com/IndexNew1/images/logo.png' , '' , @ScheduleData , @cutOffTime , @CreatedBy;      
                
         declare @ParentID1 bigint = 0      
               
         select @ParentID1 = isnull(ParentID,User_ID) from User_Detail(nolock) where User_ID = @CreatedBy      
      
                
             declare @Sender_Name1 as nvarchar(200) = ''    
         SELECT @Sender_Name1 = 'KitApp'  
   --ISNULL(Sender_Name , '')                  
   --       FROM Default_SenderID                  
   --       WHERE User_ID = @CreatedBy                  
   --          AND                   
   --        Sender_ID > 0;                  
          --SELECT @Sender_Name1;                  
          DECLARE @mobilenos1 VARCHAR(MAX);                  
             IF(@Sender_Name1 <> '' )                   
          BEGIN                  
            SET @mobilenos1 = dbo.udf_tsk_GetCollabortorMobiles ( STR(@CreatedBy));                  
        --EXEC usp_sendmessage @ParentId , @colMsgAss , @mobilenos , @Sender_Name , 0 , 2;               
              
   exec [usp_sendmessage_WithdltOrEvent]     335 , @colMsg , @mobilenos1 , @Sender_Name1 , 0 ,    2,null,@event ;                   
   --EXEC usp_sendmessage_WithDLTTemplateID @ParentID1 , @colMsg , @mobilenos1 , @Sender_Name1 , 0 ,    2,@DLTTemplateIDForNotification ;                   
                
          END;        
      
                
                      
                                END;            
                        END;            
                        SET @Counter = @Counter - 1;            
        END;            
        END;            
       -- EXEC usp_tsk_InsertReminder @Id;         
     EXEC usp_tsk_InsertReminder_WithDLTTemplateID @Id,@DLTTemplateIDForSMSReminder;         
             
   select @Id    
    
    END;


GO

/* ============================================================
   Procedure: [dbo].[usp_mk_update_leadnotes]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC usp_mk_update_leadnotes --usp_mk_get_leadnotes 327780,32222    
(    
@noteid bigint,    
@ParentID bigint ,  
@notes varchar(1000)  
)    
as    
begin    
  
update   tbl_LeadNotes  
set Notes = @notes ,UpdatedDate=getdate() 
where ParentID = @ParentID and NoteID = @noteid  

declare @LeadID bigint
select @LeadID=leadid from tbl_LeadNotes(nolock)  where  NoteID = @noteid   
  Begin try      
      
   Declare @UserID_LDACTV_1 bigint =  @parentID      
   Declare @evntMessage_1 nvarchar(max) = ''       
   Declare @NotesID_LDACTV_1 int = 99       
   Declare @CreatedOn_LDACTV_1 nvarchar(50) = ''      
   Declare @ParentID_LDACTV_1 bigint = @ParentID      
   Declare @LeadID_LDACTV_1 bigint = @LeadID      
      
   select top 1 @CreatedOn_LDACTV_1 = isnull(UpdatedDate,CreatedDate) from tbl_LeadNotes(nolock)  where NoteID=@noteid
   --isnull(CreatedDate,GETDATE()) from tbl_LeadNotes(nolock) --where  NoteID = @NotesID_LDACTV_1      
   --WHERE ParentID=@ParentID_LDACTV_1 and UserID=@UserID_LDACTV_1 and LeadID=@LeadID_LDACTV_1 order by NoteID desc      
      
      
   create table #tblEventDescrb_1      
   (      
     EVNT_Description nvarchar(max)       
   )      
      
  if( isnull(@LeadID_LDACTV_1,0) > 0 )      
   Begin      
          
   insert into #tblEventDescrb_1      
      exec  Usp_EventTemplate_DynamicVarReplacement 'Notes edited',@UserID_LDACTV_1,'','',0,'',null      
   ,0,0,'','',0,'',0,null,null,null,null,null,null,null,null,null      
   ,null,null,null,null,null,null,null,null,      
   0,0,0,null,null,null,0,null,null,null,0,null,@CreatedOn_LDACTV_1      
           
         
   select @evntMessage_1 = isnull( EVNT_Description,'') from #tblEventDescrb_1      
         
   select @evntMessage_1      
      
   if(@evntMessage_1 <> '')      
   Begin      
   exec UspSaveLeadActivity_withid @LeadID_LDACTV_1,@UserID_LDACTV_1,@ParentID_LDACTV_1,@evntMessage_1,    'Notes edited','tbl_LeadNotes',@noteID      
   end      
      
      
   End        
      
   end try      
   Begin catch      
      
      exec usp_insertErrorInfo      
      
   End catch      
      
    IF OBJECT_ID('tempdb..#tblEventDescrb_1') IS NOT NULL -- Check for table existence        
   Begin        
        DROP TABLE #tblEventDescrb_1        
   End        
         
         
   /* End lead activity  Edit Notes */      
        
    
end



GO

/* ============================================================
   Procedure: [dbo].[usp_mk_update_profile]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROC usp_mk_update_profile  
(  
  @User_ID      BIGINT,   
  @FName        VARCHAR(50),   
  @LName        VARCHAR(50),  
  @EMail        VARCHAR(50),   
  @Mobile       FLOAT,  
  @CountryCode VARCHAR(50),   
  @Company_Name VARCHAR(200),   
  @Image        VARCHAR(1000))  
AS  
BEGIN  
UPDATE User_Detail  
SET   
    FName=ISNULL(@FName, FName),   
    LName=ISNULL(@LName, LName),   
    EMail=ISNULL(@EMail, EMail),   
    Mobile=ISNULL(@Mobile, Mobile),   
    CompnayName=ISNULL(@Company_Name, CompnayName),   
    Image=ISNULL(@Image, Image)  
WHERE User_Id=@User_ID;  
 DECLARE @rowJson NVARCHAR(MAX) = (      
   SELECT *    
   FROM User_Detail WITH(NOLOCK)      
   WHERE User_Id = @User_ID      
   FOR JSON AUTO      
    ,INCLUDE_NULL_VALUES      
   )      
IF @rowJson IS NOT NULL  
BEGIN  
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @User_ID  
  ,@Activity_type = 'API_Updt_usr_profile'  
  ,@ActionType = 'U'  
  ,@RowJson = @rowJson  
  ,@Table_name = 'User_Detail'  
END  
END;


GO

