CREATE   PROCEDURE usp_mk_UpdateDailPaidCallDetail     
  @FilePath VARCHAR(MAX),     
  @UniqueId BIGINT,    
  @CallStartDateTime DATETIME,    
  @CallEndDateTime DATETIME,  
  @CallStatus NVARCHAR(500) = NULL  
AS    
BEGIN    
