/* ============================================================
   Procedure: [dbo].[usp_mk_UpdateDataeMp3ConvertedStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_mk_UpdateDataeMp3ConvertedStatus
@IsProcessed bit,
@ProcessedOn datetime,
@Reason varchar(max),
@Url varchar(max)
as
begin
	update tbl_DailPaidCallDetails
		set 
			IsProcessed = IIF(ISNULL(@IsProcessed, '') = '', 0, @IsProcessed ),
			ProcessedOn = IIF(ISNULL(@ProcessedOn, '') = '', GETDATE() , @ProcessedOn ),
			Reason = IIF(ISNULL(@Reason, '') = '', '' , @Reason )
				WHERE	CallRecordPath = @Url
end


