/* ============================================================
   Procedure: [dbo].[usp_mk_UpdateEnquiryLeadImgExt]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC usp_mk_UpdateEnquiryLeadImgExt
(
	@RowId BIGINT, 
	@Type  VARCHAR(1),
	@Ext   VARCHAR(10)
)
AS
BEGIN
    IF(@Type = 'E')
        BEGIN
            UPDATE UserEnquiry
                SET 
                    ProfileImgFileName = @Ext
            WHERE EnquiryID = @RowId;
            SELECT @@ROWCOUNT;
    END;
    IF(@Type = 'L')
        BEGIN
            UPDATE UserLeads
                SET 
                    ProfileImgFileName = @Ext
            WHERE ID = @RowId;
            SELECT @@ROWCOUNT;
    END;
END;


GO

