/* ============================================================
   Procedure: [dbo].[usp_mk_UpdateField]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE  [dbo].[usp_mk_UpdateField] (  
 @FieldId BIGINT = 0  
 ,@FieldName NVARCHAR(500) = ''  
 ,@FieldValue NVARCHAR(max)  
 ,@TableName NVARCHAR(500)  
 ,@UserId BIGINT = 0  
 ,@FilterExp NVARCHAR(MAX)  
 )  
AS  
BEGIN  
  
 --declare   
 -- @FieldId    BIGINT        = 0,   
 -- @FieldName  NVARCHAR(500) = 'PersonName',   
 -- @FieldValue NVARCHAR(500) = 'Namrata',   
 -- @TableName  NVARCHAR(500) = 'UserLeads',   
 -- @UserId     BIGINT        = 42045,   
 -- @FilterExp  NVARCHAR(MAX) = N'LeadId = 5659751'   
  
  
 DECLARE @upid BIGINT;  
  
 INSERT INTO fieldupdated (  
  Tablename  
  ,FieldName  
  ,Oldvalue  
  ,NewValue  
  ,CreatedBy  
  ,fieldid  
  )  
 SELECT @TableName  
  ,@FieldName  
  ,''  
  ,@FieldValue  
  ,@UserId  
  ,@fieldid;  
  
 SELECT @upid = SCOPE_IDENTITY();  
  
 IF NOT (  
   @FieldId = 0  
   AND @FieldName = ''  
   )  
 BEGIN  
  DECLARE @SQL NVARCHAR(MAX);  
  DECLARE @ParentId BIGINT;  
  
  /*Getting ParentID By User_ID*/  
  SELECT @ParentId = ParentID  
  FROM User_Detail with(nolock)  
  WHERE User_ID = @UserId;  
  
  BEGIN TRY  
   DECLARE @TableName_LDACTV NVARCHAR(200) = @TableName;  
  
  
   IF (@TableName_LDACTV = 'Userleads' OR @TableName_LDACTV = 'customfieldLeadvalue')  
   BEGIN  
  
  
    DECLARE @UserID_LDACTV BIGINT = @UserId  
     ,@ParentID_LDACTV BIGINT = @ParentId  
     ,@FieldName_LDACTV NVARCHAR(200) = @FieldName  
     ,@FieldValue_LDACTV NVARCHAR(500) = cast(@FieldValue as nvarchar) 
     ,@FilterExp_LDACTV NVARCHAR(MAX) = @FilterExp  
     ,@OldValue_LDACTV NVARCHAR(500) = ''  
     ,@NewValue_LDACTV NVARCHAR(500) = @FieldValue  
     ,@Query_LDACTV NVARCHAR(MAX) = ''  
     ,@ID NVARCHAR(50) = '0'  
     ,@customfieldName NVARCHAR(max)  
  
    --SET @Query_LDACTV = ' select top 1  ' + @FieldName_LDACTV + ', ID  from UserLeads(nolock) where ParentID = ' + CAST(@ParentID_LDACTV as nvarchar) + ' and ' + (REPLACE(@FilterExp_LDACTV, 'LeadId', 'ID'));  
    SELECT @ParentId = ParentID  
    FROM User_Detail  
    WHERE User_ID = @UserId;  
  
    SET @customfieldName = (  
      SELECT STRING_AGG(CONCAT (  
         '['  
         ,fieldname  
         ,']'  
         ), ',')  
      FROM (  
       SELECT DISTINCT fieldname  
       FROM customfields(NOLOCK)  
       WHERE ParentID = @ParentId  
       ) f  
      )  
    SET @Query_LDACTV = CONCAT (  
      ' select cast(', @fieldName, ' as nvarchar), ID from ( SELECT ul.* ',  
      iif(isnull(@customfieldName, '') <> '', ', c.*' , ''), '  FROM UserLeads(NOLOCK) ul '  
      ,iif(isnull(@customfieldName, '') <> '', CONCAT (  
        N' LEFT JOIN ( SELECT * FROM ( SELECT cfv.LeadID, cf.fieldname, cfv.fieldvalue FROM customfields(NOLOCK) ',
		N' cf INNER JOIN customfieldLeadvalue(NOLOCK) cfv ON cf.field_ID = cfv.fieldID  WHERE cf.ParentID = ',
		 cast(  @ParentId AS NVARCHAR), ' ) ipc PIVOT(MAX(fieldvalue) ', 
		N' FOR fieldname IN( ', @customfieldName, N' )) p ) c ON ul.ID = c.LeadID ', ''  
        ), '') + N' LEFT JOIN lead_score_history_latest(NOLOCK) LS ON UL.ID = LS.LeadId left join UserSourceSettings(nolock) us on ul.SourceName = us.SourceID left join UserMediumSettings(nolock) md on ul.MediumName = md.MediumID left join UserCampaignSettings(nolock) cm on ul.CampaignName = cm.CampaignID left join User_Detail(nolock) ag on ul.AssignedTo = ag.User_ID LEFT JOIN FollowUp_Status(NOLOCK) fs on ul.FollowUpStatus = fs.ID  WHERE ul.ParentID = ',  cast(@ParentId AS NVARCHAR) , ' and ' 
      , replace(@FilterExp, 'LeadId', 'ul.ID ')  
      ,' ) myTab '  
      )  
  
    print @Query_LDACTV  
	
    DROP TABLE IF EXISTS #temptbl DROP TABLE  
  
    IF EXISTS #tblEventDescrb  
     CREATE TABLE #temptbl (  
      OldValue NVARCHAR(max)  
      ,ID BIGINT  
      );  
  
    INSERT INTO #temptbl  
    EXECUTE sp_executesql @Query_LDACTV;  
  
    --SELECT @OldValue_LDACTV = OldValue  
    -- ,@ID = ID  
    --FROM #temptbl;  

	SELECT @OldValue_LDACTV = Case @FieldName 
			when 'MediumName' 
			Then (Select Name FROM UserMediumSettings where UserID=34594 and Cast(MediumID as nvarchar)=OldValue  ) 
			when 'SourceName' 
			Then (Select Name FROM UserSourceSettings where UserID=34594 and Cast(SourceID as nvarchar)=OldValue  ) 
			when 'CampaignName' 
			Then (Select Name FROM UserCampaignSettings where UserID=34594 and Cast(CampaignID as nvarchar)=OldValue  ) 
			Else OldValue
			END 
     ,@ID = ID  
    FROM #temptbl;  

  SELECT @NewValue_LDACTV = Case @FieldName 
			when 'MediumName' 
			Then (Select Name FROM UserMediumSettings where UserID=34594 and Cast(MediumID as nvarchar)=@NewValue_LDACTV  ) 
			when 'SourceName' 
			Then (Select Name FROM UserSourceSettings where UserID=34594 and Cast(SourceID as nvarchar)=@NewValue_LDACTV  ) 
			when 'CampaignName' 
			Then (Select Name FROM UserCampaignSettings where UserID=34594 and Cast(CampaignID as nvarchar)=@NewValue_LDACTV  ) 
			Else @NewValue_LDACTV
			END 
    --select  @OldValue_LDACTV,@ID      
    CREATE TABLE #tblEventDescrb (EVNT_Description NVARCHAR(MAX));  
  
    IF (ISNULL(@ID, 0) > 0)  
    BEGIN  
     INSERT INTO #tblEventDescrb  
     EXEC Usp_EventTemplate_DynamicVarReplacement 'Lead details edited'  
      ,@UserID_LDACTV  
      ,''  
      ,''  
      ,@ID  
      ,''  
      ,NULL  
      ,0  
      ,0  
      ,''  
      ,''  
      ,0  
      ,''  
      ,0  
      ,NULL  
      ,@FieldName_LDACTV  
      ,@OldValue_LDACTV  
      ,@NewValue_LDACTV  
      ,NULL  
      ,NULL  
      ,NULL  
      ,NULL  
      ,NULL  
      ,NULL  
      ,NULL  
      ,NULL  
      ,NULL  
      ,NULL  
      ,NULL  
      ,NULL  
      ,NULL  
      ,0  
      ,0  
      ,0  
      ,NULL  
      ,NULL  
      ,NULL  
      ,0  
      ,NULL  
      ,NULL  
      ,NULL  
      ,NULL  
      ,NULL  
      ,NULL;  
  
     DECLARE @evntMessage NVARCHAR(max) = '';  
  
     SELECT @evntMessage = (  
       SELECT isnull(EVNT_Description, '')  
       FROM #tblEventDescrb  
       );  
  
     IF (@evntMessage <> '')  
     BEGIN  
      EXEC UspSaveLeadActivity_withid @ID  
       ,@UserID_LDACTV  
       ,@ParentID_LDACTV  
       ,@evntMessage  
       ,'Lead details edited'  
       ,'fieldupdated'  
       ,@upid;  
     END  
    END;  
   END  
  
   /* Start Lead activity User details edited */  
   SET @SQL = CASE @TableName  
     /* Generating query for updateing UserEnquiry table*/  
     WHEN 'UserEnquiry'  
      THEN 'update ' + @TableName + ' set ' + @FieldName + ' = N''' + cast(@FieldValue as nvarchar) + ''' where ParentID = ' + CAST(@ParentId AS NVARCHAR) + ' AND ' + @FilterExp  
       /* Generating query for updateing UserLeads table*/  
     WHEN 'UserLeads'  
      THEN 'update ' + @TableName + ' set ModifiedOn = GETDATE() ,' + @FieldName + ' = N''' + cast(@FieldValue as nvarchar) + ''' where ParentID = ' + CAST(@ParentId AS NVARCHAR) + ' AND ' + REPLACE(@FilterExp, 'LeadId', 'ID')  
       /* Generating query for updateing Custom Field Enquiry Value table*/  
     WHEN 'customfieldEnquiryvalue'  
      THEN 'if(not exists(select * from customfieldEnquiryvalue where fieldID = ' + CAST(@FieldId AS NVARCHAR) + ' AND ' + @FilterExp + ')) begin INSERT INTO customfieldEnquiryvalue ( EnquiryID, fieldID, fieldvalue) VALUES ( CAST(LTRIM(RTRIM(SUBSTRING('''
 + @FilterExp + ''', (CHARINDEX(''='', ''' + @FilterExp + ''') + 1), LEN(''' + @FilterExp + ''')))) AS BIGINT), ' + CAST(@FieldId AS NVARCHAR) + ', ''' + @FieldValue + ''') end else begin update customfieldEnquiryvalue set fieldvalue = ''' + @FieldValue +
 ''' where fieldID = ' + CAST(@FieldId AS NVARCHAR) + ' AND ' + @FilterExp + ' end '  
       /* Generating query for updateing Custom Field Lead Value table*/  
     WHEN 'customfieldLeadvalue'  
      THEN 'if(not exists(select * from ' + @TableName + ' where fieldID = ' + CAST(@FieldId AS NVARCHAR) + ' AND ' + @FilterExp + ')) begin INSERT INTO ' + @TableName + ' ( LeadId, fieldID, fieldvalue) VALUES ( CAST(LTRIM(RTRIM(SUBSTRING(''' + @FilterExp
 + ''', (CHARINDEX(''='', ''' + @FilterExp + ''') + 1), LEN(''' + @FilterExp + ''')))) AS BIGINT), ' + CAST(@FieldId AS NVARCHAR) + ', ''' + @FieldValue + ''') end else begin update ' + @TableName + ' set fieldvalue = ''' + @FieldValue + ''' where fieldID
 = ' + CAST(@FieldId AS NVARCHAR) + ' AND ' + @FilterExp + ' end '  
     END;  
  
  
   IF (@FilterExp <> '')  
   BEGIN  
    PRINT @SQL;  
  
    EXECUTE sp_executesql @SQL;  
   END  
  
   SELECT @upid;  
  END TRY  
  
  BEGIN CATCH  
     
     
   EXEC usp_insertErrorInfo;  
  END CATCH  
 END;  
  
 DECLARE @rowJson NVARCHAR(MAX)  
  ,@rowout NVARCHAR(max)  
  
 SET @rowJson = CASE @TableName  
   WHEN 'UserEnquiry'  
    THEN 'Select @rowout= ( SELECT *  FROM ' + @TableName + ' WHERE ' + @FilterExp + ' FOR JSON AUTO ,INCLUDE_NULL_VALUES)'  
   WHEN 'UserLeads'  
    THEN 'Select @rowout= ( SELECT *  FROM ' + @TableName + ' WHERE ' + REPLACE(@FilterExp, 'LeadId', 'ID') + ' FOR JSON AUTO ,INCLUDE_NULL_VALUES)'  
   WHEN 'customfieldEnquiryvalue'  
    THEN 'Select @rowout= ( SELECT *  FROM ' + @TableName + ' WHERE fieldID = ' + CAST(@FieldId AS NVARCHAR) + ' AND ' + @FilterExp + ' FOR JSON AUTO ,INCLUDE_NULL_VALUES)'  
   WHEN 'customfieldLeadvalue'  
    THEN 'Select @rowout= ( SELECT *  FROM ' + @TableName + ' WHERE fieldID = ' + CAST(@FieldId AS NVARCHAR) + ' AND ' + @FilterExp + ' FOR JSON AUTO ,INCLUDE_NULL_VALUES)'  
   END;  
  
 EXECUTE sp_executesql @rowJson  
  ,N'@rowout nvarchar(max) OUT'  
  ,@rowout OUT;  
  
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId  
  ,@Activity_type = 'Updt_Leadenq_wtsapp'  
  ,@ActionType = 'U'  
  ,@RowJson = @rowout  
  ,@Table_name = @TableName  
  
end



GO

/* ============================================================
   Procedure: [dbo].[Usp_MK_UpdateLead_For_FollowupStatus_ChangeWithFollowupDate]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROCEDURE [dbo].[Usp_MK_UpdateLead_For_FollowupStatus_ChangeWithFollowupDate]  
(          
    @ID BIGINT,          
    @AssignedTo BIGINT,          
    @FollowUpStatus INT,          
    @NextStatusDate VARCHAR(50),          
    @Products VARCHAR(1000),          
    @AmountPaid NUMERIC(18, 2),          
    @Remarks VARCHAR(1000),          
    @ModifiedBy BIGINT          
)          
AS          
BEGIN          
        
  declare @FollowupDate   Datetime = null, @LeadNo bigint=0  
  if(@NextStatusDate <> '')            
   Begin            
     set @FollowupDate = @NextStatusDate            
   End           
        
  if(@NextStatusDate <> '')            
   Begin       
         
 UPDATE UserLeads          
 SET    AssignedTo = @AssignedTo,          
        FollowUpStatus = @FollowUpStatus,          
        NextStatusDate = convert(nvarchar(100),dbo.[fn_getISTtimefromusertime](ParentID,@NextStatusDate),121) ,           
        Products = @Products,          
        AmountPaid = @AmountPaid,          
        Remarks = @Remarks,          
        ModifiedBy = @ModifiedBy ,         
        FollowupDate = dbo.[fn_getISTtimefromusertime](ParentID,@FollowupDate),  
    @LeadNo = LeadNo  
 WHERE  ID = @ID          
           
    End    
  else    
    Begin    
        
   UPDATE UserLeads          
      SET AssignedTo = @AssignedTo,          
        FollowUpStatus = @FollowUpStatus,          
        NextStatusDate = @NextStatusDate,          
        Products = @Products,          
        AmountPaid = @AmountPaid,          
        Remarks = @Remarks,          
        ModifiedBy = @ModifiedBy ,         
        FollowupDate =  @FollowupDate,  
    @LeadNo = LeadNo  
        WHERE  ID = @ID          
    
        
    End         
           
           
 SELECT 'Record Updated' as msg, @LeadNo as LeadNo  
END     


GO

/* ============================================================
   Procedure: [dbo].[usp_mk_UpdateLeadFieldAPI]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_mk_UpdateLeadFieldAPI (
	@IdentifierField nvarchar(255),
	@IdentifierValue nvarchar(510),
	@Username nvarchar(510),
	@Password nvarchar(510),
	@tblLeadFields tblLeadField readonly
)
as
begin

--declare @tblLeadFields as dbo.tblLeadField
--insert into @tblLeadFields values(1,N'MobileNo1',N'7896541230',0)
--insert into @tblLeadFields values(2,N'CountryCode1',N'+91',0)

--declare
--	@IdentifierField nvarchar(255) =N'LeadNo',
--	@IdentifierValue nvarchar(510) = N'7', 
--	@Username nvarchar(510) = N'kmukesh343',
--	@Password nvarchar(510) = N'whatsapp1'
	 

	if(exists(
		select * from User_Detail(nolock) where
		User_Login COLLATE SQL_Latin1_General_CP1_CS_AS = @Username
			and Pwd COLLATE SQL_Latin1_General_CP1_CS_AS = @Password
	))
	begin
		drop table if exists #tblLeadFields
		select * into #tblLeadFields from  @tblLeadFields
		
		declare @ParentId bigint, @UserId bigint
		select @UserId = User_ID, @ParentId = ParentID from User_Detail(nolock) 
			where User_Login COLLATE SQL_Latin1_General_CP1_CS_AS = @Username
				and Pwd COLLATE SQL_Latin1_General_CP1_CS_AS = @Password
		
		begin try
			declare @LeadId bigint, @leadIdSql nvarchar(max), @ParamDefinition nvarchar(510),
			@colDataType nvarchar(25)

			declare @tempColName as table(
				colName nvarchar(510),
				colDataType  nvarchar(510),
				fieldType  nvarchar(510)
			)
			--drop table if exists #tempColName

			insert into @tempColName( colName, colDataType, fieldType)
			select cl.colName, cl.colDataType, cl.fieldType from (
					select COLUMN_NAME as colName, DATA_TYPE as colDataType, 'UserLeads' as fieldType from INFORMATION_SCHEMA.COLUMNS where TABLE_NAME = 'UserLeads'
						union
					select fieldname as colName, 
						(case datatype when 'd' then 'datetime' 
							when 'f' then 'numeric'
							when 'v' then 'nvarchar'  
							when 'r' then 'nvarchar'  
							when 'm' then 'nvarchar'  
							when 's' then 'nvarchar'  
							when 'c' then 'nvarchar'  
							when 'e' then 'nvarchar'  
						end ) as colDataType,
						'customfieldLeadvalue' as fieldType
					from customfields where ParentID = @ParentId
				) cl 

			if (exists (
				select * from @tempColName where colName = @IdentifierField
			))
			begin

				select @colDataType = colDataType from @tempColName where colName = @IdentifierField

				declare @MobileNo nvarchar(20), @CountryCode nvarchar(10)
				
				select top 1 @CountryCode=ltrim(rtrim(countrycode)) 
					from m_country1 where ltrim(rtrim(countrycode))=left(@IdentifierValue,len(ltrim(rtrim(countrycode))))
				
				seLECt @MobileNo = replace(@IdentifierValue, @CountryCode, '')
				
				set @ParamDefinition = ' @LeadIdOUT bigint OUTPUT '
				
				if(lower(@IdentifierField) in ('leadno', 'mobileno', 'emailid'))
				begin

					if( trim(lower(@IdentifierField)) = 'leadno')
					begin
						
						set @leadIdSql = concat( 'select top 1 @LeadIdOUT = ID from UserLeads(nolock) where ParentID = ',
							@ParentId, ' and ', @IdentifierField, ' = ',
							case when lower(@colDataType) = 'nvarchar' then concat('''', @IdentifierValue, '''')
								when lower(@colDataType) = 'varchar' then concat('''', @IdentifierValue, '''')
								when lower(@colDataType) = 'datetime' then concat('''', @IdentifierValue, '''')
								else @IdentifierValue end)
					end
					else if (trim(lower(@IdentifierField)) = 'mobileno')
					begin
						if(len(@CountryCode) > 0 and len(@MobileNo) > 0 )
						begin
							set @leadIdSql = concat( 'select top 1 @LeadIdOUT = ID from UserLeads(nolock) where ParentID = ',
							@ParentId, ' and ', 
							' (( CountryCode = ''',  @CountryCode, ''' and MobileNo = ''' , @MobileNo, ''' ) ', 
							' or ( CountryCode1 = ''', @CountryCode, ''' and MobileNo1 = ''', @MobileNo, ''' ) ',
							' or ( CountryCode2 = ''', @CountryCode, ''' and MobileNo2 = ''', @MobileNo, ''' )) ')
						end
					end
					else if ( trim(lower(@IdentifierField)) = 'emailid')
					begin
						if(len(@IdentifierValue) > 0 )
						begin
							set @leadIdSql =  concat( 'select top 1 @LeadIdOUT = ID from UserLeads(nolock) where ParentID = ',
							@ParentId, ' and ', 
							' ( EmailID = ''',  @IdentifierValue, ''' ', 
							' or EmailID1 = ''', @IdentifierValue, ''' ',
							' or  EmailID2 = ''', @IdentifierValue, ''' )')
						end
					end 								
					
					if(len(@leadIdSql) > 0)
					begin

						execute sp_executesql @leadIdSql, @ParamDefinition, @LeadIdOUT = @LeadId OUTPUT;
						if( @LeadId > 0 )
						begin
							while( exists (select 1 from #tblLeadFields where is_process = 0 ) )
							begin
								declare @fieldName nvarchar(255), @filedValue nvarchar(512), @fieldId bigint, @filterText nvarchar(255) = concat(' LeadId = ', str(@LeadId))
			
								select top 1 @fieldId = id, @fieldName = field_name, @filedValue = filed_value from #tblLeadFields where is_process = 0 
					
								declare @fieldType nvarchar(255) = ( select fieldType from @tempColName where colName = @fieldName)
						
								--exec usp_mk_UpdateField		
								--	@LeadId,
								--	@fieldName,
								--	@filedValue,
								--	@fieldType,
								--	@UserId,
								--	@filterText


								update #tblLeadFields set is_process = 1 where id = @fieldId
							end
							select 'Data submitted successfully.'
						end
					end
					else
					begin
						select concat(@IdentifierField,  ' Please provide valid data ')
					end
			
				end
				else
				begin
					select concat(@IdentifierField,  ' Invalid Identifier Field Name ')
				end
				
			end

		end try
		begin catch
			exec usp_InsertErrorInfo
		end catch
	end
	else
	begin
		select 'Username or Password incorrect';
	end
end



GO

