/* ============================================================
   Procedure: [dbo].[usp_mk_UpdatePhysicalAppointmentFormStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_mk_UpdatePhysicalAppointmentFormStatus]
(
    @PhysicalAppointmentId BIGINT,
    @FormType              VARCHAR(20),     -- 'CheckIn' or 'CheckOut'
    @JsonDetail            NVARCHAR(MAX)    -- full JSON object
)
AS
BEGIN
    SET NOCOUNT ON;

    BEGIN TRY
        -- 1?? Validate ID
        IF NOT EXISTS (
            SELECT 1 
            FROM TBL_ET_PhysicalAppointment WITH (NOLOCK)
            WHERE PhysicalAppointmentId = @PhysicalAppointmentId
        )
        BEGIN
            SELECT Success = 0, Message = 'Invalid PhysicalAppointmentId';
            RETURN;
        END

        -- 2?? Validate FormType
        IF (@FormType NOT IN ('CheckIn', 'CheckOut'))
        BEGIN
            SELECT Success = 0, Message = 'Invalid FormType. Must be CheckIn or CheckOut.';
            RETURN;
        END

        -- 3?? Parse JSON keys
        DECLARE 
            @FormId BIGINT = TRY_CAST(JSON_VALUE(@JsonDetail, '$.formid') AS BIGINT),
            @IsDynamicWebForm BIT = TRY_CAST(JSON_VALUE(@JsonDetail, '$.is_dynamicwebform') AS BIT),
            @IsFilled BIT = TRY_CAST(JSON_VALUE(@JsonDetail, '$.is_filled') AS BIT),
            @EntryId BIGINT = TRY_CAST(JSON_VALUE(@JsonDetail, '$.entryid') AS BIGINT);

        -- 4?? Determine target columns
        DECLARE 
            @TargetJsonColumn NVARCHAR(100),
            @TargetFlagColumn NVARCHAR(100);

        IF @FormType = 'CheckIn'
        BEGIN
            SET @TargetJsonColumn = 'CheckIn_Form_Detail';
            SET @TargetFlagColumn = 'IsCheckInFormFilled';
        END
        ELSE
        BEGIN
            SET @TargetJsonColumn = 'CheckOut_Form_Detail';
            SET @TargetFlagColumn = 'IsCheckOutFormFilled';
        END

        -- 5?? Fetch existing JSON
        DECLARE @ExistingJson NVARCHAR(MAX);

        DECLARE @FetchSql NVARCHAR(MAX) = 
            N'SELECT @ExistingJsonOut = ' + QUOTENAME(@TargetJsonColumn) + 
            N' FROM TBL_ET_PhysicalAppointment WHERE PhysicalAppointmentId = @Id';

        EXEC sp_executesql 
            @FetchSql, 
            N'@Id BIGINT, @ExistingJsonOut NVARCHAR(MAX) OUTPUT',
            @PhysicalAppointmentId, @ExistingJson OUTPUT;

        -- 6?? Merge or replace JSON
        DECLARE @FinalJson NVARCHAR(MAX);

        IF ISNULL(@ExistingJson, '') = ''
        BEGIN
            SET @FinalJson = @JsonDetail;
        END
        ELSE
        BEGIN
            SET @FinalJson = @ExistingJson;
            SET @FinalJson = JSON_MODIFY(@FinalJson, '$.formid', @FormId);
            SET @FinalJson = JSON_MODIFY(@FinalJson, '$.is_dynamicwebform', @IsDynamicWebForm);
            SET @FinalJson = JSON_MODIFY(@FinalJson, '$.is_filled', @IsFilled);
            SET @FinalJson = JSON_MODIFY(@FinalJson, '$.entryid', @EntryId);
        END

        -- 7?? Update JSON + Flag
        DECLARE @UpdateSql NVARCHAR(MAX) =
            N'UPDATE TBL_ET_PhysicalAppointment 
              SET ' + QUOTENAME(@TargetJsonColumn) + N' = @JsonData, 
                  ' + QUOTENAME(@TargetFlagColumn) + N' = @IsFilled
              WHERE PhysicalAppointmentId = @Id';

        EXEC sp_executesql 
            @UpdateSql,
            N'@JsonData NVARCHAR(MAX), @IsFilled BIT, @Id BIGINT',
            @FinalJson, @IsFilled, @PhysicalAppointmentId;

        -- 8?? Return success
        SELECT 
            Success = 1,
            Message = CONCAT(@FormType, ' form updated successfully for AppointmentId ', @PhysicalAppointmentId),
            PhysicalAppointmentId = @PhysicalAppointmentId,
            UpdatedOn = GETDATE(),
            FinalJson = @FinalJson;

    END TRY
    BEGIN CATCH
        SELECT 
            Success = 0,
            Message = CONCAT('Error in usp_mk_UpdatePhysicalAppointmentFormStatus: ', ERROR_MESSAGE()),
            ErrorLine = ERROR_LINE(),
            ErrorSeverity = ERROR_SEVERITY(),
            ErrorState = ERROR_STATE();
    END CATCH
END


GO

/* ============================================================
   Procedure: [dbo].[usp_mk_UpdateS3UrlOrFileName]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_mk_UpdateS3UrlOrFileName  
@UniqueId   BIGINT,   
@UrlOrFileName NVARCHAR(1000),  
@TableName NVARCHAR(500)  
AS  
BEGIN  
    DECLARE @SQL NVARCHAR(MAX);  
    SET @SQL = CASE  
                    WHEN LOWER(@TableName) = 'userenquiry'  
      THEN 'update UserEnquiry set ProfileImgFileName  = ''' + @UrlOrFileName + ''' where EnquiryID = ' + CAST(@UniqueId AS NVARCHAR)  
                    WHEN LOWER(@TableName) = 'userleads'  
      THEN 'update UserLeads set ProfileImgFileName  = ''' + @UrlOrFileName + ''' where ID = ' + CAST(@UniqueId AS NVARCHAR)  
                END;  
 PRINT @SQL  
  
 EXECUTE(@SQL)  
  
END;




