/* ============================================================
   Procedure: [dbo].[usp_mk_UpdateUserEnquiryDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_mk_UpdateUserEnquiryDetails]                   
(                  
    @EnquiryID BIGINT,                  
    @PersonName NVARCHAR(100),                  
    @PersonImage NVARCHAR(200)= '',                  
    @CompanyName NVARCHAR(100),                 
    @MobileNo NVARCHAR(100),                 
    @EmailID NVARCHAR(100),                  
    @City NVARCHAR(50),                  
    @State NVARCHAR(50),                  
    @Country NVARCHAR(50),                   
    @ResidentialAddress NVARCHAR(500) = NULL,                  
    @OfficeAddress NVARCHAR(500) = NULL,                  
    @PinCode BIGINT,                           
    @SourceName BIGINT,                  
    @MediumName BIGINT,                  
    @CampaignName BIGINT,                  
    @InitialRemarks NVARCHAR(1000),                  
    @ParentID BIGINT,                
    @custom customEnquiry readonly                  
)                              
AS                               
BEGIN             
DECLARE @Userid bigint= (select CreatedBy from UserEnquiry(nolock) where EnquiryID=@EnquiryID )
 UPDATE UserEnquiry                  
 SET    PersonName = @PersonName,  
        ProfileImgFileName = @PersonImage,  
        CompanyName = @CompanyName,                    
        MobileNo = @MobileNo,                
        EmailID = @EmailID,                  
        City = @City,                  
        STATE = @State,                  
        Country = @Country,                 
        ResidentialAddress = @ResidentialAddress,                  
        OfficeAddress = @OfficeAddress,                  
        PinCode = @PinCode,                  
        SourceName = @SourceName,                  
        MediumName = @MediumName,                  
        CampaignName = @CampaignName,                  
        InitialRemarks = @InitialRemarks,                  
        ParentID = @ParentID                  
 WHERE  EnquiryID = @EnquiryID                
               
 select * into #update from @custom              
 update #update set EnquiryID=@EnquiryID;                
   select * into #insert from #update where fieldID not in (select isnull(fieldID, 0) From customfieldEnquiryvalue where EnquiryID = @EnquiryID)                
   --delete From #update where EnquiryID in (select EnquiryID from #insert)                
   delete From #update where fieldID in (select fieldID from #insert)                
   declare @updatecount smallint                
   declare @insertcount smallint                
   select @updatecount=isnull(COUNT(fieldID), 0) from #update                
   select @insertcount=isnull(COUNT(fieldID), 0) from #insert                
   if(@updatecount >0)                
   begin                
 Update customfieldEnquiryvalue                  
    SET                   
    fieldvalue = r.fieldvalue                  
    from #update r                  
    Where customfieldEnquiryvalue.EnquiryID = r.EnquiryID and customfieldEnquiryvalue.fieldID=r.fieldID                  
    end                
    if(@insertcount >0)                
    begin                
    insert into customfieldEnquiryvalue (EnquiryID,fieldID,fieldvalue) select * from #insert;                
   end                
   drop table #update;                
   drop table #insert;                        
 SELECT 'Record Updated Successfully'    

       DECLARE @rowJson NVARCHAR(MAX) = (      
   SELECT *      
   FROM UserEnquiry WITH(NOLOCK)      
   WHERE EnquiryID = @EnquiryID      
   FOR JSON AUTO      
    ,INCLUDE_NULL_VALUES      
   )      
 IF @rowJson IS NOT NULL      
 BEGIN      
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @Userid      
  ,@Activity_type = 'Updt_User_EnqryDetails'      
  ,@ActionType = 'U'      
  ,@RowJson = @rowJson      
  ,@Table_name = 'UserEnquiry'      
 END 
END   


GO

