/* ============================================================
   Procedure: [dbo].[usp_mk_VarReplacementTaskAppointment]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE dbo.usp_mk_VarReplacementTaskAppointment
(@EventName NVARCHAR(500)  = NULL, 
 @UserID    BIGINT         = NULL, 
 @LeadID    BIGINT         = NULL, 
 @TaskType  NVARCHAR(1000) = NULL, 
 @TaskTitle NVARCHAR(1000) = NULL, 
 @Outcome   NVARCHAR(1000) = NULL
)
AS
BEGIN
    DECLARE @UserName NVARCHAR(200)= '';
    DECLARE @LeadName NVARCHAR(200)= '';
    DECLARE @EventDescription NVARCHAR(MAX)= '';
    DECLARE @EventTemplate NVARCHAR(MAX)= '';
    DECLARE @EventID BIGINT= 0;
    SELECT @UserName = ISNULL(User_Login, '')
    FROM User_Detail
    WHERE User_ID = ISNULL(@UserID, 0);
    SELECT @LeadName = ISNULL(personName, '')
    FROM UserLeads
    WHERE id = ISNULL(@LeadID, 0);
    DECLARE @EditedDateTIme NVARCHAR(100)= GETDATE();
    SELECT @EventID = ISNULL(ID, 0), 
            @EventTemplate = ISNULL(EventTemplate, '')
    FROM ActivityMaster
    WHERE EventName = @EventName;
    IF(@EventID > 0)
        BEGIN
            SELECT @EventDescription = REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(@EventTemplate, ''), '#TaskType#', ISNULL(@TaskType, '')), '#TaskTitle#', ISNULL(@TaskTitle, '')), '#username#', ISNULL(@UserName, '')), '#leadname#', ISNULL(@LeadName, '')), '#Outcome#', ISNULL(@Outcome, '')), '#EditedDateTime#', @EditedDateTIme), '#AppointmentTitle#', ISNULL(@TaskTitle, '')), '#AppointmentDateTime#', @EditedDateTIme);
    END;
    SELECT ISNULL(@EventDescription, '') AS EventDescription;
END;


GO

