/* ============================================================
   Procedure: [dbo].[Usp_ML_ChangeStatusPermissionMast]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_ML_ChangeStatusPermissionMast]             
(            
 -- @Permissionid bigint,  
  @RoleId bigint,
  @EntityId bigint          
  --@MetaData nvarchar(200)  
)            
as            
Begin     
  --declare 
  --@Permissionid bigint=5,  
  --@RoleId bigint=55,
  --@tpuserid bigint=60  ,          
  --@MetaData nvarchar(200)  ='{"IPAddress":"::1","MacAddress":"00FF08A6B99C","IsImpersonation":false,"ImpersonatorId":0}'
DECLARE @Status int=1 ,@ParentID Bigint,@UserID Bigint, @TimeZone nvarchar (400)  ,@rowJson NVARCHAR(MAX)  , @IPAdress NVARCHAR(50),@DeviceId NVARCHAR(50),@IsImpersonation BIT ,@ImpersonatorId INT    
Select @ParentID = ParentId,@TimeZone = TimeZone, @UserID=User_Id From tbl_tp_UserLogin (noLock) Where TpUser_Id = @EntityId            

			   IF @ParentId IS NULL
    BEGIN
        SET @ParentId = (SELECT ParentId FROM User_Detail WITH (NOLOCK) WHERE User_Id = @EntityId)
    END
 --   SET @IPAdress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress)    
 --SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress)    
 --SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation)    
 --SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId)   

   Begin        
       Update  tbl_ML_RolesMaster set IsActive = 0  where Role_Id = @RoleId        
  
	   
	   Update  tbl_ML_Permission_Mapping set IsActive = 0  where Role_Id = @RoleId   
     
