/* ============================================================
   Procedure: [dbo].[usp_ml_CreateMediaTokenIfRequired]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ml_CreateMediaTokenIfRequired]
    @userid INT
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @entityID INT;
    DECLARE @loginName VARCHAR(100);
    DECLARE @parentID INT;
    DECLARE @token UNIQUEIDENTIFIER;
    DECLARE @expiryDate DATETIME = DATEADD(DAY, 30, GETDATE());
    DECLARE @planEndDate DATE;

    -- First check if the user exists in User_Detail
    IF EXISTS (SELECT 1 FROM User_Detail (NOLOCK) WHERE User_id = @userid)
    BEGIN
        SELECT TOP 1 
            @entityID = ue.User_id,
            @loginName = ue.User_Login,
            @parentID = ue.ParentID
        FROM User_Detail (NOLOCK) ue
        WHERE ue.User_id = @userid
    END
    -- Else check in tbl_tp_UserLogin
    ELSE IF EXISTS (SELECT 1 FROM tbl_tp_UserLogin (NOLOCK) WHERE TpUser_Id = @userid)
    BEGIN
        SELECT TOP 1 
            @entityID = ul.TpUser_Id,
            @loginName = ul.LoginName,
            @parentID = ul.ParentID
        FROM tbl_tp_UserLogin (NOLOCK) ul
        WHERE ul.TpUser_Id = @userid
    END
    ELSE
    BEGIN
        -- Invalid user - no action
        RETURN;
    END

    -- Check if token already exists and is valid
    IF NOT EXISTS (
        SELECT 1 
        FROM Tbl_ML_MediaLibraryToken (NOLOCK) 
        WHERE EntityID = @entityID AND ExpiryDate > GETDATE()
    )
    BEGIN
        -- Check if user has an active subscription
        SELECT @planEndDate = MAX(PlanEndDate)
        FROM Price_UserSubscriptionDetails (NOLOCK)
        WHERE UserID = @userid AND IsNewPlan = 1;

        IF (@planEndDate IS NOT NULL AND @planEndDate >= CAST(GETDATE() AS DATE))
        BEGIN
            -- Generate new token
            SET @token = NEWID();

            -- Insert into token table
            INSERT INTO Tbl_ML_MediaLibraryToken (EntityID, Token, ExpiryDate,Created_ON)
            VALUES (@entityID, @token, @expiryDate, GETDATE());

            -- Optionally return the new token (in your desired format)
            SELECT 
                'Valid' AS [Status], 
                @entityID AS EntityID, 
                @token AS Token, 
                @parentID AS ParentID, 
                @loginName AS User_Login;
        END
    END
END



GO

/* ============================================================
   Procedure: [dbo].[usp_ml_deduct_storageoveruse]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ml_deduct_storageoveruse]
AS
BEGIN
    SET NOCOUNT ON;
 
    BEGIN TRY
 
        PRINT 'Step 1: Calculating Overused Users...';
 
		drop table if exists #t
		select parentid, UserStorage,dbo.fn_getallowedstorage(parentid) AllowedUsage,cast(ceiling(UserStorage-dbo.fn_getallowedstorage(parentid)) as int) as OverUsage  into #t from tbl_ML_StorageInformation(nolock) where 
		UserStorage>dbo.fn_getallowedstorage(parentid)
 
 
        PRINT 'Step 1 Completed: Overused users inserted into @Overused table.';
 
        DECLARE @Count INT,@parentid bigint=0,@cost numeric(18,2),@intcreditid bigint,@totcost numeric(18,2),@mid bigint,@overusage int,@remarks nvarchar(1000);
        SELECT @Count = COUNT(*) FROM #t;
        PRINT 'Total overused users: ' + CAST(@Count AS VARCHAR);
 
		drop table if exists #i
		create table #i(intcreditid bigint)
        IF @Count = 0
        BEGIN
            PRINT 'No users exceeded their quota.';
            RETURN;
        END
 
        -------------------------------
        PRINT 'Step 2: Deducting via usp_remote_deduct_or_refund_int_bal...';
 
        WHILE @count>0
        BEGIN
          select @parentid=min(parentid) from #t where parentid>@parentid
		  select @mid=m_id from user_detail(nolock) where user_id=@parentid
		  select top 1 @cost=pricepermonth from Price_Base_Storage_Rate(nolock) where parentid in (0,@parentid) order by Parentid desc
		  select @cost=isnull(@cost,5.00)
		  select @overusage=overusage,@remarks=concat('Credit deducted for over usage of storage by ',overusage,' GB against permitted limit of ',AllowedUsage,' GB.') from #t where parentid=@parentid
		  select @totcost=@overusage*@cost
 
		    insert into #i
            EXEC usp_remote_deduct_or_refund_int_bal @parentid,@mid,0,@totcost,20,@remarks;
 
			select @intcreditid=intcreditid from #i
		  insert into tbl_ML_UserStorageQuota(ParentID,AllocatedSpace,AllocationType,StorageUnit,StartDate,ExpiryDate,IsActive,CreatedDate,ModifiedDate,Createdby,Modifiedby,RefTable,RefId)
		  select @parentid,@overusage,'OverusedAddon','GB',getdate(),dateadd(M,1,getdate()),1,getdate(),getdate(),@parentid,@parentid,'Intcredit_details',@intcreditid
 
		  truncate table #i
		  set @count=@count-1
        END
 
        PRINT 'Step 2 Completed: Credits deducted.';
 
 
    END TRY
    BEGIN CATCH
		exec usp_inserterrorinfo 
	END CATCH
END
 


GO

