/* ============================================================
   Procedure: [dbo].[usp_ml_GetAzureUrlByCustomUrl]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ml_GetAzureUrlByCustomUrl]

    @CustomUrl NVARCHAR(MAX)

AS

BEGIN

    SET NOCOUNT ON;
 
    ----------------------------------------------------

    -- 1) Normalize / Clean Input Path

    ----------------------------------------------------

    DECLARE @NormalizedUrl NVARCHAR(MAX) = @CustomUrl;
 
    -- Convert common URL encodings → real characters

    SET @NormalizedUrl = REPLACE(@NormalizedUrl, '%20', ' '); -- space

    SET @NormalizedUrl = REPLACE(@NormalizedUrl, '%28', '('); -- (

    SET @NormalizedUrl = REPLACE(@NormalizedUrl, '%29', ')'); -- )

    SET @NormalizedUrl = REPLACE(@NormalizedUrl, '%5B', '['); -- [

    SET @NormalizedUrl = REPLACE(@NormalizedUrl, '%5D', ']'); -- ]

    SET @NormalizedUrl = REPLACE(@NormalizedUrl, '%2C', ','); -- ,

    SET @NormalizedUrl = REPLACE(@NormalizedUrl, '%27', ''''); -- apostrophe

    -- Collapse multiple slashes into single slash

    WHILE CHARINDEX('//', @NormalizedUrl) > 0

        SET @NormalizedUrl = REPLACE(@NormalizedUrl, '//', '/');
 
    -- Trim leading and trailing slashes/spaces

    SET @NormalizedUrl = LTRIM(RTRIM(@NormalizedUrl));

    IF LEFT(@NormalizedUrl,1) = '/'

        SET @NormalizedUrl = RIGHT(@NormalizedUrl, LEN(@NormalizedUrl)-1);
 
    ----------------------------------------------------

    -- 2) Perform lookup

    ----------------------------------------------------

    SELECT AzureUrl

    FROM dbo.tbl_ML_UrlMapping WITH (NOLOCK)

    WHERE 

        REPLACE(LTRIM(RTRIM(CustomUrl)), '//', '/') = @NormalizedUrl;

END




GO

