/* ============================================================
   Procedure: [dbo].[Usp_ML_GetQuota]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-------------------------------------------------------------------------------------------
CREATE   PROCEDURE [dbo].[Usp_ML_GetQuota]
    @ParentID BIGINT
AS
BEGIN
    --DECLARE @ParentID BIGINT = 34594;  
    SET NOCOUNT ON;

    DECLARE @TotalAllocatedSpace NUMERIC(20, 0) = 0;
    DECLARE @StorageUnit NVARCHAR(10) = 'MB';
    DECLARE @AlertThresholdPercentage INT = 0;

    -- Step 1: Check for valid Purchased space first, only if StartDate is valid and ExpiryDate is in the future
    SELECT TOP 1 
        @TotalAllocatedSpace = ISNULL(AllocatedSpace, 0),
        @StorageUnit = ISNULL(StorageUnit, 'MB'),
        @AlertThresholdPercentage = ISNULL(AlertThresholdPercentage, 0)
    FROM tbl_ML_UserStorageQuota
    WHERE ParentID = @ParentID 
      AND AllocationType = 'Purchased' 
      AND IsActive = 1
      AND StartDate <= GETDATE() 
      AND (ExpiryDate IS NULL OR ExpiryDate >= GETDATE());

    -- Step 2: If no valid purchased space is found (or if purchased allocation is expired), check for Default space for the same ParentID
    IF @TotalAllocatedSpace = 0
    BEGIN
        SELECT TOP 1 
            @TotalAllocatedSpace = ISNULL(AllocatedSpace, 0),
            @StorageUnit = ISNULL(StorageUnit, 'MB'),
            @AlertThresholdPercentage = ISNULL(AlertThresholdPercentage, 0)
        FROM tbl_ML_UserStorageQuota
        WHERE ParentID = @ParentID 
          AND AllocationType = 'Default' 
          AND IsActive = 1;
    END

    -- Step 3: If no Default space is found for the ParentID, fallback to Global Default (ParentID = 0)
    IF @TotalAllocatedSpace = 0
    BEGIN
        SELECT TOP 1 
            @TotalAllocatedSpace = ISNULL(AllocatedSpace, 0),
            @StorageUnit = ISNULL(StorageUnit, 'MB'),
            @AlertThresholdPercentage = ISNULL(AlertThresholdPercentage, 0)
        FROM tbl_ML_UserStorageQuota
        WHERE ParentID = 0 
          AND AllocationType = 'Default' 
          AND IsActive = 1;
    END

    -- Return the final TotalAllocatedSpace, StorageUnit, and AlertThresholdPercentage
    SELECT 
        @TotalAllocatedSpace AS TotalAllocatedSpace,
        @StorageUnit AS StorageUnit,
        @AlertThresholdPercentage AS AlertThresholdPercentage;

END;




GO

/* ============================================================
   Procedure: [dbo].[usp_ml_GetStorageLibraryList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ml_GetStorageLibraryList]
    @ReceivedLink NVARCHAR(500) = NULL,  -- e.g. '32222\Contact'
    @ParentId BIGINT = NULL,
    @UserId INT = NULL,
    @IsRoot BIT = 0,
    @PageNumber INT = 1,
    @PageSize INT = 20
AS
BEGIN
	--DECLARE
 --   @ReceivedLink NVARCHAR(500) = '32222',  -- e.g. '32222\Contact'
 --   @ParentId BIGINT = NULL,
 --   @UserId INT = NULL,
 --   @IsRoot BIT = 0,
 --   @PageNumber INT = 1,   -- start with first page
 --   @PageSize   INT = 100   -- number of records per page
    SET NOCOUNT ON;

    DECLARE @FolderId BIGINT = NULL;
    DECLARE @NormalizedLink NVARCHAR(500);

    -- Normalize path (replace / with \ and trim extra \ from start)
    IF @ReceivedLink IS NOT NULL
    BEGIN
        SET @NormalizedLink = LTRIM(RTRIM(REPLACE(@ReceivedLink, '/', '\')));
        IF LEFT(@NormalizedLink, 1) = '\' 
            SET @NormalizedLink = RIGHT(@NormalizedLink, LEN(@NormalizedLink) - 1);
    END

    -- Find FolderId based on PhysicalPath
    IF @NormalizedLink IS NOT NULL AND @NormalizedLink <> ''
    BEGIN
        SELECT TOP 1 @FolderId = FolderId
        FROM tbl_ML_FoldersInfo
        WHERE REPLACE(PhysicalPath, '/', '\') = @NormalizedLink;
    END

    ;WITH FolderCTE AS (
        -- Get unique folders
        SELECT  
            '' AS Created_By,
            fo.CreatedAt AS Created_On,
            fo.PhysicalPath AS CurrentDir,
            fo.PhysicalPath AS Download_Link,
            NULL AS Extention,
            fo.PhysicalPath AS FilePath,
            'Folder' AS File_Type,
            fo.FolderName AS Name,
            CASE 
                WHEN ISNULL(SUM(f.FileSize), 0) = 0 THEN ''
                WHEN SUM(f.FileSize) < 1024 THEN CAST(SUM(f.FileSize) AS VARCHAR(20)) + ' KB'
                WHEN SUM(f.FileSize) < 1048576 THEN CAST(SUM(f.FileSize) / 1024 AS VARCHAR(20)) + ' MB'
                ELSE CAST(SUM(f.FileSize) / 1048576 AS VARCHAR(20)) + ' GB'
            END AS Size,
            'Folder' AS Type,
            fo.ParentId,
            fo.FolderId AS ItemId,
            fo.CreatedAt,
            0 AS SortOrder
        FROM tbl_ML_FoldersInfo (nolock) fo 
        LEFT JOIN tbl_ML_FilesInfo (nolock) f ON f.FolderId = fo.FolderId
        WHERE (@FolderId IS NOT NULL AND fo.ParentFolderId = @FolderId)
           OR (@FolderId IS NULL AND fo.ParentFolderId = @ParentId)
        GROUP BY fo.FolderId, fo.FolderName, fo.ParentId, fo.PhysicalPath, fo.CreatedAt
    ),
    FileCTE AS (
        -- Get files without duplicating folder path
        SELECT  
            '' AS Created_By,
            f.CreatedAt AS Created_On,
            -- ✅ Extract folder path only, without file name
            LEFT(f.PhysicalPath, LEN(f.PhysicalPath) - CHARINDEX('\', REVERSE(f.PhysicalPath))) AS CurrentDir,
            f.PhysicalPath AS Download_Link,
            -- ✅ Fix extension issue
            f.FileType AS Extention,
            f.PhysicalPath AS FilePath,
            CASE 
                WHEN LOWER(f.FileType) IN ('png','jpg','jpeg','gif') THEN 'Image'
                WHEN LOWER(f.FileType) = 'pdf' THEN 'PDF'
                ELSE 'File'
            END AS File_Type,
            f.FileName AS Name,
            CASE 
                WHEN f.FileSize = 0 THEN ''
                WHEN f.FileSize < 1024 THEN CAST(f.FileSize AS VARCHAR(20)) + ' KB'
                WHEN f.FileSize < 1048576 THEN CAST(f.FileSize / 1024 AS VARCHAR(20)) + ' MB'
                ELSE CAST(f.FileSize / 1048576 AS VARCHAR(20)) + ' GB'
            END AS Size,
            'File' AS Type,
            f.ParentId,
            f.FileId AS ItemId,
            f.CreatedAt,
            1 AS SortOrder
        FROM tbl_ML_FilesInfo (nolock) f
        WHERE (@FolderId IS NOT NULL AND f.FolderId = @FolderId)
           OR (@FolderId IS NULL AND (f.FolderId IS NULL OR f.FolderId = 0) 
               AND (@ParentId IS NULL OR f.ParentId = @ParentId))
    ),
    Combined AS (
        SELECT * FROM FolderCTE
        UNION
        SELECT * FROM FileCTE
    )
    SELECT *, COUNT(*) OVER() AS TotalCount
    FROM Combined
    ORDER BY SortOrder ASC, CreatedAt DESC
    OFFSET (@PageNumber-1) * @PageSize ROWS
    FETCH NEXT @PageSize ROWS ONLY;
END



GO

/* ============================================================
   Procedure: [dbo].[usp_ML_GetUserDetailForRolePermission]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE [dbo].[usp_ML_GetUserDetailForRolePermission] --32222,'{}'
@ParentId BIGINT
AS
BEGIN
--DECLARE @ParentId BIGINT = 32222,
--        @MetaData NVARCHAR(200) = '{}'

DECLARE @RecordCount INT
SELECT @RecordCount = COUNT(*)
FROM tbl_tp_TicketPriorityMaster
WHERE ParentId = @ParentId

-- If no records exist, call the new procedure to insert predefined priorities
IF @RecordCount = 0
BEGIN
    EXEC [dbo].[Usp_tp_InsertPredefinedValues] @ParentId = @ParentId, @Mode = '';
END;

WITH Aggregated AS (
    SELECT
        RM.Role_Id,
        RM.RoleName,
        RM.Description,
        RM.ParentId,
        RM.CreatedBy,
        RM.CreatedDate,
        RM.IsPredefined,
        RM.Isdefault,
        RM.ParentRole_Id,
        PM.Permission_Id,
        ARM.Entityid_Id
       --TUL.Name+ '(' + TUL.LoginName + ')' AS UserName
    FROM tbl_ML_RolesMaster AS RM
    LEFT JOIN tbl_ML_Userrolemapping AS ARM ON RM.Role_Id = ARM.role_id
    --LEFT JOIN Tbl_ML_MediaLibraryToken AS TUL ON TUL.TpUser_Id = ARM.tpuserid
    LEFT JOIN tbl_ML_Permission_Mapping AS PM ON RM.Role_Id = PM.Role_Id
   -- LEFT JOIN tbl_tp_PermissionField_Mapping AS PFM ON RM.Role_Id = PFM.Role_Id
    WHERE RM.IsActive = 1 AND (RM.ParentId = @ParentId OR RM.ParentId = 0)
)
SELECT
    Role_Id,
    RoleName,
    Description,
    ParentId,
    CreatedBy,
    CreatedDate,
    IsPredefined,
    Isdefault,
    --IsAllowed,
    ParentRole_Id,
    COUNT(DISTINCT CASE WHEN COALESCE(Entityid_Id, '') <> '' THEN Entityid_Id END) AS AgentCount,
    STUFF((SELECT DISTINCT  ', ' + CAST(Entityid_Id AS NVARCHAR(MAX))
           FROM Aggregated
           WHERE Role_Id = a.Role_Id
           FOR XML PATH('')), 1, 2, '') AS tpuserid_list,
    STUFF((SELECT DISTINCT  ', ' + CAST(Permission_Id AS NVARCHAR(MAX))
           FROM Aggregated
           WHERE Role_Id = a.Role_Id
           FOR XML PATH('')), 1, 2, '') AS Permission_Id
    --STUFF((SELECT  DISTINCT  ',' + UserName
    --       FROM Aggregated
    --       WHERE Role_Id = a.Role_Id
    --       FOR XML PATH('')), 1, 2, '') AS tpuserid_Namelist
FROM Aggregated a
GROUP BY Role_Id, RoleName, Description, ParentId, CreatedBy, CreatedDate, IsPredefined, Isdefault, ParentRole_Id;

END





GO

/* ============================================================
   Procedure: [dbo].[usp_ml_GetUserStorageInfo_WithParentId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ml_GetUserStorageInfo_WithParentId]
AS
BEGIN
    SET NOCOUNT ON;

    -- Step 1: Get all valid users with active subscriptions and who are their own parent
    WITH ValidUsers AS (
        SELECT 
            user_id,
            dbo.fn_getparent_allowedstorage(user_id) AS AllowedStorage
        FROM user_detail WITH (NOLOCK)
        WHERE 
            dbo.fn_parent_hasactivesubscription(user_id) = 1
            AND user_id = parentid
    )

    -- Step 2: Aggregate storage from files by joining through ParentId
    SELECT 
        vu.user_id,
        vu.AllowedStorage,
        ISNULL(SUM(CAST(fi.FileSize AS BIGINT)), 0) AS UsedStorageInBytes,
        COUNT(fi.FileId) AS TotalFiles,
        COUNT(DISTINCT fi.FolderId) AS TotalFolders
    FROM ValidUsers vu
    LEFT JOIN tbl_ML_FoldersInfo fo WITH (NOLOCK)
        ON fo.ParentId = vu.user_id
    LEFT JOIN tbl_ML_Filesinfo fi WITH (NOLOCK)
        ON fi.ParentId = vu.user_id AND fi.IsDeleted = 0
    GROUP BY vu.user_id, vu.AllowedStorage
    ORDER BY vu.user_id
END



GO

/* ============================================================
   Procedure: [dbo].[usp_ml_InsertActivitylogandfilesfoldersinfo]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ml_InsertActivitylogandfilesfoldersinfo]
    @jsondata NVARCHAR(MAX)
AS
BEGIN
--declare  @jsondata NVARCHAR(MAX)='[{"FileName":"01052025141938160.jpg","FileSize":6645,"FolderName":"32222/Restricted/Lead/16673681/Thumbnail","UserId":0,"ParentId":0,"Remarks":"File uploaded via API","OriginalUrl":"https://thumbscdn-bde9cpcwgxg7g3as.a01.azurefd.net//testmediafiles/32222/Restricted/Lead/16673681/Thumbnail/01052025141938160.jpg","CustomUrlKey":"32222/Restricted/Lead/16673681/Thumbnail/01052025141938160.jpg","Mode":"Upload"}]'
    SET NOCOUNT ON;

    BEGIN TRY
        BEGIN TRANSACTION;

        DECLARE @FileTable TABLE (
            FileName NVARCHAR(255),
            FileSize BIGINT,
            FolderName NVARCHAR(1000),
            UserId INT,
            ParentId INT,
            Remarks NVARCHAR(1000),
            OriginalUrl NVARCHAR(MAX),
            CustomUrlKey NVARCHAR(500),
            Mode NVARCHAR(20)
        );

        -- Parse JSON data into table variable
        INSERT INTO @FileTable (FileName, FileSize, FolderName, UserId, ParentId, Remarks, OriginalUrl, CustomUrlKey, Mode)
        SELECT 
            FileName, FileSize, FolderName, UserId, ParentId, Remarks, OriginalUrl, CustomUrlKey, Mode
        FROM OPENJSON(@jsondata)
        WITH (
            FileName NVARCHAR(255),
            FileSize BIGINT,
            FolderName NVARCHAR(1000),
            UserId INT,
            ParentId INT,
            Remarks NVARCHAR(1000),
            OriginalUrl NVARCHAR(MAX),
            CustomUrlKey NVARCHAR(500),
            Mode NVARCHAR(20)
        );

        DECLARE 
            @FileName NVARCHAR(255),
            @FileSize BIGINT,
            @FullFolderPath NVARCHAR(1000),
            @UserId INT,
            @ParentId INT,
            @Remarks NVARCHAR(1000),
            @OriginalUrl NVARCHAR(MAX),
            @CustomUrlKey NVARCHAR(500),
            @Mode NVARCHAR(20),
            @FileId INT,
            @FileType NVARCHAR(20),
            @FolderId INT,
            @ParentFolderId INT,
            @PhysicalFilePath NVARCHAR(1000),
            @TempPath NVARCHAR(1000),
            @LastFolderName NVARCHAR(255);

        DECLARE cur CURSOR FOR
        SELECT FileName, FileSize, FolderName, UserId, ParentId, Remarks, OriginalUrl, CustomUrlKey, Mode
        FROM @FileTable;

        OPEN cur;
        FETCH NEXT FROM cur INTO @FileName, @FileSize, @FullFolderPath, @UserId, @ParentId, @Remarks, @OriginalUrl, @CustomUrlKey, @Mode;

        WHILE @@FETCH_STATUS = 0
        BEGIN
            -- ======================================
            -- STEP 1: CHECK IF FULL PATH EXISTS
            -- ======================================
            SELECT @FolderId = FolderId
            FROM tbl_ML_FoldersInfo
            WHERE LOWER(LTRIM(RTRIM(PhysicalPath))) = LOWER(LTRIM(RTRIM(@FullFolderPath)));

            -- ======================================
            -- STEP 2: IF NOT EXISTS, CREATE FINAL FOLDER
            -- ======================================
            IF @FolderId IS NULL
            BEGIN
                -- Find highest existing parent folder
                SET @TempPath = @FullFolderPath;

                WHILE CHARINDEX('/', @TempPath) > 0
                BEGIN
                    -- Remove the last segment one by one
                    SET @TempPath = LEFT(@TempPath, LEN(@TempPath) - CHARINDEX('/', REVERSE(@TempPath)));

                    SELECT @ParentFolderId = FolderId
                    FROM tbl_ML_FoldersInfo
                    WHERE LOWER(LTRIM(RTRIM(PhysicalPath))) = LOWER(LTRIM(RTRIM(@TempPath)));

                    IF @ParentFolderId IS NOT NULL
                        BREAK; -- Found the existing parent
                END

                -- Extract last folder name (final segment after last '/')
                SET @LastFolderName = RIGHT(@FullFolderPath, CHARINDEX('/', REVERSE(@FullFolderPath)) - 1);

                -- Insert only final missing folder
                INSERT INTO tbl_ML_FoldersInfo 
                (FolderName, PhysicalPath, UserId, ParentId, ParentFolderId, FileSize, CreatedAt, IsDeleted, IsShared)
                VALUES 
                (
                    @LastFolderName,
                    @FullFolderPath,
                    ISNULL(@UserId, 0),
                    @ParentId,
                    @ParentFolderId,
                    0,
                    GETDATE(),
                    0,
                    0
                );

                SET @FolderId = SCOPE_IDENTITY();
            END

            -- ======================================
            -- STEP 3: INSERT FILE INTO FINAL FOLDER
            -- ======================================
            IF @FolderId IS NOT NULL
            BEGIN
                SET @FileType = RIGHT(@FileName, CHARINDEX('.', REVERSE(@FileName)) - 1);
                SET @PhysicalFilePath = @FullFolderPath + '\' + @FileName;

                INSERT INTO tbl_ML_FilesInfo
                (FileName, FileType, FileSize, PhysicalPath, FolderId, EntityId, ParentId, CreatedAt, IsDeleted, IsShared)
                VALUES
                (@FileName, @FileType, @FileSize, @PhysicalFilePath, @FolderId, @UserId, @ParentId, GETDATE(), 0, 0);

                SET @FileId = SCOPE_IDENTITY();

                -- ======================================
                -- STEP 4: MAP URL IF PROVIDED
                -- ======================================
                IF LEN(@OriginalUrl) > 0 AND LEN(@CustomUrlKey) > 0
                BEGIN
                    INSERT INTO tbl_ML_UrlMapping (FileId, AzureUrl, CustomUrl)
                    VALUES (@FileId, @OriginalUrl, @CustomUrlKey);
                END

                -- ======================================
                -- STEP 5: LOG ACTIVITY
                -- ======================================
                INSERT INTO tbl_ML_StorageActivityLog
                (Mode, UserId, FileId, FolderId, FileSize, FileName, Remarks)
                VALUES
                (@Mode, @UserId, @FileId, @FolderId, @FileSize, @FileName, ISNULL(@Remarks, 'File uploaded'));

                INSERT INTO tbl_ML_EventLog
                (EventType, EventFor, ReferenceId, ParentId, UserId, Description)
                VALUES
                ('Upload', 'File', @FileId, @ParentId, @UserId, ISNULL(@Remarks, 'File uploaded'));
            END

            FETCH NEXT FROM cur INTO @FileName, @FileSize, @FullFolderPath, @UserId, @ParentId, @Remarks, @OriginalUrl, @CustomUrlKey, @Mode;
        END

        CLOSE cur;
        DEALLOCATE cur;

        COMMIT;
    END TRY
    BEGIN CATCH
        ROLLBACK;
        PRINT 'Error: ' + ERROR_MESSAGE();
        THROW;
    END CATCH
END



GO

/* ============================================================
   Procedure: [dbo].[usp_ml_InsertMultipleFilesAndLogs]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ml_InsertMultipleFilesAndLogs]
    @jsondata NVARCHAR(MAX)
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @FolderId INT, @FolderName NVARCHAR(255), @ParentId INT, @UserId INT;
    DECLARE @PhysicalFolderPath NVARCHAR(500);

    BEGIN TRY
        BEGIN TRANSACTION;

        -- Extract common folder info from first item
        SELECT TOP 1 
            @FolderName = JSON_VALUE(value, '$.FolderName'),
            @ParentId = JSON_VALUE(value, '$.ParentId'),
            @UserId = JSON_VALUE(value, '$.UserId')
        FROM OPENJSON(@jsondata);

        -- Check if folder already exists
        SELECT TOP 1 @FolderId = FolderId, @PhysicalFolderPath = PhysicalPath
        FROM tbl_ML_FoldersInfo
        WHERE LOWER(FolderName) = LOWER(@FolderName)
          AND ParentId = @ParentId AND UserId = @UserId AND IsDeleted = 0;

        -- Insert if not exists
        IF @FolderId IS NULL
        BEGIN
            SET @PhysicalFolderPath = CONCAT('/', @ParentId, '/', @FolderName);
            INSERT INTO tbl_ML_FoldersInfo (FolderName, PhysicalPath, UserId, ParentId)
            VALUES (@FolderName, @PhysicalFolderPath, @UserId, @ParentId);
            SET @FolderId = SCOPE_IDENTITY();
        END

        -- Loop through all files
        INSERT INTO tbl_ML_FilesInfo (FileName, FileType, FileSize, PhysicalPath, FolderId, EntityId, ParentId)
        SELECT 
            JSON_VALUE(value, '$.FileName'),
            RIGHT(JSON_VALUE(value, '$.FileName'), CHARINDEX('.', REVERSE(JSON_VALUE(value, '$.FileName'))) - 1),
            JSON_VALUE(value, '$.FileSize'),
            CONCAT(@PhysicalFolderPath, '/', JSON_VALUE(value, '$.FileName')),
            @FolderId,
            JSON_VALUE(value, '$.UserId'),
            JSON_VALUE(value, '$.ParentId')
        FROM OPENJSON(@jsondata)
        WHERE NOT EXISTS (
            SELECT 1 FROM tbl_ML_FilesInfo F
            WHERE F.FileName = JSON_VALUE(value, '$.FileName') AND F.FolderId = @FolderId AND F.IsDeleted = 0
        );

        -- Get FileIds of inserted files (optional if you want to return)

        -- Log StorageActivityLog
        INSERT INTO tbl_ML_StorageActivityLog (Mode, UserId, FileId, FolderId, FileSize, FileName, Remarks)
        SELECT 
            JSON_VALUE(value, '$.Mode'),
            JSON_VALUE(value, '$.UserId'),
            F.FileId,
            @FolderId,
            JSON_VALUE(value, '$.FileSize'),
            JSON_VALUE(value, '$.FileName'),
            JSON_VALUE(value, '$.Remarks')
        FROM OPENJSON(@jsondata)
        JOIN tbl_ML_FilesInfo F
            ON F.FileName = JSON_VALUE(value, '$.FileName') AND F.FolderId = @FolderId;

        -- Log EventLog
        INSERT INTO tbl_ML_EventLog (EventType, EventFor, ReferenceId, ParentId, UserId, Description)
        SELECT 
            'Upload',
            'File',
            F.FileId,
            JSON_VALUE(value, '$.ParentId'),
            JSON_VALUE(value, '$.UserId'),
            JSON_VALUE(value, '$.Remarks')
        FROM OPENJSON(@jsondata)
        JOIN tbl_ML_FilesInfo F
            ON F.FileName = JSON_VALUE(value, '$.FileName') AND F.FolderId = @FolderId;

        COMMIT;
    END TRY
    BEGIN CATCH
        ROLLBACK;
        THROW;
    END CATCH
END;


GO

/* ============================================================
   Procedure: [dbo].[Usp_ML_InsertOrUpdateQuota]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_ML_InsertOrUpdateQuota]
    @ParentID BIGINT,                           -- The Parent ID (user-specific or global)
    @AllocatedSpace NUMERIC(18, 3),             -- Space to be allocated (default or purchased)
    @AllocationType NVARCHAR(50),               -- Allocation type ('Default' or 'Purchased')
    @StorageUnit NVARCHAR(10) = 'MB',           -- Storage unit (default 'MB')
    @ValidityUnit INT,                          -- Validity unit (e.g., 1, 2, etc.)
    @ValidityType NVARCHAR(10),                 -- Validity type ('Month', 'Day', 'Year')
    @PlanId BIGINT = NULL,                      -- Plan ID (for purchases)
    @CreatedBy BIGINT                           -- User who created the record
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @GlobalDefaultSpace NUMERIC(18, 3) = 0;
    DECLARE @ExistingSpace NUMERIC(18, 3) = 0;
    DECLARE @TotalAllocatedSpace NUMERIC(18, 3) = 0;
    DECLARE @TempStartDate DATETIME;
    DECLARE @TempExpiryDate DATETIME;

    -- Step 1: Fetch the global default space (ParentID = 0) for 'Default' space
    --IF @AllocationType = 'Default'
   -- BEGIN
        SELECT TOP 1 @GlobalDefaultSpace = AllocatedSpace
        FROM tbl_ML_UserStorageQuota
        WHERE ParentID = 0 AND AllocationType = 'Default';
    --END

    -- Step 2: Check if the user already has any allocation (default or purchased)
    SELECT TOP 1 @ExistingSpace = AllocatedSpace
    FROM tbl_ML_UserStorageQuota
    WHERE ParentID = @ParentID AND IsActive = 1;

    -- Use global default if no existing space is found
    IF @ExistingSpace IS NULL OR @ExistingSpace = 0
    BEGIN
        SET @ExistingSpace = @GlobalDefaultSpace;
    END

    -- Calculate Start and Expiry Dates based on ValidityUnit and ValidityType
    SET @TempStartDate = GETDATE(); -- Default start date is current date
    
    IF @ValidityType = 'Month'
    BEGIN
        SET @TempExpiryDate = DATEADD(MONTH, 1, @TempStartDate);
    END
    ELSE IF @ValidityType = 'Day'
    BEGIN
        SET @TempExpiryDate = DATEADD(DAY, 1, @TempStartDate);
    END
    ELSE IF @ValidityType = 'Year'
    BEGIN
        SET @TempExpiryDate = DATEADD(YEAR, 1, @TempStartDate);
    END

    -- Step 3: Handle allocation type
    IF @AllocationType = 'Default'
    BEGIN
        -- Update existing 'Default' allocation or insert new one
        IF EXISTS (SELECT 1 FROM tbl_ML_UserStorageQuota WHERE ParentID = @ParentID AND AllocationType = 'Default' AND IsActive = 1)
        BEGIN
            UPDATE tbl_ML_UserStorageQuota
            SET AllocatedSpace = @AllocatedSpace, 
                StorageUnit = @StorageUnit,
                ModifiedDate = GETDATE(), 
                ModifiedBy = @CreatedBy
            WHERE ParentID = @ParentID AND AllocationType = 'Default' AND IsActive = 1;
        END
        ELSE
        BEGIN
            -- Insert a new 'Default' allocation for the user
            INSERT INTO tbl_ML_UserStorageQuota
            (ParentID, AllocatedSpace, AllocationType, StorageUnit, StartDate, ExpiryDate, PlanId, CreatedDate, CreatedBy, IsActive)
            VALUES
            (@ParentID, @AllocatedSpace, 'Default', @StorageUnit, NULL, NULL, NULL, GETDATE(), @CreatedBy, 1);
        END
    END
    ELSE IF @AllocationType = 'Purchased'
    BEGIN
        -- Step 4: Add purchased space to the existing space
        SET @TotalAllocatedSpace = @ExistingSpace + @AllocatedSpace;

        -- Update or insert the purchased space for the user
        IF EXISTS (SELECT 1 FROM tbl_ML_UserStorageQuota WHERE ParentID = @ParentID AND AllocationType = 'Purchased' AND IsActive = 1)
        BEGIN
            UPDATE tbl_ML_UserStorageQuota
            SET AllocatedSpace = @TotalAllocatedSpace,           -- Update total allocated space (default + purchased)
                AllocationType = 'Purchased',                     -- Keep type as purchased
                StorageUnit = @StorageUnit,
                ModifiedDate = GETDATE(),
                ModifiedBy = @CreatedBy,
                StartDate = @TempStartDate,
                ExpiryDate = @TempExpiryDate,
                PlanId = @PlanId
            WHERE ParentID = @ParentID AND IsActive = 1;
        END
        ELSE
        BEGIN
            -- Insert a new purchased allocation if it doesn't exist
            INSERT INTO tbl_ML_UserStorageQuota
            (ParentID, AllocatedSpace, AllocationType, StorageUnit, StartDate, ExpiryDate, PlanId, CreatedDate, CreatedBy, IsActive)
            VALUES
            (@ParentID, @TotalAllocatedSpace, 'Purchased', @StorageUnit, @TempStartDate, @TempExpiryDate, @PlanId, GETDATE(), @CreatedBy, 1);
        END

        -- Step 5: If ValidityUnit > 1, add additional records for each period
        IF @ValidityUnit > 1
        BEGIN
            DECLARE @Counter INT = 1;

            WHILE @Counter < @ValidityUnit
            BEGIN
                -- Update start and expiry dates for each additional period
                SET @TempStartDate = @TempExpiryDate;
                
                IF @ValidityType = 'Month'
                BEGIN
                    SET @TempExpiryDate = DATEADD(MONTH, 1, @TempStartDate);
                END
                ELSE IF @ValidityType = 'Day'
                BEGIN
                    SET @TempExpiryDate = DATEADD(DAY, 1, @TempStartDate);
                END
                ELSE IF @ValidityType = 'Year'
                BEGIN
                    SET @TempExpiryDate = DATEADD(YEAR, 1, @TempStartDate);
                END

                -- Insert additional record for the new period
                INSERT INTO tbl_ML_UserStorageQuota
                (ParentID, AllocatedSpace, AllocationType, StorageUnit, StartDate, ExpiryDate, PlanId, CreatedDate, CreatedBy, IsActive)
                VALUES
                (@ParentID, @TotalAllocatedSpace, 'Purchased', @StorageUnit, @TempStartDate, @TempExpiryDate, @PlanId, GETDATE(), @CreatedBy, 1);

                SET @Counter = @Counter + 1;
            END
        END
    END
END


GO

/* ============================================================
   Procedure: [dbo].[usp_ml_InsertOrUpdateUserRoleMapping]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_ml_InsertOrUpdateUserRoleMapping
    @RoleId INT,
    @EntityId INT,
    @Agent NVARCHAR(MAX)
AS
BEGIN
    SET NOCOUNT ON;

    -- Check if records exist for the given RoleId
    IF EXISTS (SELECT 1 FROM tbl_ML_Userrolemapping WHERE Role_Id = @RoleId)
    BEGIN
        -- Delete existing records for that RoleId
        DELETE FROM tbl_ML_Userrolemapping WHERE Role_Id = @RoleId;
    END

    -- Temporary table to store agent values
    DECLARE @TempTable TABLE (AgentValue NVARCHAR(50));

    -- Split @Agent values and store them in @TempTable
    ;WITH SplitValues AS (
        SELECT value
        FROM STRING_SPLIT(@Agent, ',')
    )
    INSERT INTO @TempTable (AgentValue)
    SELECT value FROM SplitValues;

    -- Insert new agent-role mappings
    INSERT INTO tbl_ML_Userrolemapping (Entityid_Id, role_id, Active, CreatedBy, CreatedDate, ModifiedBy, ModifiedDate)
    SELECT AgentValue, @RoleId, 1, @EntityId, GETDATE(), NULL, NULL  
    FROM @TempTable;
END;



