/* ============================================================
   Procedure: [dbo].[Usp_ML_InsertUpdateUserRole]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_ML_InsertUpdateUserRole]      
(      
    @RoleId BIGINT OUTPUT,      
    @EntityId BIGINT,      
    @RoleName NVARCHAR(100),      
    @Description NVARCHAR(200),      
    @Option NVARCHAR(10),      
    @DataTable NVARCHAR(MAX),  
    @Agent NVARCHAR(MAX), 
	@baserole BIGINT
)      
AS      
BEGIN     
    DECLARE @UserId BIGINT, @ParentId BIGINT, @TimeZone NVARCHAR(400), @rowJson NVARCHAR(MAX), @IPAddress NVARCHAR(50), @DeviceId NVARCHAR(50), @IsImpersonation BIT, @ImpersonatorId INT;      
    SELECT @UserId = User_Id, @ParentId = ParentId, @TimeZone = TimeZone 
    FROM tbl_tp_UserLogin (NOLOCK) 
    WHERE TpUser_Id = @EntityId AND IsActive = 1;
    if @ParentId is null
	begin	
	 SET @ParentId  = (Select parentid from User_Detail (NOLOCK) where User_id=@EntityId)
	end
    IF (@baserole = 0)  
    BEGIN  
        SET @baserole = NULL  
    END;

      
    IF (@Option = 'Insert')      
    BEGIN            
        IF NOT EXISTS (SELECT 1 FROM tbl_tp_RolesMaster WHERE Role_Id = @RoleId)    
        BEGIN    
            INSERT INTO Tbl_ML_RolesMaster (    
                ParentId,    
                RoleName,    
                Description,     
                IsActive,    
                CreatedBy,    
                CreatedDate,    
                ModifiedBy,    
                ModifiedDate,    
                IsPredefined,
				IsDefault,
				ParentRole_Id
            )    
            VALUES (    
                @ParentId,    
                @RoleName,    
                @Description,     
                1,    
                @EntityId,    
                GETDATE(),    
                NULL,    
                NULL,    
                0,
				0,
				@baserole
            );    
            
            SET @RoleId = SCOPE_IDENTITY();    
            
            INSERT INTO dbo.tbl_ML_Permission_Mapping (Role_Id, Permission_Id, Page_Id, CreatedBy, CreatedOn)    
            SELECT @RoleId, value, 0, @EntityId, GETDATE()    
            FROM OPENJSON(@DataTable) AS jsonArr    
            WHERE ISNUMERIC(jsonArr.value) = 1;    
    
            DECLARE @TempTable TABLE (AgentValue NVARCHAR(MAX));  
      
            ;WITH SplitValues AS (  
                SELECT value, ROW_NUMBER() OVER (ORDER BY (SELECT NULL)) AS rn  
                FROM STRING_SPLIT(@Agent, ',')  
            )  
            INSERT INTO @TempTable (AgentValue)  
            SELECT value  
            FROM SplitValues;  
            
            INSERT INTO tbl_ML_Userrolemapping (Entityid_Id, role_id, Active, CreatedBy, CreatedDate, ModifiedBy, ModifiedDate)   
            SELECT AgentValue, @RoleId, 1, @EntityId, GETDATE(), NULL, NULL  
            FROM @TempTable;  
            
            SELECT 'Role and permissions have been created successfully' AS resp;    
            
            SET @rowJson = (    
                SELECT *    
                FROM tbl_tp_RolesMaster tm    
                WHERE Role_Id = @RoleId    
                FOR JSON AUTO, INCLUDE_NULL_VALUES    
            );    
            
            IF @rowJson IS NOT NULL    
            BEGIN    
                EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData    
                    @User_id = @UserId,    
                    @Activity_type = 'Inst_rolemaster',    
                    @ActionType = 'I',    
                    @RowJson = @rowJson,    
                    @Table_name = 'tbl_tp_RolesMaster',    
                    @ip_adress = @IPAddress,    
                    @device_id = @DeviceId,    
                    @IsImpersonation = @IsImpersonation,    
                    @ImpersonatorId = @ImpersonatorId;    
            END;    
        END    
        ELSE    
        BEGIN    
            SELECT 'Role already exists' AS resp;    
        END;    
    END      
    ELSE IF (@Option = 'Update')      
    BEGIN      
        IF EXISTS (SELECT 1 FROM Tbl_ML_RolesMaster WHERE Role_Id = @RoleId)      
        BEGIN      
            UPDATE Tbl_ML_RolesMaster      
            SET      
                ParentId = @ParentId,      
                RoleName = @RoleName,      
                Description = @Description,          
                IsActive = 1,       
                CreatedBy = @EntityId,      
                CreatedDate = GETDATE(),      
                IsPredefined = 0,
				IsDefault=0,
		        ParentRole_Id = @baserole
            WHERE Role_Id = @RoleId;      
          
            DELETE FROM tbl_ML_Permission_Mapping WHERE Role_Id = @RoleId;      
          
            INSERT INTO dbo.tbl_ML_Permission_Mapping (Role_Id, Permission_Id, Page_Id, CreatedBy, CreatedOn)      
            SELECT @RoleId, value, 0, @EntityId, GETDATE()      
            FROM OPENJSON(@DataTable) AS jsonArr      
            WHERE ISNUMERIC(jsonArr.value) = 1;      

		    DELETE FROM tbl_ML_Userrolemapping WHERE Role_Id = @RoleId; 

		    DECLARE @TempTable1 TABLE (AgentValue NVARCHAR(MAX));  
      
            ;WITH SplitValues AS (  
                SELECT value, ROW_NUMBER() OVER (ORDER BY (SELECT NULL)) AS rn  
                FROM STRING_SPLIT(@Agent, ',')  
            )  
            INSERT INTO @TempTable1 (AgentValue)  
            SELECT value  
            FROM SplitValues;  
            
            INSERT INTO tbl_ML_Userrolemapping (Entityid_Id, role_id, Active, CreatedBy, CreatedDate, ModifiedBy, ModifiedDate)   
            SELECT AgentValue, @RoleId, 1, @EntityId, GETDATE(), NULL, NULL  
            FROM @TempTable1;  
            
            SELECT 'Role and permissions have been updated successfully' AS resp;      
          
            SET @rowJson = (    
                SELECT *    
                FROM tbl_ML_RolesMaster tm    
                WHERE Role_Id = @RoleId    
                FOR JSON AUTO, INCLUDE_NULL_VALUES    
            );    
            
           
        END      
        ELSE      
        BEGIN      
            SELECT 'Role does not exist' AS resp;      
        END;    
    END;      
END;




GO

/* ============================================================
   Procedure: [dbo].[Usp_ML_Kit19UserLoginToken]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--Exec Usp_ML_Kit19UserLoginToken @username='abhi01',@mode='kit19'
CREATE   PROCEDURE [dbo].[Usp_ML_Kit19UserLoginToken]     
@EntityID bigint =null,    
@username nvarchar(250)=null,    
--@password nvarchar(20)=null,    
@Token nvarchar(100) =null,    
@mode nvarchar(100)    
AS    
BEGIN    
--declare    
--@EntityID bigint =null,    
--@username nvarchar(250)='testuser',    
--@Token nvarchar(100) ='638514546610096428',    
--@mode nvarchar(100)='TicketPortal'    
--declare    
--@EntityID bigint =null,    
--@username nvarchar(250)='abhi01',    
--@Token nvarchar(100) =null,    
--@mode nvarchar(100)='kit19'    

Declare @parentid bigint    
 if @mode='Kit19'    
 begin    
  IF @EntityID IS NOT NULL    
  BEGIN    
   SET @parentid  = (Select parentid from User_Detail (NOLOCK) where User_id=@EntityID)    
   IF  EXISTS (SELECT 1 from Tbl_ML_MediaLibraryToken (NOLOCK) where EntityID=@EntityID and ExpiryDate> getdate())    
   begin    
    Select 'Valid' [Status], mlt.EntityID, mlt.Token, ue.ParentID, ue.User_Login from Tbl_ML_MediaLibraryToken (NOLOCK) mlt    
    JOIN User_detail (NOLOCK) ue on mlt.EntityID = ue.User_id    
    where mlt.EntityID=@EntityID  and ExpiryDate >GETDATE()    
   end    
   ELSE     
   BEGIN    
    Select 'Invalid' [Status]    
   END    
  END    
  Else    
  BEGIN    
	    Select @EntityID=User_ID,@parentid=parentid from User_Detail (NOLOCK) where User_Login=@username     
   --If Exists (Select 1 from User_Detail (NOLOCK) where User_Login=@username)    
   If (isnull(@EntityID,0) > 0)
   Begin    
    --Select @EntityID=User_ID from User_Detail (NOLOCK) where User_Login=@username     
    --set @parentid  = (Select parentid from User_Detail (NOLOCK) where User_id=@EntityID)    
    IF NOT  EXISTS (SELECT 1 from Tbl_ML_MediaLibraryToken (NOLOCK) where EntityID=@EntityID and ExpiryDate> getdate())    
    begin    
     Insert into  Tbl_ML_MediaLibraryToken (EntityID,Parentid,Token,Created_ON,ExpiryDate,EntityName)    
     Values(@EntityID,@parentid,@Token,GETDATE(),DATEADD(Day,10,Getdate()),'Kit19')    
        
     Select 'Valid' [Status], mlt.EntityID, mlt.Token, ue.ParentID, ue.User_Login from Tbl_ML_MediaLibraryToken (NOLOCK) mlt    
     JOIN User_detail (NOLOCK) ue on mlt.EntityID = ue.User_id    
     where ue.User_Login=@username and ExpiryDate >GETDATE()    
    end    
    ELSE     
    BEGIN    
     Select 'Valid' [Status], mlt.EntityID, mlt.Token, ue.ParentID, ue.User_Login from Tbl_ML_MediaLibraryToken (NOLOCK) mlt    
     JOIN User_detail (NOLOCK) ue on mlt.EntityID = ue.User_id    
     where ue.User_Login=@username and ExpiryDate >GETDATE()    
    END    
   end    
   ELSE    
   BEGIN    
   Select 'Invalid' [Status],'Wrong Username or Password' Msg    
   END    
  END    
      
    
 end    
 else if @mode='TicketPortal'    
    begin    
  IF @EntityID IS NOT NULL    
  BEGIN    
   SET @parentid  = (Select parentid from tbl_tp_UserLogin (NOLOCK) where TpUser_Id=@EntityID and IsActive=1)    
   print @parentid    
   IF  EXISTS (SELECT 1 from Tbl_ML_MediaLibraryToken (NOLOCK) where EntityID=@EntityID and ExpiryDate> getdate())    
   begin    
    Select 'Valid' [Status], mlt.EntityID, mlt.Token, ul.ParentID, ul.LoginName as User_Login from Tbl_ML_MediaLibraryToken (NOLOCK) mlt    
    JOIN tbl_tp_UserLogin (NOLOCK) ul on mlt.EntityID = ul.TpUser_Id    
    where mlt.EntityID=@EntityID  and ExpiryDate >GETDATE()    
   end    
   ELSE     
   BEGIN    
    Select 'Invalid' [Status]    
   END    
  END    
  Else    
  BEGIN    
   If Exists (Select 1 from tbl_tp_UserLogin (NOLOCK) where LoginName=@username and IsActive=1)    
   Begin    
    Select @EntityID=TpUser_Id from tbl_tp_UserLogin (NOLOCK) where LoginName =@username and IsActive=1    
    set @parentid  = (Select parentid from tbl_tp_UserLogin (NOLOCK) where TpUser_Id=@EntityID and IsActive=1)    
    IF NOT  EXISTS (SELECT 1 from Tbl_ML_MediaLibraryToken (NOLOCK) where EntityID=@EntityID and ExpiryDate> getdate())    
    begin    
     Insert into  Tbl_ML_MediaLibraryToken (EntityID,Parentid,Token,Created_ON,ExpiryDate,EntityName)    
     Values(@EntityID,@parentid,@Token,GETDATE(),DATEADD(Day,10,Getdate()),'TicketPortal')    
        
     Select 'Valid' [Status], mlt.EntityID, mlt.Token, ul.ParentID, ul.LoginName as User_Login from Tbl_ML_MediaLibraryToken (NOLOCK) mlt    
     JOIN tbl_tp_UserLogin (NOLOCK) ul on mlt.EntityID = ul.TpUser_Id    
     where ul.LoginName=@username and ExpiryDate >GETDATE()    
    end    
    ELSE     
    BEGIN    
     Select 'Valid' [Status], mlt.EntityID, mlt.Token, ul.ParentID, ul.LoginName  as User_Login from Tbl_ML_MediaLibraryToken (NOLOCK) mlt    
     JOIN tbl_tp_UserLogin (NOLOCK) ul on mlt.EntityID = ul.TpUser_Id    
     where ul.LoginName=@username and ExpiryDate >GETDATE()    
    END    
   end    
   ELSE    
   BEGIN    
   Select 'Invalid' [Status],'Wrong Username or Password' Msg    
   END    
  END    
      
    
 end    
END    



