/* ============================================================
   Procedure: [dbo].[usp_ml_ManageFolders]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ml_ManageFolders]
    @Mode NVARCHAR(50),
    @FolderId INT = NULL,
    @FolderName NVARCHAR(255) = NULL,
    @Parentid INT = NULL,
    @ParentFolderId INT = NULL,
    @ParentDirectory NVARCHAR(500) = NULL,
    @PhysicalPath NVARCHAR(500) = NULL,
    @UserId INT = NULL,
    @IsShared BIT = 0,
    @CreatedBy NVARCHAR(100) = NULL,
    @IsDeleted BIT = 0,
    @IsMigrated BIT = 0,
    @AccessType NVARCHAR(50) = NULL,
    @memberlist NVARCHAR(MAX) = NULL
AS
BEGIN
    SET NOCOUNT ON;
    BEGIN TRY
        IF @Mode = 'Insert'
        BEGIN
            -- Derive parent folder id from @PhysicalPath if not supplied
            IF (@ParentFolderId IS NULL OR @ParentFolderId = 0)
            BEGIN
                DECLARE @ParentPath NVARCHAR(500);

                -- Remove last segment (folder name) from path
                IF CHARINDEX('/', @PhysicalPath) > 0
                BEGIN
                    SET @ParentPath = LEFT(@PhysicalPath, LEN(@PhysicalPath) - CHARINDEX('/', REVERSE(@PhysicalPath)));
                END
                ELSE
                BEGIN
                    SET @ParentPath = NULL; -- no parent
                END

                -- Lookup ParentFolderId if parent path exists
                IF @ParentPath IS NOT NULL
                BEGIN
                    SELECT TOP 1 @ParentFolderId = FolderId
                    FROM tbl_ml_Foldersinfo
                    WHERE PhysicalPath = @ParentPath AND IsDeleted = 0;
                END
            END

            -- Insert new folder
            INSERT INTO tbl_ml_Foldersinfo 
            (FolderName, Parentid, ParentFolderId, PhysicalPath, UserId, 
             IsShared, CreatedAt, IsDeleted, IsMigrated, AccessType, memberlist)
            VALUES 
            (@FolderName, @Parentid, @ParentFolderId, @PhysicalPath, @UserId, 
             @IsShared, GETDATE(), @IsDeleted, @IsMigrated, @AccessType, @memberlist);

            SELECT SCOPE_IDENTITY() AS FolderId;
        END
        ELSE IF @Mode = 'GetAll'
        BEGIN
           SELECT FolderId, FolderName, Parentid, ParentFolderId, PhysicalPath, 
                   UserId, IsShared, CreatedAt, IsDeleted, IsMigrated, memberlist
            FROM tbl_ml_Foldersinfo
            WHERE IsDeleted = 0;
        END
        ELSE IF @Mode = 'GetById'
        BEGIN
            SELECT FolderId, FolderName, Parentid, ParentFolderId, PhysicalPath, 
                   UserId, IsShared, CreatedAt, IsDeleted, IsMigrated, memberlist
            FROM tbl_ml_Foldersinfo
            WHERE FolderId = @FolderId AND IsDeleted = 0;
        END
        ELSE IF @Mode = 'Delete'
        BEGIN
            UPDATE tbl_ml_Foldersinfo
            SET IsDeleted = 1
            WHERE FolderId = @FolderId;
        END
    END TRY
    BEGIN CATCH
        SELECT 
            ERROR_NUMBER() AS ErrorNumber,
            ERROR_MESSAGE() AS ErrorMessage,
            ERROR_PROCEDURE() AS ErrorProcedure,
            ERROR_LINE() AS ErrorLine;
    END CATCH
END;




GO

/* ============================================================
   Procedure: [dbo].[Usp_ML_UserToken]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


--USE [Mysms]
--GO
--/****** Object:  StoredProcedure [dbo].[Usp_ML_UserToken]    Script Date: 6/17/2024 5:53:12 PM ******/
--SET ANSI_NULLS ON
--GO
--SET QUOTED_IDENTIFIER ON
--GO


CREATE   PROCEDURE [dbo].[Usp_ML_UserToken] 
@userid bigint =null,
@username nvarchar(20)=null,
@password nvarchar(20)=null,
@token nvarchar(100) =null,
@mode nvarchar(100)
AS
BEGIN
--declare
--@userid bigint =48933,
--@username nvarchar(20)='',
--@password nvarchar(20)='',
--@Token nvarchar(100) ='638901809441715123',
--@mode nvarchar(100)='save'
    Declare @parentid bigint

	DECLARE @planEndDate DATE;
	 SET @parentid = (SELECT parentid FROM User_Detail (NOLOCK) WHERE User_id=@userid)
SELECT @planEndDate = DATEADD(DAY, 4, MAX(PlanEndDate))
FROM Price_UserSubscriptionDetails (NOLOCK)
WHERE UserID = @parentid 
  AND IsNewPlan = 1;


		--  IF (@planEndDate IS NOT NULL AND @planEndDate >= GETDATE())
		--  begin
		declare @ID bigint,@tokenexpirydate datetime
         SELECT top (1) @ID= ID, @tokenexpirydate=ExpiryDate FROM Tbl_ML_MediaLibraryToken (NOLOCK)  WHERE EntityID = @userid order by Id desc
		--select @ID,@tokenexpirydate,@planEndDate

		--   IF (@tokenexpirydate < GETDATE())
		--   begin
		  update Tbl_ML_MediaLibraryToken set ExpiryDate= @planEndDate where ID = @ID
		--   end
		 
		--  end



    -- If the mode is 'save'
    if @mode='save'
    begin
        IF @userid IS NOT NULL
        BEGIN
            -- Check if the user exists in User_Detail table
            IF EXISTS (SELECT 1 FROM User_Detail (NOLOCK) WHERE User_id = @userid)
            BEGIN
		
                -- Return details from User_Detail if user exists
                SELECT 'Valid' [Status], mlt.EntityID, mlt.Token, ue.ParentID, ue.User_Login
                FROM Tbl_ML_MediaLibraryToken (NOLOCK) mlt
                JOIN User_Detail (NOLOCK) ue ON mlt.EntityID = ue.User_id
                WHERE mlt.EntityID = @userid AND mlt.ExpiryDate > GETDATE()
            END
            ELSE IF EXISTS (SELECT 1 FROM tbl_tp_UserLogin (NOLOCK) WHERE TpUser_Id = @userid)
            BEGIN
                -- If the user does not exist in User_Detail, check tbl_tp_UserLogin
                SELECT 'Valid' [Status], mlt.EntityID, mlt.Token, ul.ParentID, ul.LoginName as User_Login
                FROM Tbl_ML_MediaLibraryToken (NOLOCK) mlt
                JOIN tbl_tp_UserLogin (NOLOCK) ul ON mlt.EntityID = ul.TpUser_Id
                WHERE mlt.EntityID = @userid AND mlt.ExpiryDate > GETDATE()
            END
            ELSE
            BEGIN
                -- If the user is not found in either table, return 'Invalid'
                SELECT 'Invalid' [Status]
            END
        END
        ELSE
        BEGIN
            -- Check by username and password
            IF EXISTS (SELECT 1 FROM User_Detail (NOLOCK) WHERE User_Login=@username AND pwd=@password)
            BEGIN
                SELECT @userid=User_ID FROM User_Detail (NOLOCK) WHERE User_Login=@username AND pwd=@password
                SET @parentid = (SELECT parentid FROM User_Detail (NOLOCK) WHERE User_id=@userid)
                
                IF NOT EXISTS (SELECT 1 FROM Tbl_ML_MediaLibraryToken (NOLOCK) WHERE EntityID=@userid AND ExpiryDate>GETDATE())
                BEGIN
                    -- Insert new token if it doesn't exist
                    INSERT INTO Tbl_ML_MediaLibraryToken (EntityID, Parentid, Token, Created_ON, ExpiryDate)
                    VALUES(@userid, @parentid, @Token, GETDATE(), DATEADD(Day,10,GETDATE()))

                    SELECT 'Valid' [Status], mlt.EntityID, mlt.Token, ue.ParentID, ue.User_Login
                    FROM Tbl_ML_MediaLibraryToken (NOLOCK) mlt
                    JOIN User_Detail (NOLOCK) ue ON mlt.EntityID = ue.User_id
                    WHERE ue.User_Login=@username AND mlt.ExpiryDate > GETDATE()
                END
                ELSE
                BEGIN
                    SELECT 'Valid' [Status], mlt.EntityID, mlt.Token, ue.ParentID, ue.User_Login
                    FROM Tbl_ML_MediaLibraryToken (NOLOCK) mlt
                    JOIN User_Detail (NOLOCK) ue ON mlt.EntityID = ue.User_id
                    WHERE ue.User_Login=@username AND mlt.ExpiryDate > GETDATE()
                END
            END
            ELSE IF EXISTS (SELECT 1 FROM tbl_tp_UserLogin (NOLOCK) WHERE LoginName=@username AND pwd=@password)
            BEGIN
                -- Check tbl_tp_UserLogin if not found in User_Detail
                SELECT @userid=TpUser_Id FROM tbl_tp_UserLogin (NOLOCK) WHERE LoginName=@username AND pwd=@password
                SET @parentid = (SELECT ParentId FROM tbl_tp_UserLogin (NOLOCK) WHERE TpUser_Id=@userid)

                IF NOT EXISTS (SELECT 1 FROM Tbl_ML_MediaLibraryToken (NOLOCK) WHERE EntityID=@userid AND ExpiryDate>GETDATE())
                BEGIN
                    -- Insert new token if it doesn't exist
                    INSERT INTO Tbl_ML_MediaLibraryToken (EntityID, Parentid, Token, Created_ON, ExpiryDate)
                    VALUES(@userid, @parentid, @Token, GETDATE(), DATEADD(Day,10,GETDATE()))

                    SELECT 'Valid' [Status], mlt.EntityID, mlt.Token, ul.ParentID, ul.LoginName as User_Login
                    FROM Tbl_ML_MediaLibraryToken (NOLOCK) mlt
                    JOIN tbl_tp_UserLogin (NOLOCK) ul ON mlt.EntityID = ul.TpUser_Id
                    WHERE ul.LoginName=@username AND mlt.ExpiryDate > GETDATE()
                END
                ELSE
                BEGIN
                    SELECT 'Valid' [Status], mlt.EntityID, mlt.Token, ul.ParentID, ul.LoginName as User_Login
                    FROM Tbl_ML_MediaLibraryToken (NOLOCK) mlt
                    JOIN tbl_tp_UserLogin (NOLOCK) ul ON mlt.EntityID = ul.TpUser_Id
                    WHERE ul.LoginName=@username AND mlt.ExpiryDate > GETDATE()
                END
            END
            ELSE
            BEGIN
                SELECT 'Invalid' [Status], 'Wrong Username or Password' Msg
            END
        END
    END
    -- For validating token
    -- For validating token
ELSE IF @mode = 'valid'
BEGIN
    -- First, check in User_Detail using the Token
    IF EXISTS (SELECT 1 FROM Tbl_ML_MediaLibraryToken (NOLOCK) WHERE Token=@Token AND ExpiryDate > GETDATE())
    BEGIN
        -- Try to fetch from User_Detail
        IF EXISTS (SELECT 1 FROM User_Detail (NOLOCK) WHERE User_id = (SELECT EntityID FROM Tbl_ML_MediaLibraryToken WHERE Token = @Token AND ExpiryDate > GETDATE()))
        BEGIN
            -- Return details from User_Detail
            SELECT 'Valid' [Status], mlt.EntityID, mlt.Token, ue.ParentID, ue.User_Login
            FROM Tbl_ML_MediaLibraryToken (NOLOCK) mlt
            JOIN User_Detail (NOLOCK) ue ON mlt.EntityID = ue.User_id
            WHERE mlt.Token = @Token AND mlt.ExpiryDate > GETDATE()
        END
        ELSE
        BEGIN
            -- If not found in User_Detail, check tbl_tp_UserLogin
            IF EXISTS (SELECT 1 FROM tbl_tp_UserLogin (NOLOCK) WHERE TpUser_Id = (SELECT EntityID FROM Tbl_ML_MediaLibraryToken WHERE Token = @Token AND ExpiryDate > GETDATE()))
            BEGIN
                -- Return details from tbl_tp_UserLogin
                SELECT 'Valid' [Status], mlt.EntityID, mlt.Token, ul.ParentID, ul.LoginName as User_Login
                FROM Tbl_ML_MediaLibraryToken (NOLOCK) mlt
                JOIN tbl_tp_UserLogin (NOLOCK) ul ON mlt.EntityID = ul.TpUser_Id
                WHERE mlt.Token = @Token AND mlt.ExpiryDate > GETDATE()
            END
            ELSE
            BEGIN
                -- If the token is invalid, return 'Invalid'
                SELECT 'Invalid' [Status]
            END
        END
    END
    ELSE
    BEGIN
        -- If token is not found at all, return 'Invalid'
        SELECT 'Invalid' [Status]
    END
END

    -- For getting username by UserID
    else if @mode ='username'
    BEGIN
        -- First check in User_Detail
        IF EXISTS (SELECT 1 FROM User_Detail WHERE CAST(User_ID AS varchar) = @username)
        BEGIN
            SELECT User_Login FROM User_Detail WHERE CAST(User_ID AS varchar) = @username
        END
        -- If not found, check in tbl_tp_UserLogin
        ELSE IF EXISTS (SELECT 1 FROM tbl_tp_UserLogin WHERE CAST(TpUser_Id AS varchar) = @username)
        BEGIN
            SELECT LoginName as User_Login FROM tbl_tp_UserLogin WHERE CAST(TpUser_Id AS varchar) = @username
        END
    END
END





