/* ============================================================
   Procedure: [dbo].[usp_mob_ActivityDateIndicator]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE [dbo].[usp_mob_ActivityDateIndicator](
	@UserId bigint,
	@ActivityDate datetime
)
as
begin

 -- declare @UserId bigint = 34594, @@ActivityDate datetime = '20220313'
declare @StartDate datetime = dateadd(d, -7, @ActivityDate), @EndDate datetime = dateadd(d, 7, @ActivityDate)

declare @StartDate1 datetime , @EndDate1 datetime 
select @StartDate1 = StartDateTime from fn_getIndiaStartEndTimefromUserTime(@UserId, @StartDate)
select @EndDate1 = EndDateTime from fn_getIndiaStartEndTimefromUserTime(@UserId, @EndDate)
   set @StartDate = @StartDate1
   set @EndDate = @EndDate1

declare @tempColor as table (
	id int,
	color nvarchar(10)
)

insert into @tempColor(id, color) values ( 1, '#e44408'), (2, '#444240'), (3, '#e6990b'), (4, '#188d61')

select c.ActivityDate, tc.color as ColorCode from (
	select cast(t.ActivityDate as date) as [ActivityDate], min([Status]) as [Status] from (
		select Id, (case when IsTask = 1 then EndDate when IsAppointment = 1 then StartDate end ) as ActivityDate, CreatedOn, (case 
					when LOWER(Status) = 'completed' then 4 else ( case 
						when CAST(iif(IsTask = 1, EndDate, StartDate) as date) > CAST(GETDATE() as date) then 3 
						when CAST(iif(IsTask = 1, EndDate, StartDate) as date) < CAST(GETDATE() as date) then 1 
						else 2 end
					) end
				) as [Status]

			from tbl_tsk_TaskHistory(nolock) where @UserId in (AssignedTo, CreatedBy) and 1 = ( case 
				when IsTask = 1 and EndDate between @StartDate and @EndDate then 1
				when IsAppointment = 1 and StartDate between @StartDate and @EndDate then 1 else 0 end )
		union
		select tsk.Id, (case when IsTask = 1 then EndDate when IsAppointment = 1 then StartDate end ) as ActivityDate, tsk.CreatedOn, (case 
					when LOWER(Status) = 'completed' then 4 else ( case 
						when CAST(iif(IsTask = 1, EndDate, StartDate) as date) > CAST(GETDATE() as date) then 3 
						when CAST(iif(IsTask = 1, EndDate, StartDate) as date) < CAST(GETDATE() as date) then 1 
						else 2 end
					) end
				) as [Status]
			from tbl_tsk_TaskHistory(nolock) tsk
				left join tbl_tsk_CollaborationUserMapping(nolock) cum on  tsk.Id = cum.TaskHistoryId
			where cum.User_Id = @UserId  and 1 = ( case 
				when IsTask = 1 and EndDate between @StartDate and @EndDate then 1
				when IsAppointment = 1 and StartDate between @StartDate and @EndDate then 1 else 0 end )
		union
		select ID, FollowupDate,  CreatedOn, ( case 
					when CreatedOn < getdate() and lih.lihCount > 1 then 4 
					when cast(lih.FollowupDate as date) = cast(getdate() as date) then 2   
					when lih.FollowupDate > getdate() then 3
					when lih.FollowupDate < getdate() then 1
				else ''  end 
			) as [Status]
			from ( select ID, FollowupDate,  CreatedOn,
				row_number() over(partition by li.ParentID, li.LeadNo order by li.ID desc) as lihCount
				from LeadInteractionHistory(nolock) li where @UserId in(CreatedBy, AssignedTo) and FollowupDate  between @StartDate and @EndDate
			) as lih
	) t 
	group by cast(t.ActivityDate as date)
) as c inner join @tempColor tc on c.Status =  tc.id
	order by c.ActivityDate asc
end



GO

