/* ============================================================
   Procedure: [dbo].[usp_mob_ContactSuggection]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_mob_ContactSuggection(      
	@FilterText nvarchar(250) = '',        
	@UserId bigint,
	@EntityType nvarchar(50) = 'Lead'
)      
as      
begin

	--declare
	--	@FilterText nvarchar(250) = '',        
	--	@UserId bigint = 34594,
	--	@EntityType nvarchar(50) = 'Lead'

	declare @ParentId bigint, @IsAdmin bit = 0;

	select @ParentId = ParentID, @IsAdmin = IsAdmin from MySMS.dbo.User_Detail(nolock) where User_ID = @UserId

	Declare @TeamCode varchar(10) = ''  
	Declare @ScopeCode varchar(10) = ''   
	Declare @UserIdTeamLst varchar(500) = ''   
	select @TeamCode = TeamCode, @ScopeCode = ScopeCode, @UserIdTeamLst = UserIdTeamLst from MySMS.dbo.ufn_GetUserRoleScope(@UserId)   


	if(@EntityType = 'Lead')
	begin
		select top 10
			ul.Id as Id,  
			ul.PersonName,
			ul.ProfileImgFileName,
			trim(concat(trim(cast(ul.CountryCode as nvarchar)), ' ', trim(cast(ul.MobileNo as nvarchar)))) as MobileNo1,
			trim(concat(trim(cast(ul.CountryCode1 as nvarchar)), ' ', trim(cast(ul.MobileNo1 as nvarchar)))) as MobileNo2,
			trim(concat(trim(cast(ul.CountryCode2 as nvarchar)), ' ', trim(cast(ul.MobileNo2 as nvarchar)))) as MobileNo3,
			ul.EmailID as EmailId1,
			ul.EmailID1 as EmailId2,
			ul.EmailID2 as EmailId3,
			ul.LeadNo,
			'Lead' as 'EntityType',
			ul.ParentId
		from UserLeads(nolock) ul
			where ul.ParentID = @ParentId 
			and 1 = (case when @isadmin=1 then 1
					when isnull(ul.assignedto,0) in (select [value] from dbo.fn_Split(@UserIdTeamLst, ',')) then 1
					when isnull(ul.assignedto,0) = @UserId then 1
				else 0 end )
			and 1 = ( case 
				when ul.PersonName like '%'+ @FilterText +'%' then 1 
				when ul.MobileNo like '%'+ @FilterText +'%' then 1 
				when ul.MobileNo1 like '%'+ @FilterText +'%' then 1
				when ul.MobileNo2 like '%'+ @FilterText +'%' then 1
				when ul.EmailID like '%'+ @FilterText +'%' then 1 
				when ul.EmailID1 like '%'+ @FilterText +'%' then 1 
				when ul.EmailID2 like '%'+ @FilterText +'%' then 1 
				else 0 end )
			order by ul.ID desc
	end  

	else if(@EntityType = 'Enquiry')
	begin
		select
			ul.EnquiryID as Id,  
			ul.PersonName,
			ul.ProfileImgFileName,
			trim(concat(trim(cast(ul.CountryCode as nvarchar)), ' ', trim(cast(ul.MobileNo as nvarchar)))) as MobileNo1,
			trim(concat(trim(cast(ul.CountryCode1 as nvarchar)), ' ', trim(cast(ul.MobileNo1 as nvarchar)))) as MobileNo2,
			trim(concat(trim(cast(ul.CountryCode2 as nvarchar)), ' ', trim(cast(ul.MobileNo2 as nvarchar)))) as MobileNo3,
			ul.EmailID as EmailId1,
			ul.EmailID1 as EmailId2,
			ul.EmailID2 as EmailId3,
			ul.LeadNo,
			'Enquiry' as EntityType,
			ul.ParentId
		from UserEnquiry(nolock) ul
			where ul.ParentID = @ParentId 
			and 1 = (case when @isadmin=1 then 1
					when isnull(ul.CreatedBy,0) in (select [value] from dbo.fn_Split(@UserIdTeamLst, ',')) then 1
					when isnull(ul.CreatedBy,0) = @UserId then 1
				else 0 end )
			and 1 = ( case 
				when ul.PersonName like '%'+ @FilterText +'%' then 1 
				when ul.MobileNo like '%'+ @FilterText +'%' then 1 
				when ul.MobileNo1 like '%'+ @FilterText +'%' then 1 
				when ul.MobileNo2 like '%'+ @FilterText +'%' then 1 
				when ul.EmailID like '%'+ @FilterText +'%' then 1 
				when ul.EmailID1 like '%'+ @FilterText +'%' then 1 
				when ul.EmailID2 like '%'+ @FilterText +'%' then 1 
				else 0 end )
			order by ul.EnquiryID desc
	end
	else
	begin
		select top 10 * from (
			select top 10
				ul.Id as Id,  
				ul.PersonName,
				ul.ProfileImgFileName,
				trim(concat(trim(cast(ul.CountryCode as nvarchar)), ' ', trim(cast(ul.MobileNo as nvarchar)))) as MobileNo1,
				trim(concat(trim(cast(ul.CountryCode1 as nvarchar)), ' ', trim(cast(ul.MobileNo1 as nvarchar)))) as MobileNo2,
				trim(concat(trim(cast(ul.CountryCode2 as nvarchar)), ' ', trim(cast(ul.MobileNo2 as nvarchar)))) as MobileNo3,
				ul.EmailID as EmailId1,
				ul.EmailID1 as EmailId2,
				ul.EmailID2 as EmailId3,
				ul.LeadNo,
				'Lead' as 'EntityType',
				ul.ParentId
			from UserLeads(nolock) ul
				where ul.ParentID = @ParentId 
				and 1 = (case when @isadmin=1 then 1
						when isnull(ul.assignedto,0) in (select [value] from dbo.fn_Split(@UserIdTeamLst, ',')) then 1
						when isnull(ul.assignedto,0) = @UserId then 1
					else 0 end )
				and 1 = ( case 
					when ul.PersonName like '%'+ @FilterText +'%' then 1 
					when ul.MobileNo like '%'+ @FilterText +'%' then 1 
					when ul.MobileNo1 like '%'+ @FilterText +'%' then 1 
					when ul.MobileNo2 like '%'+ @FilterText +'%' then 1 
					when ul.EmailID like '%'+ @FilterText +'%' then 1 
					when ul.EmailID1 like '%'+ @FilterText +'%' then 1 
					when ul.EmailID2 like '%'+ @FilterText +'%' then 1 
					else 0 end )
			union
				select top 10
				ul.EnquiryID as Id,  
				ul.PersonName,
				ul.ProfileImgFileName,
				trim(concat(trim(cast(ul.CountryCode as nvarchar)), ' ', trim(cast(ul.MobileNo as nvarchar)))) as MobileNo1,
				trim(concat(trim(cast(ul.CountryCode1 as nvarchar)), ' ', trim(cast(ul.MobileNo1 as nvarchar)))) as MobileNo2,
				trim(concat(trim(cast(ul.CountryCode2 as nvarchar)), ' ', trim(cast(ul.MobileNo2 as nvarchar)))) as MobileNo3,
				ul.EmailID as EmailId1,
				ul.EmailID1 as EmailId2,
				ul.EmailID2 as EmailId3,
				ul.LeadNo,
				'Enquiry' as EntityType,
				ul.ParentId
			from UserEnquiry(nolock) ul
				where ul.ParentID = @ParentId 
				and 1 = (case when @isadmin=1 then 1
						when isnull(ul.CreatedBy,0) in (select [value] from dbo.fn_Split(@UserIdTeamLst, ',')) then 1
						when isnull(ul.CreatedBy,0) = @UserId then 1
					else 0 end )
				and 1 = ( case 
					when ul.PersonName like '%'+ @FilterText +'%' then 1 
					when ul.MobileNo like '%'+ @FilterText +'%' then 1 
					when ul.MobileNo1 like '%'+ @FilterText +'%' then 1
					when ul.MobileNo2 like '%'+ @FilterText +'%' then 1
					when ul.EmailID like '%'+ @FilterText +'%' then 1 
					when ul.EmailID1 like '%'+ @FilterText +'%' then 1 
					when ul.EmailID2 like '%'+ @FilterText +'%' then 1 
					else 0 end )
		) p  order by p.Id asc
	end

end  



GO

/* ============================================================
   Procedure: [dbo].[usp_mob_EnquiryDetailById]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE  PROCEDURE [dbo].[usp_mob_EnquiryDetailById](          
	@EnquiryId bigint,          
	@UserId bigint          
)          
as          
begin          

	--declare
	--	@EnquiryId bigint = 367097832,          
	--	@UserId bigint = 45058          
          
	declare @ParentId bigint = 0, @TimeZoneName nvarchar(255) = 'India Standard Time'          
          
 select @ParentId = ParentID, @TimeZoneName = timezone from User_Detail(nolock) where User_ID = @UserId          
                                      
 SELECT           
  isnull(en.EnquiryID, '') as [EnquiryId],          
  en.PersonName,          
  en.CompanyName,          
  isnull(en.city, '') AS City,          
  isnull(en.[state], '') AS [State],          
  isnull(en.country, '') AS Country,          
  isnull(en.pincode, '') AS PinCode,          
  isnull(en.sourcename, '') as [SourceId],      
  isnull(en.mediumname, '') as [MediumId],      
  isnull(en.campaignname, '') as [CampaignId],      
  src.[name] AS [SourceName],      
  isnull(md.[name], '') AS MediumName,          
  isnull(cmp.[Name], '') AS NampaignName,          
  en.InitialRemarks AS InitialRemarks,          
  dbo.fn_ConvertDateTime(cast(en.CreatedDate as datetime), @TimeZoneName, 0) as CreatedOn,

  --convert(varchar(20), en.CreatedDate, 113) AS CreatedOn,          
  
  ud.user_login AS CreatedBy,          
  isnull(en.CountryCode, '') AS CountryCode,          
  isnull(en.CountryCode1, '') AS CountryCode1,          
  isnull(en.CountryCode2, '') AS CountryCode2,          
  rtrim(ltrim(isnull(en.MobileNo, ''))) AS MobileNo,          
  rtrim(ltrim(isnull(en.MobileNo1, ''))) AS MobileNo1,          
  rtrim(ltrim(isnull(en.mobileno2, ''))) AS MobileNo2,          
  isnull(en.emailid, '') AS EmailId,          
  isnull(en.emailid1, '') AS EmailId1,          
  isnull(en.emailid2, '') AS EmailId2,          
  isnull(en.OfficeAddress, '') as OfficeAddress,          
  isnull(en.residentialaddress, '') AS ResidentialAddress,              
  case when [en].[ProfileImgFileName] is null then 'https://docs.kit19.com/Thumbnail/ProfileDefault.png'  
  Else 'https://docs.kit19.com/'+ cast([en].[ParentId] as varchar(20)) + '/Enquiry/' + [en].[ProfileImgFileName] end ProfileImgFileName,            
  isnull(en.LeadNo, '') AS LeadNo,                   
  (case when isnull(en.LeadNo, 0) > 0 then 0 else 1 end) as IsOpen,          
  IsConflictWithLead=dbo.ufn_IsEnquiryConflictsLead(en.EnquiryID),              
  IsLeadDeleted=case when isnull(en.LeadNo,0) > 0 then ~dbo.ufn_IsLeadExists(en.LeadNo,en.ParentID) else cast(0 as bit) end,            
  en.whereAddress as WhereAddress,             
  en.latitude as Latitude,             
  en.longitude as Longitude,            
  ( select STRING_AGG(tm.Tag, ',') from EntityTagMapping(nolock) etm inner join             
   TagMaster(nolock) tm on etm.TagID = tm.Id where Entity = 'enquiry' and EntityID = @EnquiryId             
  ) as TagNames,
	 Isnull(MC.Country_ID, 0) CountryId,
	 Isnull(MS.State_ID, 0) StateId,
	 Isnull(MCi.City_ID, 0) CityId            
 FROM UserEnquiry en                  
   LEFT JOIN user_detail ud ON en.CreatedBy = ud.user_id                  
   LEFT JOIN usersourcesettings src ON en.sourcename = src.sourceid                  
   LEFT JOIN usermediumsettings md ON en.mediumname = md.mediumid                  
   LEFT JOIN UserCampaignSettings cmp ON en.campaignname = cmp.CampaignID                  
   Left Join M_Country1(nolock) MC ON en.Country = MC.Country_Name
   Left Join M_State1(nolock) MS ON en.State = MS.State_Name
   Left Join M_City1(nolock) MCi ON en.City = MCi.City_Name
  WHERE en.EnquiryID = @EnquiryId;                  
          
 select distinct field_ID, fieldname, fieldvalue from ( select field_ID, fieldname          
  from customfields(nolock) where ParentID = @ParentId and isActive = 1          
 )  cf left join ( select fieldID, fieldvalue from customfieldEnquiryvalue(nolock) where EnquiryID = @EnquiryId )          
 ce on cf.field_ID = ce.fieldID          



 Declare @PageCode varchar(20)  = 'PAG10002'--'PAG10031' 
 Declare @RoleCode varchar(20)
 set @RoleCode = (select RoleCode from ufn_GetUserRoleScope(@UserId))



select distinct phs.PageFieldId,   
 Case when pagfi.TableName != '' then pagfi.TableName  
else 'Custom'  
End TableName, urm.UserId, pagfi.FieldName, phs.HiddenType, phs.IsExportAllow    
 from tbl_UA_PageHiddenFields paghf  
inner join TBL_UA_UserRoleMappingMaster urm on paghf.RoleCode = urm.RoleCode  
inner join tbl_UA_PageHiddenFieldsSettings phs on paghf.PageHiddenFieldsId = phs.PageHiddenFieldsId  
inner join tbl_UA_PageFields pagfi on phs.PageFieldId = pagfi.PageFieldId    
where urm.UserId = @UserId and paghf.ParentId = @ParentId 
and paghf.PageCode = @PageCode and paghf.RoleCode = @RoleCode

--select distinct phs.PageFieldId,   
-- Case when pagfi.TableName != '' then pagfi.TableName  
--else 'Custom'  
--End TableName, urm.UserId, pagfi.FieldName, phs.HiddenType, phs.IsExportAllow, paghf.PageCode, paghf.RoleCode from  
--tbl_UA_PageHiddenFields paghf  
--inner join TBL_UA_UserRoleMappingMaster urm on paghf.RoleCode = urm.RoleCode 
--inner join tbl_UA_PageFields pagfi on paghf.PageCode = pagfi.PageCode 
--inner join tbl_UA_PageHiddenFieldsSettings phs on pagfi.PageFieldId = phs.PageFieldId 
--where urm.UserId = @UserId and 
--paghf.PageCode = @PageCode 
-- and 
--paghf.RoleCode = @RoleCode 

end 



