/* ============================================================
   Procedure: [dbo].[usp_mob_GenerateCallLog]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_mob_GenerateCallLog](
	@CustomerMobileNo nvarchar(50),
	@CustomerCountryCode nvarchar(20),
	@GatewayName nvarchar(100),
	@EntityName nvarchar(20),
	@EntityId bigint,
	@UserId bigint,
	@AgentNumber nvarchar(50),
	@AgentCountryCode nvarchar(20),
	@Direction nvarchar(20) = 'out',
	@CallStartTime datetime = null,
	@CallEndTime datetime = null,
	@CallPickupTime datetime = null,
	@AgentDisposition nvarchar(50),
	@CustomerDisposition nvarchar(50),
	@RecordingUrl nvarchar(max) = null
)

as
begin

	--declare 
	--	@CustomerMobileNo nvarchar(50),
	--	@CustomerCountryCode nvarchar(20),
	--	@GatewayName nvarchar(100),
	--	@EntityName nvarchar(20),
	--	@EntityId bigint,
	--	@UserId bigint,
	--	@AgentNumber nvarchar(50),
	--	@AgentCountryCode nvarchar(20),
	--	@Direction nvarchar(20) = 'out',
	--	@CallStartTime datetime = null,
	--	@CallEndTime datetime = null,
	--	@CallPickupTime datetime = null,
	--	@AgentDisposition nvarchar(50),
	--	@CustomerDisposition nvarchar(50),
	--	@RecordingUrl nvarchar(max) = null

	declare @CallType int = 0, @Gatewayid int = 0, @ParentId bigint = 0, @CallLogId bigint = 0;

	select @ParentId = ParentID from User_Detail(nolock) where User_ID = @UserId

	if(@GatewayName =  'sim')
	begin
		set  @CallType = 0
		set @Gatewayid = 0
	end

	Declare @Calldurationseconds int = 0
	if(@CallStartTime != '' and @CallEndTime != '')
	Begin
	set @Calldurationseconds  = DATEDIFF(second, @CallStartTime, @CallEndTime) 
	End

	insert into CallLog(callname, CallType, gatewayid, Direction, Customernumber, customercountrycode, Agentnumber, agentcountrycode, Callstarttime,
		Callendtime, Agentpickuptime, Customerpickuptime, Calldurationseconds, Billdurationseconds, customerduration, agentduration, lastdtmf, agentmode, 
		agentcalldisposition, customercalldisposition, agentuserid, outcomeid, remarks, customerentity, customerentityid, callcreatedby, callscheduledfor, 
		callcreatedon, reftable, refcolumn, refid, parentid, appid, dnid, recordurl, uniqueid)
	select CONCAT('NewCall_', FORMAT(getdate(), 'yyyyMMddHHmmss')), @CallType, @Gatewayid, @Direction, @CustomerMobileNo, @CustomerCountryCode, @AgentNumber, @AgentCountryCode, @CallStartTime, 
			@CallEndTime, null, null, @Calldurationseconds, null, null, null, null, null, 
			@AgentDisposition, @CustomerDisposition, @UserId, null, null, @EntityName, @EntityId, @UserId, null, 
			getdate(), null, null, null, @ParentId, null, null, @RecordingUrl, null

	set @CallLogId = SCOPE_IDENTITY()

	select @CallLogId
end



GO

/* ============================================================
   Procedure: [dbo].[usp_mob_GetCallDetailById]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_mob_GetCallDetailById](
	@CallLogId bigint
)
as
begin

--	declare @CallLogId bigint = 21418

	SELECT 
			c.id as id, 
			s.provider_name,
			'Call_Outgoing_20201012174912' as Title, 
			c.Callstarttime as StartDate, 
			c.Callendtime as EndDate,
			c.recordurl,
			0 as LeadId,
			dbo.fn_getentityfullname(c.customerentity, c.customerentityid)as PersonName,
			dbo.fn_getentityprofileimage(c.customerentity, c.customerentityid) as PersonImage,
			c.Customernumber as MobileNo,
			oc.OutcomeName as Outcome,
			u.User_ID as AgentId,
			u.FName as AgentName, 
			u.Image as AgentImage,
			'Outgoing' as TaskStatus,
			u.ParentID as ParentId,
			oc.OutcomeName as Outcome,
			oc.Indent as Intent,
			iif(isnull(c.outcomeid, 0) > 0, 0, 1) as IsEditable, 
			0 as IsRemoval,
			c.customerentity,
			c.customerentityid,
			c.gatewayid
		FROM calllog(NOLOCK) c 
			 LEFT JOIN user_detail u(NOLOCK) ON c.agentuserid = u.User_ID
			 LEFT JOIN TelephonyCostDeducted(NOLOCK) t ON t.parentid = c.parentid
														  AND 1 = CASE WHEN t.gatewaytype <> 0 AND t.kit19callsdialledid = c.refid
																	  THEN 1 WHEN t.GatewayType = 0 AND t.uniqueid = c.uniqueid
																	  THEN 1 ELSE 0  END
			 LEFT JOIN tbl_voip_ServiceProvider s ON s.id = c.gatewayid
			 LEFT JOIN Cloud_app_master(NOLOCK) m ON m.AppId = c.appid
			 Left join tbl_CallLogOutcomeMaster(nolock) oc on c.outcomeid = oc.Id
		WHERE c.id = @CallLogId
	end



GO

