AgentUserId,
ud.FName AgentFirstName, isnull(ud.LName, '') AgentLastName,
ud.User_Login AgentUserLogin, 
ud.Image AgentImage, 
 cl.parentid from CallLog(nolock) cl
left join User_Detail(nolock) ud on cl.agentuserid = ud.User_ID
left join UserLeads(nolock) ul on cl.customerentityid = ul.id 
Left join tbl_CallLogOutcomeMaster(nolock) oc on cl.outcomeid = oc.Id
left join kit19calls (nolock) a on cl.uniqueid = a.uniqueid 
left outer join cloud_app_master (nolock) c on c.AppId=a.appid            
where --cl.agentuserid = @UserId and 
cl.ID = @Id
End
Else
Begin
select count(*) over() as TotalRecords, cl.id as Id, cl.customerentityid EntityId, ue.PersonName PersonName, Customernumber MobileNo, 
cl.customerentity EntityType, cl.Callstarttime, cl.Callendtime, cl.Customerpickuptime, cl.Calldurationseconds, cl.Billdurationseconds, 
cl.customerduration, cl.lastdtmf, cl.customercalldisposition,
 cl.Agentpickuptime, cl.agentduration, cl.agentmode, cl.agentcalldisposition, 
    (case 
  when ((cast(a.call_start_time as Date) = cast(GetDate() as Date)) and ((a.context = 'DialerCalls') or (a.context = 'inbound')) and (dbo.callstatus1(a.uniqueid) = 'ANSWER') and (Cast(a.clientid as varchar(10)) = ' + Cast(@UserId as varchar(10)) + '))  then 'Calls answered by me'
  when ((cast(a.call_start_time as Date) = cast(GetDate() as Date)) and ((a.context = 'DialerCalls') or (a.context = 'inbound')) and (dbo.callstatus1(a.uniqueid) = 'NO ANSWER') and (Cast(a.clientid as varchar(10)) = ' + Cast(@UserId as varchar(10)) + '))  then 'Calls missed by me'
  when ((cast(a.call_start_time as Date) = cast(GetDate() as Date)) and ((a.context = 'DialerCalls') or (a.context = 'inbound')) and (dbo.callstatus1 (a.uniqueid) = 'ANSWER') and (Cast(a.clientid as varchar(10)) != ' + Cast(@UserId as varchar(10)) + '))  then 'Calls answered by me'
  when ((cast(a.call_start_time as Date) = cast(GetDate() as Date)) and ((a.context = 'DialerCalls') or (a.context = 'inbound')) and (dbo.callstatus1 (a.uniqueid) = 'NO ANSWER') and (Cast(a.clientid as varchar(10)) != ' + Cast(@UserId as varchar(10)) + '))  then 'Calls missed today'

  when ((cast(a.call_start_time as Date) = cast(GetDate() as Date)) and ((a.context = 'DialerCalls') or (a.context = 'inbound')) and (dbo.callstatus1 (a.uniqueid) = 'ANSWER'))  then 'Calls answered'
  when ((cast(a.call_start_time as Date) = cast(GetDate() as Date)) and ((a.context = 'DialerCalls') or (a.context = 'inbound')) and (dbo.callstatus1 (a.uniqueid) = 'NO ANSWER'))  then 'Calls missed'

  else 'Calls overdue' End) CallsMsgStatus,
(case when cl.gatewayid = 0 then cl.customercalldisposition
	else  dbo.callstatus1 (a.uniqueid) end ) as callstatus,
 '''' CallGetway, c.AppName IVFlow, a.context, a.dnid,            
ue.ProfileImgFileName ProfileImgFileName, Direction,
isnull(Case when Direction = 'in' then customercalldisposition
else agentcalldisposition End, '') Disposition, 
