/* ============================================================
   Procedure: [dbo].[usp_mob_GetCalllogList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_mob_GetCalllogList](
	@UserId bigint,
	@ActivityDate date
)
as
begin

--Declare	@UserId bigint = 43363,
--	@ActivityDate date = '2023-12-18 00:00:00'

Declare @StartDate DateTime
Declare @EndDate DateTime
--select * from fn_getStartfromUserTime(40457, '2022-12-03')
select @StartDate = StartDateTime, @EndDate = EndDateTime from fn_getIndiaStartEndTimefromUserTime(@UserId, @ActivityDate)

declare @ParentId bigint  = 0;
Declare @IsAdmin bit = 0      

	declare @tbluser table (User_ID bigint,Name varchar(100), Image varchar(100))
	select @IsAdmin = IsAdmin, @ParentId = ParentID from User_Detail(nolock) where User_ID = @UserId
	if(@IsAdmin = 1)
	begin
		set @UserId = 0;
		insert into @tbluser
		exec Use_GetUserDetails @ParentId
	end
	else
	Begin
		insert into @tbluser
		exec Use_GetUserDetails @UserId
	End

 Declare @TeamCode varchar(10) = ''
 Declare @ScopeCode varchar(10) = '' 
 Declare @UserIdTeamLst varchar(Max) = '' 
 Declare @UserLoginTeamLst varchar(Max) = '' 

-- select @TeamCode = TeamCode, @ScopeCode = ScopeCode, @UserIdTeamLst = UserIdTeamLst, @UserLoginTeamLst = UserLoginTeamLst from dbo.ufn_GetUserRoleScope(@UserId) 
 select @UserIdTeamLst=isnull(STRING_AGG(User_ID,','),'') From @tbluser
 select @UserLoginTeamLst=isnull(STRING_AGG( 
		
		trim(concat('''', ud.User_Login, ' ( ', isnull(ud.FName, ''), ' ',  isnull(ud.LName, ''),  ' )''')), ','),'') 

	From @tbluser aa inner join User_Detail(nolock) ud
 on aa.User_ID = ud.User_ID

    SELECT 
		c.id as id, 
		--'Call_Outgoing_20201012174912' as Title, 
		c.callname as Title, 
		c.Callstarttime as StartDate, 
		c.Callendtime as EndDate,	
		ISNULL(ul.ID,  0) as LeadId,
		isnull((case c.customerentity  when 'lead' then ul.LeadNo
		when 'enquiry' then ue.LeadNo else 0 end ), 0) as LeadNo,
		(case c.customerentity  when 'lead' then concat(ul.MobileNo, ',', ul.MobileNo1, ', ', ul.MobileNo2)
			when 'enquiry' then concat(ue.MobileNo, ',', ue.MobileNo1, ', ', ue.MobileNo2) else '' end 
		) as CsvMobileNo,		
		(case c.customerentity  when 'lead' then concat(ul.MobileNo, ',', ul.MobileNo1, ', ', ul.MobileNo2)
			when 'enquiry' then concat(ue.EmailID, ',', ue.EmailID1, ', ', ue.EmailID2) else '' end 
		) as CsvEmailId,		
		(case c.customerentity  when 'lead' then ul.PersonName
		when 'enquiry' then ue.PersonName else '' end ) as PersonName,
		'' as PersonImage,
		c.Customernumber as MobileNo,
		oc.OutcomeName as Outcome,
		u.User_ID as AgentId,
		u.FName as AgentName, 
		u.Image as AgentImage,
		c.Direction as TaskStatus,
		--'Outgoing' as TaskStatus,
		u.ParentID as ParentId,
		oc.OutcomeName as Outcome,
		oc.Indent as Intent,
		iif(isnull(c.outcomeid, 0) > 0, 0, 1) as IsEditable, 
		0 as IsRemoval,
		c.customerentity,
		c.customerentityid,
		c.gatewayid,
		case when ((c.gatewayid = 0) and (c.recordurl = '')) then 0 else 1 end HasRecording
    FROM calendar(NOLOCK) ca
         LEFT JOIN calllog(NOLOCK) c ON CAST(c.callcreatedon AS DATE) = CAST(ca.start_dts AS DATE)
		 LEFT JOIN UserEnquiry(nolock) ue on c.customerentityid = ue.EnquiryID and c.customerentity = 'enquiry' and c.customerentityid > 0
		 LEFT JOIN UserLeads(nolock) ul on c.customerentityid = ul.Id and c.customerentity = 'lead' and c.customerentityid > 0
         LEFT JOIN user_detail u(NOLOCK) ON c.agentuserid = u.User_ID
         LEFT JOIN TelephonyCostDeducted(NOLOCK) t ON t.parentid = c.parentid
                                                      AND 1 = CASE WHEN t.gatewaytype <> 0 AND t.kit19callsdialledid = c.refid
                                                                  THEN 1 WHEN t.GatewayType = 0 AND t.uniqueid = c.uniqueid
                                                                  THEN 1 ELSE 0  END
         LEFT JOIN tbl_voip_ServiceProvider s ON s.id = c.gatewayid
         LEFT JOIN Cloud_app_master(NOLOCK) m ON m.AppId = c.appid
		 Left join tbl_CallLogOutcomeMaster(nolock) oc on c.outcomeid = oc.Id
    WHERE CAST(start_dts AS DATE) BETWEEN CAST(@ActivityDate AS DATE) AND CAST(@ActivityDate AS DATE)
          AND u.User_ID in (select fs.value From fn_Split(@UserIdTeamLst,',') as fs )
		  --AND c.parentid = @ParentId and u.User_ID in (Case when @IsAdmin = 0 then isnull(@UserIdTeamLst, u.User_ID) else u.User_ID End)
		  order by c.id desc
end



GO

