	--@FilterText varchar(20) = '', @Start int = 0, @Limit int = 100

declare @ParentId bigint  = 0;
Declare @IsAdmin bit = 0      

	declare @tbluser table (User_ID bigint,Name varchar(100), Image varchar(100))
	select @IsAdmin = IsAdmin, @ParentId = ParentID from User_Detail(nolock) where User_ID = @UserId
	if(@IsAdmin = 1)
	begin
