/* ============================================================
   Procedure: [dbo].[usp_mob_GetCallScheduleList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_mob_GetCallScheduleList](
	@UserId bigint,
	@ActivityDate date
)
as
begin
--  Declare @UserId bigint = 34594, @ActivityDate date = '2022-10-06'

	
	declare @ParentId bigint  = 0;
	declare @StartDate Date;
	declare @EndDate DateTime;
	select @ParentId = ParentID from User_Detail(nolock) where User_ID = @UserId

	--select * from fn_getStartfromUserTime(40457, '2022-12-03')
	select @StartDate = StartDateTime, @EndDate = EndDateTime from fn_getIndiaStartEndTimefromUserTime(@UserId, @ActivityDate)

    SELECT 
		c.id as id, 
		--'Call_Outgoing_20201012174912' as Title, 
		c.callname as Title, 
		c.callscheduledfor as StartDate, 
		c.callscheduledfor as EndDate,	
		0 as LeadId,
		dbo.fn_getentityfullname(c.customerentityid, c.customerentityid)as PersonName,
		'' as PersonImage,
		c.Customernumber as MobileNo,
		--oc.OutcomeName as 
		'' Outcome,
		u.User_ID as AgentId,
		u.FName as AgentName, 
		u.Image as AgentImage,
		c.Direction as TaskStatus,
		--'Outgoing' as TaskStatus,
		u.ParentID as ParentId,
		--oc.OutcomeName as 
		0 Outcome,
		--oc.Indent as 
		0 Intent,
		iif(isnull(c.outcomeid, 0) > 0, 0, 1) as IsEditable, 
		0 as IsRemoval,
		c.customerentity,
		c.customerentityid,
		c.gatewayid,
		0 HasRecording
    FROM calendar(NOLOCK) ca
         LEFT JOIN calllog(NOLOCK) c ON CAST(c.callscheduledfor AS DATE) = CAST(ca.start_dts AS DATE)
         LEFT JOIN user_detail u(NOLOCK) ON c.callcreatedby = u.User_ID
         LEFT JOIN tbl_voip_ServiceProvider s ON s.id = c.gatewayid
         LEFT JOIN Cloud_app_master(NOLOCK) m ON m.AppId = c.appid
		 --Left join tbl_CallLogOutcomeMaster(nolock) oc on c.outcomeid = oc.Id
    WHERE c.Callstarttime  is null and CAST(callscheduledfor AS DATE) BETWEEN CAST(@StartDate AS DATE) AND CAST(@EndDate AS DATE)
          AND c.parentid = @ParentId

end



GO

