/* ============================================================
   Procedure: [dbo].[usp_mob_GetCustomSearchNameList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_mob_GetCustomSearchNameList](    
 @UserId bigint,          
 @EntityName nvarchar(50) = ''         
)          
as          
begin          
       
 --declare @UserId bigint = 41928, @EntityName nvarchar(50) = 'lead'          
          
 if(isnull(@EntityName, '') = '')          
 begin          
  set @EntityName = 'Lead'          
 end          
          
select sc.ID, CriteriaName, CriteriaType  
   ,(  
        SELECT   
            sc.CriteriaType,  
            tsc.FieldType,  
            tsc.FieldName,  
            tsc.Operator,  
            tsc.Value  
        FOR JSON PATH, WITHOUT_ARRAY_WRAPPER  
     ) AS Expression  
 FROM tbl_SearchCriteria AS sc WITH (NOLOCK)  
JOIN tbl_SearchCriteriaConditions AS tsc WITH (NOLOCK)   
    ON sc.ID = tsc.CriteriaID    
--from tbl_SearchCriteria(nolock)           
  where       
 1 = ( case       
  when @UserId  = @UserId then 1       
  when IsActive = 0 then 1 else 0 end )       
 and 1 = (case         
   when @EntityName = 'both' then 1         
   when CriteriaType = @EntityName  then 1        
  else 0 end )        
and ParentID = ( select ParentID from User_Detail(nolock) where User_ID = @UserId )          
      
      
end 


GO

/* ============================================================
   Procedure: [dbo].[usp_mob_GetEnquiryDetailsSearch]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_mob_GetEnquiryDetailsSearch](  
	@UserId bigint,   
	@CustomSearchId bigint = 0,  
	@PredefindSearchId bigint = 0,  
	@FilterText nvarchar(255) = '',  
	@SearchFieldType nvarchar(20) = 'default'  
)  
as  
begin  
  
	--declare   
	--	@UserId bigint = 33819,   
	--	@CustomSearchId nvarchar(50) = '208781',  
	--	@PredefindSearchId nvarchar(50) = '',  
	--	@FilterText nvarchar(255) = '',  
	--	@OffsetValue int  = 0,  
	--	@PageSize int  = 100 ,
	--	@SearchFieldType nvarchar(20) = 'default' 
  
  
 --if(@pageSize < 100)    
 --begin     
 -- set @pageSize = 100    
 --end    
  
 declare @ParentId bigint, @fieldName nvarchar(max), @TimeZoneName nvarchar(255);  
  
 declare @UserIdTeamLst varchar(Max) = ''   
 declare @tbluser table (User_ID bigint,Name varchar(100), Image varchar(100))  
 declare @IsAdmin bit = 0       
   
 select  @IsAdmin = isnull(IsAdmin,0),   
   @ParentId = ParentID,   
   @TimeZoneName = isnull(TimeZone, 'india standard time')  
  from User_Detail(nolock) where User_ID = @UserId   
   
 if(@IsAdmin = 1)  
 Begin  
  set @UserId = 0  
  insert into @tbluser  
  exec Use_GetUserDetails  @ParentId  
 end   
 else  
 Begin  
  insert into @tbluser  
  exec Use_GetUserDetails @UserID  
 End  
   
 select @UserIdTeamLst=isnull(STRING_AGG(User_ID,','),'') From @tbluser  
   
 set @fieldName = (select STRING_AGG(concat('[c.', fieldname, ']'), ',') from (  
   select distinct fieldname from customfields(nolock) where ParentID = @ParentId) f)  

 declare @fixedColumn nvarchar(max)  
 if(@SearchFieldType = 'setting')  
 Begin  
 set @fixedColumn = ' EnquiryID, PersonName, CompanyName, MobileNo, MobileNo1, MobileNo2, EmailID, EmailID1, EmailID2, City, State, Country, CountryCode, CountryCode1, CountryCode2, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, CreatedDate, CreatedBy, IsOpen, LeadNo, img_ext, ProfileImgFileName as Image, enquirysource, WhatsAppNoColName, whereAddress, latitude, longitude '  
End
 if(@SearchFieldType = 'default')  
 Begin  
 set @fixedColumn = ' EnquiryID, PersonName, CompanyName, MobileNo, MobileNo1, MobileNo2, EmailID, EmailID1, EmailID2, City, State, Country, CountryCode, CountryCode1, CountryCode2, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, CreatedDate, CreatedBy, IsOpen, LeadNo, img_ext, ProfileImgFileName as Image, enquirysource, WhatsAppNoColName, whereAddress, latitude, longitude '  
End

  
 -- ',AgentId,AgentFName,AgentLName,AgentImage,AgentLogin'  
  
 declare @DefaultSearch nvarchar(255), @PrimarySort nvarchar(255), @SecondarySort nvarchar(255),  
  @DisplayField nvarchar(max), @OrderBy nvarchar(10), @SearchField nvarchar(max)  
  
 select top 1 @DefaultSearch = default_search, @PrimarySort = primary_sort, @SecondarySort = secondary_sort,  
  @DisplayField = display_fields, @OrderBy = order_by, @SearchField = search_fields from tbl_mob_LeadEnquirySetting(nolock)  
 where (user_id = @UserId or user_id = 0) and entity_type = 'en' order by id desc  
  
 drop table if exists #customSearch  
 create table #customSearch(  
  EntityId bigint  
 )  
  
 --custome search  
 if(isnull(@CustomSearchId, 0) > 0)  
 begin  
  print 'cust'  
  declare @procedure nvarchar(255) = concat('''Exec mysms.dbo.usp_ExecuteUserSearchwithid ',    
    cast(@ParentId as nvarchar), ', ', cast(@CustomSearchId as nvarchar),  ', null ')    
   
  declare @customLeadSql nvarchar(max) = N'';  
  
  set @customLeadSql = concat(N'insert into #customSearch(EntityId) select dl.EntityID from OPENROWSET (''SQLNCLI'', ''Server=aznetpocdbs01; Database=mysms;Uid=kit19;PWD=P@ssword3110;'', ', @procedure, N'  WITH RESULT SETS ( ( EntityName nvarchar(50), EntityID bigint, personname VARCHAR(200), companyname VARCHAR(200), mobileno VARCHAR(100), mobileno1 VARCHAR(100), mobileno2 VARCHAR(100), emailid VARCHAR(100), emailid1 VARCHAR(100), emailid2 VARCHAR(100),  country VARCHAR(100), STATE VARCHAR(100), city VARCHAR(100), pincode VARCHAR(50), residentialaddress VARCHAR(500), officeaddress VARCHAR(500), sourcename VARCHAR(200) COLLATE sql_latin1_general_cp1_ci_as, mediumname VARCHAR(200) COLLATE sql_latin1_general_cp1_ci_as, campaignname VARCHAR(200) COLLATE sql_latin1_general_cp1_ci_as, initialremarks VARCHAR(1000) collate SQL_Latin1_General_CP1_CI_AS, SearchID bigint, ParentID bigint, CampaignID bigint ))'' ) dl inner join mysms.dbo.UserEnquiry(nolock) ue on dl.EntityID = ue.EnquiryID') 
  
  if(len(@customLeadSql) > 0) 
  begin 
   exec sp_executesql  @customLeadSql 
  end    
 end  
  
 declare @filterTextSql nvarchar(max) = ''  
  
 if((isnull(@FilterText, '') <> '') and (@SearchFieldType = 'setting'))      
 begin  
  set @filterTextSql = (select STRING_AGG(concat([value], ' like ''%', @FilterText, '%'''), ' or ') from fn_Split( @SearchField, ','))  
 end 
 if((isnull(@FilterText, '') <> '') and (@SearchFieldType = 'default'))      
 begin      
  set @filterTextSql = '( PersonName like ''%' + @FilterText + '%'' or EnquiryID = ' + @FilterText + ' or   
  trim(concat(trim(isnull(ul.CountryCode, '''')), '' '', trim(isnull(ul.MobileNo, '''')))) + '' '' + trim(concat(trim(isnull(ul.CountryCode1, '''')), '' '', trim(isnull(ul.MobileNo1, '''')))) + '' '' + trim(concat(trim(isnull(ul.CountryCode2, '''')), '' '', trim(isnull(ul.MobileNo2, '''')))) like ''%' + @FilterText + '%'' or (isnull(ul.EmailID, '''') + '' '' + isnull(ul.EmailID1, '''') + '' '' + isnull(ul.EmailID2, '''')) like ''%' + @FilterText + '%'' )' 
 end   
  
 declare @enquiryColumns nvarchar(max) = N'en.EnquiryID,en.PersonName,en.CompanyName,trim(concat(trim(isnull(en.CountryCode, '''')), '' '', trim(isnull(en.MobileNo, '''')))) as MobileNo,trim(concat(trim(isnull(en.CountryCode1, '''')), '' '', trim(isnull(en.MobileNo1, '''')))) as MobileNo1,trim(concat(trim(isnull(en.CountryCode2, '''')), '' '', trim(isnull(en.MobileNo2, '''')))) as MobileNo2,en.EmailID,en.EmailID1,en.EmailID2,en.City,en.State,en.Country,en.PinCode,en.ResidentialAddress,en.OfficeAddress, us.Name as [SourceName],md.Name as [MediumName],cm.Name as [CampaignName],en.InitialRemarks,en.ParentID,dbo.fn_ConvertDateTime(cast(en.CreatedDate as datetime), '''+ @TimeZoneName +N''', 0) as CreatedDate,en.CreatedBy,en.IsOpen,en.LeadNo,en.ProfileImgFileName,en.whereAddress,en.latitude,longitude,ag.User_ID as AgentId,ag.FName as AgentFName,ag.LName as AgentLName,ag.Image as AgentImage,ag.User_Login as AgentLogin';  
  
  declare @cvQuery nvarchar(max)
 if(@SearchFieldType = 'setting')      
 begin 

 set @cvQuery = N'SELECT '+ @fixedColumn + 
 iif(isnull(@DisplayField, '') <> '', concat(',',@DisplayField), '') + N' FROM ( 
    SELECT '+ @enquiryColumns +  iif(isnull(@fieldName, '') <> '', concat(',',@fieldName), '') + N' FROM UserEnquiry(NOLOCK) en '  
 + iif(isnull(@fieldName, '') <> '',  
 concat(N' LEFT JOIN ( SELECT * FROM ( SELECT cfv.EnquiryID, cf.fieldname, cfv.fieldvalue FROM customfields(NOLOCK) cf INNER JOIN customfieldEnquiryvalue(NOLOCK) cfv ON cf.field_ID = cfv.fieldID  
            WHERE cf.ParentID = ' + cast(@ParentId as nvarchar) + ') ipc PIVOT(MAX(fieldvalue) FOR fieldname IN( ' + @fieldName + N' )) p  
    ) c ON en.EnquiryID = c.EnquiryID ', ''), '')  + N'  
 left join UserSourceSettings(nolock) us on en.SourceName = us.SourceID left join UserMediumSettings(nolock) md on en.MediumName = md.MediumID left join UserCampaignSettings(nolock) cm on en.CampaignName = cm.CampaignID left join User_Detail(nolock) ag on
 en.CreatedBy = ag.User_ID '+ iif(exists(select 1 from #customSearch), ' inner join  #customSearch(nolock) cs on en.EnquiryID = cs.EntityId', '') +' WHERE en.ParentID = ' + cast(@ParentId as nvarchar) + ' and en.CreatedBy in ( '+ @UserIdTeamLst +N' ) ) e 
' + iif(isnull(@filterTextSql, '') <> '', concat(' where ', @filterTextSql), '') +  N' '  
End
 if(@SearchFieldType = 'default')      
 begin      

 set @cvQuery  = N'Select Top 1 '+ @fixedColumn +  iif(isnull(@DisplayField, '') <> '', concat(',',@DisplayField), '') + N' from UserEnquiry ul WHERE ul.ParentID = ' + cast(@ParentId as nvarchar) + ' ' + iif(isnull(@filterTextSql, '') <> '', concat(' and  ', @filterTextSql), '') +  N''  
 End  
 print @cvQuery  
 
 execute sp_executesql @cvQuery 
 
end 



