/* ============================================================
   Procedure: [dbo].[usp_mob_GetEnquiryMetaData]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_mob_GetEnquiryMetaData(
	@UserId bigint,
	@Mode nvarchar(255) = 'Enquiry'
)as 
begin
	declare @ParentId bigint = (select ParentID from User_Detail(nolock) where User_ID = @UserId)
	select SNo, FieldName, DataType, DisplayName, DefultValue, ControlType,
		cast(IsVisible as bit) as IsVisible, cast(IsRequired as bit) as IsRequired,
		MaxLength, Maximum, Minimum, Options
		from ( 
			select 'EnquiryId' as [FieldName], 'Long' as  [DataType], 'Enquiry Id' as  [DisplayName], '' as  [DefultValue], 'Hidden' as  [ControlType], 0 as [IsVisible], 0 as [IsRequired], 1 as [SNo], '' as [MaxLength], '' as [Maximum], '' as [Minimum], '' as 'Options'
			union
			select 'ProfileImgFileName' as [FieldName], 'String' as  [DataType], 'Pin Code' as  [DisplayName], '' as  [DefultValue], 'Text' as  [ControlType], 0 as [IsVisible], 1 as [IsRequired], 2 as [SNo], '' as [MaxLength], '' as [Maximum], '' as [Minimum], '' as 'Options'
			union
			select 'PersonName' as [FieldName], 'String' as  [DataType], 'Person Name' as  [DisplayName], '' as  [DefultValue], 'Text' as  [ControlType], 1 as [IsVisible], 1 as [IsRequired], 3 as [SNo], '' as [MaxLength], '' as [Maximum], '' as [Minimum], '' as 'Options'
			union
			select 'CountryCode' as [FieldName], 'String' as  [DataType], 'Country Code' as  [DisplayName], '' as  [DefultValue], 'Text' as  [ControlType], 0 as [IsVisible], 1 as [IsRequired], 4.1 as [SNo], '' as [MaxLength], '' as [Maximum], '' as [Minimum], '' as 'Options'
			union
			select 'MobileNo' as [FieldName], 'String' as  [DataType], 'Mobile No' as  [DisplayName], '' as  [DefultValue], 'Text' as  [ControlType], 1 as [IsVisible], 1 as [IsRequired], 4.2 as [SNo], '' as [MaxLength], '' as [Maximum], '' as [Minimum], '' as 'Options'
			union
			select 'CountryCode1' as [FieldName], 'String' as  [DataType], 'Country Code 1' as  [DisplayName], '' as  [DefultValue], 'Text' as  [ControlType], 0 as [IsVisible], 0 as [IsRequired], 5.1 as [SNo], '' as [MaxLength], '' as [Maximum], '' as [Minimum], '' as 'Options'
			union
			select 'MobileNo1' as [FieldName], 'String' as  [DataType], 'Mobile No 1' as  [DisplayName], '' as  [DefultValue], 'Text' as  [ControlType], 1 as [IsVisible], 0 as [IsRequired], 5.2 as [SNo], '' as [MaxLength], '' as [Maximum], '' as [Minimum], '' as 'Options'
			union
			select 'CountryCode2' as [FieldName], 'String' as  [DataType], 'Country Code 2' as  [DisplayName], '' as  [DefultValue], 'Text' as  [ControlType], 0 as [IsVisible], 0 as [IsRequired], 6.1 as [SNo], '' as [MaxLength], '' as [Maximum], '' as [Minimum], '' as 'Options'
			union
			select 'MobileNo2' as [FieldName], 'String' as  [DataType], 'Mobile No 2' as  [DisplayName], '' as  [DefultValue], 'Text' as  [ControlType], 1 as [IsVisible], 0 as [IsRequired], 6.2 as [SNo], '' as [MaxLength], '' as [Maximum], '' as [Minimum], '' as 'Options'
			union
			select 'EmailID' as [FieldName], 'String' as  [DataType], 'EmailId' as  [DisplayName], '' as  [DefultValue], 'Text' as  [ControlType], 1 as [IsVisible], 1 as [IsRequired], 7 as [SNo], '' as [MaxLength], '' as [Maximum], '' as [Minimum], '' as 'Options'
			union
			select 'EmailID1' as [FieldName], 'String' as  [DataType], 'EmailId 1' as  [DisplayName], '' as  [DefultValue], 'Text' as  [ControlType], 1 as [IsVisible], 0 as [IsRequired], 8 as [SNo], '' as [MaxLength], '' as [Maximum], '' as [Minimum], '' as 'Options'
			union
			select 'EmailID2' as [FieldName], 'String' as  [DataType], 'EmailId 2' as  [DisplayName], '' as  [DefultValue], 'Text' as  [ControlType], 1 as [IsVisible], 0 as [IsRequired], 9 as [SNo], '' as [MaxLength], '' as [Maximum], '' as [Minimum], '' as 'Options'
			union
			select 'SourceName' as [FieldName], 'Long' as  [DataType], 'Source Name' as  [DisplayName], '' as  [DefultValue], 'DropDown' as  [ControlType], 1 as [IsVisible], 1 as [IsRequired], 10 as [SNo], '' as [MaxLength], '' as [Maximum], '' as [Minimum], '' as 'Options'
			union
			select 'InitialRemarks' as [FieldName], 'String' as  [DataType], 'Remarks' as  [DisplayName], '' as  [DefultValue], 'MultiLineText' as  [ControlType], 1 as [IsVisible], 0 as [IsRequired], 11 as [SNo], '' as [MaxLength], '' as [Maximum], '' as [Minimum], '' as 'Options'
			union	
			select 'ResidentialAddress' as [FieldName], 'String' as  [DataType], 'Residential Address' as  [DisplayName], '' as  [DefultValue], 'MultiLineText' as  [ControlType], 1 as [IsVisible], 0 as [IsRequired], 11 as [SNo], '' as [MaxLength], '' as [Maximum], '' as [Minimum], '' as 'Options'
			union
			select 'OfficeAddress' as [FieldName], 'String' as  [DataType], 'Office Address' as  [DisplayName], '' as  [DefultValue], 'MultiLineText' as  [ControlType], 1 as [IsVisible], 0 as [IsRequired], 12 as [SNo], '' as [MaxLength], '' as [Maximum], '' as [Minimum], '' as 'Options'
			union
			select 'MediumName' as [FieldName], 'Long' as  [DataType], 'Medium Name' as  [DisplayName], '' as  [DefultValue], 'DropDown' as  [ControlType], 1 as [IsVisible], 0 as [IsRequired], 13 as [SNo], '' as [MaxLength], '' as [Maximum], '' as [Minimum], '' as 'Options'
			union
			select 'CampaignName' as [FieldName], 'Long' as  [DataType], 'Campaign Name' as  [DisplayName], '' as  [DefultValue], 'DropDown' as  [ControlType], 1 as [IsVisible], 0 as [IsRequired], 14 as [SNo], '' as [MaxLength], '' as [Maximum], '' as [Minimum], '' as 'Options'
			union
			select 'Country' as [FieldName], 'String' as  [DataType], 'Country Name' as  [DisplayName], '' as  [DefultValue], 'DropDown' as  [ControlType], 1 as [IsVisible], 0 as [IsRequired], 15 as [SNo], '' as [MaxLength], '' as [Maximum], '' as [Minimum], '' as 'Options'
			union
			select 'State' as [FieldName], 'String' as  [DataType], 'State' as  [DisplayName], '' as  [DefultValue], 'DropDown' as  [ControlType],  1 as [IsVisible], 0 as [IsRequired], 16 as [SNo], '' as [MaxLength], '' as [Maximum], '' as [Minimum], '' as 'Options'
			union
			select 'City' as [FieldName], 'String' as  [DataType], 'City' as  [DisplayName], '' as  [DefultValue], 'DropDown' as  [ControlType], 1 as [IsVisible], 0 as [IsRequired], 17 as [SNo], '' as [MaxLength], '' as [Maximum], '' as [Minimum], '' as 'Options'
			union
			select 'PinCode' as [FieldName], 'String' as  [DataType], 'Pin Code' as  [DisplayName], '' as  [DefultValue], 'Text' as  [ControlType], 1 as [IsVisible], 0 as [IsRequired], 18 as [SNo], '' as [MaxLength], '' as [Maximum], '' as [Minimum], '' as 'Options'
			union
			select 'WhereAddress' as [FieldName], 'String' as  [DataType], 'Where Address' as  [DisplayName], '' as  [DefultValue], 'Text' as  [ControlType], 1 as [IsVisible], 0 as [IsRequired], 19 as [SNo], '' as [MaxLength], '' as [Maximum], '' as [Minimum], '' as 'Options'
			union
			select 'Latitude' as [FieldName], 'String' as  [DataType], 'Latitude' as  [DisplayName], '' as  [DefultValue], 'Text' as  [ControlType], 1 as [IsVisible], 0 as [IsRequired], 20 as [SNo], '' as [MaxLength], '' as [Maximum], '' as [Minimum], '' as 'Options'
			union
			select 'Longitude' as [FieldName], 'String' as  [DataType], 'Longitude' as  [DisplayName], '' as  [DefultValue], 'Text' as  [ControlType], 1 as [IsVisible], 0 as [IsRequired], 21 as [SNo], '' as [MaxLength], '' as [Maximum], '' as [Minimum], '' as 'Options'
			union
			select 'CreatedBy' as [FieldName], 'Long' as  [DataType], 'Pin Code' as  [DisplayName], '' as  [DefultValue], 'Text' as  [ControlType], 0 as [IsVisible], 1 as [IsRequired], 22 as [SNo], '' as [MaxLength], '' as [Maximum], '' as [Minimum], '' as [Options]
			union
			 select 
			fieldname as [FieldName],
			(case datatype
				when 'd' then 'String'
				when 'f' then 'Float'
				when 'v' then 'String'
				when 'r' then 'String'
				when 'm' then 'String'
				when 's' then 'String'
				when 'c' then 'String'
				when 'e' then 'String'
				when 'l' then 'String'
			end ) as [DataType],
			fieldname as [DisplayName],
			isnull(defaultValue, '') as  [DefultValue],
			(case datatype  
				when 'd' then 'Date'  
				when 'f' then 'Numeric'  
				when 'v' then 'Text'  
				when 'r' then 'Radio'  
				when 'm' then 'Multiline'  
				when 's' then 'DropDown'  
				when 'c' then 'Checkbox'  
				when 'e' then 'Expression'  
				when 'l' then 'List'  
			END) as [ControlType],
			isActive as [IsVisible],
			isMandatory as [IsRequired],
			(sequence + 100) as  [SNo],
			'' as [MaxLength],
			minvalue as [Minimum],
			maxvalue as [Maximum],
			choices  as [Options]
			from customfields where isActive = 1 and ParentID = @ParentId 
		) m order by SNo asc
end



GO

/* ============================================================
   Procedure: [dbo].[usp_mob_GetFollowupDetailById]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- exec usp_mob_GetFollowupDetailById 9694694, 32222
CREATE   PROCEDURE [dbo].[usp_mob_GetFollowupDetailById] --806309,34594  
(      
 @FollowupId bigint,      
 @UserId bigint      
)      
as      
begin      
 --declare @FollowupId bigint = 9694694,@UserId bigint=32222
  
    Declare @ParentID bigint = ( select top 1 ISNULL(ParentID,0) from User_Detail with(nolock) where User_ID = @UserId )   
    exec Usp_createProductMasterTable @ParentID   
  
 Declare @Query nvarchar(max) = Concat( N'  
  
  select f.ID as Id, fs.FollowupStatus, f.FollowupDate, f.AmountPaid, f.Remarks, f.CreatedOn, f.IsReassign,      
    (      
   iif(isnull(f.Products, '''') = '''', '''', (      
    select p.ProductId, p.Name, p.FullPath as Image, p.Description, p.Price       
     from tbl_ProductMaster_' , Cast(@ParentID as nvarchar(max)) , '(nolock) p where ProductID in (      
     select isnull(TRY_CONVERT(float, [value]), 0) from fn_Split(f.Products, ''#'')      
    ) for json path)      
   )      
  ) as [Products],      
  isnull(ul.ID,0) as LeadId, isnull(ul.PersonName,'''') as PersonName, isnull(ul.ProfileImgFileName,'''') as ProfileImgFileName, a.User_ID as aUserId, a.FName as aFirstName,      
  a.LName as aLastName, a.User_Login as aUserLogin, a.Image as aImage, c.User_ID as cUserId,      
  c.FName as cFirstName, c.LName as cLastName, c.User_Login as cUserLogin, c.Image as cImage, f.ParentID      
 from LeadInteractionHistory(nolock) f      
   inner join FollowUp_Status fs on f.FollowUpStatus = fs.ID      
   left join UserLeads(nolock) ul on f.LeadNo = ul.LeadNo and f.ParentID = ul.ParentID      
   left join User_Detail(nolock) a on f.AssignedTo = a.User_ID      
   left join User_Detail(nolock) c on f.CreatedBy = c.User_ID      
  where f.ID = ', Cast( @FollowupId as nvarchar(max)) , '' )  
         
  print @Query                    
     exec sp_executesql @Query  
        
end 



GO

/* ============================================================
   Procedure: [dbo].[usp_mob_GetFollowupListByUserId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/*  
  
Procedure Name  : usp_mob_GetFollowupListByUserId  
  
Parameter(s)  : NIL  
   
Initial Version  :  
   
Revision Date  : 2024-12-06  
  
Revision Remarks : Added a temp. table #LIH to select a few LeadInteractionHistory IDs  
  
       and used this to join in special conditions (when custom order or filter is not supplied)  
  
Revision Date  : 2026-01-20  
  
Revision Remarks : Modified the dynamic SQL to find the count separateley  
      and also modified the base query for performance improvement  
   
*/  
CREATE   PROCEDURE [dbo].[usp_mob_GetFollowupListByUserId](
	@UserId bigint,
	@FullText varchar(200),
	@FilterText nvarchar(max),
	@SearchText nvarchar(max),
	@OffsetValue int = 0,
	@PagingSize int = 20 
) 
as 
begin 
--DECLARE 
    --@UserId BIGINT = 32222,
    --@FullText VARCHAR(200) = '', 
    --@FilterText NVARCHAR(MAX) = N'',
    --@SearchText NVARCHAR(MAX) = N'', 
    --@OffsetValue INT = 0, 
    --@PagingSize INT = 100

--DECLARE 
--    @UserId BIGINT = 32222,
--    @FullText VARCHAR(200) = '', 
--    @FilterText NVARCHAR(MAX) = N'
--        FollowupStatusId IN (39,40)
--        AND FollowupDateStatus IN (''overdue'',''duetoday'',''scheduled'',''nofollowup'')
--        AND (
--            CAST(CreatedOn AS DATE) BETWEEN 
--            CONVERT(DATE,''01-May-2026'') 
--            AND 
--            CONVERT(DATE,''24-May-2026'')
--        )
--        AND aUserId IN (SELECT User_ID FROM #tblUser)
--    ',
--    @SearchText NVARCHAR(MAX) = N'', 
--    @OffsetValue INT = 0, 
--    @PagingSize INT = 100
	
 
	DROP TABLE IF EXISTS #tblUser;

	CREATE TABLE #tblUser (User_ID BIGINT, Name VARCHAR(100), IMAGE NVARCHAR(200));
 
	DECLARE @ParentId BIGINT = 0;

	SELECT @ParentId = ParentID FROM User_Detail (NOLOCK) WHERE User_ID = @UserId;
 
	-- Insert User Details

	INSERT INTO #tblUser

	EXEC MySMS.dbo.Use_GetUserDetails @UserId;
 
	-- Adjust filters based on inputs

	IF (@FullText != '') 

	BEGIN

		SET @FullText = N' AND (t.PersonName LIKE ''%' + @FullText + '%'' OR CAST(t.LeadNo AS VARCHAR(20)) LIKE ''%' + @FullText + '%'' OR t.CsvMobileNo LIKE ''%' + @FullText + '%'' OR t.CsvEmailId LIKE ''%' + @FullText + '%'')';

		SET @FilterText = N'';

		SET @SearchText = N'';

	END;
 
	IF (@FilterText != '') 

	BEGIN

		SET @FilterText = N' AND ' + @FilterText;

		SET @FullText = N'';

	END;
 
	IF (@SearchText != '') 

	BEGIN

		SET @FullText = N'';

		SET @FilterText = N'';

	END;
 
	-- Construct the dynamic query

	DECLARE @query NVARCHAR(MAX);

	DECLARE @query2 NVARCHAR(MAX);

	DECLARE @query3 NVARCHAR(MAX);

	DECLARE @query4 NVARCHAR(MAX);
 


	/* Added By DBA */

	/* Date : 2024-12-06*/
 
	DECLARE @is_special_case INT = 0

	-- Get a list of valid LeadInteractionHistory IDs

	IF @FullText = N'' AND @FilterText = N'' AND @SearchText=N'' 

		BEGIN
 
			SET @is_special_case = 1;
 
			DECLARE @SQL AS NVARCHAR(MAX) = N'';

			DROP TABLE IF EXISTS #LIH;

			DROP TABLE IF EXISTS #max_id
 
			SELECT ParentID, LeadNo, MAX(ID) AS ID INTO #max_id

			FROM LeadInteractionHistory (NOLOCK) f

			WHERE ParentID = @ParentId

			GROUP BY ParentID, LeadNo
 
			CREATE CLUSTERED INDEX CIX_#max_id ON #max_id (ID DESC);
 
			CREATE TABLE #LIH (ID BIGINT);
 
			SET @SQL = N'INSERT INTO #LIH

				SELECT f.ID

				FROM LeadInteractionHistory (NOLOCK) f

				INNER JOIN #max_id mid

					ON mid.ParentID = f.ParentID AND mid.LeadNo = f.LeadNo AND mid.ID = f.ID

				INNER JOIN #tblUser u

					ON f.AssignedTo = u.User_ID

				INNER JOIN FollowUp_Status (NOLOCK) fs

					ON f.FollowUpStatus = fs.ID

				INNER JOIN UserLeads (NOLOCK) ul

					ON f.LeadNo = ul.LeadNo

					   AND f.ParentID = ul.ParentID

				INNER JOIN User_Detail (NOLOCK) a

					ON f.AssignedTo = a.User_ID

				INNER JOIN User_Detail (NOLOCK) c

					ON f.CreatedBy = c.User_ID

			WHERE f.ParentID = @pid ' +

			N' ORDER BY mid.ID DESC '

			-- +
			-- N' offset ' + cast(@OffsetValue as nvarchar(10)) + N' rows fetch next '+ cast((@OffsetValue + 1 + @PagingSize) as nvarchar(10)) + N' rows only; '
 
			EXEC sp_executeSQL @SQL, N'@pid BIGINT', @pid = @ParentId;

		END

		DECLARE @base_query NVARCHAR(MAX);
		DECLARE @base_query_with_column NVARCHAR(MAX);
		DECLARE @count_query NVARCHAR(MAX) = N''
		DECLARE @top_query NVARCHAR(MAX) = N''
		DECLARE @total_count INT;

		SET @base_query = CONCAT(
		N'SELECT <place_holder> ',

			N'FROM LeadInteractionHistory (NOLOCK) f ',

			IIF(@is_special_case = 1, N' INNER JOIN #LIH tlih ON tlih.ID = f.ID ', N''),

			'<top_query_join>',

			N'INNER JOIN #tblUser u ON f.AssignedTo = u.User_ID ',

			N'INNER JOIN FollowUp_Status (NOLOCK) fs ON f.FollowUpStatus = fs.ID ',

			N'INNER JOIN UserLeads (NOLOCK) ul ON f.LeadNo = ul.LeadNo AND f.ParentID = ul.ParentID ',

			N'INNER JOIN User_Detail (NOLOCK) a ON f.AssignedTo = a.User_ID ',

			N'INNER JOIN User_Detail (NOLOCK) c ON f.CreatedBy = c.User_ID ',

			N'WHERE f.ParentID = ' ) + CAST(@ParentId AS VARCHAR)
 
			+IIF(@is_special_case = 1, N' ', N' and f.id in (select max(id) from leadinteractionhistory(nolock) where parentid=f.ParentID and leadno=f.leadno) ') +

				+ concat( 

				N'and 1 = (CASE  ', 

					N'when isnull(''', @SearchText, ''', '''') = '''' then 1  ', 

					N'WHEN ( isnull(''', @SearchText, ''', '''') = ''Completed by me today''  ', 

						N'and (cast(f.FollowupDate AS DATE) = cast(getdate() AS DATE))  ', 

						N'and (cast(f.CreatedBy as varchar(20)) = ''', @UserId, ''') and (f.IsReassign = 0 )) THEN 1 '
		) +
		concat( N'WHEN ( isnull(''', @SearchText, ''', '''') = ''Completed Today''  ', 

						N'and (cast(f.FollowupDate AS DATE) = cast(getdate() AS DATE)) and (fs.IsConvert = 1)) THEN 1 ', 

					N'WHEN (isnull(''', @SearchText, ''', '''') = ''My Followups due Today'' and (fs.IsConvert = 0) ', 

						N'and (cast(f.FollowupDate AS DATE) = cast(getdate() AS DATE)) ',  

						N'and (cast(f.AssignedTo as varchar(20)) = ''', @UserId, ''')) THEN 1 ', 

					N'WHEN (isnull(''', @SearchText, ''', '''') = ''Followups due Today'' and (fs.IsConvert = 0) ', 

						N'and (cast(f.FollowupDate AS DATE) = cast(getdate() AS DATE)) ',  

						N'and (cast(f.AssignedTo as varchar(20)) = ''', @UserId, ''')) THEN 1 ', 

					N'WHEN (isnull(''', @SearchText, ''', '''') = ''My Overdue Followups'' and (fs.IsConvert = 0) ', 

						N'and (cast(f.FollowupDate AS DATE) < cast(getdate() AS DATE)) ', 

						N'and (cast(f.AssignedTo as varchar(20)) = ''', @UserId, ''')) THEN 1 ', 

					N'WHEN (isnull(''', @SearchText, ''', '''') = ''Overdue Followups'' and (fs.IsConvert = 0) ',  

						N'and (cast(f.FollowupDate AS DATE) < cast(getdate() AS DATE))) THEN 1 ', 

					N'WHEN (isnull(''', @SearchText, ''', '''') = ''My upcoming Followups'' ', 

						N'and (cast(f.FollowupDate AS DATE) > cast(getdate() AS DATE)) ', 

						N'and (cast(f.AssignedTo as varchar(20)) = ''', @UserId, ''')) THEN 1 ', 

					N'WHEN (isnull(''', @SearchText, ''', '''') = ''Upcoming Followups'' ', 

						N'and (cast(f.FollowupDate AS DATE) > cast(getdate() AS DATE))) THEN 1 ', 

					N'WHEN (isnull(''', @SearchText, ''', '''') = ''Not followed by me'' ',  

						N'and (cast(f.FollowupDate AS DATE) IS NULL) ', 

						N'and (cast(f.AssignedTo as varchar(20)) = ''', @UserId, ''')) THEN 1 ', 

					N'WHEN (isnull(''', @SearchText, ''', '''') = ''Not followed'' ', 

						N'and (cast(f.FollowupDate AS DATE) IS NULL)) THEN 1 ', 

					N'else 0 end ) <sort_order>');

		SET @count_query = REPLACE
								(
								REPLACE(
										REPLACE(@base_query, '<place_holder>', '@cnt = COUNT(*) ')
										, '<sort_order>', ''
										), '<top_query_join>', ''
								);
		SET @count_query = CAST(@count_query AS NVARCHAR(MAX));

		EXEC sp_executesql @stmt = @count_query, @params = N'@cnt INT OUTPUT', @cnt = @total_count OUTPUT;

		drop TABLE if exists #t;
		CREATE TABLE #t (ID BIGINT, RN INT);

		DECLARE @offset_page_query AS NVARCHAR(MAX);
		DECLARE @fetch_next INT = 0;

		SELECT @fetch_next = CASE
                                WHEN @PagingSize > (@total_count - @offsetvalue) THEN (@total_count - @offsetvalue)
                                ELSE
                                    @PagingSize
                            END;
		-- SETTING 1 IN-CASE @fetch_next IS 0
		if(isnull(@fetch_next, 0) = 0)
		begin
			set @fetch_next = 1
		end

		SET @offset_page_query = CAST(@offsetvalue AS NVARCHAR(10)) + 
				N' ROWS FETCH NEXT ' + CAST(@fetch_next AS NVARCHAR(10));

		SELECT @top_query = 'INSERT INTO #t (ID, RN)' +
		REPLACE(
			REPLACE(
					REPLACE(@base_query, '<place_holder>', ' f.ID, ROW_NUMBER() OVER (ORDER BY f.ID DESC) AS RN ')
					,'<sort_order>', ' ORDER BY f.ID DESC OFFSET ' + @offset_page_query + ' ROWS ONLY'
					)
					,'<top_query_join>', ''
				);

		EXEC sp_executesql @top_query;

	SELECT @base_query_with_column = REPLACE(
		REPLACE(
		REPLACE(@base_query, '<place_holder>', 
			--'f.ID AS Id,
			--fs.FollowupStatus,
			--f.FollowupDate, 
			'f.ID AS Id,
            f.FollowupStatus AS FollowupStatusId,
            fs.FollowupStatus,
            f.FollowupDate,
			f.AmountPaid, 
			f.Remarks, 
			f.CreatedOn, 
			f.IsReassign, 
			CASE
				WHEN CAST(f.FollowupDate AS DATE) = CAST(GETDATE() AS DATE) THEN ''duetoday'' 
				WHEN CAST(f.FollowupDate AS DATE) < CAST(GETDATE() AS DATE) THEN ''overdue'' 
				WHEN CAST(f.FollowupDate AS DATE) > CAST(GETDATE() AS DATE) THEN ''scheduled'' 
				ELSE ''nofollowup'' 
			END AS FollowupDateStatus, 
			(CASE WHEN ISNULL(f.Products, '''') = '''' THEN NULL ELSE 
				(SELECT p.ProductId, p.Name, p.FullPath AS Image, p.Description, p.Price
				FROM ProductMaster (NOLOCK) p 
				WHERE ProductID IN (SELECT TRY_CONVERT(FLOAT, [value]) FROM fn_Split(f.Products, ''#'')) 
				FOR JSON PATH) 
			END) AS Products, 
			ul.ID AS LeadId,
			ul.PersonName, 
			ul.ProfileImgFileName, 
			ul.ProfileImgFileName as Image,
			ul.LeadNo, 
			CONCAT(ul.MobileNo, 
					CASE WHEN ul.MobileNo1 <> '''' THEN '','' + ul.MobileNo1 ELSE '''' END, 
					CASE WHEN ul.MobileNo2 <> '''' THEN '','' + ul.MobileNo2 ELSE '''' END) AS CsvMobileNo, 
			CONCAT(ul.EmailId, 
					CASE WHEN ul.EmailId1 <> '''' THEN '','' + ul.EmailId1 ELSE '''' END, 
					CASE WHEN ul.EmailId2 <> '''' THEN '','' + ul.EmailId2 ELSE '''' END) AS CsvEmailId, 
			a.User_ID as aUserId, a.FName as aFirstName, 
			a.LName as aLastName, concat(a.FName, '' '', a.LName) as AgentName, 
			a.User_Login AS aUserLogin, 
			a.Image AS aImage, 
			 c.User_ID as cUserId, 
			c.FName as cFirstName, c.LName as cLastName, c.User_Login as cUserLogin, 
			c.Image as cImage,
			f.ParentID'
			)
			,'<sort_order>', ' ')
		,'<top_query_join>', IIF(@is_special_case = 1, N' INNER JOIN #t t ON t.ID = f.ID ', N' '));

	SET @query = concat(N'WITH LeadInteraction AS ( ', 

			--N'SELECT Id, FollowupStatus, FollowupDate, 
			N'SELECT Id, FollowupStatusId, FollowupStatus, FollowupDate,
			AmountPaid, Remarks, CreatedOn, IsReassign, FollowupDateStatus, Products, LeadId, PersonName, ',

			N'ProfileImgFileName, LeadNo, Image, CsvMobileNo, CsvEmailId, aUserId, aFirstName, aLastName, AgentName, aUserLogin, aImage, cUserId, ',

			N'cFirstName, cLastName, cUserLogin, cImage, ParentID FROM ( ',

			@base_query_with_column, ') ',

				N' t where (1=1) ', @FullText, N' ', @FilterText, N' )' )
 
		-- Pagination

		

 
		SET @query3 = N' SELECT ' + IIF(@is_special_case = 1, CAST(@total_count AS VARCHAR(10)), N' (select count(1) from LeadInteraction) ') +
			' as [TotalRow], * FROM LeadInteraction l  ORDER BY Id DESC ' 
			+ IIF(@is_special_case = 1
				, N' '
				, N' OFFSET ' +
				CAST(@OffsetValue AS NVARCHAR) + ' ROWS FETCH NEXT  (SELECT CASE 

                WHEN '+cast(@PagingSize as nvarchar)+' > ((select count(1) from LeadInteraction) - '+cast(@offsetvalue as nvarchar)+' ) 

                THEN ((select count(1) from LeadInteraction) - '+cast(@offsetvalue as nvarchar)+') 

                ELSE '+cast(@PagingSize as nvarchar)+' END) ROWS ONLY'
			);
 
		-- Combine and execute the query

		--DECLARE @FinalQuery NVARCHAR(MAX) = @query + @query2 + @query3;
		DECLARE @FinalQuery NVARCHAR(MAX) = CAST(@query + @query3 AS NVARCHAR(MAX)) ;
 
		print @query

		print @query2

		print @query3

		PRINT 'Final...'
		PRINT @FinalQuery;

	 EXEC sp_executesql @FinalQuery; -- Uncomment to execute
  
end


GO

/* ============================================================
   Procedure: [dbo].[usp_mob_GetFollowupListByUserId_KKv1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


/*
Procedure Name		: usp_mob_GetFollowupListByUserId
Parameter(s)		: NIL

Initial Version		:

Revision Date		: 2024-12-06
Revision Remarks	: Added a temp. table #LIH to select a few LeadInteractionHistory IDs
					  and used this to join in special conditions (when custom order or filter is not supplied)

Revision Date		: 2025-09-06
Revision Remarks	: @SearchText filter removed from @is_special_case to consider passing Search text to parameter
					  (to improve performancce)

*/
CREATE   PROCEDURE [dbo].[usp_mob_GetFollowupListByUserId_KKv1](    
	@UserId bigint,
	@FullText varchar(200),    
	@FilterText nvarchar(max),    
	@SearchText nvarchar(max),    
	@OffsetValue int = 0,    
	@PagingSize int = 20 
) 
as 
begin 
	--DECLARE 
	--	@UserId BIGINT = 32222,
	--	@FullText VARCHAR(200) = '', 
	--	@FilterText NVARCHAR(MAX) = N'',
	--	@SearchText NVARCHAR(MAX) = N'', 
	--	@OffsetValue INT = 0, 
	--	@PagingSize INT = 100;

	DROP TABLE IF EXISTS #tblUser;
	CREATE TABLE #tblUser (User_ID BIGINT, Name VARCHAR(100), IMAGE NVARCHAR(200));

	DECLARE @ParentId BIGINT = 0;
	SELECT @ParentId = ParentID FROM User_Detail (NOLOCK) WHERE User_ID = @UserId;

	-- Insert User Details
	INSERT INTO #tblUser
	EXEC MySMS.dbo.Use_GetUserDetails @UserId;

	-- Adjust filters based on inputs
	IF (@FullText != '') 
	BEGIN
		SET @FullText = N' AND (t.PersonName LIKE ''%' + @FullText + '%'' OR CAST(t.LeadNo AS VARCHAR(20)) LIKE ''%' + @FullText + '%'' OR t.CsvMobileNo LIKE ''%' + @FullText + '%'' OR t.CsvEmailId LIKE ''%' + @FullText + '%'')';
		SET @FilterText = N'';
		SET @SearchText = N'';
	END;

	IF (@FilterText != '') 
	BEGIN
		SET @FilterText = N' AND ' + @FilterText;
		SET @FullText = N'';
	END;

	IF (@SearchText != '') 
	BEGIN
		SET @FullText = N'';
		SET @FilterText = N'';
	END;

	-- Construct the dynamic query
	DECLARE @query NVARCHAR(MAX);
	DECLARE @query2 NVARCHAR(MAX);
	DECLARE @query3 NVARCHAR(MAX);
	DECLARE @query4 NVARCHAR(MAX);

 
	/* Added By DBA */
	/* Date : 2024-12-06*/

	DECLARE @is_special_case INT = 0
	-- Get a list of valid LeadInteractionHistory IDs
	IF @FullText = N'' AND @FilterText = N'' 
		--AND @SearchText=N'' /*Commented By : DBA Date : 2025-09-06 */
		BEGIN

			SET @is_special_case = 1;

			DECLARE @SQL AS NVARCHAR(MAX) = N'';
			DROP TABLE IF EXISTS #LIH;
			DROP TABLE IF EXISTS #max_id

			SELECT ParentID, LeadNo, MAX(ID) AS ID INTO #max_id
			FROM LeadInteractionHistory (NOLOCK) f
			WHERE ParentID = @ParentId
			GROUP BY ParentID, LeadNo

			CREATE CLUSTERED INDEX CIX_#max_id ON #max_id (ID DESC);

			CREATE TABLE #LIH (ID BIGINT);

			SET @SQL = N'INSERT INTO #LIH
				SELECT f.ID
				FROM LeadInteractionHistory (NOLOCK) f
				INNER JOIN #max_id mid
					ON mid.ParentID = f.ParentID AND mid.LeadNo = f.LeadNo AND mid.ID = f.ID
				INNER JOIN #tblUser u
					ON f.AssignedTo = u.User_ID
				INNER JOIN FollowUp_Status (NOLOCK) fs
					ON f.FollowUpStatus = fs.ID
				INNER JOIN UserLeads (NOLOCK) ul
					ON f.LeadNo = ul.LeadNo
					   AND f.ParentID = ul.ParentID
				INNER JOIN User_Detail (NOLOCK) a
					ON f.AssignedTo = a.User_ID
				INNER JOIN User_Detail (NOLOCK) c
					ON f.CreatedBy = c.User_ID
			WHERE f.ParentID = @pid ' +
			N' ORDER BY mid.ID DESC ' +
			N' offset ' + cast(@OffsetValue as nvarchar(10)) + N' rows fetch next '+ cast((@PagingSize * 2) as nvarchar(10)) + N' rows only; '

			EXEC sp_executeSQL @SQL, N'@pid BIGINT', @pid = @ParentId;
		END

	SET @query = concat(N'WITH LeadInteraction AS ( ', 
			N'SELECT Id, FollowupStatus, FollowupDate, AmountPaid, Remarks, CreatedOn, IsReassign, FollowupDateStatus, Products, LeadId, PersonName, ',
			N'ProfileImgFileName, LeadNo, Image, CsvMobileNo, CsvEmailId, aUserId, aFirstName, aLastName, AgentName, aUserLogin, aImage, cUserId, ',
			N'cFirstName, cLastName, cUserLogin, cImage, ParentID FROM ( ',
			N'SELECT f.ID AS Id, ',
				   N'fs.FollowupStatus, ',
				   N'f.FollowupDate, ',
				   N'f.AmountPaid, ',
				   N'f.Remarks, ',
				   N'f.CreatedOn, ',
				   N'f.IsReassign, ',
				   N'CASE ',
					   N'WHEN CAST(f.FollowupDate AS DATE) = CAST(GETDATE() AS DATE) THEN ''duetoday'' ',
					   N'WHEN CAST(f.FollowupDate AS DATE) < CAST(GETDATE() AS DATE) THEN ''overdue'' ',
					   N'WHEN CAST(f.FollowupDate AS DATE) > CAST(GETDATE() AS DATE) THEN ''scheduled'' ',
					   N'ELSE ''nofollowup'' ',
				   N'END AS FollowupDateStatus, ', 
				   N'(CASE WHEN ISNULL(f.Products, '''') = '''' THEN NULL ELSE ',
					   N'(SELECT p.ProductId, p.Name, p.FullPath AS Image, p.Description, p.Price ',
						N'FROM ProductMaster (NOLOCK) p ',
						N'WHERE ProductID IN (SELECT TRY_CONVERT(FLOAT, [value]) FROM fn_Split(f.Products, ''#'')) ',
						N'FOR JSON PATH) ',
				   N'END) AS Products, ',
				   N'ul.ID AS LeadId, ',
				   N'ul.PersonName, ',
				   N'ul.ProfileImgFileName, ',
				   N'ul.ProfileImgFileName as Image, ',
				   N'ul.LeadNo, ',
				   N'CONCAT(ul.MobileNo, ',
						  N'CASE WHEN ul.MobileNo1 <> '''' THEN '','' + ul.MobileNo1 ELSE '''' END, ',
						  N'CASE WHEN ul.MobileNo2 <> '''' THEN '','' + ul.MobileNo2 ELSE '''' END) AS CsvMobileNo, ',
				   N'CONCAT(ul.EmailId, ',
						  N'CASE WHEN ul.EmailId1 <> '''' THEN '','' + ul.EmailId1 ELSE '''' END, ',
						  N'CASE WHEN ul.EmailId2 <> '''' THEN '','' + ul.EmailId2 ELSE '''' END) AS CsvEmailId, ',
				   N'a.User_ID as aUserId, a.FName as aFirstName, ',
				   N'a.LName as aLastName, concat(a.FName, '' '', a.LName) as AgentName, ',
				   N'a.User_Login AS aUserLogin, ',
				   N'a.Image AS aImage, ',
				   N' c.User_ID as cUserId, ',
				   N'c.FName as cFirstName, c.LName as cLastName, c.User_Login as cUserLogin, ',
				   N'c.Image as cImage,',
				   N'f.ParentID ',
			N'FROM LeadInteractionHistory (NOLOCK) f ',
			IIF(@is_special_case = 1, N' INNER JOIN #LIH tlih ON tlih.ID = f.ID ', N''),
			N'INNER JOIN #tblUser u ON f.AssignedTo = u.User_ID ',
			N'INNER JOIN FollowUp_Status (NOLOCK) fs ON f.FollowUpStatus = fs.ID ',
			N'INNER JOIN UserLeads (NOLOCK) ul ON f.LeadNo = ul.LeadNo AND f.ParentID = ul.ParentID ',
			N'INNER JOIN User_Detail (NOLOCK) a ON f.AssignedTo = a.User_ID ',
			N'INNER JOIN User_Detail (NOLOCK) c ON f.CreatedBy = c.User_ID ',
			N'WHERE f.ParentID = ' ) + CAST(@ParentId AS VARCHAR) 

			+IIF(@is_special_case = 1, N'', N' and f.id in (select max(id) from leadinteractionhistory(nolock) where parentid=f.ParentID and leadno=f.leadno) ') +
				+ concat( 
				N'and 1 = (CASE  ', 
					N'when isnull(''', @SearchText, ''', '''') = '''' then 1  ', 
					N'WHEN ( isnull(''', @SearchText, ''', '''') = ''Completed by me today''  ', 
						N'and (cast(f.FollowupDate AS DATE) = cast(getdate() AS DATE))  ', 
						N'and (cast(f.CreatedBy as varchar(20)) = ''', @UserId, ''') and (f.IsReassign = 0 )) THEN 1 ')
	set @query2 =	concat( N'WHEN ( isnull(''', @SearchText, ''', '''') = ''Completed Today''  ', 
						N'and (cast(f.FollowupDate AS DATE) = cast(getdate() AS DATE)) and (fs.IsConvert = 1)) THEN 1 ', 
					N'WHEN (isnull(''', @SearchText, ''', '''') = ''My Followups due Today'' and (fs.IsConvert = 0) ', 
						N'and (cast(f.FollowupDate AS DATE) = cast(getdate() AS DATE)) ',  
						N'and (cast(f.AssignedTo as varchar(20)) = ''', @UserId, ''')) THEN 1 ', 
					N'WHEN (isnull(''', @SearchText, ''', '''') = ''Followups due Today'' and (fs.IsConvert = 0) ', 
						N'and (cast(f.FollowupDate AS DATE) = cast(getdate() AS DATE)) ',  
						N'and (cast(f.AssignedTo as varchar(20)) = ''', @UserId, ''')) THEN 1 ', 
					N'WHEN (isnull(''', @SearchText, ''', '''') = ''My Overdue Followups'' and (fs.IsConvert = 0) ', 
						N'and (cast(f.FollowupDate AS DATE) < cast(getdate() AS DATE)) ', 
						N'and (cast(f.AssignedTo as varchar(20)) = ''', @UserId, ''')) THEN 1 ', 
					N'WHEN (isnull(''', @SearchText, ''', '''') = ''Overdue Followups'' and (fs.IsConvert = 0) ',  
						N'and (cast(f.FollowupDate AS DATE) < cast(getdate() AS DATE))) THEN 1 ', 
					N'WHEN (isnull(''', @SearchText, ''', '''') = ''My upcoming Followups'' ', 
						N'and (cast(f.FollowupDate AS DATE) > cast(getdate() AS DATE)) ', 
						N'and (cast(f.AssignedTo as varchar(20)) = ''', @UserId, ''')) THEN 1 ', 
					N'WHEN (isnull(''', @SearchText, ''', '''') = ''Upcoming Followups'' ', 
						N'and (cast(f.FollowupDate AS DATE) > cast(getdate() AS DATE))) THEN 1 ', 
					N'WHEN (isnull(''', @SearchText, ''', '''') = ''Not followed by me'' ',  
						N'and (cast(f.FollowupDate AS DATE) IS NULL) ', 
						N'and (cast(f.AssignedTo as varchar(20)) = ''', @UserId, ''')) THEN 1 ', 
					N'WHEN (isnull(''', @SearchText, ''', '''') = ''Not followed'' ', 
						N'and (cast(f.FollowupDate AS DATE) IS NULL)) THEN 1 ', 
					N'else 0 end )) ',
				N' t where (1=1) ', @FullText, N' ', @FilterText, N' )' )

		-- Pagination

		SET @query3 = N' SELECT (select count(1) from LeadInteraction) as [TotalRow], * FROM LeadInteraction l  ORDER BY Id DESC OFFSET ' 
			+ CAST(@OffsetValue AS NVARCHAR) + ' ROWS FETCH NEXT  (SELECT CASE 
                WHEN '+cast(@PagingSize as nvarchar)+' > ((select count(1) from LeadInteraction) - '+cast(@offsetvalue as nvarchar)+' ) 
                THEN ((select count(1) from LeadInteraction) - '+cast(@offsetvalue as nvarchar)+') 
                ELSE '+cast(@PagingSize as nvarchar)+' END) ROWS ONLY';

		-- Combine and execute the query
		DECLARE @FinalQuery NVARCHAR(MAX) = @query + @query2 + @query3;

		print @query
		print @query2
		print @query3
		--PRINT @FinalQuery;
	 EXEC sp_executesql @FinalQuery; -- Uncomment to execute



end



GO

/* ============================================================
   Procedure: [dbo].[usp_mob_GetFormMetaData]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 --exec usp_mob_GetFormMetaData 32222,'lead'
CREATE   PROCEDURE [dbo].[usp_mob_GetFormMetaData](    
	 @UserId bigint,    
	 @Mode nvarchar(255) = 'Enquiry'    
)as     
begin    
    
 --declare @UserId bigint = 32222, @Mode nvarchar(255) = 'Lead'

 declare @ParentId bigint = (select ParentID from User_Detail(nolock) where User_ID = @UserId)    

 drop table if exists #tCF

 select * into #tCF from customfields(nolock) where isActive = 1 and ParentID = @ParentId     

   
 if(@Mode = 'Enquiry')    
 begin    
