   Procedure: [dbo].[usp_mob_GetLeadDetailByLeadId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_mob_GetLeadDetailByLeadId]
(                        
 @LeadId bigint,             
 @UserId bigint            
)          
as                                         
begin                  
				
 --DECLARE @LeadId BIGINT= 5987843, @UserId BIGINT= 32222;            
            
 declare @ParentId bigint = 0            
 select @ParentId = ParentID from User_Detail(nolock) where User_ID = @UserId            
            
 SELECT [ul].[LeadNo],             
     ISNULL([ul].[PersonName], '') PersonName,             
     ISNULL([ul].[CompanyName], '') CompanyName,             
     ISNULL([ul].[CountryCode], '') CountryCode,            
     ISNULL([ul].[CountryCode1], '') CountryCode1,            
     ISNULL([ul].[CountryCode2], '') CountryCode2,            
     ISNULL([ul].[MobileNo], '') MobileNo,            
     ISNULL([ul].[MobileNo1], '') MobileNo1,            
     ISNULL([ul].[MobileNo2], '') MobileNo2,            
     ISNULL([ul].[EmailID], '') EmailID,      
     ISNULL([ul].[EmailID1], '') EmailID1,            
     ISNULL([ul].[EmailID2], '') EmailID2,            
     ISNULL([ul].[City], '') City,             
     ISNULL([ul].[State], '') [State],             
     ISNULL([ul].[Country], '') [Country],             
     ISNULL([ul].[PinCode], '') [PinCode],             
     ISNULL([ul].[ResidentialAddress], '') ResidentialAddress,             
     [ud].[FName] + ' ' + [ud].[LName] + ' (' + [ud].[user_login] + ')' AS [AssignedTo],             
     [src].[name] AS [SourceName],             
     ISNULL([md].[name], '') AS [MediumName],             
     ISNULL([cmp].[Name], '') AS [CampaignName],             
     ISNULL([ul].[remarks], '') AS [remark],             
     ISNULL([fs].[FollowupStatus], '') FollowupStatus,             
     CONVERT(VARCHAR(20), [ul].[Createdon], 113) AS [CreatedOn],            
     CASE            
      WHEN [ul].[ModifiedOn] = ''            
      THEN CONVERT(VARCHAR(20), [ul].[CreatedOn], 113)            
      WHEN [ul].[ModifiedOn] IS NULL            
      THEN CONVERT(VARCHAR(20), [ul].[CreatedOn], 113)            
      ELSE CONVERT(VARCHAR(20), [ul].[ModifiedOn], 113)            
     END AS [modifiedon],                         
     --CONVERT(VARCHAR(20), [ul].[followupdate], 20) AS [followupdate],                         
     dbo.fn_getusertimefromindiantime(@UserId, [ul].[followupdate]) AS [followupdate],             
  case when [ul].[ProfileImgFileName] is null then 'https://docs.kit19.com/default/person.png'  
  Else 'https://docs.kit19.com/'+ cast([ul].[ParentId] as varchar(20)) + '/Lead/' + [ul].[ProfileImgFileName] end ProfileImgFileName,            
     [ud1].[FName] + ' ' + [ud1].[LName] + ' (' + [ud1].[user_login] + ')' AS [CreatedBy],             
     [ud2].[FName] + ' ' + [ud2].[LName] + ' (' + [ud2].[user_login] + ')' AS [ModifiedBy],             
     ISNULL([ul].[officeaddress], '') officeaddress,             
     ISNULL([ul].[countrycode], '') countrycode,             
     [ul].[AssignedTo] AS [assign_id],             
     [ul].[SourceName] AS [source_id],             
     [ul].[MediumName] AS [medium_id],             
     [ul].[CampaignName] AS [camp_id],             
     [ul].[FollowUpStatus] AS [follow_status_id],             
     [ul].[Products],             
     [ul].[AmountPaid],  
  [ul].LastFollowupCreatedOn,  
     ISNULL([ul].[img_ext], '.abc') AS [img_ext],             
     InitialRemarks = ISNULL([UL].InitialRemarks, ''),             
     ISNULL(ul.WhereAddress, '') WhereAddress,             
     ul.Latitude,             
     ul.Longitude,             
     ( SELECT STRING_AGG(tm.Tag, ',') FROM EntityTagMapping(NOLOCK) etm            
        INNER JOIN TagMaster(NOLOCK) tm ON etm.TagID = tm.Id WHERE Entity = 'lead' AND EntityID = ul.ID            
     ) AS TagNames,  
  Isnull(MC.Country_ID, 0) CountryId,  
  Isnull(MS.State_ID, 0) StateId,  
  Isnull(MCi.City_ID, 0) CityId  
 FROM userleads ul(NOLOCK)            
   LEFT JOIN user_detail(NOLOCK) ud ON ul.assignedto = ud.user_id            
   LEFT JOIN usersourcesettings(NOLOCK) src ON ul.sourcename = src.sourceid            
   LEFT JOIN usermediumsettings(NOLOCK) md ON ul.mediumname = md.mediumid            
   LEFT JOIN UserCampaignSettings(NOLOCK) cmp ON ul.campaignname = cmp.CampaignID            
   LEFT JOIN followup_status(NOLOCK) fs ON ul.followupstatus = fs.id            
   LEFT JOIN user_detail(NOLOCK) ud1 ON ul.createdby = ud1.user_id            
   LEFT JOIN user_detail(NOLOCK) ud2 ON ul.modifiedby = ud2.user_id            
   Left Join M_Country1(nolock) MC ON ul.Country = MC.Country_Name  
   Left Join M_State1(nolock) MS ON ul.State = MS.State_Name  
   Left Join M_City1(nolock) MCi ON ul.City = MCi.City_Name   
 WHERE [ul].[ParentID]  =@ParentId and [ul].[id] = @LeadId;   
            
select * from (        
 select *, ROW_NUMBER() OVER(Partition by field_ID ORDER BY field_ID) AS Row_Number from (           
 select field_ID, fieldname, isnull(fieldvalue, '') fieldvalue from ( select field_ID, fieldname            
   from customfields(nolock) where ParentID = @ParentId and isActive = 1            
  )  cf left join ( select fieldID, fieldvalue from customfieldLeadvalue(nolock) where LeadID = @LeadId )            
  ce on cf.field_ID = ce.fieldID            
  )t        
   )tt Where Row_Number = 1        
        
 select e.ID LeadPipeLineStatusId, e.LeadId, P.ID as PipelineID, P.Name PipeLineName, e.PipeLineStage, s.Name PipeLineStageName, e.Probability,       
 e.Amount, ud.FName + ' ' + ud.LName FullName, UL.ProfileImgFileName, e.CreatedDate, e.CreatedBy, [ud].[FName] + ' ' + [ud].[LName] + ' (' + [ud].[user_login] + ')' AS CreatedByName, e.Remarks, e.EstimatedClosureDate, (ud2.FName + ' ' + ud2.LName) as DealOwnerName from Pipeline_Master(nolock) P                   
    join PipelineStages(nolock) S on P.id=S.PipelineID           
    join LeadPipelineMapping(nolock) e on e.PipeLineStage=S.ID             
    join mysms.dbo.User_Detail(nolock) ud on e.CreatedBy=ud.User_ID          
 join UserLeads(nolock) UL on e.LeadID = UL.ID          
inner join User_Detail(nolock) ud2 on e.DealOwner = ud2.User_ID  
    where e.isdeleted=0 and e.LeadID = @LeadId and             
   e.id in (select isnull(id,0) from LeadPipelineMapping(nolock) where LeadID=e.LeadID and PipeLineStage=e.PipeLineStage)        
     
 Declare @PageCode varchar(20)  = 'PAG10031'--'PAG10002'--  
 Declare @RoleCode varchar(20)  
 set @RoleCode = (select RoleCode from ufn_GetUserRoleScope(@UserId))  
  
  select distinct phs.PageFieldId,     
 Case when pagfi.TableName != '' then pagfi.TableName    
else 'Custom'    
End TableName, urm.UserId, pagfi.FieldName, phs.HiddenType, phs.IsExportAllow      
 from tbl_UA_PageHiddenFields(nolock) paghf    
inner join TBL_UA_UserRoleMappingMaster(nolock) urm on paghf.RoleCode = urm.RoleCode    
inner join tbl_UA_PageHiddenFieldsSettings(nolock) phs on paghf.PageHiddenFieldsId = phs.PageHiddenFieldsId    
inner join tbl_UA_PageFields(nolock) pagfi on phs.PageFieldId = pagfi.PageFieldId      
where urm.UserId = @UserId and paghf.ParentId = @ParentId   
and paghf.PageCode = @PageCode and paghf.RoleCode = @RoleCode  
  
-- select distinct phs.PageFieldId,     
-- Case when pagfi.TableName != '' then pagfi.TableName    
--else 'Custom'    
--End TableName, urm.UserId, pagfi.FieldName, phs.HiddenType, phs.IsExportAllow, paghf.PageCode, paghf.RoleCode from    
--tbl_UA_PageHiddenFields paghf    
--inner join TBL_UA_UserRoleMappingMaster urm on paghf.RoleCode = urm.RoleCode   
--inner join tbl_UA_PageFields pagfi on paghf.PageCode = pagfi.PageCode   
--inner join tbl_UA_PageHiddenFieldsSettings phs on pagfi.PageFieldId = phs.PageFieldId   
--where urm.UserId = @UserId and   
--paghf.PageCode = @PageCode   
-- and   
--paghf.RoleCode = @RoleCode   
  
end   


GO

/* ============================================================
   Procedure: [dbo].[usp_mob_GetLeadDetailsSearch]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--usp_mob_GetLeadDetailsSearch 32222, 0, 0, '' ,'default'
CREATE   PROCEDURE [dbo].[usp_mob_GetLeadDetailsSearch](    
 @UserId bigint,     
 @CustomSearchId bigint = 0,    
 @PredefindSearchId bigint = 0, 
 @FilterText nvarchar(255) = '',
 @SearchFieldType nvarchar(20) = 'default'
)    
as    
begin    
  
 --declare @UserId bigint = 33819,    
 --@CustomSearchId nvarchar(50) = '0',    
 --@PredefindSearchId nvarchar(50) = '0',    
 --@FilterText nvarchar(255) = '',    
 --@OffsetValue int  = 0,    
 --@PageSize int  = 5    
    
    
 --if(@pageSize < 100)      
 --begin     
 --if(@UserId != 32222)  
 -- set @pageSize = 100      
 --end      
    
 declare @ParentId bigint, @fieldName nvarchar(max), @TimeZoneName nvarchar(255);    
    
 declare @UserIdTeamLst varchar(Max) = ''     
 declare @tbluser table (User_ID bigint,Name varchar(100), Image varchar(100))    
 declare @IsAdmin bit = 0         
     
 select  @IsAdmin = isnull(IsAdmin,0),     
   @ParentId = ParentID,     
   @TimeZoneName = isnull(TimeZone, 'india standard time')    
  from Mysms.dbo.User_Detail(nolock) where User_ID = @UserId     
     
  declare @maxScore numeric(18,2)=isnull((select (max(currentscore)*100)/99 from lead_score_history(nolock)e where parentid=@ParentID),0)                  
 declare @hot int,@warm int,@cold int                  
                  
 select @hot=hot,@warm=warm,@cold=cold from lead_cateogy_thresholds(nolock) where parentid=@ParentID                        
 if @hot is null                        
 begin                        
 select @hot=hot,@warm=warm,@cold=cold from lead_cateogy_thresholds(nolock) where parentid=0                        
 end                        
          
    
 set @fieldName = (select STRING_AGG(concat('[c.', fieldname, ']'), ',') from (    
   select distinct fieldname from customfields(nolock) where ParentID = @ParentId) f)    
 declare @fixedColumn nvarchar(max)
 if(@SearchFieldType = 'setting')
 Begin
 set @fixedColumn = ' ID, LeadNo, PersonName, CompanyName, MobileNo, MobileNo1 ,MobileNo2, EmailID, EmailID1 ,EmailID2, City, State, Country, CountryCode, CountryCode1, CountryCode2, PinCode, ResidentialAddress, OfficeAddress, AssignedTo, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, FollowUpStatus, NextStatusDate, Remarks, Products, AmountPaid, CreatedOn, CreatedBy, ModifiedOn, ModifiedBy, FollowupDate, LeadImage, temp_id, img_ext, ProfileImgFileName as Image, enquirysource, WhatsAppNoColName, LastFollowupCreatedBy, whereAddress, latitude, longitude, LastFollowupCreatedOn  '    
End
Else
Begin
 set @fixedColumn = ' ID, LeadNo, PersonName, CompanyName, MobileNo, MobileNo1 ,MobileNo2, EmailID, EmailID1 ,EmailID2, City, State, Country, CountryCode, CountryCode1, CountryCode2, PinCode, ResidentialAddress, OfficeAddress, AssignedTo, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, FollowUpStatus, NextStatusDate, Remarks, Products, AmountPaid, CreatedOn, CreatedBy, ModifiedOn, ModifiedBy, FollowupDate, LeadImage, temp_id, img_ext, ProfileImgFileName as Image, enquirysource, WhatsAppNoColName, LastFollowupCreatedBy, whereAddress, latitude, longitude, LastFollowupCreatedOn '    
End

 -- ',AgentId,AgentFName,AgentLName,AgentImage,AgentLogin'    
    
 declare @DefaultSearch nvarchar(255), @PrimarySort nvarchar(255), @SecondarySort nvarchar(255),    
  @DisplayField nvarchar(max), @OrderBy nvarchar(10), @SearchField nvarchar(max)    
    
 select top 1 @DefaultSearch = default_search, @PrimarySort = primary_sort, @SecondarySort = secondary_sort,    
  @DisplayField = display_fields, @OrderBy = order_by, @SearchField = search_fields from tbl_mob_LeadEnquirySetting(nolock)    
 where (user_id = @UserId or user_id = 0) and entity_type = 'ul' order by id desc    
    
 declare @orderByQuery nvarchar(max)  = ' order by Id desc '    
 if(isnull(@PrimarySort, '') <> '' and isnull(@SecondarySort, '') <> '')    
 begin    
  set @orderByQuery = concat( ' order by ', @PrimarySort, ',', @SecondarySort, ' ', isnull(@OrderBy, 'asc') )    
 end    
    
 drop table if exists #customSearch    
 create table #customSearch(    
  EntityId bigint    
 )    
    
 --custome search    
 if(isnull(@CustomSearchId, 0) > 0)    
 begin    
  print 'cust'    
  declare @procedure nvarchar(255) = concat('''Exec mysms.dbo.usp_ExecuteUserSearchwithid ',      
    cast(@ParentId as nvarchar), ', ', cast(@CustomSearchId as nvarchar),  ', null''')      
     
  declare @customLeadSql nvarchar(max) = N'';    
     
  set @customLeadSql = concat(N'insert into #customSearch(EntityId) select dl.EntityId from OPENROWSET (''SQLNCLI'', ''Server=aznetpocdbs01; Database=mysms;Uid=kit19;PWD=P@ssword3110;'', ', @procedure, N') dl inner join mysms.dbo.UserLeads(nolock) ue on dl.EntityID = ue.ID')      
    
  if(len(@customLeadSql) > 0)      
  begin      
   exec sp_executesql  @customLeadSql      
  end      
 end    
    
 declare @filterTextSql nvarchar(max) = ''    
    
 if((isnull(@FilterText, '') <> '') and (@SearchFieldType = 'setting'))    
 begin    
  set @filterTextSql = (select STRING_AGG(concat([value], ' like ''%', @FilterText, '%'''), ' or ') from fn_Split( @SearchField, ','))    
 end    
 if((isnull(@FilterText, '') <> '') and (@SearchFieldType = 'default'))    
 begin    
  set @filterTextSql = '( PersonName like ''%' + @FilterText + '%'' or cast(LeadNo as varchar(20)) = ''' + @FilterText + ''' or 
  trim(concat(trim(isnull(ul.CountryCode, '''')), '' '', trim(isnull(ul.MobileNo, '''')))) + '' '' + trim(concat(trim(isnull(ul.CountryCode1, '''')), '' '', trim(isnull(ul.MobileNo1, '''')))) + '' '' + trim(concat(trim(isnull(ul.CountryCode2, '''')), '' '', trim(isnull(ul.MobileNo2, '''')))) like ''%' + @FilterText + '%'' or (isnull(ul.EmailID, '''') + '' '' + isnull(ul.EmailID1, '''') + '' '' + isnull(ul.EmailID2, '''')) like ''%' + @FilterText + '%'' )' 
 end 
    
 declare @enquiryColumns nvarchar(max) = N'ul.ID,ul.PersonName,ul.CompanyName,trim(concat(trim(isnull(ul.CountryCode, '''')), '' '', trim(isnull(ul.MobileNo, '''')))) as MobileNo,trim(concat(trim(isnull(ul.CountryCode1, '''')), '' '', trim(isnull(ul.MobileNo1, '''')))) as MobileNo1,trim(concat(trim(isnull(ul.CountryCode2, '''')), '' '', trim(isnull(ul.MobileNo2, '''')))) as MobileNo2,ul.EmailID,ul.EmailID1,ul.EmailID2,ul.City,ul.State,ul.Country,ul.PinCode,ul.ResidentialAddress,ul.OfficeAddress, us.Name as [SourceName],md.Name as [MediumName],cm.Name as [CampaignName],ul.InitialRemarks,ul.ParentID,dbo.fn_ConvertDateTime(cast(ul.CreatedOn as datetime), '''+ @TimeZoneName +N''', 0) as CreatedDate,ul.CreatedBy,ul.LeadNo,ul.ProfileImgFileName,ul.whereAddress, ul.latitude,ul.longitude,ul.Remarks,( case when fs.IsConvert = 1 then ''Converted'' when fs.IsCallback = 1 and cast(ul.FollowupDate as date)  = cast(getdate() as date) then ''Due Today'' when fs.IsCallback = 1 and cast(ul.FollowupDate as date)  < cast(getdate() as date) then ''Over Due'' when fs.IsCallback = 1 and cast(ul.FollowupDate as date)  > cast(getdate() as date) then ''Scheduled'' when fs.IsConvert = 0 and fs.IsCallback = 0 then ''No Followup'' end ) as [HtmlStatus], dbo.fn_ConvertDateTime(CAST(ul.FollowupDate AS DATETIME), '''+ @TimeZoneName +N''', 0) AS FollowupDate,ag.User_ID as AgentId,ag.FName as AgentFName,ag.LName as AgentLName,ag.Image as AgentImage,ag.User_Login as AgentLogin, Profit_Loss=case when LS.ScoreAdded > 0 then ''Green_Up'' when LS.ScoreAdded < 0 then ''Red_Down'' else '''' end, CurrentScore=cast(isnull((LS.currentscore/nullif(' + cast(@maxScore as nvarchar(max)) + ',0.00))*99,0) as int) , ThresholdColor=case when cast(isnull((LS.currentscore/nullif('+ cast(@maxScore as nvarchar(max)) + ',0.00))*99,0) as int)>' + cast(@warm as nvarchar(max)) + ' then ''Hot'' when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore as nvarchar(max))+',0.00))*99,0) as int) between ' + cast(@cold as nvarchar(max)) + ' and ' + cast(@warm as nvarchar(max)) + ' then ''Warm'' else ''Cold'' end '; 

 declare @cvQuery nvarchar(max)

 if(@SearchFieldType = 'setting')    
 begin    
 set @cvQuery = N'SELECT  '+ @fixedColumn +     
 iif(isnull(@DisplayField, '') <> '', concat(',',@DisplayField), '') + N' FROM (    
    SELECT top 1 '+ @enquiryColumns +  iif(isnull(@fieldName, '') <> '', concat(',',@fieldName), '') + N' FROM UserLeads(NOLOCK) ul '    
 + iif(isnull(@fieldName, '') <> '',    
 concat(N' LEFT JOIN ( SELECT  top 1 * FROM ( SELECT top 1 cfv.LeadID, cf.fieldname, cfv.fieldvalue FROM customfields(NOLOCK) cf INNER JOIN customfieldLeadvalue(NOLOCK) cfv ON cf.field_ID = cfv.fieldID WHERE cf.ParentID = ' + cast(@ParentId as nvarchar) + ') ipc PIVOT(MAX(fieldvalue) FOR fieldname IN( ' + @fieldName + N' )) p ) c ON ul.ID = c.LeadID ', ''), '')  + N' LEFT JOIN lead_score_history_latest(NOLOCK) LS ON UL.ID = LS.LeadId left join UserSourceSettings(nolock) us on ul.SourceName = us.SourceID left join UserMediumSettings(nolock) md on ul.MediumName = md.MediumID left join UserCampaignSettings(nolock) cm on ul.CampaignName = cm.CampaignID left join User_Detail(nolock) ag on ul.AssignedTo = ag.User_ID LEFT JOIN FollowUp_Status(NOLOCK) fs on ul.FollowUpStatus = fs.ID '+ iif(exists(select 1 from #customSearch), ' inner join  #customSearch(nolock) cs on ul.Id = cs.EntityId', '') +' WHERE ul.ParentID = ' + cast(@ParentId as nvarchar) + ' and ul.CreatedBy in ( '+ @UserIdTeamLst +N' ) ) e ' +  
  iif(isnull(@filterTextSql, '') <> '', concat(' where ', @filterTextSql), '') +  N' ' + @orderByQuery + N' '    
End
Else
Begin
 set @cvQuery  = N'Select top 1 '+ @fixedColumn +  iif(isnull(@DisplayField, '') <> '', concat(',',@DisplayField), '') + N' from UserLeads ul WHERE ul.ParentID = ' + cast(@ParentId as nvarchar) + ' ' + iif(isnull(@filterTextSql, '') <> '', concat(' and  ', @filterTextSql), '') +  N''
End 
 print @cvQuery    

 execute sp_executesql @cvQuery    
end  



GO

/* ============================================================
   Procedure: [dbo].[usp_mob_GetLeadList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_mob_GetLeadList](      
 @UserId bigint,       
 @CustomSearchId nvarchar(50) = '0',      
 @PredefindSearchId nvarchar(50) = '0',      
 @FilterText nvarchar(255) = '',      
 @OffsetValue int  = 0,      
 @PageSize int  = 100      
)      
as      
begin      
-- @CustomSearchId bigint = 0,      
-- @PredefindSearchId bigint = 0,      
    
 --declare @UserId bigint = 33819,      
 --@CustomSearchId nvarchar(50) = '0',      
 --@PredefindSearchId nvarchar(50) = '0',      
 --@FilterText nvarchar(255) = '',      
 --@OffsetValue int  = 0,      
 --@PageSize int  = 5      
      
      
 --if(@pageSize < 100)        
 --begin       
 --if(@UserId != 32222)    
 -- set @pageSize = 100        
 --end        
      
 declare @ParentId bigint, @fieldName nvarchar(max), @TimeZoneName nvarchar(255);      
      
 declare @UserIdTeamLst varchar(Max) = ''       
 declare @tbluser table (User_ID bigint,Name varchar(100), Image varchar(100))      
 declare @IsAdmin bit = 0           
       
 select  @IsAdmin = isnull(IsAdmin,0),       
   @ParentId = ParentID,       
   @TimeZoneName = isnull(TimeZone, 'india standard time')      
  from User_Detail(nolock) where User_ID = @UserId       
       
  declare @maxScore numeric(18,2)=isnull((select (max(currentscore)*100)/99 from lead_score_history(nolock)e where parentid=@ParentID),0)                    
 declare @hot int,@warm int,@cold int                    
                    
 select @hot=hot,@warm=warm,@cold=cold from lead_cateogy_thresholds(nolock) where parentid=@ParentID                          
 if @hot is null                          
 begin                          
 select @hot=hot,@warm=warm,@cold=cold from lead_cateogy_thresholds(nolock) where parentid=0                          
 end                          
            
      
 if((@IsAdmin = 1) or (@ParentId = @UserId))      
 Begin      
  set @UserId = 0      
  insert into @tbluser      
  exec Use_GetUserDetails  @ParentId      
 end       
 else      
 Begin      
  insert into @tbluser      
  exec Use_GetUserDetails @UserID      
 End      
 
 select @UserIdTeamLst=isnull(STRING_AGG(User_ID,','),'') From @tbluser      
       
 set @fieldName = (select STRING_AGG(concat('[c.', fieldname, ']'), ',') from (      
 select distinct fieldname from customfields(nolock) where ParentID = @ParentId) f)      
 set @fieldName = ''

 declare @fixedColumn nvarchar(max) = 'count(*) over() as TotalRecords,Id,PersonName, ProfileImgFileName as Image,LeadNo, ParentId,isnull(Latitude,'''')Latitude,isnull(Longitude,'''')Longitude,CreatedDate,concat(MobileNo, iif(MobileNo1 <> '''', concat('', 
'', MobileNo1), ''''), iif(MobileNo2 <> '''', concat('', '', MobileNo2), '''')) as CsvMobileNo,concat(EmailId, iif(EmailId1 <> '''', concat('', '', EmailId1), ''''), iif(EmailId2 <> '''', concat('', '', EmailId2), '''')) as CsvEmailId,isnull(FollowupDate,
'''')FollowupDate,HtmlStatus,Profit_Loss as ProfitLoss,CurrentScore, ThresholdColor,AgentLogin,isnull(Remarks,'''') Remarks'      
      
 -- ',AgentId,AgentFName,AgentLName,AgentImage,AgentLogin'      
      
 declare @DefaultSearch nvarchar(255), @PrimarySort nvarchar(255), @SecondarySort nvarchar(255),      
  @DisplayField nvarchar(max), @OrderBy nvarchar(10), @SearchField nvarchar(max)      
      
 select top 1 @DefaultSearch = default_search, @PrimarySort = primary_sort, @SecondarySort = secondary_sort,      
  @DisplayField = display_fields, @OrderBy = order_by, @SearchField = search_fields from tbl_mob_LeadEnquirySetting(nolock)      
 where (user_id = @UserId or user_id = 0) and entity_type = 'ul' order by id desc      
      
 declare @orderByQuery nvarchar(max)  = ' order by Id desc '      
 if(isnull(@PrimarySort, '') <> '' and isnull(@SecondarySort, '') <> '')      
 begin      
  set @orderByQuery = concat( ' order by ', @PrimarySort, ',', @SecondarySort, ' ', isnull(@OrderBy, 'asc') )      
 end      
      
 drop table if exists #customSearch      
 create table #customSearch(      
  EntityId bigint      
 )      
      
 --custome search      
 if(isnull(@CustomSearchId, 0) > 0)      
 begin      
  print 'cust'      
  declare @procedure nvarchar(255) = concat('''Exec mysms.dbo.usp_ExecuteUserSearchwithid ',        
    cast(@ParentId as nvarchar), ', ', cast(@CustomSearchId as nvarchar),  ', null''')        
       
  declare @customLeadSql nvarchar(max) = N'';      
       
  set @customLeadSql = concat(N'insert into #customSearch(EntityId) select dl.EntityID from OPENROWSET (''SQLNCLI'', ''Server=aznetpocdbs01; Database=mysms;Uid=kit19;PWD=P@ssword3110;'', ', @procedure, N') dl inner join mysms.dbo.UserLeads(nolock) ue on dl.EntityID = ue.ID')        
      
  if(len(@customLeadSql) > 0)        
  begin        
   exec sp_executesql  @customLeadSql        
  end        
 end      
      
 declare @filterTextSql nvarchar(max) = ''      
      
 if((isnull(@FilterText, '') <> '') and (@CustomSearchId != '0'))      
 begin      
  set @filterTextSql = (select STRING_AGG(concat([value], ' like ''%', @FilterText, '%'''), ' or ') from fn_Split( @SearchField, ','))      
 end      
  if((isnull(@filterTextSql, '') = '') and (isnull(@FilterText, '') <> ''))     
 begin      
  set @filterTextSql = ' PersonName like ''%' + @FilterText +'%''';
 end

 declare @enquiryColumns varchar(max) = N'ul.ID,ul.PersonName,ul.CompanyName,trim(concat(trim(isnull(ul.CountryCode, '''')), '' '', trim(isnull(ul.MobileNo, '''')))) as MobileNo,trim(concat(trim(isnull(ul.CountryCode1, '''')), '' '', trim(isnull(ul.MobileNo1, '''')))) as MobileNo1,trim(concat(trim(isnull(ul.CountryCode2, '''')), '' '', trim(isnull(ul.MobileNo2, '''')))) as MobileNo2,ul.EmailID,ul.EmailID1,ul.EmailID2,ul.City,ul.State,ul.Country,ul.PinCode,ul.ResidentialAddress,ul.OfficeAddress, us.Name as [SourceName],md.Name as [MediumName],cm.Name as [CampaignName],isnull(ul.InitialRemarks,'''') InitialRemarks,ul.ParentID,dbo.fn_ConvertDateTime(cast(ul.CreatedOn as datetime), '''+ @TimeZoneName +N''', 0) as CreatedDate,ul.CreatedBy,ul.LeadNo,ul.ProfileImgFileName,ul.whereAddress, isnull(ul.latitude,'''')latitude,isnull(ul.longitude,'''')longitude,isnull(ul.Remarks,'''')Remarks,( case when fs.IsConvert = 1 then ''Converted'' when fs.IsCallback = 1 and cast(ul.FollowupDate as date)  = cast(getdate() as date) then ''Due Today'' when fs.IsCallback = 1 and cast(ul.FollowupDate as date)  < cast(getdate() as date) then ''Over Due'' when fs.IsCallback = 1 and cast(ul.FollowupDate as date)  > cast(getdate() as date) then ''Scheduled'' when fs.IsConvert = 0 and fs.IsCallback = 0 then ''No Followup'' end ) as [HtmlStatus], isnull(dbo.fn_ConvertDateTime(CAST(ul.FollowupDate AS DATETIME), '''+ @TimeZoneName +N''', 0),'''') AS FollowupDate,ag.User_ID as AgentId,ag.FName as AgentFName,ag.LName as AgentLName,ag.Image as AgentImage,ag.User_Login as AgentLogin, Profit_Loss=case when LS.ScoreAdded > 0 then ''Green_Up'' when LS.ScoreAdded  < 0 then ''Red_Down'' else '''' end, CurrentScore=cast(isnull((LS.currentscore/nullif(' + cast(@maxScore as varchar(max)) + ',0.00))*99,0) as int) , ThresholdColor=case when cast(isnull((LS.currentscore/nullif('+ cast(@maxScore as varchar(max)) + ',0.00))*99,0) as int)>' + cast(@warm as varchar(max)) + ' then ''Hot'' when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore as varchar(max))+',0.00))*99,0) as int) between ' + cast(@cold as varchar(max)) + ' and ' + cast(@warm as varchar(max)) + ' then ''Warm'' else ''Cold'' end ';      
      
 declare @FFieldName nvarchar(max) = iif(isnull(@fieldName, '') <> '', concat(',',@fieldName), '')
      
 declare @cvQuery nvarchar(max) = N'SELECT '+ @fixedColumn +       
 iif(isnull(@DisplayField, '') <> '', concat(',',@DisplayField), '') + N' FROM (      
    SELECT '+ @enquiryColumns +  @FFieldName + N' FROM UserLeads(NOLOCK) ul '      
 + iif(isnull(@fieldName, '') <> '', concat(N' LEFT JOIN ( SELECT * FROM ( SELECT cfv.LeadID, cf.fieldname, cfv.fieldvalue FROM customfields(NOLOCK) cf INNER JOIN customfieldLeadvalue(NOLOCK) cfv ON cf.field_ID = cfv.fieldID WHERE cf.ParentID = ' + cast(@ParentId as varchar) + ') ipc PIVOT(MAX(fieldvalue) FOR fieldname IN( ' + @fieldName + N' )) p ) c ON ul.ID = c.LeadID ', ''), '')  + N' LEFT JOIN lead_score_history_latest(NOLOCK) LS ON UL.ID = LS.LeadId left join UserSourceSettings(nolock) us on ul.SourceName = us.SourceID left join UserMediumSettings(nolock) md on ul.MediumName = md.MediumID left join UserCampaignSettings(nolock) cm on ul.CampaignName = cm.CampaignID left join User_Detail(nolock) ag on ul.AssignedTo = ag.User_ID LEFT JOIN FollowUp_Status(NOLOCK) fs on ul.FollowUpStatus = fs.ID '+ iif(exists(select 1 from #customSearch), ' inner join  #customSearch(nolock) cs on ul.Id = cs.EntityId', '') +' WHERE ul.ParentID = ' + cast(@ParentId as varchar) + ' and ul.AssignedTo in ('+ case when @UserIdTeamLst = '' then cast(@UserId as varchar) else @UserIdTeamLst end +N') ) e ' +       
  iif(isnull(@filterTextSql, '') <> '', concat(' where ', @filterTextSql), '') +  N' ' + @orderByQuery        
 + N' offset '+ cast(@OffsetValue as varchar) +' rows fetch next '+ cast(@PageSize as varchar) +' rows only'      
      
 print @cvQuery      
      
 execute sp_executesql @cvQuery
      
end    



GO

