  insert into @tbluser          
  exec Use_GetUserDetails  @ParentId          
 end           
 else          
 begin          
  insert into @tbluser          
  exec Use_GetUserDetails @UserID          
 end          
     
 select @UserIdTeamLst = isnull(STRING_AGG(User_ID,','),'') From @tbluser     
 --  select @UserIdTeamLst = dbo.udf_fn_GetUserDetails(@Userid)  
   
       --c.    
 set @fieldName = (select STRING_AGG(concat('[', fieldname, ']'), ',') from (          
 select distinct fieldname from customfields(nolock) where IsActive = 1 and ParentID = @ParentId) f)          
 --set @fieldName = ''    
  
print concat('@UserIdTeamLst => ', @UserIdTeamLst)  
    
 declare @fixedColumn nvarchar(max) = ' count(*) over() as TotalRecords,Id,PersonName, ProfileImgFileName as Image,LeadNo, ParentId,isnull(Latitude,'''')Latitude,isnull(Longitude,'''')Longitude,CreatedOn,concat(MobileNo, iif(MobileNo1 <> '''', concat('','', MobileNo1), ''''), iif(MobileNo2 <> '''', concat('', '', MobileNo2), '''')) as CsvMobileNo,concat(EmailId, iif(EmailId1 <> '''', concat('', '', EmailId1), ''''), iif(EmailId2 <> '''', concat('', '', EmailId2), '''')) as CsvEmailId,isnull(FollowupDate,'''')FollowupDate,isnull(FollowupDate,'''')LastFollowupCreatedOn,HtmlStatus,HtmlStatus1,Profit_Loss as ProfitLoss,CurrentScore, ThresholdColor,AgentLogin,isnull(Remarks,'''') Remarks'          
          
 -- ',AgentId,AgentFName,AgentLName,AgentImage,AgentLogin'          
          
 declare @DefaultSearch nvarchar(255), @PrimarySort nvarchar(255), @SecondarySort nvarchar(255),          
  @DisplayField nvarchar(max), @OrderBy nvarchar(10), @SearchField nvarchar(max)          
          
 select top 1 @DefaultSearch = default_search, @PrimarySort = primary_sort, @SecondarySort = secondary_sort,          
  @DisplayField = display_fields, @OrderBy = order_by, @SearchField = search_fields from tbl_mob_LeadEnquirySetting(nolock)          
 where (user_id = @UserId or user_id = 0) and entity_type = 'ul' order by id desc          
   
 /*  
 declare @orderByQuery nvarchar(max)  = ' order by case when cast(followupdate as date) = cast(getdate() as date) then 0    
     when followupdate < getdate()  then 1          
     when followupdate > getdate() then 2          
     when followupdate is null then 3          
      end,followupdate , Id desc '    
   */  
     
--declare @orderByQuery nvarchar(max)  = ' order by CurrentScore desc, cast(CreatedOn as datetime) DESC  '    
declare @orderByQuery nvarchar(max)  = ' order by cast(CreatedOn as datetime) DESC  '    
     
  
 declare @orderStrQuery nvarchar(max)  = ''          
 if(isnull(@Ordstr, '') <> '')    
 Begin    
 set @orderByQuery = concat( ' order by ', @Ordstr, ' ', iif(isnull(@OrderBy, '') <> '', @OrderBy, 'asc'))    
 End    
 Else    
 Begin    
  if(isnull(@PrimarySort, '') <> '' and isnull(@SecondarySort, '') <> '')          
  begin          
   set @orderByQuery = concat( ' order by ', @PrimarySort, ',', @SecondarySort, ' ', isnull(@OrderBy, 'asc') )          
   end          
 end          
          
 drop table if exists #customSearch          
 create table #customSearch(          
  EntityId bigint,  
  TotalRow int,  
 )          
          
 --custome search          
 if(isnull(@CustomSearchId, 0) > 0)          
 begin          
  print 'cust'         
    
  --declare @procedure nvarchar(max) = concat('''Exec mysms.dbo.usp_ExecuteUserSearchwithid ',            
  --  cast(@ParentId as nvarchar), ', ', cast(@CustomSearchId as nvarchar),  ', null''')            
  
  print concat('@orderByQuery => ', @orderByQuery)  
  
  declare @spid int = @@spid  
  delete from tbl_mobileAppLeadBySPID where SpId = @spid  
  
  exec usp_ExecuteUserSearchwithid_WithPaginationMobileAppNew   
  @ParentId,  
  @UserId,  
  @CustomSearchId,  
  null,  
  @OffsetValue,  
  @PageSize  
   
 insert into #customSearch(EntityId, TotalRow)   
 select LeadId, TotalRow from tbl_mobileAppLeadBySPID(nolock) where SpId = @spid  
         
 -- declare @customLeadSql nvarchar(max) = N'';       
    
 -- print @procedure  
           
 -- set @customLeadSql = concat(N'insert into #customSearch(EntityId, TotalRow) select dl.EntityID, dl.TotalRow from OPENROWSET (''SQLNCLI'', ''Server=aznetpocdbs01; Database=mysms;Uid=kit19;PWD=P@ssword3110;'', ', @procedure, N' WITH RESULT SETS ( ( EntityName nvarchar(50), EntityID bigint, personname VARCHAR(200), companyname VARCHAR(200), mobileno VARCHAR(100), mobileno1 VARCHAR(100), mobileno2 VARCHAR(100), emailid VARCHAR(100), emailid1 VARCHAR(100), emailid2 VARCHAR(100),  country VARCHAR(100), STATE VARCHAR(100), city VARCHAR(100), pincode VARCHAR(50), residentialaddress VARCHAR(500), officeaddress VARCHAR(500), sourcename VARCHAR(200) COLLATE sql_latin1_general_cp1_ci_as, mediumname VARCHAR(200) COLLATE sql_latin1_general_cp1_ci_as, campaignname VARCHAR(200) COLLATE sql_latin1_general_cp1_ci_as, initialremarks VARCHAR(1000) collate SQL_Latin1_General_CP1_CI_AS, SearchID bigint, ParentID bigint, CampaignID bigint, TotalRow int ) )'' ) dl inner join mysms.dbo.UserLeads(nolock) ue on dl.EntityID = ue.ID', '')            
     
 --print @customLeadSql  
     
 -- if(len(@customLeadSql) > 0)            
 -- begin            
 --  exec sp_executesql  @customLeadSql            
 -- end            
 end  
          
 declare @filterTextSql nvarchar(max) = ''          
 declare @filterStrSql nvarchar(max) = ''          
          
 if((isnull(@FilterText, '') <> '') and (@CustomSearchId != '0'))          
 begin          
  set @filterTextSql = (select STRING_AGG(concat([value], ' like ''%', @FilterText, '%'''), ' or ') from fn_Split( @SearchField, ','))          
 end     
     
 if(isnull(@FilterExp, '') <> '')          
 begin   
  set @FilterExp = REPLACE(@FilterExp,'[MobileNo]','[CsvMobileNo]' )   
  set @FilterExp = REPLACE(@FilterExp,'[EmailID]','[CsvEmailId]' )   
  set @filterStrSql = concat(' and ', @FilterExp)    
 end     
    
 if((isnull(@filterTextSql, '') = '') and (isnull(@FilterText, '') <> ''))         
 begin          
  set @filterTextSql = ' and ( LeadNo like ''%' + @FilterText +'%'' or PersonName like ''%' + @FilterText +'%'' or CsvMobileNo like ''%' + @FilterText +'%'' or CsvEmailId like ''%' + @FilterText +'%'')';    
 end    
 else    
 begin          
  set @filterTextSql = ' ';    
 end    
     
--select top 100 * from FollowUp_Status(nolock)    
-- ( case when fs.IsConvert = 1 then ''Converted'' when fs.IsCallback = 1 and cast(ul.FollowupDate as date)  = cast(getdate() as date) then ''Due Today'' when fs.IsCallback = 1 and cast(ul.FollowupDate as date)  < cast(getdate() as date) then ''Over Due'' when fs.IsCallback = 1 and cast(ul.FollowupDate as date)  > cast(getdate() as date) then ''Scheduled'' when fs.IsConvert = 0 and fs.IsCallback = 0 then ''No Followup'' end )    
    
 declare @enquiryColumns varchar(max) = N'ul.Id,ul.PersonName, ul.CompanyName,isnull(ProfileImgFileName,'''') Image,trim(concat(trim(isnull(ul.CountryCode, '''')), '' '', trim(isnull(ul.MobileNo, '''')))) as MobileNo,trim(concat(trim(isnull(ul.CountryCode1, '''')), '' '', trim(isnull(ul.MobileNo1, '''')))) as MobileNo1,trim(concat(trim(isnull(ul.CountryCode2, '''')), '' '', trim(isnull(ul.MobileNo2, '''')))) as MobileNo2,ul.EmailID,ul.EmailID1,ul.EmailID2,concat(MobileNo, iif(MobileNo1 <> '''', concat('''', '','', MobileNo1), ''''), iif(MobileNo2 <> '''', concat('''', '','', MobileNo2), '''')) as CsvMobileNo,concat(EmailId, iif(EmailId1 <> '''', concat('''', '','', EmailId1), ''''), iif(EmailId2 <> '''', concat('''', '','', EmailId2), '''')) as CsvEmailId,ul.City,ul.State,ul.Country,ul.PinCode,ul.ResidentialAddress,ul.OfficeAddress, isnull(us.Name, '''') [SourceName],isnull(md.Name, '''') [MediumName],isnull(cm.Name, '''') as [CampaignName],isnull(ul.InitialRemarks,'''') InitialRemarks,ul.ParentID, FORMAT(DATEADD(MINUTE,(DATEPART(tz, (CAST(''2021-01-01'' AS DATETIMEOFFSET) AT TIME ZONE '''+ @TimeZoneName +N''')) - 330), CAST(ul.CreatedOn AS DATETIME) ), ''dd-MMM-yyyy HH:mm:ss'') as CreatedOn,ul.CreatedBy,ul.LeadNo,ul.ProfileImgFileName,ul.whereAddress, isnull(Latitude,'''')Latitude,isnull(Longitude,'''')Longitude,isnull(ul.Remarks,'''')Remarks, isnull(fs.FollowupStatus, '''') as [HtmlStatus], isnull(fs.FollowupStatus, '''') as [FollowUpStatus], ( case when fs.IsConvert = 1 then ''Converted'' when fs.IsCallback = 1 and cast(ul.FollowupDate as date)  = cast(getdate() as date) then ''Due Today'' when fs.IsCallback = 1 and cast(ul.FollowupDate as date)  < cast(getdate() as date) then ''Over Due'' when fs.IsCallback = 1 and cast(ul.FollowupDate as date)  > cast(getdate() as date) then ''Scheduled'' when fs.IsConvert = 0 and fs.IsCallback = 0 then ''No Followup'' end ) as [HtmlStatus1], FORMAT(DATEADD(MINUTE,(DATEPART(tz, (CAST(''2021-01-01'' AS DATETIMEOFFSET) AT TIME ZONE '''+ @TimeZoneName +N''')) - 330), CAST(ul.FollowupDate  AS DATETIME) ), ''dd-MMM-yyyy HH:mm:ss'') AS FollowupDate, ul.AmountPaid,  ul.AssignedTo, ul.NextStatusDate, ul.FollowUpStatus FollowUpStatusId, ul.CountryCode, ul.CountryCode1, ul.CountryCode2, ag.User_ID as AgentId,ag.FName as AgentFName,ag.LName as AgentLName,ag.Image as AgentImage,ag.User_Login as AgentLogin, Profit_Loss=case when LS.ScoreAdded > 0 then ''Green_Up'' when LS.ScoreAdded  < 0 then ''Red_Down'' else '''' end, CurrentScore=cast(isnull((LS.currentscore/nullif(' + cast(@maxScore as varchar(max)) + ',0.00))*99,0) as int) , ThresholdColor=case when cast(isnull((LS.currentscore/nullif('+ cast(@maxScore as varchar(max)) + ',0.00))*99,0) as int)>' + cast(@warm as varchar(max)) + ' then ''Hot'' when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore as varchar(max))+',0.00))*99,0) as int) between ' + cast(@cold as varchar(max)) + ' and ' + cast(@warm as varchar(max)) + ' then ''Warm'' else ''Cold'' end ';      
          
 declare @FFieldName nvarchar(max) = iif(isnull(@fieldName, '') <> '', concat(',',@fieldName), '')    
  
 declare @customTotalRow int = 0, @allRowCount int = 0  
 select top 1 @customTotalRow = TotalRow from #customSearch   
  
 print concat('@customTotalRow => ', @customTotalRow, ', @filterTextSql => ', @filterTextSql, ', @filterStrSql= => ', @filterStrSql)  
  
 if(isnull(@customTotalRow, 0) = 0 and isnull(@filterTextSql, '') = '' and isnull(@filterStrSql, '') = '')  
 begin  
  declare @cteParam nvarchar(255) = ''  
  declare @sqlCte nvarchar(max) = concat(';WITH TotalCount AS (SELECT ',   
   'COUNT(1) AS TotalRecords FROM UserLeads(NOLOCK) ul ',  
   'WHERE ul.ParentID = ', @ParentId, N' and ul.AssignedTo in (',   
    case when @UserIdTeamLst = '' then cast(@UserId as varchar) else @UserIdTeamLst end,    
   N' )) select @innerAllRowCount = TotalRecords from TotalCount')  
    
  print concat('@sqlCte => ', @sqlCte)  
  
  EXEC sp_executesql @sqlCte, N'@innerAllRowCount INT OUTPUT', @innerAllRowCount = @allRowCount OUTPUT;  
 end  
  
 /* Added By DBA */  
 /* Date : 2024-12-02*/  
  
 DECLARE @is_special_case INT = 0  
 -- Get a list of valid UserLeads IDs  
 IF @CustomSearchId = N'0' AND @PredefindSearchId = N'0'   
  AND @FilterText=N'' AND @FilterExp = N'' AND @Ordstr = N''  
  BEGIN  
  
   SET @is_special_case = 1;  
  
   DECLARE @SQL AS NVARCHAR(MAX) = N'';  
   DROP TABLE IF EXISTS #UL;  
  
   CREATE TABLE #UL (ID BIGINT, CreatedOn DATETIME, CurrentScore INT);  
  
   SET @SQL = N'  
   ;with cte_1  
    AS  
    (  
    SELECT ul.ID, ul.CreatedOn ,CurrentScore=cast(isnull((LS.currentscore/nullif(2418777.00,0.00))*99,0) as int)  
    FROM UserLeads(NOLOCK) ul   
    LEFT JOIN lead_score_history_latest(NOLOCK) LS ON UL.ID = LS.LeadId  
    inner join User_Detail(nolock) ag on ul.AssignedTo = ag.User_ID  
    WHERE ul.ParentID = @pid and ul.AssignedTo in (' + case when @UserIdTeamLst = '' then cast(@UserId as nvarchar(20)) else @UserIdTeamLst end + N')' +  
    N')  
    INSERT INTO #UL (ID, CreatedOn, CurrentScore)  
    SELECT ID, CreatedOn, CurrentScore FROM cte_1 '  
    --+ @orderByQuery +  
    --N'offset ' + cast(@OffsetValue as nvarchar(10)) + N' rows fetch next '+ cast((@PageSize * 2) as nvarchar(10)) + N' rows only; '   
  
   EXEC sp_executeSQL @sql, N'@pid BIGINT', @pid = @ParentId;  
  
  END  
  
  
 declare @cvQuery nvarchar(max) = N'select '+ ( case   
   when @customTotalRow > 0 then cast(@customTotalRow as nvarchar)   
   when @allRowCount > 0 then cast(@allRowCount as nvarchar)   
  else 'count(Id) over() ' end ) +'  as TotalRecords, * from( select Id, PersonName, CompanyName, Image, MobileNo, MobileNo1, MobileNo2, EmailID, EmailID1, EmailID2, CsvMobileNo, CsvEmailId, City, State, Country, PinCode, ResidentialAddress, OfficeAddress, [SourceName], [MediumName], [CampaignName],InitialRemarks, ParentID, CreatedOn,CreatedBy,LeadNo,ProfileImgFileName,whereAddress,  Latitude, Longitude, Remarks, [HtmlStatus],  [FollowUpStatus], [HtmlStatus1], FollowupDate, AmountPaid,  AssignedTo, NextStatusDate, FollowUpStatusId, CountryCode, CountryCode1, CountryCode2, AgentId,AgentFName, AgentLName,AgentImage, AgentLogin, Profit_Loss, CurrentScore, ThresholdColor '+ @FFieldName + N' from (SELECT '+ @enquiryColumns   
   + N' FROM UserLeads(NOLOCK) ul ' + IIF(@is_special_case = 1, N' INNER JOIN  #UL tul ON tul.ID = ul.ID ', N'');    
  declare @cvQuery2 nvarchar(max) = N' LEFT JOIN lead_score_history_latest(NOLOCK) LS ON UL.ID = LS.LeadId left join UserSourceSettings(nolock) us on ul.SourceName = us.SourceID left join UserMediumSettings(nolock) md on ul.MediumName = md.MediumID left join UserCampaignSettings(nolock) cm on ul.CampaignName = cm.CampaignID inner join User_Detail(nolock) ag on ul.AssignedTo = ag.User_ID LEFT JOIN FollowUp_Status(NOLOCK) fs on ul.FollowUpStatus = fs.ID '+ iif(isnull(@CustomSearchId, 0 ) > 0, ' inner join  #customSearch(nolock) cs on ul.Id = cs.EntityId  ', concat(' WHERE ( ul.ParentID = ', @ParentId, ' and ul.AssignedTo in (', case when @UserIdTeamLst = '' then cast(@UserId as varchar) else @UserIdTeamLst end, ')) ' )) + ' ) t ' + iif(isnull(@fieldName, '') <> '', concat(N' LEFT JOIN ( SELECT * FROM ( SELECT cfv.LeadID, cf.fieldname, cfv.fieldvalue FROM customfields(NOLOCK) cf INNER JOIN customfieldLeadvalue(NOLOCK) cfv ON cf.field_ID = cfv.fieldID WHERE cf.IsActive = 1 and cf.ParentID = ' + cast(@ParentId as varchar) + ') ipc PIVOT(MAX(fieldvalue) FOR fieldname IN( ' + @fieldName + N' )) p ) c ON t.ID = c.LeadID ', ''), '')  + N') tt ';     
  declare @cvQuery3 nvarchar(max) = N' where  (1=1) ' + @filterTextSql + ' ' + @filterStrSql + ' ' +  @orderByQuery +    
  N' offset '+ cast(@OffsetValue as varchar) +' rows fetch next '+ cast(@PageSize as varchar) +' rows only '    
    
-- ' + @filterStrSql + '     
    declare @Query nvarchar(max)        
    SELECT @Query = @cvQuery + @cvQuery2 + @cvQuery3     
      
  
    print @cvQuery     
    print @cvQuery2     
    print @cvQuery3    
  
      
 execute sp_executesql @Query    
    
 --execute dbo.usp_tbl_UA_PageFieldsList_UserId_PageCode 'S', @ParentId, @UserId, 'PAG10031'    
          
end   



GO

/* ============================================================
   Procedure: [dbo].[usp_mob_GetLeadListNe$]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_mob_GetLeadListNe$](        
	@UserId bigint,   
	@CustomSearchId nvarchar(50) = '0',        
	@PredefindSearchId nvarchar(50) = '0',        
	@FilterText nvarchar(255) = '',        
	@FilterExp NVARCHAR(MAX) = '',   
	@Ordstr NVARCHAR(MAX) = '',
	@SortOrder nvarchar(50) = '',
	@OffsetValue int  = 0,   
	@PageSize int  = 10   
)   
