NE '''+ @TimeZoneName +N''')) - 330), CAST(ul.FollowupDate  AS DATETIME) ), ''dd-MMM-yyyy HH:mm:ss'') AS FollowupDate, ul.AmountPaid,  ul.AssignedTo, ul.NextStatusDate, ul.FollowUpStatus FollowUpStatusId, ul.CountryCode, ul.CountryCode1, ul.CountryCode2, ag.User_ID as AgentId,ag.FName as AgentFName,ag.LName as AgentLName,ag.Image as AgentImage,ag.User_Login as AgentLogin, Profit_Loss=case when LS.ScoreAdded > 0 then ''Green_Up'' when LS.ScoreAdded  < 0 then ''Red_Down'' else '''' end, CurrentScore=cast(isnull((LS.currentscore/nullif(' + cast(@maxScore as varchar(max)) + ',0.00))*99,0) as int) , ThresholdColor=case when cast(isnull((LS.currentscore/nullif('+ cast(@maxScore as varchar(max)) + ',0.00))*99,0) as int)>' + cast(@warm as varchar(max)) + ' then ''Hot'' when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore as varchar(max))+',0.00))*99,0) as int) between ' + cast(@cold as varchar(max)) + ' and ' + cast(@warm as varchar(max)) + ' then ''Warm'' else ''Cold'' end ';    
        
