	/* Special-case: build #UL including unassigned leads (AssignedTo = 0 or NULL) */
DECLARE @is_special_case INT = 0;
IF @CustomSearchId = N'0' AND @PredefindSearchId = N'0' 
    AND @FilterText = N'' AND @FilterExp = N'' AND @Ordstr = N''
BEGIN
    SET @is_special_case = 1;

    DROP TABLE IF EXISTS #UL;
    CREATE TABLE #UL (ID BIGINT, CreatedOn DATETIME, CurrentScore INT);

    DECLARE @SQL NVARCHAR(MAX) = N'';
    -- inject @maxScore value into the dynamic SQL
    DECLARE @maxScoreStr NVARCHAR(50) = ISNULL(CAST(@maxScore AS NVARCHAR(50)), '0');

    SET @SQL = N'
    ;WITH cte_1 AS
    (
        SELECT ul.ID,
               ul.CreatedOn,
               CurrentScore = CAST(ISNULL((LS.currentscore / NULLIF(' + @maxScoreStr + N',0.00)) * 99, 0) AS INT)
        FROM UserLeads(NOLOCK) ul
        LEFT JOIN lead_score_history_latest(NOLOCK) LS ON UL.ID = LS.LeadId
        LEFT JOIN User_Detail(NOLOCK) ag ON ul.AssignedTo = ag.User_ID
        WHERE ul.ParentID = @pid
          AND (
                ul.AssignedTo IN (' + CASE WHEN @UserIdTeamLst = '' THEN CAST(@UserId AS NVARCHAR(20)) ELSE @UserIdTeamLst END + N')
                OR ul.AssignedTo = 0
                OR ul.AssignedTo IS NULL
              )
    )
    INSERT INTO #UL (ID, CreatedOn, CurrentScore)
    SELECT ID, CreatedOn, CurrentScore FROM cte_1;';

    EXEC sp_executesql @SQL, N'@pid BIGINT', @pid = @ParentId;
END



	declare @cvQuery nvarchar(max) = N'select '+ ( case 
			when @customTotalRow > 0 then cast(@customTotalRow as nvarchar) 
			when @allRowCount > 0 then cast(@allRowCount as nvarchar) 
		else 'count(Id) over() ' end ) +'  as TotalRecords, * from( select Id, PersonName, CompanyName, Image, MobileNo, MobileNo1, MobileNo2, EmailID, EmailID1, EmailID2, CsvMobileNo, CsvEmailId, City, State, Country, PinCode, ResidentialAddress, OfficeAddress, [SourceName], [MediumName], [CampaignName],InitialRemarks, ParentID, CreatedOn,CreatedBy,LeadNo,ProfileImgFileName,whereAddress,  Latitude, Longitude, Remarks, [HtmlStatus],  [FollowUpStatus], [HtmlStatus1], FollowupDate, AmountPaid,  AssignedTo, NextStatusDate, FollowUpStatusId, CountryCode, CountryCode1, CountryCode2, AgentId,AgentFName, AgentLName,AgentImage, AgentLogin, Profit_Loss, CurrentScore, ThresholdColor '+ @FFieldName + N' from (SELECT '+ @enquiryColumns 
			+ N' FROM UserLeads(NOLOCK) ul ' + IIF(@is_special_case = 1, N' INNER JOIN  #UL tul ON tul.ID = ul.ID ', N'');  
	 declare @cvQuery2 nvarchar(max) = N' LEFT JOIN lead_score_history_latest(NOLOCK) LS ON UL.ID = LS.LeadId left join UserSourceSettings(nolock) us on ul.SourceName = us.SourceID left join UserMediumSettings(nolock) md on ul.MediumName = md.MediumID left join UserCampaignSettings(nolock) cm on ul.CampaignName = cm.CampaignID left join User_Detail(nolock) ag on ul.AssignedTo = ag.User_ID LEFT JOIN FollowUp_Status(NOLOCK) fs on ul.FollowUpStatus = fs.ID '+ iif(isnull(@CustomSearchId, 0 ) > 0, ' inner join  #customSearch(nolock) cs on ul.Id = cs.EntityId  ', concat(' WHERE ( ul.ParentID = ', @ParentId, ' and ul.AssignedTo in (', case when @UserIdTeamLst = '' then cast(@UserId as varchar) else @UserIdTeamLst end, ')) ' )) + ' ) t ' + iif(isnull(@fieldName, '') <> '', concat(N' LEFT JOIN ( SELECT * FROM ( SELECT cfv.LeadID, cf.fieldname, cfv.fieldvalue FROM customfields(NOLOCK) cf INNER JOIN customfieldLeadvalue(NOLOCK) cfv ON cf.field_ID = cfv.fieldID WHERE cf.IsActive = 1 and cf.ParentID = ' + cast(@ParentId as varchar) + ') ipc PIVOT(MAX(fieldvalue) FOR fieldname IN( ' + @fieldName + N' )) p ) c ON t.ID = c.LeadID ', ''), '')  + N') tt ';   
	 declare @cvQuery3 nvarchar(max) = N' where  (1=1) ' + @filterTextSql + ' ' + @filterStrSql + ' ' +  @orderByQuery +  
